import type { Question } from "@/types";

export const IMPORTED_BANKS: Record<string, Question[]> = {"emergency_care": [{"id": 10000, "cat": "Emergency Care", "stem": "A nurse is caring for a client with hypovolemic shock. Which of the following is the nursing priority action?", "choices": [{"id": "a", "t": "Therapeutic hypothermia"}, {"id": "b", "t": "Placing the client in the right lateral decubitus position"}, {"id": "c", "t": "Reverse Trendelenburg position"}, {"id": "d", "t": "Elevating the client's legs"}], "correct": "d", "rationale": "Adequate cardiac output is essential for perfusion of vital organs. In hypovolemic shock, elevating the legs and lowering the head of the bed promotes venous return to the brain and heart and increases cardiac output.", "whyNot": {"a": "The client should be kept warm to conserve energy.", "b": "The client should be supine with legs slightly elevated to promote return of blood to the heart and to conserve or increase cardiac output; right lateral decubitus is not the priority.", "c": "Reverse Trendelenburg reduces blood flow to vital organs."}, "keyConcept": "Critical interventions to maintain perfusion to vital organs include positioning the client with legs elevated and the head of the bed lowered, which improves cardiac output by increasing venous return to the heart."}, {"id": 10001, "cat": "Emergency Care", "stem": "A 22-year-old male comes to the emergency department following a motor vehicle accident. His eyes open to speech, he is confused, and he localizes to pain. What is his Glasgow Coma Scale (GCS) score?", "choices": [{"id": "a", "t": "10"}, {"id": "b", "t": "3"}, {"id": "c", "t": "7"}, {"id": "d", "t": "15"}, {"id": "e", "t": "12"}], "correct": "e", "rationale": "Eye response to speech = 3, verbal confused = 4, motor localizes to pain = 5. Total GCS = 12.", "whyNot": {"a": "10 indicates greater impairment than this presentation.", "b": "3 indicates no response in any category.", "c": "7 is severely impaired.", "d": "15 indicates normal response in all categories."}, "keyConcept": "The Glasgow Coma Scale provides a practical method for assessing impairment of consciousness in response to defined stimuli and for communicating findings."}, {"id": 10002, "cat": "Emergency Care", "stem": "A nurse is providing bag-mask ventilation for a client with an oropharyngeal airway in place. Which of the following is a contraindication to placement of an oropharyngeal airway? (Select all that apply.)", "choices": [{"id": "a", "t": "A client who is not breathing"}, {"id": "b", "t": "A client who has a gag reflex"}, {"id": "c", "t": "A client who is breathing"}, {"id": "d", "t": "A client with a palate fracture"}, {"id": "e", "t": "A client who is unconscious"}], "correct": ["b", "d"], "rationale": "An oropharyngeal airway is used to maintain an open airway in an unconscious client and prevents the tongue from covering the epiglottis. It should not be used in a client with an active gag reflex because it can trigger vomiting and aspiration. It also should not be inserted in a client with a palate fracture due to risk of injury to the roof of the mouth.", "whyNot": {"a": "An oropharyngeal airway can be used in a client who is not breathing to keep the airway open while providing ventilation.", "c": "It may be used in clients who are breathing or not breathing, if no contraindications exist.", "e": "It is commonly used in unconscious clients to maintain airway patency."}, "keyConcept": "Correct size is measured from incisors to the angle of the jaw. Inserted upside down and rotated 180 degrees in adults; in infants/children insert right side up while holding the tongue forward with a tongue depressor."}, {"id": 10003, "cat": "Emergency Care", "stem": "A nurse is caring for an adult client admitted to the emergency department after a motor vehicle collision. The client has a heart rate of 110 beats/minute with blood pressure of 88/56 mm Hg. Which of the following catheters will the nurse use in anticipation of rapid infusion of fluid or blood?", "choices": [{"id": "a", "t": "Yellow 24-gauge catheter"}, {"id": "b", "t": "Blue 22-gauge catheter"}, {"id": "c", "t": "Pink 20-gauge catheter"}, {"id": "d", "t": "Green 18-gauge catheter"}], "correct": "d", "rationale": "A large-bore catheter (18-gauge) is commonly used for rapid infusion and blood transfusion. Large-bore IVs minimize hemolysis and allow higher flow rates.", "whyNot": null, "keyConcept": null}, {"id": 10004, "cat": "Emergency Care", "stem": "A nurse in the emergency department is caring for a client who has experienced an electrical burn. Which of the following nursing interventions is most important in this situation?", "choices": [{"id": "a", "t": "Brush off dirt particles and debris"}, {"id": "b", "t": "Monitor for cardiac arrhythmias"}, {"id": "c", "t": "Cool the client with water"}, {"id": "d", "t": "Lower the client's head"}], "correct": "b", "rationale": "Electrical burns can disrupt the cardiac electrical cycle and cause arrhythmias. Continuous cardiac monitoring and readiness for CPR are critical.", "whyNot": {"a": "Debris removal may be needed but is not the priority.", "c": "Cold water can worsen tissue damage and is not recommended for electrical burns.", "d": "Lowering the head is not indicated."}, "keyConcept": "Electrical burns cause direct tissue injury, thermal injury, and mechanical injury from muscle contraction or falls. Arrhythmias can occur within hours after the injury."}, {"id": 10005, "cat": "Emergency Care", "stem": "A recently graduated RN has been assigned to triage in the emergency department. As clients present for initial contact with the nurse, who should be given the highest priority?", "choices": [{"id": "a", "t": "A client who fell and has wrist pain with an obvious deformity"}, {"id": "b", "t": "A client with new-onset slurred speech and right arm weakness"}, {"id": "c", "t": "A client with dysuria and urinary urgency for a day and a temperature of 100.4 F"}, {"id": "d", "t": "A client with a small laceration who has not received a recent tetanus shot"}], "correct": "b", "rationale": "Triage priority is given to potentially life-threatening conditions requiring immediate stabilization, including acute neurologic deficits.", "whyNot": {"a": "Painful but not immediately life-threatening.", "c": "Urgent but not highest priority.", "d": "Non-urgent and can wait."}, "keyConcept": "Emergency triage categories: Priority I (emergent, immediate), Priority II (urgent within 20 minutes to 2 hours), Priority III (non-urgent)."}, {"id": 10006, "cat": "Emergency Care", "stem": "Which of the following findings are most likely when assessing an elderly individual who fell and now presents with a probable hip fracture? (Select all that apply.)", "choices": [{"id": "a", "t": "Groin pain with weight bearing"}, {"id": "b", "t": "Internal rotation of the leg on the affected side"}, {"id": "c", "t": "Lengthening of the extremity"}, {"id": "d", "t": "Ecchymosis over the hip and thigh"}, {"id": "e", "t": "Muscle spasm around the fracture site"}], "correct": ["a", "d", "e"], "rationale": "Hip fractures commonly cause pain in the hip and groin with weight bearing, localized bruising, and muscle spasm. The affected leg is typically externally rotated and shortened, not internally rotated or lengthened.", "whyNot": null, "keyConcept": null}, {"id": 10007, "cat": "Emergency Care", "stem": "A nurse in the coronary care unit notes the following rhythm on a client's monitor (see image). The nurse confirms the rhythm is consistent with the client's clinical status. What is the immediate nursing action?", "choices": [{"id": "a", "t": "Administration of digoxin"}, {"id": "b", "t": "Administration of amiodarone"}, {"id": "c", "t": "Defibrillation"}, {"id": "d", "t": "Synchronized cardioversion"}], "correct": "c", "rationale": "The rhythm is ventricular fibrillation, a chaotic rhythm that prevents effective cardiac output. Immediate CPR and defibrillation are indicated as soon as the defibrillator is available.", "whyNot": {"a": "Digoxin is used in heart failure and atrial fibrillation, not VF.", "b": "Amiodarone can be used for ventricular arrhythmias, but defibrillation is the priority in VF.", "d": "Synchronized cardioversion is for stable tachyarrhythmias."}, "keyConcept": "Ventricular fibrillation is a leading cause of cardiac arrest; immediate chest compressions and rapid defibrillation improve survival."}, {"id": 10008, "cat": "Emergency Care", "stem": "A nurse sees a visitor collapse and fall to the floor several feet away. Another bystander calls for help while the nurse assesses the visitor, who is unresponsive. The nurse cannot palpate a pulse. What is the next intervention the nurse should provide?", "choices": [{"id": "a", "t": "Tilt the victim's head back and perform a chin lift to open the airway"}, {"id": "b", "t": "Tilt the victim's head back and perform a jaw thrust to open the airway"}, {"id": "c", "t": "Deliver two mouth-to-mouth rescue breaths"}, {"id": "d", "t": "Begin chest compressions"}], "correct": "d", "rationale": "High-quality CPR is the most important initial action in cardiac arrest. Begin rapid, hard chest compressions immediately; airway and breaths follow after compressions are started.", "whyNot": null, "keyConcept": "If a pulse is not palpated within 10 seconds, initiate chest compressions. Compress at least 2 inches deep in adults with full recoil and minimal interruptions."}, {"id": 10009, "cat": "Emergency Care", "stem": "A nurse is assessing a client who was transported to the ER with neurological deficits after falling off a ladder. What client assessment is included in the Glasgow Coma Scale?", "choices": [{"id": "a", "t": "Breathing patterns"}, {"id": "b", "t": "Deep tendon reflexes"}, {"id": "c", "t": "Eye accommodation to light"}, {"id": "d", "t": "Motor response to a stimulus"}], "correct": "d", "rationale": "The Glasgow Coma Scale assesses eye opening, verbal response, and motor response to stimuli.", "whyNot": {"a": "Breathing patterns are not part of GCS.", "b": "Deep tendon reflexes are not part of GCS.", "c": "Pupil accommodation is not part of GCS."}, "keyConcept": "GCS provides a standardized way to document neurologic status and to identify trends for deterioration or improvement."}, {"id": 10010, "cat": "Emergency Care", "stem": "A nurse in the emergency department is caring for a child who has severe lead toxicity. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Administer syrup of ipecac to the child."}, {"id": "b", "t": "Administer activated charcoal to the child."}, {"id": "c", "t": "Administer calcium gluconate to the child."}, {"id": "d", "t": "Administer chelation therapy."}], "correct": "d", "rationale": ", such as deferoxamine mesylate (IM), along with calcium EDTA IV or IM. Chelation B | TR fo therapy is indicated for severe lead poisoning and toxicity. It removes lead from the bloodstream by excreting it through the urine. cli 8%", "whyNot": {"a": "The administration of syrup of ipecac is not indicated for severe lead toxicity. Syrup of ipecac will induce vomiting and is contraindicated", "b": "The administration of activated charcoal is indicated for acetylsalicylic acid poisoning. Activated charcoal causes medications and toxins", "c": "The administration of calcium gluconate is indicated for magnesium toxicity."}, "keyConcept": "Lead poisoning is the accumulation of lead in the body. Risk factors include children less than 6 years of age, living in older homes built prior to 1978, and exposure to environmental elements such as soil, dust, and water that can contain lead. Children can be exposed to lead by ingesting lead-based paint. Blood lead levels greater than 5mcg/dL can cause improper function of the client's RBCs. For high blood lead levels of 20 mcg/dL or greater, chelation therapy is recommended. Precaution should be used during the administration of chelation therapy because it can cause hypocalcemia and death. Prevention of lead toxicity is aimed at educating parents about lead exposure from paint and window sills, proper handwashing techniques, and to wet mop floors to prevent airborne particles."}, {"id": 10011, "cat": "Emergency Care", "stem": "place. Which of the following nursing interventions is a priority intervention?", "choices": [{"id": "a", "t": "Place the client on a backboard"}, {"id": "b", "t": "Avoid moving the client"}, {"id": "c", "t": "Turn client on side in case of seizure"}, {"id": "d", "t": "Obtain an order for a Foley catheter"}], "correct": "a", "rationale": "co. im 30% — Hard The client should be placed on a backboard to maintain cervical spine alignment. Moving the client could result in permanent spinal cord B rs ce damage and potentially result in paralysis. The goal of care is to 1) prevent ongoing injury or progression; 2) institute treatment for evident injuries and 3) establish routine care to maintain health and prevent further complications. c | 3% oy 6%", "whyNot": {"b": "If there is a spinal cord injury, the client should be moved as little as possible. The client is usually transported on a backboard, which is", "c": "There is no indication that the client is at risk for seizure.", "d": "A catheter is not necessarily indicated. The client's cervical spine should be \"cleared\" by radiological imaging and examination."}, "keyConcept": "When a client has suspected traumatic cervical spinal cord injury, the healthcare team implements procedures to support alignment of the spine in an anatomically neutral position, including logrolling of the client when repositioning for comfort or procedures; use of transfer techniques to move the client from surface to surface; application and maintenance of C-spine collar; skincare; placing the client on an appropriate surface as ordered by the responsible healthcare provider and monitoring spinal signs."}, {"id": 10012, "cat": "Emergency Care", "stem": "A nurse in the emergency department knows that isotonic crystalloid is most appropriately prescribed for which of the following clients? O A.A 78-year-old with a serum sodium of 116 mEq/L who is having a seizure O B. A 30-year-old with diarrhea and emesis for 12 hours who is dehydrated O C. A32-year-old who is unresponsive with signs of increased intracranial pressure after head trauma O D. A 58-year-old with a BP of 210/115 mmHg and a history of chronic renal failure", "choices": [{"id": "a", "t": "Severe hyponatremia associated with neurologic changes like seizures require more rapid correction with a hypertonic saline solution (3%"}, {"id": "b", "t": "Correct Answer: A 30-year-old with diarrhea and emesis for 12 hours who is dehydrated A a o: Homeostasis is the body's state of natural equilibrium and maintenance of the normal volume and composition of body fluid is necessary to c | maintain this equilibrium."}, {"id": "c", "t": "Ahypertonic solution is used to decrease the water content of the brain; at the same time, this may increase the systolic blood pressure."}, {"id": "d", "t": "Use of isotonic intravenous solutions in individuals with chronic renal failure can result in volume overload. This can cause a further"}], "correct": "b", "rationale": "Correct Answer: A 30-year-old with diarrhea and emesis for 12 hours who is dehydrated A a o: Homeostasis is the body's state of natural equilibrium and maintenance of the normal volume and composition of body fluid is necessary to c | maintain this equilibrium. Water makes up 60% of the body's composition and is distributed between two major fluid compartments, the my I intracellular and extracellular compartments. There are various mechanisms that govern the movement of water and electrolytes between body compartments separated by a membrane. When membranes are impermeable to solutes but permeable to water, water moves from the compartment with low solute concentration to the compartment with high solute concentration. Isotonic crystalloids have the same solute concentration or \"tonicity\" as plasma and will remain in the intravascular compartment. They are the intravenous solution of choice for rapid repletion of volume loss and dehydration. But, if volume loss is ongoing and severe due to a hemorrhage, blood products will be necessary after the initial crystalloid infusion. When an isotonic fluid is infused, it will remain in the intravascular space to increase perfusion pressure and circulatory volume.", "whyNot": {"a": "Severe hyponatremia associated with neurologic changes like seizures require more rapid correction with a hypertonic saline solution (3%", "c": "Ahypertonic solution is used to decrease the water content of the brain; at the same time, this may increase the systolic blood pressure.", "d": "Use of isotonic intravenous solutions in individuals with chronic renal failure can result in volume overload. This can cause a further"}, "keyConcept": "The body is composed of 60% water, which is distributed between the intracellular and extracellular fluid compartments. Normally, the intracellular and extracellular compartments have the same osmolality and no net movement occurs between compartments. Fluids with the same osmolality of the cell interior are known as \"isotonic.\" Isotonic fluids are administered hemorrhage as they can quickly restore volume and normal distribution of water."}, {"id": 10013, "cat": "Emergency Care", "stem": "A nurse is assigned to triage after a mass casualty due to an explosion. Which of the following clients should be the priority for treatment?", "choices": [{"id": "a", "t": "A client with an open fracture of the left tibia and fibula"}, {"id": "b", "t": "A client who has a head injury, agonal respirations, and a Glasgow Coma Scale of 3"}, {"id": "c", "t": "A client with second-degree burns on the right forearm"}, {"id": "d", "t": "A client who is crying and screaming and has sustained a 5 cm laceration of the right thigh"}], "correct": "a", "rationale": "o; Triage in mass casualty is designed to allow healthcare personnel to make rapid decisions that allow them to do the most good for the B a greatest number of people. Individuals with alterations in airway, breathing, or circulation who are most likely to survive should receive priority. Four categories are used in most triage systems, which include the SALT (Sort, Assess, Life-saving interventions, c _| Treatment/Transport) and START (Simple Triage And Rapid Transport/Treatment) systems. These triage systems allow healthcare D i professionals performing triage to tag victims into categories (see table below). This client has an open fracture, an injury with a good prognosis when treated immediately. Black tag Expectant Extensive injuries, poor prognosis Red tag Immediate Life threatening injury with good prognosis when treated: 2r/3\" degree burns covering 15-40% BSA, airway obstruction, open fractures Yellow tag Delayed Requires treatment within hours: soft tissue injuries, stable abdominal injury, partial thickness burns < 15% BSA Green tab Minimum Requires treatment w/in a few days, includes minor lacerations, small fractures, minor burns", "whyNot": {"b": "A Glasgow Coma Score of 3 is associated with a poor prognosis, even when treated. Given the agonal respirations, and need for multiple", "c": "A partial thickness burn that is <15% BSA is appropriate for delayed treatment.", "d": "A minor laceration, depending on the size and depth, can be delayed for hours to a few days."}, "keyConcept": "When prioritizing care in mass casualty response, triage systems provide a method for rapid decision-making by responders that will allow them to do the most good for the most people. Triage systems prioritize individuals with alterations in airway, breathing, and circulation who are most likely to survive if they receive care."}, {"id": 10014, "cat": "Emergency Care", "stem": "Which emergency medication is accurately paired with its nursing implication?", "choices": [{"id": "a", "t": "Mannitol: This medication must be discontinued gradually"}, {"id": "b", "t": "Pentobarbital: Assess electrolytes at least every 6 hours"}, {"id": "c", "t": "Mannitol: Assess hemoglobin every 12 hours"}, {"id": "d", "t": "Phenytoin: The dosage is adjusted according to its therapeutic levels"}], "correct": "d", "rationale": "A Hi 16% Moderate Phenytoin is used to treat and prevent seizures. Nursing implications include monitoring of seizure activity and administration of dosages B I Ee according to therapeutic blood levels, among others. c | 3%", "whyNot": {"a": "Mannitol does not need to be discontinued gradually. Mannitol is used to decrease intracranial pressure; it is an osmotic diuretic. Some of", "b": "Pentobarbital requires gradual discontinuation but does not require electrolyte monitoring every 6 hours. Pentobarbital decreases the", "c": "Mannitol is an osmotic diuretic; it does not require frequent hemoglobin assessment. Mannitol is used to decrease intracranial pressure; it"}, "keyConcept": "Phenytoin (Dilantin) is used in the treatment and prevention of seizures. The nurse should continuously monitor vital signs and symptoms during IV infusion and for an hour afterward and watch for respiratory depression. A cardiac monitor should be used during phenytoin infusion in older adults or clients with cardiac disease. The nurse should also be aware of the serum concentration. There is a narrow margin between toxic and therapeutic IV doses of phenytoin."}, {"id": 10015, "cat": "Emergency Care", "stem": "Which of the following nursing diagnoses is the highest priority for a client who has presented to the emergency department with a depressed skull fracture?", "choices": [{"id": "a", "t": "At risk for acute confusion related to a depressed skull fracture"}, {"id": "b", "t": "At risk for disturbed sensory perception related to a depressed skull fracture"}, {"id": "c", "t": "At risk for permanent dysfunction related to a depressed skull fracture"}, {"id": "d", "t": "At risk for respiratory compromise related to a depressed skull fracture"}], "correct": "d", "rationale": "Of all the possible nursing diagnoses listed above, “At risk for respiratory compromise related to a depressed skull fracture” is the greatest priority. Physiological needs that present a risk to life or limb are the most important priority and include problems related to the ABCs: airway, breathing, and circulation or cardiac function.A depressed skull fracture can result in increased ICP (intracranial pressure) and, when compensatory measure fail, herniation of the brain may occur, compressing the respiratory center.", "whyNot": {"a": "The client could be at risk of confusion with a skull fracture, but the most important diagnosis relates to respiratory function.", "b": "A skull fracture may cause disturbed sensory perception; however, the nurse should first assess the client’s respiratory function.", "c": "A client may develop permanent dysfunction from a skull fracture, but the earlier priority is to assess respiratory function."}, "keyConcept": "Head injury in clients is frequently accompanied by respiratory disturbances that include arterial hypoxemia and pulmonary edema. These findings are the result of increased intracranial pressure which often occurs with head injury. Elevated ICP can lead to death or devastating neurological damage by reducing cerebral perfusion pressure (CPP) and causing cerebral ischemia or by compressing tissues in the brain and causing herniation of the brainstem or other vital structures."}, {"id": 10016, "cat": "Emergency Care", "stem": "A nurse is caring for a client who requires rapid transfusion of multiple units of blood. Which of the following will the nurse obtain for use during the transfusion to reduce the risk of cardiac arrhythmia?", "choices": [{"id": "a", "t": "Blood warmer"}, {"id": "b", "t": "Cardiac monitor"}, {"id": "c", "t": "Infusion pump"}, {"id": "d", "t": "Pulse oximeter"}], "correct": "a", "rationale": "eo, i 38% Hard s 36% Rapid transfusion of refrigerated blood products can cause cardiac arrhythmias, so a blood warmer should be used to reduce the client’s risk Cc || 26% when blood products must be rapidly infused. Only devices specially designed and approved to warm blood products should be utilized.", "whyNot": {"b": "Although a cardiac monitor should be used, it will not reduce the risk of arrhythmia. Transfusion of massive amounts of cold blood can", "c": "Allinfusion pumps are not designed to administer blood products. Blood transfusion pumps designed to be used with opaque solutions", "d": "Pulse oximetry monitors hypoxia, which may occur with volume overload. It will not prevent cardiac dysrhythmias."}, "keyConcept": "Ablood warmer should be used when transfusing large volumes of blood. Rapid or massive transfusion of cold blood can result in hypothermia and arrhythmias; citrate toxicity, hypocalcemia, and hyperkalemia."}, {"id": 10017, "cat": "Emergency Care", "stem": "diagnosis? O A. Lactate dehydrogenase O B. Amylase O C. Troponin | and T O D. Low density lipoprotein-C", "choices": [{"id": "a", "t": "Lactate dehydrogenase"}, {"id": "b", "t": "Amylase"}, {"id": "c", "t": "Troponin and T"}, {"id": "d", "t": "Low density lipoprotein-C"}], "correct": "c", "rationale": "Within the first 2-4 hours after myocardial infarction, troponin | and troponin T, a protein found in the myocardium, is released by damaged myocardial cells. Levels will be elevated in 2-4 hours after ischemic injury. Other enzymes released after myocardial infarction include creatine kinase. Creatine kinase MB is the isomer that is specific to myocardial cells. Myoglobin is also released by the heart after injury, but it is not cardiac-specific and can be released by other muscle cells in the body.", "whyNot": {"a": "Lactate dehydrogenase (LDH 1 and LDH 2) indicate myocardial necrosis and usually become positive within 48 hours after myocardial", "b": "Amylase is a digestive enzyme released by the pancreas when pancreatic cells are damaged by autodigestion in pancreatitis.", "d": "Coronary artery disease results from the deposition of excess cholesterol within the lumen of coronary blood vessels."}, "keyConcept": "When a diagnosis of myocardial infarction is suspected but cannot be diagnosed on the basis of ECG findings and clinical presentation, it is necessary to base the diagnosis on measurement of cardiac biomarkers, which are enzymes present in myocardial cells that are released in myocardial infarction. Troponins are sensitive and early markers of myocardial infarction, with elevation 2-4 hours after an ischemic injury."}, {"id": 10018, "cat": "Emergency Care", "stem": "emergencies? O A. Use of calcium channel blockers O B. Middle age O C. Obesity O D. Renal disease", "choices": [{"id": "a", "t": "Use of calcium channel blockers"}, {"id": "b", "t": "Middle age"}, {"id": "c", "t": "Obesity"}, {"id": "d", "t": "Renal disease"}], "correct": "c", "rationale": "A | | 13% Moderate Anumber of factors can increase the risk of a heat-related emergency, including age, environmental conditions, and alcohol. Preexisting B | 3\" conditions that increase the risk of heat-related emergencies include obesity, cardiovascular disease, cystic fibrosis, diabetes mellitus, dehydration, previous stroke or lesion of the central nervous system, and skin disorders. Some prescription drugs are also a risk factor for ec | 57% increased heat-related emergencies. D || 26%", "whyNot": {"a": "Beta blockers, tricyclic antidepressants, anticholinergics, anti-Parkinsonian medications, antihistamines, and phenothiazines are", "b": "Extremes of age, particularly old age, are risk factors for heat-related emergencies.", "d": "Cardiovascular disease, cystic fibrosis, diabetes mellitus, previous stroke, dehydration, and cystic fibrosis are associated with increased"}, "keyConcept": "Certain medical conditions and medications increase the risk of heat-related emergencies. Other factors that increase the risk include environmental factors, extremes of age, and alcohol."}, {"id": 10019, "cat": "Emergency Care", "stem": "contraindication to therapy? O A. “lam short of breath and feel nauseated.” O B. “I have had black tarry bowel movements lately.” O C. “I take hydrochlorothiazide and captopril for my blood pressure.” O D. “My cholesterol level is elevated, but | stopped taking my statin because of muscle pain.”", "choices": [{"id": "a", "t": "“lam short of breath and feel nauseated.”"}, {"id": "b", "t": "“I have had black tarry bowel movements lately.”"}, {"id": "c", "t": "“I take hydrochlorothiazide and captopril for my blood pressure.”"}, {"id": "d", "t": "“My cholesterol level is elevated, but stopped taking my statin because of muscle pain.”"}], "correct": "b", "rationale": "Administration of fibrinolytic therapy within 30 minutes of hospital arrival or transport to the catheterization laboratory for coronary intervention within 90 minutes are both Core Measures in Acute Myocardial Infarction considered by the Joint Commission in the evaluation of an institution. Alteplase is a fibrinolytic medication used to break up clots and restore perfusion to the heart muscle in selected clients with AMI. The recommended total doses for alteplase is based on client weight, not to exceed 100 mg. Fibrinolytic medications increase the risk of hemorrhage, including intracranial hemorrhage. Contraindications include: -Active internal bleeding -History of a recent stroke -Recent (within 3 months) intracranial or intraspinal surgery or serious head trauma -Presence of intracranial conditions that may increase the risk of bleeding (e.g. some neoplasms, arteriovenous malformations, or aneurysms) -Bleeding diathesis -Current severe uncontrolled hypertension. Black tarry bowel movements suggest gastrointestinal bleeding. Active internal bleeding is a contraindication to use of thrombolytic medications. Other contraindications include a history of a recent stroke, serious head trauma or intracranial or intraspinal surgery within the last 2 months, the presence of intracranial conditions such as aneurysms or AV malformation that may increase the risk of bleeding, and known bleeding diathesis or severe uncontrolled hypertension.", "whyNot": {"a": "These symptoms are expected with myocardial infarction.", "c": "Uncontrolled hypertension is a contraindication. Thiazide diuretics and ACEls are recommended classes of medication for initial", "d": "This is not a contraindication. The risk of myocardial infarction and other cardiovascular disorders is increased in individuals with high"}, "keyConcept": null}, {"id": 10020, "cat": "Emergency Care", "stem": "A nurse is caring for a client who was just admitted to the emergency department with a severe burn injury. Which of the following orders would the nurse question for this client?", "choices": [{"id": "a", "t": "Water"}, {"id": "b", "t": "Potassium"}, {"id": "c", "t": "Lactated Ringer’s"}, {"id": "d", "t": "Plasma expanders"}], "correct": "b", "rationale": "si 25% Hard Potassium is usually not given immediately post-burn due to the potential for hyperkalemia, as a result of the release of potassium from OB a A fo injured cells. ci 13%", "whyNot": {"a": "Water will often be administered in combination with lactated Ringer’s solution in various combinations depending on what the client", "c": "Lactated Ringer’s is given in combination with water and dextrose solutions in various combinations depending on client needs.", "d": "Plasma expanders are given with lactated Ringer’s and dextrose solutions depending on client needs."}, "keyConcept": "Burn injuries involve the partial or complete destruction of the integument (the skin. Depending upon the severity of the burn, layers of skin are destroyed, resulting in local and systemic disturbances. The skin is the largest organ of the body and has many functions. These functions include acting as a protective barrier against injury and infection; thermoregulatory control; regulation of fluid loss; synthesis of vitamin D; and sensory contact with the environment. When the skin is damaged or destroyed by a burn, it may lead to compromised immunity, hypothermia, increased fluid loss, infection, changes in appearance, function, and body image. Potassium is the major intracellular cation and it is released by damage to cells, increasing the serum potassium concentration. The nurse should monitor the client for hyperkalemia, not hypokalemia. Supplementation of potassium in clients who have sustained burns can result in toxic levels."}, {"id": 10021, "cat": "Emergency Care", "stem": "client for the procedure? O A. Admitting nurse O B. Anesthesiologist O C. Surgeon O D. Surgical suite nurse", "choices": [{"id": "a", "t": "Admitting nurse"}, {"id": "b", "t": "Anesthesiologist"}, {"id": "c", "t": "Surgeon"}, {"id": "d", "t": "Surgical suite nurse"}], "correct": "c", "rationale": "‘i 8 | o: off The health care provider who will perform the treatment or procedure is responsible for obtaining informed consent from the client. The surgeon who is performing the appendectomy must obtain informed consent.", "whyNot": {"a": "tis a nursing responsibility to witness the client signing the consent form and to verify that they are consenting voluntarily and are", "b": "The anesthesiologist is responsible for maintaining the client's airway and providing sedation and anesthesia. However, it is not their", "d": "The nurses in the surgical suite are responsible for assisting the surgeon and monitoring the client. However, it is not their responsibility to"}, "keyConcept": "The informed consent form is a document that verifies that clients agree to undergo a medical procedure after the provider informs them of the risks, benefits, alternatives to, and consequences of refusal of the procedure. Nurses who witness the signing of the form must also verify that clients are not under the influence of any sedating medications that could impair their judgment, appear to be competent, and can verbalize an understanding of the risk and benefits of the procedure."}, {"id": 10022, "cat": "Emergency Care", "stem": "A nurse is caring for a client who is unconscious. When providing oral care for the client, which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Moisten a soft toothbrush with hydrogen peroxide."}, {"id": "b", "t": "Use their thumb and index finger to keep the client's mouth open."}, {"id": "c", "t": "Turn the client on their side before starting oral care."}, {"id": "d", "t": "Apply petroleum jelly to the client's lips after oral care."}], "correct": "c", "rationale": "Placing the client on their side helps fluid run out of the client's mouth by gravity and not down their throat, preventing aspiration and choking. The nurse should also place an emesis basin, with a towel or waterproof pad underneath, against the client's lower cheek and chin so that the rinsing solution can flow into the basin and not onto the bed linens.", "whyNot": {"a": "The nurse should use chlorhexidine, not hydrogen peroxide, to moisten a soft toothbrush because this antimicrobial solution helps", "b": "The nurse should insert an oral airway, not their thumb or index finger, to keep the client's mouth open.", "d": "The nurse should apply a water-soluble lubricant to the client's lips after oral care."}, "keyConcept": "Oral hygiene for clients who are immobile or unconscious requires special precautions to prevent aspiration, but it also requires meticulous attention to cleaning all tooth surfaces while avoiding injury to the gums. Oral hygiene includes inspecting and cleaning the mucous membranes of the client's mouth with foam swabs or gauze."}, {"id": 10023, "cat": "Emergency Care", "stem": "A nurse is caring for a client who is unconscious. When providing oral care for the client, which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Moisten a soft toothbrush with hydrogen peroxide."}, {"id": "b", "t": "Use their thumb and index finger to keep the client's mouth open."}, {"id": "c", "t": "Turn the client on their side before starting oral care."}, {"id": "d", "t": "Apply petroleum jelly to the client's lips after oral care. eck Answer"}], "correct": "c", "rationale": "Placing the client on their side helps fluid run out of the client's mouth by gravity and not down their throat, preventing aspiration and B | choking. The nurse should also place an emesis basin, with a towel or waterproof pad underneath, against the client's lower cheek and chin so that the rinsing solution can flow into the basin and not onto the bed linens. c PS", "whyNot": {"a": "The nurse should use chlorhexidine, not hydrogen peroxide, to moisten a soft toothbrush because this antimicrobial solution helps", "b": "The nurse should insert an oral airway, not their thumb or index finger, to keep the client's mouth open.", "d": "The nurse should apply a water-soluble lubricant to the client's lips after oral care."}, "keyConcept": "Oral hygiene for clients who are immobile or unconscious requires special precautions to prevent aspiration, but it also requires meticulous attention to cleaning all tooth surfaces while avoiding injury to the gums. Oral hygiene includes inspecting and cleaning the mucous membranes of the client's mouth with foam swabs or gauze."}, {"id": 10024, "cat": "Emergency Care", "stem": "Which of the following questions is the most appropriate for the nurse to ask a client who is under observation after arrest by the police for public alcohol intoxication? O A.\"Did you start using marijuana when you were 13 years old?\" O B. \"Did you drink 1 liter or 2 liters of alcohol tonight?\" O C. \"How old were you when you first began to use alcohol or drugs?\" @ D. \"What kind of withdrawal symptoms do you feel when you stop taking a drug or alcohol?\" eck Answer", "choices": [{"id": "a", "t": "full nursing assessment should be performed in clients who appears intoxicated, as the client may have sustained traumatic injuries not"}, {"id": "b", "t": "This option is incorrect because it is a closed-ended question. Open-ended questions would include \"How much alcohol do you drink?\""}, {"id": "c", "t": "A of When caring for a client who is intoxicated, it's important for the nurse to remain non-judgmental."}, {"id": "d", "t": "A better way to ask this question would be “Have you experienced withdrawal symptoms if you stopped using a drug?\" and \"Can you"}], "correct": "c", "rationale": "A of When caring for a client who is intoxicated, it's important for the nurse to remain non-judgmental. The nurse recognizes that substance use c | disorder is a medical illness and will complete a full nursing assessment. The client should be questioned about co-ingestion of other e@D ; substances. It's important to realize that some medical conditions may result in the appearance of intoxication. Observation may be necessary for a period of time. The client's condition will improve over hours as the alcohol is metabolized. The nurse should be responsive, supportive, and accepting in interactions with the client. An open-ended question can help the nurse to establish a relationship of trust. It may encourage the client to identify important issues and feelings that contribute to the substance abuse.", "whyNot": {"b": "This option is incorrect because it is a closed-ended question. Open-ended questions would include \"How much alcohol do you drink?\"", "d": "A better way to ask this question would be “Have you experienced withdrawal symptoms if you stopped using a drug?\" and \"Can you"}, "keyConcept": "A full nursing assessment should be performed in clients who appears intoxicated, as the client may have sustained traumatic injuries not immediately visible or they may have a medical condition that resulted in the appearance of intoxication. When caring for an intoxicated client, the nurse should remain nonjudgmental. Open-ended questions can establish trust and may allow the client to identify feelings or events that led to abuse of alcohol or other substances. The nurse should offer information about resources for treatment."}, {"id": 10025, "cat": "Emergency Care", "stem": "RR 22/minute; BP 88/58 mmHg. The client's rhythm is shown below. Which of the following nursing interventions is most appropriate?", "choices": [{"id": "a", "t": "Prepare to administer amiodarone"}, {"id": "b", "t": "Prepare for cardioversion"}, {"id": "c", "t": "Prepare to assist the physician with endotracheal intubation"}, {"id": "d", "t": "Administer keterolac IV as ordered"}], "correct": "b", "rationale": "The client has unstable wide complex tachycardia, so immediate cardioversion is indicated.", "whyNot": {"a": "Amiodarone is a medication used to treat cardiac arrhythmias. If the client is unstable, immediate cardioversion is indicated.", "c": "The client is still breathing on his own; he may need intubation if he becomes unresponsive and is unable to protect his airway or if he", "d": "Ketorolac is an anti-inflammatory pain medication that can be given IV; however, it is not indicated in this situation."}, "keyConcept": "When evaluating a client with tachycardia (heart rate greater than 100 BPM) and symptoms of poor perfusion, it's important to determine if the client’s rhythm is causing poor perfusion and subsequent symptoms. Unstable tachycardia refers to tachycardia in which the client’s rate and rhythm are causing signs and symptoms of cardiovascular compromise and signs of poor perfusion, including hypotension, altered mental status, or ischemic chest pain. Immediate cardioversion is indicated."}, {"id": 10026, "cat": "Emergency Care", "stem": "A nurse in an emergency department is admitting a child who experienced a seizure. Which of the following diagnostic tests should the nurse anticipate the provider prescribing?", "choices": [{"id": "a", "t": "Electroencephalogram"}, {"id": "b", "t": "Electrocardiogram"}, {"id": "c", "t": "Fibrinogen level"}, {"id": "d", "t": "Indirect Coombs test"}], "correct": "a", "rationale": "An electroencephalogram is performed to assess for epilepsy by detecting abnormal brain waveforms. Seizure activity is diagnosed by B i at abnormal or absent waveforms. c | 2%", "whyNot": {"b": "An electrocardiogram is performed to assess for long QT syndrome or dysrhythmias.", "c": "A fibrinogen level is used in the diagnosis of bleeding disorders and to identify clients at risk for coronary heart disease and stroke.", "d": "An indirect Coombs test detects antibodies to RBCs in the serum prior to a client receiving a blood transfusion."}, "keyConcept": "Seizures are caused by abnormal electrical activity in the brain. The provider will prescribe laboratory and diagnostic tests, such as an EEG, lumbar puncture, and toxicology screen, to determine the cause of the seizure and location of the seizure activity in the brain."}, {"id": 10027, "cat": "Emergency Care", "stem": "A nurse in an emergency department is assigned to care for a client diagnosed with benzodiazepine ingestion. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Administer flumazenil."}, {"id": "b", "t": "Determine the client's level of orientation."}, {"id": "c", "t": "Administer activated charcoal."}, {"id": "d", "t": "Prepare the client for gastric lavage."}], "correct": "b", "rationale": "A | | 23% Moderate The first action the nurse should take when using the nursing process is to assess the client. Identifying the client's level of orientation is the OB a aan fo priority action because lethargy, drowsiness, and confusion are symptoms of benzodiazepine toxicity. I © 5%", "whyNot": {"a": "Administering flumazenil is sometimes an appropriate action for severe benzodiazepine toxicity, but it is not universally appropriate.", "c": "The nurse should administer activated charcoal and a saline cathartic after performing gastric lavage to promote the elimination of", "d": "The nurse should prepare to remove the benzodiazepine that remains in the client's stomach by administering gastric lavage. However,"}, "keyConcept": "The use of benzodiazepines is common for clients who have anxiety disorders, sleep disorders, and various other conditions. While benzodiazepine toxicity is rare with oral administration of these medications, it can occur when the benzodiazepine is combined with another agent, such as alcohol. Significant respiratory and cardiovascular complications are not common however. The nurse should ensure the client has an IV access so that fluids or norepinephrine can be administered to support the blood pressure. The nurse should also monitor oxygen saturation and ensure the client's airway is patent."}, {"id": 10028, "cat": "Emergency Care", "stem": "A nurse in the Emergency Department is assisting with a peritoneal lavage. Which best describes the purpose of this procedure?", "choices": [{"id": "a", "t": "To drain excess fluid from the stomach"}, {"id": "b", "t": "To remove fecal buildup in the lower gastrointestinal tract"}, {"id": "c", "t": "To assess for bleeding in the abdominal cavity"}, {"id": "d", "t": "To view the structures of the upper gastrointestinal tract"}], "correct": "c", "rationale": "i 35% Hard 3 i 18% Aperitoneal lavage is performed by inserting a catheter into the peritoneal cavity and aspirating the fluid inside with a syringe. It is most commonly performed to assess for bleeding in the abdominal cavity in clients who have experienced blunt trauma. Peritoneal lavage may also be performed to irrigate the peritoneal cavity in individuals with an intra-abdominal abscess; to obtain cells for cytology testing in ec | 45% individuals with cancer; and to instill warm fluids in severely hypothermic individuals.", "whyNot": {"a": "This describes a gastric lavage, not a peritoneal lavage.", "b": "This describes an enema, not a peritoneal lavage.", "d": "This describes an endoscopy, not a peritoneal lavage."}, "keyConcept": "Peritoneal lavage is most commonly performed as a diagnostic test in individuals who have experienced blunt trauma to identify intra- abdominal hemorrhage. The test provides information about injury to the solid or hollow organs, and peritoneal penetration. The procedure is performed by inserting a catheter into the peritoneal cavity to aspirate blood or fluid, although fluid may be infused to lavage the cavity, Sterility must be maintained to avoid introduction of microorganisms into the abdominal cavity. The procedure is contraindicated in hemodynamically unstable clients who require surgery; in clients with adhesions, abdominal wall hematoma, or coagulopathy."}, {"id": 10029, "cat": "Emergency Care", "stem": "@ @ & Viraln. x Record M Inbox( ™ Inbox- ] Untitle: Untitle’ (4 Google @ TEASF Online @& MarkkK | @ Micros (eeuWanes ce Nae ire ® Atte, € > @G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "mother calls the clinic after her 4-year-old choked on a peanut. The mother reports that she performed abdominal thrusts and the child is breathing normally now. The nurse should tell the mother to:"}, {"id": "b", "t": "The child’s mother does not need to test the child’s urine for internal bleeding; she should bring the child to the ER."}, {"id": "c", "t": "The mother should first bring the child to the emergency room, rather than waiting for symptoms to develop."}, {"id": "d", "t": "The mother should have the child checked in the ER rather than looking for symptoms of a pneumothorax."}], "correct": "a", "rationale": "The nurse should instruct the mother to bring the child to the ER. If aspirated, nuts may swell, leading to an airway obstruction after the initial event; endoscopy may be needed to remove fragments.", "whyNot": {"b": "The child’s mother does not need to test the child’s urine for internal bleeding; she should bring the child to the ER.", "c": "The mother should first bring the child to the emergency room, rather than waiting for symptoms to develop.", "d": "The mother should have the child checked in the ER rather than looking for symptoms of a pneumothorax."}, "keyConcept": "Common causes of children choking include foods, particularly small hard foods; coins; and toys. Foods that present a choking hazard to small children include small hard foods, including peanuts or seeds; small round foods, including berries and raisins; thick pastes like peanut butter,; fibrous foods and stringy foods like celery; and foods with leaves and stems."}, {"id": 10030, "cat": "Emergency Care", "stem": "Scale. This score is consistent with which of the following? O A Mild head injury O B. Moderate head injury O C. Severe head injury O D. Vegetative state", "choices": [{"id": "a", "t": "Ascore of 8 indicates a severe head injury, not a mild head injury."}, {"id": "b", "t": "A score of 8 indicates a severe head injury, not a head injury."}, {"id": "c", "t": "The Glasgow Coma Scale is a neurological assessment tool used to describe clients with traumatic head injury."}, {"id": "d", "t": "A score of 8 indicates a severe head injury, not a vegetative state."}], "correct": "c", "rationale": "The Glasgow Coma Scale is a neurological assessment tool used to describe clients with traumatic head injury. Clients receive a score for each of three neurological responses to stimuli. The responses that are graded include eye opening, verbal response, and motor response. The lowest score is 3 and the highest score is 15. A score of 8 or less indicates a severe head injury.", "whyNot": {"a": "Ascore of 8 indicates a severe head injury, not a mild head injury.", "b": "A score of 8 indicates a severe head injury, not a moderate head injury.", "d": "A score of 8 indicates a severe head injury, not a vegetative state."}, "keyConcept": "The Glasgow Coma Scale provides an accurate way to describe the neurological status of a client with a head injury and to measure and document any changes in the condition. The chart below shows the three areas in which responses to stimuli are graded. Possible scores range from 3 to 15. Lower scores indicate more significant head injury."}, {"id": 10031, "cat": "Emergency Care", "stem": "client have? O A. Grade O > B.Grade ll O c.Grade tl! © b.Grade iv", "choices": [{"id": "a", "t": "A grade open fracture has only minimal superficial skin damage."}, {"id": "b", "t": "A grade II open fracture has damaged the skin and part of the muscle but does not have extensive tissue damage."}, {"id": "c", "t": "This client has a Grade III open fracture, which involves excessive tissue, nerve, and vascular damage."}, {"id": "d", "t": "There is no grade IV open fracture classification."}], "correct": "c", "rationale": "This client has a Grade III open fracture, which involves excessive tissue, nerve, and vascular damage. Grade | open fractures have minimal superficial skin damage, and a Grade II open fracture has damaged the skin and part of the muscle but not with extensive tissue damage. Open fractures are graded only as Grade |, Grade Il and Grade III.", "whyNot": {"a": "A grade | open fracture has only minimal superficial skin damage.", "b": "A grade II open fracture has damaged the skin and part of the muscle but does not have extensive tissue damage.", "d": "There is no grade IV open fracture classification."}, "keyConcept": "To prevent infection in a client with a grade III fracture, the nurse must observe strict aseptic technique when cleaning the wound or changing the dressing. Other complications associated with fractures include hypovolemic shock due to hemorrhage; fat embolism syndrome; and compartment syndrome."}, {"id": 10032, "cat": "Emergency Care", "stem": "A nurse is performing an assessment of a client who has arrived in the emergency department complaining of abdominal pain. For which condition would the nurse most likely assess by using the obturator sign?", "choices": [{"id": "a", "t": "Ascites"}, {"id": "b", "t": "Gallbladder disease"}, {"id": "c", "t": "Appendicitis"}, {"id": "d", "t": "Hernia"}], "correct": "c", "rationale": "A | % Moderate The obturator test is performed to assess for appendicitis. During the test, the client lies on his back with the hip and knee flexed at 90 B | at degrees. The practitioner grips the client’s ankle and turns it to flexion and internal rotation of the hip. If the client feels pain in the area of the right lower quadrant, it is said to be a positive sign. There are no laboratory studies specific for appendicitis, but ultrasound or CT ec | 10% scanning are helpful for diagnosis. Pain typically begins in the area of the umbilicus and migrates to the right lower quadrant of the D Hi 15% abdomen.", "whyNot": {"a": "Ascites involves excess fluid in the abdomen, causing abdominal distention. Ascites is not assessed using the obturator sign. A client with", "b": "The obturator sign is not used to assess gallbladder disease. A positive Murphy's sign is indicative of gallbladder disease.", "d": "A hernia is not assessed using the obturator test."}, "keyConcept": "Appendicitis is inflammation of the lining of the appendix and is a common surgical emergency characterized by acute abdominal pain. The obturator sign is present when the internal rotation of the thigh elicits pain. The psoas sign is present when the extension of the right thigh elicits pain, consistent with retroperitoneal or retrocecal appendicitis."}, {"id": 10033, "cat": "Emergency Care", "stem": "110/65 mmHg sitting with a heart rate of 100/min. Which of the following tasks should the nurse perform next?", "choices": [{"id": "a", "t": "Check the client’s blood pressure and pulse while standing."}, {"id": "b", "t": "Document normal orthostatic blood pressure and pulse."}, {"id": "c", "t": "Assess the client’s neurological function with finger-to-nose testing and heel-to-toe walking."}, {"id": "d", "t": "Anticipate administration of intravenous crystalloid solution."}], "correct": "d", "rationale": "Correct Answer: D. Anticipate administration of intravenous crystalloid solution. A — B Orthostatic blood pressure and pulse measurement should be performed with the client supine, sitting, then standing, allowing 2 minutes c | between each change of position. A drop in systolic blood pressure of 20 mmHg or more or a drop in diastolic blood pressure of 10 mmHg or Op | more between positions reflects a positive test for orthostatic or postural hypotension. The heart rate usually rises 20 beats per minute or more with orthostasis. Orthostatic hypotension results from significant volume loss or dehydration, usually at least 25% of blood volume. The body’s compensatory loss in response to fluid deficit is vasoconstriction, preventing blood from pooling in the extremities when the individual is upright. This allows perfusion of the heart and brain. With significant blood loss or volume loss, the body’s compensatory mechanisms are overwhelmed. The clinical manifestations of postural hypotension include dizziness, syncope, blurred vision, and weakness.", "whyNot": {"a": "This client has demonstrated postural hypotension, and further testing may result in a fall.", "b": "A drop in systolic blood pressure of 20 mmHg or more or a drop in diastolic blood pressure of 10 mmHg or more between positions reflects", "c": "The priority is fluid replacement. Although neurologic testing should be performed, this client should not be walking since orthostatic"}, "keyConcept": "Orthostatic hypotension refers to a significant drop in blood pressure (20 mm Hg systolic, 10 mm Hg diastolic) or increase in heart rate > 20/minute when the client's blood pressure or heart rate is measured while supine, then while sitting or standing. It usually represents significant volume loss, although it may represent a medication effect that blunts normal postural reflexes."}, {"id": 10034, "cat": "Emergency Care", "stem": "A nurse is monitoring a client who is in the telemetry unit and notes the following on the rhythm strip (see image below). This is an example of which of the following? =", "choices": [{"id": "a", "t": "First-degree AV block"}, {"id": "b", "t": "Third-degree AV block"}, {"id": "c", "t": "Premature ventricular contraction"}, {"id": "d", "t": "Torsades de pointes 100} 2 = o 2 ° a [R"}], "correct": "c", "rationale": "8 13% The rhythm strip shows a premature ventricular contraction or PVC. This refers to an ectopic beat that originates from a cardiac pacemaker ec FY 66% in the ventricle. The depolarization wave is initiated outside the His-Purkinje conduction system, so it travels slowly throughout the D i 10% ventricles, resulting in a wide QRS complex, usually longer than 120 ms. The beat is not preceded by a P wave, which represents an atrial pacemaker. The T wave, which represents repolarization, is usually large and oriented in the opposite direction of the QRS complex. PVCs may occur in a healthy heart or in individuals with heart disease, including ischemic heart disease. Conditions that lower the threshold for ventricular pacemaker cells to activate include increased sympathetic stimulation and electrolyte disturbances, including hypokalemia. Myocarditis, myocardial ischemia, cardiomyopathy, and myocardial contusion can also result in PVCs. The clinical significance depends on the frequency of the ectopic beats and whether there is a hemodynamic change in response.", "whyNot": {"a": "First-degree AV block is represented by a prolonged PR interval (>0.20 seconds).", "b": "Third-degree AV block refers to complete dissociation of the atria and ventricles. On ECG, the P waves and QRS complexes have no", "d": "Torsades de pointes refers to a type of polymorphic ventricular tachycardia. ECG shows variable amplitudes of QRS complexes, which"}, "keyConcept": null}, {"id": 10035, "cat": "Emergency Care", "stem": "associated with this rhythm? O A. Hypervolemia, hypoxia, hypothermia, hypokalemia, and hydrogen ion accumulation O B. Hypovolemia, hypoxia, hypothermia, hyperkalemia, hypokalemia, and hydrogen ion accumulation O C. Hypovolemia, hypoxia, hypothermia, hypercalcemia, hypokalemia, and hydrogen ion accumulation O D. Hypovolemia, hypoxia, hypothermia, hyperkalemia, hypokalemia, and oxygen ion accumulation", "choices": [{"id": "a", "t": "Hypervolemia, hypoxia, hypothermia, hypokalemia, and hydrogen ion accumulation"}, {"id": "b", "t": "Hypovolemia, hypoxia, hypothermia, hyperkalemia, hypokalemia, and hydrogen ion accumulation"}, {"id": "c", "t": "Hypovolemia, hypoxia, hypothermia, hypercalcemia, hypokalemia, and hydrogen ion accumulation"}, {"id": "d", "t": "Hypovolemia, hypoxia, hypothermia, hyperkalemia, hypokalemia, and oxygen ion accumulation"}], "correct": "b", "rationale": "A || 12% Moderate The classic H signs and symptoms considered as possible causes of pulseless electrical activity are hypovolemia, hypoxia, hypothermia, OB a oa either hyperkalemia or hypokalemia, and hydrogen ion accumulation. Hydrogen ion accumulation refers to acidosis. ° c i 23%", "whyNot": {"a": "These are correct except that hypervolemia is not an \"H\" associated with PEA.", "c": "Hypercalcemia is not one of the H's associated with PEA.", "d": "Oxygen ion accumulation is not one of the H's associated with PEA."}, "keyConcept": "PEA refers to any organized rhythm that does not result in a pulse, including sinus rhythm without a pulse, with the exception of ventricular"}, {"id": 10036, "cat": "Emergency Care", "stem": "Which of the following principles govern the management of radiation contamination in a disaster?", "choices": [{"id": "a", "t": "Treat victims with the most severe symptoms first."}, {"id": "b", "t": "Treat victims at the greatest distance from the source first."}, {"id": "c", "t": "Victims with copious secretions have the greatest exposure and should be treated first."}, {"id": "d", "t": "The extent of dysphagia and ptosis should be monitored to determine exposure."}], "correct": "b", "rationale": "Triage in radiation exposure incidents prioritizes treatment of victims at the greatest distance from the source. Radiation exposure damage is c || dependent on distance and time. With greater distance and less time for exposure, dosage is diminished. Clients who are at the greatest D | distance will experience less damage and are therefore more salvageable in a disaster. Disaster triage is governed by the principle of using available resources to do the most good for the most people. Victims of radiation exposure initially appear well. The phases of acute radiation sickness include a prodrome, latent phase, manifest phase, and either recovery or death. Radiation causes internal cellular damage that is not immediately apparent.", "whyNot": {"a": "Most victims of radiation exposure initially appear well. Since damage is a function of time and distance, the greatest good for the most", "c": "Neurotoxins, such as sarin gas, result in cholinergic syndromes characterized by vomiting, diarrhea, hypersalivation, copious mucus", "d": "Dysphagia and ptosis are consistent with descending paralysis of the cranial nerves, caused by botulism. Botulism toxin is released by the"}, "keyConcept": "Radiation exposure results in cellular damage that is not immediately apparent. The severity of injury depends upon the distance from the radiation source and the length of exposure. Triage in a radiation exposure disaster prioritizes individuals who were at the greatest distance from the radiation source, resulting in a lower dose of radiation compared to the dose received by those close to the source."}, {"id": 10037, "cat": "Emergency Care", "stem": "(ICP) monitoring. The nurse should monitor the client for which of the following complications related to the ventriculostomy?", "choices": [{"id": "a", "t": "Headache"}, {"id": "b", "t": "Infection"}, {"id": "c", "t": "Bradypnea"}, {"id": "d", "t": "Hypertension"}], "correct": "b", "rationale": ", which is a potential complication of this procedure. The nurse OB a Gar: should use strict asepsis when caring for the client and the ICP monitoring equipment to avoid a life-threatening condition like meningitis. I ° © 6%", "whyNot": {"a": "The nurse should monitor a client who has a head injury for a headache; however, a headache does not indicate a complication directly", "c": "The nurse should monitor a client who has a head injury for slow respirations as well as for decreased oxygen saturation levels; however,", "d": "The nurse should monitor a client who has a ventriculostomy for hypertension; however, this is not a complication directly related to the"}, "keyConcept": "Invasive procedures and equipment, such as an intraventricular catheter, are used to monitor the intracranial pressure (ICP) of clients who have traumatic head injuries. These systems also provide access to cerebrospinal fluid for sampling and drainage. Because the catheter goes through the skull and directly into the ventricle of the brain, there is a potential for infection. Therefore, nurses must be careful to maintain strict asepsis while caring for these clients to avoid such a complication."}, {"id": 10038, "cat": "Emergency Care", "stem": "demonstrating which of the following ethical principles?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Autonomy"}, {"id": "c", "t": "Justice"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "d", "rationale": "‘i The ethical principle of nonmaleficence is demonstrated by taking actions to prevent client harm. When the nurse completes an advanced B ] education program to provide safe care in the ICU, the nurse is demonstrating the ethical principle nonmaleficence.", "whyNot": {"a": "The ethical principle of veracity is the duty to tell the truth.", "b": "The ethical principle of autonomy is respecting the client's right to make decisions about health care.", "c": "The ethical principle of justice is the duty to treat everyone equally, regardless of sex, gender identity, sexual orientation, race, culture, or"}, "keyConcept": "Nurses have an obligation to help others and promote the general good while doing no harm. When the nurse completes an advanced education program to provide safe care, the nurse is demonstrating the ethical principle nonmaleficence."}, {"id": 10039, "cat": "Emergency Care", "stem": "@ @ X& Viralm sx Record M Inbox( M Inbox- ] Untitle: Untitle (4 Google @ TEASP Online MarkK @ Micros (neusovtlacticl @ ATITE @ Newcl |. nc x) + v € > G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "0%"}, {"id": "b", "t": "0%"}, {"id": "c", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "d", "t": "0%"}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}, {"id": 10040, "cat": "Emergency Care", "stem": "Ahealthcare provider in the emergency department has ordered gastric lavage for a client with a drug overdose. Which of the following nursing actions is appropriate?", "choices": [{"id": "a", "t": "Place the client in the Trendelenburg position during lavage."}, {"id": "b", "t": "Use a small-bore nasogastric tube for lavage."}, {"id": "c", "t": "Lavage is most effective after 1-2 hours."}, {"id": "d", "t": "Suction supplies should be available at the bedside."}], "correct": "d", "rationale": "Gastric lavage, when performed for decontamination of the stomach, is performed as soon as possible after a potentially fatal overdose. An © I orogastric tube is used to remove any ingested toxins and to irrigate the stomach. There is a high risk of associated complications, so gastric ep FY lavage is only performed within an hour of potentially lethal overdose. Gastric lavage was also performed routinely in the past in clients with hematochezia, but it is not a sensitive test to distinguish upper from lower Gl bleeding. Complications of gastric lavage include aspiration, perforation of the GI tract, and arrhythmia. Suction supplies should be placed at bedside in case of aspiration. Supplies should also be available for endotracheal intubation in the event that the client develops respiratory distress. Activated charcoal is more commonly used to decontaminate the GI tract, with sorbitol to aid in evacuation of the bowel. Activated charcoal is ineffective for some toxins, including alcohol, lithium, iron.", "whyNot": {"a": "Gastric lavage is associated with a risk of aspiration. The client should be placed on the side, and the head of the bed should be elevated to", "b": "A large-bore orogastric tube is used for gastric lavage so that ingested toxins such as pills can be removed and the stomach can be", "c": "Gastric lavage is ineffective after more than an hour has elapsed from the ingestion. Although it is important to decompress the stomach,"}, "keyConcept": "Contraindications to gastric lavage for decontamination of the Gl tract in overdose include ingestion of a caustic agent, hydrocarbon ingestion, and unprotected airway. The procedure is reserved primarily for potentially lethal overdoses within an hour of ingestion of the toxic product."}, {"id": 10041, "cat": "Emergency Care", "stem": "A nurse in the emergency department is caring for a client with a score of 11 on the Glasgow Scale. What does this score indicate?", "choices": [{"id": "a", "t": "The client has a brain injury"}, {"id": "b", "t": "The client has a high level of consciousness"}, {"id": "c", "t": "The client is at risk for falls and injuries"}, {"id": "d", "t": "The client is at risk for skin breakdown"}], "correct": "a", "rationale": "The Glasgow Coma Scale is used to objectively assess the level of brain damage and the level of consciousness. A score of 11 indicates that the client has a moderate brain injury and moderately impaired level of consciousness. This scale assesses and then scores indicators such as eye-opening, verbal responses, motor responses, and movement. Scores of 8 or less indicate severe damage; scores more than 13 indicate mild damage. Other scales measure risk for falls and risk for skin breakdown.", "whyNot": {"b": "This score indicates the client has a moderate brain injury and not a high level of consciousness.", "c": "The Glasgow Coma Scale does not assess for falls in a client.", "d": "The Glasgow Coma Scale does not assess risk for skin breakdown."}, "keyConcept": "The Glasgow Coma Scale provides a standardized method to describe and monitor changes in a client's neurological status after a traumatic brain injury. The score, known as GCS, ranges from 3 to 15. The client's verbal, motor, and eye opening responses to stimuli are graded and added together to arrive at the client's GCS."}, {"id": 10042, "cat": "Emergency Care", "stem": "A client experiencing anaphylaxis after exposure to an allergen is having which of the following types of reaction?", "choices": [{"id": "a", "t": "Typel O B.typell O ctype O p.typelv eck Answer"}, {"id": "b", "t": "An example of a type I! reaction is ABO blood incompatibility. It is mediated by IgG and IgM and can lead to hemolytic anemia."}, {"id": "c", "t": "Atype Ill hypersensitivity reaction is caused by the formation of antigen-antibody complexes in serum and includes drug fever and"}, {"id": "d", "t": "A type IV hypersensitivity reaction is delayed, often by up to several days. It is mediated by T cells and can include transplant rejection."}], "correct": "a", "rationale": "Atype | allergic or hypersensitivity reaction is mediated by IgE. It occurs when an allergen binds with free IgE, which then binds to basophils and mast cells, causing the release of histamine. The initial reaction may be less severe, but over subsequent exposures, the response can increase. Clinical manifestations may include wheezing, urticaria, and hypotension. Severe anaphylaxis can lead to death. Treatment includes IM epinephrine, antishistamines, steroids, and IV fluid support.", "whyNot": {"b": "An example of a type I! reaction is ABO blood incompatibility. It is mediated by IgG and IgM and can lead to hemolytic anemia.", "c": "Atype Ill hypersensitivity reaction is caused by the formation of antigen-antibody complexes in serum and includes drug fever and", "d": "A type IV hypersensitivity reaction is delayed, often by up to several days. It is mediated by T cells and can include transplant rejection."}, "keyConcept": "Anaphylaxis is a type | allergic reaction that is rapid in onset and may cause death. Clinical manifestations include hives, throat or tongue edema, shortness of breath, vomiting, lightheadedness, and hypotension. Common triggers include venom from insect bites or stings, foods, and medication. Foods are the most common trigger in children, but medications and insect bites and stings are more common in older adults. Anaphylaxis ‘Swelling of the conjuctiva —_ — Central nervous system x RF - lightheadedness Sj loss of consciousness alte = confusion headache ~ anxiety ‘Swelling of lips, tongue and/or throat ——~ Respiratory Heart and vasculature shortness of breath \\Po = fast or slow heart rate [3 f heezes or stridor = low blood pressure 4 hoarseness > \\ = pain with swallowing Mi Inbox- — E}_ Untitle: Untitle’ (4 Google @ TEASF Online @& MarkkK | @ Micros (eeuWanes ce Nae ire @® ATITE % CLOSE © Newc) NC x + v Qa * ws * © Cb Finish update : { Browse Questions > iit Search Questions QJ"}, {"id": 10043, "cat": "Emergency Care", "stem": "posture? O A. Legs and feet extended, arms pulled up and tucked into chest O B. Legs and feet flaccid, arms rigid and flexed at the elbows O C. Legs, feet, and arms stiffly extended, hands turned outward and flexed O D. Legs, feet, and arms flaccid with no motor response Check Answer", "choices": [{"id": "a", "t": "Legs and feet extended, arms pulled up and tucked into chest"}, {"id": "b", "t": "Legs and feet flaccid, arms rigid and flexed at the elbows"}, {"id": "c", "t": "Legs, feet, and arms stiffly extended, hands turned outward and flexed"}, {"id": "d", "t": "Legs, feet, and arms flaccid with no motor response Check Answer"}], "correct": "c", "rationale": "All 12% — Easy Decerebrate posturing is a rigid form of posturing that is often exhibited after damage to parts of the brain, including the pons and the midbrain. It is displayed by rigid legs and feet, with the feet extended in plantar flexion; the arms rigidly extended down at the sides and the hands clenched and turned outward. € as 80%", "whyNot": {"a": "This position best describes decorticate posturing; it is not an example of decerebrate posturing.", "b": "A client with decerebrate posturing will have rigid legs and the arms will be extended, not flexed.", "d": "A client with decerebrate posturing will have rigid extremities; the legs, feet, and arms would not be flaccid in this case."}, "keyConcept": "Abnormal posturing is an involuntary flexion or extension of the arms and/or legs, indicating severe brain injury. Decorticate Posturing , Flexed Plantar Nexed Internally rotated Flexed Adducted Decerebrate Posturing"}, {"id": 10044, "cat": "Emergency Care", "stem": "stroke? O A. Fingerstick glucose O B. Urine culture and sensitivity O C. Serum folate O D. Blood arsenic levels", "choices": [{"id": "a", "t": "Fingerstick glucose"}, {"id": "b", "t": "Urine culture and sensitivity"}, {"id": "c", "t": "Serum folate"}, {"id": "d", "t": "Blood arsenic levels"}], "correct": "a", "rationale": "oo ii 51% Hard Signs of stroke include sudden onset of one or more of the following: numbness or weakness of the face, arms, or legs; confusion; difficulty a I aan speaking or understanding others (aphasia); vision changes; ataxia, dizziness; or loss of coordination or balance. Stroke or suspected stroke is an emergency. Initial tests include fingerstick glucose and non-contrast CT scan of the brain. Hypoglycemia must be ruled out, as it can © |_| avr) cause stroke-like symptoms. D | | 24% There are two primary types of stroke, ischemic and hemorrhagic. Ischemic strokes are caused by clots that lodge in an artery and obstruct blood flow to the brain tissue distal to the clot. Hemorrhagic strokes are caused by bleeding in the brain, often due to a ruptured aneurysm. Both types of stroke result in reduced delivery of oxygen to brain tissue, which causes cell death and permanent brain injury. Ischemic strokes can occur as a result of formation of a clot in a cerebral artery (thrombotic) or migration of a thrombus to the brain from another location in the body (embolic.) Thrombolytic therapy is the primary treatment for ischemic stroke in clients who meet the criteria for receiving thrombolytic therapy. Thrombolytic therapy must be given within 3-4 hours of symptom onset to restore perfusion to the affected area of brain tissue before it is irreversibly damaged.", "whyNot": {"b": "Aurine culture and sensitivity tests for the presence and type of bacteria in the urine. This test is not related to stroke or its treatment.", "c": "Serum folate is a blood test used to measure nutritional deficiencies. This test is not related to stroke or its treatment.", "d": "Blood arsenic levels are used to identify toxic levels of arsenic in the body. This test is not related to stroke or its treatment."}, "keyConcept": "The nurse should activate a stroke alert or notify the healthcare provider immediately if a client has suspected stroke. Hypoglycemia should be ruled out by fingerstick glucose, as it can cause stroke-like symptoms. The primary treatment option for ischemic stroke is thrombolytic therapy, usually with tissue plasminogen activator (tPA), to break down the clot. Thrombolytic therapy must be initiated as soon as possible after symptom onset, but hemorrhagic stroke must be ruled out by noncontrast CT scan or MRI before thrombolytic therapy can be initiated. CT scan also rules out brain tumor, which is another contraindication to thrombolytic therapy.The CT scan should be performed within 25 minutes of the client's arrival in the emergency department and should be read by the radiologist within 45 minutes."}, {"id": 10045, "cat": "Emergency Care", "stem": "analyzes the victim and advises a shock. As soon as the shock has been delivered, what is the first step that the nurse must take?", "choices": [{"id": "a", "t": "Immediately resume CPR"}, {"id": "b", "t": "Re-check the victim’s pulse"}, {"id": "c", "t": "Deliver two mouth-to-mouth rescue breaths"}, {"id": "d", "t": "Allow the AED to analyze the victim’s status"}], "correct": "a", "rationale": "Following a shock delivered by an AED, the provider must immediately resume CPR by giving chest compressions at a rate of 100 per minute. After a round of chest compressions, the provider may need to deliver rescue breaths. Another shock may also be advised by the AED, but the first step is to restart CPR.", "whyNot": {"b": "The nurse should start chest compressions right away without checking a pulse.", "c": "The nurse should restart CPR with chest compressions to perfuse vital organs.", "d": "Chest compressions should be restarted immediately."}, "keyConcept": "Defibrillation stuns the heart by depolarizing the myocardium and terminating ventricular fibrillation, to allow the heart’s natural pacemaker to resume an organized rhythm. The organized rhythm must produce effective mechanical activity resulting in a palpable central pulses. The heart may temporarily be in PEA or asystole after a shock, so chest compressions should be resumed immediately after the shock."}, {"id": 10046, "cat": "Emergency Care", "stem": "A nurse is caring for a client on the telemetry unit and sees the following rhythm on the monitor. Which of the following is the priority action by the nurse?", "choices": [{"id": "a", "t": "Place an oropharyngeal or nasopharyngeal airway"}, {"id": "b", "t": "Begin chest compressions"}, {"id": "c", "t": "Request a 12-lead ECG"}, {"id": "d", "t": "Call the healthcare provider"}], "correct": "b", "rationale": "The rhythm is ventricular fibrillation, a terminal rhythm that indicates cardiac arrest. Immediate initiation of CPR, beginning with chest compressions, is associated with improved outcomes. Defibrillation should be performed as soon as the defibrillator or AED is available. Ventricular fibrillation represents chaotic electrical activity in the heart with ineffective pumping and no cardiac output. Defibrillation stuns the heart and stops the electrical activity, allowing the natural pacemaker to take over.", "whyNot": {"a": "The sequence of CPR is compression, airway, then breathing. The airway can be opened by the head tilt/chin lift maneuver.", "c": "This is not an immediate priority.", "d": "It is essential to begin CPR immediately. The healthcare provider can be notified when the resuscitation is concluded."}, "keyConcept": "Ventricular fibrillation is a terminal rhythm that will progress to asystole and death if not treated promptly. The client should be defibrillated as soon as a defibrillator is available. Chest compressions should be initiated immediately while awaiting a defibrillator, in order to perfuse vital organs."}, {"id": 10047, "cat": "Emergency Care", "stem": "applies electrodes to the client's chest and limbs and the electrocardiogram (ECG) monitor shows complete heart block. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Transport the client to the cardiovascular laboratory."}, {"id": "b", "t": "Prepare the client for insertion of a transvenous pacemaker."}, {"id": "c", "t": "Activate the emergency response system and be prepared to perform CPR."}, {"id": "d", "t": "Apply transcutaneous pacemaker pads."}], "correct": "d", "rationale": "Ai The greatest risk to this client is injury or death from inadequate cardiac output and tissue perfusion. Therefore, the first action the nurse B ] should take is to apply transcutaneous pacemaker pads and begin external pacing of the heart until a temporary transvenous or permanent implanted pacemaker can be placed. Transcutaneous pacing is appropriate for emergency use, but it is intended only for short periods of c | time because it causes the client significant discomfort. @D |", "whyNot": {"a": "The nurse should plan to transport the client to the cardiovascular laboratory for placement of a temporary pacemaker under fluoroscopy", "b": "The nurse should plan to prepare the client for the possible insertion of a transvenous pacemaker by cleansing the skin in the likely", "c": "Although the client still has a palpable pulse and is breathing, the client is at risk for imminent cardiac arrest because of the complete"}, "keyConcept": "Cardiac dysrhythmias and their effects on the client range from mild to critical. The nurse must assess the client for signs and symptoms, their contributing factors, frequency, severity, manifestations of diminishing cardiac output, and changes in the client's level of consciousness. In the hospital setting, emergency equipment and personnel are readily available, but the nurse must recognize when and how they should be used. Emergency procedures can be performed without written consent if the client is not coherent and no designated client advocate is available."}, {"id": 10048, "cat": "Emergency Care", "stem": "Which of the following intravenous solutions is most likely to be infused rapidly to resuscitate an adult who is in hypovolemic shock due to a GI bleed?", "choices": [{"id": "a", "t": "Dextrose 2.5% and water"}, {"id": "b", "t": "Dextrose 5% and lactated Ringer’s solution"}, {"id": "c", "t": "0.45% sodium chloride"}, {"id": "d", "t": "0.9% sodium chloride"}], "correct": "d", "rationale": ". Clients in B | mer hypovolemic shock due to hemorrhage usually compensate initially by vasoconstriction, but if blood loss continues, the fluid in the extravascular space moves into the vascular space to maintain perfusion. Use of an isotonic solution allows the water in solution to travel c | ™% freely between the body fluid compartments to make up a whole-body water deficit. Crystalloid and colloid intravenous solutions do not @ , so blood products are required in severe shock after infusion of 2 liters of an isotonic crystalloid.", "whyNot": {"a": "This is a hypotonic solution, with an osmolality that is less than the osmolality of the extracellular fluid. When infused into the circulatory", "b": "This is a hypertonic solution, with a greater osmolality than extracellular fluid. Infusion of a hypertonic solution into the extracellular", "c": "This is a hypotonic solution, and infusion will result in a shift of body fluids from the intravascular compartments into the interstitial"}, "keyConcept": "Asolution is isotonic when the concentration of dissolved particles is similar to that of plasma. Infused isotonic solution remains within the extracellular fluid compartment and is distributed between the intravascular and interstitial spaces, resulting in increased intravascular volume. Isotonic intravenous solutions include 0.9% sodium chloride (0.9% NaCl), lactated Ringer's solution, 5% dextrose in water (D5W), and Ringer's solution."}, {"id": 10049, "cat": "Emergency Care", "stem": "A client is admitted after severe burn injury and is undergoing fluid resuscitation. Which of the following is the most accurate assessment of successful fluid resuscitation?", "choices": [{"id": "a", "t": "Urine output of >30 mL/hr"}, {"id": "b", "t": "Weight gain of 1 kg in 8 hours with good capillary refill"}, {"id": "c", "t": "Heart rate of 94/min with blood pressure of 95/55 mmHg"}, {"id": "d", "t": "Serum potassium level decrease from 5.8 mEq/L to 5.2 mEq/L"}], "correct": "a", "rationale": "Urine output of at least 30 mL/hour or 0.5 mL/kg/hr suggests that the kidneys are perfused and is the best indicator of resuscitation in a burn Cc I client. D i Burn clients experience an inflammatory response to cellular injury. Mast cells release histamine and other chemical mediators, which cause an increase in capillary permeability. As a result, fluids leak into the interstitial space (\"third-spacing\"), and the client may experience hypovolemic shock. An indwelling urinary catheter should be used to monitor fluid resuscitation. An isotonic crystalloid, such as lactated Ringer’s solution, is used for fluid resuscitation in burn victims.", "whyNot": {"b": "A rapid weight change can indicate failure of the kidneys to eliminate fluid, with a continuing shift of fluid to the third space. Excessive", "c": "Amean arterial pressure of 65 mmHg or more or a systolic pressure of 90 or more with a heart rate less than 120/minute suggest an", "d": "Resolution of hyperkalemia is one indicator of improving hemodynamic status, but urine output is the key indicator of improved tissue"}, "keyConcept": "The Parkland Formula is commonly used to estimate fluid resuscitation needs in the first 24 hours after a severe burn. The fluid requirement is estimated for adults by using the \"Rule of 9's\" to calculate percentage of body area burned: 9% for each arm, 18% for each leg, 9% for head,18% for front torso, 18% for back torso. The amount of fluid needed is 4 ml x %TBSA x weight (kgs.)50% of fluid is given in the first 8 hours and the remainder is given over 16 hours. Children and older adults may require smaller volumes."}, {"id": 10050, "cat": "Emergency Care", "stem": "A nurse is caring for a client who was admitted to the emergency department with hematemesis. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Give supplemental oxygen by nasal cannula"}, {"id": "b", "t": "Insert a urinary catheter"}, {"id": "c", "t": "Establish IV access with a large-bore IV"}, {"id": "d", "t": "Insert a nasogastric tube"}], "correct": "c", "rationale": "A || 12% Moderate Hematemesis refers to bloody vomitus, which may be bright red or have a “coffee ground” appearance. It can be the result of bleeding , including the esophagus, stomach, or duodenum. Initial treatments are pharmacologic interventions to decrease bleeding and acid production. Endoscopic treatment is the first invasive step in management and is used for diagnosis and ec | Tm treatment. Nursing diagnoses include a risk for decreased cardiac output related to blood loss; deficient fluid volume related to acute blood D i 10% loss and loss of gastric secretions; ineffective peripheral tissue perfusion related to loss of volume; anxiety related to the bleeding, hospitalization, and outcomes; and source of bleeding. The priority nursing action is to establish a large-bore IV for rapid replacement of a fluid or blood as prescribed. Rapid hemorrhage can quickly result in cardiac arrest resulting from decreased tissue perfusion and cardiac 2 8 output. & =) a = ay", "whyNot": {"a": "Supplemental oxygen can be given if necessary. But, with rapid hemorrhage, it is more important to establish IV access for replacement of", "b": "Aurinary catheter should be placed to record Is and Os. It is a reliable indicator of volume status.", "d": "A nasogastric tube may be placed for gastric lavage and to reduce distention of the stomach. Gastric lavage has uncertain efficacy for"}, "keyConcept": "Significant upper GI bleeding is usually caused by erosion of a peptic ulcer into a blood vessel or by bleeding esophageal varices. Anticipating the need for volume replacement with crystalloids and/or blood products, the nurse should establish one, preferably two, large bore intravenous lines."}, {"id": 10051, "cat": "Emergency Care", "stem": "pneumothorax? O A. Cheyne-Stokes respiration O B. Increased fremitus O C. Diminished or absent breath sounds on the affected side O D. Decreased sensation on the affected side", "choices": [{"id": "a", "t": "Cheyne-Stokes respiration"}, {"id": "b", "t": "Increased fremitus"}, {"id": "c", "t": "Diminished or absent breath sounds on the affected side"}, {"id": "d", "t": "Decreased sensation on the affected side"}], "correct": "c", "rationale": "al 4% Easy Accumulation of air in the pleural space after a crushing chest injury may be assessed by unilateral diminished or absent breath sounds. Pain B | 3\" occurs at the injury site and increases with inspiration.", "whyNot": {"a": "Cheyne-Stokes respiration is not an indication of a pneumothorax.", "b": "Increased fremitus indicates injury but is not a sign of a pneumothorax.", "d": "Decreased sensation on the affected side is not associated with a pneumothorax."}, "keyConcept": "A pneumothorax refers to air in the pleural space, a potential space formed by the membranes covering the lung and lining the chest wall. This potential space normally has a negative pressure, but entry of air into the space results in positive pressure that collapses the lung on the affected side. As a result, breath sounds on the affected side will be absent or diminished. Other signs and symptoms of pneumothorax include chest pain and shortness of breath. A chest tube is used to seal the pleural space, drain fluid, prevent further entry of air. In tension pneumothorax, air continues to enter the pleural space and accumulates, resulting in tracheal deviation, shift of the mediastinum, and flattening of the diaphragm on the affected side. A tension pneumothorax is a medical emergency that can result in hemodynamic collapse and death. If tension pneumothorax occurs, immediate decompression with a needle is indicated prior to placement of a chest tube."}, {"id": 10052, "cat": "Emergency Care", "stem": "A nurse in the emergency department is caring for a client who has sustained an open fracture of the femur in a motor vehicle collision. Which of the following types of shock is most likely in this client?", "choices": [{"id": "a", "t": "Cardiogenic"}, {"id": "b", "t": "Hypovolemic"}, {"id": "c", "t": "Neurogenic"}, {"id": "d", "t": "Anaphylactic"}], "correct": "b", "rationale": "A fractured femur, especially an open fracture, can lead to significant blood loss. The most likely type of shock is hypovolemic shock due to hemorrhage.", "whyNot": {"c": "A fractured femur does not cause neurogenic shock.", "d": "Anaphylactic shock is caused by an allergic reaction, not a fractured femur."}, "keyConcept": "There are four major types of shock: obstructive shock, cardiogenic shock, distributive shock, and hypovolemic shock. Distributive shock includes neurogenic shock and shock due to anaphylaxis and sepsis. Hypovolemic shock is the result of blood or fluid loss. Cardiogenic shock is the result of reduced cardiac output, typically after myocardial infarction. Obstructive shock is caused by mechanical obstruction of cardiac output, such as in tension pneumothorax. Shock is characterized by inadequate tissue perfusion and metabolic acidosis. Hemodynamic Patterns Associated with Specific Shock States’ Type of shock CARDIOGENIC (eg. myocardial 1 1 Infarction o cardiac tamponade) HYPOVOLEMIC feg. hemorrhage. 1 T intravascule volume depiction) DISTRIBUTIVE SHOCK (eg. septic, Ntoof anaphylaxis) ‘OBSTRUCTIVE (ee. pulmonary. Y nt embolism) Cl SVR PVR Svo, RAP N I L N NT NL T Nd T RVP PAP PAOP. NebooNeL NL Cleardivc index: SVR, systemic vascular resistance: PVR. pulmonary vascular resistance: v0, mixed venous oxygen saturation: RAP, ight arterial pressure; RVP, right ventricular pressure; PAP. pulmonary artery pressure: PAOP. pulmonary artery occlusion pressure: 1, increased; 1 decreaded: N,normal “Equalization of RAP. PAOP, diastolic PAP, and diastolic RVP indicates cardi tareponade."}, {"id": 10053, "cat": "Emergency Care", "stem": "following sexually transmitted infections does the nurse understand must be reported to the Department of Public Health?", "choices": [{"id": "a", "t": "Genital herpes"}, {"id": "b", "t": "Human papillomavirus infection"}, {"id": "c", "t": "Gonorrhea"}, {"id": "d", "t": "Trichomoniasis"}], "correct": "c", "rationale": ". At this time, the other 3 options given are not reportable. B Hl a", "whyNot": {"a": "Genital herpes does not need to be reported to the Department of Public Health.", "b": "Human papillomavirus does not need to be reported to the Department of Public Health.", "d": "Trichomoniasis does not need to be reported to the Department of Public Health."}, "keyConcept": "Each state has a list of reportable diseases, including certain sexually transmitted infections. Many of these diseases must also be reported to the US Centers for Disease Control and Prevention (CDC.) This information is used by public health professionals to plan preventive measures, allocate resources, predict trends, and identify outbreaks. The healthcare provider bears the responsibility to report these diseases - the responsibility does not rest with the client. Sexually transmitted diseases with mandatory reporting requirements include syphilis, gonorrhea, chlamydia, and HIV."}, {"id": 10054, "cat": "Emergency Care", "stem": "prioritized by the nurse when preparing to perform cardioversion?", "choices": [{"id": "a", "t": "Sedate the client"}, {"id": "b", "t": "Select the correct energy level"}, {"id": "c", "t": "Push the synchronize button"}, {"id": "d", "t": "Charge the defibrillator 100} 2 = g 2 3"}], "correct": "c", "rationale": "A Hi 15% Moderate The rhythm is supraventricular tachycardia with a narrow QRS complex. Since the client is unstable, cardioversion is indicated. B ] ue Cardioversion is a procedure that delivers a shock synchronized on the R wave of the QRS complex. When the synchronizer button is ° activated, there is a delay in the shock while the machine reads the ECG rhythm and synchronizes shock delivery. If a shock is delivered ec | 61% during the T wave or repolarization, it could cause a lethal arrhythmia such as ventricular tachycardia or ventricular fibrillation. D i 10% Synchronized cardioversion is used to treat unstable tachyarrhythmias, including supraventricular tachycardia, multifocal atrial tachycardia, atrial flutter, and atrial fibrillation.", "whyNot": {"a": "Ifa patient is unstable, sedation should not delay cardioversion.", "b": "The most important task to prioritize is to set the synchronize button since the defibrillator will deliver a high-energy defibrillating shock", "d": "The most important consideration in this procedure is to activate the synchronization mode to prevent unintentional defibrillation at high"}, "keyConcept": "Treatment of tachycardia is based on the rhythm and morphology of the QRS complexes and on clinical signs and symptoms of instability. Symptomatic tachyarrhythmias are treated with synchronized cardioversion. Delivery of a shock during the T wave (repolarization of the ventricles) can result in a lethal arrhythmia. The initial energy dose for synchronized cardioversion is 50-100 Joules (J) with a biphasic defibrillator and 100 J with a monophasic defibrillator. If the client becomes hemodynamically unstable, the nurse should turn off the synchronizer switch and defibrillate."}, {"id": 10055, "cat": "Emergency Care", "stem": "Which of the following is the priority for the nurse to consider in caring for a client after naloxone administration?", "choices": [{"id": "a", "t": "Consideration of a drug-drug interaction with naloxone"}, {"id": "b", "t": "Assessment of the client’s need for an analgesic"}, {"id": "c", "t": "Assessment of client’s respiratory status in 30 minutes"}, {"id": "d", "t": "Filing an incident report"}], "correct": "c", "rationale": "A || 12% Moderate Naloxone is an opioid receptor antagonist that works by blocking the opioid receptors in the central nervous system, displacing morphine B | aon and other opioid agonists. It is an antidote to overdose, but it has a relatively short duration of action. The onset of action occurs rapidly, peaking at 20-40 minutes. The duration of action is only 90 minutes. Because some opioid agonists have a longer duration of action than ec P| 12% naloxone, reversal of the opioid medication may require a second dose of naloxone as the action of the drug wanes.", "whyNot": {"a": "Naloxone has an effect on the body’s opioid receptors and is the antidote, so the interaction with the analgesic is known and intentional in", "b": "Naloxone will reverse all effects of an opioid medication, including analgesia, and the client may require a non-opioid analgesic to relieve", "d": "Depression of respiration is a known adverse effect of opioid analgesics, and administration of naloxone was an appropriate response."}, "keyConcept": "Naloxone is used to reverse the effects of opioid overdose, including respiratory depression. It has a shorter half-life (0 minutes) than many opioids, so the client must be carefully monitored as respiratory depression and other effects will return after the effects of naloxone subside."}, {"id": 10056, "cat": "Emergency Care", "stem": "A nurse on the telemetry unit notes the rhythm below. The client is complaining of chest pain and lightheadedness and has a weak, rapid pulse. Which of the following actions does the nurse anticipate? BIcHUCeveW TaN EEeHCEtTHE “AULA LILA", "choices": [{"id": "a", "t": "Defibrillation"}, {"id": "b", "t": "Synchronized cardioversion at 50 Joules"}, {"id": "c", "t": "Synchronized cardioversion at 200 Joules"}, {"id": "d", "t": "Adenosine 6 mg IV push"}], "correct": "b", "rationale": "The client has a supraventricular tachycardia at a rate of 180/minute. It is unstable tachycardia because the client is hypotensive with chest pain that is most likely ischemic in origin. Other signs of poor perfusion associated with unstable tachycardia include altered mental status and respiratory distress. Symptoms include palpitations, syncope, lightheadedness, and respiratory distress. The nurse should establish IV access and obtain a 12-lead ECG. Supraventricular tachycardia is a narrow complex tachycardia with a QRS of <0.12 seconds. In an unstable client, cardioversion should not be delayed. The initial dose of energy for synchronized cardioversion in supraventricular tachycardia is 50- 100 J, except in atrial fibrillation, for which the dose of energy is 120-200 J.", "whyNot": {"a": "Defibrillation is an unsynchronized shock used for ventricular fibrillation and ventricular tachycardia without a pulse.", "c": "This dose is too high. It would be appropriate for atrial fibrillation with rapid ventricular response in an unstable client.", "d": "Adenosine is used in stable tachycardia. Unstable clients require cardioversion."}, "keyConcept": "Arrhythmias, including tachycardia and bradycardia, can compromise cardiac output. When cardiac output is inadequate, the client will demonstrate signs of poor perfusion of vital organs, including respiratory distress, chest pain, and/or mental status changes or syncope. Ina client with signs of hemodynamic compromise due to tachyarrhythmia, cardioversion is usually indicated."}, {"id": 10057, "cat": "Emergency Care", "stem": "adult client, which of the following elements is missing from the following graphic? life support", "choices": [{"id": "a", "t": "Respirations at a rate of sixty breaths per minute"}, {"id": "b", "t": "Early defibrillation"}, {"id": "c", "t": "Chest compressions at a rate of 100 compressions per minute"}, {"id": "d", "t": "An open airway"}], "correct": "b", "rationale": "The American Heart Association has developed the Chain of Survival that gives steps to provide rapid management of a patient who is in cardiac arrest. The first link in the chain is to activate the emergency response system, followed by initiation of CPR, including chest compressions and breathing assistance. This is followed by early defibrillation, advanced life support measures, and post-cardiac care. Rapid administration of these steps can greatly improve the survival of a patient in cardiac arrest.", "whyNot": {"a": "Respirations at a rate of sixty breaths per minute is much too quick.", "c": "Chest compressions at a rate of 100 compressions per minute is important. However, defibrillation should be immediate priority.", "d": "Opening the airway is included in care for the client. It would not take precedence over early defibrillation."}, "keyConcept": "The systems of care that work within ACLS are an effective method of coordination of efforts between many healthcare professionals"}, {"id": 10058, "cat": "Emergency Care", "stem": "A client treated with bumetanide (Bumex) has a prescription for magnesium after laboratory studies revealed Mg 0.8 mEq/L. The nurse knows that IV magnesium is used to treat which of the following rhythms?", "choices": [{"id": "a", "t": "Third-degree heart block"}, {"id": "b", "t": "Torsades de pointes"}, {"id": "c", "t": "Multifocal atrial tachycardia © b.atrial fibrillation"}], "correct": "b", "rationale": "A | | 9% Moderate Loop diuretics, including furosemide and bumetanide, affect the balance of sodium, potassium, and chloride in the kidney. They can cause a Cc | 11% decrease in the resorption of sodium and chloride, leading to hypokalemia (low potassium) and hypomagnesemia. <1.8 mEq/L. Hypomagnesemia and hypokalemia are associated with torsades de pointes, which refers to a specific form of polymorphic ventricular tachycardia that is characterized by rapid, irregular QRS complexes twisting around the ECG baseline. Torsades de pointes is associated with a prolonged QT interval. Since hypomagnesemia can prolong the QT interval, cardiac monitoring may be necessary in clients with profound hypomagnesemia. Torsades de pointes may progress quickly to ventricular fibrillation and death. Treatment is with IV magnesium sulfate. a © o 2 ° s a = a < TaP VIVWVY WivVVivevvev Vivivy vov vvivewy May WW ‘\\ ANIM AAAS AY ty ay ra VV VY yin i WAP Vi\\Ry y y \\ ahyy) AA Ne E Al val \\ } \\ Li iE", "whyNot": {"a": "Third-degree heart block is associated with disease of the conduction system and is not typically associated with electrolyte disturbances.", "c": "Multifocal atrial tachycardia is characterized by p waves of varying morphology caused by multiple sites of atrial activity. It can be related"}, "keyConcept": null}, {"id": 10059, "cat": "Emergency Care", "stem": "understanding of the nurse’s teaching?", "choices": [{"id": "a", "t": "“I should call 911 if do not have relief of pain after taking 3 tablets 5 minutes apart.”"}, {"id": "b", "t": "“I should swallow the tablet with water.”"}, {"id": "c", "t": "“I should take this medication after lie down.”"}, {"id": "d", "t": "“I should stop taking this medication if experience a headache or flushing.”"}], "correct": "c", "rationale": "‘is B Nitroglycerin is a vasodilator that provides relief from angina for many clients. Although research shows that almost half of all clients who @c | | take nitroglycerin do not have a thorough understanding of its use, proper education can prevent unnecessary visits to the emergency D I department for many clients. Because nitroglycerin is a vasodilator, it can cause a drop in blood pressure. For that reason, the nurse should be sure the client understands that it is important to lie down before taking either the sublingual tablet or spray.", "whyNot": {"a": "In the past, clients were instructed to take 3 tablets 5 minutes apart and then to call 911 if their pain was not relieved or if it worsened.", "b": "Sublingual tablets should never be swallowed. The client must be instructed to place the tablet under the tongue. Since moisture is", "d": "These are common side effects of nitroglycerin, which are due to its vasodilatory influence."}, "keyConcept": "Nitroglycerin sublingual tablets and spray are prescribed as a PRN medication for angina. The nurse should instruct to take the medication when seated, since the vasodilator effects of nitroglycerin can cause hypotension. If chest pain is not relieved at all or continues to worsen five minutes after the first tablet or spray of nitroglycerin, clients should be instructed to call 911."}, {"id": 10060, "cat": "Emergency Care", "stem": "priority nursing intervention? O A. Assess vital signs O B. Call the healthcare provider O C. Place an IV O D. Assist the client into an upright seated position or turn to one side", "choices": [{"id": "a", "t": "Assess vital signs"}, {"id": "b", "t": "Call the healthcare provider"}, {"id": "c", "t": "Place an IV"}, {"id": "d", "t": "Assist the client into an upright seated position or turn to one side"}], "correct": "d", "rationale": "Coffee-ground emesis is characteristic of an upper Gl bleed. In a client with heavy alcohol use, it may result from esophageal varices caused Cc | by increased pressure in the portal vein (portal hypertension). Portal hypertension results in the development of collateral circulation in the rectum, stomach, and esophagus. Bright red emesis also occurs with an upper Gl bleed. The client may have a tender abdomen, or, if the client has a perforated ulcer, the abdomen may be distended and rigid. Tarry black stools, tachycardia, and hypotension are characteristic of a significant GI bleed. The priority intervention is preventing aspiration, so the nurse should assist the client to a position of sitting or, if unable to sit, to one side. Portal hypertension Portal vein ver Blood backing up into the portal vein leading tovarices", "whyNot": {"a": "Protection from aspiration is the priority. Vital signs should be assessed after positioning the client and placing an emesis basin.", "b": "The nurse should assess and stabilize the client before calling the healthcare provider.", "c": "After the assessment of the client, the nurse should supply supplemental oxygen and insert a large-bore IV for the administration of"}, "keyConcept": null}, {"id": 10061, "cat": "Emergency Care", "stem": "Which of the following findings should a nurse prioritize for immediate action when assessing a client 1 day after a cast was placed on a reduced fracture of the tibia?", "choices": [{"id": "a", "t": "Capillary refill of 2 seconds"}, {"id": "b", "t": "Nausea from pain medication"}, {"id": "c", "t": "Slight swelling of the toes of the foot on the affected side"}, {"id": "d", "t": "Paresthesias and pallor"}], "correct": "d", "rationale": "al 4% Easy Compartment syndrome is a serious complication of long bone fractures and casting. It occurs when swelling in the extremity causes an . The signs are pain out of proportion to the injury and paresthesia, including numbness and tingling. Late signs include pallor, pulselessness, and paralysis. Neurovascular assessment is performed by c | ™% checking the motor and sensory function of the distal extremity and the circulation. Coolness and delayed capillary refill are signs of poor @ . An acronym to help remember the five \"P's\" of compartment syndrome is \"pain, paresthesia, pallor, pulselessness, and paralysis.\"", "whyNot": {"a": "Capillary refill of <3 seconds is normal.", "b": "Nausea should be addressed, but it is not a priority.", "c": "Slight swelling can occur as a result of the pressure from the cast. Elevation of the foot and leg can be helpful to reduce swelling, although"}, "keyConcept": "Direct complications of bone fracture include infection, disunion of the bone segments, and avascular necrosis. Indirect complications include compartment syndrome, rhabdomyolysis, venous thromboembolism, fat embolism, and hypovolemic shock."}, {"id": 10062, "cat": "Emergency Care", "stem": "A nurse in the emergency department is assigned to care for 4 clients. Which client is a priority for assessment and treatment? O A.A patient with diabetes and increased thirst with a temperature of 100.6°F and fingerstick glucose reading of 380 mg/dL O B. A patient who takes warfarin and fell from a ladder, who had a brief loss of consciousness and now complains of a severe headache O C. Awoman who is crying after an argument with her husband with bruises on both arms O D. An older patient with a swollen and deformed ankle complaining of 8/10 pain after stepping off a curb with equal pulses in both feet", "choices": [{"id": "a", "t": "This client has a fever and elevated blood glucose, which often occurs with an infection in individuals with diabetes. The client requires"}, {"id": "b", "t": "severe headache"}, {"id": "c", "t": "The client will require assessment of injuries, which appear to be minor. She will also potentially require counseling and use of resources if"}, {"id": "d", "t": "Simple fractures can be assessed within 1 to 2 hours. Since the client has adequate blood flow beyond her ankle, there is no immediate"}], "correct": "a", "rationale": "B. severe headache Emergent priorities in the emergency department include trauma victims with injuries that threaten life or limb and clients with medical conditions that present an immediate and significant risk of harm. The ABC's (airway, breathing, circulation) are always priority items, but injuries or disorders that affect the central nervous system are also potentially devastating. In the ED, priorities include amputations, chest pain, severe respiratory distress, chemical splashes to the eye, and acute neurological deficits. An elderly client who is treated with an anticoagulant medication and falls from a height is at risk for intracranial bleeding, including subdural hematoma (SDH). A SDH occurs with tears of the bridging veins that travel in the space between the dura mater and arachnoid layers of connective tissue that cover the brain. Acute subdural hematoma and other intracranial hemorrhages increase intracranial pressure, resulting in decreased cerebral perfusion, with brainstem herniation, and death. Herniation of the brainstem refers to movement of the brainstem through the foramen magnum, the opening at the base of the skull. This client should be a priority for assessment with radiological imaging and neurological examination. A coagulation profile (PT, INR) should be obtained.", "whyNot": {"a": "This client has a fever and elevated blood glucose, which often occurs with an infection in individuals with diabetes. The client requires", "c": "The client will require assessment of injuries, which appear to be minor. She will also potentially require counseling and use of resources if", "d": "Simple fractures can be assessed within 1 to 2 hours. Since the client has adequate blood flow beyond her ankle, there is no immediate"}, "keyConcept": "In addition to airway, breathing, and circulation problems, potentially life-threatening neurological conditions should be prioritized for care. Older clients who are anticoagulated are at increased risk of intracranial bleeding after a fall. Intracranial bleeding can lead to increased intracranial pressure, brainstem herniation, and death."}, {"id": 10063, "cat": "Emergency Care", "stem": "client? O A. Diminished sensation of the skin on the affected side O B. Diminished breath sounds on the affected side O C. Increased fremitus O D. Biot's respirations", "choices": [{"id": "a", "t": "Diminished sensation of the skin on the affected side"}, {"id": "b", "t": "Diminished breath sounds on the affected side"}, {"id": "c", "t": "Increased fremitus"}, {"id": "d", "t": "Biot's respirations"}], "correct": "b", "rationale": "'s breath sounds and should suspect possible pneumothorax when breath sounds are diminished or OB a OR absent on the affected side. ° c] 3%", "whyNot": {"a": "A client with pneumothorax will typically have increased pain on the affected side and NOT diminished sensation.", "c": "Fremitus is the vibration that can be felt on the chest wall when the client takes a deep breath or speaks. Typically, fremitus is DECREASED", "d": "Biot’s respiration is an abnormal breathing pattern of quick breaths followed by periods of apnea. This sort of respiratory pattern is"}, "keyConcept": "Pneumothorax refers to the presence of air or gas in the pleural cavity, which is the potential space between the visceral and parietal pleura of the lung. A pneumothorax can impair oxygenation and/or ventilation. Clinical manifestations depend on the degree of collapse of the lung on the affected side. Tension pneumothorax can cause a shift of the mediastinum and compromised hemodynamic stability."}, {"id": 10064, "cat": "Emergency Care", "stem": "A nurse is assigned to care for the following clients in the emergency department. Which of the following should be prioritized for assessment?", "choices": [{"id": "a", "t": "A client with 9/10 pain and swelling with deformity after ankle injury sustained after misstep from a curb."}, {"id": "b", "t": "A client with syncope, chest pain, and shortness of breath who has a heart rate of 180/minute."}, {"id": "c", "t": "A client who stepped on a nail and sustained a puncture wound of the foot."}, {"id": "d", "t": "A client with neck pain and normal neurologic exam who is in a cervical collar after being hit from behind by another car traveling at 15 mph."}], "correct": "b", "rationale": "The nurse should prioritize any potentially life-threatening injuries. When prioritizing potentially serious conditions, the nurse should prioritize airway, breathing, and circulation. The client who has symptomatic tachycardia should be prioritized, since tachyarrhythmia can deteriorate to ventricular fibrillation and/or death.", "whyNot": {"a": "This injury should be assessed and treated quickly, within minute to hours. It is important to treat the client’s pain and to verify perfusion", "c": "This client’s wound should be cleansed and irrigated and the client may require a tetanus vaccine, but this is not the priority nursing", "d": "A client with a potential injury to the cervical spine/spinal cord should be immobilized until the cervical spine is “cleared” by clinical"}, "keyConcept": "Life threatening conditions are always prioritized. Problems with airway, breathing, and circulation are potentially life-threatening. Symptomatic tachycardia may progress rapidly to ventricular fibrillation and cardiac arrest if unrecognized or untreated."}, {"id": 10065, "cat": "Emergency Care", "stem": "even when the leg is elevated and the child has taken an NSAID for the relief of pain. What is the priority nursing action?", "choices": [{"id": "a", "t": "Elevate the leg and apply ice"}, {"id": "b", "t": "Assess limb color and pulses"}, {"id": "c", "t": "Remove the cast"}, {"id": "d", "t": "Encourage the client to walk"}], "correct": "b", "rationale": "The first thing that the nurse must do is to assess the limb color and pulses because these presenting signs and symptoms indicate compartment syndrome that sometimes occurs after fracture or casting of a fracture. This limb-threatening disorder is characterized by ischemic pain that results from swelling within the muscles, causing increased pressure in compartments of the limb that contain muscle, nerve, and blood vessels. Elevation of the limb and icing are not indicated; and walking will not relieve the pain and the compartment syndrome. Cast removal is indicated before permanent nerve and tissue damage occur. If compartment pressures are elevated, a fasciotomy may be indicated.", "whyNot": {"a": "The family has already elevated the leg, which has not relieved the pain.", "c": "The nurse may eventually need to remove the cast but she must first assess limb color and perfusion to check for compartment syndrome.", "d": "Encouraging the client to walk will not help and may only cause more pain."}, "keyConcept": "Compartment syndrome is a painful and limb-threatening condition that occurs when pressure within the muscles builds to dangerous levels, which causes decreased blood flow, with reduction of oxygen and nutrients in tissues within the compartment. In acute compartment syndrome, unless pressure is relieved quickly, permanent disability and tissue death may result. Compartment syndrome can be caused by crush injuries, tight casting, tight bandages, fractures, and severe bruising."}, {"id": 10066, "cat": "Emergency Care", "stem": "A client is admitted to the emergency department with chest pain and shortness of breath. Which of the following laboratory values should be reported to the healthcare provider immediately?", "choices": [{"id": "a", "t": "Hematocrit 39%"}, {"id": "b", "t": "Magnesium 2.0 mEq/L"}, {"id": "c", "t": "Troponin 1.0 mcg/L © D. Sodium 132 mEq/L"}], "correct": "c", "rationale": "Troponin is a serum cardiac marker for myocardial infarction. It is a protein that is released after cell death in the heart and has high specificity for diagnosing MI. The serum level of troponin increases at 4-6 hours after the onset of acute MI. It usually peaks within 24 hours and will return to baseline in 10 days to 2 weeks. Normal troponin values include troponin T of <0.1 mcg/L and troponin | of <0.5 mcg/L. Other cardiac markers have lower sensitivity and specificity and include creatine kinase MB.", "whyNot": {"a": "Normal hematocrit in females can range from 35-47% and in males from 39-50%. This is not a critical value.", "b": "This is a normal magnesium level."}, "keyConcept": "Biomarkers for damage to myocardial cells include troponin and creatine kinase-MB (CK-MB). Troponin is the most accurate and sensitive biomarker for myocardial infarction. It is positive in up to 80% of clients with MI within 2-3 hours of presentation at the emergency department. CK-MB becomes positive 6-9 hours or longer after presentation. One positive troponin is all that is necessary for diagnosis of non-ST-elevation MI (NSTEMI.) No cardiac markers are necessary for diagnosis of ST elevation myocardial infarction."}, {"id": 10067, "cat": "Emergency Care", "stem": "flight nurse arrives at the scene of a motor vehicle collision and observes that the victim has had a traumatic amputation. What action is a nursing priority?", "choices": [{"id": "a", "t": "The nurse should place the body part in a clean plastic bag and place it on ice to preserve it."}, {"id": "b", "t": ", dry gauze to prevent hemorrhage."}, {"id": "c", "t": "Psychological support for the client is important but the nurse must first protect the severed limb."}, {"id": "d", "t": "The amputated part should be wrapped in sterile gauze, placed in a bag, then that bag placed on ice. It should not be submerged in ice"}], "correct": "b", "rationale": ", dry gauze to prevent hemorrhage. Control of hemorrhage is part of the primary OB a epi assessment. Although you would also perform other assessments and care, including psychological support because the client has just suffered from a traumatic injury, psychological support does not take priority until the life- and limb-threatening physical needs are met. c | 2% om 15%", "whyNot": {"a": "The nurse should place the body part in a clean plastic bag and place it on ice to preserve it.", "c": "Psychological support for the client is important but the nurse must first protect the severed limb.", "d": "The amputated part should be wrapped in sterile gauze, placed in a bag, then that bag placed on ice. It should not be submerged in ice"}, "keyConcept": "The three most common causes of traumatic amputation are motor vehicle collisions, industrial accidents, and agricultural accidents. Amputations can be partial or complete. Amputations can also be classified according to the degree of tissue injury to the nerve, bone, and vascular structures. A sharp amputation has well-defined edges which minimize the damage to the associated anatomy, making successful reattachment more likely. A crush amputation has more soft tissue and arterial damage and reattachment is less likely to be successful. If the amputated part is completely detached, the nurse should control the bleeding after cleansing the site by covering the wound with a pressure dressing. The amputated part should be wrapped in sterile saline moistened gauze and placed it in a watertight container or resealable plastic bag. The bag should be placed on ice. The nurse should not allow the damaged part to come in direct contact with ice."}, {"id": 10068, "cat": "Emergency Care", "stem": "Which of the following is an appropriate response by a nurse in the ICU to a family member who will not leave the client’s room during a resuscitation?", "choices": [{"id": "a", "t": "Assign a staff member to stay with the family member to answer questions and provide explanations while the code proceeds."}, {"id": "b", "t": "Tell the family member that universal medical guidelines prevent family members from being present during emergencies in the ICU."}, {"id": "c", "t": "Notify security and ask them to escort the family member from the ICU."}, {"id": "d", "t": "Ask the family member to remain in an area outside of the room."}], "correct": "a", "rationale": "A. proceeds. @A FY 75% Moderate ce | 5% c | 2% During an emergency resuscitation/code, family members should be allowed to stay in the room if they are not disrupting client care. A staff D Hi 17% member should be assigned to stay with the family member to explain the interventions during the code. Family members may benefit from witnessing efforts at resuscitation, even if the result is poor. If a family member becomes disruptive, the charge nurse should escort the person from the room.", "whyNot": {"b": "Medical professional associations, in large part, support efforts to allow family members to remain present at a resuscitation or other", "c": "Calling security can often escalate a situation that is laden with emotion for family members, so this option should be reserved for", "d": "The family member should be allowed to remain in the room in which the resuscitation is taking place, with a staff member assigned to"}, "keyConcept": "Family members should be offered the option of remaining in the room during cardiopulmonary resuscitation, as long as client care is not disrupted. A staff member should be assigned to remain with the family member to explain interventions and answer questions."}, {"id": 10069, "cat": "Emergency Care", "stem": "most likely the cause of these symptoms?", "choices": [{"id": "a", "t": "Deep vein thrombosis"}, {"id": "b", "t": "Myocardial infarction"}, {"id": "c", "t": "Fat embolism"}, {"id": "d", "t": "Ruptured aortic aneurysm"}], "correct": "c", "rationale": "All The classic triad for fat embolism is: respiratory difficulty, change in mental status and petechial rash. Femur fracture is associated with risk B | for fat embolism from the bone marrow and the client's respiratory distress and petechiae make this the likely diagnosis. o;", "whyNot": {"a": "Deep vein thrombosis is not associated with petechiae or respiratory distress. Pulmonary embolism is associated with respiratory distress.", "b": "The typical presentation of myocardial infarction is crushing chest pain, nausea, and shortness of breath. Petechiae are characteristic of", "d": "Ruptured aortic aneurysm presents with sudden onset of tearing pain down the back, with severe hypotension."}, "keyConcept": "The incidence of fat embolism syndrome is high in clients who have experienced major traumatic injuries, particularly long bone fractures. The diagnosis is primarily based on identification of clinical signs and symptoms of dyspnea, petechiae, and cognitive dysfunction after trauma, fracture of long bones, or orthopedic surgical procedures. The syndrome is caused by systemic inflammatory response to a fat embolism and onset is usually 12-72 hours after the inciting event."}, {"id": 10070, "cat": "Emergency Care", "stem": "explanation for these findings? O a.acute MI O B. Hypocalcemia O C. Hyperkalemia O D. Cardiac tamponade", "choices": [{"id": "a", "t": "An ECG is a non-invasive method of detecting changes in heart rhythm and conduction abnormalities."}, {"id": "b", "t": "The client’s ECG results indicate a myocardial infarction, not hypocalcemia. A long QT interval is characteristic of hypocalcemia."}, {"id": "c", "t": "The client’s ECG results indicate a myocardial infarction, not hyperkalemia. Hyperkalemia is characterized by peaked T waves."}, {"id": "d", "t": "The client’s ECG results indicate a myocardial infarction, not cardiac tamponade."}], "correct": "a", "rationale": "An ECG is a non-invasive method of detecting changes in heart rhythm and conduction abnormalities. The nurse should be familiar with the B | 3\" appearance of a normal ECG and with ECG abnormalities associated with common conditions. Elevated ST segments in two contiguous leads in a client with symptoms of acute coronary syndrome are most likely to be acute myocardial infarction. c |_| 18% oe | 4%", "whyNot": {"b": "The client’s ECG results indicate a myocardial infarction, not hypocalcemia. A long QT interval is characteristic of hypocalcemia.", "c": "The client’s ECG results indicate a myocardial infarction, not hyperkalemia. Hyperkalemia is characterized by peaked T waves.", "d": "The client’s ECG results indicate a myocardial infarction, not cardiac tamponade."}, "keyConcept": "ST elevation myocardial infarction (STEMI) is characterized by clinical symptoms consistent with acute coronary syndrome in addition to persistent ST elevation in 2 or more contiguous leads. The ST elevation must be =2.5 mm ST elevation in leads V2-3 in men under 40 years, or 2=2.0 mm ST elevation in leads V2-3 in men over 40 years. In women, ST elevation of = 1.5 mm is required in V2-3 and =1 mm ST elevation in other leads. Each small square is equal to 1 mm. See image below."}, {"id": 10071, "cat": "Emergency Care", "stem": "@ @ %& Viraln. 8s Record Mi Inbox( ™ Inbox- [E} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr @® ATITE € > G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Assess muscle strength"}, {"id": "b", "t": "Assess the performance of activities of daily living"}, {"id": "c", "t": "Assess the pain level"}, {"id": "d", "t": "Assess the level of consciousness"}], "correct": "d", "rationale": "The Glasgow Coma Scale is used to assess the level of consciousness.", "whyNot": {"a": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not muscle strength.", "b": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not activities of daily living.", "c": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not level of pain."}, "keyConcept": "The Glasgow Coma Scale (GCS) is a commonly used scoring system used to describe a client's level of consciousness after a traumatic brain injury. It is used to gauge the severity of an acute brain injury and provides an objective way to record initial and subsequent level of consciousness. GCS correlates well with outcome following severe brain injury. (See table below for scoring.) Glasgow Coma Scale Eye opening Spontaneously response To speech To pain No response Nw. Best verbal Oriented to time, place, and person response Confused Inappropriate words Incomprehensible sounds No response —-NwWwaun Best motor | Obeys commands response Moves to localized pain Flexion withdrawal from pain Abnormal flexion (decorticate) Abnormal extension (decerebrate) No response —-NwWEeUD"}, {"id": 10072, "cat": "Emergency Care", "stem": "@ @ %& Viralni 8s Record Mi Inbox( M Inbox- [} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr ® Atte, € > G 23 student.atitesting.com/LT| © Newcl NC x + v Qa * ws * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Ischemic infarction"}, {"id": "b", "t": "Transmural infarction"}, {"id": "c", "t": "Subendocardial infarction"}, {"id": "d", "t": "Hypoxemia infarction"}], "correct": "b", "rationale": "Atransmural infarction describes a myocardial infarction injury that penetrates the entire wall of the myocardium. This term is used to classify the type of heart attack that has occurred, as a myocardial infarction is classified according to its location and the depth of the muscle penetrated.", "whyNot": {"a": "While a myocardial infarction involves an ischemic injury, this is not the term used in this situation.", "c": "Asubendocardial infarction only penetrates the inner part of the heart muscle during a heart attack, not the entire heart muscle.", "d": "This is not a term used to classify a myocardial infarction."}, "keyConcept": "Current terminology for acute coronary syndrome includes unstable angina (UA), non-ST elevation MI (NSTEMI), and ST elevation MI (STEMI). STEMI is usually characterized by complete occlusion of a major epicardial coronary artery, resulting in necrosis of the full thickness of the myocardium, from the endocardium through the myocardium to the epicardium."}, {"id": 10073, "cat": "Emergency Care", "stem": "the nurse anticipate as the initial action?", "choices": [{"id": "a", "t": "Gastric lavage"}, {"id": "b", "t": "Syrup of ipecac"}, {"id": "c", "t": "Activated charcoal"}, {"id": "d", "t": "Sodium bicarbonate"}], "correct": "c", "rationale": "‘i oy | Administration of activated charcoal, when given within 2 hours of an overdose, can prevent further absorption of a medication, but it is ec ; most effective when administered with 30 minutes of ingestion. Activated charcoal binds drugs and chemicals in the GI tract to prevent D I further absorption. The nurse should mix the dose in water and administer orally as a slurry. The pediatric dose is 25 mg and adult dose is 100 mg. A second dose can be repeated in 4-6 hours to prevent absorption of agents that undergo enterohepatic circulation.", "whyNot": {"a": "Gastric lavage is not routinely recommended because it is associated with a risk of aspiration. Studies have also shown that gastric lavage", "b": "Syrup of ipecac encourages emesis, but it is associated with a risk of aspiration and is not routinely recommended.", "d": "Routine use of bicarbonate is not recommended for NSAID toxicity but may be used in clients who develop severe acidosis. Volume"}, "keyConcept": "Activated charcoal is most effective in treatment of overdose when given within 30 minutes of an ingestion. The nurse should mix the dose of AC in water and administer orally as a slurry. The pediatric dose is 25 mg and adult dose is 100 mg. A second dose can be repeated in 4-6 hours to prevent absorption of agents that undergo enterohepatic circulation."}, {"id": 10074, "cat": "Emergency Care", "stem": "X-ray films reveal that a client has closed fractures of the right femur and tibia. Multiple soft-tissue contusions are also present. What is the most important next step in intervention?", "choices": [{"id": "a", "t": "Perform a neurovascular assessment of the extremity"}, {"id": "b", "t": "Reassure the client that these injuries are not that serious"}, {"id": "c", "t": "Gather equipment for a surgical reduction of the injured extremity"}, {"id": "d", "t": "Prepare the client for a surgical reduction of the injured extremity"}], "correct": "a", "rationale": "Identifying the extent of the damage is the priority. Before a treatment protocol can be determined, the nerve and vascular damage must be . c | 2%", "whyNot": {"b": "The client has suffered significant injuries; he should be reassured that he is being helped by the staff, not that his injuries are minor.", "c": "Gathering equipment will be necessary but it is not the first priority.", "d": "The client will need to be prepared for treatment, but the first priority is assessment and stabilization."}, "keyConcept": "A client with a fracture of an extremity should be assessed to determine if the trauma has resulted in neurovascular compromise. Assessment is always the initial priority in the nursing process. Assessment of the client's vascular perfusion includes assessment of skin color, capillary refill (normal = < 2 seconds); and pulses. Pedal pulses include the posterior tibialis and dorsalis pedis. The pulse should be graded on a scale of zero to five:"}, {"id": 10075, "cat": "Emergency Care", "stem": "@ @ %& Viralni 8s Record Mi Inbox( M Inbox- [} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr @ Atite = @G@ Newel NC x) + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Cover the burned area with sterile dressings"}, {"id": "b", "t": "Initiate intravenous fluid administration"}, {"id": "c", "t": "Administer pain medication as ordered"}, {"id": "d", "t": "Assess for dyspnea and stridor"}], "correct": "d", "rationale": "| 2% Easy Due to the location of the burns, the client is at risk for developing upper airway edema and subsequent respiratory distress.", "whyNot": {"a": "The nurse must first assess the client’s breathing; a burn in this location could cause respiratory distress. e@D fF 83%", "b": "Intravenous fluids are important but the nurse must first assess the client’s respiratory effort.", "c": "The client is most likely in pain but the nurse should first ensure adequate breathing before administering any medications."}, "keyConcept": "Airway, breathing, and circulation problems can be immediately life-threatening and should be prioritized in assessment and care. Disability (neurologic) and Exposure (to assess for areas of injury) are also prioritized above treatment of the burn itself."}, {"id": 10076, "cat": "Emergency Care", "stem": "A nurse in the emergency department is caring for a client with a spinal cord injury. Which intervention should the nurse prioritize?", "choices": [{"id": "a", "t": "Place a small pillow under the client's head for comfort"}, {"id": "b", "t": "Move the client gently to decrease pain"}, {"id": "c", "t": "Restrain the client's arms and legs to limit movement"}, {"id": "d", "t": "Immobilize the client's head and neck"}], "correct": "d", "rationale": "al 3% Easy The head and neck of a client with a spinal cord injury must be maintained in strict alignment with the rest of the spine. If the client is B | 3\" transported by EMS, it is likely that the paramedics will have applied a hard cervical collar, which is critical to maintain alignment and prevent injury to the spinal cord during transport. The client should be “logrolled” by 2-3 personnel when repositioning or moving, to ensure c | 2% that spinal alignment is maintained. It is not appropriate to restrain the client or use pillows for comfort until X-rays of the cervical spine and @D PY 92% clinical exam confirm there is no spinal instability.", "whyNot": {"a": "The nurse must keep the client’s head and neck in alignment and should not provide a pillow at this time.", "b": "The nurse should avoid moving the client to reduce the risk of further cord injury.", "c": "It is not appropriate to restrain the client’s arms and legs; the nurse must keep the client's head and neck in alignment."}, "keyConcept": "Spine injury should always be considered a possibility in any client who experiences significant trauma to the head or thorax. Common causes of trauma implicated in spinal cord injury include motor vehicle accidents (MVA), falls, and pedestrian-vehicle accidents. To protect the spinal cord from additional injury, healthcare personnel should institute \"spinal precautions\" in these clients. Estimates of neurologic damage caused as a result of inadequate spinal cord immobilization after a traumatic event range from 3 to 25%. Spinal precautions include holding the head in position, application of a cervical collar, maintenance of neutral alignment, and log rolling when repositioning or moving the client."}, {"id": 10077, "cat": "Emergency Care", "stem": "beats per minute, respirations 38 breaths per minute, and oxygen saturation (SaO2) 92% on room air. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Obtain a chest X-ray."}, {"id": "b", "t": "Place the client on an ECG monitor"}, {"id": "c", "t": "Administer oxygen via a high-flow mask."}, {"id": "d", "t": "Initiate IV access."}], "correct": "c", "rationale": ", breathing, and circulation approach to client care is to apply oxygen via high- B I a flow mask to increase oxygenation and improve gas exchange. The nurse should immediately check the client's airway for patency, apply high-flow oxygen, check the client's vital signs, and initiate an IV to administer fluids and medications. The client will require diagnostic OG a ae studies, such as ABGs, chest X-rays, CT scans, ECGs, and CBCs. The client might require insertion of a chest tube to re-establish negative D || 13% intrapleural pressure and to drain fluid or blood from the intrapleural cavity. The nurse should monitor the client for bleeding that can lead a to hypovolemia and decreased cardiac output. 2 8 2", "whyNot": {"a": "The nurse should obtain a chest X-ray to determine the level of injury to the lungs. However, there is another action the nurse should take &", "b": "The nurse should place the client on an ECG monitor to monitor the client for dysrhythmias. However, there is another action the nurse", "d": "The nurse should initiate an IV access to administer medications and fluids. However, there is another action the nurse should take first."}, "keyConcept": "The priority nursing actions for a client who has a chest trauma is to assess and manage the client's airway, breathing, and circulation. The nurse should immediately check the client's airway for patency, apply high-flow oxygen, check the client's vital signs, and initiate an IV to administer fluids and medications. The client will require diagnostic studies, such as ABGs, chest X-rays, CT scans, ECGs, and CBCs. The client might require insertion of a chest tube to re-establish negative intrapleural pressure and to drain fluid or blood from the intrapleural cavity. The nurse should monitor the client for bleeding because it can lead to hypovolemia and decreased cardiac output."}, {"id": 10078, "cat": "Emergency Care", "stem": "beats per minute, respirations 38 breaths per minute, and oxygen saturation (SaO2) 92% on room air. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Obtain a chest X-ray."}, {"id": "b", "t": "Place the client on an ECG monitor"}, {"id": "c", "t": "Administer oxygen via a high-flow mask."}, {"id": "d", "t": "Initiate IV access. eck Answer"}], "correct": "c", "rationale": "A The first action the nurse should take when using the airway, breathing, and circulation approach to client care is to apply oxygen via high- B - flow mask to increase oxygenation and improve gas exchange. The nurse should immediately check the client's airway for patency, apply high-flow oxygen, check the client's vital signs, and initiate an IV to administer fluids and medications. The client will require diagnostic © a studies, such as ABGs, chest X-rays, CT scans, ECGs, and CBCs. The client might require insertion of a chest tube to re-establish negative D || intrapleural pressure and to drain fluid or blood from the intrapleural cavity. The nurse should monitor the client for bleeding that can lead to hypovolemia and decreased cardiac output.", "whyNot": {"a": "The nurse should obtain a chest X-ray to determine the level of injury to the lungs. However, there is another action the nurse should take", "b": "The nurse should place the client on an ECG monitor to monitor the client for dysrhythmias. However, there is another action the nurse", "d": "The nurse should initiate an IV access to administer medications and fluids. However, there is another action the nurse should take first."}, "keyConcept": "The priority nursing actions for a client who has a chest trauma is to assess and manage the client's airway, breathing, and circulation. The nurse should immediately check the client's airway for patency, apply high-flow oxygen, check the client's vital signs, and initiate an IV to administer fluids and medications. The client will require diagnostic studies, such as ABGs, chest X-rays, CT scans, ECGs, and CBCs. The client might require insertion of a chest tube to re-establish negative intrapleural pressure and to drain fluid or blood from the intrapleural cavity. The nurse should monitor the client for bleeding because it can lead to hypovolemia and decreased cardiac output."}, {"id": 10079, "cat": "Emergency Care", "stem": "client's family. Which of the following actions should the nurse expect the neurosurgeon to take?", "choices": [{"id": "a", "t": "Invoking implied consent"}, {"id": "b", "t": "Delaying the surgery until a family member is reached"}, {"id": "c", "t": "Asking the client to sign the surgical consent form"}, {"id": "d", "t": "Prescribing naloxone to reverse the effects of the morphine"}], "correct": "a", "rationale": "If the nurse is unable to reach the client's family, the neurosurgeon has the legal right to invoke implied consent. Invoking implied consent B |] oom allows the provider to proceed with the surgery in an emergency situation. The neurosurgeon should document the details of the situation in ° the client's medical record. © |_| Uh pI 2%", "whyNot": {"b": "Delaying the surgery until a family member is reached places the client at risk for a poor outcome. Therefore, this is not the action the", "c": "A client who is sedated from morphine can become disoriented or unable to function. Therefore, the nurse should not expect the", "d": "The purpose of naloxone is to reverse the effects of opioid toxicity. Therefore, the nurse should not expect the neurosurgeon to prescribe"}, "keyConcept": "Informed requires the provider to explain the benefits and risks of a particular surgery, diagnostic exam, or treatment. The provider should also explain the alternative treatments and prognosis of the treatment before the client signs the informed consent form. The informed consent is not the form itself; it is the agreement by the client and the provider about course of treatment or a procedure. Informed consent involves a signed form which provides a written record that informed consent has been obtained. There are two types of consent: expressed and implied. Express consent is often an oral or written agreement. Generally, more invasive treatments and diagnostic exams require a written consent. Implied consent occurs when the client nonverbally indicates the client would like to receive a treatment, such as nursing care, laboratory tests, or X-rays. When there is a medical emergency and the client is unable to provide informed consent, and the client has no family member or guardian available, implied consent can be invoked to attempt to save the client's life."}, {"id": 10080, "cat": "Emergency Care", "stem": "occur with a pacemaker battery malfunction?", "choices": [{"id": "a", "t": "Chest pain radiating to the back with diaphoresis"}, {"id": "b", "t": "Dyspnea, peripheral edema, and pre-syncope"}, {"id": "c", "t": "Abdominal pain radiating to the back and nausea"}, {"id": "d", "t": "Coughing, wheezing, and low oxygen saturation"}], "correct": "b", "rationale": "‘i oo A pacemaker is a device implanted to maintain the heart rate when the client's intrinsic system is unable to do so. The stimulus is produced Cc | by a pulse generator and delivered through electrodes or leads that implanted in the epicardium or endocardium. The electrodes may be D | | unipolar or bipolar. The proximal end attaches to a pulse generator that is placed in the chest or abdomen. Causes of pacemaker malfunction and failure include lead dislodgement, battery failure, low, sensitivity, wire fracture, or improper placement of the catheter. Pacemaker failure can result in an irregular pulse, a change in heart rate, or palpitations. These symptoms may cause a reduction of cardiac output, which is characterized by symptoms of heart failure that include peripheral edema and dyspnea. If the brain is not adequately perfused, symptoms may include light-headedness, weakness, pre-syncope, or syncope.", "whyNot": {"a": "Chest pain that radiates to the back characterizes a ruptured aortic aneurysm.", "c": "Abdominal symptoms are not generally a symptom of pacemaker failure. This suggests gastrointestinal disorders like pancreatitis or", "d": "Although wheezing may sometimes characterize heart failure, these symptoms are less likely to characterize pacemaker failure."}, "keyConcept": null}, {"id": 10081, "cat": "Emergency Care", "stem": "bleeding from a wound on the arm? O A. Apply a pressure bandage to the wound. O B. Remove the victim from the area. O C. Provide rescue breathing. O D. Begin intravenous fluids for shock.", "choices": [{"id": "a", "t": "Apply a pressure bandage to the wound."}, {"id": "b", "t": "Remove the victim from the area."}, {"id": "c", "t": "Provide rescue breathing."}, {"id": "d", "t": "Begin intravenous fluids for shock."}], "correct": "b", "rationale": "The initial action in trauma is to ensure the safety of the scene, which will help prevent potential harm to rescuers. An open gas line can be a source of further injury to the victim and a source of injury to the nurse. The nurse should remove the victim from the area before any other intervention.", "whyNot": {"a": "Although it is important to control hemorrhage, the initial priority is to avoid additional injury to the victim or injury to the rescuer. The", "c": "Although the victim’s respiratory status must be addressed, it is immediately important to remove the victim from a potential area of", "d": "The client should first be removed from the area of potential additional danger."}, "keyConcept": "When providing care at the scene of a disaster, the initial priority is to ensure the safety of the scene, to prevent potential injury to caregivers and other first responders."}], "genital_reproductive": [{"id": 10082, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client who has just delivered a healthy neonate vaginally and underwent an episiotomy. Which of the following findings is commonly associated with vulvar hematoma?", "choices": [{"id": "a", "t": "Painless uterine bleeding"}, {"id": "b", "t": "Hypotension and tachycardia"}, {"id": "c", "t": "Usually not visible"}, {"id": "d", "t": "Pain or pressure"}], "correct": "d", "rationale": "Vaginal, vulvar, or retroperitoneal hematomas may form as a result of lacerations during delivery. Lacerations of the cervix, perineum, and Cc l vagina should be suspected in clients who continue to have bleeding despite the contraction of the uterus in the puerperium. Bleeding may e@D fF be a frank hemorrhage or a slower/smaller volume of vaginal bleeding. The most common type of injury is a laceration of the perineum. Cervical lacerations usually result in minimal bleeding. The most common, as a result, is vulvar hematoma, which is usually visible. It is most frequently the result of episiotomy or perineal laceration, and the most commonly associated symptom is pain. Vaginal hematomas are associated with forceps-assisted birth, primigravid mother, or episiotomy. Perineal or rectal pain or vaginal pressure is typical. If the hematoma is retroperitoneal, pain may be minimal, and the client may initially present with signs of shock. Treatment of small vulvar hematomas may require only analgesia and use of ice packs applied to the perineum for 24 hours to reduce swelling. If the hematoma is large or expands rapidly, surgical intervention may be necessary.", "whyNot": {"a": "Lacerations sustained during delivery usually occur in the cervix, perineum, or vagina.", "b": "Hypotension and tachycardia are only likely when the hemorrhage is severe.", "c": "Avulvar hematoma is usually visible."}, "keyConcept": "Avulvar hematoma following an episiotomy is the result of bleeding and trauma during the birth process. The pregnant uterus, vagina, and vulva have a rich vascular supply. The vulvar hematoma is painful and may cause discomfort in sitting or moving around. Pain medication does little to reduce the pain due to the swelling and inflammation in the area. A surgical procedure may be necessary to remove the clots."}, {"id": 10083, "cat": "GENITAL & REPRODUCTIVE", "stem": "discharge teaching? O A. The client should use condoms during sexual intercourse until all lesions are healed. O B. The client should use gloves to apply topical lidocaine to the lesions. O C. The client should tape a folded gauze pad to the lesions to avoid shedding the virus into the environment. O D. The client will be contagious until eradication of virus is confirmed by a blood test.", "choices": [{"id": "a", "t": "The client should use condoms during sexual intercourse until lesions are healed."}, {"id": "b", "t": "The client should use gloves to apply topical lidocaine to the lesions."}, {"id": "c", "t": "The client should tape a folded gauze pad to the lesions to avoid shedding the virus into the environment."}, {"id": "d", "t": "The client will be contagious until eradication of virus is confirmed by a blood test."}], "correct": "b", "rationale": "‘i o: Genital herpes is a sexually transmitted disease that is caused by the herpes simplex virus. It is very contagious, even when active lesions Cc l have healed. The disease can be spread by contact with oral or genital secretions, active lesions, and contact with mucosal surfaces. The D | nurse should teach the client to wear gloves when applying a topical medication to the lesion to avoid the spread of infection to others or to another part of the body. Although antiviral medications do not cure the disease, treatment can reduce the incidence and duration of outbreaks and can reduce the risk of transmission of the infection. Use of condoms can reduce, but not eliminate, the risk of transmitting or acquiring genital herpes.", "whyNot": {"a": "Genital herpes is extremely contagious, so individuals should remain abstinent when active lesions are present and should always wear", "c": "The lesions should be cleaned with soap and warm water and then kept dry, but they should not be bandaged.", "d": "The client will always remain contagious, as there is no cure for this viral infection. Acyclovir, valacyclovir, and famciclovir are antiviral"}, "keyConcept": "Genital herpes is a sexually transmitted disease caused by the herpes simplex virus type 1 (HSV-1) or type 2 (HSV-2). Infections are transmitted through contact with HSV in herpes lesions, mucosal surfaces, genital secretions, or oral secretions. HSV-1 and HSV-2 can be shed during periods of active disease or from normal-appearing oral or genital mucosa or skin during periods of latency. Antiviral medications do not provide a cure but can reduce the severity and frequency of outbreaks."}, {"id": 10084, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is instructing a client who will begin using a contraceptive sponge for birth control. Which of the following will maximize the efficacy of this form of birth control?", "choices": [{"id": "a", "t": "Spermicidal jelly should be inserted with the sponge."}, {"id": "b", "t": "Anew sponge must be placed every time the client has intercourse."}, {"id": "c", "t": "The sponge must be removed immediately after intercourse."}, {"id": "d", "t": "The sponge should be moistened with tap water until foamy prior to use."}], "correct": "d", "rationale": "Acontraceptive sponge is a small, round sponge made of polyurethane and impregnated with N-9 spermicide. The sponge fits over the Cc i cervix, and one size fits all. The concave side is placed over the cervix, and the opposite side has a loop that is used to remove the sponge. eD || Cervical sponges should be moistened with water until foamy before insertion. The sponge provides up to 24 hours of protection for sexual intercourse, even if multiple instances occur. After the last instance of sexual intercourse, the sponge should remain in place for at least 6 hours. Women who use the sponge should be aware that use for longer than 23 to 30 hours increases the risk of toxic shock syndrome. The failure rate of this method of contraception in the first year of use is 12% among women who have never been pregnant and 24% among women with prior pregnancies.", "whyNot": {"a": "The sponge contains a spermicide.", "b": "The sponge provides contraception for multiple encounters over a 24-hour period.", "c": "The sponge should be left in place for at least 6 hours after the last instance of sexual intercourse."}, "keyConcept": "Contraceptive sponges are impregnated with spermicide and fit over the cervix. They are one-size-fits-all. Clients should be advised to moisten the sponge until foamy before insertion. The sponge should be left in place for at least six hours after sexual intercourse. They offer up to 24 hours of protection against conception, but the risk of toxic shock syndrome due to Staphylococcus aureus is increased when the sponge is left in place for longer than 23 hours."}, {"id": 10085, "cat": "GENITAL & REPRODUCTIVE", "stem": "A client calls the clinic and tells the nurse she forgot to take her oral contraceptive this morning. Which of the following should the nurse instruct the client to do?", "choices": [{"id": "a", "t": "Take the medication immediately"}, {"id": "b", "t": "Restart the medication in the morning"}, {"id": "c", "t": "Use another form of contraception for 2 weeks"}, {"id": "d", "t": "Take two pills tonight before bedtime"}], "correct": "a", "rationale": "The nurse should instruct the client take the medication immediately, and if this happens again, as soon as she remembers that she missed B i at the medication. There is a slight risk that the client will become pregnant when only one pill has been missed. cli 8%", "whyNot": {"b": "The client should take the medication as soon as she remembers and not wait until the morning.", "c": "The client most likely does not need to use another form of contraception if she forgets one dose of the medication and then takes it soon", "d": "In this case, the client only needs to take the dose of the medication she forgot, not two pills before bedtime."}, "keyConcept": "Oral contraceptive pills should be taken at the same time each day. When a client on combined contraceptive pill forgets to take a pill, the nurse's advice will depend on how many the client has missed (more than 24 hours since it should have been taken); the part of the cycle the client was in when the pill was missed; and the type of combined pill. If the client has missed one pill anywhere in the pack or started anew pack one day late, she will still be protected against pregnancy. The client should:take the last pill missed now, even if this means taking two pills in one day and take the rest of the pack as normal. If the client has missed two or more pills or started a new pack two or more days late (48 hours or more), the nurse should advise the client to take the last pill missed, even if this means taking two pills in one day. The client should not take any earlier missed pills, but should continue to take the rest of the pills as prescribed. In this case, the client should be advised to use an alternate form of contraception. This should provide barrier protection, such as a condom."}, {"id": 10086, "cat": "GENITAL & REPRODUCTIVE", "stem": "@ @ %& Viraln. 8s Record Mi Inbox( ™ Inbox- [E} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr @® ATITE € > G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. % CLOSE Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Gonorrhea O >B. syphilis"}, {"id": "b", "t": "sll Late stages of syphilis include these symptoms and can be fatal."}, {"id": "c", "t": "Chlamydia O p.xPv"}], "correct": "b", "rationale": "sll Late stages of syphilis include these symptoms and can be fatal. A healthcare provider can diagnose tertiary syphilis with the help of multiple OR rd tests. It can affect the heart, brain, and other organs of the body. cil", "whyNot": {"a": "While untreated gonorrhea can spread to the blood and joints, it does not cause paralysis, blindness, and dementia.", "c": "Untreated chlamydia can cause pelvic inflammatory disease; however, it does not lead to paralysis, blindness, and dementia."}, "keyConcept": "Syphilis is an infection caused by the bacterium Treponema pallidum. It is usually spread by sexual contact, including direct contact with a syphilis sore (chancre), which is a firm, raised, painless genital ulcer. The most common syphilis tests detect antibodies in the blood that are produced in response to a T. pallidum infection. Two tests are required for the diagnosis if the screening test is positive. A treponemal test must be positive to make the diagnosis. Primary syphilis: a sore or sores at the original site of infection (on or around the genitals, around the anus or in the rectum, or in or around the mouth). Secondary syphilis: a skin rash, swollen lymph nodes, and fever. Latent stage: no signs or symptoms. Tertiary syphilis: 10-30 years after infection was first acquired. It can affect the heart, eyes, brain, and other organs of the body."}, {"id": 10087, "cat": "GENITAL & REPRODUCTIVE", "stem": "The nurse is developing a plan of care for a postpartum client. Which of the following considerations is most important when discussing whether oral contraceptive pills are the best method of contraception?", "choices": [{"id": "a", "t": "This is the client’s second child"}, {"id": "b", "t": "The client states she was forgetful about taking prenatal vitamins"}, {"id": "c", "t": "The client is five feet eight inches tall and weighs 145 pounds"}, {"id": "d", "t": "The client states she has had bad acne since delivery"}], "correct": "b", "rationale": "If the client was forgetful when taking her prenatal vitamins, she may have difficulties with remembering to take oral contraceptive pills. The nurse should discuss the client’s intentions for birth control and add this fact to the plan of care.", "whyNot": {"a": "Itis the client’s decision whether or not she should take oral contraceptive pills. That the client is having a second child is not significant to", "c": "This client would not be considered overweight, so it would not be a factor for her when considering oral contraceptive pills.", "d": "Acne is usually decreased with the use of hormonal contraception and is not a contraindication."}, "keyConcept": "Oral contraceptive pills can contain estrogen and progestin or progestin alone (\"mini-pill\".) The efficacy of oral contraceptive pills in preventing pregnancy is very high, with a failure rate of only 2 per 100 years of use. This is one of the primary advantages associated with the use of oral contraceptive pills compared to other forms of contraception. With respect to risks, a variety of studies have shown evidence for an increase in thromboembolic events in women on oral contraceptives. In addition, there appears to be increased risk of breast cancer in nulliparous women who have taken the pill for ten or more years after beginning the pill when they were less than 25 years of age. Other side effects include some weight gain, fluid retention, and headache."}, {"id": 10088, "cat": "GENITAL & REPRODUCTIVE", "stem": "@ @ X& Viralni x Record M Inbox( ™ Inbox- [J Untitle: Untitle’ (@ Google @ TEASP Online & MarkK @ Micros (eevee melicr @ Atite = G@ Newel NC x) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Trichomoniasis O >B. syphilis"}, {"id": "c", "t": "Human papillomavirus"}, {"id": "d", "t": "Gonorrhea"}], "correct": "c", "rationale": "| 2% Easy The vaccine for HPV is safe and effective and protects males and females against the disease. HPV vaccines are given in a series of two or B | a0 three shots over a six-month period.", "whyNot": {"a": "There is no vaccine to protect against trichomoniasis. The nurse would instead teach these clients about a vaccine against human", "d": "There is no vaccine to protect against gonorrhea. The nurse would instead teach these clients about a vaccine against human"}, "keyConcept": "More than 30,000 women and men are diagnosed each year with a cancer caused by sexually transmitted HPV infection. Cervical cancer accounts for one in three cancers caused by infection with the human papillomavirus. Vaccination prevents infection and reduces the risk of cancer. Two doses of the HPV vaccine are recommended if the series is started before the client's 15th birthday. Three doses of the HPV vaccine are recommended for teens and young adults who start the series at ages 15 through 26 years, and for immunocompromised persons."}, {"id": 10089, "cat": "GENITAL & REPRODUCTIVE", "stem": "appropriate initial intervention by the nurse?", "choices": [{"id": "a", "t": "Begin broad-spectrum antibiotics (gentamycin and clindamycin)"}, {"id": "b", "t": "Draw blood for culture and sensitivity"}, {"id": "c", "t": "Administer acetaminophen to reduce fever"}, {"id": "d", "t": "Administer IV fluid bolus"}], "correct": "b", "rationale": "28 days of childbirth, miscarriage, or induced Cc || 13% abortion. Endometritis is the most common type of postpartum infection, beginning at the placental site. Endometritis can involve the entire D Hi 17% endometrium. Culture and sensitivity using blood, intracervical, or intrauterine cultures are indicated to identify the infecting organism and guide antibiotic therapy. Blood cultures must be drawn before initiation of antibiotics. Other measures are secondary to obtaining blood cultures and then beginning antibiotic therapy. Secondary measures should address the client’s symptoms, including warm blankets, analgesics, rest, and hydration. Perineal care and sitz baths are also appropriate interventions. The mother may need encouragement to continue breastfeeding, if it is allowed during treatment, and to maintain mother-child interactions.", "whyNot": {"a": "Blood cultures should be obtained prior to initiation of antibiotic therapy.", "c": "Acetaminophen can be given to reduce fever for client comfort, but it is a secondary measure.", "d": "Hydration is a secondary measure that can be initiated after antibiotic therapy has started."}, "keyConcept": "Fever, tachycardia, and abnormal lochia in a postpartum woman suggests puerperal infection. Endometritis is the most common infection and antibiotic therapy is initiated after obtaining blood, intracervical, and intrauterine cultures."}, {"id": 10090, "cat": "GENITAL & REPRODUCTIVE", "stem": "should explain that the length of the fertility period surrounding ovulation lasts for which of the following periods of time?", "choices": [{"id": "a", "t": "12 hours before and 24 hours after ovulation"}, {"id": "b", "t": "72 hours before and 24 hours after ovulation"}, {"id": "c", "t": "72 to 80 hours before and 72 hours after ovulation"}, {"id": "d", "t": "24 to 48 hours before and 48 hours after ovulation"}], "correct": "b", "rationale": "im | 14% Hard The ovum is fertilizable for 12 to 24 hours and sperm remain mobile for about 72 hours. Therefore, the period of fertility is a total of 96 hours, On a Bort 72 hours before ovulation and 24 hours after ovulation. ° ci 15%", "whyNot": {"a": "The ovum can be fertilized for longer than 12 hours before ovulation.", "c": "The ovum can be fertilized for 72 hours before ovulation and up to 24 hours after ovulation.", "d": "The ovum can be fertilized for longer than 48 hours before ovulation and for only 24 hours after ovulation."}, "keyConcept": "The basal body temperature method of contraception or family planning is a type of natural family planning. The basal body temperature is the temperature when the woman is fully at rest. Ovulation may cause a slight increase in basal body temperature. The woman should take her body temperature at the same time each morning before she gets out of bed and before eating. The temperature should be recorded on a graph. When the temperature rises slightly (0.2° to 0.5°C (0.4° to 1.0°F) just after ovulation, the couple should avoid vaginal sex, or use condoms or a diaphragm. The couple can have unprotected sex on the 4th day and until the next menstrual period begins. <2 Ss & ° 2-0 0OOT VOD eA © © Recruited Maturing . Corpus Degenerate Follicle Follicle Ovulation Luteum = C. Luteum 37°C \\ Bate Tampgawe 36°C Luteinizing Hormone (LH) Progesterone Y Follicle-Stimulating"}, {"id": 10091, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is assessing a client who had been treated for dyspareunia. Which of the following indicates an expected outcome after treatment?", "choices": [{"id": "a", "t": "The client reports decreased menstrual bleeding"}, {"id": "b", "t": "The client reports decreased breakthrough bleeding"}, {"id": "c", "t": "The client reports little to no pain during sexual intercourse"}, {"id": "d", "t": "The client denies abdominal pain before or during menses"}], "correct": "c", "rationale": "Relief or resolution of pain during sexual intercourse is an expected outcome.", "whyNot": {"a": "Decreased menstrual bleeding would be an expected outcome in the treatment of menorrhagia.", "b": "Decreased breakthrough bleeding would be an expected outcome in the treatment of metrorrhagia.", "d": "This would be an expected outcome in the treatment of dysmenorrhea."}, "keyConcept": "Dyspareunia refers to painful intercourse. This condition can result in a diminished quality of life for the client. Causes include cancer, pelvic inflammatory disease, a history of sexual abuse, depression, anxiety, obstetrical trauma, and hormonal imbalance."}, {"id": 10092, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse ina clinic is caring for a client who has suspected uterine cancer. For which of the following procedures should the nurse prepare the client?", "choices": [{"id": "a", "t": "Bimanual pelvic examination"}, {"id": "b", "t": "Papanicolaou (Pap) test"}, {"id": "c", "t": "Digital rectal examination"}, {"id": "d", "t": "Urinalysis with culture and sensitivity"}], "correct": "a", "rationale": "o; a Due to the location of uterine cancer, the provider should perform a bimanual pelvic examination to assess for uterine size, shape, and B a contour, which can be altered by a mass. | ©", "whyNot": {"b": "A Pap test screens for cervical cancer.", "c": "A digital rectal examination screens for prostate and rectal cancer.", "d": "A urinalysis with culture and sensitivity screens for bladder cancer."}, "keyConcept": "The nurse should identify that risk factors for uterine cancer can include a family history of uterine cancer, obesity, hypertension, diabetes mellitus, no pregnancies, late menopause, uterine polyps, and smoking."}, {"id": 10093, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client who reports exposure to pubic lice. Which of the following does the nurse expect to find on an assessment?", "choices": [{"id": "a", "t": "Pruritus"}, {"id": "b", "t": "Fever"}, {"id": "c", "t": "Malodorous discharge"}, {"id": "d", "t": "Labial ulceration"}], "correct": "a", "rationale": "Pubic lice are a parasitic skin infection known as pediculosis pubis. The most common associated symptom of a pubic lice infestation is Cc I pruritus (itching), particularly in the perirectal or vulvar area. Pubic lice are transmitted through contact with infested bed linen or through D | sexual intercourse with an infested individual. The nurse may also expect excoriation of the skin in the area as a result of scratching. The genital area is usually affected, but pubic lice can also be found on the eyelashes, chest, and axilla. Treatment is by application of a shampoo, cream, or topical spray that contains permethrin, lindane, or topical malathion. Ivermectin is an oral anti-parasitic agent that can also be effective in treatment of any type of body lice. Nits are removed with a fine tooth comb, and bed linens and clothing should be washed in hot soapy water or dry-cleaned. Any upholstery that has been in contact with the client’s head should also be treated.", "whyNot": {"b": "Lice infection does not result in fever.", "c": "Discharge is not characteristic of pubic lice infestation. It is typical of sexually transmitted infections with chlamydia, gonorrhea,", "d": "Vulvar excoriations may occur from scratching, but ulcerations on the labia are not a characteristic of a pubic lice infestation."}, "keyConcept": "Pubic lice infestations are characterized by itching, usually in the perirectal or vulvar area, which may result in excoriation of skin. Pubic lice may also be found on eyelashes, chest, and in the axilla. After treatment with a topical agent containing permethrin or lindane, nits should be removed with a fine tooth comb or tweezers and linens/clothing must be washed in hot soapy water or dry-cleaned."}, {"id": 10094, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client who reports exposure to pubic lice. Which of the following does the nurse expect to find on an assessment?", "choices": [{"id": "a", "t": "Pruritus"}, {"id": "b", "t": "Fever"}, {"id": "c", "t": "Malodorous discharge"}, {"id": "d", "t": "Labial ulceration eck Answer"}], "correct": "a", "rationale": "Pubic lice are a parasitic skin infection known as pediculosis pubis. The most common associated symptom of a pubic lice infestation is Cc I pruritus (itching), particularly in the perirectal or vulvar area. Pubic lice are transmitted through contact with infested bed linen or through D | | sexual intercourse with an infested individual. The nurse may also expect excoriation of the skin in the area as a result of scratching. The genital area is usually affected, but pubic lice can also be found on the eyelashes, chest, and axilla. Treatment is by application of a shampoo, cream, or topical spray that contains permethrin, lindane, or topical malathion. Ivermectin is an oral anti-parasitic agent that can also be effective in treatment of any type of body lice. Nits are removed with a fine tooth comb, and bed linens and clothing should be washed in hot soapy water or dry-cleaned. Any upholstery that has been in contact with the client’s head should also be treated.", "whyNot": {"b": "Lice infection does not result in fever.", "c": "Discharge is not characteristic of pubic lice infestation. It is typical of sexually transmitted infections with chlamydia, gonorrhea,", "d": "Vulvar excoriations may occur from scratching, but ulcerations on the labia are not a characteristic of a pubic lice infestation."}, "keyConcept": "Pubic lice infestations are characterized by itching, usually in the perirectal or vulvar area, which may result in excoriation of skin. Pubic lice may also be found on eyelashes, chest, and in the axilla. After treatment with a topical agent containing permethrin or lindane, nits should be removed with a fine tooth comb or tweezers and linens/clothing must be washed in hot soapy water or dry-cleaned."}, {"id": 10095, "cat": "GENITAL & REPRODUCTIVE", "stem": "@ @ %& Viraln. 8s Record Mi Inbox( ™ Inbox- [E} Untitle: Untitle (4 Google @ TEASF Online & MarkkK @ Micros eae meter @ ATiTE @ Newel $ (NeES ECS eMC [-|NC x) + v € > G 23 student.atitesting.com/LT| Qa * a * OD Cb Finish update : oO Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "0% iui]"}, {"id": "b", "t": "0% 5"}, {"id": "c", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "d", "t": "0% [="}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}, {"id": 10096, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client in the labor and delivery service who is receiving oxytocin after prolonged labor. Intervention is necessary when which assessment finding is noted? O A.6 contractions in 10 minutes O B. Temperature of 99.8°F O C. Cervical dilation from 5 to 6 cm in 1 hour O D. Fetal heart rate of 150/min with moderate variability and no late decelerations", "choices": [{"id": "a", "t": "Oxytocin, a hormone produced in the posterior pituitary gland, stimulates uterine contractions and let-down of milk."}, {"id": "b", "t": "The temperature should be monitored and the healthcare provider notified when the temperature is greater than 100.4°F (38°C). If"}, {"id": "c", "t": "This is an expected finding."}, {"id": "d", "t": "This is a normal fetal heart rate. variability is normal. Late decelerations are a sign of potential fetal distress. A normal fetal heart"}], "correct": "a", "rationale": "Oxytocin, a hormone produced in the posterior pituitary gland, stimulates uterine contractions and let-down of milk. A synthetic form, Cc | | Pitocin, is used to induce or augment labor and to control postpartum bleeding. It is associated with potential risks of uterine tachysystole, D i postpartum hemorrhage, infection, and death from water intoxication, as well as uterine rupture, placental abruption, and unnecessary cesarean birth as a result of abnormalities in fetal heart rate patterns. Uterine tachysystole is characterized by more than 5 contractions in 10 minutes averaged over a 30-minute time period, a series of single contractions lasting longer than 2 minutes, or contractions of normal duration that occur within a minute of each other. Initial nursing interventions, if the fetal heart rate tracing is reassuring, include repositioning the client in the side-lying position, administration of an IV fluid bolus, and reduction or discontinuation of oxytocin. If the FHR tracing is non-reassuring, with fetal bradycardia, late decelerations, or decreased variability with tachycardia, the nurse should stop the oxytocin infusion immediately and reposition the client. Oxygen can be given at 10 L/minute by face mask if abnormalities do not improve. An IV fluid bolus can be given, and the healthcare provider should be notified. Terbutaline may be prescribed per protocol or by the HCP to treat the client.", "whyNot": {"b": "The temperature should be monitored and the healthcare provider notified when the temperature is greater than 100.4°F (38°C). If", "c": "This is an expected finding.", "d": "This is a normal fetal heart rate. Moderate variability is normal. Late decelerations are a sign of potential fetal distress. A normal fetal heart"}, "keyConcept": "Pitocin is a synthetic form of the hormone oxytocin. It is administered to induce or augment labor and to stimulate uterine contraction to control postpartum bleeding. Close fetal and maternal monitoring is necessary during administration, since risks include uterine tachysystole, fetal distress, placental abruption, or uterine rupture."}, {"id": 10097, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is asked to provide education about safe sex to a group of high-school students. Which of the following statements by a student indicates understanding? O A.\"Males in their teens are at highest risk for sexually transmitted infections.\" O B. \"HIV is transmitted to females more readily than to males.\" O C. \"I will use a lot of spermicide each time | have sexual intercourse.\" O D. \"If | only have oral sex, | won’t get an STD.\"", "choices": [{"id": "a", "t": "Young females are at highest risk for STIs."}, {"id": "b", "t": "Women are biologically more receptive than men to infection by sexually transmitted organisms."}, {"id": "c", "t": "Condoms are as effective as condoms plus spermicide."}, {"id": "d", "t": "STIs can be transmitted through genital, oral, or anal sex."}], "correct": "b", "rationale": "Women are biologically more receptive than men to infection by sexually transmitted organisms. When providing education about safe Cc | | 8% sexual practices and sexually transmitted diseases, the Centers for Disease Control and Prevention (CDC) recommend emphasizing , increased use of condoms, and prevention of recurrent sexually transmitted infections (STIs). The CDC information for teens and young adults notes that abstinence is the only way to avoid all risk, but use of condoms on every occasion is effective for prevention of STIs. When providing education, the nurse should be able to describe or demonstrate the correct use of a condom. It is important to notify teens that testing is available for free, and untreated STIs can result in increased risk of HIV infection or infertility issues in later life.", "whyNot": {"a": "Young females are at highest risk for STIs.", "c": "Condoms are as effective as condoms plus spermicide.", "d": "STIs can be transmitted through genital, oral, or anal sex."}, "keyConcept": "Women are more receptive to infection by sexually transmitted pathogens. The CDC recommends emphasis on use of condoms, avoidance of risky behaviors, and prevention of recurrent sexually transmitted infections. Nurses should emphasize that testing is available without charge."}, {"id": 10098, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is preparing to insert an indwelling urinary catheter for a female client. As the catheter is inserted, which of the following instructions should the nurse give the client?", "choices": [{"id": "a", "t": "Contract the pelvic muscles."}, {"id": "b", "t": "Take a sip of water."}, {"id": "c", "t": "Breathe out slowly through the mouth."}, {"id": "d", "t": "Bear down."}], "correct": "d", "rationale": "| 1% Female pelvis oc i 54% The nurse should instruct the client to bear down gently as if to void to relax the external sphincter and ease urinary catheter insertion. The process can also aid in the visualization of the urinary meatus. Parsretal Sane) tine ‘Sand opening Labi ese", "whyNot": {"a": "The nurse should instruct the client to contract her pelvic muscles to improve their strength and help manage urinary incontinence. This", "b": "The nurse should instruct the client to take a sip of water to help ease the insertion of a nasogastric tube, not a urinary catheter.", "c": "The nurse should ask the client to breathe out slowly through the mouth to assist the client to relax prior to inserting the rectal tip of an"}, "keyConcept": "Nurses are responsible for the insertion of indwelling urinary catheters. They should be able to identify the steps of the procedure and instruct the client on interventions to assist with the insertion."}, {"id": 10099, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is teaching a client about using a hormonal intrauterine device (IUD) for contraception. Which of the following statements by the client indicates an understanding of the information? O A.\"My doctor will replace this device every year when | have my pelvic examination.\" O B. \"This device protects me against getting a sexually transmitted infection.\" O C. \"I should expect frequent abdominal pain while this device is in place.\" O D. \"If | cannot feel the string of this device, | should notify my doctor.\"", "choices": [{"id": "a", "t": "Nurses should inform clients that the provider will replace a hormonal IUD every 3 or 5 years, depending on the type of hormonal IUD they"}, {"id": "b", "t": "An IUD does not protect against sexually transmitted infections. Clients should use barrier methods of contraception, such as condoms, to"}, {"id": "c", "t": "Abdominal pain with an IUD can indicate a potential complication. The client should report any abdominal pain to the provider."}, {"id": "d", "t": "All 10% Easy Nurses should instruct clients to notify the provider if they cannot feel the string or if they notice a change in the length of the string because ."}], "correct": "d", "rationale": "All 10% Easy Nurses should instruct clients to notify the provider if they cannot feel the string or if they notice a change in the length of the string because . chi 6%", "whyNot": {"a": "Nurses should inform clients that the provider will replace a hormonal IUD every 3 or 5 years, depending on the type of hormonal IUD they", "b": "An IUD does not protect against sexually transmitted infections. Clients should use barrier methods of contraception, such as condoms, to", "c": "Abdominal pain with an IUD can indicate a potential complication. The client should report any abdominal pain to the provider."}, "keyConcept": "Providers insert intrauterine devices (IUDs) into the uterus. Hormonal IUDs release hormones to prevent pregnancy by decreasing the mobility of the sperm. Clients should expect their provider to replace hormonal IUDs every 3 or 5 years, depending on the specific hormonal device, and copper IUDs every 10 years. Nurses should inform clients that these devices will not protect against contracting or transmitting sexually transmitted infections. They should also inform clients about the common adverse effects and the manifestations to report to the provider. Every month, clients should feel for the string of the IUD. If they cannot feel the string or if the length of the string has changed, they should notify their provider because this could indicate expulsion or dislodgement of the device."}, {"id": 10100, "cat": "GENITAL & REPRODUCTIVE", "stem": "should be reported to a physician? O", "choices": [{"id": "a", "t": "Bleeding, nausea, and rash"}, {"id": "b", "t": "Rapid heart rate, weakness, and syncopal episodes"}, {"id": "c", "t": "Hypertension, tenderness in the calf, and breast nodules"}, {"id": "d", "t": "Bradycardia, pruritis changes, and hypertension"}], "correct": "c", "rationale": "-progestin contraceptives have been associated with increased risk of thrombophlebitis, which would cause pain in the calf; breast , which may produce breast nodules; and cardiovascular changes (hypertension). °", "whyNot": {"a": "Breakthrough bleeding is a common side effect, however, nausea and a rash are not commonly reported side effects.", "b": "These side effects are not commonly reported.", "d": "Bradycardia and pruritis are not usual side effects; hypertension is."}, "keyConcept": "Combined estrogen-progestin oral contraceptive pills are used to prevent pregnancy and to resolve irregular menstruation, painful or heavy periods, endometriosis, acne, and premenstrual syndrome. They work by preventing ovulation. Monophasic pills all contain the same balance of hormones. With phasic pills, two or three different types of pill with a different balance of hormones are taken each month. Common side effects include intermenstrual spotting, nausea, breast tenderness, headaches, and migraine; weight gain, mood changes, missed periods, decreased libido, and vaginal discharge."}, {"id": 10101, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is assessing a teenage male client status post-unilateral orchiectomy. Which of the following should be included in the client’s long-term plan of care?", "choices": [{"id": "a", "t": "Chronic pain"}, {"id": "b", "t": "Risk for impaired skin integrity"}, {"id": "c", "t": "Risk for infection"}, {"id": "d", "t": "Risk for sexual dysfunction"}], "correct": "d", "rationale": "| The client is at current and future risk for sexual dysfunction. a I", "whyNot": {"a": "Chronic pain is not expected and therefore is not an appropriate long-term concern. e@D FY", "b": "The client has impaired skin integrity related to surgery. This is not a long-term concern.", "c": "Risk for infection is an appropriate diagnosis post-operatively, not long-term."}, "keyConcept": "Orchiectomy is a procedure to remove the testicle, usually performed in men in whom testicular cancer is suspected. Side effects can include fertility problems and sexual dysfunction, including erectile dysfunction, as a result of damage to the nerves that supply the penis and scrotum."}, {"id": 10102, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is teaching a client about symptoms to report to the provider while taking oral contraceptives. Which symptom should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Reduced menstrual flow"}, {"id": "b", "t": "Breast tenderness"}, {"id": "c", "t": "Leg pain"}, {"id": "d", "t": "Headaches"}], "correct": "c", "rationale": "all 6% Easy Thrombolytic disease is an adverse effect of taking oral contraceptives because these medications can contain hormones such as estrogen B I a and progestin. Leg cramps and pain are findings to report to the provider because they could indicate thrombolytic disease.", "whyNot": {"a": "Reduced menstrual flow is a common adverse effect of oral contraceptives and usually subsides after a few months of use.", "b": "Breast tenderness is a common adverse effect of oral contraceptives and usually subsides after a few months of use.", "d": "Headaches are a common adverse effect of oral contraceptives and usually subside after a few months of use."}, "keyConcept": "Oral contraceptives contain hormones, such as estrogen and progestin, that can cause side effects, such as nausea, weight gain, headaches, breast tenderness, and depression. Taking oral contraceptives can also put clients at risk for developing myocardial infarction, blood clots, and stroke. Nurses should inform clients about the common adverse effects of the medication and instruct them to notify the provider if they have shortness of breath, chest pain, leg cramps or pain, or blurry vision. Leg cramps and pain are findings that should be reported to the provider because they could indicate thrombolytic disease."}, {"id": 10103, "cat": "GENITAL & REPRODUCTIVE", "stem": "following? O A. Chlamydia O B. Genital herpes O c syphilis O D. Trichomoniasis", "choices": [{"id": "a", "t": "Chlamydia"}, {"id": "b", "t": "Genital herpes O c syphilis"}, {"id": "d", "t": "Trichomoniasis"}], "correct": "d", "rationale": "Typically, a female client with trichomoniasis experiences itching, burning, redness or soreness of the genitals; discomfort with urination; and a change in the character or volume of vaginal discharge (thin discharge or increased volume.) Vaginal discharge can be clear, white, yellowish, or greenish, but it is classically described as malodorous, with an unusual fishy smell.", "whyNot": {"a": "Chlamydia is often asymptomatic until the infection has progressed to cause pelvic inflammatory disease or other complications.", "b": "Genital herpes causes a painful vesicular rash."}, "keyConcept": "Symptoms of trichomoniasis range from mild irritation to severe inflammation. Seventy percent of infected individuals are asymptomatic. In male clients, trichomoniasis is associated with itching or irritation inside the penis; burning after urination or ejaculation; and discharge from the penis. Trichomoniasis can be treated with oral metronidazole or tinidazole. These medications are safe for pregnant women. Clients should not drink alcohol within 24 hours after taking this medication."}, {"id": 10104, "cat": "GENITAL & REPRODUCTIVE", "stem": "You are caring for a female client who would like information about contraceptive methods. Which would be considered an absolute contraindication in considering the use of using oral contraceptives?", "choices": [{"id": "a", "t": "Gallbladder disease"}, {"id": "b", "t": "High cholesterol"}, {"id": "c", "t": "Blood clotting disorders"}, {"id": "d", "t": "Gastroesophageal reflux"}], "correct": "c", "rationale": "al 3% Easy Women who take oral contraceptives are at higher risk of developing blood clots. If a woman has a blood clotting disorder, she is at even B I a greater risk of deep vein thrombosis, pulmonary embolism, or stroke.", "whyNot": {"a": "Gallbladder disease is considered a relative contraindication for oral contraceptive use, not an absolute contraindication.", "b": "High cholesterol is considered a relative contraindication for oral contraceptive use, not an absolute contraindication.", "d": "Gastroesophageal reflux is considered a relative contraindication for oral contraceptive use, not an absolute contraindication."}, "keyConcept": "Absolute contraindications to oral contraceptives include thrombophlebitis or thromboembolic disorders; cerebrovascular or coronary artery disease; breast cancer or another estrogen-dependent tumor; undiagnosed abnormal genital bleeding; known or suspected pregnancy; and benign or malignant liver tumors. Smoking increases the risk of thromboembolic disorders in clients who are taking oral contraceptives and is a relative contraindication."}, {"id": 10105, "cat": "GENITAL & REPRODUCTIVE", "stem": "Amale client reports that he was informed by a partner about recent exposure to chlamydia. Which of the following symptoms would the nurse expect when assessing this client if he has a chlamydia infection?", "choices": [{"id": "a", "t": "Vesicular rash"}, {"id": "b", "t": "Dysuria"}, {"id": "c", "t": "Pain with ejaculation"}, {"id": "d", "t": "Ulceration on penis"}], "correct": "b", "rationale": "‘i o: Chlamydia is a common sexually transmitted infection that infects both men and women but can result in serious damage to the female Cc i reproductive system, preventing future pregnancy and increasing the risk of ectopic pregnancy. Although most individuals with chlamydia D i infection are asymptomatic, male symptoms of chlamydia infection include penile discharge, dysuria (burning with urination), and testicular pain and swelling, a less common manifestation. Female symptoms may include vaginal discharge and dysuria. The CDC recommends annual testing for every sexually active woman under age 25.", "whyNot": {"a": "Vesicular lesions are associated with herpes viruses, including genital herpes.", "c": "Pain with ejaculation is not associated with chlamydia infection.", "d": "Syphilis is associated with a penile ulceration."}, "keyConcept": "Chlamydia is a common sexually transmitted infection that can cause infertility and increase the risk of ectopic pregnancy in females. Most individuals are asymptomatic, but male symptoms may include dysuria, penile discharge, and testicular pain or swelling. In sexually active women, annual testing is recommended before the age of 25. When diagnosed, both the client and all partners should be treated."}, {"id": 10106, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is teaching a client who has been newly diagnosed with genital herpes. What should the nurse advise the client?", "choices": [{"id": "a", "t": "Antiviral therapy eliminates viral shedding."}, {"id": "b", "t": "The risk of HIV infection is increased in individuals who have genital herpes."}, {"id": "c", "t": "Use of condoms eliminates the risk of transmission."}, {"id": "d", "t": "Viral transmission only occurs when herpes sores are visible."}], "correct": "b", "rationale": "Genital herpes is a sexually transmitted viral infection that cannot be cured. Infection results in episodes of disease activity characterized by painful genital ulcers interrupted by latent periods, when symptoms are absent. The virus can be transmitted during both active and latent periods of infection. Condoms reduce the risk of transmission, but do not eliminate all risk.", "whyNot": {"a": "Although antiviral medications used for suppression will reduce viral shedding, the virus not completely eliminated.", "c": "Use of condoms decreases the risk of transmission, but does not eliminate it.", "d": "Viral transmission can occur when sores are absent or present."}, "keyConcept": "Genital herpes is a sexually transmitted viral infection that cannot be cured. Infection results in episodes of disease activity characterized by painful genital ulcers interrupted by latent periods, when symptoms are absent. The virus can be transmitted during both active and latent periods of infection. Condoms reduce the risk of transmission, but do not eliminate all risk."}, {"id": 10107, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse in a gynecology clinic is caring for a 38-year-old client with suspected cervical cancer. While taking the client's history, the nurse knows to ask about which of the following risk factors for the disease?", "choices": [{"id": "a", "t": "Gestational diabetes mellitus"}, {"id": "b", "t": "First full-term pregnancy at age 26"}, {"id": "c", "t": "Human papillomavirus infection"}, {"id": "d", "t": "Menarche at age 10"}], "correct": "c", "rationale": "| 2% Easy Human papillomavirus infection is a risk factor for cervical cancer.", "whyNot": {"a": "Gestational diabetes is not a risk factor for cervical cancer.", "b": "First full-term pregnancy above age 26 is not a risk factor for cervical cancer.", "d": "Early menarche is not a risk factor for cervical cancer."}, "keyConcept": "The primary risk factor for cervical cancer is human papilloma virus infection, particularly the strains HPV16 and HPV 18. Human papillomavirus (HPV) is usually transitted by direct skin-to-skin contact. It is the most common sexually transmitted infection in the United States. Vaccination can prevent a lasting HPV infection after exposure to the virus. Gardasil 9 protects against infection from HPV-16 and HPV- 18 and 5 additional types of HPV linked with cancer. The vaccine also offers protection against 2 low-risk HPVs known to cause 90% of genital warts."}, {"id": 10108, "cat": "GENITAL & REPRODUCTIVE", "stem": "@ %&€ Viralni sx Record M Inbox( ™ Inbox- [J Untitle: Untitle’ (@ Google @ TEASP Online & MarkK @ Micros (eevee melicr @ Atite = G@ Newel NC x) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Rhogam is not administered if the mother and the fetus's blood type match (the same)."}, {"id": "b", "t": "Individuals with Rh-negative blood develop antibodies after exposure to Rh-positive blood."}, {"id": "c", "t": "Rhogam is not administered if the mother and the fetus's blood type match (the same)."}, {"id": "d", "t": "There is no risk of antibody formation leading to fetal destruction if the mother is Rh+ yet the fetus is Rh-. Rhogam is not indicated in these"}], "correct": "b", "rationale": "Individuals with Rh-negative blood develop antibodies after exposure to Rh-positive blood. Rhogam is an immune globulin given to Rh- A | a0 negative women in pregnancy if the father is not conclusively shown to be Rh-negative to prevent sensitization of Rh-negative women who have had a fetomaternal transfusion of Rh-positive fetal RBCs. A standard dose of RhoGAM is administered as an IM injection at 28 weeks c | 1% gestation to prevent the formation of antibodies against Rh-positive red blood cells. It is also given after exposure risks that occur after 28 D | | 13% weeks, including amniocentesis, second-trimester miscarriage/abortion, external version attempt, and within 72 hours of delivery if the baby is Rh-positive.", "whyNot": {"a": "Rhogam is not administered if the mother and the fetus's blood type match (the same).", "c": "Rhogam is not administered if the mother and the fetus's blood type match (the same).", "d": "There is no risk of antibody formation leading to fetal destruction if the mother is Rh+ yet the fetus is Rh-. Rhogam is not indicated in these"}, "keyConcept": "Rhogam promotes the destruction of fetal Rh-positive blood cells before the mother forms antibodies against them. It is given to Rh-negative women to prevent antibody formation that could attack Rh-positive fetal red blood cells in a subsequent pregnancy."}, {"id": 10109, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse answers a call from a client who forgot to take a low-dose combination oral contraceptive pill that was scheduled 10 hours ago. How should the nurse advise the client?", "choices": [{"id": "a", "t": "Continue with today’s pill and use an alternate form of contraception until the month’s cycle ends."}, {"id": "b", "t": "Continue with today’s pill and use sanitary pads for spotting for the remainder of the month."}, {"id": "c", "t": "Do not take another pill until after a pregnancy test in 2 weeks confirms no pregnancy."}, {"id": "d", "t": "Take the missed pill now and resume her normal schedule."}], "correct": "d", "rationale": "Oral contraceptive pills should preferably be taken at the same time each day. If a pill is missed, the client should take the pill as soon as she notices. If the client doesn’t notice until the next day, she should be instructed to take the missed pill immediately and to take the other pill at the regular time of day. If it has been more than 12 hours since the pill was missed, the client should also use emergency contraception if she has had otherwise unprotected intercourse within the past 7 days.", "whyNot": {"a": "An alternate form of contraception should be used if 2 pills or more are missed.", "b": "A low-dose pill has fewer adverse effects compared to high-dose contraceptives. Breakthrough bleeding may occur with any oral", "c": "The pills should be continued until the end of the cycle. The healthcare provider should be consulted if 2 or more pills are missed to"}, "keyConcept": "Oral contraceptive pills should be taken at the same time each day. Individuals who use oral contraceptive pills may call after they forget a scheduled pill. If a pill is missed, the client should take the pill as soon as she remembers. If a day has passed since the pill was missed, the client should immediately take the missed pill and the other, regularly scheduled pill. Emergency contraception is indicated if the client has forgotten to take a pill and more than 12 hours have passed since the scheduled dose."}, {"id": 10110, "cat": "GENITAL & REPRODUCTIVE", "stem": "@0O@ *X Viralnu «> ¢ o- =o Ss Record ™ Inbox ( student.atitesting.com/LT| Mi Inbox- — }_ Untitle: Untitle’ (@ Google @ TEASF Online & MarkkK | @ Micros (eeuWges oe Nae ire @® ATITE © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~", "choices": [{"id": "a", "t": "Testicular self-examinations should be done on a monthly basis"}, {"id": "b", "t": "Testicular self-examinations can be done while taking a shower"}, {"id": "c", "t": "Testicular cancer is usually found in older men"}, {"id": "d", "t": "Lumps should be reported to a physician"}], "correct": "c", "rationale": "Testicular cancer is primarily found in younger men.", "whyNot": {"a": "Testicular self-examinations should be done at least monthly; the nurse should provide this information.", "b": "Testicular self-examinations can easily be done while taking a shower.", "d": "Any lumps found during a testicular self-examination should be reported to the physician. The nurse should provide this information for"}, "keyConcept": "Testicular cancer is the most common cancer in men 15-34 years of age. The two types of testicular tumors most commonly identified are seminoma and nonseminoma. Nonseminomas usually grow and spread more rapidly than seminomas. The most common sign of testicular cancer is a lump or swelling in the testicle. Most testicular cancers can be cured, even when diagnosed at an advanced stage. Epididymus Testicular gs Cc Self-Examination Cancer Sites"}, {"id": 10111, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client who has been discharged with metronidazole for treatment of bacterial vaginosis. Which of the following should the nurse include when advising the client?", "choices": [{"id": "a", "t": "Male partners rarely need treatment."}, {"id": "b", "t": "Metronidazole is associated with preterm labor."}, {"id": "c", "t": "Repeat cultures must be obtained within 2 weeks after completion of treatment."}, {"id": "d", "t": "The medication may cause a copious discharge with a fishy odor."}], "correct": "a", "rationale": "on 30% Hard Bacterial vaginosis is a bacterial infection of the lower genital tract that causes an imbalance in flora and hormones in the vagina and vulva. B 1] or It is characterized by a grey-yellow malodorous (“fishy”) discharge and vaginal irritation. It is diagnosed by finding “clue cells” on microscopic examination of vaginal discharge. c | 48% of 12% Bacterial vaginosis can be sexually transmitted, but men rarely require treatment as a partner. If a woman has a female partner, the female partner may require treatment. Bacterial vaginosis can be caused by Gardnerella vaginalis, Mycoplasma hominis, or anaerobic bacteria. It iT} has been implicated in infections of the upper genital tract and PID. Bacterial vaginosis may have a role in increasing the risk of infection 2 with N. gonorrhea, C. trachomatis, HIV, and HSV. Metronidazole is used to treat bacterial vaginosis. It is contraindicated in pregnancy during g the first trimester. The nurse should advise the client to keep the perineal area clean and dry and to wear loose-fitting cotton underwear for = circulation of air to the perineum. 5", "whyNot": {"b": "Bacterial vaginosis is associated with increased risk of preterm labor (PTL), so the nurse should advise the client to be aware of signs of", "c": "Repeat cultures are not necessary.", "d": "Bacterial vaginosis, not metronidazole, causes the discharge."}, "keyConcept": "Bacterial vaginosis is an infection of the genital tract that results in vaginal irritation and a malodorous grey-yellow discharge that is described as \"fishy.\" Although it can be sexually transmitted, men rarely require treatment. In women, infection may increase the risk of contracting another sexually transmitted infection. It is treated with metronidazole, which is contraindicated in the first trimester of pregnancy."}, {"id": 10112, "cat": "GENITAL & REPRODUCTIVE", "stem": "A nurse is caring for a client who is in perimenopause. Which of the following is an example of a long-term change that may develop after menopause?", "choices": [{"id": "a", "t": "Recurrent kidney infections"}, {"id": "b", "t": "Moist skin"}, {"id": "c", "t": "Thicker hair"}, {"id": "d", "t": "Loss of bone tissue"}], "correct": "d", "rationale": "| 2% Easy Women are most likely to lose more bone tissue after menopause, leading to an increased risk of fractures and osteoporosis. Because of this, B | a0 providers should encourage calcium intake early on to build up bone tissue before it is lost later in life.", "whyNot": {"a": "Recurrent kidney infections are typically not a long-term change that develops after menopause.", "b": "Skin often becomes drier after menopause, not moist.", "c": "Hair often becomes thinner after menopause, not thicker."}, "keyConcept": "Osteoporosis can be prevented by a diet with adequate vitamin D and calcium; regular exercise; avoidance of tobacco and heavy alcohol consumption. Women 65 years of age and higher and younger women with equivalent risk should be screened for osteoporosis using DEXA scanning (dual-energy X-ray absorptiometry) of the hip and lumbar spine."}], "gerontology": [{"id": 10113, "cat": "GERONTOLOGY", "stem": "A nurse is providing teaching to a group of nursing assistants who work in an extended care facility. The nurse should include that which of the following clients is the priority to observe during meals?", "choices": [{"id": "a", "t": "A client who was recently admitted for physical therapy rehabilitation."}, {"id": "b", "t": "A client who has Parkinson's disease"}, {"id": "c", "t": "A client who has poor dentition"}, {"id": "d", "t": "A client who has anorexia"}], "correct": "b", "rationale": "A A client who has Parkinson's disease is at greatest risk for aspiration. Due to this safety risk, this client is the priority to observe during meals. OB = cil", "whyNot": {"a": "The nurse should observe a client who has recently been admitted to evaluate the client's need for assistance. However, this client is not", "c": "The nurse should observe a client who has poor dentition to evaluate the client's need for assistance or a modified diet. However, this", "d": "The nurse should observe a client who has anorexia to evaluate the client's intake. However, this client is not the highest priority to"}, "keyConcept": "The nurse should observe clients during mealtime to identify barriers to good nutrition. Clients who have identifiable issues, such as poor dentition, anorexia, and certain diseases, have an increased risk of lacking good nutrition."}, {"id": 10114, "cat": "GERONTOLOGY", "stem": "A nurse is providing information about capsaicin cream to a client who has osteoarthritis. Which of the following information should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Continuous pain relief is provided."}, {"id": "b", "t": "Inspect for skin irritation and cuts prior to application."}, {"id": "c", "t": "Cover the area with tight bandages after application."}, {"id": "d", "t": "Apply the medication every 2 hr during the day."}], "correct": "b", "rationale": "al 3% Easy Capsaicin is an ingredient found in chili peppers that has been found to provide analgesia when applied topically. However, it can cause OB SY oni blistering and should only be used on intact skin. The nurse should instruct the client to inspect the skin for irritation and cuts before applying capsaicin cream and avoid use of the cream if the skin is damaged, has a wound, or is infected because this can cause increased c | 2% pain and cellular damage.", "whyNot": {"a": "Capsaicin cream blocks neurotransmitters for pain, providing temporary relief of osteoarthritis pain. The nurse should instruct the client", "c": "The nurse should instruct the client to avoid covering the area with a bandage or compression wrap after capsaicin cream is applied", "d": "For maximum pain relief, the nurse should instruct the client to apply capsaicin cream up to four times per day. The nurse should inform"}, "keyConcept": "When providing instruction to the client on the use of capsaicin cream, the nurse should instruct the client to apply a thin film to the affected area and rub it in gently while wearing gloves. The nurse should instruct the client to wash their hands thoroughly with soap and water after the application of the cream, even if gloves are worn, to decrease the risk of causing burning to the eyes or other sensitive areas. The client should also avoid handling contact lenses or applying drops to the eye for at least 1 hr after handling, applying, or removing capsaicin cream."}, {"id": 10115, "cat": "GERONTOLOGY", "stem": "A nurse is providing home care to an elderly client with diagnoses of Type 2 diabetes and CHF. Which of the following observations is a priority concern for the nurse?", "choices": [{"id": "a", "t": "The client reports her ankles are swollen every night before she goes to bed"}, {"id": "b", "t": "The client reports an ingrown toenail that is very painful"}, {"id": "c", "t": "The homecare aide reports the client refused her shower last week"}, {"id": "d", "t": "The nurse notes the client has lost five pounds in the last two weeks"}], "correct": "b", "rationale": "A i 22% Moderate An ingrown toenail can result in serious complications in a diabetic due to poor circulation and the risk of infection. OB a 56% fo", "whyNot": {"a": "The nurse should investigate this further given the client’s congestive heart failure to determine if the edema is getting worse. However, D || 21%", "c": "The nurse should investigate the reasons for the client’s refusal, but the toenail takes priority.", "d": "Since the client has CHF, weight fluctuation may be due to diuretic therapy. Weight gain would be a higher priority as it could indicate fluid"}, "keyConcept": "Most diabetic amputations are preventable by education, close monitoring, and appropriate care. Ingrown toenails can be prevented by trimming toenails straight across, so the ends of the nail grow over the skin and not into it. Good nail care can prevent ingrown toenails and other diabetic foot problems. Clients with diabetes should see a podiatrist regularly and as needed for the care of problems like ingrown toenails, which can lead to a foot infection."}, {"id": 10116, "cat": "GERONTOLOGY", "stem": "A nurse is caring for an older adult with impaired mobility. Which of the following should the nurse consider when planning the client's daily activities?", "choices": [{"id": "a", "t": "The skin of older adults is thicker and may slough more easily"}, {"id": "b", "t": "Hyperreflexia in the older adult affects transfer techniques and modifications may be necessary"}, {"id": "c", "t": "Provide analgesia and skin care for the older adult every day after activities"}, {"id": "d", "t": "Older adults who have been sedentary for long periods may be more likely to develop orthostatic hypotension"}], "correct": "d", "rationale": ". When they stand up, they may suffer , which refers to a drop in blood pressure when the circulation changes lag behind the change in position. Orthostatic hypotension may cause light-headedness, dizziness, or syncope. It is a risk factor for falls in the elderly. c | 10%", "whyNot": {"a": "Older adults tend to have thinner skin that is more prone to damage.", "b": "Older adults are at higher risk of muscle and joint stiffness, as well as contractures, rather than hyperreflexia.", "c": "Analgesia and skin care may be necessary in some situations, but they are not always needed after daily activities."}, "keyConcept": "Many factors can contribute to impaired mobility in the elderly, including poor vision, decreased hearing, impaired proprioception and balance, loss of muscle mass, and orthostatic hypotension. It's important to consider these limitations when planning care. Older adults are at risk of fracture from falling and a hip fracture may result in loss of independence. It's important to be aware of risks and implement measures to reduce the risk of fall."}, {"id": 10117, "cat": "GERONTOLOGY", "stem": "A nurse is using the Katz ADL Index to assess a client in long-term care. Which best describes the purpose of this assessment?", "choices": [{"id": "a", "t": "It ranks the client’s abilities to perform activities of daily living"}, {"id": "b", "t": "It provides educational information to the client about how to perform ADLs"}, {"id": "c", "t": "Itis a class that teaches family members how to help a client with self-care deficit"}, {"id": "d", "t": "Itis a tool to develop nursing interventions to support activities of daily living"}], "correct": "a", "rationale": "o; Me The Katz Index of Independence in Activities of Daily Living is an assessment measure that is used to assess the client’s abilities to perform B | 3\" activities of daily living, which are then ranked on a scale. This tool helps the nurse to identify and quantify self-care deficits, which allows the nurse to plan care accordingly. c | 1% om 16%", "whyNot": {"b": "The Katz ADL is a tool that assesses client function for ADLs; it does not provide client information for ADLs. {iil}", "c": "The Katz ADL does not teach family members how to assist with ADLs; it helps the nurse to understand the level of the client’s self-care A", "d": "The nurse should already understand interventions for self-care deficit; the Katz ADL helps the nurse assess the client’s abilities to g"}, "keyConcept": "Clients may experience functional decline as a result of aging and/or health problems. Use of a scale for measurement of functional status provides an objective tool to monitor further declines or improvement in status to help the nurse evaluate and plan further intervention. The Katz ADL scale assesses basic activities of daily living."}, {"id": 10118, "cat": "GERONTOLOGY", "stem": "Aconfused older client is in soft wrist restraints to prevent injury. Which of the following tasks should not be delegated by the Registered Nurse (RN)?", "choices": [{"id": "a", "t": "Reapplying the restraints after assisting the client with toileting"}, {"id": "b", "t": "Assessing neurovascular status and psychological response to restraints"}, {"id": "c", "t": "Performing range-of-motion exercises"}, {"id": "d", "t": "Repositioning and turning the client in bed"}], "correct": "b", "rationale": "State and federal regulations require all healthcare staff members directly caring for clients in restraints to complete training in caring for the client. As a result, all staff has the knowledge and ability to reapply restraints, perform range-of-motion exercises, and reposition the client. All staff members are also able to monitor and report any changes in skin integrity to the RN, but only the RN can make the primary assessment of neurovascular status and skin (color, temperature, and integrity), need for continuing restraints, psychological response to restraints, and appropriateness of restraints. A. Unlicensed and licensed healthcare team members directly participating in the care of clients in restraints are trained to reapply restraints. C. Unlicensed and licensed healthcare team members directly participating in the care of clients in restraints have the training and ability to perform range-of-motion exercises. D. All members of the healthcare team who participate directly in care of clients in restraints are trained to reposition and turn the client in bed.", "whyNot": null, "keyConcept": "Federal and state regulations require general training in use of restraints for all healthcare personnel who are participating directly in the care of the client in restraint. This general training teaches involved staff to reapply restraints, perform range of motion exercises, reposition the client in restraints, and monitor for changes in skin integrity. However, the task of primary assessment of neurovascular status, continuing need for restraints, appropriateness of restraints, and the client's psychological response to restraints can only be performed by the RN."}, {"id": 10119, "cat": "GERONTOLOGY", "stem": "We Recor Mi Inbox = M Inbox — E} Untitl Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc N x] G GERO + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "The amount of fat and water begin to decrease, resulting in loss of turgor"}, {"id": "b", "t": "The outer layer of skin sloughs off and is replaced with new cells every few days"}, {"id": "c", "t": "The vascularity of the skin decreases, resulting in lowered ability to regulate body temperature"}, {"id": "d", "t": "Collagen begins to lose its elasticity and strength"}], "correct": "b", "rationale": "all 7% Easy As a person ages, the skin begins to lose fat, water, and collagen, resulting in loss of turgor and elasticity. Blood supply to the skin decreases, OB TY ry making it harder for an aging adult's body to regulate the temperature. This is one of the reasons older adults feel cold at higher temperatures. Although the outer layer of skin is replaced every few days in younger people, this cell replacement does not occur as quickly c | 6% in older adults.", "whyNot": {"a": "The amount of fat and water decreases in an older adult, resulting in loss of skin turgor.", "c": "An older adult’s skin vascularity decreases, lowering the ability to regulate body temperature.", "d": "The collagen found under the skin of most older adults begins to lose its elasticity and strength."}, "keyConcept": "There are many anatomical and physiological changes experienced in the course of aging. This results in increased vulnerability and special skin care needs in the elderly. Elderly individuals have fragile skin and injury can result in scar tissue, slow healing, infections, and wounds that will not heal."}, {"id": 10120, "cat": "GERONTOLOGY", "stem": "A nurse is working in a rural care facility cares for clients of all ages. The nurse understands that the age group at highest risk of death from a fall is which of the following?", "choices": [{"id": "a", "t": "Toddlers aged 12 to 18 months"}, {"id": "b", "t": "The elderly"}, {"id": "c", "t": "Teenaged males"}, {"id": "d", "t": "School-aged children of both genders"}, {"id": "e", "t": "Newborns"}], "correct": "b", "rationale": "al 4% Easy Older adults (> 65) suffer the highest number of fatal falls. The risk increases with age. This is due to cognitive, physical, and sensory changes On rsd car, associated with advancing age. c| 2% «ao g@ : Unintentional Fall Death Rates, Adults 65+ E i 8% 56.00 S400 52.00 50.00 48.00 46.00 44.00 2005 -2014, United States 42.00 Unintentional Fall Death Rates per 100,000 All Races, Both Sexes, Ages 65+ — Source: www ede govhinjurywisqars 2005 2006-2007 «2008 2009««2010«-2011.««2012«-2013 2014 —peatn nate", "whyNot": {"a": "Toddlers and young children comprise a high-risk group due to their advancing stage of development, innate curiosity, and increasing", "c": "Falls in teens are more often related to risk-taking behavior, and males generally take part in high-risk behaviors more often than their", "d": "School-aged children comprise a high-risk group due to their advancing stage of development, innate curiosity, and increasing", "e": "Newborn falls are associated with their adult caregivers."}, "keyConcept": "Two groups at high risk of injury from falls are children less than five years of age and adults 65 years of age and older. Elderly persons who fall are 10 times more likely to be hospitalized and eight times more likely to die as the result of a fall compared to children. Falls are the po] e o 2 ° s a = a <"}, {"id": 10121, "cat": "GERONTOLOGY", "stem": "A nurse is assisting in planning a staff education program on substance use in older adults. Which of the following pieces of information should the nurse plan to include in the presentation?", "choices": [{"id": "a", "t": "Older adults require higher doses of a substance to achieve the desired effect."}, {"id": "b", "t": "Older adults commonly use regression to cope with a substance use disorder."}, {"id": "c", "t": "Older adults are at increased risk for substance use following retirement."}, {"id": "d", "t": "Older adults may develop substance use to mask manifestations of dementia."}], "correct": "c", "rationale": "all om Retirement and other life change stressors increase the risk for substance use in older adults, especially if there is a prior history of substance ec ; use. Alcohol is the most commonly abused substance in adults over the age of 65, but there is a growing incidence of prescription drug abuse D | and addiction in older adults. Substance use disorders in clients with coexisting dementia can compound cognitive difficulties. Older adults often need lower doses of medications compared to younger individuals.", "whyNot": {"a": "Requiring higher doses of a substance to achieve the desired effect is a result of the length and severity of substance use rather than age.", "b": "Denial, not regression, is a defense mechanism that is common in substance users of all ages.", "d": "Substance use in older adults can result in manifestations of dementia and can also compound the effects of cognitive impairment."}, "keyConcept": "The risk of substance use disorder is increased in older adults as a result of stressors associated with significant life changes. The risk is greater in individuals with a prior history of substance abuse. Alcohol is the most commonly abused substance in the older adult population."}, {"id": 10122, "cat": "GERONTOLOGY", "stem": "Which of the following clients should the nurse assign to a room closest to the nursing station? O A.A patient with pyelonephritis and agitated delirium receiving intravenous antibiotics O B. A patient with measles on airborne isolation O C. A patient with MRSA with contact precautions O D. A post-stroke patient with right-sided weakness who needs assistance with ambulation", "choices": [{"id": "a", "t": "Client safety should be considered a priority when making room assignments."}, {"id": "b", "t": "Proximity to the nursing station is not necessary to maintain airborne precautions."}, {"id": "c", "t": "Proximity to the nursing station is not a priority when maintaining contact precautions."}, {"id": "d", "t": "The call bell should be placed within reach of the client, but proximity to the nursing station should not affect the appropriate frequency"}], "correct": "a", "rationale": "Client safety should be considered a priority when making room assignments. Delirium refers to an acute and usually reversible confusional , infection, and medication toxicity. Older clients are at greater risk of delirium during an | © 1% acute infection. om 19% Clients with delirium are disoriented and sometimes agitated, presenting a significant safety risk. Client safety measures include supervision, use of side rails, provision of a quiet environment, and promoting a normal sleep-wake cycle. The call bell should be placed within reach, and traffic paths should be cleared. Assistance with ambulation may be necessary, including the use of assistive devices. Use of restraints should be avoided since they often increase the client’s agitation. The underlying cause of delirium should be addressed with treatment, including maintenance of normal fluid and electrolyte balance and supplemental oxygen if indicated. Blood glucose levels should be monitored, and blood pressure support may be necessary in some cases.", "whyNot": {"b": "Proximity to the nursing station is not necessary to maintain airborne precautions.", "c": "Proximity to the nursing station is not a priority when maintaining contact precautions.", "d": "The call bell should be placed within reach of the client, but proximity to the nursing station should not affect the appropriate frequency"}, "keyConcept": "Delirium is an acute confusional state that may result in agitation. Clients with delirium are at risk of falls and other injuries. A nurse should implement close supervision and environmental measures to reduce risk of harm. Delirium is treated by addressing the underlying illness or condition. Nursing interventions to protect the client include placement by the nurse's station, maintenance of a quiet environment, use of side rails, and promotion of normal sleep-wake cycle."}, {"id": 10123, "cat": "GERONTOLOGY", "stem": "When advising an elderly client with osteoporosis who is at risk for a fall at home, the nurse knows that which of the following is the most effective measure to prevent falls?", "choices": [{"id": "a", "t": "Purchasing a hearing aid"}, {"id": "b", "t": "Using a walker or cane in the home"}, {"id": "c", "t": "Removing throw rugs"}, {"id": "d", "t": "Undergoing an eye examination with a change of prescription if necessary"}], "correct": "c", "rationale": "A om Falls in older adults are a common cause of significant morbidity and mortality, often resulting in loss of independence. Older people are at ec FY greater risk of falling as a result of age-related impairment or balance problems. The most effective measures among those listed are the D i installation of grab bars and removal of throw rugs. Throw rugs can easily cause a fall for an older client, even when using a walker. Although younger individuals are more likely to regain balance after slipping on a loose rug, an older adult lacks the balance and rapid reflexes to prevent injury. Other measures to reduce the risk of falls include improving lighting, installing grab bars in the bathroom, removing clutter and obstacles that could potentially cause tripping, avoiding of thick-soled shoes, engaging in exercises to improve strength and balance, avoiding alcohol consumption, and use of vitamin D supplements and appropriate medications in clients with osteoporosis.", "whyNot": {"a": "Although loss of hearing is a risk factor for falls, a hearing aid is not the most effective fall prevention measure listed.", "b": "Although using assistive devices is helpful to prevent falls, throw rugs or clutter can cause falls, even with a walker or cane.", "d": "Loss of visual acuity is a risk factor for falls in older adults, so lighting should be improved, and regular eye examinations should be"}, "keyConcept": "When providing information about home safety for an older adult with osteoporosis, a nurse is aware that falls cause significant morbidity and mortality in the elderly, often with loss of independence. The most effective measure for fall prevention is removal of throw rugs in the environment."}, {"id": 10124, "cat": "GERONTOLOGY", "stem": "The nurse is assessing an elderly client for the risk of falls. Which of the following should the nurse collect?", "choices": [{"id": "a", "t": "The facility restraint policy"}, {"id": "b", "t": "Information on gait, balance, and visual impairment"}, {"id": "c", "t": "Psychosocial history"}, {"id": "d", "t": "The facility environmental safety plan"}], "correct": "b", "rationale": ", balance, and visual impairments. The other options are not relative to the fall OB Tid 94% assessment. c | 2%", "whyNot": {"a": "The facility restraint policy is not related to a client’s fall risk.", "c": "Psychosocial history is important but it is typically not related to falls.", "d": "The facility safety plan is not information that would be collected from the client."}, "keyConcept": "Fall risk assessment should include physiological factors and environmental factors. Physiological factors include low blood pressure or orthostatic hypotension; muscle weakness; impaired mobility, unstable gait, and poor balance as a result of pain, musculoskeletal deformities, or neurologic disorders; limited physical-activity endurance; foot pain or paresthesias; and impaired vision."}, {"id": 10125, "cat": "GERONTOLOGY", "stem": "them to come. | don’t want to be a bother.” Based on this information, which of the following should be added to the client’s plan of care?", "choices": [{"id": "a", "t": "Depression"}, {"id": "b", "t": "Risk for social isolation"}, {"id": "c", "t": "Risk for suicide"}, {"id": "d", "t": "Risk for spiritual distress"}], "correct": "b", "rationale": "The client’s statement indicates the risk of social isolation.", "whyNot": {"a": "Depression is a medical diagnosis and the nurse would not be able to add this to the client’s plan of care.", "c": "The client did not express any suicidal ideations.", "d": "The client did not discuss anything of a spiritual nature."}, "keyConcept": "Social isolation in the elderly may occur as a result of illness, retirement, financial pressures, death of a spouse, or changes in role identity. Maintenance of social contacts and human interaction is beneficial to all older adults, but particularly important for an adult with a significant mobility problem that could increase social isolation and prevent the client from following the treatment plan to recuperate from surgery and regain health."}, {"id": 10126, "cat": "GERONTOLOGY", "stem": "A nurse is caring for a client who has just started to use a hearing aid. Which information from the nurse is most important in ensuring that the client uses and cares for the hearing aid correctly?", "choices": [{"id": "a", "t": "When showering or bathing with a hearing aid, always turn the affected ear away from the stream of water"}, {"id": "b", "t": "The hearing aid can be washed with soap and water if excess wax accumulates on the surface"}, {"id": "c", "t": "Always keep the hearing aid out of extreme temperatures, such as heat or cold"}, {"id": "d", "t": "Keep the hearing aid on when changing the batteries to ensure that it begins working again"}], "correct": "c", "rationale": "A | % Moderate The client should avoid extreme temperatures of heat or cold with the hearing aid, such as keeping it on a counter near an oven, allowing it , or exposing it to ice or snow. Temperature extremes can cause damage to the hearing aid and it will not work appropriately. ec | 76% of 4%", "whyNot": {"a": "The client should take the hearing aid out before showering or bathing so as not to risk its getting wet and damaged.", "b": "The ear mold may be washed with soap and water if it is first detached from the hearing aid, otherwise, it should never be washed with", "d": "The client should turn off the hearing aid before replacing the batteries. Once the batteries are in place, the client can turn it back on."}, "keyConcept": "The hearing aid-especially the ear mold-must be kept clean, dry, and free of ear wax. The ear mold can be washed with mild soap and water, but must be detached from the hearing aid to avoid causing damage to electronic components. If the client's hearing aid doesn't detach, the ear mold should be wiped clean with a damp cloth. The hearing aid should never be immersed in water and should be cleaned and dried before storing it in its case when not wearing the device."}, {"id": 10127, "cat": "GERONTOLOGY", "stem": "A nurse is caring for an elderly client who fell to the sidewalk and sustained a laceration that required sutures. The nurse understands that which of the following may impair wound healing in this client?", "choices": [{"id": "a", "t": "There is increased circulation and oxygenation of tissues"}, {"id": "b", "t": "The skin is more fragile"}, {"id": "c", "t": "There is an increase in the amount of collagen"}, {"id": "d", "t": "There is faster tissue regeneration"}], "correct": "b", "rationale": "al 3% Easy An older adult has skin that is more fragile, which may prevent appropriate healing. Fragile skin is also more likely to tear or become OB TS OR injured.Other factors that impact wound healing in older adults include chronic illnesses that impair immunity, poor nutrition, and poor ° perfusion. c | 3% p | 1%", "whyNot": {"a": "An older adult tends to have decreased circulation and oxygenation of tissues, not increased.", "c": "Older adults have decreased amounts of collagen, not increased amounts.", "d": "Older adults have slower rates of tissue regeneration, not faster rates."}, "keyConcept": "Changes in aging skin that impair adaptive and homeostatic mechanisms and leads to impaired wound healing and chronic wounds include reduced proliferation and turnover of skin cells; impaired immunity and thermoregulation, decreased subcutaneous tissues, increased fragility of the epidermis, and medical comorbidities that include disorders that reduce vascular perfusion, cardiac output, and oxygen delivery (anemia, hypoxia.)"}, {"id": 10128, "cat": "GERONTOLOGY", "stem": "A nurse is providing teaching to an elderly client about how to prevent falls in the home. Which information should the nurse include?", "choices": [{"id": "a", "t": "Keep nightlights on in the hallways and stairwells"}, {"id": "b", "t": "Remove soap buildup in the sink on a regular basis"}, {"id": "c", "t": "Avoid cleaning hardwood floors to reduce slippery surfaces"}, {"id": "d", "t": "Handrails are necessary for outdoor stairwells but not necessarily indoor stairs"}], "correct": "a", "rationale": "By keeping nightlights on in the hallways and stairwells, the client will be better able to see the surroundings if there is a need to get up B | a0 during the night. This can reduce the incidence of falling because of clutter or other obstructions that would otherwise not be seen in the dark. c | 2% p | 1%", "whyNot": {"b": "Removing soap buildup from the sink would have no effect on protecting a client from falls.", "c": "The client should keep floors clean and free from clutter to avoid falling.", "d": "Handrails should be added on both sides of stairs that are inside as well as outside to protect the client from falling."}, "keyConcept": "Age-related changes that increase the risk of falling include poor vision, with decreased acuity, depth perception and adaptation to low light. Proprioceptive (ability to judge location in space) declines and the vestibular system in the inner ear, which sends additional information to the brain about the position, deteriorates from loss of nerve fibers and cells. As people age, muscle mass decreases, and older people may compensate by using less efficient muscle groups to maintain or regain balance. Some of these changes are more pronounced in clients with chronic disease, but some changes occur independent of illness, as part of the aging process."}, {"id": 10129, "cat": "GERONTOLOGY", "stem": "The extra heart sound heard in the audio below in a 73-year-old is consistent with which of the following diagnoses? BOARD @& VITALS” Oe 0:05 THE MEDICAL SPECIALTY QUESTION BANKS", "choices": [{"id": "a", "t": "Arrhythmia"}, {"id": "b", "t": "Heart failure"}, {"id": "c", "t": "Aortic stenosis"}, {"id": "d", "t": "Mechanical heart valve"}], "correct": "b", "rationale": "The third heart sound, or S3, is an extra heart sound that occurs soon after the normal (S1 and S2) heart sounds and is associated with heart failure. S3 may be a normal finding in people under 40 years of age and some trained athletes but should disappear before middle age. It is caused by increased atrial pressure leading to increased flow rates and inflowing blood against a distended or noncompliant ventricle in mid-diastole. In patients over 40 years of age, the $3 sound is considered pathognomic for heart failure.", "whyNot": {"a": "The recording is typical of a regular rhythm with an $3, and the rate is within normal limits. It does not represent an arrhythmia.", "c": "Aortic stenosis is characterized on auscultation by a soft or normal S1, diminished or absent A2, paradoxical splitting of S2, prominent $4,", "d": "Normal mechanical valves have a loud and high-frequency metallic closing sound with a soft opening sound. Alternatively, they may have"}, "keyConcept": null}, {"id": 10130, "cat": "GERONTOLOGY", "stem": "this client as a result of age-related changes?", "choices": [{"id": "a", "t": "Skin that is thicker and more wrinkled"}, {"id": "b", "t": "Increased number and size of sweat glands"}, {"id": "c", "t": "Decreased blood vessel fragility"}, {"id": "d", "t": "Increased constipation due to decreased gastric motility"}], "correct": "d", "rationale": "all 8% Easy Changes occur throughout most body systems as a result of aging; nurses who assess older adults must be familiar with age-related changes . In an 88-year-old client, the nurse would most likely note that the client experiences more frequent constipation due to decreased gastric motility. © | 8%", "whyNot": {"a": "Skin becomes thinner and more wrinkled with age. The nurse would more likely see thinner and more wrinkled skin, not thicker skin. 2", "b": "Older adults have a decrease in the amount and size of sweat glands. The nurse would more likely see reduced sweat production in this 3", "c": "The blood vessels of older adults become more fragile with advancing age. The nurse would most likely see increased blood vessel <"}, "keyConcept": "Age-related changes in the Gl tract include decreased saliva production; reduction in the number of taste buds; impaired thirst mechanism; and decreased motility throughout the GI tract, leading to increased risk of GERD, constipation, and bowel obstruction. The liver becomes less efficient, which slows metabolism of drugs. Normal aging is associated with gradual deterioration of the bodies reserve that affects all body systems. These changes are also influenced by lifestyle choices and environment. In the elderly, presenting symptoms of an illness are usually present in the system with the least reserve rather than where the pathology lies. For example, a urinary tract infection may present with delirium, as the CNS (central nervous system) typically has the lowest reserve in the elderly client. Aging leads to loss of brain/nerve cells and atrophy and mild benign memory changes. Central nervous system changes associated with normal aging include forgetfulness; increased sensitivity to change; increased response time; and sleep pattern changes."}, {"id": 10131, "cat": "GERONTOLOGY", "stem": "A nurse is caring for an elderly client who is disoriented and agitated. Which of the following is a primary difference that distinguishes delirium from a neurocognitive disorder?", "choices": [{"id": "a", "t": "Delirium is not reversible."}, {"id": "b", "t": "Dementia has a rapid onset."}, {"id": "c", "t": "Dementia is associated with suicide and homicide."}, {"id": "d", "t": "Delirium is accompanied by rapidly fluctuating level of consciousness."}], "correct": "d", "rationale": "| 2% Easy The primary differences distinguishing delirium from a neurocognitive disorder include acute onset rapid fluctuations in the level of B | a consciousness. Delirium is reversible, but dementia is progressive. Neither disorder leads to suicide or homicide. Both are biological disorders with psychological and cognitive effects. c | 2%", "whyNot": {"a": "Neurocognitive disorders are not necessarily easy to treat; delirium may be more easily treated if the underlying cause is identified.", "b": "Dementia has a gradual, progressive onset.", "c": "Neurocognitive disorders and delirium are not necessarily associated with homicide or suicide."}, "keyConcept": "Dementia refers to a progressive neurological disorder characterized by impairment in memory and at least one other cognitive area that can include attention, orientation, judgment, abstract thinking, and personality, in an alert individual. Dementia is rare in under 50 years of age, but incidence increases with age. Delirium refers to an acute disorder of attention and cognition, including memory and perception. Delirium has an acute onset and a fluctuating course; it is characterized by inattention, distraction, disorganized thinking and/or a change in the level of consciousness. It is reversible, usually by treatment of underlying causes. Elderly clients with dementia may also have superimposed delirium. Interventions include maintenance of a quiet environment; reorienting the client with personal belongings and photographs; use of a sitter; and neuroleptic drugs, including haloperidol, as necessary."}, {"id": 10132, "cat": "GERONTOLOGY", "stem": "We Recor Mi Inbox = M Inbox — E} Untitl Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc N x] G GERO + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "The client has a catheter in place"}, {"id": "b", "t": "The client has 2 grandchildren"}, {"id": "c", "t": "The client has a \"Do Not Resuscitate\" (DNR) order"}, {"id": "d", "t": "The client has oxygen in place at 2 liters per minute"}], "correct": "b", "rationale": ", the fact that the client has 2 grandchildren is not critical in the immediate post-operative OB SY one: period. The facts that the client has a catheter, DNR order, and oxygen in place are immediately important for the nurse who will be caring for ° the client. c | 2% p | 1%", "whyNot": {"a": "Since the client has probably received IV fluids in surgery, it is important for the nurse to know that the client has a catheter in place to", "c": "The fact that an elderly client has a DNR order is important postoperatively. Older clients are more prone to unintended outcomes", "d": "The fact that the client is on 2 liters of oxygen is important to ensure that oxygen is readily available in the client’s room."}, "keyConcept": "Effective hand-off communication between nurses is associated with increased client safety, increased nurse satisfaction, and increased trust among the healthcare team. Communication issues are the leading factor in root causes of sentinel events. The Joint Commission has set a National Patient Safety Goal to standardize hand-off communications, including an opportunity to ask and respond to questions."}, {"id": 10133, "cat": "GERONTOLOGY", "stem": "What is an example of a skin lesion commonly seen in older adults ?", "choices": [{"id": "a", "t": "Impetigo"}, {"id": "b", "t": "Atopic dermatitis"}, {"id": "c", "t": "Lentigines"}, {"id": "d", "t": "Tinea pedis"}], "correct": "c", "rationale": "Lentigines, also called liver spots, are common benign skin lesions found in middle aged and older adults. They are areas of hyperpigmented skin that develop with sun exposure over the year.", "whyNot": {"a": "Impetigo is a contagious skin infection that is more commonly seen in children; it is not a common lesion in older adults.", "b": "Atopic dermatitis is also called eczema, and it is more commonly seen in younger clients, not in older adults.", "d": "Tinea pedis, or athlete’s foot, is not a common infection in older adults."}, "keyConcept": "Lentigines (liver spots) are benign skin lesions that occur in sun-exposed areas of the skin in middle age and older adults. They often develop on the backs of the hands and face. These flat lesions are 0.2 to 2 cm, with discrete borders, irregular shape, and dark color."}, {"id": 10134, "cat": "GERONTOLOGY", "stem": "We Recor Mi Inbox = M Inbox — E} Untitl Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc N x] G GERO + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "patient diagnosed with AIDS asks about the possibility of using hospice. In order to be eligible for hospice care, the patient must:"}, {"id": "b", "t": "There is no requirement that a client be willing to discuss his prognosis; in fact, hospice personnel are skilled in helping clients talk"}, {"id": "c", "t": ", the client must have two physicians who are willing to attest that the client has a life expectancy of B | 3\" less than six months, if the disease follows its normal course."}, {"id": "d", "t": "Finally, one of the general requirements of hospice is that the client does not pursue further curative treatment since it has been"}], "correct": "c", "rationale": ", the client must have two physicians who are willing to attest that the client has a life expectancy of B | 3\" less than six months, if the disease follows its normal course.", "whyNot": {"a": "Although cancer is one of the major diagnoses associated with hospice, it is not a requirement for hospice care.", "b": "There is no requirement that a client be willing to discuss his prognosis; in fact, hospice personnel are skilled in helping clients talk", "d": "Finally, one of the general requirements of hospice is that the client does not pursue further curative treatment since it has been"}, "keyConcept": "Hospice is an opportunity for clients facing a life-limiting illness or injury, hospice care to receive compassionate medical care, pain management, and emotional/spiritual support, through a team-oriented approach tailored to the client's needs and wishes. Hospice care also provides support to the client's family members."}, {"id": 10135, "cat": "GERONTOLOGY", "stem": "An 80-year-old client is scheduled for a surgical procedure. Which of the following should be implemented when obtaining informed consent from this client?", "choices": [{"id": "a", "t": "Allow family members to make the decision for the client"}, {"id": "b", "t": "Provide extra reading material about the surgery"}, {"id": "c", "t": "Encourage the client to sign immediately"}, {"id": "d", "t": "Provide adequate time for the client to process information"}], "correct": "d", "rationale": "The nurse should ensure all clients receive appropriate and accessible information when informed consent is necessary for a procedure. The nurse should confirm client understanding, especially in the presence of possible coexisting disabilities that may be present in elderly clients, including cognitive impairment, presbyacusia, and visual disturbances. The client should be provided with information concerning the nature and purpose of the proposed procedure; potential risks and benefits; alternatives to the procedure; and the risks and benefits of not receiving or undergoing the procedure.", "whyNot": {"a": "Unless the client has signed a power of attorney form, the family members should not make the decision for him about informed consent. e@D PY 94%", "b": "Reading materials may be useful, but some older adults have difficulty with reading and processing a lot of information at once.", "c": "The client does not need to sign the consent immediately. The client should be allowed adequate time to process the information."}, "keyConcept": "The nurse should ensure all clients receive appropriate and accessible information when informed consent is necessary for a procedure. The nurse should confirm client understanding, especially in the presence of possible coexisting disabilities that may be present in elderly clients, including cognitive impairment, presbyacusia, and visual disturbances. The client should be provided with information concerning the nature and purpose of the proposed procedure; potential risks and benefits; alternatives to the procedure; and the risks and benefits of not receiving or undergoing the procedure."}, {"id": 10136, "cat": "GERONTOLOGY", "stem": "A nurse is assigned to care for a client with dementia who is admitted with a stroke. Which of the following nursing diagnoses is the highest priority when caring for this client?", "choices": [{"id": "a", "t": "Bathing/hygiene self-care deficit"}, {"id": "b", "t": "Risk of injury"}, {"id": "c", "t": "Impaired physical mobility"}, {"id": "d", "t": "Disturbed thought processes"}], "correct": "b", "rationale": "| 2% Easy A client with dementia is at risk of injury due to increased risk for falls. The client may not recognize her limitations, despite immobility OB TY epi related to the stroke. ci 12%", "whyNot": {"a": "The client may be at risk of self-care deficit, but this is not the highest priority.", "c": "The client has impaired physical mobility but this is not the priority.", "d": "The client may have disturbed thought processes, but the priority nursing diagnosis is a risk for injury."}, "keyConcept": "The nurse's priority is to ensure the client's safety and prevent injury. Falls in the elderly are associated with significant morbidity and mortality. Fall prevention measures include the use of a bed alarm, close supervision, and removal of environmental hazards."}, {"id": 10137, "cat": "GERONTOLOGY", "stem": "A nurse is performing an assessment of an older client. Which of the following findings is most concerning?", "choices": [{"id": "a", "t": "Tachypnea"}, {"id": "b", "t": "Weak peripheral pulse"}, {"id": "c", "t": "Decreased skin turgor"}, {"id": "d", "t": "Decreased muscle strength"}], "correct": "a", "rationale": "; ; -< ceen with an infection ori o; tee oy In old age, the respiratory rate usually remains unchanged. Tachypnea is seen with an infection or illness. B Hl aoe", "whyNot": {"b": "Weak peripheral pulse can be a normal physiological change associated with aging.", "c": "Decreased skin turgor is a normal physiological change associated with aging.", "d": "Decreased muscle strength is a normal physiological change associated with aging."}, "keyConcept": "As clients age, physiological changes occur in all organ systems. Expected findings include decreased cardiac output, increased blood"}, {"id": 10138, "cat": "GERONTOLOGY", "stem": "priority action? O A. Ask the client’s caregiver about the bruises. O B. Ask the client why the bruises are in various stages of healing. O C. Complete the assessment with attention to any additional injuries, general hygiene, and nutritional status of the client. O D. Report the client’s bruises to the healthcare provider.", "choices": [{"id": "a", "t": "Ask the client’s caregiver about the bruises."}, {"id": "b", "t": "Ask the client why the bruises are in various stages of healing."}, {"id": "c", "t": "Complete the assessment with attention to any additional injuries, general hygiene, and nutritional status of the client."}, {"id": "d", "t": "Report the client’s bruises to the healthcare provider."}], "correct": "c", "rationale": "& client. A l 3% Easy . This suggests the injuries occurred at different times. D || 12% This finding suggests elder abuse, but it does not provide conclusive evidence. The nurse should continue the assessment to determine whether other injuries are present and whether the client has other signs of neglect or abuse, including poor hygiene and nutritional status, depression or anxiety, or inappropriate medication administration. During the assessment, it is important for the nurse to display a nonjudgmental attitude and to provide the opportunity for the client to feel the freedom to discuss any problems in the home.", "whyNot": {"a": "The need for assessment for further injury or indication of abuse is a primary concern, although it may be appropriate for the nurse to", "b": "This approach is too confrontational and will not facilitate trust on the part of the client. It is not a therapeutic response.", "d": "Elder abuse suspicions must be reported, but the nursing assessment should be performed first. Completion of the nursing assessment"}, "keyConcept": "Unusual findings that don't make sense in light of a client's explanation should be explored, particularly if the client is a member of a vulnerable population, including children and the elderly. Injuries at different stages of healing explained as a single fall suggest a need for the nurse to fully assess for other signs of abuse and to report suspicions after the assessment is complete."}, {"id": 10139, "cat": "GERONTOLOGY", "stem": "A nurse wants to avoid overstimulating her 88-year-old client who has limited mobility, yet still provide enough engagement to make his activities enjoyable. Which action of the nurse is most appropriate?", "choices": [{"id": "a", "t": "Provide books and materials that have large print"}, {"id": "b", "t": "Keep the client in an isolated environment to reduce distractions"}, {"id": "c", "t": "Open the windows in the client’s room"}, {"id": "d", "t": "Allow the client to sit in a chair next to the nurse’s station"}], "correct": "a", "rationale": "Giving the client large print books and materials may make it easier for the client to read to pass the time without having to strain to see. B | a0 This activity is stimulating enough for the client without being problematic. ci 12%", "whyNot": {"b": "Keeping the client in an isolated environment may not be stimulating enough for him and may contribute to loneliness.", "c": "Opening the windows in the client’s room may be distracting and noisy if there is too much outside noise.", "d": "While the client may have more interaction by sitting near the nurse’s station, this may be too stimulating and distracting for the client,"}, "keyConcept": "Activities for elderly clients with limited mobility include reading, crafts, exploring hobbies, spending time outdoors, visiting with friends and family, playing games, and watching movies or television."}, {"id": 10140, "cat": "GERONTOLOGY", "stem": "A nurse is helping a client who is not getting enough sleep because of increased frequency of nighttime urination. Which response from the nurse is most appropriate?", "choices": [{"id": "a", "t": "“I will help you pick out some adult diapers.”"}, {"id": "b", "t": "“Try to avoid drinking liquids after dinner and do not drink caffeine or alcohol.”"}, {"id": "c", "t": "“Avoid the use of dried fruits and vegetable juice.”"}, {"id": "d", "t": "“If you sleep on the couch, you should be able to get to the bathroom faster.”"}], "correct": "b", "rationale": ". Teaching him about the effects of OB sd oe: extra liquid and caffeine and alcohol use are appropriate measures. ° c | 1%", "whyNot": {"a": "This statement does not consider the client’s feelings about his incontinence, nor does it help the client come up with solutions. The nurse", "c": "The client does not need to avoid dried fruits or vegetable juice, as these items typically have no effect on nighttime urination.", "d": "While this may be a valid option for some people, it is not necessarily practical in this situation."}, "keyConcept": "Nocturia refers to nighttime urination. It may be caused by increased urine production or by decreased bladder capacity. Underlying conditions that contribute to nocturia include diabetes mellitus, diabetes insipidus, urinary tract infections, hypercalcemia, and hypokalemia. Although nonpharmacologic measures can reduce nocturia, they don't solve the problem for most individuals. The underlying cause should be identified and treated.. Drug therapies for nocturia include desmopressin (DDAVP), antimuscarinic agents, alpha-blockers, and 5-alpha reductase inhibitors."}, {"id": 10141, "cat": "GERONTOLOGY", "stem": "A nurse is assigned to care for a client with an ileal conduit. Which of the following best describes an ileal conduit? O A.A bag is connected to a stoma on the abdominal wall and stool from the large intestine drains into the bag O B. A feeding tube is placed directly into the stomach through the abdominal wall O C. A tube is inserted into the urethra to drain urine from the bladder, which collects in a bag O D. A bag is connected to a stoma on the abdominal wall and urine drains into the bag", "choices": [{"id": "a", "t": "This describes a colostomy or ileostomy, when stool is emptied into the bag, not urine."}, {"id": "b", "t": "This describes a gastrostomy tube, not an ileal conduit."}, {"id": "c", "t": "This describes an indwelling urinary catheter, not an ileal conduit."}, {"id": "d", "t": "—m | 27% ~~ Hard An ileal conduit may be performed for a client who has most of the bladder removed through surgery, for a reason such as bladder cancer."}], "correct": "d", "rationale": "—m | 27% ~~ Hard An ileal conduit may be performed for a client who has most of the bladder removed through surgery, for a reason such as bladder cancer. B i at After bladder removal, the ureters drain into the ileum of the small intestine, the end of which is then brought out through a stoma on the abdominal wall. The urine collects in a bag placed on the stoma and the client empties it regularly. c |_| 12%", "whyNot": {"a": "This describes a colostomy or ileostomy, when stool is emptied into the bag, not urine.", "b": "This describes a gastrostomy tube, not an ileal conduit.", "c": "This describes an indwelling urinary catheter, not an ileal conduit."}, "keyConcept": "An ileal conduit is created using the small intestine after removing the bladder. A short segment of the small intestine is placed at an opening created surgically on the surface of the abdomen, forming a stoma. Kidney Ureter Stoma (urostomy opening) lleal conduit (small piece of bowel used to carry urine)"}], "hematologic": [{"id": 10142, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client with pulmonary embolism. The client is hypotensive and dyspneic. Which of the following client outcomes is the priority in this client?", "choices": [{"id": "a", "t": "The client will remain free of hemorrhage and abnormal bleeding related to medications"}, {"id": "b", "t": "The client will have increased cardiac output"}, {"id": "c", "t": "The urinary output will be above 20 mLs per hour"}, {"id": "d", "t": "The client will be free of left-sided heart failure"}], "correct": "b", "rationale": "A ; | 25% Moderate “The client will have increased cardiac output” is the priority expected client outcome when a client with a pulmonary embolus. Although OR a aan the nurse should insure that the client will also be free of hemorrhage and abnormal bleeding related to medications such as anticoagulants that prevent future clotting, the priorities are: airway, breathing, and then circulation (which includes cardiac output). Other expected c | 3% outcomes for clients affected with pulmonary emboli are the maintenance of urinary output of 30 mLs or more per hour, and the absence of D | | 12% cor pulmonale, or right-sided heart failure.", "whyNot": {"a": "This is important for the client taking anticoagulant medications, but the nurse must first ensure that the client’s heart continues beating.", "c": "The client should have at least 30 mL of urine output per hour.", "d": "The client may be at risk of right-sided heart failure, not left-sided."}, "keyConcept": "Apulmonary embolism is a sudden blockage in an artery that supplies the lung. It usually occurs after a deep vein thrombosis breaks loose and travels through the bloodstream to the lung. Pulmonary embolism can cause permanent damage to the affected lung; low oxygen levels in the blood; and damage to other organs due to impaired gas exchange. A large PE can result in hemodynamic collapse and death. Ina hypotensive client, restoration of adequate cardiac output is the goal of treatment. Anticoagulants and/or thrombolytic medications are prescribed to break up clots and to prevent additional clots from forming."}, {"id": 10143, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who hemorrhaged postoperatively one day ago. The client has had onset of excessive clotting followed by severe bleeding. Which disorder is this client most likely affected with?", "choices": [{"id": "a", "t": "Life-threatening acute disseminated intravascular coagulation"}, {"id": "b", "t": "Life-threatening chronic disseminated intravascular coagulation"}, {"id": "c", "t": "Idiopathic thrombocytopenia purpura"}, {"id": "d", "t": "Coagulopathy"}], "correct": "a", "rationale": "This client is most likely affected with life-threatening acute disseminated intravascular coagulation (DIC). The risk factors associated with DIC are hemorrhage, septicemia, and cardiopulmonary arrest. Some signs and symptoms of DIC include excessive clotting followed by severe bleeding, hypotension, changes in mood, peripheral cyanosis, tachycardia, behavioral changes, and a decreased level of consciousness. Chronic DIC can occur months after a precipitating event and, unlike the acute form, it is not accompanied by bleeding, but only clotting. Idiopathic thrombocytopenia purpura is associated with a recent virus or an autoimmune disorder; and coagulopathy is associated with risk factors such as bleeding and autoimmune disorders.", "whyNot": {"b": "The client is most likely in DIC, but in an acute form, not a chronic form.", "c": "Idiopathic thrombocytopenia purpura is associated with a recent virus or autoimmune disorder, not surgery.", "d": "Coagulopathy is often associated with an autoimmune disorder, not surgery."}, "keyConcept": "Disseminated intravascular coagulation (DIC) is characterized by activation of systemic blood coagulation, resulting in formation of intravascular thrombi in various organs and contributing to multiorgan dysfunction. The fibrinolytic system is also pathologically activated, which may result in severe bleeding. Clients with DIC can present with both thrombotic and bleeding problems. [pic Microvascular ~ thrombosis <4PT -9TCT _ Rot specific y + taPIT +1 D-dimers < for DIC RBC fragmentation + t platelets + 1 Soluble Fibrin (MAHA) *tTCT Monomer Complexes + J fibrinogen Laboratory tests in DIC states"}, {"id": 10144, "cat": "HEMATOLOGIC", "stem": "A client who has remained in bed for most of the day develops pooling of blood in the lower extremities. This situation places the client at risk of developing which of the following conditions?", "choices": [{"id": "a", "t": "Deep vein thrombosis"}, {"id": "b", "t": "Contractures"}, {"id": "c", "t": "Urinary retention"}, {"id": "d", "t": "Constipation"}], "correct": "a", "rationale": "Pooling of blood in the lower extremities may occur with a lack of activity and ambulation. This excess blood increases the risk of blood B | a0 clotting, which could result in a deep vein thrombosis if a clot forms in the veins of the lower leg. | © 2%", "whyNot": {"b": "While an immobile client may be at higher risk of contractures, these are not caused by excessive pooling of blood.", "c": "Urinary retention does not develop from pooling of blood in the lower extremities.", "d": "While an immobile client may be more likely to develop constipation, this does not develop as a result of excessive pooling of blood in the"}, "keyConcept": "Risk factors for venous thromboembolism, including deep vein thrombosis and pulmonary embolus, fall within three broad categories of risk: stasis, hypercoagulable states, and damage to the intima of the blood vessel. Hypercoagulable states include chronic estrogen supplementation, malignancy; damage to the lining of the vessel can occur as a result of trauma or a surgical procedure."}, {"id": 10145, "cat": "HEMATOLOGIC", "stem": "A nurse is assessing a client who has a premeal blood glucose level of 42 mg/dL. Which finding should the nurse expect?", "choices": [{"id": "a", "t": "Fruity breath odor"}, {"id": "b", "t": "Diaphoresis"}, {"id": "c", "t": "Ketones in urine"}, {"id": "d", "t": "Vomiting"}], "correct": "b", "rationale": "A client who has hypoglycemia can have diaphoresis and cool, clammy skin. Hypoglycemia can occur if the blood glucose level drops below the expected reference range. Signs and Symptoms of Hypoglycemia Signs and Symptoms Treatment Weakness Clammy skin Trembling _ Consume 15g of easily absorbed carbohydrates and wait 15 Dizziness minutes before rechecking the blood glucose level. Repeat Headachi eagacne carbohydrates as needed and follow with a meal within 1 hour. Confusion Hunger Shaking", "whyNot": {"a": "Fruity breath odor is a manifestation of hyperglycemia. The expected reference range for a fasting blood glucose level is 70 to 100 mg/dL.", "c": "Ketones in the urine is a manifestation of hyperglycemia. The expected reference range for a fasting blood glucose level is 70 to 100 mg/dL.", "d": "Vomiting is a manifestation of hyperglycemia. The expected reference range for a fasting blood glucose level is 70 to 100 mg/dL."}, "keyConcept": "Hypoglycemia can occur from taking too much insulin, not eating meals at regular intervals, or increased exercise. Manifestations usually occur with blood glucose levels less than 50 mg/dL."}, {"id": 10146, "cat": "HEMATOLOGIC", "stem": "What is the most appropriate nursing action when administering a unit of packed red blood cells to a client with a bleeding peptic ulcer and anemia who currently has D5W infusing through a 20-gauge catheter?", "choices": [{"id": "a", "t": "Discontinue D5W and flush the catheter with normal saline before starting transfusion"}, {"id": "b", "t": "Use an intravenous (IV) infusion pump to piggyback on the existing line"}, {"id": "c", "t": "Start an 18-gauge catheter to replace the 20-gauge before infusing packed red blood cells using the existing intravenous line (IV)"}, {"id": "d", "t": "Attach the transfusion set to the port closest to the client using the existing intravenous tubing"}], "correct": "a", "rationale": "The only fluid that can be administered with a blood transfusion is normal saline. Cell lysis may result from a dextrose solution, and other IV solutions are incompatible with blood and may result in precipitation. A dedicated IV line must be used to infuse blood products. If using tubing that is currently in place, the infusion and tubing should be discontinued, and the catheter should be flushed with normal saline before connecting the tubing for administration of blood. After the transfusion is complete, the nurse should clear the catheter with a flush of NS before administering any fluids or medications. Saline Filter Drip chamber Roller clamp -—Toclient", "whyNot": {"b": "A dedicated IV line must be used to infuse blood products. If using tubing that is currently in place, the infusion and tubing should be", "c": "It is not necessary to replace the 20-gauge catheter, although larger-bore catheters are preferable for infusion of blood products. However,", "d": "A dedicated IV line must be used to infuse blood products."}, "keyConcept": null}, {"id": 10147, "cat": "HEMATOLOGIC", "stem": "Which of the following is most appropriate initial nursing intervention?", "choices": [{"id": "a", "t": "Reposition the client."}, {"id": "b", "t": "Administer an anxiolytic."}, {"id": "c", "t": "Increase the intravenous fluid (IVF) rate."}, {"id": "d", "t": "Call the healthcare provider."}], "correct": "d", "rationale": "Tachycardia, tachypnea, and anxiety following diagnosis of deep venous thrombosis (DVT) are all signs of possible pulmonary embolus. This life-threatening complication must be treated immediately; therefore, the most appropriate initial intervention for the nurse is to call the healthcare provider.", "whyNot": {"a": "Repositioning the client will not help the client and will only waste time before definitive treatment.", "b": "Administering an anxiolytic before calling the physician is not appropriate and may mask important symptoms.", "c": "The healthcare provider may prescribed an increase in the infusion rate if the client is hypotensive, but the nursing priority is notification"}, "keyConcept": "Pulmonary embolism (PE) occurs when a pulmonary artery is occluded, usually by a blood clot that has broken free from its site of origin and embolized to the lungs. PE can be fatal if misdiagnosed, unrecognized, or untreated. Complete hemodynamic collapse can occur rapidly, within minutes. Symptoms of PE include shortness of breath, dry cough, hemoptysis, diaphoresis or sudden chest pain that worsens with deep inspiration. Severe clinical findings suggestive of a massive PE include hypotension, hypoxemia, and loss of consciousness. Massive PE is defined as a PE that causes 50% or more occlusion of the pulmonary capillary bed."}, {"id": 10148, "cat": "HEMATOLOGIC", "stem": "he has “severe pain that is 10/10.” Which of the following interventions is most appropriate for the nurse?", "choices": [{"id": "a", "t": "Contact the healthcare provider to change the prescription to meperidine."}, {"id": "b", "t": "Contact the healthcare provider to request a prescription for patient-controlled analgesia with a higher dose of morphine."}, {"id": "c", "t": "Contact the healthcare provider to request a prescription for a non-opioid analgesic."}, {"id": "d", "t": "Contact the healthcare provider to request a consultation with an addiction specialist."}], "correct": "c", "rationale": "B. morphine. . an ; . a , os 53% Individuals with sickle cell anemia and frequent pain crises may be undertreated over time because they are mistakenly identified as having drug abuse issues or addiction. Vasoocclusive crises can result in severe pain and over time, and an individual repeatedly treated for c |__| 31% vasoocclusive crises will develop tolerance to the analgesic effects of opioid pain medication. Research has demonstrated that the risk of D || 12% substance abuse among clients with sickle cell disease is the same as in the general population. The nurse should know that the client’s self-report of pain is a reliable indicator and should take appropriate action to inform the healthcare provider of the client’s needs. External cues should not be used to judge a client’s pain level. In clients with chronic or recurrent pain, self- distraction measures often help the client to cope.", "whyNot": {"a": "Meperidine (Demerol) should not be given to clients with a sickle cell crisis since it forms a toxic metabolite (normeperidine), and effects", "c": "Severe pain typically requires an opioid analgesic. Non-opioid analgesics are usually ineffective in this case.", "d": "This response is unwarranted. Individuals with frequent sickle cell pain crises may be undertreated when their tolerance and/or coping"}, "keyConcept": "A client's self report of pain is the most reliable indicator of the severity of pain. The absence of physiological signs does not reliably distinguish absence of pain. Absence of external cues does not reliably identify absence of pain, as some clients may be able to distract themselves or may have other coping mechanisms."}, {"id": 10149, "cat": "HEMATOLOGIC", "stem": "A nurse is preparing to administer one unit of packed red blood cells. Which of the following interventions is most important for the nurse to consider when transfusing this blood product?", "choices": [{"id": "a", "t": "Only use normal saline solution with the packed cells"}, {"id": "b", "t": "Administer the packed cells over the course of no more than 20 minutes"}, {"id": "c", "t": "Premedicate with antihistamines before administration"}, {"id": "d", "t": "Do not administer to a client with anemia"}], "correct": "a", "rationale": "When the nurse infuses blood products, the only solution compatible with the unit is normal saline. Other IV solutions can cause hemolysis B | 3\" of the blood cells in the transfusion and are not considered safe to administer with blood products. cli 8%", "whyNot": {"b": "Packed cells may take longer than 20 minutes to infuse; the protocol varies by institution, but the nurse typically has several hours to", "c": "Pre-medication with antihistamines is not necessary before administering a blood product transfusion.", "d": "Anemia is not a contraindication for blood transfusions."}, "keyConcept": "Normal saline (0.9%) is isotonic and it is the only recommended intravenous solution for administration with blood products. Other intravenous solutions will cause hemolysis or clotting when mixed with red cells. 5% dextrose in water will hemolyze red cells. Intravenous solutions containing calcium, such as Lactated Ringers’s solution, can cause clot formation."}, {"id": 10150, "cat": "HEMATOLOGIC", "stem": "A nurse is admitting a school-age child who has leukemia and has a platelet count of 40,000/mm3. Which of the following precautions should the nurse initiate?", "choices": [{"id": "a", "t": "Neutropenic"}, {"id": "b", "t": "Bleeding"}, {"id": "c", "t": "Contact"}, {"id": "d", "t": "Airborne"}], "correct": "b", "rationale": "The nurse should initiate bleeding precautions for a child who has a low platelet count. The expected reference range for platelets in children is 150,000 to 400,000/mm‘. Platelet counts less than 100,000/mmi are an indication of thrombocytopenia and an increased risk for bleeding. Bleeding precautions involve specific measures to reduce the risk for bleeding, such as using soft-bristled toothbrushes, avoiding IM injections, and preventing constipation. D |", "whyNot": {"a": "The nurse should initiate neutropenic precautions for a child who has a low WBC count. The expected reference range for neutrophils is", "c": "The nurse should implement contact precautions for a child who has an illness that is transmitted through direct contact.", "d": "The nurse should implement airborne precautions for a child who has an illness that is transmitted through airborne nuclei. These include"}, "keyConcept": "The nurse should understand that a platelet count should be obtained for a child who has leukemia. Bleeding precautions are implemented for a child who has a low platelet count. It is important that the interdisciplinary team is aware of the condition in order to provide safe and effective care."}, {"id": 10151, "cat": "HEMATOLOGIC", "stem": "Which of the following instructions should the nurse provide to a client who has an IV in order to reduce the risk of clotting in the tubing?", "choices": [{"id": "a", "t": "Notify the nurse to flush the infusion site each hour"}, {"id": "b", "t": "Avoid lying on the tubing"}, {"id": "c", "t": "Change the dressing site if it feels too tight"}, {"id": "d", "t": "Keep the IV site at or above the level of the heart"}], "correct": "b", "rationale": "The nurse should instruct the client to avoid lying on the tubing. Pressure from the body can compress the tubing and cause obstruction of flow, increasing the risk of blood clotting in the tubing. Signs of clotting include slow flow and back flow into the tubing.", "whyNot": {"a": "The nurse should decide how often to flush the tubing; it is not the client’s role to notify the nurse to flush the IV.", "c": "Atight dressing at the site does not necessarily indicate a clot in the tubing; it is the nurse’s role to change the dressing, not the client.", "d": "Keeping the IV site at or above the level of the heart would not have an impact on whether or not clotting would develop in the tubing."}, "keyConcept": "Blood clots may form in intravenous tubing if it becomes kinked, obstructing the flow. Taping the IV line can reduce the risk of kinking of the line, but clotting can also occur if the client puts weight on the IV line and obstructs the flow. Other factors that promote clotting in the line include slow flow, an empty IV bag, and failure to flush the line after administering intermittent medications. If the tubing becomes clotted, the infusion must be discontinued. A new line must be started at another site, using a new cannula and administration site."}, {"id": 10152, "cat": "HEMATOLOGIC", "stem": "@ 0 @ X Viraln sx Recor M Inbox ™M Inbox ] Untitl Untitl (4 Googl @ TEAS Online & Mark! @ Micro: (INANETEMETE @ ATITE G Newc N x | G GERO + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "lron supplementation for 3 weeks prior to surgery to increase hemoglobin concentration"}, {"id": "b", "t": "Storing blood donated by family members prior to surgery"}, {"id": "c", "t": "Autologous blood donation prior to surgery"}, {"id": "d", "t": "Purchasing blood from a bank that screens multiple times"}], "correct": "c", "rationale": "A l 3% Moderate ’s own blood before reuse during a scheduled procedure. Autologous @c | 70% transfusion reduces the risk of transfusion reactions and disease transmission, but it is contraindicated in clients with bacteremia or D ; | 25% leukemia. Donations can be made every 3 days if the client's hemoglobin level remains within the target range. Blood can be frozen and {) stored for as long as ten years. Autotransfusion refers to aseptic collection, filtering, and return of the client's own blood during surgical 2 procedures. a & =) a = ay", "whyNot": {"a": "Although iron supplementation can improve hemoglobin levels in clients with iron deficiency anemia, they are not effective for", "b": "Donated blood by family members may make the client feel more comfortable, but the risk of disease transmission or transfusion reaction", "d": "Additional screening is not provided by blood banks."}, "keyConcept": "Autologous blood transfusion refers to collection of an individual's blood, usually before a surgical procedure, for reinfusion when necessary. Autologous blood transfusion reduces the risk of allergic reaction, blood type incompatibility, and transmission of infectious disease."}, {"id": 10153, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who is undergoing percutaneous liver biopsy. Which of the following will the nurse do when assisting with this procedure?", "choices": [{"id": "a", "t": "Assist the client into a seated position."}, {"id": "b", "t": "Instruct the client to take a deep breath and hold it."}, {"id": "c", "t": "Assist the client to lie on the right side after the procedure."}, {"id": "d", "t": "Obtain clotting studies post-procedure."}], "correct": "c", "rationale": "all om The liver detoxifies the blood, metabolizes nutrients and drugs, and synthesizes clotting factors and other proteins, including albumin. It ec | plays an important role in the metabolism of carbohydrates, proteins, amino acids, and lipids, including breakdown and synthesis. The D | proteins synthesized by the liver include coagulation factors | (fibrinogen), II (prothrombin), V, VII, VIII, IX, X, XI, XIII, protein C, protein S and antithrombin. With decreased liver function, production of clotting factors decreases and the risk of bleeding is increased. Clients with significant liver disease will have an increased prothrombin time (PT) and international normalized ratio. In clients with liver disease who require biopsy, clotting studies are obtained before the procedure. In preparation for a liver biopsy, the nurse should assist the client to the supine position, with the right arm behind the head. The nurse should instruct the client to exhale and hold the breath, which elevates the diaphragm away from the liver. After the procedure is complete, the client should be assisted to a side-lying position on the right side to promote hemostasis.", "whyNot": {"a": "The client is in the supine position, with the right arm behind the head.", "b": "Exhaling elevates the diaphragm away from the liver.", "d": "Clotting studies should be obtained before the procedure to determine the risk of hemorrhage."}, "keyConcept": "In advanced liver disease, hepatocytes are replaced by fibrosis and liver function diminishes, including production of vitamin K dependent clotting factors. As a result, clients with liver disease often have increased PT and INR. When undergoing invasive procedures, these clients are at greater risk of uncontrolled bleeding. During a liver biopsy, the client should be in a supine position. After the procedure, the client should be assisted to a side-lying position on the right side to promote hemostasis."}, {"id": 10154, "cat": "HEMATOLOGIC", "stem": "A nurse is planning an in-service for nursing staff about managing care for clients who develop disequilibrium syndrome. Which of the following interventions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Administer an opioid medication."}, {"id": "b", "t": "Monitor for the development of chest pain."}, {"id": "c", "t": "Assess level of consciousness."}, {"id": "d", "t": "Start an intravenous infusion of dextrose 50%."}], "correct": "c", "rationale": "Dialysis disequilibrium syndrome is the result of cerebral edema that develops due to an imbalance of solutes, primarily urea, between the circulating blood and the brain cells. This imbalance results in a fluid shift from the vascular space into the brain cells. Manifestations of cerebral edema include a change in the level of consciousness ranging from a headache to restlessness, to seizures, or coma. The nurse should assess the client's level of consciousness frequently during and after dialysis to identify the onset of dialysis disequilibrium syndrome and take corrective actions to prevent client injury, such as decreasing the dialysis exchange flow rate during dialysis.", "whyNot": {"a": "Dialysis disequilibrium syndrome can occur during hemodialysis or after completion of the session. Thought to be related to the filtering", "b": "Cardiac events, such as myocardial infarction, are a complication of hemodialysis in clients who have an underlying cardiovascular", "d": "Hypoglycemia is a potential complication of dialysis, especially in clients who have preexisting diabetes mellitus. Manifestations of"}, "keyConcept": null}, {"id": 10155, "cat": "HEMATOLOGIC", "stem": "If the client begins to hemorrhage, what is the antidote for heparin?", "choices": [{"id": "a", "t": "Vitamin K"}, {"id": "b", "t": "Warfarin (Coumadin)"}, {"id": "c", "t": "Thrombin"}, {"id": "d", "t": "Protamine sulfate"}], "correct": "d", "rationale": "All 12% — Easy Protamine sulfate is the antidote for heparin. Vitamin K is the antidote for warfarin. a | 10%", "whyNot": {"a": "Vitamin K is the antidote for warfarin and not for heparin. @D fs 86%", "b": "Warfarin can increase bleeding, not act as an antidote against bleeding.", "c": "Thrombin is related to blood clotting but it is not an antidote for heparin."}, "keyConcept": "Bleeding risk is increased with unfractionated or low molecular weight (LMW) heparin therapy. Management of bleeding in a client who is receiving heparin depends upon the location and severity of bleeding, the risk of thromboembolism, and the current aPTT (for heparin) or anti-factor Xa activity (for LMW heparin). If urgent reversal is necessary, heparin is discontinued and protamine sulfate is administered."}, {"id": 10156, "cat": "HEMATOLOGIC", "stem": "should be administered. What is the most appropriate action?", "choices": [{"id": "a", "t": "Contact the blood bank and do not administer the infusion"}, {"id": "b", "t": "Call the physician to clarify the order"}, {"id": "c", "t": "Place the unit in a biohazard container and request a new unit"}, {"id": "d", "t": "Administer the blood and monitor the client carefully"}], "correct": "a", "rationale": "The nurse should contact the blood bank as soon as she notices that there is a discrepancy between the ordered blood and the unit received. B I a The blood bank may have made an error in supplying or labeling the blood. Under no circumstances should the nurse administer the blood c] 3% anyway. p | 1%", "whyNot": {"b": "The physician does not need to clarify the order; it was not ordered incorrectly. It was either labeled incorrectly or the nurse received the", "c": "The nurse should request the correct unit but she does not need to waste the current unit by putting it in a biohazard container.", "d": "If the nurse has determined that she has the wrong type of blood, she should not administer it to the client."}, "keyConcept": "Before hanging a blood product, the nurse will thoroughly double-check the client's identification and verify the blood product. The unit to be transfused is checked against client identifiers, per facility policy. Blood transfusion reactions usually occur as an immune response against blood cells or other components of the transfused product. Acute transfusion reactions occur within the first few minutes of transfusion and delayed transfusion reactions develop hours to days later. If red blood cells are destroyed, the reaction is further classified as hemolytic. All other types of reactions are classified as nonhemolytic. Reactions can result from infectious, chemical, or physical forces or from human error during blood product preparation or administration. The nurse must be familiar with the specific product to be transfused, the appropriate administration rate, and required client monitoring. The type of blood product and client's condition usually dictate the infusion rate."}, {"id": 10157, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who has an increased white blood cell count. Which of the following medications can result in an increased WBC count?", "choices": [{"id": "a", "t": "Diuretics"}, {"id": "b", "t": "Antibiotics"}, {"id": "c", "t": "Histamine-2 blockers"}, {"id": "d", "t": "Corticosteroids"}], "correct": "d", "rationale": "A l 3% Moderate Corticosteroids are often given to reduce inflammation and pain. Initiation of corticosteroid use can cause leukocytosis (an increase in the B | a white blood cell count.) Neutrophils are the primary cell type affected. This increase in white blood cell count is caused by demarginalization of white blood cells in the walls of blood vessels, release of neutrophils from the bone marrow, and delayed transport of white blood cells to c |_| 13% tissues. The client's clinical condition should not deteriorate in association with the increased white blood cell count. @D Fs 70%", "whyNot": {"a": "Diuretic medications may have an impact on electrolyte levels but they typically do not affect the white blood cell count.", "b": "Antibiotics are given to fight infection. Infection usually results in an elevated white blood cell count, which should return to normal with", "c": "Histamine-2 blockers do not cause an increase in WBC count. They block the inflammatory response by binding to histamine receptors"}, "keyConcept": "The values in the white blood cell count reflect leukocytes distributed within the blood. It does not reflect the white blood cells in the bone marrow, tissue, or attached to the endovascular lining of blood vessels. These cells enter the bloodstream wit initiation of corticosteroid therapy. Neutrophils make up the greatest percentage of leukocytes, so they have the greatest impact on changes in the WBC count."}, {"id": 10158, "cat": "HEMATOLOGIC", "stem": "Before initiating a blood transfusion, which of the following factors is important to assess to ensure the appropriate age of blood cells, which deteriorate after a set period of time?", "choices": [{"id": "a", "t": "Presence of any clots"}, {"id": "b", "t": "Blood identification number"}, {"id": "c", "t": "Expiration date"}, {"id": "d", "t": "Blood type"}], "correct": "c", "rationale": "i | Before initiating a transfusion, two RNs must identify the correct blood product and client by looking at the hospital identification number ec fF on the bag containing the blood product and matching it to the number on the client’s identification band. The nurse who administers the D | blood product must be one of the nurses who completed the verification process. Blood products typically deteriorate over time and can only be safely stored for 35 days. The nurse must check the expiration date during the verification process while hanging a blood product. Other measures to ensure safe administration include verification of the client's blood group and type and any history of previous allergic reactions to blood products. Transfusion of blood or blood components must be initiated within 30 minutes of obtaining the blood product from the blood bank, to reduce the risk of bacterial growth.", "whyNot": {"a": "The blood must be returned to the blood bank if the presence of clots is noted, but inspection of the unit of blood for abnormalities will", "b": "The nurse must note the blood identification number, but this will not ensure the correct age of blood products. The blood bank", "d": "ABO and Rh type of the recipient of a blood transfusion are obtained after the client is identified and the sample is drawn and labeled at"}, "keyConcept": "The nurse should inspect all bags of blood and blood components before initiating transfusion for expiration date and abnormal discoloration, excessive bubbles, cloudiness, or leakage. Blood products deteriorate over time and cannot be stored for longer than 35 days. Expired blood or blood products and blood products with an abnormal appearance must be returned to the blood bank. Blood products that are not administered within thirty minutes of receipt must be returned to the blood bank for storage, to reduce the risk of bacterial growth."}, {"id": 10159, "cat": "HEMATOLOGIC", "stem": "Before initiating a blood transfusion, which of the following factors is important to assess to ensure the appropriate age of blood cells, which deteriorate after a set period of time?", "choices": [{"id": "a", "t": "Presence of any clots"}, {"id": "b", "t": "Blood identification number"}, {"id": "c", "t": "Expiration date"}, {"id": "d", "t": "Blood type eck Answer"}], "correct": "c", "rationale": "Before initiating a transfusion, two RNs must identify the correct blood product and client by looking at the hospital identification number Cc fF on the bag containing the blood product and matching it to the number on the client’s identification band. The nurse who administers the D | blood product must be one of the nurses who completed the verification process. Blood products typically deteriorate over time and can only be safely stored for 35 days. The nurse must check the expiration date during the verification process while hanging a blood product. Other measures to ensure safe administration include verification of the client's blood group and type and any history of previous allergic reactions to blood products. Transfusion of blood or blood components must be initiated within 30 minutes of obtaining the blood product from the blood bank, to reduce the risk of bacterial growth.", "whyNot": {"a": "The blood must be returned to the blood bank if the presence of clots is noted, but inspection of the unit of blood for abnormalities will", "b": "The nurse must note the blood identification number, but this will not ensure the correct age of blood products. The blood bank", "d": "ABO and Rh type of the recipient of a blood transfusion are obtained after the client is identified and the sample is drawn and labeled at"}, "keyConcept": "The nurse should inspect all bags of blood and blood components before initiating transfusion for expiration date and abnormal discoloration, excessive bubbles, cloudiness, or leakage. Blood products deteriorate over time and cannot be stored for longer than 35 days. Expired blood or blood products and blood products with an abnormal appearance must be returned to the blood bank. Blood products that are not administered within thirty minutes of receipt must be returned to the blood bank for storage, to reduce the risk of bacterial growth."}, {"id": 10160, "cat": "HEMATOLOGIC", "stem": "A nurse is planning care for a client who has hepatitis B with jaundice. Which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Initiate contact precautions."}, {"id": "b", "t": "Administer acetaminophen every 6 hr"}, {"id": "c", "t": "Provide warm compresses to the areas of pruritus."}, {"id": "d", "t": "Provide a high-calorie, high-protein diet."}], "correct": "d", "rationale": "‘ia Clients who have hepatitis are at an increased risk for inadequate nutrition due to nausea, vomiting, anorexia, and fatigue. During periods of B | nausea and vomiting, IV fluids might be required to ensure adequate fluid balance is maintained. When the client is able to tolerate an oral diet, small frequent meals that are high in calories and protein are recommended to maintain muscle mass. Between meal supplements and c |_| multiple vitamins might be needed to ensure adequate nutrition is achieved. @D Dh", "whyNot": {"a": "Contact precautions are implemented for clients who have an illness that is transmitted by direct contact with the client or with items in", "b": "Hepatitis B is a viral infection of the liver resulting in inflammation of the liver cells that manifests as fever, fatigue, anorexia, nausea,", "c": "Pruritus is a common manifestation for clients who have jaundice. Elevated levels of bilirubin and a subsequent histamine response cause"}, "keyConcept": "Hepatitis is an inflammation of the liver that is often caused by a virus, although it can also be the result of medications, alcohol, or exposure to toxic chemicals. It can also be a secondary infection, following a viral infection with Epstein-Barr, herpes simplex, varicella zoster, or cytomegalovirus. The pathophysiology of hepatitis includes inflammation of the liver with infiltration of inflammatory cells, lymphocytes, and fluids. This increases the congestion within the liver and alters the biliary and portal circulation. Viral hepatitis manifestations include fever, fatigue, anorexia, nausea, vomiting, right upper quadrant pain, and joint pain. Edema of the biliary system results in jaundice, which can cause widespread pruritus, clay-colored stools, and dark urine. Because of the inflammation in the liver, the ability to metabolize medications is decreased. When planning care for the client who has hepatitis, the nurse should address activity intolerance and provide frequent periods of rest between activities as well as before and after eating. Psychosocial assessment should also be included because the client's social contact with others can be limited due to an inability to work for extended periods of time. Monitoring the client's skin integrity and taking measures to relieve pruritus and prevent infection should also be included in the plan of care. The nurse should also"}, {"id": 10161, "cat": "HEMATOLOGIC", "stem": "A nurse is reviewing laboratory results of a client who has a WBC count of 20,000/mm3. The nurse should identify that the client has which of the following conditions?", "choices": [{"id": "a", "t": "Neutropenia"}, {"id": "b", "t": "Leukocytosis"}, {"id": "c", "t": "Thrombocytosis"}, {"id": "d", "t": "Leukopenia"}], "correct": "b", "rationale": "‘a Leukocytosis is a WBC count of greater than 10,000/mm3, which can indicate inflammation or infection. OB a c|", "whyNot": {"a": "Neutropenia is a neutrophil count of less than 2,000/mm3.", "c": "Thrombocytosis is an increase in platelets.", "d": "Leukopenia is a total WBC count of less than 4,000/mm3, which can indicate overwhelming infection or medication toxicity."}, "keyConcept": "Leukocytosis is a condition that results from an increased presence of white blood cells (WBCs) in the blood stream. This increase could be caused by an acute infectious process or from the presence of leukemia, or cancer of the blood. The nurse should monitor the client for shortness of breath, mental status changes, malaise, anorexia, and weight loss."}, {"id": 10162, "cat": "HEMATOLOGIC", "stem": "A client who had extensive pelvic surgery 24 hours ago becomes cyanotic, is gasping for breath, and complains of right-sided chest pain. What should the nurse do first?", "choices": [{"id": "a", "t": "Obtain the vital signs"}, {"id": "b", "t": "Initiate a cardiac arrest code"}, {"id": "c", "t": "Administer oxygen using a face mask"}, {"id": "d", "t": "Encourage the use of incentive spirometer"}], "correct": "c", "rationale": "A Hi 15% Moderate The client is exhibiting the classic signs and symptoms of the postoperative complication of pulmonary embolus. Initially, oxygen should be B | oom administered to increase the amount of oxygen being delivered to the pulmonary capillary bed. °", "whyNot": {"a": "Itis important to assess vital signs but the nurse should first administer oxygen.", "b": "The nurse should not call a code until she determines that the client is not breathing; she should first administer oxygen.", "d": "The nurse should not have the client use incentive spirometry as an initial intervention; she should administer oxygen."}, "keyConcept": "Most hospitalized or post-surgical individuals have one or more risk factors for venous thromboembolic (VTE) disorders, which include deep"}, {"id": 10163, "cat": "HEMATOLOGIC", "stem": "nurse to take? O A. Discontinue the lactated Ringer’s solution and start an infusion of D5W to run with the packed cells O B. Discontinue the lactated Ringer’s solution and start an infusion of 0.9% NaCl to run with the packed cells O C. Start the unit of packed red blood cells and use with the lactated Ringer’s solution O D. Wait to administer the packed red blood cells until the current IV bag of lactated Ringer’s is complete", "choices": [{"id": "a", "t": "Discontinue the lactated Ringer’s solution and start an infusion of D5W to run with the packed cells"}, {"id": "b", "t": "Discontinue the lactated Ringer’s solution and start an infusion of 0.9% NaCl to run with the packed cells"}, {"id": "c", "t": "Start the unit of packed red blood cells and use with the lactated Ringer’s solution"}, {"id": "d", "t": "Wait to administer the packed red blood cells until the current IV bag of lactated Ringer’s is complete"}], "correct": "b", "rationale": "al 3% Easy Isotonic saline, or 0.9% NaCl, is the only IV solution that is compatible with blood products. If a client is receiving another type of IV fluid and OB rT SY ase: needs blood products such as packed red blood cells, the nurse should discontinue the infusion and only use 0.9% NaCl solution. Other IV ° solutions can cause hemolysis of red blood cells or clots to form in the tubing if used with transfusions. © | 20) oi 5%", "whyNot": {"a": "The nurse should stop the lactated Ringer’s solution, but she should use normal saline solution, not DSW. 2", "c": "The nurse should only use normal saline solution with blood products, not lactated Ringer’s. 3", "d": "The nurse should not wait to start the infusion; she should stop the lactated Ringer’s solution and start normal saline to run with the g"}, "keyConcept": "An 18 gauge IV catheter is used to administer blood, using a Y infusion set specifically used for the administration of blood and blood products. Normal saline is the only intravenous fluid compatible with blood. Ringer's lactate, hyperalimentation, dextrose, and other solutions are not compatible with blood and blood products. If a blood filter is used, the filter must be isuitable for the specific blood product that is being administered."}, {"id": 10164, "cat": "HEMATOLOGIC", "stem": "finding most likely represent? O A. Thrombophlebitis O B. Varicose veins O C. Buerger’s disease O D. Compartment syndrome", "choices": [{"id": "a", "t": "Thrombophlebitis"}, {"id": "b", "t": "Varicose veins"}, {"id": "c", "t": "Buerger’s disease"}, {"id": "d", "t": "Compartment syndrome"}], "correct": "a", "rationale": "Tenderness, warmth, and redness of the leg are the symptoms of thrombophlebitis. Thrombophlebitis is vein inflammation related to a B I a blood clot. It occurs more commonly in pregnancy and the postpartum period. cj 6%", "whyNot": {"b": "Varicose veins are manifested by swollen veins visible under the skin.", "c": "In Buerger’s disease cold and clammy skin can be seen.", "d": "Compartment syndrome manifests as pain and swelling."}, "keyConcept": "Postpartum deep vein thrombosis (DVT) and superficial thrombophlebitis in the postpartum period may occur as a result of trauma to the pelvic veins from pressure exerted by the presenting fetal part. Other pregnancy related changes that increase the risk of thrombophlebitis or DVT include impaired circulation and hypercoagulability related to the increased production of estrogens during pregnancy. Thrombosis that involves only the superficial veins of the leg or thigh is unlikely to result in pulmonary emboli"}, {"id": 10165, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who has leukemia and thrombocytopenia. Which of the following actions is the nurse's priority?", "choices": [{"id": "a", "t": "Allow the client to take frequent rest periods throughout the day."}, {"id": "b", "t": "Encourage the client to cough, turn, and deep breath every 2 hr."}, {"id": "c", "t": "Obtain the client's temperature every 4 hr."}, {"id": "d", "t": "Monitor the client's platelet counts."}], "correct": "d", "rationale": "A The greatest risk to a client who has thrombocytopenia is injury due to bleeding. The priority action for the nurse is to initiate bleeding B 7 precautions, and monitor appropriate laboratory studies, including platelet count.", "whyNot": {"a": "The nurse should offer the client rest periods throughout the day. However, another action is the priority for the nurse to take.", "b": "The nurse should encourage the client to cough, turn, and deep breath every 2 hr. However, another action is the priority for the nurse to", "c": "The nurse should assess the client's temperature every 4 hr. However, another action is the priority for the nurse to take."}, "keyConcept": "Platelets are essential for blood clotting. Thrombocytopenia is a decrease in the amount of platelets circulating in the bloodstream, a condition that is often identified in clients who are being treated for cancer. The expected reference range for platelets is 150,000 to 450,000/mm3. The nurse should identify that platelets < 100,000/mm3 are associated with increased risk of bleeding. The nurse should monitor the client for signs of bleeding gums, easy bruising, and blood in the stool."}, {"id": 10166, "cat": "HEMATOLOGIC", "stem": "Acharge nurse on a pediatric unit is reviewing the laboratory results of four preschoolers. Which of the following values should the nurse report to the provider? © a. wc count 9,000/mm? O B. Lead 4 mcg/dL O c.HcT 35% O D. Iron 38 mcg/dL", "choices": [{"id": "a", "t": "5%"}, {"id": "b", "t": "This lead level is within the expected reference range for children, which is less than 10 mcg/dL."}, {"id": "c", "t": "This hematocrit level is within the expected reference range for children, which is 30 to 40%."}, {"id": "d", "t": ", which is 50 to 120 mcg/dL, and should be reported to the provider."}], "correct": "d", "rationale": ", which is 50 to 120 mcg/dL, and should be reported to the provider. B TY ear", "whyNot": {"a": "This WBC count is within the expected reference range for children, which is 5,000 to 10,000/mm?. e@", "b": "This lead level is within the expected reference range for children, which is less than 10 mcg/dL.", "c": "This hematocrit level is within the expected reference range for children, which is 30 to 40%."}, "keyConcept": "It is important for the nurse to review the laboratory results of the clients and to report any unexpected findings to the provider to ensure the client receives appropriate treatment and interventions. The nurse should be aware that the expected reference range for iron is 100 to 250 mcg/dL in newborns and 50 to 120 mcg/dL in children. Therapeutic management for iron deficiency anemia focuses on increasing the amount of supplemental iron the child receives."}, {"id": 10167, "cat": "HEMATOLOGIC", "stem": "include in the discharge education? O", "choices": [{"id": "a", "t": "Dietary supplements and herbal treatments are safe to use since they do not interact with warfarin."}, {"id": "b", "t": "The client should not make any significant change in consumption of foods rich in vitamin K."}, {"id": "c", "t": "Warfarin should always be taken with food."}, {"id": "d", "t": "Alcohol decreases the anticoagulant effect of warfarin and could promote the formation of a blood clot."}], "correct": "b", "rationale": "Warfarin is an oral anticoagulant used as long-term therapy for treatment and prevention of deep vein thrombosis, pulmonary embolism, and embolic complications of atrial fibrillation and mechanical prosthetic heart valves. The primary adverse effect associated with warfarin is the increased risk of bleeding. Warfarin inhibits synthesis and activation of vitamin K-dependent clotting factors, II, VII, IX, and X. Clients with a diet poor in vitamin K may be at higher risk for bleeding. Clients are monitored to achieve the appropriate international normalized ratio (INR) and prothrombin time (PT); when that is achieved, they should not make any significant changes in consumption of foods rich in vitamin K. Warfarin does not inactivate clotting factors that have already been activated, so the therapeutic response is only measured after three days of therapy or longer. A period of bridging therapy with another anticoagulant (heparin, enoxaparin) is required to prevent propagation or formation of blood clots.", "whyNot": {"a": "Warfarin interacts with many drugs and supplements, including herbal treatments, so the use of dietary supplements and herbal", "c": "Warfarin does not have to be taken with food, although this can sometimes reduce gastric irritation.", "d": "Alcohol increases the anticoagulant effect of warfarin and should be avoided by individuals taking warfarin, as it places them at risk of"}, "keyConcept": "Warfarin (Coumadin) is an oral anticoagulant that inhibits synthesis and activation of vitamin K dependent clotting factors. It does not affect activated clotting factors, so the therapeutic response cannot be measured until at least the third day of therapy. It is used to treat venous thromboembolic disease and to prevent formation of clots in clients with atrial fibrillation or prosthetic heart valves."}, {"id": 10168, "cat": "HEMATOLOGIC", "stem": "A nurse is preparing to give a newborn an injection of vitamin K in the nursery. The infant’s father is watching and asks, “What is that for?” Which response from the nurse is most accurate?", "choices": [{"id": "a", "t": "“Your baby is more susceptible to infection right now. This will help to protect him.”"}, {"id": "b", "t": "“This shot helps your baby to excrete more bilirubin, which will reduce the risk of jaundice.”"}, {"id": "c", "t": "“We have to ensure that his blood glucose levels are stable before we can send him to your room.”"}, {"id": "d", "t": "“This injection prevents bleeding as newborns have a higher risk.”"}], "correct": "d", "rationale": "Vitamin K is administered to newborn infants because they do not make enough of the vitamin at birth to protect themselves from severe bleeding. Babies with Vitamin K deficiency bleeding (VKDB) can bleed into their intestines, or into the brain, which can lead to brain damage and even death. Newborn infants may be at risk of bleeding in the brain or of hemorrhagic disorders if they cannot create vitamin K to help their blood clot. At birth, babies have very little vitamin K stored in their bodies because only small amounts pass to them through the placenta from their mothers. The good bacteria that produce vitamin K are not yet present in the newborn’s intestines. Breast milk contains low amounts of vitamin K, so exclusively breastfed babies don’t get enough vitamin K from breast milk, alone.", "whyNot": {"a": "Vitamin K is given to a newborn to prevent bleeding disorders; it will not help to prevent infection in the baby.", "b": "The baby needs vitamin K to prevent internal bleeding; the vitamin K injection does not have an effect on the baby’s bilirubin level or", "c": "While checking blood glucose levels in a newborn is important, vitamin K helps prevent bleeding in the baby, and is not for control of"}, "keyConcept": "Early-onset vitamin K deficiency bleeding usually occurs during the first 24 hours after birth, in infants born to mothers who have been taking anticonvulsant or antituberculosis medication. Classic vitamin K deficiency bleeding usually occurs after 24 hours after birth in infants who have not received vitamin K injections at birth. It may present as late as the first week of life. Late-onset vitamin K deficiency bleeding s most common in breastfed infants who did not receive vitamin K prophylaxis at birth and usually occurs between age 2-12 weeks, although it can be seen as long as 6 months after birth. Typeot When it Occurs Caractere"}, {"id": 10169, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client with a new prescription for warfarin (Coumadin.) Which of the following should the nurse include when teaching the client about this medication?", "choices": [{"id": "a", "t": "Partial thromboplastin time values determine the warfarin dosage"}, {"id": "b", "t": "Protamine is used to reverse warfarin's effects"}, {"id": "c", "t": "International Normalized Ratio (INR) is used to assess effectiveness"}, {"id": "d", "t": "Warfarin will facilitate blood clotting"}], "correct": "c", "rationale": "All 13% Easy INR is the value used to assess effectiveness of warfarin sodium therapy. INR reflects the prothrombin time. It is the ratio of the actual PT to B I Ee the PT that would be obtained if the thromboplastin reagent from the World Health Organization was used for the plasma test. It is now the recommended method for monitoring the effectiveness of warfarin sodium. ec fF 78% of 5%", "whyNot": {"a": "Partial thromboplastin time is used to assess the effectiveness of heparin therapy.", "b": "Fresh frozen plasma or vitamin K is used to reverse warfarin sodium’s anticoagulant effect. Protamine reverses the effects of heparin.", "d": "Warfarin sodium will help to prevent blood clots."}, "keyConcept": "Warfarin is an oral anticoagulant medication that interferes with the liver's synthesis of vitamin K-dependent clotting factors (II, VII, IX, and X). It is used for prophylaxis and treatment of: venous thrombosis, pulmonary embolism, and thromboembolism in clients with atrial fibrillation. It is also used for prevention of thrombus formation and embolization after prosthetic valve placement. Therapeutic levels can be monitored using the prothrombin time or INR."}, {"id": 10170, "cat": "HEMATOLOGIC", "stem": "*K Viral p Sa Recor ™ Inbox ™ Inbox =) Untitl« Untitl« La Goog! € OS @G 23 student.atitesting.com/LT| @ TEAS Online © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ & Mark! (SNitsvs Convert study guid« @ atits @ Newc % CLOSE { Browse Questions > iit Search Questions QJ N x G GERO x» * 3 '|1@0 + Finish update", "choices": [{"id": "a", "t": "Cardiac tamponade: Loud heart sounds and jugular vein distention"}, {"id": "b", "t": "Bacterial endocarditis: This most commonly occurs after a respiratory infection or myocardial infarction"}, {"id": "c", "t": "Venous thromboembolism: Risk factors include stasis and hypercoagulability"}, {"id": "d", "t": "Venous insufficiency: An inflammatory process that places clients at risk for pulmonary emboli"}], "correct": "c", "rationale": "Venous thromboembolism is a peripheral vascular disorder that can occur as a result of stasis, impaired venous return, and a hypercoagulation clotting disorder.", "whyNot": {"a": "Cardiac tamponade may cause jugular vein distention, but it also causes muffled heart sounds, not loud sounds.", "b": "Bacterial endocarditis most commonly occurs due to bacterial aggregation on abnormal or prosthetic cardiac valves or as a result of", "d": "Venous insufficiency is a non-inflammatory vascular disorder that is caused by insufficient venous return."}, "keyConcept": "Deep venous thrombosis (DVT) and pulmonary embolism(PE) are manifestations of venous thromboembolism (VTE) Symptoms of DVT include swelling, warmth, and erythema at the site. On physical examination, signs include calf pain on dorsiflexion of the foot, known as Homans sign; palpable, indurated, cordlike, tender vein; and discoloration of the lower extremity. In this setting, DVT is a risk factor for PE, which can result in hemodynamic collapse and death. Whey"}, {"id": 10171, "cat": "HEMATOLOGIC", "stem": "nursing action? O A. Contact the healthcare provider. O B. Return the blood to the blood bank and request a new unit of packed red blood cells. O C. Administer the blood after verifying the expiration date and identification check. O D. Administer the blood because the inclusions will be filtered in the drip chamber.", "choices": [{"id": "a", "t": "Contact the healthcare provider."}, {"id": "b", "t": "Return the blood to the blood bank and request a new unit of packed red blood cells."}, {"id": "c", "t": "Administer the blood after verifying the expiration date and identification check."}, {"id": "d", "t": "Administer the blood because the inclusions will be filtered in the drip chamber."}], "correct": "b", "rationale": "al 4% Easy When administering blood products, the nurse must verify identification of the client, matching the label to the client’s Rh (Rhesus) factor, On rsd ear the client’s ABO blood type, before checking the bag for signs that it might be contaminated, including presence of inclusions, discoloration, odor, clotting, and/or presence of air. If any of these signs are present, the nurse should return the blood to the blood bank and request a c | 5% new unit. If the blood product is past the expiration date, it is also potentially contaminated and should be returned.", "whyNot": {"a": "If there will be a significant delay in administration of blood products, the nurse should notify the healthcare provider. If there is not a", "c": "Even if the blood is matched to the client and has not expired, the presence of inclusions indicates possible contamination and it is a", "d": "The blood must be returned to the blood bank for investigation of possible contamination."}, "keyConcept": "Before administering blood products, the nurse should check for signs of contamination. These include inclusions, discoloration, clotting, odor, and the presence of air. If the blood product is past the expiration date or if any signs of contamination are present, the unit must be returned to the blood bank and a new unit requested."}, {"id": 10172, "cat": "HEMATOLOGIC", "stem": "What is the rationale for administration of fresh frozen plasma for a client who has a rapidly bleeding arterial laceration?", "choices": [{"id": "a", "t": "Rapid volume expansion"}, {"id": "b", "t": "Increase hematocrit"}, {"id": "c", "t": "Replace platelets"}, {"id": "d", "t": "Transfuse slowly"}], "correct": "a", "rationale": "eo. 51% Hard B 8% Fresh frozen plasma (FFP) is used when volume expansion and/or clotting factors are needed. It should be infused over 15 to 30 minutes, Cc Yt 38% since clotting factors deteriorate rapidly after thawing. FFP does not contain erythrocytes or platelets. It does not increase hemoglobin or D l 3% hematocrit. ABO and Rh compatibility is required, and assessment includes monitoring resolution of hypovolemia and/or coagulation studies, including activated partial thromboplastin time (aPTT) and prothrombin time (PT). FFP can be frozen for a year or more, but it must be used within 24 hours of thawing.", "whyNot": {"b": "Packed red blood cells are used to increase hemoglobin and hematocrit. One unit generally raises hemoglobin level by 1 g/dL, and", "c": "Fresh frozen plasma contains no platelets.", "d": "Fresh frozen plasma is infused over 15-30 minutes for rapid volume expansion and replacement of clotting factors."}, "keyConcept": "Fresh frozen plasma carries a risk of blood borne pathogens equal to that of whole blood. ABO and Rh compatibility is required. Fresh frozen plasma should be administered rapidly because coagulation factors become unstable after thawing. If only volume expansion is necessary, other colloid solutions are preferable."}, {"id": 10173, "cat": "HEMATOLOGIC", "stem": "A nurse is reviewing the laboratory results of a client who has thrombocytopenia. Which of the following actions should the nurse expect to take?", "choices": [{"id": "a", "t": "Apply prolonged pressure to puncture sites when obtaining blood."}, {"id": "b", "t": "Administer epoetin alfa subcutaneously."}, {"id": "c", "t": "Place the client in a private room."}, {"id": "d", "t": "Provide the client with an oral topical anesthetic before meals."}], "correct": "a", "rationale": "The nurse should implement bleeding precautions for a client who has thrombocytopenia. B i at", "whyNot": {"b": "Epoetin alfa should be administered to a client who has anemia.", "c": "A client who has neutropenia should be placed in a private room.", "d": "An oral topical anesthetic should be given to a client who has mucositis."}, "keyConcept": "Platelets are essential for blood clotting. Thrombocytopenia is a decrease in the amount of platelets circulating in the bloodstream, and this condition is often identified in clients who are being treated for cancer. Normal platelet range is 150,000 to 450,000/mm3. The nurse should know that clients are at an increased risk for bleeding once platelets drop below 100,000/mm3. The nurse should implement bleeding precautions for a client who has thrombocytopenia, such as holding prolonged pressure after punctures and implementing methods to reduce risk of injury or falls."}, {"id": 10174, "cat": "HEMATOLOGIC", "stem": "Which of the following medication orders for a client with deep vein thrombosis and overlying phlebitis is necessary to clarify with the prescriber before administration?", "choices": [{"id": "a", "t": "Heparin infusion at 800 units/hour IV"}, {"id": "b", "t": "Cephalexin 250 mg by mouth"}, {"id": "c", "t": "Warfarin 1.0 mg po"}, {"id": "d", "t": "Morphine sulfate 2 mg IV"}], "correct": "c", "rationale": "This medication order has a trailing zero, which is inappropriate under medication safety guidelines. Use of a trailing zero can lead to administration of a larger dose, in this case 10 mg. It is important to clarify the order before administration of the drug. Abbreviations should also be avoided, such as “po,” although they remain in widespread usage.", "whyNot": {"a": "Heparin infusion is typically initiated in clients with DVT in combination with warfarin until adequate INR and PT are achieved. It is nota", "b": "Cephalexin is appropriate for treatment of superficial thrombophlebitis, and there should be no confusion about the dose.", "d": "Morphine sulfate can be necessary for analgesia, but PRN titration should be avoided. A PCA pump with specific limits would be a better"}, "keyConcept": "Trailing zeros should not be used in prescriptions, since they can lead to serious medication errors. Nurses bear the responsibility of clarifying prescriptions and have legal liability for adverse client outcomes when an improper medication order is carried out."}, {"id": 10175, "cat": "HEMATOLOGIC", "stem": "After knee arthroscopy, the client has a sequential compression device (SCD). Which of the following should the nurse include in this client's care?", "choices": [{"id": "a", "t": "Elevate the SCD on two pillows"}, {"id": "b", "t": "Change the settings on the SCD to make the client more comfortable"}, {"id": "c", "t": "Stop the SCD to remove dressings and bathe the leg hourly"}, {"id": "d", "t": "Discontinue the SCD when the client is ambulatory"}], "correct": "d", "rationale": "A Hi 16% Moderate After knee arthroplasty, the knee will be extended and immobilized with a firm compression dressing and an adjustable soft extension splint B I a in place. An SCD will be applied. The SCD can be discontinued when the client is ambulatory, but while the client is in bed the SCD needs to be maintained to prevent thrombosis. c | 5%", "whyNot": {"a": "The SCD does not need to be elevated on two pillows. The nurse should check the physician’s orders about whether it is appropriate for", "b": "The SCD settings should not be changed. It is important for the SCD to be used on its ordered settings to prevent thrombosis after surgery.", "c": "Although the client may need a bath while in bed after surgery, the nurse should leave the SCD in place as long as possible until the client"}, "keyConcept": "Sequential compression devices are placed to prevent thrombi and pulmonary embolism (PE). The term venous thromboembolism (VTE) is now used to encompass both DVT and PE. The deep veins in the legs return venous blood to the right heart. The blood is pushed forward by contractions of the leg muscles and one-way venous valves. The venous system is a low-pressure system; muscles must act as pumps to increase the flow of returning blood, moving blood upward to the heart. One-way venous valves prevent backward flow and blood pooling in the venous system. DVT risk increases with injury to the venous system or lungs and with client immobility.instructions. The healthcare provider should specify in the prescription that the sleeve should be removed every 8 hours to assess skin integrity and neurovascular status. Neurovascular assessment includes assessment of the “5 Ps” of ischemia, which include pain, pulse, pallor, paresthesia, and paralysis. Unless the healthcare provider specifically orders thigh-length SCDs, knee length SCDs should be used. The prescription should specify combination therapy with knee-length or thigh-length compression hose. SCDs are contraindicated in clients with documented deep vein thrombosis."}, {"id": 10176, "cat": "HEMATOLOGIC", "stem": "A nurse is beginning a morning shift. Which of the following clients should the nurse assess initially?", "choices": [{"id": "a", "t": "A client on bed rest who complains of swelling in the lower leg"}, {"id": "b", "t": "A client complaining that the breakfast tray is late every day"}, {"id": "c", "t": "A client diagnosed with pneumonia who has bilateral crackles on an exam"}, {"id": "d", "t": "A client admitted with a urinary tract infection who complains of urinary urgency"}], "correct": "a", "rationale": "A client on bed rest is at risk of venous thromboembolic disease, including deep vein thrombosis and pulmonary embolism, which can be . Swelling in the legs is not an expected finding in clients on bedrest. This client should be the priority initial assessment, as the situation could be life-threatening or life-altering. c || 26% p| 2%", "whyNot": {"b": "This is a psychosocial problem that should be addressed, but it is not a priority.", "c": "This is an expected finding in pneumonia but requires assessment. The client should be seen after the client with possible PE.", "d": "This finding is a normal symptom in a urinary tract infection. It is not potentially life-threatening and does not take priority."}, "keyConcept": "Immobility is a significant risk factor for venous thromboembolism in hospitalized clients. Deep vein thrombosis is characterized by swelling, calf tenderness, and a positive Homan's sign. Embolization of a deep vein thrombosis to the lungs can result in cardiopulmonary arrest, making assessment and intervention a priority."}, {"id": 10177, "cat": "HEMATOLOGIC", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Bright red blood from the incision"}, {"id": "b", "t": "Petechiae under the blood pressure cuff"}, {"id": "c", "t": "Temperature of 101 degrees Fahrenheit"}, {"id": "d", "t": "Platelet count of 75,000/mm3"}], "correct": "c", "rationale": ". The client will typically have a normal temperature. B i at", "whyNot": {"a": "The nurse might expect to see bright red bleeding from the incision after the wound is closed.", "b": "The client might develop petechiae under the blood pressure cuff or under compression stockings, caused by rupture of capillary blood", "d": "Typically, the platelet count will be decreased (less then 150,000/ mm3) and the PTT will be increased."}, "keyConcept": "DIC is caused by abnormal activation of the clotting cascade in infection, childbirth, and surgical procedures. Although DIC is typically associated with bleeding, it is a disorder in which hemorrhage and thrombosis occur at the same time. Hypercoagulation causes diffuse thrombosis in small and large vessels, leading to depletion of clotting factors, fibrinogen, and platelets. This results in hemorrhage. Prompt recognition and treatment are necessary to reduce morbidity and mortality associated with DIC. The underlying cause of DIC must be identified and treated. Supportive measures include fluid replacement and administration of blood components. The nurse should monitor the client for signs of bleeding, which range from oozing to frank hemorrhage. Bleeding is the primary clinical manifestation and may cause anxiety in the client and family members. The nurse should provide care in a reassuring manner to reduce anxiety."}, {"id": 10178, "cat": "HEMATOLOGIC", "stem": "Which of the following actions should a nurse take immediately after stopping a transfusion for a client with a transfusion reaction?", "choices": [{"id": "a", "t": "Culture the catheter tip from the transfusion line"}, {"id": "b", "t": "Remove the intravenous catheter"}, {"id": "c", "t": "Flush the intravenous catheter with normal saline and run at keep vein open (KVO) rate."}, {"id": "d", "t": "Flush the IV with 5% dextrose in water (D5W) and run at KVO"}], "correct": "c", "rationale": "If a client experiences a transfusion reaction, the transfusion should be discontinued, and all IV tubing replaced, but the IV catheter should remain in place. The nurse should maintain a patent intravenous line with normal saline, flushing the line and running normal saline at KVO (keep vein open) while awaiting further prescribed medications or blood products from the healthcare provider. The healthcare provider and blood bank should be notified and blood and tubing should be returned to the blood bank.", "whyNot": {"a": "The catheter tip is cultured when infection or septicemia is suspected, but in case of a transfusion reaction, it is important to leave the", "b": "Maintenance of IV access is important after a transfusion reaction. The healthcare provider may prescribe another intravenous therapy,", "d": "Solutions with dextrose should not be used with blood products, as it may cause red blood cells to clump."}, "keyConcept": "Ifa transfusion reaction occurs, all IV tubing should be replaced after the transfusion is discontinued. The IV catheter should remain in place for IV access, with normal saline running at KVO."}, {"id": 10179, "cat": "HEMATOLOGIC", "stem": "report to the healthcare provider? O", "choices": [{"id": "a", "t": "Anuria"}, {"id": "b", "t": "Pruritus"}, {"id": "c", "t": "Nausea"}, {"id": "d", "t": "Severe headache"}], "correct": "d", "rationale": "All | Erythropoietin (EPO) is a hormone made in the kidney and is necessary for maturation of red blood cells. It is used to treat anemia Cc | associated with chronic renal failure and due to cancer and treatment with toxic chemotherapeutic drugs. Hypertension and related e@D ; headaches occur in 15% of individuals with the administration of erythropoietin. A headache may progress to seizures or encephalopathy. Increased blood pressure occurs less frequently with subcutaneous administration compared to intravenous administration of EPO. Hypertension can be relieved with dialysis or, in individuals who are not on dialysis, with a diuretic.", "whyNot": {"a": "Anuria is a urine output of less than 50 mL/day and is expected in a client on hemodialysis.", "b": "Pruritus is associated with end-stage renal disease.", "c": "Nausea is a side effect that is expected with the initiation of EPO therapy."}, "keyConcept": "Erythropoeitin is a hormone produced in the kidney that promotes maturation of red blood cells. In clients with anemia due to chemotherapy or chronic renal failure, supplementation may be necessary. Significant adverse effects include hypertension with headache, seizure, and even encephalopathy."}, {"id": 10180, "cat": "HEMATOLOGIC", "stem": "report to the healthcare provider? O", "choices": [{"id": "a", "t": "Anuria"}, {"id": "b", "t": "Pruritus"}, {"id": "c", "t": "Nausea"}, {"id": "d", "t": "Severe headache"}], "correct": "d", "rationale": "Ail | Erythropoietin (EPO) is a hormone made in the kidney and is necessary for maturation of red blood cells. It is used to treat anemia Cc | associated with chronic renal failure and due to cancer and treatment with toxic chemotherapeutic drugs. Hypertension and related ep fe headaches occur in 15% of individuals with the administration of erythropoietin. A headache may progress to seizures or encephalopathy. Increased blood pressure occurs less frequently with subcutaneous administration compared to intravenous administration of EPO. Hypertension can be relieved with dialysis or, in individuals who are not on dialysis, with a diuretic.", "whyNot": {"a": "Anuria is a urine output of less than 50 mL/day and is expected in a client on hemodialysis.", "b": "Pruritus is associated with end-stage renal disease.", "c": "Nausea is a side effect that is expected with the initiation of EPO therapy."}, "keyConcept": "Erythropoeitin is a hormone produced in the kidney that promotes maturation of red blood cells. In clients with anemia due to chemotherapy or chronic renal failure, supplementation may be necessary. Significant adverse effects include hypertension with headache, seizure, and even encephalopathy."}, {"id": 10181, "cat": "HEMATOLOGIC", "stem": "A nurse is reviewing the prescription for a client who is being evaluated for the presence of hepatitis C. Which of the following prescribed laboratory tests should the nurse identify as diagnostic for hepatitis C? O A Indirect bilirubin © B.HCVRNAtesting O C. Aspartate aminotransferase (AST) O D. Alanine aminotransferase (ALT)", "choices": [{"id": "a", "t": "Bilirubin is the result of RBC breakdown which primarily occurs in the spleen. The hemoglobin released from the RBC is further broken"}, {"id": "b", "t": "Identifying the presence of a hepatitis C infection can occur within 4 weeks of infection with the virus."}, {"id": "c", "t": "AST is an enzyme found in a number of tissues, including the heart, muscle, liver, and skeletal muscles. Injury or disease results in"}, {"id": "d", "t": "ALT is an enzyme found predominantly in the liver. Elevated levels occur with hepatic injury or disease. The normal reference range for ALT"}], "correct": "b", "rationale": "Identifying the presence of a hepatitis C infection can occur within 4 weeks of infection with the virus. The HCV RNA test provides information O : —— on the presence of the hepatitis C virus and can determine the viral load, or degree of infection. This test is used to diagnose and monitor the response to treatment of hepatitis C. c | on", "whyNot": {"a": "Bilirubin is the result of RBC breakdown which primarily occurs in the spleen. The hemoglobin released from the RBC is further broken", "c": "AST is an enzyme found in a number of tissues, including the heart, muscle, liver, and skeletal muscles. Injury or disease results in", "d": "ALT is an enzyme found predominantly in the liver. Elevated levels occur with hepatic injury or disease. The normal reference range for ALT"}, "keyConcept": "Hepatitis C is a viral infection of the liver which results in inflammation, necrosis, and remodeling of the organ. This type of hepatitis is spread primarily by blood transmission, through the shared use of needles, transfusions with infected blood or blood products, and needlestick injuries. It is largely asymptomatic with diagnosis often delayed for years until significant damage has occurred or routine laboratory examination identifies abnormal liver function. Diagnostic studies to diagnose hepatitis include liver enzymes (AST, ALT, Alkaline phosphatase) and bilirubin. Elevations of these tests indicate the presence of injury, inflammation, or disease. A liver biopsy can also be completed to diagnose and stage hepatitis, although the client should have coagulation studies completed prior to obtaining a biopsy because of the highly vascular nature of the liver and the risk for bleeding. In order to identify the specific serology of the hepatitis, additional testing can be completed. For hepatitis C, these include enzyme-linked immunosorbent assay (ELISA), the recombinant immunoblot assay, and the HCV RNA test. The HCV RNA test is especially useful in identifying the viral load and can be used to monitor the response to treatment. Nurses should be aware of the various tests used to diagnose and evaluate clients who have hepatitis as well as any special interventions related to the specific tests. For example, IM injections should be avoided in clients scheduled to have AST levels drawn because this can alter the results."}, {"id": 10182, "cat": "HEMATOLOGIC", "stem": "Before beginning a transfusion of a unit of packed red blood cells that has also been checked by another nurse, which of the following items is a priority for assessment?", "choices": [{"id": "a", "t": "Skin color"}, {"id": "b", "t": "Hematocrit"}, {"id": "c", "t": "Vital signs"}, {"id": "d", "t": "Urine output eck Answer"}], "correct": "c", "rationale": "One of the first signs of a transfusion reaction is a change in vital signs, so vital signs should be checked before beginning a transfusion and assessed again 15 minutes after beginning the transfusion. The nurse should remain with the client during the first 15 minutes of the transfusion to monitor for a reaction. A major ABO incompatibility reaction or severe allergic reaction usually occurs within transfusion of the first 50 mL of blood product. The nurse should monitor vital signs every hour afterward, until 1 hour after completion of the transfusion.", "whyNot": {"a": "Skin color may exhibit pallor in clients with severe anemia. It is not a priority assessment.", "b": "This is not the priority item at the initiation of a transfusion. A transfusion reaction is not reflected rapidly in hematocrit change.", "d": "Urine output can be reduced in clients who have had significant volume loss requiring transfusion. Although urine output should be"}, "keyConcept": "A nurse should remain with the client for fifteen minutes after initiating transfusion of whole blood or blood components. An initial sign of transfusion reaction is a change in vital signs, so they are the priority assessment before the transfusion and fifteen minutes after initiation of transfusion. The nurse should also continue to assess the client every hour until an hour after completion of the transfusion. Blood bag RH type ‘ABO group ~ Expriration| date Identification _- number"}, {"id": 10183, "cat": "HEMATOLOGIC", "stem": "A client is receiving warfarin for deep vein thrombosis. His INR is 5.0. Which of the following orders from the healthcare provider can the nurse anticipate?", "choices": [{"id": "a", "t": "Protamine sulfate IV"}, {"id": "b", "t": "Administer oral vitamin K"}, {"id": "c", "t": "Infusion of fresh frozen plasma"}, {"id": "d", "t": "Administer the next dose of warfarin at the scheduled time eck Answer"}], "correct": "b", "rationale": "all 8% Easy Warfarin is an anticoagulant medication that is monitored by prothrombin time (PT) or INR (international normalized ratio). An INR of 1.1 or c I 4% below is normal, but a target range of 2.0 to 3.0 is indicated for preventing clotting in clients with deep vein thrombosis, atrial fibrillation, or D i 10% pulmonary embolism. Clients with a high risk of a blood clot may have a target range of 2.5-3.5. An INR level >5.0 is associated with a high risk of bleeding from any trauma, so the warfarin dose should be withheld for 1-2 doses with or without administration of low-dose vitamin K, depending on the individual risk factors for bleeding.", "whyNot": {"a": "Protamine sulfate is used to reverse the effects of heparin.", "c": "Fresh frozen plasma or prothrombin complex concentrate can be used when a client has an INR >2 with serious hemorrhage.", "d": "The client’s warfarin should be withheld for 1-2 doses until the INR returns to the therapeutic range."}, "keyConcept": "Warfarin (Coumadin) interferes with hepatic synthesis of vitamin K-dependent clotting factors (II, VII, IX, X.) The nurse should assess the client for signs of bleeding and hemorrhage, including bleeding gums; nosebleed; unusual bruising; tarry, black stools; hematuria; fall in hematocrit or BP; and guaiac-positive stools, urine, or nasogastric aspirate."}, {"id": 10184, "cat": "HEMATOLOGIC", "stem": "A nurse is providing preoperative teaching for a client who will undergo surgery. Which of the following information should the nurse include regarding the antiembolitic stockings? O A.\"The stockings are applied to protect your legs and heels from skin breakdown.\" O B. \"The stockings can be rolled down during sleep if your legs get too warm.\" O C. \"The stockings improve your circulation to keep blood from pooling in your legs.” O D. \"The stockings make it easier for you to do leg exercises after your surgery.\"", "choices": [{"id": "a", "t": "Although it's possible that wearing stockings might prevent some shearing forces that could increase the risk for skin breakdown, the"}, {"id": "b", "t": "Antiembolitic stockings should not be rolled partially down. This can be constricting around the leg and can occlude circulation."}, {"id": "c", "t": ". This B | a0 promotes venous return from the legs, which helps prevent venous thrombosis, or clot formation, and peripheral edema."}, {"id": "d", "t": "Antiembolitic stockings are unlikely to facilitate leg exercises for the client after surgery."}], "correct": "c", "rationale": ". This B | a0 promotes venous return from the legs, which helps prevent venous thrombosis, or clot formation, and peripheral edema.", "whyNot": {"a": "Although it's possible that wearing stockings might prevent some shearing forces that could increase the risk for skin breakdown, the", "b": "Antiembolitic stockings should not be rolled partially down. This can be constricting around the leg and can occlude circulation.", "d": "Antiembolitic stockings are unlikely to facilitate leg exercises for the client after surgery."}, "keyConcept": "Nurses are responsible for the application of antiembolitic stockings and teaching clients about the process and purpose of the stockings. Nurses should have the skill and knowledge to measure clients for the correct fit and identify situations in which stocking use is contraindicated, such as skin lesions on the legs."}, {"id": 10185, "cat": "HEMATOLOGIC", "stem": "temperature reading was 98.6°F previously but is currently 100.6°F orally. Which of the following complications associated with a blood transfusion is most likely present?", "choices": [{"id": "a", "t": "Volume overload"}, {"id": "b", "t": "Delayed transfusion reaction"}, {"id": "c", "t": "Hyperkalemia"}, {"id": "d", "t": "Septic shock"}], "correct": "d", "rationale": "A i 8% Hard Transfusion of blood contaminated with bacterial pathogens results in signs and symptoms that appear rapidly and include fever, chills, Cc | 2% hypotension, nausea, vomiting, diarrhea, and shock. Blood transfusion rates should never exceed recommended guidelines, which specify @D YT 49% transfusion over 2-4 hours per unit of packed red blood cells. Several different types of transfusion reaction may occur, including septicemia (bacterial), febrile, hemolytic, and allergic, as well as graft vs. host disease. Signs of an immediate transfusion reaction include chills, diaphoresis, hives, pruritus, swelling, muscle aches, back pain, chest pain, dyspnea, wheezing, pallor, cyanosis, tingling and numbness, nausea, abdominal cramping, vomiting and diarrhea, and a rapid thready pulse. If the client is unconscious, the nurse should watch for a fever, weak pulse, hypotension, tachycardia or bradycardia, hemoglobinuria, oliguria, and anuria.", "whyNot": {"a": "Volume overload from a blood transfusion results in dyspnea, hypertension, tachycardia, chest pain, and potentially a cough productive of", "b": "A delayed transfusion reaction occurs days to years after a transfusion. The client may experience a drop in hematocrit, jaundice, and a", "c": "The signs of hyperkalemia include cardiac arrhythmias, ECG changes, paresthesia, weakness, cramping abdominal pain, and diarrhea."}, "keyConcept": "Transfusion of contaminated blood products results in rapid onset of septicemia, characterized by fever, chills, hypotension, nausea, vomiting, and diarrhea. The transfusion must be discontinued and a sample of the client's blood should be sent to the laboratory for culture, with the remainder of the blood product. Treatment includes IV fluids, vasopressors, and antibiotics."}, {"id": 10186, "cat": "HEMATOLOGIC", "stem": "Which solution should be hung at the bedside of a client receiving a unit of packed red blood cells?", "choices": [{"id": "a", "t": "D5NS (5% dextrose in 0.9% sodium chloride)"}, {"id": "b", "t": "5% dextrose in 0.45% sodium chloride"}, {"id": "c", "t": "Normal saline"}, {"id": "d", "t": "Lactated Ringer’s solution"}], "correct": "c", "rationale": "al 4% Easy (0.9%) saline (i.e. normal saline) is the solution of choice to hang at the bedside for use before and after transfusion of blood ec fs 89% product. Dextrose-containing IV solutions can cause clumping of red blood cells, and lactated Ringer's solution is not a first-line choice when . When transfusing blood products, a needle that is at least 19 gauge is indicated, although larger (16 or 18 gauge) needles should be used for rapid transfusion. Tubing for administration of blood products is usually Y-type with a microaggregate filter. One arm of the Y tubing is used for the isotonic saline solution, with the other arm reserved for blood product.", "whyNot": {"a": "Dextrose-containing solutions can cause clumping of red blood cells.", "b": "This option also contains dextrose, so can be eliminated.", "d": "Normal saline is the only solution that should be added to blood components."}, "keyConcept": "Isotonic saline (0.9%) is the only crystalloid solution used when transfusing blood products. Blood products are infused using Y tubing, with one arm of the tubing reserved for blood product and the other used to infuse the normal saline solution. A microaggregate filter removes particulate matter."}, {"id": 10187, "cat": "HEMATOLOGIC", "stem": "A nurse is admitting a patient at 12 weeks gestation for treatment of a deep vein thrombosis. Which of the following medications is contraindicated in pregnancy?", "choices": [{"id": "a", "t": "Prasugrel"}, {"id": "b", "t": "Warfarin"}, {"id": "c", "t": "Enoxaparin"}, {"id": "d", "t": "Unfractionated heparin"}], "correct": "b", "rationale": "a . ; “ iconce incl . . - all 9% Moderate Warfarin is an anticoagulant used in treatment of venous thromboembolic disease, including deep vein thrombosis, pulmonary embolism, and atrial thrombosis. It interferes with synthesis and activation of vitamin K dependent clotting factors. Prothrombin time (PT) and eB | 70% International Normalized Ratio (INR) are used to monitor the therapeutic effects of the drug. Warfarin is associated with fetal malformations c | | 8% and is contraindicated in early pregnancy through the first trimester for most indications. It is considered category D for patients with high- D | | 13% risk mechanical heart valves.", "whyNot": {"a": "Prasugrel is used to treat acute coronary syndromes and is not indicated for DVT, but animal studies have not demonstrated a risk to fetal", "c": "Enoxaparin (Lovenox) is a low molecular weight heparin. It is pregnancy risk category B and is preferred over unfractionated heparin for", "d": "Unfractionated heparin is preferable to enoxaparin in clients with a high risk of bleeding who may need reversal with protamine sulfate,"}, "keyConcept": "Warfarin is used to treat clients with deep vein thrombosis (DVT), atrial fibrillation, and pulmonary embolism (PE.) It is contraindicated in the first trimester of pregnancy because it is associated with increased risk of fetal malformation. Pregnancy increases the risk of venous thromboembolism four to five fold. DVT occurs three times as often as PE."}, {"id": 10188, "cat": "HEMATOLOGIC", "stem": "Which best describes the reticulocyte count, which is a part of the complete blood count (CBC)?", "choices": [{"id": "a", "t": "Ameasurement of the volume of oxygen-carrying molecules found in red blood cells"}, {"id": "b", "t": "Ameasurement of the ability to form blood clots"}, {"id": "c", "t": "Ameasurement of immature erythrocytes in the blood"}, {"id": "d", "t": "A measurement of the size of the erythrocytes"}], "correct": "c", "rationale": "A Hi 11% Moderate Reticulocytes are red blood cells that are immature and are still developing. A measurement of the number of these cells is called the B | 3\" reticulocyte count. It is normally checked to ensure that the body is creating enough red blood cells and can continue to provide oxygen to the body through hemoglobin when the reticulocytes mature. ec Pe 14% of 5%", "whyNot": {"a": "This is a measurement of hemoglobin, not the reticulocyte count.", "b": "This is a measurement of platelets, not the reticulocyte count.", "d": "This measures the mean corpuscular volume (MCV), which is the size of the red blood cells, not the reticulocyte count."}, "keyConcept": "The reticulocyte count is a measure of production of red blood cells (erythropoiesis.) In clients with anemia, the reticulocyte count can be used to differentiate between blood loss or impaired erythropoiesis as a cause of low red blood cell count."}, {"id": 10189, "cat": "HEMATOLOGIC", "stem": "Which of the following clients is a priority for assessment by a nurse on the pediatric unit?", "choices": [{"id": "a", "t": "A male infant with intussusception who is scheduled for surgery and has stool that looks like “currant jelly”"}, {"id": "b", "t": "Achild postoperative appendectomy who complains of pain"}, {"id": "c", "t": "A child admitted with pyelonephritis who has cloudy urine"}, {"id": "d", "t": "A child with a sickle cell crisis who has a sudden onset of right leg weakness"}], "correct": "d", "rationale": "Ischemic strokes can be a complication of sickle cell anemia. During a sickle cell crisis, sickled red blood cells can occlude blood supply. Other causes of stroke in children include carotid artery dissection and aneurysms. The client is at risk of significant permanent disability as a result of an acute change in condition, making this the most urgent priority for the nurse. A child with sickle cell anemia who has an ischemic stroke requires emergent treatment, just like an adult. In some cases, an exchange transfusion may be necessary.", "whyNot": {"a": "Intussusception is a condition where part of the intestine invaginates into the adjacent portion of intestine, usually around a mass or other", "b": "Although postoperative pain must be addressed, it is not the most urgent priority.", "c": "Pyelonephritis is an infection of the upper urinary tract, and cloudy urine is an expected finding."}, "keyConcept": "Priority assessments are those conditions that pose an immediate threat to survival or safety of the client, usually involving airway, breathing, or circulation. Ischemic stroke in sickle cell disease is caused by occlusion of the blood vessels that supply the brain. Time is critical to treatment to improve outcomes."}, {"id": 10190, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who has been undergoing anticoagulation with heparin for 3 days. Which of the following should the nurse monitor carefully?", "choices": [{"id": "a", "t": "Liver function tests"}, {"id": "b", "t": "Urine myoglobin"}, {"id": "c", "t": "Platelet count ©) p.pTandInR"}], "correct": "c", "rationale": "al 8 | Heparin is an anticoagulant agent given as an infusion or by subcutaneous injection for treatment of venous thrombosis or pulmonary @c | embolism. After several days, the client may develop heparin-induced thrombocytopenia, which is characterized by a platelet count of D | <150,000 cells/mm43. The nurse should monitor the client for bleeding by assessing the gums, the stool for dark tarry stools, or for an increased pulse or drop in blood pressure. The activated partial thromboplastin time (aPTT) is used to monitor the efficacy of the drug. The therapeutic level is 1.5 to 2.5 times the normal value. A normal aPTT is 30 to 40 seconds. Protamine sulfate is the antidote to heparin in cases requiring rapid reversal of anticoagulation.", "whyNot": {"a": "Liver function tests are not monitored with heparin therapy.", "b": "Urine myoglobin can appear like blood in urine in clients who have muscle breakdown. It is assessed in clients with rhabdomyolysis."}, "keyConcept": "Heparin is an anticoagulant medication given intravenously or subcutaneously for treatment of venous thromboembolic disease. When caring for a client who is receiving heparin therapy, the nurse should monitor the client for signs of bleeding, including dark tarry stools and tachycardia or hypotension. The aPTT is used to monitor therapy, but platelets must be monitored since heparin can cause a reduction in the platelet count."}, {"id": 10191, "cat": "HEMATOLOGIC", "stem": "A nurse is preparing to administer IV morphine to a client and notes the date of expiration on the prefilled syringe occurred 2 weeks ago. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Administer the medication and monitor the client for a therapeutic effect."}, {"id": "b", "t": "Discard the medication in the sharps container."}, {"id": "c", "t": "Notify the provider."}, {"id": "d", "t": "Return the medication to the pharmacy."}], "correct": "d", "rationale": "The nurse should verify the expiration date for each medication scheduled for administration. If a date has expired, the nurse should return B | the medication to the pharmacy. The nurse should know and adhere to the rights of medication administration which include: + The right medication @D | + The right dose + The right client + The right route + The right time + The right documentation", "whyNot": {"a": "The nurse should not administer any medication that has an expired expiration date.", "b": "The nurse should not discard an expired medication in the sharps container. Morphine, a controlled substance, will be disposed of by the", "c": "It is not necessary for the nurse to notify the provider. The nurse is responsible for medication administration and should obtain the"}, "keyConcept": "It is the responsibility of the nurse to administer medication to the client. The nurse should verify the accuracy and safety of the medication prior to administration and the correct procedure to take if a violation of safety is discovered."}, {"id": 10192, "cat": "HEMATOLOGIC", "stem": "transfusion? O A. Hemoglobin O B. Hematocrit O C. White blood cell count O D. Platelet count", "choices": [{"id": "a", "t": "Hemoglobin"}, {"id": "b", "t": "Hematocrit"}, {"id": "c", "t": "White blood cell count"}, {"id": "d", "t": "Platelet count"}], "correct": "c", "rationale": "all 7% Easy Clients can receive transfusions of whole blood or its components, including packed RBCs, fresh frozen plasma, albumin, clotting factors, B I Ee cryoprecipitate, and platelets. A granulocyte infusion refers to the infusion of white blood cells, including neutrophils, eosinophils, and basophils. Granulocyte concentrate transfusion is typically reserved for clients with severe neutropenia who have serious infections and ec | 78% have not responded to other treatments. In addition to monitoring the white blood cell count, a nurse must monitor a neutropenic client for D i 10% signs of infection.", "whyNot": {"a": "Transfusion of red blood cells should improve the hemoglobin level. One unit of packed red blood cells increases the hemoglobin level by", "b": "The hematocrit is a measurement associated with erythrocyte count. After red blood cell transfusion, a nurse knows the hemoglobin and", "d": "The platelet count is not affected by granulocyte infusion. Platelets are blood cells involved in clotting. Severe thrombocytopenia, low"}, "keyConcept": "A nurse caring for a client receiving a granulocyte transfusion should monitor the client for non-hemolytic febrile transfusion reaction. Granulocytes are stored at room temperature and should be used within six hours of collection when possible."}, {"id": 10193, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client with a GI bleed who has been diagnosed with liver failure due to hepatitis B. Which of the following blood products will most likely be prescribed to achieve hemostasis?", "choices": [{"id": "a", "t": "Packed red blood cells"}, {"id": "b", "t": "Cryoprecipitate"}, {"id": "c", "t": "Platelets © pb. whole blood"}], "correct": "b", "rationale": "The liver produces most coagulation factors, except factor VIII and factor XIII A-subunit. Individuals with liver disease are at risk of decreased Cc i synthesis due to decreased production capacity. Some clients may also have vitamin K deficiency. Vitamin K is necessary for the production D | of clotting factors Il, VII, IX, and X. In individuals with hemorrhage and liver failure, cryoprecipitate or fresh frozen plasma is administered to provide clotting factors. Cryoprecipitate provides VIII, XIII, and fibrinogen. It is infused through a sterile infusion set with a filter. Side effects can include allergic reactions and febrile reactions. ABO compatibility testing is recommended, but Rh factor testing is unnecessary. Cryoprecipitate is stored frozen and thawed in a water bath for 15 minutes.", "whyNot": {"a": "Packed red blood cells are given to increase hemoglobin and hematocrit.", "c": "Platelets play a small role in abnormalities of hemostasis in some individuals with liver disease, but low levels of coagulation factors are"}, "keyConcept": "Liver failure results in decreased synthesis of clotting factors and increased risk of hemorrhage. Cirrhosis also results in esophageal varices, a common cause of upper GI bleeding. When treating an upper Gl bleed in clients with liver disease, clotting factors can be replaced by administration of cryoprecipitate or fresh frozen plasma."}, {"id": 10194, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who has a new prescription for heparin therapy. The nurse should identify that which of the following statements by the client is the priority to report? O A.\"lam allergic to morphine.\" O B. \"I take antacids several times a day.\" O C. \"| had a blood clot in my leg several years ago.\" O D.\"I have been taking antibiotics for a urinary tract infection.\"", "choices": [{"id": "b", "t": ". Therefore, this statement is the priority to OB rd ree report to the provider."}, {"id": "c", "t": "The nurse should identify that the client's history of a blood clot is a risk factor for developing a new thrombus formation, and the nurse"}, {"id": "d", "t": "The nurse should monitor the client's urinary tract infection and monitor the client for adverse effects or contraindications to the"}], "correct": "b", "rationale": ". Therefore, this statement is the priority to OB rd ree report to the provider. The nurse should identify that antacids are used to treat hyperacidity caused by GERD or a peptic ulcer. A client who has peptic ulcer has an increased risk for gastrointestinal bleeding. An anticoagulant, such as heparin, increases this risk and can lead to c 7 36% severe hemorrhage. D Hi 17%", "whyNot": {"c": "The nurse should identify that the client's history of a blood clot is a risk factor for developing a new thrombus formation, and the nurse", "d": "The nurse should monitor the client's urinary tract infection and monitor the client for adverse effects or contraindications to the"}, "keyConcept": "Heparin therapy is used to prevent thrombus formation in clients who are postoperative and to suppress clotting in clients who have a pulmonary embolism or deep vein thrombosis. Heparin acts by activating antithrombin, which inactivates thrombin and factor Xa. The nurse should check the client's aPTT to monitor heparin therapy. Therapeutic anticoagulation is 1.5 to 2 times the baseline value. Heparin overdose is treated with protamine. Heparin should be used in caution in clients who are at risk for bleeding, such as clients who have gastrointestinal ulcers. The nurse should monitor a client who is on heparin therapy for bleeding. Manifestations of bleeding can include hypotension, tachycardia, ecchymosis, petechiae, discolored urine, and black, tarry stools."}, {"id": 10195, "cat": "HEMATOLOGIC", "stem": "glucose level over the past 120 days?", "choices": [{"id": "a", "t": "Postprandial blood glucose"}, {"id": "b", "t": "Fasting blood glucose"}, {"id": "c", "t": "Glycosylated hemoglobin"}, {"id": "d", "t": "Mean corpuscular hemoglobin"}], "correct": "c", "rationale": "A Glycosylated hemoglobin provides an accurate average of the client's blood glucose level over the past 120 days. This test can be used to B i determine the effectiveness of or compliance with a treatment plan. It can also be used to diagnose diabetes mellitus. o; of", "whyNot": {"a": "Postprandial blood glucose is a measurement of the circulating glucose level at a specified time after a meal and is used to diagnose", "b": "Fasting blood glucose is a measurement of the circulating blood glucose level after 8 hr without caloric intake. While it is a diagnostic tool", "d": "Mean corpuscular hemoglobin provides information about the hemoglobin content of red blood cells and is used to identify anemia."}, "keyConcept": "Manifestations of Type 1 Diabetes Mellitus & Hyperglycemia ® Weight loss QW Irritability W Fatigue & Impaired wound healing Blurred vision & Headache"}, {"id": 10196, "cat": "HEMATOLOGIC", "stem": "this client? O A. Maintain bed rest O B. Alert the blood bank to obtain blood for transfusion O C. Apply supplemental oxygen through nasal cannula O D. Start an intravenous bolus of normal saline", "choices": [{"id": "a", "t": "Maintain bed rest"}, {"id": "b", "t": "Alert the blood bank to obtain blood for transfusion"}, {"id": "c", "t": "Apply supplemental oxygen through nasal cannula"}, {"id": "d", "t": "Start an intravenous bolus of normal saline"}], "correct": "d", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": {"a": "Bed rest may be helpful to reduce oxygen demand in the initial phase of a crisis, but it will not help resolve the pain crisis.", "b": "Transfusion is only required when an aplastic crisis occurs, which refers to the failure of the bone marrow to produce red cells. Aplastic", "c": "Oxygen is indicated for Sa02 <94%."}, "keyConcept": null}, {"id": 10197, "cat": "HEMATOLOGIC", "stem": "A nurse receives laboratory data for 4 clients. Which of the following requires immediate intervention?", "choices": [{"id": "a", "t": "A client with acute lymphocytic leukemia who has a white blood cell count of 4000/mm43"}, {"id": "b", "t": "A client with deep vein thrombosis who has a PT of 50 seconds (control 12)"}, {"id": "c", "t": "A client with hypertension and diabetes who has a triglyceride level of 320 mmol/L"}, {"id": "d", "t": "A client with peptic ulcer disease and a GI bleed who has hemoglobin of 10 and a hematocrit of 30%"}], "correct": "b", "rationale": "After the ABCs, 2nd priority needs according include M-A-A-U-A-R which stands for: Mental status changes Acute pain Acute urinary elimination concerns Unaddressed or untreated problems that require immediate priority attention Abnormal laboratory or other diagnostic data that are outside of normal limits and Risks relating to a healthcare problem like safety, skin breakdown, infection and other conditions", "whyNot": {"a": "Although this is a low WBC count (normal is 5,000-10,0000 cells/mm/3), it is expected in a client with leukemia. This is not the priority", "c": "Although the triglyceride level is high, it is not immediately life-threatening. Reduction of serum triglycerides can be corrected over weeks", "d": "Although this hematocrit and hemoglobin levels are low, they are not immediately life-threatening. These findings are expected in a client"}, "keyConcept": "After the ABCs, 2nd priority needs according include M-A-A-U-A-R which stands for: Mental status changes Acute pain Acute urinary elimination concerns Unaddressed or untreated problems that require immediate priority attention Abnormal laboratory or other diagnostic data that are outside of normal limits and Risks relating to a healthcare problem like safety, skin breakdown, infection and other conditions"}, {"id": 10198, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who is diagnosed with deep vein thrombosis. When the client complains of pain and swelling in the legs, the first intervention of the nurse should be which of the following?:", "choices": [{"id": "a", "t": "Increase the client's fluid intake"}, {"id": "b", "t": "Massage the client's calves"}, {"id": "c", "t": "Elevate the foot of the bed"}, {"id": "d", "t": "Place a pillow under the client's knees"}], "correct": "c", "rationale": "A | | 8% Moderate The first intervention should be to elevate the foot of the bed. This will allow gravity to help move the blood from the lower extremities into . Alleviating the venous stasis will help to diminish the pain the client is feeling.", "whyNot": {"a": "Increasing fluids will help to maintain fluid balance, but will not help to decrease the client's pain.", "b": "Massaging the client's calves is contraindicated since this may cause a clot to break off and move into the circulation of the lungs", "d": "Placing a pillow under the client's knees is also contraindicated since the lower legs will be lower than the upper legs. This action would"}, "keyConcept": "Nursing interventions that can reduce pain and discomfort experienced by clients with deep vein thrombosis include elevation of the affected extremity; use of graduated compression stockings; application of warm compresses; and encouraging ambulation. When the client is on bed rest, the nurse should elevate the feet and lower legs periodically above the level of the heart. Active and passive leg exercises should be performed to increase venous flow."}, {"id": 10199, "cat": "HEMATOLOGIC", "stem": "understanding of the teaching? O A. \"Iwill provide a double dose of this medication if my child misses a dose.\" O B. \"I will give this medication to my child with a cup of skim milk.\" O C. \"This medication will cause my child's stools to be a light beige color.\" O D. \"I will administer this medication to my child using a straw.\"", "choices": [{"id": "a", "t": "\"Iwill provide a double dose of this medication if my child misses a dose.\""}, {"id": "b", "t": "\"I will give this medication to my child with a cup of skim milk.\""}, {"id": "c", "t": "\"This medication will cause my child's stools to be a light beige color.\""}, {"id": "d", "t": "\"I will administer this medication to my child using a straw.\""}], "correct": "d", "rationale": "A 1% Easy The nurse should identify that liquid iron supplements can temporarily stain the child's teeth. Therefore, the nurse should instruct the | B 9% parent to administer this medication using a straw, needleless syringe, or medicine dropper placed toward the back of the child's mouth. a", "whyNot": {"a": "The nurse should instruct the parent that doubling the dose can result in iron toxicity. The child should take a missed dose within 12 hr of", "b": "The nurse should instruct the parent that consuming milk with this medication can decrease iron absorption.", "c": "The nurse should instruct the parent that the medication will turn the child's stools dark green or black."}, "keyConcept": "Adverse effects of oral iron therapy include: + Gastric irritation + Nausea * Vomiting + Diarrhea or constipation + Anorexia"}, {"id": 10200, "cat": "HEMATOLOGIC", "stem": "Which best describes the purpose of a bone marrow biopsy?", "choices": [{"id": "a", "t": "To determine the cause of severe anemia"}, {"id": "b", "t": "To detect the risk of blood clots"}, {"id": "c", "t": "To test for the presence of allergens in the blood"}, {"id": "d", "t": "To determine the density of bone"}], "correct": "a", "rationale": "@ . Because red blood cells are created in the bone B | a0 marrow, a client who develops severe anemia may need a bone marrow biopsy to identify problems in the bone marrow that prevent effective erythropoiesis. c | 8%", "whyNot": {"b": "Tests used to detect blood clots include ultrasound and angiography.", "c": "Allergens in the blood are not detected through a bone marrow biopsy. Allergy skin testing is used to elicit an allergic reaction from", "d": "A bone density scan is used to measure bone density."}, "keyConcept": "Bone marrow is the soft tissue contained in the medullary canals of long bone and the interstices of cancellous bone. Yellow marrow is composed of fat cells and connective tissue. Red marrow produces blood cell progenitors (stem cells), including red blood cells (erythrocytes), white blood cells (leukocytes), and platelets.A bone marrow biopsy is performed to investigate the cause of anemia, cancers, immune and other blood related disorders."}, {"id": 10201, "cat": "HEMATOLOGIC", "stem": "A nurse is caring for a client who develops urticaria after a blood transfusion is initiated. Which of the following is the most appropriate initial action by the nurse?", "choices": [{"id": "a", "t": "Take vital signs"}, {"id": "b", "t": "Notify the physician who ordered the blood © c.callthe blood bank"}, {"id": "d", "t": "Stop the transfusion"}], "correct": "d", "rationale": "The most critical action is to stop the blood transfusion. Do not throw the blood bag or tubing away. Monitor the client's vital signs and notify the healthcare provider about the reaction. Depending on the reaction, the healthcare provider may give orders for medication to counteract the reaction. Finally, let the blood bank know about the reaction and complete any forms as required by the facility.", "whyNot": {"a": "While it is important to assess the client’s vital signs during a transfusion reaction, the nurse must stop the transfusion first.", "b": "The healthcare provider should be notified about the transfusion reaction, but this should not be the initial action. The priority nursing"}, "keyConcept": "A client who is experiencing an acute transfusion reaction will demonstrate adverse signs or symptoms during or within 24 hours of a blood transfusion, including fever, chills, pruritus, or urticaria. These symptoms usually resolve promptly without treatment. Symptoms that suggest a more serious reaction include dyspnea, red urine, loss of consciousness, and high fever. In any transfusion reaction, the nurse should stop the transfusion and keep the intravenous line open with normal saline (0.9% sodium chloride). The nurse should check information on the blood unit label and the client's identification to ensure that the \"right\" blood unit was administered to the \"right\" client. The remaining contents of the blood product container should be returned the blood bank, together with a freshly collected blood sample from the client, for investigation of the transfusion reaction."}, {"id": 10202, "cat": "HEMATOLOGIC", "stem": "speaking with the provider? O A. Thyroid hormone assay O B. Liver function tests (LFTs) O C. Hemoglobin and hematocrit O D. Brain natriuretic peptide (BNP)", "choices": [{"id": "a", "t": "Thyroid hormone assay"}, {"id": "b", "t": "Liver function tests (LFTs)"}, {"id": "c", "t": "Hemoglobin and hematocrit"}, {"id": "d", "t": "Brain natriuretic peptide (BNP)"}], "correct": "a", "rationale": "The nurse should review the results of thyroid hormone testing because long-term use of lithium can lead to thyroid dysfunction, causing goiter formation. Thyroid hormone levels should be measured annually. The nurse should evaluate the following laboratory tests while a client is taking lithium: + Renal function + Thyroid function + WBC with differential + Serum electrolytes *Glucose", "whyNot": {"b": "LFTs are performed for clients who have hepatocellular diseases; however, they are not necessary for the client who is taking lithium.", "c": "Hemoglobin and hematocrit levels are monitored for clients who have bleeding or anemia; however, monitoring hemoglobin and", "d": "BNP is used to monitor heart failure; however, it is not necessary for the client who is taking lithium."}, "keyConcept": "The nurse should be able to identify the necessary laboratory testing for a client who is taking lithium and is requesting a prescription refill. The nurse should review the results and inform the provider of those that could affect the renewal of a lithium prescription."}, {"id": 10203, "cat": "HEMATOLOGIC", "stem": "A client diagnosed with pulmonary embolism is receiving a heparin infusion. The nurse knows to administer which of the following drugs immediately in case of a serious bleeding reaction?", "choices": [{"id": "a", "t": "Protamine sulfate"}, {"id": "b", "t": "Fresh frozen plasma"}, {"id": "c", "t": "Vitamin K"}, {"id": "d", "t": "Idarucizumab"}], "correct": "a", "rationale": ". Immediate reversal can be achieved by administration of 1.0-1.5 mg per 100 units of Cc Hi 16% heparin. Given alone, protamine sulfate is a weak anticoagulant. However, in the presence of heparin, it forms a stable salt that stops the .", "whyNot": {"b": "Fresh frozen plasma is used in some settings for immediate reversal of serious bleeding in a client taking warfarin.", "c": "Vitamin K is used to reverse the actions of warfarin in 1-2 days. Warfarin depletes the vitamin K-dependent clotting factors.", "d": "Idarucizumab is the reversal agent for dabigatran, a direct thrombin inhibitor and direct oral anticoagulant (DOAC)."}, "keyConcept": "Protamine sulfate is an agent that can rapidly reverse the anticoagulant activity of heparin."}, {"id": 10204, "cat": "HEMATOLOGIC", "stem": "In which of the following situations would the nurse expect administration of lV heparin to be most likely?", "choices": [{"id": "a", "t": "Disseminated intravascular coagulation (DIC)"}, {"id": "b", "t": "Hypoglycemia"}, {"id": "c", "t": "Graves’ disease"}, {"id": "d", "t": "Hemophilia"}], "correct": "a", "rationale": "o; Disseminated intravascular coagulation (DIC) occurs when the proteins that cause blood clotting become overactive and are eventually B | expended. The person with DIC then starts to bleed easily and abnormally from various sites. Treatment is aimed at controlling bleeding but also managing clotting problems that arise from the underlying cause. Heparin may be administered as part of treatment to control blood c | clotting. D i", "whyNot": {"b": "Heparin is not indicated in the treatment of hypoglycemia.", "c": "Heparin is not indicated in the treatment of Graves’ disease.", "d": "Hemophilia can cause excess bleeding; heparin would not be indicated in its management."}, "keyConcept": "Disseminated intravascular coagulation is a coagulation disorder that results in abnormal activation of the blood clotting cascade. As clots are formed, the fibrinolytic cascade is also activated. Depletion of clotting factors occurs, and clients may experience vascular thrombosis. throughout the body simultaneous with uncontrolled bleeding. Underlying disorders that are associated with DIC include sepsis and serious infection; amniotic fluid embolism and placental abruption; cancer; and transfusion reaction."}], "integuement": [{"id": 10205, "cat": "INTEGUEMENT", "stem": "A nurse is irrigating a surgical wound. Which of the following solutions will the nurse use to irrigate the wound?", "choices": [{"id": "a", "t": "Hydrogen peroxide"}, {"id": "b", "t": "Povidone iodine solution"}, {"id": "c", "t": "Chlorhexadine"}, {"id": "d", "t": "Sterile normal saline 0.9 NS"}], "correct": "d", "rationale": "Normal saline is recommended for wound irrigation. Antiseptic solutions, including hydrogen peroxide, chlorhexidine, and povidone-iodine can cause tissue injury and impede wound healing. Sterile water, commercial wound cleansing solutions, and plain water can be used to cleanse wounds. Wound irrigation can be performed using a pulsed lavage, wound irrigation syringe, or a bulb syringe. Irrigation removes bacteria, debris, and other surface contaminants. Sterile normal saline promotes formulation of granulation tissue and healing by providing an adequately moist environment.", "whyNot": {"a": "Hydrogen peroxide can damage tissue and should not be used to cleanse wounds.", "b": "Skin irritants or cytotoxic solutions can damage tissue and impede healing.", "c": "Antiseptics may irritate the tissue."}, "keyConcept": "An irrigating syringe is used to flush a wound at low pressure. The nurse should place the tip of the catheter or syringe should remain above the wound. The irrigant should be directed at the wound to avoid introducing contaminants by flow over a contaminated site before the fluid reaches the wound. Sterile technique should be used to irrigate an open wound. A 35 cc syringe can be used with a 19 gauge needle or catheter to provide adequate pressure to cleanse the wound without damaging tissue. Although sterile technique is used for irrigation of surgical wounds and fresh lacerations, chronic wounds or ulcers can be irrigated using clean technique."}, {"id": 10206, "cat": "INTEGUEMENT", "stem": "A nurse is teaching the guardian of a school-age child who has pediculosis capitis. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Apply mayonnaise to the affected area at night."}, {"id": "b", "t": "Treat household pets."}, {"id": "c", "t": "Use an over-the-counter medication containing 1% permethrin."}, {"id": "d", "t": "Hire professional exterminators to eradicate the insects."}], "correct": "c", "rationale": "ing 1% permethrin. Pediculosis capitis is treated with 1% permethrin, which can be purchased over the counter.", "whyNot": {"a": "Home remedies, such as mayonnaise, can increase the risk for infection and should be avoided.", "b": "Pediculosis capitis is transmitted person-to-person; household pets are not hosts.", "d": "Professional exterminators are not necessary to manage pediculosis capitis occurrences. Families can treat and eradicate the infestation"}, "keyConcept": "Many people have home remedies for the treatment of pediculosis capitis or head lice; these remedies include applying mayonnaise, vinegar, or olive oil. These treatments are not effective and should not be recommended by the nurse."}, {"id": 10207, "cat": "INTEGUEMENT", "stem": "cough and drooling. The nurse should identify these findings as indications that the client has which of the following?", "choices": [{"id": "a", "t": "Pulmonary edema"}, {"id": "b", "t": "Bacterial pneumonia"}, {"id": "c", "t": "Inhalation injury"}, {"id": "d", "t": "Carbon monoxide poisoning"}], "correct": "c", "rationale": "All 11% Easy Burns on the facial area, ears, or neck presents a strong possibility that an inhalation injury might have occurred. A change in the respiratory B | a0 pattern, which includes wheezing, stridor, hoarseness, difficulty swallowing, drooling, or a brassy cough, can indicate an impending loss of airway and immediate action should be taken. ec | 79% oii 8%", "whyNot": {"a": "Difficulty breathing, especially in the supine position, and the presence of crackles on auscultation indicates pulmonary fluid overload.", "b": "Productive cough, fever, chills, tachypnea, tachycardia, and chest discomfort are indicative of a bacterial infection.", "d": "Confusion, headaches, and nausea can indicate carbon monoxide poisoning. The client's skin color can become altered, possibly"}, "keyConcept": "Clients who have sustained burns in the head and neck area or inside the mouth, or have singed nasal hairs, should be continually monitored during the resuscitation phase for the development of respiratory complications. A change in the respiratory pattern that includes a brassy cough, drooling, difficulty swallowing, hoarse voice, wheezing, or stridor indicates an impending loss of airway. Then nurse should immediately apply oxygen and inform emergency response personnel."}, {"id": 10208, "cat": "INTEGUEMENT", "stem": "A nurse is developing a plan of care for a client who has a stage 3 pressure ulcer. Which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Heat the solution using a microwave before cleaning the wound."}, {"id": "b", "t": "Reposition the client at least every 2 hr."}, {"id": "c", "t": "Clean the wound with hydrogen peroxide solution."}, {"id": "d", "t": "Massage reddened areas during dressing changes."}], "correct": "b", "rationale": "The nurse should plan to reposition the client at least every 2 hr and make a schedule to record position changes in the client's medical record.", "whyNot": {"a": "Microwaving the solution can cause it to become too hot. The nurse should ensure the solution is at body temperature to prevent lowering", "c": "Hydrogen peroxide solution is a drying agent that does not promote the healing of fragile skin. The nurse should use isotonic solutions to", "d": "The nurse should avoid massaging reddened skin because it can damage fragile capillaries and increase tissue necrosis."}, "keyConcept": "Caring for a client who has a stage 3 pressure ulcer begins with repositioning the client at least every 2 hr to prevent further breakdown of the skin. Developing a schedule for position changes and then recording the changes on the client's plan of care in the medical record ensures accountability for the care of the client. Special supportive devices, such as an overlay mattress, foam or gel mattress, or a kinetic bed, can provide pressure relief to prevent shearing and friction sores and reduce moisture to vulnerable areas of the client's body. The method for cleaning the wound, which is often performed through irrigation of the wound, depends on the stage of the pressure ulcer."}, {"id": 10209, "cat": "INTEGUEMENT", "stem": "A nurse is providing teaching for a client who has impetigo. Which of the following information should the nurse include?", "choices": [{"id": "a", "t": "Keep an occlusive dressing over the lesions until they are healed."}, {"id": "b", "t": "Remove the crust on the lesions prior to applying the topical medication."}, {"id": "c", "t": "Impetigo does not spread to others."}, {"id": "d", "t": "Wear soft cotton gloves while sleeping."}], "correct": "b", "rationale": "a The client should be instructed to soak or wash the lesions to remove the crust prior to applying the topical antibiotic ointment. This will OB ri allow the antibiotic to reach the central area of bacterial growth. cil", "whyNot": {"a": "Moisture from an occlusive dressing, clothing, or bedding can promote the growth of the bacterial organism. Occlusive dressings should", "c": "Impetigo is easily spread to others through direct contact with exudate from the lesions. This transmission can occur via direct contact or", "d": "Impetigo is not pruritic. There is no need to take measures to prevent unconscious scratching while sleeping."}, "keyConcept": "Impetigo is a superficial bacterial infection that typically develops in areas where skin integrity has been disrupted. It is more common in those with chronic health problems, poor hygiene, malnutrition, and those living in warm, humid climates. Nursing actions when caring for a client with impetigo include: ° Wear gloves when contacting lesions to prevent transmission. © Apply warm compresses and remove crusts prior to applying topical antibiotic ointment. © Instruct the client to: © Perform frequent hand hygiene. © Bathe at least once daily with antibacterial soap. © Avoid contact with others until the lesions have healed. © Donot share towels, washcloths, or combs."}, {"id": 10210, "cat": "INTEGUEMENT", "stem": "Aschool nurse is providing teaching to a guardian whose school-age child has pediculosis capitis. Which of the following statements by the guardian indicates an understanding of the teaching? O A.\"| should seal nonwashable items in airtight plastic bags.\" O B. \"My child must be free of nits before returning to school.\" O C. \"Iwill treat all members of our family.\" O D. \"Bedding, clothing, and towels should be soaked in cold water.\"", "choices": [{"id": "a", "t": "The nurse should instruct the guardian to seal items that cannot be washed, vacuumed, or dry cleaned in airtight plastic bags for 14 days to B ri Re: kill any lice."}, {"id": "b", "t": "The American Academy of Pediatrics recommends that children return to school after the initial treatment. It is not recommended that a"}, {"id": "c", "t": "The nurse should instruct the guardian that only members of the family who have lice should receive treatment because there are"}, {"id": "d", "t": "The nurse should instruct the guardian to wash recently used clothing, bed sheets, and towels in hot water."}], "correct": "a", "rationale": "The nurse should instruct the guardian to seal items that cannot be washed, vacuumed, or dry cleaned in airtight plastic bags for 14 days to B ri Re: kill any lice. ° ci 20%", "whyNot": {"b": "The American Academy of Pediatrics recommends that children return to school after the initial treatment. It is not recommended that a", "c": "The nurse should instruct the guardian that only members of the family who have lice should receive treatment because there are", "d": "The nurse should instruct the guardian to wash all recently used clothing, bed sheets, and towels in hot water."}, "keyConcept": "The nurse should be aware that pediculosis capitis is commonly referred to as head lice. To kill any lice, clients should seal nonwashable items in an airtight plastic bag for 14 days. Nonwashable items can include jackets, sweaters, hats, pillows, bicycle helmets, and stuffed animals. Furniture, carpets, and car seats should be vacuumed thoroughly and combs, brushes and hair accessories such as barrettes should be soaked for one hour with an over-the-counter pediculicide, which will kill the lice."}, {"id": 10211, "cat": "INTEGUEMENT", "stem": "Which of the following measures should be included in client teaching to prevent transmission of scabies?", "choices": [{"id": "a", "t": "Keep body areas lubricated."}, {"id": "b", "t": "Avoid sexual contact with infected people."}, {"id": "c", "t": "Avoid sun exposure between 10 am and 4 pm."}, {"id": "d", "t": "Look for eggs (nits) on hairs about %4” from the scalp or skin."}], "correct": "b", "rationale": "‘a o: Scabies refers to infestation with Sarcoptes scabiei, an itch mite. It is one of the most common contagious skin conditions, and nurses or Cc | other caregivers should use infection control precautions to reduce the spread. The mites burrow around the arms, axilla, breast, lower D Hi buttocks, genitalia, and within the webs and sides of the fingers. Clients should be advised to bathe thoroughly in morning and at night and to apply the prescribed medication after bathing. Clean clothing should be worn after bathing. Skin-to-skin contact and sexual contact should be avoided to reduce the risk of spread. Scabies infestation is treated with a topical permethrin cream.", "whyNot": {"a": "In general, individuals with skin infestations should keep the body areas dry to help with eradication.", "c": "Individuals with skin cancer should avoid direct sun exposure and use sunscreen.", "d": "Lice infestations are characterized by nits and must be treated with decontamination that includes the use of a nit-comb."}, "keyConcept": "Scabies refers to a mite infection that causes itching when mites burrow around the arms, axilla, breasts, buttocks, and genitalia. It is spread by direct contact. Skin to skin contact and sexual contact should be avoided. Treatment is topical permethrin."}, {"id": 10212, "cat": "INTEGUEMENT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitl Untitl (4 Googl! @ TEAS Online Mark! @ Micro: (leeueeitte\\ae iter: @ atiti =G@ Newc <€< > G 23 student.atitesting.com/LT| Tutorial: BoardVitals NCLEX Prep RN SA a“ ati Module: Quizzes & Assignments. % CLOSE Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions QJ N x G GERO x» * 3 '|1@0 + Finish update", "choices": [{"id": "a", "t": "Sanguineous"}, {"id": "b", "t": "Purulent"}, {"id": "c", "t": "Serosanguineous"}, {"id": "d", "t": "Serous"}], "correct": "d", "rationale": "A Serous drainage is described as clear and watery; it may have a yellow appearance. Serous drainage is normal during the inflammatory i B process of wound healing. ss cil", "whyNot": {"a": "This description fits a serous wound; sanguineous drainage is more likely to be bloody in appearance.", "b": "A purulent wound may contain pus and have an odor; the drainage described is more likely serous drainage.", "c": "Serosanguineous drainage is most likely clear or yellow with streaks of blood; the drainage described is more likely serous drainage."}, "keyConcept": "Serous drainage is pale yellow and watery. Sanguinous drainage is bloody drainage and indicates bleeding. Serosanguinous is a mixture of the two. Purulent drainage refers to pus - a thick drainage that is usually yellow, brown, or green in color."}, {"id": 10213, "cat": "INTEGUEMENT", "stem": "A nurse is admitting a client who is scheduled for operative repair of a tibial plateau fracture. Which of the following items in the client’s history is most likely to impede healing? © a. BMI of 28 kg/m2 O B. Drinking 1 beer most evenings O C. Peripheral arterial disease O D. Family history of diabetes", "choices": [{"id": "a", "t": "This BMI is classified as “overweight” (25-29.9 kg/m“2). BMI is not directly correlated with bone healing, although clients who are"}, {"id": "b", "t": "3%"}, {"id": "c", "t": "all 6% Easy , poor nutritional status, and ec | 81% advanced age."}, {"id": "d", "t": "Diabetes mellitus is a risk factor for poor wound healing, but a family history of diabetes will not affect the client’s wound healing."}], "correct": "c", "rationale": "all 6% Easy , poor nutritional status, and ec | 81% advanced age. Individuals with peripheral arterial disease have atherosclerotic narrowing of peripheral arteries, resulting in reduced blood D i 10% flow to the extremities. This prevents adequate oxygen delivery and delivery of nutrients to healing tissues.", "whyNot": {"a": "This BMI is classified as “overweight” (25-29.9 kg/m“2). BMI is not directly correlated with bone healing, although clients who are", "b": "Although heavy alcohol use is associated with nutritional deficiencies, particularly when an individual obtains a high proportion of", "d": "Diabetes mellitus is a risk factor for poor wound healing, but a family history of diabetes will not affect the client’s wound healing."}, "keyConcept": "Clients with inadequate tissue perfusion are at risk of poor wound healing because of impaired delivery of oxygen and nutrients. Causes of poor perfusion include peripheral arterial disease and hypotension. Other causes of poor wound healing include increased age, infection, dry skin, repetitive trauma, obesity, poor nutrition, and diabetes mellitus."}, {"id": 10214, "cat": "INTEGUEMENT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "The amount of fat and water begin to decrease, resulting in loss of turgor"}, {"id": "b", "t": "The outer layer of skin sloughs off and is replaced with new cells every few days"}, {"id": "c", "t": "The vascularity of the skin decreases, resulting in lowered ability to regulate body temperature"}, {"id": "d", "t": "Collagen begins to lose its elasticity and strength"}], "correct": "b", "rationale": "all 7% Easy As a person ages, the skin begins to lose fat, water, and collagen, resulting in loss of turgor and elasticity. Blood supply to the skin decreases, OB TY ry making it harder for an aging adult's body to regulate the temperature. This is one of the reasons older adults feel cold at higher temperatures. Although the outer layer of skin is replaced every few days in younger people, this cell replacement does not occur as quickly c | 6% in older adults.", "whyNot": {"a": "The amount of fat and water decreases in an older adult, resulting in loss of skin turgor.", "c": "An older adult’s skin vascularity decreases, lowering the ability to regulate body temperature.", "d": "The collagen found under the skin of most older adults begins to lose its elasticity and strength."}, "keyConcept": "There are many anatomical and physiological changes experienced in the course of aging. This results in increased vulnerability and special skin care needs in the elderly. Elderly individuals have fragile skin and injury can result in scar tissue, slow healing, infections, and wounds that will not heal."}, {"id": 10215, "cat": "INTEGUEMENT", "stem": "Which of the following pressure ulcer stages can vary in depth depending on location, but also included exposed bone/muscle?", "choices": [{"id": "a", "t": "Stage"}, {"id": "b", "t": "stage! O c stage ll O pb. stage lv"}, {"id": "d", "t": "Stage IV pressure ulcers demonstrate full-thickness tissue loss with exposed bone, tendon and/or muscle."}, {"id": "e", "t": "Unstageable"}], "correct": "d", "rationale": "Stage IV pressure ulcers demonstrate full-thickness tissue loss with exposed bone, tendon and/or muscle. Sloughing or eschar may be ; | present on some parts of the wound bed, and there is often include undermining and tunneling. Stage IV ulcers need to be managed surgically, and frequently require 3 months to 2 years to heal completed. c | o>", "whyNot": {"a": "Stage | pressure ulcers demonstrate intact skin with non-blanchable erythema involving a localized area, usually overlying a bony", "b": "Stage II pressure ulcers demonstrate a partial thickness loss of the dermis which presents as a shallow open ulcer with a red-pink wound", "e": "Unstageable pressure ulcers demonstrate full-thickness tissue loss in which the base of the ulcer is covered by slough (yellow, tan, gray,"}, "keyConcept": "Staging of pressure ulcers (bed sores) is important for proper treatment. Ongoing staging of the pressure ulcer can help to monitor progress or lack of progress to further give direction for treatment options. When pressure ulcers involve tunneling and involvement of bone and muscle generally surgical debridement is indicated. Stage IV pressure ulcers are the most serious in the staging scale for pressure ulcers that begins with stage | (redness of skin)."}, {"id": 10216, "cat": "INTEGUEMENT", "stem": "Which of the following clients should receive follow-up education from the nurse?", "choices": [{"id": "a", "t": "A client with frequent urinary tract infections who has increased her water intake"}, {"id": "b", "t": "A client with severe congestive heart failure who sleeps in a recliner"}, {"id": "c", "t": "A diabetic client with neuropathy who walks barefoot outside and inside"}, {"id": "d", "t": "A client with irritable bowel syndrome who intends to decrease consumption of cabbage and broccoli"}], "correct": "c", "rationale": "| 2% Diabetic clients who have lost feeling in the feet are at great risk for inadvertently sustaining an injury to the foot, potentially resulting in @c fF 95% infection. The risk of diabetic foot infection is increased as a result of failure to notice injury and because clients with diabetes have impaired , which impedes wound healing. Poor perfusion results from atherosclerosis and damage to blood vessels from hyperglycemia. Instructions to a diabetic client should include recommendations to wear well-fitting shoes and avoid walking barefoot.", "whyNot": {"a": "Increased water intake will flush the bladder and reduce urinary stasis, reducing the risk of UTI.", "b": "A client with severe congestive heart failure may need to maintain elevation of the upper body since lying flat can exacerbate shortness of", "d": "Dietary recommendations for clients with irritable bowel syndrome include avoidance of problem foods (e.g. caffeinated beverages,"}, "keyConcept": "Diabetic neuropathy frequently affects the lower extremities. Chronic hyperglycemia results in deposits of fructose and sorbitol in nerve tissue. Clients with diabetes should wear shoes in and outside of the house and inspect their feet regularly. Diabetes causes microvascular damage and facilitates atherosclerosis. These conditions reduce perfusion and result in impaired wound healing."}, {"id": 10217, "cat": "INTEGUEMENT", "stem": "A nurse is caring for four clients on an orthopedic unit. The nurse should identify that which of the following clients is at greatest risk for skin breakdown?", "choices": [{"id": "a", "t": "An adolescent who has a cervical fracture and is in a halo brace"}, {"id": "b", "t": "Ayoung adult client who has a femur fracture and is in skeletal balanced suspension traction"}, {"id": "c", "t": "Amiddle adult client who has a fractured ankle and a lower leg cast"}, {"id": "d", "t": "An older adult client who has a hip fracture and is in Buck's traction"}], "correct": "d", "rationale": "According to evidenced-based practice, this client has multiple risk factors for skin breakdown, such as advanced age and immobility due to the traction. Older adult clients are at risk of skin breakdown due to decreased muscle mass, thin, fragile skin, increased dryness of the skin, decreased pain perception, and decreased peripheral blood flow. Therefore, this client is at the greatest risk for skin breakdown.", "whyNot": {"a": "The nurse should identify that a halo brace is a risk factor for skin breakdown in the area of the brace; however, the client will be able to", "b": "The nurse should identify that skeletal traction is a risk factor for skin breakdown; however, the client will be able to shift their weight", "c": "The nurse should identify that a leg cast is a risk factor for skin breakdown in the area of the cast; however, the client will be able to"}, "keyConcept": "The nurse should perform a pressure injury risk assessment to identify clients who are at risk. Risk factors for pressure injury include limited sensory perception, limited or no physical activity, reduced mobility, inadequate nutritional intake, and frequent skin exposure to moisture, such as urine. Clients who are on bed rest and those who require assistance to change position are at increased risk for developing a pressure injury. The nurse should identify that older adult clients are at increased risk for skin breakdown due to decreased muscle mass, thin, fragile skin, increased dryness of skin, decreased pain perception, and decreased peripheral blood flow. The nurse should implement preventative measures to maintain the client's skin integrity and reduce the risk of pressure injury. Preventative measures include providing adequate hydration and nutritional intake, performing daily skin inspections, minimizing friction to the client's skin, frequently repositioning the client, elevating the client's head of bed no greater than 30° to minimize shearing forces, and keeping skin clean, dry, and moisturized. The nurse should use a lifting device, such as a trapeze, to lift clients up in bed to reduce the risk for skin abrasions caused by friction. The nurse should also apply alcohol-free barrier films to protect the client's skin and avoid massaging boney prominences."}, {"id": 10218, "cat": "INTEGUEMENT", "stem": "A client has systemic lupus erythematosus (SLE). Which skin manifestation is associated specifically with this disorder?", "choices": [{"id": "a", "t": "Pruritus"}, {"id": "b", "t": "Jaundice"}, {"id": "c", "t": "Butterfly-shaped rash"}, {"id": "d", "t": "Hives Untitl (4 Goog) @ TEAS Online = Mark! (SNitsvs Convert study guid« @ atits @ Newc Tutorial: BoardVitals NCLEX Prep RN Module: Quizzes & Assignments ati % CLOSE Quiz ~ Performance ~ { Browse Questions > iit Search Questions"}], "correct": "c", "rationale": "Correct Answer: C. Butterfly-shaped rash SLE is associated with a malar rash in up to 50% of individuals with lupus. The malar rash characteristic of cutaneous lupus is a red rash that can be flat or raised, forming a butterfly shape across the nose and cheeks. It may be related to exposure to ultraviolet light in sunlight and is often worse during a flare of the disease. Recurrent aphthous oral ulcers are also a common manifestation of lupus, which is an autoimmune disorder characterized by the production of autoantibodies that attack the cells and tissues of the body during periods of exacerbation or flare. These periods are interspersed with periods of disease remission.", "whyNot": {"a": "Pruritus may occur with SLE, but it is not specific and may occur in many other conditions.", "b": "Jaundice occurs in advanced liver disease.", "d": "Urticaria may occur. Hives are primarily associated with allergic reactions."}, "keyConcept": "Systemic lupus erythematosus (SLE) is a chronic inflammatory characterized by immune system abnormalities. It affects multiple body systems, including skin, joints, serous membranes (pericardium, pleura), renal, neurologic, and hematologic systems. Clinical manifestations vary, but the disease is characterized by periods of alternating exacerbation and remission."}, {"id": 10219, "cat": "INTEGUEMENT", "stem": "A nurse is caring for a school-age child who has a severe burn. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Initiate a high-protein, low-calorie diet."}, {"id": "b", "t": "Expose affected area to the air."}, {"id": "c", "t": "Establish an airway."}, {"id": "d", "t": "Implement contact isolation."}], "correct": "c", "rationale": "all 8% Easy The nurse should establish and maintain an airway in a child who has a major burn. Children who have been exposed to smoke inhalation B | a0 might have an adequate airway immediately after the injury, but inflammation, swelling and airway damage can cause respiratory distress and failure. Therefore, the nurse should frequently monitor the child's airway. ec | 86% of 4%", "whyNot": {"a": "The nurse should initiate a high-protein, high-calorie diet for clients who have severe burns.", "b": "The nurse should apply a dressing to the burned area to prevent infection.", "d": "Reverse isolation precautions are recommended to prevent wound infections."}, "keyConcept": "In clients who have severe burns, pulmonary hygiene is important to maintain adequate oxygenation and promote tissue healing. To promote good pulmonary hygiene, the nurse should take the following actions: Maintain the client in a semi-Fowler's position. Administer bronchodilators as needed. Use incentive spirometry, repositioning, and postural drainage. Administer high-flow humidified oxygen."}, {"id": 10220, "cat": "INTEGUEMENT", "stem": "medication, as he anticipates pain when his current medication “wears off.” What is the correct action by the RN?", "choices": [{"id": "a", "t": "Ask the nursing assistant to tell the client he will be there shortly."}, {"id": "b", "t": "Direct the nursing assistant to take the postop client’s vital signs."}, {"id": "c", "t": "Interrupt the dressing change to administer the pain medication to the postop client."}, {"id": "d", "t": "Ask the nursing assistant to find out how the client rates the pain on a scale of 1-10."}], "correct": "a", "rationale": "When prioritizing, the nurse must consider the urgency and magnitude of risk to client well-being. Nurses can use various frameworks to set priorities, including Maslow’s hierarchy of needs. Another framework, the \"ABCs / MAAUAR\" method places the ABCs, again, as the highest priority, followed by 2nd and 3rd priority level needs specified by the MAAUAR method of priority setting. Second priority needs after ABC's can be remembered by the acronym M-A-A-U-A-R which stands for: -Mental status changes and alterations -Acute pain -Acute urinary elimination concerns -Unaddressed and untreated problems that require immediate priority attention -Abnormal laboratory and other diagnostic data that are outside of normal limits and -Risks including those relating to a healthcare problem like safety, skin breakdown, infection and other medical conditions. All other needs are tertiary in priority. In this case, interrupting a sterile dressing change places the client with an uncovered wound vulnerable to infection and risk of potential harm. The client's need for safety from infection is an actual need requiring nursing action. If the dressing change is anticipated to take a long period of time, the task of assessing and medicating the postoperative client can be assigned to another nurse.", "whyNot": {"b": "Vital signs can be taken when a client is complaining of pain, but they are not always a reliable indicator of pain, so this is not the most", "c": "Interrupting the dressing change could leave the client’s wound open to infection. Medicating pain is less urgent, although the", "d": "Pain assessment is a task for the RN and not for unlicensed assistive personnel. The RN cannot delegate tasks requiring clinical judgment"}, "keyConcept": null}, {"id": 10221, "cat": "INTEGUEMENT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc € OS @G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE N xX G GERO + v Qa * es * © tb Finish update : { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Inadequate arterial blood supply."}, {"id": "b", "t": "Delayed healing of tissues after an injury."}, {"id": "c", "t": "Increased production of melanin in the area."}, {"id": "d", "t": "Leakage of red blood cells through the vascular wall."}], "correct": "d", "rationale": "Increased venous pressure alters the permeability of the veins, allowing extravasation of RBCs; hemolysis of RBCs releases a pigment called hemosiderin, which causes a characteristic brownish discoloration (brawny appearance).", "whyNot": {"a": "The brown discoloration is not caused by an inadequate arterial blood supply.", "b": "The client has not reported or shown an injury with varicose veins.", "c": "Varicose veins do not cause an increase in the pigment melanin."}, "keyConcept": "Brawny discoloration in clients with venous disorder is due to hemosiderin, a yellow-brown pigment released from breakdown of extravasated red blood cells. Chronic edema in one or both lower extremities often indicates venous insufficiency, especially when accompanied by dependent edema and hemosiderin deposition. Skin care is important for prevention of skin breakdown and formation of venous ulcers. Emollients and topical steroid creams are used to manage stasis dermatitis."}, {"id": 10222, "cat": "INTEGUEMENT", "stem": "The nurse uses Montgomery straps primarily to achieve which of the following outcomes?", "choices": [{"id": "a", "t": "The client is free from falls"}, {"id": "b", "t": "The client is free of bruises"}, {"id": "c", "t": "The client is free from skin breakdown"}, {"id": "d", "t": "The client is free from wandering"}], "correct": "c", "rationale": "A || 22% Moderate Montgomery straps are primarily used for dressing changes to avoid skin breakdown from removing and reapplying tape. B | 3\"", "whyNot": {"a": "Montgomery straps do not protect the client from falls. D | %", "b": "Montgomery straps do not protect the client from bruising.", "d": "Montgomery straps are not used to keep clients from wandering."}, "keyConcept": "Montgomery straps are wide strips of tape with holes and laces that secure dressings when placed on opposite wound edges and tied. They are used for clients with tape allergies and for those who require frequent dressing changes, which may lead to skin breakdown from frequent removal of tape; Two sides are adhered to either side of healthy skin of wound, then laced over to close the wound. po] e o 2 ° s a = a < Montgomery straps Nonadhesive portion ‘Adhesive portion"}, {"id": 10223, "cat": "INTEGUEMENT", "stem": "surgical wound. Which of the following is the priority action?", "choices": [{"id": "a", "t": "Take the client's vital signs"}, {"id": "b", "t": "Cover the wound with a dry sterile towel"}, {"id": "c", "t": "Using a sterile towel, press the organs back into the body cavity"}, {"id": "d", "t": "Place the client in the low Fowler’s position"}], "correct": "d", "rationale": "Ail Protrusion of an internal organ through a body cavity usually occurs 6 days or more after surgery in clients with poor wound healing or B a obesity. It is considered an emergency, and the nurse should place the client in the low Fowler’s position in order to prevent tension on the abdominal wound. The incision should be covered with a sterile towel moistened with normal saline to keep the organ moist. The nurse € i should ask someone to notify the surgeon but should remain with the client. The client’s vital signs should be closely monitored. If the client @D | requires surgical intervention, the nurse should prepare the client for surgery. Dehiscence", "whyNot": {"a": "The initial actions include placing the client in the low Fowler’s position and calling for someone to alert the surgeon.", "b": "A sterile towel should be moistened with normal saline.", "c": "The surgeon should be notified by another staff member while the nurse stays with the client, placing the client in the low Fowler’s"}, "keyConcept": "Preexisting risk factors for poor abdominal wound healing include obesity, diabetes, infection, seroma, hematoma, increased intraabdominal pressure and mechanical forces. Wound dehiscence with herniation of abdominal viscera (internal organs) is a surgical emergency. The"}, {"id": 10224, "cat": "INTEGUEMENT", "stem": "intervention by the charge nurse? O A. The nurse wears an N95 respirator mask. O B. The nurse admits another client to the client's double room. O C. The nurse uses alcohol-based hand sanitizer after removing gloves. O D. The nurse wears a gown when bathing the client.", "choices": [{"id": "a", "t": "The nurse wears an N95 respirator mask."}, {"id": "b", "t": "The nurse admits another client to the client's double room."}, {"id": "c", "t": "The nurse uses alcohol-based hand sanitizer after removing gloves."}, {"id": "d", "t": "The nurse wears a gown when bathing the client."}], "correct": "b", "rationale": "A || 23% Moderate The charge nurse should intervene because the client should be placed in a private room. Clients who have shingles or varicella zoster may OB a an require both airborne and contact precautions, if the outbreak is disseminated. Airborne precautions require a private room to prevent the ° transmission of droplet nuclei that are smaller than 5 microns. c | ™% oy 6%", "whyNot": {"a": "The nurse should wear an N95 respirator mask when caring for a client who has shingles because shingles requires airborne precautions in", "c": "After removing gloves, the nurse can use alcohol-based hand sanitizer or wash with soap and water, depending on whether soiling of the", "d": "The nurse should follow contact isolation with standard precautions, which includes wearing a gown when bathing the client or when"}, "keyConcept": "Herpes zoster, known as shingles, is infectious and caused by the varicella virus. The lesions caused by herpes zoster are distributed on dermatome nerves from one or more posterior ganglia, resulting in severe pain over the track of the nerve that can last 1 to 10 days. Following this phase, vesicles develop that rupture and crust over, lasting from 10 to 15 days. For some clients, pain can last up to 60 days after the lesions have crusted. The herpes zoster infection can be arrested with antiviral medications if administered within 24 hr of the initial eruptions. If a client who has herpes zoster is in a health care facility, contact and airborne precautions are required."}, {"id": 10225, "cat": "INTEGUEMENT", "stem": "Which of the following is an example of a skin macule? O A awart O B. An elevated nevus O C. A blister O D.A freckle", "choices": [{"id": "a", "t": "14%"}, {"id": "b", "t": "An elevated nevus is a raised, pigmented area of the skin; it is not a type of macule."}, {"id": "c", "t": "A blister is a fluid-filled lesion that may appear in areas of damaged skin; it is not a macule."}, {"id": "d", "t": ". Macules are flat and most macules are benign."}], "correct": "d", "rationale": ". Macules are flat and most macules are benign. A freckle is an B | aon example of a macule.", "whyNot": {"a": "Awartis a skin growth caused by the human papillomavirus; it is not a type of macule.", "b": "An elevated nevus is a raised, pigmented area of the skin; it is not a type of macule.", "c": "A blister is a fluid-filled lesion that may appear in areas of damaged skin; it is not a macule."}, "keyConcept": "Amacule is a flat, discolored skin lesion without any change in the thickness or texture of the skin. Macules are less than one centimeter in size. Papules are small solid lesions that rise above the surrounding skin. Vesicles which are small blisters that contain fluid."}, {"id": 10226, "cat": "INTEGUEMENT", "stem": "Which of the following interventions is most appropriate in a hospitalized client at risk of impaired skin integrity?", "choices": [{"id": "a", "t": "Limit chair-sitting to 4 hours at a time"}, {"id": "b", "t": "Break blisters and cover them with gauze"}, {"id": "c", "t": "Encourage food intake of 4000 to 5000 calories per day"}, {"id": "d", "t": "Promote ambulation when the client is able"}], "correct": "d", "rationale": "al 4% Easy The nurse should promote ambulation if the client is able to get up and walk. Ambulation decreases the negative impact of immobility, B | a0 resdistributes pressure, and promotes circulation, which decreases the risk of skin breakdown.", "whyNot": {"a": "The client should limit chair-sitting to 2 hours at a time to maintain skin integrity, not 4 hours at a time.", "b": "Blisters that develop with injuries or skin breakdown should be left intact in order to prevent infection.", "c": "It is not necessary for the client to take in 4000 to 5000 calories per day. The client's daily calorie needs should be based on individual"}, "keyConcept": "A client's daily caloric needs are based on age, weight, height, sex, and clinical conditions that may increase metabolic demand. Although resting caloric needs may be low in a client who is bedridden, it is important to include vitamins, minerals, and other nutrients in the diet. If caloric needs are reduced, nutrient rich foods should be used to supply dietary needs."}, {"id": 10227, "cat": "INTEGUEMENT", "stem": "test? O A. Severity of the condition O B. Type of pathogen O C. Appropriate antibiotic therapy O D. Condition of the immune system", "choices": [{"id": "a", "t": "Severity of the condition"}, {"id": "b", "t": "Type of pathogen"}, {"id": "c", "t": "Appropriate antibiotic therapy"}, {"id": "d", "t": "Condition of the immune system"}], "correct": "c", "rationale": "A l 3% Moderate Culture and sensitivity testing of infected tissues is used to identify the causative pathogenic organisms in infection. The sensitivity refers to B | Re: the sensitivity of the infecting organism to a variety of antibiotics, which guides the selection of appropriate antibiotics for treatment. °", "whyNot": {"a": "This option is not correct. A culture and sensitivity test does not indicate the severity of the condition.", "b": "The type of pathogenic microorganism is determined by Gram staining a smear of the specimen. The Gram stain is used to differentiate", "d": "The immune system can be assessed with a white blood cell count and by observing the response to treatment. Other blood tests can be"}, "keyConcept": "Infected tissues and body fluids are often sent to the microbiology lab for culture and sensitivity. \"Culture\" refers to propagation of microorganisms in a growth medium. The culture is used to test the sensitivity of the pathogen to antibiotic, antifungal, or antiviral drugs. Sensitivity testing determines the most effective antimicrobial drug for the particular pathogenic organism causing the infection."}, {"id": 10228, "cat": "INTEGUEMENT", "stem": "A nurse is reviewing the laboratory values for a client who has a stage 3 pressure ulcer. The nurse should identify that which of the following laboratory findings can delay wound healing?", "choices": [{"id": "a", "t": "Prealbumin 14 mg/dL"}, {"id": "b", "t": "Hemoglobin 16 g/dL © c.wec count 8,000/mm3"}, {"id": "d", "t": "aPTT 32 seconds"}], "correct": "a", "rationale": "o; The nurse should expect a client who has a prealbumin of 14 mg/dL to have malnutrition because this value is below the expected reference B | range of 22 to 45 mg/dL. Low prealbumin levels can delay wound healing and lead to infection. The value is a result of a combination of what the client has eaten, absorbed, digested, and metabolized over a short period of time. c |", "whyNot": {"b": "The nurse should identify that this hemoglobin level is within the expected reference range of 12 to 16 g/dL for a female client and 14 to 18", "d": "The nurse should identify that this aPTT is within the expected reference range of 30 to 40 seconds. Prolonged coagulation studies can"}, "keyConcept": "Risk factors for delayed wound healing of a pressure ulcer can include impaired mobility, incontinence, and the client's nutritional status. Successful wound healing depends on the client's tissue integrity, a positive nitrogen balance, and adequate serum protein levels. If the nitrogen balance is negative, the pressure ulcer will heal more slowly and further tissue destruction can occur. Deterioration of the pressure ulcer can cause an increase of protein loss due to the draining of the wound. The client's nutritional status is affected by the ability to consume adequate amounts of nutritional foods that contain vitamins, minerals, and protein. A serum prealbumin level is used to check the client's nutritional status more frequently because it has a half-life of 1.9 days compared to an albumin half-life of 21 days."}, {"id": 10229, "cat": "INTEGUEMENT", "stem": "medication? O A. Subcutaneous O B. Oral O C. Intravenous O D. Intramuscular", "choices": [{"id": "a", "t": "Subcutaneous"}, {"id": "b", "t": "Oral"}, {"id": "c", "t": "Intravenous"}, {"id": "d", "t": "Intramuscular"}], "correct": "c", "rationale": "During the initial or resuscitation phase following a burn injury, pain relief requires therapy with opioid and non-opioid analgesics. The IV route should be used because absorption through the muscle or stomach is impaired in burned tissue. Medications given via IM or subcutaneous injection can remain in tissue spaces which will not relieve pain. When fluid shifts occur as a result of a subcutaneous or IM injection, rapid absorption of the opioids can occur posing a risk for dangerous blood levels.", "whyNot": {"a": "The nurse should not give subcutaneous injections due to the difficulty of absorption from tissue during the resuscitation phase following {)", "b": "The nurse should not administer oral medication (including via the buccal and sublingual routes) due to decreased motility in the 3", "d": "The nurse should not use the intramuscular route of administration due to delays in absorption during the resuscitation phase following a <"}, "keyConcept": "During the initial or resuscitation phase following a burn injury, pain relief requires therapy with opioid and non-opioid analgesics. The IV route should be used because absorption through the muscle or stomach is impaired in burned tissue. Medications given via IM or subcutaneous injection can remain in tissue spaces which will not relieve pain. When fluid shifts occur as a result of a subcutaneous or IM injection, rapid absorption of the opioids can occur posing a risk for dangerous blood levels."}, {"id": 10230, "cat": "INTEGUEMENT", "stem": "A nurse is planning care for a client with a nursing diagnosis of impaired physical mobility related to prolonged bed rest. Which is the most appropriate nursing intervention for this diagnosis?", "choices": [{"id": "a", "t": "Keep lower side rails down and the bed in an elevated position"}, {"id": "b", "t": "Avoid turning the patient prone while in bed"}, {"id": "c", "t": "Encourage liquid intake of 1000 mL per day, unless contraindicated"}, {"id": "d", "t": "Turn and reposition every 2 hours, or more often as needed"}], "correct": "d", "rationale": "2 hours, or more often as needed, to prevent pressure . c | 2%", "whyNot": {"a": "The client’s side rails should remain up and the bed should be in the lowest position to avoid falls or injuries.", "b": "Unless contraindicated, the bedfast client should be turned prone or semi-prone at least once per day; this process prevents fluid excess", "c": "The client should have at least 2000 to 3000 mL of fluid per day to maintain fluid intake, unless on a fluid-restricted plan."}, "keyConcept": "Complications of immobility include skin breakdown, pressure ulcers, contractures, muscular weakness, muscular atrophy, disuse osteoporosis, renal calculi, urinary stasis, urinary retention, urinary incontinence, urinary tract infections, atelectasis, pneumonia, venous insufficiency, decreased respiratory vital capacity, venous stasis, orthostatic hypotension, decreased cardiac reserve, edema, emboli, thrombophlebitis, constipation and the loss of calcium from the bone. Many of these complications bear high costs and can be prevented."}, {"id": 10231, "cat": "INTEGUEMENT", "stem": "A nurse is caring for a child who has a diagnosis of ringworm. Which of the following does the nurse expect to find on assessment?", "choices": [{"id": "a", "t": "Intestinal bleeding and iron deficiency anemia"}, {"id": "b", "t": "Scaly erythematous rings with central clearing and pruritus"}, {"id": "c", "t": "Anal itching that worsens at night"}, {"id": "d", "t": "Fatty stools and weight loss"}], "correct": "b", "rationale": "Scaly erythematous rings with central clearing and pruritus are typical of ringworm. It is caused by a dermatophyte infection, tinea corporis, which affects the cutaneous layers of skin. Dermatophytosis, or tinea, refers broadly to a group of superficial fungal infections that are usually classified according to their anatomic location. These infections may affect the scalp (tinea capitis), bearded skin of the face (tinea barbae), body (tinea corporis), groin (tinea cruris, or jock itch), nails (tinea unguium or onychomycosis), and feet (tinea pedis, or athlete's foot). Tinea is spread by contact with infested linens, clothing, and haircare items.", "whyNot": {"a": "Hookworms are larger roundworms that suck blood and cause intestinal bleeding and iron deficiency anemia if chronic. They are", "c": "Pinworm (enterobius vermicularis) is a common worm infection in the United States. Eggs can be transmitted by contact through", "d": "Giardia lamblia is a parasite in fresh water that causes fatty stools and diarrhea."}, "keyConcept": "Ringworm lesions may be dry and scaly or moist and crusty; as they enlarge, their centers heal, producing a classic ring-shaped appearance. Ringworm is spread by contact with infected lesions or indirectly through contact with contaminated articles. Ring worm Raised edges ‘Sharply marginated % CLOSE { Browse Questions > iit Search Questions"}, {"id": 10232, "cat": "INTEGUEMENT", "stem": "A nurse is caring for a client with an infected abdominal incision from an open cholecystectomy. Which of the following actions is correct when performing a dressing change for this client?", "choices": [{"id": "a", "t": "Use sterile gloves, a gown, and a face shield when removing the soiled dressing."}, {"id": "b", "t": "Wear clean gloves when removing the soiled dressing and sterile gloves to place the new dressing."}, {"id": "c", "t": "Use clean gloves when removing the soiled dressing and replacing the new dressing."}, {"id": "d", "t": "Use clean gloves only when placing the new dressing."}], "correct": "b", "rationale": "all o: Goals of wound management include cleansing the wound to remove dirt or debris; treating infection to allow healing; and protecting the c || wound from trauma. D | Gloves are always necessary for contact with an open wound. Since the existing dressing is contaminated, clean gloves are used until the contaminated dressing is removed. The nurse should dispose of the contaminated gloves and dressing. Aseptic technique, using sterile supplies and sterile gloves, is indicated when cleaning the wound and applying the new dressing. Hand hygiene must be observed before gloving and after disposing of the contaminated gloves. A nurse should take care to avoid shedding microorganisms from the soiled dressing by minimizing movement and should quickly recover the wound with the new dressing, to minimize the risk of contamination.", "whyNot": {"a": "A sterile gown and gloves are not necessary when removing a soiled dressing, although a gown and face shield or goggles should be used", "c": "Sterile gloves should be used when replacing a dressing on a surgical wound.", "d": "Gloves should be worn whenever there is potential contact with blood or body fluid. The nurse should wear gloves when changing a"}, "keyConcept": "When caring for a client with an open wound, standard precautions are indicated. A nurse should always use gloves, performing hand hygiene before donning gloves and after removal of gloves. Nonsterile clean gloves are used when touching contaminated body fluids or contaminated items. After disposal of the contaminated dressing and gloves, the nurse should set up sterile supplies and use sterile gloves to clean the wound and apply the new dressing."}, {"id": 10233, "cat": "INTEGUEMENT", "stem": "A nurse is planning care for a client who is on bedrest and is at risk for the development of pressure ulcers. Which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Elevate the head of the client's bed to a 45° angle."}, {"id": "b", "t": "Apply powder to the skin to decrease areas of moisture."}, {"id": "c", "t": "Position the client when lying laterally on the trochanter."}, {"id": "d", "t": "Instruct the client to shift weight 10° to 15° at least every 30 min."}], "correct": "d", "rationale": "A | % Moderate The nurse should instruct the client to shift weight 10° to 15° at least every 30 min to prevent pressure points that can compromise the B i 19% fo integrity of the skin and increase the risk of skin breakdown. cil 9%", "whyNot": {"a": "The nurse should avoid raising the head of the client's bed higher than 30° to prevent shearing force on the skin from sliding down in the", "b": "The nurse should not apply powder to the client's skin to decrease areas of moisture because the powder creates an abrasive grit that can", "c": "The nurse should position the client when lying laterally at a 30° angle to avoid lying on the trochanter and to decrease the risk of skin"}, "keyConcept": "Preventing breakdown of the client's skin when on bedrest is the primary responsibility of the nurse. Five risk factors can lead to skin breakdown and pressure ulcers: decease in sensation, moisture, friction and shearing, decreased activity, and poor nutrition. Interventions including topical skin care and incontinence management are needed to address moisture factors. Repositioning every 1.5 or 2 hr and avoiding friction and shearing when repositioning is vital to prevention skin breakdown. Encouraging a balanced diet high in protein for healing, increased calories for fueling to the cells and for energy, Vitamin C and A, zinc, and drinking 6 to 8 glasses of water daily will help to maintain the client's skin integrity."}, {"id": 10234, "cat": "INTEGUEMENT", "stem": "A nurse is providing teaching to a client with a new ostomy site. Which of the following will the nurse include in teaching about cleaning the ostomy site?", "choices": [{"id": "a", "t": "Use an oil-based cleanser to rid the site of accumulated drainage"}, {"id": "b", "t": "Swab the site with isopropyl alcohol before applying the drainage bag"}, {"id": "c", "t": "Ensure that the skin is dry before applying the drainage bag"}, {"id": "d", "t": "If dryness or cracked skin develops, apply Vaseline to moisturize the area"}], "correct": "c", "rationale": "| 2% Easy The nurse should teach the client to ensure that the skin around the stoma site is dry before applying the bag. If the skin is wet, the bag may B I a not stick properly, resulting in gaps between the bag and the skin, with leakage or causing the bag to fall.", "whyNot": {"a": "The client should avoid oil-based cleansers, as these can prevent the bag from sticking to the skin.", "b": "Applying alcohol to the site before applying the bag can dry the skin and cause irritation.", "d": "The client should avoid using petroleum-based products such as Vaseline on the skin. These products can prevent the drainage bag from"}, "keyConcept": "When removing a used ostomy pouch, the client should use an adhesive remover wipe, The peristomal skin should be cleansed with non- moisturizing or non-oily soap, rinsed well with clean water and patted dry, To apply a new pouch, the client should be certain there is a good seal around the stoma. A leak under the skin barrier should not be fixed. The pouch should be removed to avoid skin irritation. The client should release gas in the pouch and empty the pouch before it is half-full. If the client has a lot of gas, they may want to consider use of a pouch with a vent or filter."}, {"id": 10235, "cat": "INTEGUEMENT", "stem": "A nurse is collecting data from an adolescent who has scabies. In which of the following locations should the nurse expect to find the lesions?", "choices": [{"id": "a", "t": "Hair shaft O s.Thigh"}, {"id": "c", "t": "Popliteal folds © D.Nailbeds"}], "correct": "c", "rationale": "A Hi 11% Moderate Scabies occurs between the fingers and in the axillary-cubital area, popliteal folds, and inguinal area. The lesions are itchy and appear as B | Aor brownish burrows under the skin.", "whyNot": {"a": "Scabies occurs between the fingers and in the axillary-cubital area, popliteal folds, and inguinal area."}, "keyConcept": "Children who have scabies, lice, or bedbugs might feel stigmatized and worry that they will be labeled as \"dirty.\" It is important to reinforce the fact that these infections can occur despite the location of where a child lives. Caution should be taken to protect the privacy of these children."}, {"id": 10236, "cat": "INTEGUEMENT", "stem": "While performing daily peritoneal dialysis and catheter exit site care with the mother of a child with chronic renal failure, the importance of which of the following is most important to emphasize to the mother?", "choices": [{"id": "a", "t": "Applying the occlusive dressing after cleaning the site"}, {"id": "b", "t": "Changing the dressing when the peritoneal space is dry"}, {"id": "c", "t": "Examining the area while cleaning it for any sign of infection"}, {"id": "d", "t": "Pulling on the catheter to hold it taut while cleaning the skin"}], "correct": "c", "rationale": "al 4% Easy The catheter exit area is vulnerable to infection and should be monitored for signs of infection. a | Dan", "whyNot": {"a": "An occlusive dressing is not needed because there is no danger of air being sucked in or out of the peritoneal space. The catheter is", "b": "Site care may be done any time but the child may experience abdominal pain if the peritoneal space is dry during site care.", "d": "Holding the catheter taut or pulling on it may cause irritation of the skin exit site and lead to infection."}, "keyConcept": "Catheter-related infection is a common complication of peritoneal dialysis (PD). It can lead to peritonitis and exit-site infections, permanent loss of the catheter, and transfer to hemodialysis. The primary goal of exit-site care is to prevent infection. After catheter implantation, the exit site should be covered with several layers of sterile gauze. Gauze dressings are preferred because they pull drainage away from the exit site. A client on chronic PD should monitor the exit site and perform routine care to prevent catheter infections. The nurse should provide client education that includes information about how to assess the exit site, including visual inspection and palpation of the tunnel, recognizing signs and symptoms of exit-site infection, and when to notify the provider of problems."}, {"id": 10237, "cat": "INTEGUEMENT", "stem": "A nurse is caring for a school age child who has a major burn and is experiencing severe pain. Which of the following actions should the nurse implement to manage this client's pain?", "choices": [{"id": "a", "t": "Administer morphine sulfate IV via continuous infusion."}, {"id": "b", "t": "Administer meperidine IV around the clock as needed."}, {"id": "c", "t": "Administer acetaminophen PO every 4 hr."}, {"id": "d", "t": "Administer hydrocodone PO every 6 hr."}], "correct": "a", "rationale": "o; Opioids administered IV via continuous infusion are recommended for clients who have major burns, regardless of age. om", "whyNot": {"b": "Meperidine is contraindicated for use in children. It can cause seizures, tremors, and myoclonus. D |", "c": "Oral acetaminophen is recommended for clients who have minor burns.", "d": "IV opioid medications are recommended for clients who have major burns."}, "keyConcept": "If continuous narcotic infusions are used for more than 3 days, children should be weaned from the medication slowly. It is also important for the nurse to be aware that children do not always express their pain in the same way as adults do. Children may display pain through behaviors such as anxiety, fear, anger, aggression, agitation, depression, tantrums, regression, and withdrawal."}, {"id": 10238, "cat": "INTEGUEMENT", "stem": "indicated? O A. 19-year-old client with tuberculosis O B. 5-year-old client diagnosed with acute bronchitis O C. 43-year-old client who has MRSA O D. 25-year-old client with community-acquired bacterial pneumonia", "choices": [{"id": "a", "t": "19-year-old client with tuberculosis"}, {"id": "b", "t": "5-year-old client diagnosed with acute bronchitis"}, {"id": "c", "t": "43-year-old client who has MRSA"}, {"id": "d", "t": "25-year-old client with community-acquired bacterial pneumonia"}], "correct": "c", "rationale": "A nurse is expected to understand and apply different types of isolation precautions to prevent the spread of infectious pathogenic microorganisms. Contact precautions, in addition to standard precautions, are indicated for clients who are diagnosed or suspected to be infected by select organisms that are transmitted through direct or indirect contact with the individual. Conditions that may indicate contact precaution include Clostridium difficile colitis, methicillin-resistant Staphylococcus aureus (MRSA), and vancomycin-resistant enterococcus (VRE) infections. A nurse caring for a client with MRSA should institute contact precautions to avoid transmission of this multi-drug-resistant pathogen to others in the healthcare facility.", "whyNot": {"a": "A nurse caring for clients who are diagnosed with serious respiratory infections transmitted through the airborne spray of infectious", "b": "Clients with acute bronchitis usually require only standard precautions.", "d": "Clients with community-acquired bacterial pneumonia require standard precautions. They are likely to be infected by Streptococcus"}, "keyConcept": "Select infections by virulent drug-resistant organisms transmitted through direct or indirect contact require contact precautions in addition to standard precautions. A single-client room is preferred for clients who require contact precautions. In multi-client rooms, 23 feet spatial separation between beds is recommended. Healthcare personnel caring for clients on contact precautions should wear a gown and gloves for all interactions that may involve contact with the client or potentially contaminated areas in the client's environment. PPE should be donned upon room entry and discarded before exiting the client room, in order to contain pathogens."}, {"id": 10239, "cat": "INTEGUEMENT", "stem": "A nurse is planning care for a child who has tinea pedis. Which of the following actions should the nurse include in the plan of care?", "choices": [{"id": "a", "t": "Treat infected house pets."}, {"id": "b", "t": "Use selenium sulfide shampoo."}, {"id": "c", "t": "Apply a topical antifungal cream."}, {"id": "d", "t": "Use moist, warm compresses."}], "correct": "c", "rationale": ". Tinea pedis is also known as “athlete's foot\" and refers B | Aer to a dermatophyte infection of the feet that results in distinctive scaling and thickening of the soles, intertriginous erythema and scaling, vesicular lesions, bullae, and ulcerations. ec | 17% my | 3% Tips to prevent tinea pedis: Wear sandals in community showers or locker rooms. Wear clean, light socks. Wear shoes that have adequate ventilation. Keep feet clean and dry.", "whyNot": {"a": "Tinea capitis can be transmitted from household pets, especially cats, but it is a rare source of infection. Pets should be examined and", "b": "Selenium sulfide shampoo is recommended for children who have tinea capitis. Tinea capitis is a fungal infection of the scalp.", "d": "The skin should be kept dry in children with tinea pedis. Drying agents may be recommended."}, "keyConcept": "Treatment for tinea pedis includes topical and oral antifungal agents, drying agents, and moisture reduction. The nurse should instruct adolescents and young adults to wear flips flops when they shower in dorms at school or camps. Flip flops should be cleaned after each use."}, {"id": 10240, "cat": "INTEGUEMENT", "stem": "A nurse is providing teaching to the parents of 7-year-old client with impetigo about care of the lesions. Which of the following instructions should the nurse relay to these parents?", "choices": [{"id": "a", "t": "Apply over-the-counter antibiotic ointment to the crusted lesions"}, {"id": "b", "t": "Wash the lesions using hydrogen peroxide"}, {"id": "c", "t": "The child should not return to daycare for a week after treatment is initiated."}, {"id": "d", "t": "Soak the scabs in warm saline"}], "correct": "d", "rationale": "sia 29% Hard Impetigo is an infectious disease of the skin caused by either staphylococcus or streptococcus bacteria. It is characterized by pus-filled sores B a surrounded by reddened skin. Impetigo commonly affects the face, neck, arms, and legs. It is often seen in young children. If a sore erupts, a thick, honey-colored crust is formed. The nurse should teach the parents to soak scabs and crusts in warm saline solution. The crusts should c | 40% be removed with gloved hands before applying prescribed topical antibiotics. @D | | 27%", "whyNot": {"a": "The crusts of the scores should be removed before applying a prescribed topical ointment.", "b": "Hydrogen peroxide may promote further inflammation in the areas surrounding the sores.", "c": "The child should stay at home for 24 hours after treatment is initiated. Impetigo is highly contagious. Towels used by the child should be"}, "keyConcept": "Impetigo is a highly contagious superficial skin infection caused by Staphylococcus aureus or Streptococcus pyogenes. It generally appears on the arms, legs, or face, with formation of honey-colored or golden-crusted lesions from dried serum. Local care and a topical antibiotic are usually adequate for treatment, although a systemic antibiotic may be required."}, {"id": 10241, "cat": "INTEGUEMENT", "stem": "A nurse is providing discharge instructions to a client who had a skin biopsy and has sutures in place. Which of the following client statements should indicate to the nurse that the teaching was effective? O A.\"I.can expect redness around the site for 5 days.\" O B. \"I will most likely have a fever for the first few days.\" O C. \"I should apply an antibiotic ointment to the area.\" O D. \"I will make a return appointment in 2 days for removal of my sutures.\"", "choices": [{"id": "a", "t": "The client should report redness, pain, drainage, or warmth at the biopsy site to the provider as indications of possible infection."}, {"id": "b", "t": "A fever is an indication of an infection, and the provider should be notified."}, {"id": "c", "t": "Antibiotic ointment is applied as prescribed by the provider to prevent infection."}, {"id": "d", "t": "Removal of the sutures following a biopsy is completed 7 to 10 days after the procedure."}], "correct": "c", "rationale": "Antibiotic ointment is applied as prescribed by the provider to prevent infection. B | a0", "whyNot": {"a": "The client should report redness, pain, drainage, or warmth at the biopsy site to the provider as indications of possible infection.", "b": "A fever is an indication of an infection, and the provider should be notified.", "d": "Removal of the sutures following a biopsy is completed 7 to 10 days after the procedure."}, "keyConcept": "The nurse should instruct a client who has sutures following a biopsy that the provider can prescribe a topical antibiotic ointment to prevent infection. The client should report a fever because it can indicate an infection. If the client notices redness, pain, drainage, or warmth at the biopsy site, the provider should be notified. Sutures following a biopsy are removed 7 to 10 days after the procedure."}, {"id": 10242, "cat": "INTEGUEMENT", "stem": "Which of the following lifestyle factors may have the largest impact on the development of foot wounds in a diabetic?", "choices": [{"id": "a", "t": "Caffeine intake"}, {"id": "b", "t": "Smoking"}, {"id": "c", "t": "Decreased intake of potassium"}, {"id": "d", "t": "exercise"}], "correct": "b", "rationale": "| 2% Easy A client with diabetes is at higher risk of developing poorly healing foot wounds because of impaired circulation to the lower extremities and OB rsd omar loss of sensation due to diabetic neuropathy. If the client also smokes, circulation can be further impaired because cigarette smoke reduces the amount of oxygen in the bloodstream and results in peripheral vasoconstriction. This contributes to skin breakdown and poor wound c | 3% healing.", "whyNot": {"a": "Caffeine intake typically does not affect whether a diabetic client is prone to developing foot wounds.", "c": "Decreased potassium intake does not have an impact on wound development in a client with diabetes.", "d": "Moderate exercise would more likely improve circulation, rather than contribute to wound development in a client with diabetes."}, "keyConcept": "Diabetic foot ulcers result from various factors that occur with greater frequency in clients with diabetes, including include changes in the bony architecture of the foot, peripheral neuropathy, and atherosclerotic peripheral arterial disease. Neuropathy is the largest contributing factor in the development of diabetic foot ulcers, resulting in the loss of protective sensation. Diabetic clients may remain unaware of injuries to the foot, so frequent inspection of the feet is essential."}, {"id": 10243, "cat": "INTEGUEMENT", "stem": "A nurse is reviewing the plan of care for an infant who has diaper dermatitis. Which of the following interventions should the nurse expect to be included in the plan of care?", "choices": [{"id": "a", "t": "Apply talcum powder with every diaper change."}, {"id": "b", "t": "Allow the buttocks to air dry."}, {"id": "c", "t": "Use cloth diapers until the rash is gone."}, {"id": "d", "t": "Use a hair dryer on the lowest setting to dry the skin."}], "correct": "b", "rationale": "‘i Allowing the buttocks to air dry facilitates thorough drying of the skin. OR a", "whyNot": {"a": "Talcum powder can cake and cause inhalation injury. It should not be used for infants who have diaper dermatitis. D |", "c": "Superabsorbent diapers should be used for infants who have diaper dermatitis to assist in keeping the skin dry.", "d": "Hairdryers are not recommended because they can cause further irritation or burns."}, "keyConcept": "Although superabsorbent diapers are recommended, the nurse should instruct caregivers to change diapers as soon as soiling occurs, even though the diaper might not feel \"full.\""}, {"id": 10244, "cat": "INTEGUEMENT", "stem": "A nurse is providing teaching for a client who has psoriasis and is to receive photochemotherapy and ultraviolet light (PUVA) therapy. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Avoid crowds and sick individuals throughout the treatment regimen."}, {"id": "b", "t": "Take a psoralen medication 2 hr before the scheduled light treatment."}, {"id": "c", "t": "This treatment will occur daily for several weeks."}, {"id": "d", "t": "Do not consume alcohol while undergoing this treatment regimen."}], "correct": "b", "rationale": "PUVA treatment involves the ingestion of a psoralen photosensitizing medication2 hr prior to the schedule exposure to ultraviolet A light. This time frame allows for skin exposure when the psoralen photosensitizing medication is at peak effectiveness. The light causes a change in the DNA of the epidermal cells and decreases replication.", "whyNot": {"a": "This intervention is appropriate for clients who are receiving treatment for psoriasis with biologic agents such as etanercept, infliximab,", "c": "PUVA treatments are completed two to three times each week, not on consecutive days. If the client develops redness or edema of the", "d": "Alcohol consumption should be avoided when clients are treating psoriasis with systemic medications such as methotrexate or acitretin."}, "keyConcept": "Psoriasis is an autoimmune disorder that causes scaled skin lesions due to an overgrowth of epidermal cells. PUVA treatments are indicated for clients who have moderate to severe active psoriasis that is not responding to other treatments. The client is instructed to ingest a medication that increases photosensitivity 2 hr before the scheduled exposure to an ultraviolet A light source. This timing allows for light exposure during the peak photosensitive period. Clients should be instructed to wear dark glasses during the treatment and for the remainder of the day. Treatment sessions occur two to three times per week, but not on consecutive days. The client's skin should be monitored for any indications of redness or edema, and the treatment should be delayed if those are present."}, {"id": 10245, "cat": "INTEGUEMENT", "stem": "A nurse is preparing to initiate IV therapy on a client. Which of the following solutions should the nurse identify as the best choice for preparing the client's skin at the insertion site?", "choices": [{"id": "a", "t": "lsopropyl alcohol"}, {"id": "b", "t": "Chlorhexidine"}, {"id": "c", "t": "Soap and water"}, {"id": "d", "t": "Povidone-iodine"}], "correct": "b", "rationale": "A nurse who is responsible for initiating IV therapy should be able to identify the antiseptic of choice for preparing the IV insertion site. The nurse should gather this and all necessary supplies prior to going to the client's room. Other supplies needed can include: + Infusion set + Sterile parenteral solution «IV pole or infusion pump + Nonallergenic tape Clean gloves + Tourniquet + IV catheter « Sterile gauze", "whyNot": {"a": "The nurse can use isopropyl alcohol to prepare the client’s skin prior to initiating lV therapy; however, evidence-based practices indicates", "c": "The nurse can use soap and water to cleanse the client’s skin prior to initiating IV therapy; however, evidence-based practices indicates", "d": "The nurse can use povidone-iodine to prepare the client’s skin prior to initiating IV therapy; however, evidence-based practices indicates"}, "keyConcept": "A nurse who is responsible for initiating IV therapy should be able to identify the antiseptic of choice for preparing the IV insertion site. The nurse should gather this and all necessary supplies prior to going to the client's room. Other supplies needed can include: + Infusion set + Sterile parenteral solution «IV pole or infusion pump + Nonallergenic tape Clean gloves + Tourniquet + IV catheter « Sterile gauze"}, {"id": 10246, "cat": "INTEGUEMENT", "stem": "A nurse is caring for an adolescent who has a superficial partial-thickness burn to the thigh. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Prepare the adolescent for transport to a burn facility."}, {"id": "b", "t": "Cleanse the affected area with tepid water."}, {"id": "c", "t": "Scrub the affected area using a soft-bristle brush."}, {"id": "d", "t": "Administer morphine sulfate."}], "correct": "b", "rationale": "< Management of Minor Burns Clean with mild soap and tepid water. Remove any debris from the wound. Gently remove dead skin. Apply antibacterial ointment to the Place a sterile dressing over the wound. affected area Ensure tetanus prophylaxis is up to date", "whyNot": {"a": "Minor burns do not require treatment at a burn center. They can be can be treated and managed in an outpatient setting. D | | 37%", "c": "Gentle cleansing with tepid water is recommended for a superficial partial-thickness burn. iii]", "d": "Morphine sulfate is indicated for clients who have sustained moderate to major burns. 2"}, "keyConcept": "< Management of Minor Burns Clean with mild soap and tepid water. Remove any debris from the wound. Gently remove dead skin. Apply antibacterial ointment to the Place a sterile dressing over the wound. affected area Ensure tetanus prophylaxis is up to date"}, {"id": 10247, "cat": "INTEGUEMENT", "stem": "priority to report to the provider? O", "choices": [{"id": "a", "t": "Dry skin"}, {"id": "b", "t": "Headache"}, {"id": "c", "t": "Decreased night vision"}, {"id": "d", "t": "Feelings of isolation"}], "correct": "d", "rationale": "All 11% Hard When using the urgent vs. nonurgent approach to client care, the nurse should identify that the priority finding is the adverse effect of mood B | see changes, such as feelings of isolation, which can indicate depressive behavior leading to self-harm or suicide. Therefore, feels of isolation is the priority for the adolescent to report to the provider. c |_| 19%", "whyNot": {"a": "Dry skin is a nonurgent finding because it is an expected adverse effect of the medication due to a decrease of the sebaceous gland size", "b": "A headache is a nonurgent finding because it is an expected adverse effect of the medication due to a benign elevation of intracranial", "c": "Decreased night vision is a nonurgent finding because it is an expected adverse effect of the medication due to a rare response that can"}, "keyConcept": "Isotretinoin is an effective oral medication that is used for the treatment of severe cystic acne that has not responded to other medications. Isotretinoin is the only medication available that affects specific aspects involved in acne development. Adolescents who have many cystic and nodular lesions are usually treated with the medication for a maximum of 20 weeks and should be monitored closely by a dermatologist during this time."}, {"id": 10248, "cat": "INTEGUEMENT", "stem": "may indicate a wound infection? O A. Serous drainage from the incision O B. Increased fatigue when performing daily activities. O C. Warmth and erythema at the wound site O D. Pink skin at the incision", "choices": [{"id": "a", "t": "Serous drainage from the incision"}, {"id": "b", "t": "Increased fatigue when performing daily activities."}, {"id": "c", "t": "Warmth and erythema at the wound site"}, {"id": "d", "t": "Pink skin at the incision"}], "correct": "c", "rationale": "Surgical site infections occur in 1-3% of individuals who have undergone a surgical procedure. They typically occur within 30 days of surgery. Signs of surgical site infection include pus or malodorous drainage, warmth, edema, erythema, pain or tenderness, fever, and chills.", "whyNot": {"a": "Asmall amount of serous drainage from the incision is a common occurrence and not a sign of infection.", "b": "It is to be expected that the client will have increased fatigue within a few days of a surgical procedure.", "d": "Pink skin at the incision is normal as the wound heals."}, "keyConcept": "Risk factors for surgical site infection include poorly controlled diabetes, compromised immune system, obesity, smoking, use of corticosteroids, and prolonged surgical procedures. Wound contamination is also associated with risk. Superficial surgical site infections are limited to the skin in the area of incision. Deep infections extend to muscles and other tissues. Organ infections can result in drainage of pus through a wound drain. Treatments for surgical site infection include antibiotics, debridement, and surgical interventions."}, {"id": 10249, "cat": "INTEGUEMENT", "stem": "A nurse is assessing a client who has a stage 2 pressure ulcer. The nurse should expect which of the following findings?", "choices": [{"id": "a", "t": "Exposed bone"}, {"id": "b", "t": "Nonblanchable erythema"}, {"id": "c", "t": "Partial-thickness skin loss"}, {"id": "d", "t": "Necrotic subcutaneous tissue"}], "correct": "c", "rationale": "A The nurse should expect to find manifestations of a stage 2 pressure ulcer, which can include partial-thickness skin loss and a superficial B Hl ulcer. o: of", "whyNot": {"a": "Manifestations of a stage 4 pressure ulcer can include full-thickness skin loss with exposed or palpable bone or muscle.", "b": "Manifestations of a stage 1 pressure ulcer can include nonblanchable, reddened, intact skin and blood-filled blisters.", "d": "Manifestations of a stage 3 pressure ulcer can include full-thickness skin loss with necrotic subcutaneous tissue."}, "keyConcept": "A nurse assessing a client who has a pressure ulcer should be able to identify the stage of the ulcer based on the manifestations. The nurse should identify each of the 4 stages as shown below."}, {"id": 10250, "cat": "INTEGUEMENT", "stem": "A nurse is teaching the parent of a 2-month-old infant who has seborrheic dermatitis of the scalp. Which of the following instructions should the nurse include in the teaching? O A.\"You can use petrolatum to help soften and remove patches from your infant's scalp.\" O B. \"When patches are present, you should keep your infant away from others.\" O C. \"You should avoid brushing your infant's scalp until the fontanelles have closed.\" O D. \"When patches are present, it indicates that your infant has a systemic infection.\"", "choices": [{"id": "a", "t": "o; The nurse should recommend that the parent use petrolatum, vegetable oil, or mineral oil to help soften and remove scales and crusted B i areas."}, {"id": "b", "t": "The nurse should inform the parent that seborrheic dermatitis is not contagious, so it is not necessary to keep the infant away from others."}, {"id": "c", "t": "Regardless of whether the fontanelles are open or closed, washing, brushing, and combing the scalp will not injure the infant. Brushing"}, {"id": "d", "t": "The nurse should inform the parent that the cause of seborrheic dermatitis is unknown and is not associated with a systemic infection."}], "correct": "a", "rationale": "o; The nurse should recommend that the parent use petrolatum, vegetable oil, or mineral oil to help soften and remove scales and crusted B i areas. An infant comb can be used after the scales are softened to help remove them. The scalp can then be cleaned with shampoo.", "whyNot": {"b": "The nurse should inform the parent that seborrheic dermatitis is not contagious, so it is not necessary to keep the infant away from others.", "c": "Regardless of whether the fontanelles are open or closed, washing, brushing, and combing the scalp will not injure the infant. Brushing", "d": "The nurse should inform the parent that the cause of seborrheic dermatitis is unknown and is not associated with a systemic infection."}, "keyConcept": "Softening and removing the scales can take some time, so infants should be dressed or wrapped in a warm towel to minimize heat loss during treatment."}, {"id": 10251, "cat": "INTEGUEMENT", "stem": "following is the most appropriate nursing action?", "choices": [{"id": "a", "t": "Report findings to the nurse supervisor"}, {"id": "b", "t": "Notify the surgeon"}, {"id": "c", "t": "Recognize normal findings and document"}, {"id": "d", "t": "Document findings as early signs of infection"}], "correct": "c", "rationale": "A nurse is responsible for monitoring clients who have just undergone surgery. Nursing postoperative responsibilities include assessing the client for hemorrhage or infection. Monitoring the surgical incision site for signs of infection can result in early treatment if infection occurs. On the first postoperative day, a nurse can expect the suture line to be slightly red, moist, and inflamed. This is an expected finding that represents the normal healing process.", "whyNot": {"a": "The nurse should not report normal findings to the nursing supervisor. It’s important for the nurse to recognize normal findings in the", "b": "It is unnecessary to notify the surgeon of a normal and expected postoperative finding.", "d": "Early signs of infection include reports of increased pain and warmth."}, "keyConcept": "Some swelling and slight redness is normal in the initial 24 hours after surgery, although the nurse should monitor the wound for signs of surgical site infection. Surgical site infections (SSI) occur within 30 days of surgery. The risk of developing SSI is about 1% to 3%. Signs include redness, delayed healing, fever, pain, tenderness, warmth, swelling, and pus."}, {"id": 10252, "cat": "INTEGUEMENT", "stem": "Which type of wound would most likely heal by primary intention?", "choices": [{"id": "a", "t": "Awound with a low risk of infection"}, {"id": "b", "t": "Awound that has a long healing time"}, {"id": "c", "t": "Awound with excessive drainage"}, {"id": "d", "t": "A wound that would be closed later"}], "correct": "a", "rationale": "Primary intention refers to wounds closed by close approximation of wound edges, with subsequent healing of the wound or incision. The B I a most common type of primary intention is surgical closure. c | 3%", "whyNot": {"b": "Awound with a long healing time is not an example of closure by primary intention.", "c": "Awound with excessive drainage is not a type of wound that would successfully be closed by primary intention.", "d": "Leaving a wound to be closed later is not an example of primary intention."}, "keyConcept": "Healing by primary intention is characterized by approximation of wound edges by sutures, staples or glue. Healing by secondary intention refers to healing when the wound edges cannot be approximated and the wound heals from the deeper layers outward. Tertiary intention refers to a combination of primary and secondary intention: the wound cannot be stitched up immediately but after healing begins, the edges may be approximated."}], "leadership": [{"id": 10253, "cat": "LEADERSHIP", "stem": "A nurse manager is planning an in-service about conflict management for the nurses on the unit. Which of the following situations should the nurse manager include as an example of interpersonal conflict?", "choices": [{"id": "a", "t": "Nurses on the unit disagree about the time of day that daily client weights should be obtained."}, {"id": "b", "t": "A nurse is uncertain about joining a professional nursing organization."}, {"id": "c", "t": "Nurses on the unit voice their concern at the budget cuts implemented by the administration."}, {"id": "d", "t": "An experienced nurse is uncivil to a newly licensed nurse."}], "correct": "d", "rationale": "A Hl 20% Moderate Conflict that occurs between two or more individuals is interpersonal conflict. This type of conflict can disrupt the function and productivity B | see of the unit and, in extreme cases, can become a client safety issue. Incivility and bullying are examples of interpersonal conflict.", "whyNot": {"a": "Conflict can result from differences in ideas, values, and perceptions. One type of conflict is intergroup conflict in which two or more", "b": "Intrapersonal conflict is a type of conflict in which the individual struggles internally with contradictory values or perceived wants and", "c": "Unchecked conflict can develop into an \"us versus them\" mentality. This can occur when differences in perceived values between two"}, "keyConcept": "In order for the nurse to manage conflict, an understanding of the origin of the conflict is needed. Common causes of conflict on a nursing unit include poor communication; differences in age, gender, experience, or culture; unclear expectations between members of the unit; and individual or group conflicts of interest. Results of conflict include increased workplace stress, decreased trust between members of the unit, and a decrease in productivity. The breakdown in communication that can occur as a result of conflict also places clients' safety at risk; therefore, understanding and managing conflict are important skills for the nurse to develop."}, {"id": 10254, "cat": "LEADERSHIP", "stem": "A nurse is planning to delegate tasks to a licensed practical nurse (LPN). Which of the following tasks should the nurse assign to the LPN?", "choices": [{"id": "a", "t": "Develop the plan of care for a client who has an amputation."}, {"id": "b", "t": "Obtain informed consent for a client scheduled for ostomy creation."}, {"id": "c", "t": "Access an implanted vascular access device."}, {"id": "d", "t": "Change the negative pressure wound therapy dressing on a client's chronic wound."}], "correct": "d", "rationale": "| 2% Easy The nurse should consider the five rights of delegation when evaluating a task for delegation to the LPN. The completion of a dressing B | a change is within the skill set and the scope of practice of an LPN and can be safely delegated if the LPN is familiar with the task and the client's condition is stable. c i ™%", "whyNot": {"a": "The nurse should not ask the LPN to plan client care or discharge regimen. However, the LPN can contribute to the development of the", "b": "The nurse should recognize that the provider is required to provide informed consent for a client. The nurse can ask the LPN to check that", "c": "Accessing an implanted vascular access device requires special techniques and precautions to ensure asepsis and patency. It is outside"}, "keyConcept": "Many factors are involved in the determination of the appropriateness of task delegation to members of the healthcare team. These include the clinical context, such as the availability of resources and the availability of the LPN's time to complete the task; personnel considerations, such as the scope of practice and skill competencies of the LPN; the client's needs and complexity of care involved; and the legal and professional responsibilities of both the LPN and the RN who is delegating the task."}, {"id": 10255, "cat": "LEADERSHIP", "stem": "A nurse accuses a newly licensed nurse of providing inadequate care for a client who underwent hip arthroplasty. Which of the following responses by the newly licensed nurse demonstrates assertiveness? O A.\"| feel as though | met the standard of care. Would you tell me more about your concerns?\" O B. \"You shouldn't make accusations. Your nursing care doesn't always set a good example.\" O C. \"lam sorry you are displeased. | always do my best to give good care to my clients.\" O D. \"Yes, you might be right. | haven't had the best role models since | started this position.\"", "choices": [{"id": "a", "t": "Communicating assertively is expressing thoughts in an open, honest, and direct manner that demonstrates respect for self and others."}, {"id": "b", "t": "Aggressive communication involves direct or threatening responses, which can escalate conflict and prevent effective communication. It"}, {"id": "c", "t": "Passive communication is an attempt to avoid confrontation at costs. Individual who use passive communication techniques are at"}, {"id": "d", "t": "Passive-aggressive communication involves manipulation of the situation so that the individual receiving the criticism appears to"}], "correct": "a", "rationale": "Communicating assertively is expressing thoughts in an open, honest, and direct manner that demonstrates respect for self and others. The B | 3\" use of \"I\" statements, maintaining eye contact, and congruent verbal and facial expressions are all components of assertiveness skills. The nurse demonstrates respect for the opinion of the other nurse by asking for feedback and the reason for the concerns. c | 8% p | 1%", "whyNot": {"b": "Aggressive communication involves direct or threatening responses, which can escalate conflict and prevent effective communication. It", "c": "Passive communication is an attempt to avoid confrontation at all costs. Individual who use passive communication techniques are at", "d": "Passive-aggressive communication involves manipulation of the situation so that the individual receiving the criticism appears to"}, "keyConcept": "Assertive communication techniques allow for the expression of thoughts in a direct manner while respecting the other individual's viewpoints. This technique promotes problem-solving and effective communication. Assertive communication is a highly developed skill that requires self-confidence."}, {"id": 10256, "cat": "LEADERSHIP", "stem": "An Orthodox Jewish client refuses a new prescription for omeprazole capsules for GERD. Which of the following actions is most appropriate for the nurse?", "choices": [{"id": "a", "t": "Advise the client to sprinkle the contents of the capsule on food when using it."}, {"id": "b", "t": "Consult the healthcare provider for a new medication."}, {"id": "c", "t": "Tell the client that failure to treat GERD may result in significant negative health consequences."}, {"id": "d", "t": "Ask the pharmacist if another form of the medication is available."}], "correct": "d", "rationale": ", a nonkosher substance that some Orthodox Jewish clients may refuse as B rd sen unacceptable. In cases where another form of the medication is unavailable, it may be appropriate to consult with the client’s rabbi to determine whether or not the dietary restrictions may be relaxed for the client. c |_| 15%", "whyNot": {"a": "This does not answer the client’s concern about the animal collagen contents of the capsule.", "b": "The nurse should first check with the pharmacist to determine whether or not another form of the medication is available.", "c": "This response does not solve the problem at hand concerning treatment of the client’s healthcare problem."}, "keyConcept": "Capsule medications are usually coated in collagen from animals. This is a non-kosher substance, so some Orthodox Jewish clients may refuse capsule medications as unacceptable. If this occurs, the nurse should attempt to accommodate the client's needs by asking the pharmacist for another form of the medication or by consulting the rabbi if another form of the medication is unavailable."}, {"id": 10257, "cat": "LEADERSHIP", "stem": "A nurse manager is planning strategies to overcome resistance among unit nurses for a proactive policy change. Which of the following interventions should the nurse include?", "choices": [{"id": "a", "t": "Emphasize that future revisions to the policy change are not an option."}, {"id": "b", "t": "Openly discuss the reason for the change."}, {"id": "c", "t": "Avoid redirecting the resistance of the nursing staff until opposition is resolved."}, {"id": "d", "t": "Emphasize the reason for the change rather than the benefits of the change."}], "correct": "b", "rationale": "Change within a workplace environment can create instability and conflict because it alters the balance of the work group. Change can be either proactive change or mandated change. The type of change implemented will often determine the level of resistance, and proactive change generally encounters less resistance than mandated change. Other factors also impact the amount of resistance; for example, less resistance occurs with technological change or when an entire group is required to make a change. It is the nurse manager's responsibility to identify and implement strategies to minimize or manage resistance to change. The nurse manager should encourage the nursing staff to speak openly about the change. The nurse manager should also listen to the objections about the change with an open mind to effectively address the resistance. Another strategy is for the nurse manager to share the positive aspects of the change and to share the vision for the future once the change is implemented. These strategies emphasize the positive consequences of the change and how it will benefit the clients and staff, rather than focusing on the reason for the change.", "whyNot": {"a": "The nurse manager should remain open to discuss revisions of the policy change with the unit nurses, but the nurse manager should", "c": "The nurse manager should divert the nursing staff's energy by creating a different focus to a larger problem within the organization, which", "d": "The charge nurse should focus on the benefits of the change rather than focusing on the reasons for the change. The nurse should share"}, "keyConcept": "Change within a workplace environment can create instability and conflict because it alters the balance of the work group. Change can be either proactive change or mandated change. The type of change implemented will often determine the level of resistance, and proactive change generally encounters less resistance than mandated change. Other factors also impact the amount of resistance; for example, less resistance occurs with technological change or when an entire group is required to make a change. It is the nurse manager's responsibility to identify and implement strategies to minimize or manage resistance to change. The nurse manager should encourage the nursing staff to speak openly about the change. The nurse manager should also listen to the objections about the change with an open mind to effectively address the resistance. Another strategy is for the nurse manager to share the positive aspects of the change and to share the vision for the future once the change is implemented. These strategies emphasize the positive consequences of the change and how it will benefit the clients and staff, rather than focusing on the reason for the change."}, {"id": 10258, "cat": "LEADERSHIP", "stem": "Acharge nurse is delegating tasks to nursing personnel on a ten-bed dementia care unit. Which of the following assignments is an example of overdelegation?", "choices": [{"id": "a", "t": "Assigning two assistive personnel (AP) to ambulate each client on the unit"}, {"id": "b", "t": "Assigning a newly licensed nurse to perform a wet-to-dry dressing change"}, {"id": "c", "t": "Assigning one AP to feed each client on the unit"}, {"id": "d", "t": "Assigning an experienced RN to perform a central line dressing change"}], "correct": "c", "rationale": "A Hl 21% Moderate Overdelegation is an act that places undue burden on a member of the health care team. Although assisting with feeding is within the range B I a of function and skill level of an AP, assigning one AP to assist ten clients with their meals is unrealistic and an example of overdelegation.", "whyNot": {"a": "Overdelegating places a burden on the staff members who receive the task. Assigning two APs to ambulate ten clients follows the rights of", "b": "Assigning a newly licensed nurse to perform a wet-to-dry dressing change follows the rights of delegation and is an expected assignment A", "d": "Assigning an experienced RN to perform a central line dressing change follows the rights of delegation and is an expected assignment for q"}, "keyConcept": "Overdelegation can occur when workloads are consistently heavy or if staffing levels are inadequate to meet the client care needs. Overdelegation can also occur because of inadequate planning on the part of the nurse. Assigning more work to a nurse or an AP who has experience, compared to the workload of their peers, is another example of overdelegation. Overdelegation can result in burnout, a loss of productivity, and increases the risk for client injury or missed care."}, {"id": 10259, "cat": "LEADERSHIP", "stem": "Acharge nurse on a medical-surgical unit has just been notified that the disaster protocol is being implemented following a natural disaster. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Make a list of clients who can be discharged."}, {"id": "b", "t": "Reinforce discharge teaching to clients."}, {"id": "c", "t": "Instruct the assistive personnel (AP) to focus on clients' ADLs."}, {"id": "d", "t": "Stock additional unit supplies."}], "correct": "a", "rationale": "os Following the initiation of disaster protocol, the charge nurse should identify that clients who are stable can be discharged to allow clients B | a0 who are harmed by the disaster to be admitted. The charge nurse should make a list of potential client dismissals and work collaboratively with providers to obtain discharge prescriptions. c | 2% om 15% Clients Who Can Be Potentially Discharged Following a Disaster + Ambulatory clients who were admitted previously for observation + Ambulatory clients who admitted for undergoing diagnostic evaluation + Clients who are stable and can be cared for at home by family or support services", "whyNot": {"b": "In the event of a disaster, the nurse should focus on urgent client care. Discharge teaching should not be the nurse's focus at this time.", "c": "Following a disaster, care delivery focuses on meeting critical needs, which does not include having the AP assist clients with ADLs.", "d": "Following a disaster, ancillary personnel will stock additional unit supplies for nursing personnel. The nurse should focus on urgent client"}, "keyConcept": "The role of the nurse following a disaster can take many forms. The nurse might be required to provide care in the emergency department for clients who are stable. The overall goal in nursing care during a disaster is to provide essential care to the greatest number of people."}, {"id": 10260, "cat": "LEADERSHIP", "stem": "demonstrating? O A. Right circumstances O B. Right communication O C. Right task O D. Right supervision", "choices": [{"id": "a", "t": "Right circumstances"}, {"id": "b", "t": "Right communication"}, {"id": "c", "t": "Right task"}, {"id": "d", "t": "Right supervision"}], "correct": "d", "rationale": "When planning delegation, the nurse should consider the state Nurse Practice Act, the delegatee's job description and competencies, and the facility's policies and procedures. In addition to the rights of delegation, the nurse should also consider the standards of practice and the safety of the client and staff.", "whyNot": {"a": "The rights of delegation were developed by the American Nurses Association and the National Council of State Boards of Nursing to assist", "b": "The right communication includes providing clear explanations about the tasks, client outcomes, a time frame for completion of the task,", "c": "The right task involves taking into consideration the complexity of the task, the frequency of the task, and whether or not the task is"}, "keyConcept": "When planning delegation, the nurse should consider the state Nurse Practice Act, the delegatee's job description and competencies, and the facility's policies and procedures. In addition to the rights of delegation, the nurse should also consider the standards of practice and the safety of the client and staff."}, {"id": 10261, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who has right-sided paralysis following a stroke. Which of the following information should the nurse provide the occupational therapist who will be involved in the care of the client?", "choices": [{"id": "a", "t": "The client will need a ramp built at his home."}, {"id": "b", "t": "The client is experiencing difficulty swallowing liquids."}, {"id": "c", "t": "The client is right-hand dominant."}, {"id": "d", "t": "The client wishes to complete an advance directive."}], "correct": "c", "rationale": "The nurse should inform the occupational therapist (OT) that the client is right-hand dominant. The OT assists the client to become independent with activities of daily living, such as bathing, dressing, and grooming. A client who is right-hand dominant and is experiencing right-sided paralysis will require assistance and teaching about how to perform routine activities without the use of the dominant hand and arm.", "whyNot": {"a": "The nurse should inform the social worker of the client's need for a ramp built at his home. The social worker can assist the client with", "b": "The nurse should inform the speech-language pathologist (SLP) that the client is experiencing difficulty swallowing liquids. The SLP can", "d": "The nurse should inform the social worker that the client wishes to complete an advance directive. The social worker can assist the client"}, "keyConcept": "The nurse should serve as a resource person for the interdisciplinary team members by providing the necessary information for care to be consistent across the continuum. The nurse should relay the needs of the client, as well as pertinent client information, to the team to ensure quality client outcomes."}, {"id": 10262, "cat": "LEADERSHIP", "stem": "A nurse in a provider's office is reviewing the laboratory findings for a client who is receiving chemotherapy. The client has a platelet count of 60,000/mm3. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Provide the client with information about the treatment."}, {"id": "b", "t": "Discuss these findings with the provider."}, {"id": "c", "t": "Ask the client to return to the clinic for further laboratory tests."}, {"id": "d", "t": "Obtain a referral to a specialized provider."}], "correct": "b", "rationale": "al 5% Easy The greatest risk to this client is injury from bleeding due to a low platelet count. Therefore, first action the nurse should take is to notify the OB rsd SO client’s provider about this finding. ° cf 4%", "whyNot": {"a": "The nurse should provide the client information about the treatment for a low platelet count. However, the nurse should take another", "c": "The nurse should contact the client ask them to return to the clinic for further blood specimen drawing and ongoing treatment. However,", "d": "The nurse should obtain a referral for a hematologist once the provider has a plan of action and initiates prescriptions for care. However,"}, "keyConcept": "A follow-up plan is important for the nurse to perform when the priority is to report new client information to the provider. The provider can then implement the necessary prescriptions for treatment. A follow-up plan includes the client's need for ongoing treatment, screenings, and tests. Other follow-up plans include providing the client with information about the treatment, including the late or long-term effects of the treatment, referral to a specialized provider, and informative websites."}, {"id": 10263, "cat": "LEADERSHIP", "stem": "A nurse and an assistive personnel (AP) are providing care to a group of clients. The nurse should delegate assisting which of the following clients with their meal to the AP?", "choices": [{"id": "a", "t": "A client who has a lumbosacral spinal tumor"}, {"id": "b", "t": "A client who has Guillain-Barré syndrome"}, {"id": "c", "t": "A client who has amyotrophic lateral sclerosis (ALS)"}, {"id": "d", "t": "A client who receives enteral feedings through a nasogastric tube"}], "correct": "a", "rationale": "o; The nurse should consider the five rights of delegation when considering which tasks to assign to an AP. One of these rights is the right B ] circumstance. The nurse should identify that the client who has a lumbosacral spinal tumor can have limited mobility and require assistance with setting up their meal tray and opening containers. The client is stable and not at risk for aspiration. Therefore, the nurse should c || delegate meal assistance for this client to the AP. D |", "whyNot": {"b": "When delegating tasks to an AP, the nurse should consider the task to be delegated, the frequency with which the AP has completed the", "c": "The nurse should consider the right person to assist the client who has ALS with eating. A client who has ALS is at risk for aspiration during", "d": "The nurse should identify that administering an enteral feeding through a nasogastric tube requires assessment of the tube placement,"}, "keyConcept": "To delegate effectively, the nurse should know the client's needs and acuity level, the staff abilities and job description, and the complexity of the task to be delegated. If the task is appropriate for delegation, the nurse should provide clear communication regarding the task itself, the time frame within which the task should be completed, and the information to be reported back to the nurse. The nurse is also responsible for assessing the task's completion, the performance of the staff member, and providing feedback to the staff member based upon their job performance."}, {"id": 10264, "cat": "LEADERSHIP", "stem": "assume total care for a client rather than assigning tasks to the LPN? O A.\"The client has a chronic tracheostomy that requires suctioning.\" O B. \"The client's blood pressure and pulse have been fluctuating throughout the day.\" O C. \"The client discussed being depressed when the tracheostomy was first placed.\" O D. \"The client needs to have the ostomy appliance changed.\"", "choices": [{"id": "a", "t": "The RN should consider the state's Nurse Practice Act, facility policies, the skill level of the LPN, and the client's condition when delegating"}, {"id": "b", "t": "all 9% Easy The stability of a client's condition is a criterion to consider when delegating client care."}, {"id": "c", "t": "The RN should consider the client's current condition rather than the client's history when delegating tasks. The client's history of"}, {"id": "d", "t": "The RN should ensure the LPN has the skill level to complete the task of changing the ostomy appliance and has access to the needed"}], "correct": "b", "rationale": "all 9% Easy The stability of a client's condition is a criterion to consider when delegating client care. To promote client safety, the RN should delegate OB SY ope tasks for more stable clients to the LPN. The RN should assume total care for a client who is experiencing irregular vital signs. I ° © 5%", "whyNot": {"a": "The RN should consider the state's Nurse Practice Act, facility policies, the skill level of the LPN, and the client's condition when delegating", "c": "The RN should consider the client's current condition rather than the client's history when delegating tasks. The client's history of", "d": "The RN should ensure the LPN has the skill level to complete the task of changing the ostomy appliance and has access to the needed"}, "keyConcept": "The RN should consider the skill level and work load of the LPN when delegating tasks. She should communicate assignments clearly and be willing to support and assist the LPN if needed. The RN should remember that while tasks can be delegated, the RN is ultimately responsible for the care of the client."}, {"id": 10265, "cat": "LEADERSHIP", "stem": "A nurse is teaching a newly licensed nurse about actions to take to ensure the confidentiality of a client's computerized medical record. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "\"You can only share your password with the nurse manager.\""}, {"id": "b", "t": "\"Do not allow others to see client information on your computer screen.\""}, {"id": "c", "t": "\"Securely store computer-generated worksheets in your locker for the next day.\" O D.\"Once you have logged in, do not leave the computer unattended for more than 3 minutes.\""}], "correct": "b", "rationale": "In 2005, the HIPAA Security Rule became mandatory. The rule is enforced to protect the security of personal health information, including electronic information. It is the responsibility of information technology personnel to install a firewall to protect the server from unauthorized access. It is the nurse's responsibility to follow the rules and guidelines of the agency to protect client information.", "whyNot": {"a": "A nurse should not share a password with anyone, including the nurse manager or any other health team members.", "c": "A nurse should not store or keep any computer-generated worksheets. The nurse should shred all materials prior to leaving the facility or"}, "keyConcept": "In 2005, the HIPAA Security Rule became mandatory. The rule is enforced to protect the security of personal health information, including electronic information. It is the responsibility of information technology personnel to install a firewall to protect the server from unauthorized access. It is the nurse's responsibility to follow the rules and guidelines of the agency to protect client information."}, {"id": 10266, "cat": "LEADERSHIP", "stem": "A nurse is teaching a group of assistive personnel (AP) about performing hand hygiene. Which of the following statements should the nurse include in the teaching? O A.\"You should avoid wearing artificial nails.\" O B. \"You may wear your rings when washing your arms and hand.\" O C. \"You can grow your fingernails any length.\" O D. \"You can use your own personal hand lotion after washing your hands\"", "choices": [{"id": "a", "t": "o; 2x0 Short, natural nails harbor fewer micro-organisms that can be harmful to clients."}, {"id": "b", "t": "The nurse should include in the teaching for the AP to remove jewelry and rings to facilitate proper protocol for hand washing."}, {"id": "c", "t": "The nurse should instruct the AP to manicure natural fingernails to be short, because short natural nails harbor fewer micro-organisms"}, {"id": "d", "t": "The nurse should include in the teaching for the AP to use only the agency-approved hand lotions and dispensers following hand hygiene."}], "correct": "a", "rationale": "o; 2x0 Short, natural nails harbor fewer micro-organisms that can be harmful to clients. The CDC recommends health care workers avoid wearing B | 3\" artificial nails when caring for clients who are at risk for infection. Additionally, guidelines from the World Health Organization prohibit artificial nails for caregivers in every setting.", "whyNot": {"b": "The nurse should include in the teaching for the AP to remove jewelry and rings to facilitate proper protocol for hand washing.", "c": "The nurse should instruct the AP to manicure natural fingernails to be short, because short natural nails harbor fewer micro-organisms", "d": "The nurse should include in the teaching for the AP to use only the agency-approved hand lotions and dispensers following hand hygiene."}, "keyConcept": "A nurse who is teaching a group of assistive personnel (AP) is serving as a resource individual to staff members. As a resource individual, it is vital for the nurse to provide accurate information to the target audience. Good hand hygiene requires the AP to have an understanding of the purpose of the techniques. The goals of hand hygiene include decreasing micro-organism on the hands, lowering the risk for transmission of micro-organisms, and reducing cross-contamination between clients and oneself. Short, natural nails harbor fewer micro- organisms that can be harmful to clients. The CDC recommends health care workers avoid wearing artificial nails when caring for clients who are at risk for infection. Additionally, guidelines from the World Health Organization prohibit artificial nails for caregivers in every setting. Healthcare workers should limit the amount of jewelry worn and remove jewelry when performing hand hygiene. The nurse should include in the teaching for the AP to use only agency-approved hand lotions and dispensers following hand hygiene. Using personal lotions can cause breakdown of latex gloves and might make hand hygiene practice less effective. A personal dispenser can become contaminated with micro-organisms if refilled. All healthcare providers should follow identical protocol for hand hygiene and promote accountability."}, {"id": 10267, "cat": "LEADERSHIP", "stem": "A nurse is caring for a group of clients and is delegating an assistive personnel (AP) to obtain vital signs. Which of the following clients should the nurse assign to the AP?", "choices": [{"id": "a", "t": "A client who is 1 hr postoperative following a thyroidectomy"}, {"id": "b", "t": "A client who is experiencing a new onset of chest pain"}, {"id": "c", "t": "A client who is preoperative and scheduled for gastric bypass surgery"}, {"id": "d", "t": "A client who is newly admitted following a motor vehicle crash and has bruising to the abdomen"}], "correct": "c", "rationale": "The client's physiologic status and stability are considerations when assigning an AP to collect vital signs. There is no indication that this preoperative client is unstable; therefore, the nurse can assign an AP to take vital signs for this client.", "whyNot": {"a": "Clients who are postoperative following a thyroidectomy are at risk for complications, such as hypocalcemia, hemorrhage, respiratory", "b": "The client who is experiencing a new onset of chest pain should be fully assessed by an RN, including vital signs. This client is considered", "d": "The client who experienced abdominal trauma and has bruising to the abdomen might have damage to the internal organs or might be"}, "keyConcept": "Delegation is a complex task that requires the nurse to evaluate multiple factors, including client needs and the clinical situation. Clients who are not physically stable should be assessed by an RN. Even if there is a moderate to a high risk that the client can develop complications or experience a change in status, the nurse should not delegate care tasks for the client, such as vital signs."}, {"id": 10268, "cat": "LEADERSHIP", "stem": "Acharge nurse hears a provider yelling at a staff nurse about the lack of supplies available to perform a procedure. Which of the following statements by the charge nurse is appropriate? O A.\"You should think about how you make others feel when you lose your temper.\" O B. \"I will help you with this procedure instead of the staff nurse.\" O C. \"It must be very frustrating when you don't have what you need to perform the procedure.\" O D.\"No one knew you were planning to perform a procedure. We cannot be blamed for not having the supplies needed.\"", "choices": [{"id": "a", "t": "The communication techniques used during conflict can either enable resolution or provoke further confrontation. This statement by the"}, {"id": "b", "t": "By using this approach, the charge nurse is avoiding the conflict. It is not effective, because it results in a lack of trust between the"}, {"id": "c", "t": "This statement by the charge nurse is an example of empathy, a therapeutic communication technique. The charge nurse is"}, {"id": "d", "t": "This statement by the charge nurse is an example of a defensive response. It is nontherapeutic and ignores the concerns of the provider"}], "correct": "c", "rationale": "C. This statement by the charge nurse is an example of empathy, a therapeutic communication technique. The charge nurse is acknowledging the provider's frustration, which can lead to resolution of the conflict.", "whyNot": {"a": "The communication techniques used during conflict can either enable resolution or provoke further confrontation. This statement by the", "b": "By using this approach, the charge nurse is avoiding the conflict. It is not effective, because it results in a lack of trust between the", "d": "This statement by the charge nurse is an example of a defensive response. It is nontherapeutic and ignores the concerns of the provider"}, "keyConcept": "The nurse should recognize that incivility is a component of workplace violence. Incivility includes a spectrum of behaviors from physical violence to eye-rolling, yelling, or disparaging comments. The nurse should implement facility policies that address workplace violence and identify tools that can be used to address disruptive behaviors when they occur."}, {"id": 10269, "cat": "LEADERSHIP", "stem": "A nurse is planning care for a client and needs to delegate some client care tasks to an assistive personnel (AP). Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Determine the AP's ability to read and understand the client's teaching plan."}, {"id": "b", "t": "Check the client’s record for advance directives."}, {"id": "c", "t": "Evaluate the ability of the AP to delegate to peers."}, {"id": "d", "t": "Provide a clear description of the task to the AP."}], "correct": "d", "rationale": "al 5% Easy Providing a clear, concise description of the task, as well as the objectives, expected outcomes, and the expectations for completion of the B | a0 work is essential when planning to delegate a task to the AP.", "whyNot": {"a": "The nurse cannot delegate teaching to an AP. Therefore, the nurse does not need to assess the AP's ability to understand a client's", "b": "The nurse does not need to check the client’s advance directives prior to delegating care tasks to an AP. However, it is important for the", "c": "The nurse should understand the principles and rights of delegation when assigning tasks to an AP. However, the AP cannot delegate tasks"}, "keyConcept": "There are several factors to consider when deciding about delegation to another member of the health care team. These include whether the task is within the scope of practice or range of function of the staff member as well as the facility's policies and procedures regarding the skill level and supervision required for the task. The nurse should also consider the staff member's skill and competency level in completing the task, the complexity of the task, and the workload of the staff member. Finally, the nurse should consider the safety of the client by answering the following questions: Is the client's condition stable? Has the nurse completed an assessment of the client? Is the plan of care for the client completed? Will the delegation of the task have a negative impact on the client's safety?"}, {"id": 10270, "cat": "LEADERSHIP", "stem": "A nurse manager is teaching a group of nurses about the civil judicial process. The nurse manager should include that witness depositions take place during which of the following steps?", "choices": [{"id": "a", "t": "Complaint step"}, {"id": "b", "t": "Discovery step"}, {"id": "c", "t": "Decision step"}, {"id": "d", "t": "Trial step"}], "correct": "b", "rationale": "The nurse manager should include in the teaching that the witnesses' depositions occur during the discovery step. The discovery step is when attorneys for the plaintiff and the defendant obtain relevant information about the case.", "whyNot": {"a": "During the complaint step, the plaintiff files a document alleging either the defendant failed to provide the expected level of safe care or", "c": "During the decision step, the judge provides a decision, or the jury issues a verdict.", "d": "During the trial step, both sides of the dispute are presented to the judge or jury."}, "keyConcept": "In a court of law, there are major steps followed to settle a dispute using the civil judicial process: © The first step includes the filing of a petition that outlines what the defendant failed to do or did to injure the plaintiff. When a client files a lawsuit against a nurse, the client is the plaintiff and the nurse is the defendant. © The second step includes the defendant writing a response in answer to the complaint, either admitting or denying the allegations in the petition. The plaintiff must then respond with supporting information for anything the defendant did not admit to. © The third step is the discovery phase, during which all the facts are gathered to support the plaintiff and defendant. These facts are obtained through the client's medical records, depositions, and interrogatories. Interrogatories are written questions asked and responded to under oath. Depositions are the questions asked to the opposing parties, other witnesses, and experts under oath to extract relevant and non-privileged information about the lawsuit. © The fourth step is the trial phase, which can last 1 to 3 years after the petition is filed. If the lawsuit is not settled out of court, a trial is scheduled and the relevant facts are presented to a judge or jury. © The final step is the decision phase when a judge provides a decision or a jury provides a verdict. If one party is not satisfied with the outcome, that party can file an appeal for another trial."}, {"id": 10271, "cat": "LEADERSHIP", "stem": "Acharge nurse is delegating activities to a volunteer assigned to the pediatric unit. The nurse should identify that which of the following assignments is inappropriate to delegate to a volunteer?", "choices": [{"id": "a", "t": "Transporting a school-age child who is in traction to another department"}, {"id": "b", "t": "Playing a video game with an adolescent who has sickle cell disease"}, {"id": "c", "t": "Reading a book to a preschool-age child who has AIDS"}, {"id": "d", "t": "Rocking an infant who was admitted for croup"}], "correct": "a", "rationale": "To ensure client safety, the nurse is responsible for delegating tasks to the appropriate people. The nurse should avoid assigning this task to B i at the volunteer because the individual who performs this task must understand the principles of traction. A volunteer does not have the requisite skill to perform this task. c | 5% of 12%", "whyNot": {"b": "This is an appropriate and safe assignment for the volunteer. It provides both socialization and diversional activity for the adolescent.", "c": "This is an appropriate and safe assignment for the volunteer. It provides a diversional activity for the preschooler.", "d": "This is an appropriate and safe assignment for the volunteer. It provides comfort for the client."}, "keyConcept": "Delegation involves explaining the task, determining who can complete the task, letting the individual know the expectation for completing the task, monitoring the situation, and asking for feedback. The nurse should follow the five rights of delegation, which includes right task, right circumstances, right person, right directions and communication, and right supervision and evaluation. Tasks to delegate are determined by the nurse according to the individual's skill level and to maintain safety. The volunteer can spend time interacting with the children and providing comfort, socialization, and diversional activities. The nurse should avoid assigning a task to the volunteer that is not within the volunteer's role, such as understanding the principles of traction."}, {"id": 10272, "cat": "LEADERSHIP", "stem": "and follows through with this act. Which of the following ethical principles is the nurse demonstrating?", "choices": [{"id": "a", "t": "Justice O B.Fidelity"}, {"id": "b", "t": "Fidelity is the ethical principal of keeping a promise."}, {"id": "c", "t": "Autonomy"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "b", "rationale": "Fidelity is the ethical principal of keeping a promise. The nurse is demonstrating the ethical principle of fidelity by promising the client to return soon with prescribed pain medication to treat the client's pain.", "whyNot": {"a": "Justice is the ethical principle of fairness. The nurse is demonstrating the ethical principal of justice by ensuring fair distribution of", "c": "Autonomy is the ethical principle of freedom of choice. The health care team respects autonomy for clients by including them in decision-", "d": "Nonmaleficence is the ethical principle to do no harm."}, "keyConcept": "Ethical principles reflects the guiding beliefs and values that the nurse should incorporate when practicing the profession. These moral principles are described in the formal code of professional ethics and all stem from the basic principal of respect for people."}, {"id": 10273, "cat": "LEADERSHIP", "stem": "Acharge nurse is delegating several client care tasks. Which of the following tasks should the nurse delegate to another Registered Nurse (RN)?", "choices": [{"id": "a", "t": "Collecting a urine specimen from a client who has diabetes mellitus to test for ketones"}, {"id": "b", "t": "Obtaining a wound drainage specimen from a client who has a wound that is red and painful"}, {"id": "c", "t": "Obtaining a stool specimen for an occult blood test from a client who requires screening for colon cancer"}, {"id": "d", "t": "Obtaining an expectorated sputum sample from a client who is being evaluated for tuberculosis"}], "correct": "b", "rationale": "-making skills based on knowledge of the wound-healing OB rd ea process. Therefore, the charge nurse should delegate this task to an RN. ° cf 5%", "whyNot": {"a": "The nurse can delegate this task to an assistive personnel (AP). The nurse should instruct the AP to save a sample of the urine so that the", "c": "The nurse can delegate this task to an AP. The nurse should instruct the AP to save a sample of the stool so that the nurse can repeat the", "d": "The nurse can delegate the task of obtaining an expectorated sputum specimen to an AP. When pharyngeal suctioning is required to"}, "keyConcept": "The American Nurses Association defines delegation as the transferring of responsibility for performing a task to another person. However, the nurse remains responsible for the outcome. Delegation requires the nurse to use judgment in each situation. The nurse should consider the five rights of delegation: task, circumstance, person, direction/communication, and supervision. The nurse should proceed with delegation when a step-by-step analysis indicates that the task can safely be delegated."}, {"id": 10274, "cat": "LEADERSHIP", "stem": "A nurse manager is reviewing the admission history of four adult clients. The nurse is required to report which of the following situations to an outside agency?", "choices": [{"id": "a", "t": "An older adult client who is dependent on caregivers and was admitted for the treatment of burns on the buttocks"}, {"id": "b", "t": "Ayoung adult client who was admitted for asthma and has track marks that might indicate IV substance use"}, {"id": "c", "t": "Ayoung adult client who was admitted for acute glomerulonephritis following a viral infection"}, {"id": "d", "t": "An emancipated minor who has acute appendicitis and wants to leave the facility without treatment Check Answe"}], "correct": "a", "rationale": "An older adult client who is dependent on caregivers and was admitted for the treatment of burns on the buttocks (correct) B i at Rationale A. Physical manifestations of older adult abuse can include burns to the buttocks and soles of the feet, vaginal and anal bruises, Cc | 2% skeletal fractures, welts, lacerations, and bruises at different stages of healing. Nurses are responsible for reporting suspicion of older adult .", "whyNot": {"b": "Although track marks might indicate IV substance use, the track marks might be present from scarring due to prior use. The nurse is not", "c": "The nurse is responsible for reporting certain infections as identified by the CDC. However, acute glomerulonephritis is not a reportable", "d": "An emancipated minor has the legal authority to make decisions about his health care. Although the client's decision to leave the facility"}, "keyConcept": "Older adult abuse can occur in the form of neglect or as physical, emotional, or financial abuse. The nurse should assess the older adult client for manifestations of physical or behavioral abuse. Manifestations of neglect can include pressure sores, dehydration, malnutrition, contractures, body odor, and lethargy. Physical manifestations of older adult abuse can include burns to the buttocks and soles of the feet, vaginal and anal bruises, skeletal fractures, welts, lacerations, and bruises at different stages of healing. Threats, humiliation, intimidation, and isolation are examples of emotional abuse. Financial abuse involves unauthorized or improper use of the older adult's finances. The nurse should assess the behavior of the older adult client for manifestations of abuse, such as anger, aggression, depression, physical or cognitive impairment, listlessness, and withdrawal. Nurses are responsible for reporting suspicion of older adult abuse to the local Adult Protective Services agency."}, {"id": 10275, "cat": "LEADERSHIP", "stem": "A nurse manager is reviewing the admission history of four adult clients. The nurse is required to report which of the following situations to an outside agency?", "choices": [{"id": "a", "t": "An older adult client who is dependent on caregivers and was admitted for the treatment of burns on the buttocks"}, {"id": "b", "t": "Ayoung adult client who was admitted for asthma and has track marks that might indicate IV substance use"}, {"id": "c", "t": "Ayoung adult client who was admitted for acute glomerulonephritis following a viral infection"}, {"id": "d", "t": "An emancipated minor who has acute appendicitis and wants to leave the facility without treatment"}], "correct": "a", "rationale": "An older adult client who is dependent on caregivers and was admitted for the treatment of burns on the buttocks (correct) B i at Rationale A. Physical manifestations of older adult abuse can include burns to the buttocks and soles of the feet, vaginal and anal bruises, Cc | 2% skeletal fractures, welts, lacerations, and bruises at different stages of healing. Nurses are responsible for reporting suspicion of older adult .", "whyNot": {"b": "Although track marks might indicate IV substance use, the track marks might be present from scarring due to prior use. The nurse is not", "c": "The nurse is responsible for reporting certain infections as identified by the CDC. However, acute glomerulonephritis is not a reportable", "d": "An emancipated minor has the legal authority to make decisions about his health care. Although the client's decision to leave the facility"}, "keyConcept": "Older adult abuse can occur in the form of neglect or as physical, emotional, or financial abuse. The nurse should assess the older adult client for manifestations of physical or behavioral abuse. Manifestations of neglect can include pressure sores, dehydration, malnutrition, contractures, body odor, and lethargy. Physical manifestations of older adult abuse can include burns to the buttocks and soles of the feet, vaginal and anal bruises, skeletal fractures, welts, lacerations, and bruises at different stages of healing. Threats, humiliation, intimidation, and isolation are examples of emotional abuse. Financial abuse involves unauthorized or improper use of the older adult's finances. The nurse should assess the behavior of the older adult client for manifestations of abuse, such as anger, aggression, depression, physical or cognitive impairment, listlessness, and withdrawal. Nurses are responsible for reporting suspicion of older adult abuse to the local Adult Protective Services agency."}, {"id": 10276, "cat": "LEADERSHIP", "stem": "action? O A. Inform the healthcare provider O B. Request a copy of the client’s Living Will to place in the medical record O C. Ask the client if his spouse is aware of his request O D. Ask the client if he has a Durable Power of Attorney for Health Care", "choices": [{"id": "a", "t": "Inform the healthcare provider"}, {"id": "b", "t": "Request a copy of the client’s Living Will to place in the medical record"}, {"id": "c", "t": "Ask the client if his spouse is aware of his request"}, {"id": "d", "t": "Ask the client if he has a Durable Power of Attorney for Health Care"}], "correct": "a", "rationale": "The nurse should inform the healthcare provider. This is a priority intervention since the client’s wishes cannot be honored without a do not B id ay resuscitate order by the healthcare provider entered into the client’s chart. ° c | 1%", "whyNot": {"b": "A living will describes medical care the client would like to receive in the event the client becomes incapacitated and is unable to make", "c": "This is not a priority. If the client’s family wishes to discuss the client’s decision, the nurse can answer the family’s questions and continue", "d": "A Durable Power of Attorney for Health Care allows an individual to appoint someone to make medical decisions for him/her if"}, "keyConcept": "Aliving will describes the client's wishes concerning healthcare if the client becomes incapacitated. If the client does not wish to be resuscitated while in a hospital or healthcare facility, the client's healthcare provider must enter a signed \"do not resuscitate\" order on the client's chart."}, {"id": 10277, "cat": "LEADERSHIP", "stem": "A nurse is preparing to delegate the task of obtaining clients' vital signs to an assistive personnel (AP). Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Verify the AP has passed the facility's annual competency training prior to delegating the task."}, {"id": "b", "t": "Communicate the time frame for when the AP should report the results."}, {"id": "c", "t": "Observe the AP as she obtains the vital signs of each client."}, {"id": "d", "t": "Ask the AP to take the vital signs of a client who is immediately postoperative."}], "correct": "b", "rationale": "A || 28% Moderate The right communication is one of the five rights of delegation. The nurse should communicate goals and parameters clearly to the AP, OB a ae: including the timeline for obtaining and reporting the vital signs. ° cf 4%", "whyNot": {"a": "The Joint Commission requires health care facilities to have employees undergo annual competency training for the particular population", "c": "The right level of supervision is one of the five rights of delegation. Obtaining vital signs is within the AP's range of function; therefore, the", "d": "The right circumstance is one of the five rights of delegation. The nurse should identify that a client who is immediately postoperative or"}, "keyConcept": "Nurses should recognize the allowances and limitations of delegation to assistive personnel (AP). Tasks that are within the AP's range of function include obtaining weights and performing ADLs, such as bathing, feeding, and assistance with ambulation and toileting. The AP can also be assigned to obtain vital signs of stable clients. The nurse should ensure the client's condition is stable prior to delegating any tasks to an AP and should not delegate tasks that require advanced skills, higher education, or specialized technical skill. S2S2>="}, {"id": 10278, "cat": "LEADERSHIP", "stem": "Acharge nurse is teaching a newly licensed nurse about the quality improvement process in the acute care setting. The charge nurse should include which of the following in the teaching?", "choices": [{"id": "a", "t": "The main focus of quality improvement is to improve the delivery of nursing care at the bedside."}, {"id": "b", "t": "Reports of client satisfaction typically focuses on how quickly their health condition improved."}, {"id": "c", "t": "Employees at levels of the organization should be involved in quality improvement"}, {"id": "d", "t": "One staff member on each nursing unit should be designated to monitor for quality care issues."}], "correct": "c", "rationale": "A i 22% Moderate Quality improvement is an ongoing process to improve quality which involves all members of an organization and includes clients and their B | a0 family members. The focus of quality improvement is to continually examine all process so as to identify and correct potential problems before a crisis situation emerges. Quality assurance focuses on currently existing quality. ec | 14% p | 1%", "whyNot": {"a": "Quality improvement focuses on evaluating and improving the care provided by all members of the health care team including nurses,", "b": "Client satisfaction scores typically reflect their contentment with surroundings such as food quality, friendliness of the staff, delays in", "d": "All staff members should be trained and encouraged to constantly examine processes and care provision for potential problems or"}, "keyConcept": "Health care systems are moving away from a quality assurance model toward a quality improvement model of health care delivery. Quality assurance is focused on ensuring that quality care currently exists. Quality improvement is a continuous process which charges the entire work force to look for and implement changes to improve the health care delivery system. Quality improvement is proactive and focuses on identifying problems and implementing solutions before a crisis occurs."}, {"id": 10279, "cat": "LEADERSHIP", "stem": "A nurse manager is planning to announce a major change on the unit. Which of the following communication techniques should the nurse manager use to enhance the importance of the announcement?", "choices": [{"id": "a", "t": "Present the announcement to unit staff in a conference room."}, {"id": "b", "t": "Stand with arms crossed when giving the announcement."}, {"id": "c", "t": "Stare at the people the announcement will affect the most."}, {"id": "d", "t": "Pause frequently when making the announcement."}], "correct": "a", "rationale": "o; M2 The environment in which the announcement is made can have a major impact on the manner in which the announcement is received. An ' station during shift change. c | 2%", "whyNot": {"b": "Crossing the arms over the chest suggests defensiveness or aggressiveness and will detract from the importance of the message the nurse", "c": "Eye contact promotes emotional connection and enhances communication if done appropriately. Staring impedes connecting with others", "d": "The delivery of the message is impacted by timing and vocal expression. For example, hesitation or frequent pauses during the"}, "keyConcept": "Nonverbal communication techniques can either confirm or discount the actual words being spoken. The nurse should identify that when there is a discrepancy between the verbal and nonverbal message, the receiver is more likely to believe the nonverbal message. This is an important factor for the nurse to consider when providing client care and when talking with other members of the health care team."}, {"id": 10280, "cat": "LEADERSHIP", "stem": "A nurse is providing change-of-shift report about a group of clients to the oncoming nurse. Which of the following information should the nurse include in the report? O A.\"Mr. Rodriguez in room 200 needs another IV bag at 0700.\" O B. \"Mrs. Smith in room 201 had a visitor yesterday evening.\" O C. \"Mr. Jones in room 202 had routine vitals obtained this morning.\" O D.\"Mrs. Hassler in room 203 is grumpy after waking up.\"", "choices": [{"id": "a", "t": "The nurse should include time-sensitive information in the change-of-shift report, such as the need for another IV bag at 0700."}, {"id": "b", "t": "The nurse does not need to mention information about the client's visitors unless there is a concern or incident. D l 3%"}, {"id": "c", "t": "The nurse does not need to include routine information, such as the client's vital signs, unless there is a concern that the oncoming nurse"}, {"id": "d", "t": "The nurse should not include subjective information in the change-of-shift report."}], "correct": "a", "rationale": "The nurse should include time-sensitive information in the change-of-shift report, such as the need for another IV bag at 0700.", "whyNot": {"b": "The nurse does not need to mention information about the client's visitors unless there is a concern or incident. D l 3%", "c": "The nurse does not need to include routine information, such as the client's vital signs, unless there is a concern that the oncoming nurse", "d": "The nurse should not include subjective information in the change-of-shift report."}, "keyConcept": "When providing change-of-shift report, the nurse should identify what information to include. The nurse should include current information about the client that is relevant, time-sensitive, or that reflects a change in status, such as a surgery. Subjective information, such as personal opinions, and routine care are irrelevant and should not be included."}, {"id": 10281, "cat": "LEADERSHIP", "stem": "the nurse make? O A. \"It is normal to be nervous before surgery.\" O B. \"I will notify the provider about your decision.\" O C. \"You will feel better after the surgery.\" O D.\"If you don't have the surgery, you could die.\"", "choices": [{"id": "a", "t": "\"It is normal to be nervous before surgery.\""}, {"id": "b", "t": "\"I will notify the provider about your decision.\""}, {"id": "c", "t": "\"You will feel better after the surgery.\" O D.\"If you don't have the surgery, you could die.\""}], "correct": "b", "rationale": "Easy Correct Answer: a Hl 10% B. \"I will notify the provider about your decision.\" c | 1% When a client is unsure about a surgery or treatment, it is the responsibility of the nurse to notify the provider about the client's feelings. The .", "whyNot": {"a": "By making this statement, the nurse is assuming the client is nervous and does not explore the client's feelings about the surgery.", "c": "By making this statement, the nurse is providing false reassurance and does not address the client's feelings about the surgery."}, "keyConcept": "The nurse should respect that a client has the right to change their mind at any time about a treatment or procedure, regardless of the reason. It is the nurse's responsibility to contact the provider about the client's wishes. The provider will then request the client sign a refusal form regarding the surgery."}, {"id": 10282, "cat": "LEADERSHIP", "stem": "already been through enough suffering.\" Which of the following responses should the nurse make? O A.\"Itis your right to make decisions regarding your care.\" O B. \"Your doctor made this recommendation because she feels you are a good candidate for a transplant; perhaps you should reconsider your decision.” O C. \"Your family is supportive; maybe you should allow them to make the decision.\" O D. \"Liver transplants are a common procedure at this hospital, so you shouldn't have to worry about having complications.\"", "choices": [{"id": "a", "t": "It is the nurse's responsibility to serve as an advocate for the client and support her right to make decisions regarding health care based on B I a her personal beliefs and values."}, {"id": "b", "t": "When making this statement, the nurse is giving advice. It implies that the nurse knows what is best for the client and doesn't recognize"}, {"id": "c", "t": "When making this statement, the nurse is giving advice. It implies that the nurse knows what is best for the client and doesn't recognize"}, {"id": "d", "t": "When making this statement, the nurse is belittling the client's feelings."}], "correct": "a", "rationale": "It is the nurse's responsibility to serve as an advocate for the client and support her right to make decisions regarding health care based on B I a her personal beliefs and values. c | 1%", "whyNot": {"b": "When making this statement, the nurse is giving advice. It implies that the nurse knows what is best for the client and doesn't recognize", "c": "When making this statement, the nurse is giving advice. It implies that the nurse knows what is best for the client and doesn't recognize", "d": "When making this statement, the nurse is belittling the client's feelings."}, "keyConcept": "One of the nurse's professional responsibilities is acting as a client advocate. The nurse should support the client's rights and speaks on behalf of the client. The nurse should support the client's right for self-determination even in situations where there is conflict among the individuals involved."}, {"id": 10283, "cat": "LEADERSHIP", "stem": "A nurse on a pediatric unit is planning care for a group of clients. Which of the following clients should the nurse plan to assess first?", "choices": [{"id": "a", "t": "Aschool-age child who has diabetes mellitus and requires blood glucose monitoring"}, {"id": "b", "t": "An infant who has pertussis and is receiving oxygen via nasal cannula"}, {"id": "c", "t": "An adolescent who is one day status-post an appendectomy"}, {"id": "d", "t": "A toddler who is scheduled for an upper gastrointestinal x-ray series"}], "correct": "b", "rationale": "A B. Using the airway, breathing, circulation (ABC) approach to prioritizing client care, the nurse should assess this infant first because the OB —— infant has a compromised airway and requires oxygen. cil", "whyNot": {"a": "The nurse should monitor the blood glucose level of a child who has diabetes mellitus because the child might need care to manage", "c": "The nurse should assess the adolescent who is postoperative to ensure there are no postoperative complications, such as infection.", "d": "The nurse should assess the toddler who is scheduled for x-rays to ensure the toddler has remained NPO prior to the procedure. However,"}, "keyConcept": "When planning care for multiple clients, it is important for the nurse to set priorities. The first step in prioritizing care is to identify each client's diagnoses and classify these as high, intermediate, or low priority. The highest priorities are assigned to those clients whose condition which, if untreated, can result in harm to the client. Examples of high priorities include those that address airway, breathing, and circulation, safety, and pain."}, {"id": 10284, "cat": "LEADERSHIP", "stem": "A nurse on a pediatric unit is planning care for a group of clients. Which of the following clients should the nurse plan to assess first?", "choices": [{"id": "a", "t": "Aschool-age child who has diabetes mellitus and requires blood glucose monitoring"}, {"id": "b", "t": "An infant who has pertussis and is receiving oxygen via nasal cannula"}, {"id": "c", "t": "An adolescent who is one day status-post an appendectomy"}, {"id": "d", "t": "A toddler who is scheduled for an upper gastrointestinal x-ray series eck Answer"}], "correct": "b", "rationale": "B. Using the airway, breathing, circulation (ABC) approach to prioritizing client care, the nurse should assess this infant first because the : infant has a compromised airway and requires oxygen.", "whyNot": {"a": "The nurse should monitor the blood glucose level of a child who has diabetes mellitus because the child might need care to manage", "c": "The nurse should assess the adolescent who is postoperative to ensure there are no postoperative complications, such as infection.", "d": "The nurse should assess the toddler who is scheduled for x-rays to ensure the toddler has remained NPO prior to the procedure. However,"}, "keyConcept": "When planning care for multiple clients, it is important for the nurse to set priorities. The first step in prioritizing care is to identify each client's diagnoses and classify these as high, intermediate, or low priority. The highest priorities are assigned to those clients whose condition which, if untreated, can result in harm to the client. Examples of high priorities include those that address airway, breathing, and circulation, safety, and pain."}, {"id": 10285, "cat": "LEADERSHIP", "stem": "A nurse has assigned client care activities to an assistive personnel (AP). Which of the following statements by the AP indicates a need for assistance with time management?", "choices": [{"id": "a", "t": "\" will start working with the client in room 1, then work my way to room 10.\""}, {"id": "b", "t": "\"I will give this client his meal tray first because he is going to physical therapy early.\""}, {"id": "c", "t": "\"After breakfast, will pack the belongings of clients who will be discharged this morning.\""}, {"id": "d", "t": "\"I will start by providing partial baths before breakfast.\""}], "correct": "a", "rationale": "@A ; 56% Moderate Time management involves making decisions about tasks or situations that need immediate attention and those that can be delayed. The B I a AP's statement does not include consideration of the tasks that need to be performed for each client, any time restrictions, or equipment to be organized. c | 12% iz 29%", "whyNot": {"b": "Effective time management requires the ability to prioritize tasks. Prioritization involves addressing those tasks or situations that are", "c": "Some activities should be done at a specific time, while other activities can be delayed. This statement demonstrates effective time", "d": "Clustering similar activities or providing multiple care tasks for a single client is an example of good time management and prioritization."}, "keyConcept": "Time management is a learned skill that involves planning activities that effectively use time and resources to provide client care. Key priorities should be identified along with specific actions and the required equipment and supplies needed to accomplish each activity. Time-sensitive activities should be addressed first, and interventions should be documented as soon as possible after completing the activity."}, {"id": 10286, "cat": "LEADERSHIP", "stem": "advancing kidney failure. The nurse should recognize that discontinuing this medication demonstrates which of the following ethical principles?", "choices": [{"id": "a", "t": "Justice"}, {"id": "b", "t": "Autonomy O c Fidelity"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "d", "rationale": "Nonmaleficence is the obligation to do no harm to the client. Intentionally exposing clients to serious or permanent harm is unacceptable. Should such a situation emerge during the conduct of a study, the study should be terminated immediately.", "whyNot": {"a": "Justice is the ethical principle based on the idea that the nurse must be fair in the delivery of care and use of resources. This principle is", "b": "Autonomy is the ethical principle based on the idea that a person has the right to independence and freedom, which can promote self-"}, "keyConcept": "A nurse should be able to identify and practice within the ethical principles of nursing."}, {"id": 10287, "cat": "LEADERSHIP", "stem": "purposes? O A. Ensuring the client is of age to sign the form O B. Confirming the client appears competent to provide consent O C. Asserting the nurse has explained the risks and benefits of the procedure O D. Recording that the client's partner agrees the procedure is necessary", "choices": [{"id": "a", "t": "Ensuring the client is of age to sign the form"}, {"id": "b", "t": "Confirming the client appears competent to provide consent"}, {"id": "c", "t": "Asserting the nurse has explained the risks and benefits of the procedure"}, {"id": "d", "t": "Recording that the client's partner agrees the procedure is necessary"}], "correct": "b", "rationale": "al 2% Easy By signing as a witness on an informed consent form, the nurse is confirming that the client is signing the consent form voluntarily. OB rT SY SO fo", "whyNot": {"a": "The nurse's signature does not confirm that the client is of age to sign the consent form. A minor can sign the consent form if the minor is", "c": "It is the responsibility of the provider to explain the risks and benefits of the procedure to the client.", "d": "Although support from the client's partner can be a factor when the client considers surgery, the nurse should respect the ethical principle"}, "keyConcept": "Informed consent includes the provider explaining the risks, benefits, consequences, and alternatives of a procedure, diagnostic procedure, or invasive treatment to the client. This explanation is presented in terms the client can understand in order to facilitate an educated decision. If the client is unable to comprehend the information due to age, medications, injury, or illness, a relative, parent, or guardian can legally sign the informed consent form after the provider has explained the information to them. Minors can also sign a consent form if considered an emancipated. An emancipated minor is a client who is underage and is married, divorced, or widowed, active in the military, or has been designated by a court order. Unemancipated minors can provide consent in certain circumstances, such as a minor who is pregnant, has an STI, needs treatment for substance use disorder, or is in a mental health facility. The nurse who witnesses the signature of the client on the informed consent form is using her signature to indicate the client is signing voluntarily, the signature is authentic, and that the client appears competent."}, {"id": 10288, "cat": "LEADERSHIP", "stem": "information should the nurse include in the assessment portion of the communication?", "choices": [{"id": "a", "t": "What the nurse has identified as the problem"}, {"id": "b", "t": "The client's medical diagnosis"}, {"id": "c", "t": "The client's admission date"}, {"id": "d", "t": "Opinions about treatments needed"}], "correct": "a", "rationale": "In the assessment portion of the ISBAR communication technique, the nurse should include an assessment of the client's condition, as well B | at as what appears to be the problem. c| 2%", "whyNot": {"b": "The nurse should include the client's medical diagnosis in the background portion of the communication.", "c": "The nurse should include the client's admission date in the background portion of the communication.", "d": "The nurse should include recommendations about treatment options in the recommendation portion of the communication."}, "keyConcept": "The Joint Commission identified inadequate communication among the health care team as a major factor leading to poor client outcomes, including sentinel events. The ISBAR technique is an easy to remember, effective way to improve communication among health team members. Many agencies have adopted its use as a way to improve communication and promote client safety."}, {"id": 10289, "cat": "LEADERSHIP", "stem": "A nurse has just received report on a group of clients for the upcoming shift. Which of the following actions by the nurse demonstrates effective time management skills?", "choices": [{"id": "a", "t": "Identify tasks that are time-specific."}, {"id": "b", "t": "Gather supplies as needed during client care."}, {"id": "c", "t": "Skip breaks to review clients' laboratory values."}, {"id": "d", "t": "Document client care at the end of the shift."}], "correct": "a", "rationale": "The nurse should identify tasks that are time-specific after receiving report, such as a medication that needs to be administered at a specific time. This allows the nurse to track their tasks throughout the day and assist in managing their time wisely.", "whyNot": {"b": "The nurse should gather necessary supplies and equipment prior to seeing each client to avoid interruptions to client care.", "c": "It is important for nurses to take breaks to relax, allowing them to recharge their minds and get a fresh perspective.", "d": "The nurse should document interventions when they are completed for each client throughout the shift. Documenting at the end of the"}, "keyConcept": "Effective time-management skills are a crucial part of providing client care. Constructing a priority to-do list after receiving shift report will enable the nurse to make decisions on care provision based upon condition of the clients and the timing of medications and treatments. The nurse should combine activities when possible and gather all anticipated supplies prior to entering a client's room. All client care documentation should be completed promptly to increase accuracy of documentation and decrease the risk of errors."}, {"id": 10290, "cat": "LEADERSHIP", "stem": "A nurse and an assistive personnel (AP) are providing care to a group of clients. When planning task delegation, which of the following tasks should the nurse perform?", "choices": [{"id": "a", "t": "Insertion of a client's hearing aid"}, {"id": "b", "t": "Removing a client's antiembolic stockings"}, {"id": "c", "t": "Assessing a client's sacrum for edema"}, {"id": "d", "t": "Assisting a client to cough and deep breathe"}], "correct": "c", "rationale": "al 4% Easy The nurse can delegate tasks that require less extensive educational training. However, aspects of the nursing process, such as assessment, 's specialized knowledge, clinical judgment, and educational preparation and is outside the range of function of the AP. ec a 82% of 4%", "whyNot": {"a": "The use of AP can help to free up the nurse's schedule from tasks that can be completed by less extensively trained personnel. The care", "b": "Antiembolic stockings provide compression to the legs, which limits the pooling of blood and decreases the risk for the development of", "d": "Coughing and deep breathing assists in opening the airways of a client who is postoperative or restricted to bedrest and decreases the risk"}, "keyConcept": "The nurse should use several tools when determining which tasks can be delegated. One of these tools is the decision tree for nursing assistive personnel developed jointly by the American Nurses Association and the National Council of State Boards of Nursing. This decision tree can be used to evaluate whether the task can be delegated based upon legal standards, the AP's competencies, facility policies, and client safety."}, {"id": 10291, "cat": "LEADERSHIP", "stem": "A nurse manager is planning to teach the nurses on the unit about a new infusion pump. Which of the following teaching strategies is the most effective way to ensure that the staff can use the device correctly?", "choices": [{"id": "a", "t": "Create a step-by-step instructional handout about using the device for the staff to review."}, {"id": "b", "t": "Demonstrate using the device and observe the staff returning the demonstration."}, {"id": "c", "t": "Remind the staff to review the procedure manual prior to using the new pump."}, {"id": "d", "t": "Show a video about the new infusion pump during an in-service."}], "correct": "b", "rationale": "B. Evidence-based practice indicates that psychomotor skills are best taught by using demonstration and return demonstration methods of learning, such as the \"see one, do one, teach one\" model. Planning a Demonstration to Promote Psychomotor Learning 1. Assemble and organize the equipment, making sure it is in working order. 2. Ensure all learners have a clear view of each step of the demonstration. 3. Perform each step slowly and in sequence, offering rationales for each step. 4, Encourage participants to ask questions throughout the demonstration. 5. Allow practice time for each participant to work with the equipment. 6. Complete the training with a return demonstration by each participant.", "whyNot": {"a": "The nurse manager should provide written information for the nurses during an in-service. Additional information cards can be placed on", "c": "The nurse manager should have a procedure manual available on the unit for the nurses to review prior to use and for troubleshooting, if", "d": "The nurse manager should present a visual demonstration of the use of the new infusion pump during an in-service to enhance learning in"}, "keyConcept": "In-service programs are presented to staff members in order to increase the skills, competencies, and knowledge required to promote the safe and effective care of the client. Often, the focus is on new technologies and how to use new equipment. When planning in-services for staff members, the developer should use strategies specifically for adult learners, such as focusing on solving problems or issues that affect the adult learner's immediate environment or work situation."}, {"id": 10292, "cat": "LEADERSHIP", "stem": "client understands hospice care? O A. \"Iwill have to be admitted to a long-term care facility in order to receive hospice care.\" O B.\"I should expect the hospice team to help me manage my difficulty breathing.\" O C. \"Hospice care services are available to anyone who is terminally ill, regardless of life expectancy.\" O D. \"My oncologist will continue to look for a cure for my cancer while | am receiving hospice care.\"", "choices": [{"id": "a", "t": "\"Iwill have to be admitted to a long-term care facility in order to receive hospice care.\" O B.\"I should expect the hospice team to help me manage my difficulty breathing.\""}, {"id": "b", "t": "A l 3% Moderate The focus of hospice care is to provide relief of manifestations related to a terminal illness, such as dyspnea, that can occur with terminal eB | 64% fo lung cancer."}, {"id": "c", "t": "\"Hospice care services are available to anyone who is terminally ill, regardless of life expectancy.\""}, {"id": "d", "t": "\"My oncologist will continue to look for a cure for my cancer while am receiving hospice care.\""}], "correct": "b", "rationale": "A l 3% Moderate The focus of hospice care is to provide relief of manifestations related to a terminal illness, such as dyspnea, that can occur with terminal eB | 64% fo lung cancer.", "whyNot": {"a": "The client can receive hospice care in a number of settings, such as in the client's home, in an assisted living facility, and in long-term care.", "c": "The focus of hospice care is to provide comfort care to clients who have a prognosis of 6 months or less to live.", "d": "The focus of hospice care is to provide the client with palliative care when there is no cure for the client's end-stage disease process."}, "keyConcept": "The nurse should inform the client about hospice care and evaluate the client's understanding. Hospice care is specialized palliative care that is initiated when the client is estimated to have 6 months or less to live. Hospice care focuses on maintaining the client's comfort, independence, and dignity while easing pain and manifestations of terminal illnesses, such as COPD, kidney failure, cardiac disorders, neurological diseases, and dementia. This specialized care is initiated when the client has 6 months or less to live. Hospice care includes palliative nursing care to maintain the client's comfort, independence, and dignity while easing pain and the manifestations of the client's disease process. Hospice care involves the client and the client's family."}, {"id": 10293, "cat": "LEADERSHIP", "stem": "A nurse is assigned four clients on a medical-surgical unit. Which of the following clients should the nurse assess first?", "choices": [{"id": "a", "t": "A client who has diarrhea and reports stomach pain"}, {"id": "b", "t": "A client who has a cast on the left leg and reports numbness and paresthesia"}, {"id": "c", "t": "A client who has type 1 diabetes mellitus and a fasting blood glucose level of 150 mg/dL O D.A client who has COPD and an SaO2 of 95% while receiving oxygen at 2 L/min via nasal cannula."}], "correct": "b", "rationale": "| 2% Easy When using the airway, breathing, circulation (ABC) approach to client care, the nurse should identify a client who has numbness and OB rs cei paresthesia is experiencing manifestations of acute compartment syndrome (ACS). Left untreated, the client can lose circulation and function of the extremity permanently. Therefore, the nurse should assess this client first. c 3% D 3%", "whyNot": {"a": "The nurse should assess the client who has diarrhea to determine details about the client’s pain and provide both pharmacological and", "c": "The nurse should assess a client who has hyperglycemia because the client might need to receive antidiabetic medications to prevent"}, "keyConcept": "The nurse should evaluate client needs when prioritizing care delivery to allow the nurse to avoid delays in care delivery that might result in serious complications for some clients. The nurse should also identify that client needs do not remain consistent but change with the client's condition. Therefore, frequent review and reprioritization of care delivery is needed."}, {"id": 10294, "cat": "LEADERSHIP", "stem": "A nurse is presenting an in-service about delegation to a group of newly licensed nurses. Which of the following statements by a newly licensed nurse indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Delegation ensures the client receives appropriate resources.\""}, {"id": "b", "t": "\"Delegation permits a designated individual to meet a goal on your behalf.\""}, {"id": "c", "t": "\"Delegation promotes client discharge teaching by unlicensed personnel.\""}, {"id": "d", "t": "\"Delegation shifts accountability to the individual performing the task.\""}], "correct": "b", "rationale": "Delegation is defined as directing the performance of others to accomplish goals of the nurse and the facility. Delegation is a time management tool that promotes safe client care by helping to ensure client tasks are accomplished in a timely manner.", "whyNot": {"a": "Delegation allows work to be done by others. It does not ensure that the client receives appropriate resources.", "c": "Delegation allows work to be done by others. Teaching activities should not be delegated by nurses because they require specialized", "d": "Delegation transfers the responsibility of completing client tasks from one person to another. However, the nurse retains accountability"}, "keyConcept": "Delegation is a complex process involving task assignment and supervision of members of the health care team to deliver client care. It requires the nurse to evaluate the task and provide guidance, feedback, and intervention, if necessary."}, {"id": 10295, "cat": "LEADERSHIP", "stem": "plan to take during the moving stage of change?", "choices": [{"id": "a", "t": "Identify the problem."}, {"id": "b", "t": "Inform the charge nurses that a change to established procedures is needed."}, {"id": "c", "t": "Require the charge nurses to comply with the new procedures."}, {"id": "d", "t": "Set a target date for the implementation of the new procedures."}], "correct": "d", "rationale": "all 10% Hard The second stage of Lewin's change theory is the moving stage. During the moving stage, the nurse manager should develop the plan for B i 75k change and set the target date for the implementation of the new procedures. ° ci 21% Tasks Associated With the Change Stage e@ + Develop a plan for introducing and implementing the change, including goals, objectives and strategies. «Include all team members who will be affected by the change in the planning process. + Identify those who support the change and those who are resistant. a © o 2 ° s a = a < + Set a target date for implementing the strategies. «Implement the strategies. + Offer support and encouragement to team members throughout the change process. + Devise and implement strategies to meet resistance to change. + Evaluate the integration of the change and revise strategies as needed.", "whyNot": {"a": "There are three stages involved in Lewin's change theory. The first stage is the unfreezing stage in which the nurse manager should", "b": "During the unfreezing stage, the nurse manager should make the charge nurses aware that a change is needed. This should be based upon", "c": "The third stage of Lewin's change theory is the refreezing stage. During this time, the nurse manager should focus on integration of the"}, "keyConcept": "Asa change agent, the nurse manager is responsible for guiding staff through the change process. Keeping everyone who will be impacted by the change involved in the entire process will promote acceptance of the change and increases overall success in the change process."}, {"id": 10296, "cat": "LEADERSHIP", "stem": "clients? O A. Achild who is experiencing sickle cell crisis O B. Achild who has pertussis O C. Achild who has a head injury O D. A child who has a new diagnosis of type 1 diabetes mellitus", "choices": [{"id": "a", "t": "Achild who is experiencing sickle cell crisis"}, {"id": "b", "t": "Achild who has pertussis"}, {"id": "c", "t": "Achild who has a head injury"}, {"id": "d", "t": "A child who has a new diagnosis of type 1 diabetes mellitus"}], "correct": "d", "rationale": "all 6% Easy The child who has diabetes mellitus requires monitoring and teaching, and the child who is postoperative following an appendectomy . Furthermore, both of these children are in stable condition and are noninfectious. Therefore, the RN should assign these two clients to the same room. © | Me", "whyNot": {"a": "The child who is postoperative following an appendectomy requires frequent assessments and interventions, and the child who is", "b": "The child who has pertussis requires droplet precautions and a private room. Placing the child who is postoperative following an", "c": "The child who has a head injury requires a quiet, low-stimulus environment. Due to frequent assessments and interventions for the child"}, "keyConcept": "Principles of room assignments include consideration of factors such as infection control, client care needs, and the acuity or stability of a client. Another factor to consider is the age of the clients. Placing clients who are close in age in the same room promotes feelings of comradery between the clients because they are more likely to have things in common than clients who are years apart in age."}, {"id": 10297, "cat": "LEADERSHIP", "stem": "A nurse is documenting in the medical record information of a client and suspects opioid use disorder. Which of the following manifestations should the nurse expect and document in the client’s record?", "choices": [{"id": "a", "t": "Euphoria"}, {"id": "b", "t": "Rhinorrhea"}, {"id": "c", "t": "Yawning"}, {"id": "d", "t": "Dilated pupils"}], "correct": "a", "rationale": "The client who has opioid use disorder can experience euphoria, which is a behavioral manifestation of opioid analgesics. The nurse should B 1] or distinguish between behavioral effects of opioid use and manifestations of withdrawal from opioids and accurately document these in the client's medical records. c | 11%", "whyNot": {"b": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning.", "c": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning.", "d": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning."}, "keyConcept": "Documenting client information is a vital aspect of nursing communication that allows an oncoming nurse to develop a plan of care. It also allows other health care workers who are caring for the client to access the information. Accurate documentation allows the oncoming nurse to identify whether a client is experiencing a behavioral effect of an opioid analgesic or is experiencing withdrawal.\""}, {"id": 10298, "cat": "LEADERSHIP", "stem": "A nurse is teaching a newly licensed nurse about delegating tasks to assistive personnel (AP). Which of the following statements by the newly licensed nurse indicates an understanding of the teaching? O A.\"The nurse relinquishes accountability for client outcomes when care is delegated to an AP.\" O B. \"The AP can provide client education about how to perform basic self-care to the client.\" O C. \"The nurse should consider the AP's level of experience when making delegation decisions.\" O D. \"The nurse should delegate all tasks that don't require specialized skill or knowledge to an AP.\"", "choices": [{"id": "a", "t": "Delegation is the act of assigning tasks or client care to a licensed practical nurse (LPN) or an AP. The nurse should use the five rights of"}, {"id": "b", "t": "The nurse should recognize that certain tasks cannot be delegated. These include activities or tasks that require critical thinking and"}, {"id": "c", "t": "\"The nurse should consider the AP's level of experience when making delegation decisions.\""}, {"id": "d", "t": "The nurse should consider the workload of the AP when delegating and should avoid overburdening the AP with tasks and activities. The"}], "correct": "c", "rationale": "Correct Answer: C. \"The nurse should consider the AP's level of experience when making delegation decisions.\" When delegating a task, the nurse should delegate the task to the right person. The nurse should consider the AP's job description, level of knowledge, and individual level of experience. Other considerations include the Nurse Practice Act and the facilities policies.", "whyNot": {"a": "Delegation is the act of assigning tasks or client care to a licensed practical nurse (LPN) or an AP. The nurse should use the five rights of", "b": "The nurse should recognize that certain tasks cannot be delegated. These include activities or tasks that require critical thinking and", "d": "The nurse should consider the workload of the AP when delegating and should avoid overburdening the AP with tasks and activities. The"}, "keyConcept": "Facility policies and job descriptions might limit the tasks that certain healthcare staff are allowed to complete according to the state's Nursing Practice Act. However, regardless of facility policies or job descriptions, staff members cannot perform tasks that are prohibited by the state's Nurse Practice Act."}, {"id": 10299, "cat": "LEADERSHIP", "stem": "Astaff nurse asks an assistive personnel (AP) to ambulate a client and the AP refuses. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Ambulate the client."}, {"id": "b", "t": "Dismiss the AP."}, {"id": "c", "t": "Complete an incident report."}, {"id": "d", "t": "Ask the AP about her concerns with the assignment."}], "correct": "d", "rationale": "al 3% Easy Reviewing the incident with the AP allows the nurse to understand the delegated task from the AP's perspective. The nurse should attempt 's concerns. | © 2%", "whyNot": {"a": "Ambulating the client addresses an immediate client need; however, this fails to address the underlying problem of resistance to", "b": "Dismissing the AP is beyond the authority of the staff nurse. Instead, the nurse should find a way to address the problem.", "c": "An incident report is required when there is an accident or unusual occurrence. It is not required in this situation."}, "keyConcept": "When the delegation of tasks to an AP is met with resistance, it is important for the nurse to try and understand the AP's perspective. A heavy workload or unfamiliarity with the assigned task are common reasons for resistance to delegation. The nurse might need to provide coaching to the AP or provide encouragement and feedback if the AP is lacking the knowledge or self-confidence to complete the task."}, {"id": 10300, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who is actively dying. Which of the following actions by the nurse demonstrates the ethical principle of nonmaleficence?", "choices": [{"id": "a", "t": "Discussing advance directives with the client and the client's family"}, {"id": "b", "t": "Providing comfort care measures to the client"}, {"id": "c", "t": "Withholding a dose of pain medication when the client has respiratory depression"}, {"id": "d", "t": "Giving the client privacy during perineal care"}], "correct": "c", "rationale": "A The principle of nonmaleficence is the obligation to not cause harm. The nurse should ease the client's pain with the administration of B I narcotics. However, if the nurse believes the dose is potentially lethal or could hasten the client's death, the nurse should not administer the medication based on the principle of nonmaleficence. ec | >|", "whyNot": {"a": "Discussing advance directives with the client and the client's family is an example of promoting client autonomy by respecting the client's", "b": "Providing comfort care measures to a client who is dying is an example of the principle of beneficence, which is a moral obligation to act", "d": "The nurse uses the principle of beneficence, which is a moral obligation to act to benefit others, when providing privacy during sensitive"}, "keyConcept": "The principle of nonmaleficence is the obligation to not cause harm. If a nurse believes an action could harm the client, such as administering an analgesic, the nurse should not perform the action. The nurse should provide the client with other pharmacological medications and nonpharmacological interventions to promote comfort and reduce the client's pain."}, {"id": 10301, "cat": "LEADERSHIP", "stem": "the following nursing actions demonstrates client advocacy?", "choices": [{"id": "a", "t": "Teaching the client about the importance of diuretics to treat heart failure"}, {"id": "b", "t": "Reinforcing that the client should request help when ambulating after taking the medication"}, {"id": "c", "t": "Asking the client if she would like the nurse to contact the provider to discuss the concerns"}, {"id": "d", "t": "Reassuring the client that furosemide administration could be delayed until after breakfast"}], "correct": "c", "rationale": ". The client has the right to decide ona B I Ee course of action to address her health concerns. The nurse demonstrates caring and respect for the client by asking if the client prefers the nurse to intervene. The nurse also recognizes the client's autonomy and empowers the client to participate in decisions about her care. ec Fe 74% pi 3%", "whyNot": {"a": "It is the nurse's role to teach the client about the medication. However, this does not address the client's concern and is not an example of", "b": "Reinforcing safety information with a client is part of the nurse's role as a care provider. However, it is not an example of advocacy for a", "d": "The nurse is providing false reassurance about medication administration and does not address the client's concerns about adverse"}, "keyConcept": "A nurse demonstrates client advocacy by supporting the rights of a client. The nurse can advocate for a specific client by standing up for the client's best interests in their health care, including addressing client concerns and intervening when a client's rights are being violated. The nurse can also demonstrate advocacy toward a large group of clients by advocating for common health care needs."}, {"id": 10302, "cat": "LEADERSHIP", "stem": "actions should the committee take first?", "choices": [{"id": "a", "t": "Recommend a program on medication administration to facility nurses who administer medications."}, {"id": "b", "t": "Ensure competency of medication administration by requiring nurses to pass an examination."}, {"id": "c", "t": "Conduct a root cause analysis (RCA) on the error that occurred."}, {"id": "d", "t": "Involve nurses who administer medications in quality improvement programs."}], "correct": "c", "rationale": "all 6% Easy Evidence-based practice indicates that, following a sentinel event, the first step the committee should take is to conduct a RCA to identify the B I a underlying cause or causes that led to the medication errors. Other sentinel events identified by The Joint Commission include: + Suicide of client receiving care D | % + Discharge of an infant to incorrect family + Unintended retention of a foreign object in a client following an invasive procedure + Perform invasive procedure on the wrong client or at the wrong site; perform incorrect procedure", "whyNot": {"a": "The committee should recommend a medication administration program to educate nurses about preventing medication errors.", "b": "The committee should ensure competency in medication administration to prevent medication errors from occurring. However, evidence-", "d": "The committee should involve nurses who administer medication in quality improvement programs to assist nurses in preventing"}, "keyConcept": "A nurse who is participating on a quality improvement committee following a sentinel event should be able to assist with conducting a root cause analysis (RCA). The purpose of an RCA is to identify the practices that led to the event. Focusing on systems and processes, not individual performance, the RCA can assist the committee to determine organizational improvements that are needed to prevent this type of event from occurring again."}, {"id": 10303, "cat": "LEADERSHIP", "stem": "A nurse is completing an incident report for a client who has fallen. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Make a copy of the incident report for the provider."}, {"id": "b", "t": "Submit the incident report to the risk manager."}, {"id": "c", "t": "Place the incident report in the client's medical record."}, {"id": "d", "t": "Document in the medical record that an incident report has been filed."}], "correct": "b", "rationale": ", who will investigate the OR r T7798 incident and work with other members of the healthcare team to reduce the risk for client injury. chi 6%", "whyNot": {"a": "The nurse should not make a copy of the incident report, because incident reports are confidential tools used by the facility to improve", "c": "The nurse should never place an incident report in the client's medical record because incident reports are confidential tools used by the", "d": "The nurse should document information about the fall and the client's condition but should never document that the incident report was"}, "keyConcept": "All unusual occurrences are recorded on an incident report form. Incidents that require the completion of an incident report can include a visitor fall or injury, medication error, not following a provider's prescription, an error in technique or procedure, or malfunctioning equipment. The incident report form should include the date, time, and place of the incident. The nurse should include a description of the occurrence with subjective and objective data, including the names of witnesses, medications by name and dosage, and equipment numbers. Nurses should never place a completed incident report form on the client's medical record or indicate in the client's medical record that one was completed. The nurse should document information about the fall or occurrence in the client's medical record. Incident reports are confidential tools used by the facility to improve client care."}, {"id": 10304, "cat": "LEADERSHIP", "stem": "which of the following torts? O A. Assault O B. Invasion of privacy O C. Negligence O D. Battery", "choices": [{"id": "a", "t": "Assault"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Negligence"}, {"id": "d", "t": "Battery"}], "correct": "d", "rationale": "Battery is physical contact with the client without the client's consent. Administering a medication against a client's wishes is an example of battery. A client can make a charge of battery against a nurse who failed to obtain permission to touch the client even if there was no harm or injury to the client.", "whyNot": {"a": "Assault is the act of causing a client to fear that they will be touched without their consent. This often involves the use of verbal threats,", "b": "Invasion of privacy is an intentional tort that occurs when a client's private information is shared with others without the client's consent.", "c": "Negligence is an unintentional tort that involves actions that do not meet the established standard of care and results in harm to the"}, "keyConcept": "Atort is a civil wrong committed against a client or their property. Nurses are at risk for committing intentional torts, which involve a direct violation of the client's legal rights. Examples of intentional torts include assault, battery, defamation of character, false imprisonment, invasion of privacy, and intention of causing emotional distress."}, {"id": 10305, "cat": "LEADERSHIP", "stem": "A nurse is documenting in the electronic health record of a client. An assistive personnel (AP) requests to use the computer to input a client's timed vitals. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Stay logged in and allow the AP to use the computer."}, {"id": "b", "t": "Ask the AP to come back later when the computer is available."}, {"id": "c", "t": "Input the client vitals for the AP."}, {"id": "d", "t": "Request that the AP use another computer that is not in use."}], "correct": "d", "rationale": ". This ensures client confidentially is maintained and data is entered B I a in the computer in a timely manner. If one is not available, the nurse should log off and allow the AP to use the computer.", "whyNot": {"a": "The nurse should not allow the AP to use the computer while the nurse is still logged in. Staff members should not share passwords or", "b": "The AP needs to input the data as soon as possible because it is a timed set of vital signs; therefore, the nurse should not ask the AP to", "c": "The nurse should only document care that they provide and not document care for anyone else."}, "keyConcept": "When documenting in a client's electronic health record, the nurse is accountable for any information entered under their login. The nurse should never share their password with any other staff member or stay logged in while another staff member uses the computer. If data needs to be documented and is time-sensitive, the nurse should recommend the AP use another computer. If one is not available, the nurse should log off and allow the AP to use the computer."}, {"id": 10306, "cat": "LEADERSHIP", "stem": "a violation of the client's rights and is an example of which of the following torts?", "choices": [{"id": "a", "t": "Slander"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Malpractice"}, {"id": "d", "t": "False imprisonment"}], "correct": "d", "rationale": "Unlawfully restraining a client is an example of false imprisonment. The nurse should instruct the AP that the use of restraints can increase the risk for serious injury to the client and should only be used to protect the client from injury to self or others.", "whyNot": {"a": "Making false statements that damage a client's reputation is slander, which is a form of defamation of character. Libel is written", "b": "The invasion of privacy is a quasi-intentional tort in which the client's right to privacy is violated. The HIPAA and Health Information", "c": "Malpractice is a form of professional negligence in which the actions of the nurse do not meet the established standard of care, resulting in"}, "keyConcept": "Restraining a client involves restricting the movement or activity of a client using mechanical or chemical means. The use of restraints is limited to ensuring the safety of the client or those around the client. Regulations established by The Joint Commission and the Centers for Medicare and Medicaid Services, as well as facility policies, describe the use and limitations of restraints in addition to the requirements for ongoing assessment and documentation."}, {"id": 10307, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who had a stroke 3 days ago and has developed dysphagia. The nurse should identify that a referral to which of the following members of the interdisciplinary team is the priority?", "choices": [{"id": "a", "t": "Pharmacist"}, {"id": "b", "t": "Occupational therapist"}, {"id": "c", "t": "Dietitian"}, {"id": "d", "t": "Speech therapist"}], "correct": "d", "rationale": "The greatest risk to a client who has dysphagia is aspiration due to the inability to swallow. Therefore, a speech therapist is the priority referral for this client.", "whyNot": {"a": "While a pharmacist plays an important role in the care of a client who has had a stroke, the development of dysphagia could be life-", "b": "While the occupational therapist will assist the client to gain skills to perform activities of daily living, the development of dysphagia could", "c": "While the dietitian will evaluate the client and assist with determining dietary needs following the stroke, the development of dysphagia"}, "keyConcept": "When caring for a client who has had a stroke, the nurse should assess the client for the presence of a facial droop, drooling, hoarse voice, and inability to cough on command or close their mouth. Impaired function of cranial nerves V, VII, IX, X, or XII can additionally identify clients who are at risk for aspiration pneumonia, constipation, dehydration, and malnutrition due to dysphagia. The client should be kept completely NPO if any alterations are noted in these assessments. A referral to a speech-language pathologist is a priority intervention so that a comprehensive bedside swallowing evaluation can be completed. Cranial Nerve Vv Vu Ix XII Function Chewing Facial movement Swallowing Swallowing Tongue movement Assessment Ask client to clench teeth Ask client to smile, frown, and puff out cheeks Ask client to move their tongue from slide to side and up and down Assess client's speech for hoarseness Ask client to stick out their tongue and move it from side to side"}, {"id": 10308, "cat": "LEADERSHIP", "stem": "A nurse is planning an education program about heart health for adults in the community. Which of the following principles should the nurse use when planning the program?", "choices": [{"id": "a", "t": "The program should be teacher-directed."}, {"id": "b", "t": "The content of the program should be problem-centered."}, {"id": "c", "t": "The goals of the program should be set by the teacher."}, {"id": "d", "t": "The program should be conducted in a formal atmosphere."}], "correct": "b", "rationale": "A i 10% Moderate An education program designed for adult learners should be problem-centered rather than subject-centered. The nurse should recognize OB a GY that adult clients typically learn better if they feel that the information is pertinent to them. ° ci 11%", "whyNot": {"a": "When planning education for adults, the nurse should prepare programs that are self-directed by the learner. The nurse should recognize", "c": "When planning education for adults, the nurse should prepare programs in which the teacher collaborates with the learners set the goals.", "d": "When planning education for adults, the nurse should conduct programs in an informal and relaxed atmosphere. The nurse should"}, "keyConcept": "Adults have different learning needs than children. Therefore, when planning education programs for adults, nurses should use different strategies than those used to education children. According to the work of learning theorist John Knowles, adults are self-directed, internally motivated, and are problem-focused rather than subject-centered. Adults typically learn best when they feel there is a need for the subject matter being taught. Some adults also have unique barriers to learning such as a lack of time, energy, or self-confidence."}, {"id": 10309, "cat": "LEADERSHIP", "stem": "the provider in the client's chart. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Call the emergency response team."}, {"id": "b", "t": "Notify the risk manager of the situation."}, {"id": "c", "t": "Call the provider for a stat DNR order."}, {"id": "d", "t": "Respect the family's wishes and withhold any treatment."}], "correct": "a", "rationale": "Unless the provider writes a DNR order, the nurse should make every effort to revive the client. The nurse should follow the facility's protocol B I a for enacting the emergency response procedure. ci 10%", "whyNot": {"b": "The risk manager should be notified in the event of accidents or injuries in the facility. The risk manager's role is to reduce preventable", "c": "The provider must consult with the client and family to discuss the DNR request before placing an order on the client's chart. Even though", "d": "Despite the wishes of the family for the client to experience the progression of death without interference, the nurse is legally required to"}, "keyConcept": "The nurse should actively engage the client and family in discussions regarding health care goals, including end-of-life care. The nurse should also ensure that discussions regarding the client's wishes occur between the client, the family or surrogate, and members of the healthcare team and that the actions taken are in line with the wishes of the client."}, {"id": 10310, "cat": "LEADERSHIP", "stem": "A nurse is observing an assistive personnel (AP) who is bathing a client in bed. The nurse should identify that which of the following actions by the AP indicates correct technique?", "choices": [{"id": "a", "t": "Pulling the curtain around the client's bed"}, {"id": "b", "t": "Washing the client's perineal area first"}, {"id": "c", "t": "Using a washcloth to wipe the client's eyes from the outer canthus to the inner canthus"}, {"id": "d", "t": "Filling the bath basin with tap water that is 39° C (102.2° F)"}], "correct": "a", "rationale": "The AP is following the correct procedure by closing the door to the client's room and pulling the curtain around the client's bed because B | 3\" these actions promote the client's right to privacy. cf 4%", "whyNot": {"b": "It is the responsibility of the nurse to evaluate if tasks are performed per policy and procedure. The nurse should instruct the AP to wash", "c": "It is the responsibility of the nurse to evaluate if the tasks are performed per policy and procedure. The nurse should instruct the AP to use", "d": "It is the responsibility of the nurse to evaluate if the tasks are performed per policy and procedure. The nurse should instruct the AP to"}, "keyConcept": "Asa leader, it is the responsibility of the nurse to assign the AP tasks within their range of function and to evaluate if the tasks are performed per policy and procedure. When performing a bed bath, the client's privacy should be maintained by closing the door and pulling the divider curtains to surround the bed because performing personal hygiene requires privacy. The nurse should assess if the client can perform part of the bath and then inform the AP. The nurse should evaluate if the AP is performing the bed bath from the client's cleanest areas to the client's least clean areas. If the AP is not performing the bathing task per protocol, it is the nurse's responsibility to intervene and show the AP how to perform the task."}, {"id": 10311, "cat": "LEADERSHIP", "stem": "A nurse is assessing a client who experienced a traumatic brain injury. Which of the following findings is the nurse's priority?", "choices": [{"id": "a", "t": "Glasgow coma scale score of 10"}, {"id": "b", "t": "BP dropped from 150/74 to 143/80 mm Hg in 1 hr"}, {"id": "c", "t": "Pupils are round and 6 mm in diameter O D.3.cm (1 in) clear drainage from client's ear on gauze dressing"}, {"id": "d", "t": "This finding is a priority because clear drainage from the client's ears or nose can indicate that a tear in the dura has occurred, which causes cerebral spinal fluid to drain."}], "correct": "d", "rationale": "This finding is a priority because clear drainage from the client's ears or nose can indicate that a tear in the dura has occurred, which causes cerebral spinal fluid to drain. This is a serious condition because a tear in the dura enables organisms can gain access to the cranial contents and cause meningitis.", "whyNot": {"a": "The Glasgow coma scale is used to determine a client's level of consciousness. The highest possible score is 15. A score of 8 or less is an", "b": "The nurse should continue to monitor the client's BP for the presence of a widening pulse pressure, which is a late indication of increased", "c": "Changes in pupillary response are an indication of increased intracranial pressure. Pupils that are round and 6 mm in diameter are within"}, "keyConcept": "A client who has experienced a traumatic brain injury is at risk for numerous complications, including increased intracranial pressure, ineffective respiratory status, infection, cerebral edema, coma, and brain herniation. The nurse should carefully monitor the client's neurological status because sudden changes in the client's status might indicate a need for immediate intervention."}, {"id": 10312, "cat": "LEADERSHIP", "stem": "A nurse is teaching a client about choosing a health care surrogate. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| can change who | designate as my health care surrogate as long as | have my provider's approval.\" O B. \"If | become incapacitated, end-of-life choices will be made by my health care surrogate.\" O C. \"I have to choose a family member as my health care surrogate.\" O D. \"I can verbally indicate to my nurse who | want to assign as my health care surrogate.\"", "choices": [{"id": "a", "t": "The client's provider does not need to approve changes to a client's advance directives."}, {"id": "b", "t": "al 5% Easy The client's health care surrogate is permitted to make decisions on behalf of the client when a client is in the final stages of illness."}, {"id": "c", "t": "The nurse should inform the client that the health care surrogate does not have to be a family member. The client's health care surrogate"}, {"id": "d", "t": "4%"}], "correct": "b", "rationale": "al 5% Easy The client's health care surrogate is permitted to make decisions on behalf of the client when a client is in the final stages of illness. This OB Tr tsisSdY eer occurs when the client becomes incapacitated and is no longer able to make decisions, referred to as decision ally incompetent or decision ally incapacitated. The client's living will typically include the following information: c ! 2% D 4% + Designation of the health care surrogate + Specific information about the care the client will accept, including the treatments and procedures that can and cannot be implemented + Authorization for the client's provider to withhold or discontinue life-saving treatments and the specific conditions for which it applies", "whyNot": {"a": "The client's provider does not need to approve changes to a client's advance directives.", "c": "The nurse should inform the client that the health care surrogate does not have to be a family member. The client's health care surrogate", "d": "A living will indicate the client's designated health care surrogate must be a written document. Some states even require a client's living"}, "keyConcept": "The nurse is responsible for reviewing information with the client regarding living wills and health care surrogates. The nurse should inform the client about how to designate a surrogate, the responsibilities of the surrogate, and when the surrogate is able to make decisions for the client."}, {"id": 10313, "cat": "LEADERSHIP", "stem": "demonstrating which of the following ethical principles?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Autonomy"}, {"id": "c", "t": "Justice"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "d", "rationale": "The ethical principle of nonmaleficence is demonstrated by taking actions to prevent client harm. When the nurse completes an advanced education program to provide safe care in the ICU, the nurse is demonstrating the ethical principle nonmaleficence.", "whyNot": {"a": "The ethical principle of veracity is the duty to tell the truth.", "b": "The ethical principle of autonomy is respecting the client's right to make decisions about health care.", "c": "The ethical principle of justice is the duty to treat everyone equally, regardless of sex, gender identity, sexual orientation, race, culture, or"}, "keyConcept": "Nurses have an obligation to help others and promote the general good while doing no harm. When the nurse completes an advanced education program to provide safe care, the nurse is demonstrating the ethical principle nonmaleficence."}, {"id": 10314, "cat": "LEADERSHIP", "stem": "A nurse is preparing to delegate tasks to an LPN and an assistive personnel (AP). Which of the following tasks should the nurse assign to the LPN?", "choices": [{"id": "a", "t": "Transporting a client who experienced a stroke 72 hr ago to the radiology department"}, {"id": "b", "t": "Providing a back rub to a client who has right-sided paralysis"}, {"id": "c", "t": "Removing and cleaning the cannula of a client who has a stable, exisiting tracheostomy"}, {"id": "d", "t": "Emptying the drainage from the ostomy bag of a client who has a new colostomy"}], "correct": "c", "rationale": ", specialized knowledge, and clinical judgment; B I a therefore, this task should be delegated to the LPN.", "whyNot": {"a": "The nurse should consider the job descriptions and educational preparation of the staff members when delegating tasks. The AP should", "b": "APs are trained on how to properly turn a client and perform a back rub; therefore, this task is within the AP's range of function and can be", "d": "The delegation of tasks to an AP should be limited to tasks involving the provision of care to meet basic ADLs, such as bathing and"}, "keyConcept": "The nurse should base the assignment of tasks on the staff member's educational preparation and skill level, along with legal and licensure statutes. The nurse should also determine whether the staff member has the knowledge to complete the assigned task and provide clear and concise instructions to the staff member regarding the time frame during which the task should be completed and reported to the nurse."}, {"id": 10315, "cat": "LEADERSHIP", "stem": "assign to the RN? O A. A client who has an evolving myocardial infarction O B. A client who has acute pancreatitis O C. A client who is 1 day postoperative following a total abdominal hysterectomy O D. A client who is being admitted following a stroke", "choices": [{"id": "a", "t": "A client who has an evolving myocardial infarction"}, {"id": "b", "t": "A client who has acute pancreatitis"}, {"id": "c", "t": "A client who is 1 day postoperative following a total abdominal hysterectomy"}, {"id": "d", "t": "A client who is being admitted following a stroke"}], "correct": "c", "rationale": "A C. This client is stable. The RN who has a background in maternal-newborn care will have the knowledge and skills to manage the care for a B L postoperative client who has had gynecologic surgery. o:", "whyNot": {"a": "Floating of professional staff can fill needed services on units and reduce staffing costs. However, the Joint Commission and nursing case", "b": "The nurse who floats to another unit must have the skills to provide safe care to clients. This client requires specialized care and skills that", "d": "When making client assignments, the charge nurse should consider the skills and knowledge of any staff who are floating. Client"}, "keyConcept": "Nurses who are assigned to float to another unit have a responsibility to report to the charge nurse and refuse tasks that they cannot perform safely and competently. It is not unreasonable for a floating nurse to request orientation to an unfamiliar unit and to have a resource nurse available to assist as needed."}, {"id": 10316, "cat": "LEADERSHIP", "stem": "A nurse receives a needle stick injury while administering IM pain medication to a client. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Complete an incident report."}, {"id": "b", "t": "Ask the risk manager to obtain consent for blood testing from the client."}, {"id": "c", "t": "Wash the site of the injury with soap and water."}, {"id": "d", "t": "Allow the puncture site to bleed freely."}], "correct": "c", "rationale": "The greatest risk to the nurse is transmission of an infection. Therefore, the first step the nurse should take is to wash the area with soap and water to reduce the risk for transmission. The nurse should also obtain postexposure prophylaxis, if needed.", "whyNot": {"a": "The nurse should complete an incident report to provide risk management with the information needed for follow-up. However, there is", "b": "The nurse should have the risk manager obtain consent from the client for blood testing to determine if the client has HIV, hepatitis B, or", "d": "The nurse should allow the puncture wound to bleed, without squeezing the site, to drain the blood from the site. However, there is"}, "keyConcept": "A nurse who receives a needle stick when administering a medication has the responsibility to report the incident as soon as possible. The nurse should follow the postexposure protocol indicated below: HIV + Treatment should begin as soon as possible following the exposure. Treatment can be less effective when started more than 24 hr postexposure. + Three-medication treatment is the recommendation for high risk and increased risk exposure. Two-medication treatment is recommended for low-risk exposure. + HIV antibody tests should be performed shortly after exposure and at 6 weeks, 3 months, and 6 months after exposure. Hepatitis B + Complete Anti-HBs testing after the last vaccine. + Administer hepatitis B immunoglobulin and/or hepatitis B vaccine within 1 to 7 days following exposure for nonimmune workers. Hepatitis C + Complete the Anti-HCV testing and ALT testing at baseline and 4 to 6 months after exposure."}, {"id": 10317, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who is scheduled for surgery. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Identify the client with one identifier before marking the surgical site."}, {"id": "b", "t": "Explain the risks and benefits of the procedure."}, {"id": "c", "t": "Review preoperative laboratory test results."}, {"id": "d", "t": "Contact an attorney to review the advance directives."}], "correct": "c", "rationale": "al 4% Easy The nurse should review preoperative laboratory test results to determine if any values are outside the expected reference range and could B I a cause surgical complications.", "whyNot": {"a": "The nurse should identify the client with at least two identifiers before marking the surgical site. These identifiers include comparing the", "b": "Explaining the risks and benefits of the procedure is the responsibility of the provider who is performing the procedure , not the nurse.", "d": "The nurse does not need to contact an attorney to review the advance directives, but there must be witnesses to the signing of the"}, "keyConcept": "When preparing a client for surgery, it is important the nurse ensure the client’s safety. The nurse should function in the role of an educator, advocate, and encourager to maintain and improve the health of the client. Before any procedure or preoperative action is taken, the nurse confirms the identity of the client using two identifiers. These identifiers include comparing the facility number on the client's identification band with the medical record number and asking the client to state their name and date of birth. Collecting data about the client's medical history, allergies, medications, area of the surgical site, and past procedures provides the nurse with necessary information to be an advocate for the client and report findings to the provider. The nurse also reviews laboratory data and notifies the provider of the results if any values are below or above the expected reference range. The nurse completes a cardiopulmonary assessment, assesses for manifestations of infection, notes any manifestations that contraindicates surgery, and reports any condition before the surgical procedure proceeds. Encouraging the client to sign advance directives before a surgical procedure involves the nurse educating the client about advance directives."}, {"id": 10318, "cat": "LEADERSHIP", "stem": "A nurse is planning care for a client who has anorexia nervosa and has been admitted for cardiac arrhythmias. Which of the following client goals should the nurse identify as the priority?", "choices": [{"id": "a", "t": "Attain a weight that is greater than the 75th percentile for ideal body weight."}, {"id": "b", "t": "Acknowledge misperceptions about body image."}, {"id": "c", "t": "Verbalize having a sense of control over behaviors."}, {"id": "d", "t": "Identify changes within the client's family unit that promote the client's autonomy."}], "correct": "a", "rationale": "oc. i 50% Hard A client who is less than 75% of their ideal body weight is at increased risk for systemic complications, including arrhythmias, electrolyte B | Dan imbalances, cerebral atrophy, and renal failure. When using Maslow's hierarchy of needs, the nurse should determine the priority goal is to meet the physiological need for adequate nutrition. This means working with the client to attain an increase in weight. c |_| 16% off ™%", "whyNot": {"b": "A client who has anorexia nervosa can have a severely distorted body image, such as viewing themselves as fat despite obvious", "c": "A client who has anorexia nervosa can experience obsessions, such as thinking constantly about food to the extent that food is concealed", "d": "Family members can experience a sense of powerlessness and guilt about the client's diagnosis. Family therapy works toward developing"}, "keyConcept": "Priority setting involves establishing a sequence for addressing client needs. One framework that is often used for establishing priorities is Maslow's hierarchy of needs. The nurse should also recognize that priorities can change over time, so reassessment of client's needs is important."}, {"id": 10319, "cat": "LEADERSHIP", "stem": "A nurse is delegating client care to a team of staff members. Which of the following tasks should the nurse assign to an assistive personnel (AP)?", "choices": [{"id": "a", "t": "Set up a sterile field for a surgical dressing change."}, {"id": "b", "t": "Obtain a scheduled blood glucose reading from a client."}, {"id": "c", "t": "Instruct a client about how to use an incentive spirometer following surgery."}, {"id": "d", "t": "Administer a rectal suppository to a client who has constipation."}], "correct": "b", "rationale": "al 3% Easy The nurse should assign the AP to obtain a scheduled serum blood glucose reading from a client. This task is within the range of function for OB Ts 1% the AP because the client is stable. ° c | 3%", "whyNot": {"a": "The nurse should assign the task of setting up a sterile field for a dressing change to a nurse. This task requires the skill of assessing the", "c": "The nurse should assign a nurse to instruct a client about how to use an incentive spirometer. This task requires the skills of evaluating the", "d": "The nurse should assign a nurse to administer a rectal suppository to a client who has constipation. This task requires the skill of"}, "keyConcept": "When delegating client care to staff members, the nurse should be aware of the skills required for each task being delegated and determine whether it is within the range of function for an AP or within the scope of practice for a nurse."}, {"id": 10320, "cat": "LEADERSHIP", "stem": "following tasks should the nurse delegate to the AP?", "choices": [{"id": "a", "t": "Change the abdominal dressing."}, {"id": "b", "t": "Obtain dressing supplies."}, {"id": "c", "t": "Palpate for possible bladder distention."}, {"id": "d", "t": "Notify the provider."}], "correct": "b", "rationale": "al 2% Easy A client who is 1 day postoperative and develops incisional bleeding might be unstable, limiting the tasks the AP can safely perform for this client. Obtaining the needed dressing supplies is within the range of function of an AP. Therefore, the nurse can delegate this task to the AP. OE Pe hi) Additionally, this will allow the nurse to remain with the client. c | 2% oy 6%", "whyNot": {"a": "The components of the nursing process (assessment, diagnosis, planning, intervention, and evaluation) cannot be delegated to an AP.", "c": "Because the client's surgical site is close to the bladder, potential complications involving urinary retention are possible. Palpating the", "d": "When notifying the provider regarding a client's change in condition, the use of communication tools, such as the SBAR, can provide"}, "keyConcept": "Delegation is used in emergency situations as well as during routine client care. The nurse should always follow the state's Nurse Practice Act and facility policies and procedures with regard to delegation. Assigning a task to the AP that is outside of the AP's range of function places the client's safety in jeopardy and can ultimately have a negative impact on the employment status and the licensure of the nurse."}, {"id": 10321, "cat": "LEADERSHIP", "stem": "continued treatment against the client's wishes is a violation of which of the following ethical principles?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Autonomy O c.utility"}, {"id": "d", "t": "Justice"}], "correct": "b", "rationale": "The nurse should identify that the client has the right to make his own decisions regarding health care. The ethical principle of autonomy applies to an individual's right to choose and control their care. Respecting autonomy requires the nurse to recognize that the client's choice is based on his own personal values, and those values might not be shared by the nurse. Incorrect: ACD A. The ethical principle of veracity requires the nurse to tell the truth and not to intentionally deceive or mislead clients. C. The ethical principle of utility requires the nurse to prioritize the well-being of people over the needs of an individual. D. The ethical principle of justice requires the nurse to treat everyone fairly.", "whyNot": null, "keyConcept": "The nurse should identify that the client has the right to make his own decisions regarding health care. If a client chooses to discontinue treatment, the nurse should notify the provider and ensure that the client is aware of the consequences of this decision. By performing this action, the nurse is demonstrating the ethical principle of autonomy."}, {"id": 10322, "cat": "LEADERSHIP", "stem": "intervene? O A. The nurse places a new needle on the syringe after withdrawing the medication from a vial. O B. After cleansing the injection site, the nurse uses the nondominant hand to pull the tissue laterally 3 cm (1.2 in). O C. After the medication is completely injected, the nurse immediately withdraws the needle. O D. The nurse uses the dominant hand to inject the medication at a 90° angle.", "choices": [{"id": "a", "t": "The nurse places a new needle on the syringe after withdrawing the medication from a vial."}, {"id": "b", "t": "After cleansing the injection site, the nurse uses the nondominant hand to pull the tissue laterally 3 cm (1.2 in)."}, {"id": "c", "t": "After the medication is completely injected, the nurse immediately withdraws the needle."}, {"id": "d", "t": "The nurse uses the dominant hand to inject the medication at a 90° angle."}], "correct": "c", "rationale": "A Hi 18% Moderate After injecting the medication, the nurse should wait for 10 seconds before withdrawing the needle. Waiting 10 seconds allows the B rt mu fo medication to disperse into the muscle tissue. This action reduces discomfort at the injection site and prevents the medication from seeping up the track of the needle. ec | 53% oii 8%", "whyNot": {"a": "The nurse should replace the needle after withdrawing the medication from a vial. This action prevents irritation to the subcutaneous", "b": "The nurse should take this action to reduce the escape of the medication into the subcutaneous tissue after the medication is injected.", "d": "The nurse should inject the medication at a 90° angle. This action ensures that the medication reaches the client's muscle tissue."}, "keyConcept": "The Z-track technique for intramuscular injection is used with medications that are very irritating to the tissue. The nurse should pull the skin and tissue taut and firmly holds them in this position while the needle is inserted and the medication is injected. The nurse should wait to remove the needle and release the tissue for ten seconds after injecting the medication. These steps encase the medication in the client's muscle tissue and prevent the medication from irritating subcutaneous tissue. Iron dextran is an example of a medication that should be administered using the Z-track technique. Policy at some facilities requires use of the Z-track technique for all medications administered intramuscularly."}, {"id": 10323, "cat": "LEADERSHIP", "stem": "tasks to the assistive personnel (AP). Which of the following statements should the nurse manager make to the staff nurse? O A.\"| need to talk to you about unit expectations regarding delegating and completing tasks.\" O B. \"Several staff members have commented that you don't do your fair share of the work.\" O C. \"If you don't do your share of the work, | will have to file a written admonishment.\" O D. \"You have been very inconsiderate of others by not completing your share of the work.\"", "choices": [{"id": "a", "t": "This statement opens the conversation in a nonthreatening way."}, {"id": "b", "t": "This statement is aggressive and nontherapeutic. Accusing the staff nurse of failing to do a fair share of the work can cause the staff nurse"}, {"id": "c", "t": "This statement is punitive. The nurse manager should converse with the nurse and obtain more information before threatening"}, {"id": "d", "t": "This statement is aggressive and nontherapeutic. The nurse manager should obtain more information before determining the need for"}], "correct": "a", "rationale": "This statement opens the conversation in a nonthreatening way. The focus is on the issue of the equity of the assignment rather than on any personal characteristic of the individual.", "whyNot": {"b": "This statement is aggressive and nontherapeutic. Accusing the staff nurse of failing to do a fair share of the work can cause the staff nurse", "c": "This statement is punitive. The nurse manager should converse with the nurse and obtain more information before threatening", "d": "This statement is aggressive and nontherapeutic. The nurse manager should obtain more information before determining the need for"}, "keyConcept": "The nurse should identify important steps in conflict resolution, which include focusing on the issues causing the conflict rather than verbally attacking the other individual. Other techniques include the use of active listening to gain an understanding of the other individual's perspective and to approach the conflict as a problem to be solved collaboratively."}, {"id": 10324, "cat": "LEADERSHIP", "stem": "A nurse is planning care for a group of clients and assigning tasks to a licensed practical nurse (LPN) and an assistive personnel (AP). Which of the following tasks should the nurse assign to the LPN?", "choices": [{"id": "a", "t": "Complete an admission assessment for a client who has COPD."}, {"id": "b", "t": "Measure the drainage of a client who has a closed-suction drain."}, {"id": "c", "t": "Reinforce teaching to a client about taking enoxaparin at home following a hip arthroplasty."}, {"id": "d", "t": "Develop a plan of care for a client who has cholecystitis."}], "correct": "c", "rationale": "-administration of a medication. However, the LPN can B | TR reinforce the teaching because this is within the scope of practice for an LPN. °", "whyNot": {"a": "It is not within the scope of practice for an LPN to complete an admission assessment. The LPN can collect data, but an RN must complete", "b": "Even though measuring the output of a closed-suction drain is within the scope of practice of an LPN, this task does not require a licensed", "d": "There are tasks associated with client care that the RN cannot delegate, including client teaching and aspects of the nursing process, such"}, "keyConcept": "Delegation involves the transfer of tasks or activities to another member of the health care team while retaining accountability for the client outcome. The nurse is responsible for understanding the abilities and limitations of the health care team members being delegated tasks. The nurse should focus on the five rights of delegation when determining which tasks are appropriate to delegate. The five rights include the right task, the right circumstances, the right person, the right direction, and the right supervision."}, {"id": 10325, "cat": "LEADERSHIP", "stem": "A nurse is planning to delegate tasks to an assistive personnel (AP). Which of the following factors should the nurse consider when using the five rights of delegation?", "choices": [{"id": "a", "t": "The AP's ability to prioritize"}, {"id": "b", "t": "The AP's knowledge and skill to perform the task"}, {"id": "c", "t": "The AP's work experience at the facility"}, {"id": "d", "t": "The AP's ability to complete the task without supervision"}], "correct": "b", "rationale": "| 2% Easy The right person is one of the five rights of delegation. The nurse should seek information from the AP about their individual skill level and OB rsd ower knowledge prior to delegating the task. c | 2%", "whyNot": {"a": "Although the nurse should determine the AP's ability to prioritize, this is not one of the rights of delegation.", "c": "Although the AP's work experience could be an indication of the AP's skill level, this is not one of the five rights of delegation.", "d": "The nurse maintains accountability for supervising the AP; therefore, this is not one of the five rights of delegation."}, "keyConcept": "A nurse who is planning to delegate tasks should be able to identify and satisfy the five rights of delegation. The nurse should not delegate a task if the five rights are not met. The five rights of delegation include:"}, {"id": 10326, "cat": "LEADERSHIP", "stem": "for continued mental health care? O A. Partial hospitalization program O B. Crisis stabilization units O C. Community mental health center O D. Primary care provider", "choices": [{"id": "a", "t": "Partial hospitalization program"}, {"id": "b", "t": "Crisis stabilization units"}, {"id": "c", "t": "Community mental health center"}, {"id": "d", "t": "Primary care provider"}], "correct": "a", "rationale": "eo. ia 27% ~~ ‘Hard The nurse should identify that a client who has been newly diagnosed with schizophrenia and is ready for discharge from an inpatient B I a setting will still require intensive care. Therefore, the nurse should include information about partial hospitalization programs as part of the continuum of care. These programs are designed to assist clients to transition from an inpatient setting. Partial hospitalization programs © | Cs meet 5 days per week, for about 6 hr per day.", "whyNot": {"b": "Crisis stabilization units are typically short term overnight stays, frequently 1 to 3 days. They are used for clients who have symptoms that", "c": "A client newly diagnosed with schizophrenia and being discharged from an inpatient facility would require a higher level of care to", "d": "The nurse should identify that a client who has been newly diagnosed with schizophrenia and is ready for discharge from an inpatient"}, "keyConcept": "It is important for the nurse to develop an understanding of the continuum of psychiatric mental health care and recognize what resource would best meet the needs of the client. Typically, clients who require an acute level of care should gradually decrease the intensity of the care provided in order to maintain initial improvement. Failure to gradually reduce the level of care and continue outpatient treatment increases the risk of relapse."}, {"id": 10327, "cat": "LEADERSHIP", "stem": "A nurse navigator is assuming the care of a client who has a new diagnosis of cancer and will be living at home with their family. Which of the following tasks is the responsibility of the nurse navigator?", "choices": [{"id": "a", "t": "Assist the client and family in finding community resources."}, {"id": "b", "t": "Provide in-home care for the client."}, {"id": "c", "t": "Attend medical appointments with the client."}, {"id": "d", "t": "Obtain funds and grants to financially assist the client."}], "correct": "a", "rationale": "Itis the responsibility of the nurse navigator to assist the client and family to find community resources. Often, the nurse navigator will work B | Ase with a social worker who has expertise in this area. The nurse navigator serves as a clinician, care coordinator, educator, and counselor to assist the client and family during the course of an illness. c | 5% p| 2%", "whyNot": {"b": "While the nurse navigator can assist the family with coordinating care with other health-care providers, it is not the responsibility of the", "c": "While coordinating medical appointments and schedules for the client is a responsibility of the nurse navigator, attending the", "d": "The role of the nurse navigator is to assist the client and family to navigate the health care system by providing education and support. It"}, "keyConcept": "The role of nurse navigator is a relatively new role for nurses. The nurse's responsibility within this position is to help clients and families throughout the course of an illness. The nurse navigator serves as a guide, resource, advocate, educator, and liaison for newly diagnosed clients and their families."}, {"id": 10328, "cat": "LEADERSHIP", "stem": "A nurse navigator is assuming the care of a client who has a new diagnosis of cancer and will be living at home with their family. Which of the following tasks is the responsibility of the nurse navigator?", "choices": [{"id": "a", "t": "Assist the client and family in finding community resources."}, {"id": "b", "t": "Provide in-home care for the client."}, {"id": "c", "t": "Attend medical appointments with the client."}, {"id": "d", "t": "Obtain funds and grants to financially assist the client. eck Answer"}], "correct": "a", "rationale": "‘i Itis the responsibility of the nurse navigator to assist the client and family to find community resources. Often, the nurse navigator will work B | with a social worker who has expertise in this area. The nurse navigator serves as a clinician, care coordinator, educator, and counselor to assist the client and family during the course of an illness. c |", "whyNot": {"b": "While the nurse navigator can assist the family with coordinating care with other health-care providers, it is not the responsibility of the", "c": "While coordinating medical appointments and schedules for the client is a responsibility of the nurse navigator, attending the", "d": "The role of the nurse navigator is to assist the client and family to navigate the health care system by providing education and support. It"}, "keyConcept": "The role of nurse navigator is a relatively new role for nurses. The nurse's responsibility within this position is to help clients and families throughout the course of an illness. The nurse navigator serves as a guide, resource, advocate, educator, and liaison for newly diagnosed clients and their families."}, {"id": 10329, "cat": "LEADERSHIP", "stem": "A nurse is providing dietary teaching to a client who has dysphagia following a stroke. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"Rest for 15 minutes prior to meals.\""}, {"id": "b", "t": "\"Place food in the weaker side of your mouth to chew.\""}, {"id": "c", "t": "\"Sit up in a chair for 20 minutes after eating.\""}, {"id": "d", "t": "\"Flex your head with your chin tucked down to assist with swallowing.\""}], "correct": "d", "rationale": "A nurse should inform a client who has dysphagia about the risk for aspiration when eating and swallowing. The nurse should instruct the client to prevent aspiration by allowing times of rest before eating, tucking the chin while swallowing, and sitting up for 1 hr following meals.", "whyNot": {"a": "The nurse should instruct the client to rest for 30 min prior to meals. A well-rested client will have less difficulty swallowing food.", "b": "The nurse should instruct the client to place food in the unaffected side of the mouth. This aids in the chewing and swallowing of food and", "c": "The nurse should instruct the client to sit up for 60 min following meals to aid in the digestion of food and prevent aspiration."}, "keyConcept": "A nurse should inform a client who has dysphagia about the risk for aspiration when eating and swallowing. The nurse should instruct the client to prevent aspiration by allowing times of rest before eating, tucking the chin while swallowing, and sitting up for 1 hr following meals."}, {"id": 10330, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who has pneumonia. Which of the following tools should the nurse use to assist with providing cost-effective care?", "choices": [{"id": "a", "t": "Chart audit"}, {"id": "b", "t": "Practice guideline"}, {"id": "c", "t": "Acuity rating"}, {"id": "d", "t": "Critical pathway"}], "correct": "d", "rationale": "A i 10% Moderate The nurse, as well as the interdisciplinary team, should use a critical pathway as a resource for assisting with assessing, implementing, and B | Bn evaluating the cost-effectiveness of client care. The pathway is a tool that sets out a predetermined course of progress after admission for a client who has a specific diagnosis. c i 9%", "whyNot": {"a": "Achart audit is a tool the nurse can use when participating in a performance improvement project. Patterns of care can be determined", "b": "A practice guideline is a tool the nurse can use to improve the quality of care. These guidelines provide interventions for specific health", "c": "An acuity rating is a tool that nurse managers can use for assistance when determining the hours of care and the number of staff required"}, "keyConcept": "The nurse should recognize the value of critical pathways to assist in providing cost-effective care for a client who has pneumonia. As an evidence-based tool, a critical pathway can assist with improving client outcomes and evaluating the need for updating the care plan when a variance occurs."}, {"id": 10331, "cat": "LEADERSHIP", "stem": "Acharge nurse is making assignments for the oncoming shift. Which of the following considerations should the charge nurse consider when making the assignments?", "choices": [{"id": "a", "t": "The National Patient Safety Goals"}, {"id": "b", "t": "Personal comfort level in making the assignments"}, {"id": "c", "t": "Social relationships between nurses working the oncoming shift"}, {"id": "d", "t": "The physiologic status of the clients on the unit"}], "correct": "d", "rationale": "‘i Making assignments requires knowing the physiologic status of the clients on the unit, such as the stability of the clients' vital signs, the B | amount of health education they need, and the complexity of care involved. Clients who have an unstable physiologic status might require a | © higher level of skilled care.", "whyNot": {"a": "The National Patient Safety Goals are a set of objectives developed by The Joint Commission to improve client safety. While every member", "b": "The charge nurse's role requires adequate preparation and the ability to make appropriate assignments. The charge nurse should not take", "c": "The charge nurse should be aware of the right person doing the right task for the right person. Social relationships between the nurses"}, "keyConcept": "The nurse should consider five rights of delegation when delegating care or assigning tasks to members of the health care team. The five rights can be utilized whether the nurse is delegating tasks to an LPN or assistive personnel (AP) as well as when a charge nurse is making shift assignments involving all nursing personnel. Task Delegation Re secbol RN Delegating to Stall Men Tharge Nurse Making Shit, Faght Task Tislegate only tasks thal are within he Tor ‘Tie Chent care Game Tor nada elegating nurse's own scope of practice. | chenta when making assignments, An LPN or AP For assistive personne! (AP), do not imught not be legally permitted to complete some Gelegate a tase nat neues aspects of he | cient care apna of care fr cara comnts — Tigh Cra Desogate ony The ent BTS Tagh Care T COOTER CET OT OHO personnel, or provide acatonal supension # rg 10 a newer sla member RRIF — aca Ra TPR a Barn Ha renee vel and CoO AAP wo and competency evel Nana | wen wor oad aasigrmerss Practoe Act, facility Fight ‘Clear, concise with “Use Gear, concise communication Update sia Communcaten | obectves tre fare for comeieton ane | repereng acmssons vanslers, and discharges sipecatons Impacting sat asa.gnmert | Right supervison Supervise oF pr or ng | Provide iJ Li {freeded. Provide feedback o ask tevsuaton anc leesback to $a members completion by LPN or AP."}, {"id": 10332, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who is scheduled for surgery. The nurse should identify that which of the following actions is the responsibility of the nurse?", "choices": [{"id": "a", "t": "Describe the steps of the procedure"}, {"id": "b", "t": "Explain the risks involved with the procedure"}, {"id": "c", "t": "Discuss alternate treatment options"}, {"id": "d", "t": "Determine the client's level of understanding about the procedure"}], "correct": "d", "rationale": ", the nurse is responsible for ensuring the client understands the information provided by the B | a0 provider and should notify the surgeon if the client has questions.", "whyNot": {"a": "The provider is responsible for explaining the steps of the procedure to the client.", "b": "The provider should explain the risks involved with the procedure. A nurse who attempts to explain the risks involved with the procedure", "c": "Discussing alternate treatment options is the responsibility of the provider. A nurse who attempts to discuss alternate treatment options"}, "keyConcept": "Asa part of the nursing role of client advocate, the nurse is responsible for ensuring the client understands the information provided by the provider and should notify the provider if the client has questions. When a nurse witnesses an informed consent, the nurse is verifying that the client freely gave consent, that the client's signature is genuine, and that the client is competent. The provider who will be performing the procedure is responsible for explaining the procedure to be performed, any risks involved, expected outcomes, possible complications, and alternative treatment options."}, {"id": 10333, "cat": "LEADERSHIP", "stem": "feelings. The nurse keeps her promise and returns to talk with the client as soon as she finishes administering medications. Which of the following ethical principles is the nurse demonstrating?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Justice"}, {"id": "c", "t": "Nonmaleficence O b-Fidelity"}, {"id": "d", "t": "Ethics is a branch of philosophy that helps a person determine what is right and what is wrong, regardless of the consequences."}], "correct": "d", "rationale": "Ethics is a branch of philosophy that helps a person determine what is right and what is wrong, regardless of the consequences. Nurses use ethical principles to guide their practice as they fulfill their roles as an advocate for clients and their families. Compassion and accountability are required by the nurse when using ethical principles. Nurses face challenges when there is disagreement among clients, families, and other health care providers about what actions should be taken.", "whyNot": {"a": "The ethical principle of veracity is the commitment to tell the truth. Veracity leads to trust and is a critical element of the nurse-client", "b": "The ethical principle of justice involves fairness. It includes the right of clients to be treated fairly regardless of their values, life situation,", "c": "The ethical principle of nonmaleficence is the commitment to do no harm to the client. The nurse might be required to perform care that"}, "keyConcept": "Ethics is a branch of philosophy that helps a person determine what is right and what is wrong, regardless of the consequences. Nurses use ethical principles to guide their practice as they fulfill their roles as an advocate for clients and their families. Compassion and accountability are required by the nurse when using ethical principles. Nurses face challenges when there is disagreement among clients, families, and other health care providers about what actions should be taken."}, {"id": 10334, "cat": "LEADERSHIP", "stem": "demonstrates an understanding of the information? O A.\"| should log off the EMR on the client's in-room computer if | need to leave the room to collect supplies.\" O B. \"If |use worksheets for planning care for my clients, | should discard them in the wastebasket at the end of the shift.\" O C.\"I.can permit any staff member in our facility to see information on my client's EMR.\" O D.\"I can share my facility computer password with the nurses on my client's care team.\"", "choices": [{"id": "a", "t": "The nurse should log off a computer terminal in a client's room upon leaving the room, even if the nurse expects to return momentarily."}, {"id": "b", "t": "Any printed material that contains client names or other personal information should be shredded so that the material is not accessible by"}, {"id": "c", "t": "Only staff who are directly involved with a client's care should see EMR information about that client."}, {"id": "d", "t": "The nurse should not share a facility computer password with anyone else at any time. The personal computer password should be kept"}], "correct": "a", "rationale": "The nurse should log off a computer terminal in a client's room upon leaving the room, even if the nurse expects to return momentarily. B | 3\" Protection of client information should be the nurse's priority. c | 1%", "whyNot": {"b": "Any printed material that contains client names or other personal information should be shredded so that the material is not accessible by", "c": "Only staff who are directly involved with a client's care should see EMR information about that client.", "d": "The nurse should not share a facility computer password with anyone else at any time. The personal computer password should be kept"}, "keyConcept": "The nurse should take responsibility for maintaining the privacy of electronic medical records and personal health information for the clients in his care. Strictly following a few specific rules can help to prevent a breach of confidentiality that could allow unauthorized persons to view a client's personal information. The electronic medical record should be used to enhance communication and provide accurate information about the client and her care."}, {"id": 10335, "cat": "LEADERSHIP", "stem": "A nurse in an urgent care clinic is triaging clients. Which of the following clients should the nurse identify as the priority for the provider to examine?", "choices": [{"id": "a", "t": "An adolescent client who is confrontational has decreased reasoning and has slurred speech"}, {"id": "b", "t": "Atoddler who has a laceration on the forehead and is screaming"}, {"id": "c", "t": "A middle-aged client who is diaphoretic and reports epigastric pain"}, {"id": "d", "t": "Ayoung adult who has a painful sunburn over the face and arms"}], "correct": "c", "rationale": "A | | 37% Moderate When using the urgent vs. nonurgent approach to client care, the nurse should determine that caring for a middle-aged client who is B I a diaphoretic and reports epigastric pain is the highest priority because diaphoresis and epigastric pain can be manifestations of an acute myocardial infarction or other cardiac complications. ec | 58% p | 1%", "whyNot": {"a": "The list of differentials for an adolescent client who is confrontational has decreased reasoning, and has slurred speech is long. This client", "b": "The nurse should apply pressure to the site of the laceration and work with the parent to decrease the toddler's anxiety. However, there is", "d": "A young adult who has a painful sunburn over the face and arms is experiencing a superficial burn, and the provider should inspect the"}, "keyConcept": "Sorting client data and classifying clients into priority levels of who report to the urgent care unit is an organized system called triage. Clients who receive a rapid evaluation, treatment, and priority diagnostic tests have a high acuity level, and the provider should examine these client's first. The nurse should inform lower acuity clients and family members who are waiting for care why other clients are seen first. An RN is the one who generally performs the function of triaging the incoming clients. However, if there are any questions or concerns, the provider, nurse practitioner, or physician's assistant can provide input during triage."}, {"id": 10336, "cat": "LEADERSHIP", "stem": "nurse take first? O A. Check the client's medication administration record for the provider's prescription. O B. Explain the procedure to the client. O C. Assure the client that enemas are often prescribed for constipation. O D. Assist the client to the left lateral position.", "choices": [{"id": "a", "t": "Check the client's medication administration record for the provider's prescription."}, {"id": "b", "t": "Explain the procedure to the client."}, {"id": "c", "t": "Assure the client that enemas are often prescribed for constipation."}, {"id": "d", "t": "Assist the client to the left lateral position."}], "correct": "a", "rationale": "The greatest risk to this client is injury from receiving a procedure that was not prescribed. Therefore, the first action the nurse should take is to check the client's medication administration record to verify the provider prescribed an enema for the client.", "whyNot": {"b": "The nurse should explain the procedure to the client to reduce the client's anxiety. However, the nurse should take another action first.", "c": "The nurse should explain to the client that enemas are often prescribed for constipation to reassure the client and reduce the client's", "d": "The nurse should assist the client in the left lateral position to facilitate the flow of the solution into the descending colon. However, the"}, "keyConcept": "The nurse should use the five rights of medication administration to safely administer medications. The nurse should verify a provider's prescription on the medication administration record before administering a medication. If the client is not aware of a prescription or questions the medication, the nurse should double-check the prescription to make sure they are administering the right prescription to the right client. The nurse should contact the provider if the prescription is unclear or if the client questions the need for the prescription to reduce the risk for error and client injury. The Five Rights of Medication Administration Use two identifiers, such as the client's name and date of birth to identify the client. The nurse can check the Right client . . . . . . . . client's identification bracelet or ask the client to confirm the information aloud. Compare the label on the medication with the client's medication administration record three times before administering it: Right medication 1. Before removing the container from the medication drawer 2. When removing the dosage from the container 3. At the client's bedside Confirm the correct dose with the medication administration record. Double-check dosage calculations with a Right dose second nurse. Determine if the dosage is safe for the client. Confirm that the dosage is within the expected"}, {"id": 10337, "cat": "LEADERSHIP", "stem": "partner? O A. Wear clean gloves when suctioning the client's tracheostomy. O B. Rinse and dry suction catheters and reuse for up to 24 hr. O C. Empty and rinse the suction container in a sink every 24 hr. O D. Discard oral suction tubes (Yankauer) after each use.", "choices": [{"id": "a", "t": "Wear clean gloves when suctioning the client's tracheostomy."}, {"id": "b", "t": "Rinse and dry suction catheters and reuse for up to 24 hr."}, {"id": "c", "t": "Empty and rinse the suction container in a sink every 24 hr."}, {"id": "d", "t": "Discard oral suction tubes (Yankauer) after each use."}], "correct": "b", "rationale": "‘i 26% = ‘Hard In the home setting, suction catheters can be reused for up to 24 hours. Catheters should be flushed between each use utilizing distilled OB | LER water or recently boiled water and allowed to air dry. ° c i 26% Incorrect Answer: . In the home setting, it is not necessary to wear gloves when performing tracheostomy suctioning. Caregivers should wash hands with soap and water prior to performing the suctioning. C. Suction containers pose a significant infection control risk due to the presence of potential bacteria and viruses in the sections. These containers should be carefully emptied into a toilet bowl and the container should then be carefully cleaned and disinfected. The caregiver should wear a mask and gloves when performing this procedure.", "whyNot": null, "keyConcept": "The nurse should practice cost-effective care by carefully balancing the cost of equipment while also ensuring that care is safe and effective. It is important to determine whether needed equipment can be cleaned and reused or if it must be discarded after each use, while following facility protocols and maintaining practice that is evidence-based."}, {"id": 10338, "cat": "LEADERSHIP", "stem": "Acharge nurse is delegating tasks to a licensed practical nurse (LPN). Which of the following criteria is the priority for the charge nurse to consider when delegating?", "choices": [{"id": "a", "t": "Facility policies"}, {"id": "b", "t": "The acuity of the clients"}, {"id": "c", "t": "The documented skill level of the LPN"}, {"id": "d", "t": "State Nurse Practice Act"}], "correct": "d", "rationale": "| According to evidence-based practice, the nurse should first consider the state Nurse Practice Act, which provides the legal authority for B | nursing practice. A state's Nurse Practice Act specifies the qualifications and responsibilities of nurses and outlines the specific tasks that nurses can legally perform based upon their educational preparation. c |_|", "whyNot": {"a": "When planning delegation, the charge nurse should take into account a number of factors, including the policies and procedures of the", "b": "The charge nurse should consider the established standards of care when planning delegation. The professional judgement of the charge", "c": "Delegation involves nursing judgment and evaluation of the skills and educational level of the nurse being assigned to client care. The LPN"}, "keyConcept": null}, {"id": 10339, "cat": "LEADERSHIP", "stem": "A nurse is delegating tasks to an unlicensed assistive personnel (UAP). Which of the following tasks should the nurse instruct the UAP to complete first?", "choices": [{"id": "a", "t": "Obtain a capillary blood glucose for a client who is prescribed premeal insulin"}, {"id": "b", "t": "Apply a condom catheter to a client who has urge urinary incontinence."}, {"id": "c", "t": "Feed a client who has bilateral casts due to upper arm fractures."}, {"id": "d", "t": "Ambulate a client who requires the use of a walker."}], "correct": "a", "rationale": "o; When using the urgent vs. nonurgent approach to client care, the nurse should determine the priority task to delegate is the blood glucose B ] monitoring for the client who has an insulin prescription. This task is time sensitive and should be completed first.", "whyNot": {"b": "Applying a condom catheter to an incontinent client is a nonurgent task. The client will need to have this task completed to improve the", "c": "Feeding a client who has bilateral casts is a nonurgent task. The client will need to have this task completed to meet the client's nutritional", "d": "Ambulating a client is a nonurgent task. This task will need to be completed to meet the client's mobility needs. However, there is another"}, "keyConcept": "When planning care, it is important for the nurse to prioritize tasks. Prioritization is a learned skill that must be practiced before proficiency can be achieved. It requires the ability to recognize what is the urgent, such as time-sensitive medications, and what is nonurgent, such as providing discharge teaching. The nurse should also prioritize when assigning tasks to UAPs and communicate which tasks should be done before the others."}, {"id": 10340, "cat": "LEADERSHIP", "stem": "A nurse on an oncology unit accidently administered doxorubicin to the wrong client, resulting in harm to the client. This action is an example of which of the following torts?", "choices": [{"id": "a", "t": "Battery"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Malpractice"}, {"id": "d", "t": "Assault"}], "correct": "c", "rationale": "Malpractice is an unintentional tort. To be classified as malpractice, the nurse must owe a duty to the client, the nurse must breach the duty, the client must be injured, and the nurse's breach of duty must have caused the injury.", "whyNot": {"a": "Battery is an intentional tort. To be classified as battery, the nurse must have touched the client without their consent. Battery can occur", "b": "Invasion of privacy is a quasi-intentional tort. Release of a client's confidential information to an unauthorized person is an example of", "d": "Assault is an intentional tort. To be classified as assault, the nurse must threaten the client with harm, resulting in the client being fearful"}, "keyConcept": "Nurses are legally and ethically responsible for providing accountable, safe care to their clients. The failure to provide safe care can result in legal charges against the nurse. Torts fall into three categories: intentional, quasi-intentional and unintentional. During an intentional tort, the nurse initiates an act knowing it was wrong or with the intent to harm a client. In the case of both quasi-intentional and unintentional torts, the nurse does not intend to harm the client. Intentional torts Assault Battery False imprisonment Quasi-intentional torts Invasion of privacy Defamation of character Unintentional torts Negligence Malpractice"}, {"id": 10341, "cat": "LEADERSHIP", "stem": "A nurse is preparing to contact a provider regarding a client. When using the SBAR communication tool, which of the following statements should the nurse include in the B step?", "choices": [{"id": "a", "t": "\"The client should be seen by a neurologist.\""}, {"id": "b", "t": "\"The client was found unconscious on the floor in her home.\""}, {"id": "c", "t": "\"The client is a 32-year-old female who was admitted this morning following a syncopal episode and is now experiencing seizures.’"}, {"id": "d", "t": "\"The client is disoriented. Pupils are slow to respond to light.\""}], "correct": "b", "rationale": ", which is the B step in the SBAR tool. The background portion should provide OB Td oa fo information that is pertinent to the current situation. The SBAR Process 1. Organize relevant information in sequence using the SBAR format (Situation, Background, Assessment, Recommendation). 2. Present the information. 3. Work with the provider to clarify or enhance the information and obtain prescriptions for required actions.", "whyNot": {"a": "This statement is the recommendation for action, which is the R step in the SBAR tool. The recommendation provides opinions or new", "c": "This statement is the situation as it relates to the client, which is the S step in the SBAR tool. This step provides brief information about the", "d": "This statement is the assessment as it relates to the identified problem, which is the A step in the SBAR tool. This step can include the"}, "keyConcept": "The SBAR is a communication model that provides a standardized framework for communicating important information between members of the health care team. In addition to organizing the information prior to presenting it, the nurse should also have additional documentation available, such as the client's EMR, recent laboratory or radiology findings, current vital signs, and other assessment data."}, {"id": 10342, "cat": "LEADERSHIP", "stem": "A nurse is assessing a group of clients for referrals. Which of the following clients should the nurse recommend for a referral to hospice services?", "choices": [{"id": "a", "t": "A client who has diabetes mellitus and is having difficulty self-administering insulin because of poor eye sight"}, {"id": "b", "t": "A client who has terminal cancer and requires assistance with pain management"}, {"id": "c", "t": "A client who has hemiplegia following a stroke and requires someone to provide care while their partner is at work"}, {"id": "d", "t": "A client who has dementia and requires help with activities of daily living"}], "correct": "b", "rationale": ", which includes management of symptoms, such as pain and OB SY ox dyspnea. Hospice provides a team of health care providers who work together to assist the client and family make decisions about physical, emotional, spiritual, and comfort needs. A client who has a terminal disease and is deemed to have less than 6 months to live is eligible for c | 2% hospice services.", "whyNot": {"a": "A client who has a chronic illness and difficulty managing their illness can benefit from home health services. Home health provides a", "c": "Adult day health care services are provided to clients who have physical or mental illnesses that require health services and supervision.", "d": "A client who requires a safe environment, routine personal care, and the treatment and management of health conditions, such as"}, "keyConcept": "The nurse should have knowledge of community resources available for clients who have special needs. Hospice services focus on providing care and support to clients and their families through the span of the clients' illness and death. The services continue to assist clients' families with bereavement following the death of the clients. Hospice services allow clients to die with dignity and to retain a sense of control over their lives by offering support and services to manage the manifestations of the client's illness."}, {"id": 10343, "cat": "LEADERSHIP", "stem": "should the nurse take? O A. Refuse the assignment and remain on the OB unit. O B. Ask the charge nurse to appoint a resource nurse on the AMS unit. O C. Report the charge nurse for unsafe client care practices. O D. Float to the AMS unit and perform certified nursing assistant (CNA) duties.", "choices": [{"id": "a", "t": "Refuse the assignment and remain on the OB unit."}, {"id": "b", "t": "Ask the charge nurse to appoint a resource nurse on the AMS unit."}, {"id": "c", "t": "Report the charge nurse for unsafe client care practices."}, {"id": "d", "t": "Float to the AMS unit and perform certified nursing assistant (CNA) duties."}], "correct": "b", "rationale": "A i 9% Moderate The nurse should request a resource nurse on the AMS unit to help reduce personal liability. The resource nurse should be someone who is OB rsd 73% fo skilled in the care of clients on that unit and can assist the floating nurse as needed. The nurse should document the name of the resource nurse who will be responsible for assisting with care in the client's medical records. © I i) oi 13%", "whyNot": {"a": "The nurse has the legal right to refuse a specific task if they are unable to perform it safely; however, refusing the entire assignment is not", "c": "The nurse should not report this as an unsafe client care practice. The charge nurse does not expect the nurse to perform tasks that they", "d": "The nurse should perform duties within the scope of practice of a registered nurse. The nurse can administer medications, perform simple"}, "keyConcept": "A nurse should not perform tasks without the proper education and training or current expertise. A nurse who is assigned to float should evaluate the duties of the unit and determine which duties they can perform safely. The nurse should ask for a resource on the unit who is familiar with the client care needs on that unit."}, {"id": 10344, "cat": "LEADERSHIP", "stem": "information about the client's admitting diagnosis in which component of the SBAR report?", "choices": [{"id": "a", "t": "Situation"}, {"id": "b", "t": "Background"}, {"id": "c", "t": "Assessment"}, {"id": "d", "t": "Recommendation"}], "correct": "b", "rationale": "’s medical history relevant to the situation, such as the client's admitting OB Ts oa diagnosis and surgical procedure, in this section of the report. ° c] 4%", "whyNot": {"a": "The nurse should include the nurse's name, the client's name, the name of the facility, the client's medical diagnosis, and a general", "c": "The nurse should include assessment findings, such as the client's oxygen saturation level and apical heart rate, in this section of the", "d": "The nurse should include a recommendation what should be done to correct the situation in this section of the report."}, "keyConcept": "The Situation, Background, Assessment, Recommendation (SBAR) format is a standardized communication tool used to relay clear, organized, and relevant information about a client. It is used to report a change in a client's condition during a change of shift report or during a client transfer to another unit. SBAR Format ‘Situation ‘The nurse should include the nurse's name, the clent’s name, te name of the feclty or unit, the cents medal 206 8 of the stuaton in this section of the Background: “The nurse should include information trom the Gent's medical history relevant to the stustion, such as the cies \\ agnosis, date of admission, and the surgical procedure oarformed. in this section of the report ssessment ‘The nurse should include assesement fncings i fis section ofthe report, such as vial signs, oxygen saturation level of consciousness, of wound dranage (Becommendation: | The nurse should make a recommendation on whl should be done 1o correct the situation in ths"}, {"id": 10345, "cat": "LEADERSHIP", "stem": "nurse take? O A. Inform the client that the task had been delegated hours ago. O B. Reassign the task to another nurse. O C. Ask the LPN to discuss why the dressing change has not been completed. O D. Report the issue to the unit manager.", "choices": [{"id": "a", "t": "Inform the client that the task had been delegated hours ago."}, {"id": "b", "t": "Reassign the task to another nurse."}, {"id": "c", "t": "Ask the LPN to discuss why the dressing change has not been completed."}, {"id": "d", "t": "Report the issue to the unit manager."}], "correct": "c", "rationale": ". The LPN might require teaching about the procedure, need help with time management, or might have chosen to do it at a later time as part of time or care management. The charge nurse should provide coaching to empower the LPN and build their self- OG PF eh confidence. D l 3%", "whyNot": {"a": "There can be a variety of reasons why the LPN has not completed the assigned dressing change. However, informing the client that this", "b": "Reassigning the task to another nurse does not clarify the reason for lack of action by the LPN. Additionally, it does not guarantee that the", "d": "There can be a variety of reasons why the LPN has not completed the assigned dressing change. While most reasons might be valid, such"}, "keyConcept": "Resistance to delegation can occur for several reasons. The nurse should always attempt to view the situation from the perspective of the staff member who was assigned the task. The resistance might occur because of workloads, changing client priorities, or unfamiliarity with assigned tasks. Investigating the staff member's reasoning for resisting delegation and viewing the situation from their perspective promotes team spirit. Providing coaching to staff members who are unfamiliar with an assigned task or who lack the confidence to complete a task promotes growth as well as self-esteem."}, {"id": 10346, "cat": "LEADERSHIP", "stem": "A nurse is planning an in-service with newly licensed nurses about safe delegation practices. The nurse should plan to refer the group to which of the following resources to guide delegation practices?", "choices": [{"id": "a", "t": "The state Nurse Practice Act"}, {"id": "b", "t": "The National Association for Practical Nurse Education and Services"}, {"id": "c", "t": "Benner's Novice to Expert model"}, {"id": "d", "t": "The Omnibus Budget Reconciliation Act of 1987"}], "correct": "a", "rationale": "The state Nurse Practice Act identifies the skill or education level needed by a nurse to complete a task. It also indicates tasks that can and B ] 11% fo cannot be delegated to certain members of the health care team from a legal perspective. | © 2% Nurse Practice Acts (NPA) + State NPAs provide laws to guide nursing practice. These laws help protect nurses and clients. + Each state and territory in the United States has an NPA. + NPAs include regulations about the nursing board, licensure, and education requirements. + The National Council of State Boards of Nursing has a searchable database of NPAs available on their website https://www.ncsbn.org/npa.htm", "whyNot": {"b": "This association promotes and defends the practice and education of practical nursing, but it does not define tasks that can be delegated", "c": "Patricia Benner's Novice to Expert model describes skill acquisition and performance within the nursing domain", "d": "This act established regulations for the education and certification of assistive personnel."}, "keyConcept": "Delegation is a skill that must be taught and practiced before proficiency can be obtained. However, it is an essential component of the professional nurse's responsibilities and one that requires the use of tools, such as the state's Nurse Practice Act and facility policies and procedures, to accomplish safely and effectively."}, {"id": 10347, "cat": "LEADERSHIP", "stem": "some time alone or with friends. The nurse should recommend a referral for which of the following?", "choices": [{"id": "a", "t": "Admission to a skilled nursing facility"}, {"id": "b", "t": "Assisted living"}, {"id": "c", "t": "Respite care"}, {"id": "d", "t": "Hospice care"}], "correct": "c", "rationale": "al 2% Easy Respite care provides temporary relief for a family member who provides day-to-day care for a family member who is ill and needs B | or assistance with managing a medical condition and the activities of daily living. Respite care can be provided in the home, in a day care setting, or at another type of facility. ec | 88% p | 1%", "whyNot": {"a": "Clients who are admitted to a skilled nursing facility require specialized care, such as wound care management, intravenous therapy, and", "b": "Clients who are admitted to assisted living facilities require help with meals, personal care, and 24-hr supervision. This level of care is not", "d": "Clients who receive hospice care have less than 6 months to live. Hospice caregivers focus on managing clients' pain, promoting comfort,"}, "keyConcept": "Clients who need long-term assistance due to a chronic condition often require care in the community. A number of choices are available to clients based on their specific needs. Nurses who provide care to chronically ill clients should be aware of the available services and make appropriate referrals."}, {"id": 10348, "cat": "LEADERSHIP", "stem": "Acharge nurse is making team assignments for a Registered Nurse (RN) and a Licensed Practical Nurse (LPN). Which of the following clients should the charge nurse assign to the RN?", "choices": [{"id": "a", "t": "A client who has continuous bladder irrigation"}, {"id": "b", "t": "A client who is in protective isolation"}, {"id": "c", "t": "A client who is actively dying and requires IV pain medication"}, {"id": "d", "t": "A client who is 3 days postoperative and requires a dressing change"}], "correct": "c", "rationale": ". A client who is actively dying requires frequent assessments. Updates to family members on the client's condition and therapeutic support might also be required. ec | 15% og 6%", "whyNot": {"a": "Delegation involves the transfer of responsibility for the completion of care activities to another individual while retaining accountability", "b": "It is important for the charge nurse to evaluate several factors when delegating care for clients, including the required workload for each", "d": "A consideration the charge nurse should make when assigning client care is the complexity of the tasks required. Postoperative dressing"}, "keyConcept": "Acharge nurse should use critical thinking and clinical judgment when assigning care to other members of the health care team. Activities that are appropriate for one member of the team might not be appropriate for another. The charge nurse should take into account several factors when delegating in order to provide safe and effective care for clients. One of these factors is the stability of the client. An RN should be assigned responsibility for any client who is unstable or who has experienced a sudden change in condition. The care of this client requires critical thinking skills and a level of education that is beyond the scope of a licensed practical nurse (LPN). The complexity of the task to be delegated is another factor a charge nurse should consider. The charge nurse should ensure the LPN or an assistive personnel (AP) has the knowledge base and competency to complete the assigned task. The charge nurse should also consider the amount of supervision or clinical oversight that will be required and the workload of other members of the team. Overburdening the team members with assigned client care is not only unfair to the team members, it is an unsafe practice."}, {"id": 10349, "cat": "LEADERSHIP", "stem": "A nurse is caring for a client who is scheduled for a total hip arthroplasty. Which of the following tasks is the nurse's responsibility?", "choices": [{"id": "a", "t": "Verify that the client understands the procedure they are having done."}, {"id": "b", "t": "Explain the procedure to the client."}, {"id": "c", "t": "Inform the client of the risks of the procedure."}, {"id": "d", "t": "Provide information about alternate treatments."}], "correct": "a", "rationale": "The nurse's role in witnessing informed consent is to ensure that the client has been given an explanation of the procedure by the provider and fully understands the risks and benefits of the procedure. Incorrect Answer: B. It is the responsibility of the provider to explain the procedure to the client. C. It is the responsibility of the provider to inform the client of the risks of the procedure. D. It is the responsibility of the provider to provide information about alternate treatments.", "whyNot": null, "keyConcept": "When witnessing an informed consent, the nurse must ensure that the client understands the procedure that is to be performed. If the client has any questions regarding the procedure, the nurse must notify the health care provider. It is not the nurse's responsibility to educate the client about the procedure or about the risks and benefits of the procedure. The nurse's role in witnessing a consent form is that of providing verification. By signing the consent the nurse verifies: + The client voluntarily gave consent. + The client's signature is authentic. +The client appears competent to sign the consent form."}, {"id": 10350, "cat": "LEADERSHIP", "stem": "oncoming nurse take? O A. Inform another staff member of his suspicions that the off-going nurse is impaired O B. Write a formal complaint about the nurse. O C. Confront the nurse and ask if she has been drinking. O D. Notify the charge nurse of the situation.", "choices": [{"id": "a", "t": "Inform another staff member of his suspicions that the off-going nurse is impaired"}, {"id": "b", "t": "Write a formal complaint about the nurse."}, {"id": "c", "t": "Confront the nurse and ask if she has been drinking."}, {"id": "d", "t": "Notify the charge nurse of the situation."}], "correct": "d", "rationale": "The oncoming nurse should notify the charge nurse of his suspicion that the off-going nurse is under the influence of alcohol. From this point, the charge nurse can collect data to support or refute this suspicion.", "whyNot": {"a": "The oncoming nurse does not know for sure if the off-going nurse has been drinking alcohol; therefore, the oncoming nurse should not", "b": "The oncoming nurse does not know for sure if the off-going nurse has been drinking alcohol; therefore, the oncoming nurse should not", "c": "It is not the role of the oncoming nurse to confront the off-going nurse about his suspicion that she has been drinking."}, "keyConcept": "In the event a nurse suspects another nurse of being under the influence of alcohol, the nurse should report the matter, beginning at the lowest level of hierarchy, so that further evidence can be collected. Each facility has its own policies and procedures in place to identify and intervene in situations involving an impaired nurse."}, {"id": 10351, "cat": "LEADERSHIP", "stem": "A nurse is planning care for a group of clients. Which of the following clients should the nurse plan to care for first?", "choices": [{"id": "a", "t": "A client who requires assistance with a bath"}, {"id": "b", "t": "A client who requires a dressing change on a wound"}, {"id": "c", "t": "A client who is receiving morphine via a PCA pump. O D.A client who has questions about his new prescription"}], "correct": "c", "rationale": ". nonurgent approach to client care, the nurse should identify that the client who is receiving opioids is at risk for . Therefore, the nurse should care for this client first.", "whyNot": {"a": "The nurse should assist the client who requires assistance with a bath in order to meet the client's hygiene needs and to provide an", "b": "The nurse should complete a dressing change on a wound because this enhances wound healing and provides an opportunity for the"}, "keyConcept": "When assigning priorities to client care, the nurse should consider several factors. One of the factors is Maslow's hierarchy of needs. Client care needs that address physiological needs, such as airway, breathing, and circulation take precedence over self-esteem needs. Other factors to take into account include the client's priorities, values, and beliefs, the resources available to the nurse and the client, and the urgency of the health condition."}, {"id": 10352, "cat": "LEADERSHIP", "stem": "A nurse manager is presenting an in-service to staff nurses about methods to reduce the costs of client care delivery. Which of the following statements indicates an understanding of the teaching? O A.\"I should wait to empty my client's drainable colostomy until it is three-fourths full.\" O B. \"I should delegate providing closed irrigation to an assistive personnel.\" O C.\"I should use the minimum amount of dressings when providing wound care.\" O D.\"| should use sterile gloves when providing site care to clients who have peripheral IV sites.\"", "choices": [{"id": "a", "t": "The nurse should empty the client's drainable colostomy when it is one-third to half full. If the nurse waits until it is three-fourths full, the"}, {"id": "b", "t": "It is cost-effective to delegate basic tasks to the AP, but the nurse should not delegate a skill requiring the use of sterile technique to the AP."}, {"id": "c", "t": "Cost containment is the delivery of effective and efficient care."}, {"id": "d", "t": "The nurse should use clean gloves when providing site care to clients who have peripheral IV sites. Evidence-based practice indicates that"}], "correct": "c", "rationale": "Cost containment is the delivery of effective and efficient care. Cost should be maintained without loss of quality. The nurse should use the minimum amount of dressings when providing wound care.", "whyNot": {"a": "The nurse should empty the client's drainable colostomy when it is one-third to half full. If the nurse waits until it is three-fourths full, the", "b": "It is cost-effective to delegate basic tasks to the AP, but the nurse should not delegate a skill requiring the use of sterile technique to the AP.", "d": "The nurse should use clean gloves when providing site care to clients who have peripheral IV sites. Evidence-based practice indicates that"}, "keyConcept": "Nurses do not often link the use of health supplies and equipment to organization finances, nor the amount the client eventually has to pay. However, it is possible for nurses to reduce the cost of client care delivery by managing time, staff resources, and products responsibly in order to limit unnecessary client costs."}, {"id": 10353, "cat": "LEADERSHIP", "stem": "An RN is preparing assignments for a licensed practical nurse (LPN) and an assistive personnel (AP). Which of the following tasks should the nurse assign to the LPN?", "choices": [{"id": "a", "t": "Providing postmortem care for a client"}, {"id": "b", "t": "Measuring a client's 1&O"}, {"id": "c", "t": "Obtaining a client's weight"}, {"id": "d", "t": "Inserting an indwelling urinary catheter for a client"}], "correct": "d", "rationale": "al 4% Easy When considering tasks for delegation, the nurse should identify that the insertion of an indwelling urinary catheter requires the use of B I a sterile technique and substantial technical skill that is acquired from educational preparation. Therefore, this task would not be appropriate for an AP and should be assigned to the LPN. c I 3%", "whyNot": {"a": "When planning assignments, the nurse should consider which team member is the right person for the task, which is one of the five rights", "b": "When planning assignments, the nurse should consider which team member is the right person for the task, which is one of the five rights", "c": "The job description and facility policies should be considered when delegating tasks. The nurse should identify that the job description for"}, "keyConcept": "Strategies for successful delegation include the identification of the skills and educational preparation necessary for each task to be assigned. By planning ahead and utilizing principles of cost containment, the RN can empower the delegatees and deliver cost-effective care while ensuring the safety of the client."}, {"id": 10354, "cat": "LEADERSHIP", "stem": "\"My partner isn't getting any better and it's the fault of the staff here.\" Which of the following actions should the nurse take to decrease conflict?", "choices": [{"id": "a", "t": "Offer to sit with the client and his partner in the dining room to talk about the conflict."}, {"id": "b", "t": "Avoid making direct eye contact with the client or his partner."}, {"id": "c", "t": "Stand with her hands at her side when talking to the client and his partner."}, {"id": "d", "t": "Contradict the partner's statement by telling the client and partner about the competence of the nursing staff."}], "correct": "c", "rationale": "The nurse should avoid standing in a defensive posture, such as with arms crossed, or using hostile body language, such as pointing at the B 0% individuals who are angry, especially if the gestures are combined with a frowning facial expression. The nurse should stand with her arms at her side or raised openly toward the client and his partner. The nurse should move toward the client and his partner rather than backing ec | 33% away, but should avoid standing within their personal space. Standing closer than 0.46 m (1.5 feet) to angry individuals can invade their , which could escalate the conflict. The nurse's tone of voice should remain neutral, sending a message of calmness and confidence.", "whyNot": {"a": "The nurse should speak with the client and his partner in a more private location, where a quiet discussion can take place. It can be helpful", "b": "The nurse should make eye contact with the client and his partner. It is important to keep cultural differences in mind when deciding how", "d": "The nurse should avoid defensive communication techniques, such as contradicting the partner's statements. The nurse should attempt"}, "keyConcept": "When faced with a conflict situation, the nurse should utilize the principles of therapeutic verbal and nonverbal communication. The nurse's body position and tone of voice should demonstrate confidence and the willingness to converse about the topic of conflict. Use of nonjudgmental language and techniques such as active listening, clarifying, and focusing can help de-escalate a conflict situation and allow all participants to discuss the situation openly."}, {"id": 10355, "cat": "LEADERSHIP", "stem": "take first? O A. Prevent cross-contamination of clients. O B. Complete a thorough client assessment. O C. Treat clients arriving at the facility who have yellow triage tags. O D. Maintain a client tracking system.", "choices": [{"id": "a", "t": "Prevent cross-contamination of clients."}, {"id": "b", "t": "Complete a thorough client assessment."}, {"id": "c", "t": "Treat clients arriving at the facility who have yellow triage tags."}, {"id": "d", "t": "Maintain a client tracking system."}], "correct": "a", "rationale": "Adisaster involving the release of a toxic substance indicates that the clients are at greatest risk for cross-contamination between B | at nonexposed clients and exposed clients. Therefore, the priority action is to promote the safety of the clients by separating them to prevent cross-contamination and limit the spread of the unknown toxin.", "whyNot": {"b": "The nurse should complete a thorough client assessment to determine the extent of exposure and injury to the client. However, there is", "c": "The nurse should treat clients who have a yellow triage tag, which indicates a significant injury that requires medical care. However, these", "d": "The nurse should maintain a client tracking system in a disaster situation to track the client's medical record number and information,"}, "keyConcept": "A nurse should identify the priorities of client care during a disaster situation. The nurse should promote the safety of the clients and follow the facility's emergency operation plan (EOP). Some of the components of the EOP can include: + Activation response + Internal/external communication plan + Plan for coordinated client care + Security plans + Identification of external resources + Data management strategy + Education plan for each component"}, {"id": 10356, "cat": "LEADERSHIP", "stem": "Anursing supervisor is planning an annual performance appraisal of a staff member on the unit. Which of the following actions should the nursing supervisor take?", "choices": [{"id": "a", "t": "Establish goals for the staff member prior to the meeting."}, {"id": "b", "t": "Schedule the appraisal interview as early in the staff member's shift as possible."}, {"id": "c", "t": "Provide a chair directly across the desk for the staff member to sit in."}, {"id": "d", "t": "Provide the staff member with a copy of the appraisal form in advance."}], "correct": "d", "rationale": "The completion of a performance appraisal is an opportunity to document a staff nurse's skills in comparison to the established job description. The appraisal provides an opportunity for the growth and development of the staff nurse. It also provides information to be used when evaluating bonuses, raises, promotions, and disciplinary actions if needed. In order to be effective, the performance appraisal process should be interactive between the nursing supervisor and the staff nurse, with each working collaboratively to determine a plan of action and goals for the next year.", "whyNot": {"a": "A performance appraisal is an evaluation of how well a staff nurse has completed assigned duties according to the job description, any", "d": "The nursing supervisor should ensure the staff member knows the standards by which her work will be evaluated and that she has a copy", "b": "The nursing supervisor should schedule the appraisal interview at a time that is convenient for the staff member so that the staff member", "c": "The nursing supervisor should arrange the chairs so they are side by side to help make the staff member feel comfortable. Placing the"}, "keyConcept": "The completion of a performance appraisal is an opportunity to document a staff nurse's skills in comparison to the established job description. The appraisal provides an opportunity for the growth and development of the staff nurse. It also provides information to be used when evaluating bonuses, raises, promotions, and disciplinary actions if needed. In order to be effective, the performance appraisal process should be interactive between the nursing supervisor and the staff nurse, with each working collaboratively to determine a plan of action and goals for the next year."}, {"id": 10357, "cat": "LEADERSHIP", "stem": "Which of the following individuals should a nurse's actions be compared to when establishing the standard of care that is used in a court proceeding?", "choices": [{"id": "a", "t": "The client"}, {"id": "b", "t": "Another staff nurse"}, {"id": "c", "t": "The nurse's attorney"}, {"id": "d", "t": "The client's provider"}], "correct": "b", "rationale": "All 12% = Hard The definition of negligence is practice that is below the standard of care. The benchmark for standard of care is what a reasonable, prudent OB a aan individual who has a similar background and experience would do. Another staff nurse who practices in a similar setting to the nurse is the designated individual to provide testimony regarding the standard of care. c |_| 18% off 10%", "whyNot": {"a": "Although the client might be called to testify by attorneys for both the plaintiff and the defendant, this is not the individual to define the", "c": "Although the nurse's attorney can offer an opinion regarding how the injury to the client occurred and could have been prevented, this is", "d": "Although the client's provider can be called to testify about the injury, this is not the individual to define the standard of care used to"}, "keyConcept": "The definition of professional negligence is practice that is below the standard of care. The benchmark for standard of care is what a reasonable, prudent individual who has a similar background and experience would do. Another staff nurse who practices in a similar setting to the nurse is the designated individual to provide testimony to define the standard of care. There are five features needed for an individual to be held liable for professional negligence or malpractice: 1) The existence of a professional duty to a standard of care that is expected from an individual who has similar experience and education 2) A failure to meet the standard of care or a breach of duty 3) A probability of harm that can be anticipated based on experience or resources 4) A proven relationship between the breach of duty and the injury 5) An injury to the client"}, {"id": 10358, "cat": "LEADERSHIP", "stem": "for discharge? O A. Ayoung adult client who has Crohn's disease and is scheduled for an ileostomy in 24 hr O B. An adolescent client who was admitted 24 hr ago due to a spontaneous pneumothorax O C. Amiddle adult who is 36 hr postoperative following an open laminectomy O D. An older adult client who was admitted for acute pancreatitis", "choices": [{"id": "a", "t": "Ayoung adult client who has Crohn's disease and is scheduled for an ileostomy in 24 hr"}, {"id": "b", "t": "An adolescent client who was admitted 24 hr ago due to a spontaneous pneumothorax"}, {"id": "c", "t": "Amiddle adult who is 36 hr postoperative following an open laminectomy"}, {"id": "d", "t": "An older adult client who was admitted for acute pancreatitis"}], "correct": "a", "rationale": "A client who is scheduled for surgery in 24hr and is medically stable. Therefore, the nurse should recommend this client for discharge. B | a0", "whyNot": {"b": "A client who has a pneumothorax requires rest, oxygen, and observation. The client might require a chest tube to reinflate the lung.", "c": "A client who is 36 hr postoperative following an open laminectomy is at risk for complications, such as cerebrospinal fluid leak, urinary", "d": "An older adult client who has acute pancreatitis is at risk for serious complications, such as hemorrhage, kidney failure, septic shock,"}, "keyConcept": "The role of the nurse during a mass casualty event includes working with the provider to recommend clients for discharge to make room for injured clients. The nurse should recommend clients who are medically stable, such as clients who are ambulatory, admitted for observation or diagnostic testing, near-ready for discharge with assistance from a family member or home health care, or could be transferred to another facility, such as rehabilitation facility. Other responsibilities of the nurse include calling off-duty staff into work and reassigning staff to meet the needs of the high"}, {"id": 10359, "cat": "LEADERSHIP", "stem": "A nurse manager is teaching a group of charge nurses about the recruiting and retention process for health care workers. Which of the following statements should the nurse manager include?", "choices": [{"id": "a", "t": "\"Recruiting new employees occurs as the need arises.\""}, {"id": "b", "t": "\"Retention occurs due to monetary compensation.\""}, {"id": "c", "t": "\"Retention is improved when the middle-level manager creates a positive social climate.\""}, {"id": "d", "t": "\"Recruiting by word of mouth does not improve retention.\""}], "correct": "c", "rationale": "A ; | 25% Moderate The nurse manager should include in the teaching that the middle-level manager has the greatest impact by encouraging a positive social B I Ee climate in the work environment.", "whyNot": {"a": "The nurse manager should include in the teaching that recruitment is an ongoing process to actively seek applicants.", "b": "The nurse manager should include in the teaching that nonmonetary factors, such as a desire to be employed at the organization, results", "d": "The nurse manager should include in the teaching that the best way to maintain an adequate employee pool is by staff members"}, "keyConcept": "Recruitment is defined as a constant process for actively pursuing new applicants for positions in the workplace. Nonmonetary factors, such as a desire to be employed at the organization, result more often in retention of the employee than monetary compensation. An organization should identify before recruiting why the organization is a better place to work than competitors. The best method to maintain an adequate employee pool is through staff members recommending the organization as a place for employment. Recruiting a quality employee who is talented, motivated, and has promise as an excellent worker is one of the first factors for retention. Retention begins with a healthy work environment, where all members of the team are professional, responsible, competent, and transparent. These qualities create a healthy and safe place for the health care team to work and empower the employees to do the best job possible. The middle-level managers also have the greatest impact for encouraging a positive social climate in the work environment."}, {"id": 10360, "cat": "LEADERSHIP", "stem": "A nurse manager receives a report that one of the staff nurses might be chemically impaired. Which of the following actions should the nurse manager take first?", "choices": [{"id": "a", "t": "Review the nurse's work performance history."}, {"id": "b", "t": "Complete a count of controlled substances on the unit."}, {"id": "c", "t": "Talk with the staff members who reported the nurse."}, {"id": "d", "t": "Remove the nurse from client care."}], "correct": "d", "rationale": "‘i The greatest risk in this situation is injury to clients; therefore, the first action the nurse manager should take is to remove the nurse from B I client care. A nurse who is chemically impaired can have impaired judgment and could make decisions that are unsafe for clients. The nurse should reassign care of these clients to other staff. c |_|", "whyNot": {"a": "The nurse manager should review the staff nurse's work performance, including evaluations as well as time and attendance records, to", "b": "The nurse manager should conduct a count of all the controlled substances on the unit and review the staff nurse's history of obtaining", "c": "The nurse manager should investigate the allegations of chemical impairment to determine if disciplinary action of the staff nurse is"}, "keyConcept": "The nurse is responsible for reporting other members of the health care team whom they suspect might be working while impaired. This is an important tenet of the Nursing Code of Ethics, that the nurse's primary commitment is to the client and the nurse promotes the health and safety of self and others. It is important for the nurse to realize that reporting suspected impairment of another member of the health care team is not a form of betrayal but demonstrates commitment to the well-being of the team member and the safety of the clients. Additionally, there are legal ramifications for failure to report suspected impairment. If a state Board of Nursing investigation finds that other licensees, such as nurses, knew about the impairment and did nothing, the Board can also act against those individuals for failure to comply with the Nurse Practice Act."}, {"id": 10361, "cat": "LEADERSHIP", "stem": "A nurse is observing a newly licensed nurse insert an indwelling urinary catheter for an adult client. Which of the following actions by the newly licensed nurse requires intervention?", "choices": [{"id": "a", "t": "The nurse keeps the urine collection bag resting on the client's lap."}, {"id": "b", "t": "The nurse selects a 16-Fr catheter for placement."}, {"id": "c", "t": "The nurse does not allow contact of the drainage spigot with nonsterile collection containers."}, {"id": "d", "t": "The nurse advances the catheter 5 cm (2 in) farther after the urine begins to flow."}], "correct": "a", "rationale": "o; Ms The urine collection bag should be kept below the level of the client's bladder. The nurse should intervene and notify the charge nurse. B | a0 Additionally, the nurse should discuss with the newly licensed nurse that positioning the drainage bag below the level of the bladder will enable the urine to freely drain and decrease the risk of a catheter acquired urinary tract infection (CAUTI). c | 3%", "whyNot": {"b": "The nurse should select a 14- or 16-Fr catheter for an adult client.", "c": "The nurse should not allow contact of the drainage spigot with nonsterile collection containers. Preventing this contact decreases the", "d": "The nurse should advance the catheter 5 cm (2 in) farther after the urine begins to flow. This action ensures the catheter is fully in the"}, "keyConcept": "It is important for a nurse who observes another nurse perform a skill incorrectly or unsafely to quickly intervene and assist with correcting the unsafe practice. This will prevent harm to the client. The nurse should discuss with the newly licensed nurse the action that was performed that was incorrect. Additionally, the nurse should report this to the charge nurse or the nurse manager."}, {"id": 10362, "cat": "LEADERSHIP", "stem": "between themselves. Which of the following conflict resolution strategies is the nurse manager demonstrating?", "choices": [{"id": "a", "t": "Avoiding"}, {"id": "b", "t": "Competing"}, {"id": "c", "t": "Smoothing"}, {"id": "d", "t": "Confrontation"}], "correct": "d", "rationale": "A Hl 20% Moderate Confrontation is a conflict management tool in which the nurse manager instructs two parties in conflict to work out their differences on B | a0 their own. This should involve face-to-face communication, which can be facilitated by the nurse manager. ci 21%", "whyNot": {"a": "Avoiding is an ineffective strategy in which all parties are aware of the conflict but do not make attempts to acknowledge or resolve the", "b": "Competing is a conflict management strategy in which one person wins and the other person loses. The ultimate result is that the", "c": "Smoothing is a conflict management strategy in which the parties focus on points of agreement rather than addressing the conflict."}, "keyConcept": "Conflict among staff on a unit can have a wide-reaching negative impact involving personal and professional relationships, productivity, and client care. The resolution of conflict requires all parties to be aware of the feelings and emotions they are experiencing and a mutual decision between the parties to focus on the issues causing the conflict rather than individual personalities. Finally, all parties should approach the conflict resolution as a problem to be solved mutually, which allows each member to provide input and to decide on options that are agreeable to all parties."}, {"id": 10363, "cat": "LEADERSHIP", "stem": "A nurse notes an assistive personnel (AP) from the unit sharing a picture of a client's wound taken on their personal cell phone. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Remind the AP not to share the photograph on social media."}, {"id": "b", "t": "Join the discussion with an opinion on the diagnosis."}, {"id": "c", "t": "Complete an incident report."}, {"id": "d", "t": "Report the occurrence to the charge nurse."}], "correct": "d", "rationale": "all 9% Easy It is the ethical responsibility of the nurse to report any client breach in confidentiality starting at the lowest possible level in the facility , the charge nurse in this case. cf 4% Incorrect Answer: @D PY 86% A. Confidentiality is a basic ethical principle and an expectation in the provision of medical and nursing care. The AP's action should be immediately reported to the charge nurse. B. The nurse should not engage in the conversation. Taking a picture of a client with a personal cell phone is a breach of confidentiality and should be immediately reported to the charge nurse. C. Incident reports are used to report unusual or unexpected occurrences that happen during the provision of care. Discussing a client's", "whyNot": null, "keyConcept": "All clients are entitled to the basic right of confidentiality. Guidelines from the American Nurses Association and the National Council of State Board of Nurses specifically state that taking pictures or videos of a client on a personal cell phone is an inappropriate use of social media. In the event a nurse discovers other staff members breaching a client's confidentiality, the nurse should report the matter starting at the lowest level of hierarchy. Each facility has its own policies and procedures in place to identify and intervene in situations involving a breach of client confidentiality."}, {"id": 10364, "cat": "LEADERSHIP", "stem": "A nurse manager is working to maintain fiscal and ethical accountability for the staffing. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Increase staffing when acuity levels are low."}, {"id": "b", "t": "Ask the staff to regularly work extra shifts and overtime."}, {"id": "c", "t": "Create a sense of trust to resolve staffing issues."}, {"id": "d", "t": "Focus on the number of personnel for client care."}], "correct": "c", "rationale": ". If the nurse manager , then trust is developed and ethical accountability is maintained.", "whyNot": {"a": "The nurse manager should increase staffing when acuity levels are high and decrease staffing when acuity levels are low to maintain fiscal", "b": "The nurse manager who asks staff to regularly work extra shifts and overtime is not being fiscally or ethically accountable. Instead, the", "d": "The nurse manager who is fiscally and ethically accountable focuses on all components, not just the number of personnel for client care."}, "keyConcept": "Fiscal and ethical accountability for staffing requires the nurse manager to maintain adequate staffing for low and high acuity client care. The nurse manager should stay within the staffing budget and meet the needs of the clients and staff. Therefore, increasing staffing when acuity levels are high and decreasing staffing when acuity levels are low helps to maintain fiscal accountability. The nurse manager should consider many factors to maintain fiscal and ethical accountability, including the staffing mix and competencies, job descriptions, nursing activities, and the client care organization. A client acuity system is a fairer way to meet staffing needs. During times of high client acuity, the nurse manager should create a sense of trust to resolve staffing issues. If the nurse manager works as hard as the staff to maintain client safety and meets client needs, then trust is developed and ethical accountability is maintained."}, {"id": 10365, "cat": "LEADERSHIP", "stem": "principles by not divulging the information? O a.utility O B. Paternalism O C. Justice O D. Confidentiality", "choices": [{"id": "a", "t": "Utility is the ethical principle of attempting to do what is best for the common good, rather than what is best for the individual client."}, {"id": "b", "t": "Paternalism is the ethical principle based on the idea that one individual has the right to make decisions for another. It negates the client's"}, {"id": "c", "t": "Justice is the ethical principle based on the idea that everyone should be treated fairly."}, {"id": "d", "t": ". The nurse is obligated to protect the client's B | aI confidential information and should not share any information about the client with a nurse who is not providing care for the client."}], "correct": "d", "rationale": ". The nurse is obligated to protect the client's B | aI confidential information and should not share any information about the client with a nurse who is not providing care for the client. I © 3% A. Utility is the ethical principle of attempting to do what is best for the common good, rather than what is best for the individual client. B. Paternalism is the ethical principle based on the idea that one individual has the right to make decisions for another. It negates the client's right to autonomy. C. Justice is the ethical principle based on the idea that everyone should be treated fairly.", "whyNot": null, "keyConcept": "A nurse has the responsibility to practice in a manner that is consistent with the code of ethics for nurses."}, {"id": 10366, "cat": "LEADERSHIP", "stem": "A nurse on a medical-surgical unit is delegating care for a group of clients. Which of the following specimens should the nurse delegate an unlicensed assistive personnel (UAP) to collect?", "choices": [{"id": "a", "t": "Wound drainage for culture"}, {"id": "b", "t": "Urine from an indwelling catheter"}, {"id": "c", "t": "Blood for an ABG test"}, {"id": "d", "t": "Random stool specimen"}], "correct": "d", "rationale": "The nurse should delegate tasks to the AP that do not require nursing assessment, evaluation, judgment, decision making, or problem solving skills. Tasks that require sterile technique or special skills should not be delegated to an AP. The nurse should consider each task prior to delegation to ensure the safety and quality of client care. The nurse should provide clear, concise communication regarding delegated tasks. The nurse should include what task is to be done for which client, when the task should be completed, the desired outcome of the task, outcomes that should be reported, and who will be available as a resource to the AP. The nurse who delegates a task is held accountable for the outcome and should intervene as needed to ensure safe and effective client care.", "whyNot": {"a": "Collecting drainage from a wound for culture requires the skills of a licensed nurse because it involves the use of sterile technique.", "b": "Urine from an indwelling catheter requires the skills of a licensed nurse because it involves the use of sterile technique. Therefore, the", "c": "Individuals who are specially trained to draw blood from a radial, brachial, or femoral artery, such as nurses, medical technicians, and"}, "keyConcept": "The nurse should delegate tasks to the AP that do not require nursing assessment, evaluation, judgment, decision making, or problem solving skills. Tasks that require sterile technique or special skills should not be delegated to an AP. The nurse should consider each task prior to delegation to ensure the safety and quality of client care. The nurse should provide clear, concise communication regarding delegated tasks. The nurse should include what task is to be done for which client, when the task should be completed, the desired outcome of the task, outcomes that should be reported, and who will be available as a resource to the AP. The nurse who delegates a task is held accountable for the outcome and should intervene as needed to ensure safe and effective client care."}], "muscoskeletal": [{"id": 10367, "cat": "MUSCOSKELETAL", "stem": "A nurse is preparing discharge education for a client with type 2 diabetes and rheumatoid arthritis with a new prescription for prednisone. Which of the following will the nurse include in teaching?", "choices": [{"id": "a", "t": "Prednisone can be stopped at any time."}, {"id": "b", "t": "Prednisone may cause hypoglycemia."}, {"id": "c", "t": "Prednisone suppresses the inflammatory process but doesn’t cure the disease."}, {"id": "d", "t": "Prednisone protects the client from infection."}], "correct": "c", "rationale": "8 11% Prednisone is an anti-inflammatory corticosteroid that suppresses inflammation by decreasing migration of polymorphonuclear leukocytes ec | 87% and fibroblasts. It doesn’t cure rheumatoid arthritis or other diseases characterized by inflammation, but it can reduce symptoms. It is , including osteoporosis, glucose intolerance, immune suppression, and weight gain. Chronic use or short- term use of large doses of corticosteroids suppress the pituitary-hypothalamic-adrenal axis, which can result in adrenal crisis if corticosteroids are suddenly stopped.", "whyNot": {"a": "Prednisone suppresses the adrenal-hypothalamic-pituitary axis, so stopping suddenly can precipitate an adrenal crisis. If prednisone has", "b": "Prednisone causes hyperglycemia, so clients with diabetes must carefully monitor glucose levels. It can cause diabetes and Cushing’s", "d": "Prednisone suppresses the immune response and may make the client more susceptible to infection. Prolonged use of prednisone may"}, "keyConcept": "Long term use of corticosteroids or short term use of a large dose can result in suppression of the hypothalamic-pituitary-adrenal axis, causing an adrenal crisis if the medication is stopped suddenly. Side effects include glucose intolerance, osteoporosis, weight gain, and immune suppression. Corticosteroids are used in treatment of many rheumatological disorders. They reduce associated symptoms, but do not provide a cure."}, {"id": 10368, "cat": "MUSCOSKELETAL", "stem": "A nurse is teaching the parents of a newborn about treatment measures for their newborn's plagiocephaly. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "\"Place your baby on her tummy while she is sleeping during the day.\""}, {"id": "b", "t": "\"Keep your baby's head in the same position during activities.\""}, {"id": "c", "t": "\"Place the prescribed helmet on your baby's head for 23 hours a day.\""}, {"id": "d", "t": "\"Keep your baby in an infant swing for several hours during the day.\""}], "correct": "c", "rationale": "all 8% Easy A newborn who has plagiocephaly should wear the customized prescribed helmet 23 hr per day. The helmet decreases the pressure on the B | at affected side of the skull.", "whyNot": {"a": "A newborn who has plagiocephaly should not be placed in the prone position to sleep. Instead, the parents should place the newborn ina", "b": "A newborn's head should not be placed in the same position at all times. Instead, the parents should frequently reposition the newborn's", "d": "A newborn who has plagiocephaly should not be placed in an infant swing for several hours during the day. This can put pressure on one"}, "keyConcept": "Plagiocephaly is the abnormal asymmetrical shape of an infant's head caused by molding of the skull due to positioning or acquired during birth. At this time, the infant's cranial sutures are not closed, and this allows for molding of the cranium to occur. It can also occur from placing infants on their backs to sleep because this causes the skull to flatten occipitally and develop an abnormal shape. This condition can be prevented by alternating the infant's head position while sleeping supine, avoiding prolonged placement of the infant in swings or carriers, and placing the infant in the prone position during playtime. If not resolved within 2 months, physical therapy is recommended, and a customized helmet is used for this condition. The customized helmet should be placed on the infant for 23 hours per day for about 3 months. The helmet is used to decrease the pressure on the affected side of the skull."}, {"id": 10369, "cat": "MUSCOSKELETAL", "stem": "A nurse is teaching a group of parents about fractures. Which of the following statements by a parent indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Children need a longer time to heal from a fracture than adults.\""}, {"id": "b", "t": "\"A fracture to an arm can cause it to be shorter than the non-injured arm.\""}, {"id": "c", "t": "\"A greenstick fracture is a complete break in the bone.\""}, {"id": "d", "t": "\"Bones are unable to bend, so they break.\""}], "correct": "b", "rationale": "A A fracture that involves the epiphyseal growth plate located at the end of the bone shaft can affect future longitudinal growth of the bone. On — An injury that involves this area of the bone might require surgery and the placement of an external fixation device to prevent alterations in future growth. c a oz Healing Time of a Femoral Fracture Age of the Individual Healing Time Neonate 14 to 21 days Childhood 4 to 8 weeks Adolescence 2 to 3 months Adult 2.5 to 4 months", "whyNot": {"a": "Children heal from fractures more quickly than adults due to a thicker periosteum and good blood supply.", "c": "A partial break in the bone is known as a greenstick fracture. This type of break is common in children because the bones are more porous", "d": "The bones of children are more porous than those of adults. While children might sustain fractures, they are more able to tolerate physical"}, "keyConcept": "Fracture injuries in children manifest and heal differently than those of adults. The porous nature of a child's bones provides a certain amount of protection from trauma. The child's bone is able to bend to a certain extent before a fracture occurs. Because the periosteum of the child is thicker than that of the adult, the fractures heal faster as well."}, {"id": 10370, "cat": "MUSCOSKELETAL", "stem": "from under him and he begins to fall. What is the most appropriate action for the nurse to take?", "choices": [{"id": "a", "t": "Stretch out her arms to catch the client as he falls backward"}, {"id": "b", "t": "Step out of the way and allow the client to fall back toward the wall"}, {"id": "c", "t": "Take hold of a blanket and place it under the client’s head to avoid injury"}, {"id": "d", "t": "Assume a wide stance and use her body to break the client’s fall"}], "correct": "d", "rationale": "If a nurse is working with a client who begins to fall and the nurse is at their side, the nurse should make every attempt to protect the client from being injured by breaking his fall without injuring themself in the process. In this situation, the nurse should assume a wide stance and bend at the knees, using his body to break the client’s fall, which better protects the client's body and may prevent him from hitting his head.", "whyNot": {"a": "The nurse could become injured if they try to catch the client in this manner.", "b": "The nurse should assist the client by slowly lowering them, not stepping out of the way.", "c": "The nurse most likely does not have a blanket nearby while ambulating with the client."}, "keyConcept": "A gait belt is used for safety by allowing the nurse to guide the client during ambulation to reduce the risk of falls. A gait belt can be used with acane or walker, with or without rollers. The nurse should ensure a level hazard-free surface prior to ambulation."}, {"id": 10371, "cat": "MUSCOSKELETAL", "stem": "A nurse is providing teaching for the parents of an infant with cerebral palsy. How will the nurse advise the parents to carry the infant in a sitting position to prevent scissoring of the legs?", "choices": [{"id": "a", "t": "Astride one of her hips"}, {"id": "b", "t": "Strapped in an infant seat"}, {"id": "c", "t": "Wrapped tightly in a blanket"}, {"id": "d", "t": "Under the arm using a football hold"}], "correct": "a", "rationale": "Cerebral palsy is associated with hypertonicity of muscles that can result in \"scissoring\" of the legs. Keeping the infant astride on the hips will keep the legs in abduction and prevent scissoring.", "whyNot": {"b": "Sitting in an infant seat will not necessarily keep the legs in the appropriate position.", "c": "Wrapping the infant in a blanket may cause the legs to cross and promote scissoring.", "d": "Using a football hold under the arm does not control the child’s legs."}, "keyConcept": "Cerebral palsy refers to a group of disorders of movement, coordination, and posture, caused by injury to the motor neurons in the developing brain, usually occurring before birth. Approximately seventy percent of individuals with cerebral palsy have muscular spasticity. Scissoring refers to an abnormal gait primarily associated with spasticity in children with cerebral palsy. It is characterized by flexion and extreme adduction at the hip and pelvis, resulting in touching or crossing of the knees and thighs."}, {"id": 10372, "cat": "MUSCOSKELETAL", "stem": "most likely the cause of these symptoms?", "choices": [{"id": "a", "t": "Deep vein thrombosis"}, {"id": "b", "t": "Myocardial infarction"}, {"id": "c", "t": "Fat embolism"}, {"id": "d", "t": "Ruptured aortic aneurysm"}], "correct": "c", "rationale": "all 10% Easy The classic triad for fat embolism is: respiratory difficulty, change in mental status and petechial rash. Femur fracture is associated with risk B | a0 for fat embolism from the bone marrow and the client's respiratory distress and petechiae make this the likely diagnosis.", "whyNot": {"a": "Deep vein thrombosis is not associated with petechiae or respiratory distress. Pulmonary embolism is associated with respiratory distress.", "b": "The typical presentation of myocardial infarction is crushing chest pain, nausea, and shortness of breath. Petechiae are characteristic of", "d": "Ruptured aortic aneurysm presents with sudden onset of tearing pain down the back, with severe hypotension."}, "keyConcept": "The incidence of fat embolism syndrome is high in clients who have experienced major traumatic injuries, particularly long bone fractures. The diagnosis is primarily based on identification of clinical signs and symptoms of dyspnea, petechiae, and cognitive dysfunction after trauma, fracture of long bones, or orthopedic surgical procedures. The syndrome is caused by systemic inflammatory response to a fat embolism and onset is usually 12-72 hours after the inciting event."}, {"id": 10373, "cat": "MUSCOSKELETAL", "stem": "Which of the following should the nurse assess in a client diagnosed with osteoarthritis?", "choices": [{"id": "a", "t": "Anemia"}, {"id": "b", "t": "Osteoporosis"}, {"id": "c", "t": "Weight loss"}, {"id": "d", "t": "Local joint pain"}], "correct": "d", "rationale": "al 3% Easy Osteoarthritis is a degenerative joint disease with local manifestations such as local joint pain, unlike rheumatoid arthritis, which has a B | at systemic manifestation that includes anemia and osteoporosis. | © 2% A. Anemia is sometimes associated with rheumatoid arthritis, not osteoarthritis B. Osteoporosis does not result from osteoarthritis. It results from calcium depletion and breakdown of bone. C. Clients with autoimmune arthritides that have systemic effects, including rheumatoid arthritis and ankylosing spondylitis, may experience weight loss. It does not occur as a result of osteoarthritis.", "whyNot": null, "keyConcept": "Osteoarthritis is the most common degenerative joint disease and is associated with significant disability. Precipitating factors include mechanical injury, chondrocyte response, release of cytokines, stimulation of proteolytic enzymes and collagenase, causing breakdown of cartilage in the joint. . OA starts from an injury of the articular cartilage, subchondral bone, or synovium. Release of cytokines results in inflammation, stimulating synthesis and release of enzymes that break down proteins and collagen in the joint."}, {"id": 10374, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client who has just had a plaster cast applied after a fracture of the ulna. Which of the following is the most appropriate nursing intervention?", "choices": [{"id": "a", "t": "Keep the cast covered until it is completely dry"}, {"id": "b", "t": "Handle the cast with only the tips of the fingers to avoid moving the plaster"}, {"id": "c", "t": "Rest the cast on a table for the first 48 hours while drying"}, {"id": "d", "t": "Observe edges of the cast to ensure they do not cut the skin"}], "correct": "d", "rationale": "All 10% Easy After a cast placement, the nurse should inspect the cast and the client's skin carefully for irritation or trauma that can lead to skin B ] or breakdown and infection. The nurse should also check capillary refill and skin temperature in the hand to ensure adequate circulation. | © 3%", "whyNot": {"a": "The nurse should not cover the cast until it is dry. Covering the cast will prevent moisture from escaping.", "b": "The nurse should handle the newly applied cast carefully to prevent denting of the surface. If it is necessary to handle the newly applied", "c": "The cast should rest on a soft surface, such as a pillow, while drying."}, "keyConcept": "After application of the cast, it will be firm but damp and easily damaged. It takes 24-48 hours for a cast to harden and dry. The cast should be handled carefully by lifting and supporting it on a plastic-covered pillow or with the palms of the hands. If the cast is dented or flattened, it can cause pressure to develop within the cast. A drying cast generates heat as moisture evaporates, so it should not be covered. When the cast is dry, the client's arm can be elevated to reduce swelling, but the cast should be supported along the entire length."}, {"id": 10375, "cat": "MUSCOSKELETAL", "stem": "Which of the following images represents a greenstick fracture? KHIM", "choices": [{"id": "a", "t": "l 3%"}, {"id": "b", "t": "This represents a simple fracture, where there is a clean break across a bone."}, {"id": "c", "t": "A l 3% Moderate In a greenstick fracture, a bone is partially broken and bent."}, {"id": "d", "t": "This represents a spiral fracture, in which the bone is broken due to a twisting motion and there is a spiral or helical fracture line."}], "correct": "c", "rationale": "A l 3% Moderate In a greenstick fracture, a bone is partially broken and bent. It is called a “greenstick” because it appears similar to what occurs when one B | a tries to break a green stick of wood.", "whyNot": {"a": "This represents a comminuted fracture, in which there are fragments of broken bone surrounding the fracture.", "b": "This represents a simple fracture, where there is a clean break across a bone.", "d": "This represents a spiral fracture, in which the bone is broken due to a twisting motion and there is a spiral or helical fracture line."}, "keyConcept": "Agreenstick fracture refers to a fracture in which one side of the bone bends and the opposite side breaks at the cortex. Greenstick fractures occur most often during infancy and childhood, when bones are soft. The fracture requires immobilization in a cast to prevent completion of the fracture. Types of Bones Fractures"}, {"id": 10376, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a new client in the post anesthesia care unit (PACU) after amputation of the left leg. Which of the following is the priority nursing action in the immediate postoperative period?", "choices": [{"id": "a", "t": "Monitor vital signs"}, {"id": "b", "t": "Assess the proximal pulse at the amputated part"}, {"id": "c", "t": "Place a surgical tourniquet at the bedside"}, {"id": "d", "t": "Administer IV fluids"}], "correct": "c", "rationale": "Hemorrhage is the most concerning primary immediate complication of amputation. Therefore, a surgical tourniquet is kept at the bedside B i TR in case of acute bleeding. ° oc 24%", "whyNot": {"a": "Vital signs are part of recovery care but a surgical tourniquet is necessary to prevent hemorrhage after an amputation.", "b": "Pulses should be assessed regularly but the higher priority is to prevent hemorrhage in clients who have had an amputation.", "d": "IV fluids are typically ordered during recovery care; the nurse must first ensure that a surgical tourniquet is in place to prevent hemorrhage"}, "keyConcept": "Clients may undergo amputation after traumatic injury or as a consequence of complications associated with vascular disease or diabetes. Soft or rigid dressings can be used after the amputation, but rigid dressings are preferred for superior promotion of wound healing, shaping of the stump, pain management, protection against trauma during falls, stump volume control and increased speed of prosthetic fitting. Complications that relate to surgery include risks associated with anesthesia, infection, damage to nerves and blood vessels, and bleeding or blood clots. After amputation, the client may have continued nerve pain, phantom limb pain or bone spur overgrowth at the end of the limb. Disability or a need for additional surgery can occur as a result of any of these complications."}, {"id": 10377, "cat": "MUSCOSKELETAL", "stem": "responses should the nurse make? O A.\"The Pavlik harness is used for children who have scoliosis.\" O B. \"The Pavlik harness is used to adduct the infant's hips.\" O C. \"The Pavlik harness cannot be used for your child because her condition is too severe.\" O D. \"The Pavlik harness is used for infants less than 6 months of age.\"", "choices": [{"id": "a", "t": "M"}, {"id": "b", "t": "The Pavlik harness is for infants from birth to 6 months of age who have hip dysplasia. The device is used to assist the hip into an abducted"}, {"id": "c", "t": "Treatment for developmental dysplasia of the hip for a toddler involves reduction of the hip into proper positioning using either a closed"}, {"id": "d", "t": "A | M Moderate The Pavlik harness is a soft brace designed for infants less than 6 months of age who have developmental dysplasia of the hip."}], "correct": "d", "rationale": "A | M Moderate The Pavlik harness is a soft brace designed for infants less than 6 months of age who have developmental dysplasia of the hip. The treatment B | mar for a toddler involves reduction of the hip and the use of a spica cast. This might need to be followed up with an orthotic device for a period of time to maintain the hip in an anatomically correct position. c | 3%", "whyNot": {"a": "Developmental dysplasia of the hip is a disorder that causes development of the hip to be abnormal. This can result in incomplete", "b": "The Pavlik harness is for infants from birth to 6 months of age who have hip dysplasia. The device is used to assist the hip into an abducted", "c": "Treatment for developmental dysplasia of the hip for a toddler involves reduction of the hip into proper positioning using either a closed"}, "keyConcept": "A nurse who is providing education to the parent or guardian of a toddler who has a spica cast for the treatment of developmental dysplasia of the hip should include information on cast care, transportation safety because a specialized car seat can be required to accommodate the cast, and hygiene needs, particularly the perineal area. The nurse should also address the developmental and emotional needs of the toddler who might have limited mobility related to the spica cast."}, {"id": 10378, "cat": "MUSCOSKELETAL", "stem": "A nurse is preparing a staff in-service about developmental dysplasia of the hip in preschoolers. Which of the following assessments should the nurse include?", "choices": [{"id": "a", "t": "Barlow test"}, {"id": "b", "t": "Trendelenburg sign"}, {"id": "c", "t": "Cobb technique"}, {"id": "d", "t": "Ortolani test"}], "correct": "b", "rationale": "‘i 32% Hard The Trendelenburg sign assesses for developmental dysplasia of the hip in a preschool-age child. The preschooler bears weight on the es im 27% affected leg while holding on to something for balance. The examiner observes from behind for abnormal downward tilting of the pelvis on the unaffected side. c i 8% > i” 33%", "whyNot": {"a": "Developmental dysplasia of the hip is a disorder in which the hip develops abnormally. This can result in subluxation or dislocation of the", "c": "The Cobb technique is a method used to evaluate the curvature angle of the spine for a client who has scoliosis.", "d": "The Ortolani test assesses developmental dysplasia of the hip for infants. It is most reliable when performed on infants less than 4 weeks"}, "keyConcept": "Assessment for developmental dysplasia of the hip includes observation of the gluteal folds, which will be uneven in an infant or child who has dysplasia, or evaluating the length of the legs; one will be shorter than the other if developmental dysplasia is present. Other techniques include the Ortolani and Barlow tests for infants, and, for the older child, assessment of uneven hips while a child is standing on one leg, which is an indication of a positive Trendelenburg sign."}, {"id": 10379, "cat": "MUSCOSKELETAL", "stem": "The nurse is teaching a client with rheumatoid arthritis about how to manage the fatigue associated with RA. Which statement indicates the client understands how to manage the fatigue?", "choices": [{"id": "a", "t": "“I sleep for 8 to 10 hours every night so that will have the energy to care for my children during the day.”"}, {"id": "b", "t": "“I schedule afternoon rest periods for myself in addition to sleeping 10 hours at night.”"}, {"id": "c", "t": "“I spend one weekend day a week resting in bed while my husband cares for the children.”"}, {"id": "d", "t": "“I get up early in the morning and get my household chores completed before my children wake up.”"}], "correct": "b", "rationale": "All 14% Easy Regularly scheduled rest periods during the day along with 10 hours of sleep at night helps relieve the fatigue, pain, and stiffness associated es sid 20% with RA. c | 2%", "whyNot": {"a": "While the client seems to be getting plenty of sleep at night, she should also schedule regular rest periods during the day.", "c": "Although one day of rest per week may help, the client needs more rest periods throughout the week.", "d": "Getting up early to do chores may cause the client to lose sleep and feel more tired during the day."}, "keyConcept": "Rheumatoid arthritis (RA) is a chronic, progressive, systemic inflammatory autoimmune disease process that affects synovial joints. In a = o B f= 4 ° = a = g < addition to joint pain, clients with RA often experience fatigue, weakness, low-grade fever, anorexia, and weight loss. Fatigue often makes the performance of daily tasks difficult. Resting the inflamed joint as well as the entire body by taking a nap is beneficial. Rest periods can alternate with exercise. Psychosocial interventions and participation in physical activity have been shown to provide benefits in the reduction of fatigue in clients with RA."}, {"id": 10380, "cat": "MUSCOSKELETAL", "stem": "A nurse is asked to speak to a group of women at a community health day about osteoporosis. Which of the following should she include when discussing the risk factors for osteoporosis?", "choices": [{"id": "a", "t": "Obesity"}, {"id": "b", "t": "Late menopause"}, {"id": "c", "t": "Multiparity"}, {"id": "d", "t": "Cigarette smoking"}], "correct": "d", "rationale": "A Hi 18% Moderate 8 11% Osteoporosis is a disorder that affects over 9 million people in the United States, primarily women. It is characterized by a low bone mass Cc l 3% with disruption of bone architecture and bone fragility that increases the risk of fractures, most commonly in the spine, pelvis, hip, humerus, eD | 68% or wrist. Risk factors for osteoporosis include advanced age, low body weight, excess alcohol consumption, cigarette smoking, family history of hip fracture or prior fracture, and long-term use of glucocorticoids. Smoking decreases the production of estrogen and causes earlier and more rapid bone loss. Post-menopausal women are at risk due to decreased estrogen levels, since estrogen stimulates osteoblasts to build bone. Estrogen is also necessary for conversion of vitamin D to calcitonin, which activates D cell receptors in the intestine to facilitate absorption of calcium. The fractures associated with osteoporosis are considered low trauma or pathologic fractures and may result in limited ambulation, chronic pain, depression, and loss of independence.", "whyNot": {"a": "Low body weight is a risk factor. Obesity may have a protective effect due to higher estrogen levels from the conversion of androgens in", "b": "Early menopause is a risk factor for osteoporosis.", "c": "Nulliparity is associated with increased risk for osteoporosis."}, "keyConcept": "Modifiable risk factors for osteoporosis include low body weight, excess alcohol consumption, cigarette smoking, and long-term glucocorticoid use. Postmenopausal women should supplement their diet with calcium and 800 to 1000 IU of vitamin D, which facilitates absorption of calcium and phosphate in the gut."}, {"id": 10381, "cat": "MUSCOSKELETAL", "stem": "by the nurse? O A. Positively reinforce the proper body mechanics with praise O B. Negatively reinforce the improper body mechanics with a reprimand O C. Use this observation to re-educate the staff member about the center of gravity O D. Use this observation to re-educate the staff member about the line of gravity", "choices": [{"id": "a", "t": "Positively reinforce the proper body mechanics with praise"}, {"id": "b", "t": "Negatively reinforce the improper body mechanics with a reprimand"}, {"id": "c", "t": "Use this observation to re-educate the staff member about the center of gravity"}, {"id": "d", "t": "Use this observation to re-educate the staff member about the line of gravity"}], "correct": "c", "rationale": "You should use this observation to re-educate the staff member about the center of gravity. Although the spine should remain in alignment without torsion or reaching, the knees should be bent with the center of gravity low. A reprimand is not appropriate.", "whyNot": {"a": "The nurse should use the opportunity to educate the staff member about the proper use of body mechanics.", "b": "Reprimanding the staff member is inappropriate and not helpful.", "d": "The nurse should educate the staff member about the center of gravity, not the line of gravity."}, "keyConcept": "The charge nurse observes client care delivery and outcomes resulting from care by nurses and unlicensed assistive personnel. The charge nurse should advise and educate fellow staff as necessary. The charge nurse demonstrates leadership through teaching and clinical practice. Teaching opportunities include informal teaching to staff, peer consultation, mentorship, preceptor programs, unit conferences, case studies, client rounds, and in-service programs."}, {"id": 10382, "cat": "MUSCOSKELETAL", "stem": "following positions in bed several times a day?", "choices": [{"id": "a", "t": "Prone"}, {"id": "b", "t": "Very low Fowler’s"}, {"id": "c", "t": "Modified Trendelenburg"}, {"id": "d", "t": "Side-lying"}], "correct": "a", "rationale": "To help prevent flexion deformities, a client should lie in the prone position in bed for about 2 hour several times a day. This will help to keep the hips and knees in an extended position.", "whyNot": {"b": "Low Fowler’s position will not necessarily help to prevent hip flexion deformities, as the client’s hips are still slightly flexed in this position.", "c": "The modified Trendelenburg position would not impact hip flexion deformities.", "d": "The side-lying position will not help to prevent hip flexion deformities, as the client’s hips may be flexed in this position."}, "keyConcept": "The prone position is the only fully extended position and can be used to extend the hip several times a day to prevent flexion deformity in the immobile client."}, {"id": 10383, "cat": "MUSCOSKELETAL", "stem": "who are post-op hip replacement? O A. Place pillows between the client's legs O B. Allow the client to cross the legs O C. Lower the head of the bed O D. Assist the client to sit in a low chair", "choices": [{"id": "a", "t": "Place pillows between the client's legs"}, {"id": "b", "t": "Allow the client to cross the legs"}, {"id": "c", "t": "Lower the head of the bed"}, {"id": "d", "t": "Assist the client to sit in a low chair"}], "correct": "a", "rationale": "After total hip replacement, adduction of the affected limb should be prevented, either by placing an abductor splint or 2 pillows between . ci 8%", "whyNot": {"b": "This may increase the risk of hip dislocation and should be avoided.", "c": "Lowering the head of the bed is unnecessary in this situation.", "d": "The client would not get up to sit in a chair while still in the recovery room."}, "keyConcept": "In hip replacement, the acetabulum and the head of the femur are replaced with prostheses. Common post-operative complications include dislocation of the hip prosthesis, excessive wound drainage, thromboembolism, and infection. To prevent dislocation of the prosthesis, the nurse should position the client’s leg in abduction. The femoral head component of the acetabular cap must be maintained in the correct position. The hip can be kept in abduction by splints, wedge pillows and placement of two or three pillows between the client's legs. If the client needs to be turned, the operative hip must be kept in abduction and the entire length of the leg must be supported by pillows."}, {"id": 10384, "cat": "MUSCOSKELETAL", "stem": "A nurse is preparing to perform passive range-of-motions (ROM) exercises for a client who is experiencing restrictions in activity. Which of the following action should the nurse plan to take?", "choices": [{"id": "a", "t": "Start the exercises at the toes and move to the neck."}, {"id": "b", "t": "Repeat each exercise twice."}, {"id": "c", "t": "Move the extremity joint just beyond the point of resistance."}, {"id": "d", "t": "Place a cupped hand under the extremity during the exercises."}], "correct": "d", "rationale": "Passive ROM exercises are performed by the nurse in order to move each joint of the client's body if there are no joint restrictions. Passive ROM maintains joint flexibility but does not involve muscle contraction and is of no value for maintaining muscle strength. Passive ROM exercises involve moving the joints of the client's arms, legs, and neck. The goal is for the client is to move from passive to active-assistive ROM exercises over time.", "whyNot": {"a": "The nurse should use a series of head-to-toe of passive ROM exercises that start at the client's neck and move down to the toes. The nurse", "b": "The nurse should plan to repeat each exercise three to four times to maintain joint flexibility and maximize stretching of the muscle", "c": "The nurse should move the client's extremities slowly and smoothly just to the point of resistance. The client should not feel any type of"}, "keyConcept": "Passive ROM exercises are performed by the nurse in order to move each joint of the client's body if there are no joint restrictions. Passive ROM maintains joint flexibility but does not involve muscle contraction and is of no value for maintaining muscle strength. Passive ROM exercises involve moving the joints of the client's arms, legs, and neck. The goal is for the client is to move from passive to active-assistive ROM exercises over time."}, {"id": 10385, "cat": "MUSCOSKELETAL", "stem": "Which of the following nursing instructions should be given to a 13-year-old female with scoliosis who is discharged with a thoracolumbosacral orthosis (TLSO) brace?", "choices": [{"id": "a", "t": "Avoid activities that require the use of spinal muscles."}, {"id": "b", "t": "Take showers instead of baths and keep the brace on while showering."}, {"id": "c", "t": "Wear a cotton t-shirt underneath the brace."}, {"id": "d", "t": "Apply powder or lotion beneath the brace to reduce skin irritation."}], "correct": "c", "rationale": "A Hi 16% Moderate ce | 5% Braces used to diminish progression of scoliosis include the TLSO brace, Milwaukee brace, Boston brace, and Wilmington brace. None cure ec | 70% existing spinal deformities, but they can prevent progression. These braces are molded plastic shells that are worn under outer clothing and D i 8% cover the trunk of the body. Because the molded plastic can cause skin irritation and an environment that promotes skin breakdown, a cotton shirt should be worn underneath the brace at all times to reduce sweating and subsequent complications. These braces may also be prescribed to some clients after spinal fusion.", "whyNot": {"a": "Spinal muscle exercise is important to maintain strength, which promotes stabilization of the spine. The brace is usually removed during", "b": "The brace should be worn for the prescribed period of time, usually 18-23 hours/day. It is removed for exercise and bathing. Showering in", "d": "Use of powder or lotion may irritate the skin under the brace due to the increased temperature beneath the brace."}, "keyConcept": "If the TLSO brace is applied to tightly, the superior mesenteric artery can be compressed against the duodenum, causing superior mesenteric artery syndrome, also known as cast syndrome. Cast syndrome is characterized by abdominal pain, abdominal pressure, nausea, and vomiting. Treatment is gastric decompression with a nasogastric tube and suction."}, {"id": 10386, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a toddler who is scheduled to have a lumbar puncture (LP). Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Cleanse the thoracic area with an antiseptic solution prior to the procedure."}, {"id": "b", "t": "Apply a local anesthetic cream to the puncture site 5 minutes prior to the procedure."}, {"id": "c", "t": "Instruct the parents to keep the toddler in a flat position for 30 minutes to one hour after the procedure."}, {"id": "d", "t": "Position the toddler with the head extended and chin raised during the procedure."}], "correct": "c", "rationale": "Mm | 20% Hard The nurse should inform the parents what to expect before, during, and after the procedure. After a lumbar puncture, the toddler should lie B | omy flat for about 30 minutes. It is important for the child to remain hydrated. The nurse should encourage the child to drink a glass of water, to decrease the risk of spinal headaches. If a headache occurs, an analgesic can be prescribed by the healthcare provider. ec | 49% of 4%", "whyNot": {"a": "The provider will insert the aspiration needle into the lumbar L4/L5 level of the spine. The lumbar area of the toddler's back should be", "b": "A local anesthetic cream should be applied to the lumbar area of the spine for 45 to 60 min prior to the procedure to ensure that the area is", "d": "The toddler should be positioned and held on his side with his head flexed forward. The toddler's knees should be flexed against his"}, "keyConcept": "A lumbar puncture is performed for diagnosis of possible cerebral hemorrhage or central nervous system infection. The cerebrospinal fluid is aspirated through a needle inserted into the subarachnoid space of the spinal canal at the level of L3-L4 or L4-L5; it is then sent to the lab for analysis and culture. Topical anesthetic cream or lidocaine can be applied to the puncture site approximately 1 hour prior to the procedure to numb the skin and limit the pain associated with the procedure. A small child or toddler should be positioned and held by the nurse on the side with the head flexed forward and their knees flexed toward their abdomen in a \"rolled up\" position. The lumbar area should be cleaned thoroughly prior to the procedure and strict aseptic technique should be observed. The child can experience an increase in intracranial pressure after the procedure and should be monitored for changes in pupil size, level of consciousness, respirations, or decrease in blood pressure."}, {"id": 10387, "cat": "MUSCOSKELETAL", "stem": "A nurse is developing a plan of care for a 4-year-old child who has cerebral palsy. Which of the following actions should the nurse include?", "choices": [{"id": "a", "t": "Structure interventions according to the child's chronological age."}, {"id": "b", "t": "Evaluate the child's need for referral to a speech-language therapist."}, {"id": "c", "t": "Monitor the child's pain level routinely using a numeric rating scale."}, {"id": "d", "t": "Provide total care for daily hygiene activities."}], "correct": "b", "rationale": "A ; | 25% Moderate The nurse should recognize that a child who has cerebral palsy has an increased risk for dysphagia and communication difficulties and OB a er requires a referral to a speech-language therapist. Other necessary referrals might include an audiologist, to address a potential hearing deficit, and a dentist, especially if the child is taking phenytoin for seizure management. This medication can cause gingival hyperplasia. c | 4% om 13%", "whyNot": {"a": "The nurse should structure interventions according to the child's developmental level, rather than the child's chronological age. {)", "c": "The nurse should routinely monitor the child's pain level using a developmentally appropriate pain tool, such as the FACES pain rating A", "d": "Although a 4-year-old child requires assistance and supervision with hygiene activities, the nurse should promote as much independence g"}, "keyConcept": "Nursing care of a child who has cerebral palsy involves needs assessments for referrals to providers who can address specific needs of the child. A health care team consisting of a physical therapist, occupational therapist, and speech-language therapist, in addition to the nurse and health provider, are often required to provide evidence-based care and meet the different needs of the child."}, {"id": 10388, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client who is post-op lumbar laminectomy. Which of the following is appropriate when caring for this client?", "choices": [{"id": "a", "t": "Encourage the client to cough frequently and deep-breathe"}, {"id": "b", "t": "Assist with repositioning by using the draw sheet and logrolling the client"}, {"id": "c", "t": "Assess the client for symptoms of peritonitis"}, {"id": "d", "t": "Instruct the client to bend the knees while turning"}], "correct": "b", "rationale": "A Hi 19% Moderate Logrolling will maintain the alignment of the vertebral column.", "whyNot": {"a": "The client should be instructed to deep-breathe and use the incentive spirometer. However coughing should be avoided because it would", "c": "The abdominal cavity has not been opened, so peritonitis is not a typical complication.", "d": "Flexion of the knees should be avoided in this client post-operatively as it could irritate inflamed spinal nerve roots. Bending, stooping,"}, "keyConcept": "When caring for a client who has undergone lumbar laminectomy, the nurse should consider body mechanics to maintain proper spinal alignment in a neutral spine position. The client usually must remain flat in bed for a period of time after surgery.The nurse should keep the bed flat or elevate the head of the bed slightly, placing a small pillow under the head. If the client lies on the side, the nurse should place a small pillow under the knees, or use a pillow to support the upper leg. This will minimize stress on the surgical incision. The client should be turned every 2 hours, using the logrolling technique. The nurse should advise the client not to use the side rails to change position and to maintain proper body alignment in all positions."}, {"id": 10389, "cat": "MUSCOSKELETAL", "stem": "A nurse is teaching the parent of a child who has growth hormone deficiency. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"This disorder will not affect your child's ability to gain weight.\""}, {"id": "b", "t": "\"Your child will experience a decrease in insulin sensitivity.\""}, {"id": "c", "t": "\"Your child will experience excessive bone growth.\""}, {"id": "d", "t": "\"This disorder may cause your child to appear older than their actual age.\""}], "correct": "a", "rationale": "Growth hormone deficiency affects overall skeletal growth. Children with this disorder are able to gain weight in a typical pattern. This B i oa manifestation can provide clues as to the cause of a child's short stature. ° chi 6%", "whyNot": {"b": "Children who have growth hormone deficiency will have an increased sensitivity to insulin because of the effects on the pituitary gland.", "c": "Children who have growth hormone deficiency experience decreased bone growth in relation to their height.", "d": "Children who have growth hormone deficiency typically appear younger than their chronological age. However, later in life individuals"}, "keyConcept": "Growth hormone, also known as somatotropin, is responsible for growth and development. A deficiency of growth hormone can cause improper growth in the child. This condition can be caused by pituitary tumors. Initially, the child's stature appears proportional but eventually falls below standards on the growth curve. The provider and other health care professionals should recognize this condition early and evaluate. Growth and development records can identify the alterations in expected growth for age. Manifestations of this condition include a delay in the epiphyseal bone closure and increased sensitivity to insulin. Treatment involves the administration of growth hormones."}, {"id": 10390, "cat": "MUSCOSKELETAL", "stem": "client have? O A. Grade O > B.Grade ll O c.Grade tl! O b.Grade iv", "choices": [{"id": "a", "t": "A grade open fracture has only minimal superficial skin damage."}, {"id": "b", "t": "A grade II open fracture has damaged the skin and part of the muscle but does not have extensive tissue damage."}, {"id": "c", "t": "This client has a Grade III open fracture, which involves excessive tissue, nerve, and vascular damage."}, {"id": "d", "t": "There is no grade IV open fracture classification."}], "correct": "c", "rationale": "This client has a Grade III open fracture, which involves excessive tissue, nerve, and vascular damage. Grade | open fractures have minimal superficial skin damage, and a Grade II open fracture has damaged the skin and part of the muscle but not with extensive tissue damage. Open fractures are graded only as Grade |, Grade Il and Grade III.", "whyNot": {"a": "A grade | open fracture has only minimal superficial skin damage.", "b": "A grade II open fracture has damaged the skin and part of the muscle but does not have extensive tissue damage.", "d": "There is no grade IV open fracture classification."}, "keyConcept": "To prevent infection in a client with a grade III fracture, the nurse must observe strict aseptic technique when cleaning the wound or changing the dressing. Other complications associated with fractures include hypovolemic shock due to hemorrhage; fat embolism syndrome; and compartment syndrome."}, {"id": 10391, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for an elderly client with rheumatoid arthritis. The most effective intervention for relieving stiffness in this client is which of the following?", "choices": [{"id": "a", "t": "Aspirin to decrease inflammation in the joints"}, {"id": "b", "t": "Recommending that the client lose 20 pounds"}, {"id": "c", "t": "Taking a warm shower or bath in the morning"}, {"id": "d", "t": "Applying cold to the affected joints"}], "correct": "c", "rationale": "A || 12% Moderate Awarm bath or shower in the morning may help to relieve stiffness from sleeping.", "whyNot": {"a": "Aspirin can be used before exercise to decrease inflammation, but may not be helpful in relieving stiffness. D i 8%", "b": "Losing weight may be helpful in decreasing the stress on joints, but this intervention will not help to relieve stiffness.", "d": "Cold is not effective for relieving stiffness, but may help with joint pain."}, "keyConcept": "Rheumatoid arthritis (RA) is a chronic autoimmune disease of unknown origin that causes diffuse inflammation and destruction of connective tissues. Treatment goals include Improvements in comfort level; daily incorporation of pain management techniques and strategies to modify fatigue; maintenance of optimal functional mobility; and the use of effective coping strategies to deal with actual or perceived limitations."}, {"id": 10392, "cat": "MUSCOSKELETAL", "stem": "@.@ X Viral x Reco ™M™ Inbox ™ Inbox {J untit! Untit!| €4 Gooo @ TEAS Onlin @& Mark @ Micre (eeiaenurmelicr © atit € > G 23 student.atitesting.com/LT| © New Fx ATIT G GER + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN Set Module: Results Dashboard Quiz ~ Performance ~ #& Highlight ~ S Strikeout =) Calculator Lab Values Figure/Media A nurse is caring for a 65-year-old client with poorly controlled diabetes. The client is being admitted to the hospital. During the intake assessment, the nurse notes that the client’s right hand appears similar to the hand in the photo. Based on her knowledge of this condition, the nurse knows that this is a:", "choices": [{"id": "a", "t": "Peyronie’s contracture"}, {"id": "b", "t": "Muscular dystrophy deformity"}, {"id": "c", "t": "Dupuytren’s contracture"}, {"id": "d", "t": "Ehlers-Danlos syndrome deformity"}], "correct": "c", "rationale": "The client with a hand similar to that in the photo is most likely suffering from Dupuytren’s contracture. In this condition, the fingers are bent in the direction of the palm and cannot be extended; the condition develops from fibromatosis in the palm. Dupuytren's contracture is fairly common and it is characterized by progressive fibrosis of the palmar fascia, beginning with a nodule in the palm. Eventually, usually over the course of several decades, a loss of full extension accompanied by joint stiffness occurs.", "whyNot": {"a": "Peyronie's disease refers to an acquired, localized fibrotic disorder of the tunica albuginea of the penis.", "b": "There are a variety of types of muscular dystrophy, but none are characterized by palmar contractures.", "d": "Ehlers-Danhos syndrome is characterized by skin hyperextensibility, joint hypermobility, and tissue fragility."}, "keyConcept": "The nurse can advise the client with Dupuytren contracture to apply heat. Ultrasound may also be helpful in the early stages. A physical therapist may recommend a custom splint or brace to stretch the fingers. Range of motion (ROM) exercises should be performed several % CLOSE { Browse Questions > iit Search Questions QJ"}, {"id": 10393, "cat": "MUSCOSKELETAL", "stem": "A nurse is reinforcing preoperative teaching with an adolescent client who is scheduled for surgical correction of severe scoliosis. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"You will go home the same day of the surgery.\""}, {"id": "b", "t": "\"You will have minimal pain.\""}, {"id": "c", "t": "\"You may need to receive blood.\""}, {"id": "d", "t": "\"You will be on bedrest for the first week following surgery.\""}], "correct": "c", "rationale": "A 4% Hard Clients who undergo surgical correction for severe scoliosis typically experience significant blood loss and can require blood replacements. I B 1% Options for blood replacement include the use of a blood salvage unit during surgery, the administration of autologous blood or donor | blood, and the administration of erythropoietin to stimulate new blood formation. The client's provider should discuss each of these options ec 44% with the client and the client's parents or guardians.", "whyNot": {"a": "Surgical correction of severe scoliosis can include realignment and fusion of the spine, along with the placement of internal fixation", "b": "Clients who have spinal instrumentation for scoliosis experience intense pain that requires a patient-controlled analgesia (PCA) pump.", "d": "Clients who are postoperative following surgical repair of scoliosis are assisted with ambulation 2 to 3 days following surgery with"}, "keyConcept": "Scoliosis is a spinal deformity that often involves lateral curvature and rotation of the spine. This results in asymmetry of the shoulders, ribs, and hips. The preferred treatment for moderate scoliosis with spinal curvature between 25° and 45° is bracing, which slows the progression of further curvature. For severe scoliosis with spinal curvature greater than 45°, surgery might be required. Preoperative teaching for an adolescent who is scheduled to undergo corrective surgery for scoliosis should include: Information on postoperative pain control, ambulation, and exercise Logrolling while in bed to change positions Function of the lV pump, indwelling urinary catheter, and other drainage devices that might be placed Coughing and deep breathing"}, {"id": 10394, "cat": "MUSCOSKELETAL", "stem": "of the affected foot? O A. Exercise with each diaper change O B. Exercise once a day in the morning O C. Exercise twice a day after each nap O D. Exercise every four hours during the day", "choices": [{"id": "a", "t": "Exercise with each diaper change"}, {"id": "b", "t": "Exercise once a day in the morning"}, {"id": "c", "t": "Exercise twice a day after each nap"}, {"id": "d", "t": "Exercise every four hours during the day"}], "correct": "a", "rationale": "o; say Moderate Exercising should be done often; association with a specific activity makes it easier to incorporate it into a routine. B I a", "whyNot": {"b": "Exercise should be done more than once per day. D ; | 34%", "c": "Exercise should be done more than twice per day. °", "d": "Every four hours during the day might be appropriate but it would be easier to remember if the exercise is associated with a certain ="}, "keyConcept": "Clubfoot is a congenital deformity usually caused by a shortened Achilles tendon, which causes the foot to turn in and under. The bones of the foot and ankle are misaligned due to changes in the muscles and tendons acting on the foot. Clubfoot is usually treated by casting followed by bracing."}, {"id": 10395, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client who has a simple fracture of the humerus. Which of the following images represents a simple fracture? KHIM", "choices": [{"id": "a", "t": "This is an example of a comminuted fracture, in which there are fragments of broken bone surrounding the fracture."}, {"id": "b", "t": "| 2% Easy In a simple fracture, there is a clean break across the bone."}, {"id": "c", "t": "This is an example of a greenstick fracture, where the bone is partially broken and bent. It is called a “greenstick” because it appears"}, {"id": "d", "t": "This is an example of a spiral fracture. The bone is broken due to a twisting motion and there is a spiral or helical fracture line."}], "correct": "b", "rationale": "| 2% Easy In a simple fracture, there is a clean break across the bone.", "whyNot": {"a": "This is an example of a comminuted fracture, in which there are fragments of broken bone surrounding the fracture.", "c": "This is an example of a greenstick fracture, where the bone is partially broken and bent. It is called a “greenstick” because it appears", "d": "This is an example of a spiral fracture. The bone is broken due to a twisting motion and there is a spiral or helical fracture line."}, "keyConcept": "There are different types of fractures, for which there are different causes and treatments. Some types of fractures occur more commonly in certain ages, activities, or certain bones, such as compression fractures in the spine or greenstick fractures occurring more often in children under 10. Types of Bones Fractures"}, {"id": 10396, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client with hip pain related to rheumatoid arthritis. Which of the following choices of chairs by the client demonstrates understanding of appropriate self-care skills?", "choices": [{"id": "a", "t": "Recliner chair with arms to support wrists and hands"}, {"id": "b", "t": "Couch with soft cushions to support thighs"}, {"id": "c", "t": "Straight backed chair with elevated seat"}, {"id": "d", "t": "Curved back rocking chair"}], "correct": "c", "rationale": "Rheumatoid arthritis is a chronic autoimmune disorder that results in a systemic inflammatory response. RA is characterized by symmetrical joint pain and inflammation; subcutaneous nodules; and morning stiffness. Joint pain results from inflammation that results in increased synovial tissue and destruction of joint cartilage. Permanent damage can be avoided with aggressive, early treatment. Treatment includes nonsteroidal anti-inflammatory drugs (NSAIDs), corticosteroids, and disease-modifying antirheumatic drugs (DMARDs.)", "whyNot": {"a": "Arecliner may be difficult and painful for the client to get into and out of.", "b": "A couch with soft cushions may not provide enough support for a client with rheumatoid arthritis.", "d": "This type of chair may be difficult to get into, sit in, and get out of for the client."}, "keyConcept": "Rheumatoid arthritis is a chronic autoimmune disorder that results in a systemic inflammatory response. RA is characterized by symmetrical joint pain and inflammation; subcutaneous nodules; and morning stiffness. Joint pain results from inflammation that results in increased synovial tissue and destruction of joint cartilage. Permanent damage can be avoided with aggressive, early treatment. Treatment includes nonsteroidal anti-inflammatory drugs (NSAIDs), corticosteroids, and disease-modifying antirheumatic drugs (DMARDs.)"}, {"id": 10397, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client with osteoarthritis who is receiving an injection of hydrocortisone into the knee joint. Which of the following does the nurse understand is the most significant reason for this treatment?", "choices": [{"id": "a", "t": "Repair cartilage"}, {"id": "b", "t": "Reduce inflammation caused by arthritis"}, {"id": "c", "t": "Provide physiotherapy to the joint"}, {"id": "d", "t": "Prevent ankylosis of the joint"}], "correct": "b", "rationale": "-inflammatory properties and reduce the inflammation caused by arthritis. OB SY ox", "whyNot": {"a": "Steroid injections relieve pain and inflammation but do not repair cartilage.", "c": "The injection of medication is not physiotherapy.", "d": "Ankylosis is the fusion of joints. It may be indirectly affected by steroids but this is not the primary reason for the injection."}, "keyConcept": "Steroid injections are used to relieve symptoms in clients with joint pain and inflammation, including those affected by rheumatoid arthritis, osteoarthritis, gout, and frozen shoulder. Short-acting steroid injections can provide relief within hours and last for at least one week. Longer-acting steroid injections take about a week to achieve a therapeutic effect but can be effective for two months or more."}, {"id": 10398, "cat": "MUSCOSKELETAL", "stem": "Which of the following conditions would be an indication for gallows traction? O A.Acompound open humerus fracture O B. Age over 4 years O C. Weight less than 12 kg O D. The presence of neuropathy", "choices": [{"id": "a", "t": "Gallows traction is used to treat fractures of the femoral shaft, not the humerus."}, {"id": "b", "t": "Gallows traction is used in children under 2 years old, not 4 years old."}, {"id": "c", "t": "si 45% Hard Gallows traction is used to treat fractures of the shaft of the femur in children younger than 2 years who weigh 10-12 kg (22-26.5 lbs.) The a I ar traction should lift the child's buttocks off the bed."}, {"id": "d", "t": "Neuropathy is not an indication for gallows traction."}], "correct": "c", "rationale": "si 45% Hard Gallows traction is used to treat fractures of the shaft of the femur in children younger than 2 years who weigh 10-12 kg (22-26.5 lbs.) The a I ar traction should lift the child's buttocks off the bed. The nurse should monitor the neurovascular status of the extremity after the application of traction. This type of traction is not recommended in older children because of an increased risk of compartment syndrome, vascular ec | 43% insufficiency, peroneal nerve palsy, and skin breakdown. D | T% a = N FANN a © o 2 ° s a = a < N ANS", "whyNot": {"a": "Gallows traction is used to treat fractures of the femoral shaft, not the humerus.", "b": "Gallows traction is used in children under 2 years old, not 4 years old.", "d": "Neuropathy is not an indication for gallows traction."}, "keyConcept": "Gallows traction is a type of orthopedic traction used to treat femur fractures in children under the age of 2 who weigh less than 12 kg (26.5 lbs.) Gallows traction lifts the legs and buttocks off of the bed."}, {"id": 10399, "cat": "MUSCOSKELETAL", "stem": "The nurse is caring for a client with a new plaster cast on his left arm. Which of the following will the nurse NOT include in teaching this client about cast care?", "choices": [{"id": "a", "t": "Keep the arm below the level of your heart"}, {"id": "b", "t": "Keep the cast dry"}, {"id": "c", "t": "Do not insert anything into the cast"}, {"id": "d", "t": "Exercise your joints above and below the cast every day"}], "correct": "a", "rationale": "o; With a newly applied cast, it is important to keep the arm ABOVE the level of the heart to prevent pooling of blood with consequent swelling B | and pain in the arm and hand. A plaster cast will disintegrate if it gets wet. Putting anything in the cast (for example, to scratch itchy skin) may cause pressure points and skin disruption. Either of these can lead to infection under the cast. Exercising the joints above and below the € | cast will help prevent muscle atrophy. D Hi", "whyNot": {"b": "The plaster cast should be kept dry to maintain the integrity of the cast.", "c": "The client should not slide anything under the cast, which could cause skin injury or breakdown underneath; this could further lead to skin", "d": "Over time, the cast can reduce muscle function of the affected area; however, exercising and moving the joints above and below the cast"}, "keyConcept": "Casts and splints support and protect injured bones and soft tissue while healing occurs and can be made of plaster or fiberglass The nurse should instruct the client to elevate.the injured arm or leg for the first 24 to 72 hours. The client should prop the injured arm or leg up above the heart by putting it on pillows or some other support. If the splint or cast is on the leg, the client will have to recline to allow the flow of lymph and blood to drain to the heart. The client should also exercise the uninjured fingers/toes and joins gently and often. to prevent stiffness. Ice can be applied in a plastic bag or ice pack and wrapped around the splint or cast. Compartment syndrome is a serious complication of a cast or fracture. The nurse must advise the client to report Increased pain or tightness in the cast that may be the result of swelling; numbness and tingling in the hand or foot that may be caused by increased pressure on the nerves; burning and stinging; or excessive swelling below the cast. These signs of increased pressure within the muscular compartments of the arm or leg must be evaluated urgently to avoid permanent damage, including loss of function. The image below depicts swelling compartment syndrome. causes pressure on ‘surrounding tissue"}, {"id": 10400, "cat": "MUSCOSKELETAL", "stem": "A nurse in the emergency department is caring for a client with a spinal cord injury. Which intervention should the nurse prioritize?", "choices": [{"id": "a", "t": "Place a small pillow under the client's head for comfort"}, {"id": "b", "t": "Move the client gently to decrease pain"}, {"id": "c", "t": "Restrain the client's arms and legs to limit movement"}, {"id": "d", "t": "Immobilize the client's head and neck"}], "correct": "d", "rationale": "The head and neck of a client with a spinal cord injury must be maintained in strict alignment with the rest of the spine. If the client is transported by EMS, it is likely that the paramedics will have applied a hard cervical collar, which is critical to maintain alignment and prevent injury to the spinal cord during transport. The client should be “logrolled” by 2-3 personnel when repositioning or moving, to ensure that spinal alignment is maintained. It is not appropriate to restrain the client or use pillows for comfort until X-rays of the cervical spine and clinical exam confirm there is no spinal instability.", "whyNot": {"a": "The nurse must keep the client’s head and neck in alignment and should not provide a pillow at this time.", "b": "The nurse should avoid moving the client to reduce the risk of further cord injury.", "c": "Itis not appropriate to restrain the client’s arms and legs; the nurse must keep the client's head and neck in alignment."}, "keyConcept": "Spine injury should always be considered a possibility in any client who experiences significant trauma to the head or thorax. Common causes of trauma implicated in spinal cord injury include motor vehicle accidents (MVA), falls, and pedestrian-vehicle accidents. To protect the spinal cord from additional injury, healthcare personnel should institute \"spinal precautions\" in these clients. Estimates of neurologic damage caused as a result of inadequate spinal cord immobilization after a traumatic event range from 3 to 25%. Spinal precautions include holding the head in position, application of a cervical collar, maintenance of neutral alignment, and log rolling when repositioning or moving the client."}, {"id": 10401, "cat": "MUSCOSKELETAL", "stem": "Which of the following is a low-risk therapy that the nurse can include in a discussion with a client who complains of stress and back pain?", "choices": [{"id": "a", "t": "Over-the-counter medications"}, {"id": "b", "t": "Relaxation techniques"}, {"id": "c", "t": "Acupuncture"}, {"id": "d", "t": "Spinal manipulation"}], "correct": "b", "rationale": "A| o: Low-risk therapies include therapies that do not have potential adverse effects and can be implemented by nurses with training and © i experience in the use of those therapies. These include relaxation techniques, touch, meditation, humor and laughter, massage, music and D | imagery therapy, and spiritual measures. Mind-body therapies connect physiological functions with emotions and feelings. Biofeedback is an example of a low-risk therapy employs use of technology to increase awareness of the body's neurological response to pain to enable minimization of extreme responses. Massage stretches and relaxes muscles and connective tissue, which improves tissue perfusion and relieves stress.", "whyNot": {"a": "Over-the-counter medications have the potential for adverse effects.", "c": "Acupuncture has the potential for adverse effects, although it is usually considered fairly low risk.", "d": "Spinal manipulation has the potential to cause harm."}, "keyConcept": "Low-risk therapies include treatment modalities that complement or replace analgesic medications for relief of pain and do not have potential adverse effects. Examples of low-risk therapy for stress and back pain include massage, biofeedback, guided imagery, movement (dance, yoga), and energy therapies."}, {"id": 10402, "cat": "MUSCOSKELETAL", "stem": "The nurse is caring for an elderly man who has hip pain related to rheumatoid arthritis. This client is practicing appropriate self-care activities when the client chooses to sit in which of the following chairs?", "choices": [{"id": "a", "t": "Reclining chair with arms to support wrists and hands"}, {"id": "b", "t": "Couch with soft cushions to support thighs"}, {"id": "c", "t": "Straight-backed chair with an elevated seat"}, {"id": "d", "t": "Curved back rocking chair"}], "correct": "c", "rationale": "A | | 26% Moderate Itis important for clients with rheumatoid arthritis to maintain proper posture and body alignment to support joints and decrease pain and B ] 12% stiffness. The client will be most comfortable sitting in a straight-backed chair with an elevated seat.", "whyNot": {"a": "Arecliner may be difficult for the client to get into or get out of; support for the hands and wrists might be important with arthritis, but it", "b": "Soft cushions might be comfortable, but the client would benefit from a supportive chair to best help his hip pain.", "d": "Acurved back rocking chair may be difficult for the client to sit in or to get out of; he should instead sit in a stable chair that has support."}, "keyConcept": "Hip pain can be relieved at night by advising the client to sleep with wedge-shaped pillows under the hip to provide cushioning. A pillow between the knees can reduce stress across the hips. Placement of one or more pillows under the knees is also recommended to reduce stress on the hip. Ice packs can be helpful to relieve hip pain caused by inflammation in clients with osteoarthritis or rheumatoid arthritis. 2 = ® 4 z = a iat g <"}, {"id": 10403, "cat": "MUSCOSKELETAL", "stem": "A nurse in an outpatient clinic is assessing a client who presents with knee pain. The nurse knows that the most reliable indicator of a client’s pain level is which of the following?", "choices": [{"id": "a", "t": "Vital signs"}, {"id": "b", "t": "Presence of physical signs of injury"}, {"id": "c", "t": "Client’s report of pain"}, {"id": "d", "t": "Cultural background"}], "correct": "c", "rationale": "al 5% Easy The client’s self-report of pain is the most reliable diagnostic measure and can be reported using a standardized visual analog pain scale. A , including the 1-10 pain scale, color pain scale, and faces (Wong-Baker). Use of the Wong-Baker pain scale or a similar scale allows individuals who are non-verbal to categorize their pain. The Wong-Baker scale uses ratings from 0-10 with a O€ FP 92% facial expression to correlate with each pain level. A similar type of facial pain scale is shown below. “Pain” Face Scale ao a nasa » )(@) (Sw) eS) (es Nae, Ww —= — rN 2 (S g o 5 [a < 0 2 4 6 8 10 No pain Mild, Nagging, Distressing, Intense, Worst possible, annoying uncomfortable, miserable dreadful, unbearable, pain troublesome pain horrible excrutiating pain pain pain", "whyNot": {"a": "Although pain may cause a physiological response with tachycardia, muscle tension, and hypertension or diaphoresis, the lack of a", "b": "Pain can be caused by damage or inflammation to tissues but may also be neuropathic, due to abnormal or damaged pain nerve", "d": "Although expression of pain may be influenced by cultural factors, this is not a reliable indicator when assessing a client’s pain self-report."}, "keyConcept": "Client self-report of pain is the most reliable diagnostic measure of pain. Standardized visual analog pain scales allow clients to categorize"}, {"id": 10404, "cat": "MUSCOSKELETAL", "stem": "A nurse has given a client a nursing diagnosis of self-care deficit related to a musculoskeletal disorder. Which intervention regarding activities of daily living would be most appropriate?", "choices": [{"id": "a", "t": "Set long-term goals for the patient to learn activities of daily living"}, {"id": "b", "t": "Encourage the patient to be independent, but help when necessary"}, {"id": "c", "t": "Positively reinforce complete achievements, not partial attempts at ADLs"}, {"id": "d", "t": "Provide bathing and toileting care but teach the client to brush his teeth and hair"}], "correct": "b", "rationale": "The nurse should encourage the client to perform as many activities of daily living as possible but provide help when necessary. This promotes independence for the client but provides an opportunity for intervention when necessary, to avoid frustrating the client.", "whyNot": {"a": "The nurse should set short-term goals to avoid frustration for the client.", "c": "The nurse should positively reinforce both partial attempts and complete achievements of activities of daily living.", "d": "The client should learn to perform as many activities as possible to foster independence."}, "keyConcept": "Adiagnosis of self-care deficit refers to the inability of an individual to perform self-care. It may occur as the result of temporary limitations, such as those that result during recovery from fracture, illness, or surgery. Self-care deficit may also result from gradual deterioration of the client's ability or willingness to perform act self-care activities. A nurse can intervene to coordinate services to maximize the client's independence, to provide a safe environment and to support the client's needs."}, {"id": 10405, "cat": "MUSCOSKELETAL", "stem": "with the transfer to a chair. Which of the following should the nurse do first?", "choices": [{"id": "a", "t": "Premedicate the client with the prescribed analgesic"}, {"id": "b", "t": "Verify the surgeon’s prescription for activity for this client"}, {"id": "c", "t": "Ask another staff member to assist"}, {"id": "d", "t": "Delegate the task to an unlicensed assistant"}], "correct": "b", "rationale": "All There may be prescribed activity restrictions for a client who has been admitted recently after a surgical procedure. The nurse should verify o: TT the healthcare provider’s prescription for activity before assisting the client to a chair. The risks associated with assisting a client to get out of bed earlier than prescribed include possible falls and injury to the surgical site. € i >|", "whyNot": {"a": "The priority is to determine the client’s prescribed activity, and pain medication should not be given prior to assessing the client’s pain", "c": "Although a client who is not able to bear weight may require assistance, in some cases the client’s size may require additional help for a", "d": "The activity prescription should be verified. If the client is getting out of bed for the first time after surgery, the unlicensed assistant may"}, "keyConcept": "Itis important to verify the healthcare provider's prescription for activity for a client admitted after a surgical procedure. Assisting the client to ambulate earlier than prescribed may increase the risk of injury to the surgical site."}, {"id": 10406, "cat": "MUSCOSKELETAL", "stem": "Which best describes placement of a spica cast?", "choices": [{"id": "a", "t": "Acast applied around the neck and trunk of the body"}, {"id": "b", "t": "A cast applied from the thigh to the ankle"}, {"id": "c", "t": "A cast applied from the chest to the thighs or knees"}, {"id": "d", "t": "A cast applied from the area below the knee to the foot"}], "correct": "c", "rationale": "Aspica cast is used to keep the hips in the proper position. It extends from the chest down over the hips and then down to the thighs or knees. A spica is commonly used to manage developmental hip dysplasia in infants. aHs. Hip Spica Casts", "whyNot": {"a": "This describes a Minerva cast, which is placed after neck surgery.", "b": "This describes a leg cylinder cast, which is applied for a leg fracture.", "d": "This describes a short leg cast, which is placed for lower leg fractures"}, "keyConcept": "Ahip spica cast is a sort of orthopedic cast used to immobilize the hip or thigh. It is used to facilitate healing of injured hip joints or of fractured femurs. A hip spica includes the trunk of the body and one or both legs."}, {"id": 10407, "cat": "MUSCOSKELETAL", "stem": "crutch gaits? O A. Any crutch gait that keeps weight off the affected side O B. 2-point gait O C. 3-point gait O D. 4-point gait", "choices": [{"id": "a", "t": "Any crutch gait that keeps weight off the affected side"}, {"id": "b", "t": "2-point gait"}, {"id": "c", "t": "3-point gait"}, {"id": "d", "t": "4-point gait"}], "correct": "c", "rationale": "A Hi 13% Moderate The client can use the 3-point gait if able to bear all bodyweight on the unaffected leg. The weight is transferred between the 2 crutches and . The nurse instructs the client to move the crutches (both) and the weaker leg forward and then to move the unaffected leg forward. o: 68% of 7%", "whyNot": {"a": "Crutch gaits involve alternating body weight on 1 or both legs and crutches. The standard gaits are the swing-through, swing-to-gait, 2-", "b": "The 2-point gait requires the client to move the left crutch and right foot forward together and then the right crutch and left foot forward", "d": "This is an easy gait but requires the client to bear weight on both legs."}, "keyConcept": "Crutch gaits involve transfer of body weight between one or both legs and the crutches. A client with an injury to a lower extremity can use a three-point gait with crutches if able to bear all body weight on the unaffected leg. A client must be able to bear weight on both legs in order to use a four-point crutch gait."}, {"id": 10408, "cat": "MUSCOSKELETAL", "stem": "inflammation. Which of the following non-pharmacological interventions should the nurse recommend?", "choices": [{"id": "a", "t": "Changing position to a position of more comfort"}, {"id": "b", "t": "Resting from activities that aggravate the pain"}, {"id": "c", "t": "Completing exercises that stretch the involved muscle group"}, {"id": "d", "t": "Using a heating pad"}], "correct": "b", "rationale": ": i 49% Inflammation is usually the cause of an acute exacerbation of chronic low back pain. It can be caused by repetitive or strenuous activities c | 1% that lead to stress and injury in previously injured muscles and joints. Intervention should be targeted at reducing inflammation at the area my rd sen of injury. Any activity that aggravates the pain promotes further inflammation and delays healing. Rest and avoidance of activities that reproduce pain will allow healing. Correct Answer: B. Resting from all activities that aggravate the pain", "whyNot": {"a": "Positioning the client correctly can reduce pain but is unlikely to diminish the inflammatory process that is underlying the pain.", "c": "Although stretching exercises are used in rehabilitation of individuals with back pain, exercises should be delayed until the acute", "d": "Application of heat causes vasodilation and can promote movement of inflammatory mediators to the area of injury, so heat should be"}, "keyConcept": "An acute exacerbation of chronic low back pain is often the result of inflammation that occurs in response to activities that increase stress in previously injured muscles or joints. Rest from activities that provokes the pain is a non-pharmacological intervention to effectively prevent continued inflammation and promote healing."}, {"id": 10409, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a 6-month-old infant who is scheduled for a lumbar puncture. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "The child should be NPO for 8 hours before the procedure."}, {"id": "b", "t": "Apply a eutectic mixture of lidocaine and prilocaine cream topically 15 min prior to the procedure."}, {"id": "c", "t": "Place the infant in a side-lying position for 2 hr following the procedure."}, {"id": "d", "t": "Hold the infant's chin to his chest and knees to his abdomen during the procedure."}], "correct": "d", "rationale": ", the nurse should position the infant on his side in a fetal position, with knees curled to abdomen and chin tucked to B 19% chest, to open the subarachnoid space. | ° cli 8%", "whyNot": {"a": "Fasting is not required prior to a lumbar puncture.", "b": "The nurse should apply a eutectic mixture of lidocaine and prilocaine cream topically 60 min prior to the procedure. This mixture numbs", "c": "The nurse should position the infant flat following the procedure to prevent postural drainage."}, "keyConcept": "a © o 2 ° s a = a < The nurse should obtain informed consent from the guardians of the child prior to the procedure. The nurse should position the infant with knees curled inward toward the abdomen and the chin tucked to the chest. Following the procedure, the nurse should observe the infant for changes in motor activity, level of consciousness, and other neurologic changes. Positioning an Infant for a Lumbar Puncture fk al, e Place the infant in a lateral decubitus position e Maintain alignment of feet, knees, and hips"}, {"id": 10410, "cat": "MUSCOSKELETAL", "stem": "Assessing the client using the bulge sign would most likely check for which type of injury?", "choices": [{"id": "a", "t": "Amass in the abdomen"}, {"id": "b", "t": "A penetrating chest wound"}, {"id": "c", "t": "Adeep vein thrombosis"}, {"id": "d", "t": "Fluid in the knee joint"}], "correct": "d", "rationale": "The bulge sign indicates fluid on the knee. The nurse first presses the medial aspect of the knee joint and \"milks\" any fluid upward. The B | 3\" nurse then moves to the lateral side of the knee and presses. Bulging on the medial side with pressure on the lateral side indicates fluid in the joint. This is known as a positive bulge sign. It is uncommon to see bulging on the lateral side with pressure on the medial aspect of the c I 4% knee. oo 51%", "whyNot": {"a": "Amass in the abdomen may be determined by a number of assessment measures, including palpation and radiography, but it is not", "b": "A penetrating chest wound is usually an obvious injury; it is not assessed using the bulge sign.", "c": "Deep vein thrombosis is assessed using Homan’s sign, which refers to calf pain with dorsiflexion of the foot."}, "keyConcept": "When assessing the knee for injury, the nurse inspects the knee, assesses the temperature, presence of fluid, tendonitis, cartilage tears, and ligament laxity. Another test for the presence of fluid in the joint, known as an effusion, is the patella tap test. The examiner places one hand superior to the patella and milks the suprapatellar pouch with a slight downward pressure, pushing on the patella with the other hand. The patella will bounce off the underlying bone if there is fluid in the joint."}, {"id": 10411, "cat": "MUSCOSKELETAL", "stem": "@ @ X Viral x Reco. ™M™ Inbox ™ Inbox {J untit! Untit! (4 Gooo @ TEAS Onlin @ Mark @ Micre (Qeteinaenurei amelie © atit <€ > G 23 student.atitesting.com/LT| © New Fx 2 ATIT G GERC + v Qa * ws * © Cb Finish update : yee Tutorial: BoardVitals NCLEX Prep RN % CLOSE Sati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "12-year-old girl is diagnosed with idiopathic scoliosis and is fitted with a brace. The length of time the brace must be worn varies, but as a general guideline the nurse instructs the client and her parents that the"}, {"id": "b", "t": "This is not an indication to stop wearing the brace."}, {"id": "c", "t": "The brace will not correct the curvature; it is worn to stop the progression of the curvature."}, {"id": "d", "t": "A Since the brace is worn to stop the progression of the curve, it is usually worn only until approximately 6 months after physical maturity."}], "correct": "d", "rationale": "A Since the brace is worn to stop the progression of the curve, it is usually worn only until approximately 6 months after physical maturity. B L Once the bones stop growing, changes in muscle, bone structure and position are less likely to occur. c", "whyNot": {"a": "Pain is not usually a symptom of scoliosis.", "b": "This is not an indication to stop wearing the brace.", "c": "The brace will not correct the curvature; it is worn to stop the progression of the curvature."}, "keyConcept": "Scoliosis is a lateral curving of the spine. The thoracic area is the most commonly affected. Scoliosis can be classified as functional or structural. Functional scoliosis is the result of another deformity and can be corrected by treating the underlying problem. Structural scoliosis is usually idiopathic although it may be congenital or secondary to another disorder. Idiopathic scoliosis is probably genetic, but the etiology is not completely understood. Treatment options for adolescents include monitoring, bracing, and surgical correction."}, {"id": 10412, "cat": "MUSCOSKELETAL", "stem": "A nurse is providing home care for a toddler with multiple developmental disabilities who rarely goes outdoors because of photosensitivity. Which nutritional deficit is this client most likely to have?", "choices": [{"id": "a", "t": "Vitamin C deficiency"}, {"id": "b", "t": "Vitamin D deficiency"}, {"id": "c", "t": "Magnesium deficiency"}, {"id": "d", "t": "Vitamin B deficiency"}], "correct": "b", "rationale": "al 4% Easy Toddlers and young children who stay indoors by choice to play video games or watch television or because of a medical problem such as OB rsd SO photosensitivity are at risk for developing a vitamin D deficiency. Vitamin D is synthesized with sunlight, therefore, the lack of sunshine ° depletes the body’s vitamin D. Vitamins C, B, and magnesium are not depleted by the absence of sunshine. c | 2% my | 3%", "whyNot": {"a": "This client is not at risk of vitamin C deficiency by staying indoors.", "c": "This client is most likely not at risk of magnesium deficiency if dietary intake is normal. Magnesium is not impacted by going outdoors.", "d": "This client would not develop a vitamin B deficiency by staying indoors."}, "keyConcept": "Side effects of vitamin D deficiency include muscle aches and weakness, periodontitis, and \"light-headedness\"; rickets, a pediatric disorder that results in delayed growth and deformity of long bones; osteomalacia, a bone-thinning disorder in adults characterized by proximal muscle weakness and bone fragility; osteoporosis, characterized by reduced bone mineral density and increased bone fragility; increased risk of fracture"}, {"id": 10413, "cat": "MUSCOSKELETAL", "stem": "A nurse in the ICU is caring for a client who has been sedated and on a mechanical ventilator for ten days. Which of the following is a hazard associated with immobility?", "choices": [{"id": "a", "t": "Extension contractures"}, {"id": "b", "t": "Positive nitrogen balance"}, {"id": "c", "t": "Hypocalcemia"}, {"id": "d", "t": "Muscular atrophy"}], "correct": "d", "rationale": "All 10% Easy There are many hazards associated with immobility including muscular atrophy, hypercalcemia (not hypocalcemia), muscular weakness, , a negative nitrogen balance, and skin breakdown with pressure ulcers. Clients who are able should be encouraged to participate in out-of-bed activity and exercise, including ambulation, to avoid the consequences and hazards associated with complete bed c | 4% rest and immobility. When a client is unconscious, the nurse should perform range of motion exercises to prevent contractures and should @ . The nurse should also use devices such as a bedboard to prevent complications such as foot drop.", "whyNot": {"a": "Flexion contractures are more likely to develop with immobility, rather than extension contractures.", "b": "A client would be more likely to develop a negative nitrogen balance with immobility, not a positive nitrogen balance.", "c": "Hypercalcemia is a greater risk with immobility, rather than hypocalcemia."}, "keyConcept": "Immobility is associated with significant loss of muscle strength, endurance, and muscle mass; demineralization of bone; hypercalcemia; loss of joint mobility; contractures; cardiopulmonary deconditioning; slowing of the gastrointestinal tract; risk of skin breakdown; and cognitive decline. Complications of immobility include atelectasis; pooling of respiratory secretions leading to hypostatic pneumonia; foot drop; urinary stasis leading to urinary tract infections; renal calculi due to hypercalcemia; and pressure ulcer formation due to ischemia."}, {"id": 10414, "cat": "MUSCOSKELETAL", "stem": "A nurse in the emergency department is assigned to care for 4 clients. Which client is a priority for assessment and treatment? O A.A patient with diabetes and increased thirst with a temperature of 100.6°F and fingerstick glucose reading of 380 mg/dL O B. A patient who takes warfarin and fell from a ladder, who had a brief loss of consciousness and now complains of a severe headache O C. Awoman who is crying after an argument with her husband with bruises on both arms O D. An older patient with a swollen and deformed ankle complaining of 8/10 pain after stepping off a curb with equal pulses in both feet", "choices": [{"id": "a", "t": "This client has a fever and elevated blood glucose, which often occurs with an infection in individuals with diabetes. The client requires"}, {"id": "b", "t": "severe headache A 9%"}, {"id": "c", "t": "The client will require assessment of injuries, which appear to be minor. She will also potentially require counseling and use of resources if"}, {"id": "d", "t": "Simple fractures can be assessed within 1 to 2 hours. Since the client has adequate blood flow beyond her ankle, there is no immediate"}], "correct": "a", "rationale": "B. severe headache A | | 9% Easy c | 1% Emergent priorities in the emergency department include trauma victims with injuries that threaten life or limb and clients with medical . The ABC's (airway, breathing, circulation) are always priority items, but injuries or disorders that affect the central nervous system are also potentially devastating. In the ED, priorities include amputations, chest pain, severe respiratory distress, chemical splashes to the eye, and acute neurological deficits. An elderly client who is treated with an anticoagulant medication and falls from a height is at risk for intracranial bleeding, including subdural hematoma (SDH). A SDH occurs with tears of the bridging veins that travel in the space between the dura mater and arachnoid layers of connective tissue that cover the brain. a © o 2 ° s a = a < Acute subdural hematoma and other intracranial hemorrhages increase intracranial pressure, resulting in decreased cerebral perfusion, with brainstem herniation, and death. Herniation of the brainstem refers to movement of the brainstem through the foramen magnum, the opening at the base of the skull. This client should be a priority for assessment with radiological imaging and neurological examination. A coagulation profile (PT, INR) should be obtained.", "whyNot": {"a": "This client has a fever and elevated blood glucose, which often occurs with an infection in individuals with diabetes. The client requires", "c": "The client will require assessment of injuries, which appear to be minor. She will also potentially require counseling and use of resources if", "d": "Simple fractures can be assessed within 1 to 2 hours. Since the client has adequate blood flow beyond her ankle, there is no immediate"}, "keyConcept": "In addition to airway, breathing, and circulation problems, potentially life-threatening neurological conditions should be prioritized for care. Older clients who are anticoagulated are at increased risk of intracranial bleeding after a fall. Intracranial bleeding can lead to increased intracranial pressure, brainstem herniation, and death."}, {"id": 10415, "cat": "MUSCOSKELETAL", "stem": "A client with a diagnosis of polyarteritis nodosa asks the nurse for information about this disorder. What information should the nurse include in her response?", "choices": [{"id": "a", "t": "Clients with this disease have an excellent prognosis"}, {"id": "b", "t": "The disorder affects males and females in equal numbers"}, {"id": "c", "t": "The disorder is considered one of hypersensitivity and the exact cause is unknown"}, {"id": "d", "t": "Clients with this disease have problems with only the kidneys and retina of the eyes"}], "correct": "c", "rationale": "A l 3% Moderate An autoimmune response plays a role in the development of polyarteritis,; although drugs and infections may precipitate its development. B | nove", "whyNot": {"a": "Most clients with polyarteritis nodosa have a poor prognosis, especially with little treatment. D | | 13%", "b": "The condition is more common in males than in females.", "d": "Clients with this condition can have multiple problems with a number of body systems, including heart attack, kidney failure, and stroke."}, "keyConcept": "Polyarteritis nodosa (PAN), also known as panarteritis nodosa, is a systemic disorder of necrotizing inflammation of blood vessels, known as"}, {"id": 10416, "cat": "MUSCOSKELETAL", "stem": "A nurse is assessing a client who has HIV. Which finding should the nurse identify as a manifestation of HIV-associated muscle wasting?", "choices": [{"id": "a", "t": "Unintentional weight loss of 15% of body weight in 6 months"}, {"id": "b", "t": "Fecal impaction"}, {"id": "c", "t": "Diminished strength"}, {"id": "d", "t": "Report of increased fat gain on the back of the neck"}], "correct": "c", "rationale": "A client who has HIV-associated muscle wasting will report a decrease in strength as well as muscle wasting caused by gastrointestinal lab: ti f nutrients. 8 | mS malabsorption of nutrients. p | 1%", "whyNot": {"a": "HIV associated weight loss and wasting might cause an unintentional weight loss of less than 5% of body weight in 6 months.", "b": "A client who has HIV-associated muscle wasting might report having diarrhea, rather than a fecal impaction, which is generally found ina", "d": "A client report of increased fat gain in the back of the neck can be a manifestation of HIV-associated lipodystrophy. It is not a manifestation"}, "keyConcept": "HIV-associated muscle wasting can have many causative factors. Muscle wasting can result from inflammatory changes that increase the body's calorie use, resulting in protein breakdown."}, {"id": 10417, "cat": "MUSCOSKELETAL", "stem": "A nurse is providing discharge teaching for a client who has rheumatoid arthritis. Which of the following statements should the nurse include in the teaching? O A.\"You might experience joint stiffness when you get out of bed.\" O B. \"You might experience abdominal pain.\" O C. \"You might experience weight gain.\" O D. \"You might experience low blood pressure.\"", "choices": [{"id": "a", "t": "The nurse should include in the teaching that a client who has rheumatoid arthritis might experience stiffness in the joints upon rising from ."}, {"id": "b", "t": "A client who has rheumatoid arthritis might experience pleuritic pain upon inspiration, not abdominal pain."}, {"id": "c", "t": "A client who has rheumatoid arthritis might experience weight loss, not weight gain."}, {"id": "d", "t": "Rheumatoid arthritis does not cause low blood pressure."}], "correct": "a", "rationale": "The nurse should include in the teaching that a client who has rheumatoid arthritis might experience stiffness in the joints upon rising from . c | 2%", "whyNot": {"b": "A client who has rheumatoid arthritis might experience pleuritic pain upon inspiration, not abdominal pain.", "c": "A client who has rheumatoid arthritis might experience weight loss, not weight gain.", "d": "Rheumatoid arthritis does not cause low blood pressure."}, "keyConcept": "Rheumatoid arthritis (RA) is a chronic and progressive systemic inflammatory autoimmune disease of the synovial joints. The nurse should"}, {"id": 10418, "cat": "MUSCOSKELETAL", "stem": "client's pain? O A. Self-report of pain is an unreliable diagnostic measure of pain. O B. Pain described as pins and needles is typical of visceral pain. O C. Localized pain described as throbbing or aching is typical of nociceptive pain. O D. In clients complaining of acute pain, lack of physiological changes like increased heart rate or muscle tension indicates the client is not truly experiencing pain.", "choices": [{"id": "a", "t": "Self-report of pain is an unreliable diagnostic measure of pain."}, {"id": "b", "t": "Pain described as pins and needles is typical of visceral pain."}, {"id": "c", "t": "Localized pain described as throbbing or aching is typical of nociceptive pain."}, {"id": "d", "t": "In clients complaining of acute pain, lack of physiological changes like increased heart rate or muscle tension indicates the client is not truly experiencing pain."}], "correct": "c", "rationale": "Al oz Pain can be divided into categories by duration or origin. Duration can be acute or chronic. Acute pain refers to pain that is usually temporary ec | and resolves with healing. Chronic pain recurs frequently or may be ongoing. It lasts longer than 3 months, with persistence after tissues D I have healed. Pain categories by site of origin include nociceptive pain and neuropathic pain. Nociceptive pain which arises from inflammation or damage to tissue exclusive of the nervous system, includes somatic pain and visceral pain. Neuropathic pain refers to pain that is caused by abnormal or damaged nerve fibers/tissue. In acute pain, a physiological response may occur as a result of activation of the fight or flight response of the sympathetic nervous system to an injury. Sympathetic responses include hypertension, tachycardia, anxiety, diaphoresis, and muscle tension. Behavioral responses also may occur. However, lack of a physiological or behavioral response is not an indication that pain is absent. Pain exists when the client reports perception of pain. Self-report using a standardized pain scale is the most reliable diagnostic measure of pain.", "whyNot": {"a": "Self-report of pain using a standardized pain scale is the most reliable diagnostic measure of pain in individuals over the age of 7. Younger", "b": "Neuropathic pain is often described as a “burning” or “pins and needles” sensation. It is caused by damaged or abnormal pain nerves.", "d": "Some clients with acute pain may not demonstrate physiological or behavioral changes, but that is not an indication of lack of pain."}, "keyConcept": "Pain can be acute or chronic. Chronic pain lasts longer than 3 months and may be ongoing or intermittent. Pain can also be classified as neuropathic or nociceptive. Damage to tissues outside the peripheral and central nervous system results in nociceptive pain. Neuropathic pain is caused by tissue damage or abnormal signaling activity in the central or peripheral nervous system."}, {"id": 10419, "cat": "MUSCOSKELETAL", "stem": "@0@ X Viral x Reco M Inbox ™ Inbox =) Untit! Untit (4 Gooo @ TEAS Onlin & Mark @ Micrc Convert study guide (J ATIT @ New ‘oma FX 2S ATIT G GERC a v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE Sati Module: Results Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "8%"}, {"id": "b", "t": "A | | 8% Moderate Pillows should not be used in the crib because they will increase the risk of sudden infant death syndrome."}, {"id": "c", "t": "Children typically need 5 to 10 casts to correct the deformity."}, {"id": "d", "t": "Infants with clubfoot still need frequent holding, like any other newborn."}], "correct": "b", "rationale": "A | | 8% Moderate Pillows should not be used in the crib because they will increase the risk of sudden infant death syndrome. However, elevating the extremity es rd 10% at different points during the day is helpful in reducing edema. cm 18%", "whyNot": {"c": "Children typically need 5 to 10 casts to correct the deformity.", "d": "Infants with clubfoot still need frequent holding, like any other newborn."}, "keyConcept": "Congenital talipes equinovarus, also referred to as clubfoot, is one of the most common birth defects involving the musculoskeletal system. In individuals with clubfoot, the foot is plantar flexed at the ankle and subtalar joints, the hind foot is inverted, and the midfoot and forefoot are adducted and inverted. Contractures of soft tissues maintain the malalignments. Clubfoot is usually treated using the Ponseti technique, which involves stretching the foot, casting, and tenotomy, followed by wearing braces. 2 = ® 4 z = a iat g <"}, {"id": 10420, "cat": "MUSCOSKELETAL", "stem": "Which of the following tasks should a nurse prioritize when caring for a client in the PACU who is one hour post-op total hip replacement?", "choices": [{"id": "a", "t": "Assessment of urine cloudiness or pus in the catheter bag"}, {"id": "b", "t": "Placement of the abduction pillow"}, {"id": "c", "t": "Assessment of bloody drainage in a suction drainage device"}, {"id": "d", "t": "Last dose of pain medication and assessment of client pain level"}], "correct": "c", "rationale": "A i 9% Hard Complications of total hip replacement include dislocation of the prosthesis, bleeding, infection, and deep vein thrombosis. During the ec | 39% immediate postoperative period, the priority assessment is monitoring blood loss since this is a potentially life-threatening complication of D Hl 23% surgery, particularly in the first few hours.", "whyNot": {"a": "Cloudiness and pus in urine can be a sign of urinary tract infection in a client who has an indwelling urinary catheter, but it does not", "b": "An abduction pillow is placed between the legs of the client after total joint replacement of the hip to prevent adduction of the hip and", "d": "Pain control is always important, but hemorrhage is a priority. Many surgeons prescribe a patient-controlled analgesia device with"}, "keyConcept": "In the immediate post-operative period, the client will be in the post-anesthesia care unit (PACU.) There are three phases of recovery in the PACU. Phase 1 is the immediate recovery phase. During phase 2, the nurse prepares the client for self/hospital care, Phase 3 is preparation for discharge. The PACU stay can be 4-6 hours, during which the client is closely monitored for hemorrhage and other potential complications of surgery. The client is discharged after regaining motor and sensory function and stable vital signs. Before discharge from the PACU, the client should be oriented and without evidence of complications."}, {"id": 10421, "cat": "MUSCOSKELETAL", "stem": "A nurse is assessing the mobility of a client's shoulder. Which of the following actions should the nurse take to test extension range-of-motion (ROM)?", "choices": [{"id": "a", "t": "Move the arm from a position above the head to the client's side using a forward motion."}, {"id": "b", "t": "Move the arm behind the body keeping the elbow straight."}, {"id": "c", "t": "Move the arm in a full complete circle."}, {"id": "d", "t": "Raise the arm from a side position to a position above the client's head using a forward motion."}], "correct": "a", "rationale": "@A || 24% Hard By moving the arm using a forward motion from above the head to the client's side, the nurse is testing the extension ROM of the client's B Hi 18% shoulder. cm 19%", "whyNot": {"b": "By moving the arm behind the body and keeping the elbow straight, the nurse is testing the hyperextension ROM of the client's shoulder.", "c": "By moving the arm in a full complete circle, the nurse is testing the circumduction ROM of the client's shoulder. Circumduction combines", "d": "Raise the arm from a side position to a position above the client's head using a forward motion. This motion demonstrates shoulder"}, "keyConcept": "A nurse should be able to assess a client's ROM as a baseline measure to determine mobility status. The nurse can use the findings of this assessment later to compare and evaluate whether a loss of joint mobility has occurred as a result of disease progression or as the result of prescribed treatments."}, {"id": 10422, "cat": "MUSCOSKELETAL", "stem": "A nurse is providing discharge instructions to the guardian of an infant who has developmental hip dysplasia and has a newly applied plaster spica cast. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Use a heat lamp to facilitate drying."}, {"id": "b", "t": "Avoid turning the infant until the cast is dry."}, {"id": "c", "t": "Secure the child with a seat belt during trips in the car."}, {"id": "d", "t": "Check the temperature of the infant's toes every hour for at least the first 24 hours."}], "correct": "d", "rationale": "'s lower extremity to identify complications, such . Monitoring of the temperature of the child's toes, along with the color of the toes, should be completed hourly for the first 24 hours following cast placement and then every day. The guardian should be instructed to report any signs of ischemia, such as € | 11% pallor or coolness of the toes, immediately. @ , especially when moving the toes. Pallor The infant's skin color can become pale and cool to the touch. tll 2 The nurse might be unable to detect pulses in the infant's lower extremities due to the 5 Pulselessness 4 presence of the cast. g a a Paresthesia This might be difficult to determine in an infant; however, an older child might state the casted g extremity is tingling or feels like it has \"gone to sleep\" < Paralysis The parent or guardian should observe the ability of the infant to move the toes independently. ¥ If the infant becomes unable to move the toes, the provider should be notified.", "whyNot": {"a": "Acool fan can be used to facilitate drying of a plaster cast. The use of a heat lamp will result in uneven drying, with the outside of the cast", "b": "The infant should be turned every two hours to expose all areas of the cast to facilitate drying. This will also avoid the development of any", "c": "An infant who has a spica cast is unable to fit safely and securely in a standard car seat. The nurse should instruct the guardian to obtain a"}, "keyConcept": "Anewly applied plaster cast may become too tight if additional swelling occurs, especially in the first 24 hours, so it is especially important to check circulation. General discharge instructions for a child with a plaster cast should cover education for the patient and family regarding cast care at home (e.g., keeping the area dry)."}, {"id": 10423, "cat": "MUSCOSKELETAL", "stem": "A nurse is providing information about capsaicin cream to a client who has osteoarthritis. Which of the following information should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Continuous pain relief is provided."}, {"id": "b", "t": "Inspect for skin irritation and cuts prior to application."}, {"id": "c", "t": "Cover the area with tight bandages after application."}, {"id": "d", "t": "Apply the medication every 2 hr during the day."}], "correct": "b", "rationale": "al 3% Easy Capsaicin is an ingredient found in chili peppers that has been found to provide analgesia when applied topically. However, it can cause es rsd 92% blistering and should only be used on intact skin. The nurse should instruct the client to inspect the skin for irritation and cuts before applying capsaicin cream and avoid use of the cream if the skin is damaged, has a wound, or is infected because this can cause increased € | 2%) pain and cellular damage.", "whyNot": {"a": "Capsaicin cream blocks neurotransmitters for pain, providing temporary relief of osteoarthritis pain. The nurse should instruct the client", "c": "The nurse should instruct the client to avoid covering the area with a bandage or compression wrap after capsaicin cream is applied", "d": "For maximum pain relief, the nurse should instruct the client to apply capsaicin cream up to four times per day. The nurse should inform"}, "keyConcept": "When providing instruction to the client on the use of capsaicin cream, the nurse should instruct the client to apply a thin film to the affected area and rub it in gently while wearing gloves. The nurse should instruct the client to wash their hands thoroughly with soap and water after the application of the cream, even if gloves are worn, to decrease the risk of causing burning to the eyes or other sensitive areas. The client should also avoid handling contact lenses or applying drops to the eye for at least 1 hr after handling, applying, or removing capsaicin cream."}, {"id": 10424, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client who has a cast on his arm after reduction of a fracture of the ulna. What is a normal finding when checking neurovascular status of the distal extremity?", "choices": [{"id": "a", "t": "Skin is pale and cool to the touch O B.A strong pulse that is easily palpated"}, {"id": "b", "t": "Astrong pulse that is easily palpated indicates that blood flow remains to the distal extremity and is not obstructed by the cast."}, {"id": "c", "t": "In testing capillary refill, blood returns within 10 seconds"}, {"id": "d", "t": "Slight numbness and tingling when compared to the unaffected side"}], "correct": "b", "rationale": "Astrong pulse that is easily palpated indicates that blood flow remains to the distal extremity and is not obstructed by the cast.", "whyNot": {"a": "Pale skin that is cool to the touch indicates decreased circulation, which may mean that the cast is too tight or impeding blood flow.", "c": "Normal capillary refill should be less than 3 seconds, not 10 seconds.", "d": "There should be no numbness or tingling in the extremity; this indicates an obstruction that is affecting the nerves."}, "keyConcept": "A fracture of the arm or leg may result in swelling in the discrete and limited compartments of the extremity. Blood flow into the space, with edema and inflammation, can result in increased compartmental pressure and, if not addressed, perfusion is reduced and tissue damage and necrosis may occur. The signs of compartment syndrome include pallor, paresthesias, pain (out of proportion to the injury), paralysis, and pulselessness. Compartment syndrome is treated by fasciotomy, which relieves the pressure within the fascia contained compartments."}, {"id": 10425, "cat": "MUSCOSKELETAL", "stem": "diagnoses is the priority for this client with regards to the new prescription?", "choices": [{"id": "a", "t": "Depression"}, {"id": "b", "t": "Risk for infection"}, {"id": "c", "t": "Risk for cardiac arrhythmia"}, {"id": "d", "t": "Impaired physical mobility"}], "correct": "b", "rationale": "A Hi 12% Hard ec i” 41% Ankylosing spondylitis (AS) is a rheumatological disease that causes spinal stiffness and back pain. It is a systemic disorder that can result in © Hl 22% pain in other joints and effects on the eyes, heart, lungs, and kidneys. In addition to treatment with NSAIDs (nonsteroidal anti-inflammatory D Hi 19% medications), sulfasalazine, and physical therapy, tumor necrosis factor inhibitors may be used to treat AS and other rheumatological disorders. Tumor necrosis factor (TNF) inhibitors, including infliximab (Remicade), adalimumab (Humira), and etanercept (Enbrel), reduce inflammation by suppressing the body’s normal immune response. Immune suppression can lead to new infections, including serious fungal infections, or reactivation of a latent or chronic infection, including TB or hepatitis B. These medications also increase the risk of certain malignancies. Nursing interventions and education should focus on ways to prevent infection in this setting. Increased risk for infection is the primary nursing concern with respect to the new prescription for this client. 2 = ® 4 z = a iat g <", "whyNot": {"a": "Individuals with chronic and progressive debilitating illnesses often become depressed or have a sense of hopelessness. With respect to", "c": "Etanercept is not associated with cardiac arrhythmia.", "d": "Although impaired physical mobility is a concern for any client with AS or another rheumatological disorder, it is important to realize that"}, "keyConcept": "Tumor necrosis factor inhibitors are used to treat several rheumatological disorders, including rheumatoid arthritis, psoriatic arthritis, and AS. They are associated with impairment of the immune system, which increases the risk of opportunistic infections, reactivation of latent infections, including TB, and malignancy, including lymphoma. Increased risk for infection is the primary nursing concern."}, {"id": 10426, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client with a cast after reduction of a tibial fracture. The nurse understands that which of the following is a symptom of compartment syndrome?", "choices": [{"id": "a", "t": "Intense muscle pain, numbness, burning, and a feeling of tight muscles"}, {"id": "b", "t": "Blistering rash, sweating, and high fever"}, {"id": "c", "t": "Abdominal fullness, belching, nausea, and flatulence"}, {"id": "d", "t": "Muscle cramps, diarrhea, nausea, and vomiting"}], "correct": "a", "rationale": "Compartment syndrome develops as inflammation and edema increase the pressure within the confined fascial space known as a muscle . Since there is no room for expansion of tissues in the four compartments of the lower leg, continued swelling can disrupt normal blood flow. If perfusion is blocked by intracompartment pressure, ischemic damage and necrosis may result. The client with c| 2%) compartment syndrome typically complains of intense muscle pain that is described as burning; there may be numbness and tingling, as .", "whyNot": {"b": "A blistering rash, sweating, and high fever are not associated with compartment syndrome.", "c": "These symptoms describe gastrointestinal pathology, not compartment syndrome.", "d": "Muscle cramps, diarrhea, nausea, and vomiting are not symptoms associated with compartment syndrome."}, "keyConcept": "The fascial compartments of the extremities are confined spaces and edema and inflammation associated with injury or fracture can rapidly increase the pressure within the compartment, preventing perfusion of tissues. The five P's of compartment syndrome include, progressively, Disproportionate Pain, Pallor, Paresthesia, Paralysis, and Pulselessness."}, {"id": 10427, "cat": "MUSCOSKELETAL", "stem": "A nurse is seeing a 5-month-old in the clinic who is wearing a device that is seen in the image below. This device is used in treatment of which of the following conditions?", "choices": [{"id": "a", "t": "Seizures © B. club foot"}, {"id": "c", "t": "Shoulder dislocation"}, {"id": "d", "t": "Hip dysplasia"}], "correct": "d", "rationale": "This is a Pavlik harness, which is used to keep a baby’s hips aligned within the hip joint and is prescribed for infants who are diagnosed with congenital hip dysplasia.", "whyNot": {"a": "An infant who has seizures will be treated with medication, not the Pavlik harness.", "c": "An infant with shoulder dislocation would wear a sling on the shoulder."}, "keyConcept": "Developmental dysplasia of the hip is associated with abnormalities in the development of the hip in infants and young children. The disorder can include abnormalities of the acetabulum, proximal femur, and mechanical instability of the hip joint, including dislocation between the head and acetabulum, subluxation (partial dislocation), and dysplasia of the hip joint. Laxity in the newborn hip increases the risk of dislocation and relocation of the hip. Continued dysplasia of the hip can result in limited abduction of the hip and contractures. The Pavlik harness is used in infants under 6 months of age."}, {"id": 10428, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a child with developmental dysplasia of the hip. Which of the following is the primary intervention for this child?", "choices": [{"id": "a", "t": "Flexion of the hip"}, {"id": "b", "t": "Extension of the hip"}, {"id": "c", "t": "Adduction of the hip"}, {"id": "d", "t": "Abduction of the hip"}], "correct": "d", "rationale": "Abduction will enable the head of the femur to fit into the acetabulum, thereby correcting the dysplasia.", "whyNot": {"a": "Flexion of the hip will not correct the dysplasia; the child needs abduction of the hip.", "b": "Extension of the hip will not correct the dysplasia; the child needs abduction of the hip.", "c": "Adduction of the hip will not correct the dysplasia and will only keep the head of the femur outside of the joint; the child needs abduction"}, "keyConcept": "The hip joint, a ball and socket joint, has not formed properly in children with developmental dysplasia of the hip (DDH). The acetabulum is. shallow, resulting in looseness of the femoral head. DDH is most often present at birth, but it may also develop during a child's first year of life. Babies whose legs are swaddled tightly with the hips and knees straight are at higher risk for developing DDH after birth. Parents should be advised on how to swaddle their infants safely and to understand that when done improperly, swaddling may result in problems like DDH. Normal hip joint Developmental dysplasia"}, {"id": 10429, "cat": "MUSCOSKELETAL", "stem": "Which of the following clients would benefit from the application of warm moist heat?", "choices": [{"id": "a", "t": "A client with appendicitis"}, {"id": "b", "t": "A client with a recently sprained joint"}, {"id": "c", "t": "A client with a suspected malignancy"}, {"id": "d", "t": "A client with chronic low back pain"}], "correct": "d", "rationale": "al 3% Easy Direct application of warm moist heat would benefit a client with low back pain because the heat can relax muscle spasms. The other B r 12% options are incorrect for using heat.", "whyNot": {"a": "Applying heat to the site for appendicitis will not relieve the pain or help the condition.", "b": "The nurse should place ice on a recent sprain to promote comfort, rather than heat.", "c": "Heat application would not have an effect on malignancy."}, "keyConcept": "Moist heat increases blood flow to a chronically injured joint and relaxes the muscle to promote healing after inflammation has subsided. Use of ice packs is generally recommended for acute inflammation. It constricts local blood vessels and reduces the presence of 2 = 5 a . . a Ss inflammatory mediators in the area of injury. x fa a <"}, {"id": 10430, "cat": "MUSCOSKELETAL", "stem": "A nurse is creating a plan of care for a child who has a fractured femur and is in Buck's traction. Which of the following interventions should the nurse include?", "choices": [{"id": "a", "t": "Remove the weights when changing the child's bed linens."}, {"id": "b", "t": "Maintain the affected leg in an extended position."}, {"id": "c", "t": "Monitor the child's halo device for redness every 4 hr."}, {"id": "d", "t": "Apply antibiotic ointment to the child's pin sites every 2 hr."}], "correct": "b", "rationale": "al 3% Easy The nurse should maintain the child's affected leg in an extended position while in Buck's traction. This position minimizes the occurrence of es | 78% painful muscle spasms and decreases the risk for further injury to the child's affected extremity. ci 14% of 5%", "whyNot": {"a": "The nurse should maintain the weights in place to avoid the pain and discomfort caused by muscle spasms.", "c": "The nurse should identify that a halo device is used for a child who requires cervical traction. Buck's traction is used in the treatment of", "d": "Providing pin care is an approved nursing intervention for a child who is in skeletal traction. Buck's traction uses skin straps or a special"}, "keyConcept": "Various Traction Categories Applied distal to the fracture site onto the body part nearest the hands Manual Most commonly used when a closed reduction is performed May be used during a cast application Applied directly to the skeletal formation using a wire, pin, or tongs Skeletal Inserted into the breadth of the bone farthest away from the fracture Applied directly to the surface of the skin and indirectly to the skeletal structures Skin Contains a pulling mechanism that is attached to the skin using adhesive or elastic material"}, {"id": 10431, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a client who has chronic back pain and requests pain medication. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Determine the time the client last received pain medication."}, {"id": "b", "t": "Measure the client's vital signs."}, {"id": "c", "t": "Ask the client to rate the level of pain on a scale from 0 to 10."}, {"id": "d", "t": "Assess the client for any allergies to medications."}], "correct": "c", "rationale": "A Using evidence-based practice, the first action the nurse should take is to ask the client to rate the pain level on a scale from 0 to 10 to B - determine the severity of the client's pain. o; on", "whyNot": {"a": "The nurse should determine when the client last received pain medication to identify when the client can have the next dose. However,", "b": "The nurse should measure the client's vital signs to assess the client's overall status. However, evidence-based practice indicates that the", "d": "The nurse should assess the client for allergies to medications to avoid a potential adverse reaction. However, evidence-based practice"}, "keyConcept": "The nurse should identify that the client's self-report of pain is the measurement used to determine pain intensity. The client's perception of pain is the data the nurse should use when deciding how to respond to the client's request for pain medication. COMPARATIVE PAIN SCALE CHART Pain Assesment Tool © S08CCCCC® L L 1 1 n 1 L 1 j L 1 ee"}, {"id": 10432, "cat": "MUSCOSKELETAL", "stem": "relief that use which of the following strategies?", "choices": [{"id": "a", "t": "Physical therapy"}, {"id": "b", "t": "Distraction"}, {"id": "c", "t": "Cutaneous stimulation"}, {"id": "d", "t": "Imagery"}], "correct": "b", "rationale": "All o: Factors that increase a client's experience of pain and reduce pain tolerance include monotony, lack of knowledge, fatigue, and fear. © I Distraction is used to help individuals pay less attention to the presence of pain, which may decrease the level of pain perceived. Methods of D | distraction include music, ambulation, deep breathing, socializing with friends and family, prayer, television, and music. Other non- pharmacological modalities used to relieve pain include guided imagery, massage, and relaxation.", "whyNot": {"a": "Physical therapy is directed at rehabilitation of a muscle group to strengthen or compensate for muscle or joint disability through exercise.", "c": "Cutaneous stimulation refers to stimulation of the nerves through transcutaneous currents, such as a TENS (transcutaneous electrical", "d": "Imagery is a type of distraction that requires an ability to concentrate on a pleasant thought to divert the focus from pain."}, "keyConcept": "An individual's experience of pain can be increased or precipitated by monotony, fatigue, fear, or lack of knowledge. The perception of pain can be reduced by non-pharmacological techniques that include distraction, relaxation, massage, and guided imagery."}, {"id": 10433, "cat": "MUSCOSKELETAL", "stem": "A nurse is caring for a child who is suspected of having Legg-Calve-Perthes disorder. The nurse should anticipate a prescription for which of the following diagnostic procedures?", "choices": [{"id": "a", "t": "Bone marrow biopsy"}, {"id": "b", "t": "Genetic testing"}, {"id": "c", "t": "Bone densitometry"}, {"id": "d", "t": "Radiographs"}], "correct": "d", "rationale": "A Hi 13% Hard Achild who has Legg-Calve-Perthes exhibits necrosis of the femoral head, which can be diagnosed by radiographs or magnetic resonance B ] 15% imaging of the hip and pelvis. The disease has four distinct phases that involve changes to the femoral head. These changes allow for diagnosis and determination of the phase of the disorder. € || 33% ec i” 39%", "whyNot": {"a": "Legg-Calve-Perthes is a skeletal disorder that results in necrosis of the femoral head due to an interruption of blood flow to the femoral", "b": "Legg-Calve-Perthes involves necrosis of the femoral head. The cause is unknown, but it occurs most often in male clients between the", "c": "Bone densitometry is a radiologic test used to diagnose the presence of osteoporosis. It measures the mineral content and density of the"}, "keyConcept": "Legg-Calve-Perthes disease is self-limiting; however, early identification and treatment provide improved outcomes. The role of the nurse includes education of the family regarding limitations to activities, the administration of NSAIDs, physical therapy, and exercise. If braces or casting are required to prevent subluxation of the hip, the nurse should also provide education regarding their care."}], "ncleex_5": [{"id": 10434, "cat": "NCLEEX 5", "stem": "Which of the following images represents anisocoria? Se ee XS O D. None of the above a © o 2 ° s a = a <", "choices": [{"id": "a", "t": "This represents mydriasis, bilaterally dilated pupils. Mydriatic eye drops used by eye care providers would cause bilateral dilation of the"}, {"id": "b", "t": "This represents miosis, bilaterally constricted pupils."}, {"id": "c", "t": "al 5% Easy Option C represents anisocoria, which refers to the unequal size of the pupils."}, {"id": "d", "t": "The correct answer is (C)."}], "correct": "c", "rationale": "al 5% Easy Option C represents anisocoria, which refers to the unequal size of the pupils. It affects up to 20 percent of the population and is usually B | a benign.", "whyNot": {"a": "This represents mydriasis, bilaterally dilated pupils. Mydriatic eye drops used by eye care providers would cause bilateral dilation of the", "b": "This represents miosis, bilaterally constricted pupils.", "d": "The correct answer is (C)."}, "keyConcept": "The parasympathetic and sympathetic nervous systems stimulate the iris muscle to contract or dilate, which regulates the amount of light through the pupil. Anisocoria, or unequal pupil size, can be a normal finding in one fifth of people, but it can also represent a variety of medical conditions, some of which can be serious. When assessing a client with anisocoria, it's important to determine how long the anisocoria has been present. Pupils should be measured and reactivity to light and dark should be assessed. Associated symptoms or signs, such as diplopia, ptosis, and any neurological changes, will help the nurse determine the etiology. Referenc"}, {"id": 10435, "cat": "NCLEEX 5", "stem": "Which of the following images represents anisocoria? Se ee XS O D. None of the above Check Answer", "choices": [{"id": "a", "t": "This represents mydriasis, bilaterally dilated pupils. Mydriatic eye drops used by eye care providers would cause bilateral dilation of the"}, {"id": "b", "t": "This represents miosis, bilaterally constricted pupils."}, {"id": "c", "t": "al 5% Easy Option C represents anisocoria, which refers to the unequal size of the pupils."}, {"id": "d", "t": "The correct answer is (C)."}], "correct": "c", "rationale": "al 5% Easy Option C represents anisocoria, which refers to the unequal size of the pupils. It affects up to 20 percent of the population and is usually B | a benign.", "whyNot": {"a": "This represents mydriasis, bilaterally dilated pupils. Mydriatic eye drops used by eye care providers would cause bilateral dilation of the", "b": "This represents miosis, bilaterally constricted pupils.", "d": "The correct answer is (C)."}, "keyConcept": "The parasympathetic and sympathetic nervous systems stimulate the iris muscle to contract or dilate, which regulates the amount of light through the pupil. Anisocoria, or unequal pupil size, can be a normal finding in one fifth of people, but it can also represent a variety of medical conditions, some of which can be serious. When assessing a client with anisocoria, it's important to determine how long the anisocoria has been present. Pupils should be measured and reactivity to light and dark should be assessed. Associated symptoms or signs, such as diplopia, ptosis, and any neurological changes, will help the nurse determine the etiology. Referenc"}, {"id": 10436, "cat": "NCLEEX 5", "stem": "adult client, which of the following elements is missing from the following graphic? / Early fesceniny initiation of EMS ‘of CPR life support", "choices": [{"id": "a", "t": "Respirations at a rate of sixty breaths per minute"}, {"id": "b", "t": "Early defibrillation"}, {"id": "c", "t": "Chest compressions at a rate of 100 compressions per minute"}, {"id": "d", "t": "An open airway"}], "correct": "b", "rationale": "8 The American Heart Association has developed the Chain of Survival that gives steps to provide rapid management of a patient who is in © Hi 16% a cardiac arrest. The first link in the chain is to activate the emergency response system, followed by initiation of CPR, including chest D Hl 23% a compressions and breathing assistance. This is followed by early defibrillation, advanced life support measures, and post-cardiac care. Rapid < administration of these steps can greatly improve the survival of a patient in cardiac arrest.", "whyNot": {"a": "Respirations at a rate of sixty breaths per minute is much too quick.", "c": "Chest compressions at a rate of 100 compressions per minute is important. However, defibrillation should be immediate priority.", "d": "Opening the airway is included in care for the client. It would not take precedence over early defibrillation."}, "keyConcept": "The systems of care that work within ACLS are an effective method of coordination of efforts between many healthcare professionals working toward a common goal. The most important element of cardiopulmonary resuscitation is the rapid response."}, {"id": 10437, "cat": "NCLEEX 5", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onlir x && Revi x @ Micr x (ete NeeMcl @ Alli x @New x | NCL xX + v Finish update : € > G 23 student.atitesting.com/LTI Q * ws * © Cb ) see Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments. Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "0%"}, {"id": "b", "t": "0%"}, {"id": "d", "t": "A 0% Moderate B 0% © 0% @D 0% E 0% 2 (S g o 5 [a <"}, {"id": "e", "t": "0%"}], "correct": "d", "rationale": "A 0% Moderate B 0% © 0% @D 0% E 0% 2 (S g o 5 [a <", "whyNot": null, "keyConcept": null}, {"id": 10438, "cat": "NCLEEX 5", "stem": "prevent an air embolism in this case? Type of Complication Nursing Interventions Hemorrhage Keep stopcocks closed, monitor tubing Embolism Clot Use heparin-coated catheters, flush regularly Infection Maintain sterile technique", "choices": [{"id": "a", "t": "Monitor site dressing for drainage"}, {"id": "b", "t": "Keep patient in Trendelenburg during insertion"}, {"id": "c", "t": "Ask the patient to cough every 4 hours"}, {"id": "d", "t": "Flush with saline, followed by heparin, every shift"}], "correct": "b", "rationale": ". An air embolism can cause S an occlusion if it becomes lodged within a blood vessel and prevents blood flow. The nurse can take measures to prevent an air embolism a Ld Gs c during insertion of a pulmonary artery catheter by placing the client in the Trendelenburg position. This position, with the head down, c |_| 18% i decreases the risk of air entering circulation. D || 27% *", "whyNot": {"a": "Monitor site dressing for drainage. This would provide an early alert for bleeding but would not prevent embolus.", "c": "Ask the patient to cough every four hours. This would not prevent embolism.", "d": "Flush with saline, followed by heparin, every shift. This would keep the line patent but would not prevent an embolism."}, "keyConcept": "Apulmonary artery catheter is usually a multilumen catheter, 110 cm long, with extra connecting tubes for attachment to a pressure transducer. The PA lumen or distal lumen is at the tip. A 1.5-cc balloon is located proximal to the tip. A thermistor used to measure temperature changes for calculation of cardiac output is approximately four cm proximal to the balloon. Two additional lumens usually are present 19 cm and 30 cm from the tip. Depending on the degree of right heart enlargement and the position of the catheter, they reside within the right ventricle, right atrium, or the superior vena cava."}, {"id": 10439, "cat": "NCLEEX 5", "stem": "describes the port as noted in the diagram?", "choices": [{"id": "a", "t": "Arteriovenous graft"}, {"id": "b", "t": "Non-tunneled central venous catheter"}, {"id": "c", "t": "Synthetic venous catheter"}, {"id": "d", "t": "Arteriovenous fistula"}], "correct": "d", "rationale": "The patient in the picture has an arteriovenous (AV) fistula, which is created when a surgeon connects an artery and a vein. The AV fistula is cannulated during the hemodialysis process so that blood can be removed from the site, sent to the dialyzer for cleaning, and then returned to the same site.", "whyNot": {"a": "An arteriovenous graft uses a synthetic tube that connects an artery to a vein.", "b": "Anon-tunneled central vein catheter is a catheter inserted directly into a central vein for rapid resuscitation or pressure monitoring.", "c": "Asynthetic venous catheter refers to a catheter that is not of biological material"}, "keyConcept": "There are three primary forms of chronic vascular access for hemodialysis that you may see. They include native arteriovenous fistulas, arteriovenous shunts using graft material, and tunneled double-lumen catheters. A native AV fistula creating by taking a large vein, usually in the forearm, and attaching it directly to a nearby artery."}, {"id": 10440, "cat": "NCLEEX 5", "stem": "Convert study guid¢ (J ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja) Qa * @ New x | NCL x x» * 3 '|1@0 + Finish update & Highlight ~ & Lab Values Figure/Media A nurse is caring for a client who has a simple fracture of the humerus. Which of the following images represents a simple fracture? HHO Oana Oss Occ Ooo", "choices": [{"id": "a", "t": "This is an example of a comminuted fracture, in which there are fragments of broken bone surrounding the fracture."}, {"id": "b", "t": "In a simple fracture, there is a clean break across the bone."}, {"id": "c", "t": "This is an example of a greenstick fracture, where the bone is partially broken and bent. It is called a “greenstick” because it appears"}, {"id": "d", "t": "This is an example of a spiral fracture. The bone is broken due to a twisting motion and there is a spiral or helical fracture line."}], "correct": "b", "rationale": "In a simple fracture, there is a clean break across the bone.", "whyNot": {"a": "This is an example of a comminuted fracture, in which there are fragments of broken bone surrounding the fracture.", "c": "This is an example of a greenstick fracture, where the bone is partially broken and bent. It is called a “greenstick” because it appears", "d": "This is an example of a spiral fracture. The bone is broken due to a twisting motion and there is a spiral or helical fracture line."}, "keyConcept": null}, {"id": 10441, "cat": "NCLEEX 5", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onlir x && Revi x @ Micr x Geiger @ Alli x @New x | NCL xX + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : see Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments. Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "0%"}, {"id": "b", "t": "0%"}, {"id": "c", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "d", "t": "0%"}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}, {"id": 10442, "cat": "NCLEEX 5", "stem": "A nurse is instructed to palpate a client’s radial pulse. At which location should the nurse palpate? 2 (S g o 5 [a <", "choices": [{"id": "a", "t": "This is a location to palpate the apical pulse. e@"}, {"id": "b", "t": "This is a location to palpate the femoral pulse."}, {"id": "c", "t": "This is a location to palpate the carotid pulse."}, {"id": "d", "t": "a| 1% Easy The radial pulse is palpated at the wrist."}], "correct": "d", "rationale": "a| 1% Easy The radial pulse is palpated at the wrist.", "whyNot": {"a": "This is a location to palpate the apical pulse. e@", "b": "This is a location to palpate the femoral pulse.", "c": "This is a location to palpate the carotid pulse."}, "keyConcept": "Measurement of the pulse is performed by palpating an artery as it passes over a hard surface at specific sites around the body. The radial pulse is the most commonly assessed pulse in an adult. It is palpated on the lateral aspect of the wrist in alignment with the thumb. A = | —"}, {"id": 10443, "cat": "NCLEEX 5", "stem": "Which of the following images represents a greenstick fracture? HHO Oana Oss Occ Ooo", "choices": [{"id": "a", "t": "This represents a comminuted fracture, in which there are fragments of broken bone surrounding the fracture."}, {"id": "b", "t": "This represents a simple fracture, where there is a clean break across a bone."}, {"id": "c", "t": "In a greenstick fracture, a bone is partially broken and bent."}, {"id": "d", "t": "This represents a spiral fracture, in which the bone is broken due to a twisting motion and there is a spiral or helical fracture line."}], "correct": "c", "rationale": "In a greenstick fracture, a bone is partially broken and bent. It is called a “greenstick” because it appears similar to what occurs when one c tries to break a green stick of wood.", "whyNot": {"a": "This represents a comminuted fracture, in which there are fragments of broken bone surrounding the fracture.", "b": "This represents a simple fracture, where there is a clean break across a bone.", "d": "This represents a spiral fracture, in which the bone is broken due to a twisting motion and there is a spiral or helical fracture line."}, "keyConcept": "Agreenstick fracture refers to a fracture in which one side of the bone bends and the opposite side breaks at the cortex. Greenstick fractures occur most often during infancy and childhood, when bones are soft. The fracture requires immobilization in a cast to prevent completion of the fracture. Transverse Types of Bones Fractures Oblique, displaced Spiral Greenstick Comminuted"}, {"id": 10444, "cat": "NCLEEX 5", "stem": "The nurse is caring for a child with renal failure and consequent hyperkalemia. Which of the following cardiac rhythms would the nurse expect to see in this child? 2 2 g Fi O : De H 5 Su THALES 5 < f /", "choices": [{"id": "a", "t": "0%"}, {"id": "b", "t": "0%"}, {"id": "c", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "d", "t": "0%"}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}], "nclex_1": [{"id": 10445, "cat": "NCLEX 1", "stem": "A nurse is seeing a 5-month-old in the clinic who is wearing a device that is seen in the image below. This device is used in treatment of which of the following conditions?", "choices": [{"id": "a", "t": "Seizures"}, {"id": "b", "t": "club foot a © o 2 ° s a = a <"}, {"id": "c", "t": "Shoulder dislocation"}, {"id": "d", "t": "Hip dysplasia"}], "correct": "d", "rationale": "a | 1% Easy This is a Pavlik harness, which is used to keep a baby’s hips aligned within the hip joint and is prescribed for infants who are diagnosed with . ° c] 4%", "whyNot": {"a": "An infant who has seizures will be treated with medication, not the Pavlik harness.", "b": "An infant with clubfoot would wear a brace on one or both feet, not a brace that covers the body.", "c": "An infant with shoulder dislocation would wear a sling on the shoulder."}, "keyConcept": "Developmental dysplasia of the hip is associated with abnormalities in the development of the hip in infants and young children. The Grade ] (ll Pause @©O000000 0 © Oi"}, {"id": 10446, "cat": "NCLEX 1", "stem": "Based on the picture, which type of reflex is the infant displaying?", "choices": [{"id": "a", "t": "Tonic neck"}, {"id": "b", "t": "Parachute a © o 2 ° s a = a <"}, {"id": "c", "t": "Truncal incurvation"}, {"id": "d", "t": "Step"}], "correct": "b", "rationale": ", which develops among older infants. When the baby is held upright and then moved quickly so that he is falling forward, the infant will put his arms out to catch himself or to break the fall. ° ci 20% oii 8%", "whyNot": {"a": "The tonic neck reflex is a primitive reflex that disappears around 3 months of age. The infant's arms and head appear to be in a classical", "c": "The truncal curvature reflex occurs if the side of the infant’s spine is stroked or tapped while the infant lies on the stomach. The infant will", "d": "The step reflex refers to reflexive stepping motions when the sole of the infant's foot touches a hard surface."}, "keyConcept": null}, {"id": 10447, "cat": "NCLEX 1", "stem": "A nurse is teaching a client who is at 32 weeks of gestation about findings to immediately report to the provider. Which of the following manifestations should the nurse include?", "choices": [{"id": "a", "t": "Watery discharge from the vagina"}, {"id": "b", "t": "Swelling of the ankles"}, {"id": "c", "t": "Heartburn after eating"}, {"id": "d", "t": "Lightheadedness when lying on back"}], "correct": "a", "rationale": "Asudden watery discharge from the vagina could indicate that the amniotic membranes have ruptured. This finding should always be B Hl 13% immediately reported to the physician. ° c | 2%", "whyNot": {"b": "Swelling of the ankles is a common discomfort during pregnancy and can be relieved by sitting with the legs elevated.", "c": "Heartburn occurs during pregnancy due to pressure on the stomach from the enlarging uterus. It can be relieved by eating smaller, more", "d": "Supine hypotension occurs when a client feels lightheaded when lying on their back. The nurse should instruct the client to use the side-"}, "keyConcept": "The nurse should inform pregnant clients about the manifestations of potential pregnancy complications, such as swelling of the face, chills, vaginal bleeding, severe headaches, and visual disturbances. If the client experiences any of these, the provider should be notified immediately to allow for prompt intervention. Although spontaneous rupture of the membranes after 37 weeks is an expected finding, the occurrence should always be immediately reported to the physician."}], "nclex_10_ante_neonatal_care": [{"id": 10448, "cat": "NCLEX 10-ante...neonatal care", "stem": "nurse? O A. Place the infant on the mother’s abdomen and help her get him to cry O B. Assist the mother with breastfeeding the infant to wake him up O C. Place the infant in a radiant warmer and dry him with a towel O D. Call a code blue and notify the neonatal resuscitation team", "choices": [{"id": "a", "t": "Place the infant on the mother’s abdomen and help her get him to cry"}, {"id": "b", "t": "Assist the mother with breastfeeding the infant to wake him up"}, {"id": "c", "t": "Place the infant in a radiant warmer and dry him with a towel"}, {"id": "d", "t": "Call a code blue and notify the neonatal resuscitation team"}], "correct": "c", "rationale": "Depending on facility policy, a newborn infant may be placed in a radiant warmer for observation or on the mother’s abdomen immediately after delivery. However, if the infant is pale and not crying, the nurse should place him in a warmer and dry him off to stimulate him to cry. In many cases, gentle stimulation after birth is enough to make an infant cry; if he does not respond, then further measures, such as pressurized oxygen, are necessary.", "whyNot": {"a": "The infant may eventually be placed on the mother’s abdomen; however, this infant is showing signs of distress and is not crying. The", "b": "The infant is not sleepy and does not need to breastfeed at this moment. The nurse should place him in a radiant warmer to stimulate him", "d": "While a code blue may be necessary if the nurse has attempted unsuccessfully to get the infant to breathe, the nurse should first make"}, "keyConcept": "Radiant warmer beds provide accessibility for resuscitation or procedures while providing thermal stability in the neonate. When the neonate's condition has stabilized, the infant can be moved to a preheated incubator, on skin temperature servocontrol, if necessary. The axillary temperature should be monitored closely. Temperature should be checked 30 minutes after moving the neonate to the incubator and every hour for four hours afterwards."}, {"id": 10449, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing care for a client who is at 28 weeks of gestation. The client has placenta previa and is actively bleeding. Which of the following medications should the nurse expect the provider to prescribe?", "choices": [{"id": "a", "t": "Betamethasone"}, {"id": "b", "t": "Protamine sulfate O c. oxytocin"}, {"id": "d", "t": "Methylergonovine"}], "correct": "a", "rationale": "Betamethasone is a common glucocorticoid given to a client who is pregnant and at risk for preterm delivery to promote fetal lung maturity. Because the client is actively bleeding, the nurse should identify that the client is at risk for preterm delivery.", "whyNot": {"b": "Protamine sulfate is a heparin antagonist that is used to reverse the effects of heparin overdose. It is not indicated for a client who has", "d": "Methylergonovine is prescribed for a client who is experiencing postpartum hemorrhage."}, "keyConcept": "Placenta previa is a condition that occurs during pregnancy in which the placenta is implanted in the uterine wall close to the cervix. Clients who have placenta previa experience painless, bright red bleeding during their second or third trimester. Depending on the severity of the previa, the provider might monitor this closely and prescribe bedrest and no intercourse. Glucocorticoids, such as betamethasone, are given to clients who have placenta previa to enhance fetal lung maturity in the event of preterm delivery."}, {"id": 10450, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following postpartum clients is at highest risk of hemorrhage after delivery? O A.A primigravida O B. A client with pregnancy-induced hypertension O C. A client under age 25 O D. A client of Hispanic ethnicity", "choices": [{"id": "a", "t": "Hemorrhage after delivery is more often seen in clients who have delivered several children in the past, not those who are delivering their"}, {"id": "b", "t": "all 9% Easy A client with pregnancy-induced hypertension is at increased risk of bleeding during the postpartum period."}, {"id": "c", "t": "Age under 25 does not increase the risk of hemorrhage following delivery."}, {"id": "d", "t": "There is not an increased risk of postpartum hemorrhage in a client with Hispanic ethnicity as compared to clients of other backgrounds."}], "correct": "b", "rationale": "all 9% Easy A client with pregnancy-induced hypertension is at increased risk of bleeding during the postpartum period. High blood pressure can es r..tsisdz 87% increase the risk of vessel rupture, which could lead to hemorrhage and possible shock in the client. c I 3%", "whyNot": {"a": "Hemorrhage after delivery is more often seen in clients who have delivered several children in the past, not those who are delivering their", "c": "Age under 25 does not increase the risk of hemorrhage following delivery.", "d": "There is not an increased risk of postpartum hemorrhage in a client with Hispanic ethnicity as compared to clients of other backgrounds."}, "keyConcept": "Once a baby is delivered, the uterus normally contracts by tightening the uterine muscles and expelling the placenta. After the placenta is delivered, these contractions compress the bleeding vessels at the placental attachment site. If the uterus does not contract strongly enough, called uterine atony, these the vessels bleed freely and hemorrhage occurs. This is the most common cause of postpartum hemorrhage. Risk factors include placental abruption ( early detachment of the placenta from the uterus; )placenta previa (placenta covers or is near the cervical opening); overdistended uterus (due to large fetus or excess amniotic fluid); multiple gestation; gestational hypertension; multiparity; prolonged labor; obesity; and infection. 2 = ® 4 z = a iat g <"}, {"id": 10451, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following postpartum clients is at highest risk of hemorrhage after delivery? O A.A primigravida O B. A client with pregnancy-induced hypertension O C. A client under age 25 O D. A client of Hispanic ethnicity eck Answer", "choices": [{"id": "a", "t": "Hemorrhage after delivery is more often seen in clients who have delivered several children in the past, not those who are delivering their"}, {"id": "b", "t": "all 9% Easy A client with pregnancy-induced hypertension is at increased risk of bleeding during the postpartum period."}, {"id": "c", "t": "Age under 25 does not increase the risk of hemorrhage following delivery."}, {"id": "d", "t": "There is not an increased risk of postpartum hemorrhage in a client with Hispanic ethnicity as compared to clients of other backgrounds."}], "correct": "b", "rationale": "all 9% Easy A client with pregnancy-induced hypertension is at increased risk of bleeding during the postpartum period. High blood pressure can B r..tsisdz 87% increase the risk of vessel rupture, which could lead to hemorrhage and possible shock in the client. c I 3%", "whyNot": {"a": "Hemorrhage after delivery is more often seen in clients who have delivered several children in the past, not those who are delivering their", "c": "Age under 25 does not increase the risk of hemorrhage following delivery.", "d": "There is not an increased risk of postpartum hemorrhage in a client with Hispanic ethnicity as compared to clients of other backgrounds."}, "keyConcept": "Once a baby is delivered, the uterus normally contracts by tightening the uterine muscles and expelling the placenta. After the placenta is delivered, these contractions compress the bleeding vessels at the placental attachment site. If the uterus does not contract strongly enough, called uterine atony, these the vessels bleed freely and hemorrhage occurs. This is the most common cause of postpartum hemorrhage. Risk factors include placental abruption ( early detachment of the placenta from the uterus; )placenta previa (placenta covers or is near the cervical opening); overdistended uterus (due to large fetus or excess amniotic fluid); multiple gestation; gestational 2 (S g o 5 [a < hypertension; multiparity; prolonged labor; obesity; and infection."}, {"id": 10452, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is receiving a magnesium sulfate IV infusion and exhibiting manifestations of magnesium toxicity. Which of the following medications should the nurse expect to administer?", "choices": [{"id": "a", "t": "Nifedipine"}, {"id": "b", "t": "Pyridoxine"}, {"id": "c", "t": "Protamine sulfate"}, {"id": "d", "t": "Calcium gluconate"}], "correct": "d", "rationale": "al 3% Easy Calcium gluconate or calcium chloride is used to treat magnesium sulfate toxicity. It acts to increase the transmission of nerve impulses and , skeletal, and smooth muscle.", "whyNot": {"a": "Nifedipine is a calcium channel blocker used as an antihypertensive medication. It can be administered to clients who have gestational", "b": "Pyridoxine, or vitamin B6, is a vitamin supplement that is prescribed to clients who have hyperemesis gravidarum.", "c": "Protamine sulfate is a medication administered to treat a heparin overdose."}, "keyConcept": "Magnesium sulfate is administered intravenously to clients who are pregnant and have severe preeclampsia to prevent seizure activity. It is a central nervous system depressant that works to block neuromuscular transmission of acetylcholine. Magnesium is excreted through the kidneys. Therefore, an alteration in renal function, such as with preeclampsia, can lead to the development of magnesium toxicity. 2 = ® 4 z = a iat g < Manifestations of magnesium toxicity include absent deep tendon reflexes, respiratory depression, blurred vision, muscle weakness, a decreased level of consciousness, and cardiac arrest. Calcium gluconate or calcium chloride can be administered intravenously to reverse the effects of magnesium toxicity."}, {"id": 10453, "cat": "NCLEX 10-ante...neonatal care", "stem": "of the following is the most appropriate action for the nurse to take?", "choices": [{"id": "a", "t": "Explain to the mother that she is free to go but the infant must remain in the hospital until released by the physician"}, {"id": "b", "t": "Inform the client that if she takes her infant out of the hospital she will be reported to child protective services"}, {"id": "c", "t": "Call the physician on call and obtain orders for a mild antidepressant for the client"}, {"id": "d", "t": "Allow the client to take her infant home after completing discharge instructions"}], "correct": "d", "rationale": "A | | 26% Moderate The child belongs to the mother and she may sign him or her out when she leaves. ce | 11%", "whyNot": {"a": "The baby is under the guardianship of the mother and the mother may take the child with her when she leaves. ep fe 62%", "b": "A statement like this is threatening and will interfere with any attempts at teaching. A referral to protective services may or may not be", "c": "The client has not demonstrated signs or symptoms of depression in this case. This action by the nurse would be inappropriate."}, "keyConcept": "Discharge against medical advice in postpartum women occurs most frequently among women who have had caesarean section delivery or otherwise complicated births. The risk of AMA departure is increased in vulnerable women with psychosocial and medical risk factors, so the nurse should provide discharge instructions and arrange early follow-up visits. The nurse should provide emotional support, identify the 2 = ® 4 z = a iat g < client's reason for early discharge, attempt to provide continuity of care after discharge, and consider additional steps, including referral to. counseling or support services for vulnerable women."}, {"id": 10454, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is teaching a client who is at 32 weeks of gestation about findings to immediately report to the provider. Which of the following manifestations should the nurse include?", "choices": [{"id": "a", "t": "Watery discharge from the vagina"}, {"id": "b", "t": "Swelling of the ankles"}, {"id": "c", "t": "Heartburn after eating"}, {"id": "d", "t": "Lightheadedness when lying on back"}], "correct": "a", "rationale": "o; Asudden watery discharge from the vagina could indicate that the amniotic membranes have ruptured. This finding should always be B | immediately reported to the physician.", "whyNot": {"b": "Swelling of the ankles is a common discomfort during pregnancy and can be relieved by sitting with the legs elevated.", "c": "Heartburn occurs during pregnancy due to pressure on the stomach from the enlarging uterus. It can be relieved by eating smaller, more", "d": "Supine hypotension occurs when a client feels lightheaded when lying on their back. The nurse should instruct the client to use the side-"}, "keyConcept": "The nurse should inform pregnant clients about the manifestations of potential pregnancy complications, such as swelling of the face, chills, vaginal bleeding, severe headaches, and visual disturbances. If the client experiences any of these, the provider should be notified immediately to allow for prompt intervention. Although spontaneous rupture of the membranes after 37 weeks is an expected finding, the occurrence should always be immediately reported to the physician."}, {"id": 10455, "cat": "NCLEX 10-ante...neonatal care", "stem": "nurse use as a common indication for non-stress test (NST) in a pregnant client?", "choices": [{"id": "a", "t": "The client is 41 weeks gestation"}, {"id": "b", "t": "The client is 39 years old"}, {"id": "c", "t": "The client’s first child had Down syndrome"}, {"id": "d", "t": "The client had an abnormal ultrasound"}], "correct": "a", "rationale": "A fetal non-stress test is a simple, non-invasive test performed in pregnancies at > 28 weeks gestation. No stress is placed on the fetus during the test. One monitor is placed on the mother’s abdomen to measure fetal heart rate and another is placed to measure contractions. Fetal movement, heart rate and the reactivity of the fetal heart rate to movement is measured for 20-30 minutes. 2 = ® 4 z = a iat g <", "whyNot": {"b": "The client’s age of 39 years puts her at higher risk of having a baby born with Down syndrome or another birth defect. This would warrant", "c": "This part of the client’s history would most likely warrant an amniocentesis, not an NST.", "d": "An abnormal ultrasound would not be followed with an NST; the client would most likely need an amniocentesis."}, "keyConcept": "A fetal non-stress test is a simple, non-invasive test performed in pregnancies at > 28 weeks gestation. No stress is placed on the fetus during the test. One monitor is placed on the mother’s abdomen to measure fetal heart rate and another is placed to measure contractions. Fetal movement, heart rate and the reactivity of the fetal heart rate to movement is measured for 20-30 minutes. 2 = ® 4 z = a iat g <"}, {"id": 10456, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a neonate after delivery. Which of the following assessment items is most concerning for the nurse?", "choices": [{"id": "a", "t": "Dullness to percussion over the bladder"}, {"id": "b", "t": "Single testicle palpated"}, {"id": "c", "t": "Auscultation of bilateral wheezes"}, {"id": "d", "t": "Ptosis of the left eyelid"}], "correct": "d", "rationale": "At birth, any cranial nerve abnormality is concerning. The eyelids should sit symmetrically above the pupils, with the irises visible. Ptosis © fe refers to drooping of the eyelid below the level of the pupil and may indicate paralysis of the oculomotor nerve. Among the choices given, ep || this finding is concerning and should be assessed. Infants should blink to light and should be able to close both eyes tightly when crying. The corneal reflex can be tested by gently touching the cornea with a tissue paper. Sucking, swallowing, and tongue movement should be observed to test cranial nerves V, Vil, IX, X, and XII.", "whyNot": {"a": "Neonates void shortly after birth. Until they do, dullness to percussion over the bladder is a normal finding.", "b": "An undescended testicle at birth is not concerning since most testes that are undescended will descend spontaneously by the age of 6", "c": "Immediately after birth, a neonate must transition to extrauterine life. This includes a transition from the fetal cardiovascular system."}, "keyConcept": "Aneurological assessment of a newborn after delivery includes assessment of level of alertness, muscle tone, cranial nerves and reflexes. Facial asymmetry, including drooping eyelid, is concerning for a cranial nerve impairment."}, {"id": 10457, "cat": "NCLEX 10-ante...neonatal care", "stem": "most appropriate response from the nurse?", "choices": [{"id": "a", "t": "“Try to feed your baby again in 2 more hours; this will eventually go away.”"}, {"id": "b", "t": "“Before you try to feed your baby again, take a warm shower.”"}, {"id": "c", "t": "“Use a breast pump for two or three minutes on a high setting in between feedings.”"}, {"id": "d", "t": "“Place these lettuce leaves inside your bra to help reduce the swelling.”"}], "correct": "b", "rationale": "Engorgement may occur approximately 2 to 3 days after giving birth when the breasts swell and become painful, limiting the ability to produce enough milk for the baby. A mother who is engorged but who wants to breastfeed may consider taking a short shower just prior to feeding her baby. The warm water encourages let-down of milk and may make feeding easier.", "whyNot": {"a": "Waiting two hours and then trying to feed the baby will not help the engorgement. The nurse should assist the mother to take measures to", "c": "The mother may resolve some of the engorgement by using a breast pump briefly on a low setting to encourage milk let-down. Using a", "d": "Lettuce leaves have not been shown to resolve breast engorgement and should not be used."}, "keyConcept": "Breast engorgement results from expansion and pressure exerted by the synthesis and storage of breast milk on the mammary glands. Engorgement affects the infant's ability to latch-on. It results in changes in the shape and curvature of the nipple, making the breast inflexible, flat, hard, and swollen. The nipples on an engorged breast are flat. Engorgement commonly occurs when the breasts switch from colostrum to mature milk, although it may occur later as a result of inadequate removal of breast milk. Clinical manifestations include swelling and edema;a shiny and diffusely red appearance; and pain. Both breasts are usually affected."}, {"id": 10458, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x <€ > G 23 student.atitesting.com/LT| Convert study guide @ alli x @ New x [=| NCL! x | + v Qa * ws * © Cb Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Rhogam is not administered if the mother and the fetus's blood type match (the same)."}, {"id": "b", "t": "o; Individuals with Rh-negative blood develop antibodies after exposure to Rh-positive blood."}, {"id": "c", "t": "Rhogam is not administered if the mother and the fetus's blood type match (the same)."}, {"id": "d", "t": "There is no risk of antibody formation leading to fetal destruction if the mother is Rh+ yet the fetus is Rh-. Rhogam is not indicated in these"}], "correct": "b", "rationale": "o; Individuals with Rh-negative blood develop antibodies after exposure to Rh-positive blood. Rhogam is an immune globulin given to Rh- A I negative women in pregnancy if the father is not conclusively shown to be Rh-negative to prevent sensitization of Rh-negative women who have had a fetomaternal transfusion of Rh-positive fetal RBCs. A standard dose of RhoGAM is administered as an |M injection at 28 weeks € | gestation to prevent the formation of antibodies against Rh-positive red blood cells. It is also given after exposure risks that occur after 28 D Hi weeks, including amniocentesis, second-trimester miscarriage/abortion, external version attempt, and within 72 hours of delivery if the baby is Rh-positive.", "whyNot": {"a": "Rhogam is not administered if the mother and the fetus's blood type match (the same).", "c": "Rhogam is not administered if the mother and the fetus's blood type match (the same).", "d": "There is no risk of antibody formation leading to fetal destruction if the mother is Rh+ yet the fetus is Rh-. Rhogam is not indicated in these"}, "keyConcept": "Rhogam promotes the destruction of fetal Rh-positive blood cells before the mother forms antibodies against them. It is given to Rh-negative women to prevent antibody formation that could attack Rh-positive fetal red blood cells in a subsequent pregnancy."}, {"id": 10459, "cat": "NCLEX 10-ante...neonatal care", "stem": "rate monitoring, which of the following actions by the nurse is most appropriate?", "choices": [{"id": "a", "t": "Turn the client on her left side and notify the physician"}, {"id": "b", "t": "Increase the rate of oxytocin (Pitocin) IV"}, {"id": "c", "t": "Assist the client to take slow, deep breaths"}, {"id": "d", "t": "Continue to monitor FHR but make no changes"}], "correct": "d", "rationale": "A Hi 18% Moderate An increase in FHR from 110 bpm to 140 bpm is most likely in response to stimulation from the vaginal exam. The fetal heart rate is not . The nurse should note the change and continue to monitor. I © 6%", "whyNot": {"a": "The nurse does not need to notify the physician or turn the client on her side. This is a normal response from the baby after cervical", "b": "Increasing oxytocin (Pitocin) would only stimulate further contractions, which is not necessary. The infant is responding in a normal", "c": "While assisting the client to take slow, deep breaths may be calming, it is not necessary for this response in heart rate."}, "keyConcept": "Fetal distress is reflected by changes in the normal pattern of fetal heart rate in response to uterine contractions during labor. Electronic fetal 2 = ® 4 z = a iat g < monitoring can be external, internal, or both. The client may be confined to bed during both types of electronic monitoring, but can move around to find a comfortable position..External electronic fetal heart rate monitoring is performed by attaching a pair of belts around the mother's abdomen. One belt uses Doppler to detect the fetal heart rate and the other belt measures length of contractions and time between contractions. With internal monitoring, an electrode is placed on the part of the fetus closest to the cervix, usually the scalp, to record the fetal heart rate. Uterine contractions also may be monitored with an intrauterine pressure catheter inserted through the vagina into the uterus. Internal monitoring is only used after the membranes of the amniotic sac have ruptured."}, {"id": 10460, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja) A nurse is administering magnesium sulfate IV at 2 g per hr to a client who is pregnant and is experiencing preeclampsia with severe features. Which of the following findings indicates to the nurse that it is safe to continue to administer the medication?", "choices": [{"id": "a", "t": "Diminished deep-tendon reflexes"}, {"id": "b", "t": "Respiratory rate of 16/min"}, {"id": "c", "t": "Urine output of 50 mL in 4 hr"}, {"id": "d", "t": "Increased drowsiness"}], "correct": "b", "rationale": "The client's respiratory rate should be at least 12/min to maintain adequate respiratory function. Bradypnea is a clinical manifestation of magnesium toxicity. Therefore, based on this finding, it is safe for the nurse to continue administering the medication.", "whyNot": {"a": "Diminished or absent deep-tendon reflexes are manifestations of magnesium toxicity. Therefore, the nurse should discontinue the", "c": "The client's urine output should be at least 25 to 30 mL/hr to promote adequate excretion of magnesium. Therefore, the nurse should", "d": "Increased drowsiness is a common effect of magnesium sulfate, however a decreased level of consciousness is a potential a manifestation"}, "keyConcept": "Nursing assessments to monitor for a client who is receiving magnesium sulfate include: + Blood pressure, heart rate, and respiratory rate 0 Check every 15 to 30 min. «Intake and output 0 Intake should be no more than a total of 125 mL/hr. 0 Output should be at least 25 to 30 mL/hr. + Visual disturbances + Presence of headache + Epigastric pain 0 Check every 60 min. + Loss or diminished deep tendon reflexes, including increased edema + Laboratory values, including: o Magnesium level o Prothrombin time o Partial thromboplastin time 0 Platelet count"}, {"id": 10461, "cat": "NCLEX 10-ante...neonatal care", "stem": "hormones from the anterior pituitary gland?", "choices": [{"id": "a", "t": "Prolactin"}, {"id": "b", "t": "Oxytocin"}, {"id": "c", "t": "Estrogen"}, {"id": "d", "t": "Progesterone"}], "correct": "a", "rationale": "Prolactin stimulates secretion of milk from the breasts.", "whyNot": {"b": "Oxytocin is released from the posterior pituitary. It causes uterine contractions and the let-down reflex.", "c": "Estrogen is not a pituitary hormone.", "d": "Progesterone is not a pituitary hormone."}, "keyConcept": null}, {"id": 10462, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ (J ATI? X © New x x ]) untii x Untii x (4 Goo x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions", "choices": [{"id": "a", "t": "Painless uterine bleeding"}, {"id": "b", "t": "Hypotension and tachycardia"}, {"id": "c", "t": "Usually not visible"}, {"id": "d", "t": "Pain or pressure"}], "correct": "d", "rationale": "Vaginal, vulvar, or retroperitoneal hematomas may form as a result of lacerations during delivery. Lacerations of the cervix, perineum, and © I vagina should be suspected in clients who continue to have bleeding despite the contraction of the uterus in the puerperium. Bleeding may ep fF be a frank hemorrhage or a slower/smaller volume of vaginal bleeding. The most common type of injury is a laceration of the perineum. Cervical lacerations usually result in minimal bleeding. The most common, as a result, is vulvar hematoma, which is usually visible. It is most frequently the result of episiotomy or perineal laceration, and the most commonly associated symptom is pain. Vaginal hematomas are associated with forceps-assisted birth, primigravid mother, or episiotomy. Perineal or rectal pain or vaginal pressure is typical. If the hematoma is retroperitoneal, pain may be minimal, and the client may initially present with signs of shock. Treatment of small vulvar hematomas may require only analgesia and use of ice packs applied to the perineum for 24 hours to reduce swelling. If the hematoma is large or expands rapidly, surgical intervention may be necessary.", "whyNot": {"a": "Lacerations sustained during delivery usually occur in the cervix, perineum, or vagina.", "b": "Hypotension and tachycardia are only likely when the hemorrhage is severe.", "c": "A vulvar hematoma is usually visible."}, "keyConcept": "Avulvar hematoma following an episiotomy is the result of bleeding and trauma during the birth process. The pregnant uterus, vagina, and vulva have a rich vascular supply. The vulvar hematoma is painful and may cause discomfort in sitting or moving around. Pain medication does little to reduce the pain due to the swelling and inflammation in the area. A surgical procedure may be necessary to remove the clots."}, {"id": 10463, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is admitting a pregnant client for observation and possible labor induction. Which of the following actions is part of the nurse’s physical assessment?", "choices": [{"id": "a", "t": "Check for a list of the client’s medications"}, {"id": "b", "t": "Measure fundal height"}, {"id": "c", "t": "Assess use of alcohol or nicotine during pregnancy"}, {"id": "d", "t": "Determine social support"}], "correct": "b", "rationale": "al 4% Easy The physical exam that is performed during admission of a pregnant client includes actions that make up the physical assessment, such as. es | sd 89% measuring fundal height, checking vital signs, checking cervical dilation, and assessing for contractions. Finding information such as a list of medications, history of alcohol or nicotine use, and amount of social support is part of the client history. € I i) o| 2%", "whyNot": {"a": "Checking for a list of the client’s medications would be part of taking the client’s history, not part of the physical assessment.", "c": "Assessing for the use of alcohol or nicotine during pregnancy is included as part of the client’s history, not the physical assessment.", "d": "Determining the amount of social support the client has is part of the client’s social history. It is not included as part of the physical"}, "keyConcept": "During the third trimester, the client is seen by the healthcare provider every 2 to 4 weeks, depending on the client's health and obstetrical history. Starting at 36 weeks the client will undergo weekly checkups until delivery. During the third trimester, prenatal care includes vaginal exams to check the baby's position. Screening for group B streptococcus (GBS) also occurs during the third trimester. 2 = ® 4 z = a iat g <"}, {"id": 10464, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a neonate with exstrophy of the bladder. Which of the following is the most appropriate initial nursing intervention?", "choices": [{"id": "a", "t": "Prepare for immediate surgical repair."}, {"id": "b", "t": "Place a protective plastic film over the bladder."}, {"id": "c", "t": "Place petroleum jelly gauze over the bladder."}, {"id": "d", "t": "Place a urinary catheter into the bladder."}], "correct": "b", "rationale": "Exstrophy of the bladder is a disorder that results from failure of the bladder to develop properly in the abdominal cavity during fusion in the embryo. As a result, the bladder is exposed externally and must be surgically repaired. The initial nursing intervention should occur prior to surgery to prevent infection, injury, or loss of moisture. The initial nursing action is to place a protective non-adherent plastic film, such as Saran wrap, or a transparent adhesive dressing, over the exposed bladder to maintain moistness and prevent infection. The umbilical clamp used during delivery is usually replaced with soft tape or silk ligature.", "whyNot": {"a": "The initial nursing intervention should protect the bladder before surgery. Surgery is not emergent.", "c": "Bladder tissue is delicate and can be damaged by petroleum jelly.", "d": "Aneonate usually urinates several hours after birth. Placement of a urinary catheter is not the appropriate nursing intervention."}, "keyConcept": "Bladder exstrophy is a congenital condition that results in an open, inside-out bladder (the inner surface exposed) on the surface of the lower abdominal wall and an open exposed dorsal urethra. Trauma to the open bladder should be avoided by measures that include placement of a non-adhesive plastic film or transparent adhesive dressing over the exposed bladder."}, {"id": 10465, "cat": "NCLEX 10-ante...neonatal care", "stem": "information should the nurse include about black cohosh?", "choices": [{"id": "a", "t": "\"Black cohosh affects hormones.\""}, {"id": "b", "t": "\"Black cohosh can help relieve headache pain.\""}, {"id": "c", "t": "\"Black cohosh increases the risk for bleeding.\""}, {"id": "d", "t": "\"Black cohosh causes elevated blood pressure.\""}], "correct": "a", "rationale": "Black cohosh does affect hormones, relieving menopausal manifestations and helping disturbed sleeping patterns. However, black cohosh should not be taken during the first and second trimesters of pregnancy due to its estrogenic effects. Black cohosh is sometimes used to stimulate uterine contractions.", "whyNot": {"b": "Black cohosh has no analgesic effect if the client has a headache, but it does have the adverse effect of causing headaches. However,", "c": "Black cohosh does not affect the risk for bleeding. However, garlic decreases platelet aggregation and can increase the risk for bleeding.", "d": "Black cohosh does not cause increased blood pressure. However, ephedra is a stimulant that can increase heart rate and elevate blood"}, "keyConcept": "Black cohosh and many other over-the-counter herbals supplements and medications should not be taken when pregnant due to possible adverse effects on the fetus. Encourage pregnant women to check with their obstetrician for a list of supplements and medications that can be taken while pregnant. Black cohosh mimics estrogen."}, {"id": 10466, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is teaching a class to expectant mothers. Which of the following should the nurse advise the group to avoid in order to prevent toxoplasmosis?", "choices": [{"id": "a", "t": "Contact with cat feces"}, {"id": "b", "t": "Eating freshwater fish"}, {"id": "c", "t": "Excessive exposure to radiation"}, {"id": "d", "t": "Working with heavy metals"}], "correct": "a", "rationale": "Toxoplasma gondii can be transmitted by exposure to infected cat feces or by ingesting undercooked contaminated meat.", "whyNot": {"b": "The parasite is found in warm-blooded animals, not in fish.", "c": "Toxoplasmosis is not associated with radiation.", "d": "Toxoplasmosis is not associated with heavy metals."}, "keyConcept": "If a pregnant woman has been infected with Toxoplasma before becoming pregnant, the unborn child is usually protected by maternal immunity. Experts suggest waiting for 6 months after a recent infection to become pregnant. Infected infants but are often asymptomatic at birth but can develop serious symptoms later in life, including blindness or mental disability. Infected newborns sometimes have eye or brain damage at birth. Pregnant women should avoid changing cat litter if possible. If no one else can change cat litter, the woman should wear disposable gloves and wash her hands with soap and water afterwards. The cat litter box should be changed daily. The parasite does not become infectious until 1 to 5 days after it is shed in a cat’s feces. Household cats should be kept indoors and fed with commercially prepared foods."}, {"id": 10467, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing care for a client who is in preterm labor at 30 weeks of gestation. Which of the following medications should the nurse expect the provider to prescribe to accelerate fetal lung maturity?", "choices": [{"id": "a", "t": "Calcium gluconate"}, {"id": "b", "t": "Indomethacin O c. oxytocin"}, {"id": "d", "t": "Betamethasone"}], "correct": "d", "rationale": "Betamethasone is a glucocorticoid that is given to clients who are in preterm labor to hasten surfactant production, which accelerates fetal lung maturity.", "whyNot": {"a": "Calcium gluconate is administered to treat magnesium sulfate toxicity.", "b": "Indomethacin is an NSAID that is used to suppress preterm labor by blocking prostaglandin production to relax the uterine muscles. It"}, "keyConcept": "Preterm labor or birth occurs when labor or delivery occurs prior to 37 weeks of gestation. Depending on the severity of the preterm labor manifestations, it is usually managed with restricted activity. Medications can be administered to stop uterine contractions, such as magnesium sulfate, nifedipine, or indomethacin. Betamethasone, a glucocorticoid, can be administered IM to increase fetal lung maturity through increased production of surfactant."}, {"id": 10468, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is in labor with cervical dilation of 5 cm. Which of the following findings on the assessment requires intervention by the nurse?", "choices": [{"id": "a", "t": "Contraction intensity of 45 mmHg."}, {"id": "b", "t": "Resting uterine tone of 10 mmHg"}, {"id": "c", "t": "Duration of contractions of 100 seconds"}, {"id": "d", "t": "Frequency of contractions every 4 minutes"}], "correct": "c", "rationale": "All FI Normal uterine contractions in the active phase of the first stage of labor (which begins at some point when the cervix is dilated between 4-7 ec fF cm) should not last longer than 90 seconds. The uterus contracts to dilate and efface the cervix while causing the fetus to descend. During D | | contractions, blood flow through the intervillous space and spiral arterioles can decrease, which places stress on the fetus. Typically, the length of uterine contraction is 40-70 seconds. During the active phase of the first stage of labor, contractions are more regular, at a frequency of 3-5 minutes. During this stage of labor, there is rapid dilation and effacement. Fetal descent begins. Maternal feelings of helplessness, anxiety, and restlessness often increase as the contractions become stronger.", "whyNot": {"a": "The intensity of contractions refers to the strength of contractions at the peak and should not exceed 80 mmHg. Contraction intensity", "b": "Resting tone refers to the tension in the uterine muscles between contractions. The tension averages 10 mmHg and should not exceed 20", "d": "The first stage of labor is characterized by 2-5 contractions every 10 minutes. Contractions should occur no more frequently than once"}, "keyConcept": "During normal labor, regular uterine contractions cause progressive dilation and effacement of the cervix, with descent and eventual expulsion of the fetus. The first stage consists of a latent phase and an active phase. The latent phase is characterized by gradual change in the cervix. The active phase is characterized by rapid cervical change. The active phase usually begins when the cervix is 5-6 cm dilated and lasts until complete cervical dilation. Uterine contractions during this stage should not last longer than 90 seconds. During contractions, blood flow through the placenta may decrease."}, {"id": 10469, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following findings on an assessment of a newborn is concerning in the first hour after a spontaneous vaginal delivery?", "choices": [{"id": "a", "t": "Respiratory rate of 58/min"}, {"id": "b", "t": "Systolic blood pressure of 65 mmHg"}, {"id": "c", "t": "Capillary glucose of 28 mg/dL"}, {"id": "d", "t": "Flat red marks on the upper eyelids and forehead that blanch with pressure"}], "correct": "c", "rationale": "all 8% Easy cy 6% The fetus stores glycogen during pregnancy to use during the transition period to extrauterine life. In the neonatal period, normal glucose is © fs 79% considered 30 mg/dL or more, but optimal levels are 70-100 mg/dL. The glucose level rises and stabilizes in the newborn within 2-3 hours , but a level of 30 mg/dL is concerning. Neonatal hypoglycemia can result in significant neurologic damage, manifested by cognitive developmental delay, recurrent seizure activity, developmental delay, and personality disorders. Normal vital signs during this period are in the table below. Respiratory rate 30-60/minute Heart rate 110-160/minute u Systolic blood pressure | 60-80 mm Hg 2 Diastolic blood pressure | 40-50 mm Hg B Temperature 97.7-99.5 F (36.5-37.5 C) axillary 2 &", "whyNot": {"a": "This respiratory rate is within the normal range for a newborn.", "b": "This is within the normal range of systolic blood pressure in a neonate.", "d": "This describes telangiectatic nevi, sometimes known as “stork bites.” They may be pink or red and are usually found on the nose,"}, "keyConcept": "The fetus stores glycogen during gestation to use during the transition to extrauterine life. A glucose of less than 30 mg/dL is concerning in the first hour of life. Although neonates may be asymptomatic, symptoms of hypoglycemia in newborns include hypotonia, lethargy, poor feeding, jitteriness, seizures, congestive heart failure, cyanosis, apnea, and hypothermia."}, {"id": 10470, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is teaching a client who is at 24 weeks of gestation and scheduled for an amniocentesis procedure. Which of the following client statements indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Iwill lie on my right side during this test.\""}, {"id": "b", "t": "\"I cannot eat or drink anything for 24 hours prior to this procedure.\""}, {"id": "c", "t": "\"I must urinate prior to the procedure.\""}, {"id": "d", "t": "\"I will be given medication to put me to sleep during this procedure.\""}], "correct": "c", "rationale": "During an amniocentesis, a needle is inserted through the maternal abdomen and there is a risk for puncture. The client's bladder should be empty prior to the procedure to allow for better visualization of the gestational sac and to reduce this risk.", "whyNot": {"a": "During an amniocentesis, the client should be in a supine position with a wedge placed under her right hip to move the uterus off of the", "b": "The client does not need to be NPO for 24 hr prior to the procedure.", "d": "During an amniocentesis, the client should be conscious and awake. There is no indication for sedative use for this procedure."}, "keyConcept": "Amniocentesis is an invasive procedure performed to evaluate the amniotic fluid for fetal chromosomal abnormalities and fetal lung maturity. The client should be instructed to empty her bladder prior to the test to decrease the risk for puncture. The client should be ina supine position. Ultrasonography is used to visualize the fetus and allow the provider to safely insert the needle through the abdomen. The amniotic fluid is aspirated and then examined after the procedure."}, {"id": 10471, "cat": "NCLEX 10-ante...neonatal care", "stem": "following? O A. Increased peristaltic action during pregnancy O B. Displacement of the stomach by the diaphragm O C. Decreased secretion of hydrochloric acid O D. Backflow of stomach contents into the esophagus", "choices": [{"id": "a", "t": "Increased peristaltic action during pregnancy"}, {"id": "b", "t": "Displacement of the stomach by the diaphragm"}, {"id": "c", "t": "Decreased secretion of hydrochloric acid"}, {"id": "d", "t": "Backflow of stomach contents into the esophagus"}], "correct": "d", "rationale": "A Heartburn is caused when stomach contents enter the distal end of the esophagus, producing a burning sensation. The client should avoid B | spicy food, eat smaller portions and more frequent meals. I ©", "whyNot": {"a": "Increased peristaltic action does not necessarily occur during pregnancy and is not the cause of heartburn in this case.", "b": "The increasing size of the baby may push some stomach acid upward, but it does not displace the stomach by the diaphragm.", "c": "Decreased secretion of hydrochloric acid would not contribute to increased symptoms of heartburn."}, "keyConcept": "Heartburn is a common gastrointestinal symptom that may occur in any trimester of pregnancy as a result of the effects of pregnancy hormones on the lower esophageal sphincter and gastric clearance, as well as the mechanical effect of the enlarging uterus pushing against the abdominal contents. Interventions used to relieve symptoms include diet and lifestyle modifications, antacids, antihistamines, and proton pump inhibitors."}, {"id": 10472, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a pregnant client who is having an initial prenatal visit at 30 weeks’ gestation. Which of the following vaccines are considered safe for administration in this client?", "choices": [{"id": "a", "t": "Tetanus, diphtheria, and pertussis"}, {"id": "b", "t": "Varicella"}, {"id": "c", "t": "Measles, mumps, and rubella"}, {"id": "d", "t": "Influenza nasal spray"}], "correct": "a", "rationale": "ce | 4% Pregnant women should not receive vaccines that contain live attenuated viruses, which are weakened viruses that theoretically can still © I 6% pose a danger through vaccination. Some viruses are associated with the development of severe birth defects if the mother is infected D Hl 21% during pregnancy. Live attenuated viral vaccines are contraindicated in pregnancy, and women who receive the vaccines should also be counseled to avoid pregnancy within 4 weeks of receiving these vaccines. They include the MMR and varicella vaccines, as well as LAIV (live attenuated influenza vaccine), which is administered as a nasal spray. Pregnant women can receive killed influenza vaccine by injection throughout pregnancy, which is recommended for all pregnant women. The immune system is suppressed during pregnancy, placing pregnant women at increased risk of illness and complications. Of the options listed, only Tdap is considered safe in pregnancy. It is recommended for all pregnant women from 27 to 36 weeks’ gestation in order to provide passive immunity against pertussis to the newborn. Pertussis is a respiratory infection caused by Bordetella pertussis and is commonly known as whooping cough. 2 = ® 4 z = a iat g <", "whyNot": {"b": "Varicella contains live virus and is contraindicated in pregnancy. It causes chicken pox and shingles, but the risk of contracting the virus is", "c": "MMR contains a live attenuated virus and is contraindicated.", "d": "Influenza vaccine by nasal spray (LAIV) is contraindicated, although injectable influenza vaccine is considered safe and is recommended"}, "keyConcept": "Live attenuated virus vaccines are contraindicated during pregnancy and within four weeks of pregnancy. They include nasal influenza vaccines, MMR, and varicella vaccine"}, {"id": 10473, "cat": "NCLEX 10-ante...neonatal care", "stem": "@O@ * Viral «<> ¢G o- =o x Sa Recc xX ™_ Inbo student.atitesting.com/LT| x ™_ Inbo x ] untii x Untii x (4 Goor x @ TEAS x Tutorial: BoardVitals NCLEX Prep RN a Poa ati Module: Quizzes & Assignments Dashboard Quiz ~ Performance ~ Onlir x G@ Mark x = @ Micr x Convert study guid« @ alli x @ New x [=| NCL! x | + v % CLOSE Qa * ws * © Cb Finish update : { Browse Questions ~ it Search Questions [a]", "choices": [{"id": "a", "t": "Heart rate"}, {"id": "b", "t": "Muscle tone"}, {"id": "c", "t": "Respiratory effort"}, {"id": "d", "t": "Presence of vernix caseosa"}], "correct": "d", "rationale": "Assessing for the presence of vernix caseosa is not included in calculating Apgar scores.", "whyNot": {"a": "Heart rate is assessed for obtaining Apgar scores, along with muscle tone, respiratory effort, reflex irritability and color.", "b": "An infant’s muscle tone is one of the assessments performed as part of obtaining the Apgar score.", "c": "The infant’s respiratory effort is one of the assessments performed as part of obtaining the Apgar score."}, "keyConcept": null}, {"id": 10474, "cat": "NCLEX 10-ante...neonatal care", "stem": "fundus is firm and contracted and there is a significant amount of bright red lochia. Which of the following is the most likely condition?", "choices": [{"id": "a", "t": "Subinvolution of the uterus"}, {"id": "b", "t": "Perineal laceration"}, {"id": "c", "t": "Retained placental fragments"}, {"id": "d", "t": "Puerperal infection"}], "correct": "b", "rationale": "S| 28% Hard A client who complains of pain or vaginal pressure and has a large amount of bright red lochia with a firm uterus most likely has a perineal es a 30% laceration. A client may develop a perineal laceration during delivery because of such factors as an extensive episiotomy, use of forceps during delivery, or a precipitous delivery. The nurse must assess the client’s perineum to determine if a laceration is present, continue to € [-— 32% D monitor the amount of lochia, and monitor the client’s vital signs for changes that indicate significant blood loss. 1%", "whyNot": {"a": "Subinvolution of the uterus occurs when the uterus does not return to its normal size after childbirth. The signs and symptoms that this", "c": "Retained placental fragments are often signified by a boggy uterus with increased bleeding. The symptoms this client are displaying do", "d": "Puerperal infection may cause foul-smelling drainage. The symptoms this client are displaying do not indicate a puerperal infection."}, "keyConcept": "Perineal lacerations or tears occur when the infant's head is either too large for the vagina to stretch around or the head is a normal size but the vagina doesn't stretch easily. The tears are described as 1st to 4th degree, depending upon the size and depth of the laceration. First- degree tears only involve the perineal skin — the skin between the vaginal opening and the rectum and the tissue directly beneath the skin. They frequently heal on their own. Fourth-degree tears extend through the anal sphincter and into the mucous membrane that lines the rectum. They usually require repair with anesthesia in an operating room."}, {"id": 10475, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is counseling the mother of a 12-month old child who is weaning the child from breastfeeding. Which of the following statements by the mother indicates a need for further teaching?", "choices": [{"id": "a", "t": "“Iwill discourage my child from drinking cow's milk because that will result in increased consumption of solids.”"}, {"id": "b", "t": "“I should never put my child to sleep with a bottle for comfort.”"}, {"id": "c", "t": "“I will begin weaning gradually and will still breastfeed at times.”"}, {"id": "d", "t": "“I should substitute some feedings with cow’s milk for breast milk.”"}], "correct": "a", "rationale": "The CDC recommends that cow's milk is not introduced until infants are 12 months old, but it is not known to result in increased consumption of solid foods. If too much cow's milk is consumed it may lead to decreased consumption of solid foods. Gradual weaning over a period of several weeks to several months helps mothers avoid breast engorgement, which can occur when breastfeeding is suddenly stopped. When weaning, the mother should watch for cues that indicate the infant is ready to advance. In most infants who are exclusively breastfed, weaning begins around the 6th month of life with the gradual introduction of pureed solid foods. Although solid foods are offered at this age, the mother should continue to offer breast milk and formula, which provides protein, fats, and calcium. A cup with a lid can usually be successfully used by children when they reach the age of a year.", "whyNot": {"b": "This statement indicates correct understanding of infant feeding. Allowing a child to sleep with a bottle can result in dental caries, ear", "c": "This statement indicates correct understanding, since gradual weaning reduces breast engorgement that occurs when breastfeeding is", "d": "This statement indicates correct understanding of weaning, which should be gradual. In addition to avoiding maternal discomfort, gradual"}, "keyConcept": "Weaning from breastmilk in exclusively breastfed infants occurs around 6 months of age and should be gradual, to avoid breast engorgement. Solid foods are offered at this time, in addition to breast milk and formula. Breast milk and formula are important sources of calcium, protein, and fats. Cow's milk can be introduced at 12 months, but excess consumption of cow's milk will lead to decreased appetite for solid food."}, {"id": 10476, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is planning to administer terbutaline to a client who is in premature labor. The nurse should closely monitor the client and notify the provider if the client experiences which of the following adverse effects?", "choices": [{"id": "a", "t": "Headaches O B.anxiety"}, {"id": "c", "t": "Tremors"}, {"id": "d", "t": "Dyspnea"}], "correct": "d", "rationale": "‘i The presence of dyspnea is a manifestation of pulmonary edema, which is a potentially life-threatening complication of terbutaline. This B I adverse effect should be reported to the provider immediately.", "whyNot": {"a": "Headaches are a common, non-life-threatening adverse effect related to terbutaline therapy.", "c": "Tremors, or shakiness, is a common, non-life-threatening adverse effect related to terbutaline therapy."}, "keyConcept": "Terbutaline is a beta-adrenergic agonist that is most often administered for tocolysis. The medication is administered subcutaneously while another medication with a slower onset of action is administered concurrently. Also, a subcutaneous injection of 0.25 mg can be given during labor augmentation or induction to suppress uterine tachysystole or to suppress contractions before cesarean birth."}, {"id": 10477, "cat": "NCLEX 10-ante...neonatal care", "stem": "true concerning immunity in a newborn?", "choices": [{"id": "a", "t": "Immunity will only occur with the transfer of immunoglobulins through breast milk."}, {"id": "b", "t": "Neonates have IgG antibodies from the mother and produce IgM in utero."}, {"id": "c", "t": "Neonates only have IgM antibodies from the mother."}, {"id": "d", "t": "Neonates have maternal IgA antibodies and produce IgM antibodies after 24-48 hours."}], "correct": "b", "rationale": "IgG antibody produced by the mother crosses the placenta to provide passive acquired immunity to certain bacterial pathogens. This occurs during the third trimester. The fetus also begins to produce IgM antibody by the end of the third trimester. At birth, these are the only antibodies the neonate has, but IgA is supplied through breastfeeding.", "whyNot": {"a": "Placental transfer of IgG occurs and the fetus also begins to produce IgM antibodies in the third trimester.", "c": "IgM is produced by the fetus. The fetus receives maternal IgG antibody in utero to certain pathogenic organisms.", "d": "Maternal IgA is not transferred through the placenta. A newborn has IgG and IgM. Breastfeeding supplies IgA through colostrum."}, "keyConcept": "At birth, the fetus has IgG antibody transferred across the placenta and IgM antibody produced by the fetus at the end of the third trimester. IgA is supplied to the neonate through breastmilk."}, {"id": 10478, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X ©@ New x x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions", "choices": [{"id": "a", "t": "Ask the mother to describe her interventions."}, {"id": "b", "t": "Determine the pattern of crying, including frequency and duration."}, {"id": "c", "t": "Ask the mother about her support system."}, {"id": "d", "t": "Tell the mother to try using a pacifier to soothe the crying child."}], "correct": "b", "rationale": "The priority nursing action is to obtain more information about the child's crying, as part of the assessment process. The nurse should © I determine the pattern of crying and obtain information about the quality of the infant’s cry in order to identify signs of potentially serious D | causes. The nurse should obtain information about volume, pitch, and tone; the length of any periods of silence; the onset of the crying that is troubling to the parent; and factors that exacerbate or relieve the infant's crying. Infants may cry up to 3 hours daily in the initial 3-4 months of life. It is a normal response to hunger, thirst, pain, or the need for company or. distraction. New parents are often unaware that a certain amount of crying is normal, and they may become concerned that their child is crying excessively.", "whyNot": {"a": "This is an important part of the nurse’s assessment, but the initial action should be to determine the pattern and quality of crying.", "c": "The priority action is assessment, which includes obtaining additional information about the child's crying. The nurse should ask about", "d": "A pacifier is helpful when soothing a crying infant, but the most important task is assessment of the infant's crying. This suggestion would"}, "keyConcept": "Infants may cry up to 3 hours a day in the first 3-4 months of life in normal response to hunger, thirst, pain, or a need for company or distraction. When evaluating a complaint by a parent that an infant is crying excessively, the nurse should obtain information about the pattern and quality of crying."}, {"id": 10479, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing teaching to a client who is initiating breastfeeding. Which of the following should the nurse relay to this client?", "choices": [{"id": "a", "t": "The breast should be dried before attempting feeding to facilitate latching."}, {"id": "b", "t": "The mother should always depress the breast tissue around the infant’s nose."}, {"id": "c", "t": "Itis preferable to offer only 1 breast each feeding."}, {"id": "d", "t": "The mother should awaken the baby at least every 3 hours during the day to feed."}], "correct": "d", "rationale": "Until the infant is feeding well and gains weight adequately, the mother should awaken the infant for feedings at least every 3 hours during the day and every 4 hours at night. At this point, the infant can be fed on demand. Neonates usually require 8 to 12 feedings every 24 hours, although the feeding pattern varies among infants, with some feeding every 2-3 hours and others feeding every hour or so for up to5 feedings, with a period of sleep for 3-4 hours between clusters of feedings.", "whyNot": {"a": "The mother can encourage feeding by expressing a small amount of colostrum or milk by hand and rubbing it on the nipple and areola.", "b": "The nurse should advise the mother that if the infant is unable to breathe, reflexes will cause the infant to move the head and pull back in", "c": "Itis preferable to feed from both breasts, spending approximately 15 to 20 minutes per breast, although some mothers nurse from only 1"}, "keyConcept": "Newborns should be awakened at least every three hours during the day and every 4 hours at night, until they are feeding well and gaining weight. Neonates require 8-12 feedings every 24 hours."}, {"id": 10480, "cat": "NCLEX 10-ante...neonatal care", "stem": "During routine prenatal testing, it is determined that a pregnant client is not immune to rubella. Which of the following considerations must the nurse consider when preparing to administer the rubella vaccine?", "choices": [{"id": "a", "t": "Educate the client that she will need at least two doses of the vaccine to provide rubella immunity"}, {"id": "b", "t": "Do not provide the vaccine to a pregnant client. The client cannot receive the vaccine until after childbirth"}, {"id": "c", "t": "Many clients develop fever, swelling at the site of injection, and bleeding into the joints after rubella vaccine administration"}, {"id": "d", "t": "The client must wait at least six months after receiving the vaccine before becoming pregnant again"}], "correct": "b", "rationale": "all 7% Easy Routine testing for rubella immunity during pregnancy may determine that a pregnant client is not immune to rubella and that the vaccine is es TC 82% necessary to avoid potential birth defects in future pregnancies. Although the client needs the vaccine for protection, it should not be given during pregnancy. The rubella vaccine is often administered the first postpartum day while the client is still in the hospital. € I Sh of 8%", "whyNot": {"a": "Only one dose of the rubella vaccine is necessary to provide immunity. The client will not need at least two doses.", "c": "Some clients may develop pain or redness at the injection site with a rubella vaccine. Bleeding into the joints after the injection is not a", "d": "A client who receives the rubella vaccine after giving birth can safely become pregnant again and does not need to wait six months."}, "keyConcept": "Rubella can be prevented with the MMR vaccine, which protects against three diseases: measles, mumps, and rubella. Children should receive two doses of the MMR vaccine, starting with the first dose at 12 through 15 months of age, and the second dose at 4 through 6 years. of age. MMR vaccine is very safe and effective. One dose of the MMR vaccine is about 97% effective at preventing rubella. The Advisory Committee on Immunization Practices (ACIP) recommends that healthy adults who do not have evidence of immunity to measles, mumps, and rubella should get vaccinated against these diseases. Women of childbearing age, especially those who grew in areas where routine rubella vaccination might not occur, should be vaccinated with 1 dose of MMR vaccine or have serologic evidence of rubella immunity, but the vaccine is a live attenuated virus vaccine and is contraindicated in pregnant women. 2 = ® 4 z = a iat g <"}, {"id": 10481, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is comforting a client whose infant has died after delivery at 25 weeks' gestation. Which of the following statements from the nurse is most appropriate?", "choices": [{"id": "a", "t": "“This is probably for the best, because his organs were so immature.”"}, {"id": "b", "t": "“You should try to get pregnant again soon to get over this loss.”"}, {"id": "c", "t": "“You can stay with your baby for as long as you want and say anything you want.”"}, {"id": "d", "t": "“If you want me to, can call the chaplain to stay with you.”"}], "correct": "c", "rationale": "a| 1% Easy When a neonate dies, the mother should be allowed to stay as long as she wants and say whatever she wants to say. She is grieving and . A photograph needs to be taken in case the mother wants a picture at a later time. This applies to the father, as well. The other options are not appropriate, although the hospital chaplain may be called, if the mother requests. O€ PC 51% of 7%", "whyNot": {"a": "This statement would not particularly helpful; the mother knows the infant was immature and she would probably not be comforted by", "b": "This is inappropriate and an insensitive thing to say; it should be avoided.", "d": "While calling the chaplain would be appropriate, the nurse should stay with the client."}, "keyConcept": "Compassion is the ability of the nurse to be with a client who is suffering. A person who is mourning must first learn to accept the reality of the loss and to process the pain of grief while caring for the self. The bereaved must adjust to life without the deceased while finding a lasting 2 = 5 a & = a fa a connection with the deceased. <"}, {"id": 10482, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X ©@ New x % CLOSE { Browse Questions ~ it Search Questions", "choices": [{"id": "a", "t": "Place the client lying in the left lateral recumbent position and recheck blood pressure in 5 minutes in the left arm"}, {"id": "b", "t": "Place the client in the left lateral recumbent position and recheck blood pressure in the right arm in 5 minutes."}, {"id": "c", "t": "Ask the client to stand and recheck blood pressure while standing"}, {"id": "d", "t": "Take the client’s blood pressure in the opposite arm in the same position"}], "correct": "a", "rationale": "During pregnancy, maternal positioning can affect blood pressure. Blood pressure usually decreases in the first and second trimester as the circulation expands and as hormonal changes result in dilation of blood vessels. It usually recovers to pre-pregnancy levels in the third trimester. The client should be placed in a left lateral recumbent position to reduce pressure on her blood vessels (vena cava syndrome), which improves venous return to the heart. The blood pressure should be rechecked in 5 minutes. The blood pressure should be checked in the left arm, as checking it in the right arm may result in a falsely lower blood pressure measurement, since that arm is now positioned above the heart. Placing the client in the supine position is likely to compress maternal blood vessels.", "whyNot": {"b": "This may result in a falsely low measurement. The blood pressure should be checked in the left arm when the client is in the left lateral", "c": "In pregnancy, the blood pressure may rise with standing, as pressure on the vena cava is relieved.", "d": "The client should be moved from the supine position since it can cause occlusion of maternal blood vessels, resulting in hypotension."}, "keyConcept": "After 20 weeks' gestation, the size of the gravid uterus can compress the inferior vena cava, decreasing the return of blood into the heart (preload.) clients in a supine position or prolonged standing during pregnancy can experience symptoms of hypotension.The left lateral recumbent position reduces pressure on maternal blood vessels."}, {"id": 10483, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja) A nurse is caring for a client who is suspected to have an ectopic pregnancy. Which of the following findings should the nurse identify as a manifestation of ectopic pregnancy?", "choices": [{"id": "a", "t": "No alteration in menses"}, {"id": "b", "t": "Shoulder pain"}, {"id": "c", "t": "Progesterone level higher than the expected reference range"}, {"id": "d", "t": "Report of severe leg cramps"}], "correct": "b", "rationale": "An ectopic pregnancy can result in the rupture of a fallopian tube, which causes bleeding into the peritoneal cavity. The resulting collection of blood can irritate the diaphragm and cause referred shoulder pain.", "whyNot": {"a": "A client who is experiencing an ectopic pregnancy will report a delay in their menstrual cycle.", "c": "A progesterone level that is lower than the expected reference range is an indication of ectopic pregnancy. During a typical developing", "d": "A client's report of severe leg cramps is a finding associated with thrombophlebitis during pregnancy."}, "keyConcept": "An ectopic pregnancy is a pregnancy that is implanted outside of the uterus, typically in one of the fallopian tubes. Manifestations of ectopic pregnancy usually present at 5 to 8 weeks of gestation and include abdominal pain, tenderness, and progesterone levels below the expected range. An ectopic pregnancy is considered an emergency and manifestations should be reported to the provider promptly. If left untreated, the fallopian tube can rupture, resulting in intra-abdominal hemorrhaging and decreased fertility."}, {"id": 10484, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a G1PO female client who is at 37 weeks’ gestation. The healthcare provider should be called immediately for which of the following findings during the assessment?", "choices": [{"id": "a", "t": "Low back pain"}, {"id": "b", "t": "Blood pressure 130/80 mmHg."}, {"id": "c", "t": "Severe headache with blurred vision"}, {"id": "d", "t": "Weight gain of 2 lbs since the last visit 5 days earlier"}], "correct": "c", "rationale": "Preeclampsia is a leading cause of maternal morbidity and mortality. It is characterized by onset of hypertension (blood pressure >140 mm Hg systolic or >90 mm Hg diastolic) after the 20th week of gestation in a woman with previously normal blood pressure, accompanied by proteinuria or new onset of one of the following: low platelet count, renal insufficiency, liver dysfunction, pulmonary edema, or neurological symptoms. Urine protein is 0.3 g or more in a 24-hour urine specimen or a 1+ dipstick reading for protein. Preeclampsia can lead to stroke, acute renal failure, pulmonary edema, DIC, and fetal or maternal death. It may progress to eclampsia, which is characterized by seizures. Risk factors include a prior history of preeclampsia, pregestational diabetes mellitus,advanced maternal age, multifetal gestation, obesity, chronic kidney disease, and lupus. Platelets, urine and serum protein, serum creatinine, weight, and blood pressure should be monitored carefully in the last trimester of pregnancy in women at high risk of preeclampsia. The only option for reversal of preeclampsia is delivery, but in clients who are at 36 weeks’ gestation or less, pharmacologic treatment may include antihypertensive medication and magnesium sulfate for seizure prophylaxis. Nursing interventions include accurate blood pressure measurement, dietary guidance to target a healthy body weight; providing client education about warning signs of preeclampsia; and monitoring weight gain that may indicate fluid imbalance and edema.", "whyNot": {"a": "Pain should be addressed, but it is not necessary to call the healthcare provider immediately. Many pregnant women experience back pain", "b": "Blood pressures of 140 mmHg systolic and 90 mmHg diastolic or greater are consistent with preeclampsia. However, this blood pressure is", "d": "Rapid weight gain should prompt concern, but normal weight gain in women in the third trimester is a pound per week. The client should"}, "keyConcept": "Preeclampsia refers to new onset of hypertension after 20 weeks' gestation, accompanied by proteinuria, thrombocytopenia, liver dysfunction, neurologic symptoms, or pulmonary edema. The nurse should educate the client about warning signs of preeclampsia, including headache, sudden weight gain, swelling, visual changes, and right upper quadrant abdominal pain. Preeclampsia can only be reversed by delivery of the fetus and placenta."}, {"id": 10485, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X % CLOSE { Browse Questions ~ it Search Questions [a] Qa * @ New x {- NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "The client is having regular contractions and the cervix is dilated to 10 cm"}, {"id": "b", "t": "The fetus has completely descended into the pelvic cavity"}, {"id": "c", "t": "The client is pushing to deliver the baby; it is also called the “transition stage”"}, {"id": "d", "t": "The baby has been delivered and the mother is now delivering the placenta"}], "correct": "d", "rationale": "The third stage of labor occurs after the baby has been delivered and the mother is delivering the placenta. The mother continues to experience contractions, which are designed to push the placenta out. The third stage typically lasts between 5 and 10 minutes.", "whyNot": {"a": "The third stage of labor describes the delivery of the placenta. The client will already have a fully dilated cervix because she has already", "b": "The third stage of labor occurs after the baby has been born; it describes the delivery of the placenta, not the descent of the baby into the", "c": "The third stage of labor occurs when the mother delivers the placenta. The client will already have delivered the baby by this time."}, "keyConcept": "There are three stages of childbirth. The first stage begins from the onset of true labor and lasts until the cervix is completely dilated to 10 cm. The second stage continues after the cervix is dilated to 10 cm until the delivery of the baby. The third stage is the delivery of the placenta. The third stage is the shortest stage."}, {"id": 10486, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following responses would the nurse expect to see from a client who is in the latent phase of labor?", "choices": [{"id": "a", "t": "Contractions every 5 to 10 minutes"}, {"id": "b", "t": "Contractions lasting 1 to 2 minutes"}, {"id": "c", "t": "Cervical dilation of 6 to 7 cm"}, {"id": "d", "t": "Cervical effacement of 80 percent"}], "correct": "a", "rationale": "The latent phase occurs during the first stage of labor when a woman’s body is beginning to change for childbirth. During the latent stage, the nurse can expect to see contractions that are still several minutes apart and that last for 30 to 40 seconds. Cervical dilation is between 0 and 3 cm during the latent phase and effacement ranges from 0 to 40 percent.", "whyNot": {"b": "During the latent phase of labor, contractions tend to last for only 30 to 40 seconds.", "c": "The latent phase of labor is an early phase. The nurse would expect to see cervical dilation between 0 and 3 cm.", "d": "The latent phase of labor is an early phase. The nurse would expect to see effacement between 0 and 40 percent."}, "keyConcept": "Labor begins when the mother feels regular contractions, which result in cervical dilation and effacement. Effacement refers to softening and thinning of the cervix, which allows the baby to enter the birth canal. The stages of labor include early or latent labor, which lasts until the cervix has dilated to 3 cm; the active phase, which lasts from the time the cervix is dilated 3 cm until the cervix has dilated to 7 cm; and the transition phase, which lasts from cervical dilation of 7 cm until the cervix has dilated to 10 cm. The first stage of labor is the longest stage, with an unpredictable length ranging from hours to days."}, {"id": 10487, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing preconception teaching to a client who has phenylketonuria (PKU). Which of the following statements by the client indicates an understanding of the teaching? O A.\"I should avoid getting pregnant because of this disorder.\" O B. \"I will need my PKU levels checked once a year when I'm pregnant.\" O C.\"I should avoid foods high in protein for at least 3 months prior to pregnancy.\" O D. \"I will need to deliver my baby by cesarean section because of this disorder.\"", "choices": [{"id": "a", "t": "There is no restriction on pregnancy for a client who has PKU. However, a client who has PKU will need counseling prior to conception and"}, {"id": "b", "t": "A client who has PKU will need to have her phenylalanine levels monitored one to two times per week throughout pregnancy."}, {"id": "c", "t": "A client who has PKU should decrease her dietary intake of protein for at least 3 months prior to conception."}, {"id": "d", "t": "A client who has PKU is not at increased risk for fetal macrosomia and will not require a cesarean birth."}], "correct": "c", "rationale": "A client who has PKU should decrease her dietary intake of protein for at least 3 months prior to conception. The client should be instructed to avoid meat and beans and to eat more fruits and vegetables. This will decrease the likelihood that the fetus will be exposed to high levels of PKU and will help to prevent neurocognitive impairments.", "whyNot": {"a": "There is no restriction on pregnancy for a client who has PKU. However, a client who has PKU will need counseling prior to conception and", "b": "A client who has PKU will need to have her phenylalanine levels monitored one to two times per week throughout pregnancy.", "d": "A client who has PKU is not at increased risk for fetal macrosomia and will not require a cesarean birth."}, "keyConcept": "Phenylalanine is an amino acid that is converted into tyrosine once ingested. With phenylketonuria (PKU), the body is unable to form this conversion; thus, phenylalanine accumulates in the bloodstream and can attack the brain cells. PKU is an inherited disorder that can cause cognitive and neurological impairments. Treatment includes placing the client on a low-phenylalanine diet, which includes eating fruits and vegetables and avoiding high-protein foods like meat and beans. A client who has PKU and desires pregnancy should consult with her provider. The client should be instructed to consume a low-phenylalanine diet for 3 months prior to conception and during pregnancy to prevent exposing the fetus to high phenylalanine levels, which can cause cognitive and neurological impairments."}, {"id": 10488, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X ©@ New x x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions An early sign of pregnancy is a bluish discoloration of the cervix from venous congestion. It can be observed as early as 8-10 weeks from the time of conception. It is known as:", "choices": [{"id": "a", "t": "Chadwick’s sign"}, {"id": "b", "t": "Chadway’s sign"}, {"id": "c", "t": "Hegar’s sign"}, {"id": "d", "t": "Goodell’s sign"}], "correct": "a", "rationale": "o; Chadwick's sign is the early sign of pregnancy which is caused by venous congestion in the cervix, causing it to become bluish in color. B I", "whyNot": {"b": "Chadway’s sign is not the name of a condition or diagnosis in medicine and this description does not apply. D i", "c": "Hegar’s sign occurs when the lower portion of the uterus softens. It is not associated with discoloration of the cervix or Chadwick's sign.", "d": "Goodell’s sign occurs with softening of the cervix. It is not the same as Chadwick's sign, which is the bluish discoloration of the cervix at 8"}, "keyConcept": "Diagnosis of pregnancy is made with history and physical examination, laboratory evaluation, and ultrasonography. The classic signs of pregnancy are missed menstrual cycle in a woman with menses of regular frequency, in association with nausea, vomiting, generalized malaise, and breast tenderness. On physical examination, signs include an enlarged uterus on bimanual examination, breast changes, and softening and enlargement of the cervix (Hegar sign; approximately 6 wk). Chadwick's sign is a bluish discoloration of the cervix from venous congestion and can be observed by 8-10 weeks. Signs of Early Pregnancy"}, {"id": 10489, "cat": "NCLEX 10-ante...neonatal care", "stem": "following? O A. Metabolism of brown adipose tissue O B. Increased shunting of blood to the skin surface O C. Decreased utilization of glycogen stores O D. Decreased shivering to keep warm", "choices": [{"id": "a", "t": "Metabolism of brown adipose tissue"}, {"id": "b", "t": "Increased shunting of blood to the skin surface"}, {"id": "c", "t": "Decreased utilization of glycogen stores"}, {"id": "d", "t": "Decreased shivering to keep warm"}], "correct": "a", "rationale": "Infants burn brown fat as a response to cold stress and there is increased utilization of glycogen and calorie stores. Hypoglycemia may occur c ] 14% from stress as a result of a cold environment. om 13%", "whyNot": {"b": "Increased shunting of blood to the skin surface", "c": "The infant would utilize more glycogen stores in response to cold stress from the environment.", "d": "Newborn infants do not have the capacity to shiver. This is not a response to cold stress in the neonate."}, "keyConcept": "Itis important to maintain constant body temperature in neonates. Hypothermia and hyperthermia are associated with increased morbidity and mortality. Non-shivering thermogenesis is the main source of heat production in the neonate. It refers to the production of heat by the metabolism of brown fat, which is deposited after 28 weeks gestation around the scapulae, kidneys, adrenals, neck, and axilla. The neonate’s response to a cold environment is constriction of superficial blood vessels to maintain heat in the core and prevent transmission of heat to the periphery. Superficial vasoconstriction results in a mottled appearance of the skin. If the neonate is not warmed then cold stress can occur, resulting in increased metabolic rate, leading to increased oxygen consumption; increased caloric consumption and decreased glycogen stores which can lead to hypoglycemia; development of acidosis due to pulmonary vasoconstriction; and thermal shock and disseminated intravascular coagulation, progressing to death 2 = ® 4 z = a iat g <"}, {"id": 10490, "cat": "NCLEX 10-ante...neonatal care", "stem": "finding most likely represent? O A. Thrombophlebitis O B. Varicose veins O C. Buerger’s disease O D. Compartment syndrome", "choices": [{"id": "a", "t": "Thrombophlebitis"}, {"id": "b", "t": "Varicose veins"}, {"id": "c", "t": "Buerger’s disease"}, {"id": "d", "t": "Compartment syndrome"}], "correct": "a", "rationale": "Postpartum deep vein thrombosis (DVT) and superficial thrombophlebitis in the postpartum period may occur as a result of trauma to the pelvic veins from pressure exerted by the presenting fetal part. Other pregnancy related changes that increase the risk of thrombophlebitis or DVT include impaired circulation and hypercoagulability related to the increased production of estrogens during pregnancy. Thrombosis. that involves only the superficial veins of the leg or thigh is unlikely to result in pulmonary emboli 2 = ® 4 z = a iat g <", "whyNot": {"b": "Varicose veins are manifested by swollen veins visible under the skin.", "c": "In Buerger’s disease cold and clammy skin can be seen.", "d": "Compartment syndrome manifests as pain and swelling."}, "keyConcept": "Postpartum deep vein thrombosis (DVT) and superficial thrombophlebitis in the postpartum period may occur as a result of trauma to the pelvic veins from pressure exerted by the presenting fetal part. Other pregnancy related changes that increase the risk of thrombophlebitis or DVT include impaired circulation and hypercoagulability related to the increased production of estrogens during pregnancy. Thrombosis. that involves only the superficial veins of the leg or thigh is unlikely to result in pulmonary emboli 2 = ® 4 z = a iat g <"}, {"id": 10491, "cat": "NCLEX 10-ante...neonatal care", "stem": "When developing the teaching plan for a primiparous client who is bottle feeding her term neonate for the first feeding, which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Keep the nipple of the bottle full of formula while feeding"}, {"id": "b", "t": "term babies have well-developed sucking skills"}, {"id": "c", "t": "Burp the baby after 6 oz. of formula have been taken"}, {"id": "d", "t": "Propping of the bottle may make it easier to feed the baby"}], "correct": "a", "rationale": "Formula should fill the entire nipple of the bottle while the baby is sucking. This decreases the amount of air taken in by the baby prevents : Not all babies at term are born with well-developed sucking skills. cm 18%", "whyNot": {"b": "Not all babies who are born full-term have well-developed sucking skills.", "c": "A baby who is eating formula should be burped after eating 2 to 3 oz. at a time or more often if the baby stops eating in between or", "d": "The nurse should tell the parent to never prop a bottle. It will not cause the baby to get too much air but it can cause the baby to choke. It"}, "keyConcept": "The American Academy of Pediatrics recommends exclusively breastfeeding for the first six months of life. All women are not able to breastfeed and breastfeeding is contraindicated in some cases, including mothers with HIV or active tuberculosis. The energy requirement for infants in the first three months is 110 kcal/kg/day. Breast milk provides 67 kcal/100 ml. 2 = ® 4 z = a iat g < Most children receive formula at some point during the first year of life. Formula simulates the caloric content of breast milk. The type of formula is generally specified by the pediatrician. Most newborns should be fed every 3 to 4 hours. If the infant demonstrates adequate weight gain, he/she can be allowed to sleep through the night, but initially, most infants should be woken up for feedings during the night. Most infants require 6-8 feedings per 24 hours. Newborns usually drink 15-30 mL of formula at each feeding in the first day of life, with a gradual increase over the first week."}, {"id": 10492, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is preparing to set up continuous internal fetal monitoring for a high-risk pregnant client who is in labor. Which of the following must be present before the nurse initiates internal fetal monitoring?", "choices": [{"id": "a", "t": "Membranes that have not ruptured yet"}, {"id": "b", "t": "Cervical dilation of at least 2 cm"}, {"id": "c", "t": "Evidence of at least three periods of fetal heart rate decelerations"}, {"id": "d", "t": "Epidural anesthesia to control discomfort"}], "correct": "b", "rationale": "Continuous internal fetal monitoring is a useful tool for consistently assessing fetal heart rate during labor for high-risk clients. When setting up an internal fetal monitoring system, a probe that measures the heart rate is inserted into the baby’s presenting part, which is usually the scalp if it is a cephalic presentation. The mother must have a cervical dilation of at least 2 cm before the probe can be internally placed.", "whyNot": {"a": "The membranes should be ruptured before the nurse places the internal monitoring system. This type of fetal monitor is placed internally", "c": "Fetal heart decelerations are a dangerous sign for the fetus. The client does not need to show that she is having fetal decelerations before", "d": "While a client may have an epidural to provide comfort during labor, it is not necessary to have an epidural before an internal fetal monitor"}, "keyConcept": "Fetal heart rate monitoring during labor demonstrates changes in fetal heart rate patterns in response to contractions. Auscultation, internal monitoring, or external fetal monitoring can be utilized. Auscultation can be performed using a Doppler transducer. External monitoring is performed by wrapping a pair of belts around the mother's abdomen. One belt uses Doppler to detect the fetal heart rate while the other belt measures the length and timing of contractions. Internal monitoring is performed using an electrode that is placed on the presenting part of the fetus, usually the scalp, to record the fetal heart rate. Uterine contractions may be monitored using an intrauterine pressure catheter inserted through the vagina. Internal monitoring can be used only after the membranes have ruptured."}, {"id": 10493, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is planning care for a newborn who requires phototherapy. Which of the following interventions should the nurse include in the plan of care?", "choices": [{"id": "a", "t": "Position the newborn supine throughout therapy."}, {"id": "b", "t": "Apply lotion to the newborn's skin twice per day."}, {"id": "c", "t": "Check the newborn's temperature every 8 hr."}, {"id": "d", "t": "Remove the newborn's eye mask during feedings."}], "correct": "d", "rationale": "A newborn undergoing phototherapy should be placed under the light with only a diaper and eye mask on to ensure that all areas of the skin are exposed to the light. The eye mask is used to prevent exposure of the eyes to UV light during phototherapy. However, the eye mask should be removed for each feeding to allow for stimulation of the optic nerve, bonding with the newborn, and assessment of the newborn's eyes.", "whyNot": {"a": "A newborn undergoing phototherapy should be repositioned every 2 hr. This is to ensure that all skin areas are exposed to light therapy.", "b": "A newborn undergoing phototherapy should not have lotion applied to his skin because this can cause burns and increase tanning of the", "c": "A newborn undergoing phototherapy should have his temperature monitored every 4 hr due to the risk associated with hypothermia or"}, "keyConcept": "Phototherapy is used to treat infants who have hyperbilirubinemia. Fluorescent light with carious spectrums is used to facilitate the excretion of bilirubin. The light breaks down the bilirubin to a soluble form to leave the body through urine and feces. During phototherapy, the newborn should be monitored closely. Some of the nursing interventions for phototherapy include: * Assess the skin frequently for skin breakdown. © Reposition the newborn every 2 hr to ensure all areas of the skin are exposed to light therapy. © Place the newborn under light therapy with only a diaper to expose the entire body to light therapy. © Place an eye mask over the newborn's eyes to prevent exposure to the UV light of phototherapy. © Remove the eye mask during feeding time to assess the eyes and promote stimulation. © Avoid using lotion on the newborn's skin because this can cause burns and increased tanning of the skin. * Monitor temperature every 4 hr because hypothermia or hyperthermia can occur while receiving therapy. © Document intake and output to ensure that phototherapy is effective. * Ensure phototherapy is set up correctly to prevent complications from occurring."}, {"id": 10494, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is assessing a client who is in labor and received an epidural anesthesia block for pain relief. Which of the following manifestations should the nurse identify as an adverse effect of the epidural block?", "choices": [{"id": "a", "t": "Vomiting"}, {"id": "b", "t": "Tachycardia"}, {"id": "c", "t": "Flank pain"}, {"id": "d", "t": "Hypotension"}], "correct": "d", "rationale": "A The nurse should identify hypotension as an adverse effect of epidural anesthesia. To minimize the likelihood of hypotension, the nurse B } should administer an IV fluid bolus prior to the placement of the epidural catheter.", "whyNot": {"a": "Vomiting is not an adverse effect of epidural anesthesia. It is an adverse effect of opioids and opioid agonist analgesics, both of which can", "b": "Tachycardia is not an adverse effect of epidural anesthesia. It is an adverse effect of opioid agonist-antagonist analgesics, such as", "c": "Flank pain is not an adverse effect of epidural anesthesia. It is an adverse effect of magnesium sulfate, which is used for premature labor,"}, "keyConcept": "Nursing Interventions for maternal hypotension + Increase IV infusion rate. + Administer oxygen by nonrebreather mask at 10 L/min. + Elevate the client's legs. + Place client in a lateral position. + Monitor BP and FHR every 5 min. + Remain with the client until condition improves."}, {"id": 10495, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ *% Viral x sx Recc xX M Inbo X M Inbo x ] Unt x Untii x 4 Goor x @ TEAS x Onlir x && Mark x @ Micr x @ Ali x @New x | NCL x + v < > CG student.atitesting.com/LTI Qa * sw * © © | Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Rooting reflex"}, {"id": "b", "t": "Sucking reflex"}, {"id": "c", "t": "Babinski reflex"}, {"id": "d", "t": "Swallowing reflex"}], "correct": "a", "rationale": "The infant is demonstrating the rooting reflex, which occurs when the area around the mouth is stimulated and the infant turns her head in . This is a normal reflex present at birth that helps the infant to look for the breast or bottle to start feeding. I © 4%", "whyNot": {"b": "The sucking reflex is described as the infant making sucking motions when the area around the mouth is stimulated; the description given", "c": "The Babinski reflex is associated with the plantar surface of the feet, not with the mouth.", "d": "The swallowing reflex refers to the act of swallowing when liquid or food enters the mouth."}, "keyConcept": "Newborn reflexes are tested as part of the assessment of brain and nerve activity. The root reflex begins when the corner of the baby's mouth is stroked or touched. The newborn will turn his or her head and open his or her mouth to \"root\" in the direction of stroking. Rooting helps the infant become ready to suck. When the roof of the baby's mouth is touched, the baby will begin to suck. The suck reflex s not fully developed until about 36 weeks. The Moro reflex is known as the startle reflex because it usually occurs when a baby is startled by a loud sound or movement and throws back his or her head, extends out the arms and legs, cries, then pulls the arms and legs back in. Other 2 = ® 4 z = a iat g < normal newborn reflexes include the tonic neck reflex, step reflex, grasp reflex. and Babinski reflex."}, {"id": 10496, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a newborn who has necrotizing enterocolitis (NEC). Which of the following findings should the nurse recognize as a risk factor for this condition?", "choices": [{"id": "a", "t": "Macrosomia"}, {"id": "b", "t": "Transient tachypnea of the newborn (TTN)"}, {"id": "c", "t": "Maternal gestational hypertension"}, {"id": "d", "t": "Gestational age of 35 weeks"}], "correct": "d", "rationale": "The cause of NEC is unknown, but infants who were born prematurely are at the greatest risk. Gestational age of 35 weeks, or preterm birth, B Hl places a newborn at risk for NEC. This could be due to the lack of oxygen during delivery and a weakened immune system.", "whyNot": {"a": "Macrosomia, an infant who weighs more than 3.6 kg (8 lb) at birth, does not place a newborn at risk for NEC. Low birth weight or preterm", "b": "TTN does not place a newborn at risk for NEC. Preterm birth is a risk factor for NEC.", "c": "Maternal gestational hypertension does not place a newborn at risk for NEC. Preterm birth is a risk factor for NEC."}, "keyConcept": "Necrotizing enterocolitis (NEC) is a disease that develops in infancy and affects the intestines. The inner mucosal lining of the intestines becomes inflamed and causes decreased blood supply to the bowel, necrosis, and eventually death to the infected portion of the bowel. The cause of this condition is unknown but could be due to a lack of oxygen during birth. The greatest risk factor for this condition is preterm labor or birth. Preterm infants can have a weak immune system, hypoxia, and other complications that could predispose them to this condition. Manifestations are associated with inflamed and infected bowels, and the child can exhibit abdominal swelling, vomiting, poor feeding, diarrhea, and bloody stools. Treatment for NEC depends on the severity. The nurse should keep the child NPO, give IV fluids for hydration, and administer enteral feedings via nasogastric tube or parental nutrition if needed. Surgery could be warranted to remove the infected portion of the intestines."}, {"id": 10497, "cat": "NCLEX 10-ante...neonatal care", "stem": "Into which of the following positions should the nurse assist a client to facilitate progress in labor when the fetus is in the occiput posterior position?", "choices": [{"id": "a", "t": "Lithotomy"}, {"id": "b", "t": "Supine with a towel roll under the right hip"}, {"id": "c", "t": "Hands and knees"}, {"id": "d", "t": "Knee to chest"}], "correct": "c", "rationale": "S| 17% Hard The occiput posterior position refers to the position of the baby with head down and back to the side. This is the most common type of B I % malposition of the occiput during labor. The nurse should assist the client to a position on the hands and knees to facilitate rotation of the fetus from the posterior to the anterior position. O€ | 52% om 23%", "whyNot": {"a": "The lithotomy position is characterized by the client lying on the back with the knees elevated. It does not facilitate progression of labor.", "b": "This position can relieve compression on the vena cava but is not useful for rotating a malpositioned fetus.", "d": "The knee-to-chest position is useful to relieve cord compression when the umbilical cord is prolapsed."}, "keyConcept": "The occiput posterior position occurs as a result of failure of internal rotation before delivery, causing the occiput to lie in the posterior portion of the pelvis, instead of the anterior pelvis, with the vertex presenting. This causes the head to be deflexed. In most cases, the occiput rotates anteriorly when the occiput meets the pelvic floor, allowing normal delivery. Assisting the client to a position on the hands and knees may facilitate rotation to the anterior position. 2 = ® 4 z = a iat g <"}, {"id": 10498, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja) A nurse is planning an initial visit to a client's home after delivery of a term neonate. Which of the following is the best time for a visiting nurse to schedule the initial home care visit following the delivery of a newborn?", "choices": [{"id": "a", "t": "When the mother is feeding the infant"}, {"id": "b", "t": "When the father is not at home"}, {"id": "c", "t": "When it is convenient for the family"}, {"id": "d", "t": "When the nurse has extra time to spend visiting with the family"}], "correct": "c", "rationale": "Productive relationships are formed when the nurse is willing to cooperate with the family’s schedule.", "whyNot": {"a": "The mother may be distracted when feeding the infant and the visit will not be as productive.", "b": "The father should be included in the visit if possible.", "d": "This may not be at a time when it is convenient for the family and may impede learning."}, "keyConcept": "The home health nurse must balance scheduling difficulties with meeting the client's need for health care. Perinatal care comprises a continuum of care. Since new mothers are usually healthy, home health care focuses on primary and secondary prevention of health problems for mother and child."}, {"id": 10499, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a pregnant client whose last menstrual period was on February 11. By July 18, a physical assessment of the client should indicate that the top of the fundus is at which of the following locations?", "choices": [{"id": "a", "t": "Even with the umbilicus"}, {"id": "b", "t": "Just above the symphysis pubis"}, {"id": "c", "t": "Two finger-breadths above the umbilicus"}, {"id": "d", "t": "Halfway between the symphysis and umbilicus"}], "correct": "a", "rationale": "oo i! 50% Hard At about the 22nd week of gestation, the top of the fundus is at the level of the umbilicus. ce | 8% cm 23% B. This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be much D Hl 20% higher than the symphysis pubis.", "whyNot": {"c": "At this point, the top of the fundus would be at about the umbilicus, not two finger-breadths above.", "d": "This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be at about"}, "keyConcept": "Fundal height is defined as the distance from the pubic bone to the top of the uterus measured in centimeters. After 20 weeks of pregnancy, the fundal height measurement matches the number of weeks gestation, +/- 2 weeks. The fundal height measurement is not as accurate in women who are obese, carrying multiples, or with a history of fibroid tumors. 2 (S g o 5 x < Asmaller or larger fundal height than expected or a fundal height that increases more or less quickly than expected could be due to intrauterine growth restriction, fetal macrosomia (large baby), oligohydramnios (reduced amniotic fluid), or polyhydramnios (increase in amniotic fluid.) — 36 wk — wuwk nm 32 wk | l —_ ip — 1¢ 9k a 3 \\S — Jowk \\S \\e = —— 12 wk Poe bone \\s"}, {"id": 10500, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x € OS @G 23 student.atitesting.com/LT| Convert study guid« @ alli x @ New x [=| NCL! x | + v Qa * ws * © Cb Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Bright red blood from the incision"}, {"id": "b", "t": "Petechiae under the blood pressure cuff"}, {"id": "c", "t": "Temperature of 101 degrees Fahrenheit"}, {"id": "d", "t": "Platelet count of 75,000/mm3"}], "correct": "c", "rationale": "A A client with DIC will have signs of excessive bleeding or bruising. The client will typically have a normal temperature. B -", "whyNot": {"a": "The nurse might expect to see bright red bleeding from the incision after the wound is closed. D i", "b": "The client might develop petechiae under the blood pressure cuff or under compression stockings, caused by rupture of capillary blood", "d": "Typically, the platelet count will be decreased (less then 150,000/ mm3) and the PTT will be increased."}, "keyConcept": "DIC is caused by abnormal activation of the clotting cascade in infection, childbirth, and surgical procedures. Although DIC is typically associated with bleeding, it is a disorder in which hemorrhage and thrombosis occur at the same time. Hypercoagulation causes diffuse thrombosis in small and large vessels, leading to depletion of clotting factors, fibrinogen, and platelets. This results in hemorrhage. Prompt recognition and treatment are necessary to reduce morbidity and mortality associated with DIC. The underlying cause of DIC must be identified and treated. Supportive measures include fluid replacement and administration of blood components. The nurse should monitor the client for signs of bleeding, which range from oozing to frank hemorrhage. Bleeding is the primary clinical manifestation and may cause anxiety in the client and family members. The nurse should provide care in a reassuring manner to reduce anxiety."}, {"id": 10501, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a term neonate born to a mother who used oxycodone daily during pregnancy. Which of the following is indicated in infants with neonatal abstinence syndrome?", "choices": [{"id": "a", "t": "Positioning of the newborn in the supine position after a feeding"}, {"id": "b", "t": "Placement of the newborn near the nurses’ station"}, {"id": "c", "t": "Stimulating the newborn regularly by playing music"}, {"id": "d", "t": "Swaddling the newborn and placing in a side-lying position for feeding"}], "correct": "d", "rationale": ". The syndrome occurs when a newborn born to a mother with opioid dependence © I 6% experiences withdrawal within 24-48 hours after birth. The newborn may be irritable with poor feeding. Other characteristics include a high- @pD | 60% pitched cry, diarrhea, and vomiting. Autonomic nervous system manifestations of opioid withdrawal in neonates can include diaphoresis (sweating), dilated pupils, and sneezing. During neonatal withdrawal, the newborn may be hypersensitive to stimuli, making feeding difficult. An appropriate nursing intervention is swaddling of the infant during feeding while placing in a side-lying position. This can minimize excessive stimulation and promote feeding. Swaddling will also reduce the risk of skin excoriation due to excessive movement. The infant’s arms should be flexed before tightly swaddling to minimize skin irritation. Use of barrier protection for the elbows, knees, and heels and mittens for the hands may also help prevent skin damage and irritation.", "whyNot": {"a": "The newborn should be placed on the right side after feeding. This reduces the risk of emesis and promotes gastric emptying.", "b": "Infants with neonatal abstinence syndrome are hypersensitive to stimuli. Unnecessary stimulation can be prevented by clustering care to", "c": "The newborn will be hypersensitive to stimuli and should be placed in a quiet section of the nursery with low lighting to minimize"}, "keyConcept": "Neonatal abstinence syndrome occurs in newborns born to opioid dependent mothers. Withdrawal will begin within 24-48 hours, resulting in neonatal irritability, poor feeding, diarrhea, vomiting, a high pitched cry, dilated pupils, sneezing, and sweating. Swaddling the infant prevents excoriation and reduces stimulation during feeding. Placing the swaddled infant in a side-lying position promotes feeding."}, {"id": 10502, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client at 28 weeks' gestation who has a new prescription for dinoprostone (Cervidil). Which of the following is the most appropriate nursing intervention?", "choices": [{"id": "a", "t": "Provide instructions about the medication"}, {"id": "b", "t": "Recheck vital signs and maternal history for medical problems before administering the drug"}, {"id": "c", "t": "Call the doctor"}, {"id": "d", "t": "Determine the correct dose and route of administration"}], "correct": "c", "rationale": "A i 10% Hard Dinoprostone (Cervidil) is a medication used to ripen the cervix for a pregnant woman at near term. It is used when there is medical B ri 28% indication for inducing labor. Cervidil is a form of prostaglandin E2 that is usually manufactured in gel form. It acts to stimulate the smooth muscles of the uterus, causing uterine contractions. It is contraindicated for clients who can not deliver vaginally and for those who have had O€ | A7% six or more pregnancies. It is also contraindicated if there is known allergy to prostaglandin. D Hi 15% The most appropriate nursing intervention by the nurse is to call the doctor for clarification when this drug is prescribed for a client at 28 weeks' gestation, since it is intended for clients at near term. It will harm both the mother and the developing fetus if not cancelled. Providing instructions, rechecking vital signs and maternal history for medical problems and determining the correct dose and route of administration are not appropriate nursing actions because the safety of the mother and developing fetus will be compromised if the medication is administered.", "whyNot": {"a": "Provide instructions about the medication.", "b": "Recheck vital signs and maternal history for medical problems before administering the drug.", "d": "Determine the correct dose and route of administration."}, "keyConcept": "Dinoprostone (Cervidil) in a vaginal gel is used to “ripen” the cervix in pregnancy at or near term when induction of labor is indicated. It can be administered as a vaginal suppository for induction of midtrimester abortion, and management of missed abortion up to 28 weeks. Dinoprostone produces contractions similar to those occurring during labor at term by stimulating the myometrium. It initiates softening, effacement, and dilation of the cervix, known as “cervical ripening”. Dinoprostone also stimulates G! smooth muscle."}, {"id": 10503, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is teaching a client who is pregnant about a new prescription for iron supplements. With which of the following beverages should the nurse instruct the client to take the iron supplement?", "choices": [{"id": "a", "t": "Coffee © B. whole mitk"}, {"id": "c", "t": "Green tea"}, {"id": "d", "t": "Orange juice"}], "correct": "d", "rationale": "A 0% Easy Orange juice contains vitamin C, which aids in the absorption of iron through the gastrointestinal tract.", "whyNot": {"a": "Caffeine, which is found in tea and coffee, can interfere with iron absorption. Clients who are pregnant should consume no more than 200 ep | 89%", "c": "Caffeine, which is found in green and black tea, can interfere with iron absorption. Therefore, clients should avoid taking iron supplements"}, "keyConcept": "Itis recommended when taking iron supplements that the client ingest a diet that is high in vitamin C. The absorption of iron is increased 2 = ® 4 z = a iat g < when taken in conjunction with drinks that contain vitamin C, such as orange juice. The client should also be instructed to take iron supplements on an empty stomach and to avoid taking the supplements with tea, coffee, and milk because these drinks and the presence of food can interfere with the absorption of iron. Clients who are taking iron supplements should be instructed that their stool might change color to dark green or black. Constipation is also an adverse effect of iron supplements."}, {"id": 10504, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following findings is unexpected when assessing a preterm newborn for cold stress?", "choices": [{"id": "a", "t": "Shivering"}, {"id": "b", "t": "Weak cry O culrritability"}, {"id": "d", "t": "Feeding difficulty"}], "correct": "a", "rationale": "Neonates have immature nervous systems and do not have adequate muscle tissue to generate heat by shivering. They are able to increase the metabolic rate and generate heat by nonshivering thermogenesis, using brown adipose tissue developed during the third trimester. After depletion of brown adipose tissue, nonshivering thermogenesis becomes less effective, resulting in cold stress in the neonate that can may result in death. Preterm newborns have less brown adipose tissue stores than term infants, so they are at increased risk for cold stress. The nurse should frequently monitor the neonate’s temperature to determine if the infant is cold. Cold stress causes increased oxygen and glucose demand and increased release of norepinephrine in order to generate heat. Hypoxia and acidemia occur when oxygenation is inadequate. If glucose stores are depleted, hypoglycemia will develop if the repletion of stores is impaired by poor intake and slow motility in the gastrointestinal tract. Cold stress is manifest by neurologic, cardiovascular, respiratory, gastrointestinal, and musculoskeletal changes as listed in the table below. Low body temperature is characteristic of cold stress. Cardiovascular Respiratory Neurological Gastrointestinal Musculoskeletal Bradycardia Tachypnea, progressing to apnea and hypoxia Irritability or lethargy Emesis, hypoglycemia, decreased motility, increased gastric residuals ‘Weak suck or cry, hypotonia", "whyNot": {"b": "Aweak cry is characteristic, and a weak suck may also be seen.", "d": "Feeding difficulties are characteristic of cold stress."}, "keyConcept": "Shivering is a method of heat generation, but neonates do not have adequate muscle mass to generate heat by shivering. They increase the metabolic rate and generate heat by using brown adipose tissue developed during the third trimester. Premature neonates have low stores. of brown adipose tissue, which places them at greater risk of cold stress."}, {"id": 10505, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client one day after an uncomplicated vaginal delivery. Which gastrointestinal changes would a nurse most likely see in this client?", "choices": [{"id": "a", "t": "Abdominal pain"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Gastroesophageal reflux"}, {"id": "d", "t": "Constipation"}], "correct": "d", "rationale": "‘i Many women become constipated after giving birth, which can occur for several reasons. Some women are inactive during the first few days B I after delivery, which contributes to slowed gastrointestinal transit. Fluid intake and intake of fruits and vegetables may be lacking, which can also contribute to constipation. € I", "whyNot": {"a": "Abdominal pain is not a common sign that would occur after a normal vaginal delivery.", "b": "Diarrhea is not a common finding that develops after a vaginal delivery; instead, the client may more likely suffer from constipation.", "c": "Gastroesophageal reflux is not a common sign that would develop after a vaginal delivery."}, "keyConcept": "Causes of constipation after vaginal delivery can include use of systemic narcotics (such as morphine, Vicodin, or Percocet) during labor or for postpartum pain; sore perineum due to hemorrhoids, an episiotomy, or a tear, which may lead to constipation due to fear of pushing or straining; and use of iron supplement in prenatal vitamins. The client should be encouraged to ambulate, increase fluids, and increase consumption of high-fiber foods."}, {"id": 10506, "cat": "NCLEX 10-ante...neonatal care", "stem": "for the nurse to relay to the parents?", "choices": [{"id": "a", "t": "Move the car seat to the back seat and secure it facing forward"}, {"id": "b", "t": "Move the car seat to the back seat and secure it facing backward"}, {"id": "c", "t": "Leave the car seat in the front seat but ensure that the seatbelt is tight around the base"}, {"id": "d", "t": "Tell the parents that they need to use a different car seat"}], "correct": "b", "rationale": "al 4% Easy According to the American Academy of Pediatrics (AAP), a newborn infant must be placed in a rear-facing car seat that is appropriate for his es rss 94% size and is secured in the backseat. The nurse in this situation has an opportunity to educate new parents about appropriate standards of car seat use for their infant and may also instruct them about properly securing the infant within the car seat. € | 176)", "whyNot": {"a": "The car seat needs to be moved to the back seat but it should be rear facing.", "c": "The car seat needs to be moved to the back seat.", "d": "The parents do not necessarily need a different car seat, they just need to position it in the back seat."}, "keyConcept": "Infants should be placed in a rear-facing car seat in the back seat as early as the initial trip home from the hospital. An rear facing seat should never be placed in a front seat with an active passenger side airbag, as serious injury or death can occur if the airbag deploys. Three types of rear-facing seats are available: rear-facing-only, convertible, and 3-in-1. When children reach the highest weight or length allowed by the manufacturer of their rear-facing-only seat, they should continue to ride rear-facing in either a convertible or 3-in-1 seat. Rear-facing-only seats are used for infants up to 22 to 40 pounds. These seats have carrying handles and usually have a base that can be left in the car. The seat locks into and out of the base, so there is no need to reinstall the seat with each use. 2 = ® 4 z = a iat g <"}, {"id": 10507, "cat": "NCLEX 10-ante...neonatal care", "stem": "the following? O A. Beans O B. Steamed broccoli O C. Sour Cream O D. Corn", "choices": [{"id": "a", "t": "Beans"}, {"id": "b", "t": "Steamed broccoli"}, {"id": "c", "t": "Sour Cream"}, {"id": "d", "t": "Corn"}], "correct": "a", "rationale": "Protein intake is a concern for all who subscribe to vegetarian diets. Combining two incomplete proteins such as rice and beans to make a B I % complete protein can improve the dietary intake of protein. c| 1% Protein is found in a variety of foods, including: * Beans and peas © Dairy products like cheese, greek yogurt, and milk ° Eges * Grains and vegetables (these generally provide less protein than is found in other sources) © Meats and poultry * Nuts and seeds * Seafood (fish and shellfish) © Soy products 2 = ® 4 z = a iat g <", "whyNot": {"b": "Broccoli does not contain enough protein to meet the needs of a vegan diet. While vegetables such as broccoli are important, this is not", "c": "Sour cream does not contain enough protein to meet the dietary needs of this client. The rice should be combined with another good", "d": "While corn is important as a vegetable in the diet, it does not contain enough protein to meet this client’s dietary needs."}, "keyConcept": "Consumption of 75 to 100 grams of protein is recommended per day in pregnancy. Protein positively affects the growth of fetal tissue, including the brain. It is also necessary for the growth of breast and uterine tissue during pregnancy, and and in increasing blood volume. Pregnant women should also consume 400 mcg per day of synthetic folic acid from fortified foods (cereals and other grains), supplements, or both, in addition to consuming folate from foods from dietary sources; and 30 mg/day iron, beginning early in pregnancy"}, {"id": 10508, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in a clinic receives a phone call from a client who asks about using a home pregnancy test. Which of the following information should the nurse provide to the client? O A.\"You should wait at least 8 weeks after your last menstrual period to test for pregnancy.\" O B. \"You should stop taking any prescribed medications for at least 24 hours prior to the test.\" O C. \"You should not eat or drink for at least 8 hours prior to the test.\" O D. \"You should perform the test the first time you urinate in the morning.\"", "choices": [{"id": "a", "t": "Home pregnancy tests can detect the presence of human chorionic gonadotrophin (hCG) as early as one week before the next expected ep 89%"}, {"id": "b", "t": "The nurse should not advise the client to stop taking prescribed medications in preparation for home urine pregnancy tests, because"}, {"id": "c", "t": "There are no food or drink restrictions required prior to performing a pregnancy test."}, {"id": "d", "t": "all 6% Easy The nurse should instruct the client to perform the urine pregnancy test during the first morning void to provide the most accurate results."}], "correct": "d", "rationale": "all 6% Easy The nurse should instruct the client to perform the urine pregnancy test during the first morning void to provide the most accurate results.", "whyNot": {"a": "Home pregnancy tests can detect the presence of human chorionic gonadotrophin (hCG) as early as one week before the next expected ep | 89%", "b": "The nurse should not advise the client to stop taking all prescribed medications in preparation for home urine pregnancy tests, because", "c": "There are no food or drink restrictions required prior to performing a pregnancy test."}, "keyConcept": "Home pregnancy tests are designed to detect the presence of human chorionic gonadotrophin (hCG) in a client's urine. This hormone begins to be produced following fertilization and levels can be detected as early as 1 week following conception. To ensure the most accurate results, home pregnancy tests should be performed according to the manufacturer's instructions. Clients should read the instructions carefully and not omit any steps. Clients should also pay attention for things to avoid prior to testing to ensure accurate results. If the results are negative, the client should repeat the test within 1 week to ensure the result was not a false negative. For the most accurate confirmation of pregnancy status, clients should see a provider for testing and examination."}, {"id": 10509, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing instructions to a client about breastfeeding her infant. Which of the following will be included in the instruction?", "choices": [{"id": "a", "t": "Position the client according to protocol"}, {"id": "b", "t": "Place the thumb finger below the areola and the other four fingers above the areola"}, {"id": "c", "t": "Place the index finger above the areola and the other three fingers below the areola"}, {"id": "d", "t": "Put one finger to the nipple to ensure that the infant will suck"}], "correct": "c", "rationale": "A Hi 16% Moderate Breastfeeding is an important task for a new mother in order to provide adequate nutrition to the infant, and facilitate maternal-infant . The technique for this breastfeeding should be explained or demonstrated in order to promote effective breastfeeding and prevent breast trauma. This type of hold involves placing the index finger above the areola and the other three fingers below the areola. The oc Sh.) infant needs to take the entire nipple into the mouth allowing the jaws to compress the milk ducts beneath the areola. D | | ™%", "whyNot": {"a": "The breastfeeding client is instructed to position herself according to her comfort because not all protocols will be effective; clients have", "b": "The hand using the C-hold supports the breast. This type of hold involves placing the index finger above the areola and the other three", "d": "The mother’s hand should be away from the nipple so that the infant can latch on the breast."}, "keyConcept": "Breast milk provides nutrition with an ideal mix of vitamins, protein, and fat. It is more easily digested than infant formula and contains 2 = ® 4 z = a iat g < antibodies that offer protection against viruses and bacteria. It is associated with a reduced risk of asthma or allergies. Exclusive breastfeeding for 6 months or longer is associated with fewer ear infections, respiratory illnesses, diarrheal illnesses, hospitalizations and doctor visits."}, {"id": 10510, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a woman who is receiving oxytocin to induce labor. The nurse must observe the client carefully for signs of which of the following?", "choices": [{"id": "a", "t": "Hypoglycemia"}, {"id": "b", "t": "Severe pain"}, {"id": "c", "t": "Uterine tetany"}, {"id": "d", "t": "Bloody show"}], "correct": "c", "rationale": "All Oxytocin may induce uterine tetany, which may restrict blood flow to the fetus and slow the progression of labor. B I", "whyNot": {"a": "Hypoglycemia is unrelated to the administration of oxytocin. D i", "b": "Pain is expected to be associated with intense contractions.", "d": "Bloody show is to be expected as labor progresses."}, "keyConcept": "Oxytocin should only be used when induction of labor is necessary for medical reasons and should only be used by experienced healthcare providers in a setting in which surgical and intensive care facilities are immediately available. During oxytocin administration, uterine contractions, fetal and maternal heart rate, maternal blood pressure, and, if possible, intrauterine pressure should be continuously monitored to avoid complications. If uterine tetany occurs, oxytocin administration should be immediately discontinued; oxytocin-induced stimulation of the uterine contractions usually decreases soon after the drug is discontinued. Severe adverse reactions include uterine rupture, postpartum hemorrhage, and uterine tetany. Oxytocin also has an antidiuretic effect that can result in water intoxication when given for long periods of time with large volumes of low sodium fluids."}, {"id": 10511, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is planning to administer an IM medication to a newborn prior to discharge. The nurse should expect to inject the medication into which of the following locations?", "choices": [{"id": "a", "t": "Vastus lateralis"}, {"id": "b", "t": "Abdomen"}, {"id": "c", "t": "Dorsogluteal O D.peltoid"}], "correct": "a", "rationale": "The nurse should administer an IM injection in the vastus lateralis muscle of newborn. The vastus lateralis is a well-developed muscle that is , infants, and small children. cf 6%", "whyNot": {"b": "The nurse should not administer an IM injection into the abdomen of a newborn because this can cause injury to the infant. The abdomen", "c": "The nurse should not administer an IM injection in the dorsogluteal muscle of a newborn because of its proximity to the sciatic nerve."}, "keyConcept": "Muscle size, needle length, and the total amount of medication being injected should be carefully considered by the nurse prior to administration. The nurse should wear nonsterile gloves, stabilize the area of injection, use antiseptic to clean the injection site, and place the injection area between the thumb and forefinger. The needle should remain at a 90° angle while the medication is slowly injected. Following the injection, the nurse should withdraw the needle quickly and place a dry gauze pad over the site. The nurse should finally apply gentle pressure to the injection site to ensure minimal pain and bleeding."}, {"id": 10512, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client with pregnancy-induced hypertension who is scheduled for a cesarean section. In which position should the nurse place the client before she is transferred to the delivery suite?", "choices": [{"id": "a", "t": "Supine"}, {"id": "b", "t": "Prone"}, {"id": "c", "t": "Left lateral"}, {"id": "d", "t": "Trendelenburg"}], "correct": "c", "rationale": "‘i 8 | o: of Positioning client on her left side will take the pressure off the inferior vena cava and will increase blood return to the heart.", "whyNot": {"a": "Positioning the client supine would place increased pressure on the inferior vena cava and should be avoided.", "b": "The client should not be positioned prone in this situation.", "d": "The client should not be positioned in Trendelenburg; this places too much pressure on the inferior vena cava from the weight of the baby."}, "keyConcept": "Cardiac output is increased in most of pregnancy, except the late phase, as a result of an increase in blood volume, body weight, and increased metabolism. During the late phase of pregnancy, the enlarged uterus impedes blood return to the heart. Pregnancy induced hypertension causes impaired blood flow to the fetus. Bedrest in the left lateral recumbent position can increase fetal blood flow, since the uterus is moved away from the maternal inferior vena cava and the right iliac artery. This causes spontaneous diuresis due to increased blood flow to the kidneys and increases blood flow to the heart, increasing the clients cardiac output."}, {"id": 10513, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X ©@ New x % CLOSE { Browse Questions ~ it Search Questions", "choices": [{"id": "a", "t": "Placing the infant in the supine position"}, {"id": "b", "t": "Using loose bedding"}, {"id": "c", "t": "Supplementing breastfeeding with formula"}, {"id": "d", "t": "Using a soft mattress"}], "correct": "a", "rationale": "SIDS refers to a sudden, unexplained death in an infant who is under 1 year of age. It is the leading cause of death in infants between the ages of 1 month and 1 year, with most cases occurring between 2 and 4 months of age. Risk can be reduced by placing the infant in the supine position (on the back) anytime the infant is sleeping, even for a short period of time. Since this recommendation was made by the American Academy of Pediatrics Committee on Infant Sleep Position and Sudden Infant Death Syndrome in 2000, the death rate from SIDS has decreased by 40% in the United States. SIDS is more likely to occur in preterm infants and those discharged from the NICU. Parents of high- risk infants should be instructed in cardiopulmonary resuscitation (CPR). Risk factors include tobacco smoke exposure both before and after birth, co-sleeping with adults, overheating, lying on a soft sleep surface, and the presence of toys, loose bed clothing, or bumper pads in the infant’s bed. Pacifier use has also been associated with a reduction in SIDS.", "whyNot": {"b": "Soft objects and loose bedding should be kept away from the infant’s sleep area.", "c": "Breastfeeding is associated with a reduced risk of SIDS.", "d": "A firm sleep surface should be used for infants to reduce risk."}, "keyConcept": "SIDS refers to sudden, unexplained death in an infant under the age of one year. Risk factors include tobacco smoke exposure before and after birth; co-sleeping; overheating; and the presence of toys or loose objects in the crib. The SIDS rate has decreased by 40% in the US since the American Academy of Pediatrics recommended infants be placed in the supine position any time they are sleeping."}, {"id": 10514, "cat": "NCLEX 10-ante...neonatal care", "stem": "Ahealthcare provider orders a serum alpha-fetoprotein test for a pregnant client at 20 weeks’ gestation. Which best describes the purpose of this test?", "choices": [{"id": "a", "t": "Identifying renal disease in the mother"}, {"id": "b", "t": "Verifying the risk of maternal-fetal blood type incompatibility"}, {"id": "c", "t": "Assessing for fetal hyperbilirubinemia"}, {"id": "d", "t": "Excluding the presence of fetal neural tube defects"}], "correct": "d", "rationale": "A Aserum alpha-fetoprotein test detects the amount of a protein produced by the fetus during development. The test is typically performed B = between 15 and 22 weeks’ gestation to rule out the presence of certain birth defects, including neural tube defects such as spina bifida. It may also be performed to detect the presence of genetic abnormalities such as Down syndrome or Turner syndrome. € I", "whyNot": {"a": "An alpha-fetoprotein test is not performed to detect kidney disease in a pregnant mother.", "b": "The alpha-fetoprotein test assesses for the possibility of birth defects in the fetus; it is unrelated to maternal-fetal blood incompatibility.", "c": "The alpha-fetoprotein test does not measure for high bilirubin in the fetus."}, "keyConcept": "Open neural tube defects (NTDs) are congenital anomalies that develop when a portion of the neural tube fails to close normally during the third and fourth weeks after conception. These anomalies can affect the vertebrae, spinal cord, cranium, and/or brain. Alpha-fetoprotein is a fetal-specific globulin, synthesized by the fetal yolk sac, gastrointestinal tract, and liver. The function of alpha-fetoprotein is unknown, but it can be measured in maternal serum (MSAFP), amniotic fluid, and fetal plasma. Abnormalities may indicate neural tube and non-neural tube defects in the fetus. Elevated MSAFP should prompt an ultrasound examination to further assess whether an open NTD or another anomaly associated with elevated MSAFP levels is present."}, {"id": 10515, "cat": "NCLEX 10-ante...neonatal care", "stem": "Aneonate develops hyperbilirubinemia and phototherapy is initiated. What should the plan of care include for an infant receiving phototherapy?", "choices": [{"id": "a", "t": "Taking vital signs every hour"}, {"id": "b", "t": "Keeping the eye shields on for 8 hours at a time"}, {"id": "c", "t": "Giving additional fluids every two hours"}, {"id": "d", "t": "Covering the neonate with a lightweight blanket"}], "correct": "c", "rationale": "Insensible and intestinal fluid losses increase during phototherapy; extra fluids prevent dehydration.", "whyNot": {"a": "The nurse does not need to assess the infant’s vital signs every hour with phototherapy.", "b": "The eye shields should be on the baby whenever she is under the phototherapy lights.", "d": "The baby should not be covered with a blanket; this prevents the phototherapy lights from reaching the skin."}, "keyConcept": "Unconjugated hyperbilirubinemia is the most common form of neonatal hyperbilirubinemia. Unconjugated bilirubin has not been metabolized and cannot be excreted via the normal pathways in the urine and bowel. Accumulated bilirubin binds with lipids and albumin, resulting in the yellow appearance of the skin and sclera. Unconjugated bilirubin is a neurotoxin that can cross the blood-brain barrier, leading to significant brain damage. Phototherapy treatment for jaundice is performed by exposure of skin to a light source, which converts. unconjugated bilirubin molecules into water-soluble molecules that can be excreted by in urine and stool."}, {"id": 10516, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in an outpatient clinic is assessing a 25-year-old woman at 30 weeks gestation. Which of the following findings could indicate a possible complication?", "choices": [{"id": "a", "t": "Increased vaginal discharge"}, {"id": "b", "t": "Feels pressure at diaphragm"}, {"id": "c", "t": "Positive urine test for glucose and ketones"}, {"id": "d", "t": "Pedal edema in both feet in the evenings"}], "correct": "c", "rationale": "All Positive urine test for glucose and ketones could indicate gestational diabetes mellitus. B I", "whyNot": {"a": "Itis normal for a pregnant client to experience an increased amount of vaginal discharge. D I", "b": "Pressure in the area of the diaphragm may occur with growth of the baby and pressure from the expanding uterus.", "d": "Increased edema in the lower legs and feet is a common occurrence that is more likely to occur in the evenings, after the client has been"}, "keyConcept": "Gestational diabetes (GD) is diagnosed when a woman develop diabetes for the first time during pregnancy. women who have had GD are at higher risk of developing diabetes later in life. Risk factors include being overweight or obese; physical inactivity; history of GD in a previous pregnancy; history of giving birth to a baby weighing 9 pounds or more in a previous pregnancy; high blood pressure; history of heart disease; polycystic ovary syndrome (PCOS); and African-American, Native American, Asian American, Hispanic, and Pacific Island ethnicity."}, {"id": 10517, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is at 30 weeks’ gestation and scheduled for a biophysical profile. Which best describes the process of a biophysical profile?", "choices": [{"id": "a", "t": "An ultrasound is used to visualize characteristics of the fetus and observe for fetal responses to stimuli"}, {"id": "b", "t": "The clinician monitors the fetal heart rate and uterine contractions while the client pushes a button whenever she feels a fetal movement"}, {"id": "c", "t": "Uterine contractions are stimulated while the fetus is monitored and the client presses a button whenever she feels a fetal movement"}, {"id": "d", "t": "A needle is inserted into the amniotic sac under ultrasound and a small amount of fluid is withdrawn for testing"}], "correct": "a", "rationale": "o; A biophysical profile is a test used to assess the mother and the baby, particularly in a high-risk pregnancy. A biophysical profile combines an B | ultrasound with a non-stress test. The clinician performs an ultrasound to check the status of the baby while the mother pushes a button on a monitor when she feels the baby move. € i", "whyNot": {"b": "This describes a non-stress test, not a biophysical profile.", "c": "This describes a contraction stress test, not a biophysical profile.", "d": "This describes an amniocentesis, not a biophysical profile."}, "keyConcept": "The biophysical profile combines ultrasound evaluation with a non-stress test (NST). It is performed during the third trimester to determine fetal health. The test is performed if there are questions about fetal health and well being resulting from either an examination, maternal/fetal symptoms, or if the pregnancy is considered high risk. The NST is performed by attaching one belt to the mother’s abdomen to measure fetal heart rate, and another belt to measure contractions. Movement, heart rate and “reactivity” of heart rate to movement are measured for 20-30 minutes. The ultrasound may take as long as an hour. Attributes measured in a biophysical profile include breathing, movement, muscle tone, heart rate, and amniotic fluid volume."}, {"id": 10518, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is assessing a new client during an initial prenatal visit at 10 weeks’ gestation. The nurse understands that which of the following factors on assessment places the client at risk for preterm birth?", "choices": [{"id": "a", "t": "Age 30"}, {"id": "b", "t": "Hypoglycemia"}, {"id": "c", "t": "Non-Hispanic white ethnicity"}, {"id": "d", "t": "Tobacco use"}], "correct": "d", "rationale": "Infection is associated with increased risk of preterm birth. It results in a release of prostaglandins, which promote contractions and increase cervical softening. Other risk factors include use of illicit drugs, history of a prior cervical procedure like a cone biopsy or loop excision, or a history of a spontaneous preterm birth (which is the most significant risk factor). Poor maternal nutritional status may increase risk. Short interpregnancy intervals, cervical insufficiency, and vaginal bleeding in early pregnancy are also associated with increased risk. Aterm pregnancy lasts 38-42 weeks, and 85% of women deliver within 7 days of their due date. Birth before 37 weeks’ gestation is defined as preterm birth. Preterm labor refers to cervical changes and uterine contractions that occur at 20-37 weeks of gestation and may occur without preterm birth. A short length of gestation is a more serious risk to the newborn than low birth weight, as the intrauterine time correlates with the maturation of body systems. Preterm births account for 85% of complications in newborns at the time of delivery. Approximately 75% of preterm births are spontaneous, and the remainder are medically indicated to resolve risk to the mother or fetus associated with continuing pregnancy. Tobacco smoking has a dose-dependent relationship with increased risk.", "whyNot": {"a": "Maternal age <17 or >35 is associated with increased risk of preterm birth.", "b": "Type 1 diabetes is associated with increased risk of preterm birth.", "c": "The highest rate of preterm labor and birth is among non-Hispanic black women."}, "keyConcept": "Delivery before 37 weeks' gestation defines preterm birth. Risk factors for preterm birth include previous history of spontaneous preterm birth, infection, maternal use of tobacco or illicit drugs, maternal diabetes, and a history of cervical procedure, such as a cone biopsy. Length of gestation is closely correlated with maturation of body systems. Respiratory complications, including respiratory distress syndrome, bronchopulmonary dysplasia, apnea, and chronic lung disease, result from failure of the lungs to fully mature. Respiratory complications are a significant cause of morbidity and mortality of in the preterm infant. Other complications include patent ductus arteriosis, retinopathy of prematurity, necrotizing enterocolitis, and intraventricular hemorrhage."}, {"id": 10519, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is teaching a client who is at 32 weeks of gestation about findings to immediately report to the provider. Which of the following manifestations should the nurse include?", "choices": [{"id": "a", "t": "Watery discharge from the vagina"}, {"id": "b", "t": "Swelling of the ankles"}, {"id": "c", "t": "Heartburn after eating"}, {"id": "d", "t": "Lightheadedness when lying on back"}], "correct": "a", "rationale": "Asudden watery discharge from the vagina could indicate that the amniotic membranes have ruptured. This finding should always be B immediately reported to the physician. - ©", "whyNot": {"b": "Swelling of the ankles is a common discomfort during pregnancy and can be relieved by sitting with the legs elevated.", "c": "Heartburn occurs during pregnancy due to pressure on the stomach from the enlarging uterus. It can be relieved by eating smaller, more", "d": "Supine hypotension occurs when a client feels lightheaded when lying on their back. The nurse should instruct the client to use the side-"}, "keyConcept": "The nurse should inform pregnant clients about the manifestations of potential pregnancy complications, such as swelling of the face, chills, vaginal bleeding, severe headaches, and visual disturbances. If the client experiences any of these, the provider should be notified immediately to allow for prompt intervention. Although spontaneous rupture of the membranes after 37 weeks is an expected finding, the occurrence should always be immediately reported to the physician."}, {"id": 10520, "cat": "NCLEX 10-ante...neonatal care", "stem": "contributing factor in the neonate's size at birth?", "choices": [{"id": "a", "t": "Placenta previa"}, {"id": "b", "t": "Cephalopelvic disproportion"}, {"id": "c", "t": "Maternal inactivity"}, {"id": "d", "t": "Warm climate"}, {"id": "e", "t": "None of the above"}], "correct": "a", "rationale": "SGA or IUGR (intrauterine growth restriction) is a condition where the newborn is at or below the 10th percentile for weight on the newborn B ] 12% classification chart. This condition predisposes the client to instability in extrauterine life. Close monitoring and extra care are needed. Placenta previa causes SGA due to deficiency in fetal circulation, because the placenta is not implanted correctly or fully attached to the c I 4% uterus. SGA can result from maternal diseases such as hypertension; environmental factors such as exposure to X-rays; maternal ; or substance abuse.", "whyNot": {"b": "Cephalopelvic disproportion is usually caused by a large fetus and incompatibility of the maternal pelvis.", "c": "Maternal inactivity is not proven to cause SGA.", "d": "Warm climate is not proven to cause SGA."}, "keyConcept": "Small for gestational age is a term that describes an infant who is smaller than the usual amount for the number of weeks of pregnancy. SGA babies usually have birth weights below the 10th percentile for babies of the same gestational age. SGA is often the result of intrauterine growth restriction (IUGR). IUGR occurs when the fetus does not receive the necessary nutrients and oxygen for proper growth and development of organs and tissues. It can begin at any time in pregnancy. Early-onset IUGR is usually the result of chromosomal abnormalities, maternal disease, or severe problems with the placenta. Late-onset growth restriction (after 32 weeks) is usually related to other problems."}, {"id": 10521, "cat": "NCLEX 10-ante...neonatal care", "stem": "effective teaching? O A. Amniotic fluid volume O B. Size of the placenta O C. Amniotic fluid color O D. Fetal gestational age", "choices": [{"id": "a", "t": "Amniotic fluid volume"}, {"id": "b", "t": "Size of the placenta"}, {"id": "c", "t": "Amniotic fluid color"}, {"id": "d", "t": "Fetal gestational age"}], "correct": "a", "rationale": "The biophysical profile typically measures five parameters to assess the fetus: fetal breathing, movement, and tone; amniotic volume; and . The test uses a scale of 0 to 2 for each parameter with a maximum score of 10. I © 4%", "whyNot": {"b": "The biophysical profile does not measure the size of the placenta.", "c": "The biophysical profile does not consider the amniotic fluid color.", "d": "The biophysical profile does not measure the gestational age."}, "keyConcept": "A biophysical profile is a test performed in the third trimester to evaluate fetal health in cases where the pregnancy is considered high risk or 2 when maternal or fetal signs and symptoms raise concerns. It consists of a fetal ultrasound and a nonstress test. The nonstress test monitors x changes in fetal heart rate while the mother is at rest. The fetal ultrasound assess amniotic fluid volume, muscle tone, movement, and a breathing. <"}, {"id": 10522, "cat": "NCLEX 10-ante...neonatal care", "stem": "breast discomfort and engorgement? O", "choices": [{"id": "a", "t": "Breast engorgement is unlikely to occur after the client leaves the hospital."}, {"id": "b", "t": "It is more comfortable for a client who is not lactating to go without a bra for the first 72 hours."}, {"id": "c", "t": "Apply cool compresses to the breasts before feeding."}, {"id": "d", "t": "The client should apply a small amount of breast milk to sore nipples and let them air dry after feeding."}], "correct": "d", "rationale": "3-5 days after birth. Cool compresses should be applied after (not before) feeding. Warm . Application of breast milk, especially colostrum, to the nipple area can help soothe the discomfort and help promote healing. The fats and protein in the milk may € |_| ah increase healing of cracks and fissures that often develop and cause discomfort. @D fe 65%", "whyNot": {"a": "Breast engorgement occurs 3-5 days after delivery.", "b": "The client who is not lactating should wear a supportive, well-fitting bra continuously for the initial 72 hours after delivery.", "c": "Warm compresses or a warm shower are recommended to promote letdown and increase milk flow before breastfeeding."}, "keyConcept": "Breast engorgement occurs 3-5 days after delivery in many postpartum women, when the breasts switch from colostrum to production of mature milk. The breasts become hard and swollen, causing pain and making it difficult for the newborn to feed due to flattening of the nipples. Warm compresses before breastfeeding can facilitate letdown. There is some evidence that supports the application of cabbage leaves to the breasts to decrease duct congestion and engorgement. 2 = ® 4 z = a iat g <"}, {"id": 10523, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is preparing to administer Rho(D) immune globulin for a client who is postpartum. Which of the following criteria should the nurse identify for administering Rho(D) immune globulin?", "choices": [{"id": "a", "t": "The client is Rh positive with a newborn who is Rh positive."}, {"id": "b", "t": "The client is Rh negative with a newborn who is Rh negative."}, {"id": "c", "t": "The client is Rh negative with a newborn who is Rh positive."}, {"id": "d", "t": "The client is Rh positive with a newborn who is Rh negative."}], "correct": "c", "rationale": "Rho(D) immune globulin contains antibodies to Rho(D). The nurse should identify the need to administer Rho(D) immune globulin to prevent antibody formation in a client who is Rh negative following exposure to Rh positive blood from their infant. Intrauterine transfusion can also occur before the infant is born, which is the administration of Rh negative, type O blood into the umbilical vein. These transfusions can be administered as often as every 14 days until the fetus reaches 37 to 38 weeks of gestation and the fetus' lungs mature.", "whyNot": {"a": "The nurse should identify that a client who is Rh positive with a newborn who is Rh positive would not receive Rho(D) immune globulin", "b": "The nurse should identify that a client who is Rh negative with a newborn who is Rh negative would not receive Rho(D) immune because", "d": "The nurse should identify that a client who is Rh positive with a newborn who is Rh negative Rho(D) would not receive Rho(D) immune"}, "keyConcept": "Rho(D) RhoGAN is only given to women who are Rh-negative with an Rh-positive pregnancy. RhoGAM is a brand of the Rh immunoglobulin given as an injection to prevent problems with a baby who has Rh-positive blood."}, {"id": 10524, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X ©@ New x x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x see Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions", "choices": [{"id": "a", "t": "October 8"}, {"id": "b", "t": "October 12"}, {"id": "c", "t": "October 22"}, {"id": "d", "t": "October 30"}], "correct": "a", "rationale": "To arrive at the estimated date of delivery, Naegele’s rule uses the first day of the date of the last normal menstrual period minus 3 months © i plus 7 days. Therefore, this client’s estimated date of delivery is (January 1) - 3 months plus 7, or October 8. Other methods to determine the D I estimated date of delivery include measurement of the uterine height (McDonald’s measurement); auscultation of fetal heart rate by Doppler; and ultrasound, specifically around the 16-18th week of pregnancy. Naegele’s rule assumes the client will have a 28-day cycle. The rule is not as accurate when the client has a longer or shorter menstrual cycle. B. The rule is not based on the last day of the cycle. Length of menstrual bleeding varies among individuals. C. This date is consistent with the conception date of the embryo, which is based on the period of fertility 24-72 hours from with time of ovulation, which is approximately 14 days from the beginning of the last menstrual period. The trophoblast implants 7-10 days after fertilization. Using the date of conception results in a later date than the true gestational age. D. This date may have been calculated from the period of spotting. It should not be used to calculate the gestational age. Spotting may occur when the trophoblast implants into the endometrial lining of the uterus, but use of this date will result in a delay of the estimated date of birth.", "whyNot": null, "keyConcept": "Naegele's rule is used to calculate an estimated date of delivery based upon the date of the last normal menstrual period. The client's estimated date of delivery is calculated by using the first day of the last normal menstrual period and substracting three months, then adding 7 days."}, {"id": 10525, "cat": "NCLEX 10-ante...neonatal care", "stem": "Aneonate develops hyperbilirubinemia and phototherapy is initiated. What should the plan of care include for an infant receiving phototherapy?", "choices": [{"id": "a", "t": "Taking vital signs every hour"}, {"id": "b", "t": "Keeping the eye shields on for 8 hours at a time"}, {"id": "c", "t": "Giving additional fluids every two hours"}, {"id": "d", "t": "Covering the neonate with a lightweight blanket"}], "correct": "c", "rationale": "g additional fluids every two hours Insensible and intestinal fluid losses increase during phototherapy; extra fluids prevent dehydration.", "whyNot": {"a": "The nurse does not need to assess the infant’s vital signs every hour with phototherapy.", "b": "The eye shields should be on the baby whenever she is under the phototherapy lights.", "d": "The baby should not be covered with a blanket; this prevents the phototherapy lights from reaching the skin."}, "keyConcept": "Unconjugated hyperbilirubinemia is the most common form of neonatal hyperbilirubinemia. Unconjugated bilirubin has not been metabolized and cannot be excreted via the normal pathways in the urine and bowel. Accumulated bilirubin binds with lipids and albumin, resulting in the yellow appearance of the skin and sclera. Unconjugated bilirubin is a neurotoxin that can cross the blood-brain barrier, leading to significant brain damage. Phototherapy treatment for jaundice is performed by exposure of skin to a light source, which converts. unconjugated bilirubin molecules into water-soluble molecules that can be excreted by in urine and stool."}, {"id": 10526, "cat": "NCLEX 10-ante...neonatal care", "stem": "interventions is most appropriate ? O", "choices": [{"id": "a", "t": "Restrict fluids until the client has had a bowel movement"}, {"id": "b", "t": "Provide the client with a meal or snack"}, {"id": "c", "t": "Start an IV of normal saline and administer antibiotics"}, {"id": "d", "t": "Keep the client NPO and notify the physician"}], "correct": "b", "rationale": ", a patient may be hungry and want to eat. In this situation, the patient should be allowed to have a es Td 14% snack or a meal, as she is not exhibiting abnormal symptoms following the delivery. The nurse should monitor the client’s food and fluid intake and administer stool softeners as ordered to avoid straining with defecation because of the episiotomy and the hemorrhoids. € i i) om 18%", "whyNot": {"a": "Fluids would be encouraged to prevent constipation.", "c": "There is no indication in the question IV antibiotics are needed at this time", "d": "The client should not be kept NPO. They are allowed to eat freely and their intake should be monitored."}, "keyConcept": "The postpartum period, which lasts six to eight weeks, begins after the delivery of the baby and ends when the mother's body has nearly returned to its pre-pregnant state. The key to maintaining energy and health during this busy period is good nutrition. The mother should be encouraged to eat nutrient-dense foods."}, {"id": 10527, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing teaching for a client who is planning to attempt pregnancy. Which of the following dietary requirements should the nurse stress to prevent neural tube defects? O AVitaminc O B. Calcium O C. Folate O D. Iron", "choices": [{"id": "a", "t": "Vitamin C deficiency is not associated with neural tube defects."}, {"id": "b", "t": "2%"}, {"id": "c", "t": "a| 1% Easy (folate) in the first 8 weeks of gestation."}, {"id": "d", "t": "Iron promotes the development of red blood cells, but prenatal intake or deficiency is not associated with neural tube defects."}], "correct": "c", "rationale": "a| 1% Easy (folate) in the first 8 weeks of gestation. Neural ec Ft 92% tube defects include anencephaly and spina bifida. Women attempting conception should be counseled to ensure adequate intake of foods , which include green leafy vegetables and fortified grain products such as cereals, pastas, and bread. Prenatal vitamins include adequate amounts of folic acid. Amounts of 400-800 mcg daily are recommended for women planning to become pregnant.", "whyNot": {"a": "Vitamin C deficiency is not associated with neural tube defects.", "b": "Calcium levels should be adequate to form bones and teeth, but calcium intake is not associated with neural tube defects. Mineralization", "d": "Iron promotes the development of red blood cells, but prenatal intake or deficiency is not associated with neural tube defects."}, "keyConcept": "Folic acid supplementation is recommended for pregnant women and those attempting to conceive, since deficiency is linked to an increased risk of neural tube defects, including spina bifida and anencephaly. Leafy green vegetables and fortified grain products are good dietary sources, but prenatal vitamins contain adequate supplementation."}, {"id": 10528, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ (J ATI? X © New x x ]) untii x Untii x (4 Goo x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions A nurse is teaching the parents of a newborn about treatment measures for their newborn's plagiocephaly. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "\"Place your baby on her tummy while she is sleeping during the day.\""}, {"id": "b", "t": "\"Keep your baby's head in the same position during activities.”"}, {"id": "c", "t": "\"Place the prescribed helmet on your baby's head for 23 hours a day.\""}, {"id": "d", "t": "\"Keep your baby in an infant swing for several hours during the day.\""}], "correct": "c", "rationale": "A A newborn who has plagiocephaly should wear the customized prescribed helmet 23 hr per day. The helmet decreases the pressure on the B : affected side of the skull. o: aT", "whyNot": {"a": "A newborn who has plagiocephaly should not be placed in the prone position to sleep. Instead, the parents should place the newborn ina", "b": "A newborn's head should not be placed in the same position at all times. Instead, the parents should frequently reposition the newborn's", "d": "A newborn who has plagiocephaly should not be placed in an infant swing for several hours during the day. This can put pressure on one"}, "keyConcept": "Plagiocephaly is the abnormal asymmetrical shape of an infant's head caused by molding of the skull due to positioning or acquired during birth. At this time, the infant's cranial sutures are not closed, and this allows for molding of the cranium to occur. It can also occur from placing infants on their backs to sleep because this causes the skull to flatten occipitally and develop an abnormal shape. This condition can be prevented by alternating the infant's head position while sleeping supine, avoiding prolonged placement of the infant in swings or carriers, and placing the infant in the prone position during playtime. If not resolved within 2 months, physical therapy is recommended, and a customized helmet is used for this condition. The customized helmet should be placed on the infant for 23 hours per day for about 3 months. The helmet is used to decrease the pressure on the affected side of the skull."}, {"id": 10529, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is assessing a client at 34 weeks’ gestation who complains of feeling faint. Her blood pressure while supine is 100/60 mmHg. Which of the following nursing interventions is most appropriate?", "choices": [{"id": "a", "t": "Place the client lying in the left lateral recumbent position and recheck blood pressure in 5 minutes in the left arm"}, {"id": "b", "t": "Place the client in the left lateral recumbent position and recheck blood pressure in the right arm in 5 minutes."}, {"id": "c", "t": "Ask the client to stand and recheck blood pressure while standing"}, {"id": "d", "t": "Take the client’s blood pressure in the opposite arm in the same position"}], "correct": "a", "rationale": "During pregnancy, maternal positioning can affect blood pressure. Blood pressure usually decreases in the first and second trimester as the circulation expands and as hormonal changes result in dilation of blood vessels. It usually recovers to pre-pregnancy levels in the third trimester. The client should be placed in a left lateral recumbent position to reduce pressure on her blood vessels (vena cava syndrome), which improves venous return to the heart. The blood pressure should be rechecked in 5 minutes. The blood pressure should be checked in the left arm, as checking it in the right arm may result in a falsely lower blood pressure measurement, since that arm is now positioned above the heart. Placing the client in the supine position is likely to compress maternal blood vessels.", "whyNot": {"b": "This may result in a falsely low measurement. The blood pressure should be checked in the left arm when the client is in the left lateral", "c": "In pregnancy, the blood pressure may rise with standing, as pressure on the vena cava is relieved.", "d": "The client should be moved from the supine position since it can cause occlusion of maternal blood vessels, resulting in hypotension."}, "keyConcept": "After 20 weeks' gestation, the size of the gravid uterus can compress the inferior vena cava, decreasing the return of blood into the heart (preload.) clients in a supine position or prolonged standing during pregnancy can experience symptoms of hypotension.The left lateral recumbent position reduces pressure on maternal blood vessels."}, {"id": 10530, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is in labor. The anesthesiologist has just administered a pudendal block. Which of the following is correct regarding a pudendal block? O A.A pudendal block may cause side effects of respiratory depression and hypotension O B. A pudendal block is one of the first drugs administered for pain control during labor O C. A pudendal block anesthetizes the perineum, vulva, and rectum O D. A pudendal block is only used in emergency situations", "choices": [{"id": "a", "t": "Hi 19%"}, {"id": "b", "t": "A pudendal block is typically administered not long before the baby is delivered; it is not one of the first medications administered for pain"}, {"id": "c", "t": "A Hi 19% Moderate A pudendal block is a type of anesthetic block used for pain control during labor."}, {"id": "d", "t": "A pudendal block may be given before delivery of an infant; it is not only used in emergency situations only."}], "correct": "c", "rationale": "A Hi 19% Moderate A pudendal block is a type of anesthetic block used for pain control during labor. It is given during the time that the mother is in labor but . A pudendal block anesthetizes the perineum, vulva, and rectum before the infant is delivered. OG _ 0 o| 2% Needle guide 2 (S g o 5 x < Pudendal nerve Ischial spine . Sacrospinous ligament ©BoardVitals", "whyNot": {"b": "A pudendal block is typically administered not long before the baby is delivered; it is not one of the first medications administered for pain", "d": "A pudendal block may be given before delivery of an infant; it is not only used in emergency situations only."}, "keyConcept": null}, {"id": 10531, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following is the priority nursing intervention after calling for assistance?", "choices": [{"id": "a", "t": "Administer oxygen by face mask at 8 L/min."}, {"id": "b", "t": "Obtain IV access."}, {"id": "c", "t": "Prepare the client for an emergency cesarean section."}, {"id": "d", "t": "Use a sterile gloved hand and apply finger pressure to elevate the presenting part of the fetus."}], "correct": "d", "rationale": "All 3 | Prolapse of the umbilical cord occurs when the umbilical cord precedes the presenting part of the fetus or protrudes through the cervix. This © i compresses the umbilical cord and prevents perfusion of the fetus. Risk factors include fetal presentations that are not vertex; rupture of the ep fF amniotic membranes; a transverse lie, in which the presenting part is not engaged; a long umbilical cord; multifetal pregnancy; small-for- gestational-age fetus; and polyhydramnios. The nurse should call for assistance immediately and notify the provider. The critical intervention is elevation of the fetal part that is compressing the umbilical cord. The nurse should use a sterile-gloved hand to insert two fingers into the vagina, one on each side of the cord, and apply gentle pressure to elevate the fetal part. The client should then be assisted into the Trendelenburg position, knee-chest position, or side-lying position with a towel roll placed under the right or left hip. A warm sterile towel soaked in sterile saline should be used to cover the cord to prevent drying and maintain perfusion. The fetal heart rate should be monitored. Variable decelerations indicate fetal hypoxia and asphyxia. Umbilical Cord Prolapse Occult Cou Prolapse ver Cord Prolapse The cord dropping alngsie the baby, The cord coming before ‘but may no be seenin advance ‘thebaby's head can come out", "whyNot": {"a": "Oxygen should be administered, but this is not the priority intervention.", "b": "lV access should be initiated for fluid resuscitation, but this is not the initial intervention.", "c": "After elevating the part from the cord, preparation for a cesarean section will be necessary if the client is not completely dilated. Vaginal"}, "keyConcept": null}, {"id": 10532, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Qa * @ New x | NCL Xx x» *o!1@0 + v Finish update :", "choices": [{"id": "a", "t": "Discontinue the medication infusion."}, {"id": "b", "t": "Prepare the client for an emergency cesarean birth."}, {"id": "c", "t": "Determine the client's current blood glucose level."}, {"id": "d", "t": "Administer an additional loading dose of the medication."}], "correct": "a", "rationale": "A. Magnesium toxicity is manifested as bradypnea, or a respiratory rate of less than 12/min, and absent deep tendon reflexes. The magnesium sulfate infusion should be discontinued and calcium gluconate should be administered immediately via IV.", "whyNot": {"b": "There is no evidence or indication for preparing the client for a cesarean birth at this time.", "c": "Assessing and determining the current maternal blood glucose level would give the nurse no relevant data concerning the effects of the", "d": "Administering an additional loading dose of the medication can worsen the magnesium toxicity, which can lead to respiratory or cardiac"}, "keyConcept": null}, {"id": 10533, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client in the labor and delivery service who is receiving oxytocin after prolonged labor. Intervention is necessary when which assessment finding is noted? O A.6 contractions in 10 minutes O B. Temperature of 99.8°F O C. Cervical dilation from 5 to 6 cm in 1 hour O D. Fetal heart rate of 150/min with moderate variability and no late decelerations", "choices": [{"id": "a", "t": "Oxytocin, a hormone produced in the posterior pituitary gland, stimulates uterine contractions and let-down of milk."}, {"id": "b", "t": "The temperature should be monitored and the healthcare provider notified when the temperature is greater than 100.4°F (38°C). If"}, {"id": "c", "t": "This is an expected finding."}, {"id": "d", "t": "This is a normal fetal heart rate. variability is normal. Late decelerations are a sign of potential fetal distress. A normal fetal heart"}], "correct": "a", "rationale": "Oxytocin, a hormone produced in the posterior pituitary gland, stimulates uterine contractions and let-down of milk. A synthetic form, © i Pitocin, is used to induce or augment labor and to control postpartum bleeding. It is associated with potential risks of uterine tachysystole, D | | postpartum hemorrhage, infection, and death from water intoxication, as well as uterine rupture, placental abruption, and unnecessary cesarean birth as a result of abnormalities in fetal heart rate patterns. Uterine tachysystole is characterized by more than 5 contractions in 10 minutes averaged over a 30-minute time period, a series of single contractions lasting longer than 2 minutes, or contractions of normal duration that occur within a minute of each other. Initial nursing interventions, if the fetal heart rate tracing is reassuring, include repositioning the client in the side-lying position, administration of an IV fluid bolus, and reduction or discontinuation of oxytocin. If the FHR tracing is non-reassuring, with fetal bradycardia, late decelerations, or decreased variability with tachycardia, the nurse should stop the oxytocin infusion immediately and reposition the client. Oxygen can be given at 10 L/minute by face mask if abnormalities do not improve. An IV fluid bolus can be given, and the healthcare provider should be notified. Terbutaline may be prescribed per protocol or by the HCP to treat the client.", "whyNot": {"b": "The temperature should be monitored and the healthcare provider notified when the temperature is greater than 100.4°F (38°C). If", "c": "This is an expected finding.", "d": "This is a normal fetal heart rate. Moderate variability is normal. Late decelerations are a sign of potential fetal distress. A normal fetal heart"}, "keyConcept": "Pitocin is a synthetic form of the hormone oxytocin. It is administered to induce or augment labor and to stimulate uterine contraction to control postpartum bleeding. Close fetal and maternal monitoring is necessary during administration, since risks include uterine tachysystole, fetal distress, placental abruption, or uterine rupture."}, {"id": 10534, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who reports morning sickness at 7 weeks’ gestation. Which of the following is the appropriate nursing response?", "choices": [{"id": "a", "t": "Advise the client to drink 16 ounces of water upon awakening."}, {"id": "b", "t": "Tell the client that nausea and vomiting typically do not last past the first trimester."}, {"id": "c", "t": "Advise the client that hot foods are less likely to cause nausea than cold foods."}, {"id": "d", "t": "Advise the client to consume a snack high in carbohydrates and/or protein when she awakens."}], "correct": "d", "rationale": "Nausea and vomiting of pregnancy (NVP) commonly occur during the first trimester of pregnancy. It is most likely the result of rising levels of hormones in pregnancy, including human chorionic gonadotropin, estrogen, and progesterone. Dietary management can often reduce the severity of symptoms. The nurse should advise the client to consume a high-protein or high-carbohydrate snack on awakening and before bedtime; to eat several small meals high in protein or carbohydrates and low in fat throughout the day; to avoid fluids with meals but to consume ginger and flavored lollipops when nauseous. Women should be advised not to skip meals. The client should also consume foods that are high in vitamin B6 and/or iron.", "whyNot": {"a": "The client should be encouraged to avoid excessive fluid intake early in the day or when nauseated, and to compensate by drinking", "b": "While this is accurate, this response does not address the client’s current symptoms.", "c": "Cold or cool foods and beverages are recommended. Hot foods or spicy/fatty foods may worsen NVP."}, "keyConcept": "NVP is common in the first trimester of pregnancy, as a result of rising hormone levels. Dietary measures can be helpful to reduce symptoms, although some women may require antiemetic medication. Ginger and vitamin B6 supplements can be helpful. NVP usually resolves by the 14th week of pregnancy."}, {"id": 10535, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guid¢ ® ATI? X ©@ New x x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions", "choices": [{"id": "a", "t": "Painless uterine bleeding"}, {"id": "b", "t": "Hypotension and tachycardia"}, {"id": "c", "t": "Usually not visible"}, {"id": "d", "t": "Pain or pressure"}], "correct": "d", "rationale": "Vaginal, vulvar, or retroperitoneal hematomas may form as a result of lacerations during delivery. Lacerations of the cervix, perineum, and © I vagina should be suspected in clients who continue to have bleeding despite the contraction of the uterus in the puerperium. Bleeding may ep fF be a frank hemorrhage or a slower/smaller volume of vaginal bleeding. The most common type of injury is a laceration of the perineum. Cervical lacerations usually result in minimal bleeding. The most common, as a result, is vulvar hematoma, which is usually visible. It is most frequently the result of episiotomy or perineal laceration, and the most commonly associated symptom is pain. Vaginal hematomas are associated with forceps-assisted birth, primigravid mother, or episiotomy. Perineal or rectal pain or vaginal pressure is typical. If the hematoma is retroperitoneal, pain may be minimal, and the client may initially present with signs of shock. Treatment of small vulvar hematomas may require only analgesia and use of ice packs applied to the perineum for 24 hours to reduce swelling. If the hematoma is large or expands rapidly, surgical intervention may be necessary.", "whyNot": {"a": "Lacerations sustained during delivery usually occur in the cervix, perineum, or vagina.", "b": "Hypotension and tachycardia are only likely when the hemorrhage is severe.", "c": "A vulvar hematoma is usually visible."}, "keyConcept": "Avulvar hematoma following an episiotomy is the result of bleeding and trauma during the birth process. The pregnant uterus, vagina, and vulva have a rich vascular supply. The vulvar hematoma is painful and may cause discomfort in sitting or moving around. Pain medication does little to reduce the pain due to the swelling and inflammation in the area. A surgical procedure may be necessary to remove the clots."}, {"id": 10536, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in a clinic is teaching a client who is planning to become pregnant about the effects of folic acid deficiency. Which of the following complications should the nurse include?", "choices": [{"id": "a", "t": "Maternal physiological anemia"}, {"id": "b", "t": "Maternal pica"}, {"id": "c", "t": "Fetal cardiac malformations"}, {"id": "d", "t": "Fetal neural tube defects"}], "correct": "d", "rationale": "Easy Folic acid has a direct effect on the closure of the neural tube. Deficiency of folic acid can result in defects such as spina bifida, , and anencephaly. Foods high in folic acid include leafy green vegetables, liver, peanuts, cereals, and whole-grain breads. ] 3%", "whyNot": {"a": "Physiological anemia is a normal response to pregnancy caused by expansion of the plasma volume to a greater degree than increase in", "b": "Pica refers to cravings for nonnutritive substances, such as dirt, clay ice, and starch, which can occur during pregnancy. Clients who have", "c": "Cardiac anomalies in fetal development can occur due to wide variety of factors, such as genetic factors and exposure to environmental"}, "keyConcept": "Folic acid supplementation prior to and during pregnancy reduces the risk of neural tube defects in the fetus. Dietary sources of folic acid, or folate include grains, liver, peanuts, and fortified products such as cereals. Neural tube defects affect the development of the fetus in the first trimester and can result in severe nervous system damage, brain malformation, and spina bifida. The recommended daily intake of folic acid for clients who are planning to become pregnant is 400 mcg daily."}, {"id": 10537, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x € OS @G 23 student.atitesting.com/LT| Convert study guid« @ alli x @ New x [=| NCL! x | + v Qa * ws * © Cb Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Bright red blood from the incision"}, {"id": "b", "t": "Petechiae under the blood pressure cuff"}, {"id": "c", "t": "Temperature of 101 degrees Fahrenheit"}, {"id": "d", "t": "Platelet count of 75,000/mm3"}], "correct": "c", "rationale": "A A client with DIC will have signs of excessive bleeding or bruising. The client will typically have a normal temperature. B -", "whyNot": {"a": "The nurse might expect to see bright red bleeding from the incision after the wound is closed. D i", "b": "The client might develop petechiae under the blood pressure cuff or under compression stockings, caused by rupture of capillary blood", "d": "Typically, the platelet count will be decreased (less then 150,000/ mm3) and the PTT will be increased."}, "keyConcept": "DIC is caused by abnormal activation of the clotting cascade in infection, childbirth, and surgical procedures. Although DIC is typically associated with bleeding, it is a disorder in which hemorrhage and thrombosis occur at the same time. Hypercoagulation causes diffuse thrombosis in small and large vessels, leading to depletion of clotting factors, fibrinogen, and platelets. This results in hemorrhage. Prompt recognition and treatment are necessary to reduce morbidity and mortality associated with DIC. The underlying cause of DIC must be identified and treated. Supportive measures include fluid replacement and administration of blood components. The nurse should monitor the client for signs of bleeding, which range from oozing to frank hemorrhage. Bleeding is the primary clinical manifestation and may cause anxiety in the client and family members. The nurse should provide care in a reassuring manner to reduce anxiety."}, {"id": 10538, "cat": "NCLEX 10-ante...neonatal care", "stem": "finding most likely represent? O A. Thrombophlebitis O B. Varicose veins O C. Buerger’s disease O D. Compartment syndrome", "choices": [{"id": "a", "t": "Thrombophlebitis"}, {"id": "b", "t": "Varicose veins"}, {"id": "c", "t": "Buerger’s disease"}, {"id": "d", "t": "Compartment syndrome"}], "correct": "a", "rationale": "0; ME oe 5 Tenderness, warmth, and redness of the leg are the symptoms of thrombophlebitis. Thrombophlebitis is vein inflammation related to a . It occurs more commonly in pregnancy and the postpartum period. cf 6%", "whyNot": {"b": "Varicose veins are manifested by swollen veins visible under the skin.", "c": "In Buerger’s disease cold and clammy skin can be seen.", "d": "Compartment syndrome manifests as pain and swelling."}, "keyConcept": "Postpartum deep vein thrombosis (DVT) and superficial thrombophlebitis in the postpartum period may occur as a result of trauma to the pelvic veins from pressure exerted by the presenting fetal part. Other pregnancy related changes that increase the risk of thrombophlebitis or DVT include impaired circulation and hypercoagulability related to the increased production of estrogens during pregnancy. Thrombosis. that involves only the superficial veins of the leg or thigh is unlikely to result in pulmonary emboli 2 = ® 4 z = a iat g <"}, {"id": 10539, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is assessing a client who is 2 days postpartum. There is 8 cm of bright red lochia with small clots saturating the perineal pad. How should the nurse document these findings?", "choices": [{"id": "a", "t": "Scant O B.Light"}, {"id": "b", "t": ". From 2.5 cm to 10 cm is characterized as light lochia."}, {"id": "d", "t": "Heavy"}], "correct": "b", "rationale": ". From 2.5 cm to 10 cm is characterized as light lochia. es ri 31% Lochia should be assessed for amount, consistency, and color. It usually trickles from the vaginal introitus, but during uterine contractions, flow is more consistent. When assessing the client, the nurse should look for pooled lochia on the pad. Lochia that has pooled in the vagina € | 9% can be expelled by uterine massage or when the client is ambulating. After expression of any clots or dark blood that has collected in the D Hi 17% vagina, the flow should return to a bright red trickle. Abnormalities include excessive blood loss, foul odor, spurts of bright red blood, persistence of bright red lochia after the third day postpartum, or continuous flow of lochia alba or serosa, particularly when accompanied by fever or abdominal pain.", "whyNot": {"a": "Scant lochia refers to less than 2.5 cm on the perineal pad.", "d": "Heavy lochia refers to saturation of the perineal pad in less than 2 hours."}, "keyConcept": "After delivery, lochia rubra is present from 1-3 days, followed by lochia serosa from day 4 through day10, and lochia alba from days 11-21. After delivery, saturation of one pad in less than an hour, the presence of large clots, or a constant trickle of lochia are signs that may indicate serious complications, including hemorrhage or retained placenta. Foul-smelling lochia indicates infection. Abnormal progression of the sequence of changes in lochia should be investigated."}, {"id": 10540, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in an outpatient clinic is assessing a 25-year-old woman at 30 weeks gestation. Which of the following findings could indicate a possible complication?", "choices": [{"id": "a", "t": "Increased vaginal discharge"}, {"id": "b", "t": "Feels pressure at diaphragm"}, {"id": "c", "t": "Positive urine test for glucose and ketones"}, {"id": "d", "t": "Pedal edema in both feet in the evenings"}], "correct": "c", "rationale": "All Positive urine test for glucose and ketones could indicate gestational diabetes mellitus. B I", "whyNot": {"a": "Itis normal for a pregnant client to experience an increased amount of vaginal discharge. D I", "b": "Pressure in the area of the diaphragm may occur with growth of the baby and pressure from the expanding uterus.", "d": "Increased edema in the lower legs and feet is a common occurrence that is more likely to occur in the evenings, after the client has been"}, "keyConcept": "Gestational diabetes (GD) is diagnosed when a woman develop diabetes for the first time during pregnancy. women who have had GD are at higher risk of developing diabetes later in life. Risk factors include being overweight or obese; physical inactivity; history of GD in a previous pregnancy; history of giving birth to a baby weighing 9 pounds or more in a previous pregnancy; high blood pressure; history of heart disease; polycystic ovary syndrome (PCOS); and African-American, Native American, Asian American, Hispanic, and Pacific Island ethnicity."}, {"id": 10541, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a postpartum client who had rubella at the time of delivery. The client asks why their newborn is being placed in isolation. Which of the following responses should the nurse make?", "choices": [{"id": "a", "t": "\"Isolation is mandatory because your baby has the virus that can infect others.\""}, {"id": "b", "t": "\"Your baby has an increased risk for developing another TORCH infection.\""}, {"id": "c", "t": "\"Your baby might develop a complication of rubella known as encephalitis.”"}, {"id": "d", "t": "\"Exposure to rubella will suppress your baby's immune response.\""}], "correct": "a", "rationale": "@A Fe AT% Hard Infants who are born to clients who have rubella will continue to shed the rubella virus for up to 18 months following delivery. These infants B _ 15% are a serious source of infection to women in their childbearing years and other susceptible individuals. Isolation is mandatory until the 9 infant's urine and pharyngeal mucous are free of the infection. € |_| 14% om! 24%", "whyNot": {"b": "TORCH stands for toxoplasmosis, other, rubella, cytomegalovirus, and herpes. TORCH infections can cross the placenta and affect the", "c": "Newborns who are exposed to the rubella virus during gestation are at increased risk to develop hearing loss, congenital cataracts, and", "d": "Exposure to rubella does not affect the infant's immune response. All newborns have a high risk for infection during the first few months"}, "keyConcept": "Manifestations of congenital rubella syndrome + Hearing loss (most common) + Glaucoma + Cataracts + Cardiac Defects 0 Coarctation of the aorta o Patent ductus arteriosus o Pulmonary artery stenosis + Hypotonia + Microcephaly + Brain abnormalities"}, {"id": 10542, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a pregnant client whose last menstrual period was on February 11. By July 18, a physical assessment of the client should indicate that the top of the fundus is at which of the following locations?", "choices": [{"id": "a", "t": "Even with the umbilicus"}, {"id": "b", "t": "Just above the symphysis pubis"}, {"id": "c", "t": "Two finger-breadths above the umbilicus"}, {"id": "d", "t": "Halfway between the symphysis and umbilicus"}], "correct": "a", "rationale": "oo. li! 50% Hard At about the 22nd week of gestation, the top of the fundus is at the level of the umbilicus. ce | 8% cm 23% B. This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be much D Hi 20% higher than the symphysis pubis.", "whyNot": {"c": "At this point, the top of the fundus would be at about the umbilicus, not two finger-breadths above.", "d": "This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be at about"}, "keyConcept": "Fundal height is defined as the distance from the pubic bone to the top of the uterus measured in centimeters. After 20 weeks of pregnancy, the fundal height measurement matches the number of weeks gestation, +/- 2 weeks. The fundal height measurement is not as accurate in women who are obese, carrying multiples, or with a history of fibroid tumors. 2 (S g o 5 [a < Asmaller or larger fundal height than expected or a fundal height that increases more or less quickly than expected could be due to intrauterine growth restriction, fetal macrosomia (large baby), oligohydramnios (reduced amniotic fluid), or polyhydramnios (increase in amniotic fluid.) — 36k — wwk nm 32 wk | —_ Gp mw tk — leuk a 12 wk Pubic bone 5"}, {"id": 10543, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x «<> ¢G student.atitesting.com/LT| Convert study guid« @ alli x @ New x [=| NCL! x | + v Qa * ws * © Cb Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Lochia alba"}, {"id": "b", "t": "Lochia rubra"}, {"id": "c", "t": "Lochia serosa"}, {"id": "d", "t": "Lochia venosa"}], "correct": "c", "rationale": "Al Lochia serosa is pink and watery in appearance with a serosanguinous consistency. It typically develops within 3 to 10 days following B H delivery. o:", "whyNot": {"a": "Lochia alba is white or yellow and develops within approximately 10 days after delivery.", "b": "Lochia rubra is bright red and develops immediately following birth.", "d": "Lochia venosa is not a type of drainage that occurs after delivery."}, "keyConcept": "Lochia refers to the vaginal discharge that begins after giving birth, during the puerperium. It contains blood, mucus, and uterine tissue. Lochia discharge typically continues for 4 to 6 weeks after childbirth. There are three stages of lochia. Lochia is sterile for the first 2 to 3 days and composed largely of blood, known as lochia rubra. Composed of blood, shreds of fetal membranes, By the third or fourth day, as the uterus begins to be colonized by vaginal commensals such as non-hemolytic streptococci and E. coli, lochia serosa appears. It has a serosanguinous consistency and character and also contains serous exudate, erythrocytes, leukocytes, and cervical mucus. Lochia alba, the last stage, has fewer erythrocytes and a white appearance."}, {"id": 10544, "cat": "NCLEX 10-ante...neonatal care", "stem": "@ @ * Viral x Na Recc xX ™ Inbo x ™ Inbo x =) Untii x Untii x La Goor x @ TEA x Onlir x @ Mark x @ Micr x Convert study guide ® ATIT xX @ New x {. NCL x + v < > CG student.atitesting.com/LTI Qa * sw * © © | Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE sg Pas ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Helps to regulate blood glucose"}, {"id": "b", "t": "Facilitates maternal absorption of calcium"}, {"id": "c", "t": "Promotes blood clotting in the mother and newborn"}, {"id": "d", "t": "Helps to prevent neural tube defects in the newborn"}], "correct": "d", "rationale": "a| 1% Easy Folic acid is critical for the prevention of neural tube defects in the newborn. To be most effective, the mother should begin taking folic acid . The other listed conditions are not affected by folic acid I 4 © 2% intake.", "whyNot": {"a": "Folate does not regulate blood glucose. It is regulated by insulin and glucagon.", "b": "Calcium absorption is regulated by vitamin D.", "c": "Folate is important to formation of red blood cells, but it is not necessary for coagulation."}, "keyConcept": "Folate (folic acid) is a B vitamin. Folate and vitamin B12 are necessary for the formation of normal red blood cells and the synthesis of DNA (deoxyribonucleic acid) Folate is also necessary for normal development of a fetus’s nervous system. Folate deficiency in a pregnant woman increases the risk of defects of the spinal cord or brain in the fetus. 2 = ® 4 z = a iat g <"}, {"id": 10545, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which condition would most likely place a client at risk of postpartum hemorrhage?", "choices": [{"id": "a", "t": "Involution of the uterus"}, {"id": "b", "t": "Use of magnesium sulfate during labor"}, {"id": "c", "t": "Uterine cramps and excessive contractions"}, {"id": "d", "t": "Expulsion of the placenta within 20 minutes of infant delivery"}], "correct": "b", "rationale": "Magnesium sulfate is sometimes used during labor and delivery to treat high blood pressure in the mother. Magnesium sulfate may cause es 4d 40% vasodilation and could contribute to platelet inhibition, which increases the risk of hemorrhage. ci 16%", "whyNot": {"a": "Involution of the uterus is a normal process that occurs after delivery and does not increase the risk of hemorrhage.", "c": "Uterine cramping is the body’s attempt to staunch excess blood flow; this would not contribute to hemorrhage after delivery.", "d": "Expulsion of the placenta within 20 minutes after delivery is normal and does not increase the risk of postpartum hemorrhage."}, "keyConcept": "Postpartum hemorrhage (PPH) is the greatest cause of maternal mortality. It is defined as blood loss > 500 mL following vaginal delivery or > e 1000 mL following cesarean delivery. The most common cause is uterine atony, which refers to failure of the uterus to contract and retract z after delivery. Risk factors for PPH include labor induction and augmentation, chorioamnionitis, magnesium sulfate use, and history of 2 previous PPH. a"}, {"id": 10546, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is preparing to perform a non-stress test. Which position would the nurse recommend that the client be placed in?", "choices": [{"id": "a", "t": "Lateral position"}, {"id": "b", "t": "Supine position"}, {"id": "c", "t": "Trendelenberg position"}, {"id": "d", "t": "High Fowler’s position"}], "correct": "a", "rationale": "The client is placed in a lateral position to avoid vena cava compression.", "whyNot": {"b": "The supine position would increase the risk of vena cava compression and should be avoided.", "c": "The trendelenberg position would not be a suitable position for a non-stress test.", "d": "The client lies on her side during the procedure, not in the high Fowler’s position."}, "keyConcept": "Pregnant clients should not be placed in a supine position for prolonged periods as this may result in compression of the large vessels (vena cava) due to the gravity/weight of the full uterus on those vessels. This compression can cause decreased blood flow."}, {"id": 10547, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is reviewing postpartum nutrition needs with a client who is breastfeeding. Which of the following statements by the client indicates an understanding of the instructions? O A.\"Lcan continue to smoke as long as | do it 30 minutes prior breastfeeding.\" O B. \"I should take folic acid to increase my milk supply.” O C. \"I will continue adding 200 calories per day to my diet.\" O D. \"I will continue taking my vitamins while | am breastfeeding.\"", "choices": [{"id": "a", "t": "Clients who are breastfeeding should avoid smoking because it will impair milk production. If a client continues smoking, it is"}, {"id": "b", "t": "Folic acid does not increase milk production."}, {"id": "c", "t": "Clients who are breastfeeding require an additional 450 to 500 calories per day to support adequate nutrition."}, {"id": "d", "t": "A Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and can continue to take vitamin supplements."}], "correct": "d", "rationale": "A Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and can continue to take vitamin supplements. This can B ; assist the client to ensure they receive adequate nutrition while breastfeeding. The client should balance their calories burned and consumed as well. C |__|", "whyNot": {"a": "Clients who are breastfeeding should avoid smoking because it will impair milk production. If a client continues smoking, it is", "b": "Folic acid does not increase milk production.", "c": "Clients who are breastfeeding require an additional 450 to 500 calories per day to support adequate nutrition."}, "keyConcept": "Clients who are breastfeeding should increase their daily caloric intake by 450 to 500 calories to support adequate nutrition and breast milk production. Smoking alters breastmilk production. Consuming large amounts of caffeinated beverages is not recommended while breastfeeding due to caffeine entering the breast milk. Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and should be informed that they can continue to take their vitamin supplements. This can assist the client to ensure they receive adequate nutrition while breastfeeding."}, {"id": 10548, "cat": "NCLEX 10-ante...neonatal care", "stem": "discoloration similar in appearance to a bruise on the infant’s lower back, just above the buttocks. Which of the following is the best response by the nurse? O A.\"Has the infant suffered an injury of any sort since coming home from the hospital?\" O B. \"Let's take a look. This type of spot is common in babies of Asian descent and will likely disappear eventually.” O C. \"Why didn't anyone notice this until just now?\" O D. \"I will notify the healthcare provider right away.\" O E. \"| hope it’s nothing serious.\"", "choices": [{"id": "a", "t": "Hi"}, {"id": "b", "t": "A Hi Mongolian spots are common in Asian infants, Hispanics and Native Americans."}, {"id": "c", "t": "Mongolian spots are often present at birth, but occasionally become apparent later in the first few weeks of life. It is entirely possible that"}, {"id": "d", "t": "There is no need to inform the healthcare provider immediately. Mongolian spots are benign and require no treatment."}, {"id": "e", "t": "Expressing the hope that it is nothing serious will inspire feelings of fear in the mother and should be avoided."}], "correct": "b", "rationale": "A Hi Mongolian spots are common in Asian infants, Hispanics and Native Americans. They are less common in Caucasian infants. They often o: disappear in the first few years of life. ©", "whyNot": {"a": "Asking this question implies wrongdoing. Although the area resembles a bruise, it is a common birthmark. E", "c": "Mongolian spots are often present at birth, but occasionally become apparent later in the first few weeks of life. It is entirely possible that", "d": "There is no need to inform the healthcare provider immediately. Mongolian spots are benign and require no treatment.", "e": "Expressing the hope that it is nothing serious will inspire feelings of fear in the mother and should be avoided."}, "keyConcept": "Mongolian spots are hyperpigmented dark blue to black lesions that usually appear on the lumbosacral area in infants with darkly pigmented skin Mongolian spots often disappear before the age of five, but they may persist into adulthood in some cases. Mongolian spots are sometimes associated with other congenital disorders. Mongolian blue spots"}, {"id": 10549, "cat": "NCLEX 10-ante...neonatal care", "stem": "What type of colostomy is used for the management of anorectal malformation in a neonate?", "choices": [{"id": "a", "t": "Adivided descending colostomy O B.A divided transverse colostomy"}, {"id": "c", "t": "A sigmoid colostomy"}, {"id": "d", "t": "An ascending colostomy"}], "correct": "a", "rationale": "The type of colostomy that is used for the management of anorectal malformations is a divided colostomy, also known as a double-barreled colostomy. This type of colostomy completely diverts fecal contents, provides bowel decompression, and preserves the distal colon for surgical repair at one or two months of life.", "whyNot": {"c": "Asigmoid colostomy is located in the sigmoid colon and is not used to manage anorectal malformations.", "d": "An ascending colostomy is located in the ascending colon and is not used to manage anorectal malformations."}, "keyConcept": "Anorectal malformations include imperforate anus and cloaca, which refers to a common opening for the genital, urinary, and gastrointestinal tract. Infants born with these malformations may have a primary repair or the surgery may be delayed for one to two months after the creation of a divided colostomy. The divided colostomy is one in which the surgeon divides the intestine and creates a stoma (the opening through the abdominal wall) for each portion. The proximal portion of the bowel is active and this stoma passes stool. The distal segment is separated from the digestive tract but continues to produce mucus. A divided colostomy preserves the distal portion of the colon for use in the corrective surgery."}, {"id": 10550, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a newborn who has necrotizing enterocolitis (NEC). Which of the following findings should the nurse recognize as a risk factor for this condition?", "choices": [{"id": "a", "t": "Macrosomia"}, {"id": "b", "t": "Transient tachypnea of the newborn (TTN)"}, {"id": "c", "t": "Maternal gestational hypertension"}, {"id": "d", "t": "Gestational age of 35 weeks"}], "correct": "d", "rationale": "‘im The cause of NEC is unknown, but infants who were born prematurely are at the greatest risk. Gestational age of 35 weeks, or preterm birth, B Hl places a newborn at risk for NEC. This could be due to the lack of oxygen during delivery and a weakened immune system.", "whyNot": {"a": "Macrosomia, an infant who weighs more than 3.6 kg (8 lb) at birth, does not place a newborn at risk for NEC. Low birth weight or preterm", "b": "TTN does not place a newborn at risk for NEC. Preterm birth is a risk factor for NEC.", "c": "Maternal gestational hypertension does not place a newborn at risk for NEC. Preterm birth is a risk factor for NEC."}, "keyConcept": "Necrotizing enterocolitis (NEC) is a disease that develops in infancy and affects the intestines. The inner mucosal lining of the intestines becomes inflamed and causes decreased blood supply to the bowel, necrosis, and eventually death to the infected portion of the bowel. The cause of this condition is unknown but could be due to a lack of oxygen during birth. The greatest risk factor for this condition is preterm labor or birth. Preterm infants can have a weak immune system, hypoxia, and other complications that could predispose them to this condition. Manifestations are associated with inflamed and infected bowels, and the child can exhibit abdominal swelling, vomiting, poor feeding, diarrhea, and bloody stools. Treatment for NEC depends on the severity. The nurse should keep the child NPO, give IV fluids for hydration, and administer enteral feedings via nasogastric tube or parental nutrition if needed. Surgery could be warranted to remove the infected portion of the intestines."}, {"id": 10551, "cat": "NCLEX 10-ante...neonatal care", "stem": "syndrome? O A. “Children with Down syndrome are often afraid of strangers and have difficulty making friends.” O B. “At some point during their life, children with Down syndrome will need to be institutionalized.” O C. “Children with Down syndrome often become violent when they experience hormonal changes during puberty.” O D. “There is a broad spectrum of mental capabilities and physical characteristics in children with Down syndrome.”", "choices": [{"id": "a", "t": "“Children with Down syndrome are often afraid of strangers and have difficulty making friends.”"}, {"id": "b", "t": "“At some point during their life, children with Down syndrome will need to be institutionalized.”"}, {"id": "c", "t": "“Children with Down syndrome often become violent when they experience hormonal changes during puberty.”"}, {"id": "d", "t": "“There is a broad spectrum of mental capabilities and physical characteristics in children with Down syndrome.”"}], "correct": "d", "rationale": "The mental abilities of Down syndrome children range from severe intellectual disabilities to low average intelligence. Children with Down's syndrome also exhibit a wide range of physical characteristics.", "whyNot": {"a": "Children with Down syndrome are not necessarily afraid of strangers and often make friends with peers.", "b": "There is a range of intellectual disability with Down syndrome; not all individuals will need to be institutionalized.", "c": "This is not a true statement."}, "keyConcept": "Down syndrome is a chromosomal anomaly, occurring in about 1 in 700 to 800 births. It is caused by trisomy of chromosome 21, which leads to multiple a variety of characteristic manifestations. Down syndrome is the most common trisomy, accounting for about one-third of all moderate to severe mental handicaps in school-aged children. Clinical manifestations include a flat occiput and flattened facial appearance; small head; epicanthic folds at the inner angle of the eyes; flat nasal bridge; upward-slanting palpebral fissures; Brushfield spots (speckling of the iris); protruding tongue; small and dysplastic ears; and increased nuchal skin."}, {"id": 10552, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following findings on a newborn assessment should be reported by the nurse to the healthcare provider?", "choices": [{"id": "a", "t": "Heart rate of 120/min"}, {"id": "b", "t": "Respiratory rate of 35/min"}, {"id": "c", "t": "Sacral dimple"}, {"id": "d", "t": "Areas of purplish hyperpigmentation on the buttocks"}], "correct": "c", "rationale": "Al a | Asacral dimple should be reported to the healthcare provider for further evaluation. It may be caused by spina bifida occulta, which is a ec fF common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. A sacral dimple may D Hi represent a dermal sinus tract, or tract between the skin and the spinal cord. Assessment is needed. Some individuals may have variants of spina bifida occulta in which the spinal cord is tethered or split in two, which causes stretching and neurological damage. Others may have thickening of the nerve fibers at the base of the spinal cord. Spina bifida occurs in 10-20% of births, but many individuals with spina bifida occulta have no other significant findings or impairment.", "whyNot": {"a": "The normal heart rate for a newborn is 110-160/minute.", "b": "The normal respiratory rate in a newborn is 30-60/minute.", "d": "This describes Mongolian spots, a normal finding of purplish/blue pigmentation on the buttocks, back, or neck."}, "keyConcept": "Asacral dimple on a newborn assessment may represent spina bifida occulta, a common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. Other signs of spina bifida occulta include a hairy patch, hemangioma, dark red spot, or hypopigmented spot near the sacrum."}, {"id": 10553, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following findings on a newborn assessment should be reported by the nurse to the healthcare provider?", "choices": [{"id": "a", "t": "Heart rate of 120/min"}, {"id": "b", "t": "Respiratory rate of 35/min"}, {"id": "c", "t": "Sacral dimple"}, {"id": "d", "t": "Areas of purplish hyperpigmentation on the buttocks"}], "correct": "c", "rationale": "al 7 | Asacral dimple should be reported to the healthcare provider for further evaluation. It may be caused by spina bifida occulta, which is a ec fF common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. A sacral dimple may D Hi represent a dermal sinus tract, or tract between the skin and the spinal cord. Assessment is needed. Some individuals may have variants of spina bifida occulta in which the spinal cord is tethered or split in two, which causes stretching and neurological damage. Others may have thickening of the nerve fibers at the base of the spinal cord. Spina bifida occurs in 10-20% of births, but many individuals with spina bifida occulta have no other significant findings or impairment.", "whyNot": {"a": "The normal heart rate for a newborn is 110-160/minute.", "b": "The normal respiratory rate in a newborn is 30-60/minute.", "d": "This describes Mongolian spots, a normal finding of purplish/blue pigmentation on the buttocks, back, or neck."}, "keyConcept": "Asacral dimple on a newborn assessment may represent spina bifida occulta, a common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. Other signs of spina bifida occulta include a hairy patch, hemangioma, dark red spot, or hypopigmented spot near the sacrum."}, {"id": 10554, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following best describes the indications for performing an alpha-fetoprotein test?", "choices": [{"id": "a", "t": "To identify fetal neural tube defects"}, {"id": "b", "t": "To test fetal heart rate"}, {"id": "c", "t": "To identify infection in the amniotic sac"}, {"id": "d", "t": "To determine whether the placenta is in the correct location"}], "correct": "a", "rationale": "An alpha-fetoprotein test is performed on a pregnant woman to identify certain abnormalities in the fetus, including neural tube defects, congenital nephrosis, abdominal wall defects, and fetal anemia. Neural tube defects include spina bifida and anencephaly. Alpha-fetoprotein is produced by the fetal yolk sac, GI tract, and liver.", "whyNot": {"b": "The alpha-fetoprotein test does not check the heart rate of the fetus, A fetal heart rate monitor is used to measure fetal heart rate.", "c": "The alpha-fetoprotein test does not check for infection in the amniotic sac, known as chorioamnionitis. Culture of amniotic fluid is the", "d": "The alpha-fetoprotein does not determine the placement of the placenta. Ultrasound is used to visualize the placenta."}, "keyConcept": "Alpha fetoprotein is produced by the fetus but crosses the placenta. Maternal levels of alpha fetoprotein are tested as part of a triple screen in pregnant women. It is most accurate between the 16th and 18th week of gestation. High levels of AFP are associated with neural tube defects, including spina bifica and anencephaly. If screening tests are abnormal, further evaluation is warranted."}, {"id": 10555, "cat": "NCLEX 10-ante...neonatal care", "stem": "The nurse is developing a plan of care for a postpartum client. Which of the following considerations is most important when discussing whether oral contraceptive pills are the best method of contraception?", "choices": [{"id": "a", "t": "This is the client’s second child"}, {"id": "b", "t": "The client states she was forgetful about taking prenatal vitamins"}, {"id": "c", "t": "The client is five feet eight inches tall and weighs 145 pounds"}, {"id": "d", "t": "The client states she has had bad acne since delivery"}], "correct": "b", "rationale": "A If the client was forgetful when taking her prenatal vitamins, she may have difficulties with remembering to take oral contraceptive pills. The es — nurse should discuss the client’s intentions for birth control and add this fact to the plan of care.", "whyNot": {"a": "Itis the client’s decision whether or not she should take oral contraceptive pills. That the client is having a second child is not significant to", "c": "This client would not be considered overweight, so it would not be a factor for her when considering oral contraceptive pills.", "d": "Acne is usually decreased with the use of hormonal contraception and is not a contraindication."}, "keyConcept": "Oral contraceptive pills can contain estrogen and progestin or progestin alone (\"mini-pill\".) The efficacy of oral contraceptive pills in preventing pregnancy is very high, with a failure rate of only 2 per 100 years of use. This is one of the primary advantages associated with the use of oral contraceptive pills compared to other forms of contraception. With respect to risks, a variety of studies have shown evidence for an increase in thromboembolic events in women on oral contraceptives. In addition, there appears to be increased risk of breast cancer in nulliparous women who have taken the pill for ten or more years after beginning the pill when they were less than 25 years of age. Other side effects include some weight gain, fluid retention, and headache."}, {"id": 10556, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ) ATI? X se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 ) Qa * @ New x |. NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Monitoring the color and cry every 4 hours"}, {"id": "b", "t": "Feeding with a bottle every 3 hours"}, {"id": "c", "t": "Obtaining extracorporeal membrane oxygenation equipment."}, {"id": "d", "t": "Providing warm, humidified oxygen in a warm environment"}], "correct": "d", "rationale": "Transient tachypnea is a common cause of respiratory distress in the newborn that begins within the first hours after birth and usually resolves within 72 hours. In addition to signs of respiratory distress, it is characterized by hypoxia and a need for supplemental oxygen. The infant may require gavage feeding (through an NG tube) until the tachypnea resolves adequately for bottle or breastfeeding.", "whyNot": {"a": "The nurse should monitor the infant’s color and cry more often than every 4 hours.", "b": "The infant may not be able to eat by bottle as long as he has tachypnea.", "c": "The nurse does not need to consider ECMO in this situation; the infant requires oxygen for now."}, "keyConcept": "Transient tachypnea is a common cause of respiratory distress in the newborn that begins within the first hours after birth and usually resolves within 72 hours. In addition to signs of respiratory distress, it is characterized by hypoxia and a need for supplemental oxygen. The infant may require gavage feeding (through an NG tube) until the tachypnea resolves adequately for bottle or breastfeeding."}, {"id": 10557, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is preparing to give a newborn an injection of vitamin K in the nursery. The infant’s father is watching and asks, “What is that for?” Which response from the nurse is most accurate?", "choices": [{"id": "a", "t": "“Your baby is more susceptible to infection right now. This will help to protect him.”"}, {"id": "b", "t": "“This shot helps your baby to excrete more bilirubin, which will reduce the risk of jaundice.”"}, {"id": "c", "t": "“We have to ensure that his blood glucose levels are stable before we can send him to your room.”"}, {"id": "d", "t": "“This injection prevents bleeding as newborns have a higher risk.”"}], "correct": "d", "rationale": "al 2% Easy Vitamin K is administered to newborn infants because they do not make enough of the vitamin at birth to protect themselves from severe . Babies with Vitamin K deficiency bleeding (VKDB) can bleed into their intestines, or into the brain, which can lead to brain damage | © 1% and even death. Newborn infants may be at risk of bleeding in the brain or of hemorrhagic disorders if they cannot create vitamin K to help their blood clot. At birth, babies have very little vitamin K stored in their bodies because only small amounts pass to them through the @bD Ft 92% placenta from their mothers. The good bacteria that produce vitamin K are not yet present in the newborn’s intestines. Breast milk contains low amounts of vitamin K, so exclusively breastfed babies don’t get enough vitamin K from breast milk, alone.", "whyNot": {"a": "Vitamin K is given to a newborn to prevent bleeding disorders; it will not help to prevent infection in the baby.", "b": "The baby needs vitamin K to prevent internal bleeding; the vitamin K injection does not have an effect on the baby’s bilirubin level or", "c": "While checking blood glucose levels in a newborn is important, vitamin K helps prevent bleeding in the baby, and is not for control of"}, "keyConcept": "Early-onset vitamin K deficiency bleeding usually occurs during the first 24 hours after birth, in infants born to mothers who have been taking anticonvulsant or antituberculosis medication. Classic vitamin K deficiency bleeding usually occurs after 24 hours after birth in infants who have not received vitamin K injections at birth. It may present as late as the first week of life. Late-onset vitamin K deficiency bleeding s most common in breastfed infants who did not receive vitamin K prophylaxis at birth and usually occurs between age 2-12 weeks, although it can be seen as long as 6 months after birth. Npeot Wen t cars Craracteentics"}, {"id": 10558, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse has been assigned to care for a pregnant client who has been diagnosed with HELLP syndrome. Which of the following nursing interventions is most important when caring for this client?", "choices": [{"id": "a", "t": "Palpate the abdomen every 4 hours to check for masses or bleeding"}, {"id": "b", "t": "Increase IV fluids to avoid hypotension and shock"}, {"id": "c", "t": "Administer magnesium sulfate as ordered"}, {"id": "d", "t": "Keep the client in a supine position with the legs elevated"}], "correct": "c", "rationale": "A | % Hard HELLP syndrome is a severe form of preeclampsia. It most commonly occurs in the third trimester, but can develop earlier in the pregnancy B | B08 or in the first 48 hours postpartum. Preeclampsia is characterized by new onset hypertension and proteinuria. HELLP resolves with delivery, which is indicated in clients who have preeclampsia and HELLP with a platelet count < 100,000/L; if the client has progressive deterioration ec | 55% in hepatic or renal function; persistent and severe headaches, visual changes, epigastric pain, nausea, or vomiting; gestational age of 38 ; suspected placental abruption; severe fetal growth restriction; oligohydramnios; or nonreassuring fetal stress test. Magnesium sulfate is provided to reduce the risk of seizures, which occur with eclampsia. It may lower blood pressure slightly. Labetalol may be given to reduce blood pressure.", "whyNot": {"a": "A client with HELLP syndrome may have an enlarged liver and abdominal pain, but it is not necessary to palpate the abdomen repeatedly.", "b": "A client with HELLP syndrome is likely to have high blood pressure, not hypotension. Although hypertension is typical, some clients with", "d": "Elevation of the legs is not indicated."}, "keyConcept": "Signs of preeclampsia or eclampsia, such as edema, hyperreflexia, or seizures may be present in HELLP syndrome. Blood is drawn and sent to the laboratory for CBC with platelet count, liver enzymes, and coagulation studies, including PT/PTT/INR, and fibrinogen. Close monitoring is critical. Delivery is sometimes postponed to allow the fetus to mature. The decision is based on the condition of the mother and fetus and the gestational age of the fetus. When delivery is delayed because of early gestational age, a course of corticosteroids is usually prescribed for the mother, to promote fetal lung maturation."}, {"id": 10559, "cat": "NCLEX 10-ante...neonatal care", "stem": "the following conditions? O A. Missed abortion O B. Ectopic pregnancy O C. Placenta previa O D. Hydatidiform mole", "choices": [{"id": "a", "t": "Missed abortion"}, {"id": "b", "t": "Ectopic pregnancy"}, {"id": "c", "t": "Placenta previa"}, {"id": "d", "t": "Hydatidiform mole"}], "correct": "b", "rationale": "|UD is a device implanted in the uterus by a provider to prevent pregnancy. A complication of using this device is an increased risk for an OB a eave ectopic pregnancy. The manifestations of an ectopic pregnancy include unilateral lower quadrant pain that can occur either with or without bleeding. This should be reported immediately to the provider. c | 11% oi 9%", "whyNot": {"c": "A client who has placenta previa will present with painless, bright red bleeding during the second or third trimester of pregnancy.", "d": "A client who has a hydatidiform mole usually has dark brown vaginal bleeding during the second trimester that is not accompanied by"}, "keyConcept": "An intrauterine device (IUD) is a device that is inserted into the uterus by a provider and releases hormones to prevent pregnancy by preventing fertilization or thickening the cervical mucus. One potential complication of using an IUD an increased risk for ectopic pregnancy. An ectopic pregnancy is a pregnancy that is implanted outside of the uterus, such as in the fallopian tubes or abdominal cavity. A client who is experiencing an ectopic pregnancy presents with bright red bleeding and sharp abdominal pain. A client who is exhibiting these manifestations should be evaluated and treated immediately."}, {"id": 10560, "cat": "NCLEX 10-ante...neonatal care", "stem": "Convert study guide ® ATI? X % CLOSE { Browse Questions > iit Search Questions QJ Qa * @ New x {- NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Use a sterile gauze pad to apply light pressure to the area"}, {"id": "b", "t": "Notify the healthcare provider immediately"}, {"id": "c", "t": "Assess heart rate and oxygen saturation"}, {"id": "d", "t": "Place a tighter diaper on the infant to place pressure on the affected area"}], "correct": "a", "rationale": "Circumcision is a procedure often performed in the United States that is characterized by the removal of the foreskin or puce of the glans penis. The benefits of routine circumcision are unclear. The procedure is usually performed before discharge from the hospital. The infant is positioned on a plastic restraint form. Soap and water or a povidone-iodine prep are used to cleanse the penis, and the infant is draped to create a sterile field and to maintain body temperature. The procedure takes several minutes and is generally performed with minimal bleeding. A piece of petrolatum gauze is used as a dressing to prevent the diaper from adhering to the penis. A PlastiBell is sometimes used to apply direct pressure to prevent hemorrhage during circumcision. It remains in place and protects the area from infection or from adhering to the diaper. The rim remains in place for about a week before it falls off. The nurse should check the circumcision site for bleeding and normal voiding every hour for 12 hours after the circumcision. The immediate priority if bleeding occurs at the site is to apply light pressure to the area with a sterile gauze pad. Circumcision surgery Dorsal slit Foreskin", "whyNot": {"b": "After administering first aid to stabilize the bleeding lesion, the nurse should check vital signs and then notify the healthcare provider if", "c": "The initial priority is first aid for a bleeding lesion. After this has been administered, vital signs can be assessed.", "d": "Gelfoam powder or a sponge can be used to control bleeding, but the use of a folded sterile gauze pad is the initial step."}, "keyConcept": null}, {"id": 10561, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is 2 days postpartum who has 2800 mL of urine output over the past 24 hours. Which of the following does the nurse understand concerning the client’s postpartum urine output?", "choices": [{"id": "a", "t": "The client should restrict fluid intake."}, {"id": "b", "t": "The client has overflow due to urinary retention."}, {"id": "c", "t": "The client may have uterine atony."}, {"id": "d", "t": "Fluids should be encouraged."}], "correct": "d", "rationale": "mM | 16% Hard The client should be encouraged to increase her intake of fluids to prevent dehydration and to replace fluids that are lost at delivery. B | aoe Postpartum diuresis is normal in the initial 2-3 days after delivery and may exceed 3,000 mL/day. During this period, the blood volume decreases due to blood loss during childbirth, diaphoresis, and diuresis of excess fluid that is accumulated during the final period of c |__| 23% pregnancy. With elimination of the placenta, approximately 500 mL of blood is returned to the maternal circulation. The uterus also @ , which results in a return of additional blood to the maternal circulation. The nurse should assess the client’s ability to void regularly since urethral and/or perineal edema may cause difficulty voiding. Urinary retention can result in overflow, with frequent voiding of small amounts of urine.", "whyNot": {"a": "The client should be encouraged to increase oral intake of fluids to prevent dehydration and replace fluids lost during delivery.", "b": "Urinary retention can result in overflow, manifested by frequent voiding of small amounts of urine (usually less than 150 mL).", "c": "Bladder distention can result in uterine atony and may displace the uterine fundus to one side."}, "keyConcept": "Urine output in the postpartum client may initially exceed 3,000 mL/day, contributing to a decrease in maternal blood volume. Abnormal voiding patterns may indicate urethral or perineal edema, or urinary retention, often characterized by overflow of small volumes of urine with frequent voiding."}, {"id": 10562, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is 2 days postpartum who has 2800 mL of urine output over the past 24 hours. Which of the following does the nurse understand concerning the client’s postpartum urine output?", "choices": [{"id": "a", "t": "The client should restrict fluid intake."}, {"id": "b", "t": "The client has overflow due to urinary retention."}, {"id": "c", "t": "The client may have uterine atony."}, {"id": "d", "t": "Fluids should be encouraged. eck Answer"}], "correct": "d", "rationale": "mM | 16% Hard The client should be encouraged to increase her intake of fluids to prevent dehydration and to replace fluids that are lost at delivery. B | aoe Postpartum diuresis is normal in the initial 2-3 days after delivery and may exceed 3,000 mL/day. During this period, the blood volume decreases due to blood loss during childbirth, diaphoresis, and diuresis of excess fluid that is accumulated during the final period of c |__| 23% pregnancy. With elimination of the placenta, approximately 500 mL of blood is returned to the maternal circulation. The uterus also , which results in a return of additional blood to the maternal circulation. The nurse should assess the client’s ability to void regularly since urethral and/or perineal edema may cause difficulty voiding. Urinary retention can result in overflow, with frequent voiding of small amounts of urine.", "whyNot": {"a": "The client should be encouraged to increase oral intake of fluids to prevent dehydration and replace fluids lost during delivery.", "b": "Urinary retention can result in overflow, manifested by frequent voiding of small amounts of urine (usually less than 150 mL).", "c": "Bladder distention can result in uterine atony and may displace the uterine fundus to one side."}, "keyConcept": "Urine output in the postpartum client may initially exceed 3,000 mL/day, contributing to a decrease in maternal blood volume. Abnormal voiding patterns may indicate urethral or perineal edema, or urinary retention, often characterized by overflow of small volumes of urine with frequent voiding."}, {"id": 10563, "cat": "NCLEX 10-ante...neonatal care", "stem": "nurse use as a common indication for non-stress test (NST) in a pregnant client?", "choices": [{"id": "a", "t": "The client is 41 weeks gestation"}, {"id": "b", "t": "The client is 39 years old"}, {"id": "c", "t": "The client’s first child had Down syndrome"}, {"id": "d", "t": "The client had an abnormal ultrasound"}], "correct": "a", "rationale": "Anon-stress test (NST) is a procedure that is performed by attaching a fetal monitor to a pregnant client and recording the fetal heart rate B Hl ag: fo and activities; the mother pushes a button whenever she feels the baby move. Of the options provided, a NST would most likely be indicated for a pregnant client who is past her due date. | 3% ©", "whyNot": {"b": "The client’s age of 39 years puts her at higher risk of having a baby born with Down syndrome or another birth defect. This would warrant", "c": "This part of the client’s history would most likely warrant an amniocentesis, not an NST.", "d": "An abnormal ultrasound would not be followed with an NST; the client would most likely need an amniocentesis."}, "keyConcept": "A fetal non-stress test is a simple, non-invasive test performed in pregnancies at > 28 weeks gestation. No stress is placed on the fetus during the test. One monitor is placed on the mother’s abdomen to measure fetal heart rate and another is placed to measure contractions. Fetal movement, heart rate and the reactivity of the fetal heart rate to movement is measured for 20-30 minutes."}, {"id": 10564, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client with a fractured wrist who is 36 weeks pregnant. Which of the following assessment items should the nurse prioritize?", "choices": [{"id": "a", "t": "The client reports 3 contractions in the past hour."}, {"id": "b", "t": "The client has a hemoglobin of 12 g/dL."}, {"id": "c", "t": "The fetal heart rate is 210/min."}, {"id": "d", "t": "The fetus kicked 6 times in the past hour."}], "correct": "c", "rationale": "al 5% Easy 160 beats per minute for more than 10 minutes. This is the concerning item for the nurse. ec FY 90% Fetal tachycardia is associated with fetal hypoxia and fetal distress. In fetal movement, fetal tachycardia is a primary indicator of fetal health.", "whyNot": {"a": "Braxton Hicks contractions are painless and occur beginning in mid-pregnancy. They are a physiological response to the stretched uterus", "b": "Hemoglobin can decrease during pregnancy, resulting in a relative increase in plasma volume compared to the increase in red blood cells.", "d": "Fetal movement of 10 in 2 hours or 4 per hour is considered reassuring as an indicator of fetal health."}, "keyConcept": "Assessment of fetal health status includes assessment of fetal movement, including extent, timing, and any changes in the pattern of movement. Fetal heart rate can be detected early in pregnancy, and should be routinely assessed with a fetoscope for rate and rhythm. Fetal tachycardia may indicate fetal hypoxia or distress."}, {"id": 10565, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is in labor with cervical dilation of 5 cm. Which of the following findings on the assessment requires intervention by the nurse?", "choices": [{"id": "a", "t": "Contraction intensity of 45 mmHg"}, {"id": "b", "t": "Resting uterine tone of 10 mmHg"}, {"id": "c", "t": "Duration of contractions of 100 seconds"}, {"id": "d", "t": "Frequency of contractions every 4 minutes"}], "correct": "c", "rationale": "| 7% Normal uterine contractions in the active phase of the first stage of labor (which begins at some point when the cervix is dilated between 4-7 @c FY 75% cm) should not last longer than 90 seconds. The uterus contracts to dilate and efface the cervix while causing the fetus to descend. During , blood flow through the intervillous space and spiral arterioles can decrease, which places stress on the fetus. Typically, the length of uterine contraction is 40-70 seconds. During the active phase of the first stage of labor, contractions are more regular, at a frequency of 3-5 minutes. During this stage of labor, there is rapid dilation and effacement. Fetal descent begins. Maternal feelings of helplessness, anxiety, and restlessness often increase as the contractions become stronger.", "whyNot": {"a": "The intensity of contractions refers to the strength of contractions at the peak and should not exceed 80 mmHg. Contraction intensity", "b": "Resting tone refers to the tension in the uterine muscles between contractions. The tension averages 10 mmHg and should not exceed 20", "d": "The first stage of labor is characterized by 2-5 contractions every 10 minutes. Contractions should occur no more frequently than once"}, "keyConcept": "During normal labor, regular uterine contractions cause progressive dilation and effacement of the cervix, with descent and eventual expulsion of the fetus. The first stage consists of a latent phase and an active phase. The latent phase is characterized by gradual change in the cervix. The active phase is characterized by rapid cervical change. The active phase usually begins when the cervix is 5-6 cm dilated and lasts until complete cervical dilation. Uterine contractions during this stage should not last longer than 90 seconds. During contractions, blood flow through the placenta may decrease."}, {"id": 10566, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is providing teaching to a client who is initiating breastfeeding. Which of the following should the nurse relay to this client?", "choices": [{"id": "a", "t": "The breast should be dried before attempting feeding to facilitate latching."}, {"id": "b", "t": "The mother should always depress the breast tissue around the infant’s nose."}, {"id": "c", "t": "Itis preferable to offer only 1 breast each feeding."}, {"id": "d", "t": "The mother should awaken the baby at least every 3 hours during the day to feed."}], "correct": "d", "rationale": "A || 13% Moderate ry 20% Until the infant is feeding well and gains weight adequately, the mother should awaken the infant for feedings at least every 3 hours during c | 5% the day and every 4 hours at night. At this point, the infant can be fed on demand. Neonates usually require 8 to 12 feedings every 24 hours, eD | 62% although the feeding pattern varies among infants, with some feeding every 2-3 hours and others feeding every hour or so for up to 5 feedings, with a period of sleep for 3-4 hours between clusters of feedings.", "whyNot": {"a": "The mother can encourage feeding by expressing a small amount of colostrum or milk by hand and rubbing it on the nipple and areola.", "b": "The nurse should advise the mother that if the infant is unable to breathe, reflexes will cause the infant to move the head and pull back in", "c": "Itis preferable to feed from both breasts, spending approximately 15 to 20 minutes per breast, although some mothers nurse from only 1"}, "keyConcept": "Newborns should be awakened at least every three hours during the day and every 4 hours at night, until they are feeding well and gaining weight. Neonates require 8-12 feedings every 24 hours."}, {"id": 10567, "cat": "NCLEX 10-ante...neonatal care", "stem": "A client at 24 weeks gestation arrives with painless, bright red vaginal bleeding. Which of the following conditions does the nurse suspect in this client?", "choices": [{"id": "a", "t": "Abruptio placenta"}, {"id": "b", "t": "Placenta previa"}, {"id": "c", "t": "Premature rupture of membrane"}, {"id": "d", "t": "Rupture of the uterus"}], "correct": "b", "rationale": "All 13% Easy In placenta previa sudden painless, bright red vaginal bleeding occurs.", "whyNot": {"a": "In abruptio placenta dark red vaginal bleeding associated with severe pain occurs.", "c": "Premature rupture of membrane occurs beyond 37 weeks gestation and would show clear fluid with or without a mucus plug.", "d": "Rupture of the uterus can occur due to the stress resulting from labor contractions."}, "keyConcept": "Placenta previa is characterized by abnormal implantation of the placenta on the lower part of the uterus. As the cervix begins to dilate, the"}, {"id": 10568, "cat": "NCLEX 10-ante...neonatal care", "stem": "following? O A. Metabolism of brown adipose tissue O B. Increased shunting of blood to the skin surface O C. Decreased utilization of glycogen stores O D. Decreased shivering to keep warm", "choices": [{"id": "a", "t": "Metabolism of brown adipose tissue"}, {"id": "b", "t": "Increased shunting of blood to the skin surface"}, {"id": "c", "t": "Decreased utilization of glycogen stores"}, {"id": "d", "t": "Decreased shivering to keep warm"}], "correct": "a", "rationale": "Infants burn brown fat as a response to cold stress and there is increased utilization of glycogen and calorie stores. Hypoglycemia may occur C ] aon from stress as a result of a cold environment. om 13%", "whyNot": {"b": "Increased shunting of blood to the skin surface", "c": "The infant would utilize more glycogen stores in response to cold stress from the environment.", "d": "Newborn infants do not have the capacity to shiver. This is not a response to cold stress in the neonate."}, "keyConcept": "It is important to maintain constant body temperature in neonates. Hypothermia and hyperthermia are associated with increased morbidity and mortality. Non-shivering thermogenesis is the main source of heat production in the neonate. It refers to the production of heat by the metabolism of brown fat, which is deposited after 28 weeks gestation around the scapulae, kidneys, adrenals, neck, and axilla. The neonate’s response to a cold environment is constriction of superficial blood vessels to maintain heat in the core and prevent transmission of heat to the periphery. Superficial vasoconstriction results in a mottled appearance of the skin. If the neonate is not warmed then cold stress can occur, resulting in increased metabolic rate, leading to increased oxygen consumption; increased caloric consumption and decreased glycogen stores which can lead to hypoglycemia; development of acidosis due to pulmonary vasoconstriction; and thermal shock and disseminated intravascular coagulation, progressing to death"}, {"id": 10569, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in an antepartum clinic is providing teaching to a client who is at 38 weeks of gestation and has a new prescription for dinoprostone gel. Which of the following statements should the nurse include? O A.\"This medication promotes softening of the cervix.\" O B. \"This medication is used to treat preeclampsia.\" O C. \"This medication promotes relaxation of the uterine muscles.\" O D. \"This medication is used to treat cervical insufficiency.\"", "choices": [{"id": "a", "t": "Dinoprostone is used to prepare, or ripen, the cervix for the induction of labor in clients who are full term."}, {"id": "b", "t": "Magnesium sulfate is used to treat preeclampsia and prevent eclamptic seizures. Dinoprostone is not recommended for the treatment of"}, {"id": "c", "t": "Dinoprostone causes intensification, not relaxation, of uterine muscles. °"}, {"id": "d", "t": "Cervical insufficiency is painless cervical dilation which leads to recurrent preterm births. Treatment for cervical insufficiency is cerclage ="}], "correct": "a", "rationale": "Dinoprostone is used to prepare, or ripen, the cervix for the induction of labor in clients who are full term.", "whyNot": {"b": "Magnesium sulfate is used to treat preeclampsia and prevent eclamptic seizures. Dinoprostone is not recommended for the treatment of", "c": "Dinoprostone causes intensification, not relaxation, of uterine muscles. °", "d": "Cervical insufficiency is painless cervical dilation which leads to recurrent preterm births. Treatment for cervical insufficiency is cerclage ="}, "keyConcept": "Contraindications for labor induction include: » Hemorrhage + Placenta previa * Shoulder presentation + Acute fetal distress *Grand multiparity + Breech presentation"}, {"id": 10570, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following findings is unexpected when assessing a preterm newborn for cold stress?", "choices": [{"id": "a", "t": "Shivering"}, {"id": "b", "t": "Weak cry © c irritability"}, {"id": "d", "t": "Feeding difficulty"}], "correct": "a", "rationale": "Neonates have immature nervous systems and do not have adequate muscle tissue to generate heat by shivering. They are able to increase B | mer the metabolic rate and generate heat by nonshivering thermogenesis, using brown adipose tissue developed during the third trimester. After depletion of brown adipose tissue, nonshivering thermogenesis becomes less effective, resulting in cold stress in the neonate that can may c | 13% result in death. Preterm newborns have less brown adipose tissue stores than term infants, so they are at increased risk for cold stress. The ’s temperature to determine if the infant is cold. Cold stress causes increased oxygen and glucose demand and increased release of norepinephrine in order to generate heat. Hypoxia and acidemia occur when oxygenation is inadequate. If glucose stores are depleted, hypoglycemia will develop if the repletion of stores is impaired by poor intake and slow motility in the gastrointestinal tract. Cold stress is manifest by neurologic, cardiovascular, respiratory, gastrointestinal, and musculoskeletal changes as listed in the table below. Low body temperature is characteristic of cold stress.", "whyNot": {"b": "A weak cry is characteristic, and a weak suck may also be seen.", "d": "Feeding difficulties are characteristic of cold stress."}, "keyConcept": "Shivering is a method of heat generation, but neonates do not have adequate muscle mass to generate heat by shivering. They increase the metabolic rate and generate heat by using brown adipose tissue developed during the third trimester. Premature neonates have low stores of brown adipose tissue, which places them at greater risk of cold stress."}, {"id": 10571, "cat": "NCLEX 10-ante...neonatal care", "stem": "effective teaching? O A. Amniotic fluid volume O B. Size of the placenta O C. Amniotic fluid color O D. Fetal gestational age", "choices": [{"id": "a", "t": "Amniotic fluid volume"}, {"id": "b", "t": "Size of the placenta"}, {"id": "c", "t": "Amniotic fluid color"}, {"id": "d", "t": "Fetal gestational age"}], "correct": "a", "rationale": "The biophysical profile typically measures five parameters to assess the fetus: fetal breathing, movement, and tone; amniotic volume; and B I Ee fetal heart reactivity. The test uses a scale of 0 to 2 for each parameter with a maximum score of 10. I © 4%", "whyNot": {"b": "The biophysical profile does not measure the size of the placenta.", "c": "The biophysical profile does not consider the amniotic fluid color.", "d": "The biophysical profile does not measure the gestational age."}, "keyConcept": "A biophysical profile is a test performed in the third trimester to evaluate fetal health in cases where the pregnancy is considered high risk or when maternal or fetal signs and symptoms raise concerns. It consists of a fetal ultrasound and a nonstress test. The nonstress test monitors changes in fetal heart rate while the mother is at rest. The fetal ultrasound assess amniotic fluid volume, muscle tone, movement, and breathing."}, {"id": 10572, "cat": "NCLEX 10-ante...neonatal care", "stem": "Which of the following responses would the nurse expect to see from a client who is in the latent phase of labor?", "choices": [{"id": "a", "t": "Contractions every 5 to 10 minutes"}, {"id": "b", "t": "Contractions lasting 1 to 2 minutes"}, {"id": "c", "t": "Cervical dilation of 6 to 7 cm"}, {"id": "d", "t": "Cervical effacement of 80 percent"}], "correct": "a", "rationale": "@ ’s body is beginning to change for childbirth. During the latent stage, B B ne the nurse can expect to see contractions that are still several minutes apart and that last for 30 to 40 seconds. Cervical dilation is between 0 and 3 cm during the latent phase and effacement ranges from 0 to 40 percent. c | 13% of 11%", "whyNot": {"b": "During the latent phase of labor, contractions tend to last for only 30 to 40 seconds.", "c": "The latent phase of labor is an early phase. The nurse would expect to see cervical dilation between 0 and 3.cm.", "d": "The latent phase of labor is an early phase. The nurse would expect to see effacement between 0 and 40 percent."}, "keyConcept": "Labor begins when the mother feels regular contractions, which result in cervical dilation and effacement. Effacement refers to softening and thinning of the cervix, which allows the baby to enter the birth canal. The stages of labor include early or latent labor, which lasts until the cervix has dilated to 3 cm; the active phase, which lasts from the time the cervix is dilated 3 cm until the cervix has dilated to 7 cm; and the transition phase, which lasts from cervical dilation of 7 cm until the cervix has dilated to 10 cm. The first stage of labor is the longest stage, with an unpredictable length ranging from hours to days."}, {"id": 10573, "cat": "NCLEX 10-ante...neonatal care", "stem": "of the following best describes this type of pain control?", "choices": [{"id": "a", "t": "Intrathecal anesthesia"}, {"id": "b", "t": "Patient-controlled epidural"}, {"id": "c", "t": "Sphenopalatine nerve block"}, {"id": "d", "t": "Pudendal nerve block"}], "correct": "d", "rationale": "A | | 13% Moderate A pudendal nerve block can be used during labor to anesthetize the nerves that send pain messages from the vagina and perineum. This B I a type of block involves the injection of medication into the pudendal nerves, which pass near each ischial spine. A pudendal nerve block may be an option for pain control if a client needs an assisted delivery, such as with the use of forceps or an episiotomy. c | 6%", "whyNot": {"a": "Intrathecal anesthesia involves placing anesthetic medication into the fluid surrounding the spinal cord. The intrathecal administration", "b": "A client-controlled epidural involves injecting medication into the epidural space in the spine. The medication may be delivered at a", "c": "Asphenopalatine nerve block provides anesthesia to nerves of the face."}, "keyConcept": "During labor, the descent of fetus places pressure on the pelvic floor, vagina, and perineum, and generates pain that is transmitted by the pudendal nerve (S2-4). A pudendal block can be used to interrupt transmission of pain signals from these areas. The most commonly used anesthetic during childbirth is an epidural. An epidural is a regional nerve block that provides loss of sensation below the T8-T10 spinal level. Other analgesic/anesthetics used during labor include spinal analgesia, combination spinal and epidural analgesia, and general anesthesia."}, {"id": 10574, "cat": "NCLEX 10-ante...neonatal care", "stem": "A newborn with cephalohematoma is undergoing assessment. The parents complained about the condition of their newborn. Which of the following courses of action is appropriate for the nurse to take?", "choices": [{"id": "a", "t": "Call the doctor immediately"}, {"id": "b", "t": "Position the newborn in upright position"}, {"id": "c", "t": "Administer hot and cold compresses to the affected area"}, {"id": "d", "t": "Provide reassurance"}], "correct": "d", "rationale": "A || 12% Moderate Cephalohematoma is a condition in which there is a collection of blood between the skull and periosteum. It is usually caused by prolonged B | Ase labor and instrumental delivery. Providing reassurance and stating that the cephalohematoma will resolve after three weeks is appropriate. During such time, the blood clot is slowly reabsorbed from the periphery towards the center of the affected area. c | 2%", "whyNot": {"a": "Severe forms of this condition are associated with symptoms such as jaundice, anemia, and hypotension. If these other symptoms occur iT}", "b": "It is inappropriate to position the newborn client upright because of the baby's inability to maintain this position. It also predisposes the 3", "c": "Administering hot and cold compresses is inappropriate as the newborn’s thermal regulating system is immature and injury or trauma can <"}, "keyConcept": "Acephalohematoma is a hemorrhage between the skull and the periosteum. It can occur at any age, including in neonates as a result of rupture of the blood vessels crossing the periosteum. Boundaries of a cephalohematoma are limited by individual bones, in contrast to Caput succedaneum which is a collection of fluid or blood above the periosteum, between the scalp and lining of the periosteum, this collection crosses suture lines."}, {"id": 10575, "cat": "NCLEX 10-ante...neonatal care", "stem": "newborn? O A. When the mother is feeding the infant O B. When the father is not at home O C. When it is convenient for the family O D. When the nurse has extra time to spend visiting with the family", "choices": [{"id": "a", "t": "When the mother is feeding the infant"}, {"id": "b", "t": "When the father is not at home"}, {"id": "c", "t": "When it is convenient for the family"}, {"id": "d", "t": "When the nurse has extra time to spend visiting with the family"}], "correct": "c", "rationale": "A || 21% Moderate Productive relationships are formed when the nurse is willing to cooperate with the family’s schedule.", "whyNot": {"a": "The mother may be distracted when feeding the infant and the visit will not be as productive. D l 3%", "b": "The father should be included in the visit if possible.", "d": "This may not be at a time when it is convenient for the family and may impede learning."}, "keyConcept": "The home health nurse must balance scheduling difficulties with meeting the client's need for health care. Perinatal care comprises a"}, {"id": 10576, "cat": "NCLEX 10-ante...neonatal care", "stem": "fetal heart rate monitor reveals minimal variability and bradycardia. Which of the following tasks does the nurse anticipate?", "choices": [{"id": "a", "t": "Place the client in the knee-to-chest position"}, {"id": "b", "t": "Prepare for immediate cesarean delivery"}, {"id": "c", "t": "Prepare for forceps delivery"}, {"id": "d", "t": "Prepare to suction the neonate with an endotracheal tube below the vocal cords before first attempts at breathing"}], "correct": "b", "rationale": "A | | 25% Moderate This describes uterine rupture, a life-threatening emergency. It can be complete, which involves the uterine wall and peritoneal cavity, with OB sd aa internal bleeding. Uterine rupture can also be incomplete, which refers to the dehiscence of a scar after a prior cesarean birth. There may not be internal bleeding present with incomplete rupture. Risk factors include uterine trauma, including previous cesarean section; congenital c | 1% uterine abnormalities; polyhydramnios, multi-fetal gestation, and large for gestational age; hyperstimulation of the uterus, including ; forceps-assisted delivery, and external or internal version of the fetus. Oxytocin is used to stimulate uterine contractions, either to initiate or to augment labor.", "whyNot": {"a": "The Trendelenburg position is recommended for uterine rupture. The knee-to-chest position is recommended for uterine cord prolapse.", "c": "Forceps delivery is a risk factor for uterine rupture.", "d": "Meconium in the amniotic fluid is an indication for suctioning."}, "keyConcept": "Oxytocin is used to stimulate uterine contractions, either to initiate or to augment labor. It increases the risk of uterine rupture, particularly in women who have had a prior cesarean section. Oxytocin is administered by an infusion pump and the dose is typically increased until labor progress is normal, or strong contractions occur at two- to three-minute intervals. Uterine and fetal monitoring are required. Uterine tachysystole, which refers to more than 5 contractions in ten minutes, is an adverse effect that can result in fetal hypoxemia."}, {"id": 10577, "cat": "NCLEX 10-ante...neonatal care", "stem": "the following? O A. Beans O B. Steamed broccoli O C. Sour Cream O D. Corn", "choices": [{"id": "a", "t": "Beans"}, {"id": "b", "t": "Steamed broccoli"}, {"id": "c", "t": "Sour Cream"}, {"id": "d", "t": "Corn"}], "correct": "a", "rationale": "Protein intake is a concern for all who subscribe to vegetarian diets. Combining two incomplete proteins such as rice and beans to make a B ] a complete protein can improve the dietary intake of protein. c | 1% Protein is found in a variety of foods, including: © Beans and peas * Dairy products like cheese, greek yogurt, and milk ° Eges © Grains and vegetables (these generally provide less protein than is found in other sources) © Meats and poultry ¢ Nuts and seeds © Seafood (fish and shellfish) © Soy products", "whyNot": {"b": "Broccoli does not contain enough protein to meet the needs of a vegan diet. While vegetables such as broccoli are important, this is not", "c": "Sour cream does not contain enough protein to meet the dietary needs of this client. The rice should be combined with another good", "d": "While corn is important as a vegetable in the diet, it does not contain enough protein to meet this client’s dietary needs."}, "keyConcept": "Consumption of 75 to 100 grams of protein is recommended per day in pregnancy. Protein positively affects the growth of fetal tissue, including the brain. It is also necessary for the growth of breast and uterine tissue during pregnancy, and and in increasing blood volume. Pregnant women should also consume 400 mcg per day of synthetic folic acid from fortified foods (cereals and other grains), supplements, or both, in addition to consuming folate from foods from dietary sources; and 30 mg/day iron, beginning early in pregnancy"}, {"id": 10578, "cat": "NCLEX 10-ante...neonatal care", "stem": "contributing factor in the neonate's size at birth?", "choices": [{"id": "a", "t": "Placenta previa"}, {"id": "b", "t": "Cephalopelvic disproportion"}, {"id": "c", "t": "Maternal inactivity"}, {"id": "d", "t": "Warm climate"}, {"id": "e", "t": "None of the above"}], "correct": "a", "rationale": "eo. 46% Hard SGA or IUGR (intrauterine growth restriction) is a condition where the newborn is at or below the 10th percentile for weight on the newborn B ] Aen classification chart. This condition predisposes the client to instability in extrauterine life. Close monitoring and extra care are needed. Placenta previa causes SGA due to deficiency in fetal circulation, because the placenta is not implanted correctly or fully attached to the c | 4% uterus. SGA can result from maternal diseases such as hypertension; environmental factors such as exposure to X-rays; maternal ; or substance abuse. E | | 37%", "whyNot": {"b": "Cephalopelvic disproportion is usually caused by a large fetus and incompatibility of the maternal pelvis.", "c": "Maternal inactivity is not proven to cause SGA.", "d": "Warm climate is not proven to cause SGA."}, "keyConcept": "Small for gestational age is a term that describes an infant who is smaller than the usual amount for the number of weeks of pregnancy. SGA babies usually have birth weights below the 10th percentile for babies of the same gestational age. SGA is often the result of intrauterine growth restriction (IUGR). IUGR occurs when the fetus does not receive the necessary nutrients and oxygen for proper growth and development of organs and tissues. It can begin at any time in pregnancy. Early-onset IUGR is usually the result of chromosomal abnormalities, maternal disease, or severe problems with the placenta. Late-onset growth restriction (after 32 weeks) is usually related to other problems."}, {"id": 10579, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client with pregnancy-induced hypertension who is scheduled for a cesarean section. In which position should the nurse place the client before she is transferred to the delivery suite?", "choices": [{"id": "a", "t": "Supine"}, {"id": "b", "t": "Prone"}, {"id": "c", "t": "Left lateral"}, {"id": "d", "t": "Trendelenburg"}], "correct": "c", "rationale": "A Hi 18% Moderate Positioning client on her left side will take the pressure off the inferior vena cava and will increase blood return to the heart. 6%", "whyNot": {"a": "Positioning the client supine would place increased pressure on the inferior vena cava and should be avoided.", "b": "The client should not be positioned prone in this situation.", "d": "The client should not be positioned in Trendelenburg; this places too much pressure on the inferior vena cava from the weight of the baby."}, "keyConcept": "Cardiac output is increased in most of pregnancy, except the late phase, as a result of an increase in blood volume, body weight, and increased metabolism. During the late phase of pregnancy, the enlarged uterus impedes blood return to the heart. Pregnancy induced hypertension causes impaired blood flow to the fetus. Bedrest in the left lateral recumbent position can increase fetal blood flow, since the uterus is moved away from the maternal inferior vena cava and the right iliac artery. This causes spontaneous diuresis due to increased blood flow to the kidneys and increases blood flow to the heart, increasing the clients cardiac output."}, {"id": 10580, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a client who is suspected to have an ectopic pregnancy. Which of the following findings should the nurse identify as a manifestation of ectopic pregnancy?", "choices": [{"id": "a", "t": "No alteration in menses"}, {"id": "b", "t": "Shoulder pain"}, {"id": "c", "t": "Progesterone level higher than the expected reference range"}, {"id": "d", "t": "Report of severe leg cramps"}], "correct": "b", "rationale": ", which causes bleeding into the peritoneal cavity. The resulting collection OB TY car of blood can irritate the diaphragm and cause referred shoulder pain.", "whyNot": {"c": "A progesterone level that is lower than the expected reference range is an indication of ectopic pregnancy. During a typical developing", "d": "A client's report of severe leg cramps is a finding associated with thrombophlebitis during pregnancy."}, "keyConcept": "An ectopic pregnancy is a pregnancy that is implanted outside of the uterus, typically in one of the fallopian tubes. Manifestations of ectopic pregnancy usually present at 5 to 8 weeks of gestation and include abdominal pain, tenderness, and progesterone levels below the expected range. An ectopic pregnancy is considered an emergency and manifestations should be reported to the provider promptly. If left untreated, the fallopian tube can rupture, resulting in intra-abdominal hemorrhaging and decreased fertility."}, {"id": 10581, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse in the newborn nursery has just received report. Which of the following infants should the nurse see first?", "choices": [{"id": "a", "t": "Atwo day old who is lying quietly alert with a heart rate of 185"}, {"id": "b", "t": "Aone day old who is crying and has a bulging anterior fontanelle"}, {"id": "c", "t": "A 12-hour-old who is being held, with respirations that are 45 breaths per minute and irregular O D.A five hour old who is sleeping and whose hands and feet are blue bilaterally"}], "correct": "a", "rationale": "The normal heart rate for this age is 120 to 160 beats per minute. The other options are all normal for the age.", "whyNot": {"b": "A bulging fontanelle may appear with crying and is not considered abnormal. D | | 13%", "c": "Arespiratory rate of 45/minute in an infant is not abnormal; an infant’s breathing patterns may be irregular."}, "keyConcept": "The normal heart rate is 120 to 160 beats per minute in awake neonates but may decrease to 85 to 90 beats per minute during sleep. An abnormal heart rate may indicate sepsis or cardiac disease."}, {"id": 10582, "cat": "NCLEX 10-ante...neonatal care", "stem": "A nurse is caring for a neonate after delivery. Which of the following assessment items is most concerning for the nurse?", "choices": [{"id": "a", "t": "Dullness to percussion over the bladder"}, {"id": "b", "t": "Single testicle palpated"}, {"id": "c", "t": "Auscultation of bilateral wheezes"}, {"id": "d", "t": "Ptosis of the left eyelid"}], "correct": "d", "rationale": "A l 3% Hard cy | 7% At birth, any cranial nerve abnormality is concerning. The eyelids should sit symmetrically above the pupils, with the irises visible. Ptosis Cc | 63% refers to drooping of the eyelid below the level of the pupil and may indicate paralysis of the oculomotor nerve. Among the choices given, eD | | 27% this finding is concerning and should be assessed. Infants should blink to light and should be able to close both eyes tightly when crying. The corneal reflex can be tested by gently touching the cornea with a tissue paper. Sucking, swallowing, and tongue movement should be observed to test cranial nerves V, VII, IX, X, and XII.", "whyNot": {"a": "Neonates void shortly after birth. Until they do, dullness to percussion over the bladder is a normal finding.", "b": "An undescended testicle at birth is not concerning since most testes that are undescended will descend spontaneously by the age of 6", "c": "Immediately after birth, a neonate must transition to extrauterine life. This includes a transition from the fetal cardiovascular system."}, "keyConcept": "Aneurological assessment of a newborn after delivery includes assessment of level of alertness, muscle tone, cranial nerves and reflexes. Facial asymmetry, including drooping eyelid, is concerning for a cranial nerve impairment."}, {"id": 10583, "cat": "NCLEX 10-ante...neonatal care", "stem": "€ > G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ X Sx Reco X M Inbo x M Inbo. x [] Untii x Untii x (4 Goor x @ TEAS x Onlir x € Mark x @ Micr x (ee Teel @ atii x % CLOSE { Browse Questions > iit Search Questions QJ Qa * @ New x {- NCL x x» * 2 '1@0 + Finish update", "choices": [{"id": "a", "t": "Heart rate"}, {"id": "b", "t": "Muscle tone"}, {"id": "c", "t": "Respiratory effort"}, {"id": "d", "t": "Presence of vernix caseosa"}], "correct": "d", "rationale": "Assessing for the presence of vernix caseosa is not included in calculating Apgar scores.", "whyNot": {"a": "Heart rate is assessed for obtaining Apgar scores, along with muscle tone, respiratory effort, reflex irritability and color.", "b": "An infant’s muscle tone is one of the assessments performed as part of obtaining the Apgar score.", "c": "The infant’s respiratory effort is one of the assessments performed as part of obtaining the Apgar score."}, "keyConcept": "The diagram pictured below illustrates the factors scored when using Apgar scores to describe neonatal well-being at one and five minutes after birth. (Taken on tat min and Sth min of Iie and lator # necessary fowbom baby on fe sienplo criteria on a scale from zero to two, |} ——_ then summing up the fve values | ‘determined by evaluating the thus obtained = Wow Ready )__ vt J [bs This Chas"}, {"id": 10584, "cat": "NCLEX 10-ante...neonatal care", "stem": "fetal lung maturity? O A. Alpha-fetoprotein (AFP) test O B. Lecithin/sphingomyelin (L/S) ratio test O C. Kleihauer-Betke test O D. Chorionic villus sample test", "choices": [{"id": "a", "t": "Alpha-fetoprotein (AFP) test"}, {"id": "b", "t": "Lecithin/sphingomyelin (L/S) ratio test"}, {"id": "c", "t": "Kleihauer-Betke test"}, {"id": "d", "t": "Chorionic villus sample test"}], "correct": "b", "rationale": "A || 32% Moderate Atest of the L/S (lecithin/sphingomyelin) ratio is determined by amniocentesis. The test is used to determine fetal lung maturity. A sample of OB rid ae: fo the amniotic fluid is analyzed to identify presence of surfactant. Surfactant is needed by the fetal lungs to keep the alveoli from collapsing and to promote gas exchange. © I i) oii 8%", "whyNot": {"a": "The AFP (alpha-fetoprotein) test is used to assess for fetal neural tube defects or chromosome disorders and is performed at around 15", "c": "The Kleihauer-Betke test measure the amount of fetal hemoglobin transferred to the maternal circulation, usually after trauma. It is", "d": "A chorionic villus test requires a sample of the placenta to check for chromosomal abnormalities of the fetus."}, "keyConcept": "Amniocentesis is an invasive procedure performed in women who are in preterm labor to determine fetal well-being and evaluate fetal lung maturity. Amniotic fluid is aspirated during the procedure and sent for determination of the lecithin/sphingomyelin (L/S) ratio. This test identifies the presence of surfactant, which the fetal lungs need to promote gas exchange and prevent alveoli from collapsing."}], "nclex_11_audio_questions": [{"id": 10585, "cat": "NCLEX 11- Audio Questions", "stem": "previously. Which of the following is the most likely pathogen associated with the child's diagnosis? BOARD @& VITALS\" __—— f\\ o———“___ goto THE MEDICAL SPECIALTY QUESTION BANKS E ey 100}", "choices": [{"id": "a", "t": "Streptococcal infection ° ="}, {"id": "b", "t": "Parainfluenza virus infection g ° ="}, {"id": "c", "t": "Mononucleosis c a"}, {"id": "d", "t": "Klebsiella infection zy"}, {"id": "e", "t": "Cryptococcal infection"}], "correct": "b", "rationale": "‘i 25% Hard Acute croup is the most common cause of acute stridor in children. Croup is most commonly caused by parainfluenza virus, primarily types 1 @B 43% and 2. Other viral causes can include influenza A and B, measles, adenovirus, and respiratory syncytial virus (RSV). Croup causes a ° inflammation and edema of the larynx, trachea, and large bronchi, leading to airway obstruction of varying degrees. This can prompt c | ™% increased work of breathing and stridor. A \"steeple\" sign may be visible on AP views of the subglottic airway. D i 10% E 14%", "whyNot": {"a": "Streptococcal infection is characterized by sore throat and headache. It is not associated with stridor or wheezing.", "c": "Mononucleosis is characterized by sore throat, headache, lethargy, and fatigue, among other signs and symptoms.", "d": "Klebsiella can infect the body at multiple sites. If it affects the respiratory system, it most commonly leads to pneumonia which results in"}, "keyConcept": null}, {"id": 10586, "cat": "NCLEX 11- Audio Questions", "stem": "The audio clip below demonstrates which of the following sounds? BOARD @& VITALS\" __—— f\\ o———“___ 00:10 THE MEDICAL SPECIALTY QUESTION BANKS D> : ey", "choices": [{"id": "a", "t": "Rhonchi iii]"}, {"id": "b", "t": "Wheezing ¢ 8"}, {"id": "c", "t": "Rales ES = a"}, {"id": "d", "t": "Stridor &"}, {"id": "e", "t": "Normal lung sounds SJ"}], "correct": "b", "rationale": "A || 13% Moderate Wheezing sounds like a continuous whistling sound produced in the airways during breathing. The sound of wheezing is most obvious when OB a oa exhaling. It is caused by some part of the respiratory tree being narrowed or obstructed. Wheezing is commonly experienced by persons with ° lung disease; the most common causes of wheezing are asthma and COPD. c | 5% oi 22%", "whyNot": {"a": "Rhonchi. Rhonchi is also know as course crackles. Rhonchi are thick, wheeze-like, sonorous type sounds. Rhonchi occur most commonly", "c": "Rales. Rales are also known as fine crackles. They usually sound like bubbling or fine rattling. Rales occur most commonly with heart", "d": "Stridor is a high pitched sound that is usually easily heard even without a stethoscope.", "e": "Normal lung sounds."}, "keyConcept": null}, {"id": 10587, "cat": "NCLEX 11- Audio Questions", "stem": "What is the most common cause of the cardiac murmur heard in the audio clip? BOARD @& VITALS” Oe 0:05 THE MEDICAL SPECIALTY QUESTION BANKS : ey", "choices": [{"id": "a", "t": "Mitral valve prolapse"}, {"id": "b", "t": "Mitral stenosis"}, {"id": "c", "t": "Aortic regurgitation"}, {"id": "d", "t": "Ventricular septal defect"}], "correct": "a", "rationale": "co. ia 31% — Hard Mitral valve prolapse (MVP) is the most common cause of a late systolic murmur. It begins right after a mid-systolic click and runs to the end B | FE of systole. MVP is enhanced by standing and Valsalva maneuvers and decreased by squatting. This is because maneuvers like Valsalva ° decrease the volume of the left ventricle and cause the prolapse to occur sooner and more severely. In contrast, anything that increases c | 33% venous return and diastolic filling like squatting increases the ventricular volume to maintain tension along the chordae and to keep the D || 13% valve shut. MVP is usually heard best at the apex.", "whyNot": {"b": "Mitral stenosis causes a diastolic murmur.", "c": "Aortic regurgitation is a diastolic murmur.", "d": "Ventricular septal defect causes a harsh, holosystolic murmur."}, "keyConcept": null}, {"id": 10588, "cat": "NCLEX 11- Audio Questions", "stem": "Convert study guide (J ATI? X % CLOSE { Browse Questions > iit Search Questions Qa * @ New x | NCL x x» * 93 '!1@0 + Finish update & Highlight ~ & Calculator Figure/Media The extra heart sound heard in the audio below in a 73-year-old is consistent with which of the following diagnoses? BOARD @& VITALS” Oe 0:05 THE MEDICAL SPECIALTY QUESTION BANKS", "choices": [{"id": "a", "t": "Arrhythmia"}, {"id": "b", "t": "Heart failure"}, {"id": "c", "t": "Aortic stenosis"}, {"id": "d", "t": "Mechanical heart valve"}], "correct": "b", "rationale": "The third heart sound, or S3, is an extra heart sound that occurs soon after the normal (S1 and S2) heart sounds and is associated with heart failure. S3 may be a normal finding in people under 40 years of age and some trained athletes but should disappear before middle age. It is caused by increased atrial pressure leading to increased flow rates and inflowing blood against a distended or noncompliant ventricle in mid-diastole. In patients over 40 years of age, the S3 sound is considered pathognomic for heart failure.", "whyNot": {"a": "The recording is typical of a regular rhythm with an $3, and the rate is within normal limits. It does not represent an arrhythmia.", "c": "Aortic stenosis is characterized on auscultation by a soft or normal S1, diminished or absent A2, paradoxical splitting of S2, prominent $4,", "d": "Normal mechanical valves have a loud and high-frequency metallic closing sound with a soft opening sound. Alternatively, they may have"}, "keyConcept": null}], "nclex_12_cardiovascular": [{"id": 10589, "cat": "NCLEX 12- Cardiovascular", "stem": "110/65 mmHg sitting with a heart rate of 100/min. Which of the following tasks should the nurse perform next?", "choices": [{"id": "a", "t": "Check the client’s blood pressure and pulse while standing."}, {"id": "b", "t": "Document normal orthostatic blood pressure and pulse."}, {"id": "c", "t": "Assess the client’s neurological function with finger-to-nose testing and heel-to-toe walking."}, {"id": "d", "t": "Anticipate administration of intravenous crystalloid solution."}], "correct": "d", "rationale": "Hard Correct Answer: D. Anticipate administration of intravenous crystalloid solution. A | Givi ce | 9% Orthostatic blood pressure and pulse measurement should be performed with the client supine, sitting, then standing, allowing 2 minutes c | 1% between each change of position. A drop in systolic blood pressure of 20 mmHg or more or a drop in diastolic blood pressure of 10 mmHg or ev im 24% more between positions reflects a positive test for orthostatic or postural hypotension. The heart rate usually rises 20 beats per minute or more with orthostasis. Orthostatic hypotension results from significant volume loss or dehydration, usually at least 25% of blood volume. The body’s compensatory loss in response to fluid deficit is vasoconstriction, preventing blood from pooling in the extremities when the individual is upright. This allows perfusion of the heart and brain. With significant blood loss or volume loss, the body’s compensatory mechanisms are overwhelmed. The clinical manifestations of postural hypotension include dizziness, syncope, blurred vision, and weakness.", "whyNot": {"a": "This client has demonstrated postural hypotension, and further testing may result in a fall.", "b": "A drop in systolic blood pressure of 20 mmHg or more or a drop in diastolic blood pressure of 10 mmHg or more between positions reflects", "c": "The priority is fluid replacement. Although neurologic testing should be performed, this client should not be walking since orthostatic"}, "keyConcept": "Orthostatic hypotension refers to a significant drop in blood pressure (20 mm Hg systolic, 10 mm Hg diastolic) or increase in heart rate > 20/minute when the client's blood pressure or heart rate is measured while supine, then while sitting or standing. It usually represents significant volume loss, although it may represent a medication effect that blunts normal postural reflexes."}, {"id": 10590, "cat": "NCLEX 12- Cardiovascular", "stem": "xX Ss Recc X M Inbo x M Inbo x [Ej Untii x Untii x (4 Goo x @ TEAS X Onli x €& Mark xX @ Micr x Convert study guid: @ alli x @New x | NCL xX + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "On discharge from the hospital"}, {"id": "b", "t": "On discharge from the cardiac care unit"}, {"id": "c", "t": "On admission to the hospital"}, {"id": "d", "t": "4 weeks after the onset of illness"}], "correct": "c", "rationale": "| 2% Easy Abasic principle of rehabilitation, including cardiac rehabilitation, is that rehabilitation begins on hospital admission. Early rehabilitation is B | Ee important to promote maximum functioning ability as the client recovers.", "whyNot": {"a": "The client will need discharge instructions when he leaves the hospital; however, discharge planning should begin upon admission.", "b": "The client may need to know some discharge instructions when he is moved from the cardiac care unit, but discharge planning should", "d": "The client should know discharge instructions before 4 weeks after the onset of illness. Discharge instructions should begin upon"}, "keyConcept": "Cardiac rehabilitation (cardiac rehab) refers to individualized outpatient programs of exercise and education that are designed to help clients improve their health and facilitate recovery from myocardial infarction, other forms of heart disease or cardiac surgery. Cardiac rehab includes exercise training, emotional support, and education about lifestyle changes to reduce the risk of recurrent cardiac events. Lifestyle changes may include the adoption of a heart-healthy diet, maintenance of a healthy weight, and smoking cessation. Cardiac rehab goals include prevention of progressive worsening of the condition; reduction of the risk of future cardiac events; and improvement of strength, health, and quality of life."}, {"id": 10591, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who just returned from cardiac catheterization. Which of the following is an appropriate nursing intervention for this client?", "choices": [{"id": "a", "t": "Encourage ambulation"}, {"id": "b", "t": "Limit motion of the affected extremity"}, {"id": "c", "t": "Place a warm compress on the puncture site"}, {"id": "d", "t": "Place the client in a side-lying position"}], "correct": "b", "rationale": "All 13% Easy Indications for coronary catheterization include acute coronary syndrome, pre-operative coronary assessment, evaluation of aortic stenosis, Cc l 3% mitral valve regurgitation; and coronary/hemodynamic evaluation in congestive heart failure. Depending upon the procedure, . Complications of coronary catheterization can include dysrhythmia, stroke, bleeding, vascular injury, contrast reaction, air embolism, thromboemboli, pulmonary edema and vagal stimulation with bradycardia. The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. a © o 2 ° s a = a < The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less. Movement is discouraged immediately after catheterization since the puncture site may hemorrhage.", "whyNot": {"a": "The site should be protected by placing the client in the supine position with the extremity straightened. Movements should be", "c": "The puncture site should be protected. Warm compresses facilitate hemorrhage. Sandbags or pressure bandages are used to promote", "d": "The client should be in the supine position with the extremity extended and the head at no more than 30 degrees of elevation."}, "keyConcept": "The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less."}, {"id": 10592, "cat": "NCLEX 12- Cardiovascular", "stem": "following actions should the nurse take first?", "choices": [{"id": "a", "t": "The nurse should give the drug at a dose of 0.125 mg."}, {"id": "b", "t": "The nurse should obtain a serum digoxin level before giving the drug."}, {"id": "c", "t": "The nurse should hold the prescribed dose and notify the healthcare provider."}, {"id": "d", "t": "The nurse should order an ECG."}], "correct": "c", "rationale": "5% Digoxin is a cardiac glycoside, a drug that has a variety of effects that include cardiac inotropy, electrophysiological effects on conduction, ec | 92% and reduction of sympathetic nervous system activation. It has a narrow therapeutic window, which means that toxicity can occur at doses . Digoxin must be monitored closely. Adverse cardiac effects range from heart block to atrial or ventricular tachycardia. If the client has bradycardia, the provider must be notified when the heart rate is below 60 in order to determine if treatment should continue or if the dose should be held. Digoxin slows conduction through the atrioventricular node (AV node) and slows the sinoatrial node, which can result in severe bradycardia or sinoatrial block in clients who have preexisting sinus node disease or heart block.", "whyNot": {"a": "The nurse should assess the client and contact the healthcare provider before giving the dose or changing the dosage. The nurse cannot", "b": "Although obtaining a serum digoxin level is used to determine if the client has a toxic digoxin level, the immediate priority is to notify the", "d": "Although it is important to order an ECG in some cases to determine if the bradycardia is a function of heart block and requires pacing, the"}, "keyConcept": "Digoxin is a cardiac inotrope with electrophysiological effects on cardiac conduction. It must be closely monitored with measurement of serum levels, since toxicity can occur close to therapeutic levels. Digoxin is primarily excreted through the kidneys, so the dose may require adjustment in renal failure. Dose may require adjustment in the elderly and in other individuals with lean body mass. There are significant potential drug interactions that can increase the serum level and may cause toxicity."}, {"id": 10593, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide (J ATI? X % CLOSE { Browse Questions > iit Search Questions", "choices": [{"id": "a", "t": "Flatness of the jugular vein"}, {"id": "b", "t": "Decreased urine output"}, {"id": "c", "t": "Crackles on lung exam"}, {"id": "d", "t": "S3 heart sound"}], "correct": "a", "rationale": "Congestive heart failure results from dilated cardiomyopathy with left ventricular failure, resulting in decreased cardiac output. In the early stages of cardiomyopathy, the heart rate increases and the muscle of the ventricle increases in size, but when decompensation occurs, findings on assessment include: ° Cough ¢ Shortness of breath © Crackles on auscultation of lungs © Chest pain ° Fatigue © Pitting edema e Jugular venous distention ° Enlarged liver © S3 or S4heart murmur e Syncope An echocardiogram shows diminished contractility and enlarged chambers. ECG may show left ventricular hypertrophy. Treatment can include oxygen, beta-blockers, cardiac inotropes (dobutamine), and diuretics. Flatness of the jugular vein would reflect improvement from an exacerbation and an appropriate response to therapy.", "whyNot": {"b": "Diuretics increase urine output.", "c": "Crackles in the lungs indicate fluid overload and would not be a sign of medication efficacy with a diuretic.", "d": "An $3 heart sound is associated with congestive heart failure."}, "keyConcept": "Furosemide (Lasix) is a loop diuretic often used in management of congestive heart failure. Diuretics relieve fluid overload by increasing the volume of urine. When assessing response to diuretic therapy, the nurse should monitor daily weight, intake and output ratios, amount and location of edema, reduction of jugular venous distention, lung sounds, skin turgor, and mucous membranes."}, {"id": 10594, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client with peripheral artery disease. Which of the following is a sign of intermittent claudication?", "choices": [{"id": "a", "t": "Dependent edema"}, {"id": "b", "t": "Pain with activity"}, {"id": "c", "t": "Pain with rest that is relieved by walking"}, {"id": "d", "t": "Skin discoloration at the ankles"}], "correct": "b", "rationale": ". It is Cc || 24% characterized by diminished pulses in one extremity with signs of arterial insufficiency. Intermittent claudication refers to pain in a specific D i 9% muscle group that is caused by activity and relieved with rest. It is caused by ischemia due to inadequate blood flow to the contracting muscles. The degree of muscle pain experienced by clients with peripheral artery disease (PAD) will depend upon the amount of arterial stenosis, the level of activity, and whether collateral circulation has developed. Peripheral artery disease can affect the arms, buttocks, thighs, or lower legs. Clinically, more severe manifestations of chronic peripheral artery disease are ischemic ulcers, rest pain, and gangrene.", "whyNot": {"a": "Peripheral edema may be the result of venous, not arterial, insufficiency.", "c": "This describes rest pain, which occurs as peripheral arterial disease progresses.", "d": "Venous stasis can result in discoloration of the skin. It is not a characteristic of intermittent claudication."}, "keyConcept": "Peripheral arterial disease is usually caused by build up of cholesterol plaques (arteriosclerosis) and most commonly affects the lower extremities, resulting in clinical signs of inadequate perfusion, including diminished pulses, loss of hair, and cool skin in the affected extremity. Intermittent claudication is the result of inadequate blood flow to contracting muscles and refers specifically to pain that increases with activity and is relieved by rest."}, {"id": 10595, "cat": "NCLEX 12- Cardiovascular", "stem": "After receiving morning laboratory results, the nurse will need to intervene for which of the following clients?", "choices": [{"id": "a", "t": "A client with end-stage liver disease and elevated ammonia level"}, {"id": "b", "t": "A client receiving warfarin with an INR of 2.0"}, {"id": "c", "t": "A client with heart failure who has a digoxin level of 2.4 ng/mL"}, {"id": "d", "t": "A client with myocardial infarction and elevated CK-MB"}], "correct": "c", "rationale": "A | | 8% Moderate Digoxin is a cardiac glycoside used for the treatment of congestive heart failure and atrial fibrillation. Therapeutic levels are 0.8-2 ng/L. Toxic B I a levels are >2 ng/L. Toxic effects of digoxin are most likely to occur in clients with hypokalemia, hypomagnesemia, hypoxia, hypercalcemia, and heart disease. Toxicity results in exaggeration of the pharmacological effect, including tachyarrhythmia and bradyarrhythmia. Clinical ec | 12% signs include nausea, vomiting, headache, disorientation, seizures, and hallucinations. A typical visual change associated with digoxin D Hi 15% toxicity is seeing yellow or yellow-green halos around objects. There has been speculation that Vincent Van Gogh experienced digoxin toxicity.", "whyNot": {"a": "Elevated ammonia levels are an expected finding in end-stage liver disease; although it is important to address this finding, it is not", "b": "Warfarin is a vitamin K-dependent anticoagulant. Efficacy is monitored by the PT and INR. This is an expected finding. Depending on the", "d": "CK-MB is a cardiac isoenzyme released from a damaged myocardium. Elevation of cardiac isoenzymes is expected in myocardial"}, "keyConcept": "Digoxin is used for treatment of congestive heart failure and atrial fibrillation. Digoxin levels must be monitored carefully, as toxic effects occur with levels of more than 2 ng/L and may occur at lower levels in clients with coexisting hypokalemia, hypercalcemia, hypomagnesemia, hypoxia, and heart disease."}, {"id": 10596, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide (J ATI? X @ New x | NCL X + v Qx we XO! @O Finish update : Tutorial: BoardVitals NCLEX Prep RN Module: Quizzes & Assignments ati Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Prepare to administer amiodarone"}, {"id": "b", "t": "Prepare for cardioversion"}, {"id": "c", "t": "Prepare to assist the physician with endotracheal intubation"}, {"id": "d", "t": "Administer keterolac IV as ordered"}], "correct": "b", "rationale": "The client has unstable wide complex tachycardia, so immediate cardioversion is indicated.", "whyNot": {"a": "Amiodarone is a medication used to treat cardiac arrhythmias. If the client is unstable, immediate cardioversion is indicated.", "c": "The client is still breathing on his own; he may need intubation if he becomes unresponsive and is unable to protect his airway or if he", "d": "Ketorolac is an anti-inflammatory pain medication that can be given IV; however, it is not indicated in this situation."}, "keyConcept": "When evaluating a client with tachycardia (heart rate greater than 100 BPM) and symptoms of poor perfusion, it's important to determine if the client’s rhythm is causing poor perfusion and subsequent symptoms. Unstable tachycardia refers to tachycardia in which the client’s rate and rhythm are causing signs and symptoms of cardiovascular compromise and signs of poor perfusion, including hypotension, altered mental status, or ischemic chest pain. Immediate cardioversion is indicated."}, {"id": 10597, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing community education about risk factors for coronary vascular disease (CVD). Which of the following would be considered an example of a non-modifiable risk factor for heart disease?", "choices": [{"id": "a", "t": "High blood pressure"}, {"id": "b", "t": "Age"}, {"id": "c", "t": "Cholesterol"}, {"id": "d", "t": "Pre-diabetes"}], "correct": "b", "rationale": "| 2% Easy Advancing age increases the risk of heart disease. Age is considered to be a non-modifiable risk factor for the development of the disease. OB rs cei", "whyNot": {"a": "High blood pressure is a risk factor for heart disease but it is considered a modifiable risk factor.", "c": "Cholesterol is considered a modifiable risk factor for heart disease in that the affected person can make changes that will affect", "d": "The presence of pre-diabetes is considered a risk factor for diabetes, but it is a modifiable risk factor."}, "keyConcept": "Non-modifiable risk factors for heart disease include age, family history, ethnicity, and gender. Men are three to five times as likely as women to have CVD. A positive family history of a first-degree relative with coronary artery disease is generally associated with a twofold increase in the risk for CVD. African-Americans, Native Americans, and Asians are at higher risk compared to Americans of European descent."}, {"id": 10598, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing community education about risk factors for coronary vascular disease (CVD). Which of the following would be considered an example of a non-modifiable risk factor for heart disease?", "choices": [{"id": "a", "t": "High blood pressure"}, {"id": "b", "t": "Age"}, {"id": "c", "t": "Cholesterol"}, {"id": "d", "t": "Pre-diabetes eck Answer"}], "correct": "b", "rationale": "| 2% Easy Advancing age increases the risk of heart disease. Age is considered to be a non-modifiable risk factor for the development of the disease. B rs cei", "whyNot": {"a": "High blood pressure is a risk factor for heart disease but it is considered a modifiable risk factor.", "c": "Cholesterol is considered a modifiable risk factor for heart disease in that the affected person can make changes that will affect", "d": "The presence of pre-diabetes is considered a risk factor for diabetes, but it is a modifiable risk factor."}, "keyConcept": "Non-modifiable risk factors for heart disease include age, family history, ethnicity, and gender. Men are three to five times as likely as women to have CVD. A positive family history of a first-degree relative with coronary artery disease is generally associated with a twofold increase in the risk for CVD. African-Americans, Native Americans, and Asians are at higher risk compared to Americans of European descent."}, {"id": 10599, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is preparing to apply thigh-length antiembolic stockings to a client. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Measure the length of both legs from the tip of the great toe to the widest part of the thigh."}, {"id": "b", "t": "Measure the circumference of each thigh at a point 7.6 cm (3 in) above the knee cap."}, {"id": "c", "t": "Select a stocking size that is one size larger than the client's measurements indicate."}, {"id": "d", "t": "Apply the stockings first thing in the morning before the client gets out of bed."}], "correct": "d", "rationale": "A || 24% Moderate The nurse should apply the antiembolic stockings first thing in the morning and, if possible, before the client gets out of bed. When the legs B | mar are in a dependent position, such as in a standing or sitting position, the veins can become distended resulting in edema. The stockings should be applied before this occurs. c | 3%", "whyNot": {"a": "For thigh-length antiembolic stockings, the nurse should measure both legs from the heel to the gluteal fold.", "b": "For thigh-length antiembolic stockings, the nurse should measure both thighs at the widest point of the thigh.", "c": "The nurse should compare the client's measurements to the size chart and select the correct size stocking. Stockings that are too large will"}, "keyConcept": "The nurse should be able to complete proper measurements, select the correct stockings size, and apply antiembolic stockings to a client. Antiembolic stockings are applied for the following purposes: + To facilitate venous return from the lower extremities + To prevent venous stasis and deep vein thrombosis (DVT) * To reduce peripheral edema"}, {"id": 10600, "cat": "NCLEX 12- Cardiovascular", "stem": "following complications should the nurse suspect?", "choices": [{"id": "a", "t": "Retroperitoneal bleeding"}, {"id": "b", "t": "Cardiac tamponade"}, {"id": "c", "t": "Bleeding from the incisional site"}, {"id": "d", "t": "Sepsis"}], "correct": "c", "rationale": "im | 14% Easy The nurse should suspect that bleeding is occurring from the incision site and draining under the client. The nurse should check the incision B | aI site for hematoma, apply pressure, monitor the client's vital signs, and notify the provider.", "whyNot": {"a": "The nurse should identify that manifestations of retroperitoneal bleeding can include tachycardia and hypotension. Retroperitoneal", "b": "The nurse should identify that manifestations of cardiac tamponade can include chest pain, dyspnea, and hypotension and involves", "d": "The nurse should identify that manifestations of sepsis can include tachycardia, hypotension, dyspnea, and elevated temperature, rather"}, "keyConcept": "Acardiac catheterization is an invasive procedure used to diagnose cardiovascular disease and to evaluate the function of the left or right side of the heart and coronary arteries. Before the procedure, clients should receive testing, such as ECGs, CBCs, coagulation studies, renal function studies, and chest X-rays. The nurse should ask the client about an allergy to iodine or shellfish because a contrast agent is used during a left heart catheterization. Preprocedure nursing care includes taking a complete set of vital signs, listening to the client's lungs, and checking the client's peripheral pulses. The nurse should confirm that the client has been NPO for 8 hr prior to the procedure. The nurse should confirm that informed consent for the procedure is obtained. The nurse might administer a sedative to the client to reduce the client's anxiety prior to the procedure. During the cardiac catheterization, the client will have one or two IVs lines to administer fluids and medications. The client's ECG, pulse oximetry, and blood pressure are continuously monitored, and the client is instructed to report any chest pain, pressure, or shortness of breath. Resuscitation equipment should be available in case the client develops a myocardial infarction, dysrhythmias, or any hemodynamic instability. After the procedure, the client should remain on bedrest for 2 to 6 hr and should keep the extremity of the insertion site straight to decrease the risk for bleeding and hematoma formation. The nurse should check the client's vital signs every 15 min for 1 hr, then every 30 min for 2 hr as per facility protocol until the client is stable. The nurse should frequently check the client's pulses, temperature and color on the affected extremity, and the insertion site for bleeding or a hematoma and report any changes. The nurse should also check the client for evidence of"}, {"id": 10601, "cat": "NCLEX 12- Cardiovascular", "stem": "A client is receiving cilostazol (Pletal) for peripheral arterial disease causing intermittent claudication. The nurse determines this medication is effective when the client reports which of the following? O A.\"lam having less back pain.\" O B. \"I do not have headaches anymore.\" O C. \"lam able to walk further without leg pain.\" O D. \"My toes are turning grayish black.\"", "choices": [{"id": "a", "t": "Peripheral arterial disease causes pain mainly in the leg muscles."}, {"id": "b", "t": "Headaches may occur as a side effect of this drug."}, {"id": "c", "t": "| 2% Easy Cilostazol is indicated for management of intermittent claudication."}, {"id": "d", "t": "Peripheral arterial disease causes decreased blood supply to the peripheral tissues and may cause gangrene of the toes; the drug is"}], "correct": "c", "rationale": "| 2% Easy Cilostazol is indicated for management of intermittent claudication. Symptoms usually improve within 2 to 4 weeks of therapy. It inhibits B | 3\" aggregation of platelets.", "whyNot": {"a": "Peripheral arterial disease causes pain mainly in the leg muscles.", "b": "Headaches may occur as a side effect of this drug.", "d": "Peripheral arterial disease causes decreased blood supply to the peripheral tissues and may cause gangrene of the toes; the drug is"}, "keyConcept": "Peripheral arterial disease is caused by atherosclerotic plaque formation, usually in the arteries that perfuse the tissues of the leg and foot. Intermittent claudication refers to ischemic pain that occurs with exertion, relieved with rest. Rest pain indicates more severe peripheral arterial disease. It occurs due to poor perfusion that is relieved by placing the legs in the dependent position."}, {"id": 10602, "cat": "NCLEX 12- Cardiovascular", "stem": "factors for coronary artery disease should be the focus of the teaching plan for this client?", "choices": [{"id": "a", "t": "Gender"}, {"id": "b", "t": "Family history OcpM"}, {"id": "d", "t": "Cigarette smoking"}], "correct": "d", "rationale": "10% The nurse’s teaching plan should focus on modifiable risk factors. The risk factors for coronary heart disease (CHD) are age >50 in men and c | 5% post-menopause in women, male gender, family history of CHD in a first-degree relative age <50 (male) or <60 (female), hypertension, e@D fs 85% dyslipidemia, obesity, and cigarette smoking. Coronary heart disease risk equivalents are noncoronary atherosclerotic disease, including peripheral artery disease, carotid artery disease, and abdominal aortic aneurysm; diabetes mellitus; and chronic kidney disease. The non- modifiable risk factors for this client include gender and family history. He is not obese. Only cigarette smoking is a modifiable risk factor. a © o 2 ° s a = a <", "whyNot": {"a": "Although male gender increases the risk of CHD, this risk factor cannot be modified.", "b": "Family history is a non-modifiable risk factor for CHD."}, "keyConcept": null}, {"id": 10603, "cat": "NCLEX 12- Cardiovascular", "stem": "prevent an air embolism in this case? Type of Complication Nursing Interventions Hemorrhage Keep stopcocks closed, monitor tubing Embolism Clot Use heparin-coated catheters, flush regularly Infection Maintain sterile technique", "choices": [{"id": "a", "t": "Monitor site dressing for drainage"}, {"id": "b", "t": "Keep patient in Trendelenburg during insertion"}, {"id": "c", "t": "Ask the patient to cough every 4 hours"}, {"id": "d", "t": "Flush with saline, followed by heparin, every shift 100} 2 = o 2"}], "correct": "b", "rationale": "* An air embolism develops when air enters a large blood vessel and produces a gas bubble within the circulation. An air embolism can cause OB rd Om an occlusion if it becomes lodged within a blood vessel and prevents blood flow. The nurse can take measures to prevent an air embolism ° during insertion of a pulmonary artery catheter by placing the client in the Trendelenburg position. This position, with the head down, c |_| 18% decreases the risk of air entering circulation. D Hl 27%", "whyNot": {"a": "Monitor site dressing for drainage. This would provide an early alert for bleeding but would not prevent embolus.", "c": "Ask the patient to cough every four hours. This would not prevent embolism.", "d": "Flush with saline, followed by heparin, every shift. This would keep the line patent but would not prevent an embolism."}, "keyConcept": "Apulmonary artery catheter is usually a multilumen catheter, 110 cm long, with extra connecting tubes for attachment to a pressure transducer. The PA lumen or distal lumen is at the tip. A 1.5-cc balloon is located proximal to the tip. A thermistor used to measure temperature changes for calculation of cardiac output is approximately four cm proximal to the balloon. Two additional lumens usually are present 19 cm and 30 cm from the tip. Depending on the degree of right heart enlargement and the position of the catheter, they reside within the right ventricle, right atrium, or the superior vena cava."}, {"id": 10604, "cat": "NCLEX 12- Cardiovascular", "stem": "xX Ss Recc X M Inbo x M Inbo x [Ej Untii x Untii x (4 Goo x @ TEAS X Onli x €& Mark xX @ Micr x Convert study guid: @ alli x @New x | NCL xX + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Ischemic infarction"}, {"id": "b", "t": "Transmural infarction"}, {"id": "c", "t": "Subendocardial infarction"}, {"id": "d", "t": "Hypoxemia infarction"}], "correct": "b", "rationale": "Atransmural infarction describes a myocardial infarction injury that penetrates the entire wall of the myocardium. This term is used to OB | cesar classify the type of heart attack that has occurred, as a myocardial infarction is classified according to its location and the depth of the muscle penetrated. c |_| 16% p| 2%", "whyNot": {"a": "While a myocardial infarction involves an ischemic injury, this is not the term used in this situation.", "c": "Asubendocardial infarction only penetrates the inner part of the heart muscle during a heart attack, not the entire heart muscle.", "d": "This is not a term used to classify a myocardial infarction."}, "keyConcept": "Current terminology for acute coronary syndrome includes unstable angina (UA), non-ST elevation MI (NSTEMI), and ST elevation MI (STEMI). STEMI is usually characterized by complete occlusion of a major epicardial coronary artery, resulting in necrosis of the full thickness of the myocardium, from the endocardium through the myocardium to the epicardium."}, {"id": 10605, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide ® ATI? X @ New x {- NCL x aP v Qa * Finish update : x» *o!1@0 Tutorial: BoardVitals NCLEX Prep RN Module: Quizzes & Assignments ati Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Hypertension is an important risk factor for heart disease and stroke."}, {"id": "b", "t": "This is the incorrect statement and indicates a need for additional teaching."}, {"id": "c", "t": "Hypertension is often asymptomatic, which is why it is often called “the silent killer.”"}, {"id": "d", "t": "Various conditions and medications can lead to secondary hypertension, including thyroid disease, certain medications, congenital blood"}, {"id": "e", "t": "Eating too many foods high in sodium can cause fluid retention, which increases blood pressure."}], "correct": "b", "rationale": "This is the incorrect statement and indicates a need for additional teaching. Primary hypertension often develops slowly over months and years. Secondary hypertension tends to appear suddenly and causes a higher blood pressure than does primary hypertension.", "whyNot": {"a": "Hypertension is an important risk factor for heart disease and stroke.", "c": "Hypertension is often asymptomatic, which is why it is often called “the silent killer.”", "d": "Various conditions and medications can lead to secondary hypertension, including thyroid disease, certain medications, congenital blood", "e": "Eating too many foods high in sodium can cause fluid retention, which increases blood pressure."}, "keyConcept": "Primary HTN is caused by a combination of genetic and environmental factors. Secondary HTN develops as a result of an underlying disorder, such as sleep apnea or pheochromocytoma. Older age and African American ethnicity increase the risk of hypertension. Other factors that influence development of primary hypertension include family history, increased body weight, sedentary lifestyle, vitamin D deficiency, excess sodium intake, and stress."}, {"id": 10606, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is preparing to place a peripheral IV cannula for administration of a medication. Which of the following sites should the nurse select initially ?", "choices": [{"id": "a", "t": "Veins in the foot"}, {"id": "b", "t": "Veins in the scalp"}, {"id": "c", "t": "Veins in the leg"}, {"id": "d", "t": "Veins in the hand"}], "correct": "d", "rationale": ", forearm, or antecubital fossa as first choices for a peripheral IV in an adult.", "whyNot": {"a": "Veins in the foot are typically used when no other veins are available in an adult, or as a primary site in an infant. e@D fF 95%", "b": "The nurse would use a scalp vein in an infant, not in an adult.", "c": "Leg veins are typically not used for IV catheter insertion."}, "keyConcept": "Peripheral IV lines are usually started at the most peripheral site that is available and appropriate for the infused fluid or medication. Cannulation of a distal site allows a more proximal site if the initial attempt fails. If a proximal vein is attempted initially, with a second attempt to start an IV distal to the site, the fluid may leak from the injured proximal vessel. The veins on the dorsum of the hand are usually selected because they are easily accessible. If the nurse is unable to start an IV on the dorsum of the hand, the next preferred site is the veins of the forearm and then the median cubital vein that crosses the antecubital fossa. For infusion of large volumes of fluid in clients who have undergone trauma, it is common to go directly to the median cubital vein as the first choice because it will accommodate a large bore IV and it is usually easy to catheterize."}, {"id": 10607, "cat": "NCLEX 12- Cardiovascular", "stem": "basis. What additional screening would you expect this client to get after his annual primary care appointment, based on his risk factors?", "choices": [{"id": "a", "t": "Acomplete blood count"}, {"id": "b", "t": "HIV screening"}, {"id": "c", "t": "Colorectal cancer screening"}, {"id": "d", "t": "A glucose tolerance test"}], "correct": "d", "rationale": "A Hl 20% Moderate In addition to the lipid level screening, you would expect this client to have the oral glucose tolerance test, fasting blood glucose, or random B | 3\" blood glucose level to evaluate possible diabetes since the client has a random blood glucose level of 180 after meals and he is also affected with an ethnicity and weight that place him at risk for diabetes. There is no indication that this client is at risk for HIV or colorectal cancer, c | 4% therefore, those screenings are not necessary. @D fT 73%", "whyNot": {"b": "This client does not have risk factors for HIV infection; this test is not indicated.", "c": "This client is not necessarily at high risk of developing colorectal cancer at this time; this test is not the highest priority."}, "keyConcept": "Diabetes mellitus refers to disorders of abnormal carbohydrate metabolism that are characterized by hyperglycemia and a relative or absolute impairment in insulin secretion, with a range of abnormalities in peripheral resistance to the action of insulin. A random blood glucose of >200 mg/dL on two separate tests is diagnostic of diabetes."}, {"id": 10608, "cat": "NCLEX 12- Cardiovascular", "stem": "The nurse is giving discharge instructions to a client returning home after a myocardial infarction. The nurse should instruct the client about gradually increasing exercise guided by which of the following vital signs?", "choices": [{"id": "a", "t": "Respiratory rate"}, {"id": "b", "t": "Heart rate"}, {"id": "c", "t": "Blood pressure"}, {"id": "d", "t": "Oral temperature"}], "correct": "b", "rationale": "A | % Moderate Following a myocardial infarction, the client will be prescribed a program of exercise that should be guided by heart rate. The nurse should OB Td 78% instruct the client about how to accurately count the heart rate using the carotid pulse. Exercise should be decreased if the client develops ° shortness of breath, if the pulse increases by more than 25 beats per minute, or if the heart rate goes above 120 beats per minute. c |_| 14% D 0%", "whyNot": {"a": "Respiratory rate is not a reliable indicator of cardiac function with exercise since the client may become short of breath even if cardiac", "c": "Blood pressure changes would be a late sign of problems since blood pressure changes more slowly than heart rate with exercise.", "d": "Temperature is unrelated to cardiac function with exercise."}, "keyConcept": "Cardiac rehabilitation programs include both education and exercise. The goals of cardiac rehab are to improve cardiovascular function; improve overall health and quality of life; reduce symptoms; and reduce the risk of future heart problems. A client who is beginning an exercise program should be instructed to monitor heart rate and to gradually increase exercise guided by a target heart rate. The client should immediately stop exercise is angina occurs."}, {"id": 10609, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is reviewing the laboratory findings of a client who had a myocardial infarction (Ml). The nurse should identify that which of the following cardiac enzymes can confirm the MI occurred ten days ago?", "choices": [{"id": "a", "t": "Creatinine kinase MB"}, {"id": "b", "t": "Creatinine phosphokinase"}, {"id": "c", "t": "Troponin T"}, {"id": "d", "t": "Myoglobin"}], "correct": "c", "rationale": "A Hi 11% Moderate An elevated troponin T level indicates myocardial injury and can remain elevated for 10 to 14 days following an MI. B | a0", "whyNot": {"a": "Creatinine kinase MB levels can indicate cardiac muscle injury due to an elevation 3 to 6 hr after an MI. The levels return to the expected", "b": "Creatinine phosphokinase levels can indicate cardiac or skeletal muscle injury due to an elevation 4 to 8 hr after an MI. The levels return to", "d": "An elevated myoglobin level can indicate skeletal or cardiac muscle injury. The level would be elevated within 3 hr after the injury and"}, "keyConcept": "Early diagnosis and intervention for an acute MI can reduce the risk for significant myocardial damage. Troponin is a myocardial muscle protein that is released specifically in response to myocardial injury. Troponin levels can elevate within 4 to 6 hr after an infarction, peak at 10 to 24 hr, and last up to 14 days following the injury. Nursing care for a client who has chest discomfort includes checking the client's vital signs, inserting a peripheral IV, obtaining a 12-lead ECG, and administering nitroglycerin, aspirin, or opioids to the client as prescribed. The nurse should provide the client with supplemental oxygen and recheck the client's vital signs and pain level every 5 min."}, {"id": 10610, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse in the emergency department is caring for a client who has sustained an open fracture of the femur in a motor vehicle collision. Which of the following types of shock is most likely in this client?", "choices": [{"id": "a", "t": "Cardiogenic"}, {"id": "b", "t": "Hypovolemic"}, {"id": "c", "t": "Neurogenic"}, {"id": "d", "t": "Anaphylactic eck Answer"}], "correct": "b", "rationale": "A fractured femur, especially an open fracture, can lead to significant blood loss. The most likely type of shock is hypovolemic shock due to hemorrhage.", "whyNot": {"c": "A fractured femur does not cause neurogenic shock.", "d": "Anaphylactic shock is caused by an allergic reaction, not a fractured femur."}, "keyConcept": null}, {"id": 10611, "cat": "NCLEX 12- Cardiovascular", "stem": "A client with angina shows the nurse the nitroglycerin tablets (Nitrostat) that he carries in a plastic bag in his pocket. Where should the nurse advise the client to store his nitroglycerin tablets?", "choices": [{"id": "a", "t": "The refrigerator"}, {"id": "b", "t": "Acool moist place"}, {"id": "c", "t": "A dark container to shield it from light O D.A plastic pill container that is readily available eck Answer"}], "correct": "c", "rationale": "| 2% Easy Nitroglycerin in all forms (sublingual, transdermal, or intravenous) should be shielded from light to prevent deterioration.", "whyNot": {"a": "Nitroglycerin does not need to be refrigerated. D i 10%", "b": "Nitroglycerin does not need to be kept in a cool, moist place. iii]"}, "keyConcept": "< Nitroglycerin is used for treatment of angina. It produces a vasodilator effect on the peripheral veins and arteries and reduces cardiac oxygen demand by decreasing preload. Nitroglycerin also dilates coronary arteries and improves the collateral flow to ischemic regions of the heart. Onset of action is 1-3 minutes."}, {"id": 10612, "cat": "NCLEX 12- Cardiovascular", "stem": "@ @ % Viral x x Recc xX ™M Inbo X M Inbo x [J Untit x Untii x (4 Goo x @ TEAS x Onlir x € Mark x @ Micr x (Geet eenicl @ Alli x @New x | NCL X + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Grapefruit juice"}, {"id": "b", "t": "Spinach"}, {"id": "c", "t": "Black licorice"}, {"id": "d", "t": "Ham"}], "correct": "c", "rationale": "Digoxin is an antiarrhythmic medication which also acts as a cardiac inotrope. Cardiac inotropes increase the contractility of the heart. Digoxin is used to treat clients with heart failure and/or atrial fibrillation. It slows conduction through the atrioventricular (AV) node of the heart, reducing the heart rate. Digoxin serum levels must be closely monitored since toxicity can occur outside a narrow therapeutic range. The therapeutic range is 0.8 - 2 ng/mL.", "whyNot": {"a": "A client who takes digoxin does not need to avoid grapefruit juice, as this does not cause a reaction with the medication.", "b": "There is no need for a client who takes digoxin to avoid spinach.", "d": "There is no need for a client who takes digoxin to avoid ham."}, "keyConcept": "Digoxin is an antiarrhythmic medication which also acts as a cardiac inotrope. Cardiac inotropes increase the contractility of the heart. Digoxin is used to treat clients with heart failure and/or atrial fibrillation. It slows conduction through the atrioventricular (AV) node of the heart, reducing the heart rate. Digoxin serum levels must be closely monitored since toxicity can occur outside a narrow therapeutic range. The therapeutic range is 0.8 - 2 ng/mL."}, {"id": 10613, "cat": "NCLEX 12- Cardiovascular", "stem": "xX Ss Recc X M Inbo x M Inbo x [Ej Untii x Untii x (4 Goo x @ TEAS X Onli x €& Mark xX @ Micr x Convert study guid: @ alli x @New x | NCL xX + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Upper half of the artery, near the chin"}, {"id": "b", "t": "Lower half of the artery, at the level of the cricoid cartilage."}, {"id": "c", "t": "Outer aspect of the artery, toward the back of the neck"}, {"id": "d", "t": "Inner aspect of the artery, toward the trachea"}], "correct": "b", "rationale": "‘i 30% Hard When palpating the carotid artery, the nurse should check the pulse on the lower half of the artery, at the level of the cricoid cartilage. ec ia 29% Palpating the artery too high on the neck could result in stimulation of the carotid sinus, which could cause a drop in the heart rate. ci 10%", "whyNot": {"a": "The nurse should palpate the carotid artery in the lower half of the artery, closer to the clavicle. Palpating the carotid artery high on the", "c": "The nurse must assess the lower half of the artery.", "d": "The nurse must assess the lower half of the artery."}, "keyConcept": "When assessing the carotid artery, the nurse will palpate one side at a time, gently tilting the head to relax the sternomastoid muscle. The carotid artery is palpated by placing the fingers near the client's upper neck between the sternomastoid and trachea at the level of the cricoid cartilage."}, {"id": 10614, "cat": "NCLEX 12- Cardiovascular", "stem": "intervention by the nurse? O A. Encourage the client to drink at least 1000 mL/day O B. Provide parenteral rehydration therapy prescribed by the physician O C. Turn and reposition every 2 hours O D. Monitor vital signs every shift", "choices": [{"id": "a", "t": "Encourage the client to drink at least 1000 mL/day"}, {"id": "b", "t": "Provide parenteral rehydration therapy prescribed by the physician"}, {"id": "c", "t": "Turn and reposition every 2 hours"}, {"id": "d", "t": "Monitor vital signs every shift"}], "correct": "b", "rationale": "all 10% Easy Initially, replenish the extracellular fluid volume with isotonic IV fluids until adequate circulating blood volume and renal perfusion are OB Tt~s~SY ers achieved. c| 2%", "whyNot": {"a": "Oral fluid intake should be greater than 1,000 mL/day.", "c": "Turning and repositioning the client at regular intervals aids the prevention of skin breakdown, but it is first necessary to rehydrate the", "d": "Vital signs should be taken and monitored as parental and oral rehydration are achieved."}, "keyConcept": "The gastrointestinal tract is a common source of fluid loss. Severe dehydration refers to volume loss of 10% or more and can result in hypovolemic shock. Severe fluid volume deficit requires emergent IV therapy with rapid infusion of isotonic fluid."}, {"id": 10615, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse in the emergency department is caring for a client who has sustained a pelvic fracture in a motor vehicle collision. Which of the following would be a sign of hypovolemic shock in this client?", "choices": [{"id": "a", "t": "Distended neck veins"}, {"id": "b", "t": "An apical pulse rate of 140 BPM"}, {"id": "c", "t": "Ablood pressure of 170/100 mm Hg"}, {"id": "d", "t": "A urine output of 70 ml per hour"}], "correct": "b", "rationale": "All 10% Easy Tachycardia is a compensatory mechanism in the early stages of hypovolemic shock in which the body attempts to increase blood flow to eB TY 75% fo the organs. ci 10%", "whyNot": {"a": "This is a sign of fluid volume excess, not loss of volume.", "c": "Blood pressure decreases, not increases, due to loss of blood volume", "d": "Urine output decreases below 30 ml per hour as decreased blood volume causes decreased glomerular filtration rate."}, "keyConcept": "Hypovolemic shock usually occurs as a result of rapid blood loss (hemorrhage.) It refers to a condition in which rapid fluid loss results in multiple organ failure due to inadequate circulating blood volume and inadequate perfusion. Tachycardia occurs early, as a compensatory measure to increase cardiac output and to improve perfusion. When compensatory mechanisms are overwhelmed, blood pressure and urine output decrease. The client will have signs and symptoms that reflect organ dysfunction, including mental status change due to decreased perfusion of the brain."}, {"id": 10616, "cat": "NCLEX 12- Cardiovascular", "stem": "intervention that the nurse should provide?", "choices": [{"id": "a", "t": "Tilt the victim’s head back and perform a chin lift to open the airway"}, {"id": "b", "t": "Tilt the victim’s head back and perform a jaw thrust to open the airway"}, {"id": "c", "t": "Deliver two mouth-to-mouth rescue breaths"}, {"id": "d", "t": "Begin chest compressions"}], "correct": "d", "rationale": "| 13% Easy High quality CPR is the most important initial action when a person is unresponsive and in cardiac arrest. Providers should begin rapid, high- B I Ee quality chest compressions at a rate of 100 times per minute in an unresponsive, pulseless individual. Only after delivering chest | © 1% compressions should the nurse open the airway and deliver mouth-to-mouth rescue breaths.", "whyNot": {"a": "The nurse should begin with chest compressions.", "b": "The nurse should begin with chest compressions.", "c": "The nurse should first provide chest compressions before opening the airway and giving rescue breaths."}, "keyConcept": "If unable to palpate a pulse within 10 seconds, the nurse should initiate chest compressions. Quality chest compressions should be hard and fast, at a depth of at least 2\" in adults. Between compressions, there should be complete chest recoil. Interruptions in compressions should be minimized. If another provider is available, the nurse and provider should rotate roles for chest compressions to minimize fatigue and ensure adequate compression."}, {"id": 10617, "cat": "NCLEX 12- Cardiovascular", "stem": "reporting to the healthcare provider?", "choices": [{"id": "a", "t": "The client has a blood pressure of 150/90 mmHg."}, {"id": "b", "t": "The client has a heart rate of 68/min, down from 80/min."}, {"id": "c", "t": "The client has wheezing on auscultation."}, {"id": "d", "t": "The client has a headache."}], "correct": "c", "rationale": "all 6% Easy cm 1% Propranolol is a nonselective beta blocker that affects both beta-1 and beta-2 receptors throughout the body. It is used to treat high blood ec | 80% pressure, essential tremor, and symptoms of “stage fright.” Beta-1 receptors are primarily found in the heart, and blocking them will reduce . Beta-2 receptors are found in the smooth muscle of the bronchial airways, and beta-2 blockade constricts the airways, so nonselective beta blockers are not the best choice of medication for those clients with chronic lung disease, such as COPD or asthma.", "whyNot": {"a": "It may take several days before the blood pressure impacts of propranolol take maximum effect.", "b": "Propranolol is a negative inotropic drug, which means that it slows the heart rate. This is expected. The nurse should monitor for further", "d": "Lightheadedness may occur with initiation of beta blocker therapy. Other adverse effects include fatigue and impotence."}, "keyConcept": "Propranolol is a nonselective beta blocker that affects both beta-1 and beta-2 receptors throughout the body, including the heart and bronchial airways. It is used to treat high blood pressure, essential tremor, and symptoms of “stage fright\". The action of propranolol on the beta 2 receptors in the airways causes constriction, so it is not the best choice for clients with lung disorders like asthma or COPD."}, {"id": 10618, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a client who has heart failure about increasing dietary potassium. The nurse should instruct the client that which of the following food selections contains the highest amount of potassium?", "choices": [{"id": "a", "t": "1 medium apple"}, {"id": "b", "t": "1 medium baked potato © ©. 1 cup of raw green grapes"}, {"id": "d", "t": "1 large scrambled egg"}], "correct": "b", "rationale": "All Amedium baked potato is the best food source of potassium because it contains 941 mg potassium per serving. es a", "whyNot": {"a": "One medium apple contains 195 mg potassium. The nurse should recommend a different food because another choice contains more D I", "d": "One large egg scrambled contains 81 mg potassium per serving. The nurse should recommend a different food because another choice"}, "keyConcept": "Clients who have heart failure and take loop or thiazide diuretics can develop hypokalemia due to potassium excretion. The nurse should instruct the client to increase dietary potassium. Foods high in potassium can include dried fruits, bananas, lentils, sweet potatoes, baked potatoes, squash, and yogurt. The nurse should instruct the client to monitor for manifestations of hypokalemia, such as muscle weakness, orthostatic hypotension, and irregular heartrate, and to have potassium levels checked periodically."}, {"id": 10619, "cat": "NCLEX 12- Cardiovascular", "stem": "applies electrodes to the client's chest and limbs and the electrocardiogram (ECG) monitor shows complete heart block. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Transport the client to the cardiovascular laboratory."}, {"id": "b", "t": "Prepare the client for insertion of a transvenous pacemaker."}, {"id": "c", "t": "Activate the emergency response system and be prepared to perform CPR."}, {"id": "d", "t": "Apply transcutaneous pacemaker pads."}], "correct": "d", "rationale": "All 11% Hard The greatest risk to this client is injury or death from inadequate cardiac output and tissue perfusion. Therefore, the first action the nurse B ] nove should take is to apply transcutaneous pacemaker pads and begin external pacing of the heart until a temporary transvenous or permanent implanted pacemaker can be placed. Transcutaneous pacing is appropriate for emergency use, but it is intended only for short periods of c | 33% time because it causes the client significant discomfort. @D Ye 47%", "whyNot": {"a": "The nurse should plan to transport the client to the cardiovascular laboratory for placement of a temporary pacemaker under fluoroscopy", "b": "The nurse should plan to prepare the client for the possible insertion of a transvenous pacemaker by cleansing the skin in the likely", "c": "Although the client still has a palpable pulse and is breathing, the client is at risk for imminent cardiac arrest because of the complete"}, "keyConcept": "Cardiac dysrhythmias and their effects on the client range from mild to critical. The nurse must assess the client for signs and symptoms, their contributing factors, frequency, severity, manifestations of diminishing cardiac output, and changes in the client's level of consciousness. In the hospital setting, emergency equipment and personnel are readily available, but the nurse must recognize when and how they should be used. Emergency procedures can be performed without written consent if the client is not coherent and no designated client advocate is available."}, {"id": 10620, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is checking blood pressure levels in the community and notes a blood pressure of 138/88 mmHg on a client. The client asks what his blood pressure means. Which response from the nurse is accurate?", "choices": [{"id": "a", "t": "“This is a normal blood pressure reading; you shouldn’t worry.”"}, {"id": "b", "t": "“This is within a range considered prehypertension; you should have this checked again with your provider.”"}, {"id": "c", "t": "“This is within a range considered hypertension; you should have this checked again with your provider.”"}, {"id": "d", "t": "“This level is probably a little low; you should increase your salt intake.”"}], "correct": "c", "rationale": "A l 3% Hard This blood pressure measurement falls within the range of Stage | hypertension, which is a systolic measurement between 130 and 139 B TY eam mmbg and a diastolic measurement between 80 and 89 mmHg. The client should have his blood pressure checked assessed by the provider. Two accurate measurements are necessary to make the diagnosis. Lifestyle modifications and antihypertensive medication are ec | 33% recommended to avoid complications associated with chronic hypertension. D 0%", "whyNot": {"a": "New guidelines state a normal blood pressure is less than 120 mm Hg systolic.", "b": "New guidelines no longer use the term \"prehypertension.\" Elevated blood pressure without a diagnosis of hypertension refers to blood", "d": "The client's reading suggests hypertension and a second measurement should be obtained to make the diagnosis."}, "keyConcept": "New guidelines state that a systolic blood pressure between 120 and 129 mm Hg systolic is considered \"elevated blood pressure\" without the diagnosis of hypertension. Stage 1 hypertension is now between 130 and 139 mm Hg systolic or between 80 and 89 mm Hg diastolic, previously considered prehypertension.. Stage 2 high blood pressure refers to measurements of 140 mm Hg systolic or 90 mm Hg diastolic."}, {"id": 10621, "cat": "NCLEX 12- Cardiovascular", "stem": "@ @ % Viral x ss Recc x M Inbo X M Inbo x [Ej Untit x Untii x (4 Goor x @ TEAS x Onlir x € Mark x @ Micr x (ee Teel @ Alli x @New x | NCL xX + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Grapefruit juice"}, {"id": "b", "t": "Spinach"}, {"id": "c", "t": "Black licorice"}, {"id": "d", "t": "Ham"}], "correct": "c", "rationale": "Digoxin is an antiarrhythmic medication which also acts as a cardiac inotrope. Cardiac inotropes increase the contractility of the heart. Digoxin is used to treat clients with heart failure and/or atrial fibrillation. It slows conduction through the atrioventricular (AV) node of the heart, reducing the heart rate. Digoxin serum levels must be closely monitored since toxicity can occur outside a narrow therapeutic range. The therapeutic range is 0.8 - 2 ng/mL.", "whyNot": {"a": "A client who takes digoxin does not need to avoid grapefruit juice, as this does not cause a reaction with the medication.", "b": "There is no need for a client who takes digoxin to avoid spinach.", "d": "There is no need for a client who takes digoxin to avoid ham."}, "keyConcept": "Digoxin is an antiarrhythmic medication which also acts as a cardiac inotrope. Cardiac inotropes increase the contractility of the heart. Digoxin is used to treat clients with heart failure and/or atrial fibrillation. It slows conduction through the atrioventricular (AV) node of the heart, reducing the heart rate. Digoxin serum levels must be closely monitored since toxicity can occur outside a narrow therapeutic range. The therapeutic range is 0.8 - 2 ng/mL."}, {"id": 10622, "cat": "NCLEX 12- Cardiovascular", "stem": "appropriate response to this allegation?", "choices": [{"id": "a", "t": "“ will double-check with the triage nurse.”"}, {"id": "b", "t": "“Let me retake the blood pressure now.”"}, {"id": "c", "t": "“It was done when you were not looking.”"}, {"id": "d", "t": "“Well, it was taken a month ago anyway.”"}], "correct": "a", "rationale": "; ; ; oo . eon 21% Hard The provider should trust but verify the reports of coworkers under their supervision. First, check to see if the blood pressure was taken. A triage nurse who is negligent in performing duties should be addressed. If they did take the blood pressure, this should be verified with the B | 1 patient. The client should always receive competent and appropriate care. Cc 0% D 0%", "whyNot": {"b": "The blood pressure may need to be checked, but it is not the first response. When a client reports negligence, it should be followed-up.", "c": "False reassurance does not take care of a negligent employee.", "d": "Giving excuses for someone who may not be performing appropriate care is unprofessional. When a patient is on medication for ADHD,"}, "keyConcept": "The standard of care and policy for triage of clients with ADHD includes blood pressure measurement. The clinician has a duty to provide the standard of care for all clients. The provider is liable if the standard of care is not met and could be liable if the child is harmed due to the breach in care."}, {"id": 10623, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client with hypovolemic shock. Which of the following is the nursing priority action?", "choices": [{"id": "a", "t": "Therapeutic hypothermia"}, {"id": "b", "t": "Placing the client in the right lateral decubitus position"}, {"id": "c", "t": "Reverse Trendelenburg position"}, {"id": "d", "t": "Elevating the client’s legs"}], "correct": "d", "rationale": "| 5% Adequate cardiac output is essential for perfusion of vital organs. When a client is in hypovolemic shock, the nurse should elevate the client’s Cc Hl 21% legs and lower the head of the bed, which will promote venous return to the brain and heart and increase cardiac output. e@", "whyNot": {"a": "The client should be kept warm to conserve energy.", "b": "The client should be supine with legs slightly elevated to promote the return of blood to the heart and to conserve or increase cardiac", "c": "The reverse Trendelenburg position is head upward and feet at a lower level. This position reduces blood flow to vital organs, including"}, "keyConcept": "Critical interventions to maintain perfusion to vital organs include positioning the client with legs elevated and the head of the bed lowered. This position improves cardiac output by increasing venous return to the heart."}, {"id": 10624, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse has a client who requires a peripheral IV. Which action of the nurse would most likely prevent the formation of a hematoma at an IV site?", "choices": [{"id": "a", "t": "Periodically applying warm compresses to the site to promote circulation"}, {"id": "b", "t": "Starting the IV in the most proximal vein available."}, {"id": "c", "t": "Releasing the tourniquet as soon as successful venipuncture has been achieved"}, {"id": "d", "t": "Using sterile technique with dressing changes"}], "correct": "c", "rationale": "All 11% Easy When a nurse starts and IV and uses a tourniquet, blood pools in the lower part of the extremity. This pooled blood is more likely to lead to a B ] a hematoma if the nurse does not release the tourniquet right away.", "whyNot": {"a": "Applying warm compresses at the site may promote circulation, but it will not prevent a hematoma.", "b": "Using a proximal vein does not prevent hematoma formation.", "d": "Dressing changes require aseptic technique, but that would not prevent a hematoma from forming."}, "keyConcept": "Leakage of blood from a blood vessel into the surrounding soft tissue is the cause of a hematoma. A tourniquet prevents blood return to the heart from the extremity. A hematoma can also occur when an IV catheter passes through more than one wall of a vessel or if pressure is not applied to the IV site when the catheter is removed. A hematoma should be controlled with direct pressure. It usually resolves over the course of 2 weeks."}, {"id": 10625, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide ® ATI? X % CLOSE { Browse Questions > iit Search Questions QJ Qa * @ New x {- NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Congestive heart failure"}, {"id": "b", "t": "Cardiac tamponade"}, {"id": "c", "t": "Pericardial effusion"}, {"id": "d", "t": "Restenosis of the coronary artery"}], "correct": "c", "rationale": "Pericarditis with pericardial effusion is a complication of myocardial infarction but can be caused by infection, other trauma, or autoimmune disease. It refers to the accumulation of an abnormally large amount of pericardial fluid in the potential space between the two thin tissue layers of the pericardium (visceral and parietal pericardium) surrounding the heart. The pericardium of the heart anchors the heart in the mediastinum and provides a protective layer around the heart. Clinical signs of an effusion may include distant heart sounds and a friction rub, dyspnea and chest pressure or discomfort, stabbing chest pain that increases when the client is supine, radiation of substernal chest pain to the left shoulder or neck, anxiety, and a pericardial friction rub. If effusion progresses to cardiac tamponade, it compresses the heart and results in decreased cardiac output. Cardiac tamponade causes tachycardia, hypotension, muffled heart sounds, jugular venous distention with clear lungs, and pulsus paradoxus. Pulsus paradoxus refers to a 10 mmHg or greater drop in systolic blood pressure during inspiration. Nursing interventions include keeping the client in the high Fowler’s position to relieve pain, monitoring pain, administering prescribed medications, and assessing the client for cardiac tamponade. Aspirin, NSAIDs, colchicine, and corticosteroids are all used to treat pericarditis.", "whyNot": {"a": "The friction rub is consistent with pericarditis. It is characterized by a scratching or grating noise on cardiac auscultation.", "b": "Cardiac tamponade results in diminished cardiac output, JVD with clear lungs, and pulsus paradoxus. Dyspnea, tachycardia, and", "d": "Restenosis of a coronary artery would not result in a friction rub."}, "keyConcept": "Pericarditis refers to inflammation of the lining of the heart and may occur after myocardial infarction. It is sometimes accompanied by a pericardial effusion, which refers to fluid in the pericardial space. If the effusion is large, it can cause cardiac tamponade, which can prevent the heart from pumping adequately."}, {"id": 10626, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who had a thoraco-abdominal aneurysm repaired 2 days ago. Which of the following findings should the nurse consider unexpected and report to the physician immediately?", "choices": [{"id": "a", "t": "Abdominal pain at 5 on a scale of 0 to 10 for the last 2 days"}, {"id": "b", "t": "Heart rate of 100 bpm after ambulating 200 feet"}, {"id": "c", "t": "Urine output of 2,000 mL in 24 hours"}, {"id": "d", "t": "Weakness and numbness in the lower extremities"}], "correct": "d", "rationale": "| 2% Easy One of the complications of thoraco-abdominal aneurysm repair is spinal cord injury. Therefore, it is important for the nurse to assess for B | a0 signs and symptoms of neurological changes at and below the level of the aneurysm repair.", "whyNot": {"a": "The client is expected to have moderate pain following surgery.", "b": "An elevated heart rate is expected after physical exertion.", "c": "Itis important to monitor urine output following surgery, but a urine output of 2,000 mL in 24 hours is adequate following surgery."}, "keyConcept": "An aortic aneurysm is a dilation of the wall of the aorta at any point along the aorta from the ascending aorta to the level of the bifurcation of"}, {"id": 10627, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide ) ATI? X se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Poa ati Module: Quizzes & Assignments Dashboard Quiz —_Performance ~” { Browse Questions ~ {Search Questions [2 ) Qa * @ New x |. NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Peripheral edema"}, {"id": "b", "t": "Productive cough"}, {"id": "c", "t": "Twitching of the extremities"}, {"id": "d", "t": "Lethargy progressing to coma"}], "correct": "a", "rationale": "Cor pulmonale is right ventricular failure caused by pulmonary congestion; edema results from increasing venous pressure. |", "whyNot": {"b": "The client with cor pulmonale typically does not have a productive cough. D Hi", "c": "Twitching of the extremities is not associated with cor pulmonale.", "d": "The client with cor pulmonale may have episodes of fainting, but not lethargy progressing to coma."}, "keyConcept": "Cor pulmonale is a complication of chronic obstructive pulmonary disease (COPD) that refers to right-sided heart failure. caused by an increase in blood pressure in the pulmonary artery, which carries blood from the heart to the lungs. This is known as pulmonary hypertension, which leads to enlargement and subsequent right-sided heart failure. Causes of cor pulmonale include COPD, cystic fibrosis, sleep apnea, scleroderma of the lungs, blood clots in the lungs, or other damage to lung tissue."}, {"id": 10628, "cat": "NCLEX 12- Cardiovascular", "stem": "Which of the following clients should receive education about the need for prophylactic antibiotics before undergoing dental procedures?", "choices": [{"id": "a", "t": "A client with a mechanical mitral valve replacement"}, {"id": "b", "t": "A client with atrial fibrillation"}, {"id": "c", "t": "A client with mitral valve prolapse"}, {"id": "d", "t": "A client with congestive heart failure after inferior myocardial infarction"}], "correct": "a", "rationale": "8 | 3% Antibiotic prophylaxis before dental work is recommended for individuals who have prosthetic heart valves. This recommendation includes © | | 7% bioprosthetic and homograft valves, in addition to mechanical valves. Other indications for antibiotic prophylaxis include a prior history of D Hi 13% infective endocarditis, completely repaired congenital heart defects with prosthetic devices or materials after 6 months, repaired congenital heart diseases with residual defects, valve regurgitation in structurally abnormal valves in transplanted hearts, and unrepaired cyanotic congenital heart disease.", "whyNot": {"b": "Atrial fibrillation is not an indication for antibacterial prophylaxis.", "c": "Acquired aortic or mitral valve disease in a native valve is not an indication for antibiotic prophylaxis.", "d": "Congestive heart failure is not an indication for antibiotic prophylaxis."}, "keyConcept": "Prosthetic valves may be mechanical or biologic. Mechanical valves are made of combinations of metal alloys, pyrolite carbon, and Dacron. Biologic valves are made of human, bovine, or porcine cardiac tissues. Clients with valvular heart disease and prosthetic valves should use prophylactic antibiotics before dental procedures to prevent infectious endocarditis."}, {"id": 10629, "cat": "NCLEX 12- Cardiovascular", "stem": "@ @ *% Viral x sx Recc xX M Inbo X M Inbo x ] Unt x Untii x 4 Goor x @ TEAS x Onlir x && Mark x @ Micr x @ Ali x @New x | NCL x + v < > CG student.atitesting.com/LTI Qa * sw * © © | Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "The rate, type and settings of the pacemaker"}, {"id": "b", "t": "The client's emotional status"}, {"id": "c", "t": "The client's cardiac status"}, {"id": "d", "t": "The teaching that the client has received"}], "correct": "c", "rationale": "‘i The nurse should first assess the client's cardiovascular status since this will help determine if the pacemaker is effective. Other assessments B | are important, but not as critical as assessing the client's cardiac status. o:", "whyNot": {"a": "Documenting pacemaker settings will ensure that the settings match the order.", "b": "The client's emotional status is important, but psychosocial needs are a lower priority than physical needs.", "d": "Teaching about the pacemaker should have been started prior to the procedure and will continue until the client is discharged or the"}, "keyConcept": "Apermanent pacemakers is implanted during a short surgical procedure. The parts of a pacemaker are the pulse generator, which contains the power source, usually a lithium-iodide battery and a small electronic circuit; the leads, and the electrodes at the terminal ends of the leads. The pulse generator is placed in a subcutaneous pocket created in the chest wall. The pulse generator is attached to leads, which are threaded through the vascular system to the heart and implanted into the myocardial wall. Pacemaker electrodes may be unipolar or bipolar. A pacemaker may be single or dual chamber. Most implanted pacemakers are dual-chamber pacemakers and some have cardioversion-defibrillation settings."}, {"id": 10630, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who has heart failure and reports increased shortness of breath. After increasing the client's oxygen, which of the following actions should the nurse take next?", "choices": [{"id": "a", "t": "Record the client's intake and output."}, {"id": "b", "t": "Assist the client into high-Fowler's position."}, {"id": "c", "t": "Auscultate lungs sounds."}, {"id": "d", "t": "Check oxygen saturation with pulse oximeter."}], "correct": "b", "rationale": "Using the airway, breathing, and circulation approach to client care, the first action the nurse should take is to assist the client into high- Fowler's position. This action increases chest expansion decreases venous return to the heart and decreases lung congestion.", "whyNot": {"a": "The nurse should record the client's intake and output to monitor fluid status. However, there is another action the nurse should take first.", "c": "The nurse should auscultate the client's lung sounds to provide the nurse with information about the client's breathing and fluid status.", "d": "The nurse should check the client's oxygen saturation to provide the nurse with data to adjust oxygen therapy. However, there is another"}, "keyConcept": "Nursing interventions for a client who has heart failure and shortness of breath should include administering supplemental oxygen to increase oxygen saturation to 90%, and to place the client in a high-Fowler's position to increase chest expansion and increase oxygenation. The nurse should place pillows under the client's arms to increase chest expansion and encourage the client to perform coughing and deep breathing exercises every 2 hr to improve gas exchange. Other interventions should include measuring and recording the client's weight and intake and output to evaluate fluid status as well as to auscultate the client's lung sounds to evaluate the client's breathing. The nurse should continuously monitor the client's pulse oximeter to adjust or maintain oxygen therapy."}, {"id": 10631, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guid¢ ® ATI? X ©@ New x % CLOSE { Browse Questions ~ it Search Questions", "choices": [{"id": "a", "t": "Notify the client’s primary care provider."}, {"id": "b", "t": "Measure the blood pressure using a manual cuff."}, {"id": "c", "t": "Give the client a prescribed dose of prn clonidine."}, {"id": "d", "t": "Direct the UAP to ask the client if any symptoms are occurring such as chest pain or headache and recheck the blood pressure."}], "correct": "b", "rationale": "The RN should make a primary assessment of the client and should recheck the blood pressure using a manual cuff before taking further action. If the client’s blood pressure reading is not as high using the manual cuff, the RN should ask the UAP to use a different automated machine when taking subsequent measurements.", "whyNot": {"a": "The nurse should first make an assessment of the client and should verify the reading using a manual cuff. If the reading is accurate, the", "c": "Itis important for the RN to verify the reading and assess the client before taking any further action.", "d": "In the case of a change in the client’s condition, a severely high blood pressure reading is associated with a risk of significant risk of harm"}, "keyConcept": "If assistive personnel report an abnormal blood pressure reading, the RN should make a primary assessment of the client and should recheck the blood pressure using a manual cuff before taking any action. If there is a discrepancy between an automatic machine and a manual cuff, the automatic machine should be recalibrated and checked again before putting it back in use."}, {"id": 10632, "cat": "NCLEX 12- Cardiovascular", "stem": "following actions should the nurse take first?", "choices": [{"id": "a", "t": "The nurse should give the drug at a dose of 0.125 mg."}, {"id": "b", "t": "The nurse should obtain a serum digoxin level before giving the drug."}, {"id": "c", "t": "The nurse should hold the prescribed dose and notify the healthcare provider."}, {"id": "d", "t": "The nurse should order an ECG."}], "correct": "c", "rationale": "a| 1% Easy ce I 5% Digoxin is a cardiac glycoside, a drug that has a variety of effects that include cardiac inotropy, electrophysiological effects on conduction, ec Ft 92% and reduction of sympathetic nervous system activation. It has a narrow therapeutic window, which means that toxicity can occur at doses . Digoxin must be monitored closely. Adverse cardiac effects range from heart block to atrial or ventricular tachycardia. If the client has bradycardia, the provider must be notified when the heart rate is below 60 in order to determine if treatment should continue or if the dose should be held. Digoxin slows conduction through the atrioventricular node (AV node) and slows the sinoatrial node, which can result in severe bradycardia or sinoatrial block in clients who have preexisting sinus node disease or heart block.", "whyNot": {"a": "The nurse should assess the client and contact the healthcare provider before giving the dose or changing the dosage. The nurse cannot", "b": "Although obtaining a serum digoxin level is used to determine if the client has a toxic digoxin level, the immediate priority is to notify the", "d": "Although it is important to order an ECG in some cases to determine if the bradycardia is a function of heart block and requires pacing, the"}, "keyConcept": "Digoxin is a cardiac inotrope with electrophysiological effects on cardiac conduction. It must be closely monitored with measurement of serum levels, since toxicity can occur close to therapeutic levels. Digoxin is primarily excreted through the kidneys, so the dose may require adjustment in renal failure. Dose may require adjustment in the elderly and in other individuals with lean body mass. There are significant potential drug interactions that can increase the serum level and may cause toxicity."}, {"id": 10633, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing the peripheral IV infusion site of a client who reports pain at the insertion site. The nurse finds erythema and a streak formation at the site. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Remove the catheter and insert another at a different site."}, {"id": "b", "t": "Administer an analgesic PO."}, {"id": "c", "t": "Request a prescription for placement of a central venous access device."}, {"id": "d", "t": "Apply an ice pack to the reddened area at the site."}], "correct": "a", "rationale": "These findings can indicate phlebitis at the IV insertion site. The nurse should stop the infusion, remove the IV catheter, and establish B 1% peripheral IV access elsewhere. Manifestations of phlebitis can include: © 2% + Redness D i 11% + Tenderness + Pain + Warmth along the course of the vein starting at access site + Red streak 2 = g + Palpable cord along the vein = a fa a <", "whyNot": {"b": "Before administering any medication for the client's discomfort, the nurse should assess the pain and try to identify and eliminate its", "c": "Acentral venous access device is for long-term administration of various medications and IV preparations.", "d": "Once the IV has been discontinued, the nurse can apply warm, moist compresses to the affected site."}, "keyConcept": "Nurses caring for a client receiving IV fluid therapy should be able to identify the manifestations of the complications of IV therapy. Nurses should be able to implement the correct interventions to address any complications."}, {"id": 10634, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide ) ATI? X % CLOSE x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN “ati Module: Quizzes & Assignments Dashboard Quiz ~ Performance ~ { Browse Questions ~ it Search Questions Ja) Qa * @ New x |. NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Increased blood pressure"}, {"id": "b", "t": "Conversion to normal sinus rhythm"}, {"id": "c", "t": "Reduced episodes of finger numbness"}, {"id": "d", "t": "Increased Sp02"}], "correct": "c", "rationale": "Calcium channel blockers are first-line drug therapy for the treatment of vasospasms with Raynaud’s phenomenon. Nifedipine relaxes smooth muscle and improves circulation, thereby reducing finger numbness.", "whyNot": {"a": "Nifedipine decreases blood pressure.", "b": "Nifedipine is not an antiarrhythmic medication.", "d": "Vasospasm can prevent an accurate measurement of SpO2 in the affected extremity. Nifedipine does not increase the SpO2."}, "keyConcept": "Calcium channel blockers are used to treat Raynaud's syndrome, a vasospastic disorder that cause reduced perfusion and pain in the hands and feet. They are also used to treat hypertension and achalasia."}, {"id": 10635, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who will have a cardiac pacemaker placement later in the day. The client asks the nurse, “How soon after the procedure can | be discharged?” Which response from the nurse is correct?", "choices": [{"id": "a", "t": "“You may require care in the ICU for one to two days before discharge.”"}, {"id": "b", "t": "“Most people go home after 4 to 5 days if they are stable.”"}, {"id": "c", "t": "“People are typically discharged the next day, if complications do not occur.”"}, {"id": "d", "t": "“Most people are discharged within 1 to 2 hours of placement.”"}], "correct": "c", "rationale": "Pacemaker implantation can be done on as an outpatient surgery, but in most cases, the client is admitted and monitored overnight. Discharge usually occurs within a day, if the client remains stable and develops no complications. The site will continue to heal over time. The client can return to most normal activities within 3-7 days, but should avoid heavy lifting for 3-4 weeks. The client should self-monitor for signs of infection or other complications after discharge.", "whyNot": {"a": "ICU care is unnecessary unless significant complications occur.", "b": "Most clients can be discharged within 24 hours. Overnight observation is typical.", "d": "Most clients go home after spending one night in the hospital for observation after pacemaker implantation."}, "keyConcept": "The nurse should teach the client to monitor the pulse after discharge and to notify the healthcare provider if the pulse varies from the expected rate. The client should always carry the ID card that contains information about the pacemaker. The client can show the ID card if the pacemaker sets off a metal detector or to avoid screening with devices that have a strong magnet, such as a hand-held security wand. The client should not carry a cell phone in a shirt pocket overlying the pacemaker, even if the cell phone is turned off. Strong magnets, including those in MRIs, and strong electrical fields, including those emitted by ham radios or heavy duty electrical equipment, must be avoided."}, {"id": 10636, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja) Qa * @ New x |. NCL x x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Apical"}, {"id": "b", "t": "Pulses are pressure waves with the artery caused by contraction of the left ventricle."}, {"id": "c", "t": "Radial"}, {"id": "d", "t": "Carotid"}, {"id": "e", "t": "Pedal"}], "correct": "b", "rationale": "Pulses are pressure waves with the artery caused by contraction of the left ventricle. They can be palpated in locations where the artery runs close to the surface. Palpation is performed using the fingertips. The intensity of a pulse is graded on a scale of 0 to 4 +, with 0 indicating no palpable pulse; 1 + is a faint, but detectable pulse; 2 + is a slightly more diminished pulse than normal; 3 + is a normal pulse; and 4 + indicates a bounding pulse. The femoral pulse is the pulse most commonly palpated during CPR.", "whyNot": {"a": "Apical", "c": "Radial", "d": "Carotid", "e": "Pedal"}, "keyConcept": "Pulses are pressure waves with the artery caused by contraction of the left ventricle. They can be palpated in locations where the artery runs close to the surface. Palpation is performed using the fingertips. The intensity of a pulse is graded on a scale of 0 to 4 +, with 0 indicating no palpable pulse; 1 + is a faint, but detectable pulse; 2 + is a slightly more diminished pulse than normal; 3 + is a normal pulse; and 4 + indicates a bounding pulse. The femoral pulse is the pulse most commonly palpated during CPR."}, {"id": 10637, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is preparing to apply thigh-length antiembolic stockings to a client. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Measure the length of both legs from the tip of the great toe to the widest part of the thigh."}, {"id": "b", "t": "Measure the circumference of each thigh at a point 7.6 cm (3 in) above the knee cap."}, {"id": "c", "t": "Select a stocking size that is one size larger than the client's measurements indicate."}, {"id": "d", "t": "Apply the stockings first thing in the morning before the client gets out of bed."}], "correct": "d", "rationale": "The nurse should apply the antiembolic stockings first thing in the morning and, if possible, before the client gets out of bed. When the legs. are in a dependent position, such as in a standing or sitting position, the veins can become distended resulting in edema. The stockings should be applied before this occurs.", "whyNot": {"a": "For thigh-length antiembolic stockings, the nurse should measure both legs from the heel to the gluteal fold.", "b": "For thigh-length antiembolic stockings, the nurse should measure both thighs at the widest point of the thigh.", "c": "The nurse should compare the client's measurements to the size chart and select the correct size stocking. Stockings that are too large will"}, "keyConcept": "The nurse should be able to complete proper measurements, select the correct stockings size, and apply antiembolic stockings to a client. Antiembolic stockings are applied for the following purposes: + To facilitate venous return from the lower extremities + To prevent venous stasis and deep vein thrombosis (DVT) + To reduce peripheral edema"}, {"id": 10638, "cat": "NCLEX 12- Cardiovascular", "stem": "Convert study guid¢ ® ATI? X ©@ New x x ] untii x Untii x (4 Goor x @ TEAS x Onli x = & Mark x @ Micr x se Tutorial: BoardVitals NCLEX Prep RN % CLOSE “ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ {Search Questions", "choices": [{"id": "a", "t": "“I should call 911 if do not have relief of pain after taking 3 tablets 5 minutes apart.”"}, {"id": "b", "t": "“I should swallow the tablet with water.”"}, {"id": "c", "t": "“I should take this medication after lie down.”"}, {"id": "d", "t": "“I should stop taking this medication if experience a headache or flushing.”"}], "correct": "c", "rationale": "‘is B Nitroglycerin is a vasodilator that provides relief from angina for many clients. Although research shows that almost half of all clients who ec | | take nitroglycerin do not have a thorough understanding of its use, proper education can prevent unnecessary visits to the emergency D I department for many clients. Because nitroglycerin is a vasodilator, it can cause a drop in blood pressure. For that reason, the nurse should be sure the client understands that it is important to lie down before taking either the sublingual tablet or spray.", "whyNot": {"a": "In the past, clients were instructed to take 3 tablets 5 minutes apart and then to call 911 if their pain was not relieved or if it worsened.", "b": "Sublingual tablets should never be swallowed. The client must be instructed to place the tablet under the tongue. Since moisture is", "d": "These are common side effects of nitroglycerin, which are due to its vasodilatory influence."}, "keyConcept": "Nitroglycerin sublingual tablets and spray are prescribed as a PRN medication for angina. The nurse should instruct to take the medication when seated, since the vasodilator effects of nitroglycerin can cause hypotension. If chest pain is not relieved at all or continues to worsen five minutes after the first tablet or spray of nitroglycerin, clients should be instructed to call 911."}, {"id": 10639, "cat": "NCLEX 12- Cardiovascular", "stem": "factors for coronary artery disease should be the focus of the teaching plan for this client?", "choices": [{"id": "a", "t": "Gender"}, {"id": "b", "t": "Family history Ocem"}, {"id": "d", "t": "Cigarette smoking"}], "correct": "d", "rationale": "A| | The nurse’s teaching plan should focus on modifiable risk factors. The risk factors for coronary heart disease (CHD) are age >50 in men and © I post-menopause in women, male gender, family history of CHD in a first-degree relative age <50 (male) or <60 (female), hypertension, ep | dyslipidemia, obesity, and cigarette smoking. Coronary heart disease risk equivalents are noncoronary atherosclerotic disease, including peripheral artery disease, carotid artery disease, and abdominal aortic aneurysm; diabetes mellitus; and chronic kidney disease. The non- modifiable risk factors for this client include gender and family history. He is not obese. Only cigarette smoking is a modifiable risk factor.", "whyNot": {"a": "Although male gender increases the risk of CHD, this risk factor cannot be modified.", "b": "Family history is a non-modifiable risk factor for CHD."}, "keyConcept": "The major cause of coronary artery disease is atherosclerosis. This refers to focal deposits of cholesterol and lipids within the intima of arteries. Although atherosclerosis can affect any artery, it occurs most commonly in the coronary arteries. Atherosclerotic coronary artery disease begins as fatty streaks in the wall of the artery. This progresses to a raised fibrous plaque composed of lipids, primarily cholesterol. Platelets aggregate at the site of damage in the arterial wall and can create a thrombus. As the plaque progresses, it incorporates lipids, thrombi, damaged tissue, and calcium. Obstruction of arterial flow by plaques results in ischemia and angina. Total occlusion results in myocardial infarction."}, {"id": 10640, "cat": "NCLEX 12- Cardiovascular", "stem": "Which condition would most likely be a contraindication for placement of a pulmonary artery catheter?", "choices": [{"id": "a", "t": "Atherosclerosis"}, {"id": "b", "t": "History of myocardial infarction"}, {"id": "c", "t": "Hyperlipidemia"}, {"id": "d", "t": "Infection at insertion site"}], "correct": "d", "rationale": "Apulmonary artery catheter is introduced through a major vessel, and threaded into the heart, where it measures pressures inside the heart and other parameters. Contraindications include infection at the insertion site, right ventricular assist device, and insertion during cardiopulmonary bypass. Introduction of infectious organisms through the catheter skin tract and colonization of the hub can result in bloodstream infection.", "whyNot": {"a": "Atherosclerosis is a condition that contributes to heart disease and may result in the need for a pulmonary artery catheter; it is not a", "b": "Some clients with a history of myocardial infarction may need a pulmonary artery catheter during treatment; this is not a", "c": "Hyperlipidemia may contribute to heart disease, which could require a pulmonary artery catheter; this is not a contraindication."}, "keyConcept": "Apulmonary artery catheter (Swan Ganz catheter) can be used to measure cardiac output, right sided intracardiac pressures, central venous pressure, mixed venous oxygen saturation, pulmonary artery pressure, and pulmonary capillary wedge (occlusion) pressure. A PAC may be placed to monitor volume status in a client in severe shock or to monitor pulmonary artery pressure in clients with pulmonary hypertension. Complications associated with placement of a PAC include atrial and/or ventricular arrhythmias; catheter misplacement; perforation of a cardiac chamber; rupture of a cardiac valve; or rupture of the pulmonary artery. Infection at the insertion site is an absolute contraindication. Thrombocytopenia, coagulopathy, acid-base and electrolyte disturbances are relative contraindications."}, {"id": 10641, "cat": "NCLEX 12- Cardiovascular", "stem": "diuresis within what period of time?", "choices": [{"id": "a", "t": "5-10 minutes"}, {"id": "b", "t": "15-30 minutes"}, {"id": "c", "t": "30-60 minutes"}, {"id": "d", "t": "1-2 hours"}], "correct": "a", "rationale": "Furosemide (Lasix) is a loop diuretic commonly used to reduce edema related to congestive heart failure, liver disease, and renal insufficiency. Furosemide blocks reabsorption of sodium and chloride and therefore increases excretion at the Loop of Henle and distal tubule of the kidney nephron, increasing renal excretion of water, sodium, chloride, magnesium, potassium, and calcium. A decrease in serum potassium is a common adverse effect. Electrolytes, renal function, and hepatic function should be monitored for decreased serum sodium, calcium, and magnesium concentrations. Furosemide may also cause an increase in BUN, serum glucose, creatinine, and uric acid levels. The usual initial dose of furosemide is 40 mg injected slowly intravenously over 1 to 2 minutes. If a satisfactory response does not occur within 1 hour, the dose may be increased to 80 mg injected over 1-2 minutes.The onset of action of intravenous furosemide is within 5 minutes. The peak action occurs at 30 minutes, and the duration of action is 2 hours. Oral furosemide has an onset of action of 30-60 minutes, peaking at 1-2 hours, and lasting 6-8 hours.", "whyNot": {"b": "Peak action occurs at 30 minutes.", "c": "Peak action occurs at 30 minutes, but the onset of action is 5 minutes.", "d": "The duration of action of intravenous furosemide is 2 hours."}, "keyConcept": "Furosemide is a loop diuretic used to relieve edema (including pulmonary edema) in clients with heart failure, cirrhosis of the liver, and renal disease. IV furosemide has a rapid onset of action of 5 minutes and results in increased excretion of water, sodium, chloride, magnesium, potassium, and calcium. Hypokalemia (decreased serum potassium concentration) is common."}, {"id": 10642, "cat": "NCLEX 12- Cardiovascular", "stem": "best action? O A. Immediately notify the healthcare provider. O B. Notify the charge nurse. O C. Review the client’s medication administration record. O D. Assess the client for symptoms of hypotension.", "choices": [{"id": "a", "t": "Immediately notify the healthcare provider."}, {"id": "b", "t": "Notify the charge nurse."}, {"id": "c", "t": "Review the client’s medication administration record."}, {"id": "d", "t": "Assess the client for symptoms of hypotension."}], "correct": "d", "rationale": "A i 25% Moderate The nurse must notify the provider but should first assess the client for symptoms that may be the result of hypotension, including pallor, , poor perfusion, and dizziness. The correct format to communicate with the provider is SBAR: Status, Background, Assessment, and Recommendation. All of this information should be on hand when the nurse communicates with the provider, including € I 2%) recent vital signs, laboratory results, and the medication administration record (MAR). @D fF 72%", "whyNot": {"a": "The nurse should have all information the provider will request, including assessment of symptoms associated with low blood pressure.", "b": "This action may be appropriate after the client has been assessed.", "c": "After assessing the client, the nurse should gather recent laboratory results, recent vital signs, and the MAR."}, "keyConcept": "When an unlicensed aide reports a change in vital signs or client condition, the nurse must first make a professional nursing assessment before taking further action. The nurse cannot base actions on a report by UAP. 2 = ® 4 z = a iat g <"}, {"id": 10643, "cat": "NCLEX 12- Cardiovascular", "stem": "this client? I AB AK arate jeBH o/s aL} AYA AW", "choices": [{"id": "a", "t": "Cardioversion"}, {"id": "b", "t": "Fluid resuscitation"}, {"id": "c", "t": "Transcutaneous pacing"}, {"id": "d", "t": "Amiodarone"}], "correct": "c", "rationale": "A Hi 19% Hard Mm The rhythm shown is third-degree heart block, which is characterized by a complete block of conduction between the atria and ventricles. a | peat rs) This block usually occurs at the AV node or the bundle of His. Third-degree heart block on ECG displays complete dissociation of the atrial 2 and ventricular rhythms. Bradycardia occurs since the ventricular beats occur at a slower rate. Cardiac output diminishes, resulting in ec | 39% Ss bradycardia and hypotension. Associated symptoms include syncope, pre-syncope, angina, and acute pulmonary edema. Third-degree D Hi 16% c heart block is unlikely to respond to atropine, so atropine is not recommended. Transcutaneous pacing (TCP) should be initiated. If TCP fails a < to resolve symptoms, transvenous pacing may be required.", "whyNot": {"a": "Cardioversion is used for treatment in clients who have an unstable tachycardia or who have tachycardia unresponsive to medication.", "b": "Fluid bolus is indicated in hypotension from hypovolemia. This case represents hypotension due to cardiac arrhythmia.", "d": "Amiodarone is an anti-arrhythmic medication used in the treatment of tachyarrhythmia."}, "keyConcept": "Third-degree atrioventricular block is characterized by independent atrial and ventricular rhythms. The atrial rhythm is usually sinus at 60- 100/minute. The ventricular rhythm may be an escape rhythm at 40-60/minute. Complete AV dissociation is emergently treated with transvenous or transcutaneous pacing."}, {"id": 10644, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse views the cardiac monitor of a client with a bundle branch block. The nurse expects which of the following findings on the monitor in a client with bundle branch block?", "choices": [{"id": "a", "t": "Sagging ST segments"}, {"id": "b", "t": "The absence of P wave configurations"}, {"id": "c", "t": "Peaked T waves following every QRS complex"}, {"id": "d", "t": "Widening of the QRS complexes to 0.12 seconds or greater"}], "correct": "d", "rationale": "A Hi 13% Moderate This is the correct response. Bundle branch block interrupts the impulses from the AV node to the ventricle, delaying conduction through the . cil 8%", "whyNot": {"a": "Changes in the ST segments are usually seen as a result of cardiac ischemia or damage.", "b": "P waves would not be absent in a client with a bundle branch block; they are produced when the SA node initiates an electrical impulse at", "c": "Peaked T waves are associated with hyperkalemia."}, "keyConcept": "Bundle branch block refers to a delay or obstruction of the electrical impulse generated by the sinus node at some point along the pathway to activate the left or right ventricle. Since the QRS complex represents depolarization of the ventricles, the QRS complex is widened as a result of delay in depolarization that occurs when the electrical impulse is blocked. RBBB LBBB vi v6 vi v6 rsR’ qRs R Anterior Lateral Anterior Lateral"}, {"id": 10645, "cat": "NCLEX 12- Cardiovascular", "stem": "@0O@ * Vira x Na Rec xX ™ Inbe x ™ Inbe x =) Unt x Unt x ta Gor x @ TEA x On! x @ Ma x @ Mic x Convert study guide ) ATI xX ®@ Nev xX {. NC! x +} 1ne X + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE sg Poa ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ {Search Questions [2 )", "choices": [{"id": "a", "t": "Avoid sudden discontinuation of the drug"}, {"id": "b", "t": "Monitor the blood pressure annually"}, {"id": "c", "t": "Check blood glucose before taking the medication"}, {"id": "d", "t": "Discontinue the medication if severe headaches develop"}], "correct": "a", "rationale": "Atenolol is a beta-adrenergic antagonist indicated for the management of hypertension. Sudden discontinuation of this drug is dangerous . cj 6%", "whyNot": {"b": "Blood pressure needs to be monitored more frequently than annually.", "c": "Although beta-blockers can block signs of hypoglycemia in diabetic clients, it is unnecessary to check blood glucose levels before taking", "d": "The medication should not be discontinued without a physician’s order."}, "keyConcept": "Atenolol is a beta blocker and it is used to treat hypertension and angina pectoris. Sudden discontinuation of this medication can cause rebound hypertension or ischemia. Clients with diabetes should be informed that beta blockers can mask the symptoms of hypoglycemia."}, {"id": 10646, "cat": "NCLEX 12- Cardiovascular", "stem": "which of the following electrolyte abnormalities?", "choices": [{"id": "a", "t": "Hypernatremia"}, {"id": "b", "t": "Hyponatremia"}, {"id": "c", "t": "Hyperkalemia"}, {"id": "d", "t": "Hypokalemia"}], "correct": "d", "rationale": ". Hypokalemia is generally defined as a serum potassium level of less than 3.5 mEq/L. B i 0% (3.5 mmol/L) and is associated with development of U waves on ECG. ci 17% o> ox mney —~Saaney e 4 z s I a cc g", "whyNot": {"a": "The presence of U waves on the ECG indicate hypokalemia, not hypernatremia.", "b": "The presence of U waves on the ECG indicate hypokalemia, not hyponatremia.", "c": "The presence of U waves on the ECG indicate hypokalemia, not hyperkalemia."}, "keyConcept": "Hypokalemia may result from inadequate potassium intake, increased potassium excretion, or a shift of potassium from the extracellular to the intracellular space. The most common cause of hypokalemia is increased excretion. Increased excretion can occur with vomiting, diarrhea, or as a result of medications, including diuretics, amphetamines, and other stimulants. It also occurs in clients with Cushing syndrome."}, {"id": 10647, "cat": "NCLEX 12- Cardiovascular", "stem": "(ASCVD)? O A. High-density lipoprotein cholesterol (HDL-C) 75 mg/dL. O B. High-density lipoprotein cholesterol 80 mg/dL O C. Low-density lipoprotein cholesterol (LDL-C) 75 mg/dL O D. Low-density lipoprotein cholesterol 190 mg/dL", "choices": [{"id": "a", "t": "High-density lipoprotein cholesterol (HDL-C) 75 mg/dL."}, {"id": "b", "t": "High-density lipoprotein cholesterol 80 mg/dL"}, {"id": "c", "t": "Low-density lipoprotein cholesterol (LDL-C) 75 mg/dL"}, {"id": "d", "t": "Low-density lipoprotein cholesterol 190 mg/dL"}], "correct": "d", "rationale": "A Low-density lipoprotein cholesterol of 190 mg/dL is above recommended levels for cholesterol and is associated with high risk of B i atherosclerotic coronary vascular disease, stroke, and peripheral arterial disease. Low-density lipoprotein cholesterol contributes to the elevation of total cholesterol, and levels >130 mg/dL are associated with increased ep fF risk of cardiovascular disease. Coronary artery disease (CAD) develops due to the formation of cholesterol plaques in the coronary arteries. The plaques may rupture, attracting formation of platelets and causing coronary thrombosis with acute myocardial infarction. Atherosclerosis also results in stroke and peripheral artery disease. Current recommendations suggest treatment to lower cholesterol for the following groups: + Individuals with clinical atherosclerotic cardiovascular disease + Individuals with LDL-cholesterol levels >190 mg/dL, such as those with familial hypercholesterolemia + Individuals with diabetes aged 40 to 75 years old with LDL-cholesterol levels between 70 and 189 mg/dL cholesterol + Individuals without evidence of cardiovascular disease or diabetes but who have LDL-cholesterol levels between 70 and 189 mg/dL anda 10-year risk of atherosclerotic cardiovascular disease >7.5% High-density lipoproteins bind with low-density lipoprotein cholesterol to reduce the total cholesterol level. A high-density lipoprotein level of at least 70 mg/dL is considered cardioprotective.", "whyNot": {"a": "HDL-C levels greater than 70 mg/dL are desirable to reduce the risk of CAD.", "b": "HDL-C levels of 80 mg/dL will reduce total cholesterol by binding to LDL-C.", "c": "An LDL-C of 75 mg/dL is associated with a reduced risk of CAD."}, "keyConcept": "LDL cholesterol makes up 60-70% of total cholesterol and high levels increase the risk of coronary artery disease. LDL cholesterol should be treated with statins in individuals with very high levels (> 189 mg/dL) and in those with certain cardiovascular risk factors. High density lipoprotein cholesterol (HDL-C) is beneficial and levels > 60 mg/dL are desirable."}, {"id": 10648, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse in a pediatric clinic is caring for an infant who has heart failure and is taking digoxin. Which of the following parent statements indicates a therapeutic response to the medication?", "choices": [{"id": "a", "t": "\"My baby is breathing easier than before.”"}, {"id": "b", "t": "\"My baby is taking longer naps now.\""}, {"id": "c", "t": "\"My baby is having fewer wet diapers since starting the medication.\" O D.\"My baby's heart rate is faster than it was before the medication.\""}], "correct": "a", "rationale": "The desired effect of digoxin is to increase cardiac output. The medication also should decrease venous pressure and pulmonary edema. , the nurse should identify this statement by the parent as indicating a therapeutic response to the medication. I © 2% om 18%", "whyNot": {"b": "The desired effect of digoxin is to increase cardiac output, which should decrease fatigue.", "c": "The desired effect of digoxin is an increased urinary output due to improved cardiac output, which will increase the number of wet"}, "keyConcept": "Manifestations of Heart Failure 2 = ® 4 z = a iat g < «Tachycardia + Anorexia + Pale extremities + Hypotension + Flaring nares + Orthopnea + Coughing + Wheezing + Weight gain + Periorbital edema + Distended neck veins"}, {"id": 10649, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who received a permanent pacemaker 6 weeks ago and is experiencing dysrhythmias. Which of the following orders should the nurse clarify with the provider?", "choices": [{"id": "a", "t": "Cardiac enzymes"}, {"id": "b", "t": "MRI of the chest"}, {"id": "c", "t": "Daily physical therapy"}, {"id": "d", "t": "Low-sodium diet"}], "correct": "b", "rationale": "A i 10% Moderate The nurse should identify that a permanent pacemaker is a contraindication for an MRI of the chest. The magnets in the machine can create es rs 75% electromagnetic interference, causing the pacemaker to malfunction. Therefore, the nurse should clarify this prescription before scheduling. cil 12%", "whyNot": {"a": "The nurse should expect the provider to assess and monitor cardiac enzyme levels for a client who has angina. A permanent pacemaker is", "c": "The nurse should encourage daily physical therapy for the client. Ambulation is necessary to help prevent venous thrombosis or", "d": "Limiting sodium intake is a general recommendation for clients who have cardiovascular disorders. A permanent pacemaker is not a"}, "keyConcept": "Manifestations for clients who are experiencing poor oxygen levels and inadequate tissue perfusion from dysrhythmias include: 2 = ® 4 z = a iat g < + Decreased urine output + Difficulty breathing + Appearing nervous + Skin cool to the touch + Chest pain + Dizziness"}, {"id": 10650, "cat": "NCLEX 12- Cardiovascular", "stem": "contraindication to therapy? O A. “lam short of breath and feel nauseated.” O B. “I have had black tarry bowel movements lately.” O C. “I take hydrochlorothiazide and captopril for my blood pressure.” O D. “My cholesterol level is elevated, but | stopped taking my statin because of muscle pain.”", "choices": [{"id": "a", "t": "“lam short of breath and feel nauseated.”"}, {"id": "b", "t": "“I have had black tarry bowel movements lately.”"}, {"id": "c", "t": "“I take hydrochlorothiazide and captopril for my blood pressure.”"}, {"id": "d", "t": "“My cholesterol level is elevated, but stopped taking my statin because of muscle pain.”"}], "correct": "b", "rationale": "All o: Administration of fibrinolytic therapy within 30 minutes of hospital arrival or transport to the catheterization laboratory for coronary © | intervention within 90 minutes are both Core Measures in Acute Myocardial Infarction considered by the Joint Commission in the evaluation D | | of an institution. Alteplase is a fibrinolytic medication used to break up clots and restore perfusion to the heart muscle in selected clients with AMI. The recommended total doses for alteplase is based on client weight, not to exceed 100 mg. Fibrinolytic medications increase the risk of hemorrhage, including intracranial hemorrhage. Contraindications include: -Active internal bleeding -History of a recent stroke -Recent (within 3 months) intracranial or intraspinal surgery or serious head trauma -Presence of intracranial conditions that may increase the risk of bleeding (e.g. some neoplasms, arteriovenous malformations, or aneurysms) -Bleeding diathesis -Current severe uncontrolled hypertension. Black tarry bowel movements suggest gastrointestinal bleeding. Active internal bleeding is a contraindication to use of thrombolytic medications. Other contraindications include a history of a recent stroke, serious head trauma or intracranial or intraspinal surgery within the last 2 months, the presence of intracranial conditions such as aneurysms or AV malformation that may increase the risk of bleeding, and known bleeding diathesis or severe uncontrolled hypertension.", "whyNot": {"a": "These symptoms are expected with myocardial infarction.", "c": "Uncontrolled hypertension is a contraindication. Thiazide diuretics and ACEls are recommended classes of medication for initial", "d": "This is not a contraindication. The risk of myocardial infarction and other cardiovascular disorders is increased in individuals with high"}, "keyConcept": "Active internal bleeding is a contraindication to use of thrombolytic medications for treatment of acute myocardial infarction. Other contraindications include a history of a recent stroke, serious head trauma or intracranial or intraspinal surgery within the last 2 months, the presence of intracranial conditions such as aneurysms or AV malformation that may increase the risk of bleeding, and known bleeding"}, {"id": 10651, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is preparing to place a peripheral IV cannula for administration of a medication. Which of the following sites should the nurse select initially ?", "choices": [{"id": "a", "t": "Veins in the foot"}, {"id": "b", "t": "Veins in the scalp"}, {"id": "c", "t": "Veins in the leg"}, {"id": "d", "t": "Veins in the hand"}], "correct": "d", "rationale": "a| 1% Easy A nurse would typically use the veins in the hand, forearm, or antecubital fossa as first choices for a peripheral IV in an adult.", "whyNot": {"a": "Veins in the foot are typically used when no other veins are available in an adult, or as a primary site in an infant. ep fC 95%", "b": "The nurse would use a scalp vein in an infant, not in an adult.", "c": "Leg veins are typically not used for IV catheter insertion."}, "keyConcept": "Peripheral IV lines are usually started at the most peripheral site that is available and appropriate for the infused fluid or medication. Cannulation of a distal site allows a more proximal site if the initial attempt fails. If a proximal vein is attempted initially, with a second attempt to start an IV distal to the site, the fluid may leak from the injured proximal vessel. The veins on the dorsum of the hand are usually selected because they are easily accessible. If the nurse is unable to start an IV on the dorsum of the hand, the next preferred site is the veins of the forearm and then the median cubital vein that crosses the antecubital fossa. For infusion of large volumes of fluid in clients who have undergone trauma, it is common to go directly to the median cubital vein as the first choice because it will accommodate a large bore IV and itis usually easy to catheterize."}, {"id": 10652, "cat": "NCLEX 12- Cardiovascular", "stem": "nurse take? O A. Perform defibrillation O B. Prepare for transcutaneous pacing O C. Administer IV epinephrine O D. Place the client in modified Trendelenburg position", "choices": [{"id": "a", "t": "Perform defibrillation"}, {"id": "b", "t": "Prepare for transcutaneous pacing"}, {"id": "c", "t": "Administer IV epinephrine"}, {"id": "d", "t": "Place the client in modified Trendelenburg position"}], "correct": "c", "rationale": "A | | 28% Moderate 2 The nurse should administer epinephrine during asystole because it improves perfusion and myocardial contractility, increasing heart rate . In addition, CPR must be performed immediately and should be continued while the medication is being administered. s", "whyNot": {"a": "Defibrillation is not indicated for asystole, because asystole is not considered a shockable cardiac rhythm.", "b": "Transcutaneous and transvenous pacing are used with bradycardias, atrioventricular (AV) conduction disorders, and sometimes with", "d": "Elevating the client's lower extremities to increase blood flow to the brain is indicated for the treatment of a client who is in hypovolemic"}, "keyConcept": "Ventricular asystole is the absence of electrical activity in the heart, resulting in no waveform on the ECG and no palpable pulse or blood pressure. It results in the loss of consciousness and respirations. Because immediate intervention is necessary, nurses must be aware in advance of the life-saving actions to take. By performing CPR and administering epinephrine, the nurse can help to ensure that the client will be without adequate cardiac output for the shortest possible period of time."}, {"id": 10653, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is completing the admission assessment of a client who is scheduled for peripheral bypass graft surgery on the left leg. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Rubor on the client's affected leg when elevated © B.3+ dorsal pedal pulse on the client's left foot"}, {"id": "c", "t": "Increased hair on the client's left calf"}, {"id": "d", "t": "Report of intermittent claudication in the client's affected leg"}], "correct": "d", "rationale": "A Hi 13% Moderate Peripheral bypass graft surgery is performed to increase arterial blood flow to the extremity of a client who has severe peripheral arterial B ] 12% disease. The nurse should expect a client who has peripheral arterial disease to experience intermittent claudication, numbness, or burning pain in the extremity that ceases with rest. € | Sh", "whyNot": {"a": "The nurse should expect a client who has peripheral arterial disease to experience reddening, or rubor, when the affected leg is placed ina", "c": "The nurse should expect a client who has peripheral arterial disease to have hair loss on the affected calf."}, "keyConcept": "Peripheral bypass graft surgery is performed to increase arterial blood flow to the extremity of a client who has severe peripheral arterial 3 disease. a < Manifestations of peripheral arterial disease can include intermittent claudication, or burning, cramping muscle pain that discontinues with rest, loss of hair on the lower calf and ankle, thickened toenails, dependent rubor, or reddening, when the extremity is in a dependent position and decreased or absent pulses. The nurse should instruct the client to participate in gradual progressive exercise to increase peripheral circulation, avoid exposure to cold temperatures, wear warm socks and shoes to increase vasodilation, and increase fluid intake to reduce the risk for thrombophlebitis. The nurse should also advise the client to avoid nicotine and caffeine as well as reduce stress to decrease the risk for vasoconstriction."}, {"id": 10654, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is reviewing the following rhythm on a telemetry monitor. She recognizes the rhythm as which of the following?", "choices": [{"id": "a", "t": "First-degree AV block"}, {"id": "b", "t": "Atrial fibrillation"}, {"id": "c", "t": "Bradycardia"}, {"id": "d", "t": "Sinus rhythm"}], "correct": "d", "rationale": "all 9% Easy i Normal sinus rhythm is the default rhythm of the heart. It is generated when a pacemaker impulse occurs in the sinoatrial node and is a I x3 Fe} (S transmitted to the ventricles through the atrioventricular (AV) node and the His-Purkinje system. The rhythm is regular, with P waves g preceding a narrow QRS complex and a constant PR interval at a rate between 60-100 per minute in adults. Children may have higher age- c | 9% s appropriate rates. oo 7% F comes < 7 a Segment Pp el LN aims __ | Q artnet", "whyNot": {"a": "First-degree AV block is characterized by a prolonged PR interval of >0.20 ms.", "b": "Atrial fibrillation is characterized by an irregular baseline without regular P waves and is due to disorganized atrial activity.", "c": "Bradycardia refers to a heart rate below the normal range for children and <60/minute in adults."}, "keyConcept": null}, {"id": 10655, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client following a stroke. Which of the following findings indicates the client is experiencing difficulty with swallowing?", "choices": [{"id": "a", "t": "Lips are dry and scaly"}, {"id": "b", "t": "Coughing while eating."}, {"id": "c", "t": "Enlargement of the thyroid gland"}, {"id": "d", "t": "Inflammation of the gums"}], "correct": "b", "rationale": "a| 1% Easy The client who coughs while eating might be experiencing dysphagia or difficulty with swallowing. Other assessment findings can include: es sd 93% + Change in voice tone or quality after swallowing © I 4% + Abnormal movements of the mouth, tongue, or lips + Slow, weak, imprecise, or uncoordinated speech + Abnormal gag reflex + Delayed swallowing + Incomplete oral clearance or pocketing of food + Regurgitation + Pharyngeal pooling 2 = ® 4 z = a iat g < + Delayed or absent trigger to swallow + Inability to speak consistently", "whyNot": {"a": "Lips that are dry and scaly are an indication of poor nutrition. Other manifestations of the lips can include redness, swelling, and angular", "c": "An enlargement of the thyroid gland can be an indication of poor nutrition. Other manifestations of the neck glands can include", "d": "Inflammation of the gums can be an indication of poor nutrition. Other manifestations of the gums can include receding and spongy gums"}, "keyConcept": "It is imperative that the nurse is able to identify manifestations of dysphagia so that difficulties with swallowing are quickly addressed. Dysphagia can lead to an insufficient amount of food being consumed which, in turn, leads to malnutrition."}, {"id": 10656, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a client about a new prescription for nitroglycerin sublingual tablets. Part of the nurse's teaching will include which of the following instructions?", "choices": [{"id": "a", "t": "Limit the tablets to no more than 4 per day"}, {"id": "b", "t": "Discontinue the medication if a headache occurs"}, {"id": "c", "t": "Store the medication in a dark container"}, {"id": "d", "t": "Increase the number of tablets taken if dizziness occurs"}], "correct": "c", "rationale": "A Nitroglycerin is sensitive to moisture and to light and should be kept in a dark, airtight container. B 7", "whyNot": {"a": "Nitroglycerin is used PRN. It may be needed several times daily. The client should seek medical attention if 3 tablets are not effective for D |", "b": "A headache is a common side effect of nitroglycerin and the nitroglycerin should not be discontinued if a headache occurs.", "d": "The healthcare provider should be notified if dizziness occurs. The dosage may need to be reduced, not increased."}, "keyConcept": "Nitroglycerin spray and sublingual tablets are prescribed PRN and used to stop an episode of angina or to prevent angina when taken before exertion. The nurse should advise the client to sit before placing a sublingual tablet under your tongue. The oral spray should be sprayed on or under the tongue. The client may become dizzy or lightheaded after using a tablet or spray. This is expected since nitroglycerin is a venous and arterial vasodilator. Nitroglycerin sublingual tablets should not be chewed, crushed, or swallowed. They are absorbed through the lining of the mouth. The tablets should be placed under the tongue or between the cheek and gum and allowed to dissolve."}, {"id": 10657, "cat": "NCLEX 12- Cardiovascular", "stem": "Which of the following clients is at highest risk of developing atrial fibrillation?", "choices": [{"id": "a", "t": "A client with hepatitis"}, {"id": "b", "t": "A client with hyperthyroidism"}, {"id": "c", "t": "A client who is overweight"}, {"id": "d", "t": "A client with gastroesophageal reflux"}], "correct": "b", "rationale": "15% of individuals with hyperthyroidism. The exact relationship between the two conditions is not es Tr 59% entirely clear, but clients with hyperthyroidism should be monitored for development of atrial fibrillation as a possible complication. my | 3% hehehehe Jl. Atrial Fibrillation", "whyNot": {"a": "Hepatitis typically has no effect on the development of atrial fibrillation.", "c": "Being overweight is not an independent risk factor for development of atrial fibrillation.", "d": "Gastroesophageal reflux is not associated with increased risk of atrial fibrillation."}, "keyConcept": "Atrial fibrillation (AF) is the most common arrhythmia. It is characterized by disorganized atrial electrical activity and contraction resulting in an “irregularly irregular” ventricular response (“fibrillation waves”). The incidence of atrial fibrillation increases with age. States of excess catecholamine levels predispose to atrial fibrillation. These conditions include hyperthyroidism, thyrotoxicosis, and pheochromocytoma. Other risk factors include abnormalities of the conduction system due to ischemic heart disease or age related fibrotic changes."}, {"id": 10658, "cat": "NCLEX 12- Cardiovascular", "stem": "The nurse is assessing a newly admitted client. Findings include a full bounding pulse, moist crackles, distended peripheral veins, and polyuria. Which of the following conditions is associated with these findings?", "choices": [{"id": "a", "t": "Diabetes"}, {"id": "b", "t": "Hypervolemia"}, {"id": "c", "t": "Respiratory disorder"}, {"id": "d", "t": "Hypokalemia"}], "correct": "b", "rationale": "al 3% Easy Hypervolemia is a condition in which there is excess fluid volume in the extracellular fluid. It is usually caused by impaired homeostasis. es | sd 89% Heart failure, liver cirrhosis, renal failure, adrenal gland disorders, and corticosteroid administration can cause fluid overload. Common manifestations include full bounding pulse, moist crackles, distended neck and peripheral veins, dyspnea or orthopnea, peripheral edema, cl Gi and polyuria.", "whyNot": {"a": "Diabetes causes polyuria but not the other symptoms.", "c": "Respiratory disorder does not cause polyuria or distended peripheral neck veins.", "d": "Hypokalemia does not cause the symptoms manifested by the client."}, "keyConcept": "Hypervolemia refers to an isotonic expansion of the extracellular fluid caused by an increase in total body sodium content and an increase in total body water. It occurs as a result of compromised regulatory mechanisms for sodium and water associated with disorders that include reduced cardiac output in decompensated heart failure; kidney failure; renal insufficiency; and liver failure. Excess intake of sodium or water can also result in hypervolemia. Fluid restriction and sodium restriction are critical to management. 2 = ® 4 z = a iat g <"}, {"id": 10659, "cat": "NCLEX 12- Cardiovascular", "stem": "appropriate action? O A. Place the client in the reverse Trendelenburg position O B. Give atropine 0.5 mg IVP every 3-5 min up to 3 mg maximum dose O C. Give the next dose of propranolol O D. Commence Valsalva maneuver (encourage the client to “bear down” or to cough forcefully) 2 8", "choices": [{"id": "a", "t": "Place the client in the reverse Trendelenburg position"}, {"id": "b", "t": "Give atropine 0.5 mg IVP every 3-5 min up to 3 mg maximum dose"}, {"id": "c", "t": "Give the next dose of propranolol"}, {"id": "d", "t": "Commence Valsalva maneuver (encourage the client to “bear down” or to cough forcefully) 2 8"}], "correct": "b", "rationale": "A Hi 12% Moderate < Atropine is the treatment for symptomatic bradycardia, which is characterized by a heart rate of less than 60 bpm, resulting in symptoms © | 1% caused by the decreased heart rate.. Look for evidence that the rate is causing hypoperfusion, such as altered mental status, ischemic chest D I | 10% pain, acute heart failure, shock, dizziness, dyspnea, weakness, or fatigue. If atropine does not resolve the client’s bradycardia, dopamine or epinephrine infusion may be helpful, or transcutaneous pacing should be initiated. pecne OnEpinaphvine cafe 2iomeghamin", "whyNot": {"a": "Clients with hypotension should be placed in the Trendelenburg position, which allows the preferential flow of oxygenated blood to the", "c": "Propranolol is a beta blocker and negative chronotrope that reduces the heart rate.", "d": "Valsalva maneuvers stimulate the vagus nerve, which results in decreased heart rate."}, "keyConcept": "Atropine is the initial treatment for symptomatic bradycardia, although transcutaneous or transvenous pacing are necessary for treatment of high degree block - third degree AV block and Mobitz Type II AV block.."}, {"id": 10660, "cat": "NCLEX 12- Cardiovascular", "stem": "therapy? O A. Flatness of the jugular vein O B. Decreased urine output O C. Crackles on lung exam O D. $3 heart sound", "choices": [{"id": "a", "t": "Flatness of the jugular vein"}, {"id": "b", "t": "Decreased urine output"}, {"id": "c", "t": "Crackles on lung exam"}, {"id": "d", "t": "$3 heart sound"}], "correct": "a", "rationale": "Furosemide (Lasix) is a loop diuretic often used in management of congestive heart failure. Diuretics relieve fluid overload by increasing the volume of urine. When assessing response to diuretic therapy, the nurse should monitor daily weight, intake and output ratios, amount and location of edema, reduction of jugular venous distention, lung sounds, skin turgor, and mucous membranes.", "whyNot": {"b": "Diuretics increase urine output.", "c": "Crackles in the lungs indicate fluid overload and would not be a sign of medication efficacy with a diuretic.", "d": "An S3 heart sound is associated with congestive heart failure."}, "keyConcept": "Furosemide (Lasix) is a loop diuretic often used in management of congestive heart failure. Diuretics relieve fluid overload by increasing the volume of urine. When assessing response to diuretic therapy, the nurse should monitor daily weight, intake and output ratios, amount and location of edema, reduction of jugular venous distention, lung sounds, skin turgor, and mucous membranes."}, {"id": 10661, "cat": "NCLEX 12- Cardiovascular", "stem": "@0O@ * Vira x Na Rec xX ™ Inbe x ™ Inbe x =) Unt x Unt x ta Gor x @ TEA x On! x @ Ma x @ Mic x Convert study guide ) ATI xX ®@ Nev xX {. NC! x +} TEA xX + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE sg Pas ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "On discharge from the hospital"}, {"id": "b", "t": "On discharge from the cardiac care unit"}, {"id": "c", "t": "On admission to the hospital"}, {"id": "d", "t": "4 weeks after the onset of illness"}], "correct": "c", "rationale": "al 2% Easy A basic principle of rehabilitation, including cardiac rehabilitation, is that rehabilitation begins on hospital admission. Early rehabilitation is .", "whyNot": {"a": "The client will need discharge instructions when he leaves the hospital; however, discharge planning should begin upon admission.", "b": "The client may need to know some discharge instructions when he is moved from the cardiac care unit, but discharge planning should", "d": "The client should know discharge instructions before 4 weeks after the onset of illness. Discharge instructions should begin upon"}, "keyConcept": "Cardiac rehabilitation (cardiac rehab) refers to individualized outpatient programs of exercise and education that are designed to help clients improve their health and facilitate recovery from myocardial infarction, other forms of heart disease or cardiac surgery. Cardiac rehab includes exercise training, emotional support, and education about lifestyle changes to reduce the risk of recurrent cardiac events. Lifestyle changes may include the adoption of a heart-healthy diet, maintenance of a healthy weight, and smoking cessation. Cardiac rehab goals include prevention of progressive worsening of the condition; reduction of the risk of future cardiac events; and improvement of strength, health, and quality of life. 2 = ® 4 z = a iat g <"}, {"id": 10662, "cat": "NCLEX 12- Cardiovascular", "stem": "While assessing a client's heart sounds, a nurse auscultates a swishing sound between the S1 and S2 heart sounds. The nurse should document this finding as which of the following?", "choices": [{"id": "a", "t": "A systolic murmur O B.A third heart sound (S3)"}, {"id": "c", "t": "A diastolic murmur"}, {"id": "d", "t": "A fourth heart sound (S4)"}], "correct": "a", "rationale": "Cardiac murmurs indicate turbulence in the blood flow through the cardiac valves. They vary in volume from faint to loud and are swishing B ] 14% or blowing sounds that the nurse can hear between the expected heart sounds. A systolic murmur occurs during systole, or between the S1 and S2 heart sounds. | 2% Heart Murmurs and Heart Sounds \\ Ast 2nd 3rd Atrial ; UL « fly Ai— Z \\ Normal i © ANAK | 2 + — lim — ah a c NMA iM 3 veteeainion | > wan AAW — ' ‘Aortic regurgitation | | ' Ane.nnm yp $l <n romney —— i 1 1 7 Patent ductus arteriosus | i 1 ' ' Nw ; NYA AN | 1 | Diastole Systole Diastole Systote Timing and amplitude of heart murmurs", "whyNot": {"c": "Cardiac murmurs can be an indication of valvular stenosis or regurgitation. When heard between the S, and the S,, or diastole, it is referred", "d": "An additional heart sound heard late in the diastolic cycle, the S4 is auscultated as a \"LUB lub dub\" sound and indicates decreased"}, "keyConcept": null}, {"id": 10663, "cat": "NCLEX 12- Cardiovascular", "stem": "administered for which of the following types of shock?", "choices": [{"id": "a", "t": "Cardiogenic © B. obstructive"}, {"id": "c", "t": "Hypovolemic © b.bistributive"}], "correct": "a", "rationale": "The nurse should recognize that a prescription to reduce afterload will reduce the resistance to left ventricular ejection and allow the heart to . This is a treatment for clients who have cardiogenic shock, often caused by myocardial infarction. 7] © 8% Stages of Shock (mild Decrease a MAP of 5 to 10 mm Hg from iti vasoconstriction) baseline, increased heart rate ill e oe Decrease in MAP of 10 to 50 mm Hg from o Activation of renal and hormonal — 8 . . . baseline, increased heart rate decreased ° Nonprogressive mechanisms (renin, aldosterone, ADH . 2 . pulse pressure, decreased urine output, c secretion) . . a increased thirst = < Decrease in MAP > 20 mm Hg from baseline, sense of impending doom, . confusion, increased thirst, hypotension, Progressive Unable to meet oxygen demands, tachycardia, weak pulse, pallor to cyanosis, anuria, decreased oxygen saturation level, acidosis, hyperkalemia Loss of consciousness, nonpalpable pulse, cold, dusky extremities, Not present (development of MODS, Refractot bradypnea, shallow respirations, \"y microthrombi formation) ye! P . unmeasurable oxygen saturation level, death.", "whyNot": {"c": "Fluid replacement and reduction of further fluid loss are the focus of management of hypovolemic shock. Hemorrhagic shock is a specific"}, "keyConcept": null}, {"id": 10664, "cat": "NCLEX 12- Cardiovascular", "stem": "occur with a pacemaker battery malfunction?", "choices": [{"id": "a", "t": "Chest pain radiating to the back with diaphoresis"}, {"id": "b", "t": "Dyspnea, peripheral edema, and pre-syncope"}, {"id": "c", "t": "Abdominal pain radiating to the back and nausea"}, {"id": "d", "t": "Coughing, wheezing, and low oxygen saturation"}], "correct": "b", "rationale": "‘i o: A pacemaker is a device implanted to maintain the heart rate when the client's intrinsic system is unable to do so. The stimulus is produced © | by a pulse generator and delivered through electrodes or leads that implanted in the epicardium or endocardium. The electrodes may be D i unipolar or bipolar. The proximal end attaches to a pulse generator that is placed in the chest or abdomen. Causes of pacemaker malfunction and failure include lead dislodgement, battery failure, low, sensitivity, wire fracture, or improper placement of the catheter. Pacemaker failure can result in an irregular pulse, a change in heart rate, or palpitations. These symptoms may cause a reduction of cardiac output, which is characterized by symptoms of heart failure that include peripheral edema and dyspnea. If the brain is not adequately perfused, symptoms may include light-headedness, weakness, pre-syncope, or syncope.", "whyNot": {"a": "Chest pain that radiates to the back characterizes a ruptured aortic aneurysm.", "c": "Abdominal symptoms are not generally a symptom of pacemaker failure. This suggests gastrointestinal disorders like pancreatitis or", "d": "Although wheezing may sometimes characterize heart failure, these symptoms are less likely to characterize pacemaker failure."}, "keyConcept": "Ineffective tissue perfusion in a client with a pacemaker may be related to pacemaker battery failure with subsequent arrhythmia and decreased cardiac output. Signs and symptoms include low blood pressure, decreased heart rate and cardiac output, with cold, clammy skin and other signs of decreased perfusion, including changes in level of consciousness."}, {"id": 10665, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a client who has a new prescription for daily aspirin. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"Aspirin reduces the formation of blood clots that could cause a heart attack.\""}, {"id": "b", "t": "\"Aspirin relieves pain during a myocardial infarction.\""}, {"id": "c", "t": "\"Aspirin dissolves clots that are forming in your coronary arteries.\""}, {"id": "d", "t": "\"Aspirin can lower total cholesterol.\""}], "correct": "a", "rationale": "Aspirin decreases platelet aggregation and inhibits vasoconstriction that can cause a myocardial infarction. The nurse should instruct the client to take 81 to 325 mg of aspirin each day with food to reduce the risk for a formation of a thrombus as well as to monitor for and report tinnitus and any indication of bleeding, such as tarry stools, bruising, or bleeding gums.", "whyNot": {"b": "Pain associated with a myocardial infarction requires an opioid analgesic for relief. Aspirin will not alleviate ischemic pain.", "c": "Aspirin can relieve mild to moderate pain and reduce inflammation and fever. However, it does not dissolve clots. Thrombolytic therapy", "d": "Aspirin can relieve mild to moderate pain, reduce inflammation, and fever. However, it does not lower total cholesterol. Statin"}, "keyConcept": "Low-dose daily aspirin is prescribed for clients who have angina or suspected coronary artery disease to decrease platelet aggregation and inhibit vasoconstriction that can cause a myocardial infarction. The nurse should instruct the client to take 81 to 325 mg of aspirin each day with food to reduce the risk for a formation of a thrombus as well as to monitor for and report tinnitus and any indication of bleeding, such as tarry stools, bruising, or bleeding gums. Clients who have new-onset angina should call emergency services and then chew 4 chewable aspirin, which are 81 mg each, to initiate the antiplatelet effects."}, {"id": 10666, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse advises a client with congestive heart failure and a new prescription for furosemide to take the medication in the morning. Why is this the recommendation?", "choices": [{"id": "a", "t": "Additional nighttime accumulation of fluid can be excreted."}, {"id": "b", "t": "Taking the drug in the daytime will prevent disturbance of sleep."}, {"id": "c", "t": "Electrolyte balance is maintained with morning administration of the medication."}, {"id": "d", "t": "The drug is more rapidly absorbed when the client is awake."}], "correct": "b", "rationale": "al 5% Easy Treatment for congestive heart failure often includes loop diuretic therapy with furosemide or bumetanide to reduce peripheral and © I 3% pulmonary edema by reducing sodium and water retention by the kidney. Furosemide and bumetanide may result in hypokalemia from . Other medications used for treatment of heart failure include angiotensin-converting enzyme inhibitors (ACEls), including Lisinopril, enalapril, and captopril; angiotensin II receptor blockers (ARBs) such as valsartan and losartan; beta-blockers, including metoprolol or carvedilol; and digoxin, which is a cardiac inotrope that increases the contractility of the heart and reduces heart rate. Advise clients to take furosemide early in the day to avoid the disturbance in sleep caused by nighttime urination.", "whyNot": {"a": "The time of administration does not affect the mechanism or efficacy of the drug.", "c": "The time of administration does not affect electrolyte balance.", "d": "The time of administration does not affect absorption of the drug."}, "keyConcept": "Heart failure results in volume overload coupled with inadequate perfusion. Loop diuretics, including furosemide (Lasix) and bumetanide (Bumex) interfere with reabsorption of sodium and water by the kidney, resulting in diuresis. This results in reduction of preload and improves symptoms in clients with heart failure."}, {"id": 10667, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who just returned from cardiac catheterization. Which of the following is an appropriate nursing intervention for this client?", "choices": [{"id": "a", "t": "Encourage ambulation"}, {"id": "b", "t": "Limit motion of the affected extremity"}, {"id": "c", "t": "Place a warm compress on the puncture site"}, {"id": "d", "t": "Place the client in a side-lying position eck Answer"}], "correct": "b", "rationale": "Indications for coronary catheterization include acute coronary syndrome, pre-operative coronary assessment, evaluation of aortic stenosis, © I mitral valve regurgitation; and coronary/hemodynamic evaluation in congestive heart failure. Depending upon the procedure, D | anticoagulation may be administered. Complications of coronary catheterization can include dysrhythmia, stroke, bleeding, vascular injury, contrast reaction, air embolism, thromboemboli, pulmonary edema and vagal stimulation with bradycardia. The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less. Movement is discouraged immediately after catheterization since the puncture site may hemorrhage.", "whyNot": {"a": "The site should be protected by placing the client in the supine position with the extremity straightened. Movements should be", "c": "The puncture site should be protected. Warm compresses facilitate hemorrhage. Sandbags or pressure bandages are used to promote", "d": "The client should be in the supine position with the extremity extended and the head at no more than 30 degrees of elevation."}, "keyConcept": "The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less."}, {"id": 10668, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a student nurse about cardioversion. Which of the following information should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Use ultrasound gel on the conductor paddles."}, {"id": "b", "t": "Place the conductor paddles over the client's clothing."}, {"id": "c", "t": "Avoid touching the client's bed during the procedure."}, {"id": "d", "t": "Turn the synchronize mode off prior to the procedure."}], "correct": "c", "rationale": "A The nurse should instruct the student to avoid touching the client, the client's bed, or any equipment near the client to prevent injury to the B : nurse from an electrical charge. o:", "whyNot": {"a": "The nurse should instruct the student to use a conducting medium with electrical conductivity to protect the client's skin and safely", "b": "The nurse should instruct the student to place the conductor paddles on the client's skin to safely deliver the electrical current.", "d": "The nurse should instruct the student to set the defibrillator to synchronized mode to discharge the shock during ventricular"}, "keyConcept": "Electrical cardioversion is used to treat tachydysrhythmias, such as atrial fibrillation, supraventricular tachycardia, or ventricular tachycardia with a pulse. The defibrillator is synchronized with the client's QRS complex to ensure electrical impulses are discharged during ventricular depolarization. The client's ECG monitor is connected to the external defibrillator. A conductive medium gel is applied to the paddles, which are placed in the front and the back of the client. The client will receive moderate sedation and supplemental oxygen via a bag-valve-mask. The voltage from the cardioversion can vary from 50 to 360 joules. The nurse should monitor the client's ECG, vital signs, oxygen saturation, and airway throughout the procedure, but the nurse should not touch the client, the client's bed, or any equipment near the client during the discharge of the electrical current to prevent injury to the nurse. The nurse should monitor the client's ECG, vital signs, airway, and level of consciousness following the procedure. The nurse should assess the client for conversion to normal sinus rhythm, strong peripheral pulses, and adequate blood pressure, which indicate a successful response to cardioversion."}, {"id": 10669, "cat": "NCLEX 12- Cardiovascular", "stem": "A client has undergone cardiac catheterization. The nurse should prioritize palpation of the pulse at which of the following sites?", "choices": [{"id": "a", "t": "At the insertion site"}, {"id": "b", "t": "In extremities"}, {"id": "c", "t": "Distal to the catheter insertion site"}, {"id": "d", "t": "Above (proximal to) the catheter insertion site"}], "correct": "c", "rationale": "A After cardiac catheterization, the pulse distal to catheter site should be assessed every 2-3 hours to make sure that there is no clotting, B LC bleeding, or obstruction of the blood vessel. o on Coronary Artery Right Catheter Coronary Entrance Artery Catheter Heart Catheter", "whyNot": {"a": "The nurse would not palpate the pulse at the insertion site; the nurse should keep pressure and a dressing on the site to avoid blood loss.", "b": "Checking pulses in extremities may be valid but the nurse must first check the area distal to the catheterization site.", "d": "The nurse must check the area distal to the catheter site, not above the site."}, "keyConcept": "Cardiac catheterization refers to the insertion of a catheter into a vein or artery, usually from a groin or jugular access site, which is then guided into the heart. Cardiac catheterization is performed for diagnostic and/or interventional purposes. The client is required to remain on bed rest, usually for 6 hours, after catheterization. When caring for a client after this procedure, the nurse should perform a neurovascular assessment with each set of vital signs. This should include palpation of the pulse distal to the insertion site. The puncture site should be assessed every 30 minutes for 4 hours, then hourly until ambulation. The site should be reassessed after the client's first ambulation and then a minimum of 4 hourly assessments prior to discharge."}, {"id": 10670, "cat": "NCLEX 12- Cardiovascular", "stem": "A client reports to the nurse that his anginal pain is worse after activity. To help the client understand this, the nurse explains that angina pectoris is a sign of which of the following?", "choices": [{"id": "a", "t": "Mitral insufficiency"}, {"id": "b", "t": "Myocardial ischemia"}, {"id": "c", "t": "Myocardial infarction"}, {"id": "d", "t": "Coronary embolism"}], "correct": "b", "rationale": "A i 9% Moderate Angina pectoris is chest pain caused by reduced perfusion to cardiac muscle with subsequent hypoxemia. es rs 10%", "whyNot": {"a": "This refers to an incompetent mitral valve. While it could indirectly relate to angina, that would not be the direct cause.", "c": "Cell death does not occur in angina. Cell death occurs in myocardial infarction after complete blockage of flow to the cardiac muscle.", "d": "Coronary thrombosis, not embolism, is the usual mechanism of occlusion or narrowing of the coronary arteries in acute coronary"}, "keyConcept": "Acute coronary syndrome refers to a range of conditions associated with sudden reduction of blood flow to the heart. These conditions include angina, characterized by ischemic chest pain, and myocardial infarction, characterized by cell death and destruction of heart tissue. Rapid diagnosis is important to outcome in ACS. Treatment goals include improved or restored perfusion, treatment of complications and prevention of future cardiovascular events. 2 = ® 4 z = a iat g <"}, {"id": 10671, "cat": "NCLEX 12- Cardiovascular", "stem": "which of the following? O A. Below normal O B. Within normal limits O C. Above normal O D. Consistent with pulmonary edema", "choices": [{"id": "a", "t": "Below normal"}, {"id": "b", "t": "Within normal limits"}, {"id": "c", "t": "Above normal"}, {"id": "d", "t": "Consistent with pulmonary edema"}], "correct": "c", "rationale": "A Hi 18% Moderate 3 14% A pulmonary capillary wedge pressure (PCWP) is obtained by wedging a catheter in a tapering branch of one of the pulmonary arteries. It is ec | 54% an estimate of the left ventricular end diastolic pressure or preload of the heart. A PCWP higher than 18 mmHg suggests heart failure. A D Hi 13% normal PCWP is 5-12 mmHg. As PCWP increases, pulmonary edema may occur. Levels over 25-30 mmHg are consistent with pulmonary edema. Mm 2 (S g Prosi Pot g Thormitar @ a Peto Beloon @) <k Zs Distal Pot ® Pulmonary Artery Superior Vena Cava @ Right Ventricle", "whyNot": {"a": "Normal pulmonary capillary wedge pressures are 5-12 mmHg. This pressure is above normal.", "b": "APCWP >12 mmbg is above normal.", "d": "Pulmonary edema occurs at PCWPs above 25-30 mmHg."}, "keyConcept": "The pulmonary wedge pressure or pulmonary capillary wedge pressure is the pressure measured by wedging a pulmonary catheter with an inflated balloon into a small pulmonary arterial branch. It estimates the left ventricular end diastolic volume and pressure. Increased pulmonary wedge pressure suggest congestive heart failure. Pressures > 20 mm Hg usually result in pulmonary edema."}, {"id": 10672, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client who has had nausea, vomiting, and diarrhea for the past 3 days. Which of the following findings should indicate to the nurse the client is experiencing hypovolemia?", "choices": [{"id": "a", "t": "Decreased heart rate"}, {"id": "b", "t": "Decreased hematocrit"}, {"id": "c", "t": "Increased blood pressure"}, {"id": "d", "t": "Weak pulse"}], "correct": "d", "rationale": ", which are rated as +1 and can B H 13% be described as thready. Other manifestations that can indicate hypovolemia include: cl 7% + Increased BUN oo. i! 11% + Increased hematocrit + Increased urine specific gravity + Decreased urine output + Decreased central venous pressure + Decreased capillary refill + Decreased skin turgor 2 = ® 4 z = a iat g <", "whyNot": {"a": "The heart rate of a client who has hypovolemia will be increased to compensate for the decreased circulating volume.", "b": "The hematocrit of a client who has hypovolemia will be increased due to the decreased circulating volume.", "c": "The blood pressure of a client who has hypovolemia will be decreased due to the decreased circulating volume."}, "keyConcept": "The nurse caring for a client who has been experiencing nausea, vomiting, and diarrhea for the past 3 days should be able to identify manifestations of hypovolemia and incorporate interventions into the plan of care to manage the manifestations."}, {"id": 10673, "cat": "NCLEX 12- Cardiovascular", "stem": "the most important factor to consider for enhanced absorption?", "choices": [{"id": "a", "t": "The site should be near the heart."}, {"id": "b", "t": "The site should be over a bony prominence."}, {"id": "c", "t": "The site should be muscular if possible."}, {"id": "d", "t": "The site should not be hairy."}], "correct": "d", "rationale": "A Hi 14% Moderate , intravenous infusion, transdermal patches, and topical ointment formulations. It is used to © | | 7% treat ischemia and relieve associated chest pain in clients with coronary heart disease, including angina and myocardial infarction. @pD PF 11% Nitroglycerin dilates the veins and arteries to improve the flow of blood to the heart muscle. The side effects of nitroglycerin include hypotension, tachycardia, flushing, and headache. The site of application should be free of hair to increase absorption. Nurses should also avoid application of nitroglycerin ointment on distal extremities since they may receive less blood flow and decrease absorption. Clients should be cautioned that concurrent us of medications for erectile dysfunction with nitroglycerin is contraindicated.", "whyNot": {"a": "Nitroglycerin ointment is often placed on the chest, but placement near the heart is not the most important factor in absorption.", "b": "This is not an important factor for promoting absorption.", "c": "This is not the most important factor in absorption."}, "keyConcept": "When applying topical nitroglycerin ointment, the nurse should rotate sites to prevent skin irritation and should remove patches or ointment from the previous site before application of a new patch. Ointment should be applied by using dose-measuring application papers supplied with the ointment. The nurse should squeeze ointment on the printed measuring scale and use the paper to spread ointment onto non-hairy area of skin (chest, abdomen, thighs; avoid distal extremities) in a thin, even layer, covering a 2- 3-inch area. Ointment should not come in contact with hands. It should not be massaged or rubbed, because this will increase absorption and interfere with sustained action. An occlusive dressing may be applied if prescribed by the healthcare provider."}, {"id": 10674, "cat": "NCLEX 12- Cardiovascular", "stem": "action? O A. Administration of digoxin O B. Administration of amiodarone O C. Defibrillation O D. Synchronized cardioversion", "choices": [{"id": "a", "t": "Administration of digoxin"}, {"id": "b", "t": "Administration of amiodarone"}, {"id": "c", "t": "Defibrillation"}, {"id": "d", "t": "Synchronized cardioversion"}], "correct": "c", "rationale": "a : C. Defibrillation Fel cm | 10% A The rhythm is ventricular fibrillation. Ventricular fibrillation is a rhythm of chaotic electrical activity in the heart that renders the heart ec TY 70% = = unable to effectively pump and maintain cardiac output. This is a terminal rhythm. Immediate CPR is indicated, followed by defibrillation as D Hi 17% ¢ soon as the defibrillator is available. Defibrillation refers to nonsynchronized random administration of shock during a cardiac cycle. It a < results in interruption and termination of the abnormal electrical rhythm, allowing the sinus node to resume normal pacemaker activity.", "whyNot": {"a": "Digoxin is used in heart failure and atrial fibrillation.", "b": "Amiodarone is an antiarrhythmic used in the treatment of ventricular arrhythmias, but the priority intervention in ventricular fibrillation is", "d": "Synchronized cardioversion is used for the treatment of stable tachyarrhythmia."}, "keyConcept": "VF is an irregular heartbeat characterized by uncoordinated contractions of the ventricle. During ventricular fibrillation, the heart does not pump blood effectively. It is the leading cause of death in cardiac arrest and occurs most frequently in clients with preexisting heart disease, including myocardial infarction. Immediate chest compressions and rapid defibrillation increase the risk of survival."}, {"id": 10675, "cat": "NCLEX 12- Cardiovascular", "stem": "@0@ ¥ Vira x «<> ¢G Na Rec xX ™~ Inbc x student.atitesting.com/LT| ™ = Inbc x unt x GR unt x ta Go x @tTe x Fon x Cma x O@ Mic x Tutorial: BoardVitals NCLEX Prep RN a Pas ati Module: Quizzes & Assignments Convert study guide ® AT| xX % CLOSE Dashboard Quiz ~ Performance ~ { Browse Questions ~ it Search Questions Ja) ® Nev x Qa * Finish update", "choices": [{"id": "a", "t": "Upper half of the artery, near the chin"}, {"id": "b", "t": "Lower half of the artery, at the level of the cricoid cartilage."}, {"id": "c", "t": "Outer aspect of the artery, toward the back of the neck"}, {"id": "d", "t": "Inner aspect of the artery, toward the trachea"}], "correct": "b", "rationale": "‘i When palpating the carotid artery, the nurse should check the pulse on the lower half of the artery, at the level of the cricoid cartilage. es ri Palpating the artery too high on the neck could result in stimulation of the carotid sinus, which could cause a drop in the heart rate.", "whyNot": {"a": "The nurse should palpate the carotid artery in the lower half of the artery, closer to the clavicle. Palpating the carotid artery high on the", "c": "The nurse must assess the lower half of the artery.", "d": "The nurse must assess the lower half of the artery."}, "keyConcept": "When assessing the carotid artery, the nurse will palpate one side at a time, gently tilting the head to relax the sternomastoid muscle. The carotid artery is palpated by placing the fingers near the client's upper neck between the sternomastoid and trachea at the level of the cricoid cartilage."}, {"id": 10676, "cat": "NCLEX 12- Cardiovascular", "stem": "prioritized by the nurse when preparing to perform cardioversion?", "choices": [{"id": "a", "t": "Sedate the client"}, {"id": "b", "t": "Select the correct energy level"}, {"id": "c", "t": "Push the synchronize button"}, {"id": "d", "t": "Charge the defibrillator"}], "correct": "c", "rationale": "A Hi 15% Moderate z The rhythm is supraventricular tachycardia with a narrow QRS complex. Since the client is unstable, cardioversion is indicated. B H URS a Cardioversion is a procedure that delivers a shock synchronized on the R wave of the QRS complex. When the synchronizer button is gq activated, there is a delay in the shock while the machine reads the ECG rhythm and synchronizes shock delivery. Ifa shock is delivered o: Ges < during the T wave or repolarization, it could cause a lethal arrhythmia such as ventricular tachycardia or ventricular fibrillation. D i 10% Synchronized cardioversion is used to treat unstable tachyarrhythmias, including supraventricular tachycardia, multifocal atrial tachycardia, atrial flutter, and atrial fibrillation.", "whyNot": {"a": "Ifa patient is unstable, sedation should not delay cardioversion.", "b": "The most important task to prioritize is to set the synchronize button since the defibrillator will deliver a high-energy defibrillating shock", "d": "The most important consideration in this procedure is to activate the synchronization mode to prevent unintentional defibrillation at high"}, "keyConcept": "Treatment of tachycardia is based on the rhythm and morphology of the QRS complexes and on clinical signs and symptoms of instability. Symptomatic tachyarrhythmias are treated with synchronized cardioversion. Delivery of a shock during the T wave (repolarization of the ventricles) can result in a lethal arrhythmia. The initial energy dose for synchronized cardioversion is 50-100 Joules (J) with a biphasic defibrillator and 100 J with a monophasic defibrillator. If the client becomes hemodynamically unstable, the nurse should turn off the synchronizer switch and defibrillate."}, {"id": 10677, "cat": "NCLEX 12- Cardiovascular", "stem": "@ @ % Vie x x. Rec x M Inb X ™ Inbe x [J Unt x GR Unt x a Go x @TE x Fon x € ma x <€< > G 23 student.atitesting.com/LT| Tutorial: BoardVitals NCLEX Prep RN sg Poa ati Module: Quizzes & Assignments Dashboard Quiz ~ Performance ~ @ Mic x Convert study guide @ atl xX @GnNe x | nNCci x Pree x + v % CLOSE Qa * es * © tb Finish update : { Browse Questions ~ it Search Questions [a]", "choices": [{"id": "a", "t": "Cardiac tamponade: Loud heart sounds and jugular vein distention"}, {"id": "b", "t": "Bacterial endocarditis: This most commonly occurs after a respiratory infection or myocardial infarction"}, {"id": "c", "t": "Venous thromboembolism: Risk factors include stasis and hypercoagulability"}, {"id": "d", "t": "Venous insufficiency: An inflammatory process that places clients at risk for pulmonary emboli"}], "correct": "c", "rationale": "Venous thromboembolism is a peripheral vascular disorder that can occur as a result of stasis, impaired venous return, and a hypercoagulation clotting disorder.", "whyNot": {"a": "Cardiac tamponade may cause jugular vein distention, but it also causes muffled heart sounds, not loud sounds.", "b": "Bacterial endocarditis most commonly occurs due to bacterial aggregation on abnormal or prosthetic cardiac valves or as a result of", "d": "Venous insufficiency is a non-inflammatory vascular disorder that is caused by insufficient venous return."}, "keyConcept": "Deep venous thrombosis (DVT) and pulmonary embolism(PE) are manifestations of venous thromboembolism (VTE) Symptoms of DVT include swelling, warmth, and erythema at the site. On physical examination, signs include calf pain on dorsiflexion of the foot, known as Homans sign; palpable, indurated, cordlike, tender vein; and discoloration of the lower extremity. In this setting, DVT is a risk factor for PE, which can result in hemodynamic collapse and death."}, {"id": 10678, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client admitted with congestive heart failure who is receiving furosemide. Which of the following laboratory results should cause concern?", "choices": [{"id": "a", "t": "Glucose 115 g/dL"}, {"id": "b", "t": "Calcium 8.8 mg/dL."}, {"id": "c", "t": "Potassium 2.4 mEq/L © b. Sodium 135 mEq/L"}], "correct": "c", "rationale": "Diuretic drugs increase urine output by the kidney, known as diuresis. This occurs by alterations in sodium excretion in the kidney. Furosemide is a common loop diuretic, which refers to its mechanism of action at the loop of Henle in the nephron of the kidney. Loop diuretics block reabsorption of sodium by the sodium-potassium-chloride pump in the loop of Henle. As a result, the urine that arrives at the distal tubule of the nephron has a high sodium content. The receptors in the distal tubule sense the higher sodium content and sodium is reabsorbed while potassium is excreted. Potassium is critical to muscle contraction and nerve conduction. Normal potassium levels are 3.5-5.1 mEq/dL. Levels below 2.5 mEq/L can result in muscle weakness that usually begins in the lower extremities, with depression of deep tendon reflexes. Hypokalemia can also cause muscle cramps and muscle breakdown (rhabdomyolysis). Respiratory muscle weakness can lead to respiratory failure and death. Hypokalemia can result in ileus, with anorexia, nausea, vomiting, and abdominal distention. Cardiac abnormalities that occur with hypokalemia can include bradycardia, AV block, ventricular tachycardia, premature atrial beats, paroxysmal atrial tachycardia, and ventricular fibrillation. Symptoms include weak pulses, orthostatic hypotension, flaccid paralysis, confusion, shallow respirations with decreased breath sounds, decreased bowel sounds, and decreased deep tendon reflexes. ECG signs of hypokalemia include ST depression, inverted T waves, and prominent U waves. Hypokalemia is sometimes associated with depletion of magnesium, so it is important to check the magnesium level in a client with low potassium levels. Causes of hypokalemia include laxatives, diuretics, corticosteroids, anorexia, fasting, hypervolemia, Cushing’s syndrome, and fluid loss from vomiting, diarrhea, or NG suction. Treatment is elimination of the cause and supplementation of potassium. IV potassium chloride is required in severe hypokalemia. Saline solution should be used initially because dextrose solutions stimulate insulin, which drives potassium into cells.", "whyNot": {"a": "Normal random glucose levels range from 65-110 mg/dL.", "b": "Normal calcium levels range from 8.5-10.2 mg/dL."}, "keyConcept": "Loop diuretics include furosemide (Lasix) and bumetanide (Bumex.) They are often used in treatment of heart failure and other states of volume overload and can result in hypokalemia. Hypokalemia can result in weakness or paralysis, which may affect cardiac muscle, smooth muscle in the Gl tract, and muscles of respiration. Manifestations include depressed deep tendon reflexes, decreased bowel sounds, and shallow respirations. ECG changes in hypokalemia include depression of the ST segment, flat or inverted T waves and prominent u-waves."}, {"id": 10679, "cat": "NCLEX 12- Cardiovascular", "stem": "oO @ XX Vira x Na Rec xX ™ Inbe x ™ Inbe x =) Unt x Unt x ta Gor x @ TEA x On! x G@ Ma x @ Mic x Convert study guide (J ATI xX ®@ Nev xX {. NC! x +} TEA xX + v «> ¢ student.atitesting.com/LT| Q * x * => tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE sg Pas ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Be sure to get 8-10 hours of sleep each night"}, {"id": "b", "t": "Do the daily chores in the morning before getting tired"}, {"id": "c", "t": "On one day each week, do nothing"}, {"id": "d", "t": "Schedule regular rest periods throughout the day"}], "correct": "d", "rationale": "al 3% Easy The nurse should recommend that the client takes regularly scheduled rest periods throughout the day.", "whyNot": {"a": "Although getting 8-10 hours of sleep each night is desirable, a client with HF will continue to get tired during the day. ep ft 93%", "b": "Doing all the chores in the morning may not be realistic for a client with HF. This client may have to do a chore and then sit down to rest for", "c": "Resting one day each week will not help the fatigue that a client with HF will experience on the other six days."}, "keyConcept": "Patients with heart failure are helped by resting as needed to allow the heart to rest and prevent immediate damage or decompensation. The heart has become an enlarged ineffective pump that has not improved with the permanent chronic disease of heart failure."}, {"id": 10680, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who is experiencing fluid volume deficit. Which of the following manifestations should the nurse expect?", "choices": [{"id": "a", "t": "Neck veins flatten when lying supine."}, {"id": "b", "t": "Ankles have pitting edema bilaterally."}, {"id": "c", "t": "Urinary output is greater than intake in 24 hours."}, {"id": "d", "t": "Skin turgor returns to expected position within 2 seconds."}], "correct": "a", "rationale": "The nurse should expect a client who has fluid volume deficit to have neck veins that flatten when lying supine and inhaling, due to . cm 19% o| 4%", "whyNot": {"b": "The nurse should expect a client who has fluid volume deficit to have dry mucous membranes and sunken eyeballs with decreased", "c": "The nurse should expect a client who has fluid volume deficit to have a urinary output that is less than intake in a 24-hr period due to", "d": "The nurse should expect a client who has fluid volume deficit to have a slowed return of skin turgor of 3 seconds or more."}, "keyConcept": "Fluid volume deficit is due to a loss of fluids and electrolytes and is initially lost from the intravascular system, causing hypovolemia. Hypovolemia, or fluid volume deficit, can occur from a lack of fluid intake, bleeding, fluid losses from the skin; gastrointestinal tract; or kidneys, and third spacing of fluid. Third spacing is when fluid shifts from the vascular system and moves into areas that are not available, as extracellular fluid. The fluid can be isolated in injured tissue, peritoneal or pleural cavities, or in the bowel."}, {"id": 10681, "cat": "NCLEX 12- Cardiovascular", "stem": "place the client to best decrease preload?", "choices": [{"id": "a", "t": "Contour"}, {"id": "b", "t": "Orthopneic"}, {"id": "c", "t": "Recumbent"}, {"id": "d", "t": "Trendelenburg"}], "correct": "b", "rationale": "’s paroxysmal dyspnea was probably due to sleeping in bed with the legs at the level of the heart; this position increases venous es rd 56% return from dependent body areas increasing the intravascular volume. Sitting up and leaning forward while keeping the legs dependent slows venous return as well as increases thoracic capacity. € |__| 22% om 18%", "whyNot": {"a": "The contour position is not considered a sleeping position.", "c": "This is not the best option for positioning for this client, as the legs would still be at the level of the heart.", "d": "This puts the client’s head below the level of the heart; it is not the best option."}, "keyConcept": "The orthopneic position is also known as the tripod position. It places the client in a sitting position or on the side of the bed with an overbed table in front to lean on and several pillows on the table to rest on. 2 (S g o 5 [a < Clients who are having difficulty breathing are often placed in this position because it allows maximum expansion of the chest. The position is also used to improve breathing for clients who have COPD (chronic obstructive pulmonary disease.) O Location Qricemat Narrowing of the ‘coronary ‘coronary / artery artery Normal"}, {"id": 10682, "cat": "NCLEX 12- Cardiovascular", "stem": "After receiving morning laboratory results, the nurse will need to intervene for which of the following clients? O A.A client with end-stage liver disease and elevated ammonia level O B. A client receiving warfarin with an INR of 2.0 O C. A client with heart failure who has a digoxin level of 2.4 ng/mL O D. A client with myocardial infarction and elevated CK-MB", "choices": [{"id": "a", "t": "Elevated ammonia levels are an expected finding in end-stage liver disease; although it is important to address this finding, it is not"}, {"id": "b", "t": "Warfarin is a vitamin K-dependent anticoagulant. Efficacy is monitored by the PT and INR. This is an expected finding. Depending on the"}, {"id": "c", "t": "Digoxin is a cardiac glycoside used for the treatment of congestive heart failure and atrial fibrillation."}, {"id": "d", "t": "CK-MB is a cardiac isoenzyme released from a damaged myocardium. Elevation of cardiac isoenzymes is expected in myocardial"}], "correct": "c", "rationale": "Digoxin is a cardiac glycoside used for the treatment of congestive heart failure and atrial fibrillation. Therapeutic levels are 0.8-2 ng/L. Toxic levels are >2 ng/L. Toxic effects of digoxin are most likely to occur in clients with hypokalemia, hypomagnesemia, hypoxia, hypercalcemia, and heart disease. Toxicity results in exaggeration of the pharmacological effect, including tachyarrhythmia and bradyarrhythmia. Clinical signs include nausea, vomiting, headache, disorientation, seizures, and hallucinations. A typical visual change associated with digoxin toxicity is seeing yellow or yellow-green halos around objects. There has been speculation that Vincent Van Gogh experienced digoxin toxicity.", "whyNot": {"a": "Elevated ammonia levels are an expected finding in end-stage liver disease; although it is important to address this finding, it is not", "b": "Warfarin is a vitamin K-dependent anticoagulant. Efficacy is monitored by the PT and INR. This is an expected finding. Depending on the", "d": "CK-MB is a cardiac isoenzyme released from a damaged myocardium. Elevation of cardiac isoenzymes is expected in myocardial"}, "keyConcept": "Digoxin is used for treatment of congestive heart failure and atrial fibrillation. Digoxin levels must be monitored carefully, as toxic effects occur with levels of more than 2 ng/L and may occur at lower levels in clients with coexisting hypokalemia, hypercalcemia, hypomagnesemia, hypoxia, and heart disease."}, {"id": 10683, "cat": "NCLEX 12- Cardiovascular", "stem": "interventions is most appropriate with this diagnosis? Atrial Fibrillation", "choices": [{"id": "a", "t": "Prepare the client for unsynchronized cardioversion"}, {"id": "b", "t": "Administer 100% oxygen and prepare to assist with endotracheal intubation"}, {"id": "c", "t": "Administer anticoagulant therapy as ordered"}, {"id": "d", "t": "Monitor intake and output for the next 24 hours"}], "correct": "c", "rationale": "‘i B due to pooling of blood in the atrium. If the client has a rapid ventricular response, then agents may be given to control the rate and rhythm. I o: halehebehonela he , Le \\ Anticoagulant medications are commonly prescribed for clients with atrial fibrillation, to reduce the risk of stroke from thromboembolism", "whyNot": {"a": "If the duration of atrial fibrillation is unknown, synchronized cardioversion is usually performed after the client is anticoagulated, to avoid", "b": "The client may need oxygen if he is experiencing shortness of breath, but no indication is given for rapid intubation in this client.", "d": "It may be necessary to monitor fluid status in clients who develop heart failure due to an arrhythmia, but it is not appropriate in this case."}, "keyConcept": "Atrial fibrillation (AF) refers to a rhythm caused by disorganized electrical impulses that usually originate in the roots of the pulmonary veins. This leads to irregular conduction of ventricular impulses and, depending on the rate of ventricular response, ineffective ventricular filling or contraction may occur. Clients with AF may complain of palpitations, weakness, fatigue, dizziness, dyspnea, and ischemic chest pain. AF is diagnosed by electrocardiogram (ECG). It is characterized on ECG by absence of P waves, with disorganized electrical activity, and irregular R-R intervals. The figure below demonstrates atrial fibrillation and a normal tracing that displays P waves before each QRS complex. ld pal"}, {"id": 10684, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is administering prescribed vasopressin to a client with diabetes insipidus. The nurse will monitor the client for which of the following adverse effects?", "choices": [{"id": "a", "t": "Rash"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Chest pain"}, {"id": "d", "t": "Sore throat"}], "correct": "c", "rationale": "A i 9% Moderate ce 8% Vasopressin (Pitressin) is used to treat central diabetes insipidus and gastrointestinal hemorrhage from esophageal varices. It is an analog of ec PF 77% antidiuretic hormone and causes vasoconstriction and reabsorption of water in the collection duct of the kidney. Adverse effects include , myocardial infarction, TIA, stroke, bowel ischemia, and dysrhythmia. The nurse should monitor the client for signs of toxicity, which include angina (chest pain). Pitressin is contraindicated in ischemic heart disease and is not indicated in clients with nephrogenic diabetes insipidus. Alcohol, lithium, phenytoin, and epinephrine may increase the effects of vasopressin.", "whyNot": {"a": "Arash is not a typical adverse effect of vasopressin.", "b": "Diarrhea is not a common adverse effect, nausea is though.", "d": "Asore throat is not an adverse effect associated with vasopressin."}, "keyConcept": "Vasopressin (Pitressin) is a synthetic analog of antidiuretic hormone, which is released by the posterior pituitary gland. Vasopressin is used to treat GI hemorrhage from esophageal varices and central diabetes insipidus. Adverse effects include hypertension, myocardial infarction, TIA, stroke, bowel ischemia, and cardiac arrhythmias."}, {"id": 10685, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing nutritional teaching to the guardian of an infant who has heart failure. Which of the following guardian statements indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Iwill feed my baby every 4 hours.\""}, {"id": "b", "t": "\"I will add corn oil to my baby's bottles.\""}, {"id": "c", "t": "\"Iwill give my baby a minimum of 1 hour to finish a bottle.\""}, {"id": "d", "t": "\"I will place my baby on her stomach for a few minutes each day.\""}], "correct": "b", "rationale": "The guardian should add corn oil produced just for consumption by infants to fortify the formula by increasing the number of calories per es rd 31% ounce. This addition allows the infant to consume more calories in a smaller amount of formula. ci 26% om 14%", "whyNot": {"a": "The guardian should feed the infant every 3 hr because of the increased metabolic rate and fatigue that limits adequate calorie intake.", "c": "The nurse should instruct the guardian to limit bottle time to 30 min. The guardian should avoid allowing the infant to take as much time", "d": "The nurse should instruct the guardian to hold the infant at a 45° angle during feedings. The guardian should avoid placing the infant"}, "keyConcept": "Manifestations of Heart Failure «Tachycardia + Restlessness + Dyspnea + Nasal flaring + Wheezing + Grunting + Weight gain + Distended neck veins + Cool, pale extremities + Periorbital edema . er + Decreased urine output"}, {"id": 10686, "cat": "NCLEX 12- Cardiovascular", "stem": "after the 1-month post-discharge appointment with the surgeon?", "choices": [{"id": "a", "t": "Showering"}, {"id": "b", "t": "Lifting anything heavier than 10 pounds"}, {"id": "c", "t": "A program of gradually progressive walking"}, {"id": "d", "t": "Light housework"}], "correct": "b", "rationale": "a| 1% Easy Most clients who have undergone cardiac surgery have a median sternotomy incision, which takes about 3 months to heal. es sd 93%", "whyNot": {"a": "Showering or bathing is allowed as long as the incision is well-approximated with no open areas or drainage.", "c": "Activities should be gradually resumed on discharge.", "d": "Measures that promote healing include avoiding heavy lifting, performing muscle reconditioning exercises, and using caution when"}, "keyConcept": "Limitations after open heart surgery include no pushing/pulling for four weeks; no lifting more than 10 pounds for at least the four weeks and no lifting more than 20 pounds for weeks 4-8; no driving for four weeks; no reaching above the head for four weeks; splinting the chest with a pillow when deep breathing, coughing and getting in and out of chairs or bed for a minimum of four weeks; and pacing physical activity, and sexual activity. 2 = ® 4 z = a iat g <"}, {"id": 10687, "cat": "NCLEX 12- Cardiovascular", "stem": "A client has returned to his room after having surgery and the physician has ordered TED hose to be placed by the nurse. Which best describes the purpose of TED hose? O A.To control the client’s pain after surgery O B. To prevent infection in the lower extremities O C. To promote circulation and help prevent blood clots O D. To promote range of motion in the affected extremity", "choices": [{"id": "a", "t": "TED hose do not control the client’s pain."}, {"id": "b", "t": "TED hose do not prevent infection."}, {"id": "c", "t": "TED hose are anti-embolism stockings that are designed to promote circulation and blood flow back to the heart."}, {"id": "d", "t": "TED hose do not promote range of motion."}], "correct": "c", "rationale": "TED hose are anti-embolism stockings that are designed to promote circulation and blood flow back to the heart. They help prevent the development of blood clots.", "whyNot": {"a": "TED hose do not control the client’s pain.", "b": "TED hose do not prevent infection.", "d": "TED hose do not promote range of motion."}, "keyConcept": "TED hose are \"thromboembolic deterrent\" stockings, also known as anti-embolism stockings. TED hose have a compression level < 20 mm Hg. They are prescribed for non-ambulatory clients to promote venous return, prevent venous stasis, and prevent clot formation in the deep veins of the lower extremities. Compression socks are used for ambulatory clients with circulatory problems such as venous insufficiency, lymphedema, and varicose veins. Compression levels range from 15 to 20 mm Hg to 60 mmHg (above 20 mmHg is considered prescription strength). Compression socks help keep blood from pooling in the ankles, where the pressure is the greatest. They can be worn for up to six months or more."}, {"id": 10688, "cat": "NCLEX 12- Cardiovascular", "stem": "to monitor to determine whether to increase or decrease exercise levels?", "choices": [{"id": "a", "t": "Pulse rate"}, {"id": "b", "t": "Blood pressure"}, {"id": "c", "t": "Body temperature"}, {"id": "d", "t": "Respiratory rate"}], "correct": "a", "rationale": "o; The client who is on a progressive exercise program at home after an MI should be taught to monitor heart rate. The pulse rate is expected to B ] increase with exercise but should not increase more than 25 bpm above baseline. ©", "whyNot": {"b": "Although blood pressure may increase with exercise, this is not the most important vital sign to monitor when adjusting exercise levels.", "c": "Body temperature may increase with exercise, but this is not considered the most important vital sign to use when adjusting exercise", "d": "Respiratory rate may increase with exercise, but this is not considered the most important vital sign to use when adjusting exercise levels."}, "keyConcept": "Guidelines from the American Heart Association (AHA) for management of myocardial infarction recommend that clients may begin walking soon after discharge, resume sexual activity in as early as one week, and drive within three weeks. Recovery times will vary depending on individual circumstances. When advising the client to gradually increase the level of exertion, the nurse should advise the use of the pulse to monitor cardiac demand. The heart rate increases in response to increased cardiac demand. The recovering client should gradually build up a tolerance to exercise."}, {"id": 10689, "cat": "NCLEX 12- Cardiovascular", "stem": "(ICP) monitoring. The nurse should monitor the client for which of the following complications related to the ventriculostomy?", "choices": [{"id": "a", "t": "Headache"}, {"id": "b", "t": "Infection"}, {"id": "c", "t": "Bradypnea"}, {"id": "d", "t": "Hypertension"}], "correct": "b", "rationale": "‘i The nurse should monitor a client who has a ventriculostomy for infection, which is a potential complication of this procedure. The nurse es a should use strict asepsis when caring for the client and the ICP monitoring equipment to avoid a life-threatening condition like meningitis. I ©", "whyNot": {"a": "The nurse should monitor a client who has a head injury for a headache; however, a headache does not indicate a complication directly", "c": "The nurse should monitor a client who has a head injury for slow respirations as well as for decreased oxygen saturation levels; however,", "d": "The nurse should monitor a client who has a ventriculostomy for hypertension; however, this is not a complication directly related to the"}, "keyConcept": "Invasive procedures and equipment, such as an intraventricular catheter, are used to monitor the intracranial pressure (ICP) of clients who have traumatic head injuries. These systems also provide access to cerebrospinal fluid for sampling and drainage. Because the catheter goes through the skull and directly into the ventricle of the brain, there is a potential for infection. Therefore, nurses must be careful to maintain strict asepsis while caring for these clients to avoid such a complication."}, {"id": 10690, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is reviewing the DASH diet for hypertension with a client during discharge teaching. Which of the following statements by the client indicates an understanding of the teaching? O A.\"My daily sodium consumption should be 3,000 milligrams.” O B. \"I should consume foods that are low in potassium.\" O C.\"I need to lose at least 25 pounds to see a decrease in my blood pressure.\" O D. \"| should consume low-fat dairy products.\"", "choices": [{"id": "a", "t": "The client's daily sodium consumption should be 1500 mg or less. This assists with lowering systolic and diastolic blood pressures, as well"}, {"id": "b", "t": "The nurse should encourage the client to consume high-potassium foods. This assists with lowering systolic and diastolic blood pressures,"}, {"id": "c", "t": "Blood pressure will typically decrease when a client has a weight loss of 4.5 to 6.8 kg (10 to 15 lb)."}, {"id": "d", "t": "The DASH (Dietary Approaches to Stop Hypertension) eating plan includes is a low sodium diet rich in fruits and vegetables, and low-fat or non-fat dairy, with whole grains."}], "correct": "d", "rationale": "The DASH (Dietary Approaches to Stop Hypertension) eating plan includes is a low sodium diet rich in fruits and vegetables, and low-fat or non-fat dairy, with whole grains. It is a high fiber, low to moderate fat diet, rich in potassium, calcium, and magnesium. Lifestyle modifications are the initial step in reduction of blood pressure in individuals with prehypertension or hypertension. Individuals with severe hypertension may not be able to eliminate medication, but the DASH diet can improve the response to medication and lower blood pressure. The DASH diet is associated with lower cholesterol, reduced insulin resistance, and reduced risk of developing diabetes when combined with exercise and weight loss. Blood Pressure Classification for Adults Category Systolic Diastolic Normal <120 and <80 Prehypertensive 120 to 139 or 80 to 89 | Stage 1 hypertension 140 to 159 or 90 to 99 [ Stage 2 hypertension > 160 or >110", "whyNot": {"a": "The client's daily sodium consumption should be 1500 mg or less. This assists with lowering systolic and diastolic blood pressures, as well", "b": "The nurse should encourage the client to consume high-potassium foods. This assists with lowering systolic and diastolic blood pressures,", "c": "Blood pressure will typically decrease when a client has a weight loss of 4.5 to 6.8 kg (10 to 15 lb)."}, "keyConcept": "The DASH diet was initially devised to lower blood pressure, but it has other beneficial effects on cardiovascular health, weight loss, and diabetes. Lifestyle modifications are an essential part of the treatment of hypertension. Weight loss is the most effective method, as well as increasing exercise, smoking cessation, and increasing intake of potassium, calcium, and magnesium."}, {"id": 10691, "cat": "NCLEX 12- Cardiovascular", "stem": "explanation for these findings? O A.Acute MI O B. Hypocalcemia O C. Hyperkalemia O D. Cardiac tamponade", "choices": [{"id": "a", "t": "An ECG is a non-invasive method of detecting changes in heart rhythm and conduction abnormalities."}, {"id": "b", "t": "3%"}, {"id": "c", "t": "The client’s ECG results indicate a myocardial infarction, not hyperkalemia. Hyperkalemia is characterized by peaked T waves."}, {"id": "d", "t": "The client’s ECG results indicate a myocardial infarction, not cardiac tamponade."}], "correct": "a", "rationale": "An ECG is a non-invasive method of detecting changes in heart rhythm and conduction abnormalities. The nurse should be familiar with the B 3% appearance of a normal ECG and with ECG abnormalities associated with common conditions. Elevated ST segments in two contiguous leads I ina client with symptoms of acute coronary syndrome are most likely to be acute myocardial infarction. € |_| 18%) o| 4%", "whyNot": {"b": "The client’s ECG results indicate a myocardial infarction, not hypocalcemia. A long QT interval is characteristic of hypocalcemia.", "c": "The client’s ECG results indicate a myocardial infarction, not hyperkalemia. Hyperkalemia is characterized by peaked T waves.", "d": "The client’s ECG results indicate a myocardial infarction, not cardiac tamponade."}, "keyConcept": "ST elevation myocardial infarction (STEMI) is characterized by clinical symptoms consistent with acute coronary syndrome in addition to persistent ST elevation in 2 or more contiguous leads. The ST elevation must be = 2.5 mm ST elevation in leads V2-3 in men under 40 years, or 22.0 mm ST elevation in leads V2-3 in men over 40 years. In women, ST elevation of = 1.5 mm is required in V2-3 and = 1 mm ST elevation in other leads. Each small square is equal to 1 mm. See image below. 2 = ® 4 z = a iat g <"}, {"id": 10692, "cat": "NCLEX 12- Cardiovascular", "stem": "if concerned that the prescription for KCl is inappropriate or inaccurate?", "choices": [{"id": "a", "t": "The nurse should give the prescription as written."}, {"id": "b", "t": "The nurse should withhold the KCl, pending the next set of laboratory results."}, {"id": "c", "t": "The nurse should clarify the order with the physician."}, {"id": "d", "t": "The nurse should contact the nursing supervisor."}], "correct": "c", "rationale": "al 2% Easy cm | 10% Potassium replacement is usually administered as potassium chloride. Symptoms associated with toxicity include slow, irregular heartbeat; ec fF 86% fatigue; muscle weakness; paresthesia; confusion; dyspnea; peaked T waves; depressed ST segments; prolonged QT segments; widened QRS ; loss of P waves; and cardiac arrhythmias. If the serum potassium level is greater than 2.5 mEq/liter, potassium chloride should be given at a rate of 10 mEq/hour or less ina concentration less than 30 mEq/liter. In cases where potassium supplementation is urgent, potassium chloride may be infused at a rate of 40 mEq/hour. In this case, the client has a high-normal potassium level and no potassium should be administered. A nurse has both a personal and a legal obligation to provide care consistent with competence within the scope of licensure. The nurse will be held responsible for failure to act due to negligence, which refers to conduct that falls below the standard of care. This can include both acts of commission and omission. Malpractice refers to the nurse’s failure to meet a duty to a client that resulted in injury. This includes responsibility for medication errors that result in harm to the client. For this reason, if a nurse questions an order or if an order is unclear, the nurse should contact the healthcare provider who prescribed the medication or intervention. 2 = ® 4 z = a iat g <", "whyNot": {"a": "The nurse should always contact the prescriber before administration of an order that is concerning.", "b": "The nurse should contact the healthcare provider and should not simply make the decision to withhold the prescription.", "d": "The initial action should be to contact the healthcare provider. If concerns remain after speaking with the provider, it is appropriate to"}, "keyConcept": "A nurse must provide competent care and can be liable for conduct that does not meet the standard of care. This can include acts of commission or omission. If a nurse believes an order is unclear or has questions about the order, the nurse must contact the healthcare provider who wrote the prescription."}, {"id": 10693, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is reviewing the laboratory findings of a client who had a myocardial infarction (MI). The nurse should identify that which of the following cardiac enzymes can confirm the MI occurred ten days ago?", "choices": [{"id": "a", "t": "Creatinine kinase MB"}, {"id": "b", "t": "Creatinine phosphokinase"}, {"id": "c", "t": "Troponin T"}, {"id": "d", "t": "Myoglobin"}], "correct": "c", "rationale": "An elevated troponin T level indicates myocardial injury and can remain elevated for 10 to 14 days following an MI.", "whyNot": {"a": "Creatinine kinase MB levels can indicate cardiac muscle injury due to an elevation 3 to 6 hr after an MI. The levels return to the expected", "b": "Creatinine phosphokinase levels can indicate cardiac or skeletal muscle injury due to an elevation 4 to 8 hr after an MI. The levels return to", "d": "An elevated myoglobin level can indicate skeletal or cardiac muscle injury. The level would be elevated within 3 hr after the injury and"}, "keyConcept": "Early diagnosis and intervention for an acute MI can reduce the risk for significant myocardial damage. Troponin is a myocardial muscle protein that is released specifically in response to myocardial injury. Troponin levels can elevate within 4 to 6 hr after an infarction, peak at 10 to 24 hr, and last up to 14 days following the injury. Nursing care for a client who has chest discomfort includes checking the client's vital signs, inserting a peripheral IV, obtaining a 12-lead ECG, and administering nitroglycerin, aspirin, or opioids to the client as prescribed. The nurse should provide the client with supplemental oxygen and recheck the client's vital signs and pain level every 5 min."}, {"id": 10694, "cat": "NCLEX 12- Cardiovascular", "stem": "analyzes the victim and advises a shock. As soon as the shock has been delivered, what is the first step that the nurse must take?", "choices": [{"id": "a", "t": "Immediately resume CPR"}, {"id": "b", "t": "Re-check the victim’s pulse"}, {"id": "c", "t": "Deliver two mouth-to-mouth rescue breaths"}, {"id": "d", "t": "Allow the AED to analyze the victim's status"}], "correct": "a", "rationale": "Following a shock delivered by an AED, the provider must immediately resume CPR by giving chest compressions at a rate of 100 per minute. B rd 29% After a round of chest compressions, the provider may need to deliver rescue breaths. Another shock may also be advised by the AED, but the first step is to restart CPR. cl 176) om 16%", "whyNot": {"b": "The nurse should start chest compressions right away without checking a pulse.", "c": "The nurse should restart CPR with chest compressions to perfuse vital organs.", "d": "Chest compressions should be restarted immediately."}, "keyConcept": "Defibrillation stuns the heart by depolarizing the myocardium and terminating ventricular fibrillation, to allow the heart’s natural pacemaker to resume an organized rhythm. The organized rhythm must produce effective mechanical activity resulting in a palpable central pulses. The heart may temporarily be in PEA or asystole after a shock, so chest compressions should be resumed immediately after the shock. 2 = ® 4 z = a iat g <"}, {"id": 10695, "cat": "NCLEX 12- Cardiovascular", "stem": "employed on a full-time basis. What follow-up testing and screening will you expect this client to get?", "choices": [{"id": "a", "t": "Lipid screening"}, {"id": "b", "t": "Human papillomavirus screening"}, {"id": "c", "t": "PSA screening"}, {"id": "d", "t": "Bone density screening"}], "correct": "a", "rationale": "You would expect this client to be screened for lipid levels. This client has some risk factors associated with abnormal lipid levels and coronary heart disease. Some of these risk factors include ethnicity, gender, hypertension, and weight. The family history is unknown. It is recommended that men with known risk factors for heart disease are screened with lipid levels as soon as 20 years of age. HPV, PSA and bone density screening are not indicated, as based on this client’s data.", "whyNot": {"b": "This client is not at high risk of contracting HPV due to his age and social factors; this is not a priority screening.", "c": "This client is not at high risk of prostate cancer, based on his age. PSA screening is not a priority screening in this case.", "d": "This client is not at risk of osteoporosis; a bone density screening is not a priority screening in this case."}, "keyConcept": "The United States Preventive Services Task Force recommends screening men 20 to 35 years of age for lipid disorders if they are at increased risk of coronary heart disease (CHD). Risk factors for CHD include hypertension, diabetes, personal history of CHD or noncoronary atherosclerosis, including abdominal aortic aneurysm, peripheral artery disease, carotid artery stenosis, family history of cardiovascular disease before 50 years of age in male relatives or 60 years of age in female relatives; obesity, and tobacco use."}, {"id": 10696, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client with the diagnosis of right ventricular failure. Which condition unrelated to cardiac disease is the major cause of right ventricular failure?", "choices": [{"id": "a", "t": "Renal disease"}, {"id": "b", "t": "Hypovolemic shock"}, {"id": "c", "t": "Severe systemic infection"}, {"id": "d", "t": "Chronic obstructive pulmonary disease"}], "correct": "d", "rationale": "Chronic obstructive pulmonary disease, or COPD, causes destruction of capillary beds around the alveoli, interfering with blood flow to the ‘ — oe lungs from the right side of the heart. As the heart continues to strain against this resistance, heart failure eventually results. increased blood pressure in the right side of the heart makes it harder for the heart to pump blood to the lungs. The high pressure puts a strain on the right € | 12% side of the heart that can result in cor pulmonale. @bD J 56%", "whyNot": {"a": "A client may eventually develop heart disease as a secondary complication of renal disease, but the more likely cause is COPD.", "b": "Hypovolemic shock causes a reduction in circulatory volume and not necessarily right ventricular heart failure.", "c": "Severe systemic infection would not necessarily contribute to right heart failure."}, "keyConcept": "Cor pulmonale is a condition that causes the right side of the heart to fail. It results from long-term pulmonary hypertension, which is high blood pressure in the arteries of the lung. This results in increased right ventricular pressure, leading to strain and eventual loss of compensatory mechanisms in the right heart. Pulmonary hypertension develops in response to abnormally low oxygen levels in the vessels inside the lungs as a result of COPD. COPD Expiration through pursed lips _ Cyanoss Neck ein distention (Chronic cough Wheezes = Decreased breath sounds CCrackles atthe lung bases |__- Distant heart sounds Cigarette smoking — Retraction of lower ib interspaces during inspiration (Hoover's sign)"}, {"id": 10697, "cat": "NCLEX 12- Cardiovascular", "stem": "Which of the following complications would be most likely to occur following cardioversion?", "choices": [{"id": "a", "t": "Stroke"}, {"id": "b", "t": "Hypertension"}, {"id": "c", "t": "Nausea and vomiting"}, {"id": "d", "t": "Urinary incontinence"}], "correct": "a", "rationale": "Astroke may occur if a clot in the atrium embolizes and travels to the brain. Anticoagulant medications are indicated prior to cardioversion in clients who undergo cardioversion for atrial fibrillation of unknown duration, since blood clots may form from stasis if contraction of the atrium is ineffective.", "whyNot": {"b": "Low blood pressure is more likely after cardioversion, if an unexpected dysrhythmia occurs.", "c": "Nausea and vomiting are not typical complications associated with cardioversion.", "d": "Urinary incontinence does not usually occur as a complication of cardioversion."}, "keyConcept": "Complications associated with cardioversion include dysrhythmia, stroke, skin burns, and complications of any sedative medication given prior to the procedure. Bradycardia may occur after cardioversion if the sinus node does not take over as the cardiac pacemaker."}, {"id": 10698, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client in hypovolemic shock after a gastrointestinal bleed. The nurse knows that which of the following indicates fluid replacement therapy has been effective?", "choices": [{"id": "a", "t": "The mean arterial blood pressure is over 65 mm Hg"}, {"id": "b", "t": "Heart rate of >100/minute"}, {"id": "c", "t": "Urine output is greater than 30 ml per hour"}, {"id": "d", "t": "Respiratory rate is between 12 and 20 breaths per minute"}], "correct": "c", "rationale": "A || 29% Moderate Urine output is the earliest and best indicator of the effectiveness of fluid replacement in hypovolemic shock. A urine collection device . Vital signs are a late and unreliable indicator of the adequacy of fluid replacement.", "whyNot": {"a": "While mean arterial pressure over 65 mmHg indicates that the client is reaching a normal range of fluid volume, the increase in blood", "b": "Tachycardia can occur as a compensatory response to increase cardiac output in shock.", "d": "Normal respiratory rate is between 12 and 20 breaths per minute, but vital signs are a late measurement of compensation for shock."}, "keyConcept": "The goals of treatment for a client in hypovolemic shock due to hemorrhage include controlling further blood loss, increasing oxygen delivery by ensuring adequate ventilation, increasing oxygen saturation of blood, and restoring blood flow; and fluid resuscitation. Initial fluid resuscitation should begin with an isotonic crystalloid (lactated Ringer solution or normal saline.) An initial bolus of 1-2 L is given in adult . and 20 mL/kg should be administered to pediatric client. Urine output of >0.5 to 1 ml/kg/hour indicates adequate renal perfusion. The underlying disorder may affect the heart rate, mental status, and capillary refill, so these are less reliable indicators of adequate perfusion. Compensatory vasoconstriction occurs in hypovolemic shock, so measurement of mean arterial pressure (MAP) only provides an estimate and organ hypoperfusion may be present despite normal values. 2 = ® 4 z = a iat g <"}, {"id": 10699, "cat": "NCLEX 12- Cardiovascular", "stem": "patient's potassium level is 3.0 mEq/L. (Click on the exhibit, located to the right, for more of the patient's labs and medications.) Based on this, which of the following interventions should the nurse prioritize?", "choices": [{"id": "a", "t": "Notify the healthcare provider"}, {"id": "b", "t": "Attach defibrillator pads"}, {"id": "c", "t": "Administer potassium supplementation"}, {"id": "d", "t": "Administer an additional 80 mg of sotalol"}], "correct": "c", "rationale": "This client has ventricular ectopy with premature ventricular contractions occurring every second beat (ventricular bigeminy) and a run of ventricular tachycardia. This is not unusual after myocardial infarction, which increases the risk of ventricular ectopy. Ventricular ectopy is exacerbated by electrolyte imbalances, hypoxia, fever, stimulant use, and exercise. The client’s laboratory studies show a low potassium level (hypokalemia). Normal potassium levels are 3.5 millequivalents per liter (mEq/L) to 5.0 mEq/L. The priority for the nurse is to administer potassium supplementation as ordered for this client. Potassium levels are often monitored closely in clients who have had myocardial infarction, particularly when the client is on a medication that could potentially reduce serum levels of potassium. Supplementation is contraindicated in renal failure. (The first image shows ventricular bigeminy. The second image depicts ventricular tachycardia. ) V. Tach UD#: 50107213625 thay 21:02:28 R18 i}", "whyNot": {"a": "The nurse should administer the prescribed potassium and assess the client before notifying the healthcare provider.", "b": "The client is stable, and correction of the hypokalemia should resolve the ventricular ectopy.", "d": "Sotalol is an antiarrhythmic drug and is given twice a day. There is no order to add sotalol, and it has a half-life of 12 hours, so a drop in the"}, "keyConcept": "Ventricular irritability is common after myocardial infarction and can result in arrhythmias. Electrolyte imbalances, including hyperkalemia and hypokalemia, exacerbate cardiac arrhythmias and should be closely monitored. Other exacerbating factors include hypoxia, stimulant use, fever, and exercise."}, {"id": 10700, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is planning to advise a client with heart failure who has a new prescription for digoxin. Which of the following signs of toxicity should the nurse include when advising the client?", "choices": [{"id": "a", "t": "Increased pedal edema"}, {"id": "b", "t": "Redness on upper chest and neck"}, {"id": "c", "t": "Vision changes, including appearance of yellow haloes around some objects"}, {"id": "d", "t": "Dry cough"}], "correct": "c", "rationale": "Digoxin is a cardiac glycoside. It increases the contractility of the heart (positive inotrope) and reduces the heart rate (negative chronotrope) in individuals with congestive heart failure. These actions increase the cardiac output of the heart. It is also used for the treatment of atrial fibrillation. Therapeutic levels of digoxin range from 0.5 to 2 ng/mL. The medication is contraindicated in second- and third-degree heart block and should not be given to clients with a pulse <60/min. A client with digoxin toxicity may complain of nausea, vomiting, and/or yellow-green haloes around objects. The client should also be advised that use of a calcium supplement may lead to increased risk of toxicity, including arrhythmias. The antidote for digoxin toxicity is Digibind. A high-potassium diet is recommended for individuals who take digoxin.", "whyNot": {"a": "Digoxin is used to treat congestive heart failure. One of the signs of congestive heart failure is peripheral edema.", "b": "This describes red man syndrome, which is a hypersensitivity reaction to vancomycin.", "d": "Adry, persistent cough is a side effect of angiotensin-converting enzyme inhibitors (ACEIs)."}, "keyConcept": "Digoxin is a medication used to treat congestive heart failure. It is a cardiac inotrope, which increases the contractility of the heart. Levels must be monitored carefully, since toxicity occurs at serum concentrations above the therapeutic range of 0.5 to 2 ng/mL. Signs of toxicity include arrhythmias, nausea, vomiting, and visual changes, including an appearance of yellow/yellow-green haloes around objects."}, {"id": 10701, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse on the telemetry unit notes the rhythm below. The client is complaining of chest pain and lightheadedness and has a weak, rapid pulse. Which of the following actions does the nurse anticipate? rcvueveerversuresveer ten ALLA Biel tie fe pe Pie feeb fralee Per Wee", "choices": [{"id": "a", "t": "Defibrillation"}, {"id": "b", "t": "Synchronized cardioversion at 50 Joules"}, {"id": "c", "t": "Synchronized cardioversion at 200 Joules"}, {"id": "d", "t": "Adenosine 6 mg IV push"}], "correct": "b", "rationale": "The client has a supraventricular tachycardia at a rate of 180/minute. It is unstable tachycardia because the client is hypotensive with chest pain that is most likely ischemic in origin. Other signs of poor perfusion associated with unstable tachycardia include altered mental status and respiratory distress. Symptoms include palpitations, syncope, lightheadedness, and respiratory distress. The nurse should establish IV access and obtain a 12-lead ECG. Supraventricular tachycardia is a narrow complex tachycardia with a QRS of <0.12 seconds. In an unstable client, cardioversion should not be delayed. The initial dose of energy for synchronized cardioversion in supraventricular tachycardia is 50- 100 J, except in atrial fibrillation, for which the dose of energy is 120-200 J.", "whyNot": {"a": "Defibrillation is an unsynchronized shock used for ventricular fibrillation and ventricular tachycardia without a pulse.", "c": "This dose is too high. It would be appropriate for atrial fibrillation with rapid ventricular response in an unstable client.", "d": "Adenosine is used in stable tachycardia. Unstable clients require cardioversion."}, "keyConcept": "Arrhythmias, including tachycardia and bradycardia, can compromise cardiac output. When cardiac output is inadequate, the client will demonstrate signs of poor perfusion of vital organs, including respiratory distress, chest pain, and/or mental status changes or syncope. Ina client with signs of hemodynamic compromise due to tachyarrhythmia, cardioversion is usually indicated."}, {"id": 10702, "cat": "NCLEX 12- Cardiovascular", "stem": "A client who has received an initial dose of a new prescription for clonidine calls the nurse to report lightheadedness when standing up. What is the priority action for the nurse?", "choices": [{"id": "a", "t": "Give the client a fluid bolus"}, {"id": "b", "t": "Assist the client with ambulation"}, {"id": "c", "t": "Assist the client to a sitting position"}, {"id": "d", "t": "Obtain orthostatic blood pressure measurements"}], "correct": "c", "rationale": "Correct Answer: C. Assist the client to a sitting position A \\ B Initiation of a new medication can sometimes result in side effects. Clonidine is a central alpha-adrenergic agonist that works by inhibiting ec r the sympathetic nervous system, resulting in peripheral vasodilation. Orthostatic hypotension occurs when the sympathetic nervous system D a is blocked from reacting when the individual changes position, such as moving from lying to standing. Normally, when someone rises to a standing position from a lying position, the sympathetic nervous system reflexes cause peripheral vasoconstriction to send more oxygenated blood to the brain. Orthostatic hypotension is more likely to occur when a medication is initiated. Other medications associated with orthostatic hypotension include various types of anti-hypertensive medications, tricyclic antidepressants, drugs used to treat erectile dysfunction, and opioid analgesics. Dehydration can also cause orthostatic hypotension. The client’s safety should be the priority action, so the nurse should assist the client to a sitting position and assess the client’s symptoms in the seated position.", "whyNot": {"a": "Dehydration may add to orthostatic hypotension, but determining the cause and intervention with a fluid bolus is not the priority over the", "b": "The client should be assisted to a seated position and assessed. The client should not ambulate when feeling symptomatic while standing.", "d": "The initial nursing action should be to protect the client’s safety by assisting the client to a seated position. The client’s symptoms should"}, "keyConcept": "Clients may experience orthostatic hypotension as a result of illness or the effects of medication. The priority action by the nurse is to assist the client to a seated position to ensure safety."}, {"id": 10703, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a client who has a new prescription for metoprolol. Which of the following statements by the client indicates an understanding of the teaching? O A.\"I should place the tablet under my tongue.\" O B. \"I should have my clotting time checked weekly.\" O C. \"I will monitor for a fever while taking this medication.\" O D. \"I will call my doctor if my pulse is less than 60 beats per minute.\"", "choices": [{"id": "a", "t": "Metoprolol is administered orally, not sublingually."}, {"id": "b", "t": "Metoprolol does not affect bleeding or clotting time. Metoprolol can cause elevated liver enzymes, BUN, potassium, and blood glucose."}, {"id": "c", "t": "Metoprolol does not cause a fever or leukopenia. Some medications, such as cyclosporine, can cause leukopenia. Clients who take these"}, {"id": "d", "t": "a| 1% Easy Metoprolol is a beta-adrenergic antagonist that is used to treat hypertension and angina."}], "correct": "d", "rationale": "a| 1% Easy Metoprolol is a beta-adrenergic antagonist that is used to treat hypertension and angina. Adverse effects can include bradycardia, AV heart , heart failure, and postural hypotension. The client should monitor heart rate daily and notify the provider if bradycardia, or a pulse rate of less than 60/min, occurs. The client should change positions slowly to reduce the risk for postural hypotension. € I 6)", "whyNot": {"a": "Metoprolol is administered orally, not sublingually.", "b": "Metoprolol does not affect bleeding or clotting time. Metoprolol can cause elevated liver enzymes, BUN, potassium, and blood glucose.", "c": "Metoprolol does not cause a fever or leukopenia. Some medications, such as cyclosporine, can cause leukopenia. Clients who take these"}, "keyConcept": "Metoprolol is a beta-adrenergic antagonist used to treat hypertension and angina. Adverse effects can include bradycardia, AV heart block, heart failure, and postural hypotension. The client should monitor heart rate daily and notify the provider if bradycardia, or a pulse rate of less than 60/min, occurs. The client should change positions slowly to reduce the risk for postural hypotension. Metoprolol can cause hypoglycemia or hyperglycemia and can mask early manifestations of hypoglycemia, such as tachycardia and tremors. Clients who have diabetes mellitus should learn to recognize other indications of hypoglycemia, such as hunger and fatigue, and to monitor their blood glucose levels carefully."}, {"id": 10704, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing discharge instructions to the guardian of an 8-year-old child following a cardiac catheterization. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Keep the child home from school for 1 week."}, {"id": "b", "t": "Give the child acetaminophen for discomfort."}, {"id": "c", "t": "Offer the child ice chips for the first 24 hr."}, {"id": "d", "t": "Assist the child to take a tub bath the day after the procedure."}], "correct": "b", "rationale": "The child might experience minor discomfort at the puncture site. The guardian should offer either acetaminophen or ibuprofen. The child A || should not be given aspirin because of the associated risk for Reye syndrome. eB | cil", "whyNot": {"a": "The child can attend school but should avoid strenuous activity. D I", "c": "The child should begin fluid intake with sips of clear liquids but can resume a regular diet as soon as she desires.", "d": "The child should keep the site clean and dry and, therefore, avoid tub baths for at least 3 days after the procedure. The nurse should"}, "keyConcept": "The nurse should provide discharge instructions to the guardian of a child following cardiac catheterization. Care After Cardiac Catheterization Keep the site clean and dry. Avoid tub baths for the first 3 days. Avoid strenuous activity. Consume a regular diet without restrictions. Use ibuprofen or acetaminophen for pain."}, {"id": 10705, "cat": "NCLEX 12- Cardiovascular", "stem": "@ @ & Viraln 8x Recor Mi Inbox Mi Inbox Eq Untitl Untitl 4 Googl @ TEAS Online €& Mark! @ Micro (NATE @ ATITs G Newc N x | Grea; + <€ > G 23 student.atitesting.com/LT| se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "Antispasmodic effects on the pericardium"}, {"id": "b", "t": "Causing increased myocardial oxygen demand"}, {"id": "c", "t": "Vasodilation of peripheral vasculature"}, {"id": "d", "t": "Improved conductivity in the myocardium"}], "correct": "c", "rationale": "A Nitroglycerin produces peripheral vasodilatation, which reduces preload, afterload, and myocardial oxygen demand and consumption. B '", "whyNot": {"a": "Nitroglycerin does not cause pericardial spasticity. D | |", "b": "Nitroglycerin causes a decrease in myocardial oxygen demands.", "d": "It does not affect conduction in the myocardium."}, "keyConcept": "Nitroglycerin relieves angina by increasing coronary blood flow through dilation of the coronary arteries. It improves collateral flow to ischemic regions through vasodilation. It reduces myocardial oxygen demand by decreasing preload."}, {"id": 10706, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who just had coronary artery bypass graft surgery. The nurse knows not to rewarm the client too rapidly due to a risk of which of the following complications?", "choices": [{"id": "a", "t": "Septicemia"}, {"id": "b", "t": "Hypotension"}, {"id": "c", "t": "Tissue necrosis"}, {"id": "d", "t": "Hypertension"}], "correct": "b", "rationale": "S| 13% Hard During cardiac surgery, the client is maintained in a hypothermic state to reduce the metabolic demand of the heart and vital organs to es a 40% prevent ischemia. Rewarming begins immediately after completion of surgery, but clients often have residual hypothermia even after extended warming on cardiopulmonary bypass. This occurs as a result of continuing intraoperative heat losses, vasoconstriction in € |__| 21% peripheral tissues, a drop in temperature as blood circulates to the cold peripheral circulation; and infusion of cold intravenous fluids. A D | | 26% warming rate of no more than 1.8°F per hour is recommended (1°C) to prevent rapid peripheral vasodilation, hypotension and shock.", "whyNot": {"a": "Septicemia is a potential complication of coronary artery bypass graft surgery, but it is not caused by rapid rewarming.", "c": "Tissue rewarming promotes vasodilation, but hypothermia causes peripheral vasoconstriction. Tissue necrosis is likely to be associated", "d": "Rewarming causes vasodilation, not vasoconstriction, so it is unlikely to cause hypertension."}, "keyConcept": "Hypothermia is maintained during cardiac surgery to reduce metabolic demand and risk of ischemia. Rewarming must be gradual to avoid rapid peripheral vasodilation and hypotension. 2 = ® 4 z = a iat g <"}, {"id": 10707, "cat": "NCLEX 12- Cardiovascular", "stem": "nursing interventions does the nurse anticipate in a client with onset of symptomatic hypovolemia?", "choices": [{"id": "a", "t": "Establish a large-bore IV catheter"}, {"id": "b", "t": "Administer anti-inflammatory medications"}, {"id": "c", "t": "Encourage the client to use the bathroom every 4 hours and as needed"}, {"id": "d", "t": "Report urine output of less than 40 mL per hour"}], "correct": "a", "rationale": "Causes of severe intravascular volume depletion include hemorrhage, trauma, diarrhea and heatstroke. Acute compensation occurs initially by vasoconstriction, followed by migration of fluid from the extravascular compartment into the intravascular compartment. This allows maintenance of circulating volume, but total body water remains depleted. With a major loss of volume, compensatory measures are overwhelmed. 2 = ® 4 z = a iat g < lsotonic crystalloid solutions, including lactated Ringer's solution and 0.9% normal saline, are most often used for volume resuscitation. Colloid solutions, including albumin or dextrans, can be used in cases of major hemorrhage or volume depletion, although blood products are necessary in significant hemorrhage in order to maintain oxygen carrying capacity.", "whyNot": {"b": "Anti-inflammatory medications are not indicated for treatment of hypovolemia. D I | 10%", "c": "Hypovolemia is a state of volume depletion. Urine output would be decreased. The nurse should promote fluid intake.", "d": "Normal urine output is 30 mL per hour; 40 mL per hour is an adequate UOP and does not need to be reported."}, "keyConcept": "Causes of severe intravascular volume depletion include hemorrhage, trauma, diarrhea and heatstroke. Acute compensation occurs initially by vasoconstriction, followed by migration of fluid from the extravascular compartment into the intravascular compartment. This allows maintenance of circulating volume, but total body water remains depleted. With a major loss of volume, compensatory measures are overwhelmed. 2 = ® 4 z = a iat g < lsotonic crystalloid solutions, including lactated Ringer's solution and 0.9% normal saline, are most often used for volume resuscitation. Colloid solutions, including albumin or dextrans, can be used in cases of major hemorrhage or volume depletion, although blood products are necessary in significant hemorrhage in order to maintain oxygen carrying capacity."}, {"id": 10708, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing education about hypertension to a client who is newly diagnosed with primary hypertension. Which of the following statements by the client indicates a need for additional teaching? O A.\"Uncontrolled hypertension increases my risk of heart disease and stroke.\" O B. \"Primary hypertension develops quickly, over a period of days to weeks.\" O C. \"Many people with high blood pressure have no signs or symptoms to warn them that their blood pressure is high.\" O D. \"Secondary hypertension is caused by an underlying health condition or medication.\" O E. \"Eating a diet high in sodium can increase blood pressure.\"", "choices": [{"id": "a", "t": "Hypertension is an important risk factor for heart disease and stroke. E"}, {"id": "b", "t": "This is the incorrect statement and indicates a need for additional teaching."}, {"id": "c", "t": "Hypertension is often asymptomatic, which is why it is often called “the silent killer.”"}, {"id": "d", "t": "Various conditions and medications can lead to secondary hypertension, including thyroid disease, certain medications, congenital blood"}, {"id": "e", "t": "Eating too many foods high in sodium can cause fluid retention, which increases blood pressure."}], "correct": "b", "rationale": "This is the incorrect statement and indicates a need for additional teaching. Primary hypertension often develops slowly over months and years. Secondary hypertension tends to appear suddenly and causes a higher blood pressure than does primary hypertension.", "whyNot": {"a": "Hypertension is an important risk factor for heart disease and stroke. E |", "c": "Hypertension is often asymptomatic, which is why it is often called “the silent killer.”", "d": "Various conditions and medications can lead to secondary hypertension, including thyroid disease, certain medications, congenital blood", "e": "Eating too many foods high in sodium can cause fluid retention, which increases blood pressure."}, "keyConcept": "Primary HTN is caused by a combination of genetic and environmental factors. Secondary HTN develops as a result of an underlying disorder, such as sleep apnea or pheochromocytoma. Older age and African American ethnicity increase the risk of hypertension. Other factors that influence development of primary hypertension include family history, increased body weight, sedentary lifestyle, vitamin D deficiency, excess sodium intake, and stress."}, {"id": 10709, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is providing discharge instructions for a client who had a permanent cardiac pacemaker implanted. Which of the following is the most important instruction for this client?", "choices": [{"id": "a", "t": "Know the signs of a heart attack"}, {"id": "b", "t": "Maintain strict bed rest with bathroom privileges for one week"}, {"id": "c", "t": "Eat a low-cholesterol diet to minimize plaque formation"}, {"id": "d", "t": "Understand how to prevent pacemaker malfunction eck Answer"}], "correct": "d", "rationale": "A Hl 22% Moderate B 2% malfunction. Measures to prevent pacemaker malfunction include avoidance of magnetic fields and performance of a pulse check at least | once a week. C i iis The most important instruction for a client with a permanent pacemaker is to be sure the client knows how to prevent pacemaker", "whyNot": {"a": "Having a pacemaker will not place the client at increased risk for myocardial infarction; therefore, information about signs of a heart", "b": "Although there may be restrictions about how much the client should lift, he will not be placed on bed rest unless there are other health", "c": "The client might be prescribed a low-cholesterol diet, but that instruction will not be related to the permanent pacemaker."}, "keyConcept": "Pacemakers are checked periodically to see whether they are functioning normally and to make sure the battery has adequate charge. Pacemaker checks are usually done by telephone every month or two, using a special device; the pacemaker is usually evaluated in the doctor's office once or twice a year. Strong electromagnetic fields, metal detectors and other electronic devices can interfere with pacemaker functioning. The nurse should instruct the client that microwave ovens do not pose a danger to the pacemaker, nor do cellular phones if kept at more than 6 inches away from the pacemaker."}, {"id": 10710, "cat": "NCLEX 12- Cardiovascular", "stem": "Which life-threatening cardiac arrhythmia occurs with complete AV dissociation characterized by failure of any atrial impulses to be conducted to the ventricle?", "choices": [{"id": "a", "t": "Mobitz type Il arrhythmia"}, {"id": "b", "t": "Third-degree heart block"}, {"id": "c", "t": "Mobitz type arrhythmia"}, {"id": "d", "t": "First-degree atrioventricular block"}], "correct": "b", "rationale": "-degree heart block also called complete AV disassociation, occurs when there are absolutely no atrial impulses transmitted through es Ts 65% the atrioventricular node to the ventricle. This cardiac arrhythmia requires emergency treatment which can include immediate cardiac pacing and preparation for emergency basic and advanced life support in case of cardiac arrest. A first-degree atrioventricular block is € I Sh usually asymptomatic and it occurs because the AV node impulse is delayed, thus prolonging the PR interval; this arrhythmia can lead to D | | 26% more severe heart block if left untreated. Second-degree atrioventricular (AV) block type I, also referred to as Mobitz type | and Wenckebach, occurs when there are progressive conduction delays through the AV node; second-degree AV block Mobitz type Il, also occurs when the AV node impulses are often blocked as they attempt to reach the ventricles. This arrhythmia can lead to a complete heart block when left untreated.", "whyNot": {"a": "Mobitz type Il is caused by blocked AV node impulses and may eventually lead to complete heart block.", "c": "Mobitz type | results in conduction delays through the AV node.", "d": "First-degree heart block may be asymptomatic; it typically occurs when the AV impulse node is delayed."}, "keyConcept": "Third degree atrioventricular block refers to a conduction block between the atria and the ventricles. The ECG reflects the dissociation of P waves and QRS complexes. The ventricles generate their own impulse, which is typically slower than the sinus rate. (See figure.) » + t il | i : ' Il"}, {"id": 10711, "cat": "NCLEX 12- Cardiovascular", "stem": "client’s teaching? O A. Replace tablets every month. O B. If there is no relief after 1 tablet or if pain worsens after 1 tablet, contact EMS. O C. Keep this medication refrigerated. O D. Swallow the tablet with water or juice.", "choices": [{"id": "a", "t": "Replace tablets every month."}, {"id": "b", "t": "If there is no relief after 1 tablet or if pain worsens after 1 tablet, contact EMS."}, {"id": "c", "t": "Keep this medication refrigerated."}, {"id": "d", "t": "Swallow the tablet with water or juice."}], "correct": "b", "rationale": "‘i o: Sublingual nitroglycerin tablets and spray are self-administered by clients as needed, for relief of angina. Nitroglycerin dilates the coronary © | | arteries of the heart to improve blood flow. If the client does not achieve some relief of chest pain or if chest pain worsens after one D | nitroglycerin tablet, EMS should be contacted. The traditional recommendation was for clients to take one nitroglycerin dose sublingually every five minutes for up to three doses before calling for emergency medical services (EMS) evaluation. This recommendation was updated in 2004 by the American College of Cardiology and the American Heart Association, after research suggested that waiting for three doses could result in significant delays in obtaining EMS assistance. The client will require evaluation with an ECG to rule out acute coronary syndrome or myocardial infarction. When using nitroglycerin tablets, the client should be sure the mouth is moist and should not swallow saliva until the tablet is dissolved. The tablet may be crushed between the teeth in cases of severe pain, but should still be absorbed sublingually. Nitroglycerin tablets should be kept in a dark glass container at all times to prevent degradation of the medication. It is inactivated by heat, light, air, and moisture, and tablets should be replaced every six months.", "whyNot": {"a": "Nitroglycerin tablets should be replaced every 6 months after opening to ensure they retain potency.", "c": "Nitroglycerin tablets are kept with the client in case of chest pain.", "d": "Nitroglycerin should not be swallowed. The sublingual form is taken under the tongue."}, "keyConcept": "Nitroglycerin tablets should be kept in a dark glass container at all times to prevent degradation of the medication, since nitroglycerin is inactivated by heat, light, air, and moisture. Unused tablets should be discarded and replaced every six months. The tablets should be taken sublingually. The mouth should be moist, but the client should not swallow saliva until the tablet is completely dissolved. If chest pain worsens or does not improve within five minutes after one NTG tablet, the client should call EMS."}, {"id": 10712, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is auscultating heart sounds on a client and detects an S4 sound. The nurse should identify that this sound represents which of the following heart conditions?", "choices": [{"id": "a", "t": "Atrial gallop"}, {"id": "b", "t": "Ventricular gallop"}, {"id": "c", "t": "Closure of the mitral valve"}, {"id": "d", "t": "Closure of pulmonic valve"}], "correct": "a", "rationale": "The nurse should identify that an $4 sound represents an atrial gallop, which is caused by decreased compliance of either or both ventricles. B 43% This can be heard in clients who have hypertension, anemia, ventricular hypertrophy, myocardial infarction, aortic or pulmonic stenosis, and | pulmonary emboli. € |_| 11% of 5%", "whyNot": {"b": "An S3 represents a ventricular gallop caused by a rush of blood into a ventricle that is very compliant. This can be an expected finding in", "c": "Closure of the mitral valve is represented by the S1 heart sound.", "d": "Closure of the pulmonic valve is represented by the S2 heart sound."}, "keyConcept": "A nurse who is auscultating hearts should be able to identify S1 and S2 as expected heart sounds, and recognize unexpected heart sounds such as S3 and S4, referred to as gallop sounds. It is important for the nurse to understand what causes these sounds to occur and the individual heart valves associated with them."}, {"id": 10713, "cat": "NCLEX 12- Cardiovascular", "stem": "medications? O A. Remind the client that he only needs to continue seeing the health care provider if he is having symptoms of hypertension O B. Advise the client to report back if experiencing a weight gain of 1 lb. per month O C. Tell the client to take his medicine in the morning to reduce periods of nighttime urination O D. Remind the client that his medicine can cause changes in his mood; he should report side effects of hostility and paranoia", "choices": [{"id": "a", "t": "Remind the client that he only needs to continue seeing the health care provider if he is having symptoms of hypertension"}, {"id": "b", "t": "Advise the client to report back if experiencing a weight gain of 1 lb. per month"}, {"id": "c", "t": "Tell the client to take his medicine in the morning to reduce periods of nighttime urination"}, {"id": "d", "t": "Remind the client that his medicine can cause changes in his mood; he should report side effects of hostility and paranoia"}], "correct": "c", "rationale": "al 2% Easy The nurse should advise the client to take his diuretic medication in the morning. A diuretic will increase urine output, so it would be best to . If the client takes the medication at night, he may be more likely to wake up during the night to use the bathroom.", "whyNot": {"a": "Most clients do not have symptoms of hypertension; the client should continue to see a health care provider to manage his hypertension", "b": "Although the client may have some weight changes, an initial weight gain of 1 lb. per month is not a reason to contact the health care", "d": "Side effects of hostility and paranoia are typically not associated with diuretic use."}, "keyConcept": "Thiazide diuretics are recommended as an initial treatment for hypertension. Diuretics enhance the excretion of various electrolytes and water by affecting renal mechanisms for tubular secretion and reabsorption. They increase urine output and may be better tolerated if taken during the daytime hours. 2 = ® 4 z = a iat g <"}, {"id": 10714, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client with heart failure who has signs of reduced cardiac output. Which best describes cardiac output?", "choices": [{"id": "a", "t": "The stroke volume compared to body surface area"}, {"id": "b", "t": "The volume of blood ejected from the ventricle in one minute"}, {"id": "c", "t": "The volume of blood ejected from the ventricle with each heartbeat"}, {"id": "d", "t": "The amount of fluid returning to the heart before contraction"}], "correct": "b", "rationale": ", or the stroke volume x heart rate. Cardiac output normally ranges from 4-8 L/minute, depending upon the body's metabolic needs.", "whyNot": {"a": "This describes the stroke volume index, which is the volume of blood ejected with each heartbeat compared to body surface area.", "c": "This describes the stroke volume, not cardiac output.", "d": "This describes preload, or the filling pressure of blood returning to the heart; it does not define cardiac output."}, "keyConcept": "Reduced cardiac output can be caused by myocardial infarction, heart failure due to hypertension, valvular heart disease, congenital heart disease, cardiomyopathy, pulmonary disease, arrhythmias, fluid overload, decreased fluid volume, medication effects, or electrolyte imbalance. Signs can include tachycardia, tachypnea, decreased peripheral pulses, cool skin, angina, exercise intolerance, decreased urine output, volume overload, lung crackles, orthopnea, pedal edema, an $3 or $4 heart sound, and hypotension. 2 = ® 4 z = a iat g <"}, {"id": 10715, "cat": "NCLEX 12- Cardiovascular", "stem": "diagnosis? O A. Lactate dehydrogenase O B. Amylase O C. Troponin | and T O D. Low density lipoprotein-C", "choices": [{"id": "a", "t": "Lactate dehydrogenase"}, {"id": "b", "t": "Amylase"}, {"id": "c", "t": "Troponin and T"}, {"id": "d", "t": "Low density lipoprotein-C"}], "correct": "c", "rationale": "| 1% Within the first 2-4 hours after myocardial infarction, troponin | and troponin T, a protein found in the myocardium, is released by damaged ec | 96% myocardial cells. Levels will be elevated in 2-4 hours after ischemic injury. Other enzymes released after myocardial infarction include . Creatine kinase MB is the isomer that is specific to myocardial cells. Myoglobin is also released by the heart after injury, but it iT} is not cardiac-specific and can be released by other muscle cells in the body. 2 & 3 =) a =", "whyNot": {"a": "Lactate dehydrogenase (LDH 1 and LDH 2) indicate myocardial necrosis and usually become positive within 48 hours after myocardial <", "b": "Amylase is a digestive enzyme released by the pancreas when pancreatic cells are damaged by autodigestion in pancreatitis.", "d": "Coronary artery disease results from the deposition of excess cholesterol within the lumen of coronary blood vessels."}, "keyConcept": "When a diagnosis of myocardial infarction is suspected but cannot be diagnosed on the basis of ECG findings and clinical presentation, it is necessary to base the diagnosis on measurement of cardiac biomarkers, which are enzymes present in myocardial cells that are released in myocardial infarction. Troponins are sensitive and early markers of myocardial infarction, with elevation 2-4 hours after an ischemic injury."}, {"id": 10716, "cat": "NCLEX 12- Cardiovascular", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc EX test automa Nx @teas + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Order a stat ECG"}, {"id": "b", "t": "Call for help and begin chest compressions"}, {"id": "c", "t": "Start oxygen at 2 liters per minute"}, {"id": "d", "t": "Call the monitor tech to determine the client's cardiac rhythm"}], "correct": "b", "rationale": "| 2% Easy Once the nurse determines that the client is unresponsive and pulseless, the first response should be to alert someone to notify the RRT or OB a one: fo call a code. Once that is done, the nurse should immediately start CPR. When the RRT arrives, they will connect the client to a crash cart monitor to determine the cardiac rhythm. c | 2% p| 2%", "whyNot": {"a": "A stat ECG will not give the nurse any information she needs emergently. When a client is unresponsive and pulseless, the nurse must call", "c": "Although oxygen will be started by the RRT, CPR is the first intervention after calling for help.", "d": "Knowing the client's cardiac rhythm will not change the need to begin CPR immediately. A client who is unresponsive and pulseless must"}, "keyConcept": "Apulseless rhythm indicates failure of the heart to produce adequate cardiac output. Chest compressions should be initiated immediately. The nurse should call for help, but should not leave the client."}, {"id": 10717, "cat": "NCLEX 12- Cardiovascular", "stem": "€ > G 23 student.atitesting.com/LT| We Recor Mi Inbox = M Inbox — E} Untitl Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc EX test automa Ni x | @tea + v Qa * ws * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Ischemic infarction"}, {"id": "b", "t": "Transmural infarction"}, {"id": "c", "t": "Subendocardial infarction"}, {"id": "d", "t": "Hypoxemia infarction"}], "correct": "b", "rationale": "Atransmural infarction describes a myocardial infarction injury that penetrates the entire wall of the myocardium. This term is used to classify the type of heart attack that has occurred, as a myocardial infarction is classified according to its location and the depth of the muscle penetrated.", "whyNot": {"a": "While a myocardial infarction involves an ischemic injury, this is not the term used in this situation.", "c": "Asubendocardial infarction only penetrates the inner part of the heart muscle during a heart attack, not the entire heart muscle.", "d": "This is not a term used to classify a myocardial infarction."}, "keyConcept": "Current terminology for acute coronary syndrome includes unstable angina (UA), non-ST elevation MI (NSTEMI), and ST elevation MI (STEMI). STEMI is usually characterized by complete occlusion of a major epicardial coronary artery, resulting in necrosis of the full thickness of the myocardium, from the endocardium through the myocardium to the epicardium."}, {"id": 10718, "cat": "NCLEX 12- Cardiovascular", "stem": "appropriate first nursing intervention? Rar B/C brs! v.\\ae eon 67, SSBB AGEL Ss LGLOBe Jo) SUEDE ial See Lenn oes as 4) 4+ mt —~", "choices": [{"id": "a", "t": "Call the rapid response team for cardioversion."}, {"id": "b", "t": "Notify the healthcare provider and prepare to administer atropine."}, {"id": "c", "t": "Notify the cardiologist and prepare for transcutaneous or transvenous pacing."}, {"id": "d", "t": "Document the rhythm and assessment in the client’s chart and monitor for further changes."}], "correct": "c", "rationale": "Whatever the cause, the nurse should recognize a complete heart block. The rhythm shown is third-degree heart block, which is complete dissociation of atrial and ventricular arrhythmia caused by a failure of the conduction system. This can occur after radiofrequency ablation, which is ablation of electrical pathways that cause tachyarrhythmia. Third-degree heart block can result in pre-syncope (lightheadedness), dizziness, fainting, confusion, hypotension, bradycardia, or heart failure. The ECG will demonstrate a regular rate and rhythm, but the P waves and Q waves have no relationship to one another. Third-degree heart block requires temporary or permanent pacing and is a life- threatening condition.", "whyNot": {"a": "Cardioversion is indicated for the treatment of stable tachyarrhythmia.", "b": "Pacing is necessary for Mobitz type Il second-degree heart block and third-degree heart block because both conditions involve disorders", "d": "Third-degree heart block must be treated immediately because it is a life-threatening arrhythmia."}, "keyConcept": "Complete heart block, or third-degree atrioventricular block, refers to complete AV dissociation, in which no atrial impulses are conducted to the ventricles. Atria and ventricles contract independently. The ventricles contract in an escape rhythm, with the rate dependent upon the site of the block. The atrial rate is usually sinus at 60-100/minute. AV block results in reduction of cardiac output, with ischemia, heart failure, and syncope. A transcutaneous or transvenous pacemaker should be placed emergently."}, {"id": 10719, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client’s blood pressure and notes that it is 128/82 mmHg. What is the client's pulse pressure? O a.128 mmHg © B.82mmHg © c.46 mmHg © p.16 mmHg", "choices": [{"id": "a", "t": "This is the systolic pressure, not the pulse pressure."}, {"id": "b", "t": "This would be considered the diastolic pressure, not the pulse pressure."}, {"id": "c", "t": "The pulse pressure is the difference between the systolic and the diastolic measurements of blood pressure."}, {"id": "d", "t": "This result does not indicate the pulse pressure, which is the difference between the systolic and diastolic pressures."}], "correct": "c", "rationale": "The pulse pressure is the difference between the systolic and the diastolic measurements of blood pressure. A widening pulse pressure occurs when one level changes and the other stays the same, or when both levels move in opposite directions. In the example above, the systolic measurement is 128 mmHg and the diastolic pressure is 82 mmHg. The difference between the two is 46 mmHg.", "whyNot": {"a": "This is the systolic pressure, not the pulse pressure.", "b": "This would be considered the diastolic pressure, not the pulse pressure.", "d": "This result does not indicate the pulse pressure, which is the difference between the systolic and diastolic pressures."}, "keyConcept": "The pulse pressure is the difference between the diastolic and systolic blood pressures. It represents the force of contraction generated by the heart."}, {"id": 10720, "cat": "NCLEX 12- Cardiovascular", "stem": "€ > G 23 student.atitesting.com/LT| Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. % CLOSE Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "0% mw"}, {"id": "b", "t": "0% 5"}, {"id": "c", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "d", "t": "0% [="}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}, {"id": 10721, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is caring for a client who is experiencing chest pain. The nurse should identify that which of the following characteristics distinguishes angina from a myocardial infarction (MI)?", "choices": [{"id": "a", "t": "Stable angina is relieved with rest and nitroglycerin."}, {"id": "b", "t": "The pain of an MI resolves in less than 15 min."}, {"id": "c", "t": "The type of activity that causes an MI is identifiable."}, {"id": "d", "t": "Stable angina can occur for longer than 30 min."}], "correct": "a", "rationale": "The nurse should identify that stable angina occurs following exertion or stress, is relieved by rest and nitroglycerin, and should last less than 15 min.", "whyNot": {"b": "The nurse should identify that pain associated with an MI usually lasts longer than 30 min and requires opioid analgesics for relief.", "c": "The nurse should identify that an MI usually occurs in the morning without any activity or apparent cause.", "d": "The nurse should identify that the pain of stable angina usually occurs for 15 min or less."}, "keyConcept": "The nurse should notify the provider or rapid response team when caring for a client who is experiencing chest discomfort. The nurse should evaluate the client's description of the location, radiation, onset, intensity, duration, and any precipitating and relieving factors of the pain or discomfort. The nurse should check the client's vital signs, insert a peripheral IV, obtain a 12-lead ECG, and administer nitroglycerin, aspirin, or opioids to the client as prescribed. The nurse should provide the client with supplemental oxygen and recheck the client's vital signs and pain level every 5 min. The following chart compares angina pain and myocardial infarction: Location of Relieving . . woe ae Other . Duration of pain Precipitating cause . . pain Factors manifestations Substernal ain, . P Relieved by : pressure . . Angina . rest or Less than 15 min Stress or exertion See nitroglycerine to the left oe arm Substernal pain or pressure ae Nausea, vomiting, that can : 9 fi 4 Requires Occurs without diaphoresis, Myocardial radiate to opioids for 30 min or longer cause, often in the dysrhythmias,"}, {"id": 10722, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is teaching a client who has heart failure. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"Restrict your fluid intake to 3,000 milliliters per day.\""}, {"id": "b", "t": "\"Stop exercising if you can no longer carry on a conversation.\""}, {"id": "c", "t": "\"Limit your sodium intake to 3,500 milligrams per day.\""}, {"id": "d", "t": "\"Weigh yourself once each week.\""}], "correct": "b", "rationale": "A Hi 11% Moderate The nurse should instruct the client to begin exercising slowly and gradually advance in intensity three times per week. To reduce the risk for OB a Gan: hypoxia, the client should stop exercising if experiencing chest pain or dyspnea and if unable to carry on a conversation. ° cH 15%", "whyNot": {"a": "The nurse should instruct the client to restrict fluid intake to 2,000 mL/day to decrease fluid retention. The nurse can advise the client to", "c": "The nurse should instruct the client to restrict sodium intake to 2,000 to 3,000 mg/day to decrease fluid retention.", "d": "The nurse should instruct the client to weigh himself at the same time each day to monitor for fluid retention."}, "keyConcept": "The nurse should instruct a client who has heart failure to restrict fluid intake to 2,000 mL/day to decrease fluid retention. The nurse can advise the client to pour the amount of fluid to be consumed each day into an empty 2 L bottle to control daily fluid intake. The client should weigh himself at the same time each day to monitor for fluid retention. The client should report a 1-day weight gain of 0.45 to 0.9 kg (1 to 2 lb) as this is a manifestation of fluid retention. The nurse should instruct the client to restrict sodium intake to 2,000 to 3,000 mg/day to decrease fluid retention. The nurse should also advise the client to begin exercising slowly and gradually advance in intensity by walking three times per week. To reduce the risk for hypoxia, the client should stop exercising if experiencing chest pain or dyspnea and if unable to carry on a conversation. The client should report manifestations of increased heart failure, such as rapid weight gain, a decrease in exercise tolerance, a new cough, dyspnea, or increased edema."}, {"id": 10723, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client with peripheral artery disease. Which of the following is a sign of intermittent claudication?", "choices": [{"id": "a", "t": "Dependent edema"}, {"id": "b", "t": "Pain with activity"}, {"id": "c", "t": "Pain with rest that is relieved by walking"}, {"id": "d", "t": "Skin discoloration at the ankles"}], "correct": "b", "rationale": "al o: Peripheral arterial occlusive disease is usually caused by arteriosclerosis and most commonly affects the lower extremities. It is Cc || characterized by diminished pulses in one extremity with signs of arterial insufficiency. Intermittent claudication refers to pain in a specific D i muscle group that is caused by activity and relieved with rest. It is caused by ischemia due to inadequate blood flow to the contracting muscles. The degree of muscle pain experienced by clients with peripheral artery disease (PAD) will depend upon the amount of arterial stenosis, the level of activity, and whether collateral circulation has developed. Peripheral artery disease can affect the arms, buttocks, thighs, or lower legs. Clinically, more severe manifestations of chronic peripheral artery disease are ischemic ulcers, rest pain, and gangrene.", "whyNot": {"a": "Peripheral edema may be the result of venous, not arterial, insufficiency.", "c": "This describes rest pain, which occurs as peripheral arterial disease progresses.", "d": "Venous stasis can result in discoloration of the skin. It is not a characteristic of intermittent claudication."}, "keyConcept": "Peripheral arterial disease is usually caused by build up of cholesterol plaques (arteriosclerosis) and most commonly affects the lower extremities, resulting in clinical signs of inadequate perfusion, including diminished pulses, loss of hair, and cool skin in the affected extremity. Intermittent claudication is the result of inadequate blood flow to contracting muscles and refers specifically to pain that increases with activity and is relieved by rest."}, {"id": 10724, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse is assessing a client at 34 weeks’ gestation who complains of feeling faint. Her blood pressure while supine is 100/60 mmHg. Which of the following nursing interventions is most appropriate?", "choices": [{"id": "a", "t": "Place the client lying in the left lateral recumbent position and recheck blood pressure in 5 minutes in the left arm"}, {"id": "b", "t": "Place the client in the left lateral recumbent position and recheck blood pressure in the right arm in 5 minutes"}, {"id": "c", "t": "Ask the client to stand and recheck blood pressure while standing"}, {"id": "d", "t": "Take the client’s blood pressure in the opposite arm in the same position"}], "correct": "a", "rationale": "on 33% Hard During pregnancy, maternal positioning can affect blood pressure. Blood pressure usually decreases in the first and second trimester as the B | cesar circulation expands and as hormonal changes result in dilation of blood vessels. It usually recovers to pre-pregnancy levels in the third trimester. The client should be placed in a left lateral recumbent position to reduce pressure on her blood vessels (vena cava syndrome), c | 8% which improves venous return to the heart. The blood pressure should be rechecked in 5 minutes. The blood pressure should be checked in D | | 13% the left arm, as checking it in the right arm may result in a falsely lower blood pressure measurement, since that arm is now positioned above the heart. Placing the client in the supine position is likely to compress maternal blood vessels.", "whyNot": {"b": "This may result in a falsely low measurement. The blood pressure should be checked in the left arm when the client is in the left lateral", "c": "In pregnancy, the blood pressure may rise with standing, as pressure on the vena cava is relieved.", "d": "The client should be moved from the supine position since it can cause occlusion of maternal blood vessels, resulting in hypotension."}, "keyConcept": "After 20 weeks' gestation, the size of the gravid uterus can compress the inferior vena cava, decreasing the return of blood into the heart (preload.) clients in a supine position or prolonged standing during pregnancy can experience symptoms of hypotension.The left lateral recumbent position reduces pressure on maternal blood vessels."}, {"id": 10725, "cat": "NCLEX 12- Cardiovascular", "stem": "A nurse on a cardiac unit is assessing a client who is on telemetry and has a heart rate of 46/min. The nurse should anticipate that which of the following treatments will be used?", "choices": [{"id": "a", "t": "Defibrillation"}, {"id": "b", "t": "Pacemaker insertion"}, {"id": "c", "t": "Synchronized cardioversion"}, {"id": "d", "t": "Administration of propranolol"}], "correct": "b", "rationale": "Pacemakers are used to increase the heart rate of clients who have bradycardia. A pacemaker can either be temporary or permanent. A temporary pacemaker is used for emergency or short-term treatment of bradydysrhythmias. A permanent pacemaker is used to treat long- term conduction disorders. Pacemakers can be set at on-demand, synchronous pacing or fixed, asynchronous pacing. For synchronous pacing, the pacemaker is set to sense the client's heart rate. If the client's heart rate drops below a set rate, the pacemaker fires electrical impulses to pace the client's heart. For asynchronous pacing, the pacemaker is set to fire electrical impulses at a continuous rate. The nurse should monitor the client for evidence of bleeding or infection at the pacemaker insertion site, pneumothorax, hemothorax, which is caused by a puncture of the client's lung or subclavian artery, ventricular dysrhythmias, which is caused by irritation of the ventricle wall, and hiccups, which can indicate lead dislocation. The nurse should monitor the client's vital signs and ECG. The nurse should document the model of the pacemaker, type of generator, date of insertion, stimulation threshold, and pacer settings. The nurse should instruct the client to keep cell phones at least 6 inches away from the pacemaker generator and to avoid strong electromagnetic fields that might interfere with the pacemaker function. The nurse should also instruct the client to wear a medical alert bracelet to alert medical personnel to the presence of the pacemaker.", "whyNot": {"a": "Defibrillation would be used for a client who has ventricular fibrillation or pulseless ventricular tachycardia.", "c": "Synchronized cardioversion would be used for a client who has a tachydysrhythmia, such as atrial fibrillation, supraventricular", "d": "The administration of propranolol would be used for a client who has tachycardia or hypertension to decrease heart rate and lower the"}, "keyConcept": "Pacemakers are used to increase the heart rate of clients who have bradycardia. A pacemaker can either be temporary or permanent. A temporary pacemaker is used for emergency or short-term treatment of bradydysrhythmias. A permanent pacemaker is used to treat long- term conduction disorders. Pacemakers can be set at on-demand, synchronous pacing or fixed, asynchronous pacing. For synchronous pacing, the pacemaker is set to sense the client's heart rate. If the client's heart rate drops below a set rate, the pacemaker fires electrical impulses to pace the client's heart. For asynchronous pacing, the pacemaker is set to fire electrical impulses at a continuous rate. The nurse should monitor the client for evidence of bleeding or infection at the pacemaker insertion site, pneumothorax, hemothorax, which is caused by a puncture of the client's lung or subclavian artery, ventricular dysrhythmias, which is caused by irritation of the ventricle wall, and hiccups, which can indicate lead dislocation. The nurse should monitor the client's vital signs and ECG. The nurse should document the model of the pacemaker, type of generator, date of insertion, stimulation threshold, and pacer settings. The nurse should instruct the client to keep cell phones at least 6 inches away from the pacemaker generator and to avoid strong electromagnetic fields that might interfere with the pacemaker function. The nurse should also instruct the client to wear a medical alert bracelet to alert medical personnel to the presence of the pacemaker."}, {"id": 10726, "cat": "NCLEX 12- Cardiovascular", "stem": "provider? O A. New onset of crackles on auscultation of the lungs and murmur of mitral regurgitation. O B. Heart rate of 105/min with blood pressure 150/95 mmHg O C. Pain in the region of the heart that is improved by leaning forward O D. Excessive sleeping O E. Intermittent premature ventricular contractions", "choices": [{"id": "a", "t": "New onset of crackles on auscultation of the lungs and murmur of mitral regurgitation."}, {"id": "b", "t": "Heart rate of 105/min with blood pressure 150/95 mmHg"}, {"id": "c", "t": "Pain in the region of the heart that is improved by leaning forward"}, {"id": "d", "t": "Excessive sleeping"}, {"id": "e", "t": "Intermittent premature ventricular contractions"}], "correct": "a", "rationale": "Anew onset of pulmonary edema should be reported urgently to the healthcare provider. Papillary muscle rupture is a life-threatening complication of acute myocardial infarction. It can occur up to 7 days after myocardial infarction but most commonly occurs within 24 hours. The onset of cardiogenic shock with hypotension and pulmonary edema, often in conjunction with a new murmur of mitral regurgitation, requires urgent treatment. Papillary muscle rupture is most common with an inferior myocardial infarction but may occur with anterior MI. Other complications of myocardial infarction include reinfarction, angina, enlarging infarct, both ventricular and atrial arrhythmias, conduction blocks, heart failure, ventricular aneurysms, cardiac rupture, and pericarditis.", "whyNot": {"b": "Although a heart rate of 105/minute is tachycardic, tachyarrhythmias usually do not cause instability until the rate exceeds 150/minute.", "c": "Pain in the region of the heart improved by leaning forward is consistent with pericarditis. Post-MI pericarditis is inflammation of the", "d": "This is not concerning if the client is easily arousable and has a stable mental status without any signs of neurological compromise.", "e": "Premature ventricular contractions occur in up to 90% of individuals after acute MI. They do not present an immediate threat."}, "keyConcept": "Complications after myocardial infarction include arrhythmias, congestive heart failure (with pulmonary edema); cardiogenic shock; papillary muscle dysfunction, pericarditis, and ventricular aneurysm. Dressler syndrome and pulmonary emboli are other complications. Papillary muscle rupture occurs when the area of the papillary muscle is infarcted. It results in mitral regurgitation into the left atrium and pulmonary congestion, with dyspneal and pulmonary edema. The murmur is heard best at the cardiac apex that radiates toward the axilla. Pulmonary edema can occur independently as a complication of MI."}], "nclex_13_critical_care": [{"id": 10727, "cat": "NCLEX 13-Critical Care", "stem": "Which of the following responses should the nurse make?", "choices": [{"id": "a", "t": "\"There is no reason to believe anything will go wrong. You'll be fine.\""}, {"id": "b", "t": "\"Why do you want us to stand by and not help you at a time when you might need it the most?\""}, {"id": "c", "t": "\"You really should discuss this request with the hospital's chaplain.\""}, {"id": "d", "t": "\"I'll make sure your doctor talks with you about your request.\""}], "correct": "d", "rationale": "-not-resuscitate order after consulting with them. Another B | 3\" action the nurse should take is to check to see if the client has submitted advance directives that specify their wishes when and if they are not able to communicate them.", "whyNot": {"a": "With this response, the nurse is demonstrating the nontherapeutic communication technique of giving false reassurance. It conveys an", "b": "Asking \"why\" questions can feel accusatory and cause the client to respond defensively. These types of questions do not facilitate further", "c": "The nurse has a responsibility to address the client's request and not suggest that there is a need for spiritual guidance. This response is"}, "keyConcept": "Providers write \"do-not-resuscitate\" (DNR) or \"allow-natural-death\" (AND) orders in clients' medical records after consulting with them and their families and weighing the options. This keeps nurses and other healthcare professionals from initiating cardiopulmonary resuscitation (CPR) when those clients have no pulse or respirations."}, {"id": 10728, "cat": "NCLEX 13-Critical Care", "stem": "prompt intervention by the nurse? O A. The UAP assists the client to a prone position. O B. The UAP uses the lift sheet to move the client. O C. The UAP encourages the client when he attempts to brush his teeth. O D. The UAP performs passive range of motion exercises.", "choices": [{"id": "a", "t": "The UAP assists the client to a prone position."}, {"id": "b", "t": "The UAP uses the lift sheet to move the client."}, {"id": "c", "t": "The UAP encourages the client when he attempts to brush his teeth."}, {"id": "d", "t": "The UAP performs passive range of motion exercises."}], "correct": "a", "rationale": "A client who is experiencing increased intracranial pressure should not be placed in a prone position. Clients with increased intracranial pressure should generally be placed in a position with the head elevated, to reduce intracranial swelling.", "whyNot": {"b": "This is an appropriate action and doesn’t require action by the nurse.", "c": "The client should be encouraged to attempt activities of daily living.", "d": "Passive range of motion exercises are useful to prevent contractures. They can be performed by UAP, so there is no reason for the nurse to"}, "keyConcept": "Delegation is the process of transferring a task or intervention to unlicensed personnel for whom the task or intervention is normally outside of the scope of practice. Although the nurse may delegate performance of a task, accountability for the outcome cannot be delegated."}, {"id": 10729, "cat": "NCLEX 13-Critical Care", "stem": "In the post-anesthesia care unit, a nurse is tending to a client with a decreased level of consciousness after receiving general anesthesia for an amputation. What is the highest priority diagnosis for the nurse?", "choices": [{"id": "a", "t": "Impaired physical mobility"}, {"id": "b", "t": "Inability to protect the airway O G.Risk of fluid deficit"}, {"id": "d", "t": "Acute pain"}], "correct": "b", "rationale": "all 7% Easy Physical conditions that pose an imminent risk of harm, including issues that affect the airway, breathing, or circulation, are priority nursing Cc | 2% diagnoses when implementing care. Inability to clear secretions or potential obstruction from relaxation of the muscles of the tongue and D l 3% airway result in respiratory compromise, posing the greatest threat to the client’s survival. Post-operative respiratory complications include hypoxemia from retained secretions, hypoventilation, bronchospasm, and aspiration; hypoventilation from the depression of the respiratory drive; and airway obstruction due to the tongue falling back to obstruct the airway or due to an inability to clear secretions. Use of suction and an oral airway can be helpful in the PACU in this situation. Turning the client to a side-lying position to prevent hypoxemia. If the client's unresponsiveness is due to an opioid analgesic, naloxone may be necessary as a reversal agent.", "whyNot": {"a": "Although it is important for the client to regain the ability to ambulate and for the nurse to reposition the client to prevent pressure ulcers,", "d": "Acute pain is often an appropriate nursing diagnosis. Although an assessment of pain is important after surgery, it is not the priority. Most"}, "keyConcept": "The priority in a post-operative client with a decreased level of consciousness is airway protection. Use of airway suction, an oral airway, and placement of the client in a side-lying position are helpful interventions to clear airway secretions, protect the airway, and prevent hypoxemia."}, {"id": 10730, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client status post craniotomy who has clear wound drainage of 60 mL during one shift from a drain placed during the procedure. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Log-roll the client with the operative side up."}, {"id": "b", "t": "Cleanse the wound site using sterile saline and apply a new dressing."}, {"id": "c", "t": "Mark the drainage saturation of the dressing and monitor q 12 hours."}, {"id": "d", "t": "Notify the healthcare provider of the amount and color of drainage."}], "correct": "d", "rationale": "A Drainage of 50 mL or more per shift or drainage that saturates dressings during the shift suggest the possibility of a leak of cerebral spinal B 4 fluid as a result of an injury to the dura during surgery. A breach in the dura provides a breach in the body’s defense system against central nervous system infection, including encephalitis, abscess, or meningitis. A dural leak can be exacerbated by increased intracranial pressure c _| that results from injury and inflammation. Treatment targets reduction of pressure on the wound, including elevation of the head of the bed, @D | placement of a lumbar drain, bedrest, or surgical intervention.", "whyNot": {"a": "The correct position usually prescribed by the neurosurgeon after craniotomy places the head of the bed at 30 degrees of elevation. This", "b": "The healthcare provider should be notified when excessive drainage is noted. The healthcare provider will evaluate the fluid to identify a", "c": "Although the drainage edge should be marked on the dressing at least once a shift, this is not the priority action when the volume of"}, "keyConcept": "Signs of a CSF leak include presence of glucose in wound drainage when tested with a reagent strip; a clear, pink, or yellowish halo around bloody or serosanguinous drainage on the client's dressing, sheet, or pillowcase; and/or reports of headache. If signs and symptoms of cerebrospinal fluid leak occur, the nurse should notify the healthcare provider. Interventions include maintenance of activity restrictions to reduce stress on the dural tear; frequent dressing changes; use of stringent sterile technique for dressing changes; monitoring for signs and symptoms of meningitis; and administration of any prescribed antimicrobials. Dural tears usually resolve without surgical intervention."}, {"id": 10731, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client in the ICU who has ARDS and is mechanically ventilated. Why is a gastrostomy tube preferable to total parenteral nutrition (TPN) for feeding this client?", "choices": [{"id": "a", "t": "A higher calorie count can be provided with enteral feeding."}, {"id": "b", "t": "Hyperglycemia occurs less frequently with enteral feedings compared to TPN."}, {"id": "c", "t": "Gut integrity is maintained with enteral feeding, preventing the formation of stress ulcers."}, {"id": "d", "t": "Enteral feeding does not result in infectious complications."}], "correct": "c", "rationale": "A Hi 15% Moderate Complications of critical illness include hypoperfusion of the Gl tract with the formation of stress ulcers. In a client who is hypoxemic, the B rt see body shunts blood preferentially to the heart and brain. Enteral feeding should be initiated early in the ICU to preserve the integrity and function of the mucosa of the gut, which will limit the translocation of bacteria from gut to bloodstream and prevent the formation of stress ec a 60% ulcers.", "whyNot": {"a": "Either modality of feeding is adequate to supply nutritional needs. There are various formulas available for enteral feeding and for TPN.", "b": "Hyperglycemia occurs as a result of increased gluconeogenesis due to stress in critically ill clients. This occurs in both enteral feeding and", "d": "The complication rate due to infection is lower with enteral feeding but mortality is equivalent to TPN-associated mortality."}, "keyConcept": "Enteral feeding is usually preferable to total parenteral nutrition in critically ill clients who do not have contraindications. Enteral feeding maintains the integrity of the gut mucosa, preventing translocation of gut bacteria into the bloodstream and reducing the risk of stress ulcers in critically ill clients."}, {"id": 10732, "cat": "NCLEX 13-Critical Care", "stem": "lives alone and does not remember taking her medication in the past 4 weeks. She appears lethargic. Which of the following is the appropriate initial nursing action?", "choices": [{"id": "a", "t": "Prepare for endotracheal intubation."}, {"id": "b", "t": "Cover the client with a warming blanket."}, {"id": "c", "t": "Prepare to administer IV levothyroxine."}, {"id": "d", "t": "Send blood to the lab for a serum thyroid panel."}], "correct": "a", "rationale": "o; This presentation suggests myxedema coma and respiratory depression, which is a complication of severe hypothyroidism. Hypothyroidism B ri can progress to a coma state, with central depression of the respiratory drive, hypoventilation, and bradycardia. Additionally, in a client with myxedema, the tongue may be swollen, causing airway obstruction. Puffiness of the hands and face, a thickened nose, swollen lips, and an c |_| enlarged tongue may occur secondary to non-pitting edema that occurs with abnormal deposition of mucin in the skin and other tissues. D || Airway and ventilation should be prioritized.", "whyNot": {"b": "Supportive measures include the correction of hypothermia and administration of electrolytes and/or glucose as necessary, but the", "c": "Although treatment with levothyroxine (T4) and liothyronine (T3) should be given, airway and ventilation are priorities in this patient.", "d": "Treatment should not be delayed for analysis of laboratory results."}, "keyConcept": "Hypothyroidism results in nonspecific slowing of the body's metabolic processes and function. The degree of severity of symptoms depends upon the severity and duration of thyroid hormone deficiency. Characteristics of hypothyroidism include fatigue, lethargy, and neurocognitive slowing, which may manifest as memory loss, personality change, loss of initiative, or depression. Progression of lethargy and somnolence may result in myxedema coma, which is a medical emergency. Characteristics of myxedema coma include mental status changes, hypothermia, hypoventilation, and hypotension. Treatment includes supportive care and IV replacement of thyroid hormone."}, {"id": 10733, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client who just returned from cardiac catheterization. Which of the following is an appropriate nursing intervention for this client?", "choices": [{"id": "a", "t": "Encourage ambulation"}, {"id": "b", "t": "Limit motion of the affected extremity"}, {"id": "c", "t": "Place a warm compress on the puncture site"}, {"id": "d", "t": "Place the client in a side-lying position"}], "correct": "b", "rationale": "a o: Indications for coronary catheterization include acute coronary syndrome, pre-operative coronary assessment, evaluation of aortic stenosis, Cc l mitral valve regurgitation; and coronary/hemodynamic evaluation in congestive heart failure. Depending upon the procedure, D | anticoagulation may be administered. Complications of coronary catheterization can include dysrhythmia, stroke, bleeding, vascular injury, contrast reaction, air embolism, thromboemboli, pulmonary edema and vagal stimulation with bradycardia. The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less. Movement is discouraged immediately after catheterization since the puncture site may hemorrhage.", "whyNot": {"a": "The site should be protected by placing the client in the supine position with the extremity straightened. Movements should be", "c": "The puncture site should be protected. Warm compresses facilitate hemorrhage. Sandbags or pressure bandages are used to promote", "d": "The client should be in the supine position with the extremity extended and the head at no more than 30 degrees of elevation."}, "keyConcept": "The primary nursing task in a client returning from cardiac catheterization is protecting and monitoring the puncture site. The site should be assessed for bleeding, hematoma, distal pulses, skin color and temperature; tenderness and embolization or closure of the access site due to thrombosis or dissection. The extremity should be placed straight, and the client should be positioned in the supine position, with the head elevated 30 degrees or less."}, {"id": 10734, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client with 3rd degree burns over 15% of his body surface. Which of the following indicates adequate fluid replacement during the first 24 hours post-burn?", "choices": [{"id": "a", "t": "Hematocrit level rising from 50 to 55"}, {"id": "b", "t": "Slowing of a previously rapid heart rate"}, {"id": "c", "t": "Falling CVP readings"}, {"id": "d", "t": "Urinary output of 15 to 20 ml/hr"}], "correct": "b", "rationale": ". The heart rate decreases as intravascular volume normalizes. OB a aan", "whyNot": {"a": "This would indicate low blood volume and hemo-concentration.", "c": "Falling CVP readings indicate hypovolemia.", "d": "This indicates inadequate renal perfusion. If kidney perfusion is adequate, output should be above 30 ml/hr in the average adult or at least"}, "keyConcept": "Blood volume status and the magnitude of arterial pressure variation were strongly correlated. Hypovolemia is reflected by pulmonary capillary wedge pressure (PCWP) <5 mm Hg, central venous pressure (CVP) <5 mm Hg, tachycardia, signs of peripheral vasoconstriction, and aurine output < 0.5 ml/kg/h. Return of these indicators to normal will demonstrate improved volume status."}, {"id": 10735, "cat": "NCLEX 13-Critical Care", "stem": "Which condition would most likely be a contraindication for placement of a pulmonary artery catheter?", "choices": [{"id": "a", "t": "Atherosclerosis"}, {"id": "b", "t": "History of myocardial infarction"}, {"id": "c", "t": "Hyperlipidemia"}, {"id": "d", "t": "Infection at insertion site"}], "correct": "d", "rationale": "All 10% Easy Apulmonary artery catheter is introduced through a major vessel, and threaded into the heart, where it measures pressures inside the heart B ] a and other parameters. Contraindications include infection at the insertion site, right ventricular assist device, and insertion during cardiopulmonary bypass. Introduction of infectious organisms through the catheter skin tract and colonization of the hub can result in c | 2% bloodstream infection. @D fF 81%", "whyNot": {"a": "Atherosclerosis is a condition that contributes to heart disease and may result in the need for a pulmonary artery catheter; it is not a", "b": "Some clients with a history of myocardial infarction may need a pulmonary artery catheter during treatment; this is not a", "c": "Hyperlipidemia may contribute to heart disease, which could require a pulmonary artery catheter; this is not a contraindication."}, "keyConcept": "Apulmonary artery catheter (Swan Ganz catheter) can be used to measure cardiac output, right sided intracardiac pressures, central venous pressure, mixed venous oxygen saturation, pulmonary artery pressure, and pulmonary capillary wedge (occlusion) pressure. A PAC may be placed to monitor volume status in a client in severe shock or to monitor pulmonary artery pressure in clients with pulmonary hypertension. Complications associated with placement of a PAC include atrial and/or ventricular arrhythmias; catheter misplacement; perforation of a cardiac chamber; rupture of a cardiac valve; or rupture of the pulmonary artery. Infection at the insertion site is an absolute contraindication. Thrombocytopenia, coagulopathy, acid-base and electrolyte disturbances are relative contraindications."}, {"id": 10736, "cat": "NCLEX 13-Critical Care", "stem": "nurse? O A. A client who returned to the unit after cardiac catheterization O B. A client hospitalized with congestive heart failure who is receiving IV heparin for initial treatment of deep vein thrombosis O C. A client who is scheduled for electrical cardioversion for atrial fibrillation this afternoon O D. A client who received thrombolytic therapy for a myocardial infarction yesterday and requires monitoring after several runs of ventricular tachycardia", "choices": [{"id": "a", "t": "A client who returned to the unit after cardiac catheterization"}, {"id": "b", "t": "A client hospitalized with congestive heart failure who is receiving IV heparin for initial treatment of deep vein thrombosis"}, {"id": "c", "t": "A client who is scheduled for electrical cardioversion for atrial fibrillation this afternoon"}, {"id": "d", "t": "A client who received thrombolytic therapy for a myocardial infarction yesterday and requires monitoring after several runs of ventricular tachycardia"}], "correct": "a", "rationale": "B. thrombosis A Hi 15% Moderate Monitoring an IV heparin infusion on a client with deep vein thrombosis is the least specialized task among these options and would be the most appropriate to assign a float nurse who typically works on a general medical-surgical unit. It is most appropriate to assign the most c |_| 19% experienced nurse to the most complex or specialized tasks. D | | 8%", "whyNot": {"a": "During cardiac catheterization, a cardiologist inserts a needle and guidewire through the femoral artery in the groin in order to inject", "c": "A client who is stable and has atrial fibrillation may be scheduled for elective cardioversion. These clients usually receive sedation and", "d": "Arrhythmias are a complication of myocardial infarction, and a nurse trained in cardiac care should be monitoring the client in this"}, "keyConcept": "When assigning care, the appropriate person should be matched to the appropriate task, in consideration of their scope of practice, job description, knowledge, skill, and experience. When a float nurse rotates through an unfamiliar unit, the charge nurse should only assign the float to tasks the float nurse can perform with demonstrated competence. In general, it is best to assign the most complex tasks to the most experienced or knowledgeable staff member."}, {"id": 10737, "cat": "NCLEX 13-Critical Care", "stem": "@ @ & Viraln. 8x Record M Inbox( ™ Inbox- Ej Untitle: Untitle’ (@ Google @ TEASF Online & MarkkK | @ Micros (eeuWges oe Nae ire @® Atte, € > @G 23 student.atitesting.com/LT| Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Assess muscle strength"}, {"id": "b", "t": "Assess the performance of activities of daily living"}, {"id": "c", "t": "Assess the pain level"}, {"id": "d", "t": "Assess the level of consciousness"}], "correct": "d", "rationale": "The Glasgow Coma Scale is used to assess the level of consciousness.", "whyNot": {"a": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not muscle strength.", "b": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not activities of daily living.", "c": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not level of pain."}, "keyConcept": "The Glasgow Coma Scale (GCS) is a commonly used scoring system used to describe a client's level of consciousness after a traumatic brain injury. It is used to gauge the severity of an acute brain injury and provides an objective way to record initial and subsequent level of consciousness. GCS correlates well with outcome following severe brain injury. (See table below for scoring.) Glasgow Coma Scale Eye opening Spontaneously response To speech To pain No response Nw. Best verbal Oriented to time, place, and person response Confused Inappropriate words Incomprehensible sounds No response —-NwWwaun Best motor | Obeys commands response Moves to localized pain Flexion withdrawal from pain Abnormal flexion (decorticate) Abnormal extension (decerebrate) No response —-NwWEeUD"}, {"id": 10738, "cat": "NCLEX 13-Critical Care", "stem": "posture? O A. Legs and feet extended, arms pulled up and tucked into chest O B. Legs and feet flaccid, arms rigid and flexed at the elbows O C. Legs, feet, and arms stiffly extended, hands turned outward and flexed O D. Legs, feet, and arms flaccid with no motor response", "choices": [{"id": "a", "t": "Legs and feet extended, arms pulled up and tucked into chest"}, {"id": "b", "t": "Legs and feet flaccid, arms rigid and flexed at the elbows"}, {"id": "c", "t": "Legs, feet, and arms stiffly extended, hands turned outward and flexed"}, {"id": "d", "t": "Legs, feet, and arms flaccid with no motor response"}], "correct": "c", "rationale": "All 12% — Easy Decerebrate posturing is a rigid form of posturing that is often exhibited after damage to parts of the brain, including the pons and the B I Ee midbrain. It is displayed by rigid legs and feet, with the feet extended in plantar flexion; the arms rigidly extended down at the sides and the hands clenched and turned outward. O€ as Gu oe | 4%", "whyNot": {"a": "This position best describes decorticate posturing; it is not an example of decerebrate posturing.", "b": "A client with decerebrate posturing will have rigid legs and the arms will be extended, not flexed.", "d": "A client with decerebrate posturing will have rigid extremities; the legs, feet, and arms would not be flaccid in this case."}, "keyConcept": "Abnormal posturing is an involuntary flexion or extension of the arms and/or legs, indicating severe brain injury. Decorticate Posturing , Flexed Plantar Nexed Internally rotated Flexed Adducted Decerebrate Posturing"}, {"id": 10739, "cat": "NCLEX 13-Critical Care", "stem": "chart. Which of the following is the correct action?", "choices": [{"id": "a", "t": "Continue the resuscitation once it is in progress, following regular protocol."}, {"id": "b", "t": "Continue the resuscitation only if the patient has cardiac activity."}, {"id": "c", "t": "Verify DNR status with the healthcare provider before stopping resuscitation."}, {"id": "d", "t": "Stop the resuscitation as soon as the order is discovered."}], "correct": "d", "rationale": "A l 3% Moderate As soon as the error is noted, it must be rectified by stopping the resuscitation immediately according to the client’s advance directives. It is B | a0 common for healthcare personnel to react to an unresponsive client by initiating resuscitation since failure to do so can result in legal and professional penalties. However, when a client has advanced directives recorded in the chart, these orders must be respected promptly once c |__| 26% discovered. @", "whyNot": {"a": "Ignoring a legal directive by a client by failing to stop a resuscitation once the client’s wishes have been determined constitutes", "b": "Although an honest error can occur, failure to correct the action once the error is discovered can result in legal consequences.", "c": "An advanced directive can only be placed in the chart after the healthcare provider provides documentation of consultation with the client"}, "keyConcept": "In the absence of an advance directive or DNR, healthcare professionals have an obligation to begin resuscitation. If an advance directive is available, the client's wishes must be respected."}, {"id": 10740, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client who was just admitted to the emergency department with a severe burn injury. Which of the following orders would the nurse question for this client?", "choices": [{"id": "a", "t": "Water"}, {"id": "b", "t": "Potassium"}, {"id": "c", "t": "Lactated Ringer’s"}, {"id": "d", "t": "Plasma expanders"}], "correct": "b", "rationale": "Potassium is usually not given immediately post-burn due to the potential for hyperkalemia, as a result of the release of potassium from OB a coer injured cells. ci 13%", "whyNot": {"a": "Water will often be administered in combination with lactated Ringer’s solution in various combinations depending on what the client", "c": "Lactated Ringer’s is given in combination with water and dextrose solutions in various combinations depending on client needs.", "d": "Plasma expanders are given with lactated Ringer’s and dextrose solutions depending on client needs."}, "keyConcept": "Burn injuries involve the partial or complete destruction of the integument (the skin. Depending upon the severity of the burn, layers of skin are destroyed, resulting in local and systemic disturbances. The skin is the largest organ of the body and has many functions. These functions include acting as a protective barrier against injury and infection; thermoregulatory control; regulation of fluid loss; synthesis of vitamin D; and sensory contact with the environment. When the skin is damaged or destroyed by a burn, it may lead to compromised immunity, hypothermia, increased fluid loss, infection, changes in appearance, function, and body image. Potassium is the major intracellular cation and it is released by damage to cells, increasing the serum potassium concentration. The nurse should monitor the client for hyperkalemia, not hypokalemia. Supplementation of potassium in clients who have sustained burns can result in toxic levels."}, {"id": 10741, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is monitoring a client who is in the telemetry unit and notes the following on the rhythm strip (see image below). This is an example of which of the following? an", "choices": [{"id": "a", "t": "First-degree AV block"}, {"id": "b", "t": "Third-degree AV block"}, {"id": "c", "t": "Premature ventricular contraction"}, {"id": "d", "t": "Torsades de pointes 100} 2 = o 2 ° a [R"}], "correct": "c", "rationale": "8 13% The rhythm strip shows a premature ventricular contraction or PVC. This refers to an ectopic beat that originates from a cardiac pacemaker ec FY 66% in the ventricle. The depolarization wave is initiated outside the His-Purkinje conduction system, so it travels slowly throughout the D i 10% ventricles, resulting in a wide QRS complex, usually longer than 120 ms. The beat is not preceded by a P wave, which represents an atrial pacemaker. The T wave, which represents repolarization, is usually large and oriented in the opposite direction of the QRS complex. PVCs may occur in a healthy heart or in individuals with heart disease, including ischemic heart disease. Conditions that lower the threshold for ventricular pacemaker cells to activate include increased sympathetic stimulation and electrolyte disturbances, including hypokalemia. Myocarditis, myocardial ischemia, cardiomyopathy, and myocardial contusion can also result in PVCs. The clinical significance depends on the frequency of the ectopic beats and whether there is a hemodynamic change in response.", "whyNot": {"a": "First-degree AV block is represented by a prolonged PR interval (>0.20 seconds).", "b": "Third-degree AV block refers to complete dissociation of the atria and ventricles. On ECG, the P waves and QRS complexes have no", "d": "Torsades de pointes refers to a type of polymorphic ventricular tachycardia. ECG shows variable amplitudes of QRS complexes, which"}, "keyConcept": null}, {"id": 10742, "cat": "NCLEX 13-Critical Care", "stem": "which of the following? O A. Below normal O B. Within normal limits O C. Above normal O D. Consistent with pulmonary edema", "choices": [{"id": "a", "t": "Below normal"}, {"id": "b", "t": "Within normal limits"}, {"id": "c", "t": "Above normal"}, {"id": "d", "t": "Consistent with pulmonary edema"}], "correct": "c", "rationale": "‘i 2m Apulmonary capillary wedge pressure (PCWP) is obtained by wedging a catheter in a tapering branch of one of the pulmonary arteries. It is ec ; an estimate of the left ventricular end diastolic pressure or preload of the heart. A PCWP higher than 18 mmHg suggests heart failure. A D || normal PCWP is 5-12 mmHg. As PCWP increases, pulmonary edema may occur. Levels over 25-30 mmHg are consistent with pulmonary edema. Proximal Port Port to the Thermistor @ Port tothe Balloon @) Distal Pot © Pulmonary Artery Superior Vena Cava __ Right Atrium = — Right Ventricle", "whyNot": {"a": "Normal pulmonary capillary wedge pressures are 5-12 mmHg. This pressure is above normal.", "b": "A PCWP >12 mmHg is above normal.", "d": "Pulmonary edema occurs at PCWPs above 25-30 mmHg."}, "keyConcept": null}, {"id": 10743, "cat": "NCLEX 13-Critical Care", "stem": "education to the student nurse concerning care of a client after withdrawal of life support?", "choices": [{"id": "a", "t": "“Dopamine and norepinephrine will be used to maintain blood flow to the vital organs, but other medications will be discontinued.”"}, {"id": "b", "t": "“Basic care will continue, so we will be able to monitor any changes in vital signs or electrolytes.”"}, {"id": "c", "t": "“An intravenous morphine infusion will be administered to reduce anxiety and provide comfort.”"}, {"id": "d", "t": "“To prevent hunger, we will begin intravenous feedings with a parenteral nutritional supplement.”"}], "correct": "c", "rationale": "Withdrawal of ventilator support can result in dyspnea, restlessness, and tachycardia. Dyspnea is a subjective symptoms that may be accompanied by anxiety and fear of suffocation. Clients who are actively dying have difficulty managing secretions or coughing at the end of life. Use of suctioning can help clear airways. Elevation of the head of the bed or placing the client in a side-lying position can be helpful. A fan provides movement of cool air. Supplemental oxygen may be prescribed. Morphine is titrated to provide relief for the client. Benzodiazepines such as midazolam can also be administered to reduce anxiety. Timely assessment and intervention to alleviate pain, discomfort, or anxiety is the primary nursing responsibility in this situation. Holistic nursing care at the end of life includes physical and psychosocial care for the client and support for family members.", "whyNot": {"a": "Withdrawal of life support usually includes discontinuation of blood products, vasopressors, antibiotics, and nutritional support.", "b": "After life support is withdrawn, vital signs and blood draws are discontinued to minimize discomfort for the client.", "d": "Nutritional support is typically withdrawn after withdrawal of life support. The nurse's primary goal is to provide comfort to the client."}, "keyConcept": "When providing end-of-life care, physical care measures are related to relief of symptoms rather than cure of a disease or medical condition. Dyspnea is a common subjective symptoms and often causes anxiety and fear of suffocation in dying clients. Dying clients may also find it difficult to clear secretions by coughing. Suctioning, repositioning the client, or provision of a fan can be helpful. Morphine is used to treat symptoms of dyspnea. Benzodiazepines may also be prescribed to relieve anxiety."}, {"id": 10744, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is assessing a client who was transported to the ER with neurological deficits after falling off a ladder. What client assessment is included in the Glasgow Coma Scale?", "choices": [{"id": "a", "t": "Breathing patterns"}, {"id": "b", "t": "Deep tendon reflexes"}, {"id": "c", "t": "Eye accommodation to light"}, {"id": "d", "t": "Motor response to a stimulus"}], "correct": "d", "rationale": "| 2% Easy The three areas of assessment to determine the level of unconsciousness using the Glasgow Coma Scale are motor, verbal, and eye response B | aI to stimuli. ci 16%", "whyNot": {"a": "Breathing patterns are not measured as part of the Glasgow Coma Scale.", "b": "Deep tendon reflexes are not assessed as part of the Glasgow Coma Scale.", "c": "Change in pupil size is not measured as part of the Glasgow Coma Scale."}, "keyConcept": "a © o 2 ° s a = a < The Glasgow Coma Scale provides a standardized way to document a client's neurological status. The score should be documented ona coma scale chart. The Glasgow Coma Scale provides a way for healthcare providers to identify trends rapidly so that any improvement or deterioration in the client's condition can be communicated urgently to the healthcare provider. Deterioration in a client's condition should prompt immediate review of any factors that could be responsible for the change that can be corrected. Glasgow Coma Scale Eye opening Spontaneously response To speech To pain No response Nw Best verbal Oriented to time, place, and person response Confused Inappropriate words Incomprehensible sounds No response —NWwWeun Best motor | Obeys commands response Moves to localized pain Flexion withdrawal from pain Abnormal flexion (decorticate) wWERunn"}, {"id": 10745, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is assessing an elderly client with pneumonia. Which of the following findings is potentially an early sign of sepsis?", "choices": [{"id": "a", "t": "Respiratory rate of 19/minute"}, {"id": "b", "t": "Altered mental status"}, {"id": "c", "t": "White blood cell count of 11,000"}, {"id": "d", "t": "Hypoglycemia"}], "correct": "b", "rationale": "al Sepsis refers to a systemic inflammatory response to a documented or suspected infection. In this case, altered mental status should be o: considered as a potential early sign of sepsis. Severe sepsis has mortality rates from 28-50%. a © Early identification of clients with known or suspected infection who may go on to develop sepsis is aided by the use of the quick SOFA D l score. The qSOFA score refers to the sequential (sepsis-related) organ failure assessment score, a commonly used scoring system to help identify sepsis for early intervention, in order to decrease sepsis-associated mortality. Clients outside the intensive care unit should be monitored for signs of sepsis to identify potential risk. The qSOFA score is easy to calculate. It has 3 components, each of which is allocated 1 point: @ Respiratory rate =22/minute Altered mentation Systolic blood pressure <100 mmHg Ascore of 22 is associated with poor outcomes due to sepsis.", "whyNot": {"a": "A respiratory rate of 222/minute should be considered as a potential harbinger of sepsis.", "c": "AWBC count >12,000 /microL or leukopenia (WBC count <4000/microL) is consistent with potential sepsis.", "d": "Hyperglycemia in a client who is not diabetic may be a harbinger of sepsis."}, "keyConcept": "Sepsis is a systemic inflammatory response to a suspected or documented infection. The pathogen responsible for the infection remains unidentified in up to 30% of cases. Severe sepsis is associated with mortality rates up to 50%, but early identification and treatment can improves outcomes. The qSOFA score gives one point for hypotension (systolic blood pressure <100 mmHg), impaired mentation or level of consciousness, and respiratory rate of 22 or higher/minute. A score of 2 or higher is associated with poor outcome."}, {"id": 10746, "cat": "NCLEX 13-Critical Care", "stem": "prevent an air embolism in this case? % CLOSE © Newc! NC x + v Qa * es * © tb Finish update : { Browse Questions > iit Search Questions QJ Type of Complication Nursing Interventions Hemorrhage Keep stopcocks closed, monitor tubing Embolism Clot Use heparin-coated catheters, flush regularly Infection Maintain sterile technique", "choices": [{"id": "a", "t": "Monitor site dressing for drainage"}, {"id": "b", "t": "Keep patient in Trendelenburg during insertion"}, {"id": "c", "t": "Ask the patient to cough every 4 hours"}, {"id": "d", "t": "Flush with saline, followed by heparin, every shift"}], "correct": "b", "rationale": "An air embolism develops when air enters a large blood vessel and produces a gas bubble within the circulation. An air embolism can cause an occlusion if it becomes lodged within a blood vessel and prevents blood flow. The nurse can take measures to prevent an air embolism during insertion of a pulmonary artery catheter by placing the client in the Trendelenburg position. This position, with the head down, decreases the risk of air entering circulation.", "whyNot": {"a": "Monitor site dressing for drainage. This would provide an early alert for bleeding but would not prevent embolus.", "c": "Ask the patient to cough every four hours. This would not prevent embolism.", "d": "Flush with saline, followed by heparin, every shift. This would keep the line patent but would not prevent an embolism."}, "keyConcept": "Apulmonary artery catheter is usually a multilumen catheter, 110 cm long, with extra connecting tubes for attachment to a pressure transducer. The PA lumen or distal lumen is at the tip. A 1.5-cc balloon is located proximal to the tip. A thermistor used to measure temperature changes for calculation of cardiac output is approximately four cm proximal to the balloon. Two additional lumens usually are present 19 cm and 30 cm from the tip. Depending on the degree of right heart enlargement and the position of the catheter, they reside within the right ventricle, right atrium, or the superior vena cava."}, {"id": 10747, "cat": "NCLEX 13-Critical Care", "stem": "appropriate first nursing intervention? Rar B/C brs! v.\\ae eon 67, SSBB AGEL Ss LGLOBe Jo) SUEDE ial See Lenn oes as 4) 4+ mt —~", "choices": [{"id": "a", "t": "Call the rapid response team for cardioversion."}, {"id": "b", "t": "Notify the healthcare provider and prepare to administer atropine. @ C. Notify the cardiologist and prepare for transcutaneous or transvenous pacing."}, {"id": "c", "t": "Whatever the cause, the nurse should recognize a complete heart block."}, {"id": "d", "t": "Document the rhythm and assessment in the client’s chart and monitor for further changes. eck Answer"}], "correct": "c", "rationale": "Whatever the cause, the nurse should recognize a complete heart block. The rhythm shown is third-degree heart block, which is complete dissociation of atrial and ventricular arrhythmia caused by a failure of the conduction system. This can occur after radiofrequency ablation, which is ablation of electrical pathways that cause tachyarrhythmia. Third-degree heart block can result in pre-syncope (lightheadedness), dizziness, fainting, confusion, hypotension, bradycardia, or heart failure. The ECG will demonstrate a regular rate and rhythm, but the P waves and Q waves have no relationship to one another. Third-degree heart block requires temporary or permanent pacing and is a life- threatening condition.", "whyNot": {"a": "Cardioversion is indicated for the treatment of stable tachyarrhythmia.", "b": "Pacing is necessary for Mobitz type Il second-degree heart block and third-degree heart block because both conditions involve disorders", "d": "Third-degree heart block must be treated immediately because it is a life-threatening arrhythmia."}, "keyConcept": "Complete heart block, or third-degree atrioventricular block, refers to complete AV dissociation, in which no atrial impulses are conducted to the ventricles. Atria and ventricles contract independently. The ventricles contract in an escape rhythm, with the rate dependent upon the site of the block. The atrial rate is usually sinus at 60-100/minute. AV block results in reduction of cardiac output, with ischemia, heart failure, and syncope. A transcutaneous or transvenous pacemaker should be placed emergently."}, {"id": 10748, "cat": "NCLEX 13-Critical Care", "stem": "action? t O A. Administration of digoxin O B. Administration of amiodarone © c. defibrillation O D. Synchronized cardioversion", "choices": [{"id": "a", "t": "Administration of digoxin"}, {"id": "b", "t": "Administration of amiodarone © c. defibrillation"}, {"id": "c", "t": "Option C (text recovered from OCR is incomplete)."}, {"id": "d", "t": "Synchronized cardioversion"}], "correct": "c", "rationale": "Correct Answer: C. Defibrillation eo I of The rhythm is ventricular fibrillation. Ventricular fibrillation is a rhythm of chaotic electrical activity in the heart that renders the heart ec FY unable to effectively pump and maintain cardiac output. This is a terminal rhythm. Immediate CPR is indicated, followed by defibrillation as my Hl soon as the defibrillator is available. Defibrillation refers to nonsynchronized random administration of shock during a cardiac cycle. It results in interruption and termination of the abnormal electrical rhythm, allowing the sinus node to resume normal pacemaker activity.", "whyNot": {"a": "Digoxin is used in heart failure and atrial fibrillation.", "b": "Amiodarone is an antiarrhythmic used in the treatment of ventricular arrhythmias, but the priority intervention in ventricular fibrillation is", "d": "Synchronized cardioversion is used for the treatment of stable tachyarrhythmia."}, "keyConcept": "VF is an irregular heartbeat characterized by uncoordinated contractions of the ventricle. During ventricular fibrillation, the heart does not pump blood effectively. It is the leading cause of death in cardiac arrest and occurs most frequently in clients with preexisting heart disease, including myocardial infarction. Immediate chest compressions and rapid defibrillation increase the risk of survival."}, {"id": 10749, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is documenting the assessment findings of a client who is in the ICU. Which of the following information should the nurse identify as subjective data?", "choices": [{"id": "a", "t": "Blood pressure"}, {"id": "b", "t": "Level of consciousness"}, {"id": "c", "t": "Nausea"}, {"id": "d", "t": "Petechiae"}], "correct": "c", "rationale": "Subjective data are information that only the client can perceive and report. The nurse cannot determine that the client feels nauseated.", "whyNot": {"a": "Objective data are information the nurse can observe or measure. The nurse can measure the client's blood pressure.", "b": "Objective data are information the nurse can observe or measure. The nurse can test and observe the client's responsiveness to", "d": "Objective data are information the nurse can observe or measure. The nurse can observe petechiae, which are small intradermal or"}, "keyConcept": "Nurses gather subjective data about symptoms during the assessment step of the nursing process. These data include clients' feelings, perceptions, and descriptions of their health status. Clients are the only ones who can describe and verify their own symptoms. Nurses collect objective data through observation (feeling, seeing, hearing, and smelling), physical examination, and the use of measurement tools and equipment."}, {"id": 10750, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is caring for a client with a fenestrated tracheostomy tube. What is the purpose of a fenestrated trach tube?", "choices": [{"id": "a", "t": "It allows a stylet to be introduced through the tracheostomy"}, {"id": "b", "t": "It reduces the risk of infection by promoting mucous drainage."}, {"id": "c", "t": "Itis used to keep the stoma from closing."}, {"id": "d", "t": "It allows air to pass over the vocal cords to enable the client to talk with a tracheostomy in place."}], "correct": "d", "rationale": "A | | 8% Moderate A fenestrated tracheostomy tube has holes on the posterior aspect of the outer cannula, above the cuff. It is used to allow the client to , cough, and speak when the tube is in place. A fenestrated tube is often used as a “step-down” tube before extubation is attempted. c | ™%", "whyNot": {"a": "This describes all types of tracheostomy tubes.The stylet is used for placement of the outer cannula of the tracheostomy tube.", "b": "A fenestrated tracheostomy tube does improve coughing and swallowing, but does not promote drainage or reduce the risk of infection.", "c": "The outer cannula is used to keep the stoma from closing."}, "keyConcept": "A fenestrated tube allows the client to breath normally with a tracheostomy in place. The client can speak through the mouth when using a fenestrated tube with a deflated cup, as air passes upwards through the fenestrations and over the vocal cords to allow vocalization. Swallowing and coughing are also improved. A fenestrated tube is often placed just before decannulation."}, {"id": 10751, "cat": "NCLEX 13-Critical Care", "stem": "A nurse is preparing to perform endotracheal suctioning for a client who is intubated and mechanically ventilated. Which of the following will the nurse consider when performing this task?", "choices": [{"id": "a", "t": "Suction for the shortest time possible to remove secretions"}, {"id": "b", "t": "Instill 10 cc of normal saline solution into the tube to break up secretions for better results"}, {"id": "c", "t": "Start suction pressure at the highest setting and slowly decrease the amount"}, {"id": "d", "t": "Decrease the Fi02 prior to suctioning and then turn it up when suctioning is complete"}], "correct": "a", "rationale": "Endotracheal suction produces a negative pressure in the trachea, reducing oxygenation. The nurse should suction for no longer than ten B i at seconds to remove secretions. The client should be hyperoxygenated in preparation for suction and no more than one or two passes should be made. Long periods of suctioning result in hypoxemia and should be avoided. c | 2% of 4%", "whyNot": {"b": "While this practice may be common in some locations, instilling normal saline solution before suctioning has not been shown to be", "c": "Instead of starting at the highest suction pressure setting, the nurse should start at the lowest suction setting and increase as needed.", "d": "Before starting to suction, the nurse should provide extra oxygen to the client by turning up the Fi02 and then decreasing it when"}, "keyConcept": "Endotracheal suctioning should not be routinely performed; it should be performed only when necessary to clear secretions and maintain a patent airway in a client who is unable to effectively clear secretions or who is in respiratory distress. Complications include damage to the airway mucosa with risk of pulmonary hemorrhage; introduction of infectious pathogens into the airway; bronchospasm; bradycardia in response to vagal stimulation; hemodynamic instability; and pulmonary vasoconstriction."}, {"id": 10752, "cat": "NCLEX 13-Critical Care", "stem": "Which of the following clients should receive priority for a nurse’s assessment at the beginning of the shift?", "choices": [{"id": "a", "t": "A client with pancreatitis who has nausea and vomiting"}, {"id": "b", "t": "A client who had a hip replacement the previous day and is complaining of 8/10 pain"}, {"id": "c", "t": "An elderly client who fell out of bed last night and has new-onset lethargy and confusion"}, {"id": "d", "t": "An elderly client who has lung cancer and COPD with an oxygen saturation of 89% by pulse oximetry"}], "correct": "c", "rationale": "A client with a closed head injury and a changed level of consciousness is an emergent priority, as mental status changes or neurological deficits may indicate increased intracranial pressure (ICP) from intracranial hemorrhage and/or increased intracerebral edema. Irreversible progression of cerebral edema can result in death, as the brain may herniate and compress the respiratory center. Each shift should begin with a basic neurological assessment that includes the level of consciousness, speech, mentation, pupillary size and response, and the strength of a hand grasp. After a baseline is established, subsequent assessments can be compared to determine if any changes indicative of increased ICP are present. A. Although nausea and vomiting must be addressed, the priority is a potential increase in ICP in the patient who fell.", "whyNot": {"b": "Pain should be addressed in a timely fashion, but it is not life-threatening.", "d": "An oxygen saturation of 88-92% is a target goal for clients with COPD. Higher oxygen saturation may suppress the client’s respiratory drive"}, "keyConcept": "Signs of increased intracranial pressure (ICP) include altered level of consciousness, unequal pupil size or reactivity, headache, decreased"}, {"id": 10753, "cat": "NCLEX 13-Critical Care", "stem": "Acharge nurse in the intensive care unit is assigning clients. Which of the following clients should be assigned to the most experienced nurse?", "choices": [{"id": "a", "t": "A client with a potassium level of 6.0 mEq/L who has peaked T waves"}, {"id": "b", "t": "A client with type diabetes with a blood glucose level of 280 mg/dL"}, {"id": "c", "t": "A client with congestive heart failure who is scheduled for an echocardiogram O D.A client with COPD who has ABG values of: pH 7.38, PaO2 78, PaCO2 42, HCO3 24"}], "correct": "a", "rationale": "The normal serum potassium level is 3.5-5.0 mEq/L. The client with a potassium level of 6.0 mEq/L and peaked T waves has hyperkalemia, which can produce life-threatening arrhythmias, including ventricular fibrillation, leading to death. The most experienced nurse should be assigned to this client, who is the least stable client. Early changes on ECG at potassium levels 5.5-6.5 mEq/L include tall, peaked T waves, shortening of the QT interval, and ST-segment depression. In clients with hyperkalemia and ECG changes, treatment includes: © IVcalcium to stabilize myocardial cell membrane © Identify and remove source of potassium intake IV glucose and insulin infusion to increase potassium uptake by cells © Sodium bicarbonate to treat severe metabolic acidosis, when present © Diuretics or gastrointestinal cation-exchange medications to increase elimination of potassium", "whyNot": {"b": "Although this glucose level is high, it is not life-threatening.", "c": "An echocardiogram is a routine procedure, so a less experienced nurse can be assigned. There is no indication that this client is unstable."}, "keyConcept": "When assigning client care, the most experienced nurse should care for unstable clients. Hyperkalemia results in ECG changes and can cause fatal arrhythmias and death. Treatment is multifaceted and may include IV calcium, infusion of IV glucose and insulin, diuretics, cation exchange resins, and sodium bicarbonate."}, {"id": 10754, "cat": "NCLEX 13-Critical Care", "stem": "Alicensed practical nurse (LPN) was pulled to the intensive care unit. Which of the following tasks can the charge nurse assign to the LPN?", "choices": [{"id": "a", "t": "Assess a client with new onset dyspnea"}, {"id": "b", "t": "Assist the healthcare provider with insertion of a radial arterial line for blood pressure monitoring"}, {"id": "c", "t": "Begin transfusion of a liter of packed red blood cells prescribed for a client with a GI bleed"}, {"id": "d", "t": "Begin dopamine infusion for a client who is hypotensive"}], "correct": "b", "rationale": "The LPN can assist with a procedure, so this is the most appropriate task.", "whyNot": {"a": "The registered nurse cannot delegate assessment. A client with new onset dyspnea is also unstable, another reason the client cannot be", "c": "The LPN cannot initiate a transfusion, so this task is not appropriate for assignment by the RN.", "d": "A hypotensive client who requires a vasopressor (dopamine) is unstable, so this client should not be assigned to the LPN."}, "keyConcept": "An assignment refers to the allocation of client care responsibilities or interventions that are within the LPN's scope of practice and/or scope of employment. LPNs can generally be assigned care of stable clients and can perform tasks for which they have the appropriate knowledge or skill."}], "nclex_15_endoctrine": [{"id": 10755, "cat": "NCLEX 15- ENDOCTRINE", "stem": "The nurse is giving a talk about diabetes to a group of 8th grade students. Which of the following does the nurse know is the greatest risk factor for development of type 2 diabetes?", "choices": [{"id": "a", "t": "Obesity"}, {"id": "b", "t": "High blood pressure"}, {"id": "c", "t": "Adiet high in fat and cholesterol"}, {"id": "d", "t": "Cigarette smoking and secondhand smoke"}], "correct": "a", "rationale": "Research shows that the biggest risk factor for the development of type 2 diabetes is obesity. Although hypertension and cigarette smoke are B | a0 harmful to health, they have not been directly related to the development of type 2 diabetes. A diet high in fat and cholesterol may lead to obesity and heart disease, but that is not a factor that puts a person at the highest risk for development of diabetes. c | 8% p| 2%", "whyNot": {"b": "High blood pressure may develop in an 8th grade student and can be harmful to his or her health, but it is not the biggest risk factor for", "c": "Adiet that is high in fat and cholesterol can contribute to heart disease and obesity; however, this type of diet is not the biggest risk factor", "d": "Smoking and secondhand smoke exposure can be harmful, but they are not the biggest risk factors for developing type 2 diabetes."}, "keyConcept": "Risk factors for type 2 diabetes mellitus (non-insulin dependent diabetes) include overweight or obese body habitus; age 45 or older; family history of diabetes; African American, Alaska Native, American Indian, Asian American, Hispanic/Latino, Native Hawaiian, or Pacific Islander ethnicity; high blood pressure; low level of HDL (“good”) cholesterol, or a high level of triglycerides; history of gestational diabetes or fetal macrosomia (birth of baby > 9lbs); sedentary lifestyle; history of heart disease or stroke; depression; polycystic ovary syndrome (PCOS); and acanthosis nigricans (dark, thick, and velvety skin around the neck or axilla.)"}, {"id": 10756, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is assessing a client who has Cushing's disease. Which of the following manifestations is the priority for the nurse to report?", "choices": [{"id": "a", "t": "Peripheral edema"}, {"id": "b", "t": "Fatigue"}, {"id": "c", "t": "Fragile skin"}, {"id": "d", "t": "Joint pain"}], "correct": "a", "rationale": "The greatest risk to a client who has Cushing's disease is fluid retention, which can lead to pulmonary edema, hypertension, and heart failure. Therefore, this is the priority finding for the nurse to report.", "whyNot": {"b": "Cushing's disease puts the client at risk for fatigue. However, another finding is the priority for the nurse to report.", "c": "Cushing's disease puts the client at risk for fragile skin and hyperpigmentation. However, another finding is the priority for the nurse to", "d": "Cushing's disease puts the client at risk for muscle atrophy and pathologic fractures. However, another finding is the priority for the nurse"}, "keyConcept": "Cushing's disease is an endocrine disorder caused by an increased secretion of cortisol from the adrenal gland. Excess cortisol can lead to fluid and electrolyte imbalances, decreased muscle mass, osteoporosis, hyperglycemia, suppressed immune system, and depression. The nurse should monitor for these manifestations when caring for clients who have Cushing's disease to prevent further complications."}, {"id": 10757, "cat": "NCLEX 15- ENDOCTRINE", "stem": "hypoglycemia manifested by diaphoresis and tachycardia every afternoon about 1-2 hours before dinner. Which of the following changes should the nurse discuss with the client’s primary care provider?", "choices": [{"id": "a", "t": "Decrease the evening NPH insulin dose"}, {"id": "b", "t": "Decrease the morning NPH insulin dose"}, {"id": "c", "t": "Decrease the evening dose of regular insulin"}, {"id": "d", "t": "Decrease the morning dose of regular insulin"}], "correct": "b", "rationale": ". Hypoglycemia results when dietary intake is too low or an insulin dose is too high. Regular insulin acts within 2-5 hours, with a duration of 5-8 hours, and it is given 30-60 minutes before a meal, which it is intended to cover. NPH has a peak c |_| 13% action in 4-12 hours with a duration of action for 12-18 hours. NPH covers basal requirements through the night with an evening dose, and D Hi 14% the morning dose covers the second meal of the day. In this client, the morning dose of NPH is the most likely cause of the afternoon hypoglycemia. The best course of action is reducing the morning NPH dose.", "whyNot": {"a": "The evening NPH insulin dose supplies basal insulin during the night. It is not the cause of this client’s afternoon hypoglycemic episodes.", "c": "Regular insulin that is given before a meal covers that meal.", "d": "Regular insulin that is given before a meal covers that meal."}, "keyConcept": "Hypoglycemia (blood glucose < 70 mg/dL or <3.9 mmol/L) occurs when there is proportionately too much insulin available for available blood glucose. Signs of hypoglycemia include diaphoresis, tremor, weakness, irritability, confusion, visual disturbance, and decreased level of consciousness. If untreated, hypoglycemia can result in seizures, loss of consciousness, and death. Ingestion of 10-15 grams of a simple carbohydrate will reverse the process."}, {"id": 10758, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse in an outpatient clinic is assessing a 25-year-old woman at 30 weeks gestation. Which of the following findings could indicate a possible complication?", "choices": [{"id": "a", "t": "Increased vaginal discharge"}, {"id": "b", "t": "Feels pressure at diaphragm"}, {"id": "c", "t": "Positive urine test for glucose and ketones"}, {"id": "d", "t": "Pedal edema in both feet in the evenings"}], "correct": "c", "rationale": "all 7% Easy Positive urine test for glucose and ketones could indicate gestational diabetes mellitus. B I a", "whyNot": {"a": "tis normal for a pregnant client to experience an increased amount of vaginal discharge.", "b": "Pressure in the area of the diaphragm may occur with growth of the baby and pressure from the expanding uterus.", "d": "Increased edema in the lower legs and feet is a common occurrence that is more likely to occur in the evenings, after the client has been"}, "keyConcept": "Gestational diabetes (GD) is diagnosed when a woman develop diabetes for the first time during pregnancy. women who have had GD are at higher risk of developing diabetes later in life. Risk factors include being overweight or obese; physical inactivity; history of GD in a previous pregnancy; history of giving birth to a baby weighing 9 pounds or more in a previous pregnancy; high blood pressure; history of heart disease; polycystic ovary syndrome (PCOS); and African-American, Native American, Asian American, Hispanic, and Pacific Island ethnicity."}, {"id": 10759, "cat": "NCLEX 15- ENDOCTRINE", "stem": "likely to be which of the following?", "choices": [{"id": "a", "t": "Consult the dietician to follow-up with dietary instructions."}, {"id": "b", "t": "Provide a booklet on diet for the client to read at leisure."}, {"id": "c", "t": "Leave the client to watch a recorded diabetic education program."}, {"id": "d", "t": "Review the client's typical diet and discuss items that may increase blood glucose levels."}], "correct": "d", "rationale": "All 14% — Easy The most effective learning occurs in an adult client when the nurse’s teaching adds to the client’s knowledge about a topic perceived as B I Ee vital to the client's health and when the teaching is perceived as providing information that will benefit the client. By assisting a client to identify his or her choices in diet, the nurse is providing information specific to the client’s health. This is a type of active learning that c | 1% requires the client to participate in identification of menu items that may be problematic. @", "whyNot": {"a": "Although the dietician can provide valuable input for the client with respect to an appropriate diet, the nurse has an opportunity to teach", "b": "Although books and pamphlets can be helpful for reinforcement of nursing teaching, it is better to tailor teaching to the client’s specific", "c": "Patient education channels can be a useful way to reinforce nursing teaching, but it is important to engage the client when initiating"}, "keyConcept": "Successful techniques to use when teaching an adult client about a new health condition include providing information the client feels is vital and beneficial to his health and involving the client actively in decision making and planning."}, {"id": 10760, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following measures provides the best assessment of diabetic autonomic neuropathy in a client with type 2 diabetes mellitus?", "choices": [{"id": "a", "t": "Orthostatic blood pressure measurements"}, {"id": "b", "t": "Gait assessment"}, {"id": "c", "t": "Sensory exam of the feet"}, {"id": "d", "t": "Inspection for diabetic ulcers on the feet"}], "correct": "a", "rationale": "Diabetic neuropathy refers to nerve damage caused by metabolic derangements associated with diabetes mellitus. Sensory neuropathy is Cc | the most common manifestation of diabetic neuropathy and can lead to loss of protective sensation in the feet that increases the risk of D | injury, infection, and subsequent amputation. Autonomic neuropathy refers to damage to the autonomic nervous system, which controls all involuntary body functions. These functions include heart rate, blood pressure, sexual function, digestion, and perspiration. Clinical evidence of derangements of the autonomic nervous system include postural hypotension, tachycardia, blunted hypoglycemic response, impotence, urinary retention, bowel incontinence, and diarrhea. Orthostatic blood pressure movements are taken in the supine and standing positions. A drop of at least 20 mmHg systolic blood pressure or at least 10 mmHg diastolic blood pressure with standing is diagnostic of postural hypotension.", "whyNot": {"b": "Diabetic sensory neuropathy affects gait due to loss of sensation in the foot. Loss of proprioceptive sensation is often an early sign of", "c": "Asensory exam of the foot does not assess the autonomic nervous system.", "d": "Loss of sensation in the feet increases the risk of diabetic ulcers due to sensory neuropathy, not autonomic neuropathy."}, "keyConcept": "Diabetic neuropathy occurs in up to 70% of individuals with diabetes mellitus, occurring equally in type 1 diabetes and type 2 diabetes. Although multiple mechanisms of injury have been proposed, most experts believe that nerve damage results from accumulation of sorbitol and fructose in the nerves during periods of hyperglycemia. Microvascular damage also contributes to diabetic neuropathy. Characteristics include reduced nerve conduction, demyelinization, and ischemia due to vascular damage."}, {"id": 10761, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a child who has short stature. Which of the following diagnostic tests should be completed to assess growth hormone (GH) deficiency?", "choices": [{"id": "a", "t": "Bone age scan"}, {"id": "b", "t": "GH level"}, {"id": "c", "t": "Serum insulin-like growth factor 1 (IGF-1)"}, {"id": "d", "t": "DNA testing"}], "correct": "c", "rationale": "A | | 9% Hard Aserum IGF-1 is obtained as a preliminary test to determine GH deficiency. IGF and insulin-like growth factor binding protein 3 levels are B a oan measured and if they are low, further testing for GH deficiency is recommended. oc i 33% Symptoms of growth hormone deficiency in children include: © Below-average height © Slower-than-normal growth © Poor muscle development © Low blood glucose levels © Delayed onset of puberty", "whyNot": {"b": "Obtaining a single level of GH does not accurately confirm a GH deficiency.", "d": "DNA testing is not used to determine GH deficiency."}, "keyConcept": "Growth hormone provocative testing involves provoking the release of growth hormone with the use of a neuromodulator or agent such as clonidine, levodopa, insulin, glucagon, or propranolol. It is completed as an outpatient procedure and takes a few hours. Typically, an IV is inserted so that specimens can be drawn without requiring multiple venipunctures."}, {"id": 10762, "cat": "NCLEX 15- ENDOCTRINE", "stem": "care? O A. Avoidance of glucose infusion O B. Avoidance of potassium infusion O C. Administration of sodium bicarbonate O D. Initial infusion of isotonic crystalloids", "choices": [{"id": "a", "t": "Avoidance of glucose infusion"}, {"id": "b", "t": "Avoidance of potassium infusion"}, {"id": "c", "t": "Administration of sodium bicarbonate"}, {"id": "d", "t": "Initial infusion of isotonic crystalloids"}], "correct": "d", "rationale": "(DKA) is an acute complication of diabetes that is characterized by uncontrolled hyperglycemia due to insulin B I a deficiency. It can result in individuals with undiagnosed diabetes mellitus type 1 or in those who are nonadherent to therapy for type 1 diabetes. Conditions that increase metabolism of carbohydrates, including physical and emotional stressors, can result in increased c |__| 24% production of hormones such as cortisol, glucagon, and epinephrine, which stimulate production of glucose by the liver and cause reduction @D ft 54% of the effects of insulin. Clinical manifestations include polyuria, polydipsia, polyphagia, blurred vision, fruity breath, Kussmaul respirations, mental status changes, nausea, vomiting, and abdominal pain. In addition to hyperglycemia, dehydration, acidosis, and electrolyte abnormalities characterize DKA. Treatment includes restoration of volume with isotonic fluid, repletion of potassium (due to whole body potassium deficit); and correction of hyperglycemia with infusion of insulin. Bicarbonate is only indicated for a pH of <7.0.", "whyNot": {"a": "When the serum glucose level reaches 250 mg/dL, glucose is added to intravenous fluids to avoid a rapid shift in osmolarity and to prevent", "b": "Although the initial serum potassium level may be normal or elevated, a whole body potassium deficit is usually present. Insulin is", "c": "Sodium bicarbonate is not routinely administered in DKA. It is indicated only for a pH of <7.0."}, "keyConcept": "Glucosuria in clients with diabetic ketoacidosis results in osmotic diuresis and subsequent volume depletion. Replacement of fluid volume with isotonic crystalloids is an essential part of therapy. DKA usually results in whole body potassium depletion, so supplemental potassium is usually indicated."}, {"id": 10763, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who was recently diagnosed with diabetes mellitus and reports feeling shaky and weak. Which action should the nurse take?", "choices": [{"id": "a", "t": "Provide subcutaneous insulin for the client."}, {"id": "b", "t": "Offer the client 120 mL (4 02) of fruit juice."}, {"id": "c", "t": "Give the client IV potassium."}, {"id": "d", "t": "Administer IV sodium bicarbonate to the client."}], "correct": "b", "rationale": "al 3% Easy The client has manifestations of hypoglycemia. The nurse should offer the client 10 to 15 g of a carbohydrate, such as 120 mL (4 02) of fruit OB rT sid 04% juice. c | 2%", "whyNot": {"a": "The client is exhibiting manifestations of hypoglycemia. Therefore, the nurse should not administer insulin to the client.", "c": "IV potassium may be used to treat hypokalemia.", "d": "IV sodium bicarbonate may be used to treat metabolic acidosis."}, "keyConcept": "The nurse should identify manifestations of both hypoglycemia and hyperglycemia and be able to intervene based on those manifestations. The nurse should administer 15 g of an absorbable carbohydrate, wait 15 min, and recheck the blood glucose level for a client who has manifestations of hypoglycemia. Foods that Contain 15 g of Carbohydrates: +1 cup (8 oz) low-fat milk +1 tbsp sugar + ¥2 cup (4 02) sugared soda or juice + Glucose tablets + Glucose gel tube"}, {"id": 10764, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is teaching a client with diabetes about the appropriate use of glucagon. The nurse will explain that glucagon is for which of the following reasons?", "choices": [{"id": "a", "t": "Lower high levels of blood glucose"}, {"id": "b", "t": "Stimulate insulin production by the pancreas"}, {"id": "c", "t": "Promote glycogen synthesis in the liver"}, {"id": "d", "t": "Increase levels of glucose in the bloodstream"}], "correct": "d", "rationale": ". A diabetic client may need a dose of glucagon, available as B 7% a medication, when experiencing hypoglycemia. The glucagon can help to raise dangerously low levels of blood glucose. i cH 9% Conan a A. Glucagon is designed to raise blood glucose levels, not lower them. B. Increased insulin production can reduce blood glucose levels; glucagon is designed to raise glucose levels. C. Glucagon does not promote glycogen synthesis in the liver.", "whyNot": null, "keyConcept": "Glucagon promotes production of glucose from glycogen stores in the liver. It is used for acute management of severe hypoglycemia when glucose cannot be administered. The nurse should educate the client and family about recognition of the signs and symptoms of hypoglycemia. The client should be instructed to take oral glucose as soon as symptoms of hypoglycemia occur. Glucagon is reserved for episodes when the client is unable to swallow because of a decreased level of consciousness. Onset of therapeutic effect is usually within 10- 15 minutes. 2 (S g o 5 x < Insulin/Glucagon cycle Adipose cells ; CSee= Pancreatic beta cells Aner. 4 Liver breaks down Pancreatic alpha cells alycogen to glucose release glucagon"}, {"id": 10765, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is asked to speak to a group of women at a community health day about osteoporosis. Which of the following should she include when discussing the risk factors for osteoporosis? OA obesity O B. Late menopause © c. Multiparity O D. Cigarette smoking", "choices": [{"id": "a", "t": "Low body weight is a risk factor. Obesity may have a protective effect due to higher estrogen levels from the conversion of androgens in"}, {"id": "b", "t": "Early menopause is a risk factor for osteoporosis."}, {"id": "c", "t": "Nulliparity is associated with increased risk for osteoporosis."}, {"id": "d", "t": "Osteoporosis is a disorder that affects over 9 million people in the United States, primarily women."}], "correct": "d", "rationale": "Osteoporosis is a disorder that affects over 9 million people in the United States, primarily women. It is characterized by a low bone mass © I with disruption of bone architecture and bone fragility that increases the risk of fractures, most commonly in the spine, pelvis, hip, humerus, ep | or wrist. Risk factors for osteoporosis include advanced age, low body weight, excess alcohol consumption, cigarette smoking, family history of hip fracture or prior fracture, and long-term use of glucocorticoids. Smoking decreases the production of estrogen and causes earlier and more rapid bone loss. Post-menopausal women are at risk due to decreased estrogen levels, since estrogen stimulates osteoblasts to build bone. Estrogen is also necessary for conversion of vitamin D to calcitonin, which activates D cell receptors in the intestine to facilitate absorption of calcium. The fractures associated with osteoporosis are considered low trauma or pathologic fractures and may result in limited ambulation, chronic pain, depression, and loss of independence.", "whyNot": {"a": "Low body weight is a risk factor. Obesity may have a protective effect due to higher estrogen levels from the conversion of androgens in", "b": "Early menopause is a risk factor for osteoporosis.", "c": "Nulliparity is associated with increased risk for osteoporosis."}, "keyConcept": "Modifiable risk factors for osteoporosis include low body weight, excess alcohol consumption, cigarette smoking, and long-term glucocorticoid use. Postmenopausal women should supplement their diet with calcium and 800 to 1000 IU of vitamin D, which facilitates absorption of calcium and phosphate in the gut."}, {"id": 10766, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse offers a snack of crackers at midafternoon to a client with a prescription for 25 units of NPH insulin before breakfast each day. This snack is prescribed for which of the following reasons?", "choices": [{"id": "a", "t": "Prevention of diabetic ketoacidosis"}, {"id": "b", "t": "Prevention of insulin reaction"}, {"id": "c", "t": "Regulation of carbohydrate metabolism"}, {"id": "d", "t": "Maintenance of nutritional requirements"}], "correct": "c", "rationale": "Correct Answer: C. Regulation of carbohydrate metabolism Acarbohydrate snack in the midafternoon will prevent hypoglycemia in a client who has a peak action of intermediate-acting insulin at that time. The peak action for intermediate action is 4-12 hours. Intermediate acting insulin is provided to control the basal level of insulin in a client with diabetes. The highest risk of hypoglycemia is during the period of peak action. A bedtime snack should also be given to avoid nighttime hypoglycemic episodes.", "whyNot": {"a": "Diabetic ketoacidosis is caused by insulin deficiency.", "b": "The reaction prevented is hypoglycemia in response to the peak onset of insulin action.", "d": "Crackers will add little nutritional value but will prevent hypoglycemia as the intermediate-acting insulin hits its peak."}, "keyConcept": "Intermediate acting insulin has onset of 1.5-2 hours, with a peak action between 4-12 hours and duration of action of 18-24 hours. The risk of hypoglycemia is highest during the period of peak action."}, {"id": 10767, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is assigned to care for a newly admitted client in a hyperosmotic hyperglycemic state (HHS). Which of the following laboratory findings does the nurse expect? ©", "choices": [{"id": "a", "t": "hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent ec ;"}, {"id": "b", "t": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS."}, {"id": "c", "t": "Al oa A hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent ec ; hyperglycemia but adequate insulin to prevent the development of ketoacidosis."}, {"id": "d", "t": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}], "correct": "c", "rationale": "Al oa A hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent ec ; hyperglycemia but adequate insulin to prevent the development of ketoacidosis. Risk factors include older age, preexisting underlying D | | conditions such as stroke or sepsis, and dehydration. HHS is usually characterized by glucose >600 mg/dL and hyperosmolarity resulting in dehydration. The onset of HHS is usually gradual. Findings include polyuria, polydipsia, polyphagia, nausea, vomiting, abdominal pain, altered mental status, reversible paralysis, and coma. Coma typically occurs with serum osmolarity >350 mOsm/L. Normal serum osmolarity is 275-295 mOsm/L.", "whyNot": {"a": "This is a normal BUN. In HHS, BUN >30 mg/dL is expected as a result of dehydration. Creatinine would be expected to be >1.5 mg/dL.", "b": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS.", "d": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}, "keyConcept": "Hyperglycemic hyperosmolar nonketotic syndrome is characterized by hyperglycemia, hyperosmolarity, and dehydration. The condition occurs when individuals produce enough insulin to reduce ketosis but inadequate insulin to control hyperglycemia. Hyperglycemia results in osmotic diuresis, causing fluid and electrolyte imbalances."}, {"id": 10768, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is providing teaching for a client who will undergo a thyroidectomy. How should the nurse advise the client concerning the Lugol solution prescribed before surgery?", "choices": [{"id": "a", "t": "Take the medication with juice"}, {"id": "b", "t": "Take the medication before going to bed"}, {"id": "c", "t": "Avoid exposure to sunlight when taking the medication"}, {"id": "d", "t": "Take propylthiouracil (PTU) after taking Lugol solution"}], "correct": "a", "rationale": "oi 33% Hard Hi 19% The thyroid gland absorbs dietary iodine, found in many foods, combines it with the amino acid tyrosine, and converts it into thyroid | 35% hormones thyroxine (T4) and triiodothyronine (T3). Although iodine is necessary for synthesis of thyroid hormone in individuals with normal D Hi 13% thyroid function, it inhibits synthesis and release of thyroid hormone in individuals with hyperthyroidism. B © Lugol solution is a solution of potassium iodide and iodine that is given prior to a thyroidectomy. The client should be instructed to take 5-7 drops 3 times a day for 10 days before the surgery. In clients who are hyperthyroid, the iodine will inhibit synthesis of thyroid hormone and secretion into the circulation while decreasing the size and vascularity of the gland to reduce the risk of complications of surgery. The solution has a bitter taste and should be given with juice. Lugol solution is also used for treatment of thyroid storm and for short-term treatment of hyperthyroidism. It should not be taken after PTU, methimazole, or radioactive iodine.", "whyNot": {"b": "Lugol solution drops are taken 3 times a day.", "c": "Photosensitivity does not occur with Lugol solution.", "d": "PTU, methimazole, or radioactive iodine should not be taken after Lugol solution."}, "keyConcept": "Lugol solution, a potassium iodide-iodine solution, inhibits synthesis and release of thyroid hormone in individuals with hyperthyroidism. It is prescribed for individuals with hyperthyroidism for ten days prior to thyroidectomy, to decrease serum levels of thyroid hormone and reduce the size and vascularity of the thyroid gland. It is also used in conjunction with other medications to treat thyroid storm."}, {"id": 10769, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with Addison’s disease. Which of the following does the nurse expect to find when assessing the client?", "choices": [{"id": "a", "t": "Hyperpigmentation of skin"}, {"id": "b", "t": "Truncal obesity"}, {"id": "c", "t": "Acne"}, {"id": "d", "t": "Hirsutism"}], "correct": "a", "rationale": "Addison’s disease refers to primary adrenal insufficiency that results from damage to or malfunction of the adrenal gland. This causes a drop in production of aldosterone and cortisol. Aldosterone is a mineralocorticoid, and its effects include increased absorption of sodium and excretion of potassium by the kidney. Cortisol is a glucocorticoid that regulates the body’s stress response and immune function and affects the metabolism of glucose, fat, and protein. The adrenal gland also produces sex hormones, including estrogens and androgens. Findings on assessment of a client with Addison’s disease include weight loss, salt craving, orthostatic hypotension, weakness, fatigue, nausea, vomiting, and hyperpigmentation. Electrolyte manifestations of Addison’s disease include hypoglycemia, hyperkalemia, hyponatremia, and hypercalcemia. Clients with adrenal insufficiency may require increased dosages of glucocorticoids during periods of illness or stress to avoid Addisonian crisis, a medical emergency. Bronzing of the skin occurs in clients with Addison’s disease due to stimulation of melanocytes by excess ACTH.", "whyNot": {"b": "Truncal obesity is associated with Cushing disease and an excess of glucocorticoids.", "c": "Acne is associated with Cushing disease and excess glucocorticoids.", "d": "Hirsutism occurs with Cushing disease, which is associated with excess glucocorticoid levels. Addison’s disease is associated with"}, "keyConcept": "Addison’s disease or adrenal hypofunction is a rare disorder characterized by inadequate production of the steroid hormones cortisol and aldosterone by the outer layer of cells of the adrenal glands, known as the adrenal cortex. Treatment includes replacement of these hormones and supportive measures that include volume replacement."}, {"id": 10770, "cat": "NCLEX 15- ENDOCTRINE", "stem": "When instructing a client with type 2 diabetes mellitus who is being discharged with a prescription for glipizide, which statement should the nurse recognize as a sign of the need for further education? O A.\"I should call my healthcare provider if my morning blood glucose is below 60 mg/dL.\" O B. \"I can expect weight gain with this medication.\" O C.\"I should avoid alcohol after starting this medication.\" O D. \"Ido not have to read the labels of foods that are 'sugar-free.\"\"", "choices": [{"id": "a", "t": "This statement by a client indicates understanding. Hypoglycemia is a major adverse effect associated with sulfonylurea medications,"}, {"id": "b", "t": "This statement by a client indicates understanding. Weight gain is a major adverse effect associated with sulfonylurea medications,"}, {"id": "c", "t": "This statement by a client indicates understanding. Hypoglycemia can occur with alcohol intake and should be avoided with sulfonylurea"}, {"id": "d", "t": "Foods that are labeled “sugar-free,” “diabetic,” and “sugarless” may still contain carbohydrates that can raise the serum blood glucose."}], "correct": "d", "rationale": "Foods that are labeled “sugar-free,” “diabetic,” and “sugarless” may still contain carbohydrates that can raise the serum blood glucose. © | | These carbohydrates, often used as sweeteners, include brown sugar, corn syrup, and honey. ep |", "whyNot": {"a": "This statement by a client indicates understanding. Hypoglycemia is a major adverse effect associated with sulfonylurea medications,", "b": "This statement by a client indicates understanding. Weight gain is a major adverse effect associated with sulfonylurea medications,", "c": "This statement by a client indicates understanding. Hypoglycemia can occur with alcohol intake and should be avoided with sulfonylurea"}, "keyConcept": "Glipizide (Glucotrol) is a sulfonylurea hypoglycemic medication. It reduces the level of blood glucose by stimulating the pancreas to release more insulin and by increasing the sensitivity of insulin receptors. It is not used in type 1 diabetes mellitus, because the mechanism of action requires a functioning pancreas. The nurse should review signs of hypoglycemia and hyperglycemia with client and advise the client to drink a glass of orange juice or ingest 2- 3 tsp of sugar, if symptoms of hypoglycemia occur. Concurrent use of a beta-blocker medication may mask the signs/symptoms of hypoglycemia."}, {"id": 10771, "cat": "NCLEX 15- ENDOCTRINE", "stem": "@O@ *& Viral nu «<> ¢G o- =o Sa Record ™ Inbox ( student.atitesting.com/LT| ™ Inbox - ) untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaencriaelicr ® Atte, NC x + v © Newcl EX test automa Qa * ws * © Cb Finish update : se Tutorial: BoardVitals NCLEX Prep RN % CLOSE Pas ati Module: Quizzes & Assignments Dashboard Quiz —_ Performance ~” { Browse Questions ~ |{ Search Questions [2 )", "choices": [{"id": "a", "t": "They have a history of long-term steroid use"}, {"id": "b", "t": "They have a history of hypoparathyroidism"}, {"id": "c", "t": "They have taken excessive amounts of estrogen"}, {"id": "d", "t": "They lift weights at a gym"}], "correct": "a", "rationale": "Use of steroids leads to bone demineralization.", "whyNot": {"b": "Hyperparathyroidism accelerates bone demineralization, not hypoparathyroidism. D |", "c": "Estrogen aids in depositing calcium into the bones.", "d": "Weight-bearing exercise helps prevent bone demineralization."}, "keyConcept": "Osteoporosis is characterized by low bone mass, disruption of bone architecture, and skeletal fragility. Osteoporosis is associated with an increased risk of fracture. Risk factors include advanced age, previous fracture, long-term glucocorticoid therapy, low body weight (less than 58 kg [127 lb]), family history of hip fracture, cigarette smoking, and excess alcohol intake."}, {"id": 10772, "cat": "NCLEX 15- ENDOCTRINE", "stem": "@0O@ * Viralnu ™ Inbox( =™ Inbox - <€ 2» G student.atitesting.com/LT| ) untitle: Untitle (4 Google @ TEASF Online = & Mark k Tutorial: BoardVitals NCLEX Prep RN sg Poa ati Module: Quizzes & Assignments Dashboard Quiz ~ Performance ~ A nurse is teaching a group of adults about diabetes. She provides them with all of the following facts EXCEPT:", "choices": [{"id": "a", "t": "Having a sibling with diabetes increases one's risk of developing the disease"}, {"id": "b", "t": "Being Caucasian increases one's risk of developing diabetes"}, {"id": "c", "t": "Being over the age of 45 increases the risk of developing the disease"}, {"id": "d", "t": "Having high blood pressure increases the risk of developing the disease"}], "correct": "b", "rationale": "The following groups are at higher risk of developing diabetes: African Americans, Alaska Natives, American Indians, Asian Americans Hispanics/Latinos, or Pacific Islander Americans.", "whyNot": {"a": "Ifa client has a sibling with diabetes, he or she is more likely to develop the disease.", "c": "A client over the age of 45 years is at higher risk of developing diabetes because of age.", "d": "High blood pressure puts a client at higher risk of developing other illnesses, such as diabetes."}, "keyConcept": "Risk factors for the development of type 2 diabetes include overweight or obesity; age 45 or older; family history of diabetes; African American, Alaska Native, American Indian, Asian American, Hispanic/Latino, Native Hawaiian, or Pacific Islander heritage; high blood @ Micros (eeiNenencenme ice ® Atte, NC x + v © Newcl EX test automa % CLOSE Qa * ws * © Cb Finish update : { Browse Questions ~ it Search Questions [a]"}, {"id": 10773, "cat": "NCLEX 15- ENDOCTRINE", "stem": "most likely to give an accurate diagnosis?", "choices": [{"id": "a", "t": "Pancreatic ultrasound O B.CT scan"}, {"id": "c", "t": "Serum amylase"}, {"id": "d", "t": "Endoscopic ultrasound with fine-needle aspiration biopsy"}], "correct": "d", "rationale": "| 11% The pancreas is a mixed gland composed of endocrine and exocrine cells. It lies behind the stomach, extending from the duodenum to the © | | 7% spleen. It is divided into three portions, known as the head, body, and tail. The exocrine cells of the pancreas secrete digestive enzymes, @pD PF 11% including amylase, lipase, trypsin, and chymotrypsin. The endocrine cells produce glucagon and insulin. Pancreatic tumors can obstruct the biliary ducts, causing obstructive jaundice. Although an ultrasound is usually the first test performed for individuals with epigastric pain, weight loss, and/or jaundice, it is not as sensitive as endoscopic retrograde cholangiopancreatography (ERCP) or endoscopic ultrasound (EUS), particularly for small tumors. An advantage of EUS is the ability to obtain a fine-needle aspirate biopsy. ERCP allows sampling of cytology brushings. Endoscopic procedures are invasive, so a formal, signed consent form is required. The client must fast prior to an endoscopic procedure and dentures should be removed and placed in a denture cup. Endoscopic examinations are performed under sedation, to relax the client and facilitate passage of the endoscope. 2 = ® 4 z = a iat g <", "whyNot": {"a": "Apancreatic ultrasound is less sensitive than ERCP, but it is less expensive and less invasive than ERCP and can identify dilation of the", "c": "Serum amylase is released when pancreatic cells are inflamed; it is used in the diagnosis of pancreatitis."}, "keyConcept": "Endoscopic ultrasound or endoscopic retrograde cholangiopancreatography are sensitive and specific tests for diagnosis of a malignancy of the pancreas. They allow biopsy (EUS) or collection of cytology brushings. Large pancreatic tumors can be identified by transabdominal ultrasound, but more invasive diagnostic procedures are necessary to obtain tissue or cell samples. A signed consent form is required before endoscopic procedures and the client should be fasting."}, {"id": 10774, "cat": "NCLEX 15- ENDOCTRINE", "stem": "correct? O A. “Okay, let’s get started and I'll check your glucose now.” O B. “I’ll need to come back in an hour and check it then.” O C. “You were supposed to fast for 24 hours before this test.” O D. “I'll check with the healthcare provider first before performing the test.”", "choices": [{"id": "a", "t": "“Okay, let’s get started and I'll check your glucose now.”"}, {"id": "b", "t": "“I’ll need to come back in an hour and check it then.”"}, {"id": "c", "t": "“You were supposed to fast for 24 hours before this test.”"}, {"id": "d", "t": "“I'll check with the healthcare provider first before performing the test.”"}], "correct": "d", "rationale": "Eating food or drinking liquids that have calories, particularly from carbohydrates, can change blood glucose levels and will not provide an accurate result. Before checking the blood glucose level in this client, the nurse should notify the healthcare provider that the client has not fasted for the recommended 8-hour period.", "whyNot": {"a": "The nurse should first check with the healthcare provider before drawing the client’s fasting glucose level if he has only fasted for 3 hours", "b": "Waiting an hour will not correct the situation. The test should be performed after the client has fasted for eight hours.", "c": "The recommended period of fasting is 8 hours prior to the test, not 24 hours."}, "keyConcept": "A fasting blood sugar level less than 100 mg/L (5.6 mmol/dL) is normal. Pre-diabetes is characterized by a fasting blood sugar level from 100 to 125 mg/dL (5.6 to 6.9 mmol/L). A fasting blood glucose level of 126 mgd/L (7 mmol/L) or higher on two separate tests is diagnostic of diabetes.The client should not eat or drink anything but water for eight hours before the fasting blood glucose test. Specific medications, including corticosteroids, aspirin, oral contraceptives, and hormone therapy, can affect blood glucose levels. The healthcare provider will advise the client whether or not to hold a medication pending the fasting blood glucose test."}, {"id": 10775, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with newly diagnosed diabetes mellitus type 1 (insulin-dependent). Which of the following signs would not be expected in a client with new-onset type 1 diabetes?", "choices": [{"id": "a", "t": "Polyuria"}, {"id": "b", "t": "Polydipsia"}, {"id": "c", "t": "Weight gain"}, {"id": "d", "t": "Polyphagia"}], "correct": "c", "rationale": "All Insulin is secreted by the beta cells of the pancreas. This anabolic hormone is necessary for the transport and metabolism of glucose for B energy; stimulation of glucose storage by liver and muscle; regulation of release of glucose by the liver; storage of dietary fat in adipose 1 tissue; and to enhance transport of amino acids into cells. Glucagon is a hormone that acts to stimulate the liver to release glucose by O€ as glycogenolysis and gluconeogenesis, which is the opposite effect of insulin. The secretion of insulin and glucagon into the blood in response D | | to the blood glucose concentration is the primary mechanism of glucose homeostasis in the body. Individuals with type 1 diabetes do not make insulin, due to autoimmune destruction of the beta cells of the pancreas. These individuals need an exogenous supply of insulin to regulate blood glucose levels. Type 1 diabetes is usually diagnosed in childhood, although 25% of cases are diagnosed in adults. New onset diabetes is often characterized by hyperglycemia with polyphagia, polyuria, and polydipsia. Some individuals may present with diabetic ketoacidosis (DKA.) Weight loss occurs when insulin is not available to facilitate cellular uptake of glucose. This results in catabolism (breakdown) of protein and fat stores to supply energy. Weight loss may also occur as a result of osmotic diuresis due to hyperglycemia with subsequent glucosuria (glucose in the urine). Type 2 diabetes is characterized by insulin resistance and impaired insulin production. Control of blood glucose levels can be managed in some cases with weight loss and dietary management. Type 1 diabetes is far less common than type 2 diabetes, only occurring in 5-15% of all cases of diabetes mellitus.", "whyNot": {"a": "Polyuria occurs when glucose cannot be taken up into cells and is excreted by the kidneys. The presence of glucose in urine results in", "b": "Polydipsia, or increased thirst, occurs due to dehydration after osmotic diuresis.", "d": "The breakdown of fats and proteins for energy induces a starvation state, which results in polyphagia (significantly increased"}, "keyConcept": "Type 1 diabetes is characterized by destruction of the pancreatic beta cells, which produce insulin. It is most commonly diagnosed in childhood, although 25% of cases are diagnosed in adults. Insulin is necessary to utilize glucose for cellular energy and to regulate the conversion of amino acids to glucose in the liver. Signs of new-onset type 1 diabetes include weight loss, polyphagia, polyuria, and polydipsia. Weight loss may occur as a result of catabolism of muscles that occurs due to inability of cells to process glucose for energy needs. Diabetic ketoacidosis may be the initial presentation."}, {"id": 10776, "cat": "NCLEX 15- ENDOCTRINE", "stem": "prioritize? O A. Prepare for potassium infusion. O B. Obtain a urine sample for urinalysis. O C. Administer regular insulin by sliding scale. O D. Begin infusion of normal saline.", "choices": [{"id": "a", "t": "Prepare for potassium infusion."}, {"id": "b", "t": "Obtain a urine sample for urinalysis."}, {"id": "c", "t": "Administer regular insulin by sliding scale."}, {"id": "d", "t": "Begin infusion of normal saline."}], "correct": "d", "rationale": "A The client’s pH and history suggest diabetic ketoacidosis (DKA). This is caused by hyperglycemia and leads to dehydration from the osmotic B : diuresis due to high urine glucose levels. The client should receive 0.9% normal saline to restore tissue perfusion and reduce synthesis and release of stress hormones. C |__| o;", "whyNot": {"a": "Although clients with DKA may have a total body potassium deficit, the initial serum potassium may be normal or high. A potassium", "b": "Although urinalysis is an important part of the evaluation, it is not a priority action.", "c": "Serum glucose levels will fall rapidly with rehydration, so insulin should be initiated after initial volume infusion."}, "keyConcept": "Diabetic ketoacidosis is characterized by hyperglycemia, ketosis, metabolic acidosis, and dehydration. Total body potassium stores are usually depleted as a result of osmotic diuresis from glucosuria. Clinical signs include polyuria, polyphagia, and polydipsia. Signs of dehydration include tenting of skin, dry mucous membranes, and tachycardia. Abdominal pain and vomiting lead to additional potassium loss. Kussmaul respirations refer to rapid deep breathing as the body attempts to achieve acid-base homeostasis by exhalation of carbon dioxide. Fruity breath is characteristic, caused by acetone."}, {"id": 10777, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following measures provides the best assessment of diabetic autonomic neuropathy in a client with type 2 diabetes mellitus?", "choices": [{"id": "a", "t": "Orthostatic blood pressure measurements"}, {"id": "b", "t": "Gait assessment"}, {"id": "c", "t": "Sensory exam of the feet"}, {"id": "d", "t": "Inspection for diabetic ulcers on the feet"}], "correct": "a", "rationale": "eo, ia 26% = Hard 8 | 3% Diabetic neuropathy refers to nerve damage caused by metabolic derangements associated with diabetes mellitus. Sensory neuropathy is © | 60% the most common manifestation of diabetic neuropathy and can lead to loss of protective sensation in the feet that increases the risk of D i 11% injury, infection, and subsequent amputation. Autonomic neuropathy refers to damage to the autonomic nervous system, which controls all involuntary body functions. These functions include heart rate, blood pressure, sexual function, digestion, and perspiration. Clinical evidence of derangements of the autonomic nervous system include postural hypotension, tachycardia, blunted hypoglycemic response, impotence, urinary retention, bowel incontinence, and diarrhea. Orthostatic blood pressure movements are taken in the supine and standing positions. A drop of at least 20 mmhg systolic blood pressure or at least 10 mmHg diastolic blood pressure with standing is diagnostic of postural hypotension. 2 = ® 4 z = a iat g <", "whyNot": {"b": "Diabetic sensory neuropathy affects gait due to loss of sensation in the foot. Loss of proprioceptive sensation is often an early sign of", "c": "Asensory exam of the foot does not assess the autonomic nervous system.", "d": "Loss of sensation in the feet increases the risk of diabetic ulcers due to sensory neuropathy, not autonomic neuropathy."}, "keyConcept": "Diabetic neuropathy occurs in up to 70% of individuals with diabetes mellitus, occurring equally in type 1 diabetes and type 2 diabetes. Although multiple mechanisms of injury have been proposed, most experts believe that nerve damage results from accumulation of sorbitol and fructose in the nerves during periods of hyperglycemia. Microvascular damage also contributes to diabetic neuropathy. Characteristics include reduced nerve conduction, demyelinization, and ischemia due to vascular damage."}, {"id": 10778, "cat": "NCLEX 15- ENDOCTRINE", "stem": "should explain that the length of the fertility period surrounding ovulation lasts for which of the following periods of time?", "choices": [{"id": "a", "t": "12 hours before and 24 hours after ovulation"}, {"id": "b", "t": "72 hours before and 24 hours after ovulation"}, {"id": "c", "t": "72 to 80 hours before and 72 hours after ovulation"}, {"id": "d", "t": "24 to 48 hours before and 48 hours after ovulation"}], "correct": "b", "rationale": "| 14% Hard The ovum is fertilizable for 12 to 24 hours and sperm remain mobile for about 72 hours. Therefore, the period of fertility is a total of 96 hours, es a 30% 72 hours before ovulation and 24 hours after ovulation. ci 15%", "whyNot": {"a": "The ovum can be fertilized for longer than 12 hours before ovulation.", "c": "The ovum can be fertilized for 72 hours before ovulation and up to 24 hours after ovulation.", "d": "The ovum can be fertilized for longer than 48 hours before ovulation and for only 24 hours after ovulation."}, "keyConcept": "The basal body temperature method of contraception or family planning is a type of natural family planning. The basal body temperature is the temperature when the woman is fully at rest. Ovulation may cause a slight increase in basal body temperature. The woman should take her body temperature at the same time each morning before she gets out of bed and before eating. The temperature should be recorded on a graph. When the temperature rises slightly (0.2° to 0.5°C (0.4° to 1.0°F) just after ovulation, the couple should avoid vaginal sex, or use condoms or a diaphragm. 2 (S g o 5 x < The couple can have unprotected sex on the 4th day and until the next menstrual period begins. > Fee OOS #3 00 zz © Recruited Maturing Ovulation Corpus Degenerate Follicle Follicle Luteum —C. Luteum 37°C. ate Vann 36°C Luteinizing Homone (LH) Progesterone Pa Fs 8 E & Follicle-Stimulating Hormone (FSH) Follicular Phase i Luteal Phase Menstruation @> 22 es iH"}, {"id": 10779, "cat": "NCLEX 15- ENDOCTRINE", "stem": "hypertension, hyperthermia and a tachyarrhythmia. What life-threatening disorder is this client most likely affected with?", "choices": [{"id": "a", "t": "Diabetic ketoacidosis"}, {"id": "b", "t": "Hypoglycemia"}, {"id": "c", "t": "Thyroid storm"}, {"id": "d", "t": "Cushing’s reflex"}], "correct": "c", "rationale": "all 8% Easy This client is most likely affected with thyroid storm, a potentially life-threatening event with a high rate of mortality. The signs and , or thyroid crisis, are chest pain, dyspnea, hypertension, hyperthermia, and tachyarrhythmias, among other signs and symptoms. Some of the disorders that can precipitate thyroid storm in clients with hyperthyroidism include infection, such as a urinary O€ PF 85%) tract infection, trauma, emotional stress, and digoxin toxicity.", "whyNot": {"a": "Diabetic ketoacidosis would cause an extremely elevated glucose level; this client’s level is only 145 mg/dL.", "b": "Hypoglycemia would cause a low blood glucose level; this client’s level is 145 mg/dL.", "d": "These symptoms are not indications of Cushing’s reflex."}, "keyConcept": "Thyroid storm is an extreme degree of hyperthyroidism that occurs in individuals with untreated or undertreated hyperthyroidism. Clinical manifestations of thyroid storm include tachycardia, palpitations; extremely high body temperature, chest pain, shortness of breath, anxiety, 2 = ® 4 z = a iat g < irritability, disorientation, diaphoresis, weakness, and heart failure. Extremely high body temperature differentiates thyroid storm from simple hyperthyroidism. Body temperatures rise as high as 105 F -106F (40.5-41.1 C)."}, {"id": 10780, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is teaching the parent of a child who has growth hormone deficiency. Which of the following statements should the nurse make? O A.\"This disorder will not affect your child's ability to gain weight.\" O B. \"Your child will experience a decrease in insulin sensitivity.\" O C. \"Your child will experience excessive bone growth.\" O D. \"This disorder may cause your child to appear older than their actual age.\"", "choices": [{"id": "a", "t": "Growth hormone deficiency affects overall skeletal growth."}, {"id": "b", "t": "Children who have growth hormone deficiency will have an increased sensitivity to insulin because of the effects on the pituitary gland."}, {"id": "c", "t": "Children who have growth hormone deficiency experience decreased bone growth in relation to their height."}, {"id": "d", "t": "Children who have growth hormone deficiency typically appear younger than their chronological age. However, later in life individuals"}], "correct": "a", "rationale": "Growth hormone deficiency affects overall skeletal growth. Children with this disorder are able to gain weight in a typical pattern. This manifestation can provide clues as to the cause of a child's short stature.", "whyNot": {"b": "Children who have growth hormone deficiency will have an increased sensitivity to insulin because of the effects on the pituitary gland.", "c": "Children who have growth hormone deficiency experience decreased bone growth in relation to their height.", "d": "Children who have growth hormone deficiency typically appear younger than their chronological age. However, later in life individuals"}, "keyConcept": "Growth hormone, also known as somatotropin, is responsible for growth and development. A deficiency of growth hormone can cause improper growth in the child. This condition can be caused by pituitary tumors. Initially, the child's stature appears proportional but eventually falls below standards on the growth curve. The provider and other health care professionals should recognize this condition early and evaluate. Growth and development records can identify the alterations in expected growth for age. Manifestations of this condition include a delay in the epiphyseal bone closure and increased sensitivity to insulin. Treatment involves the administration of growth hormones."}, {"id": 10781, "cat": "NCLEX 15- ENDOCTRINE", "stem": "and I’m tired of people asking me about it!” How should the nurse respond?", "choices": [{"id": "a", "t": "“It’s important for you to realize that carbohydrates can increase your blood glucose, which will cause additional health problems over time.”"}, {"id": "b", "t": "“You seem very angry. Can you tell me why you are feeling so upset?”"}, {"id": "c", "t": "“Your healthcare provider must have this information to advise you on how to control your diabetes.”"}, {"id": "d", "t": "“Don’t be angry. You don’t have to tell me what you eat.”"}], "correct": "b", "rationale": "Nm | 16% Easy The client may be angry about the condition and having to make accommodations for the condition, or the client may be upset about the © | 2% effects the condition has had on health, particularly if they are progressive or irreversible. The nurse’s priority is to allow the client to express D angry feelings and underlying concerns and to provide empathy and support. An open-ended question will allow the client to express anger, which will provide an opportunity to de-escalate and help the client cope with the frustrations. The nurse also acknowledges the client’s anger by a reflective statement. 0%", "whyNot": {"a": "This is not a therapeutic response and seems dismissive. The nurse is giving advice but fails to acknowledge or explore the client’s s", "c": "This response does not address the client’s anger or concerns and does not show acceptance or empathy.", "d": "This response may deescalate the client’s anger but does not acknowledge or explore the client’s anger or help to address the client’s"}, "keyConcept": "Clients who are faced with life changes or behavior modifications as a result of a health condition may be upset about the condition or reluctant to make significant changes. The nurse should understand that angry responses may reflect fear and concern and should provide acceptance and encouragement for the client, which establishes trust and provides a therapeutic environment in which the client can express fears and feelings, including anger."}, {"id": 10782, "cat": "NCLEX 15- ENDOCTRINE", "stem": "hormones from the anterior pituitary gland?", "choices": [{"id": "a", "t": "Prolactin"}, {"id": "b", "t": "Oxytocin"}, {"id": "c", "t": "Estrogen"}, {"id": "d", "t": "Progesterone"}], "correct": "a", "rationale": "Prolactin stimulates secretion of milk from the breasts. 3m 17%", "whyNot": {"b": "Oxytocin is released from the posterior pituitary. It causes uterine contractions and the let-down reflex.", "c": "Estrogen is not a pituitary hormone.", "d": "Progesterone is not a pituitary hormone."}, "keyConcept": "The two hormones that control milk production are prolactin and oxytocin. Prolactin is secreted by the anterior pituitary gland. When the baby sucks at the breasts, the pituitary gland is signaled to release prolactin into the bloodstream. The prolactin then stimulates the milk glands to secrete milk. The more a baby sucks, the more milk the breasts produce. To increase the milk supply, the mother should have the baby suck longer and more frequently. ‘Supporting tissue 4 NS on Duet Muscle colls— oxytocin makes them [>| contract Gland celts— prolactin makes them secrete"}, {"id": 10783, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who has returned to the unit after subtotal thyroidectomy. Which of the following does the nurse know to monitor for signs of laryngeal nerve damage?", "choices": [{"id": "a", "t": "Tetany"}, {"id": "b", "t": "Hoarseness"}, {"id": "c", "t": "Tachypnea"}, {"id": "d", "t": "Facial paralysis"}], "correct": "b", "rationale": "A | | % Moderate The laryngeal nerve controls function of the intrinsic muscles of the larynx. Damage to the laryngeal nerve can occur as a result of es rd 78% endotracheal intubation, viral infection, tumors in the neck or chest, neurological disorders, or as a complication of neck or chest surgery. The right nerve is at greater risk of damage in thyroid surgery because of its position near the right inferior thyroid artery. Symptoms include € l Sh difficulties with swallowing and speaking and hoarseness. Laryngoscopy is used to confirm damage to the nerve. D || 12% 2 = © 4 z = a fant g <", "whyNot": {"a": "Tetany is caused by hypocalcemia and can be the result of removal of the parathyroid glands.", "c": "The rate of breathing is not affected by damage to the laryngeal nerve.", "d": "The laryngeal nerve does not innervate the facial muscles."}, "keyConcept": "Damage to the laryngeal nerve may occur during surgery of the head and neck and during intubation. Symptoms include hoarseness and difficulty with swallowing and speaking."}, {"id": 10784, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following clients should receive follow-up education from the nurse?", "choices": [{"id": "a", "t": "A client with frequent urinary tract infections who has increased her water intake"}, {"id": "b", "t": "A client with severe congestive heart failure who sleeps in a recliner"}, {"id": "c", "t": "A diabetic client with neuropathy who walks barefoot outside and inside"}, {"id": "d", "t": "A client with irritable bowel syndrome who intends to decrease consumption of cabbage and broccoli"}], "correct": "c", "rationale": "a| 1% Easy , potentially resulting in ec fF 95% infection. The risk of diabetic foot infection is increased as a result of failure to notice injury and because clients with diabetes have impaired , which impedes wound healing. Poor perfusion results from atherosclerosis and damage to blood vessels from hyperglycemia. Instructions to a diabetic client should include recommendations to wear well-fitting shoes and avoid walking barefoot.", "whyNot": {"a": "Increased water intake will flush the bladder and reduce urinary stasis, reducing the risk of UTI.", "b": "A client with severe congestive heart failure may need to maintain elevation of the upper body since lying flat can exacerbate shortness of", "d": "Dietary recommendations for clients with irritable bowel syndrome include avoidance of problem foods (e.g. caffeinated beverages,"}, "keyConcept": "Diabetic neuropathy frequently affects the lower extremities. Chronic hyperglycemia results in deposits of fructose and sorbitol in nerve tissue. Clients with diabetes should wear shoes in and outside of the house and inspect their feet regularly. Diabetes causes microvascular damage and facilitates atherosclerosis. These conditions reduce perfusion and result in impaired wound healing."}, {"id": 10785, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse prepares to administer medications at the onset of her shift. Which of the following is the priority for the nurse to administer?", "choices": [{"id": "a", "t": "Furosemide for a client with a potassium level of 3.0"}, {"id": "b", "t": "Pre-prandial regular insulin for a client who has just received a breakfast tray"}, {"id": "c", "t": "Magnesium citrate solution for a client who has not had a bowel movement in 2 days"}, {"id": "d", "t": "Aspirin 81 mg for a client with a history of coronary artery disease"}], "correct": "b", "rationale": "Pre-prandial insulin (regular or fast acting) should be administered to the client before they consume their meal. Pre-prandial insulin is usually ordered as “q AC” (before each meal). It may be ordered on a sliding scale protocol, in which case the nurse should assess the client’s fingerstick glucose reading and administered the ordered amount of insulin before the client eats.", "whyNot": {"a": "Furosemide is a loop diuretic and can result in hypokalemia. A normal potassium level is 3.5-5.0 mEq/L, so this client already has a low", "c": "Magnesium citrate can be given as a laxative, but this is not the immediate priority.", "d": "Most clients with coronary artery disease take low dose aspirin as a form of secondary prevention. This is not a priority for the"}, "keyConcept": "Insulin replacement therapy mimics the physiologic delivery of insulin to achieve glycemic control in clients with diabetes. People without diabetes secrete insulin in two basic patterns, background and prandial. Prandial insulin is secreted proportional to the glucose rise that results from food ingestion. It is necessary for uptake of glucose into cells and suppresses glucose production and lipolysis. Preprandial insulin should be administered before meals are served."}, {"id": 10786, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is administering prescribed vasopressin to a client with diabetes insipidus. The nurse will monitor the client for which of the following adverse effects?", "choices": [{"id": "a", "t": "Rash"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Chest pain"}, {"id": "d", "t": "Sore throat"}], "correct": "c", "rationale": "All off Vasopressin (Pitressin) is used to treat central diabetes insipidus and gastrointestinal hemorrhage from esophageal varices. It is an analog of ec PF antidiuretic hormone and causes vasoconstriction and reabsorption of water in the collection duct of the kidney. Adverse effects include D I hypertension, myocardial infarction, TIA, stroke, bowel ischemia, and dysrhythmia. The nurse should monitor the client for signs of toxicity, which include angina (chest pain). Pitressin is contraindicated in ischemic heart disease and is not indicated in clients with nephrogenic diabetes insipidus. Alcohol, lithium, phenytoin, and epinephrine may increase the effects of vasopressin.", "whyNot": {"a": "Arash is not a typical adverse effect of vasopressin.", "b": "Diarrhea is not a common adverse effect, nausea is though.", "d": "Asore throat is not an adverse effect associated with vasopressin."}, "keyConcept": "Vasopressin (Pitressin) is a synthetic analog of antidiuretic hormone, which is released by the posterior pituitary gland. Vasopressin is used to treat GI hemorrhage from esophageal varices and central diabetes insipidus. Adverse effects include hypertension, myocardial infarction, TIA, stroke, bowel ischemia, and cardiac arrhythmias."}, {"id": 10787, "cat": "NCLEX 15- ENDOCTRINE", "stem": "deciliter (mg/dL). Further information can be obtained by clicking on the exhibit link to the right. Which of the following is the most appropriate action by the nurse?", "choices": [{"id": "a", "t": "Administer 15 units of NPH now and 9 units of regular insulin after breakfast"}, {"id": "b", "t": "Administer NPH and regular insulin in the same syringe, drawing NPH first"}, {"id": "c", "t": "Administer NPH and regular insulin in same syringe, drawing regular first"}, {"id": "d", "t": "Administer the two insulin doses in separate injections"}], "correct": "c", "rationale": "A Regular insulin and rapid-acting insulin, including lispro and aspart, can be mixed safely in the same syringe with NPH insulin, which is an B HS intermediate-acting insulin. Since regular insulin is drawn from a multi-use vial, it should be drawn first to avoid contamination of the vial. NPH insulin is then drawn into the same syringe. o is of Although two syringes can be used, that would require two injections and additional client discomfort, so it is preferable to mix the two in the same syringe. The MAR indicates that 15 units of NPH insulin should be given at 0700, and the sliding scale indicates that this client, who has a blood glucose level of 280 mg/dL, should receive 9 units of regular insulin before breakfast. To prepare the dose, the nurse should inject 15 units of air into the vial of NPH insulin. It is important to avoid inverting the vial or allowing the needle to pass into the insulin solution. Nine units should be injected into the regular insulin vial, and the dose should be withdrawn without leaving air bubbles. Next, 15 units of NPH insulin should be withdrawn into the syringe. There should be a total of 24 units of insulin in the syringe. It is important to avoid overdrawing the NPH insulin, because the entire syringe will have to be wasted.", "whyNot": {"a": "“AC” refers to the Latin abbreviation used to indicate a medication given “before meals.”", "b": "Regular insulin in a multidose syringe may be contaminated if the NPH insulin is drawn up initially.", "d": "This is not the best option, as two separate injections will cause additional client discomfort."}, "keyConcept": "Regular (R) insulin is short-acting insulin, with an onset of action of 30 min -1 hour, and peak action at 2-5 hours after administration. Regular insulin provides coverage for meals consumed within 30-60 minutes after administration and has a duration of action of 5-8 hours. Intermediate-acting insulin (NPH (N) and lente (L) insulin) has an onset of action of 1-2 hours, with peak levels 3-12 hours after administration and duration of action of 18-24 hours. it provides coverage for up to half a day or overnight. Mixed insulins combinations should be reviewed prior to administration."}, {"id": 10788, "cat": "NCLEX 15- ENDOCTRINE", "stem": "@ @ & Viral ne «<> ¢G Sa Record ™ Inbox ( student.atitesting.com/LT| ™ Inbox - ) untitle: Untitle (4 Google @ TEASF Online & MarkkK @ Micros eae me ier @ Atite = @G@ Newel Qa * s * O Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE a Poa ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ {Search Questions [2 )", "choices": [{"id": "a", "t": "Do nothing; this is common practice"}, {"id": "b", "t": "Call the physician to obtain an order for insulin"}, {"id": "c", "t": "Obtain a bedside glucose level"}, {"id": "d", "t": "Give the client's usual morning insulin dose"}], "correct": "c", "rationale": "al 5% Easy The nurse should first obtain a bedside glucose level. Insulin and hypoglycemic medications often require adjustment when an individual is . If the surgeon has not provided instructions, the nurse should clarify the surgeon's intention.", "whyNot": {"a": "The nurse should NOT assume that the lack of an insulin order was intentional, so it would be inappropriate to do nothing.", "b": "The nurse should obtain a current blood glucose level before calling the surgeon. With this asessment data, a decision can be made about", "d": "Without a specific insulin order, the nurse should NOT assume that the client should receive his usual morning insulin dose. Since the"}, "keyConcept": "Blood glucose levels are affected by pre-operative NPO status, surgical stress, and anesthesia. Surgical procedures may result in a number of metabolic changes and alterations in normal glucose homeostasis. Hyperglycemia due to abnormal glucose balance may develop and it is a risk factor for postoperative sepsis, endothelial dysfunction], cerebral ischemia, and impaired wound healing. A stress response due to surgery may also cause diabetic ketoacidosis (DKA) or hyperglycemic hyperosmolar syndrome during surgery or in the post-operative period. 2 = © 4 z = a fant g <"}, {"id": 10789, "cat": "NCLEX 15- ENDOCTRINE", "stem": "ketoacidosis in this client? O A. Bradypnea O B. Hyperthermia O C. Kussmaul respirations O D. Decreased urine output", "choices": [{"id": "a", "t": "Bradypnea"}, {"id": "b", "t": "Hyperthermia"}, {"id": "c", "t": "Kussmaul respirations"}, {"id": "d", "t": "Decreased urine output"}], "correct": "c", "rationale": "A 3% Easy Diabetic ketoacidosis (DKA) is a complication of diabetes mellitus that can be life-threatening when untreated. It is caused by the breakdown B 3% of fats into ketones for energy metabolism in the absence of insulin, which is necessary for uptake of glucose by cells. DKA is characterized by hyperglycemia, ketosis, and acidosis. ec fF 86% of 7% Diabetic ketoacidosis usually occurs in clients with Type 1 diabetes mellitus. It can be precipitated by any condition that increases carbohydrate metabolism, including infection, trauma, surgery, and other stressors. Increased production of stress hormones, including glucagon, epinephrine, and cortisol, cause the liver to produce glucose and antagonize the effects of insulin. Clinical manifestations associated with DKA include polyuria, polydipsia, and polyphagia. Gastrointestinal effects include nausea, vomiting, and abdominal pain. Blurred vision and headaches may occur as a result of osmotic diuresis in diabetic ketoacidosis. Clients may develop a fruity odor to the breath resulting from production of ketone bodies. Kussmaul respirations refer to rapid, deep respirations that occur in response to metabolic acidosis, as the body tries to increase the excretion of carbon dioxide. 2 = ® 4 z = a iat g <", "whyNot": {"a": "The respiratory rate increases in an attempt to compensate for metabolic acidosis by excreting carbon dioxide.", "b": "FALSE: Fever can result from infection but is not a typical sign of diabetic ketoacidosis.", "d": "FALSE: Polyuria occurs in diabetic ketoacidosis as a result of osmotic diuresis due to increased osmotic pressure from elevated glucose."}, "keyConcept": "Clinical manifestations of diabetic ketoacidosis include polydipsia, polyuria, fruity breath, Kussmaul respirations, nausea, vomiting, and abdominal pain. Kussmaul respirations are rapid, deep respirations that result from the body's attempt to increase ventilation to reduce levels of CO2. The fruity breath characteristic of DKA results from breakdown of fats into ketone bodies."}, {"id": 10790, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who has abruptly discontinued use of exogenous steroids. Which of the following does the nurse expect to find on assessment? O A.Acne O B. Hypertension O C. Hyperglycemia O D. Hypocortisolism", "choices": [{"id": "a", "t": "This is a symptom of excess glucocorticoid levels and may occur in the use of exogenous steroids."}, {"id": "b", "t": "Addisonian crisis results in hypotension."}, {"id": "c", "t": "Addisonian crisis results in hypoglycemia."}, {"id": "d", "t": "Abrupt discontinuation of a glucocorticoid medication can result in an adrenal crisis that is caused by hypocortisolism."}], "correct": "d", "rationale": "Abrupt discontinuation of a glucocorticoid medication can result in an adrenal crisis that is caused by hypocortisolism. Use of exogenous corticosteroids disrupts the feedback mechanism between the adrenal gland and the pituitary and hypothalamus. As a result, the release of ACTH (adrenocorticotropic hormone) by the pituitary gland is inhibited and the adrenal gland may not respond to sudden withdrawal of exogenous glucocorticoids with the production of cortisol, causing hypotension, syncope, shock, abdominal pain, nausea, vomiting, hyponatremia, hypoglycemia, and hyperkalemia.", "whyNot": {"a": "This is a symptom of excess glucocorticoid levels and may occur in the use of exogenous steroids.", "b": "Addisonian crisis results in hypotension.", "c": "Addisonian crisis results in hypoglycemia."}, "keyConcept": "Use of high doses of glucocorticoid medication for several days or low doses over more than a few weeks suppresses the feedback loop between the hypothalamus, pituitary gland, and adrenal glands. Steroids should be tapered, since abrupt discontinuation can result in an adrenal crisis."}, {"id": 10791, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a 65-year-old female client with a new prescription for calcium supplements. Which of the following should the nurse advise the client supplement to maximize calcium absorption? O AVitaminc © >B.Vitamin D O c.vitamin B12 © D.Vitamin A", "choices": [{"id": "a", "t": "Vitamin C is necessary for collagen production, which contributes to the repair and maintenance of bones. However, it does not play a"}, {"id": "b", "t": "Osteoporosis affects 9 million individuals in the United States, primarily women."}, {"id": "c", "t": "Calcium is necessary for the uptake of vitamin B12 and intrinsic factor in the small intestine, but B12 does not influence calcium"}, {"id": "d", "t": "Vitamin A does not increase the absorption of calcium from the Gl tract."}], "correct": "b", "rationale": "Osteoporosis affects 9 million individuals in the United States, primarily women. More than half of all women over the age of 50 will break a bone during their lifetime as a result of osteoporosis. This is primarily due to decreases in estrogen. Estrogen stimulates the release of calcitonin and activation of vitamin D (1,25(OH)2D) receptors in the gut, necessary for absorption of calcium. Post-menopausal women and men over the age of 70 should take 800 to 1,000 IU units of supplemental vitamin D daily in addition to calcium supplementation. Fortified milk is the most readily available source of dietary vitamin D, containing approximately 100 IU vitamin D in an 8-ounce serving. Vitamin D concentrations are increased by exposure to sunlight but use of sunscreen blocks synthesis of vitamin D. Multivitamins usually contain 400 IU units of vitamin D, which is not adequate for prevention of osteoporosis.", "whyNot": {"a": "Vitamin C is necessary for collagen production, which contributes to the repair and maintenance of bones. However, it does not play a", "c": "Calcium is necessary for the uptake of vitamin B12 and intrinsic factor in the small intestine, but B12 does not influence calcium", "d": "Vitamin A does not increase the absorption of calcium from the Gl tract."}, "keyConcept": "Osteoporosis and subsequent fracture occur in over 50% of women over the age of 50, largely because estrogen levels decrease. Estrogen facilitates absorption of calcium from the intestine by stimulating the release of calcitonin and activation of vitamin D receptors in the gut, In the absence of estrogen, postmenopausal women and men over the age of 70 should take 800 to 1000 IU of supplemental Vitamin D daily, to facilitate absorption of calcium from dietary sources and supplements."}, {"id": 10792, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is providing teaching to a client who has developed diabetes insipidus following a head injury. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| should limit my fluid intake to 32 ounces of water daily.\" O B. \"Iwill have to use insulin to control my blood glucose levels as a result of this condition.\" O C.\"I should expect to gain weight as a result of this condition.\" O D. \"This condition causes excess urination and increased thirst.\"", "choices": [{"id": "a", "t": "Excessive thirst is a manifestation of diabetes insipidus because of excessive diuresis and subsequent increase in serum sodium."}, {"id": "b", "t": "Elevated blood glucose levels are a manifestation of diabetes mellitus. Diabetes insipidus does not affect blood glucose levels."}, {"id": "c", "t": "Weight loss is a manifestation of diabetes insipidus because the body loses large amounts of fluid through polyuria."}, {"id": "d", "t": "Polyuria, nocturia, and polydipsia are characteristics of diabetes insipidus."}], "correct": "d", "rationale": "Polyuria, nocturia, and polydipsia are characteristics of diabetes insipidus. Sodium levels are elevated, resulting in excessive thirst. Urine is dilute.", "whyNot": {"a": "Excessive thirst is a manifestation of diabetes insipidus because of excessive diuresis and subsequent increase in serum sodium.", "b": "Elevated blood glucose levels are a manifestation of diabetes mellitus. Diabetes insipidus does not affect blood glucose levels.", "c": "Weight loss is a manifestation of diabetes insipidus because the body loses large amounts of fluid through polyuria."}, "keyConcept": "Diabetes insipidus (DI) is an endocrine disorder that results in decreased production of antidiuretic hormone (ADH) in the posterior pituitary gland (central Dl) or impaired response to ADH in the kidney (nephrogenic D!). Laboratory values indicative of central DI include low levels of serum ADH, hypernatremia, and increased plasma osmolarity due to the increased loss of body fluid through excessive urination. Urinalysis will reveal decreased osmolarity and specific gravity for a client who has DI. Urine volume ranges from 4 to 30 L/day, leading to a risk of hypovolemia. Clinical signs are polyuria, nocturia, and polydipsia. The nurse should monitor the client for manifestations of dehydration, including muscle weakness, weight loss, extreme thirst, headache, constipation, and dizziness. Clients should be encouraged to consume fluids in volume equal to their urine output."}, {"id": 10793, "cat": "NCLEX 15- ENDOCTRINE", "stem": "prescribed for intravenous treatment?", "choices": [{"id": "a", "t": "Insulin Aspart (Novolog) © B. Insulin NPH"}, {"id": "c", "t": "Insulin glargine (Lantus) © b.Humulink"}, {"id": "d", "t": "Humulin R is used when treating a client with diabetic ketoacidosis."}], "correct": "d", "rationale": "Humulin R is used when treating a client with diabetic ketoacidosis. It is the only type of insulin that should be used intravenously for treatment of severe diabetic ketoacidosis. The initial infusion should begin at 0.1 units/kg/hour. Regular insulin is used subcutaneously for general dosing of regular diabetes and can be given as multiple daily doses or a continuous subcutaneous infusion.", "whyNot": {"a": "Aspart or Novolog is a very rapidly acting insulin that is normally given before a meal and injected subcutaneously.", "c": "Insulin glargine is a long-acting insulin that is administered by subcutaneous injection."}, "keyConcept": "When treating diabetic ketoacidosis, an IV insulin infusion is initiated with regular insulin, which is the only type of insulin given IV. The infusion is usually titrated to the client's blood glucose, which is monitored hourly. Rapid reduction of blood glucose can result in cerebral edema, so must be avoided. Insulin also causes potassium to move back into the cells, so potassium levels must be monitored closely, with supplementation added to IV fluid replacement when the client has a potassium level of 3.3 mEq/L or lower."}, {"id": 10794, "cat": "NCLEX 15- ENDOCTRINE", "stem": "concerning? O A. Potassium level of 4.8 mEq/L O B. BUN of 16 mg/dL and creatinine of 0.8 mg/dL O C. Changes in T waves on the cardiac monitor O D. Heart rate of 115/minute", "choices": [{"id": "a", "t": "Potassium level of 4.8 mEq/L"}, {"id": "b", "t": "BUN of 16 mg/dL and creatinine of 0.8 mg/dL"}, {"id": "c", "t": "Changes in T waves on the cardiac monitor"}, {"id": "d", "t": "Heart rate of 115/minute"}], "correct": "c", "rationale": "Correct Answer: C. Changes in T waves on the cardiac monitor A ' B Diabetic ketoacidosis occurs as a result of untreated hyperglycemia in both type 1 and type 2 diabetes mellitus. In clients with insulin ec | SY deficiency, cellular uptake of insulin is reduced and the liver continues to make glucose from amino acids, a process known as D i gluconeogenesis. This continues to elevate blood glucose levels. Insulin is also necessary for cellular uptake of potassium, so insulin deficiency increases the serum level of potassium Blood is filtered through the kidney and glucosuria results, causing osmotic diuresis, with contraction of blood volume and further increases in serum glucose levels. There is also a whole body loss of hydrogen ions, potassium, and other electrolytes through diuresis.Loss of hydrogen ions causes metabolic acidosis. Serum potassium levels in DKA are often normal or factitiously elevated, when there is an actual potassium deficit. Fluctuations in serum potassium levels affect the myocardial cells and can result in arrhythmias. Changes in the T wave on the cardiac monitor can indicate hypokalemia or hyperkalemia. Peaked T waves occur with hyperkalemia, but flattening of the T wave and lengthening of the QT interval indicate low serum potassium. Potassium levels can change with an insulin infusion in clients with diabetic ketoacidosis (DKA), as insulin drives potassium into cells. Because of whole body potassium depletion, potassium supplementation is normally needed when the client is normokalemic and voiding. A change in T waves is significant for possible shifts in potassium during therapy.", "whyNot": {"a": "Diabetic ketoacidosis results from hyperglycemia that causes osmotic diuresis. clients become volume depleted and have depletion of", "b": "Dehydration characterizes DKA. clients experience osmotic diuresis due to glycosuria.", "d": "Children have heart rate changes in response to physiological stressors. In this case, dehydration and DKA would be expected to increase"}, "keyConcept": "Although there is whole body potassium depletion in clients with DKA, potassium levels may be normal or elevated on presentation, since insulin is required for cellular uptake of potassium. Abnormalities in serum potassium levels in clients with DKA may result in changes in the T wave on ECG. Hypokalemia is characterized on ECG by flattening of T waves. Hyperkalemia is characterized by peaked T waves."}, {"id": 10795, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse knows that which of the following is most likely to be associated with central diabetes insipidus?", "choices": [{"id": "a", "t": "Pancreas O B.Kidney"}, {"id": "c", "t": "Anterior pituitary gland"}, {"id": "d", "t": "Posterior pituitary gland"}], "correct": "d", "rationale": "All 11% Hard 3 14% The posterior pituitary secretes antidiuretic hormone and oxytocin. Central diabetes insipidus occurs with inadequate production or release © || 27% of antidiuretic hormone by the posterior pituitary gland, which stores and release oxytocin and ADH. @pD fe 48%", "whyNot": {"a": "The pancreas is a mixed endocrine and exocrine gland. It is associated with diabetes mellitus, which is due to inadequate production of", "c": "The anterior pituitary gland produces, stores, and releases prolactin, the gonadotropins LH and FSH, growth hormone, thyroid releasing"}, "keyConcept": "There are two types of diabetes insipidus, a rare disorder that prevents the kidney from concentrating urine. Central diabetes insipidus refers to inadequate production or release of antidiuretic hormone by the pituitary gland. Nephrogenic diabetes insipidus refers to resistance of the kidney to antidiuretic hormone. Both result in large amounts of dilute urine and symptoms of increased thirst despite drinking large amounts of water."}, {"id": 10796, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following lifestyle factors may have the largest impact on the development of foot wounds in a diabetic?", "choices": [{"id": "a", "t": "Caffeine intake"}, {"id": "b", "t": "Smoking"}, {"id": "c", "t": "Decreased intake of potassium"}, {"id": "d", "t": "exercise"}], "correct": "b", "rationale": "A client with diabetes is at higher risk of developing poorly healing foot wounds because of impaired circulation to the lower extremities and loss of sensation due to diabetic neuropathy. If the client also smokes, circulation can be further impaired because cigarette smoke reduces the amount of oxygen in the bloodstream and results in peripheral vasoconstriction. This contributes to skin breakdown and poor wound healing.", "whyNot": {"a": "Caffeine intake typically does not affect whether a diabetic client is prone to developing foot wounds.", "c": "Decreased potassium intake does not have an impact on wound development in a client with diabetes.", "d": "Moderate exercise would more likely improve circulation, rather than contribute to wound development in a client with diabetes."}, "keyConcept": "Diabetic foot ulcers result from various factors that occur with greater frequency in clients with diabetes, including include changes in the bony architecture of the foot, peripheral neuropathy, and atherosclerotic peripheral arterial disease. Neuropathy is the largest contributing factor in the development of diabetic foot ulcers, resulting in the loss of protective sensation. Diabetic clients may remain unaware of injuries to the foot, so frequent inspection of the feet is essential."}, {"id": 10797, "cat": "NCLEX 15- ENDOCTRINE", "stem": "You are caring for a female client who would like information about contraceptive methods. Which would be considered an absolute contraindication in considering the use of using oral contraceptives?", "choices": [{"id": "a", "t": "Gallbladder disease"}, {"id": "b", "t": "High cholesterol"}, {"id": "c", "t": "Blood clotting disorders"}, {"id": "d", "t": "Gastroesophageal reflux"}], "correct": "c", "rationale": "Women who take oral contraceptives are at higher risk of developing blood clots. If a woman has a blood clotting disorder, she is at even greater risk of deep vein thrombosis, pulmonary embolism, or stroke.", "whyNot": {"a": "Gallbladder disease is considered a relative contraindication for oral contraceptive use, not an absolute contraindication.", "b": "High cholesterol is considered a relative contraindication for oral contraceptive use, not an absolute contraindication.", "d": "Gastroesophageal reflux is considered a relative contraindication for oral contraceptive use, not an absolute contraindication."}, "keyConcept": "Absolute contraindications to oral contraceptives include thrombophlebitis or thromboembolic disorders; cerebrovascular or coronary artery disease; breast cancer or another estrogen-dependent tumor; undiagnosed abnormal genital bleeding; known or suspected pregnancy; and benign or malignant liver tumors. Smoking increases the risk of thromboembolic disorders in clients who are taking oral contraceptives and is a relative contraindication."}, {"id": 10798, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is discharging a client with rheumatoid arthritis who has a new prescription for prednisone. The nurse knows that which of the following is a side effect of prolonged use?", "choices": [{"id": "a", "t": "Decreased appetite"}, {"id": "b", "t": "Hyperpigmentation"}, {"id": "c", "t": "Weight loss"}, {"id": "d", "t": "Loss of bone mass"}], "correct": "d", "rationale": "al 3% ce | 8% Corticosteroids have a variety of long-term effects, including increased appetite, fluid retention, weight gain, hyperglycemia, truncal obesity, © I 3% acne, hirsutism, easy bruising, and increased risk of infection. Headaches and irritability, cataracts, loss of bone mass (osteoporosis), @ , and potassium loss are also associated with long-term corticosteroid use. Menstrual irregularities may occur. Use of prednisone and other corticosteroids suppresses the hypothalamic-pituitary axis, so the exogenous steroids must be tapered and should not be stopped abruptly or the client may have an adrenal crisis. Hypothalamic pituitary adrenal axis Hypothalamus Adrenal gland Pruitary gland the hypothalamus responds tolevel ‘fcortzo!, toimmune system", "whyNot": {"a": "Increased appetite is a common side effect of long-term use of corticosteroids.", "b": "Hyperpigmentation is associated with Addison’s disease.", "c": "Long-term corticosteroid use causes increased appetite, fluid retention, and weight gain. Truncal obesity is characteristic."}, "keyConcept": "Long-term use of corticosteroid medications results in suppression of the hypothalamic-pituitary-adrenal axis. Long term use of corticosteroids results in increased intraocular pressure, fluid retention, hypertension, psychological effects (aggression, mood swings); weight gain, truncal obesity, and \"buffalo hump\"; cataracts, glucose intolerance, increased risk of infection, osteoporosis, thinning of skin,"}, {"id": 10799, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who has a serum calcium level of 11.8 mg/dL. Which complication is the client at highest risk for?", "choices": [{"id": "a", "t": "Liver disease"}, {"id": "b", "t": "Kidney stones"}, {"id": "c", "t": "Irritable bowel syndrome"}, {"id": "d", "t": "Respiratory distress"}], "correct": "b", "rationale": "A This calcium result is above normal, indicating hypercalcemia. High levels of calcium are associated with an increased risk of kidney stones. es ——", "whyNot": {"a": "This calcium result is high, but liver disease is not a complication associated with hypercalcemia. D I |", "c": "Irritable bowel syndrome is not associated with high levels of serum calcium.", "d": "The client has hypercalcemia, but respiratory distress is not a complication associated with high calcium levels."}, "keyConcept": "Hypercalcemia can be the result of excess intake of calcium (such as supplements or antacids) or altered excretion of calcium (such as in clients with renal failure or those taking thiazide diuretics). Other causes of hypercalcemia include prolonged immobility, glucocorticoid use, hyperthyroidism, hyperparathyroidism, lithium use, dehydration, or malignancy with metastasis to bone."}, {"id": 10800, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is assessing a client with Graves’ disease. Which sign or symptom would the nurse expect to see in a client with long-standing Grave's disease?", "choices": [{"id": "a", "t": "Exophthalmos"}, {"id": "b", "t": "Bradycardia"}, {"id": "c", "t": "Constipation"}, {"id": "d", "t": "Dry, pale skin"}], "correct": "a", "rationale": "Exophthalmos is a characteristic of Grave's disease. It refers to proptosis (bulging of the eyes.) Exophthalmos is associated with autoimmune . Exophthalmos occurs in up to 25% of individuals with Grave's disease. € I Sh of 5%", "whyNot": {"b": "Tachycardia is associated with hyperthyroidism and Grave's disease, not bradycardia.", "c": "Increased GI motility is associated with hyperthyroidism and Graves’ disease, not constipation.", "d": "Moist, warm skin is associated with hyperthyroidism."}, "keyConcept": "Grave's disease is a common cause of hyperthyroidism. It results in formation of autoimmune antibodies to thyroid stimulating hormone receptors, causing increased production of thyroid hormone by the thyroid gland. It is also known as toxic diffuse goiter."}, {"id": 10801, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is assessing a client with Graves’ disease. Which sign or symptom would the nurse expect to see in a client with long-standing Grave's disease?", "choices": [{"id": "a", "t": "Exophthalmos"}, {"id": "b", "t": "Bradycardia"}, {"id": "c", "t": "Constipation"}, {"id": "d", "t": "Dry, pale skin eck Answer"}], "correct": "a", "rationale": "Exophthalmos is a characteristic of Grave's disease. It refers to proptosis (bulging of the eyes.) Exophthalmos is associated with autoimmune . Exophthalmos occurs in up to 25% of individuals with Grave's disease. € I Sh of 5%", "whyNot": {"b": "Tachycardia is associated with hyperthyroidism and Grave's disease, not bradycardia.", "c": "Increased GI motility is associated with hyperthyroidism and Graves’ disease, not constipation.", "d": "Moist, warm skin is associated with hyperthyroidism."}, "keyConcept": "Grave's disease is a common cause of hyperthyroidism. It results in formation of autoimmune antibodies to thyroid stimulating hormone receptors, causing increased production of thyroid hormone by the thyroid gland. It is also known as toxic diffuse goiter."}, {"id": 10802, "cat": "NCLEX 15- ENDOCTRINE", "stem": "lives alone and does not remember taking her medication in the past 4 weeks. She appears lethargic. Which of the following is the appropriate initial nursing action?", "choices": [{"id": "a", "t": "Prepare for endotracheal intubation."}, {"id": "b", "t": "Cover the client with a warming blanket."}, {"id": "c", "t": "Prepare to administer IV levothyroxine."}, {"id": "d", "t": "Send blood to the lab for a serum thyroid panel."}], "correct": "a", "rationale": "This presentation suggests myxedema coma and respiratory depression, which is a complication of severe hypothyroidism. Hypothyroidism B 28% can progress to a coma state, with central depression of the respiratory drive, hypoventilation, and bradycardia. Additionally, in a client with |_| myxedema, the tongue may be swollen, causing airway obstruction. Puffiness of the hands and face, a thickened nose, swollen lips, and an € |_| tS enlarged tongue may occur secondary to non-pitting edema that occurs with abnormal deposition of mucin in the skin and other tissues. D || 12% Airway and ventilation should be prioritized.", "whyNot": {"b": "Supportive measures include the correction of hypothermia and administration of electrolytes and/or glucose as necessary, but the", "c": "Although treatment with levothyroxine (T4) and liothyronine (T3) should be given, airway and ventilation are priorities in this patient.", "d": "Treatment should not be delayed for analysis of laboratory results."}, "keyConcept": "Hypothyroidism results in nonspecific slowing of the body's metabolic processes and function. The degree of severity of symptoms depends upon the severity and duration of thyroid hormone deficiency. Characteristics of hypothyroidism include fatigue, lethargy, and neurocognitive slowing, which may manifest as memory loss, personality change, loss of initiative, or depression. Progression of lethargy and somnolence may result in myxedema coma, which is a medical emergency. Characteristics of myxedema coma include mental status changes, hypothermia, hypoventilation, and hypotension. Treatment includes supportive care and IV replacement of thyroid hormone."}, {"id": 10803, "cat": "NCLEX 15- ENDOCTRINE", "stem": "The infusion rate of total parental nutrition (TPN) is tapered before being discontinued. This is done to prevent which of the following complications?", "choices": [{"id": "a", "t": "Essential fatty acid deficiency"}, {"id": "b", "t": "Dehydration"}, {"id": "c", "t": "Rebound hypoglycemia"}, {"id": "d", "t": "Malnutrition"}], "correct": "c", "rationale": "al 2% Easy When dextrose is abruptly discontinued, rebound hypoglycemia can occur. The nurse should assess the client for symptoms of .", "whyNot": {"a": "The client would most likely not develop essential fatty acid deficiency from tapering TPN.", "b": "The client should be well hydrated and would not necessarily develop dehydration in this situation.", "d": "The TPN has provided nutrition; the client would not likely develop malnutrition if he is well enough to taper the dose."}, "keyConcept": "Tapering of TPN is a common practice. It may not always be necessary to prevent rebound hypoglycemia, but reducing the rate by 50% for an hour or 2 before discontinuation is easy to do and reduces the risk of hypoglycemia. Hypoglycemia after abrupt discontinuation of TPN is a complication that occurs when endogenous insulin levels do not adjust to the sudden withdrawal of dextrose in the TPN solution. Clients with underlying conditions affecting glucose regulation may be more susceptible, but the risk of hypoglycemia is low in clients with stable glucose levels, especially in clients who are receiving another source of carbohydrates. 2 = ® 4 z = a iat g <"}, {"id": 10804, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is preparing discharge education for a client with type 2 diabetes and rheumatoid arthritis with a new prescription for prednisone. Which of the following will the nurse include in teaching?", "choices": [{"id": "a", "t": "Prednisone can be stopped at any time."}, {"id": "b", "t": "Prednisone may cause hypoglycemia."}, {"id": "c", "t": "Prednisone suppresses the inflammatory process but doesn’t cure the disease."}, {"id": "d", "t": "Prednisone protects the client from infection."}], "correct": "c", "rationale": "A| of Prednisone is an anti-inflammatory corticosteroid that suppresses inflammation by decreasing migration of polymorphonuclear leukocytes ec Fs and fibroblasts. It doesn’t cure rheumatoid arthritis or other diseases characterized by inflammation, but it can reduce symptoms. It is D | associated with many side effects, including osteoporosis, glucose intolerance, immune suppression, and weight gain. Chronic use or short- term use of large doses of corticosteroids suppress the pituitary-hypothalamic-adrenal axis, which can result in adrenal crisis if corticosteroids are suddenly stopped.", "whyNot": {"a": "Prednisone suppresses the adrenal-hypothalamic-pituitary axis, so stopping suddenly can precipitate an adrenal crisis. If prednisone has", "b": "Prednisone causes hyperglycemia, so clients with diabetes must carefully monitor glucose levels. It can cause diabetes and Cushing’s", "d": "Prednisone suppresses the immune response and may make the client more susceptible to infection. Prolonged use of prednisone may"}, "keyConcept": "Long term use of corticosteroids or short term use of a large dose can result in suppression of the hypothalamic-pituitary-adrenal axis, causing an adrenal crisis if the medication is stopped suddenly. Side effects include glucose intolerance, osteoporosis, weight gain, and immune suppression. Corticosteroids are used in treatment of many rheumatological disorders. They reduce associated symptoms, but do not provide a cure."}, {"id": 10805, "cat": "NCLEX 15- ENDOCTRINE", "stem": "the following reasons? O A. Prednisone induces the body to stop producing natural steroids and the patient might have a crisis O B. His flare will return O C. He might start bleeding O D. He needs the entire dose of antibiotics to get better", "choices": [{"id": "a", "t": "Prednisone induces the body to stop producing natural steroids and the patient might have a crisis"}, {"id": "b", "t": "His flare will return"}, {"id": "c", "t": "He might start bleeding"}, {"id": "d", "t": "He needs the entire dose of antibiotics to get better"}], "correct": "a", "rationale": "Prednisone and other drugs in the steroid family suppress the normal adrenal-pituitary-hypothalamic feedback loop. When a person takes a high-dose steroid like prednisone, the body normalizes by decreasing the amount of natural cortisol hormone it produces. Negative Feedback Corticotropin Releasing Hormone ACTH Adrenocorticotropic Hormone HPA Axis CORT", "whyNot": {"b": "While this might happen, it is more important to know that he would have a crisis if he stops the medication suddenly.", "c": "The client would not necessarily start bleeding when stopping prednisone.", "d": "Prednisone is not an antibiotic, it is a steroid."}, "keyConcept": "Cortisol is a natural steroid produced in the adrenal glands. As cortisol levels rise, the release of corticotrophin-releasing hormone from the © Newcl EX test automa % CLOSE { Browse Questions ~ it Search Questions Ja)"}, {"id": 10806, "cat": "NCLEX 15- ENDOCTRINE", "stem": "of the following methods of contraception should the nurse suggest for this client?", "choices": [{"id": "a", "t": "Transdermal contraceptive"}, {"id": "b", "t": "Oral contraceptive pill"}, {"id": "c", "t": "Male condom"}, {"id": "d", "t": "Intrauterine device (IUD)"}], "correct": "c", "rationale": "None of the choices given provide the client with protection against sexually transmitted infections (STIs), which is an important consideration for a client who has multiple sexual partners. Additionally, smoking over the age of 35 years is a contraindication to the use of a hormonal contraception. Contraindications include smoking in clients over 35 years of age; a history of coronary artery or cerebrovascular disease, thromboembolic disease, breast cancer, or gallbladder disease; estrogen-dependent tumor; cirrhosis; liver tumor; headaches with focal neurologic symptoms; hypertension; diabetes for more than 20 years; and lactation for <6 weeks’ postpartum.", "whyNot": {"a": "This client has a contraindication to use of a hormonal contraceptive, and a transdermal contraceptive would not offer protection against", "b": "The client has a contraindication (smoking over the age of 35) to an oral contraceptive pill, and it would not offer protection from STIs.", "d": "The IUD would not protect this client from STIs."}, "keyConcept": "When advising clients about contraception, it's important to consider lifestyle risk factors for harmful effects; the coexistent risk of sexually transmitted infections; and plans for conception. Although a male condom does not provide the most effective contraceptive protection, it reduces the risk of transmission of sexually transmitted diseases."}, {"id": 10807, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with type 2 diabetes who takes metformin (Glucophage). The client has a cardiac catheterization scheduled. Which of the following should the nurse advise?", "choices": [{"id": "a", "t": "Limit protein in the diet on the day before the procedure."}, {"id": "b", "t": "Take metformin with water only on the day of the procedure."}, {"id": "c", "t": "Discontinue the medication prior to the procedure."}, {"id": "d", "t": "Continue to take the medication as usual."}], "correct": "c", "rationale": "A| FI Diabetes is associated with increased risk of cardiovascular disease. Cardiac catheterization requires the use of potentially nephrotoxic ec PF contrast, and metformin compounds the risk of acute kidney injury, so it is discontinued a day before the procedure and 2 days after. During D Hi this time, the client is usually placed on sliding scale insulin in order to avoid hypoglycemia as a result of fasting before the procedure.", "whyNot": {"a": "The client will be NPO before the procedure and should resume a normal diet after the procedure.", "b": "Metformin should be stopped a day before the procedure.", "d": "Metformin should be stopped before the procedure, with sliding scale insulin prescribed to avoid renal damage and hypoglycemia"}, "keyConcept": "When a client scheduled for a procedure must be kept NPO, it may be necessary for the prescriber to adjust hypoglycemic medications, including oral hypoglycemics or basal insulin. Metformin is an oral hypoglycemic used in treatment of type 2 diabetes. In addition to the potential for hypoglycemia in a client who is kept NPO, metformin increases the risk of renal injury in clients who are undergoing a diagnostic procedure requiring nephrotoxic contrast."}, {"id": 10808, "cat": "NCLEX 15- ENDOCTRINE", "stem": "The nurse is developing a care plan for a client with hypocalcemia. The client's serum calcium level is below 8.5 mg/dL. Which of the following nursing diagnoses is appropriate?", "choices": [{"id": "a", "t": "Risk for imbalanced fluid volume"}, {"id": "b", "t": "Constipation O Risk for injury"}, {"id": "c", "t": "A Hi 20% Moderate Hypocalcemia produces symptoms that include tetany, laryngospasm, dysrhythmia, paresthesias, and seizures."}, {"id": "d", "t": "Ineffective coping"}], "correct": "c", "rationale": "A Hi 20% Moderate Hypocalcemia produces symptoms that include tetany, laryngospasm, dysrhythmia, paresthesias, and seizures. The nurse caring for a client B 1] 11% with hypocalcemia should develop a care plan that takes these symptoms into account. Risk for injury is an appropriate nursing diagnosis for clients with hypocalcemia due to laryngospasm, dysrhythmia, and seizures. The nurse should implement seizure precautions and O€ | 68%) provide a quiet or non-stimulating environment.", "whyNot": {"a": "Risk for imbalanced fluid volume is not appropriate for hypocalcemia because fluid volume is not affected by low serum levels of calcium.", "b": "Constipation occurs in hypercalcemia and not hypocalcemia.", "d": "Ineffective coping is also an inappropriate diagnosis because there is no indication that the client is distressed or anxious."}, "keyConcept": "Calcium is essential to cell function, nerve transmission, membrane stability, intracellular signaling, coagulation, and bone structure. Treatment of a client with hypocalcemia depends on the cause, severity, presence of symptoms, and the pace of development of hypocalcemia developed. Mild hypocalcemic emergencies are conservatively managed with supportive care and laboratory evaluation. Severe, symptomatic hypocalcemia is treated aggressively as it may result in refractory hypotension, seizures, tetany, or arrhythmias. 2 = ® 4 z = a iat g <"}, {"id": 10809, "cat": "NCLEX 15- ENDOCTRINE", "stem": "An adolescent is to receive radioactive iodine for Graves’ disease. Which statement by the client reflects the need for further teaching? O A.\" plan to socialize on Facebook since | have to keep several feet away from my friends for a few days\" O B. \"Taking radioactive iodine will not affect my ability to have children in the future\" O C. \"The advantage of radioactive iodine is that | will not need medication for my disease\" O D. \"I should try to use a separate bathroom from the rest of my family for a few days\"", "choices": [{"id": "a", "t": "To reduce the risk of exposure to others, clients are advised to avoid public places for at least one day and maintain prudent distance from"}, {"id": "b", "t": "Avoid pregnant women and children for 5 to 11 days. This treatment has not been found to affect long-term fertility."}, {"id": "c", "t": "Most clients will need lifelong thyroid replacement after radioactive iodine."}, {"id": "d", "t": "Clients are taught not to share utensils, food, or towels. Use of a private bathroom is desirable. Clients are instructed to flush the toilet"}], "correct": "c", "rationale": "Most clients will need lifelong thyroid replacement after radioactive iodine.", "whyNot": {"a": "To reduce the risk of exposure to others, clients are advised to avoid public places for at least one day and maintain prudent distance from", "b": "Avoid pregnant women and children for 5 to 11 days. This treatment has not been found to affect long-term fertility.", "d": "Clients are taught not to share utensils, food, or towels. Use of a private bathroom is desirable. Clients are instructed to flush the toilet"}, "keyConcept": "Graves' disease is an autoimmune disease characterized by hyperthyroidism due to circulating autoantibodies, thyroid-stimulating immunoglobulins (TSIs), which bind to and activate thyrotropin receptors, causing the thyroid gland to grow and the thyroid follicles to increase synthesis of thyroid hormone. The most commonly used treatment for Graves disease is radioactive iodine. Thyroid function test results generally improve within 6-8 weeks of therapy, but can be variable. The desired result is hypothyroidism due to destruction of the gland, usually 2-3 months after administration.When clients become hypothyroid, they require lifelong replacement with thyroid hormone. Thyroid system"}, {"id": 10810, "cat": "NCLEX 15- ENDOCTRINE", "stem": "An adolescent is to receive radioactive iodine for Graves’ disease. Which statement by the client reflects the need for further teaching? O A.\" plan to socialize on Facebook since | have to keep several feet away from my friends for a few days\" O B. \"Taking radioactive iodine will not affect my ability to have children in the future\" O C. \"The advantage of radioactive iodine is that | will not need medication for my disease\" O D. \"I should try to use a separate bathroom from the rest of my family for a few days\" eck Answer", "choices": [{"id": "a", "t": "To reduce the risk of exposure to others, clients are advised to avoid public places for at least one day and maintain prudent distance from"}, {"id": "b", "t": "Avoid pregnant women and children for 5 to 11 days. This treatment has not been found to affect long-term fertility."}, {"id": "c", "t": "Most clients will need lifelong thyroid replacement after radioactive iodine."}, {"id": "d", "t": "Clients are taught not to share utensils, food, or towels. Use of a private bathroom is desirable. Clients are instructed to flush the toilet"}], "correct": "c", "rationale": "Most clients will need lifelong thyroid replacement after radioactive iodine.", "whyNot": {"a": "To reduce the risk of exposure to others, clients are advised to avoid public places for at least one day and maintain prudent distance from", "b": "Avoid pregnant women and children for 5 to 11 days. This treatment has not been found to affect long-term fertility.", "d": "Clients are taught not to share utensils, food, or towels. Use of a private bathroom is desirable. Clients are instructed to flush the toilet"}, "keyConcept": "Graves' disease is an autoimmune disease characterized by hyperthyroidism due to circulating autoantibodies, thyroid-stimulating immunoglobulins (TSIs), which bind to and activate thyrotropin receptors, causing the thyroid gland to grow and the thyroid follicles to increase synthesis of thyroid hormone. The most commonly used treatment for Graves disease is radioactive iodine. Thyroid function test results generally improve within 6-8 weeks of therapy, but can be variable. The desired result is hypothyroidism due to destruction of the gland, usually 2-3 months after administration.When clients become hypothyroid, they require lifelong replacement with thyroid hormone. Thyroid system"}, {"id": 10811, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Tachycardia and hyperthermia in a client with Grave’s disease after a subtotal thyroidectomy may indicate which of the following potentially fatal complications?", "choices": [{"id": "a", "t": "Hypokalemia"}, {"id": "b", "t": "Hypothyroidism"}, {"id": "c", "t": "Hypercalcemia"}, {"id": "d", "t": "Thyrotoxicosis"}], "correct": "d", "rationale": "Graves' disease is a syndrome that includes hyperthyroidism, goiter, eye disease, and pretibial or localized myxedema. Hyperthyroidism is © i the most common feature of Graves' disease, caused by autoantibodies to the thyrotropin receptor that activate the receptor, stimulating ep | thyroid hormone synthesis and secretion as well as thyroid growth. Thyroid storm or thyrotoxic storm can result from manipulation of the thyroid gland in a client with Grave's disease. It is potentially fatal, so it is important to monitor the client for symptoms of increased sympathetic output, which include hyperthermia, tachycardia, tremors, nausea, and altered mental status. Cardiac arrhythmias may result from thyrotoxicosis. Medications used to manage this condition include intravenous beta blockers, sodium iodine, propylthiouracil, and corticosteroids.", "whyNot": {"a": "Hypokalemia may occur during periods of hyperthyroidism and results in thyrotoxic periodic paralysis, but it is associated with significant", "b": "Hypothyroidism results in slowed metabolism, including bradycardia and hypothermia.", "c": "Hypocalcemia is likely to occur during thyroid surgery if the parathyroid glands are injured or the blood supply is interrupted."}, "keyConcept": "Grave's disease is an auto-immune disorder that results in stimulation of the thyrotropin receptor in the thyroid gland, stimulating excess production of thyroid hormone. Manipulation of the thyroid gland during thyroidectomy in a client with Grave's disease can result in release of excess thyroid hormone into the blood stream, precipitating thyrotoxic storm. Symptoms include hyperthermia, tachycardia, tremors, nausea, and altered mental status."}, {"id": 10812, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following findings should the nurse report to the healthcare provider after assessing a client with acromegaly in an outpatient setting?", "choices": [{"id": "a", "t": "Fasting blood glucose 130 mg/dL"}, {"id": "b", "t": "Hot flashes"}, {"id": "c", "t": "Headache and visual field loss"}, {"id": "d", "t": "Erectile dysfunction"}], "correct": "c", "rationale": "Eas) Correct Answer: C. Headache and visual field loss @ i Gs Y ce | 4% Acromegaly is an endocrine disorder that results from overproduction of growth hormone, usually as the result of a benign pituitary ec TY 83% adenoma. Clients with acromegaly may experience headaches and visual field defects from the growth of the tumor mass in the pituitary D I 3 gland. When acromegaly occurs in an adult, it causes stimulation of growth of a variety of tissues, including skin, viscera (organs), and bone. Growth hormone excess results in lipolysis and insulin antagonism. Other hormone synthesis in the pituitary gland may be suppressed by growth of a large adenoma, causing reduction of other hormones. This can result in hot flashes, vaginal atrophy, galactorrhea, menstrual dysfunction, erectile dysfunction, decreased facial hair growth in men, and decreased testicular volume. The effects of growth hormone on the thyroid gland, liver, heart, lungs, and kidneys result in other abnormalities. Hypertension, angina, and heart failure are cardiovascular 2 manifestations of acromegaly. Sleep apnea can occur as a result of changes in the soft tissues of the pharynx. 8 & = a fa a", "whyNot": {"a": "Hyperglycemia is a common finding in individuals with acromegaly due to the effects of increased growth hormone on insulin and glucose", "b": "Hot flashes and menstrual irregularities result from reduced synthesis of reproductive hormones in many patients with acromegaly due to", "d": "Erectile dysfunction is a common finding in men with acromegaly due to suppression of male hormones by the growth of a pituitary"}, "keyConcept": "Growth hormone (GH) is an anabolic hormone produced by the anterior pituitary gland. It promotes synthesis of protein and mobilization of glucose and free fatty acid. It also stimulates the liver to produce insulin-like growth factor-1 (somatomedin C.), which stimulates growth of bones and soft tissues and, in a feedback loop, signals the anterior pituitary to reduce synthesis of GH. Benign pituitary adenomas are the most common cause of overproduction of GH. This results in insulin antagonism and increased blood glucose levels. In adults, acromegaly occurs as a result of excess GH."}, {"id": 10813, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with syndrome of inappropriate antidiuretic hormone (SIADH). Which of the following is a common clinical manifestation of this disorder?", "choices": [{"id": "a", "t": "Decreased sodium level"}, {"id": "b", "t": "Increased serum osmolality"}, {"id": "c", "t": "Decreased blood pressure"}, {"id": "d", "t": "Increased urine output"}], "correct": "a", "rationale": "o; A client with SIADH will typically have a low sodium level. This is due to the increase in antidiuretic hormone, which results in retention of B Hi excess water by the kidney. The client will develop hypervolemic hyponatremia as a result of dilution.", "whyNot": {"b": "Typically, serum osmolality will be decreased and NOT increased, as a result of the dilutional effect of excess fluid.", "c": "Water retention might result in increased blood pressure, and not decreased blood pressure.", "d": "Antidiuretic hormone reduces urine output."}, "keyConcept": "The syndrome of inappropriate antidiuretic hormone secretion (SIADH) is characterized by hyponatremia and hypo-osmolality resulting from inappropriate secretion of the antidiuretic hormone arginine vasopressin (AVP) despite a normal or increased plasma volume, resulting in impaired water excretion. Treatment includes water restriction, 3% hypertonic saline (513 mEq/L), administration of loop diuretics with saline; and treatment with vasopressin-2 receptor antagonists such as conivaptan or tolvaptan."}, {"id": 10814, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who is in perimenopause. Which of the following is an example of a long-term change that may develop after menopause?", "choices": [{"id": "a", "t": "Recurrent kidney infections"}, {"id": "b", "t": "Moist skin"}, {"id": "c", "t": "Thicker hair"}, {"id": "d", "t": "Loss of bone tissue"}], "correct": "d", "rationale": "al 2% Easy Women are most likely to lose more bone tissue after menopause, leading to an increased risk of fractures and osteoporosis. Because of this, . I © 2%", "whyNot": {"a": "Recurrent kidney infections are typically not a long-term change that develops after menopause.", "b": "Skin often becomes drier after menopause, not moist.", "c": "Hair often becomes thinner after menopause, not thicker."}, "keyConcept": "Osteoporosis can be prevented by a diet with adequate vitamin D and calcium; regular exercise; avoidance of tobacco and heavy alcohol consumption. Women 65 years of age and higher and younger women with equivalent risk should be screened for osteoporosis using DEXA scanning (dual-energy X-ray absorptiometry) of the hip and lumbar spine."}, {"id": 10815, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is preparing to teach a client who has a new prescription of methylprednisolone for rheumatoid arthritis. Which of the following will the nurse include when instructing this client about the new medication?", "choices": [{"id": "a", "t": "Stop taking the medication when symptoms resolve."}, {"id": "b", "t": "Watch for signs of hypoglycemia."}, {"id": "c", "t": "The risk of infection is reduced with glucocorticoid medications."}, {"id": "d", "t": "Do not discontinue the medication suddenly."}], "correct": "d", "rationale": "a| 1% Easy cy 6% Long-term glucocorticoid therapy suppresses the hypothalamic pituitary adrenal axis and the production of endogenous glucocorticoids. As © I 3% aresult, abrupt discontinuation of glucocorticoids can result in adrenal crisis, which can be life-threatening. An established dose regimen @pD | 90% should not be altered. This intermediate-acting corticosteroid is used for the treatment of acute and chronic inflammatory disorders. Laboratory studies that should be monitored periodically include kidney function, liver function, serum electrolytes, thyroid function, total cholesterol, and glucose. Weight gain, osteoporosis, headaches, insomnia, psychosis, edema, aseptic necrosis of bone, moon facies, truncal obesity, cataracts, and hypokalemia are potential adverse effects.", "whyNot": {"a": "The healthcare provider should be contacted before any changes are made when taking long-term glucocorticoid medications.", "b": "Hyperglycemia is an adverse effect associated with glucocorticoid administration.", "c": "Risk of infection is increased with the use of a glucocorticoid."}, "keyConcept": "Long-term systemic use of corticosteroids is associated with significant risk of adverse events that include osteoporosis and fractures; adrenal suppression; hyperglycemia and diabetes; cardiovascular disease, and dyslipidemia, dermatological and GI events; psychiatric disturbances; and immunosuppression. These medications should never be stopped abruptly, as long-term use suppresses the hypothalamic- pituitary-adrenal axis and sudden discontinuation can result in life-threatening adrenal crisis."}, {"id": 10816, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is providing home care to an elderly client with diagnoses of Type 2 diabetes and CHF. Which of the following observations is a priority concern for the nurse?", "choices": [{"id": "a", "t": "The client reports her ankles are swollen every night before she goes to bed"}, {"id": "b", "t": "The client reports an ingrown toenail that is very painful"}, {"id": "c", "t": "The homecare aide reports the client refused her shower last week"}, {"id": "d", "t": "The nurse notes the client has lost five pounds in the last two weeks"}], "correct": "b", "rationale": "Most diabetic amputations are preventable by education, close monitoring, and appropriate care. Ingrown toenails can be prevented by trimming toenails straight across, so the ends of the nail grow over the skin and not into it. Good nail care can prevent ingrown toenails and other diabetic foot problems. Clients with diabetes should see a podiatrist regularly and as needed for the care of problems like ingrown toenails, which can lead to a foot infection.", "whyNot": {"a": "The nurse should investigate this further given the client’s congestive heart failure to determine if the edema is getting worse. However, D Hl", "c": "The nurse should investigate the reasons for the client’s refusal, but the toenail takes priority.", "d": "Since the client has CHF, weight fluctuation may be due to diuretic therapy. Weight gain would be a higher priority as it could indicate fluid"}, "keyConcept": "Most diabetic amputations are preventable by education, close monitoring, and appropriate care. Ingrown toenails can be prevented by trimming toenails straight across, so the ends of the nail grow over the skin and not into it. Good nail care can prevent ingrown toenails and other diabetic foot problems. Clients with diabetes should see a podiatrist regularly and as needed for the care of problems like ingrown toenails, which can lead to a foot infection."}, {"id": 10817, "cat": "NCLEX 15- ENDOCTRINE", "stem": "The nurse is assessing a client with suspected hypothyroidism. Which of the following is an expected finding in a client with this disorder?", "choices": [{"id": "a", "t": "Short attention span and weight loss"}, {"id": "b", "t": "Weight loss and flushed skin"}, {"id": "c", "t": "Rapid pulse and heat intolerance"}, {"id": "d", "t": "Dry skin and constipation"}], "correct": "d", "rationale": "a © o 2 ° s a = a < Hypothyroidism can be the result of a derangement in the hypothalamic-pituitary axis or a primary thyroid disorder. Whatever the etiology, the clinical manifestations are the same, resulting from slowed metabolic processes. These signs and symptoms include fatigue, slow movement, and slow speech, cold intolerance, constipation, weight gain, delayed relaxation of deep tendon reflexes, and bradycardia. Other signs include coarse dry skin and hair; edema; and hoarseness.", "whyNot": {"a": "Short attention span and weight loss are associated with hyperthyroidism, not hypothyroidism.", "b": "Weight loss and flushed skin are associated with hyperthyroidism, not hypothyroidism.", "c": "Arapid pulse and heat intolerance are associated with hyperthyroidism, not hypothyroidism."}, "keyConcept": "a © o 2 ° s a = a < Hypothyroidism can be the result of a derangement in the hypothalamic-pituitary axis or a primary thyroid disorder. Whatever the etiology, the clinical manifestations are the same, resulting from slowed metabolic processes. These signs and symptoms include fatigue, slow movement, and slow speech, cold intolerance, constipation, weight gain, delayed relaxation of deep tendon reflexes, and bradycardia. Other signs include coarse dry skin and hair; edema; and hoarseness."}, {"id": 10818, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with acromegaly. This condition results from oversecretion of which of the following?", "choices": [{"id": "a", "t": "Luteinizing hormone"}, {"id": "b", "t": "Growth hormone"}, {"id": "c", "t": "Parathyroid hormone"}, {"id": "d", "t": "Mineralocorticoids"}], "correct": "b", "rationale": "Correct Answer: B. Growth hormone Acromegaly refers to enlargement of the viscera due to an excess of growth hormone. Growth hormone is secreted by the pituitary gland, and acromegaly is usually caused by a benign tumor of the pituitary gland. Gigantism occurs when oversecretion of growth hormone occurs in early childhood. Individuals with acromegaly as the result of a tumor in later life may experience gradual changes in the shape of the face, including protrusion of the jaw or brow. Thickened lips, coarsening of facial features, and enlargement of hands and feet may be initially noticed. Headaches and impaired vision may occur as a result of the mass effect of a pituitary tumor. Menstrual irregularities and enlargement of organs, including the heart, kidneys, liver, and spleen, may occur.", "whyNot": {"a": "Luteinizing hormone is released by the anterior pituitary gland and triggers production of testosterone in the testes in men and ovulation", "c": "Parathyroid hormone is released by the parathyroid glands and does not cause acromegaly. It is associated with calcium metabolism.", "d": "Mineralocorticoids regulate excretion of water, sodium, and potassium by the kidney and are produced by the adrenal glands. The"}, "keyConcept": "Acromegaly is a rare disorder of excessive bone and soft tissue growth caused by elevated levels of growth hormone, which is secreted by the pituitary gland. Oversecretion is usually the result of a benign adenoma of the pituitary. If it occurs in children prior to fusion of bones, gigantism can occur. In adults, gradual enlargement and coarsening of soft features occur and clients may experience headaches or impaired vision as a result of the mass effect of the pituitary tumor."}, {"id": 10819, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client who was admitted early in the shift with pancreatitis. When evaluating the client’s laboratory results, what is the immediate priority for intervention?", "choices": [{"id": "a", "t": "White blood cell count 11,000 cells/mm43 © B. Sodium 118 mEq/L"}, {"id": "b", "t": "Option B (text recovered from OCR is incomplete)."}, {"id": "c", "t": "Potassium 3.5 mEq/L"}, {"id": "d", "t": "Serum amylase 120 units/dL"}], "correct": "b", "rationale": "Correct Answer: B. Sodium 118 mEq/L a I o: c | The priority for intervention is the sodium level, which is very low. The normal range of sodium is 135-145 mg/dL. When the sodium level D | drops below 120 mEq/mL, hyponatremia can result in seizures and other neurologic findings.", "whyNot": {"a": "This is slightly above the limit of normal but is not the priority for intervention. An elevated white blood cell count is consistent with the", "c": "This is a normal potassium level. Potassium should be monitored, particularly if the client is vomiting. Abnormal potassium is associated", "d": "Serum amylase reflects the release of the digestive enzyme from damaged pancreatic cells. It is expected to be elevated in pancreatitis."}, "keyConcept": "Sodium (Na) is a major extracellular fluid cation. The balance of sodium is important for many physiologic functions, including facilitation of impulse transmission in nerve and muscle fibers mediated through the sodium-potassium pump; and maintaining acid-base balance by combining with bicarbonate and chloride. The normal serum sodium concentration ranges from 135 to 145 mEq/L. Hyponatremia can result in neurologic symptoms and cerebral edema. Sodium cannot be replaced too rapidly or it may cause central pontine myelinolysis, which refers to severe damage to myelin sheaths in the area of the pons."}, {"id": 10820, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is assigned to a client admitted to the emergency department with a suspected diagnosis of acute pancreatitis. Which region will most likely be painful for this client?", "choices": [{"id": "a", "t": "Periumbilical pain migrating to the right lower quadrant"}, {"id": "b", "t": "Right upper quadrant pain that radiates to the right shoulder"}, {"id": "c", "t": "Right flank pain that radiates to the groin"}, {"id": "d", "t": "Epigastric pain that radiates to the back"}], "correct": "d", "rationale": "A Hi 13% Moderate Acute pancreatitis results in mid-epigastric or left upper quadrant pain that may radiate to the back. The pancreas is located primarily in the Cc I 5% retroperitoneal cavity, behind the stomach and extending horizontally to the spleen. The pain may be alleviated by leaning forward and eD ; 56% increased by lying supine. The pancreas secretes digestive enzymes and hormones, functioning as an exocrine and endocrine gland. A high-fat meal exacerbates pain from pancreatitis as a result of overstimulation of pancreatic secretion of digestive enzymes. Nausea and vomiting are characteristic, and hypovolemia results from third-spacing of fluid. Severe pancreatitis can result in acute respiratory distress syndrome caused by a systemic inflammatory response. Hypocalcemia may also occur when calcium is bound by necrosed fat. Areas of referred pain to the abdomen Cholecystisis Pancreatitis Appendicitis Nephrolithiasis: t", "whyNot": {"a": "Appendicitis pain begins in the periumbilical region and migrates over time to the right lower quadrant. Tenderness can be elicited at", "b": "Cholecystitis is characterized by right upper quadrant pain that may radiate to the right shoulder.", "c": "Flank pain results from nephrolithiasis (renal colic) and causes severe intermittent pain when the stone moves through the ureter. Pain"}, "keyConcept": null}, {"id": 10821, "cat": "NCLEX 15- ENDOCTRINE", "stem": "The nurse is caring for a client admitted with non-productive cough, dyspnea on exertion, chills and a oxygen saturation of 92%. What is the most appropriate nursing diagnosis for this client?", "choices": [{"id": "a", "t": "Ineffective airway clearance"}, {"id": "b", "t": "Impaired gas exchange"}, {"id": "c", "t": "Activity intolerance"}, {"id": "d", "t": "Risk for infection"}], "correct": "b", "rationale": "‘i The client is not exchanging air well. The nurse should be suspicious of pneumonia or other conditions that limit air exchange. This is the OB a most appropriate diagnosis cil off", "whyNot": {"a": "Ineffective airway clearance may be applicable to this patient. However, nothing in the question suggests they have an airway clearance", "c": "Activity intolerance is not the priority diagnosis.", "d": "The client likely has an infection, so this diagnosis is not the most appropriate."}, "keyConcept": "Care planning is a critical component of nursing. It is vital the nurse learn how to plan care, revise care as needed and to evaluate care to inure quality client outcomes."}, {"id": 10822, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a 26 year-old male client who asks about testicular self-exam. Which of the following will the nurse advise the client is the best time for a man to perform a testicular self-examination?", "choices": [{"id": "a", "t": "After strenuous exercise"}, {"id": "b", "t": "First thing in the morning"}, {"id": "c", "t": "After sexual intercourse or masturbation"}, {"id": "d", "t": "After a warm shower"}], "correct": "d", "rationale": "-examination is when the testicles are most relaxed and hanging as low as possible. This is typically after a B | oom fo warm shower. Exercise and sexual intercourse may typically cause the testicles to pull up into the body making the exam more difficult. Time of day is not as critical. c | 1%", "whyNot": {"a": "Exercise may cause the testicles to move closer to the body, making a testicular self-exam more difficult.", "b": "The time of day to perform a testicular self-exam is not as critical as the other circumstances.", "c": "Sexual intercourse may cause the testicles to move closer to the body, making a testicular self-exam more difficult."}, "keyConcept": "Testicular cancer is the most common solid tumor in men between the ages of 20 and 34. Early detection and treatment is associated with better prognosis. The client should choose a specific day, such as the first day of the month, to create a routine. The exam is easier to perform while the client is standing up after a warm bath or shower. Warmth makes the skin of the scrotum soft and relaxed, so it is easier to examine the testicular surface underneath it. The client should become familiar with the normal characteristics of the testes, including the epididymis on the back surface, which stores sperm from the testicles. The epididymis feels like a bump on the side of the testis, which might be mistaken for an abnormal growth if the client is unaware. The client should hold each testis in the hand, feeling for changes in size or weight since the last self-exam. The client should also look at the scrotum to see if there are any changes. Each testis should individually be held in both hands and slowly rolled with the thumb and fingers of the hand, feeling for small lumps or areas of soreness. A small, firm lump attached to the testis is the most common finding in testicular cancer."}, {"id": 10823, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is providing teaching to a client who has Graves' disease and is to add propranolol to her medication regimen. Which of the following information should the nurse include? O A.\"An adverse effect of this medication is jaundice.\" O B. \"Take your pulse before each dose of medication.\" O C. \"The purpose of this medication is to decrease the production of thyroid hormone.\" O D. \"Stop taking this medication if you have a fever.\"", "choices": [{"id": "a", "t": "Yellowing of the skin is an adverse effect of methimazole, not propranolol."}, {"id": "b", "t": "al 3% Easy Propranolol can cause bradycardia."}, {"id": "c", "t": "The purpose of propranolol is to suppress tachycardia, diaphoresis, and other effects of Graves' disease."}, {"id": "d", "t": "Fever is not an adverse effect of this medication. A low-grade fever can occur with Graves' disease, but the client should not abruptly stop"}], "correct": "b", "rationale": "al 3% Easy Propranolol can cause bradycardia. The client should take her pulse before each dose of medication. If there is a significant change in the OB rsd ase: pulse rate, the client should withhold the dose and consult the provider. ° ci 10%", "whyNot": {"a": "Yellowing of the skin is an adverse effect of methimazole, not propranolol.", "c": "The purpose of propranolol is to suppress tachycardia, diaphoresis, and other effects of Graves' disease.", "d": "Fever is not an adverse effect of this medication. A low-grade fever can occur with Graves' disease, but the client should not abruptly stop"}, "keyConcept": "Hyperthyroidism is an endocrine disorder in which the thyroid gland produces an excess of thyroid hormone resulting in an increase in metabolism in all body organs. The most common form of hyperthyroidism is Graves’ disease. Nonsurgical management for Graves' disease includes drug therapy with antithyroid drugs known as thionamides. The thionamide most frequently prescribed is methimazole. Propylthiouracil, another thionamide, is prescribed less often as it can lead to liver toxicity. These medications block the production of thyroid hormone by preventing iodide binding the thyroid gland. Other medication treatment includes beta-adrenergic blocking agents such as propranolol. While beta-blockers do not inhibit thyroid production, the drugs are used for supportive treatment of some of the symptoms of Graves' disease, such as tachycardia and palpitations, diaphoresis, and anxiety."}, {"id": 10824, "cat": "NCLEX 15- ENDOCTRINE", "stem": "instructions for home care, what is the most appropriate way for the nurse to explain the necessary monitoring and dressing changes for the client’s continuing care?", "choices": [{"id": "a", "t": "Use pictures that demonstrate signs of infection and dressing changes."}, {"id": "b", "t": "Identify a bilingual relative to translate for the client and his wife."}, {"id": "c", "t": "Use an interpreter from a fee-paid agency or a telephone interpretation service."}, {"id": "d", "t": "Demonstrate a dressing change for the client with written instructions that he can review with the help of a bilingual friend or family member."}], "correct": "c", "rationale": "all 9% Easy It is important to communicate health information accurately in the client’s own language, which can best be accomplished by using the B | a0 services of a qualified translator with knowledge of medical terminology. Barriers to effective teaching and continuing self-care include language barriers, low health literacy, and cultural differences. OG FT 81% oi 9%", "whyNot": {"a": "This solution will not provide the client with an opportunity to ask any questions, and the nurse will be unable to determine if the client", "b": "A professional medical translator or telephone translation service is preferable to translation by a family member or friend. Family or", "d": "This solution does not allow the client to address any questions to the nurse and does not allow the nurse to assess the client’s"}, "keyConcept": "When providing health information and education to a non-English speaking client, a qualified translator should be provided, since translation by family and friends may violate client privacy rights. The client should have the opportunity to ask questions and confirm understanding. A qualified translator should understand medical terminology in order to provide correct information."}, {"id": 10825, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is performing a complete physical assessment of the endocrine system. Which endocrine gland will the nurse be able to palpate?", "choices": [{"id": "a", "t": "The pituitary gland"}, {"id": "b", "t": "The hypothalamus"}, {"id": "c", "t": "The parathyroid gland"}, {"id": "d", "t": "The thyroid gland"}], "correct": "d", "rationale": "A 2% Easy The only endocrine gland that can be palpated during the physical assessment process is the thyroid gland, a butterfly-shaped gland located | anterior to the upper part of the trachea and just inferior to the larynx. The pituitary and hypothalamus are located within the skull, and the parathyroid glands are located behind the thyroid gland so they cannot be palpated. c | 4%", "whyNot": {"a": "The pituitary gland is in the brain; it cannot be palpated.", "b": "The hypothalamus is part of the brain in the skull; it cannot be palpated.", "c": "The parathyroid glands are behind the thyroid gland; it cannot be palpated."}, "keyConcept": "po] e o 2 ° s a = a < The thyroid gland should be inspected and palpated when performing a full physical assessment. It is palpated from a posterior position, with the examiner behind the client. The nurse should note firmness, size, and any tenderness. If abnormalities are noted, the nurse should auscultate the lobes of the thyroid with the diaphragm of the stethoscope. Laboratory assessment of thyroid function may include measurement of the serum TSH concentration, which is increased in hypothroidism; serum T3 and T4; and thyroid antibodies. is the single best screening test of thyroid function because of its high sensitivity. Major Endocrine Glands Male Female sata Pineal gland Pituitary gland Thyroid gland —.9 23 Trrms Adrenal gland . Pancreas"}, {"id": 10826, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client with a tumor of the anterior pituitary gland. Which of the following hormones secreted by the anterior pituitary gland may exhibit abnormal levels?", "choices": [{"id": "a", "t": "Aldosterone"}, {"id": "b", "t": "Prolactin"}, {"id": "c", "t": "Vasopressin"}, {"id": "d", "t": "Cortisol"}], "correct": "b", "rationale": "Hormones secreted by the anterior pituitary gland include growth hormone, adrenocorticotropic hormone, thyroid-stimulating hormone, prolactin, and gonadotropins, which include follicle-stimulating hormone and luteinizing hormone.", "whyNot": {"a": "Aldosterone is a mineralocorticoid produced by the adrenal glands and regulated by adrenocorticotropic hormone (ACTH).", "c": "Vasopressin is released by the posterior pituitary gland. It is also known as antidiuretic hormone and acts on the kidneys to regulate", "d": "Cortisol is a glucocorticoid produced and secreted by the adrenal gland."}, "keyConcept": "The anterior pituitary gland secretes growth hormone, adrenocorticotropic hormone, thyroid stimulating hormone, prolactin, and gonadotropins. A tumor can interfere with function of any of the target organs related to these hormones. The posterior pituitary gland secretes oxytocin and ADH (anti-diuretic hormone."}, {"id": 10827, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is reviewing the medication administration record (MAR) of a client with type 2 diabetes mellitus at 1900 (See image). Which of the following interventions is most appropriate for the nurse to implement? Medication Adi ration Record", "choices": [{"id": "a", "t": "Provide orange juice immediately."}, {"id": "b", "t": "Ask the UAP to teach the client about symptoms of hypoglycemia."}, {"id": "c", "t": "Perform a stat bedside fingerstick glucose check."}, {"id": "d", "t": "Provide a bedtime snack for the client."}], "correct": "d", "rationale": "Sliding scale regular insulin was administered at 1630 in addition to the intermediate-acting insulin. Although the insulin was administered before the evening meal, the peak effect of intermediate-acting Humulin N ( NPH) insulin occurs 5-8 hours after injection. A bedtime snack Regular insulin by sliding scale SQq ac &hs FSG<60 notify HCP 1-150: 0 units 151-200: 2 units 201-250: 4 units 07300N | 16300N 251-300: 6 units 8G 220 BG 205 4 units 4 units 301-350: 8 units 1130 0N >350: notify HCP 8G 348 8 units Humulin N 30 units sc BID ac 07300N | 1630 0N will reduce the risk of a hypoglycemic episode during the night.", "whyNot": {"a": "Orange juice raises the blood sugar, but there is no mention of hypoglycemic symptoms or low blood glucose, so it is not necessary to", "b": "Teaching is a nursing task and cannot be delegated to UAP. It is not a priority intervention for the nurse at this time.", "c": "The client’s blood glucose is checked g AC and HS, which should occur at approximately 2100. The peak effect of the client’s intermediate"}, "keyConcept": null}, {"id": 10828, "cat": "NCLEX 15- ENDOCTRINE", "stem": "dosage? O A. Hand tremors O B. Bradycardia O C. Pale skin O D. Slow speech", "choices": [{"id": "a", "t": "Hand tremors"}, {"id": "b", "t": "Bradycardia"}, {"id": "c", "t": "Pale skin"}, {"id": "d", "t": "Slow speech"}], "correct": "a", "rationale": "The nurse should identify that hand tremors is a manifestation of hyperthyroidism that can result from thyroid hormone replacement B ] 13% therapy. The nurse should report this finding to the provider due to the possible need for a decrease in the dosage of medication. | ° © 2%", "whyNot": {"b": "Bradycardia is an expected finding of hypothyroidism. This finding indicates the need for continued thyroid hormone replacement", "c": "Pale skin, or pallor, is an expected finding of hypothyroidism. This finding indicates the need for continued thyroid hormone replacement", "d": "Slow thought processes and speech are expected findings of hypothyroidism. This finding indicates the need for continued thyroid"}, "keyConcept": "Hypothyroidism is an endocrine disorder that occurs as the result of low levels of thyroid hormone, causing decreased metabolism. Manifestations of hypothyroidism include hyponatremia, hypoglycemia, hypoventilation, hypotension, bradycardia, hypothermia, dry and pale skin, and changes in mental processes."}, {"id": 10829, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A client is newly diagnosed with insulin-dependent diabetes. The healthcare provider prescribes 6 units of regular insulin each morning before breakfast. Which of the following does the nurse expect?", "choices": [{"id": "a", "t": "Onset of 1-2 hours with peak action of 6-8 hours and 12-14 hour duration"}, {"id": "b", "t": "Onset of 30-60 minutes with 2-4 hour peak action and duration of 6-8 hours"}, {"id": "c", "t": "Incompatible with other insulin preparations"}, {"id": "d", "t": "Onset of 2 hours with no peak and action of >40 hours"}], "correct": "b", "rationale": "All 13% Easy A nurse should understand the actions of different types of insulin used to treat diabetes mellitus types 1 and 2, since each type has a Cc | 1% different onset, peak, and duration of action. Insulin is provided to replace inadequate endogenous insulin that is normally produced by the . Insulin lowers blood glucose by stimulating glucose uptake in skeletal muscle and fat and by inhibiting hepatic glucose production. Regular insulin has an onset of action of 30-60 minutes, peak action at 2-4 hours, and duration of 6-8 hours, depending upon preparation. Beta blockers and clonidine may mask some of the signs and symptoms of hypoglycemia.", "whyNot": {"a": "Intermediate-acting insulin preparations have an onset of 1-2 hours with a peak action at 6-8 hours and a duration of 12-14 hours.", "c": "Regular insulin is compatible with other insulin preparation.", "d": "This describes insulin degludec."}, "keyConcept": "The nurse must verify the name of the insulin before administration, because each insulin has a different peak and duration. Regular insulin begins to act in 30 to 60 minutes, reaches a peak concentration in 2 to 4 hours, and has a duration of action of 6 to 8 hours. Intermediate- acting insulins begin to act in 1 to 2 hours, reach a peak concentration in 4 to 15 hours, and have a duration of action of 22 to 28 hours. Long- acting insulins begin to act in 4 to 8 hours, reach a peak concentration in 10 to 30 hours, and have a duration of action of 36 hours or more. Rapid-acting insulins are clear. Intermediate- and long-acting insulins are turbid (cloudy)."}, {"id": 10830, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following individuals would benefit from dietary management of diabetes mellitus by meal planning using advanced carbohydrate counting (ACC)? O A.A 60-year-old adult with type 2 diabetes controlled with exercise and diet O B. A35-year-old adult with type 2 diabetes who is treated with metformin, an oral hypoglycemic medication O C. A 19-year-old female with type 1 diabetes who uses an insulin pump O D.A 40-year-old male with type 2 diabetes who is treated with a split dose of mixed insulin", "choices": [{"id": "a", "t": "Clients who use diet and exercise to control type 2 diabetes should use basic carbohydrate counting, which allows them to identify"}, {"id": "b", "t": "Clients who use oral hypoglycemics to control type 2 diabetes should use basic carbohydrate counting, which allows them to identify"}, {"id": "c", "t": "‘a oi Advanced carbohydrate counting is a meal planning strategy that uses the number of carbohydrates consumed to determine a client’s daily ec | | insulin needs."}, {"id": "d", "t": "Clients who use fixed insulin regimes to control diabetes should use basic carbohydrate counting, which allows them to identify"}], "correct": "c", "rationale": "‘a oi Advanced carbohydrate counting is a meal planning strategy that uses the number of carbohydrates consumed to determine a client’s daily ec | | insulin needs. It is based on the client’s ratio of insulin to carbohydrates, so clients must be able to count the number of carbohydrate grams D Hl in their meal to determine the appropriate insulin dose. Clients with an insulin pump can use this approach to determine the best dose of pre-prandial (before meal) rapid-acting insulin by estimating their calorie consumption planned for the meal. ACC is also a good strategy for clients on multiple injection therapy daily. This gives the client additional flexibility to determine what and when to eat. A registered dietician or certified diabetes educator can be helpful for educating clients in the use of ACC or carbohydrate counting for management of diabetes.", "whyNot": {"a": "Clients who use diet and exercise to control type 2 diabetes should use basic carbohydrate counting, which allows them to identify", "b": "Clients who use oral hypoglycemics to control type 2 diabetes should use basic carbohydrate counting, which allows them to identify", "d": "Clients who use fixed insulin regimes to control diabetes should use basic carbohydrate counting, which allows them to identify"}, "keyConcept": "Clients with type 1 diabetes mellitus should base meal planning on their usual food intake and balance that with insulin and exercise pattern. Clients who use rapid-acting insulin can adjust their dosage before a meal, using the current blood glucose level and the carbohydrate content of the meal. This strategy is known as advanced carbohydrate counting."}, {"id": 10831, "cat": "NCLEX 15- ENDOCTRINE", "stem": "the nurse include in the client's postoperative care plan?", "choices": [{"id": "a", "t": "Maintain the client in a low-Fowler's position."}, {"id": "b", "t": "Encourage deep breathing and coughing."}, {"id": "c", "t": "Monitor the client's neurologic status every 2 hr for the first 12 hr following surgery."}, {"id": "d", "t": "Observe dressing drainage for the presence of glucose."}], "correct": "d", "rationale": "All 11% Hard The nurse should monitor the drainage to the mustache dressing and observe for the presence of glucose, which would indicate the B a oR fo presence of cerebrospinal fluid. The nurse should notify the provider if this occurs. cia 28%", "whyNot": {"a": "The nurse should maintain the client a high-Fowler's position after surgery.", "b": "A client who is postoperative should be discouraged from coughing, sneezing, and blowing the nose because this increases pressure in the", "c": "Mental status, vision, and neuromuscular responses should be monitored every hour for the first 24 hr following surgery because of the"}, "keyConcept": "In surgery for removal of the pituitary gland, a less invasive endoscopic trans-nasal approach is sometimes used instead of the trans- sphenoidal method. In either case, nurses are responsible for closely monitoring vital signs, neurological signs, and the mustache dressing and should use interventions to avoid complications as needed. Nurses will need to teach the client about the purpose of prescribed hormones and medications and the importance of compliance with the medication schedule."}, {"id": 10832, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse in an outpatient clinic is assessing a client with type 1 diabetes mellitus. Which of the following laboratory results should the nurse prioritize for reporting to the healthcare provider?", "choices": [{"id": "a", "t": "Serum potassium 4.0 mEq/L"}, {"id": "b", "t": "Fasting blood glucose 90 mg/dL"}, {"id": "c", "t": "Serum sodium 138 mEq/L"}, {"id": "d", "t": "Serum creatinine 2.2 mg/dL"}], "correct": "d", "rationale": "al 3% Easy ce | 5% Diabetic nephropathy is a complication of diabetes mellitus caused by damage to small blood vessels in the kidney. The kidney functions as Cc | 2% a filter and eliminates waste products, including creatinine, a by-product of metabolism. Normally, serum creatinine levels are 0.5-1.2 mg/dL e@D PY 91% and reflect the glomerular filtration rate. An increase in serum creatinine indicates a loss of kidney function. Progression of diabetic nephropathy can be limited by tight control of glucose and early treatment. Diabetic nephropathy is equally as common in type 1 and type 2 iT} diabetes. ce} = ® 2. 3 =) a =", "whyNot": {"a": "This is a normal serum potassium level (3.5-5.0 mEq/L). <", "b": "This is a normal fasting blood glucose (70-99 mg/dL).", "c": "This a normal serum sodium (135-145 mEq/L)."}, "keyConcept": "Diabetic nephropathy, the primary cause of end stage renal disease in the United States, is a microvascular complication of diabetes mellitus that affects the blood vessels that supply the renal glomeruli. Risk factors include chronic hyperglycemia, smoking, hypertension, and genetic predisposition. Clients with diabetes mellitus should undergo annual screening for microalbuminuria, an early test for detection of protein in the urine."}, {"id": 10833, "cat": "NCLEX 15- ENDOCTRINE", "stem": "dipstick is positive for ketones. Which of the following initial interventions is anticipated by the nurse?", "choices": [{"id": "a", "t": "Administer 0.9% saline solution at 10 ml/kg"}, {"id": "b", "t": "Administer Kayexalate (sodium polystyrene sulfonate)"}, {"id": "c", "t": "Administer oral hypoglycemic medications."}, {"id": "d", "t": "Administer 500 ml 0.45% saline solution"}], "correct": "a", "rationale": "@ 380 mg/dL, positive urine ketones, mental status changes, and vomiting, the client is most likely in diabetic B a 80% ketoacidosis (DKA), one of the most serious complications of diabetes. DKA results from insulin deficiency, preventing uptake of glucose by cells and elevated blood glucose levels. High levels of urine glucose cause osmotic diuresis, leading to volume depletion. Initial management © i 20) includes fluid resuscitation with 10-20 ml/kg of an isotonic solution such as normal saline (0.9% NS) to prevent hemodynamic collapse. D || 13%", "whyNot": {"b": "Kayexalate is a treatment for hyperkalemia (increased potassium levels. DKA is associated with hypokalemia. Administration of fluids is", "c": "Insulin is necessary for treatment of diabetic ketoacidosis. Oral diabetic medications are not effective.", "d": "Isotonic fluid (0.9% NS) is indicated."}, "keyConcept": "DKA is caused by reduction of circulating insulin, leading to an elevation in counterregulatory hormones, including glucagon, catecholamines, and cortisol. This results in increased glucose production in the liver; impaired cellular uptake of glucose; and release of free fatty acids from adipose tissue into the circulation (lipolysis). Fatty acids are oxidized in the liver to ketone bodies, which causes excess ketones in blood and urine and metabolic acidosis. Infection is a frequent precipitating cause of DKA. Treatment includes fluid and electrolyte resuscitation and intravenous insulin administration, in addition to treatment of the underlying cause."}, {"id": 10834, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A client in the intensive care unit after head trauma develops diabetes insipidus. Which of the following nursing actions is appropriate?", "choices": [{"id": "a", "t": "Monitor glucose and use sliding-scale insulin"}, {"id": "b", "t": "Place the client in the Trendelenburg position"}, {"id": "c", "t": "Administer desmopressin"}, {"id": "d", "t": "Ensure fluid restriction"}], "correct": "c", "rationale": "Correct Answer: C. Administer desmopressin A — B Central or neurogenic diabetes insipidus occurs as a result of impaired production, secretion, or transport of antidiuretic hormone, which ec | helps regulate water balance. This condition can occur after brain surgery, head trauma, or an infection of the central nervous system or with my ] brain tumors. It is characterized by increased thirst (polydipsia) and increased urine output (polyuria) with dilute urine with a low specific gravity of urine. When ADH release is impaired, it can be replaced with desmopressin, which is an analog of vasopressin that does not have vasoconstrictive properties. In the past, vasopressin was used but is no longer available. Desmopressin is available as a liquid that can be administered intranasally, in an oral tablet, or in a parenteral formulation. When a client is able to drink, he/she is generally able to replace the water loss orally. When replacing fluids in a client who is unable to drink, dextrose and water should be given through IV. The nurse should monitor the client’s urine output, serum sodium, and specific gravity of urine.", "whyNot": {"a": "Diabetes mellitus is associated with high blood glucose.", "b": "The Trendelenburg position reduces blood flow to the head and is usually contraindicated in neurological conditions.", "d": "When a client is able to drink, he/she is generally able to replace the water loss orally."}, "keyConcept": "In diabetes insipidus, decreases in ADH (antidiuretic hormone) result in fluid and electrolyte imbalance due to increased urinary output and increased plasma osmolality. It is characterized by increased thirst and increased urination, with excretion of large quantities of urine with low specific gravity. Urinary output ranges from 5 to 20 L per day. Central diabetes insipidus may be permanent after intracranial surgery. It is usually reversible after head trauma."}, {"id": 10835, "cat": "NCLEX 15- ENDOCTRINE", "stem": "which of the following? O A. Nourishment with a latent effect to counteract late insulin activity O B. Added calories to help the teen gain weight O C. Encouragement for the teen to adhere to her diet O D. A source of concentrated carbohydrates for immediate utilization", "choices": [{"id": "a", "t": "Nourishment with a latent effect to counteract late insulin activity"}, {"id": "b", "t": "Added calories to help the teen gain weight"}, {"id": "c", "t": "Encouragement for the teen to adhere to her diet"}, {"id": "d", "t": "A source of concentrated carbohydrates for immediate utilization"}], "correct": "a", "rationale": "Humulin N insulin lasts for 10-18 hours. A bedtime snack consisting of carbohydrates and protein will help to prevent hypoglycemia during B 1% the night while the action of the insulin will still be high. | c| 2%", "whyNot": {"b": "The question does not give any information about the teen’s weight. She should have a bedtime snack to avoid developing hypoglycemia", "c": "There is no evidence that the client is noncompliant with her medication or eating habits. The bedtime snack is encouraged to avoid the", "d": "The nurse should explain the source of the food that the client needs as part of a bedtime snack. The snack should actually be a good"}, "keyConcept": "Humulin N (insulin isophane) is a man-made form of insulin used to improve control of blood sugar in adults and children with diabetes mellitus. It is an intermediate-acting insulin that starts to work within 2 to 4 hours after injection, peaks in 4 to 8 hours, and keeps working for 10 to 18 hours. A bedtime snack will help prevent hypoglycemia during the night."}, {"id": 10836, "cat": "NCLEX 15- ENDOCTRINE", "stem": "hyperthyroidism? O A. Insufficient iodine intake O B. Hashimoto's thyroiditis O C. Autoantibodies to thyroid stimulating hormone receptors O D. Radiation treatment", "choices": [{"id": "a", "t": "Insufficient iodine intake"}, {"id": "b", "t": "Hashimoto's thyroiditis"}, {"id": "c", "t": "Autoantibodies to thyroid stimulating hormone receptors"}, {"id": "d", "t": "Radiation treatment"}], "correct": "c", "rationale": "| 16% Hard Grave's disease is the most common cause of hyperthyroidism. In Grave's disease, the client develops antibodies to thyroid stimulating B | Dan hormone receptors in the thyroid gland. These autoantibodies stimulate production and release of thyroid hormone. Symptoms of hyperthyroidism include rapid heart rate, increased sweating, and weight loss. ec | 49% off 1%", "whyNot": {"a": "Insufficient iodine intake would more likely lead to hypothyroidism, not hyperthyroidism.", "b": "Hashimoto's autoimmune thyroiditis, also known as chronic autoimmune thyroiditis, causes gradual loss of thyroid function.", "d": "Radiation treatment can destroy the structure of the thyroid gland and result in hypothyroidism, not hyperthyroidism."}, "keyConcept": "Several different disorders can cause hyperthyroidism. It is essential that the correct cause be identified because appropriate therapy depends upon the underlying mechanism of the hyperthyroidism Causes include increased synthesis of hormone; inflammation and destruction of the thyroid tissue, causing release of thyroid hormone into the circulation; or an extrathyroidal source of thyroid hormone. The radioactive iodine uptake test will show uptake of radioactive iodine by the thyroid if the cause is increased synthesis of thyroid hormone by the thyroid gland. If inflammation and destruction are causing release of preformed hormone into the circulation, the radioactive iodine test will show decreased or absent uptake of radioactive iodine into the thyroid gland."}, {"id": 10837, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse is caring for a client diagnosed with hypothyroidism. Which of the following is an indication of myxedema coma?", "choices": [{"id": "a", "t": "Hypocalcemia"}, {"id": "b", "t": "Tachycardia"}, {"id": "c", "t": "Tachypnea"}, {"id": "d", "t": "Decreased body temperature"}], "correct": "d", "rationale": "1] or subcutaneous and interstitial tissues. Myxedema coma is a complication of profound hypothyroidism. Metabolism is slowed, so bradycardia and bradypnea can be expected. This can result from precipitating factors such as infection, heart failure, stroke, trauma, and surgery. c | 6% Hypothermia, fatigue, hyporeflexia, decreased mental function, hypoventilation, cardiac arrest, and respiratory failure may occur. Skin @ , with facial and preorbital edema. Clients will be obtunded or comatose or may have seizures. Decreased bowel sounds mirror decreased activity in the Gl tract. The nurse should assess the client’s cardiovascular status, noting the quality of peripheral pulses and capillary refill. Increased jugular venous distention and pulsus paradoxus may indicate pericardial effusion or tamponade. Thyroid studies should be obtained. The client should be placed on a cardiac monitor, and pulmonary artery pressure and central venous pressure monitoring should be initiated if available. Fluid status should be followed with hourly Is and Os. Fluids should be given intravenously to maintain a blood pressure of <90 mmHg systolic while watching for signs of overload due to heart failure. Vasopressors may be necessary if hypotension is refractory to", "whyNot": {"a": "Hypocalcemia is not associated with myxedema coma.", "b": "Bradycardia is associated with myxedema.", "c": "Bradypnea is associated with myxedema."}, "keyConcept": "Myxedema coma is a complication of severe hypothyroidism, and usually occurs in the presence of a precipitating factor such as trauma, infection, cold exposure, or administration of hypnotics or opiates. Clients with myxedema coma are hypothermic, hypercapnic, and hyponatremic, in addition to exhibiting other signs of hypothyroidism."}, {"id": 10838, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse in a provider's office is reviewing the laboratory results of a client who is being evaluated for secondary hypothyroidism. Which of the following laboratory findings indicates secondary hypothyroidism?", "choices": [{"id": "a", "t": "Elevated thyroxine (T4)"}, {"id": "b", "t": "Decreased triiodothyronine (T3)"}, {"id": "c", "t": "Elevated thyroid stimulating hormone (TSH)"}, {"id": "d", "t": "Decreased cholesterol"}], "correct": "b", "rationale": "3 is an expected finding for a client who has hypothyroidism.", "whyNot": {"a": "Decreased T4 is an expected finding for a client who has hypothyroidism.", "c": "Adecreased or near-normal TSH level is an expected finding in a client who has secondary hypothyroidism. An elevated TSH level", "d": "Elevated cholesterol is an expected finding for a client who has hypothyroidism."}, "keyConcept": "a © o 2 ° s a = a < Hypothyroidism is an endocrine disorder that occurs when low levels of thyroid hormones are produced resulting in a decrease in metabolism in body organs. Female clients are affected by hypothyroidism more frequently than male clients and the disease occurs most often between 30 and 60 years of age. The testing for thyroid function includes measuring blood levels of the following: © Triiodothyronine (T3) © Thyroxine (T4) © Thyroid-stimulating hormone (TSH) In clients who have hypothyroidism, T3 and T4 levels will be decreased. TSH levels will be increased in primary disease, and decreased in secondary or tertiary hypothyroidism. Other testing for hypothyroidism includes cholesterol screening. Most clients who have hypothyroidism have elevated cholesterol. Other manifestations of the disease include: * Cool, dry, scaly skin © Decreased hair growth © Bradycardia, which can lead to dysrhythmias ¢ Hypotension © Dyspnea and hypoventilation © Weight gain © Decreased appetite © Constipation * Abdominal distention ¢ Lethargy and somnolence * Cold intolerance, decreased body temperature"}, {"id": 10839, "cat": "NCLEX 15- ENDOCTRINE", "stem": "likely to be which of the following?", "choices": [{"id": "a", "t": "Consult the dietician to follow-up with dietary instructions."}, {"id": "b", "t": "Provide a booklet on diet for the client to read at leisure."}, {"id": "c", "t": "Leave the client to watch a recorded diabetic education program."}, {"id": "d", "t": "Review the client's typical diet and discuss items that may increase blood glucose levels."}], "correct": "d", "rationale": "The most effective learning occurs in an adult client when the nurse’s teaching adds to the client’s knowledge about a topic perceived as vital to the client's health and when the teaching is perceived as providing information that will benefit the client. By assisting a client to identify his or her choices in diet, the nurse is providing information specific to the client’s health. This is a type of active learning that requires the client to participate in identification of menu items that may be problematic.", "whyNot": {"a": "Although the dietician can provide valuable input for the client with respect to an appropriate diet, the nurse has an opportunity to teach", "b": "Although books and pamphlets can be helpful for reinforcement of nursing teaching, it is better to tailor teaching to the client’s specific", "c": "Patient education channels can be a useful way to reinforce nursing teaching, but it is important to engage the client when initiating"}, "keyConcept": "Successful techniques to use when teaching an adult client about a new health condition include providing information the client feels is vital and beneficial to his health and involving the client actively in decision making and planning."}, {"id": 10840, "cat": "NCLEX 15- ENDOCTRINE", "stem": "A nurse in a provider's office is reviewing the laboratory reports of a client who is being evaluated for Graves' disease. Which of the following laboratory results is an indication of Graves' disease?", "choices": [{"id": "a", "t": "Decreased thyrotropin receptor antibodies (TRAb)"}, {"id": "b", "t": "Decreased thyroid-stimulating hormone (TSH)"}, {"id": "c", "t": "Decreased thyroxine (T4)"}, {"id": "d", "t": "Decreased triiodothyronine (T3)"}], "correct": "b", "rationale": "A | | 8% Moderate In the presence of Graves' disease, a low TSH level is an expected finding. The pituitary gland decreases the production of TSH when thyroid OB rd ae: hormone levels are elevated. ° ci 12% of 5%", "whyNot": {"a": "In the presence of Graves' disease, elevated thyrotropin receptor antibodies is an expected finding.", "c": "In the presence of Graves' disease, an elevated T4 level is an expected finding.", "d": "In the presence of Graves' disease, an elevated T3 level is an expected finding."}, "keyConcept": "Testing for thyroid function includes measuring blood levels of the following: © Triiodothyronine (T3) © Thyroxine (T4) © Thyroid-stimulating hormone (TSH) T3 and T4 levels will be increased in a client who has Graves' disease. TSH levels will be decreased in a client who has Graves' disease, the most common type of hyperthyroidism, and increased in secondary or tertiary hyperthyroidism. Other diagnostic testing for Graves’ disease includes thyroid scanning with radioactive iodine and ultrasounds to determine the size of the thyroid and if any masses are present. An ECG may also be performed to determine if dysrhythmias are present."}, {"id": 10841, "cat": "NCLEX 15- ENDOCTRINE", "stem": "Which of the following instructions should a nurse give to a client who is beginning over-the-counter calcium supplements at a dose of 1000 mg/day, as recommended by the healthcare provider?", "choices": [{"id": "a", "t": "Divide the daily dose and take it with food."}, {"id": "b", "t": "Return in 1 week to have a serum calcium level drawn."}, {"id": "c", "t": "Vitamin D supplements should be stopped when taking calcium supplements."}, {"id": "d", "t": "Take calcium at night before bedtime."}], "correct": "a", "rationale": "si 28% Oral calcium supplements are given to clients who are unable to consume adequate calcium in diet. The main forms of oral calcium Cc | 5% supplements are calcium carbonate and calcium citrate. Calcium carbonate is absorbed better when taken with food. It is an ingredient in -the-counter antacids, including Rolaids and Tums. Most tablets provide between 200 and 400 mg of calcium. Calcium citrate is a more expensive form of calcium. It is well absorbed on either a full stomach or empty stomach and can be more easily absorbed by individuals with a lower level of stomach acid. A nurse should instruct the client to divide the doses since absorption is improved when the individual consumes 500 mg or less at a time. Calcium supplements can cause bloating, gas, and constipation. About 99% of the body’s calcium is stored in the bones and teeth, and the remainder is in the serum, where it is tightly regulated and doesn’t fluctuate significantly in response to changes in dietary intake.", "whyNot": {"b": "It is not necessary to monitor serum calcium.", "c": "Both vitamin D and calcium are necessary for bone health and are recommended for some groups, including elderly clients who do not", "d": "Calcium should be taken in divided doses throughout the day. Calcium carbonate is absorbed best in an acidic environment, so it should"}, "keyConcept": "Oral calcium supplements are prescribed for clients who are unable to maintain adequate dietary calcium intake. They are used to treat and prevent hypocalcemia and as an adjunct treatment to prevent postmenopausal osteoporosis. Some forms (Tums, Rolaids) are used for relief of acid indigestion or heartburn. Calcium supplements are also used to treat hyperphosphatemia in end-stage renal disease. One gram of calcium carbonate contains 400 mg elemental calcium (20 mEq calcium)."}, {"id": 10842, "cat": "NCLEX 15- ENDOCTRINE", "stem": "teaching? O A. Liver function tests O B. Hearing test O C. Urinalysis O D. Dental examination", "choices": [{"id": "a", "t": "Liver function tests"}, {"id": "b", "t": "Hearing test"}, {"id": "c", "t": "Urinalysis"}, {"id": "d", "t": "Dental examination"}], "correct": "a", "rationale": "The nurse should inform the client that statins, such as atorvastatin, can cause liver damage and should not be taken by clients who have a history of liver disease. The client should undergo baseline liver function testing before beginning therapy and every 6 to 12 months thereafter. The nurse should also include information regarding baseline examinations of serum cholesterol and triglyceride levels.", "whyNot": {"b": "Atorvastatin does not affect the hearing. Therefore, the nurse does not need to include information regarding a baseline examination of", "c": "A Urinalysis is not a necessary baseline examination for this medication. Atorvastatin does not affect the genitourinary system except for", "d": "A dental examination is not a necessary baseline examination for this medication. Atorvastatin does not affect the teeth and gums."}, "keyConcept": "The nurse should review pertinent information, such as drug handbooks, to gather accurate information prior to teaching a client about a new medication. This information should include baseline laboratory information so the client has an understanding of what testing will need to be done and why."}], "nclex_16_gastrointenstinal": [{"id": 10843, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Which of the following is the most appropriate recommendation by the nurse who is caring for a client at 23 weeks’ gestation with a complaint of significant heartburn?", "choices": [{"id": "a", "t": "Take an antacid with sodium bicarbonate"}, {"id": "b", "t": "Lie on the side after a meal"}, {"id": "c", "t": "Avoid dairy items in the diet"}, {"id": "d", "t": "Eat 6 small meals daily"}], "correct": "d", "rationale": "A Hi 16% Moderate cy 6% During pregnancy, the stomach is displaced upward and compressed by the growing uterus. An increase in the hormone progesterone Cc I 4% during pregnancy results in a slowing of the Gl tract motility, delayed emptying time of the stomach, and relaxation of the esophageal e@ , which can cause heartburn (pyrosis). The nurse should advise the client to eat frequent small meals in place of 3 larger meals each day. Other interventions to reduce heartburn include reduction of fluid intake with meals and elimination of dietary triggers like fatty or fried foods, carbonated drinks, spicy food, and caffeine or chocolate. The nurse should advise the client to stay in an upright position after meals to reduce reflux from the stomach into the esophagus. Clients should also be advised to elevate the head of the bed 4-6 inches.", "whyNot": {"a": "Alka-Seltzer is a common sodium bicarbonate antacid rated class C in pregnancy. The client should be encouraged to use other", "b": "The upright position is recommended for 2-3 hours after meals to aid digestion and reduce heartburn.", "c": "Dairy items are an important part of the diet during pregnancy."}, "keyConcept": "Several factors increase the risk of heartburn in women who are pregnant. They include displacement of the stomach upward by the growing uterus and slowing of the GI tract due to increased progesterone levels, which also cause relaxation of the lower esophageal sphincter and delayed emptying of the stomach."}, {"id": 10844, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client with diabetic gastroparesis has a new prescription for metoclopramide (Reglan.) Which symptom should the nurse instruct the client to report immediately as a potentially serious adverse effect?", "choices": [{"id": "a", "t": "Constipation"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Lip smacking"}, {"id": "d", "t": "Agitation"}], "correct": "c", "rationale": "‘i om Involuntary lip smacking and other uncontrollable movements of the face, head, legs, arms, or body are characteristic of tardive dyskinesia. ec | This condition is a potential side effect of neuroleptic drugs, including antipsychotic medications, as well as antiemetics such as D Hi metoclopramide. Movements characteristic of tardive dyskinesia include torticollis and a protruding or twisting tongue. The risk of tardive dyskinesia increases in older clients, in those on high doses, and in clients on long-term therapy. Tardive dyskinesia is frequently an irreversible condition. Metoclopramide blocks dopaminergic receptors in the chemoreceptor trigger zone of the central nervous system, stimulates increased motility of the upper GI tract, and increases the rate of gastric emptying. It is also used to treat post-operative nausea and vomiting, gastroesophageal reflux disease and intractable hiccups. Other adverse effects associated with metoclopramide include neuroleptic malignant syndrome and extrapyramidal side effects, including parkinsonian symptoms.", "whyNot": {"a": "Metoclopramide is a prokinetic agent and promotes gastric emptying and motility in the GI tract. It may cause diarrhea with high doses", "b": "Diarrhea may occur with high doses of metoclopramide, a prokinetic agent used to treat gastroparesis and nausea/vomiting. Diarrhea is", "d": "Metoclopramide does not cause agitation. It is more likely to cause sedation or drowsiness."}, "keyConcept": "When providing education to a client with a new prescription for metoclopramide, the nurse should instruct the client to take metoclopramide as directed, but if a dose is missed, the client should take it as soon as remembered, unless it is almost time for next dose. Clients should be advised that metoclopramide may cause sedation, so driving or operating heavy machinery should be avoided until the client's response to the medication is known. Alcohol and other CNS depressants should be avoided when taking metoclopramide, as they have an additive effect. The nurse should Inform the client of the risk of extrapyramidal symptoms, tardive dyskinesia, and neuroleptic malignant syndrome and advise the client to notify health care professional immediately if involuntary or repetitive movements of eyes, face, or limbs occur."}, {"id": 10845, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is conveying information to a client with an ileostomy. Which of the following statements by the client will indicate that the client has understood the teaching?", "choices": [{"id": "a", "t": "“If a blockage occurs, should add water through the stomal opening.”"}, {"id": "b", "t": "“Ifa blockage occurs, should take a laxative to clear the obstruction.”"}, {"id": "c", "t": "“Ifa blockage occurs, should eat high-fiber foods.”"}, {"id": "d", "t": "“If a blockage occurs, should begin a liquid diet.”"}], "correct": "d", "rationale": "All 14% Hard Blockage occurs fairly commonly with an ileostomy, so dietary guidelines are important to avoid blockage of the intestine or ileostomy. The B i nOee nurse should advise the client to eat 6 small meals daily, chewing food very thoroughly. The client should drink at least 8 cups of fluid daily and should avoid foods like dried fruits, nuts, sunflower and other seeds, hotdogs or sausages with casings, raw cabbage, celery, coconut, c |_| 27% apple peel, pineapple, and oranges. If the client experiences blockage, a liquid diet should be initiated. The client can cut the opening of the @D ft 49% pouch a little larger than normal, as the stoma may swell when there is a blockage. Massaging the abdomen, bathing in warm water, and moving into different body positions may relieve the blockage. Oral enzymes can also be used to relieve the blockage, but if the client remains blocked or without stomal output for several hours, the healthcare provider should be notified immediately or the client should seek medical care at an emergency department. The client should never use laxatives or lavage to relieve a blockage. a = © 2 ° = a = lleostomy g < Meostomy bag Stoma", "whyNot": {"a": "Lavage should never be attempted by the client to clear a blockage.", "b": "The client should never use laxatives in an attempt to clear a blockage.", "c": "A liquid diet should be initiated if the client develops a blockage. High-fiber foods should be avoided by clients with an ileostomy."}, "keyConcept": null}, {"id": 10846, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "enema. Which of the following is the appropriate nursing action?", "choices": [{"id": "a", "t": "Tell the client that the process is necessary but will only take a little longer."}, {"id": "b", "t": "Tell the client to take slow deep breaths."}, {"id": "c", "t": "Advance the tube 2 cm and continue the instillation."}, {"id": "d", "t": "Stop the instillation for 30 seconds before resuming at a slower rate."}], "correct": "d", "rationale": "58g 11% Intestinal spasms may occur with a rapid infusion of an enema solution, causing pain, cramping, and a sensation of fullness. When a client Cc | 2% reports any of these symptoms, the enema instillation should be stopped for 30 seconds before resuming at a slower rate. Rapid infusion e@D fs 86% may increase the possibility of premature ejection of the solution, which can interfere with bowel evacuation necessary for the surgical iT} procedure. 2 ® 2. 3 =) a =", "whyNot": {"a": "This response does not answer the client’s current pain and discomfort. <", "b": "Although this advice may help the client tolerate the enema, it should be given before the enema is instilled. If it is repeated, it should be", "c": "This response does not answer the client’s concern. Instillation should be initiated with the tube at a depth that will allow the instillation"}, "keyConcept": "Intestinal spasms and abdominal cramping can occur if an enema solution is infused too rapidly. If this occurs, the instillation should be stopped for thirty seconds and resumed at a slower rate."}, {"id": 10847, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Before a nurse removes an NG tube from a client, what should the nurse instruct the client to do?", "choices": [{"id": "a", "t": "Take a deep breath and hold it"}, {"id": "b", "t": "Perform a Valsalva maneuver"}, {"id": "c", "t": "Exhale"}, {"id": "d", "t": "Inhale deeply and exhale rapidly"}], "correct": "a", "rationale": "Moderate Correct Answer: A. Take a deep breath and hold it Of | Sh ce | 10% Anasogastric tube is used to administer tube feedings and medications for clients who are unable to eat by mouth, including those who are c || 19% unable to swallow adequately without aspirating food or liquids into the lungs. They are also used to facilitate suctioning stomach contents my ] ag: fo for prevention of nausea, vomiting, and gastric distention and to remove stomach contents for analysis. When removing a nasogastric tube, the nurse should assist the client to a seated position if possible, placing a disposable pad across the client’s chest to shield it from spillage. The tube should be disconnected and unpinned from the client’s gown. Before removing the tube, the nurse may instill 50 mL of air to clear the tube of any contents, but this is optional. Instruct the client to take a deep breath and hold it, which will close the epiglottis and allow the tube to pass easily through the esophagus into the nose. The NG tube should be pinched to prevent contents from draining into the client’s throat and removed with a smooth, continuous motion.", "whyNot": {"b": "The client should take a deep breath and hold it, which will close the epiglottis.", "c": "The client should inhale and hold the breath, not exhale.", "d": "Exhalation will open the epiglottis and prevent easy removal."}, "keyConcept": "When removing a nasogastric tube, the nurse should assist the client to a seated position and disconnect the tube, unpinning it from the client's gown.The nurse should instruct the client to breathe deeply and hold the breath, which closes the epiglottis, allowing the tube to pass easily from the esophagus to the nose.The tube should be removed with a smooth, continuous motion."}, {"id": 10848, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is admitted with a new diagnosis of hepatic encephalopathy and has a prescription for lactulose. Which of the following indicates to the nurse, that the treatment was effective?", "choices": [{"id": "a", "t": "Increased bowel movements"}, {"id": "b", "t": "Increased bruising"}, {"id": "c", "t": "Increased sedation"}, {"id": "d", "t": "Hypoactive bowel sounds"}], "correct": "a", "rationale": "Eas) Correct Answer: A. Increased bowel movements OA Pe oe y . Ammonia is produced in the Gl tract as c | 3% bacteria degrade amino acids, urea, and other substrates. The liver detoxifies and eliminates ammonia, so reduced liver function results in my | 3\" elevated levels. Lactulose inhibits production of ammonia in the Gl tract by reducing the number of bacteria in the colon. When treated effectively, the client should have 2-4 loose stools per day. Lactulose is administered orally or by nasogastric tube for severe hepatic encephalopathy, but it can be administered as an enema for clients who are comatose.", "whyNot": {"b": "Cirrhosis is often associated with increased bruising and increased risk of bleeding due to decreased synthesis of clotting factors.", "c": "Hepatic encephalopathy is associated with lethargy and coma. Increased sedation would suggest worsening of the condition.", "d": "Ileus is associated with overdose of lactulose."}, "keyConcept": "The breakdown of protein by bacteria in the intestines results in ammonia, which is absorbed into the circulation through the gut mucosa.. The healthy liver normally converts ammonia into urea, which is then eliminated in urine. Ammonia levels in the blood rise when the liver is not able to convert ammonia to urea, resulting in high ammonia levels and hepatic encephalopathy."}, {"id": 10849, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has just had a gastrostomy tube placed. Which complication is most commonly associated with a gastrostomy tube?", "choices": [{"id": "a", "t": "Infection"}, {"id": "b", "t": "Dysphagia"}, {"id": "c", "t": "Sinusitis"}, {"id": "d", "t": "Pulmonary aspiration"}], "correct": "a", "rationale": "A gastrostomy tube enters the stomach through an incision in the abdomen; a client with this type of feeding tube may be at higher risk of B 1] or infection of the skin and membranes surrounding the abdominal cavity if microorganisms are introduced through the tube. | © 1%", "whyNot": {"b": "Dysphagia describes difficulty swallowing; a client is not at risk of dysphagia with a gastrostomy tube.", "c": "Sinusitis refers to an infection in the sinuses, which may occur with a nasogastric tube, not a gastrostomy tube.", "d": "Pulmonary aspiration is more common with the use of nasogastric or orogastric feeding tubes, not gastrostomy tubes."}, "keyConcept": "Peritonitis is an inflammatory process within the peritoneal cavity commonly caused by a bacterial infection. Peritonitis is a major"}, {"id": 10850, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is assigned to care for a client admitted for treatment of cholecystitis. The nurse would expect the client's history to include intolerance to which of the following?", "choices": [{"id": "a", "t": "Carbohydrates"}, {"id": "b", "t": "Fatty foods"}, {"id": "c", "t": "Protein"}, {"id": "d", "t": "Vitamin C"}], "correct": "b", "rationale": "Inflammation of the gallbladder (cholecystitis) and/or the presence of gallstones (cholelithiasis) interfere with movement of bile from the liver or gallbladder into the small intestine. Bile is secreted from the gallbladder into the small intestine to facilitate the breakdown of fats into fatty acids in the digestive process. ‘Areas of referred pain to the abdomen | ee FE -) € K a", "whyNot": {"a": "Carbohydrate digestion is not affected by gallbladder problems.", "c": "Digestion of proteins is not affected by gallbladder/bile. Pepsin is the active protein-digesting enzyme.", "d": "Absorption of vitamin C occurs in the mucous membranes of the mouth, stomach, and small intestine. It is not affected by bile from the"}, "keyConcept": "Acute cholecystitis is characterized by right upper quadrant pain, fever, and leukocytosis (elevated white blood cell count) resulting from gallbladder inflammation. Clinical manifestations of acute cholecystitis include severe abdominal pain, most commonly in the right upper quadrant or epigastrium, which may radiate to the right shoulder or back; fever, nausea, vomiting, and anorexia. The client frequently has a history of fatty food ingestion one hour or more before the initial onset of pain."}, {"id": 10851, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is scheduled for an ileostomy. Which of the following interventions would be most helpful in preparing the client psychologically for the surgery?", "choices": [{"id": "a", "t": "Include family members in preoperative teaching sessions"}, {"id": "b", "t": "Encourage the client to ask questions about managing the ileostomy"}, {"id": "c", "t": "Provide a brief, thorough explanation of preoperative and postoperative procedures"}, {"id": "d", "t": "Invite a member of the ostomy association to visit the client"}], "correct": "c", "rationale": "Providing explanations of preoperative and postoperative procedures helps the client prepare and understand what can be expected. It also provides an opportunity for the client to share concerns.", "whyNot": {"a": "Including family members in the teaching sessions is beneficial but does not focus on the client’s psychological preparation.", "b": "Encouraging the client to ask questions about managing the ileostomy may be rushing the client psychologically into accepting the", "d": "The client should have the opportunity to express concerns and to agree to an ostomy association visitor before the invitation is extended."}, "keyConcept": "Many clients have difficulty coping with an ostomy. An ostomy often results in changes in body image, self-esteem, sexuality, quality of life, and role function. The nurse should encourage the client to express fears and concerns. The nurse can help alleviate some anxiety and assist the client with adjustment by providing factual information about what to expect."}, {"id": 10852, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is recovering from a hysterectomy with paralytic ileus. The client has no bowel sounds and has not passed flatus. Which of the following is a treatment priority for this client?", "choices": [{"id": "a", "t": "The client should be prepped to return to the OR."}, {"id": "b", "t": "The client should receive oral fluids and a pureed diet to stimulate the digestive tract."}, {"id": "c", "t": "Anasogastric tube should be attached to intermittent or constant suction."}, {"id": "d", "t": "Bed rest should be encouraged."}], "correct": "c", "rationale": "A || 12% Moderate Paralytic ileus is a common postoperative complication that results from hypomotility of the gastrointestinal tract due to the effects of ec | 55% anesthetic medication or from manipulation of the bowel during surgery. Clinical manifestations include absence of bowel sounds, absence D l 3% of flatus, nausea, vomiting, abdominal distention, and failure to pass stool. Initial treatment measures include passage of a nasogastric tube connected to intermittent or continuous suction. Early ambulation after surgery can reduce the risk of paralytic ileus.", "whyNot": {"a": "A nasogastric tube to decompress the abdomen is the usual initial treatment for paralytic ileus, which can result from manipulation of the", "b": "The client should be NPO until the return of bowel sounds.", "d": "Ambulation can reduce the risk of paralytic ileus. The client should be encouraged to ambulate."}, "keyConcept": "Paralytic ileus refers to a nonmechanical bowel obstruction caused by hypomotility of the Gl tract, often the result of general anesthetics or manipulation of the bowel during surgery. Early ambulation should be encouraged to reduce the risk of ileus. If paralytic ileus develops, treatment includes keeping the client NPO, IV fluid replacement, and use of nasogastric suction to low wall suction for decompression of the Gl tract."}, {"id": 10853, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "What is the priority action for a nurse who notes an obstructed feeding tube when caring for a client?", "choices": [{"id": "a", "t": "Instill a carbonated soda into the tube."}, {"id": "b", "t": "Aspirate the tube with a small-bore syringe."}, {"id": "c", "t": "Flush the tube with warm water and aspirate"}, {"id": "d", "t": "Install a commercial solution of digestive enzymes into the tube."}], "correct": "c", "rationale": "8 13% Enteral feeding tubes can become obstructed by thick feeding formulas or by inadequately crushed or diluted medications. The likelihood of ec FY 77% successfully unclogging a feeding tube decreases as time passes, so it is important to initiate intervention quickly. The obstructing contents -bore syringe with a large barrel, followed by aspiration. A gentle pattern of flushing and aspiration is most likely to be successful by providing a back-and-forth motion to dislodge the material.", "whyNot": {"a": "Use of a carbonated beverage is not an appropriate way to dislodge a bolus of clogged material from a feeding tube. Carbonated colas", "b": "Use of a small-bore syringe may create significant pressure and cause damage to the feeding tube.", "d": "Initial attempts to unclog the tube should be made using warm water and a back-and-forth motion, before using a commercial enzyme"}, "keyConcept": "Improperly crushed or diluted medications can obstruct an enteral feeding tube. If this occurs, it's important to act quickly to relieve the obstruction. Using a large syringe, the nurse should flush the tube, then aspirate, repeating until the obstruction is relieved by the gentle back and forth movement."}, {"id": 10854, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing teaching for a client who has a new prescription for famotidine. Which of the following statements indicates client understanding of the teaching?", "choices": [{"id": "a", "t": "“This medication coats the lining of my stomach.”"}, {"id": "b", "t": "“This medication will not stop my stomach pain immediately.”"}, {"id": "c", "t": "“I may experience increased acid production with this medication.”"}, {"id": "d", "t": "“I should take this pill after finish my meal.”"}], "correct": "b", "rationale": "Famotodine is an H2 blocker (histamine 2 receptor blocker) and decreases acid production in the stomach, which reduces damage to the @B 41% gastric lining. It may take several days before pain relief is achieved. — © 3% of 9%", "whyNot": {"a": "Sucralfate is a drug that coats the stomach lining. Famotodine is an H2 blocker and works by decreasing acid production.", "c": "Famotidine reduces acid production.", "d": "Famotidine should be taken 1 hour before mealtimes."}, "keyConcept": "Histamine blockers (H2 blockers) include cimetidine (Tagamet HB), ranitidine (Zantac), nizatidine (Axid) and famotidine (Pepsid). They block production of acid in the stomach, allowing the gastric lining to heal and preventing further damage."}, {"id": 10855, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "likely to be found on an examination of this client?", "choices": [{"id": "a", "t": "Chvostek’s sign"}, {"id": "b", "t": "Murphy’s sign"}, {"id": "c", "t": "Cullen’s sign"}, {"id": "d", "t": "Koplik spots"}], "correct": "c", "rationale": "All ° Cullen’s sign (see figure below) refers to a bluish discoloration and superficial edema around the umbilicus and is associated with pancreatic ec Ei necrosis and bleeding in severe pancreatitis. Turner’s sign may also be seen in severe pancreatitis associated with retroperitoneal D | hemorrhage, which refers to bruising over the flanks. Clinical manifestations of pancreatitis include epigastric pain that may radiate to the back, nausea, vomiting, fevers, and tachycardia. Primary treatment measures include making the client NPO and giving IV fluids and analgesics. A nasogastric tube is usually placed to prevent vomiting, decrease abdominal distention, and prevent entry of stomach acid into the duodenum. The client has gallstone pancreatitis, so a cholecystectomy will be performed.", "whyNot": {"a": "Chvostek’s sign is seen in hypocalcemia and refers to the contraction of the facial muscles when the facial nerve is tapped anterior to the", "b": "A positive Murphy sign refers to pain with deep inspiration when the gallbladder is palpated. It is associated with acute cholecystitis.", "d": "Koplik spots are spots on the oral mucosa associated with measles (rubeola)."}, "keyConcept": "Pancreatitis is associated with epigastric pain and elevation of amylase and lipase. Signs associated with severe pancreatitis include Cullen's sign, periumbilical edema and bruising, which indicates pancreatic necrosis; and Turner's sign, bruising over the flanks, which indicates"}, {"id": 10856, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "respirations 30/min. The client’s pulse oximeter shows an oxygen saturation of 87%. Which of the following does the nurse know may be affecting the accuracy of the client’s pulse oximetry reading?", "choices": [{"id": "a", "t": "Increased body temperature"}, {"id": "b", "t": "Tachypnea"}, {"id": "c", "t": "Tachycardia"}, {"id": "d", "t": "Hypotension"}], "correct": "d", "rationale": "All ° Hypotension results in poor perfusion and may cause peripheral vasoconstriction, both of which can cause inaccuracies in pulse oximetry Cc I readings. A pulse oximeter estimates the oxygen saturation of arterial blood by measuring the amount of absorbed by hemoglobin through e@D | use of a light emitting component and a light sensor attached to the finger, toe, nose, or earlobe. In a low perfusion state, the amount of blood flow and the associated hemoglobin content will be reduced. Failure to sense accurate correct oxyhemoglobin content can also occur when the sensor is positioned incorrectly or ill-fitting, during excessive movement, and in carbon monoxide poisoning and smoke inhalation.", "whyNot": {"a": "Increased body temperature does not independently cause an inaccurate reading by pulse oximetry.", "b": "Hypoxemia may result from low oxygen content of blood but does not affect the accuracy of a reading by a pulse oximeter. A low reading", "c": "Tachycardia with a rate under 150/min is unlikely to cause reduced cardiac output, so this client’s heart rate is not likely to be a factor"}, "keyConcept": "Apulse oximeter can provide a falsely low reading in clients with hypotension and/or peripheral vasoconstriction. Other causes of inaccurate readings include carbon monoxide poisoning and an ill-fitting or poorly positioned sensor. Pulse Oximeter"}, {"id": 10857, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is assessing a client’s stoma during the initial postoperative period after colostomy. Which of the following observations should be reported immediately to the physician?", "choices": [{"id": "a", "t": "The stoma is slightly edematous"}, {"id": "b", "t": "The stoma is white to bluish-white"}, {"id": "c", "t": "The stoma oozes a small amount of blood"}, {"id": "d", "t": "The stoma does not expel stool"}], "correct": "b", "rationale": "| 2% Easy Awhite stoma indicates lack of blood supply. The stoma should be deep pink.", "whyNot": {"a": "Mild edema and slight oozing of blood are normal in the early postoperative period.", "c": "Oozing of blood is normal at this stage of recovery.", "d": "The colostomy usually does not start to function for 2 to 4 days after surgery."}, "keyConcept": "Lack of blood supply to the stoma can result in stomal necrosis, a complication of colostomy that occurs in up to 14% of clients in the immediate postoperative period. If necrosis occurs and extends to the bowel, immediate revision of the colostomy is necessary. Early identification of poor perfusion can prevent the necessity of a surgical procedure."}, {"id": 10858, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client diagnosed with ulcerative colitis who has a new prescription for sulfasalazine. Which of the following should the nurse include when developing teaching materials for the client?", "choices": [{"id": "a", "t": "Eat a low-protein diet and reduce caloric intake"}, {"id": "b", "t": "Maintain a fluid intake of 2,000 mL/day minimum"}, {"id": "c", "t": "Stop medication when symptoms resolve"}, {"id": "d", "t": "Limit caffeine to 1 cup of coffee with breakfast daily"}], "correct": "b", "rationale": "Correct Answer: B. Maintain a fluid intake of 2,000 mL/day minimum Ulcerative colitis is a chronic inflammatory bowel disease characterized by exacerbation and remission. Clients should follow a low-residue, high-calorie, high-protein diet supplemented by vitamins and minerals in order to maintain adequate nutrition. Low-residue foods limit the irritation of the GI tract and may decrease symptoms. A low-residue diet includes foods that are easily digested, such as rice, pasta, enriched bread, canned fruit, cooked vegetables, and easily digestible meats. Foods such as raw vegetables and fruits, whole grains, alcohol, fried foods, and spicy foods may irritate the inflamed colon and should be avoided. Fluid intake necessary to maintain fluid balance, hydration, and electrolyte balance is 2,000-3,000 mL per day. Clients should be instructed to eat small, frequent meals to decrease the load of fecal material in the GI tract, which will decrease stimulation and peristalsis.", "whyNot": {"a": "Adequate caloric intake is necessary to meet metabolic needs. Clients should be encouraged to consume a high-protein diet.", "c": "Sulfasalazine should be taken on a continuous basis, even in the absence of symptoms, in order to maintain remission of symptoms. This", "d": "The client should avoid anything that stimulates the intestine, including tobacco, alcohol, and caffeine."}, "keyConcept": "Ulcerative colitis is a chronic inflammatory bowel disease characterized by periods of exacerbation and remission. Low residue foods are less likely to irritate the colon, but it's important for clients to maintain adequate nutrition with high calorie, high-protein foods low in residue, supplemented by vitamins and minerals. 2-3 liters of fluid intake are necessary to maintain hydration and balance."}, {"id": 10859, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "The nurse is preparing to teach a client with peptic ulcer disease about a diet that should be followed after discharge. The nurse should encourage the client to eat which of the following?", "choices": [{"id": "a", "t": "Bland foods"}, {"id": "b", "t": "High-protein foods"}, {"id": "c", "t": "Any foods that are tolerated"}, {"id": "d", "t": "A glass of milk with each meal"}], "correct": "c", "rationale": "Apeptic ulcer is a defect in the gastric or duodenal wall that extends through the muscularis mucosa into the deeper layers. The most common cause is infection with Helicobacter pylori. NSAIDs (nonsteroidal anti-inflammatory drugs) are another cause, as they erode the gastric mucosa.Management includes testing for H. pylori infection and eradicating the bacteria. NSAIDs are discontinued and antisecretory medications may be prescribe to promote healing. Although dietary factors are not proven to cause PUD, clients should avoid foods that result in symptoms.", "whyNot": {"a": "There is no need for the client to eat bland foods", "b": "There is no need for the client to eat all high-protein foods", "d": "Milk may be included in the diet, but limiting the intake of milk is recommended."}, "keyConcept": "Apeptic ulcer is a defect in the gastric or duodenal wall that extends through the muscularis mucosa into the deeper layers. The most common cause is infection with Helicobacter pylori. NSAIDs (nonsteroidal anti-inflammatory drugs) are another cause, as they erode the gastric mucosa.Management includes testing for H. pylori infection and eradicating the bacteria. NSAIDs are discontinued and antisecretory medications may be prescribe to promote healing. Although dietary factors are not proven to cause PUD, clients should avoid foods that result in symptoms."}, {"id": 10860, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "appropriate? O A. At risk for nutritional deficits related to dysphagia O B. At risk for nutritional deficits related to anorexia O C. At risk for nutritional deficits related to dumping syndrome O D. At risk for nutritional deficits related to lactose intolerance", "choices": [{"id": "a", "t": "At risk for nutritional deficits related to dysphagia"}, {"id": "b", "t": "At risk for nutritional deficits related to anorexia"}, {"id": "c", "t": "At risk for nutritional deficits related to dumping syndrome"}, {"id": "d", "t": "At risk for nutritional deficits related to lactose intolerance"}], "correct": "c", "rationale": "This client is at risk of nutritional deficits related to dumping syndrome. Dumping syndrome is characterized by a bowel movement within 30 minutes after a meal and having abdominal distention, sweating, palpitations, cramping, and syncope after a meal.", "whyNot": {"a": "The client has not shown difficulty with eating; his symptoms are not associated with dysphagia.", "b": "The client does not show evidence of anorexia since he ate a meal 30 minutes ago.", "d": "Lactose intolerance is characterized by flatus, cramping, and osmotic diarrhea. This client is not showing signs of lactose intolerance."}, "keyConcept": "Dumping syndrome is also known as rapid gastric emptying. It is often associated with gastric surgery, but diabetes is a common cause of non-surgical dumping syndrome. It occurs when a large volume of undigested food moves from the stomach to small intestine, causing a rapid fluid shift into the intestine. Symptoms include crampy abdominal pain, nausea, vomiting, and diarrhea, usually 10-30 minutes after eating. Symptoms associated with the autonomic nerves and the nerve plexuses that innervate the stomach and small intestine include diaphoresis, flushing, dizziness, and palpitations. Mi Inbox- J} Untitle: Untitle’ (4 Google @ TEASF Online @& MarkkK | @ Micros (eeuWanes ce Nae ire ® Atte, % CLOSE © Newcl NC x + v Qa * ws * © Cb Finish update : { Browse Questions > iit Search Questions QJ"}, {"id": 10861, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "the nurse? O A. Send a stool sample for testing for C. difficile toxin O B. Dilute the hypertonic formula with water O C. Reduce the rate of feeding O D. Discontinue feeding", "choices": [{"id": "a", "t": "Send a stool sample for testing for C. difficile toxin"}, {"id": "b", "t": "Dilute the hypertonic formula with water"}, {"id": "c", "t": "Reduce the rate of feeding"}, {"id": "d", "t": "Discontinue feeding"}], "correct": "c", "rationale": "Hypertonic and isotonic enteral formulas are usually well tolerated, but hypertonic fluids can occasionally cause gastrointestinal symptoms due to a shift of fluids into the GI tract down an osmolar concentration gradient. The symptoms are usually relieved by slowing the rate of feeding. The rate can then gradually be increased to the desired amount, after alleviation of the GI symptoms.", "whyNot": {"a": "The symptoms experienced by this client occurred shortly after beginning enteral feedings with a hypertonic solution, so the initial", "b": "Dilution of an enteral formula may result in changes in the microbial balance in the Gl tract that are detrimental to the client or may result", "d": "The initial intervention is a reduction of the rate of feeding. If feeding is discontinued, the client will require another source of nutrition."}, "keyConcept": "Although hypertonic enteral feedings are usually well-tolerated, they can sometimes cause an osmotic shift of fluids into the GI tract, causing cramping, nausea, vomiting, and/or diarrhea. These symptoms can usually be alleviated by slowing down the rate of feeding until symptoms resolve."}, {"id": 10862, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "communicating with the healthcare provider? Oa Sodium 132 mEq/L O B. Potassium 2.9 mEq/L O c.albumin 2.6 g/d O b.inris", "choices": [{"id": "a", "t": "Hyponatremia can occur in clients with cirrhosis as a result of excess water retention. Although this client’s serum sodium level is low, it is"}, {"id": "b", "t": "Use of loop diuretics, including furosemide, can result in hypokalemia."}, {"id": "c", "t": "Liver disease results in reduced protein synthesis, reflected in low albumin. Albumin infusion can be helpful on a temporary basis to"}, {"id": "d", "t": "Anormal INR is a measure of coagulation that reflects prothrombin time. Individuals with liver disease often have elevated prothrombin"}], "correct": "b", "rationale": "Use of loop diuretics, including furosemide, can result in hypokalemia. Rapid correction of hypokalemia is necessary to prevent the development of serious and life-threatening complications. Hypokalemia can result in life-threatening cardiac arrhythmias and, in clients with cirrhosis, hepatic encephalopathy. Hepatic encephalopathy may be precipitated by hypokalemia, hypovolemia, infection, increased protein intake, gastrointestinal bleeding, or constipation. In clients with liver failure, expected findings include low serum albumin, increased PT and INR, increased serum ammonia, ALT, AST, and serum bilirubin. Low serum albumin and increased PT and INR result from decreased synthesis of plasma proteins. Elevated serum ammonia results from the impaired detoxification of ammonia by the liver. Damaged hepatic cells release AST and ALT into the circulation.", "whyNot": {"a": "Hyponatremia can occur in clients with cirrhosis as a result of excess water retention. Although this client’s serum sodium level is low, it is", "c": "Liver disease results in reduced protein synthesis, reflected in low albumin. Albumin infusion can be helpful on a temporary basis to", "d": "Anormal INR is a measure of coagulation that reflects prothrombin time. Individuals with liver disease often have elevated prothrombin"}, "keyConcept": "Hypokalemia can result in life-threatening cardiac arrhythmias and exacerbation of hepatic encephalopathy in clients with cirrhosis. Normal serum potassium levels are 3.5 mEq/L to 5.0 mEq/L. Expected laboratory findings in advanced liver disease include hyponatremia, increased serum bilirubin, increased serum ammonia, increased INR and PT, and low serum albumin."}, {"id": 10863, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "the healthcare provider? O A. Edema of the stoma O B. Mucus from the rectum O C. Protrusion of the stoma above the abdominal wall O D. Gray and dusky stoma", "choices": [{"id": "a", "t": "Edema of the stoma"}, {"id": "b", "t": "Mucus from the rectum"}, {"id": "c", "t": "Protrusion of the stoma above the abdominal wall"}, {"id": "d", "t": "Gray and dusky stoma"}], "correct": "d", "rationale": "The stoma should be a pink-reddish color. A grey, dusky color indicates necrosis, and the healthcare provider should be notified Cc i immediately. Stoma ischemia usually presents within the first 24 hours after surgery, initially appearing bluish in color. The nurse can insert a e@D | small test tube while shining a flashlight within the tube to determine the depth of necrosis. An ischemic stoma will not bleed when pricked by a needle. Superficial ischemia is usually managed with observation, but early revision may be necessary for full-thickness necrosis. Stomal complications include poor siting; complications in the peri-intestinal area, mucocutaneous junction, or stoma proper; and iatrogenic complications. Complications of the stoma proper include bleeding, prolapse, retraction, and necrosis. The necrotic stoma may appear dark red, purple, or grey (cyanotic) or may appear brown or black. Advanced necrosis is characterized by odor and sloughing of the mucosa. Nursing interventions to prevent ischemia include monitoring for abdominal distention and careful assessment for constriction of the faceplate.", "whyNot": {"a": "Edema is present in the postoperative period and for up to 6 weeks after placement.", "b": "Mucus discharge from the rectum is common after a colostomy. It should be clear or the color of putty.", "c": "The stoma protrudes from the abdominal wall and is fitted with a faceplate that is part of a 2-piece system including the plastic collection"}, "keyConcept": "In the post-operative client who has undergone colostomy, The normal stoma is pink-reddish in color. The new stoma should be assessed for ischemia, which initially appears blue and cyanotic. An ischemic stoma will not bleed when pricked by a needle. Necrosis appears grey and dusky in color. The depth of necrosis should be measured using a small test tube and flashlight."}, {"id": 10864, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client one day after an uncomplicated vaginal delivery. Which gastrointestinal changes would a nurse most likely see in this client?", "choices": [{"id": "a", "t": "Abdominal pain"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Gastroesophageal reflux"}, {"id": "d", "t": "Constipation"}], "correct": "d", "rationale": "A Hi 16% Moderate Many women become constipated after giving birth, which can occur for several reasons. Some women are inactive during the first few days B I a after delivery, which contributes to slowed gastrointestinal transit. Fluid intake and intake of fruits and vegetables may be lacking, which can also contribute to constipation.", "whyNot": {"a": "Abdominal pain is not a common sign that would occur after a normal vaginal delivery.", "b": "Diarrhea is not a common finding that develops after a vaginal delivery; instead, the client may more likely suffer from constipation.", "c": "Gastroesophageal reflux is not a common sign that would develop after a vaginal delivery."}, "keyConcept": "Causes of constipation after vaginal delivery can include use of systemic narcotics (such as morphine, Vicodin, or Percocet) during labor or for postpartum pain; sore perineum due to hemorrhoids, an episiotomy, or a tear, which may lead to constipation due to fear of pushing or straining; and use of iron supplement in prenatal vitamins. The client should be encouraged to ambulate, increase fluids, and increase consumption of high-fiber foods."}, {"id": 10865, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is assessing a client with complaint of abdominal pain. In which situation during physical assessment would the nurse use light palpation?", "choices": [{"id": "a", "t": "When overcoming resistance from tense muscles"}, {"id": "b", "t": "When there is excessive adipose tissue"}, {"id": "c", "t": "When there is a freely mobile mass in the abdomen"}, {"id": "d", "t": "When assessing an area with tenderness"}], "correct": "d", "rationale": "| 2% Easy When using light palpation, the nurse gently touches the client’s body using the fingertips or by very lightly using the palms of the hands. If B | 3\" the client has a tender area, the nurse would want to press lightly, not with deep palpation, to avoid causing further pain for the client. ci 13%", "whyNot": {"a": "The nurse would more likely use deep palpation in this situation, not light palpation.", "b": "When excessive fat tissue is present, the nurse would have to use more pressure with palpation. This would warrant deep palpation, not", "c": "A freely mobile mass in the abdomen would be assessed using the ballottement technique, not light palpation."}, "keyConcept": "Physical examination of the abdomen is the most important part of the evaluation of abdominal complaints such as pain, distention, enlarged organs, or masses.The abdominal exam is conducted in a sequence that begins with observation and then auscultation, percussion, and palpation, followed by ancillary maneuvers. Gentle palpation is used initially to determine if peritoneal signs and significant tenderness exist and whether the pertinent findings are general or localized. Palpation should always begin with light, soft, circular movements starting in the area away from the suspected pathology."}, {"id": 10866, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with suspected peptic ulcer disease. The healthcare provider will order which of the following tests to determine the etiology and to guide treatment?", "choices": [{"id": "a", "t": "Serum amylase"}, {"id": "b", "t": "C13 breath urea"}, {"id": "c", "t": "Stool test for C. difficile toxin"}, {"id": "d", "t": "Folate"}], "correct": "b", "rationale": "Peptic ulcers are usually found in the stomach or duodenum, although they can also occur in the esophagus. Causes include ingestion of Cc i 10% irritant substances such as nonsteroidal anti-inflammatory drugs (ibuprofen, indomethacin), infection by the Helicobacter pylori bacteria (H. D i pylori), and hypersecretion of acid due to stress. Some individuals may have a genetic predisposition to formation of peptic ulcers. Peptic ulcers erode the lining and mucosa of the Gl tract. If they erode into a blood vessel, bleeding may occur. Duodenal ulcers are usually associated with hypersecretion of stomach acid and result in epigastric pain 2-3 hours after mealtime. The pain is alleviated by food. Gastric ulcers generally are associated with normal stomach acid or hyposecretion. They are characterized by mid-epigastric pain 30 minutes to an hour after meal time, with increased pain when food is consumed. 8% Treatment of ulcers includes the use of medications that suppress acid production in the stomach, including H2 receptor blockers (antihistamine) and proton pump inhibitors (PPI) like lansoprazole (Prevacid), omeprazole (Prilosec), and pantoprazole (Cipher), as well as antacids (Mylanta) and drugs that form a barrier on the stomach lining (sucralfate or Carafate). H. pylori is easily transmitted and should be treated with a 3-drug regimen that includes an antibiotic (clarithromycin and amoxicillin or Flagyl and tetracycline) and a proton pump inhibitor or bismuth salicylate (Pepto-Bismol). Noninvasive tests for H. pylori include a C13 urea breath test, stool exam, and serologic antibody testing.", "whyNot": {"a": "Serum amylase is increased in acute pancreatitis.", "c": "C. difficile toxin is found in individuals who have Clostridium difficile enterocolitis, which should be considered in all hospitalized clients", "d": "Folate deficiency occurs in pernicious anemia and other malabsorption syndromes."}, "keyConcept": "Peptic ulcers are most commonly found in the stomach or duodenum. Important causes are infection by Helicobacter pylori bacteria and exposure to mucosal irritants, including use of nonsteroidal anti-inflammatory medications. Hypersecretion of acid contributes to formation of ulcers. Gastrointestinal bleeding can occur when a peptic ulcer erodes into a blood vessel. a © o 2 ° s a = a <"}, {"id": 10867, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with chronic hepatitis C who has returned to the unit after a liver biopsy. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Educate the client about cirrhosis and its progression"}, {"id": "b", "t": "Review pre-procedure coagulation studies"}, {"id": "c", "t": "Turn the client on the right side to provide pressure at the site"}, {"id": "d", "t": "Perform a detailed assessment"}], "correct": "c", "rationale": "The correct priority is to provide pressure at the site to prevent bleeding, as this is a circulation issue and individuals with liver disease are at higher risk of significant bleeding as a result of decreased production of clotting factors.", "whyNot": {"a": "The results of the biopsy have not returned, so teaching about cirrhosis is premature and teaching is not a priority at this time.", "b": "This is important to do prior to a liver biopsy in a client with liver disease who may be at increased risk of bleeding.", "d": "Performing a detailed assessment is important, but it is not the immediate priority."}, "keyConcept": "When determining priority of various nursing tasks, those tasks that are a threat to the client's immediate survival or safety should take precedence. These include airway, breathing, and circulation. The liver is highly vascular and clients with liver disease may be at greater risk of bleeding abnormally due to reduced production of clotting factors."}, {"id": 10868, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with ulcerative colitis. This disorder is related to the function of which of the following in response to stress?", "choices": [{"id": "a", "t": "Sympathetic nervous system affecting the pancreas"}, {"id": "b", "t": "Parasympathetic nervous system affecting the adrenal glands"}, {"id": "c", "t": "Hypothalamus affecting peristalsis"}, {"id": "d", "t": "Thyroid gland affecting metabolism"}], "correct": "b", "rationale": "‘i Ulcerative colitis is a form of inflammatory bowel disease. Ulcerative colitis generally affects only the rectum and large intestine, with OB | inflammation of the bowel mucosa and submucosa. Crohn's disease, in contrast, affects the entire bowel wall, and lesions can occur anywhere in the Gl tract. Inflammatory bowel disease is characterized by periods of remission and exacerbation. Exacerbation can be c | triggered by environmental factors that include stress. Emotions affect the parasympathetic nervous system, which is a branch of the D | autonomic nervous system, by increasing motility of the gastrointestinal tract and secretions within the Gl tract. During an exacerbation, clients experience abdominal cramping, urgency, diarrhea, and rectal bleeding.", "whyNot": {"a": "The sympathetic nervous system decreases GI motility.", "c": "The hypothalamus does not directly affect peristalsis.", "d": "The thyroid gland and its impact on metabolism do not affect peristalsis within the Gl tract."}, "keyConcept": "Stimulation of the parasympathetic nervous system increases bowel motility. During periods of stress, this can contribute to an exacerbation of symptoms in individuals with inflammatory bowel disease (ulcerative colitis or Crohn's disease.)"}, {"id": 10869, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "prompted these symptoms? O A. Wound site infection O B. Extension of the esophageal tumor into the lungs O C. Fluid leaking into the mediastinum O D. Feeding intolerance", "choices": [{"id": "a", "t": "Wound site infection"}, {"id": "b", "t": "Extension of the esophageal tumor into the lungs"}, {"id": "c", "t": "Fluid leaking into the mediastinum"}, {"id": "d", "t": "Feeding intolerance"}], "correct": "c", "rationale": "‘i After resection of all or a portion of the esophagus for esophageal cancer, the client will receive parenteral nutrition or enteral feeding. B I Before the initiation of oral fluids, a swallowing study will be performed. Oral fluids should be gradually introduced with water at 30-60 mL hourly, progressing to small, frequent meals. Complications that may occur include regurgitation and leakage of fluid or feeding into the O€ | mediastinum. The nurse should watch for pain, dyspnea, and fever, which occur with leakage. D Hi", "whyNot": {"a": "Dyspnea is not a common characteristic of wound site infections.", "b": "The most likely cause of these symptoms is leakage into the mediastinum.", "d": "Intolerance to feeding could cause gastrointestinal symptoms, including nausea or abdominal pain, but a fever and chest pain are not"}, "keyConcept": "Esophageal procedures or trauma can result in leakage of digestive and other fluids into the mediastinum, causing mediastinitis (infection or inflammation.) Symptoms can include fever, chest pain, and dyspnea, possible signs of leakage."}, {"id": 10870, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is preparing to remove a nasogastric tube. What instruction should the nurse give to the client?", "choices": [{"id": "a", "t": "Say something"}, {"id": "b", "t": "Lean forward"}, {"id": "c", "t": "Breathe normally"}, {"id": "d", "t": "Take a deep breath and hold it"}], "correct": "d", "rationale": ", thereby preventing accidental aspiration of the gastric contents. B | ue fo", "whyNot": {"a": "The client should not speak while the nasogastric tube is being removed; this could increase the risk of aspiration. e@", "b": "The client should be in the semi-Fowlers position.", "c": "The client should hold her breath during the procedure."}, "keyConcept": "After receiving an order for removal of an NG tube, the nurse should explain the procedure to the client and assist the client to the semi-"}, {"id": 10871, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "dehydration? Oa Sodium 140 mEq/L O B. Potassium 4.0 mEq/dL O C. Hemoglobin 20 g/dL O D. Iron 100 mcg/dL", "choices": [{"id": "b", "t": "The nurse should identify that this potassium level is within the expected reference range of 3.5 to 5.0 mEq/L. Severe dehydration leads to"}, {"id": "c", "t": "A i 10% Moderate The nurse should identify that this hemoglobin level is above the expected reference range of 12 to 16 g/dL for female clients and 14 to 18 B I Ee g/dL for male clients."}, {"id": "d", "t": "The nurse should identify that this iron level is within the expected reference range of 60 to 160 mcg/dL for female clients and 80 to 180"}], "correct": "c", "rationale": "A i 10% Moderate The nurse should identify that this hemoglobin level is above the expected reference range of 12 to 16 g/dL for female clients and 14 to 18 B I Ee g/dL for male clients. This level is an indication of severe dehydration. Dehydration depletes the client's extracellular fluid, causing the RBCs to remain the same while the total blood volume decreases. The percentage of total blood volume that is taken up by the RBCs increases, ec Fe 74% causing the hemoglobin to increase. This is known as hemoconcentration. Therefore, the nurse should report this laboratory value to the D i 10% provider.", "whyNot": {"b": "The nurse should identify that this potassium level is within the expected reference range of 3.5 to 5.0 mEq/L. Severe dehydration leads to", "d": "The nurse should identify that this iron level is within the expected reference range of 60 to 160 mcg/dL for female clients and 80 to 180"}, "keyConcept": "Clinical dehydration is common in clients who experience severe diarrhea. Clients with this condition are not able to replace their fluid output with the necessary amount of fluid intake. Laboratory values, including sodium, potassium, and hemoglobin are used as indicators to determine the extent of the client's dehydration. An increased hemoglobin level signifies severe dehydration. Dehydration depletes the client's extracellular fluid, causing no change in the number of RBCs, thus decreasing total blood volume. The percentage of total blood volume that is taken up by the RBCs increases, leading to an increase in the client's hemoglobin level. The nurse should also assess the client for physical manifestations of dehydration. These include: + Confusion Lethargy +» Tachycardia + Orthostatic hypotension + Poor skin turgor"}, {"id": 10872, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing discharge education to a client with a new PEG (percutaneous endoscopic gastrostomy) tube. Which of the following statements by the client indicates that more teaching is required?", "choices": [{"id": "a", "t": "“I will perform skin care for my tube every day.”"}, {"id": "b", "t": "“I need to use a small piece of tape to anchor the tube to my skin.”"}, {"id": "c", "t": "“When remove the dressing, will carefully cut it away with a pair of scissors.”"}, {"id": "d", "t": "“I will wash the exit site with soap and water and pat dry.”"}], "correct": "c", "rationale": "A | | 9% Moderate The client should be taught to gently remove the dressing with his/her fingers and should not use scissors to cut away the tape. Use of . oi 14% Nasogastric tube a © o 2 ° s a = a < Nasoduodenal tube", "whyNot": {"a": "This statement indicates understanding. The client monitor the tube and care for the skin on a daily basis to prevent infection.", "b": "The tube is initially taped or sutured to anchor it to the skin, until healing has occurred. There is an internal and an external bumper, and", "d": "This statement indicates understanding. The client should wash the skin with mild soap and water and pat dry to avoid irritating the site."}, "keyConcept": "A client with a PEG tube should check the length daily, from the end of the tube to the insertion site. The client should also check to be certain the bumper fits snugly against the skin; it should not fit too tightly. The client should clean the skin around the PEG tube at least once a day, checking for redness, swelling, or drainage from the stoma. Turning the tube gently each will decrease pressure on the skin beneath the bumper, reducing the risk of breakdown and infection. The nurse should also advise the client to keep the skin around the tube dry, to prevent irritation. Topical ointments should be applied if prescribed by the provider."}, {"id": 10873, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Which of the following measures should be implemented promptly after a client’s nasogastric (NG) tube has been removed?", "choices": [{"id": "a", "t": "Provide the client with oral hygiene"}, {"id": "b", "t": "Offer the client liquids to drink"}, {"id": "c", "t": "Encourage the client to cough and deep breathe"}, {"id": "d", "t": "Auscultate the client’s bowel sounds"}], "correct": "a", "rationale": "on 28% Hard The first action is to provide mouth care. Then, if appropriate and no longer on oral restrictions, oral liquids should be allowed. B I Ee", "whyNot": {"b": "The client may be offered liquids to drink if he is not on oral restrictions and the healthcare provider has allowed it, but this is not the first D || 29%", "c": "Coughing and deep breathing are performed to reduce the chance of atelectasis, but these are not the first actions done after removing an", "d": "While it is important to auscultate the client’s bowel sounds, it is not the first action to perform after removing an NG tube."}, "keyConcept": "An NG tube should be removed when it is no longer required. Before removing an NG tube, verify the healthcare provider's orders. If the NG tube was ordered to remove gastric content, the provider's order may request a “trial” by clamping the tube for a number of hours to see if the client tolerates its removal. During the trial, the client should not experience any nausea, vomiting, or abdominal distension."}, {"id": 10874, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is reviewing the laboratory values of a client who has severe hyperemesis gravidarum. Which of the following laboratory findings should the nurse identify as a manifestation of this condition?", "choices": [{"id": "a", "t": "Hemoglobin 11.2 g/dL"}, {"id": "b", "t": "Urine ketones present"}, {"id": "c", "t": "Potassium 4.0 mEq/L © p. Platelets 98,000/mm3"}], "correct": "b", "rationale": "A Hi 15% Moderate The presence of ketones in the urine is associated with the breakdown of proteins and fats that occurs in a client who has hyperemesis OB a oa gravidarum. The breakdown of fat stores provides the client with more energy. ° ci 12%", "whyNot": {"a": "This value is within the expected reference range for a pregnant client. A hemoglobin value provides a rapid indirect measure of the", "c": "Potassium levels are expected to be decreased in a client who has hyperemesis gravidarum due to excessive vomiting. This finding is"}, "keyConcept": "Hyperemesis gravidarum is excessive nausea and vomiting that occurs during pregnancy, which causes an imbalance of nutrition and electrolytes. Clients who have hyperemesis gravidarum are unable to digest nutritious foods and the body will start using fat stores as a fuel. This results in ketosis, causing the client's urine to have high levels of ketones present. Manifestations of hyperemesis gravidarum include weight loss, dehydration, nausea, vomiting, dry mucous membranes, and decrease skin turgor. Laboratory results might show manifestations of dehydration, such as an altered hematocrit, electrolyte imbalances, and the presence of ketonuria. Nursing measures are focused on restoring fluid balance: observing for signs of metabolic acidosis due to hypovolemia or metabolic alkalosis due to loss of gastric secretions; providing oral care; and providing a quiet restful environment that is free from odors."}, {"id": 10875, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "@ @ %& Viraln. 8s Record Mi Inbox( ™ Inbox- [E} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr @® ATITE € > @G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE © Newc) NC x + v Qa * ws * © Cb Finish update : { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Blood in the stool"}, {"id": "b", "t": "Food intolerances"}, {"id": "c", "t": "Complaints of nausea"}, {"id": "d", "t": "Hourly urine output"}], "correct": "a", "rationale": "Erosion of blood vessels may lead to hemorrhage, a life-threatening situation further complicated by decreased prothrombin production, which occurs with cirrhosis.", "whyNot": {"b": "Food intolerances are not the most important assessment in this situation.", "c": "Nausea may develop in this client but it is not the most important assessment at this point.", "d": "The most important assessment in this client is blood in the stool, not hourly urine output."}, "keyConcept": "Clients with liver disease or cirrhosis are at risk for multiple medical complications including bleeding from the esophagus or stomach, ascites (fluid buildup in the abdomen), encephalopathy, edema, bacterial infections of the peritoneum (gut lining), and liver cancer. Normal vs. cirrhotic liver Normal liver Cirrhotic liver"}, {"id": 10876, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is evaluating a client's intake and output. Which of the following findings should the nurse report to the provider?", "choices": [{"id": "a", "t": "The client did not have a bowel movement in the past 24 hr."}, {"id": "b", "t": "The client had a urine output of 50 mL in the past 2 hr."}, {"id": "c", "t": "The client had an oral intake of 360 mL for breakfast."}, {"id": "d", "t": "The client experienced a weight loss of 0.8 kg (1.8 lb) in the past 24 hr"}], "correct": "b", "rationale": "A client who has had less than 60 mL of output in 2 hr is in need of further assessment. The nurse should report this finding to the provider.", "whyNot": {"a": "A client who has had less than three bowel movements in one week is considered to have constipation. The nurse does not need to report", "c": "An oral intake of 360 mL for a meal indicates the client is consuming an adequate nutritional intake. The nurse should continue to monitor", "d": "The nurse should report a weight loss or weight gain greater than 1 kg (2.2 lb) to the provider. This would equate to 1 L of fluid either lost"}, "keyConcept": "The nurse is responsible for evaluating a client's intake and output and reporting abnormal findings to the provider. The nurse should identify those findings that fall outside the accepted parameters, report these findings, and intervene as needed."}, {"id": 10877, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a teenage client with a new colostomy. What is the most appropriate response by the nurse when the client refuses to look at the colostomy?", "choices": [{"id": "a", "t": "“We will teach your mother how to take care of your colostomy before you leave the hospital.”"}, {"id": "b", "t": "“I know how you feel. A colostomy makes you feel ugly.”"}, {"id": "c", "t": "“You are being discharged tomorrow. You need to learn how to take care of your colostomy before you are discharged.”"}, {"id": "d", "t": "“Tell me about what you are feeling right now. What is upsetting you?”"}], "correct": "d", "rationale": ". This is particularly true of . The most therapeutic comment for the nurse to make is to ask the client to talk about her feelings. By describing the upsetting thoughts and emotions, the teenager may begin to work through negative feelings. The nurse c | 2% should NOT assume that she knows how the teenager feels but should give her the opportunity to discuss her concerns. @D Fs 96%", "whyNot": {"a": "The teen should learn how to take care of her colostomy; her mother should not do it for her.", "b": "The nurse should not assume that she knows how the girl feels.", "c": "This sounds like more of a warning from the nurse than an opportunity to discuss the situation with the girl."}, "keyConcept": "The creation of a stoma leads to an alteration in body image as the client becomes aware of the change in their appearance and function. The individual will face physical, mental, emotional, social, and sexual change, as change in one domain causes change in the others. Rehabilitation after ostomy surgery is directed towards a return to a normal way of living. This process requires ongoing adaptation to the disease process, treatment, and medical and nursing care in the hospital and community. The nurse's understanding of the actual and potential problems associated with an alteration in body image enables the nurse to assess the meaning of the alteration in body image for the client and to provide counseling."}, {"id": 10878, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is teaching a group of clients about stomatitis related to chemotherapy. Which of the following statements by a client indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Iwill try chewing larger pieces of food.\""}, {"id": "b", "t": "\"I will eat scrambled eggs and bananas for breakfast.\""}, {"id": "c", "t": "\"I will consume foods that are hot.\" O D.\"I will add more citrus foods to my diet.\""}], "correct": "b", "rationale": "al 3% Easy Foods such as scrambled eggs and bananas are nonirritating and soft; therefore, they might be more easily tolerated by a client who has OB rT 84% stomatitis cf 5%", "whyNot": {"a": "The nurse should encourage the client to cut food into small pieces to reduce irritation to mucous membranes.", "c": "Foods that are room temperature or cold are better for a client who has stomatitis"}, "keyConcept": "Chemotherapy can cause adverse effects to the gastrointestinal tract, including anorexia, nausea and vomiting, and stomatitis. Nutritional recommendations to manage stomatitis include eating cold foods, consuming soft or nonirritating foods, and adding gravies or sauces to increase fluid content."}, {"id": 10879, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Which of the following items should be at the bedside before a nurse performs gastric lavage?", "choices": [{"id": "a", "t": "An endotracheal tube with stylet"}, {"id": "b", "t": "Asuction source and suction device"}, {"id": "c", "t": "Enteral formula preparation"}, {"id": "d", "t": "Medication to instill into the tube"}], "correct": "b", "rationale": "When performing gastric lavage, the nurse inserts a tube into the client’s mouth or nose and passes it into the stomach. The tube is then used to irrigate the stomach and remove excess stomach contents. A suction kit must be available at bedside in case the client gags and vomits during the procedure.", "whyNot": {"a": "An endotracheal tube and stylet are needed when a client is in respiratory failure and requires an airway for mechanical ventilation.", "c": "Formula feeding is not performed during gastric lavage.", "d": "Medication is not administered during gastric lavage."}, "keyConcept": "Gastric lavage is used to decontaminate the stomach after ingestion of a toxin. It decreases the amount of toxin that is absorbed by the client. Gastric lavage should only be performed if the client presents within one to two hours of ingestion and if suspected to have ingested a quantity of a poison likely to cause toxicity. When gastric decontamination is indicated, activated charcoal is more commonly administered than performance of gastric lavage. Activated charcoal binds toxins in the stomach to reduce absorption."}, {"id": 10880, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "@ @ %& Viraln. 8s Record Mi Inbox( ™ Inbox- [E} Untitle: Untitle’ €@ Google @ TEASP Online & MarkK @ Micros (eeinaenuriaelicr @® ATITE € > G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Keep the infant in a semi-sitting position, especially after feedings"}, {"id": "b", "t": "Make certain the infant takes at least 8 oz of formula at each feeding"}, {"id": "c", "t": "Never use a pacifier"}, {"id": "d", "t": "Keep the infant prone following feedings"}], "correct": "a", "rationale": "Chalasia is an incompetent cardiac sphincter. This allows gastric contents to flow back into the esophagus, which leads to regurgitation. Keeping the infant upright uses gravity to help keep stomach contents out of the esophagus and also limits pressure on the cardiac sphincter.", "whyNot": {"b": "8 oz of formula at a time is too much for a week-old infant and would likely induce regurgitation.", "c": "This would have no effect on chalasia.", "d": "This would promote regurgitation."}, "keyConcept": "Chalasia refers to the relaxation of a ring of muscle (such as the cardiac sphincter of the esophagus) surrounding a bodily opening. In the case of chalasia affecting the esophageal sphincter, symptoms of gastric reflux will occur. Chalasia is often identified in young children, and is related to congenital incompetence of the lower esophageal sphincter, allowing unrestricted reflux of gastric contents. This contrasts with achalasia, which refers to restriction at the gastroesphageal junction that limits esophageal emptying."}, {"id": 10881, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is administering prescribed vasopressin to a client with diabetes insipidus. The nurse will monitor the client for which of the following adverse effects?", "choices": [{"id": "a", "t": "Rash"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Chest pain"}, {"id": "d", "t": "Sore throat"}], "correct": "c", "rationale": "Vasopressin (Pitressin) is used to treat central diabetes insipidus and gastrointestinal hemorrhage from esophageal varices. It is an analog of antidiuretic hormone and causes vasoconstriction and reabsorption of water in the collection duct of the kidney. Adverse effects include hypertension, myocardial infarction, TIA, stroke, bowel ischemia, and dysrhythmia. The nurse should monitor the client for signs of toxicity, which include angina (chest pain). Pitressin is contraindicated in ischemic heart disease and is not indicated in clients with nephrogenic diabetes insipidus. Alcohol, lithium, phenytoin, and epinephrine may increase the effects of vasopressin.", "whyNot": {"a": "Arash is nota typical adverse effect of vasopressin.", "b": "Diarrhea is not a common adverse effect, nausea is though.", "d": "Asore throat is not an adverse effect associated with vasopressin."}, "keyConcept": "Vasopressin (Pitressin) is a synthetic analog of antidiuretic hormone, which is released by the posterior pituitary gland. Vasopressin is used to treat GI hemorrhage from esophageal varices and central diabetes insipidus. Adverse effects include hypertension, myocardial infarction, TIA, stroke, bowel ischemia, and cardiac arrhythmias."}, {"id": 10882, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Aslightly overweight client is to be discharged from the hospital after a cholecystectomy. What is most important for the nurse to include in teaching the client about nutrition?", "choices": [{"id": "a", "t": "Alist of fatty foods that may be included in the diet"}, {"id": "b", "t": "Fatty foods may not be tolerated for several weeks"}, {"id": "c", "t": "The importance of a low-calorie diet to promote weight reduction"}, {"id": "d", "t": "Encouragement for the client to join a weight reduction program in the community"}], "correct": "b", "rationale": "Bile, which aids in fat digestion, is not as concentrated as before surgery. Once the body adapts to the absence of the gallbladder the client should be able to tolerate a regular diet that contains fat. Initially, the client should avoid fatty foods.", "whyNot": {"a": "The client may need to avoid fatty foods entirely in the first few weeks following surgery until his body adapts to the absence of the", "c": "Adiet for weight reduction may be helpful for this client, but the client needs to first know that he should avoid fats in the weeks following", "d": "The client may benefit from joining a weight reduction program, but the nurse must first teach him to avoid excess fat in his diet."}, "keyConcept": "After cholecystectomy, the nurse should advise the client to eat a nutritious diet without a lot of excess fat or spices; otherwise, a special diet is not necessary. Adequate fluid intake should be encouraged for all clients, but this is not specifically related to the surgery. The nurse should advise the client to call the healthcare provider if the client develops jaundice, fever, chills, redness, swelling, increasing pain, pus, or a foul smell at the incision site; dark or rust-colored urine; clay-colored stools; increased abdominal pain; rectal bleeding; and leg swelling or shortness of breath."}, {"id": 10883, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing discharge instructions to a client with a new ileostomy. Which of the following statements indicates that the client understands the discharge instructions? O A.| should be able to resume weight lifting in 2 weeks O B. | can return to work in 2 weeks O C. | need to drink at least 3,000 mL a day of fluid O D. 1 will need to avoid getting my stoma wet while bathing", "choices": [{"id": "a", "t": "5%"}, {"id": "b", "t": "The client will not resume working as soon as 2 weeks after surgery."}, {"id": "c", "t": ", the client needs to drink at least 3,000 mL/day."}, {"id": "d", "t": "Water does not harm the stoma, so the client does not need to worry about getting it wet."}], "correct": "c", "rationale": ", the client needs to drink at least 3,000 mL/day. 5 15%", "whyNot": {"a": "Heavy lifting should be avoided and the surgeon will indicate when the client can participate in sports again. D 31%", "b": "The client will not resume working as soon as 2 weeks after surgery.", "d": "Water does not harm the stoma, so the client does not need to worry about getting it wet."}, "keyConcept": "A client with an ileostomy should be instructed to maintain adequate daily fluid intake and to recognize the signs of fluid or electrolyte depletion. Signs of dehydration include dry mouth, dry skin, thick stool, decreased urination, and light-headedness. The client should be instructed to increase fluid intake if these signs occur. The client should notify the healthcare provider if dehydration signs and symptoms persist."}, {"id": 10884, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Aclinician is observed drinking alcohol at work. Regarding this colleague’s behavior, which of the following is the most appropriate action?", "choices": [{"id": "a", "t": "Ask the clinician to stop drinking at work"}, {"id": "b", "t": "Determine if he is sober"}, {"id": "c", "t": "Ask the clinician to leave and get treatment"}, {"id": "d", "t": "Write a letter to the medical board"}], "correct": "c", "rationale": "This is the most appropriate action for the colleague’s behavior.", "whyNot": {"a": "The colleague is impaired and should not be allowed to continue working. Asking them to stop does not change the fact they may be", "b": "Sometimes, sobriety is hard to determine.", "d": "Writing a letter will not promote client safety right now."}, "keyConcept": "Impaired staff members should not operate in the workplace. All medical workers share the responsibility of ensuring competent care is given. Accountability for practice involves a commitment to offering quality care to all clients."}, {"id": 10885, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "following reasons? O A. Caffeine increases acid production in the stomach. O B. Caffeine causes distention of the stomach. O C. Caffeine relaxes the lower esophageal sphincter. O D. Caffeine decreases production of saliva.", "choices": [{"id": "a", "t": "Caffeine increases acid production in the stomach."}, {"id": "b", "t": "Caffeine causes distention of the stomach."}, {"id": "c", "t": "Caffeine relaxes the lower esophageal sphincter."}, {"id": "d", "t": "Caffeine decreases production of saliva."}], "correct": "c", "rationale": "Correct Answer: C. Caffeine relaxes the lower esophageal sphincter. A —— B When providing instructions about management of GERD, a nurse should be able to explain the rationale for dietary and lifestyle changes. ec | Smoking, caffeine, alcohol, and fatty foods relax the lower esophageal sphincter muscle, allowing reflux of stomach contents and gastric my | acid into the esophagus. Fatty foods stimulate secretion of gastric enzymes. Increased intra-abdominal pressure due to obesity, pregnancy, or tight clothing also facilitates reflux. Clients should be advised to avoid tight or constricting clothing. The nurse should discuss approaches to weight loss with overweight clients who have GERD. Other recommendations for management of GERD include elevation of the head of the bed 4-6 inches with bricks or blocks, to promote esophageal drainage by gravity.", "whyNot": {"a": "The nurse should recommend avoiding milk and late night snacks or meals before bedtime since this stimulates secretion of gastric acid.", "b": "The nurse should advise the client to avoid large meals and to consume adequate amounts of fluids between small, frequent meals in", "d": "When instructing the client about dietary modifications for management of GERD, the nurse should encourage the client to chew gum or"}, "keyConcept": "Gastroesophageal reflux disease is characterized by reflux of acidic gastric contents into the esophagus, causing heartburn, epigastric pain, and a sour taste. Clients should avoid tobacco and consumption of fatty foods, alcohol, and caffeine-containing beverages, which relax the lower esophageal sphincter. Increased intra-abdominal pressure facilitates reflux, so clients should avoid constricting clothing, eat frequent small meals instead of 2 or 3 large meals, and, if overweight, should lose weight. Eating meals or snacks should be avoided for 2-3 hours before bedtime. Elevation of the head of the bed promotes drainage by gravity and can reduce nocturnal reflux symptoms."}, {"id": 10886, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is preparing a client for a nuclear imaging procedure for suspected esophageal cancer. Which of the following statements should the nurse make about nuclear imaging procedures?", "choices": [{"id": "a", "t": "\"This procedure will identify your liver enzyme levels.\""}, {"id": "b", "t": "\"You will be given an injection of a radioactive substance.\""}, {"id": "c", "t": "\"An endoscope tube will be inserted through your mouth.\""}, {"id": "d", "t": "\"Fluid will be aspirated with a needle.\""}], "correct": "b", "rationale": "Nuclear imaging involves the administration of an oral or IV radioactive tracer to identify cancerous tissue.", "whyNot": {"a": "Liver function tests involve the identification of altered liver enzymes, which can be present in a client who has cancer. However, liver", "c": "Endoscopy permits visualization inside the body and is not a form of nuclear imaging.", "d": "Aneedle biopsy is performed to aspirate fluid and tissue samples for cancer cells. It is not a form of nuclear imaging."}, "keyConcept": "Nuclear imaging involves the administration of an oral or IV radioactive isotope to identify cancerous tissue or tumors. The nurse should explain that the client will receive the radioactive isotope 4 to 6 hr prior to the procedure. Clients will need to increase oral fluids to increase urinary excretion of the radioactive isotope."}, {"id": 10887, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "does the nurse understand that this client is experiencing?", "choices": [{"id": "a", "t": "Inadequate coping"}, {"id": "b", "t": "Disturbed thought patterns"}, {"id": "c", "t": "Social isolation"}, {"id": "d", "t": "Sleep disorder"}], "correct": "a", "rationale": "This client is experiencing difficulty coping with a disease that she feels is controlling her life. Her thought patterns are not disturbed and B I Ee there is no evidence that she has a sleep disorder. She also is not suffering from social isolation at this time. Any of these problems might develop over time for the client without thoughtful intervention by the nurse and medical team. c | | 18% D 0%", "whyNot": {"b": "The client is not experiencing disturbed thought patterns; she is trying to manage a very difficult aspect of her disease.", "c": "The client is not necessarily experiencing social isolation; she feels she cannot leave the house because of her disease, not because of", "d": "The client is not demonstrating any signs of a sleep disorder."}, "keyConcept": "CD is a chronic, inflammatory, autoimmune disorder of the gastrointestinal tract that has a significant impact on clients’ physical and emotional well-being. Crohn's disease is accompanied by debilitating physical symptoms, which affects the client's overall well-being and quality of life. Symptoms include diarrhea, abdominal pain, weight loss, and fatigue. Crohn's disease is characterized by cycles of active flares and remission; complications such as abscesses, strictures, and fistulas can lead to hospitalization and surgery in clients with moderate to severe disease. Inadequate coping skills may lead to verbalization of inability to cope, discouragement, anxiety, preoccupation with self, emotional tension, poor self-esteem, depression and dependency. The nurse should first assess the client's situation and assist the client to identify ineffective coping behaviors and consequences and to acknowledge his/her coping abilities."}, {"id": 10888, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Ahealthcare provider in the emergency department has ordered gastric lavage for a client with a drug overdose. Which of the following nursing actions is appropriate?", "choices": [{"id": "a", "t": "Place the client in the Trendelenburg position during lavage."}, {"id": "b", "t": "Use a small-bore nasogastric tube for lavage."}, {"id": "c", "t": "Lavage is most effective after 1-2 hours."}, {"id": "d", "t": "Suction supplies should be available at the bedside."}], "correct": "d", "rationale": "Gastric lavage, when performed for decontamination of the stomach, is performed as soon as possible after a potentially fatal overdose. An Cc I orogastric tube is used to remove any ingested toxins and to irrigate the stomach. There is a high risk of associated complications, so gastric ep fF lavage is only performed within an hour of potentially lethal overdose. Gastric lavage was also performed routinely in the past in clients with hematochezia, but it is not a sensitive test to distinguish upper from lower Gl bleeding. Complications of gastric lavage include aspiration, perforation of the GI tract, and arrhythmia. Suction supplies should be placed at bedside in case of aspiration. Supplies should also be available for endotracheal intubation in the event that the client develops respiratory distress. Activated charcoal is more commonly used to decontaminate the Gl tract, with sorbitol to aid in evacuation of the bowel. Activated charcoal is ineffective for some toxins, including alcohol, lithium, iron.", "whyNot": {"a": "Gastric lavage is associated with a risk of aspiration. The client should be placed on the side, and the head of the bed should be elevated", "b": "A large-bore orogastric tube is used for gastric lavage so that ingested toxins such as pills can be removed and the stomach can be", "c": "Gastric lavage is ineffective after more than an hour has elapsed from the ingestion. Although it is important to decompress the stomach,"}, "keyConcept": "Contraindications to gastric lavage for decontamination of the GI tract in overdose include ingestion of a caustic agent, hydrocarbon ingestion, and unprotected airway. The procedure is reserved primarily for potentially lethal overdoses within an hour of ingestion of the toxic product."}, {"id": 10889, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "the following to avoid a frequent complication of the procedure? Oa vitamin B6 O B. Vitamin E O vitamin B12 O D. Intrinsic factor", "choices": [{"id": "a", "t": "Vitamin B6 is not routinely supplemented after gastric bypass."}, {"id": "b", "t": "3%"}, {"id": "c", "t": "Moderate Correct Answer: C."}, {"id": "d", "t": "The decrease in intrinsic factor is responsible for vitamin B12 malabsorption, but vitamin B12 supplements are administered, not intrinsic"}], "correct": "c", "rationale": "Moderate Correct Answer: C. Vitamin B12 A | ue 2 types of bariatric (weight-loss) surgical procedures: restrictive surgery and malabsorption surgery. Restrictive surgeries include ec | 71% gastric band surgery and sleeve gastrectomy, both performed laparoscopically. Roux-en-Y gastric bypass restricts the stomach volume and my . Toe bypasses most of the stomach and duodenum. As a result of malabsorption caused by bypass of parts of the GI tract, the client will require supplements. These include vitamin A, vitamin B1 (thiamine), folate, vitamin B12, vitamin E, and vitamin K. Minerals that require supplementation include iron, selenium, and zinc. B12 deficiency occurs because of the reduced number of parietal cells, which produce gastric acid necessary to cleave vitamin B12 from protein in the diet, and reduced levels of intrinsic factor. Vitamin B12 deficiency is characterized by pernicious anemia and peripheral neuropathy and is common within the first year of surgery if supplementation isn’t administered. a = o B f= 4 ° = a = g <", "whyNot": {"a": "Vitamin B6 is not routinely supplemented after gastric bypass.", "b": "Vitamin E supplementation through an adult multivitamin is required.", "d": "The decrease in intrinsic factor is responsible for vitamin B12 malabsorption, but vitamin B12 supplements are administered, not intrinsic"}, "keyConcept": "Roux-en-Y gastric bypass surgery results in restriction of gastric volume and malabsorption through bypass of most of the stomach and duodenum. Without dietary sources of some vitamins, deficiencies will occur. Clients are most likely to require the fat-soluble vitamins A, E, and kK; and water soluble B vitamins, thiamine, folate, and B12. Mineral supplementation should include iron , selenium, and zinc."}, {"id": 10890, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is scheduled for a screening colonoscopy. Which of the following is true about cancer screening?", "choices": [{"id": "a", "t": "Colonoscopy is recommended every 10 years after age 45"}, {"id": "b", "t": "Annual PSA (prostate specific antigen) is recommended to screen for prostate cancer after age 50"}, {"id": "c", "t": "Mammography is recommended every 5 years after age 60"}, {"id": "d", "t": "Pap smear should be scheduled every 4 years for women over 18"}], "correct": "a", "rationale": "@A 53% Hard B 38% 4% 5% Health promotion and prevention of cancer are best achieved through health education and screening. The American Cancer Society has provided guidelines for cancer screening for different ages. The seven warning signals of cancer are changes in bowel or bladder habits, a sore that does not heal, unusual bleeding or discharge, thickening or lump in the breast, indigestion or difficulty swallowing, obvious change c in wart or mole, and nagging cough or hoarseness. Options for cancer screening for colon and rectal cancer include a sigmoidoscopy every 5 D years after age 45 (unless a colonoscopy is substituted at any time), with colonoscopy every 10 years after age 45.", "whyNot": {"b": "The United States Preventive Services Task Force recommends against use of PSA for screening for prostate cancer, except for selective", "c": "Screening for breast cancer involves clinical breast examination every 3 years from ages 20 to 39, and an annual mammography after age", "d": "Cancer screening for cervical cancer includes a Pap smear test every 3 years for women over age 21."}, "keyConcept": "Options for screening for colon cancer include annual fecal occult blood test, fecal immunochemical test; multitargeted stool DNA test; flexible signoidoscopy, CT colonography, and colonoscopy."}, {"id": 10891, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "provider? O A. Joint pain O B. Diarrhea O C. Rash O D. Excessive sweating", "choices": [{"id": "a", "t": "Joint pain"}, {"id": "b", "t": "Diarrhea"}, {"id": "c", "t": "Rash"}, {"id": "d", "t": "Excessive sweating"}], "correct": "c", "rationale": "A Hi 15% Moderate Metronidazole may cause negative side effects with use, some of which should be reported to a health care provider right away to prevent B | oR further complications. The client should notify the provider if a rash occurs, as Stevens-Johnson syndrome may occur with this medication. °", "whyNot": {"a": "Joint pain is not associated with metronidazole use.", "b": "Diarrhea, while uncomfortable and a condition that could lead to further complications, can be a side effect associated with", "d": "Excessive sweating has not been associated with metronidazole use."}, "keyConcept": "Side effects of metronidazole include dizziness, headache, aseptic meningitis (IV), encephalopathy (IV), optic neuropathy, abdominal pain, anorexia, nausea, diarrhea, dry mouth, furry tongue, glossitis, unpleasant taste, vomiting, Stevens-Johnson Syndrome, rash, burning and mild dryness of the skin, skin irritation, redness, leukopenia, and peripheral neuropathy. The client should notify the healthcare provider if rash occurs. The nurse should caution the client to avoid intake of alcoholic beverages or preparations containing alcohol during and for at least 3 days after treatment with metronidazole, including vaginal gel, since this may cause a disulfiram (Antabuse) like reaction."}, {"id": 10892, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "most likely to give an accurate diagnosis?", "choices": [{"id": "a", "t": "Pancreatic ultrasound"}, {"id": "b", "t": "CT scan"}, {"id": "c", "t": "Serum amylase"}, {"id": "d", "t": "Endoscopic ultrasound with fine-needle aspiration biopsy"}], "correct": "d", "rationale": "The pancreas is a mixed gland composed of endocrine and exocrine cells. It lies behind the stomach, extending from the duodenum to the c | spleen. It is divided into three portions, known as the head, body, and tail. The exocrine cells of the pancreas secrete digestive enzymes, e@D FY including amylase, lipase, trypsin, and chymotrypsin. The endocrine cells produce glucagon and insulin. Pancreatic tumors can obstruct the biliary ducts, causing obstructive jaundice. Although an ultrasound is usually the first test performed for individuals with epigastric pain, weight loss, and/or jaundice, it is not as sensitive as endoscopic retrograde cholangiopancreatography (ERCP) or endoscopic ultrasound (EUS), particularly for small tumors. An advantage of EUS is the ability to obtain a fine-needle aspirate biopsy. ERCP allows sampling of cytology brushings. Endoscopic procedures are invasive, so a formal, signed consent form is required. The client must fast prior to an endoscopic procedure and dentures should be removed and placed in a denture cup. Endoscopic examinations are performed under sedation, to relax the client and facilitate passage of the endoscope.", "whyNot": {"a": "Apancreatic ultrasound is less sensitive than ERCP, but it is less expensive and less invasive than ERCP and can identify dilation of the", "b": "ACT scan does not allow biopsy confirmation of a malignancy.", "c": "Serum amylase is released when pancreatic cells are inflamed; it is used in the diagnosis of pancreatitis."}, "keyConcept": "Endoscopic ultrasound or endoscopic retrograde cholangiopancreatography are sensitive and specific tests for diagnosis of a malignancy of the pancreas. They allow biopsy (EUS) or collection of cytology brushings. Large pancreatic tumors can be identified by transabdominal ultrasound, but more invasive diagnostic procedures are necessary to obtain tissue or cell samples. A signed consent form is required before endoscopic procedures and the client should be fasting."}, {"id": 10893, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with chronic hepatitis C and cirrhosis who was admitted for hepatic encephalopathy. Which of the following does the nurse expect when assessing the client?", "choices": [{"id": "a", "t": "Hyperactive reflexes"}, {"id": "b", "t": "Agitation and restlessness"}, {"id": "c", "t": "Asterixis"}, {"id": "d", "t": "Enlarged liver"}], "correct": "c", "rationale": "Asterixis is a sign of hepatic encephalopathy in individuals with cirrhosis of the liver. The liver converts ammonia to urea, so replacement of hepatocytes with scar tissue in cirrhosis results in the buildup of ammonia in the blood stream. Asterixis is characterized by a flapping movement of the wrists and fingers in a coarse tremor caused by brief relaxation of wrist dorsiflexion. Other clinical manifestations of hepatic encephalopathy include lethargy, confusion, difficulty awakening, changes in motor function, and cognitive changes. A late sign associated with cirrhosis that may be noted in clients with hepatic encephalopathy is fetor hepaticus, which refers to breath with a fruity, musty, or sweet fecal smell. Lactulose is prescribed to maximize excretion of ammonia.", "whyNot": {"a": "Reflexes are diminished.", "b": "The client is likely to be lethargic and difficult to awaken.", "d": "In late-stage liver disease, scar tissue replaces hepatocytes, and the liver becomes small and firm."}, "keyConcept": "Liver cirrhosis (hepatic cirrhosis) is a chronic disease characterized by diffuse destruction and fibrotic regeneration of hepatocytes. As necrotic tissues become fibrotic, the diseases alters the liver structure and normal vasculature, impairing flow of blood and lymph, resulting in hepatic insufficiency. The liver's functions include breakdown and elimination of ammonia. Serum levels of ammonia rise in end stage liver disease and result in a neurologic syndrome, hepatic encephalopathy."}, {"id": 10894, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "What potential nursing diagnosis is most appropriate for a client with recurrent episodes of Clostridium difficile?", "choices": [{"id": "a", "t": "At risk for edema related to the infectious disease process"}, {"id": "b", "t": "Potential resistance to pharmacological interventions related to resistant strains"}, {"id": "c", "t": "Alteration of respiratory function related to the infectious disease process"}, {"id": "d", "t": "Alteration of neurological function related to the infectious disease process"}], "correct": "b", "rationale": "Clostridium difficile is mostly associated with infections that develop in healthcare facilities, and a new strain has been identified that is more resistant to traditional treatment. A client infected with this specific strain may have more difficulty recovering if the treatment cannot fight off the infection.", "whyNot": {"a": "Edema is not an outcome of C. difficile infection.", "c": "C. difficile infection affects the gastrointestinal tract, not the respiratory tract.", "d": "Altered neurological function is not associated with C. difficile infection."}, "keyConcept": "Clostridium difficile (C. difficile) is a bacterium that causes a variety of gastrointestinal conditions, ranging from diarrhea to colitis and toxic megacolon. Risk factors include antibiotic use, older age, and admission to a hospital or nursing home. Symptoms include watery diarrhea, fever, nausea, abdominal pain or tenderness, and anorexia. As the infection progresses, abdominal distention occurs, with reduction of bowel sounds and tympany to percussion. Recurrence of infection suggests a drug-resistant strain. How C. difficile Spreads. % CLOSE { Browse Questions > iit Search Questions"}, {"id": 10895, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with an enterostomy feeding tube when she notices leakage of fluid around the insertion site. What is the most appropriate action?", "choices": [{"id": "a", "t": "Notify the health care provider right away"}, {"id": "b", "t": "Stabilize the tube and check that the balloon is inflated"}, {"id": "c", "t": "Gently push the tube further into the abdomen"}, {"id": "d", "t": "Aspirate from the tube to determine the amount of stomach contents."}], "correct": "b", "rationale": "A || 19% Moderate The nurse’s first priority is to stabilize the feeding tube and prevent dislodgment. The nurse should ensure that the balloon is inflated and OB a GY the tube is in the correct place. ° c | 1%", "whyNot": {"a": "While the health care provider may need to be notified in this situation, the first action of the nurse is to stabilize the tube.", "c": "The nurse should never push the tube further into the abdomen; if the tube is coming out, the nurse should stabilize it in place but should", "d": "Aspirating from the tube will not prevent dislodgment or leaking."}, "keyConcept": "Tube leakage is a complication associated with feeding tubes. Excessive tube motion can result in expansion of the tube entry site, which promotes leakage around the tube. The nurse should secure the tube immediately when leakage it noted. The area around the stoma should be cleaned with soap and water and protected with a barrier cream. Gentle traction on the tube sometimes helps to resolve a leak but too much traction may result in skin necrosis. In some cases, the tube may require removal for a few days until the stoma heals."}, {"id": 10896, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with chronic hepatitis B and cirrhosis. Which of the following findings would indicate deficient vitamin K absorption as a result of the client’s disease?", "choices": [{"id": "a", "t": "Petechiae and purpura"}, {"id": "b", "t": "Asterixis"}, {"id": "c", "t": "Gynecomastia"}, {"id": "d", "t": "Ascites"}], "correct": "a", "rationale": "Vitamin K is a fat-soluble vitamin necessary for the production of clotting factors in the liver. Deficiency in vitamin K results in increased PT B 1] or (prothrombin time) and INR (international normalized ratio). The nurse would expect signs of easy bruising, petechiae, purpura, and bleeding gums. c | 1% of 12% Normal vs. citthotic liver Normal liver Cirthotic iver Le) = ® 8 = 3 =) a = ay <", "whyNot": {"b": "Asterixis occurs in hepatic encephalopathy. It refers to a flapping tremor of the hands when they are extended. Hepatic encephalopathy is", "c": "Gynecomastia is due to hyperestrogenism.", "d": "Ascites is due to portal hypertension."}, "keyConcept": "Vitamin K is a fat soluble vitamin that cannot be produced in the body. Important functions include a role in production of clotting factors. Production of clotting factors is decreased in damaged hepatocytes, such as those seen in clients with end stage liver disease/cirrhosis.Signs include easy bruising, bleeding gums, purpura, petechiae, and bleeding gums."}, {"id": 10897, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse begins her shift on a med-surg unit after receiving a report on 4 clients. Which of the following should be her immediate priority?", "choices": [{"id": "a", "t": "A client complaining of to severe left upper quadrant pain after an endoscopic retrograde cholangiopancreatography (ERCP)"}, {"id": "b", "t": "A client with cramping abdominal pain 1 hour after a colonoscopy"}, {"id": "c", "t": "A client admitted today with small bowel obstruction who has large amounts of green-brown drainage from a nasogastric tube"}, {"id": "d", "t": "A client who reports white stool 6 hours after a barium swallow"}], "correct": "a", "rationale": "A. cholangiopancreatography (ERCP) @ : A. A client complaining of moderate to severe left upper quadrant pain after an endoscopic retrograde (ERCP) c Hl 27% p| 2% Pancreatitis is a complication of ERCP. During this diagnostic procedure, an endoscope is passed through the mouth and upper Gl tract into the duodenum to allow assessment of the pancreatic and biliary ducts. The study is performed under fluoroscopy using a contrast medium to reveal strictures and obstructions or to perform a biopsy. During this procedure, dilation of strictures and removal of obstruction can also be performed. Irritation or perforation of the pancreatic or biliary duct during the procedure can result in pancreatitis. Symptoms include pain in the left upper quadrant or epigastric region, sometimes radiating to the back. Laboratory studies show a rapid increase in pancreatic enzymes amylase and lipase. Pancreatitis can be a life-threatening condition.", "whyNot": {"b": "Crampy abdominal pain is a common effect of colonoscopy.", "c": "A client with bowel obstruction is expected to have drainage of bile-colored drainage after a nasogastric tube is inserted and set to low", "d": "After a barium swallow, barium contrast medium may affect the color of a client’s stool for as long as 3 days. This is not an unexpected"}, "keyConcept": "When prioritizing client care, conditions that present a threat to survival or safety take precedence over other concerns. Medical conditions that require immediate attention should then be prioritized. When caring for clients who have undergone diagnostic or therapeutic procedures, the nurse should recognize the signs and symptoms associated with complications."}, {"id": 10898, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "auscultation. Which of the following is the appropriate nursing intervention?", "choices": [{"id": "a", "t": "Begin incentive spirometry with the client."}, {"id": "b", "t": "Stop the feeding and assess the tube position."}, {"id": "c", "t": "Begin treatment with inhaled albuterol."}, {"id": "d", "t": "Request a prescription for furosemide."}], "correct": "b", "rationale": "al 5% Easy Nasoenteric tubes have a lower risk of aspiration compared to a nasogastric tube but can still become dislodged and travel in the lungs, c | 2% causing aspiration. They are passed through the nose and into the duodenum or jejunum of the small intestine. Aspiration pneumonia D l 3% remains a risk when clients are fed through the nasoenteric tube. Signs of aspiration pneumonia include decreased breath sounds, wheezing, crackles, a productive cough, or dyspnea. If these signs occur, the nurse should immediately stop the feeding and check the position of the tube by obtaining an X-ray, measuring the depth of insertion, and/or checking the pH of aspirate from the tube. Capnography can also be used to detect exhaled CO2 from a feeding tube, which indicates placement in the airway.", "whyNot": {"a": "Incentive spirometry is used to assist clients in expanding the lungs to avoid atelectasis, or collapse of the lung’s alveoli. In this case,", "c": "Although inhaled albuterol or another bronchodilator may be used when treating aspiration pneumonia, it is most important for the nurse", "d": "Furosemide is used to treat pulmonary edema that occurs in heart failure or fluid overload. Although crackles occur in pulmonary edema,"}, "keyConcept": "Aspiration can occur with nasogastric or nasoenteric feeding if the tube becomes dislodged. Signs include wheezing, crackles, decreased breath sounds, dyspnea, and a productive cough. If this occurs, the feeding must be stopped immediately and the position of the tube must be confirmed. Confirmation methods include X-ray, measurement of the tube depth, measurement of the pH of aspirate from the tube, or capnography to detect exhaled CO2 from the feeding tube."}, {"id": 10899, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with hepatitis A. Which of the following precautions is indicated when caring for this client?", "choices": [{"id": "a", "t": "Prevent the spread of infection using reverse isolation techniques"}, {"id": "b", "t": "Use caution when bringing food to the client"}, {"id": "c", "t": "Wear gloves when emptying the client’s urinal"}, {"id": "d", "t": "Dona mask, gown and gloves before entering the client’s room"}], "correct": "c", "rationale": "The hepatitis A virus is present in the stool, but may also be found in the urine and naso-tracheal secretions of clients with hepatitis A. Gloves must be worn when emptying the urinal. Hepatitis A Fever Malaise Anorexa Hepatomegaly ‘Nausea and vomiting LUght stools ‘Abdominal pain >\" Dark urine", "whyNot": {"a": "Reverse isolation is indicated for immunocompromised clients at risk of acquiring infection. It is not indicated for a client with hepatitis A.", "b": "Bringing food to the client requires no special handling; however, disposable utensils should be used since naso-tracheal secretions", "d": "Mask, gown, and gloves are not necessary before going into the client’s room. Standard precautions are indicated when caring for clients"}, "keyConcept": "Only standard precautions are necessary when caring for a client with hepatitis A. Gloves should be worn when contact with blood and body fluid is anticipated.. Goggles/masks are worn when splashing or aerosol of blood-contaminated secretions is anticipated."}, {"id": 10900, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "discussion? O A. Protamine sulfate O B. Vasopressin O C. Oxytocin O D. Vitamin K", "choices": [{"id": "a", "t": "Protamine sulfate"}, {"id": "b", "t": "Vasopressin"}, {"id": "c", "t": "Oxytocin"}, {"id": "d", "t": "Vitamin K"}], "correct": "b", "rationale": "N o: © vasopressors. It works in gastrointestinal bleeding by constricting the arterioles and reducing inflow to the portal vein. Vasopressin also D | causes contraction of smooth muscles in the GI tract. Vasopressin is an analog of antidiuretic hormone used to treat diabetes insipidus and hemorrhagic shock unresponsive to other High pressures in the portal vein caused by cirrhosis lead to development of engorged vessels in the GI tract, known as varices. For treatment of GI hemorrhage, vasopressin is given in combination with intravenous nitroglycerin, which reduces the pressure in the portal vein. The use of this combination reduces the systemic effects of vasopressin, which could result in ischemia in other organs. Vasopressin is administered as a bolus followed by infusion. Normal vs. cirrhotic liver Normal liver Cirrhotic liver", "whyNot": {"a": "Protamine sulfate is the antidote used to reduce the anticoagulant effects of heparin in patients who experience a severe bleeding", "c": "Oxytocin is used to stimulate uterine contractions when medical induction of labor is indicated.", "d": "Vitamin K is used to reverse the anticoagulant effects of warfarin in patients with bleeding or who are scheduled for surgery. If immediate"}, "keyConcept": null}, {"id": 10901, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is at high risk for developing ascites because of cirrhosis of the liver. How should the nurse assess for the presence of ascites?", "choices": [{"id": "a", "t": "Observe the client for signs of respiratory distress"}, {"id": "b", "t": "Percuss the client’s abdomen and listen for dull sounds"}, {"id": "c", "t": "Palpate the lower extremities over the tibia and observe for edema"}, {"id": "d", "t": "Listen for decreased or absent bowel sounds while auscultating the abdomen"}], "correct": "b", "rationale": "Percussing over the client’s abdomen will produce a dull, not tympanic, sound if fluid is present.", "whyNot": {"a": "Ascites may cause respiratory distress, but this is not the method of assessment.", "c": "This assessment does not check for ascites.", "d": "Auscultating bowel sounds is not a method of assessment for ascites."}, "keyConcept": "Cirrhosis is a chronic, irreversible liver disease characterized by inflammation and fibrosis of liver cells (hepatocytes). This leads to the formation of scar tissue within the liver, which causes obstruction of hepatic blood flow and impedes liver function. Impaired portal blood flow leads to edema, ascites, esophageal varices, hemorrhoids, and varicose veins. Paracentesis is a procedure to drain the abdomen of ascitic fluid in clients with end-stage liver disease. (Image below.)"}, {"id": 10902, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "appropriate nursing intervention? O A. Assist the client with ambulation. O B. Increase the protein content of the client's next meal. O C. Assess the client’s proprioception and peripheral sensation. O D. Notify the healthcare provider to request a prescription for a serum ammonia level.", "choices": [{"id": "a", "t": "Assist the client with ambulation."}, {"id": "b", "t": "Increase the protein content of the client's next meal."}, {"id": "c", "t": "Assess the client’s proprioception and peripheral sensation."}, {"id": "d", "t": "Notify the healthcare provider to request a prescription for a serum ammonia level."}], "correct": "d", "rationale": "| 1% Hepatic encephalopathy is a complication of cirrhosis and end-stage liver disease. It is caused by reduced clearance of ammonia from the Cc | 38% bloodstream. Clients with hepatic encephalopathy appear confused and lethargic and may have slurred speech. Hepatic encephalopathy eD ; 61% can result in coma. Treatment is directed at reducing the production and absorption of ammonia, primarily from the Gl tract. Medications used to treat hepatic encephalopathy include lactulose, which promotes the reduction of the bacterial load of urease-producing bacteria in the intestine and promotes increased transit through the colon. Rifaximin or neomycin are used when lactulose is ineffective and are nonabsorbable antibiotics that alter the gut flora.", "whyNot": {"a": "Hepatic encephalopathy increases the risk of falling, so the client should be on bed rest until mentation is clear.", "b": "A low-protein diet is recommended for treatment of hepatic encephalopathy.", "c": "Acharacteristic sign of hepatic encephalopathy is asterixis, which refers to a flapping tremor of the hands when the arms are extended"}, "keyConcept": "Most ammonia in the body results from the breakdown of protein by bacteria in the intestines. The healthy liver converts ammonia into urea, which is then eliminated in urine. Ammonia levels in the blood rise when the liver is not able to convert ammonia to urea, resulting in high ammonia levels and hepatic encephalopathy."}, {"id": 10903, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing dietary teaching to a client who has chronic constipation. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Maintain a fluid intake of 1,000 mL each day"}, {"id": "b", "t": "Increase intake of cooked fruits © c brink hot liquids"}, {"id": "c", "t": "‘i The nurse should instruct a client who has constipation to drink hot liquids because they stimulate peristalsis."}, {"id": "d", "t": "Take a laxative daily"}], "correct": "c", "rationale": "‘i The nurse should instruct a client who has constipation to drink hot liquids because they stimulate peristalsis. oi oc", "whyNot": {"a": "The nurse should instruct a client who has constipation to maintain a daily fluid intake of 1,500 to 3,000 mL each day.", "b": "The nurse should instruct a client who has constipation to increase intake of raw fruits because this will provide more fiber in the diet.", "d": "The nurse should instruct a client who has constipation that the overuse of laxatives can impair bowel motility and that laxatives are not"}, "keyConcept": "Other instructions to provide for a client who has chronic constipation include: establish a regular exercise program, increase intake of high- fiber foods such as vegetables and whole grains, maintain a consistent daily routine for defecation, and respond to the urge to defecate, rather than ignoring it."}, {"id": 10904, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing teaching for a client who will be using a polyethylene glycol bowel prep for a scheduled colonoscopy. Which of the following should the nurse include in teaching?", "choices": [{"id": "a", "t": "Consume a regular diet until beginning the bowel prep."}, {"id": "b", "t": "The bowel prep will result in the evacuation of bowel contents a day after completion."}, {"id": "c", "t": "If feces are expelled, discontinue the prep."}, {"id": "d", "t": "Take current medications in accordance with the healthcare provider’s instructions."}], "correct": "d", "rationale": "A Hi 13% Moderate 8 14% Before beginning the bowel prep, the client will usually be restricted to a clear liquid diet. Some medications can be withheld prior to bowel Cc | 2% preparation for a colonoscopy because of lack of absorption, and the healthcare provider may prescribe modifications for those clients on eD | 71% anticoagulant medications or those with diabetes. The client should be instructed to consult with the healthcare provider. Ethylene glycol solutions with electrolytes are safe: they don't cause massive shifts of fluids and electrolytes. They include GoLYTELY and CoLYTE.", "whyNot": {"a": "Aclear liquid diet is generally initiated prior to a bowel prep.", "b": "The client will begin to experience the effects of the bowel prep within 2-3 hours after initiation.", "c": "The full amount prescribed should be completed to allow adequate visualization of the bowel during the procedure."}, "keyConcept": "Before a colonoscopy, a full bowel prep is usually performed to cleanse the bowel for better visualization of any pathology. Medication and dietary changes are often required several days before the examination. Most medications may be continued, although providers may prescribe modification for some clients, including those with diabetes or those on anticoagulant medication."}, {"id": 10905, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is preparing to administer an enteral feeding through a client's NG tube. For which of the following purposes should the nurse measure the client's gastric residual?", "choices": [{"id": "a", "t": "To confirm the placement of the NG tube"}, {"id": "b", "t": "To remove gastric acid that might cause dyspepsia"}, {"id": "c", "t": "To determine the client's risk for aspiration."}, {"id": "d", "t": "To identify delayed gastric emptying"}], "correct": "d", "rationale": "A ; | 34% Moderate 11% The nurse should measure the amount of unabsorbed formula from the previous enteral feeding to identify delayed gastric emptying. If it is delayed, the nurse should avoid overfeeding the client, which can cause gastric distention.", "whyNot": {"a": "The nurse should test the pH of the gastric residual to help confirm NG tube placement.", "b": "Unless the residual exceeds the amount the facility's policy or the provider specifies, the nurse should return it to the stomach. Policies", "c": "Measuring gastric residual does not help identify the client's risk for aspiration. Positioning the client in high Fowler's or elevating the"}, "keyConcept": "Gastric residual is the amount of fluid, secretions, and formula that remains in a client's stomach after the last intermittent enteral feeding, or the residual that is present every 4 to 6 hr for clients who are receiving continuous feeding. Before withdrawing gastric residual, the nurse should flush the client's NG tube with 30 mL of water to facilitate aspiration of fluid. If it is difficult to aspirate fluid, the nurse should try repositioning the client from side to side."}, {"id": 10906, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client informs a nurse at a clinic visit that he has been taking megadoses of vitamin A on the advice of a friend. Which of the following does the nurse understand is true concerning vitamin A?", "choices": [{"id": "a", "t": "The body has a large vitamin A requirement but can synthesize it as needed."}, {"id": "b", "t": "Vitamin A is toxic in small amounts."}, {"id": "c", "t": "The liver stores vitamin A easily in large amounts."}, {"id": "d", "t": "Vitamin A is a fat soluble vitamin"}], "correct": "d", "rationale": "Vitamin A is one of the fat-soluble vitamins, which also include D, E, and K. They are necessary for bodily functions and are stored in the liver Cc i and adipose tissues. Because they are stored and not needed in large doses, they can be toxic and cause serious health problems when ep Po taken in megadoses. Water-soluble vitamins, including B complex and C vitamins, are eliminated more rapidly than fat-soluble vitamins, making fat-soluble vitamins a greater risk. Vitamin A, also known as retinol, is important for cell division, immune system regulation, and prevention of some cancers (due to antioxidant properties); it plays a role in reproduction and gene expression, helps with vision when the light changes, and also is important for the growth of bones and teeth. Sources include foods like fish, liver, and dairy products. Carrots, winter squash, and dark green vegetables are also rich in beta-carotene, a precursor that is converted to vitamin A by the body. Fat soluble vitamins and sources D. E K Vision, Strengthens bones, Immune system, Blood clotting, Reproduction, Calcium absorption, Flushes toxins Bone health Bone health, Immune system Immune system, ‘Skin", "whyNot": {"a": "The requirement for vitamin A is not large, and the body is unable to synthesize the precursor of vitamin A, so one or both forms are", "b": "Vitamin A can usually be supplied without supplements through the diet, but small amounts to meet the daily requirement are not toxic.", "c": "The liver and adipose tissues store excess vitamin A. But, in large amounts, vitamin A toxicity can cause dizziness, dry and itchy skin,"}, "keyConcept": null}, {"id": 10907, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is undergoing percutaneous liver biopsy. Which of the following will the nurse do when assisting with this procedure?", "choices": [{"id": "a", "t": "Assist the client into a seated position."}, {"id": "b", "t": "Instruct the client to take a deep breath and hold it."}, {"id": "c", "t": "Assist the client to lie on the right side after the procedure."}, {"id": "d", "t": "Obtain clotting studies post-procedure."}], "correct": "c", "rationale": "3 i 18% The liver detoxifies the blood, metabolizes nutrients and drugs, and synthesizes clotting factors and other proteins, including albumin. It @c | 64% plays an important role in the metabolism of carbohydrates, proteins, amino acids, and lipids, including breakdown and synthesis. The | (fibrinogen), II (prothrombin), V, VII, VIII, IX, X, XI, XIII, protein C, protein S and antithrombin. With decreased liver function, production of clotting factors decreases and the risk of bleeding is increased. Clients with significant liver disease will have an increased prothrombin time (PT) and international normalized ratio. In clients with liver disease who require biopsy, clotting studies are obtained before the procedure. In preparation for a liver biopsy, the nurse should assist the client to the supine position, with the right arm behind the head. The nurse should instruct the client to exhale and hold the breath, which elevates the diaphragm away from the liver. After the procedure is complete, the client should be assisted to a side-lying position on the right side to promote hemostasis.", "whyNot": {"a": "The client is in the supine position, with the right arm behind the head.", "b": "Exhaling elevates the diaphragm away from the liver.", "d": "Clotting studies should be obtained before the procedure to determine the risk of hemorrhage."}, "keyConcept": "In advanced liver disease, hepatocytes are replaced by fibrosis and liver function diminishes, including production of vitamin K dependent clotting factors. As a result, clients with liver disease often have increased PT and INR. When undergoing invasive procedures, these clients are at greater risk of uncontrolled bleeding. During a liver biopsy, the client should be in a supine position. After the procedure, the client should be assisted to a side-lying position on the right side to promote hemostasis."}, {"id": 10908, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for an infant who is post-operative following a surgical procedure to correct intussusception. Which of the following is most appropriate for re-initiation of feedings after this procedure?", "choices": [{"id": "a", "t": "Cereal-thickened milk"}, {"id": "b", "t": "Full-strength formula"}, {"id": "c", "t": "Half of full-strength formula"}, {"id": "d", "t": "Oral electrolyte solution"}], "correct": "d", "rationale": "A | | 8% Moderate When a child is ready to take liquids by mouth postoperatively, clear liquids are usually offered first. If clear liquids as tolerated, then the B | at concentration and the amount of fluid will be increased. ci 17%", "whyNot": {"a": "Clear liquids should be offered first; cereal-thickened milk is too thick to start right after surgery.", "b": "Full-strength formula is too thick to start after this surgery; the client needs to start with clear liquids.", "c": "This is not correct; the client needs to start with clear liquids."}, "keyConcept": "a © o 2 ° s a = a < Intussusception is the most common cause of intestinal obstruction in children under the age of 2. It refers to telescoping of a segment of the intestine inside the adjacent segment and can occur anywhere in the large or small intestine, although it most commonly occurs at the ileocecal junction (of the small and large intestine.) Initial treatment is fluid resuscitation and decompression of the GI tract with a nasogastric tube. Unless there is evidence of perforation or peritonitis, the physician will usually attempt nonoperative reduction using a therapeutic enema. Surgical reduction is sometimes necessary. Folded-in Section of Bowel Intussusception of the Bowel"}, {"id": 10909, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "aspiration? O A. Displays continual tongue rolling while eating O B. Attempts to rapidly swallow with each bite O C. Displays no coughing when food enters the airway O D. Attempts to regurgitate food after swallowing", "choices": [{"id": "a", "t": "Displays continual tongue rolling while eating"}, {"id": "b", "t": "Attempts to rapidly swallow with each bite"}, {"id": "c", "t": "Displays no coughing when food enters the airway"}, {"id": "d", "t": "Attempts to regurgitate food after swallowing"}], "correct": "c", "rationale": "All 12% — Hard The nurse should identify that a client who has silent aspiration might not display coughing when food enters the airway. However, the B r] or client will have manifestations of silent aspiration within 24 hr, such as aspiration pneumonia. > ZZ! 28%", "whyNot": {"a": "The nurse should identify that a client who has dysphagia will have abnormal movement of the mouth, tongue, or lips but will not have", "b": "The nurse should identify that a client who has dysphagia will have delayed swallowing and often incomplete oral clearance that includes", "d": "The nurse should identify that the client who has dysphagia might attempt to regurgitate food after swallowing. However, this is not an"}, "keyConcept": "Dysphagia is when a client has difficulty swallowing and is often caused by neurogenic, myogenic, obstructive, or connective tissue disorders. Numerous complications can occur, including silent aspiration that can lead to pneumonia, dehydration, malnutrition, and weight loss. Coughing during or after eating, a change in voice tone or quality after swallowing, or drooling or leakage of food from the mouth when eating can indicate that the client has dysphagia."}, {"id": 10910, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who is scheduled for a barium study of the upper gastrointestinal system (UGI series) for suspected peptic ulcer disease. Which is the priority nursing intervention?", "choices": [{"id": "a", "t": "Tell the client to decrease oral intake after the procedure"}, {"id": "b", "t": "Keep the client NPO"}, {"id": "c", "t": "Obtain informed consent"}, {"id": "d", "t": "Explain that the barium swallow requires drinking a white, chalky substance"}], "correct": "b", "rationale": "Abarium study of the upper GI tract is accurate only when the client’s GI tract is empty. The client must be kept NPO for 8-10 hours prior to the study, so this is the priority action.", "whyNot": {"a": "Barium can cause constipation, so it is important for the client to increase intake of water after the procedure. This is not, however, the", "c": "Informed consent is unnecessary for this non-invasive radiological study.", "d": "This is a true statement, but not the priority intervention."}, "keyConcept": "Priorities of care are established using frameworks that include the ABCs, Maslow's Hierarchy of Needs, and the ABCs plus MAAUAR method of establishing priority. Physical and biological needs are the priority in Maslow's Hierarchy."}, {"id": 10911, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is assessing a client who has dysphagia. Which of the following manifestations should the nurse expect?", "choices": [{"id": "a", "t": "Absence of tongue thrust"}, {"id": "b", "t": "Increased movement of the larynx during swallowing"}, {"id": "c", "t": "Pocketing food in the mouth after swallowing"}, {"id": "d", "t": "Decreased salivation"}], "correct": "c", "rationale": "A Hi 11% Moderate The nurse should identify that the presence of food stored in the cheeks, under the tongue and palate are manifestations of dysphagia. B 1] 80% Clients who have dysphagia often pocket food in the oral cavity due to the inability to swallow it. og 6%", "whyNot": {"a": "The nurse should identify and report the presence of tongue thrusting, which can indicate impaired swallowing. Clients who have", "b": "The nurse should identify that delayed or absent, rather than increased, movement of the larynx during swallowing is a manifestation of", "d": "The nurse should identify increased, rather than decreased, salivation during meals is a manifestation of dysphagia."}, "keyConcept": "Dysphagia is the term for difficulty swallowing. Clients who have dysphagia are sometimes unaware of its presence. It can be a sensation that contributes to the client having difficulty in the passage of solids or liquids from the mouth to the stomach, a lack of pharyngeal sensation, or various other inadequacies of the swallowing mechanism."}, {"id": 10912, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is teaching a client who reports recurrent constipation. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "\"Bear down forcefully when defecating.\""}, {"id": "b", "t": "\"Drink 1,500 mL of water per day.\""}, {"id": "c", "t": "\"Add more raw vegetables to your diet.\""}, {"id": "d", "t": "\"Postpone defecating when you feel the urge until the feeling becomes more urgent.\""}], "correct": "c", "rationale": ", the client should increase their fiber intake to 20 to 35 g each day to increase the stool's bulk and help move it B | BoA through the colon. Raw vegetables and fruit are good sources of fiber. my | 3%", "whyNot": {"a": "Bearing down forcefully during defecation increases the risk for developing hemorrhoids.", "b": "Clients should drink 2,000 to 3,000 mL of fluid per day to promote healthy defecation.", "d": "The client should not postpone defecating if they feel the urge to do so because retaining stool can lead to constipation."}, "keyConcept": "Constipation is the passage of fewer than three bowel movements per week, which can result in stool that is hard and difficult to pass. Measures to prevent constipation include setting regular times for defecation, adding plenty of fiber and fluid to the diet, and engaging in moderate exercise regularly."}, {"id": 10913, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has a nasogastric (NG) tube connected to wall suction. Which of the following should the nurse do when administering a medication through the NG tube?", "choices": [{"id": "a", "t": "Clamp the nasogastric tube for 30 minutes after the medication is administered."}, {"id": "b", "t": "After giving the medication, set the NG tube on low intermittent suction for 30 minutes."}, {"id": "c", "t": "Position the client in the supine position so the medication will be better absorbed."}, {"id": "d", "t": "Aspirate the NG tube after giving the medication."}], "correct": "a", "rationale": "The nurse should always check with the pharmacist to determine if the prescribed medication is available in a liquid form, but if a liquid form is not available, the nurse must ensure that the medication can be safely crushed. Crushed tablets should be dissolved in warm water. If the tube is connected to wall suction, the suction should be disconnected, and the tube should be clamped for 30 minutes after administration of the medication to allow absorption. Before administering medications, the nurse should check and confirm placement of the tube.", "whyNot": {"b": "The suction should be turned off prior to giving the medication, and the tube should be clamped with the suction off for 30 minutes after", "c": "Medications or feedings should be given in the semi-Fowler’s position with the head of the bed elevated at least 30 degrees.", "d": "Before and after giving medications, the tube should be flushed with 15-30 mL of water (5-10 mL in children)."}, "keyConcept": "Anasogastric tube can be used to relieve obstruction or decompress the abdomen. Medications and feedings can be given through the NG tube. If an NG tube is hooked to wall suction, it must be disconnected before administering the medication and the tube should be clamped for thirty minutes after to allow absorption."}, {"id": 10914, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client who is undergoing radiation therapy complains to the nurse that he is experiencing diarrhea. Which of the following interventions should the nurse advise for the client?", "choices": [{"id": "a", "t": "“You should increase your intake of milk; that will soothe your stomach.”"}, {"id": "b", "t": "“Drink more caffeinated beverages. This increases circulation to your gastrointestinal tract.”"}, {"id": "c", "t": "“Try to eat three large meals a day instead of smaller meals and snacks.”"}, {"id": "d", "t": "“Increase your water intake to at least 8 cups per day.”"}], "correct": "d", "rationale": "The client should be instructed to increase fluid intake—typically water—to at least 8 cups per day. Increased fluid intake can prevent dehydration associated with diarrhea and fluids may be better tolerated than some solid foods.", "whyNot": {"a": "Milk and dairy products are not well-tolerated by many people and can result in worsening diarrhea.", "b": "Caffeinated beverages stimulate the digestive tract and could worsen diarrhea; they should be avoided in this situation.", "c": "The client should eat several smaller meals a day, to reduce the volume digested with each meal."}, "keyConcept": null}, {"id": 10915, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is talking with a client who is scheduled for jejunostomy tube placement. Which of the following statements by the client indicates an understanding of the information?", "choices": [{"id": "a", "t": "\"This type of tube has a higher risk of causing choking than a tube in the nose.\""}, {"id": "b", "t": "\"The liquid food that goes into this tube will bypass my stomach.\""}, {"id": "c", "t": "\"This tube can only be used for short periods of time, usually less than a month.\" O D.\"The liquid food that goes into this tube is less likely to get stuck than with other tubes.\""}], "correct": "b", "rationale": "Ajejunostomy tube is inserted into the jejunum, which is a portion of the small intestine. This type of tube is appropriate for clients who have altered gastrointestinal function in portions of the gastrointestinal tract above the jejunum. Jejunostomy tubes are used following gastric surgery because intestinal motility returns more quickly than gastric motility. Routes for Enteral Nutrition Route Jejunostomy or percutaneous endoscopic jejunostomy (PEJ) Gastrostomy or percutaneous endoscopic gastrostomy (PEG) Nasointestinal (NI) Nasogastric (NG)", "whyNot": {"a": "A jejunostomy tube has a low risk for aspiration. It is the preferred type of feeding tube for clients at high risk of aspiration. Feeding tubes", "c": "Ajejunostomy tube is appropriate for both short- and long-term use. The tube can be used temporarily after surgery or for long-term"}, "keyConcept": null}, {"id": 10916, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "@ @ *& Viraln 8 Recorc Mi Inbox( MM Inbox- ] Untitle: Untitle’ a Google @ TEASP Online & Markk @ Micros (@QNETSCENEMCED @& ATITE G Newcl Nc x) + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Temporarily stop the enema and allow the cramping to subside"}, {"id": "b", "t": "Immediately stop the enema and notify the healthcare provider."}, {"id": "c", "t": "Continue with the enema; this is an expected finding"}, {"id": "d", "t": "Raise the enema bag to allow some of the fluid to exit the abdomen"}], "correct": "a", "rationale": "Abdominal cramping during administration of an enema is not uncommon. If this happens, the nurse should temporarily stop the enema B 1] or until the cramping eases. ci 19%", "whyNot": {"b": "There is no need to stop the enema or notify the physician if the cramping eases after stopping the enema for a few minutes.", "c": "Although cramping is expected, the nurse should not continue administering the enema since the cramping can usually be relieved by", "d": "The enema bag should not be raised or lowered; raising the bag will cause the speed of the enema to increase, leading to more cramping."}, "keyConcept": "To administer an enema, the nurse inserts fluid into the rectum. This is usually done to cleanse the lower intestines and colon to remove accumulated toxins and fecal matter by stimulation of bowel movements. Reasons for administering enemas include colon cleansing, relief of constipation, removal of excessive potassium and ammonia, medication delivery, to reduce bowel inflammation, and to prepare the bowel for surgery."}, {"id": 10917, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has a suspected duodenal ulcer. Which of the following diagnostic examinations will most likely confirm the diagnosis?", "choices": [{"id": "a", "t": "Upper Gl series"}, {"id": "b", "t": "Hemoccult test for stool"}, {"id": "c", "t": "Urea breath test"}, {"id": "d", "t": "Endoscopic exam with biopsy for Helicobacter pylori"}], "correct": "d", "rationale": "‘i 32% Hard An esophagogastroduodenoscopy (EGD), which is also known as an upper endoscopy or upper gastrointestinal endoscopy, is a diagnostic B ] Aon procedure that is performed to view the esophagus, stomach, and duodenum (part of the small intestine). An endoscopic exam with biopsy is the most accurate test for diagnosing a peptic ulcer. History and clinical signs are often used for diagnosis in combination with upper GI c | 4% series, C13 urea breath testing, serologic tests for H. pylori antibodies, or stool exam for H. pylori antigen. Duodenal ulcers are caused by @D YT 50% hypersecretion of stomach acid. They manifest with pain in the epigastrium 2-3 hours after meals and relieved by food. Peptic ulcers can cause Gl bleeding, when the ulcer erodes into a blood vessel. Melena (dark, tarry stool) is characteristic of upper GI bleeding. The client must be fasting for upper endoscopy. Dentures should be removed and placed in a cup. A consent must be obtained from the client for the procedure, which is performed under sedation. a © o 2 ° s a = a < az", "whyNot": {"a": "Upper GI X-rays with contrast may show a cratered appearance in the duodenum, but the most accurate diagnostic test is endoscopy with", "b": "Although GI bleeding may occur with peptic ulcer disease, this is a nonspecific test and is not used for diagnosis.", "c": "C13 urea breath testing is frequently an initial step in determining the treatment of suspected peptic ulcer disease. If H. pylori is present, it"}, "keyConcept": "Endoscopy is the most reliable test for diagnosis of peptic ulcer, by visualization of the ulcer. In an EGD, an endoscope is passed through the"}, {"id": 10918, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with chronic cirrhosis of the liver. The nurse knows that which of the following is a potentially life-threatening complication of chronic liver cirrhosis?", "choices": [{"id": "a", "t": "Spider angiomas"}, {"id": "b", "t": "Fetor hepaticus"}, {"id": "c", "t": "Asterixis"}, {"id": "d", "t": "Varices"}], "correct": "d", "rationale": "-threatening emergency complication of chronic liver cirrhosis if they begin to bleed. B | Aor Hemorrhage of esophageal varices can lead to death. ci 12%", "whyNot": {"a": "Spider angiomas, which are harmless red lesions on the skin that result from capillary fragility, are a sign of chronic liver cirrhosis and not", "b": "Fetor hepaticus is a fruity odor to the breath that can develop with liver cirrhosis; it is not life-threatening.", "c": "Asterixis refers to tremors and a sign of liver cirrhosis but is not life-threatening."}, "keyConcept": "Esophageal varices occur in about half of all people with alcoholic cirrhosis and approximately one-third of these will experience variceal hemorrhage, a life-threatening event. In a healthy individual, the hepatic portal vein brings blood from the spleen and the gastrointestinal tract, and its associated organs, to the liver. As cirrhosis progresses, portal hypertension results from increased resistance to blood flow through the damaged liver. This results in increased pressure that stimulates the development of collateral channels to bypass the portal vein. Portal hypertension causes splenomegaly, ascites, and development of esophageal varices."}, {"id": 10919, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Which of the following precautions should be used by a nurse caring for a client who has a diagnosis of Clostridium difficile colitis?", "choices": [{"id": "a", "t": "Gloves and a surgical mask when working within 3 feet of the client"}, {"id": "b", "t": "N95 respirator"}, {"id": "c", "t": "Dedicated equipment only for this client to be disinfected before removing from the room"}, {"id": "d", "t": "Surgical mask worn by client during transport"}], "correct": "c", "rationale": "im 17% Easy . difficile is highly contagious and results in many serious nosocomial (healthcare-related) infections. It is transmitted by direct contact. ec | 80% Infection with this organism causes a range of gastrointestinal conditions from diarrhea to toxic megacolon, a life-threatening disorder. , including a private room, when available. If a private room is not available, the client may be placed ina room with another client who is infected with the same microorganism. Healthcare workers must wear gloves when entering the room and {) should wear a gown when the client has uncontrolled body fluids. The gown should be removed before leaving the room. Gloves should also 2 be removed and healthcare workers should wash their hands with antibacterial soap before leaving the room. Dedicated equipment should g be used only for the client and must be disinfected before removing it from the client’s room. = we", "whyNot": {"a": "Amask should be used within 3 feet of clients who require droplet precautions for infections including influenza, rubella, mumps, and >", "b": "N95 respirators should be worn by susceptible people entering the room of a client who is on airborne isolation precautions for diseases,", "d": "This is a requirement for both airborne and droplet precautions."}, "keyConcept": "C. difficile can cause a variety of conditions, including pseudomembranous colitis (PMC), toxic megacolon, perforations of the colon, and sepsis. Risk factors include long hospital stays, inmunocompromise, antibiotic therapy, and proton pump inhibitors. The bacteria is shed in feces and infection is spread mainly through contaminated hands of healthcare workers. Contact precautions are required."}, {"id": 10920, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who asks about risk factors for colon cancer. Which of the following increases the risk of colon cancer?", "choices": [{"id": "a", "t": "Ahistory of inflammatory bowel disease (IBD) O B.A family history of colorectal polyps or cancer"}, {"id": "c", "t": "Tobacco use"}, {"id": "d", "t": "Consumption of alcohol"}, {"id": "e", "t": "of these"}], "correct": "e", "rationale": ". A high-fat diet, lack of exercise and obesity are also risk factors for the disease. a I Bon", "whyNot": {"a": "clients with ulcerative colitis and Crohn’s disease are at increased risk of colon cancer. The prevalence of colon cancer is higher in clients", "c": "Tobacco use increases the risk of many cancers, including colon cancer.", "d": "Alcohol consumption is related to a higher risk of developing colorectal cancer. This may in part be due to poor diet in individuals who"}, "keyConcept": "The risk of developing CRC is influenced by both environmental and genetic factors. Protective factors that reduce the risk include aspirin and nonsteroidal anti-inflammatory drugs, physical exercise, consumption of fresh fruits and vegetables, dietary fiber, adequate folate and vitamin B6. consumption of fish, coffee intake, and post-menopausal hormone therapy in women."}, {"id": 10921, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with a feeding tube. Which action would most likely prevent clogging of the tube?", "choices": [{"id": "a", "t": "Daily injections of heparin into the tube"}, {"id": "b", "t": "Infusing the enteral formula at an increased rate"}, {"id": "c", "t": "Flushing the tube with warm water after each use"}, {"id": "d", "t": "Gently stripping the tube before administering the feeding"}], "correct": "c", "rationale": "| 2% Easy In most cases, flushing the tube with approximately 15-20 mL of warm water after each feeding can reduce the incidence of the tube B | a0 clogging. The nurse can perform this activity as soon as the client’s feeding is complete.", "whyNot": {"a": "Heparin is used for intravenous catheters and not for feeding tubes.", "b": "Increasing the rate of the formula administration would not necessarily reduce the risk of a clog in the tube.", "d": "Stripping the tube does not reduce the risk of clogging and is not recommended."}, "keyConcept": "Obstruction is a common complication of tube feeding. The most important intervention to prevent blockage is to flush the tube with a minimum of 10 mL warm water or more after each feed or medication. When administering medication, tablets should be crushed and dissolved completely in warm water before administration. Thick suspensions may require dilution with water. If the tube becomes blocked, the nurse should instill small amounts of carbonated water or warm water and push and pull the plunger of the syringe to move the liquid in and out of the feeding tube."}, {"id": 10922, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is administering an enema to a client who is scheduled for gastrointestinal surgery. What should the nurse do when the client complains of abdominal cramps during the enema?", "choices": [{"id": "a", "t": "Reduce the rate of the infusion"}, {"id": "b", "t": "Discontinue the enema and try again later"}, {"id": "c", "t": "Lower the container below the level of the rectum"}, {"id": "d", "t": "Close the lumen of the tubing and wait until the discomfort subsides"}], "correct": "d", "rationale": "When administering an enema, the nurse will monitor the client for cramping as the enema solutions flows into the client’s rectum. Abdominal muscle tension may indicate cramping. If cramping occurs while administering the enema, the nurse should stop the flow and ask the client to take several deep breaths. The enema may be continued when the cramping subsides and the client becomes comfortable again.", "whyNot": {"a": "Reducing the infusion rate may still cause cramping. The nurse should temporarily stop the flow of the enema by clamping the tubing and e@D i", "b": "The nurse has been ordered to complete the enema and should not stop and try again later. She should instead temporarily stop the flow", "c": "Lowering the container below the level of the rectum will only slow the flow of the enema solution, but may still cause cramping."}, "keyConcept": "When administering an enema, the nurse will monitor the client for cramping as the enema solutions flows into the client’s rectum. Abdominal muscle tension may indicate cramping. If cramping occurs while administering the enema, the nurse should stop the flow and ask the client to take several deep breaths. The enema may be continued when the cramping subsides and the client becomes comfortable again."}, {"id": 10923, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "What type of colostomy is used for the management of anorectal malformation in a neonate?", "choices": [{"id": "a", "t": "Adivided descending colostomy"}, {"id": "b", "t": "A divided transverse colostomy"}, {"id": "c", "t": "Asigmoid colostomy"}, {"id": "d", "t": "An ascending colostomy"}], "correct": "a", "rationale": "ided descending colostomy The type of colostomy that is used for the management of anorectal malformations is a divided colostomy, also known as a double-barreled colostomy. This type of colostomy completely diverts fecal contents, provides bowel decompression, and preserves the distal colon for surgical repair at one or two months of life.", "whyNot": {"b": "A divided transverse colostomy is located in the transverse colon and is not used to manage anorectal malformations.", "c": "Asigmoid colostomy is located in the sigmoid colon and is not used to manage anorectal malformations.", "d": "An ascending colostomy is located in the ascending colon and is not used to manage anorectal malformations."}, "keyConcept": "Anorectal malformations include imperforate anus and cloaca, which refers to a common opening for the genital, urinary, and gastrointestinal tract. Infants born with these malformations may have a primary repair or the surgery may be delayed for one to two months after the creation of a divided colostomy. The divided colostomy is one in which the surgeon divides the intestine and creates a stoma (the opening through the abdominal wall) for each portion. The proximal portion of the bowel is active and this stoma passes stool. The distal segment is separated from the digestive tract but continues to produce mucus. A divided colostomy preserves the distal portion of the colon for use in the corrective surgery."}, {"id": 10924, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is assessing a client with jaundice who has clay-colored stool. What is the most likely cause of these findings?", "choices": [{"id": "a", "t": "Increased cholecystokinin production"}, {"id": "b", "t": "Increased production of bile"}, {"id": "c", "t": "Decreased flow of bile into the intestine"}, {"id": "d", "t": "Increased breakdown of hemoglobin"}], "correct": "c", "rationale": "Correct Answer: C. Decreased flow of bile into the intestine Jaundice refers to yellowish discoloration of the sclera of the eyes and of the skin. It is caused by increased levels of bilirubin. Bilirubin is a brown/yellow substance made in the liver from the breakdown of red blood cells. It is removed from the body through stool and gives stool its brown color. Jaundice can be caused by necrosis of hepatocytes (liver cells) as a result of diseases that include hepatitis and cirrhosis or by anything that increases hemolysis (breakdown of red blood cells). Jaundice can also be the result of obstruction of bile drainage into the small intestine. Clay-colored stool indicates obstruction of the bile ducts. Pruritus is also associated with jaundice. Ereeechapanc orcuation of Ble nats", "whyNot": {"a": "Cholecystokinin is a pancreatic digestive enzyme that causes the release of bile from the gallbladder.", "b": "Clay-colored stools occur from decreased flow of bile into the intestine. The liver produces bile from cholesterol and bilirubin. Production", "d": "Increased breakdown of hemoglobin can result in jaundice but would not affect the color of stool."}, "keyConcept": "Jaundice is caused by increased serum levels of bilirubin, a substance made from breakdown of red blood cells and excreted in the stool. Excess hemolysis, liver disease, and obstruction of the biliary system can all lead to jaundice. Since bilirubin gives feces its brown color, clay colored stools in the presence of jaundice suggest obstruction of the biliary tree."}, {"id": 10925, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "@ @ & Viraln. 8x Record M Inbox( ™ Inbox- Ej Untitle: Untitle’ (@ Google @ TEASF Online & MarkkK | @ Micros (eeuWges oe Nae ire @® Atte, € > @G 23 student.atitesting.com/LT| Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Afraid that her baby’s vomiting will resume"}, {"id": "b", "t": "Unaware that she is allowed to feed her baby"}, {"id": "c", "t": "Not sure how to feed her baby with a special nipple"}, {"id": "d", "t": "Uncertain if her baby will tolerate the thickened formula"}], "correct": "a", "rationale": "Previous experiences with projectile vomiting are frightening; the nurse should explain that this should not recur and encourage the mother to resume feeding her baby.", "whyNot": {"b": "The nurse should teach the mother that the baby can eat after surgery; the mother is most likely aware that she should feed the baby.", "c": "A baby who has had surgery for pyloric stenosis does not need to use a special nipple to feed.", "d": "The baby most likely does not need thickened formula after this type of surgery."}, "keyConcept": "Infantile hypertrophic pyloric stenosis (IHPS) is a disorder of young infants caused by hypertrophy of the pylorus. Pyloric stenosis can result in progressive obstruction of the gastric outlet, leading to forceful non-bilious projectile vomiting. On physical examination, a palpable mass the size of an olive may be noted in the right upper quadrant of the abdomen. Loss of stomach acid through vomiting can lead to metabolic alkalosis. If the condition is not corrected, hypokalemia can occur."}, {"id": 10926, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing teaching to a client with gastroesophageal reflux disease. Which of the following dietary measures would be useful in preventing esophageal reflux?", "choices": [{"id": "a", "t": "Eating small frequent meals"}, {"id": "b", "t": "Increasing fluid intake"}, {"id": "c", "t": "Avoiding air swallowing with meals"}, {"id": "d", "t": "Adding a bedtime snack to the dietary plan"}], "correct": "a", "rationale": "Esophageal reflux worsens when the stomach is overdistended with food. An important strategy is to eat small, frequent meals. B I io", "whyNot": {"b": "Fluid intake should be decreased during meals to reduce abdominal distention.", "c": "Avoiding air swallowing does not prevent reflux.", "d": "Food intake in the evening should be strictly limited to reduce the incidence of nighttime reflux, so snacks are not recommended."}, "keyConcept": "Some degree of physiologic reflux occurs normally after meals, but physiologic reflex is asymptomatic. Gastroesophageal reflux disease refers to pathologic reflux of acidic stomach contents into the esophagus, causing symptoms of regurgitation and heartburn. Lifestyle modifications include weight loss in overweight clients and elevating the head of the bed for sleep. Tight clothing around the abdomen should be avoided as this can increase intragastric pressure and promote reflux of stomach contents. Some foods can trigger symptoms due to relaxation of the lower esophageal sphincter and should be avoided. These items include fatty foods, caffeine, chocolate, spicy foods, food with high fat content, carbonated beverages, and peppermint. Alcohol and tobacco should be avoided. Frequent small meals should be consumed instead of 3 large meals, to reduce gastric distention and pressure. a = o B f= 4 ° = a = g <"}, {"id": 10927, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "the subclavian vein. The current bag of solution was hung 24 hr ago, and 400 mL remain to infuse. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Remove the current bag and hang a new bag."}, {"id": "b", "t": "Infuse the remaining solution at the current rate and then hang a new bag."}, {"id": "c", "t": "Increase the infusion rate so the remaining solution is administered within 1 hr and hang a new bag."}, {"id": "d", "t": "Remove the current bag and hang a bag of dextrose 5% in water (D5W)."}], "correct": "a", "rationale": "o; TPN solutions contain high levels of dextrose and proteins which provide an excellent environment for bacterial growth. For this reason, TPN B ] solution should be discarded after hanging for 24 hr. | ©", "whyNot": {"b": "The current bag of TPN should not hang for longer than 24 hr due to the risk of infection.", "c": "The rate of TPN infusion should never be increased abruptly, due to the risk of hyperglycemia. The infusion rate is prescribed by the", "d": "Administration of TPN should never be discontinued abruptly, due to the sudden change in blood glucose that can occur. If a new bag of"}, "keyConcept": "While the client is receiving TPN, the nurse is responsible to protect the catheter insertion site, ensure proper function of the infusion pump, and monitor the client's electrolyte and glucose levels as well as the client's fluid balance. Intensive nutrition therapy is beneficial to the client but does present risks. Careful monitoring by the nurse can help to avoid complications."}, {"id": 10928, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "this medication? O A. Use proper sleep hygiene techniques to improve rest O B. Use emollients to relieve itching O C. Take the medication with some food to decrease the risk of nausea O D. Drink an adequate amount of fluid and exercise or ambulate to help prevent constipation", "choices": [{"id": "a", "t": "Use proper sleep hygiene techniques to improve rest"}, {"id": "b", "t": "Use emollients to relieve itching"}, {"id": "c", "t": "Take the medication with some food to decrease the risk of nausea"}, {"id": "d", "t": "Drink an adequate amount of fluid and exercise or ambulate to help prevent constipation"}], "correct": "d", "rationale": "A 3% Easy Oxycodone is an opioid medication. Related medications include hydrocodone, morphine, hydromorphone, and fentanyl. They bind to ! B 1% opioid receptors in the central nervous system and in the intestine. In the intestine, opioids slow gut peristalsis and increase the absorption | of water from the gut, which leads to constipation. Constipation is one of the most common side effects that result from opioid medications. c | 9% Although clients will develop tolerance to the analgesic effects, they rarely develop tolerance to the constipating effects of opioids. Proactive @D fF 88% measures include drinking 2-3 liters of fluid daily, exercising, consumption of a high-fiber diet, and defecating whenever there an urge arises. Stool softeners and stimulant laxatives can be used to treat constipation caused by opioid medications.", "whyNot": {"a": "Opioids are sedating. Breakthrough pain at night should be reported to the healthcare provider, as it may indicate inadequate analgesia.", "b": "Because opioids also cause histamine release, pruritus and flushing are characteristic. Use of antihistamines like diphenhydramine can", "c": "Nausea is associated with the stimulation of the opioid receptors in the chemoreceptor trigger zone in the brain and opioid receptors in"}, "keyConcept": "Constipation is a common side effect of opioid medications. Non-pharmacologic measures to reduce constipation include maintenance of adequate fluid intake, high fiber diet, physical activity. Stool softeners and stimulant laxatives are sometimes necessary."}, {"id": 10929, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "What is it? Symptoms: Itis immune system disease in which consumption of gluten causes damage the small -Diarrhea -Constipation -Stomach pain intestine. -Bloating Gluten is found in foods that -Gas contain wheat, rye, and barley -Anemia such as bread, pasta, crackers, -Osteoporosis cereals. References: https://www.niddk.nih.gov/health-information/digestive-diseases/celiac-disease", "choices": [{"id": "a", "t": "Green stool is not necessarily associated with celiac disease."}, {"id": "b", "t": "Celiac disease is an immunological small intestine enteropathy characterized by the inability to metabolize the gliadin component of dietary gluten found in grains such as wheat, barley, rye, and oats; this results in excessive glutamine that is toxic to the mucosal cells."}, {"id": "c", "t": "The client may sustain damage to intestinal villi with celiac disease, but there is not a complete absence."}, {"id": "d", "t": "The client is not at risk of dehydration because of celiac disease."}], "correct": "b", "rationale": "Celiac disease is an immunological small intestine enteropathy characterized by the inability to metabolize the gliadin component of dietary gluten found in grains such as wheat, barley, rye, and oats; this results in excessive glutamine that is toxic to the mucosal cells.", "whyNot": {"a": "Green stool is not necessarily associated with celiac disease.", "c": "The client may sustain damage to intestinal villi with celiac disease, but there is not a complete absence.", "d": "The client is not at risk of dehydration because of celiac disease."}, "keyConcept": "Celiac disease is also known as gluten-sensitive enteropathy. It is an immune-mediated inflammatory disease of the small intestine that is caused by sensitivity to dietary gluten and related proteins in individuals who are genetically predisposed. Celiac disease is not a food allergy, which are mediated by immunoglobulins G and E. Symptoms in infants that suggest a need for screening include failure to thrive, persistent diarrhea, chronic constipation, recurrent abdominal pain, vomiting, dental enamel hypoplasia of permanent teeth, short stature, pubertal delay, iron deficiency anemia not responsive to supplementation, dermatitis, aphthous stomatitis, pathologic fractures, arthritis or arthralgias, abnormal liver tests, and chronic fatigue. Celiac Disease What is it? Symptoms: Itis immune system disease in which consumption of gluten causes damage the small -Diarrhea -Constipation -Stomach pain intestine. -Bloating Gluten is found in foods that -Gas contain wheat, rye, and barley -Anemia such as bread, pasta, crackers, -Osteoporosis cereals."}, {"id": 10930, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is preparing to administer a cleansing enema to a client. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Don sterile gloves."}, {"id": "b", "t": "Assist the client to the left Sims' position."}, {"id": "c", "t": "Hang the enema container 60 cm (24 in) above the anus."}, {"id": "d", "t": "Lubricate 2 to 4 cm (0.8 to 1.6 in) of the tip of the rectal tube."}], "correct": "b", "rationale": "| 2% Easy The left side-lying or Sims' position makes it easier for the enema solution to flow by gravity into the sigmoid and descending colon, which OB rs ry will improve retention of the fluid. The nurse should also have the client's right leg flexed to facilitate insertion of the rectal tube. I © 4% om 13%", "whyNot": {"a": "The nurse should don clean gloves to administer an enema.", "c": "The height of the fluid container affects the speed of instillation. The maximum recommended height is 45 cm (18 in).", "d": "The nurse should lubricate 6 to 8 cm (2.5 to 3 in) of the tip of the rectal tube using water-soluble jelly."}, "keyConcept": "A nurse who is caring for a client needing a cleansing enema should be able to identify the supplies needed and administer the enema. The nurse should also be able to identify potential unexpected outcomes and the related interventions necessary. These can include the following: Unexpected Outcome Related interventions “Abdomen becomes rigid and distended and the client ‘Stop the enema, notify the provider, and obtain vital signs. reports severe pain ‘Abdominal pain or cramping develops ‘Stow the rate of instillation and have the client take slow, deep breaths. | Bleeding develops ‘Slop the enema, notify the provider, remain with the cient, and obtain vital signs."}, {"id": 10931, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client with suspected peptic ulcer disease has a positive urea breath test for H. pylori. Which of the following medications prescribed for this client could produce a false-negative test?", "choices": [{"id": "a", "t": "Ibuprofen"}, {"id": "b", "t": "Aspirin"}, {"id": "c", "t": "Hydrochlorothiazide"}, {"id": "d", "t": "Omeprazole"}], "correct": "d", "rationale": "Testing for H. pylori is performed to make the diagnosis and determine treatment in a client with suspected peptic ulcer disease (PUD). Cc Hi Helicobacter pylori bacteria is one of the most common causes of peptic ulcer disease and requires treatment when present. Medications ep | that can interfere with the accuracy of the test and cause a false negative include proton pump inhibitors such as omeprazole, H2 blockers. such as ranitidine, and bismuth preparations, including Pepto-Bismol.", "whyNot": {"a": "Ibuprofen does not interfere with the C14 urea breath test.", "b": "Aspirin does not interfere with the C14 urea breath test.", "c": "Hydrochlorothiazide does not interfere with the C14 urea breath test."}, "keyConcept": "Helicobacter pylori is a common cause of gastritis and peptic ulcer disease. When using the urea breath test for H. pylori testing, no food, drink, smoking or chewing gum should be used for at least two hours before the test. H2 blockers should not be taken for 2 days before the test. Bismuth compounds, antibiotics, and proton pump inhibitors should not be taken for a minimum of 14 days prior to the test."}, {"id": 10932, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for an elderly client with a suspected diagnosis of acute diverticulitis. Which of the following tests does the nurse anticipate will be ordered by the healthcare provider to confirm the diagnosis?", "choices": [{"id": "a", "t": "Upper Gl series"}, {"id": "b", "t": "Angiography"}, {"id": "c", "t": "Barium enema"}, {"id": "d", "t": "Abdominal CT scan"}], "correct": "d", "rationale": "‘a Diverticulosis refers to sac-like outpouchings in the wall of the colon, usually as the result of increased pressure in the colon in individuals B | who are constipated and strain when defecating. Diverticulosis occurs more frequently in adults over the age of 60. Diverticula can become inflamed when food and bacteria become trapped, which is known as acute diverticulitis. Clinical signs of diverticulitis include left lower c |_| quadrant pain and cramping, abdominal distention, intermittent constipation and other bowel irregularities, and fever. The diagnosis of @D | diverticulosis is made by colonoscopy or barium enema, usually done for other reasons. When the diverticula become inflamed, a barium enema and a colonoscopy are contraindicated since they may cause perforation of the inflamed tissue, resulting in peritonitis. An MRI, ultrasound, or abdominal CT with contrast are most frequently used to confirm the diagnosis. During the acute illness, the client should be consuming a low-fiber diet. Antibiotics and analgesics are used in treatment. If complications (including perforation of the intestine, hemorrhage, or intestinal obstruction) occur, surgery may be necessary. Diverticulosis Internal view", "whyNot": {"a": "Diverticulitis occurs in the large intestine. An upper Gl series can only visualize the esophagus, stomach, and part of the small intestine.", "b": "Angiography is used to diagnose intestinal ischemia, which results from atherosclerotic disease.", "c": "Abarium enema is contraindicated in acute diverticulitis due to the risk of perforation."}, "keyConcept": null}, {"id": 10933, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has undergone bariatric surgery for weight loss. Which of the following prescriptions by the healthcare provider should the nurse question?", "choices": [{"id": "a", "t": "Place the client in a low Fowler position"}, {"id": "b", "t": "Begin administration of morphine by patient-controlled analgesia pump (PCA)"}, {"id": "c", "t": "Recommend a clear diet low in carbohydrates for 48 hours"}, {"id": "d", "t": "Place a nasogastric tube for nausea and vomiting"}], "correct": "d", "rationale": "Dumping syndrome is a complication of bariatric surgery that is characterized by the rapid emptying of gastric contents into the intestine, Cc Hi which causes nausea, vomiting, diarrhea, diaphoresis, hypotension, and weakness. It is caused by the sudden presence of a large amount of e@D Dh hyperosmolar matter in the intestines, which contributes to a fluid shift from the vascular system into the intestinal lumen. Nasogastric tubes are contraindicated due to the potential risk of disruption of the surgical site, causing anastomotic leak and hemorrhage. If the client experiences nausea after surgery, intravenous antiemetic medication is the preferred treatment.", "whyNot": {"a": "Placing the client in the low Fowler position slows gastric emptying and is recommended during mealtime.", "b": "Analgesia by a patient-controlled pump is commonly prescribed after bariatric surgery.", "c": "Alow-carbohydrate diet of multiple small meals and separate consumption of food and fluid by at least 30 minutes is recommended to"}, "keyConcept": "Dumping syndrome is caused by rapid emptying of gastric contents into the intestine, after gastric bypass surgery. The hyperosmolar load results in rapid fluid shifts from the intravascular space into the lumen of the intestine. Symptoms include nausea, vomiting, diarrhea, diaphoresis, and hypotension."}, {"id": 10934, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client refuses to look at or care for a new colostomy. Which of the following statements by the nurse would be most appropriate?", "choices": [{"id": "a", "t": "\"It has been 4 days since your surgery, and you will soon be discharged. You have to learn to care for your colostomy before you leave the hospital.\""}, {"id": "b", "t": "\"I think we will need to teach your spouse to care for your colostomy if you are not going to be able to do it.\" O C.\"l understand how you feel. It is important for you to feel attractive and you think having a colostomy changes your attractiveness.\""}, {"id": "d", "t": "\"I can see that you are upset. Let's talk about your concerns.\""}], "correct": "d", "rationale": "| 2% Easy It is important for the nurse to recognize that people go through a grieving process when adjusting to a colostomy. The nurse should be B | a0 accepting and provide the client with opportunities to share their concerns and feelings when the client is ready.", "whyNot": {"a": "Lecturing the client about the need to learn how to care for the colostomy is not encouraging.", "b": "Attempting to shame the client into caring for the colostomy by implying the client's spouse will have to assume care can be"}, "keyConcept": "Clients who must undergo creation of an ostomy for fecal diversion commonly experience physical, psychological, and emotional stress related to concerns and fear concerning sexuality, social acceptance, and other perceived life changes. An important nursing task is to assist the client to cope and adapt psychologically to significant lifestyle changes and alterations in body image associated with the surgery. The nurse should provide acceptance and support, while encouraging the client to share concerns."}, {"id": 10935, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is preparing to administer a nasogastric (NG) tube feeding to a client. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Determine tube placement by aspirating and checking the pH of the secretions."}, {"id": "b", "t": "Follow the feeding solution with 100 mL of water."}, {"id": "c", "t": "Use the plunger of the syringe to gently push the feeding through the tube."}, {"id": "d", "t": "Chill the feeding solution prior to administration."}], "correct": "a", "rationale": "The nurse should check the placement of the tube by aspirating secretions and checking the pH levels of the secretions. A pH of 6 or greater B I a indicates intestinal or pulmonary placement. cf 5%", "whyNot": {"b": "The nurse should follow the feeding solution with 30 mL of water.", "c": "The nurse should pour the solution into the barrel of the syringe and allow it to flow through the tube by gravity. °", "d": "The nurse should administer feeding formula at room temperature. Chilled formula can cause gastric cramping and gastrointestinal ="}, "keyConcept": "The nurse is responsible for administering enteral feedings through a nasogastric (NG) tube. The nurse should be able to check proper tube placement, administer the feeding, and evaluate the effectiveness of the feeding."}, {"id": 10936, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client diagnosed with a flare of chronic pancreatitis. Which of the following prescriptions does the nurse anticipate for this client?", "choices": [{"id": "a", "t": "Adiet that is high in potassium"}, {"id": "b", "t": "Enzymatic therapy"}, {"id": "c", "t": "Adiet that is low in complex proteins"}, {"id": "d", "t": "Corticosteroid therapy"}], "correct": "b", "rationale": ", maintain nutritional status, OB rd cen and to relieve pain. The client should be advised to eat a diet that is high in protein and carbohydrates and low in fats. Corticosteroid therapy is not indicated. Pancreatitis does not lead to alterations of potassium levels, however, vitamins C and B can become depleted so these c |_| 17% vitamins are often supplemented. D Hi 17%", "whyNot": {"a": "Potassium supplements are typically not needed for a client with pancreatitis.", "c": "A client with pancreatitis should increase protein and carbohydrate intake but decrease the intake of fats.", "d": "Corticosteroid therapy is not indicated for use in pancreatitis."}, "keyConcept": "Chronic pancreatitis is characterized by unrelenting pain with occasional flares. It may eventually lead to pancreatic insufficiency as the disease progresses. Pancreatic enzyme replacement therapy may be prescribed to relive pain for a client with chronic pancreatitis by suppressing stimulation of the pancreatic exocrine glands. It contains amylase, lipase, and protease, which aid in the digestion of fats, carbohydrates, and proteins. Small, low-fat meals and adequate hydration are also recommended."}, {"id": 10937, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Which test would be most useful to view the structures of the interior of the large intestine?", "choices": [{"id": "a", "t": "Fecal occult blood test"}, {"id": "b", "t": "Flexible sigmoidoscopy"}, {"id": "c", "t": "Endoscopic retrograde cholangiopancreatography"}, {"id": "d", "t": "Barium swallow"}], "correct": "b", "rationale": ". Pictures of the colon are then transmitted to a monitor to allow the healthcare provider to view the structures of the interior of the colon and to obtain tissue for biopsy of any abnormalities. c |_| 17% of 12%", "whyNot": {"c": "Endoscopic retrograde cholangiopancreatography (ERCP) is used to evaulate the biliary system, not the large intestine.", "d": "A barium swallow typically looks at the upper gastrointestinal tract, not the large intestine. A barium enema may be used to look at the"}, "keyConcept": "A flexible sigmoidoscopy is one method used for screening for colorectal cancer in conjunction with fecal occult blood testing and for investigation of gastrointestinal complaints. Only the last 61 cm of colon can be visualized with flexible sigmoidoscopy, The entire colon can be visualized with colonoscopy."}, {"id": 10938, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A client has a deficiency of fat-soluble vitamins. The nurse understands that the body must produce which of the following for absorption of fat-soluble vitamins? O Bile O B. Amylase O C. Intrinsic factor O D. Lipase", "choices": [{"id": "a", "t": "D E K"}, {"id": "b", "t": "Amylase is necessary for digestion of starches."}, {"id": "c", "t": "Intrinsic factor is necessary for absorption of B vitamins."}, {"id": "d", "t": "Lipase is necessary for digestion of lipids."}], "correct": "a", "rationale": "The fat-soluble vitamins are vitamins D, E, A, and K. Vitamins cannot be synthesized in the body, so they must be consumed in small amounts. Cc | | in foods and/or supplements. They remain stored in the body for long periods of time and are associated with an increased risk of toxicity D || compared to water-soluble vitamins. These vitamins must be absorbed into the enterocyte cells of the intestine after they are solubilized by bile salts into micelles. Fat soluble vitamins and sources A D E K Se % Vision, Strengthens bones, Immune system, Blood clotting, Reproduction, Calcium absorption, Flushes toxins Bone health Bone health, immune system Immune system, ‘Skin", "whyNot": {"b": "Amylase is necessary for digestion of starches.", "c": "Intrinsic factor is necessary for absorption of B vitamins.", "d": "Lipase is necessary for digestion of lipids."}, "keyConcept": "Fat soluble vitamins are not produced in the body, so they must be consumed in diet or supplements. Bile salts are necessary for solublization into micelles for their absorption by intestinal cells."}, {"id": 10939, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is instructing a client about preparations for a colonoscopy. She explains that a clear liquid diet includes which of the following?", "choices": [{"id": "a", "t": "Gelatin, tea, milk"}, {"id": "b", "t": "Tea, cola, milk"}, {"id": "c", "t": "Apple juice, tea, water"}, {"id": "d", "t": "Ice cream, gelatin, tea"}], "correct": "c", "rationale": "| 2% Easy Aclear liquid diet includes foods and liquids that have thin consistency and are mostly transparent. Apple juice, tea, and water are included , as are gelatin and broth.", "whyNot": {"a": "Gelatin and tea are included in a clear liquid diet, but milk is not a clear liquid.", "b": "Tea and cola may be included as part of a clear liquid diet, but milk is not a clear liquid.", "d": "While gelatin and tea may be included in a clear liquid diet, ice cream is not a clear liquid."}, "keyConcept": "Aclear liquid diet may be recommended for 24-48 hours prior to colonoscopy. Clear liquid diets exclude red or purple colored substances and alcohol. Examples of clear liquids include water, tea, plain coffee, lemonade from powdered mix, carbonated beverages and soda, clear juices such as apple and white grape, plain or flavored gelatin, sports drinks such as Gatorade®; popsicles, hard candy, fat-free broth, bouillon or consommé."}, {"id": 10940, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "@ @ X& Viralm sx Record M Inbox( M Inbox- ] Untitle: Untitle (4 Google @ TEASP Online & MarkkK @ Micros (@QNERWSUCNEMCE @ ATITE G Newcl Nc x) + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Melena"}, {"id": "b", "t": "Occult blood"}, {"id": "c", "t": "Hematochezia"}, {"id": "d", "t": "Steatorrhea"}], "correct": "c", "rationale": "A || 13% Hard Hematochezia refers to bright red blood found on the surface of stool. It appears when there is bleeding in the lower intestinal tract or the B | aa anus.", "whyNot": {"a": "Melena means black, tarry stools from internal bleeding, not bright red blood on the stool.", "b": "Occult blood cannot be detected when looking at the stool; in order to know if occult blood is present, it must be tested.", "d": "Steatorrhea refers to increased fat content in the stools, not blood in the stools."}, "keyConcept": "Bright red blood in stool is generally the result of bleeding in the lower GI tract, including the rectum. Bleeding in the upper GI tract usually manifests as tarry, black stools (melena) due to the increased transit time through the bowel. GI bleeding may not be visible, but a fecal occult blood test will react positively with a stool sample when microscopic amounts of blood are present in stool."}, {"id": 10941, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing education about dietary recommendations for a client with irritable bowel syndrome. Which of the following menu choices reflects client understanding?", "choices": [{"id": "a", "t": "Bananas, cabbage, and milk"}, {"id": "b", "t": "Fish, pita bread, and beef broth"}, {"id": "c", "t": "Pork chops, honey, and tea"}, {"id": "d", "t": "Beans"}], "correct": "b", "rationale": "i Dietary management is an important part of the management of irritable bowel syndrome, a functional bowel disorder that is characterized o: by alterations in colonic motility. Patients with irritable bowel syndrome experience abdominal pain with chronic constipation, diarrhea, or mixed constipation and diarrhea. Dietary measures include restriction of caffeine; alcohol; and avoidance of gas-producing foods, including c | cruciferous vegetables (cauliflower, broccoli, cabbage, onions) and bananas. Foods that are spicy or fatty should be avoided since they can D | irritate the gastrointestinal tract. Dairy products and hot and cold foods and beverages are also gastrointestinal irritants that should be avoided.fermentable oligosaccharides, Disaccharides, monosaccharides, and polyols, known as FODMAPs, include honey, wheat, and high- fructose corn syrup. They should also be avoided. Increased fiber intake is encouraged, including consumptions of nuts, fruits, vegetables, grains, legumes, and fruits. Protein, bread, and bland foods are usually well-tolerated by individuals with IBS.", "whyNot": {"a": "Dairy products should be avoided, as they can irritate the Gl tract. Bananas and cabbages tend to increase production of gas and should", "c": "Honey is a FODMAP and should be avoided by clients with IBS.", "d": "Beans increase gas production and should be avoided. Cheese is a dairy product that is a gastrointestinal irritant and should be avoided."}, "keyConcept": "Irritable bowel syndrome is a chronic disorder that affects up to 20% of the US population. It is characterized by intermittent abdominal pain with alterations in bowel function. Clients will experience constipation, diarrhea, or mixed constipation and diarrhea. Other symptoms include flatulence, bloating, an urge to defecate; with urgency, and a sensation of incomplete evacuation. Dietary measures are an important part of management. Clients should avoid gas-producing foods, dairy products, caffeine, alcohol, and foods in the FODMAP group. Treatments include anticholinergic medications, stress management, and relaxation techniques, and acupuncture."}, {"id": 10942, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client with a feeding tube who experiences nausea and vomiting with intermittent feeding. Which of the following is the most appropriate initial nursing intervention?", "choices": [{"id": "a", "t": "Add fiber to the feeding"}, {"id": "b", "t": "Reduce the rate of administration"}, {"id": "c", "t": "Carefully clean and protect the stoma"}, {"id": "d", "t": "Reposition the tube"}], "correct": "b", "rationale": ". Nausea and vomiting are often caused by too rapid OB sd omar administration of feeding. Before administration of a bolus tube feeding, the nurse should check residual volume by aspirating all stomach contents and feeding should be held if the residual is greater than 150 mL or as otherwise prescribed. The nurse should warm the feeding to c I 3% room temperature, as cold feedings are more likely to cause abdominal cramping. When using an open system (syringe), the plunger is , which should be pinched or clamped to prevent entrance of excess air into the stomach. The feeding is added to the barrel of the syringe, which can be raised or lowered to adjust the flow rate. Other causes of nausea and vomiting include fat malabsorption, lactose intolerance, contamination of food, and contamination of the feeding bag. Other interventions that may reduce nausea, vomiting, or abdominal discomfort include cleaning the feeding set thoroughly if it is reusable, cleaning the top of the formula can before opening, use of a low-fat formula, and advising the client to remain sitting or in the Fowler's position for 30 minutes after feeding.", "whyNot": {"a": "Fiber is added to the feeding to reduce diarrhea.", "c": "Cleaning and protecting the stoma is an important nursing intervention, but it is not the most appropriate initial intervention in this case.", "d": "The tube requires repositioning if it migrates."}, "keyConcept": "Nausea and vomiting may occur if tube feedings are administered at a rapid rate. The initial intervention is to reduce the rate of feeding. With an open system, the flow rate can be adjusted by raising or lowering the syringe."}, {"id": 10943, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing discharge teaching to a client who has a new colostomy. The client asks if it is all right to get the colostomy bag wet. Which of the following is the most appropriate response?", "choices": [{"id": "a", "t": "“Yes, you can get it wet, but you may want to empty it before swimming or bathing.”"}, {"id": "b", "t": "“Yes, you can get it wet if you use a specially-designed waterproof bag.”"}, {"id": "c", "t": "“No, you cannot get it wet and you must apply plastic wrap or a plastic bag before swimming or bathing.”"}, {"id": "d", "t": "“No, you cannot get it wet and you should remove the bag before swimming or bathing.”"}], "correct": "a", "rationale": "A client who has a colostomy bag connected to a stoma for output may swim or bathe with the bag in place. The bag is designed to stick to the skin and remain in place even if it becomes wet. The nurse should counsel the client to empty the bag beforehand, though, as others may be able to view the contents of the bag during activities like swimming.", "whyNot": {"b": "A standard ostomy bag will stay in place while swimming or bathing; the client does not need a special bag.", "c": "Application of plastic wrap is unnecessary before water-based activities.", "d": "The client should not remove the collection bag before swimming or bathing, as output from the stoma could contaminate the water."}, "keyConcept": "Pouching systems are waterproof. However, the client may feel more secure by wearing an ostomy belt or placing tape around the edges of the skin barrier when planning to bathe or swim. If the client uses tape, it should not be removed after leaving the water, as this may cause leakage. The client should be instructed to change the skin and the back of the skin barrier when changing the pouching system. A mirror can be used to check skin under the stoma. Areas where stool has leaked may need reinforcement with skin barrier strips, rings or paste when replacing the bag."}, {"id": 10944, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "Ahome health nurse is performing an initial assessment of a client who has Crohn's disease and is experiencing fecal incontinence. Which of the following actions should take priority?", "choices": [{"id": "a", "t": "Instruct the client to avoid fried, acidic, and spicy foods."}, {"id": "b", "t": "Use positive communication skills to provide support for the client."}, {"id": "c", "t": "Check the skin around the client's anus and rectum for indications of breakdown."}, {"id": "d", "t": "Encourage the client to keep a bowel movement diary to identify triggers."}], "correct": "c", "rationale": "A Hi 14% Moderate The greatest risk for this client is infection from skin breakdown. Therefore, the first action the nurse should take is to assess the client's skin B i at around the rectum and on the buttocks for open sores or any indications of breaks in the skin. The digestive enzymes in stool can irritate the client's skin and cause redness and lesions. O€ Le 69% off 10%", "whyNot": {"a": "Fried, acidic, and spicy foods have an increased likelihood of causing fecal incontinence. The nurse should instruct the client to bake or", "b": "Fecal incontinence can often cause clients to feel embarrassed. The nurse should maintain a positive and supportive attitude to help the", "d": "A bowel movement diary to identify triggers is an important tool to help the client develop a regular toileting routine. The nurse should"}, "keyConcept": "Fecal incontinence is the inability to control bowel movements. Accidental bowel leakage is usually not a serious medical problem, but it can certainly interfere with the client's daily life. Clients who have fecal incontinence might avoid social activities for fear of embarrassment. Clients have an increased risk of developing an infection from skin breakdown if the stool is not removed from the skin promptly. Therefore, the nurse should assess the skin around the client's rectum and on the buttocks for any indication of redness, lesions, or breakdown often to prevent infection."}, {"id": 10945, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "initial nursing action? O A. Complete a head-to-toe assessment O B. Place a nasogastric tube O C. Notify the healthcare provider O D. Establish IV access", "choices": [{"id": "a", "t": "Complete a head-to-toe assessment"}, {"id": "b", "t": "Place a nasogastric tube"}, {"id": "c", "t": "Notify the healthcare provider"}, {"id": "d", "t": "Establish IV access"}], "correct": "c", "rationale": "| 3% Abluish discoloration around the umbilicus is known as Cullen’s sign. It reflects pancreatic necrosis or intraabdominal bleeding, typically in ec ; 54% clients with pancreatitis. The healthcare provider should be notified. D Hl 27% a © o 2 ° s a = a <", "whyNot": {"a": "Acomplete assessment is important, but the client has evidence of intraabdominal bleeding, so the priority is notifying the healthcare", "b": "A nasogastric tube may be placed to prevent emesis, reduce stomach acid in the duodenum, and reduce abdominal distension. This is not", "d": "A client with pancreatitis will be NPO and require IV fluids, but this is not the priority."}, "keyConcept": "When prioritizing tasks for client care, priority is given to items that pose immediate harm or threats to client safety. Airway, breathing, and circulation are prioritized. Intraabdominal bleeding is a priority item and notification of the healthcare provider is indicated."}, {"id": 10946, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is teaching a group of nurses about chronic gastritis. Which of the following should be included in this in-service?", "choices": [{"id": "a", "t": "Clients with chronic gastritis should receive a monthly injection of vitamin B12."}, {"id": "b", "t": "Clients with chronic gastritis may develop pernicious anemia from reduced production of hydrochloric acid by damaged cells in the stomach."}, {"id": "c", "t": "Vitamin K deficiency results in coagulopathy in these clients due to malabsorption from chronic gastritis."}, {"id": "d", "t": "Increased production of intrinsic factor results in pernicious anemia in clients with chronic gastritis."}], "correct": "a", "rationale": "Parietal cells are damaged in clients with chronic gastritis. They produce intrinsic factor, which is necessary for absorption of vitamin B12. Chronic gastritis is associated with a risk of deficiency of B12, which causes pernicious anemia. Monthly B12 injections are necessary for treatment.", "whyNot": {"b": "Parietal cells produce intrinsic factor, necessary for absorption of vitamin B12. This is the cause of pernicious anemia.", "c": "Vitamin K deficiency occurs in liver disease.", "d": "Decreased cleavage and production of intrinsic factor results in decreased absorption of vitamin B12 and pernicious anemia."}, "keyConcept": "Clients with chronic gastritis may have a deficiency of vitamin B12, as a result of damage to parietal cells in the gastric mucosa. Parietal cells produce intrinsic factor, necessary for absorption of B12 in the diet."}, {"id": 10947, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "should be included in the nurse’s education plan to prepare the client for the test?", "choices": [{"id": "a", "t": "High-fat meal morning of the test"}, {"id": "b", "t": "NPO from midnight before the test"}, {"id": "c", "t": "Bismuth salicylate (Pepto-Bismol) should be taken the night before the test"}, {"id": "d", "t": "Clear liquids only until the test"}], "correct": "b", "rationale": "(H. pylori) bacteria. Other causes include ingestion of Cc Hi 14% irritants, including NSAIDs (nonsteroidal anti-inflammatory drugs) and increased production of stomach acid due to stress. If H. pylori is D || 13% present, the treatment will include a combination of two antibiotics (clarithromycin plus amoxicillin or Flagyl plus tetracycline) with a fm] proton pump inhibitor such as omeprazole (Prilosec) or bismuth salicylate (Pepto-Bismol). Urea breath testing for H. pylori requires that the 2 client remain NPO after midnight. The test is performed by having the client ingest a carbon-enriched urea solution tagged with a g radioisotope. The bacteria convert urea to ammonia and carbon dioxide, and the presence of radiolabeled carbon dioxide indicates presence = of H. pylori. = <", "whyNot": {"a": "The client should have nothing by mouth after midnight on the day of the test.", "c": "Bismuth salicylate interferes with urea breath testing and may result in a false negative. This medication should be discontinued at least 4", "d": "The client should remain NPO after midnight."}, "keyConcept": "Helicobacter pylori is a frequent cause of peptic ulcer disease. Tests for H. pylori include urea breath testing. After the client ingests carbon- enriched urea solution w/radioisotope tag. If H. pylori is present, the bacteria will convert urea to ammonia and radiolabeled carbon dioxide, which confirms presence of H. pylori."}, {"id": 10948, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has a nasogastric tube that is connected to low-intermittent suction. Which method is most appropriate for determining if the suction is working appropriately?", "choices": [{"id": "a", "t": "Temporarily disconnect the tubing between the NG and the drainage tube and listen for suction noises."}, {"id": "b", "t": "Turn up the suction on the wall-mounted device and listen with a stethoscope over the client’s abdomen"}, {"id": "c", "t": "Instill 10 mL of air into the NG tube and listen with a stethoscope over the client’s abdomen"}, {"id": "d", "t": "Record the volume in the suction container every four hours."}], "correct": "a", "rationale": "oc, i 43% Hard A nurse who is caring for a client who is undergoing gastric decompression by low-intermittent suction must monitor regularly to ensure that B I a the suction is working and set at the appropriate level. To do this, the nurse should temporarily disconnect the tubing between the NG and the drainage tube and listen for suction. c |_| 20% iz 32% The most common nasogastric tube used for gastric decompression is the double-lumen gastric (Salem) sump tube. It is made of clear plastic and sized according to the French method. The Salem tube can be used to irrigate the stomach or to draw fluid and gas from the stomach.", "whyNot": {"b": "The nurse should disconnect the suction from the client before turning up the suction level. Turning the suction up too high can damage", "c": "This procedure assesses tube placement. It does not assess suction pressure.", "d": "This does not show that the suction is currently working appropriately."}, "keyConcept": "Intermittent suction reduces the risk of mucosal erosion by alternating periods of suction with release of suction. Intermittent suction is used more frequently than continuous suction because of the reduced risk of damage to the mucosa. To prepare for nasogastric suction, the nurse should have the suction device and collection container connected to the suction source, usually a wall-mounted suction source. Portable suction machines are also available. The suction device has an on/off switch, a setting for intermittent or continuous suction, and a dial to set the amount of suction, which is measured in mm Hg. The nurse should verify the amount of suction prescribed. After placement and verification of the tube’s position, a tapered adapter to used to connect the nasogastric tube to the suction tubing. Wearing gloves, the nurse should connect the proximal end of the nasogastric tube to the distal end of the suction tubing. The nurse should use the least amount of suction pressure necessary. The suction gauges must be checked every 2 to 4 hours to verify the direction of flow. To test the suction set- up, the nurse should temporarily disconnect the tubing between the nasogastric and drainage tubing to listen for the sound of the suction. The container must be replaced before it becomes full to maintain suction."}, {"id": 10949, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is providing teaching for a client with a new prescription of aluminum hydroxide. Which of the following statements by the client indicates understanding of the nurse's teaching?", "choices": [{"id": "a", "t": "“My medication should be taken with food.”"}, {"id": "b", "t": "“I should eat a high-fat diet.”"}, {"id": "c", "t": "“Diarrhea is normal with this medication.”"}, {"id": "d", "t": "“I should wait an hour before take other oral medications.”"}], "correct": "d", "rationale": "A || 26% Moderate Aluminum hydroxide is an antacid that may be prescribed to treat symptoms of heartburn and indigestion. Oral medications should not be B | a0 taken within 1 hour of an antacid. Antacids can be taken up to 7 times a day, 1-2 hours after meals and at bedtime. Aluminum hydroxide and magnesium hydroxide are both antacids that neutralize acid in the gut, providing relief of symptoms. c | 8%", "whyNot": {"a": "Antacids should be taken following a meal.", "b": "A high-fiber diet is recommended with aluminum hydroxide.", "c": "Constipation may occur with aluminum hydroxide."}, "keyConcept": "Oral aluminum hydroxide is used as an antacid. It works by neutralization of acid in the gut. It should be taken after meals and at bedtime to relieve symptoms of gastroesophageal reflux disease. It should be used cautiously by clients who have renal disease or liver disease."}, {"id": 10950, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "The nurse is caring for a client experiencing constipation. Which of the following medications will the nurse expect to administer to the client?", "choices": [{"id": "a", "t": "Nitroglycerin tablets"}, {"id": "b", "t": "Glycerine suppositories"}, {"id": "c", "t": "Aminophylline"}, {"id": "d", "t": "Nitroprusside"}], "correct": "b", "rationale": "Glycerine suppositories are osmotic laxatives. Glycerine draws water into the lumen of the colon for relief of constipation. The nurse should assess the client for abdominal distention, presence of bowel sounds, normal pattern of bowel function, and color, consistency, and amount of stool produced. Suppositories should only be used for treatment of constipation for a short period of time.", "whyNot": {"a": "Nitroglycerin tablets are used to treat angina, not constipation.", "c": "Aminophylline is not used to treat constipation.", "d": "Nitroprusside is used to treat elevated blood pressure and chest pain, not constipation."}, "keyConcept": null}, {"id": 10951, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has 3 mail-in fecal occult blood tests. Which of the following instructions should the nurse relay to the client?", "choices": [{"id": "a", "t": "No dietary changes are necessary."}, {"id": "b", "t": "The bowel test will determine if microorganisms are in the gastrointestinal tract."}, {"id": "c", "t": "This is a screening test for colon cancer."}, {"id": "d", "t": "The client will continue to take warfarin during the test period."}], "correct": "c", "rationale": "Fecal occult blood testing is used to identify microscopic amounts of blood in the stool. It is used as a screening test for colon cancer. Because it is not specific for colon cancer, additional testing with colonoscopy is necessary if a screening exam is positive.", "whyNot": {"a": "Clients should avoid red meat, poultry, and fish when planning to obtain stool specimens for occult blood, as these items can interfere", "b": "The test only determines whether blood is present in the stool.", "d": "Anticoagulants may interfere with the test, and the client should ask the healthcare provider about stopping an anticoagulant prior to"}, "keyConcept": "Fecal occult blood tests are used to identify microscopic amounts of blood in stool, which may indicate colon cancer or other sources of gastrointestinal bleeding, including peptic ulcers. If the tests are positive, further examination of the colon is indicated to determine the cause of bleeding."}, {"id": 10952, "cat": "NCLEX 16-GASTROINTENSTINAL", "stem": "A nurse is caring for a client who has extracellular fluid volume (ECV) deficit due to vomiting and diarrhea and requires IV fluid therapy. Which of the following solutions should the nurse prepare to infuse?", "choices": [{"id": "a", "t": "Dextrose 5% in lactated Ringer's"}, {"id": "b", "t": "3% sodium chloride"}, {"id": "c", "t": "0.9% sodium chloride"}, {"id": "d", "t": "Dextrose 10% in water"}], "correct": "c", "rationale": "A client who is experiencing ECV due to increased gastrointestinal output has an isotonic imbalance and will require a sodium-containing isotonic solution for fluid therapy. This type of solution will expand ECV, both vascular and interstitial, and will help rehydrate the cells.", "whyNot": {"a": "Dextrose 5% in lactated Ringer's is a hypertonic IV solution, which will pull additional water from the client’s cells and worsen the fluid", "b": "3% sodium chloride is a hypertonic IV solution, which will pull additional water from the client’s cells and worsen the fluid deficit.", "d": "Dextrose 10% in water is a hypertonic IV solution, which will pull additional water from the client’s cells and worsen the fluid deficit."}, "keyConcept": "A nurse who is caring for a client who has ECV deficit due to increased gastrointestinal output should be able to identify the type of solution that the client will need for fluid therapy. There are various types of intravenous solutions the nurse should be able to identify: Intravenous Solutions Hypertonic Hypotonic Dextrose 10% in water (0.225% sodium chiorde 394 0F 5% soxdum chionde (45% sodium chide Dextrose 5% in 0.45% sodium chloride Dextrose 5% in 0.9% sodium chloride Dextrose 5% i lactated Ringer's"}], "nclex_19_health_promotion_maint": [{"id": 10953, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Jaundice"}, {"id": "b", "t": "Bleeding"}, {"id": "c", "t": "Feeding and vital signs"}, {"id": "d", "t": "Apgar scores"}], "correct": "c", "rationale": "Aneonate undergoes extensive assessment after birth, but continuing assessments are performed throughout the hospitalization. Assessments during hospitalization should include general observations about airway, focussing on noises, secretions, cough, any artificial airways; breathing: bilateral air entry and movement, breath sounds, respiratory rate, rhythm, work of breathing; and circulation, including pulse, skin color and moisture, skin turgor, capillary and refill time. Focused assessment of any problem areas is also performed during periodic assessments.", "whyNot": {"a": "Jaundice typically does not develop in the first hour after birth. D || 21%", "b": "The infant is not at high risk for bleeding.", "d": "Apgar scores should be completed the first few minutes after birth, not in the first hour."}, "keyConcept": "Aneonate undergoes extensive assessment after birth, but continuing assessments are performed throughout the hospitalization. Assessments during hospitalization should include general observations about airway, focussing on noises, secretions, cough, any artificial airways; breathing: bilateral air entry and movement, breath sounds, respiratory rate, rhythm, work of breathing; and circulation, including pulse, skin color and moisture, skin turgor, capillary and refill time. Focused assessment of any problem areas is also performed during periodic assessments."}, {"id": 10954, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Sf Viralr = Ss Recor = Inbox % Inbox Until Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc N x] G GERO + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Jaundice"}, {"id": "b", "t": "Bleeding"}, {"id": "c", "t": "Feeding and vital signs"}, {"id": "d", "t": "Apgar scores"}], "correct": "c", "rationale": "A Hi 14% Moderate The infant should be monitored for stable vital signs and the nurse should ensure that the mother tries to feed him. B I Et", "whyNot": {"a": "Jaundice typically does not develop in the first hour after birth. D Hl 21%", "b": "The infant is not at high risk for bleeding.", "d": "Apgar scores should be completed the first few minutes after birth, not in the first hour."}, "keyConcept": "Aneonate undergoes extensive assessment after birth, but continuing assessments are performed throughout the hospitalization. Assessments during hospitalization should include general observations about airway, focussing on noises, secretions, cough, any artificial airways; breathing: bilateral air entry and movement, breath sounds, respiratory rate, rhythm, work of breathing; and circulation, including pulse, skin color and moisture, skin turgor, capillary and refill time. Focused assessment of any problem areas is also performed during periodic assessments. a = o B f= 4 ° = a = g <"}, {"id": 10955, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "fetal heart rate monitor reveals minimal variability and bradycardia. Which of the following tasks does the nurse anticipate?", "choices": [{"id": "a", "t": "Place the client in the knee-to-chest position"}, {"id": "b", "t": "Prepare for immediate cesarean delivery"}, {"id": "c", "t": "Prepare for forceps delivery"}, {"id": "d", "t": "Prepare to suction the neonate with an endotracheal tube below the vocal cords before first attempts at breathing"}], "correct": "b", "rationale": "This describes uterine rupture, a life-threatening emergency. It can be complete, which involves the uterine wall and peritoneal cavity, with internal bleeding. Uterine rupture can also be incomplete, which refers to the dehiscence of a scar after a prior cesarean birth. There may not be internal bleeding present with incomplete rupture. Risk factors include uterine trauma, including previous cesarean section; congenital uterine abnormalities; polyhydramnios, multi-fetal gestation, and large for gestational age; hyperstimulation of the uterus, including administration of oxytocin; forceps-assisted delivery, and external or internal version of the fetus. Oxytocin is used to stimulate uterine contractions, either to initiate or to augment labor.", "whyNot": {"a": "The Trendelenburg position is recommended for uterine rupture. The knee-to-chest position is recommended for uterine cord prolapse.", "c": "Forceps delivery is a risk factor for uterine rupture.", "d": "Meconium in the amniotic fluid is an indication for suctioning."}, "keyConcept": "Oxytocin is used to stimulate uterine contractions, either to initiate or to augment labor. It increases the risk of uterine rupture, particularly in women who have had a prior cesarean section. Oxytocin is administered by an infusion pump and the dose is typically increased until labor progress is normal, or strong contractions occur at two- to three-minute intervals. Uterine and fetal monitoring are required. Uterine tachysystole, which refers to more than 5 contractions in ten minutes, is an adverse effect that can result in fetal hypoxemia."}, {"id": 10956, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is preparing to teach about self-administration of insulin to an adult client who has a low literacy level. Which of the following strategies should the nurse use to enhance the client's understanding?", "choices": [{"id": "a", "t": "Simplify terms using acronyms."}, {"id": "b", "t": "Link new information with what the client already knows."}, {"id": "c", "t": "Provide the client with written materials using large print."}, {"id": "d", "t": "Plan on no more than one or two teaching sessions."}], "correct": "b", "rationale": "Teaching begins with an assessment of knowledge the client already has or what the client has already experienced. For clients who cannot read or read well, the nurse must use other strategies for learning, such as demonstrations, role-playing, and modeling.", "whyNot": {"a": "The nurse should use short, simple words. Using acronyms can reduce understanding and cause confusion.", "c": "If the client has a low literacy level or cannot read or read well, printed materials will not help. Large-print materials are appropriate for", "d": "The nurse should divide the teaching into multiple sessions. Dividing information into multiple, short sessions that emphasize one key"}, "keyConcept": "After nurses assess clients for barriers to learning, they must tailor their teaching strategies accordingly. Additional teaching strategies for clients who have a low literacy level include asking for return demonstrations, using \"teach back\" methods, holding one-on-one discussions, conducting group discussions, using discovery, answering questions, giving explanations, offering descriptions, giving examples, emphasizing key information, showing images, and reinforcing through repetition."}, {"id": 10957, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing information at a community center about screening for cancer prevention. Which of the following statements should the nurse include in the teaching? O A.\"Females should have a mammogram every 2 years beginning at age 45.\" O B. \"Males and females should have a colonoscopy every 5 years beginning at age 60.\" O C. \"Females will need to have an annual breast examination after the age of 40.\" O D. \"Males and females should have a fecal occult test done every 2 to 3 years.\"", "choices": [{"id": "a", "t": "Female clients should begin annual mammograms at age 40."}, {"id": "b", "t": "Both male and female clients should have a colonoscopy at age 50 and then every 10 years thereafter."}, {"id": "c", "t": "mw | 27% ~~ Hard Female clients should have annual breast exams after the age of 40."}, {"id": "d", "t": "Both male and female clients should have a fecal occult test done every year."}], "correct": "c", "rationale": "mw | 27% ~~ Hard Female clients should have annual breast exams after the age of 40. 8 13% Annual mammograms after age 40 (earlier if family history of cancer) ec | 51% off 8% Provider visit annual for manual breast examination Colonoscopy screening after age 50 and repeated every 10 years (unless abnormal findings, then more frequently) Annual fecal occult blood test Annual digital exams (most often for males)", "whyNot": {"a": "Female clients should begin annual mammograms at age 40.", "b": "Both male and female clients should have a colonoscopy at age 50 and then every 10 years thereafter.", "d": "Both male and female clients should have a fecal occult test done every year."}, "keyConcept": "Early identification and diagnosis of cancer can reduce the incidence of death from cancer or cancer complications. The nurse should inform clients of the following screening recommendations:"}, {"id": 10958, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following findings during an assessment of a child who is 30 months old requires further evaluation?", "choices": [{"id": "a", "t": "The child's current weight is 6x the weight at birth."}, {"id": "b", "t": "Primary dentition (20 teeth) is complete."}, {"id": "c", "t": "Chest circumference is greater than head circumference."}, {"id": "d", "t": "The child speaks in 3-word sentences."}], "correct": "a", "rationale": "At 30 months, toddlers have usually quadrupled their birthweight, so this suggests the child is overweight and will require further evaluation. Physical development from 1-3 years of age is marked by slowed growth velocity compared to the first year of life. During the first year of life, birth weight doubles by 6 months and triples by 12 months. A child achieves 50% of his or her adult height by 2 years of age.", "whyNot": {"b": "This is an expected finding at 30 months of age. The eruption of teeth appears between 6 and 9 months of age in most children.", "c": "This proportion is typical in childhood. The toddler appears potbellied and may appear bowlegged.", "d": "At 24 months, toddlers can usually speak 2- to 3-word sentences, so this is expected and normal."}, "keyConcept": "Toddlers usually quadruple birthweight by 30 months, since the period between 1-3 years of age is characterized by slow growth velocity. Birth weight doubles by 6 months and triples by 12 months. At 2 years, a child achieves 50% of his adult height."}, {"id": 10959, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 10-year-old client with rheumatic fever who is on bed rest. Which of the following would be an appropriate diversional activity for the nurse to encourage?", "choices": [{"id": "a", "t": "Watching television with a roommate"}, {"id": "b", "t": "Coloring in picture books with a sibling"}, {"id": "c", "t": "Keeping up with schoolwork"}, {"id": "d", "t": "Building a bird house"}], "correct": "c", "rationale": "A Hi 16% Moderate The client should be encouraged to keep up with schoolwork. The developmental stage of a child at ten years of age reflects industry versus . Keeping up with peers is very important to this age group. °", "whyNot": {"a": "The child who needs bed rest may watch some television as a sedentary activity, however, this child would best benefit from keeping up", "b": "A 10-year-old child may or may not enjoy coloring in picture books, based on her age and interests. This child would most likely benefit", "d": "Building a birdhouse is a potentially complicated activity that this 10-year-old child may not be able to accomplish. This child would more"}, "keyConcept": "Children who are school age like organized structure and work towards the desired outcome. Hospitalization may cause anxiety about falling behind the child's peers. Some hospitals have programs to help children keep up in their schoolwork. The nurse should encourage the parents to contact the child’s school about schoolwork at home or in the hospital, and how to arrange support for returning to school. After an injury, illness diagnosis or hospital stay that occurs during the school year, the parents should be encouraged to talk with the child’s school teachers, school nurse, and/or principal to let them know about the child's illness. The parents should ask about getting schoolwork to do at home or in the hospital and ask the school to make a plan to help the child manage schoolwork during his/her recovery."}, {"id": 10960, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a neonate with exstrophy of the bladder. Which of the following is the most appropriate initial nursing intervention?", "choices": [{"id": "a", "t": "Prepare for immediate surgical repair."}, {"id": "b", "t": "Place a protective plastic film over the bladder."}, {"id": "c", "t": "Place petroleum jelly gauze over the bladder."}, {"id": "d", "t": "Place a urinary catheter into the bladder."}], "correct": "b", "rationale": "i 28% Hard Exstrophy of the bladder is a disorder that results from failure of the bladder to develop properly in the abdominal cavity during fusion in the OB rs ar embryo. As a result, the bladder is exposed externally and must be surgically repaired. The initial nursing intervention should occur prior to surgery to prevent infection, injury, or loss of moisture. The initial nursing action is to place a protective non-adherent plastic film, such as c |_| 12% Saran wrap, or a transparent adhesive dressing, over the exposed bladder to maintain moistness and prevent infection. The umbilical clamp .", "whyNot": {"a": "The initial nursing intervention should protect the bladder before surgery. Surgery is not emergent.", "c": "Bladder tissue is delicate and can be damaged by petroleum jelly.", "d": "Aneonate usually urinates several hours after birth. Placement of a urinary catheter is not the appropriate nursing intervention."}, "keyConcept": "Bladder exstrophy is a congenital condition that results in an open, inside-out bladder (the inner surface exposed) on the surface of the lower abdominal wall and an open exposed dorsal urethra. Trauma to the open bladder should be avoided by measures that include placement of a non-adhesive plastic film or transparent adhesive dressing over the exposed bladder."}, {"id": 10961, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 4-year-old child who has been hospitalized for several weeks. Which of the following toys will the nurse select to limit developmental delay and provide entertainment for this child?", "choices": [{"id": "a", "t": "Board games"}, {"id": "b", "t": "Stacking and pulling toys"}, {"id": "c", "t": "Puppets or dolls"}, {"id": "d", "t": "A deck of cards to play Old Maid"}], "correct": "c", "rationale": "25% When a child is on bedrest or hospitalized for long periods of time, he or she should have built-in play periods in the daily schedule to allow ec i 65% continual mastery of tasks necessary for physical, emotional, and social development and to relieve or express stress and anxiety. The type D l 3% of toy and length of time of the play period depends upon the child’s age and their physical and emotional status. Preschool school children have strong imaginations, enjoy dressing up or make-believe, and like to imitate adults. In addition to using puppets or dolls, play can include drawing, coloring, using modeling clay, and playing simple games like “Mother May |” or “Simon Says.” Use of dolls, puppets, and creative outlets such as coloring may allow a child to express anger or anxiety about the hospitalization that otherwise he or she would have been unable to express. Preschool children also may enjoy playing with toy medical kits.", "whyNot": {"a": "Board games are appropriate for school-age children.", "b": "Toddlers enjoy toys they can push or pull, repetitively stack, or drop into a container. These toys are entertaining when children are", "d": "Cards are appropriate for school-age children."}, "keyConcept": "When children are hospitalized or confined to bedrest, it's important to schedule activities that will allow continuing mastery of developmental tasks. Completion of tasks that allow the child to maintain and advance physical, social, and emotional development will also help to relieve the stress and anxiety experienced by the child as a result of illness or hospitalization."}, {"id": 10962, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is performing a comprehensive physical examination of an older adult client who has osteoporosis. Which of the following postural changes should the nurse expect to find in this client?", "choices": [{"id": "a", "t": "Lordosis"}, {"id": "b", "t": "Torticollis"}, {"id": "c", "t": "Kyphosis"}, {"id": "d", "t": "Scoliosis"}], "correct": "c", "rationale": "Kyphosis, which is a forward \"stooping\" posture with a loss of height, is an angulation of the posterior curve of the thoracic spine, which is usually a result of osteoporosis. It is most common in older adults and increases with aging and vertebral fractures.", "whyNot": {"a": "Lordosis, or swayback, is an exaggerated lumbar curve or anterior convexity of the lumbar spine that is common during pregnancy.", "b": "Torticollis is an inclination of the head toward one side resulting from a contraction of the sternocleidomastoid muscle. This condition can", "d": "Scoliosis is a lateral curvature and rotation of the thoracic spine that is most often seen in adolescents."}, "keyConcept": "Part of a comprehensive physical examining is assessing for alterations in posture. Other changes nurses might observe include genu valgum (\"knock knees\"), genu varum (\"bowlegs\"), pigeon toes, clubfoot, foot drop, and congenital hip dysplasia."}, {"id": 10963, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing teaching about foodborne illness and food safety issues at a local community center. What statement should the nurse include in the teaching? O A.\"Unpasteurized fruit juice is a common cause of foodborne illness.\" O B. \"Store hard-boiled eggs in the refrigerator for up to 2 weeks.\" O C. \"The recommended internal temperature for cooking ground beef is 145 degrees Fahrenheit.\" O D. \"The onset of norovirus occurs 5 to 7 days after exposure to the virus.\"", "choices": [{"id": "a", "t": "The nurse should include in the teaching that unpasteurized fruit juice is a common cause of foodborne illness."}, {"id": "b", "t": "The nurse should include in the teaching to store -boiled eggs in the refrigerator for no longer than 1 week."}, {"id": "c", "t": "The nurse should include in the teaching that the recommended internal temperature for cooking ground beef is 160° F (71°C)."}, {"id": "d", "t": "The nurse should include in the teaching that the onset of norovirus occurs 24 to 48 hr after exposure to the virus. Norovirus"}], "correct": "a", "rationale": "The nurse should include in the teaching that unpasteurized fruit juice is a common cause of foodborne illness. Other common causes of B I Ee foodborne illness include raw or undercooked animal products, raw fruits and vegetables contaminated with animal feces, and uncooked food handled by someone who has an illness. © Zz 27% om 20%", "whyNot": {"b": "The nurse should include in the teaching to store hard-boiled eggs in the refrigerator for no longer than 1 week.", "c": "The nurse should include in the teaching that the recommended internal temperature for cooking ground beef is 160° F (71°C).", "d": "The nurse should include in the teaching that the onset of norovirus occurs 24 to 48 hr after exposure to the virus. Norovirus"}, "keyConcept": "One of the primary reasons for foodborne illnesses is the improper and unsanitary handling of food. All food handlers should undergo instruction in proper handwashing and personal hygiene. Fruits and vegetables should be thoroughly washed before eating. Emphasis should also be placed on steps to prevent contamination between cooked foods and raw foods, such as using separate cutting boards and utensils for raw meat and vegetables. Foods should be cooked to safe internal temperatures to destroy food-borne pathogens such as salmonella, clostridium perfringens, staphylococcus aureus, and escherichia coli. Finally, foods should be refrigerated promptly to prevent the growth of bacteria."}, {"id": 10964, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Acharge nurse on a psychiatric unit is giving in-service training to incoming nurses about risk factors for substance use disorder. Which of the following facts will the charge nurse include in this discussion?", "choices": [{"id": "a", "t": "Substance abuse during the early twenties is associated with greater risk than adolescent use."}, {"id": "b", "t": "If an older adult does not have a history of early alcohol use or abuse, he/she is unlikely to use alcohol later in life."}, {"id": "c", "t": "The metabolism of alcohol may explain variations in risk among genetically related populations."}, {"id": "d", "t": "Alaskans have a low rate of alcohol use disorder because they metabolize differently and experience unpleasant side effects."}], "correct": "c", "rationale": "A Hl 20% Moderate Alcohol use disorder includes excessive use and dependence. Multiple risk factors have been identified, including personal and social factors B ] Aer that increase the risk. Sociocultural theories have been developed after studying different population variations. Some cultures, including Native Americans and Alaskan natives, have a high incidence of alcohol use disorder in the population; others, such as Asian populations, ec S| 62% have a low rate of alcohol use disorder, attributed in part to a difference in metabolism that results in unpleasant symptoms when alcohol is , including flush and headache. Multiple factors, including environmental, social, and genetic factors, account for disparities in the risk of alcohol and other substance use disorders.", "whyNot": {"a": "The developing brain is more vulnerable to the effects of substance use than the adult brain. Early use increases the risk of addiction.", "b": "Older adults may develop alcohol use or other substance use disorders in later life, even when they did not have any issues in earlier", "d": "Asians metabolize alcohol differently in many instances, and it results in unpleasant side effects, so rates of alcohol use and abuse are"}, "keyConcept": "Risk factors for substance use disorder, including alcohol abuse and dependence, include genetic, social, and environmental factors. Genetic factors are estimated to account for 40-60% of individual vulnerability to addiction. Early age of first use is another risk factor, since the brain is more vulnerable during development than in adulthood."}, {"id": 10965, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in a pediatric clinic anticipates that oral iron supplementation will be required in which of the following infants?", "choices": [{"id": "a", "t": "An 8-month-old infant who has recently started solid foods while breastfeeding"}, {"id": "b", "t": "An 11-week-old infant who was born at 33 weeks’ gestation and receives feedings of breast milk by bottle"}, {"id": "c", "t": "A3-month-old infant born at 40 weeks’ gestation who has been exclusively breastfed O D.A5-month-old infant born at 38 weeks’ gestation who has been exclusively fed with formula"}], "correct": "b", "rationale": "All 11% Hard eo: 7 39% During gestation, the fetus receives iron from the mother that is then stored in the liver, bone marrow, spleen, and hemoglobin. Iron stores c Hi 15% should last 5 or 6 months in infants who are carried to term, but preterm infants and those born in multiples deplete iron stores by 2-3 . Iron can be administered by oral supplement or with dietary sources of iron that include iron-fortified formula. Breast milk contains low iron levels, so oral iron drops can be used to supplement iron in infants who are exclusively breastfed. When solid foods are added to the diet, iron-fortified infant cereal and iron-rich foods are a good source.", "whyNot": {"a": "lron-fortified infant cereals are commonly the initial foods introduced, so iron supplementation is less likely to be necessary for this child.", "c": "Breastfed infants delivered at term do not typically require supplementation until the age of 6 months. At that age, solid foods fortified"}, "keyConcept": "Iron stores last 5-6 months in term infants and 2-3 months in multiple gestation and preterm infants. Supplementation with oral iron drops is recommended for infants who are exclusively breastfed. Iron-fortified formula and iron-fortified cereal can be used to add recommended amounts of supplemental iron in infants who are formula-fed and those who have advanced to solid foods."}, {"id": 10966, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "An RN has volunteered to administer seasonal influenza vaccines at a senior center in the community. Which of the following clients receiving the vaccine should the nurse question? O A.A75-year-old client with history of egg allergy involving allergic symptoms that included angioedema O B. A 70-year-old client with coronary artery disease and congestive heart failure O C. A 65-year-old client with chronic obstructive pulmonary disease (COPD) O D.A 73-year-old client with a history of latex allergy resulting in a rash", "choices": [{"id": "a", "t": ", a nurse should always screen the client for contraindications and precautions."}, {"id": "b", "t": "3%"}, {"id": "c", "t": "COPD increases the risk of infection, so immunization is particularly important in this client."}, {"id": "d", "t": "The influenza vaccine is not made with latex, and there is no cross-reaction."}], "correct": "a", "rationale": ", a nurse should always screen the client for contraindications and precautions. Contraindications are Cc l 3% conditions that create an increased risk of a serious adverse reaction, and precautions are conditions under which the vaccine should not be . Although the flu vaccine is created using eggs, the Centers for Disease Control advise that any client with egg allergy of any severity can receive any recommended influenza vaccine appropriate for the client’s age. For people with a history of severe allergic reaction to egg involving any symptom other than hives (angioedema or respiratory distress) or who required epinephrine, the vaccine should be administered in a medical setting, so administration at a community health fair is not appropriate. Vaccine administration should be supervised by a healthcare provider with the ability to recognize and treat severe allergic conditions.", "whyNot": {"b": "This is not a contraindication.", "c": "COPD increases the risk of infection, so immunization is particularly important in this client.", "d": "The influenza vaccine is not made with latex, and there is no cross-reaction."}, "keyConcept": "The seasonal flu vaccine is created using eggs, but it is not contraindicated in clients with egg allergy. Individuals who have had a serious allergic reaction to eggs, including respiratory distress and angioedema, should receive the vaccine in a medical setting where a healthcare provider is available who can recognize and treat a serious reaction."}, {"id": 10967, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a client who is at 24 weeks of gestation and scheduled for an amniocentesis procedure. Which of the following client statements indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\" will lie on my right side during this test.\""}, {"id": "b", "t": "\"I cannot eat or drink anything for 24 hours prior to this procedure.\""}, {"id": "c", "t": "\"I must urinate prior to the procedure.\""}, {"id": "d", "t": "\"1 will be given medication to put me to sleep during this procedure.\""}], "correct": "c", "rationale": "All 12% Easy During an amniocentesis, a needle is inserted through the maternal abdomen and there is a risk for puncture. The client's bladder should be B I a empty prior to the procedure to allow for better visualization of the gestational sac and to reduce this risk.", "whyNot": {"a": "During an amniocentesis, the client should be in a supine position with a wedge placed under her right hip to move the uterus off of the", "b": "The client does not need to be NPO for 24 hr prior to the procedure.", "d": "During an amniocentesis, the client should be conscious and awake. There is no indication for sedative use for this procedure."}, "keyConcept": "Amniocentesis is an invasive procedure performed to evaluate the amniotic fluid for fetal chromosomal abnormalities and fetal lung maturity. The client should be instructed to empty her bladder prior to the test to decrease the risk for puncture. The client should be ina supine position. Ultrasonography is used to visualize the fetus and allow the provider to safely insert the needle through the abdomen. The amniotic fluid is aspirated and then examined after the procedure."}, {"id": 10968, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "of recurrence? O A. Metronidazole tablet taken by the client and her partner O B. Vaginal douche using an iodine solution O C. Application of trichloroacetic acid to the lesions O D. Intramuscular injection of penicillin", "choices": [{"id": "a", "t": "Metronidazole tablet taken by the client and her partner"}, {"id": "b", "t": "Vaginal douche using an iodine solution"}, {"id": "c", "t": "Application of trichloroacetic acid to the lesions"}, {"id": "d", "t": "Intramuscular injection of penicillin"}], "correct": "a", "rationale": "Trichomoniasis is an infection caused by a protozoan principally transmitted through sexual contact. Its clinical characteristics include B | Bt genital itching, vaginal discharge, and painful urination. In order to prevent the recurrence of the infection, both the client and the partner must be treated. Treatment for trichomoniasis is metronidazole or tinazole. Sexual activity should be avoided until seven to ten days after c | 6% treatment. Trichomoniasis in pregnant women is associated with preterm labor and low birthweight. Metronidazole and tinazole are safe in , but clients should be cautioned to avoid alcohol for 24 hours after treatment.", "whyNot": {"b": "A nurse should advise the client to avoid douching because it can destroy the normal vaginal flora and increase the risk of acquiring", "c": "Trichloroacetic acid is a treatment used for genital warts.", "d": "Penicillin is used to treat syphilis."}, "keyConcept": "Trichomoniasis is considered the most common curable sexually transmitted infection. Seventy percent of infections are undetected. Trichomoniasis can increase the risk of other sexually transmitted infections. The infection is treated with metronidazole or tinidazole, which are safe in pregnancy. Recurrence occurs within 3 months in 20% of individuals treated for trichomoniasis, so treatment of sexual partners is necessary to avoid recurrent infection."}, {"id": 10969, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Presbycusis"}, {"id": "b", "t": "Tinnitus"}, {"id": "c", "t": "Meniere’s disease."}, {"id": "d", "t": "Conductive hearing loss eck Answer"}], "correct": "b", "rationale": "| 2% Easy Tinnitus is a condition described as a ringing in the ears, typically caused by an injury to the ear structure or hearing loss because of age- B rsd omar related changes. Tinnitus may be manifested as ringing, buzzing, crackling, or hissing sounds in the ears and is more than just an annoying sensation. Many people who develop tinnitus may also have difficulties sleeping or concentrating and may eventually develop increased c | 5% levels of stress and depression. D l 3%", "whyNot": {"a": "Presbycusis describes the age-related hearing loss that occurs in an aging adult.", "c": "Meniere’s disease is a disorder of the inner ear that may cause symptoms of ringing in the ears, but it does not occur from damage to the", "d": "Conductive hearing loss occurs from changes in the structure of the outer ear, such as the eardrum or the ear canal. It is not caused by"}, "keyConcept": "Tinnitus is the perception of noise or ringing in the ears. It can be caused by many conditions such as damage and loss of the tiny sensory hair cells in the cochlea of the inner ear (caused by aging or noise exposure), certain medications, tumors, or head and neck injuries."}, {"id": 10970, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Piaget? O A. An 18-month-old toddler O B. A 4-year-old preschooler O C. An 8-year-old third grade student O D.A 15-year-old high school student eck Answer", "choices": [{"id": "a", "t": "An 18-month-old toddler"}, {"id": "b", "t": "A 4-year-old preschooler"}, {"id": "c", "t": "An 8-year-old third grade student O D.A 15-year-old high school student eck Answer"}], "correct": "c", "rationale": ", as defined by Jean Piaget, encompasses middle and late childhood, within the age range of approximately 6 B | see to 11 years old. The concrete operations stage is a time when children develop more logical reasoning, they become better listeners, and they are able to think more objectively. c | 63% om 14%", "whyNot": {"a": "An 18-month-old toddler is considered to be in the sensory-motor stage (birth to 2 years), as defined by Piaget. This stage is characterized", "b": "A 4-year-old preschooler is considered to be in the pre-operation stage (2 to 7 years), as defined by Piaget. This stage is characterized by"}, "keyConcept": "Piaget's conceptual framework of childhood cognitive development describes the developmental stage of children from ages 6-11 as the concrete operational stage. At this stage, thinking becomes more systematic and logical, but concrete objects and activities remain necessary for understanding. Piaget's stages are listed in the figure below. Piaget's Periods of Cognitive Development Birth to Imagination! ‘experience ‘grow, child de- centers Ethics, politics, ideas | socialimoral issues explored"}, {"id": 10971, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following findings on an assessment of a newborn is concerning in the first hour after a spontaneous vaginal delivery?", "choices": [{"id": "a", "t": "Respiratory rate of 58/min"}, {"id": "b", "t": "Systolic blood pressure of 65 mmHg"}, {"id": "c", "t": "Capillary glucose of 28 mg/dL"}, {"id": "d", "t": "Flat red marks on the upper eyelids and forehead that blanch with pressure"}], "correct": "c", "rationale": "all 8% Easy cy 6% The fetus stores glycogen during pregnancy to use during the transition period to extrauterine life. In the neonatal period, normal glucose is @c fF 79% considered 30 mg/dL or more, but optimal levels are 70-100 mg/dL. The glucose level rises and stabilizes in the newborn within 2-3 hours , but a level of 30 mg/dL is concerning. Neonatal hypoglycemia can result in significant neurologic damage, manifested by cognitive developmental delay, recurrent seizure activity, developmental delay, and personality disorders. Normal vital signs during this period are in the table below. Respiratory rate Heart rate 110-160/minute Systolic blood pressure | 60-80 mm Hg Diastolic blood pressure | 40-50 mm Hg Temperature 97.7-99.5 F (36.5-37.5 C) axillary 30-60/minute", "whyNot": {"a": "This respiratory rate is within the normal range for a newborn.", "b": "This is within the normal range of systolic blood pressure in a neonate.", "d": "This describes telangiectatic nevi, sometimes known as “stork bites.” They may be pink or red and are usually found on the nose,"}, "keyConcept": "The fetus stores glycogen during gestation to use during the transition to extrauterine life. A glucose of less than 30 mg/dL is concerning in the first hour of life. Although neonates may be asymptomatic, symptoms of hypoglycemia in newborns include hypotonia, lethargy, poor feeding, jitteriness, seizures, congestive heart failure, cyanosis, apnea, and hypothermia."}, {"id": 10972, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Provide distraction with toys"}, {"id": "b", "t": "Allow the child to see he is making her upset"}, {"id": "c", "t": "Offer the choice of two different liquids"}, {"id": "d", "t": "Take his food away until he drinks"}], "correct": "c", "rationale": "al 4% Easy The child is expressing negativity in an effort to achieve control. Offering him a choice within reasonable limits is a way for him to have B | a0 control.", "whyNot": {"a": "This child is demonstrating negativity, which is typical for his age. Distracting the child with toys will not meet his needs for fluids.", "b": "The child is not at an age where he would understand that he is making his mother upset.", "d": "The child is demonstrating negativity, which is typical for his age. Taking his food away until he drinks would limit his nutritional intake as"}, "keyConcept": "A persistent negative response to requests is a characteristic common in two-year-olds. Negativity in a two-year-old is the toddler's way to is assert self-control. Strategies for enlisting cooperation include providing choices to the child."}, {"id": 10973, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "following questions should the nurse prioritize when compiling the health history? O A.\"Does your child use the potty?\" O B. \"Does your child watch television?\" O C. \"How many words does your child use?\" O D. \"Does your child have tantrums?\"", "choices": [{"id": "a", "t": "This is not a priority assessment in light of the parent’s concerns."}, {"id": "b", "t": "Limited screen time is important but not a priority assessment."}, {"id": "c", "t": "The mother’s remarks should prompt concern for a developmental disorder."}, {"id": "d", "t": "Tantrums are an expected finding, but children with ASD also have tantrums sometimes due to frustration. This is not a priority"}], "correct": "c", "rationale": "The mother’s remarks should prompt concern for a developmental disorder. Autism spectrum disorder is a developmental disorder with onset before the age of 3. This neurodevelopmental disorder results in difficulties in communication and social interaction coupled with restrictive and repetitive patterns of behavior or activities. The delay in social skills, particularly in communication, is an early sign and should be the priority in assessment. The normal vocabulary for a 2-year-old is 300 words with an ability to use phrases of 2 to 4 words. Children with autism spectrum disorder have a delayed acquisition of language and communication skills in the first 2 years of life.", "whyNot": {"a": "This is not a priority assessment in light of the parent’s concerns.", "b": "Limited screen time is important but not a priority assessment.", "d": "Tantrums are an expected finding, but children with ASD also have tantrums sometimes due to frustration. This is not a priority"}, "keyConcept": "Autism spectrum disorder is a neurodevelopmental disorder that results in difficulty in communication and social interaction with restrictive and repetitive patterns of behavior or activities. Delay in language and communication skills in the first two years of life is an early sign of autism."}, {"id": 10974, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ 0 @ X Viraln sx Recor M Inbox ™M Inbox ] Untitl Untitl (4 Googl @ TEAS Online & Mark! @ Micro: (INANETEMETE @ ATITE G Newc N x | G GERO + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Suicide"}, {"id": "b", "t": "Cancer"}, {"id": "c", "t": "Accidents"}, {"id": "d", "t": "Eating disorders"}], "correct": "c", "rationale": "Mm | 22% Easy Accidents, including motor vehicle accidents as well as accidents that occur as a result of poor decision making, are the leading cause of 12-19.", "whyNot": {"a": "While suicide may be a more common cause of death among adolescents than other age groups, accidents are the leading cause of death.", "b": "While some adolescents do develop cancer that leads to death, accidents are the leading cause of death in adolescents.", "d": "Some adolescents do develop eating disorders, but the leading cause of death in this age group is accidents."}, "keyConcept": "More than 50% of all deaths among children between the ages of 1 to 14 years and almost 75% of deaths among youths aged between 15 and 24 years are caused by injuries, including unintentional injuries (accidents), suicides, and homicides. Adolescents should be screened for problems related to alcohol or substance use. Early intervention after trauma incidents involving alcohol misuse can reduce the risk of injury recurrence by about 50%. Other measures to reduce injuries include restricting access to firearms, use of seat belts, helmets, and smoke detectors."}, {"id": 10975, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing teaching to a client who has a BMI of 32 kg/m2 who wants to lose weight. Which of the following statements by the client indicates a need for further teaching?", "choices": [{"id": "a", "t": "“My goal is to lose 4 pounds (1.8 kg) per week for the next 2 months.”"}, {"id": "b", "t": "“I will try to decrease my calorie intake by 500 calories a day.”"}, {"id": "c", "t": "“I need to increase how many fruits and vegetables eat and cut back on red meat.”"}, {"id": "d", "t": "“I plan to exercise at least 150 minutes a week.”"}], "correct": "a", "rationale": "@ . The client should be taught that it is not healthy to attempt to lose four pounds (1.8 B ] aon kg) per week and that this practice could be harmful and could result in gaining the weight back. Instead, the client should learn that a normal goal is a weight loss of approximately 1-2 pounds (.45kg-.9kg) per week. c | 8% off 8%", "whyNot": {"b": "Decreasing calorie intake by 500 calories per day is a normal goal that would foster weight loss in a client. {)", "c": "This indicates that the client understands the importance of vitamins and minerals from fruits and vegetables as well as the potential A", "d": "This is the amount of exercise per week recommended by the Centers for Disease Control and Prevention. It is a normal goal in this g"}, "keyConcept": "An average woman needs to eat about 2000 calories per day to maintain current weight, and 1500 calories to lose one pound of weight per week. An average man needs 2500 calories to maintain, and 2000 to lose one pound of weight per week. However, this depends on numerous factors. The nurse should assist the client to determine daily caloric needs. To lose one pound per week, caloric intake should be 500 calories per day less than caloric needs."}, {"id": 10976, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "The mother of a 12-month old child tells the nurse that the child never received the hepatitis B vaccine, but she would like to consider this option now. Which response from the nurse is accurate?", "choices": [{"id": "a", "t": "“This usually starts at birth; it is too late to start it now.”"}, {"id": "b", "t": "“We must first check his antigen levels before giving the vaccine.”"}, {"id": "c", "t": "“He can have the vaccine, but he must wait until he is at least 24 months.”"}, {"id": "d", "t": "“We can start the series whenever you are ready.”"}], "correct": "d", "rationale": "The nurse can tell this parent that the child can receive the first injection of the series right away or whenever the mother and the child are ready. Hepatitis B injections are given to newborn babies, so this 12-month-old child is not too young to receive the vaccine.", "whyNot": {"a": "While many infants start the hepatitis B series just after birth, it is not too late for this infant to start the series.", "b": "There is no need to check antigen levels first; if the baby has not had the vaccine, he can receive the series.", "c": "The child does not need to wait until he is 24 months old to start the series; it can be started right away."}, "keyConcept": "Hepatitis B virus is transmitted through blood and body fluids. Children who become infected with the hepatitis B virus during the first five years of life have a 15% to 25% risk for premature death from liver disease, including liver failure or liver cancer. Most newborns in the United States are vaccinated against the hepatitis B virus, usually in the first few days of life. The CDC (Centers for Disease Control) recommends the hepatitis B vaccine be given the day a baby’s born, one month later, and then six months later."}, {"id": 10977, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is visiting a family with a one-month-old baby. The mother is frustrated with the baby’s behavior. She says, “I try to give him his rattle, but he doesn’t do anything with it. How can | get him to respond?” Which of the following is the most appropriate response of the nurse?", "choices": [{"id": "a", "t": "“Try putting your hand over his and shaking the rattle with him.”"}, {"id": "b", "t": "“Shake the rattle in his face first and then he should take it from you.”"}, {"id": "c", "t": "“He should be able to do that by now. will call the physician to check into developmental testing.”"}, {"id": "d", "t": "“He has not discovered that he is able to make noise with the rattle. Give him time to learn that skill.”"}], "correct": "d", "rationale": "Children reach the sensorimotor stage of secondary circular reactions at approximately 4 to 5 months. This stage is characterized by a child accidentally learning that he or she can control something in the environment and then repeat the action to control it again. In this example, achild who is one month old has not developed the skill to use a rattle yet and the parents should be educated on the appropriate expectations for his age.", "whyNot": {"a": "The parents may place their hand over their infant’s hand to shake the rattle, but the baby is not old enough to learn how to move the", "b": "The parents may shake the rattle in front of the baby, but he is not old enough to learn how to move the rattle on his own through this", "c": "The infant is not old enough to understand how to move a rattle. There is no need to contact the physician about this for developmental"}, "keyConcept": "The psychologist Jean Piaget proposed four stages of cognitive, or mental, development, beginning at birth and continuing through adulthood. The first stage of development is referred to as the sensorimotor stage, which begins at birth and lasts through 24 months of age. There are six sub-stages of sensorimotor development, and the initial sub-stage of sensorimotor development includes simple reflexes. The second sub-stage is primary circular reaction, from one to four months of age. During this stage, the infant associates an action centered on its body with pleasure and repeats the pleasurable action. In the third sub-stage, secondary circular reaction, the infant will repeat pleasurable actions that involve objects in addition to actions involving their own bodies. An example is shaking a rattle for the pleasure of hearing the sound that it produces. This sub-stage occurs between 4 and 8 months of age. The other substages of sensorimotor development include coordination of secondary circular reactions; tertiary circular reactions; and mental representations."}, {"id": 10978, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "S36 Viraln = 8x Recor = _Inbox ™ Inbox 2) untitl Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atiti =G@ Newc Nx G GERO + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE SA a“ ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Chadwick’s sign"}, {"id": "b", "t": "Chadway’s sign"}, {"id": "c", "t": "Hegar’s sign"}, {"id": "d", "t": "Goodell’s sign"}], "correct": "a", "rationale": "Chadwick's sign is the early sign of pregnancy which is caused by venous congestion in the cervix, causing it to become bluish in color. B | a0", "whyNot": {"b": "Chadway’s sign is not the name of a condition or diagnosis in medicine and this description does not apply.", "c": "Hegar’s sign occurs when the lower portion of the uterus softens. It is not associated with discoloration of the cervix or Chadwick's sign.", "d": "Goodell’s sign occurs with softening of the cervix. It is not the same as Chadwick’s sign, which is the bluish discoloration of the cervix at 8"}, "keyConcept": "Diagnosis of pregnancy is made with history and physical examination, laboratory evaluation, and ultrasonography. The classic signs of pregnancy are missed menstrual cycle in a woman with menses of regular frequency, in association with nausea, vomiting, generalized malaise, and breast tenderness. On physical examination, signs include an enlarged uterus on bimanual examination, breast changes, and softening and enlargement of the cervix (Hegar sign; approximately 6 wk). Chadwick's sign is a bluish discoloration of the cervix from venous congestion and can be observed by 8-10 weeks."}, {"id": 10979, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is completing a pain assessment for a toddler and asks the toddler to self-report the pain. Which of the following pain scales should the nurse use? O a Faces O s.rtacc O C. Numeric scale O D. Children's Hospital of Eastern Ohio Pain Scale (CHEOPS)", "choices": [{"id": "a", "t": "oo; The FACES pain assessment scale is recommended for children as young as 3 years old and is appropriate for use with toddlers."}, {"id": "b", "t": "The FLACC pain assessment scale is recommended for infants and children between 2 months and 7 years of age who are unable to self-"}, {"id": "c", "t": "The numeric scale is used for children 5 years and older. The nurse should ensure the child is able to count and has an understanding of"}, {"id": "d", "t": "This scale is used for children from 1 to 5 years old who are unable to self-report pain."}], "correct": "a", "rationale": "oo; The FACES pain assessment scale is recommended for children as young as 3 years old and is appropriate for use with toddlers. om c | >|", "whyNot": {"b": "The FLACC pain assessment scale is recommended for infants and children between 2 months and 7 years of age who are unable to self-", "c": "The numeric scale is used for children 5 years and older. The nurse should ensure the child is able to count and has an understanding of", "d": "This scale is used for children from 1 to 5 years old who are unable to self-report pain."}, "keyConcept": "When assessing pain in any age of client, it is important for the nurse base the assessment on development and not simply the client's age. It is also important to remember that children with chronic pain can become very efficient at distracting themselves from the pain to cope. Therefore, the nurse should not discount a child's pain if they are able to distract themselves."}, {"id": 10980, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a newborn. Which of the following findings should the nurse prioritize when reporting to the healthcare provider?", "choices": [{"id": "a", "t": "Respiratory rate of 40/min"}, {"id": "b", "t": "Heart rate of 160/min"}, {"id": "c", "t": "Cyanosis in the feet and hands"}, {"id": "d", "t": "Presence of 1 artery in the umbilical cord"}], "correct": "d", "rationale": "Two arteries and one vein are normally found in the umbilical cord. A single artery in the umbilical cord may be associated with congenital Cc || defects and should be reported to the healthcare provider. e@D PY", "whyNot": {"a": "The normal respiratory rate in a newborn is 30-60/minute.", "b": "The normal heart rate in a neonate is between 110-160/minute.", "c": "Cyanosis in the feet and hands is known as acrocyanosis, which is normal in a newborn during the first day of life. It may occur up to 10"}, "keyConcept": "At delivery, the nurse assessing the newborn must assess the umbilical cord, which should .have two arteries and one vein. If only one artery is present, it may be associated with other congenital defects. The healthcare provider should be notified to begin an assessment to identify other abnormalities."}, {"id": 10981, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a class about cultural and religious influences on food choices to a group of newly licensed nurses. Which statement by a class attendee indicates an understanding of the teaching? O A.\"Clients who practice Roman Catholicism do not drink caffeinated beverages.\" O B. \"Clients who practice Orthodox Judaism do not eat meat with dairy products.\" O C. \"Clients who are Mormon eat only the protein of animals that are slaughtered under strict guidelines.\" O D. \"Clients who practice Hinduism fast during the period of Ramadan.\"", "choices": [{"id": "a", "t": "This is not a practice of clients following Roman Catholic dietary practices. Clients who adhere to Roman Catholic dietary practices might"}, {"id": "b", "t": "Clients who follow Orthodox Judaism dietary practices do not eat meat with dairy products."}, {"id": "c", "t": "Several religions have dietary practices that involve how food is prepared. Clients who follow Kosher dietary practices eat only the protein"}, {"id": "d", "t": "Clients who practice Islam typically fast during the month of Ramadan. These clients may restrict dietary intake from dawn to after the sun"}], "correct": "b", "rationale": "Clients who follow Orthodox Judaism dietary practices do not eat meat with dairy products.", "whyNot": {"a": "This is not a practice of clients following Roman Catholic dietary practices. Clients who adhere to Roman Catholic dietary practices might", "c": "Several religions have dietary practices that involve how food is prepared. Clients who follow Kosher dietary practices eat only the protein", "d": "Clients who practice Islam typically fast during the month of Ramadan. These clients may restrict dietary intake from dawn to after the sun"}, "keyConcept": "Religious beliefs and cultural practices can affect food choices and consumption. Nurses should be aware of this and should ask clients about cultural, ethnic, and religious practices that are related to nutrition. Practices such as fasts can affect the administration of medications or other treatments. It is important for the nurse to recognize and respect the food choices clients make and assist them as needed to obtain healthy food within their religious beliefs and cultural practices."}, {"id": 10982, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Keep the infant in a semi-sitting position, especially after feedings"}, {"id": "b", "t": "Make certain the infant takes at least 8 oz of formula at each feeding"}, {"id": "c", "t": "Never use a pacifier"}, {"id": "d", "t": "Keep the infant prone following feedings"}], "correct": "a", "rationale": "Chalasia is an incompetent cardiac sphincter. This allows gastric contents to flow back into the esophagus, which leads to regurgitation. Keeping the infant upright uses gravity to help keep stomach contents out of the esophagus and also limits pressure on the cardiac sphincter.", "whyNot": {"b": "8 oz of formula at a time is too much for a week-old infant and would likely induce regurgitation.", "c": "This would have no effect on chalasia.", "d": "This would promote regurgitation."}, "keyConcept": "Chalasia refers to the relaxation of a ring of muscle (such as the cardiac sphincter of the esophagus) surrounding a bodily opening. In the case of chalasia affecting the esophageal sphincter, symptoms of gastric reflux will occur. Chalasia is often identified in young children, and is related to congenital incompetence of the lower esophageal sphincter, allowing unrestricted reflux of gastric contents. This contrasts with achalasia, which refers to restriction at the gastroesphageal junction that limits esophageal emptying."}, {"id": 10983, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is educating a group of refugees about the initial signs of tuberculosis. Which of the following is an initial symptom of this condition?", "choices": [{"id": "a", "t": "Nausea and vomiting"}, {"id": "b", "t": "Cough with bloody sputum"}, {"id": "c", "t": "Pruritic rash"}, {"id": "d", "t": "Headache and blurred vision"}], "correct": "b", "rationale": "‘i o: Tuberculosis is caused by infection with the bacteria Mycobacteria tuberculosis. Infection spreads through airborne transmission and it is Cc I highly contagious. Individuals at high risk of developing TB include those with impaired immunity or people recently infected, including D I those who have immigrated from areas of the world with high rates of TB, close contacts of someone with TB, and individuals who belong to groups that have a high rate of TB transmission or who work with those groups, which include the homeless, injection drug users, and people with HIV infection. There are increasing numbers of multidrug-resistant strains of TB, which develop as a result of lack of compliance with treatment programs or due to spontaneous mutations in the tubercle bacillus. TB is treated with a multidrug regimen, for prolonged periods of time (9 months or more.) Initial manifestations include a persistent cough, hemoptysis (a bloody cough), weight loss, fever, chills, night sweats, anorexia, and dyspnea. The diagnosis should be considered in at-risk individuals with these symptoms. Initial testing includes a tuberculin skin test, chest X-ray, and acid-fast sputum smear, which is the staining technique necessary to identify the bacteria. A definitive diagnosis is made by culture.", "whyNot": {"a": "Tuberculosis is an airborne disease, and the initial symptoms are related to the respiratory tract.", "c": "Atuberculin skin test is performed by injecting a small amount of purified protein derivative (PPD) subcutaneously in the forearm. The test", "d": "Fever can result in a headache, but a headache is not a primary symptom of TB, and blurred vision would not be expected."}, "keyConcept": "Individuals at high risk of developing tuberculosis include those with impaired immune systems or those recently infected, including close contacts of individuals with TB; recent immigrants from areas where the prevalence of TB is high; and the homeless, incarcerated, injection drug users, and those who work or reside with high risk populations."}, {"id": 10984, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who is in labor. The fetal monitor shows bradycardia. Which of the following can result in fetal bradycardia?", "choices": [{"id": "a", "t": "The nurse performs a vaginal exam"}, {"id": "b", "t": "The mother has developed chorioamnionitis"}, {"id": "c", "t": "The mother is dehydrated"}, {"id": "d", "t": "The mother has received spinal anesthesia."}], "correct": "d", "rationale": "The administration of spinal anesthetic medications to the mother causes maternal hypotension that results in fetal hypoxia, a cause of fetal bradycardia.", "whyNot": {"a": "A vaginal exam may be more likely to stimulate the fetus and cause an increase in the heart rate.", "b": "Chorioamnionitis would more likely cause an increased fetal heart rate in response to infection.", "c": "Maternal dehydration may cause a decrease in overall circulating fluid and an increased fetal heart rate as a compensatory response."}, "keyConcept": "The most common causes of fetal bradycardia in the intrapartum period include poor uterine perfusion, maternal hypotension after spinal anesthesia, umbilical cord prolapse, rapid fetal descent, tachysystole, placental abruption, or uterine rupture. The effect of spinal anesthesia on fetal heart rate is due to maternal hypotension, which causes fetal hypoxia."}, {"id": 10985, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "€ 9 GCG 23 student.atitesting.com/LT! Qa * sw * © Cb Finish update ? Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Moro reflex pe) © o 2 ° s a = a <"}, {"id": "b", "t": "Babinski reflex"}, {"id": "c", "t": "Tonic neck reflex"}, {"id": "d", "t": "Stepping reflex"}], "correct": "c", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": {"a": "The Moro reflex often disappears after 4 months of age. The Moro reflex assesses the infant’s ability to startle.", "b": "The Babinski reflex assesses reflexes on the sole of the foot.", "d": "The stepping reflex occurs when the infant is held up and she makes a stepping motion when her feet touch a hard surface."}, "keyConcept": null}, {"id": 10986, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc € OS @G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE N xX G GERO + v Qa * es * © tb Finish update : { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Lochia alba"}, {"id": "b", "t": "Lochia rubra"}, {"id": "c", "t": "Lochia serosa"}, {"id": "d", "t": "Lochia venosa"}], "correct": "c", "rationale": "Lochia serosa is pink and watery in appearance with a serosanguinous consistency. It typically develops within 3 to 10 days following delivery.", "whyNot": {"a": "Lochia alba is white or yellow and develops within approximately 10 days after delivery.", "b": "Lochia rubra is bright red and develops immediately following birth.", "d": "Lochia venosa is not a type of drainage that occurs after delivery."}, "keyConcept": "Lochia refers to the vaginal discharge that begins after giving birth, during the puerperium. It contains blood, mucus, and uterine tissue. Lochia discharge typically continues for 4 to 6 weeks after childbirth. There are three stages of lochia. Lochia is sterile for the first 2 to 3 days and composed largely of blood, known as lochia rubra. Composed of blood, shreds of fetal membranes, By the third or fourth day, as the uterus begins to be colonized by vaginal commensals such as non-hemolytic streptococci and E. coli, lochia serosa appears. It has a serosanguinous consistency and character and also contains serous exudate, erythrocytes, leukocytes, and cervical mucus. Lochia alba, the last stage, has fewer erythrocytes and a white appearance."}, {"id": 10987, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ 0 @ X Viraln sx Recor M Inbox ™M Inbox ] Untitl Untitl (4 Googl @ TEAS Online & Mark! @ Micro: (INANETEMETE @ ATITE G Newc N x | G GERO + v € > @G 23 student.atitesting.com/LT| Qa * es * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "genetic factor that alters a person’s chances of developing a disease is known as:"}, {"id": "b", "t": "Agenetic predisposition is a genetic factor that alters a person’s susceptibility of developing a disease."}, {"id": "c", "t": "Pharmacogenomics involves using DNA and genes to develop and manage medications."}, {"id": "d", "t": "A genotype refers to inherited genes in a particular person."}], "correct": "b", "rationale": "Agenetic predisposition is a genetic factor that alters a person’s susceptibility of developing a disease. A person with a genetic predisposition to a disease may be more likely to develop the condition when compared to others.", "whyNot": {"a": "Genomics is the study of genes and their functions in the body.", "c": "Pharmacogenomics involves using DNA and genes to develop and manage medications.", "d": "A genotype refers to inherited genes in a particular person."}, "keyConcept": "An individual may be at high risk of acquiring a disease as a result of one or more genetic mutations, which do not necessarily have to be abnormal. This is called a genetic predisposition or susceptibility."}, {"id": 10988, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "What is the most common cause of death in the United States?", "choices": [{"id": "a", "t": "Cardiovascular illnesses"}, {"id": "b", "t": "Medical errors"}, {"id": "c", "t": "Chronic lower respiratory tract disease"}, {"id": "d", "t": "Cancer"}], "correct": "a", "rationale": "Cardiovascular disease (CVD) is the most common cause of death overall in the USA. One death from cardiovascular disease occurs on average every 40 seconds. CVD accounts for more deaths than the next four leading causes combined.", "whyNot": {"b": "Ten percent of all deaths in the United States are due to medical errors. Medical errors are the third leading cause of death in the USA.", "c": "Chronic lower respiratory tract disease is the fourth leading cause of death overall in the USA.", "d": "Cancer is the second-highest cause of death overall in the USA."}, "keyConcept": "Cardiovascular disease is the most common cause of death in the United States, but up to 80% of these deaths are preventable. Risk factors for cardiovascular disease that can be modified include consumption of a diet high in fat, lack of physical activity and smoking."}, {"id": 10989, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a class to expectant mothers. Which of the following should the nurse advise the group to avoid in order to prevent toxoplasmosis?", "choices": [{"id": "a", "t": "Contact with cat feces"}, {"id": "b", "t": "Eating freshwater fish"}, {"id": "c", "t": "Excessive exposure to radiation"}, {"id": "d", "t": "Working with heavy metals"}], "correct": "a", "rationale": "Toxoplasma gondii can be transmitted by exposure to infected cat feces or by ingesting undercooked contaminated meat.", "whyNot": {"b": "The parasite is found in warm-blooded animals, not in fish.", "c": "Toxoplasmosis is not associated with radiation.", "d": "Toxoplasmosis is not associated with heavy metals."}, "keyConcept": "If a pregnant woman has been infected with Toxoplasma before becoming pregnant, the unborn child is usually protected by maternal immunity. Experts suggest waiting for 6 months after a recent infection to become pregnant. Infected infants but are often asymptomatic at birth but can develop serious symptoms later in life, including blindness or mental disability. Infected newborns sometimes have eye or brain damage at birth. Pregnant women should avoid changing cat litter if possible. If no one else can change cat litter, the woman should wear disposable gloves and wash her hands with soap and water afterwards. The cat litter box should be changed daily. The parasite does not become infectious until 1 to 5 days after it is shed in a cat’s feces. Household cats should be kept indoors and fed with commercially prepared foods."}, {"id": 10990, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is reviewing postpartum nutrition needs with a client who is breastfeeding. Which of the following statements by the client indicates an understanding of the instructions? O A.\"Ican continue to smoke as long as | do it 30 minutes prior breastfeeding.\" O B. \"I should take folic acid to increase my milk supply.\" O C. \"| will continue adding 200 calories per day to my diet.\" O D.\"I will continue taking my vitamins while | am breastfeeding.\"", "choices": [{"id": "a", "t": "Clients who are breastfeeding should avoid smoking because it will impair milk production. If a client continues smoking, it is"}, {"id": "b", "t": "Folic acid does not increase milk production."}, {"id": "c", "t": "Clients who are breastfeeding require an additional 450 to 500 calories per day to support adequate nutrition."}, {"id": "d", "t": "Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and can continue to take vitamin supplements."}], "correct": "d", "rationale": "Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and can continue to take vitamin supplements. This can assist the client to ensure they receive adequate nutrition while breastfeeding. The client should balance their calories burned and consumed as well.", "whyNot": {"a": "Clients who are breastfeeding should avoid smoking because it will impair milk production. If a client continues smoking, it is", "b": "Folic acid does not increase milk production.", "c": "Clients who are breastfeeding require an additional 450 to 500 calories per day to support adequate nutrition."}, "keyConcept": "Clients who are breastfeeding should increase their daily caloric intake by 450 to 500 calories to support adequate nutrition and breast milk production. Smoking alters breastmilk production. Consuming large amounts of caffeinated beverages is not recommended while breastfeeding due to caffeine entering the breast milk. Clients who breastfeed are instructed to consume a well-balanced, nutritious diet and should be informed that they can continue to take their vitamin supplements. This can assist the client to ensure they receive adequate nutrition while breastfeeding."}, {"id": 10991, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in a clinic is teaching a client who is planning to become pregnant about the effects of folic acid deficiency. Which of the following complications should the nurse include?", "choices": [{"id": "a", "t": "Maternal physiological anemia"}, {"id": "b", "t": "Maternal pica"}, {"id": "c", "t": "Fetal cardiac malformations"}, {"id": "d", "t": "Fetal neural tube defects"}], "correct": "d", "rationale": "Eas) Folic acid has a direct effect on the closure of the neural tube. Deficiency of folic acid can result in defects such as spina bifida, A I io y encephalocele, and anencephaly. Foods high in folic acid include leafy green vegetables, liver, peanuts, cereals, and whole-grain breads. | 3%", "whyNot": {"a": "Physiological anemia is a normal response to pregnancy caused by expansion of the plasma volume to a greater degree than increase in", "b": "Pica refers to cravings for nonnutritive substances, such as dirt, clay ice, and starch, which can occur during pregnancy. Clients who have", "c": "Cardiac anomalies in fetal development can occur due to wide variety of factors, such as genetic factors and exposure to environmental"}, "keyConcept": "Folic acid supplementation prior to and during pregnancy reduces the risk of neural tube defects in the fetus. Dietary sources of folic acid, or folate include grains, liver, peanuts, and fortified products such as cereals. Neural tube defects affect the development of the fetus in the first trimester and can result in severe nervous system damage, brain malformation, and spina bifida. The recommended daily intake of folic acid for clients who are planning to become pregnant is 400 mcg daily."}, {"id": 10992, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "true concerning immunity in a newborn?", "choices": [{"id": "a", "t": "Immunity will only occur with the transfer of immunoglobulins through breast milk."}, {"id": "b", "t": "Neonates have IgG antibodies from the mother and produce IgM in utero."}, {"id": "c", "t": "Neonates only have IgM antibodies from the mother."}, {"id": "d", "t": "Neonates have maternal IgA antibodies and produce IgM antibodies after 24-48 hours."}], "correct": "b", "rationale": "sl 15% Hard IgG antibody produced by the mother crosses the placenta to provide passive acquired immunity to certain bacterial pathogens. This occurs c Hi 15% during the third trimester. The fetus also begins to produce IgM antibody by the end of the third trimester. At birth, these are the only my | 26% antibodies the neonate has, but IgA is supplied through breastfeeding. °", "whyNot": {"a": "Placental transfer of IgG occurs and the fetus also begins to produce IgM antibodies in the third trimester.", "c": "IgM is produced by the fetus. The fetus receives maternal IgG antibody in utero to certain pathogenic organisms.", "d": "Maternal IgA is not transferred through the placenta. A newborn has IgG and IgM. Breastfeeding supplies IgA through colostrum."}, "keyConcept": "At birth, the fetus has IgG antibody transferred across the placenta and IgM antibody produced by the fetus at the end of the third trimester. IgA is supplied to the neonate through breastmilk."}, {"id": 10993, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "This disorder is also known as Bell’s palsy"}, {"id": "b", "t": "Medications prescribed may include anti-epileptic drugs such as Tegretol"}, {"id": "c", "t": "In order to prevent symptoms, the client should try to avoid extremes of heat and cold"}, {"id": "d", "t": "This disorder affects the fifth cranial nerve"}], "correct": "a", "rationale": "Trigeminal neuralgia is not the same as Bell’s palsy, which is a temporary form of facial paralysis. cy 17%", "whyNot": {"b": "Medications such as Tegretol and Dilantin may be used in the treatment of trigeminal neuralgia. D | | 22%", "c": "The pain associated with trigeminal neuralgia may be compounded by extremes in temperature.", "d": "Trigeminal neuralgia is a neurologic disorder that affects the fifth cranial nerve."}, "keyConcept": "Trigeminal neuralgia is a chronic pain disorder that affects the trigeminal nerve. The classical symptoms include episodes of severe, sudden,"}, {"id": 10994, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Based on Erikson’s eight stages of psychosocial development, which age group experiences the stage of autonomy vs. shame and doubt?", "choices": [{"id": "a", "t": "Infants"}, {"id": "b", "t": "Toddlers"}, {"id": "c", "t": "School-aged children"}, {"id": "d", "t": "Adolescents"}], "correct": "b", "rationale": "Correct Answer: B. Toddlers. eo | o: Autonomy vs. shame and doubt is the key psychosocial stage of development for children who are in toddlerhood. c |", "whyNot": {"a": "An infant is in a stage of trust vs. mistrust, where he learns to trust a caregiver.", "c": "School-age children are in the industry vs. inferiority stage where they experience success that leads to more self-confidence.", "d": "Adolescents are in the identity vs. role confusion stage, where they develop a sense of personal identity."}, "keyConcept": "During this stage, children are becoming more independent and want to control their activities. They learn important activities such as toilet training, and dressing themselves. The goal of this period is to establish more autonomy and independence."}, {"id": 10995, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Into which of the following positions should the nurse assist a client to facilitate progress in labor when the fetus is in the occiput posterior position?", "choices": [{"id": "a", "t": "Lithotomy"}, {"id": "b", "t": "Supine with a towel roll under the right hip"}, {"id": "c", "t": "Hands and knees"}, {"id": "d", "t": "Knee to chest"}], "correct": "c", "rationale": "A Hi 11% Hard The occiput posterior position refers to the position of the baby with head down and back to the side. This is the most common type of B ] a malposition of the occiput during labor. The nurse should assist the client to a position on the hands and knees to facilitate rotation of the fetus from the posterior to the anterior position. ec | 52% om 23%", "whyNot": {"a": "The lithotomy position is characterized by the client lying on the back with the knees elevated. It does not facilitate progression of labor.", "b": "This position can relieve compression on the vena cava but is not useful for rotating a malpositioned fetus.", "d": "The knee-to-chest position is useful to relieve cord compression when the umbilical cord is prolapsed."}, "keyConcept": "The occiput posterior position occurs as a result of failure of internal rotation before delivery, causing the occiput to lie in the posterior portion of the pelvis, instead of the anterior pelvis, with the vertex presenting. This causes the head to be deflexed. In most cases, the occiput rotates anteriorly when the occiput meets the pelvic floor, allowing normal delivery. Assisting the client to a position on the hands and knees may facilitate rotation to the anterior position."}, {"id": 10996, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing discharge teaching to a client who has schizophrenia and a new prescription for clozapine. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"You will lose weight while taking this medication.\""}, {"id": "b", "t": "\"You are likely to develop hand tremors if you take this medication for a long time.\""}, {"id": "c", "t": "\"You may experience temporary numbness of the mouth after each dose.\""}, {"id": "d", "t": "\"You should have your white blood cell count monitored every week.\""}], "correct": "d", "rationale": "Due to the risk for agranulocytosis, the nurse should monitor the client's WBC count weekly while taking clozapine.", "whyNot": {"a": "Clozapine increases the risk for significant weight gain and the development of diabetes mellitus. The client's weight should be", "b": "Clozapine has a low risk for extrapyramidal symptoms, but the client should be instructed to report any appearance of extrapyramidal", "c": "Asenapine, rather than clozapine, causes temporary numbing of the mouth."}, "keyConcept": "Clozapine, a second generation antipsychotic (SGA) is indicated for the treatment of schizophrenia. Clozapine produces less extrapyramidal reactions, but it carries a higher risk of hematologic adverse effects. Due to the high risk for agranulocytosis, clozapine is only available through the Clozaril REMS program, which monitors clients, white blood cell testing, and controlled distribution of clozapine. The nurse should include these adverse effects and their manifestations in the discharge teaching for the client: ‘Agranulocytosis Unexplained fever, lethargy, malaise, flu-like symptoms. Diabetes Hyperglycemia, polyuria, polydipsia, polyphagia Dyslipidemia Elevated LDL cholesterol, increased total cholesterol, decreased HDL cholesterol | Weight gain Increase in weight, BMI, and waist circumference Extrapyramidal symptoms Parkinsonism Tardive dyskinesia Akathisia Acute dystonia ‘Orthostatic hypotension Decreased blood pressure when changing positions Anticholinergic symptoms: Dry mouth, constipation"}, {"id": 10997, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in the birthing room is assessing a newborn. Which of the following findings should be assigned an Apgar value of 2?", "choices": [{"id": "a", "t": "Astrong cry"}, {"id": "b", "t": "Legs and arms slightly flexed"}, {"id": "c", "t": "Body pink and extremities blue"}, {"id": "d", "t": "A heart rate of ninety beats per minute"}], "correct": "a", "rationale": "APGAR is an acronym that stands for \"appearance, pulse, grimace, activity, and respiration.\" The score is a measure of the physical condition po] e o 2 ° s a = a < of the neonate. The score is obtained by adding points (2, 1, or 0) for heart rate, respiratory effort, muscle tone, response to stimulation, and skin color; a score of ten represents the best possible condition. The score is calculated at one and five minutes after delivery. (Taken on tat min and Sth min of lie and later necessary determined by evaluating the | newborn baby on ve simple | Srora on a scale om zero totwo, |—_\\_ | then summing up te fve valves \\ thes obtaned (( Scores 3 and below are generally regarded as entically low. 4 to 6 | taxty tow, and 7¥0 10 generally", "whyNot": {"b": "Legs and arms slightly flexed demonstrates some flexion; this would be assigned a 1. D Hi", "c": "Peripheral cyanosis receives a score of 1, not 2.", "d": "A heart rate of 90 bpm would receive a score of 1, not 2."}, "keyConcept": "APGAR is an acronym that stands for \"appearance, pulse, grimace, activity, and respiration.\" The score is a measure of the physical condition po] e o 2 ° s a = a < of the neonate. The score is obtained by adding points (2, 1, or 0) for heart rate, respiratory effort, muscle tone, response to stimulation, and skin color; a score of ten represents the best possible condition. The score is calculated at one and five minutes after delivery. (Taken on tat min and Sth min of lie and later necessary determined by evaluating the | newborn baby on ve simple | Srora on a scale om zero totwo, |—_\\_ | then summing up te fve valves \\ thes obtaned (( Scores 3 and below are generally regarded as entically low. 4 to 6 | taxty tow, and 7¥0 10 generally"}, {"id": 10998, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Sf Viralr = Ss Recor = Inbox % Inbox Until Untitl (@ Googi @ TEAS Online & Mark! |= @ Micro: (eens cee Nae irel @ aAtits = G@ Newc N x] G GERO + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "The client’s grandchildren will not be allowed to visit"}, {"id": "b", "t": "visitors will need to wear masks whenever visiting with the client"}, {"id": "c", "t": "No pregnant visitors should be allowed"}, {"id": "d", "t": "The family should wash their hands before and after caring for the client"}], "correct": "d", "rationale": "-washing is the best way to prevent the spread of infection. B | 3\"", "whyNot": {"a": "There is no need to restrict visitors. Good hand-washing should prevent the spread of infection. e@D fF 95%", "b": "There is no evidence to indicate the need to wear masks unless splash or spray is anticipated during contact with the client.", "c": "There is no need to restrict visitors. Good hand-washing should prevent the spread of infection."}, "keyConcept": "Infection control measures indicated for wound care include handwashing. Hands should be washed with soap and water when hands are visibly soiled with blood, body fluids, secretions, excretions, and exudates from wounds. When hands are not visibly soiled, the family may use an alcohol-based hand rub or wash with soap and water. Gloves should be worn when in contact with the wound. or wound drainage. All used dressings and disposable supplies should be contained in a leak-proof bag before placing in the garbage can."}, {"id": 10999, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is counseling a client who is HIV positive on her initial prenatal visit. Which of the following should the nurse include in teaching the client?", "choices": [{"id": "a", "t": "Antiretroviral therapy (ART) should be discontinued during pregnancy."}, {"id": "b", "t": "Breastfeeding is contraindicated for mothers who are HIV positive."}, {"id": "c", "t": "Intramuscular influenza vaccine is contraindicated during pregnancy."}, {"id": "d", "t": "The newborn develops antibodies to HIV in utero and will not require treatment."}], "correct": "b", "rationale": "all 7% Easy HIVis a retrovirus and is transmitted from mother to neonate in the perinatal period. Transmission can occur in utero, at labor and delivery, Cc i 10% or through breastfeeding in the postnatal period. Mothers with HIV infection who live in developed countries with access to safer alternatives . Breastfeeding is also contraindicated in mothers with active tuberculosis or who are positive for human T-cell lymphotropic virus type | or type Il.", "whyNot": {"a": "ART has not been shown to increase the rate of birth defects in the first trimester and should be initiated as soon as possible during", "c": "Live attenuated influenza vaccine is contraindicated. Injectable influenza vaccines are killed vaccines and pose no risk of infection in", "d": "All infants born to an HIV-positive mother should receive antiretroviral prophylactic therapy. They do not develop immunity to the virus."}, "keyConcept": "Transmission of HIV from mother to neonate occur at any time during the perinatal period and during breastfeeding. Breastfeeding is not recommended by mothers with HIV infection if other alternatives are available for feeding the newborn."}, {"id": 11000, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "medications? O A. Remind the client that he only needs to continue seeing the health care provider if he is having symptoms of hypertension O B. Advise the client to report back if experiencing a weight gain of 1 lb. per month O C. Tell the client to take his medicine in the morning to reduce periods of nighttime urination O D. Remind the client that his medicine can cause changes in his mood; he should report side effects of hostility and paranoia", "choices": [{"id": "a", "t": "Remind the client that he only needs to continue seeing the health care provider if he is having symptoms of hypertension"}, {"id": "b", "t": "Advise the client to report back if experiencing a weight gain of 1 lb. per month"}, {"id": "c", "t": "Tell the client to take his medicine in the morning to reduce periods of nighttime urination"}, {"id": "d", "t": "Remind the client that his medicine can cause changes in his mood; he should report side effects of hostility and paranoia"}], "correct": "c", "rationale": "al 2% Easy The nurse should advise the client to take his diuretic medication in the morning. A diuretic will increase urine output, so it would be best to B I a take it during the day. If the client takes the medication at night, he may be more likely to wake up during the night to use the bathroom.", "whyNot": {"a": "Most clients do not have symptoms of hypertension; the client should continue to see a health care provider to manage his hypertension", "b": "Although the client may have some weight changes, an initial weight gain of 1 lb. per month is not a reason to contact the health care", "d": "Side effects of hostility and paranoia are typically not associated with diuretic use."}, "keyConcept": "Thiazide diuretics are recommended as an initial treatment for hypertension. Diuretics enhance the excretion of various electrolytes and water by affecting renal mechanisms for tubular secretion and reabsorption. They increase urine output and may be better tolerated if taken during the daytime hours."}, {"id": 11001, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "When developing the teaching plan for a primiparous client who is bottle feeding her term neonate for the first feeding, which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Keep the nipple of the bottle full of formula while feeding"}, {"id": "b", "t": "term babies have well-developed sucking skills"}, {"id": "c", "t": "Burp the baby after 6 oz. of formula have been taken"}, {"id": "d", "t": "Propping of the bottle may make it easier to feed the baby"}], "correct": "a", "rationale": "Formula should fill the entire nipple of the bottle while the baby is sucking. This decreases the amount of air taken in by the baby prevents. B | a0 regurgitation: Not all babies at term are born with well-developed sucking skills. ci 18%", "whyNot": {"b": "Not all babies who are born full-term have well-developed sucking skills.", "c": "A baby who is eating formula should be burped after eating 2 to 3 oz. at a time or more often if the baby stops eating in between or", "d": "The nurse should tell the parent to never prop a bottle. It will not cause the baby to get too much air but it can cause the baby to choke. It"}, "keyConcept": "The American Academy of Pediatrics recommends exclusively breastfeeding for the first six months of life. All women are not able to breastfeed and breastfeeding is contraindicated in some cases, including mothers with HIV or active tuberculosis. The energy requirement for infants in the first three months is 110 kcal/kg/day. Breast milk provides 67 kcal/100 ml. Most children receive formula at some point during the first year of life. Formula simulates the caloric content of breast milk. The type of formula is generally specified by the pediatrician. Most newborns should be fed every 3 to 4 hours. If the infant demonstrates adequate weight gain, he/she can be allowed to sleep through the night, but initially, most infants should be woken up for feedings during the night. Most infants require 6-8 feedings per 24 hours. Newborns usually drink 15-30 mL of formula at each feeding in the first day of life, with a gradual increase over the first week."}, {"id": 11002, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who has a presumptive diagnosis of gonorrhea. The nurse understands that which of the following co-infections is most likely to be detected by a urinary PCR test? O anv O >B. syphilis O C. Chlamydia O D. Trichomonas", "choices": [{"id": "a", "t": "Risk of HIV infection is increased in clients with other STIs, particularly syphilis."}, {"id": "b", "t": "Syphilis increases the risk of HIV infection by up to 4x the risk of uninfected individuals."}, {"id": "c", "t": "Chlamydia is the most common sexually transmitted infection in the United States."}, {"id": "d", "t": "Trichomonas, a parasite infection, is not the most likely co-infection seen with gonorrhea. Trichomonas causes copious, malodorous,"}], "correct": "c", "rationale": "Chlamydia is the most common sexually transmitted infection in the United States. It is caused by the bacteria Chlamydia trachomatis and frequently occurs in conjunction with gonorrhea infections. Chlamydia infection may be asymptomatic, but it places women at increased risk of ectopic pregnancy and infertility. Treatment for chlamydia is azithromycin, which is usually administered with treatment for gonorrhea. Diagnosis can be made by urinary polymerase chain reaction (PCR).", "whyNot": {"a": "Risk of HIV infection is increased in clients with other STIs, particularly syphilis.", "b": "Syphilis increases the risk of HIV infection by up to 4x the risk of uninfected individuals.", "d": "Trichomonas, a parasite infection, is not the most likely co-infection seen with gonorrhea. Trichomonas causes copious, malodorous,"}, "keyConcept": "Chlamydia, the most common sexually transmitted infection in the United States, is often accompanied by co-infection with gonorrhea. Treatment is usually provided empirically for both infections when one is diagnosed. Treatment should be provided to all sexual partners."}, {"id": 11003, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 65-year-old female client with a new prescription for calcium supplements. Which of the following should the nurse advise the client supplement to maximize calcium absorption?", "choices": [{"id": "a", "t": "Vitamin C"}, {"id": "b", "t": "Vitamin D O vitamin B12"}, {"id": "d", "t": "Vitamin A"}], "correct": "b", "rationale": "All 10% Easy Osteoporosis affects 9 million individuals in the United States, primarily women. More than half of all women over the age of 50 will break a Cc | T% bone during their lifetime as a result of osteoporosis. This is primarily due to decreases in estrogen. Estrogen stimulates the release of (1,25(OH)2D) receptors in the gut, necessary for absorption of calcium. Post-menopausal women and men over the age of 70 should take 800 to 1,000 IU units of supplemental vitamin D daily in addition to calcium supplementation. Fortified milk is the most readily available source of dietary vitamin D, containing approximately 100 IU vitamin D in an 8-ounce serving. Vitamin D concentrations are increased by exposure to sunlight but use of sunscreen blocks synthesis of vitamin D. Multivitamins usually contain 400 IU units of vitamin D, which is not adequate for prevention of osteoporosis.", "whyNot": {"a": "Vitamin C is necessary for collagen production, which contributes to the repair and maintenance of bones. However, it does not play a", "d": "Vitamin A does not increase the absorption of calcium from the Gl tract."}, "keyConcept": "Osteoporosis and subsequent fracture occur in over 50% of women over the age of 50, largely because estrogen levels decrease. Estrogen facilitates absorption of calcium from the intestine by stimulating the release of calcitonin and activation of vitamin D receptors in the gut, In the absence of estrogen, postmenopausal women and men over the age of 70 should take 800 to 1000 IU of supplemental Vitamin D daily, to facilitate absorption of calcium from dietary sources and supplements."}, {"id": 11004, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a pregnant client whose last menstrual period was on February 11. By July 18, a physical assessment of the client should indicate that the top of the fundus is at which of the following locations?", "choices": [{"id": "a", "t": "Even with the umbilicus"}, {"id": "b", "t": "Just above the symphysis pubis"}, {"id": "c", "t": "Two finger-breadths above the umbilicus"}, {"id": "d", "t": "Halfway between the symphysis and umbilicus"}], "correct": "a", "rationale": "Fundal height is defined as the distance from the pubic bone to the top of the uterus measured in centimeters. After 20 weeks of pregnancy, the fundal height measurement matches the number of weeks gestation, +/- 2 weeks. The fundal height measurement is not as accurate in women who are obese, carrying multiples, or with a history of fibroid tumors. Asmaller or larger fundal height than expected or a fundal height that increases more or less quickly than expected could be due to intrauterine growth restriction, fetal macrosomia (large baby), oligohydramnios (reduced amniotic fluid), or polyhydramnios (increase in amniotic fluid.) a 36 wk — wuwk ——~ 3owk", "whyNot": {"b": "This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be much D Hl 20%", "c": "At this point, the top of the fundus would be at about the umbilicus, not two finger-breadths above.", "d": "This information indicates that the client is at approximately 22 weeks’ gestation. At this point, the top of the fundus would be at about"}, "keyConcept": "Fundal height is defined as the distance from the pubic bone to the top of the uterus measured in centimeters. After 20 weeks of pregnancy, the fundal height measurement matches the number of weeks gestation, +/- 2 weeks. The fundal height measurement is not as accurate in women who are obese, carrying multiples, or with a history of fibroid tumors. Asmaller or larger fundal height than expected or a fundal height that increases more or less quickly than expected could be due to intrauterine growth restriction, fetal macrosomia (large baby), oligohydramnios (reduced amniotic fluid), or polyhydramnios (increase in amniotic fluid.) a 36 wk — wuwk ——~ 3owk"}, {"id": 11005, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assisting a healthcare provider with a potentially painful procedure on a 4-year-old child. Which of the following statements from the nurse is most appropriate when addressing this client’s pain?", "choices": [{"id": "a", "t": "“The doctor is going to sew this up and then put a dressing on your wound.”"}, {"id": "b", "t": "\"Hold still, this is going to hurt some.”"}, {"id": "c", "t": "“You have an owie right now, but we are going to help it get better.”"}, {"id": "d", "t": "“Be a big boy and don’t cry; it will be right.”"}], "correct": "c", "rationale": "al 5% Easy Preschool-aged children who are between 3 and 5 years old need only simple explanations from caregivers. This age group is also B | a significantly afraid of pain or any situation that might cause harm, yet they do not always have the language to express these fears. Using simple terms and allowing the child to express himself, whether it is through words or crying, will help to get him through a potentially ec P| 88% painful situation.", "whyNot": {"a": "A 4-year-old child needs a simple explanation for what is going to happen. This explanation may be too complicated for the child to", "b": "Preschool-aged children can be significantly afraid of pain; telling the child ahead of time that the procedure will hurt will only increase", "d": "The nurse should understand that the child may cry and not expect him to remain tough or avoid emotion."}, "keyConcept": "Ayoung child (3-5 years old) will typically use verbal expressions like 'Ouch\" or \"it hurts\" when expressing pain. This population will generally show a lack of cooperation and may thrash arms and legs, crying and screaming. The 4-year-old will worry in anticipation of a painful procedure and may cling to the parent or nurse. Hugs and other forms of physical comfort are helpful. With ongoing pain, the child will become irritable and restless."}, {"id": 11006, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who has a serum calcium level of 11.8 mg/dL. Which complication is the client at highest risk for?", "choices": [{"id": "a", "t": "Liver disease"}, {"id": "b", "t": "Kidney stones"}, {"id": "c", "t": "Irritable bowel syndrome"}, {"id": "d", "t": "Respiratory distress"}], "correct": "b", "rationale": "This calcium result is above normal, indicating hypercalcemia. High levels of calcium are associated with an increased risk of kidney stones.", "whyNot": {"a": "This calcium result is high, but liver disease is not a complication associated with hypercalcemia.", "c": "Irritable bowel syndrome is not associated with high levels of serum calcium.", "d": "The client has hypercalcemia, but respiratory distress is not a complication associated with high calcium levels."}, "keyConcept": "Hypercalcemia can be the result of excess intake of calcium (such as supplements or antacids) or altered excretion of calcium (such as in clients with renal failure or those taking thiazide diuretics). Other causes of hypercalcemia include prolonged immobility, glucocorticoid use, hyperthyroidism, hyperparathyroidism, lithium use, dehydration, or malignancy with metastasis to bone."}, {"id": 11007, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl € Goog! @ TEAS Online @ Mark! @ Micro: (lererrrpaie Nae rer @ atits @ Newc N x) G GERO + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Provide the infant with a pacifier"}, {"id": "b", "t": "Hang a mobile over the infant’s crib"}, {"id": "c", "t": "Provide the infant with a soft toy"}, {"id": "d", "t": "Warm the infant’s formula prior to feeding"}], "correct": "a", "rationale": "Oral needs are primary during infancy. Providing the infant with a pacifier to suck on will help the infant meet this need. B i at", "whyNot": {"b": "An infant this young will be unable to focus on a mobile, and will probably be positioned in a side-lying position post-operatively, so D || 29%", "c": "An infant who is only a few days only is incapable of playing with a soft toy and would not benefit from this intervention.", "d": "Warming the formula prior to feeding is a comfort measure, but it does not meet a developmental need."}, "keyConcept": "Infants and toddlers with developmental disorders often require lengthy hospitalizations. The healthcare team should have a plan for"}, {"id": 11008, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a client about birth control and preventing sexually transmitted infections. Which method is most effective in preventing both pregnancy and sexually transmitted diseases?", "choices": [{"id": "a", "t": "Condoms"}, {"id": "b", "t": "Birth control pills"}, {"id": "c", "t": "Adiaphragm"}, {"id": "d", "t": "A vaginal ring"}], "correct": "a", "rationale": "Condoms provide a physical barrier that not only prevents sperm from entering a woman’s uterus and causing pregnancy, but the barrier ~~ — . c | 3%", "whyNot": {"b": "Birth control pills work to prevent pregnancy, but they do not prevent sexually transmitted diseases.", "c": "A diaphragm works to prevent pregnancy, but it does not prevent sexually transmitted diseases.", "d": "A vaginal ring works to prevent pregnancy, but it does not prevent sexually transmitted diseases."}, "keyConcept": "Primary prevention of sexually transmitted diseases can be effective with correct use of barrier protection, such as condoms. Condom use does not provide absolute protection against sexually transmitted infections (STI). The most reliable ways to avoid transmission of STIs are to abstain from sexual activity, or to be in a long-term mutually monogamous relationship with an uninfected partner. Effectiveness of Contraceptive Methods ore tertoneiayoermeted oe sauna dam prostate cougweaectvomeni casa ‘coma Siewenemnaaee Sadmente Tecate Go EE Pils Take 2 pal each day. eupepocn ye (5) ax Patch, Rigs Keepin place seer (oO) we /} chonprontine Wot¢ d4 Prapbeage Ue comecthy ~~ *% 9% oo” ns aya ale Condem Tomas Gem @» he ~ onetime <$ f--n—— 2% ermmyamenes —_spemidn Seeders Bas a&, 9 as less “hapecanngnnnat eeubes etter av woman sho cnpetanad sa tstsandad peguey taeche _\"wahunbulenyenel ypesiouet xh comecpeor mated"}, {"id": 11009, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing discharge instructions to the guardian of an 8-year-old child following a cardiac catheterization. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Keep the child home from school for 1 week."}, {"id": "b", "t": "Give the child acetaminophen for discomfort."}, {"id": "c", "t": "Offer the child ice chips for the first 24 hr."}, {"id": "d", "t": "Assist the child to take a tub bath the day after the procedure."}], "correct": "b", "rationale": "The child might experience minor discomfort at the puncture site. The guardian should offer either acetaminophen or ibuprofen. The child A || should not be given aspirin because of the associated risk for Reye syndrome. eB | cil", "whyNot": {"a": "The child can attend school but should avoid strenuous activity.", "c": "The child should begin fluid intake with sips of clear liquids but can resume a regular diet as soon as she desires.", "d": "The child should keep the site clean and dry and, therefore, avoid tub baths for at least 3 days after the procedure. The nurse should"}, "keyConcept": "The nurse should provide discharge instructions to the guardian of a child following cardiac catheterization. Care After Cardiac Catheterization Keep the site clean and dry. Avoid tub baths for the first 3 days. Avoid strenuous activity. Consume a regular diet without restrictions. Use ibuprofen or acetaminophen for pain."}, {"id": 11010, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a neonate who just underwent circumcision. If bleeding should occur, what is the initial priority?", "choices": [{"id": "a", "t": "Use a sterile gauze pad to apply light pressure to the area"}, {"id": "b", "t": "Notify the healthcare provider immediately"}, {"id": "c", "t": "Assess heart rate and oxygen saturation"}, {"id": "d", "t": "Place a tighter diaper on the infant to place pressure on the affected area"}], "correct": "a", "rationale": "Circumcision is a procedure often performed in the United States that is characterized by the removal of the foreskin or puce of the glans penis. The benefits of routine circumcision are unclear. The procedure is usually performed before discharge from the hospital. The infant is positioned on a plastic restraint form. Soap and water or a povidone-iodine prep are used to cleanse the penis, and the infant is draped to create a sterile field and to maintain body temperature. The procedure takes several minutes and is generally performed with minimal bleeding. A piece of petrolatum gauze is used as a dressing to prevent the diaper from adhering to the penis. A PlastiBell is sometimes used to apply direct pressure to prevent hemorrhage during circumcision. It remains in place and protects the area from infection or from adhering to the diaper. The rim remains in place for about a week before it falls off. The nurse should check the circumcision site for bleeding and normal voiding every hour for 12 hours after the circumcision. The immediate priority if bleeding occurs at the site is to apply light pressure to the area with a sterile gauze pad. Circumcision surgery Dorsal slit Foreskin", "whyNot": {"b": "After administering first aid to stabilize the bleeding lesion, the nurse should check vital signs and then notify the healthcare provider if", "c": "The initial priority is first aid for a bleeding lesion. After this has been administered, vital signs can be assessed.", "d": "Gelfoam powder or a sponge can be used to control bleeding, but the use of a folded sterile gauze pad is the initial step."}, "keyConcept": null}, {"id": 11011, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "observed by the nurse? O A. Areassuring pattern O B. Fetal tachycardia O C. Early deceleration O D. Late deceleration", "choices": [{"id": "a", "t": "Areassuring pattern"}, {"id": "b", "t": "Fetal tachycardia"}, {"id": "c", "t": "Early deceleration"}, {"id": "d", "t": "Late deceleration"}], "correct": "b", "rationale": "A | | 25% Moderate When measured by electronic fetal monitoring, a normal fetal heart rate (FHR) is between 110 and 160 bpm. A rate of more than 160-180 OB a aan beats per minute (bpm) represents fetal tachycardia. Fetal tachycardia usually ranges between 170-220 bpm. Fetal tachycardia is a nonreassuring pattern that requires further evaluation to rule out fetal acidosis. c - 6% D 3%", "whyNot": {"a": "The heart rate described represents fetal tachycardia.", "c": "The description is not indicative of early deceleration.", "d": "This rate does not reflect a late deceleration."}, "keyConcept": "The fetal heart rate monitor measures the FHR during a uterine contraction and 30 seconds after the contraction to identify the fetal response. An external transducer is placed on the maternal abdomen and held in place by an elastic belt or girdle. The transducer uses Doppler ultrasound to detect the fetal heartbeat. Internal fetal heart rate monitoring is performed by placing an electrode into the fetal scalp. Electronic fetal heart rate monitoring is used to assess fetal well-being during labor and detect fetal compromise indications. Fetal heart rate patterns are classified as reassuring, nonreassuring, or ominous. Nonreassuring patterns include fetal tachycardia, bradycardia, and late decelerations with good short-term variability. Nonreassuring patterns should be evaluated further to rule out fetal acidosis."}, {"id": 11012, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assigned to care for a 9-month-old child who is being admitted to the pediatric unit. Which of the following nursing interventions is most appropriate when admitting this client?", "choices": [{"id": "a", "t": "Encourage the primary caregiver to leave the unit while completing admission."}, {"id": "b", "t": "Ask the primary caregiver to restrain the client when preparing to draw blood."}, {"id": "c", "t": "Determine if the child would prefer to go to the playroom to complete admission."}, {"id": "d", "t": "When examining the child, allow the child to remain in the primary caregiver’s lap."}], "correct": "d", "rationale": "| 3% A nurse understands that separation anxiety, the most significant stressor that affects children from the middle of infancy to the age of 30 c | 5% months, results from hospitalization in early childhood. If separation can be reduced, this will increase the ability of the child to respond to eD PY 91% other stressors. Also known as anaclitic depression, separation anxiety progresses through 3 stages. During the protest state, the child may scream, cry, and be inconsolable when the parent leaves. The stage of despair is characterized by cessation of crying and onset of obvious despair, with decreased interest in food or play. Finally, detachment occurs. During this stage, the child appears adjusted to loss and appears to be more interested in the surroundings, evidenced by a willingness to play with others and form relationships. This behavior results from the child’s resignation and attempt to detach from the parents. Detachment is unusual during a hospitalization, which has time constraints. The child should be prepared for admission, but preparation does not negate the need to avoid causing unnecessary anxiety or fear during the process of admission. The nurse should encourage the child to remain in the lap of the primary caregiver during the physical exam.", "whyNot": {"a": "The primary caregiver should generally be present during the admission process.", "b": "Restraining the child will increase anxiety. If the child must be restrained, it is appropriate to have hospital personnel restrain the client", "c": "An infant of this age is unable to consent or to make a decision."}, "keyConcept": "Hospitalization in early childhood can increase the severity of separation anxiety, which usually occurs from mid-infancy to the age of 30 months. Reduction of separation can reduce the child's stress and prevent progression. Separation anxiety progresses over time through 3 stages: protest, despair, and detachment."}, {"id": 11013, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following should the nurse assess first on a well-child exam in a 6-week-old infant who is sleeping?", "choices": [{"id": "a", "t": "Examination of ears with an otoscope"}, {"id": "b", "t": "Assessment of Moro reflex"}, {"id": "c", "t": "Auscultation of lungs and heart sounds"}, {"id": "d", "t": "Percussion and palpation of the abdomen"}], "correct": "c", "rationale": "all 6% Easy When a nurse is assessing an infant, the nurse should begin the examination with an auscultation of all areas to be examined in a head to toe B | nove order. Next, palpation and percussion should be performed. The assessment of pupillary response, ears, and mouth are performed after palpation and auscultation since these maneuvers are more likely to elicit crying from the infant. The final step in the exam is an assessment ec | 83% of the Moro reflex, as the infant is likely to be awake by this point in the exam, and this assessment typically results in a reflex startle . Other reflexes can be tested in the course of assessment, as the relevant body part is examined.", "whyNot": {"a": "Assessment of the ears, mouth, and pupillary response are more invasive parts of the exam. They should normally be performed towards", "b": "The Moro reflex is the final step of the assessment of an infant, as it will result in crying and a reflexive startle.", "d": "Palpation and percussion should be performed after auscultation is complete and while the infant is still likely to be quiet and calm."}, "keyConcept": "When assessing a sleeping infant, the initial assessment should be auscultation, while the child is quiet, followed by palpation and percussion. The final steps in the exam are pupillary reflex, ear exam, and assessment of the Moro reflex. Testing the Moro reflex usually results in a reflex startle response and crying."}, {"id": 11014, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Trichomoniasis O >B. syphilis"}, {"id": "c", "t": "Human papillomavirus"}, {"id": "d", "t": "Gonorrhea"}], "correct": "c", "rationale": "| 2% Easy The vaccine for HPV is safe and effective and protects males and females against the disease. HPV vaccines are given in a series of two or B | a0 three shots over a six-month period.", "whyNot": {"a": "There is no vaccine to protect against trichomoniasis. The nurse would instead teach these clients about a vaccine against human", "d": "There is no vaccine to protect against gonorrhea. The nurse would instead teach these clients about a vaccine against human"}, "keyConcept": "More than 30,000 women and men are diagnosed each year with a cancer caused by sexually transmitted HPV infection. Cervical cancer accounts for one in three cancers caused by infection with the human papillomavirus. Vaccination prevents infection and reduces the risk of cancer. Two doses of the HPV vaccine are recommended if the series is started before the client's 15th birthday. Three doses of the HPV vaccine are recommended for teens and young adults who start the series at ages 15 through 26 years, and for immunocompromised persons."}, {"id": 11015, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Ahealthcare provider orders a serum alpha-fetoprotein test for a pregnant client at 20 weeks’ gestation. Which best describes the purpose of this test?", "choices": [{"id": "a", "t": "Identifying renal disease in the mother"}, {"id": "b", "t": "Verifying the risk of maternal-fetal blood type incompatibility"}, {"id": "c", "t": "Assessing for fetal hyperbilirubinemia"}, {"id": "d", "t": "Excluding the presence of fetal neural tube defects"}], "correct": "d", "rationale": "-fetoprotein test detects the amount of a protein produced by the fetus during development. The test is typically performed B | see between 15 and 22 weeks’ gestation to rule out the presence of certain birth defects, including neural tube defects such as spina bifida. It may also be performed to detect the presence of genetic abnormalities such as Down syndrome or Turner syndrome. c | 5%", "whyNot": {"a": "An alpha-fetoprotein test is not performed to detect kidney disease in a pregnant mother.", "b": "The alpha-fetoprotein test assesses for the possibility of birth defects in the fetus; it is unrelated to maternal-fetal blood incompatibility.", "c": "The alpha-fetoprotein test does not measure for high bilirubin in the fetus."}, "keyConcept": "Open neural tube defects (NTDs) are congenital anomalies that develop when a portion of the neural tube fails to close normally during the third and fourth weeks after conception. These anomalies can affect the vertebrae, spinal cord, cranium, and/or brain. Alpha-fetoprotein is a fetal-specific globulin, synthesized by the fetal yolk sac, gastrointestinal tract, and liver. The function of alpha-fetoprotein is unknown, but it can be measured in maternal serum (MSAFP), amniotic fluid, and fetal plasma. Abnormalities may indicate neural tube and non-neural tube defects in the fetus. Elevated MSAFP should prompt an ultrasound examination to further assess whether an open NTD or another anomaly associated with elevated MSAFP levels is present."}, {"id": 11016, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Acommunity health nurse is leading a discussion about sexual assault with a neighborhood task force. Which of the following statements by a member of the task force indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Rape is a crime of passion.\""}, {"id": "b", "t": "\"Acquaintance rape often involves the use of alcohol.\""}, {"id": "c", "t": "\"Most people who are sexually assaulted are under 21 years old.\""}, {"id": "d", "t": "\"Most sexual assault is committed by strangers.\""}], "correct": "b", "rationale": "A Alcohol and other substances are often associated with acquaintance or date rape. OB —", "whyNot": {"a": "Most rapes are premeditated and are about power or control over other people rather than an act of lust. A crime of passion is based on D I", "c": "Individuals of any age, sex, and gender identity experience sexual assault. Sexual assault resulting in rape is the second-most common", "d": "Most people who experience sexual assault know the perpetrator."}, "keyConcept": "It is important when teaching and discussing with members of the public about sexual assault to clarify common misperceptions. When teaching a group, the nurse should give accurate information and should also support group members if discussions become emotional. Assisting group members to examine their feelings about topics such as sexual assault can make members more empathetic and able to better understand the emotions of clients. Teaching aids such as pamphlets and electronic technologies can enhance learning."}, {"id": 11017, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "interventions is most appropriate ? O", "choices": [{"id": "a", "t": "Restrict fluids until the client has had a bowel movement"}, {"id": "b", "t": "Provide the client with a meal or snack"}, {"id": "c", "t": "Start an IV of normal saline and administer antibiotics"}, {"id": "d", "t": "Keep the client NPO and notify the physician"}], "correct": "b", "rationale": "Following a normal vaginal delivery, a patient may be hungry and want to eat. In this situation, the patient should be allowed to have a snack or a meal, as she is not exhibiting abnormal symptoms following the delivery. The nurse should monitor the client’s food and fluid intake and administer stool softeners as ordered to avoid straining with defecation because of the episiotomy and the hemorrhoids.", "whyNot": {"a": "Fluids would be encouraged to prevent constipation.", "c": "There is no indication in the question IV antibiotics are needed at this time", "d": "The client should not be kept NPO. They are allowed to eat freely and their intake should be monitored."}, "keyConcept": "The postpartum period, which lasts six to eight weeks, begins after the delivery of the baby and ends when the mother's body has nearly returned to its pre-pregnant state. The key to maintaining energy and health during this busy period is good nutrition. The mother should be encouraged to eat nutrient-dense foods."}, {"id": 11018, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "actions should the nurse take? O A. Ask the child to sing a song. O B. Ask the parents to restrain the child. O C. Tell the child that he/she won't feel the needlestick. O D. Inject the deltoid muscle.", "choices": [{"id": "a", "t": "Ask the child to sing a song."}, {"id": "b", "t": "Ask the parents to restrain the child."}, {"id": "c", "t": "Tell the child that he/she won't feel the needlestick."}, {"id": "d", "t": "Inject the deltoid muscle."}], "correct": "a", "rationale": "o; oH School-age children may be fearful of an injection, and stress can be experienced by both the child and the parent. A prior unpleasant or Cc | painful injection can increase the risk of fear and anxiety. Some children at this age are concerned about body mutilation or experience D || stress due to perceived loss of control. The nurse should evaluate each child to determine the child’s attitude toward the injection. Some children are readily cooperative and will remain still while receiving an injection. Helpful actions include those that restore the child’s feeling of control over his or her body. Giving the child permission to cry or complain can sometimes reduce resistance and facilitate cooperation. Distraction techniques are also useful to assist the child with coping. These include asking the child to tell a joke or story, sing, or count numbers.", "whyNot": {"b": "Restraining a child will increase the stress associated with the injection. Parents should be encouraged to hold younger children securely", "c": "Itis dishonest to tell a child that a needlestick will not hurt. The nurse should prepare the child by describing the sensation of pain in age-", "d": "The anterolateral thigh is preferred for small children. The vaccine can be given in the posterior triceps aspect of the upper arm in older"}, "keyConcept": "Stress experienced by school age children in association with an injection will vary. The nurse should evaluate each child individually to determine their attitude towards an injection. Techniques to reduce distress include distraction and giving the child permission to complain orcry."}, {"id": 11019, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is performing a developmental assessment on a 9-month-old child. Which of the following outcomes would warrant further investigation by the health care provider?", "choices": [{"id": "a", "t": "The child is only army crawling but is not walking"}, {"id": "b", "t": "The child does not copy shapes © c. The child is not babbling"}, {"id": "c", "t": "Lack of babbling or vocalizations in a child over the age of 6 months indicates a possible hearing loss."}, {"id": "d", "t": "The child is drooling from the mouth"}], "correct": "c", "rationale": "Lack of babbling or vocalizations in a child over the age of 6 months indicates a possible hearing loss. If the child cannot hear, he may not be able to hear and copy others or hear himself and the sounds he makes as he practices talking. A lack of babbling in this 9-month-old child, during the assessment and with reports from the parents, warrants further investigation by a health care provider.", "whyNot": {"a": "Many children are unable to walk at 9 months old; a child who is army crawling is learning to get around but should not be expected to", "b": "The child has not reached a developmental age to where he can copy shapes. This skill does not develop until about 2 years old.", "d": "Drooling signifies tooth eruption, which would be normal in a 9-month-old child."}, "keyConcept": "Hearing loss should ideally be identified by 3 months of age so that treatment can begin before the baby is 6 months old. This period is an important time for speech and language development. Early signs of hearing loss include failure to startle in response to a sudden loud sound, music, and voices; unable to be soothed by soft sounds; and not moving or waking up at the sound of voices or nearby noises when sleeping in a quiet room. By 2 months, it is cause for concern if the infant doesn't make any vowel sounds (\"ohh\".) Speech and language milestones in a 9-month-old child include understanding “no”; making different sounds like “mamamama’; copying sounds and gestures of others; and using fingers to point at things. Hearing tests for infants include behavioral audiometry. This screening test used in infants to observe their behavior in response to different sounds. Reacts to loud sounds Calms down or smiles when spoken to Recognizes your voice and calms down if crying When feeding, starts or stops sucking in response to sound Coos and makes pleasure sounds Has a special way of crying for different needs Smiles when he or she sees you Follows sounds with his or her eyes"}, {"id": 11020, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "By using condoms"}, {"id": "b", "t": "Through the use of oral contraceptives"}, {"id": "c", "t": "By practicing abstinence"}, {"id": "d", "t": "By maintaining monogamous relationships"}], "correct": "c", "rationale": "Abstaining from oral, anal, and vaginal sex is the most effective way to avoid contracting a sexually transmitted disease.", "whyNot": {"a": "Condoms may reduce the likelihood of contracting an STD, but are not the most effective way of preventing these diseases.", "b": "Oral contraceptives do not protect against STDs.", "d": "An STD may be contracted from a single partner."}, "keyConcept": "The only certain way to prevent a sexually transmitted infection is abstinence. No precautions are 100% effective in prevention of STI."}, {"id": 11021, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "weight loss plan? O A. Family dietary habits and preferences O B. Family readiness for change O C. Family financial resources for purchase of healthy food items O D. Child’s normal routine of physical activity", "choices": [{"id": "a", "t": "Family dietary habits and preferences"}, {"id": "b", "t": "Family readiness for change"}, {"id": "c", "t": "Family financial resources for purchase of healthy food items"}, {"id": "d", "t": "Child’s normal routine of physical activity"}], "correct": "b", "rationale": "Implementation of a treatment plan for weight loss is unlikely to succeed if the family and the child are not ready to change. Initiation of a plan without the commitment or interest of the child and family can result in frustration that may discourage future attempts at weight loss. The nurse can determine the family’s readiness to change by identifying the importance with which they view the changes, their motivation for change, their willingness to change behaviors and diet, and their confidence in their ability to make these changes.", "whyNot": {"a": "After determining the family’s readiness for change, the family’s dietary habits and preferences must be considered. These habits and", "c": "The family’s financial resources will influence their food choices. Knowledge of the family resources will allow the nurse to provide", "d": "Although physical activity pattern is an important consideration when determining caloric intake in a weight loss plan, it is not the priority"}, "keyConcept": "A desire for change is the most important predictor of success of a weight loss plan. When implementing a weight loss plan for children, the family and the child must both be ready for change."}, {"id": 11022, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Sx Recor Mi Inbox M Inbox [J Untitlc Untitl € Goog! @ TEAS Online @ Mark! @ Micro: (lererrrpaie Nae rer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Low"}, {"id": "b", "t": "Normal O cHigh"}, {"id": "d", "t": "Critical"}], "correct": "b", "rationale": "all Ablood pressure of 92/60 mmHg is considered within the normal range for a 2-year-old child. OB TCS", "whyNot": {"a": "This blood pressure reading is not too low for a child of this age. D |", "d": "This is not a result that would be considered a crisis; blood pressure of 92/60 mmHg is normal for a child of this age."}, "keyConcept": "When assessing a child's blood pressure, it should be normal for age. In the assessment of circulation, the nurse should evaluate central and peripheral pulses, which should be strong and equal; capillary refill, which is normally < 2 seconds; skin color and temperature should be pink, warm, and dry; and urine output, which can be an indicator of poor perfusion. A change in the child's level of consciousness may indicate poor perfusion to the brain."}, {"id": 11023, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "following? O A. Increased peristaltic action during pregnancy O B. Displacement of the stomach by the diaphragm O C. Decreased secretion of hydrochloric acid O D. Backflow of stomach contents into the esophagus", "choices": [{"id": "a", "t": "Increased peristaltic action during pregnancy"}, {"id": "b", "t": "Displacement of the stomach by the diaphragm"}, {"id": "c", "t": "Decreased secretion of hydrochloric acid"}, {"id": "d", "t": "Backflow of stomach contents into the esophagus"}], "correct": "d", "rationale": "Heartburn is caused when stomach contents enter the distal end of the esophagus, producing a burning sensation. The client should avoid spicy food, eat smaller portions and more frequent meals.", "whyNot": {"a": "Increased peristaltic action does not necessarily occur during pregnancy and is not the cause of heartburn in this case.", "b": "The increasing size of the baby may push some stomach acid upward, but it does not displace the stomach by the diaphragm.", "c": "Decreased secretion of hydrochloric acid would not contribute to increased symptoms of heartburn."}, "keyConcept": "Heartburn is a common gastrointestinal symptom that may occur in any trimester of pregnancy as a result of the effects of pregnancy hormones on the lower esophageal sphincter and gastric clearance, as well as the mechanical effect of the enlarging uterus pushing against the abdominal contents. Interventions used to relieve symptoms include diet and lifestyle modifications, antacids, antihistamines, and proton pump inhibitors.."}, {"id": 11024, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "most appropriate response from the nurse?", "choices": [{"id": "a", "t": "“Try to feed your baby again in 2 more hours; this will eventually go away.”"}, {"id": "b", "t": "“Before you try to feed your baby again, take a warm shower.”"}, {"id": "c", "t": "“Use a breast pump for two or three minutes on a high setting in between feedings.”"}, {"id": "d", "t": "“Place these lettuce leaves inside your bra to help reduce the swelling.”"}], "correct": "b", "rationale": "2 to 3 days after giving birth when the breasts swell and become painful, limiting the ability to OB TY cen produce enough milk for the baby. A mother who is engorged but who wants to breastfeed may consider taking a short shower just prior to feeding her baby. The warm water encourages let-down of milk and may make feeding easier. © Hl AG >i! 24%", "whyNot": {"a": "Waiting two hours and then trying to feed the baby will not help the engorgement. The nurse should assist the mother to take measures to", "c": "The mother may resolve some of the engorgement by using a breast pump briefly on a low setting to encourage milk let-down. Using a", "d": "Lettuce leaves have not been shown to resolve breast engorgement and should not be used."}, "keyConcept": "Breast engorgement results from expansion and pressure exerted by the synthesis and storage of breast milk on the mammary glands. Engorgement affects the infant's ability to latch-on. It results in changes in the shape and curvature of the nipple, making the breast inflexible, flat, hard, and swollen. The nipples on an engorged breast are flat. Engorgement commonly occurs when the breasts switch from colostrum to mature milk, although it may occur later as a result of inadequate removal of breast milk. Clinical manifestations include swelling and edema;a shiny and diffusely red appearance; and pain. Both breasts are usually affected."}, {"id": 11025, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for an 8-year-old female who is on strict bed rest. Which of the following activities should the nurse suggest to facilitate the child’s growth and development during this period?", "choices": [{"id": "a", "t": "Watching age-appropriate television favorites"}, {"id": "b", "t": "Completing missed schoolwork provided by teachers"}, {"id": "c", "t": "Playing with dolls"}, {"id": "d", "t": "Receiving visits from friends"}], "correct": "b", "rationale": "A | % Moderate The primary conflict identified in school-age children in Erickson’s stages of psychosocial development is the conflict of industry vs. Cc | 14% inferiority. Attaining a sense of competence is the primary developmental goal in this age group. The nurse should encourage the parents to D || 24% provide regular work from school, which will allow the child to cope with the stress of hospitalization while learning new skills and keeping up with school work. Achieving competence or sense of industry will help prevent a sense of inferiority.", "whyNot": {"a": "This activity is appropriate for a hospitalized individual but will not specifically meet growth and development needs for the child’s age.", "c": "Preschool children benefit from playing with dolls and puppets because they are at a developmental stage when imagination, imitation,", "d": "Visits with friends are enjoyable for all children, but peer group relationships are more important for growth and development in"}, "keyConcept": "The primary developmental goal for school-age children is attaining a sense of competence. The primary conflict for this age group is \"industry vs. inferiority.\" A school-age child should be encouraged to keep up with regular schoolwork while hospitalized, to facilitate growth and development and reduce stress"}, {"id": 11026, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Screening members of the community for substance abuse disorders"}, {"id": "b", "t": "Increasing public awareness among high-school students through education programs"}, {"id": "c", "t": "Referring individuals with substance use disorders to groups such as Alcoholics Anonymous"}, {"id": "d", "t": "Providing emotional support to individuals recovering from substance abuse disorders"}], "correct": "b", "rationale": "all 8% Easy Substance use disorders are a significant public health problem in the United States. Primary prevention measures are measures to prevent OB TCS ears the occurrence of a disorder or condition in an individual or community. Primary prevention measures include campaigns and education to increase public awareness about the hazards associated with substance use, including the risk of developing dependence; assisting c | 5% individuals to develop life skills; and forming awareness groups and community action groups. D | ™%", "whyNot": {"a": "Screening individuals for substance use disorders will identify individuals who have already developed a disorder. This is a secondary", "c": "Referral of individuals to mutual help groups like AA or Narcotics Anonymous is a strategy to limit the consequences of the disease,", "d": "This is a tertiary prevention strategy, designed to limit complications and to improve outcomes when disease (substance abuse) is already"}, "keyConcept": "Primary prevention measures target prevention before a disease or injury occurs, by reducing exposures to hazards that increase risk; altering unhealthy or unsafe behaviors that increase likelihood of disease or injury; and increasing resistance to disease or injury in event of an exposure. On a community level, raising public awareness of behaviors and other factors that increase risk and assisting \"at-risk\" groups to develop appropriate skills to reduce their risk are examples of primary prevention measures."}, {"id": 11027, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "hormones from the anterior pituitary gland?", "choices": [{"id": "a", "t": "Prolactin"}, {"id": "b", "t": "Oxytocin"}, {"id": "c", "t": "Estrogen"}, {"id": "d", "t": "Progesterone"}], "correct": "a", "rationale": "a © o 2 ° s a = a < The two hormones that control milk production are prolactin and oxytocin. Prolactin is secreted by the anterior pituitary gland. When the baby sucks at the breasts, the pituitary gland is signaled to release prolactin into the bloodstream. The prolactin then stimulates the milk glands to secrete milk. The more a baby sucks, the more milk the breasts produce. To increase the milk supply, the mother should have the baby suck longer and more frequently. Gland tissue Supporting tissuo es ~ ~~ Duct Muscle colls— oxytocin makes them >| contract prolactin makes", "whyNot": {"b": "Oxytocin is released from the posterior pituitary. It causes uterine contractions and the let-down reflex. D |", "c": "Estrogen is not a pituitary hormone.", "d": "Progesterone is not a pituitary hormone."}, "keyConcept": "a © o 2 ° s a = a < The two hormones that control milk production are prolactin and oxytocin. Prolactin is secreted by the anterior pituitary gland. When the baby sucks at the breasts, the pituitary gland is signaled to release prolactin into the bloodstream. The prolactin then stimulates the milk glands to secrete milk. The more a baby sucks, the more milk the breasts produce. To increase the milk supply, the mother should have the baby suck longer and more frequently. Gland tissue Supporting tissuo es ~ ~~ Duct Muscle colls— oxytocin makes them >| contract prolactin makes"}, {"id": 11028, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who has an episiotomy after vaginal delivery of a term infant. Which information should the nurse give the postpartum client regarding proper perineal care?", "choices": [{"id": "a", "t": "Avoid using topical antiseptic creams or sprays"}, {"id": "b", "t": "Clean the perineum from back to front after voiding"}, {"id": "c", "t": "Wipe the perineum dry; do not blot"}, {"id": "d", "t": "Use a squeeze bottle with warm water to keep the site clean"}], "correct": "d", "rationale": "all 9% Easy Asqueeze bottle filled with warm water or antiseptic solution can be used in the perineal area to keep the area clean and to rinse away B | a0 bacteria. The client may also use this bottle to manage and control perineal pain.", "whyNot": {"a": "Following delivery, a client may need to use topical antiseptic sprays or creams as ordered to help with pain control and to reduce swelling", "b": "The client should clean the perineum from front to back after voiding or defecating, which reduces the spread of microorganisms from the", "c": "The client should blot the area dry; wiping may damage or irritate the tissues of the perineum."}, "keyConcept": "The perineum refers to the area between the urethra and the anus. In women, the perineum includes the vaginal opening. This area undergoes a lot of stress and change during pregnancy and delivery, which may include skin tears or surgical episiotomy. The nurse should provide instructions for good perineal care to improve client comfort and reduce the risk of infection or impaired healing."}, {"id": 11029, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Two toddlers are arguing over a toy in the playroom. Which of the following is the most appropriate response by the nurse?", "choices": [{"id": "a", "t": "If you can’t play together nicely, I’ll have to put you back in your rooms"}, {"id": "b", "t": "Give the toy to me. Now neither of you will have it"}, {"id": "c", "t": "Let me see if can get a good toy for each of you"}, {"id": "d", "t": "One of you should play with it for a while, and then give it to the other"}], "correct": "c", "rationale": "Atoddler has not developed the concept of sharing, so two similar toys should be provided to prevent disagreements. Playing together in harmony is not a developmental achievement expected of toddlers.", "whyNot": {"a": "Toddlers at a young age are not developmentally ready to share with others. Threatening to put them back in their rooms will only punish", "b": "Taking the toy away will not teach them anything; it will only punish them for something they do not yet understand.", "d": "These two toddlers are not yet developmentally ready for sharing. It is unrealistic to expect one of them to play with the toy for a while"}, "keyConcept": "Play in the hospital reminds the child of the familiar, friendly environment of home and helps to create continuity of everyday life for the hospitalized child. At different stages of development, children exhibit different tendencies when playing. Toddlers engage in parallel play alongside other children without much interaction with each other. Two toddlers may be engaged in similar or completely different activities but enjoy being around others their own age. It may appear that the toddler doesn’t care about the presence of the other children, but will exhibit dismay when separated from the group. At this stage, there is minimal cooperation or sharing."}, {"id": 11030, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a neonate. What attributes would most likely be seen during the first period of reactivity of a newborn infant?", "choices": [{"id": "a", "t": "Quiet, restful, and sleeping"}, {"id": "b", "t": "Alert and exploring"}, {"id": "c", "t": "Gagging and choking"}, {"id": "d", "t": "Sweating and shaking"}], "correct": "b", "rationale": "The first period of reactivity in a neonate occurs in the first 30 minutes after birth, during which the neonate is usually alert and attentive and typically nurses with strong suck. The neonate may be tachycardic and tachypneic, and can demonstrate irregular respirations with possible flaring, retractions and grunting. The second period of neonatal reactivity occurs 4 to 8 hours after birth and can last from 10 minutes to several hours. The neonate will have unstable vital signs & color changes and may expel meconium. The neonate will nurse and is alert in most cases, and will experience brief periods of tachypnea and tachycardia, often with increased mucus production", "whyNot": {"a": "This most likely describes the period of relative inactivity, which follows the first period of reactivity.", "c": "Gagging and choking on mucus may occur during the second period of reactivity, which often occurs 4 to 8 hours after birth.", "d": "Sweating and shaking typically do not develop in a newborn infant."}, "keyConcept": "The first period of reactivity in a neonate occurs in the first 30 minutes after birth, during which the neonate is usually alert and attentive and typically nurses with strong suck. The neonate may be tachycardic and tachypneic, and can demonstrate irregular respirations with possible flaring, retractions and grunting. The second period of neonatal reactivity occurs 4 to 8 hours after birth and can last from 10 minutes to several hours. The neonate will have unstable vital signs & color changes and may expel meconium. The neonate will nurse and is alert in most cases, and will experience brief periods of tachypnea and tachycardia, often with increased mucus production"}, {"id": 11031, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a client with complaint of hand and wrist pain. Which best describes using Tinel’s sign as part of the health assessment?", "choices": [{"id": "a", "t": "The nurse taps the median nerve with a reflex hammer to check for pain"}, {"id": "b", "t": "The client presses the backs of his hands together and holds for 60 seconds"}, {"id": "c", "t": "The client grasps the nurse’s hands and alternately squeezes each hand"}, {"id": "d", "t": "The nurse occludes the radial artery and then the ulnar artery to check for capillary refill"}], "correct": "a", "rationale": "Tinel’s sign is a test for carpal tunnel syndrome in which the nurse uses a reflex hammer to tap the median nerve in the wrist. If the client B | ma fo complains of pain with this test, further assessment and testing of carpal tunnel syndrome is warranted. ci 13%", "whyNot": {"b": "This describes Phalen’s maneuver, which also tests for carpal tunnel syndrome.", "c": "This test checks for bilateral strength and grip in the client’s hands.", "d": "This is the Allen test and checks for signs of occlusion in the major arteries of the wrist."}, "keyConcept": "Carpal tunnel syndrome is a progressive condition caused by compression of the median nerve in the wrist. Symptoms usually start"}, {"id": 11032, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "immediately? O A. Constipation O B. Suicidal thoughts O C. Photophobia O D. Dry mouth", "choices": [{"id": "a", "t": "Constipation"}, {"id": "b", "t": "Suicidal thoughts"}, {"id": "c", "t": "Photophobia"}, {"id": "d", "t": "Dry mouth"}], "correct": "b", "rationale": "The greatest risk to this client is injury from a suicide attempt; therefore, this is the priority to report to the provider immediately. Desipramine can cause suicidal thoughts and behaviors, which puts the client at risk. The parents should monitor and report any indication of increased depression or thoughts of suicidal behavior.", "whyNot": {"a": "The client is at risk for constipation because of the anticholinergic effects of desipramine. The client should increase fluid intake to reduce", "c": "The client is at risk for photophobia because of the anticholinergic effects of desipramine. The client should wear sun glasses and", "d": "The client is at risk for dry mouth because of the anticholinergic effects of desipramine. The client should increase fluids and suck on hard"}, "keyConcept": "Desipramine, a tricyclic antidepressant, is used to treat depression. There is an increased risk for suicide attempt or suicidal thoughts during early treatment and dose adjustments. The risk is increased in children and adolescents. The nurse should instruct parents to monitor their child for increased thoughts of suicide or dying, a suicide attempt, worsening depression, and anxiety; these manifestations should be reported to the provider immediately."}, {"id": 11033, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "indicates that birth is imminent? O A. Sitting on one buttock O B. Talking and asking a lot of questions O C. Complaining of pain in the lower back O D. Requesting ice chips or water to drink", "choices": [{"id": "a", "t": "Sitting on one buttock"}, {"id": "b", "t": "Talking and asking a lot of questions"}, {"id": "c", "t": "Complaining of pain in the lower back"}, {"id": "d", "t": "Requesting ice chips or water to drink"}], "correct": "a", "rationale": "co. i 44% — Hard If the nurse does not know which stage of labor a client is experiencing, the nurse can perform a rapid assessment to determine how much B | a0 time is left. There are several behaviors that a pregnant client may exhibit that indicate that labor is imminent, including sitting on one buttock, making grunting sounds, bearing down during contractions, or making outright statements like \"the baby is coming now.” © | 208 p | 1%", "whyNot": {"b": "A client who is showing signs that birth is imminent may be less likely to talk and ask a lot of questions. Most women in this stage are", "c": "Pain in the lower back is not necessarily a sign of imminent birth. The client would more likely have pain or pressure in the vagina, which", "d": "A client who is showing signs of imminent birth may be less likely to focus on thirst and may be more focused on the fact that the baby is"}, "keyConcept": "The progression of labor is divided into three phases. When a client arrives at a healthcare facility in labor, the nurse must gather pertinent information about the client's health history, including blood type, allergies, previous illness, pregnancy complications, preferences for labor and delivery, childbirth preparations; and obstetric, medical, and social history. In addition to an assessment of the client's behaviors, the nurse assesses vital signs, physical exam, contraction pattern (frequency, interval, duration, and intensity), fetal well-being (through assessment of fetal heart rate); rupture of membranes, characteristics of amniotic fluid, and contractions. The nurse should perform Leopold’s maneuver to determine the fetal presenting part, point of maximum impulse, fetal descent and engagement."}, {"id": 11034, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which condition would most likely place a client at risk of postpartum hemorrhage?", "choices": [{"id": "a", "t": "Involution of the uterus"}, {"id": "b", "t": "Use of magnesium sulfate during labor"}, {"id": "c", "t": "Uterine cramps and excessive contractions"}, {"id": "d", "t": "Expulsion of the placenta within 20 minutes of infant delivery"}], "correct": "b", "rationale": "Magnesium sulfate is sometimes used during labor and delivery to treat high blood pressure in the mother. Magnesium sulfate may cause OB | AO vasodilation and could contribute to platelet inhibition, which increases the risk of hemorrhage. ° ci 16%", "whyNot": {"a": "Involution of the uterus is a normal process that occurs after delivery and does not increase the risk of hemorrhage.", "c": "Uterine cramping is the body’s attempt to staunch excess blood flow; this would not contribute to hemorrhage after delivery.", "d": "Expulsion of the placenta within 20 minutes after delivery is normal and does not increase the risk of postpartum hemorrhage."}, "keyConcept": "Postpartum hemorrhage (PPH) is the greatest cause of maternal mortality. It is defined as blood loss > 500 mL following vaginal delivery or > 1000 mL following cesarean delivery. The most common cause is uterine atony, which refers to failure of the uterus to contract and retract after delivery. Risk factors for PPH include labor induction and augmentation, chorioamnionitis, magnesium sulfate use, and history of previous PPH."}, {"id": 11035, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a G2P1 client at 26 weeks’ gestation. Which of the following findings should the nurse prioritize to report to the healthcare provider?", "choices": [{"id": "a", "t": "Vaginal secretion pH of 5"}, {"id": "b", "t": "Hemoglobin of 9.2 g/dL"}, {"id": "c", "t": "White blood cell count of 14,000"}, {"id": "d", "t": "1-hour glucose tolerance test of 128 mg/dL"}], "correct": "b", "rationale": ", as a result of a diet low in iron and low iron stores. Most women who are pregnant are advised to take a multivitamin with iron to meet the increased iron needs of fetal development and to maintain adequate es | 48% maternal stores of iron. Additional supplementation may be required if anemia persists despite taking a multivitamin with iron. Hemoglobin c | 35% levels <11 g/dL in the first or third trimester and <10.5 g/dL in the second trimester are considered abnormal, so this is the priority option. D i This client should be evaluated to determine if symptoms of anemia are occurring, including weakness or fatigue. Additional laboratory workup may include measurement of serum ferritin to determine the cause of anemia, and the client may require an iron supplement. 10%", "whyNot": {"a": "An acidic pH is normal during pregnancy. It inhibits the growth of bacteria and reduces the risk of infection.", "c": "Leukocytosis of up to 15,000 cells/mm*3 is normal in pregnancy.", "d": "A 1-hour glucose screen consists of measurement of blood glucose 1 hour after consumption of a 50-gram oral glucose load. It is normal if"}, "keyConcept": "Most women who are pregnant should take a multivitamin with iron to help maintain an adequate maternal iron store and to meet the iron needs of the fetus for development. Iron deficiency anemia occurs commonly during pregnancy, due to both low iron stores and a diet with inadequate iron."}, {"id": 11036, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a Chinese American client who has a family history of hypertension. Which of the following cultural factors can place this client at an increased risk for this condition?", "choices": [{"id": "a", "t": "Use of dairy products"}, {"id": "b", "t": "Consumption of raw fruits"}, {"id": "c", "t": "High sodium content of traditional diet"}, {"id": "d", "t": "Large quantities of shellfish in the traditional diet"}], "correct": "c", "rationale": ", while relatively low in fat and dairy products. . The nurse should advise the client to read labels to identify and limit foods that are high in sodium. Although the traditional Chinese diet is low in fat, fat intake increases in the American ec PF 92% Chinese diet and causes an increased percentage of body fat, leading to an increased risk for developing hypertension.", "whyNot": {"a": "Lactose intolerance is common in the Chinese American population; therefore, many people in this population consume dairy products", "b": "Raw fruit does not increase the risk for the development of hypertension.", "d": "The nurse should encourage the client to consume shellfish because it is a good source of protein and vitamins and does not increase the"}, "keyConcept": "The traditional Chinese American diet is generally high in complex carbohydrates and sodium, while relatively low in fat and dairy products. Calcium is usually obtained through tofu and small fish that are eaten with the bones in. The nurse should advise a client on a low-sodium diet to review food labels; choose processed products that have the lowest amount of sodium per serving; select fresh or frozen poultry without added broth or sodium solutions; choose condiments like ketchup and soy sauce with low sodium content; and rinse canned beans to lower the sodium content up to 40%."}, {"id": 11037, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing teaching for a client who is planning to attempt pregnancy. Which of the following dietary requirements should the nurse stress to prevent neural tube defects?", "choices": [{"id": "a", "t": "Vitamin C"}, {"id": "b", "t": "Calcium"}, {"id": "c", "t": "Folate"}, {"id": "d", "t": "Iron"}], "correct": "c", "rationale": "| 2% The risk of fetal neural tube defect is increased in women with inadequate intake of folic acid (folate) in the first 8 weeks of gestation. Neural ec fF 92% tube defects include anencephaly and spina bifida. Women attempting conception should be counseled to ensure adequate intake of foods , which include green leafy vegetables and fortified grain products such as cereals, pastas, and bread. Prenatal vitamins include adequate amounts of folic acid. Amounts of 400-800 mcg daily are recommended for women planning to become pregnant.", "whyNot": {"a": "Vitamin C deficiency is not associated with neural tube defects.", "b": "Calcium levels should be adequate to form bones and teeth, but calcium intake is not associated with neural tube defects. Mineralization", "d": "Iron promotes the development of red blood cells, but prenatal intake or deficiency is not associated with neural tube defects."}, "keyConcept": "Folic acid supplementation is recommended for pregnant women and those attempting to conceive, since deficiency is linked to an increased risk of neural tube defects, including spina bifida and anencephaly. Leafy green vegetables and fortified grain products are good dietary sources, but prenatal vitamins contain adequate supplementation."}, {"id": 11038, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 14-month-old toddler who has a low white blood cell count. Which of the following immunizations should be avoided for this child?", "choices": [{"id": "a", "t": "Inactivated polio"}, {"id": "b", "t": "Measles, mumps, and rubella"}, {"id": "c", "t": "Diphtheria, tetanus, and pertussis"}, {"id": "d", "t": "Haemophilus influenzae B"}], "correct": "b", "rationale": "| o: It is important for a nurse to understand the contraindications and precautions associated with different vaccines on the immunization Cc | schedule. The MMR is a live attenuated virus vaccine. Live, attenuated vaccines contain a weakened version of the living pathogenic D Hi organism. Immunization through the introduction of live attenuated viruses such as measles, mumps, and rubella (MMR) is not recommended for immunocompromised individuals or pregnant women. The nurse should tell the mother to reschedule the immunization when the child has a normal white blood cell count.", "whyNot": {"a": "This is not a live attenuated vaccine.", "c": "This is not a live vaccine.", "d": "This is an inactivated vaccine."}, "keyConcept": "White blood cells play an important role in the body's response to infection. Individuals with a low white blood cell count are at higher risk for infection, so live attenuated vaccines should be withheld until the white blood cell count returns to normal. Live “attenuated” vaccines have been changed so they are not able to cause disease."}, {"id": 11039, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Aschool nurse is caring for a 7-year-old child who has recently experienced the death of his mother. The child is most likely to have which of the following reactions to death?", "choices": [{"id": "a", "t": "The child thinks about how the death personally affects himself/herself."}, {"id": "b", "t": "The child understands that death is permanent but has difficulty perceiving his/her own death."}, {"id": "c", "t": "The child believes that death can be reversed."}, {"id": "d", "t": "The child understands his/her own death is inevitable."}], "correct": "b", "rationale": ", depending on their level of cognitive and emotional development and developmental age, as well OB a ce as the reaction of the parent or primary caregiver to the death, the parent's attitude about death, and his or her interaction with the child, Children between the ages of 6 and 9 years generally understand that death is final and irreversible but have difficulty imagining their own c || 34% death. They may become preoccupied with the medical aspects or physical aspects of death.", "whyNot": {"a": "Children understand that death eventually affects everyone and begin to think about how the death will affect them personally. However,", "c": "Children up to the age of 5 years are likely to believe that death is reversible. Their thoughts and beliefs may be based on fantasy or", "d": "Adolescents have an adult view of death and understand the inevitability of their own death, although it is difficult to appreciate."}, "keyConcept": "Achild's reaction to death depends upon their level of cognitive and emotional development and the reaction of their parent or primary caregiver. Parental attitudes and the parent's interaction with the child will influence the child's reaction to the death of a close family member or the other parent."}, {"id": 11040, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following is an example of symbolic play? O A.A2-month-old child stares at her fingers and moves them in front of her face O B. An 18-month-old plays peek-a-boo with his father O C. A3-year-old pretends a rug is a magic carpet O D. A 5-year-old races his sister in the backyard to see who wins", "choices": [{"id": "a", "t": "A2-month-old child has not developed enough to engage in symbolic play. A child who is staring at her fingers and moving them in front"}, {"id": "b", "t": "A child who plays peek-a-boo is engaging in interactive play with his father. This is not an example of symbolic play."}, {"id": "c", "t": "Symbolic play involves substituting one object to pretend it is another."}, {"id": "d", "t": "Symbolic play involves substituting one object to pretend that it is another. Racing in the backyard is not an example of symbolic play."}], "correct": "c", "rationale": "Symbolic play involves substituting one object to pretend it is another. This type of play starts to develop in children around the age of 18 months. An example is pretending that a rug in a room is a magic carpet.", "whyNot": {"a": "A2-month-old child has not developed enough to engage in symbolic play. A child who is staring at her fingers and moving them in front", "b": "A child who plays peek-a-boo is engaging in interactive play with his father. This is not an example of symbolic play.", "d": "Symbolic play involves substituting one object to pretend that it is another. Racing in the backyard is not an example of symbolic play."}, "keyConcept": "Children begin to use one object to represent another object and engage in one or two simple actions of symbolic or pretend to play around the age of 18 months. Examples include imitating a few steps of adult behavior during play, such as pretending to feed a baby doll with the toy spoon and bowl.; laughing when a parent places a bowl on the head and pretends it is a hat; pretending to drink from an empty cup by making slurping noises and saying “ah” when finished."}, {"id": 11041, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following is the most appropriate recommendation by the nurse who is caring for a client at 23 weeks’ gestation with a complaint of significant heartburn?", "choices": [{"id": "a", "t": "Take an antacid with sodium bicarbonate"}, {"id": "b", "t": "Lie on the side after a meal"}, {"id": "c", "t": "Avoid dairy items in the diet"}, {"id": "d", "t": "Eat 6 small meals daily eck Answer"}], "correct": "d", "rationale": "During pregnancy, the stomach is displaced upward and compressed by the growing uterus. An increase in the hormone progesterone Cc I during pregnancy results in a slowing of the Gl tract motility, delayed emptying time of the stomach, and relaxation of the esophageal D | sphincter, which can cause heartburn (pyrosis). The nurse should advise the client to eat frequent small meals in place of 3 larger meals each day. Other interventions to reduce heartburn include reduction of fluid intake with meals and elimination of dietary triggers like fatty or fried foods, carbonated drinks, spicy food, and caffeine or chocolate. The nurse should advise the client to stay in an upright position after meals to reduce reflux from the stomach into the esophagus. Clients should also be advised to elevate the head of the bed 4-6 inches.", "whyNot": {"a": "Alka-Seltzer is a common sodium bicarbonate antacid rated class C in pregnancy. The client should be encouraged to use other", "b": "The upright position is recommended for 2-3 hours after meals to aid digestion and reduce heartburn.", "c": "Dairy items are an important part of the diet during pregnancy."}, "keyConcept": "Several factors increase the risk of heartburn in women who are pregnant. They include displacement of the stomach upward by the growing uterus and slowing of the GI tract due to increased progesterone levels, which also cause relaxation of the lower esophageal sphincter and delayed emptying of the stomach."}, {"id": 11042, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing discharge teaching about diet and fluid restrictions to a client who has a calcium oxalate kidney stone. Which instruction should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Increase intake of spinach."}, {"id": "b", "t": "Limit sodium to no more than 2,300 mg/day."}, {"id": "c", "t": "Increase intake of vitamin C supplements."}, {"id": "d", "t": "Limit consumption of high-purine foods."}], "correct": "b", "rationale": "Stones that consist of calcium oxalate require a limitation of the client's dietary calcium intake to no more than 1,000 to 1,200 mg of calcium a day. Clients should avoid calcium supplements. N x G GERO x» *o!1@0 + Finish update po] e o 2 ° s a = a <", "whyNot": {"a": "Spinach is a food that is high in oxalate and, when combined with calcium, might result in calcium stone formation.", "c": "Large doses of vitamin C can cause calcium stone formation.", "d": "Foods that contain purine, such as organ meats and red wine, cause uric acid stone formation."}, "keyConcept": "Stones that consist of calcium oxalate require a limitation of the client's dietary calcium intake to no more than 1,000 to 1,200 mg of calcium a day. Clients should avoid calcium supplements. N x G GERO x» *o!1@0 + Finish update po] e o 2 ° s a = a <"}, {"id": 11043, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing information about colon cancer prevention to a group of adults. Which of the following statements should the nurse include? O A.\"Colonoscopies for individuals with no family history of cancer should begin at age 40.\" O B. \"A sigmoidoscopy is recommended every 5 years beginning at age 60.\" O C. \"Fecal occult blood tests should be performed annually beginning at age 45.\" O D. \"An annual digital rectal exam is recommended beginning at age 60.\"", "choices": [{"id": "a", "t": "Acolonoscopy is recommended every 10 years beginning at age 45 for a client who has no family history of cancer. D i 8%"}, {"id": "b", "t": "A sigmoidoscopy is recommended every 5 years beginning at age 45."}, {"id": "c", "t": "Clients who are age 45 to 75 should have fecal occult blood tests performed annually."}, {"id": "d", "t": "An annual digital rectal exam is no longer recomended"}], "correct": "c", "rationale": "Clients who are age 45 to 75 should have fecal occult blood tests performed annually. 5 15%", "whyNot": {"a": "Acolonoscopy is recommended every 10 years beginning at age 45 for a client who has no family history of cancer. D i 8%", "b": "A sigmoidoscopy is recommended every 5 years beginning at age 45.", "d": "An annual digital rectal exam is no longer recomended"}, "keyConcept": "Early identification and diagnosis of cancer can reduce the incidence of death from cancer or cancer complications. The nurse should inform clients of the following colon cancer screening recommendations:"}, {"id": 11044, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in a pediatric clinic is performing an assessment of an 8 year old client. What is an example of psychosocial history that would be collected during the health assessment of a child?", "choices": [{"id": "a", "t": "The number of hours a child sleeps at night"}, {"id": "b", "t": "Adaptive equipment the child needs for activities O C.A family history of diabetes"}, {"id": "d", "t": "A description of the home environment"}], "correct": "d", "rationale": "A Hi 17% Moderate The psychosocial portion of the client’s history refers to factors that affect the child’s home life, including a description of the home a a aE environment, as well as socioeconomic status, and any other factors that relate to the child’s psychological development as related to the social environment. c I 4%", "whyNot": {"a": "This would be an example of a physical or behavioral portion of the health history, not the psychosocial history.", "b": "This is an example of part of the physical assessment during the health history, not the psychosocial portion of the history."}, "keyConcept": "Psychosocial assessment includes an evaluation of an individual’s mental health and social well-being. It assesses the client's environment, perception of self and the client's ability to function in the community."}, {"id": 11045, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following statements indicates a need for further education for a client who is being discharged after receiving initial treatment for tuberculosis?", "choices": [{"id": "a", "t": "\"Iwill carefully cover my nose and mouth when sneezing or coughing.\""}, {"id": "b", "t": "\"I will supplement my diet with additional foods rich in vitamin C, protein, and iron.\""}, {"id": "c", "t": "\"My family members don't need testing.\" O D.\"I will take my isoniazid for at least 6 months until complete the entire course.\""}], "correct": "c", "rationale": ". TB is an ec FY 77% airborne infection and is easily transmitted in aerosol form.", "whyNot": {"a": "This statement is correct. Because TB is spread by airborne transmission, it is important to instruct clients with TB to take precautions", "b": "This statement is correct. Individuals with tuberculosis often have deficiencies in proteins and iron and should include these elements in"}, "keyConcept": "When caring for a client who is diagnosed with TB, the goals of treatment are compliance with therapy; avoidance of recurrent disease; achieving normal pulmonary function; and avoidance of disease transmission to others. Screening programs for TB in the United States are targeted at identification of individuals in known risk groups with TB. After a positive tuberculin skin test, a chest X-ray should be obtained to identify active pulmonary TB. Individuals strongly suspected of active TB should receive a four-drug therapy and be placed on respiratory isolation. A medical workup should include chest X-ray, sputum smear and culture."}, {"id": 11046, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Empowering the client and facilitating their control over their health status"}, {"id": "b", "t": "The provision of education relating to lifestyle choices"}, {"id": "c", "t": "Maximizing the client’s ability to make knowledgeable choices"}, {"id": "d", "t": "Establishment of an immunization schedule for a newborn"}], "correct": "a", "rationale": "@A i 65% Moderate The most accurate definition of health promotion is empowering the client to take control over their health and health care status. Health B Hl a promotion activities include teaching about lifestyle choices and immunization schedules, among other things, and all of this education aims to facilitate the client’s ability to make knowledgeable decisions; these activities are only some aspects of comprehensive health c |_| 15% promotion.", "whyNot": {"b": "The provision of education regarding lifestyle choices is one component of health promotion but it does not accurately define the entire", "c": "Maximizing the client’s ability to make knowledgeable choices is part of health promotion. However, it does not define the entire concept", "d": "Establishing an immunization schedule for a newborn is one activity that is completed as part of health promotion, but it does not define"}, "keyConcept": "The World Health Organization (WHO) defines health as \"a state of complete physical, mental and social well-being and not merely the absence of disease or infirmity.\" Health promotion is defined by the WHO as\"the process of enabling people to increase their control over, and improve their health.\" The nurse can promote health through a variety of activities, including Identification of risk factors for disease/illness; assessment and provision of education for clients about health risks based on family, population, and/or community characteristics; assessment of the client's readiness to learn, learning preferences and barriers to learning; planning and participation in community health education; providing clients with education about actions to promote and maintain health and prevent disease; and informing the client about immunization schedules and needs."}, {"id": 11047, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing instruction to a client about common discomforts during pregnancy. Which of the following statements from the client indicates that further teaching is necessary?", "choices": [{"id": "a", "t": "“I should rest more often with my feet up, especially if develop varicose veins in my legs.”"}, {"id": "b", "t": "“It helps to lie down on my side when start to feel dizzy and lightheaded.”"}, {"id": "c", "t": "“I need to stop drinking so much fluid before go to bed at night.”"}, {"id": "d", "t": "“I should call my doctor if develop a nosebleed or my gums start to bleed.”"}], "correct": "d", "rationale": "Al 15% Hard Increased estrogen levels during pregnancy can lead to an increased risk of capillary bleeding and connective tissue changes. The pregnant B | a client may develop more frequent nosebleeds, gingivitis that leads to bleeding gums, and nasal congestion. These are not uncommon discomforts of pregnancy and do not warrant a call to the health care provider unless the bleeding is severe or cannot be stopped. c | 32% oo i” 38%", "whyNot": {"a": "The client should be taught to rest and put her feet up, particularly if she starts to develop varicose veins.", "b": "The client should be taught to lie down on her side if she starts to feel dizzy and lightheaded.", "c": "The client should be taught to limit fluid intake at night if it is disrupting her sleep habits."}, "keyConcept": "Pregnant women experience anatomic and physiologic changes in almost every organ system that begin after conception and progress through delivery. After delivery, the body reverts to the non-pregnant state within weeks. The nurse should advise the client of the effects of these hormonal changes during gestation. In addition to hormones produced by the uterus, the pituitary, adrenal, and thyroid glands are among the endocrine glands affected. Estrogen levels are highest in the second trimester of pregnancy."}, {"id": 11048, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is administering immunizations to a four month-old infant. Which of the following actions should the nurse take to provide atraumatic care?", "choices": [{"id": "a", "t": "Administer 81 mg of aspirin to the infant."}, {"id": "b", "t": "Use the deltoid muscle for injecting the vaccine."}, {"id": "c", "t": "Ask the infant's parents to leave the room during the procedure."}, {"id": "d", "t": "Provide sucrose solution on the infant's pacifier."}], "correct": "d", "rationale": "al 3% Easy The nurse should allow the infant to suck on a pacifier with sucrose solution for about 2 min prior to the procedure and during the B | Ase procedure. This can decrease the pain and discomfort associated with immunizations and is an appropriate action for the nurse to take in providing atraumatic care. c I 3%", "whyNot": {"a": "Administering aspirin to an infant can increase the risk for developing Reye syndrome. To minimize discomfort, the nurse should apply a fm]", "b": "The nurse should use the deltoid muscle for administration of immunizations to toddlers. The deltoid muscles of infants are not 3", "c": "Separating the parents from the infant can produce anxiety in the infant. The parents can assist with consoling the infant after the <"}, "keyConcept": "The administration of immunizations can be a traumatic and painful procedure for infants and children. To make this a less traumatic experience, the nurse should use the appropriate needles and provide comfort. The recommended needle length for injections for infants is 25 mm (Lin). The nurse should use the vastus lateralis muscle for IM injections for infants. The deltoid muscle is recommended for children older than 1 year of age because the muscle is more developed at that age. To minimize pain at the injection site, the nurse can apply a topical anesthetic cream, such as lidocaine/prilocaine cream, 1 hr prior to administration of the injection. To decrease the behavioral pain response to the injection, such as crying, the nurse can apply 2% sucrose solution to the infant's pacifier and allow the infant to suck on it 2 min prior to and during the procedure."}, {"id": 11049, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is reviewing the concept of ageism with a newly licensed nurse. Which of the following information should the nurse include?", "choices": [{"id": "a", "t": "Ageism refers to the high level of respect that some cultures give to their elders."}, {"id": "b", "t": "Ageism refers to the stereotype that older adults are not able to understand new information."}, {"id": "c", "t": "Ageism refers to assumptions about older adults based on gender and economic status."}, {"id": "d", "t": "Ageism refers to physiological changes experienced by older adults."}], "correct": "b", "rationale": "A l 3% Moderate Ageism is a stereotype of older adults based solely on age. The belief that older adults are unable to learn and understand new information is OB TY Gen a myth of aging. Other common myths of aging include the idea that all older adults are nonproductive, unable to be flexible in their ideas, and have dementia. In reality, dementia affects clients who have a neurological disorder regardless of age. Older adults are often active in c i 8% their community and are just as likely to embrace new ideas and concepts as any other age group. D Hl 20%", "whyNot": {"a": "Ageism results in a decrease in respect for older adults.", "c": "Ageism is a stereotype of older adults based solely on age rather than gender or economic status.", "d": "Ageism is a stereotype of older adults based solely on age. Physiological changes, such as diminished vision or decreased skin elasticity,"}, "keyConcept": "Nurses should use their understanding of expected physical and psychosocial development to help break through the bias and stereotypes of ageism. The use of evidence-based practice and knowledge of developmental tasks can help the nurse refute myths and stereotypes. Dispelling these myths is part of culturally competent care. The nurse should treat older adults as individuals and use their knowledge of physiological changes of aging to assist with assessment and to provide evidence-based care."}, {"id": 11050, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Aneighbor who is a nurse is called on to assist with an emergency home birth. What should the nurse do to help expel the placenta?", "choices": [{"id": "a", "t": "Put pressure on the fundus"}, {"id": "b", "t": "Ask the mother to bear down"}, {"id": "c", "t": "Have the mother breast feed the newborn"}, {"id": "d", "t": "Place gentle pressure on the cord"}], "correct": "c", "rationale": "mw | 27% ~~ Hard Suckling will induce neural stimulation of the posterior pituitary gland, which in turn will release oxytocin and cause uterine contractions. B | Re: The other options could cause uterine prolapse. °", "whyNot": {"a": "Forcibly pressing on the fundus is not a method to help expel the placenta; this action could cause uterine prolapse.", "b": "The mother may feel the urge to push or bear down if she feels contractions during delivery of the placenta. Asking the mother to bear", "d": "Placing pressure on the cord will not stimulate the uterus to contract and expel the placenta. Pressure on the cord should be done very"}, "keyConcept": "Manual cord traction confers no benefit to the mother and increases the risk of postpartum hemorrhage, which is the leading complication of childbirth. If the delivery of the placenta is delayed. nursing the baby will help stimulate contractions to expel the placenta because nursing causes the release of natural oxytocin into the body. Coughing, sneezing, and laughing can be also be used."}, {"id": 11051, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Having a sibling with diabetes increases one's risk of developing the disease"}, {"id": "b", "t": "Being Caucasian increases one's risk of developing diabetes"}, {"id": "c", "t": "Being over the age of 45 increases the risk of developing the disease"}, {"id": "d", "t": "Having high blood pressure increases the risk of developing the disease"}], "correct": "b", "rationale": "A || 12% Moderate The following groups are at higher risk of developing diabetes: African Americans, Alaska Natives, American Indians, Asian Americans OB a GY Hispanics/Latinos, or Pacific Islander Americans. ° cli 8%", "whyNot": {"a": "If a client has a sibling with diabetes, he or she is more likely to develop the disease.", "c": "A client over the age of 45 years is at higher risk of developing diabetes because of age.", "d": "High blood pressure puts a client at higher risk of developing other illnesses, such as diabetes."}, "keyConcept": "Risk factors for the development of type 2 diabetes include overweight or obesity; age 45 or older; family history of diabetes; African American, Alaska Native, American Indian, Asian American, Hispanic/Latino, Native Hawaiian, or Pacific Islander heritage; high blood pressure; low level of HDL cholesterol, or a high level of triglycerides; history of gestational diabetes or macrosomia (birth to a baby > 9 lbs); sedentary lifestyle; history of heart disease or stroke; depression; polycystic ovary syndrome; and acanthosis nigricans, characterized by dark, thick, and velvety skin around the neck or armpits."}, {"id": 11052, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A client at 24 weeks gestation arrives with painless, bright red vaginal bleeding. Which of the following conditions does the nurse suspect in this client?", "choices": [{"id": "a", "t": "Abruptio placenta"}, {"id": "b", "t": "Placenta previa"}, {"id": "c", "t": "Premature rupture of membrane"}, {"id": "d", "t": "Rupture of the uterus"}], "correct": "b", "rationale": "In placenta previa sudden painless, bright red vaginal bleeding occurs.", "whyNot": {"a": "In abruptio placenta dark red vaginal bleeding associated with severe pain occurs.", "c": "Premature rupture of membrane occurs beyond 37 weeks gestation and would show clear fluid with or without a mucus plug.", "d": "Rupture of the uterus can occur due to the stress resulting from labor contractions."}, "keyConcept": "Placenta previa is characterized by abnormal implantation of the placenta on the lower part of the uterus. As the cervix begins to dilate, the lower uterine segment separates from the upper segment.The placenta is unable to stretch and accommodate the changing cervix, resulting in painless, bright red vaginal bleeding. Intravenous therapy. This would be prescribed by the physician to replace the blood that was lost during bleeding. When placenta previa is diagnosed or suspected, vaginal examinations should be avoided, as this may initiate hemorrhage that is potentially fatal for both mother and fetus. External monitoring should be used and volume replacement may be necessary."}, {"id": 11053, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a female client who is starting nicotine replacement therapy. Which of the following statements by the client indicates an understanding of the teaching? O A.\"I should avoid eating right before | chew a piece of nicotine gum.\" O B.\"I will need to stop using the nicotine gum after 1 year.\" O C. \"If | become pregnant, | can switch from nicotine gum to the nicotine patch.\" O D.\"I should chew the nicotine gum quickly for about 15 minutes.\"", "choices": [{"id": "a", "t": "The client should avoid eating or drinking 15 min prior to and while chewing the nicotine gum."}, {"id": "b", "t": "The client should not use nicotine gum for longer than 6 months."}, {"id": "c", "t": "The client should avoid nicotine products, including nicotine gum and nicotine patches, while pregnant or breastfeeding."}, {"id": "d", "t": "The client should chew the nicotine gum slowly and intermittently over 30 min."}], "correct": "a", "rationale": "The client should avoid eating or drinking 15 min prior to and while chewing the nicotine gum. ° : — cil", "whyNot": {"b": "The client should not use nicotine gum for longer than 6 months.", "c": "The client should avoid all nicotine products, including nicotine gum and nicotine patches, while pregnant or breastfeeding.", "d": "The client should chew the nicotine gum slowly and intermittently over 30 min."}, "keyConcept": "Nicotine chewing gum is adjunct therapy in the management of nicotine withdrawal for a client who wishes to cease smoking. Female clients should be informed that nicotine has effects on the fetus and is excreted in breast milk. If pregnancy occurs, the client should discontinue the nicotine gum and notify the provider immediately."}, {"id": 11054, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a female client who is starting nicotine replacement therapy. Which of the following statements by the client indicates an understanding of the teaching? O A.\"I should avoid eating right before | chew a piece of nicotine gum.\" O B.\"I will need to stop using the nicotine gum after 1 year.\" O C. \"If | become pregnant, | can switch from nicotine gum to the nicotine patch.\" O D.\"I should chew the nicotine gum quickly for about 15 minutes.\" eck Answer", "choices": [{"id": "a", "t": "The client should avoid eating or drinking 15 min prior to and while chewing the nicotine gum."}, {"id": "b", "t": "The client should not use nicotine gum for longer than 6 months."}, {"id": "c", "t": "The client should avoid nicotine products, including nicotine gum and nicotine patches, while pregnant or breastfeeding."}, {"id": "d", "t": "The client should chew the nicotine gum slowly and intermittently over 30 min."}], "correct": "a", "rationale": "The client should avoid eating or drinking 15 min prior to and while chewing the nicotine gum.", "whyNot": {"b": "The client should not use nicotine gum for longer than 6 months.", "c": "The client should avoid all nicotine products, including nicotine gum and nicotine patches, while pregnant or breastfeeding.", "d": "The client should chew the nicotine gum slowly and intermittently over 30 min."}, "keyConcept": "Nicotine chewing gum is adjunct therapy in the management of nicotine withdrawal for a client who wishes to cease smoking. Female clients should be informed that nicotine has effects on the fetus and is excreted in breast milk. If pregnancy occurs, the client should discontinue the nicotine gum and notify the provider immediately."}, {"id": 11055, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "fundus is firm and contracted and there is a significant amount of bright red lochia. Which of the following is the most likely condition?", "choices": [{"id": "a", "t": "Subinvolution of the uterus"}, {"id": "b", "t": "Perineal laceration"}, {"id": "c", "t": "Retained placental fragments"}, {"id": "d", "t": "Puerperal infection"}], "correct": "b", "rationale": "A il 28% Hard A client who complains of pain or vaginal pressure and has a large amount of bright red lochia with a firm uterus most likely has a perineal OR i sen laceration. A client may develop a perineal laceration during delivery because of such factors as an extensive episiotomy, use of forceps during delivery, or a precipitous delivery. The nurse must assess the client’s perineum to determine if a laceration is present, continue to c || 32% monitor the amount of lochia, and monitor the client’s vital signs for changes that indicate significant blood loss.", "whyNot": {"a": "Subinvolution of the uterus occurs when the uterus does not return to its normal size after childbirth. The signs and symptoms that this", "c": "Retained placental fragments are often signified by a boggy uterus with increased bleeding. The symptoms this client are displaying do", "d": "Puerperal infection may cause foul-smelling drainage. The symptoms this client are displaying do not indicate a puerperal infection."}, "keyConcept": "Perineal lacerations or tears occur when the infant's head is either too large for the vagina to stretch around or the head is a normal size but the vagina doesn't stretch easily. The tears are described as 1st to 4th degree, depending upon the size and depth of the laceration. First- degree tears only involve the perineal skin — the skin between the vaginal opening and the rectum and the tissue directly beneath the skin. They frequently heal on their own. Fourth-degree tears extend through the anal sphincter and into the mucous membrane that lines the rectum. They usually require repair with anesthesia in an operating room."}, {"id": 11056, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Mumps is caused by a virus and may lead to encephalitis."}, {"id": "b", "t": "Pertussis is caused by bacteria and does not lead to encephalitis. D 29%"}, {"id": "c", "t": "Polio is also caused by a virus but does not usually result in encephalitis."}, {"id": "d", "t": "Scarlet fever is caused by bacteria and does not lead to encephalitis."}], "correct": "a", "rationale": "Mumps is caused by a virus and may lead to encephalitis. 8 9%", "whyNot": {"b": "Pertussis is caused by bacteria and does not lead to encephalitis. D || 29%", "c": "Polio is also caused by a virus but does not usually result in encephalitis.", "d": "Scarlet fever is caused by bacteria and does not lead to encephalitis."}, "keyConcept": "Viral infections of the central nervous system result in aseptic meningitis or encephalitis Encephalitis occurs most frequently due to viruses,"}, {"id": 11057, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for an 11-month-old infant who is hospitalized and placed on contact precautions. Which of the following toys should the nurse recommend to meet the developmental needs of the infant? O A.A bucket of plastic blocks O B. Hanging crib toys O C. Modeling clay O D. Crayons and a coloring book", "choices": [{"id": "a", "t": "At the age of 11 months, an infant enjoys opportunities for sequential play."}, {"id": "b", "t": "An 11-month-old infant who is able to stand up can pull the toys that are hanging from the crib, which puts the infant at risk for"}, {"id": "c", "t": "Modeling clay is not an age-appropriate toy for an 11-month-old infant due to the risk for the infant ingesting it."}, {"id": "d", "t": "Crayons and a coloring book are not age-appropriate toys for an 11-month-old client because the infant does not have the fine motor skill"}], "correct": "a", "rationale": "At the age of 11 months, an infant enjoys opportunities for sequential play. Dumping out a bucket filled with plastic blocks will allow the infant to put the blocks back into the bucket. This also allows the infant to further develop fine motor skills.", "whyNot": {"b": "An 11-month-old infant who is able to stand up can pull the toys that are hanging from the crib, which puts the infant at risk for", "c": "Modeling clay is not an age-appropriate toy for an 11-month-old infant due to the risk for the infant ingesting it.", "d": "Crayons and a coloring book are not age-appropriate toys for an 11-month-old client because the infant does not have the fine motor skill"}, "keyConcept": "The nurse should be aware of expected growth and development patterns during the various stages of infancy and childhood. It is important for the nurse to identify which activities are age-appropriate for the 11-month-old infant who is hospitalized. Both fine and gross motor skills should be considered when providing activities for the infant."}, {"id": 11058, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who reports morning sickness at 7 weeks’ gestation. Which of the following is the appropriate nursing response?", "choices": [{"id": "a", "t": "Advise the client to drink 16 ounces of water upon awakening."}, {"id": "b", "t": "Tell the client that nausea and vomiting typically do not last past the first trimester."}, {"id": "c", "t": "Advise the client that hot foods are less likely to cause nausea than cold foods."}, {"id": "d", "t": "Advise the client to consume a snack high in carbohydrates and/or protein when she awakens."}], "correct": "d", "rationale": "(NVP) commonly occur during the first trimester of pregnancy. It is most likely the result of rising levels of B | Toe hormones in pregnancy, including human chorionic gonadotropin, estrogen, and progesterone. Dietary management can often reduce the severity of symptoms. The nurse should advise the client to consume a high-protein or high-carbohydrate snack on awakening and before c | 6% bedtime; to eat several small meals high in protein or carbohydrates and low in fat throughout the day; to avoid fluids with meals but to @D ft 1% consume ginger and flavored lollipops when nauseous. Women should be advised not to skip meals. The client should also consume foods that are high in vitamin B6 and/or iron.", "whyNot": {"a": "The client should be encouraged to avoid excessive fluid intake early in the day or when nauseated, and to compensate by drinking", "b": "While this is accurate, this response does not address the client’s current symptoms.", "c": "Cold or cool foods and beverages are recommended. Hot foods or spicy/fatty foods may worsen NVP."}, "keyConcept": "NVP is common in the first trimester of pregnancy, as a result of rising hormone levels. Dietary measures can be helpful to reduce symptoms, although some women may require antiemetic medication. Ginger and vitamin B6 supplements can be helpful. NVP usually resolves by the 14th week of pregnancy."}, {"id": 11059, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a client for tactile fremitus. The nurse does which of the following while performing this part of the exam?", "choices": [{"id": "a", "t": "Auscultate several areas over each lung"}, {"id": "b", "t": "Ask the client to repeat “ninety-nine” in a normal voice while you feel for vibrations on their back"}, {"id": "c", "t": "Palpate the chest using the fingertip"}, {"id": "d", "t": "Tell the client to repeat the sound “ee” several times"}], "correct": "b", "rationale": "“ninety-nine” several times. Tactile fremitus vibrations may be decreased or even absent if vibrations from the larynx to the chest surface are blocked by things like COPD, obstruction, tumor, pleural effusion, or pneumothorax. c |_| 19% of 5%", "whyNot": {"a": "This describes lung auscultation, which is a standard form of assessment, but is not part of tactile fremitus.", "c": "Tactile fremitus is performed using the flat part of the hand, not the fingertips.", "d": "This describes performing the egophony test, not tactile fremitus."}, "keyConcept": "Tactile fremitus is elicited by a maneuver performed in the exam of the chest. It refers to tremulous vibration of the chest wall during speaking that is palpable on physical examination. When vibrations from the larynx to the chest surface are impeded by chronic obstructive pulmonary disease, obstruction, pleural effusion, or pneumothorax, tactile fremitus may be absent or decreased."}, {"id": 11060, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Every 10 years, to boost immunity"}, {"id": "b", "t": "Every 5 years, to boost immunity"}, {"id": "c", "t": "Because it contains the pertussis vaccine which cannot be given to infants"}, {"id": "d", "t": "To protect against herpes virus"}], "correct": "a", "rationale": "Td is administered every 10 years, or after exposure to tetanus in some circumstances. ce | 10%", "whyNot": {"b": "The Td vaccine is given every 10 years, not every 5 years.", "c": "The Td vaccine does not contain pertussis. It is a vaccine designed as a booster for adults and is not indicated for infants.", "d": "The Td vaccine protects against tetanus and diphtheria; it does not protect against herpes."}, "keyConcept": "Tetanus is an infection caused by Clostridium tetani bacteria. Four kinds of vaccines are used today to protect against tetanus. All are combined vaccines that also protect against other diseases. They include diphtheria and tetanus (DT) vaccines; diphtheria, tetanus, and pertussis (DTaP) vaccines; tetanus and diphtheria (Td) vaccines; and tetanus, diphtheria, and pertussis (Tdap) vaccines. Individuals younger than 7 years old receive DTaP or DT, while older children and adults receive Tdap and Td. Td boosters are recommended every ten years."}, {"id": 11061, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a client who is 6 weeks postpartum. Which of the following findings is normal for this client?", "choices": [{"id": "a", "t": "Pinkish brown vaginal discharge that has a serosanguinous consistency"}, {"id": "b", "t": "Creamy colored discharge with a fleshy odor"}, {"id": "c", "t": "Cervical edema"}, {"id": "d", "t": "Complete restoration of vaginal muscle tone"}], "correct": "b", "rationale": "Lochia alba refers to post-birth discharge that lasts from day 11 up to 8 weeks’ postpartum. It is yellowish or creamy colored with a fleshy I 6% ©", "whyNot": {"a": "This describes lochia serosa, which typically begins on the fourth postpartum day and can last up to 10 days after delivery.", "c": "Cervical edema generally lasts up to 3 days after delivery. The cervix may have bruising or lacerations immediately following delivery but", "d": "Although the vagina regains its normal shape quickly after pregnancy, pre-delivery muscle tone is never completely restored."}, "keyConcept": "The puerperium, or postpartum period, lasts from immediately after birth until about six weeks, at which time the body has returned to a near pre-pregnancy state. The uterus undergoes rapid reduction in size, known as involution. The decidua is cast off as lochia, after which the cervix will close. The vaginal tone improves and size diminishes, with return of rugae. Ovulation/menstruation resume at 6-10 weeks in women who are not breastfeeding."}, {"id": 11062, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which best describes why infants are started on solid foods at about 5 to 6 months of age?", "choices": [{"id": "a", "t": "Solid foods help in controlling an infant’s weight"}, {"id": "b", "t": "Infants at this age are learning how to chew"}, {"id": "c", "t": "The fetal reserve of iron is depleted by this age"}, {"id": "d", "t": "The infant’s swallowing reflex has not developed to accommodate solid foods"}], "correct": "c", "rationale": "Fetal iron reserves are depleted by 5 to 6 months of age and some babies may not have enough iron in their diets without the introduction of solid foods.", "whyNot": {"a": "Solid foods do not necessarily control an infant’s weight. A baby may become overweight or may have inadequate nutrition whether she is", "b": "Most solid foods that are first introduced at 5 to 6 months are very soft and pureed. Chewing these foods is unnecessary.", "d": "Most foods started at the solid stage are very soft or pureed. If the infant has been able to swallow breast milk or formula, he should be"}, "keyConcept": "Because of the health benefits of breast milk, the American Academy of Pediatrics recommends feeding infants nothing but breast milk for the first six months of life. If breast milk is not an option, formula is an acceptable alternative. When introducing solid foods, single- ingredient foods should be introduced first, one food at a time. They should be introduced every few days to determine if the child has an allergic reaction. Infants should consume no more than 28 to 32 ounces of formula per day after the introduction of solid foods. Breastfed children can nurse on demand after the introduction of solid foods."}, {"id": 11063, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "of the following nursing diagnoses does this represent?", "choices": [{"id": "a", "t": "Ineffective self-health maintenance"}, {"id": "b", "t": "Ineffective coping skills"}, {"id": "c", "t": "Disturbance of body image"}, {"id": "d", "t": "Impaired verbal communication"}], "correct": "c", "rationale": "al 2% Easy The client’s response indicates a disturbance in body image, which is reflected by the client’s priority of keeping the amputation “hidden.” B I a This indicates the client’s negative feelings about “hiding” evidence of the amputation, despite the fact that the amputation presents a variety of challenges to the client’s health. The client’s preoccupation with the appearance of the amputation indicates a disturbance in body ec | 93% image that is reflected in negative feelings about the appearance of the amputation.", "whyNot": {"a": "The diagnosis of “ineffective self-help maintenance” is a diagnosis that is supported by evidence of the client’s inability to maintain", "b": "Ineffective coping skills may be related the client’s inability to manage stress due to the new condition. There is no evidence that this", "d": "Ineffective verbal communication is a diagnosis that would be supported by alterations in the ability to communicate. There is no"}, "keyConcept": "Disturbance in body image may result from a permanent alteration in structure and/or function as a result of removal of internal or external body parts or mutilating surgery, presence of drains, dressings, attached medical equipment, a medical condition, or pregnancy. A person with disturbed body image has an actual change in structure or function coupled with alterations in social function, hiding of a body part, refusal to acknowledge a change or care for an altered body part, and/or preoccupation about the changed part or function."}, {"id": 11064, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who is in the third stage of labor. Which best describes the third stage of labor?", "choices": [{"id": "a", "t": "The client is having regular contractions and the cervix is dilated to 10 cm"}, {"id": "b", "t": "The fetus has completely descended into the pelvic cavity"}, {"id": "c", "t": "The client is pushing to deliver the baby; it is also called the “transition stage”"}, {"id": "d", "t": "The baby has been delivered and the mother is now delivering the placenta"}], "correct": "d", "rationale": "The third stage of labor occurs after the baby has been delivered and the mother is delivering the placenta. The mother continues to experience contractions, which are designed to push the placenta out. The third stage typically lasts between 5 and 10 minutes.", "whyNot": {"a": "The third stage of labor describes the delivery of the placenta. The client will already have a fully dilated cervix because she has already", "b": "The third stage of labor occurs after the baby has been born; it describes the delivery of the placenta, not the descent of the baby into the", "c": "The third stage of labor occurs when the mother delivers the placenta. The client will already have delivered the baby by this time."}, "keyConcept": "There are three stages of childbirth. The first stage begins from the onset of true labor and lasts until the cervix is completely dilated to 10 cm. The second stage continues after the cervix is dilated to 10 cm until the delivery of the baby. The third stage is the delivery of the placenta. The third stage is the shortest stage."}, {"id": 11065, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. % CLOSE Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "They have a history of long-term steroid use"}, {"id": "b", "t": "They have a history of hypoparathyroidism"}, {"id": "c", "t": "They have taken excessive amounts of estrogen"}, {"id": "d", "t": "They lift weights at a gym"}], "correct": "a", "rationale": "o; Use of steroids leads to bone demineralization. om", "whyNot": {"b": "Hyperparathyroidism accelerates bone demineralization, not hypoparathyroidism. D |", "c": "Estrogen aids in depositing calcium into the bones.", "d": "Weight-bearing exercise helps prevent bone demineralization."}, "keyConcept": "Osteoporosis is characterized by low bone mass, disruption of bone architecture, and skeletal fragility. Osteoporosis is associated with an increased risk of fracture. Risk factors include advanced age, previous fracture, long-term glucocorticoid therapy, low body weight (less than 58 kg [127 lb]), family history of hip fracture, cigarette smoking, and excess alcohol intake."}, {"id": 11066, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is counseling the mother of a 12-month old child who is weaning the child from breastfeeding. Which of the following statements by the mother indicates a need for further teaching?", "choices": [{"id": "a", "t": "“I will discourage my child from drinking cow's milk because that will result in increased consumption of solids.”"}, {"id": "b", "t": "“I should never put my child to sleep with a bottle for comfort.”"}, {"id": "c", "t": "“I will begin weaning gradually and will still breastfeed at times.”"}, {"id": "d", "t": "“I should substitute some feedings with cow’s milk for breast milk.”"}], "correct": "a", "rationale": "The CDC recommends that cow's milk is not introduced until infants are 12 months old, but it is not known to result in increased B I Ee consumption of solid foods. If too much cow's milk is consumed it may lead to decreased consumption of solid foods. i © 9% Gradual weaning over a period of several weeks to several months helps mothers avoid breast engorgement, which can occur when D Hi 15% breastfeeding is suddenly stopped. When weaning, the mother should watch for cues that indicate the infant is ready to advance. In most infants who are exclusively breastfed, weaning begins around the 6th month of life with the gradual introduction of pureed solid foods. Although solid foods are offered at this age, the mother should continue to offer breast milk and formula, which provides protein, fats, and calcium. A cup with a lid can usually be successfully used by children when they reach the age of a year.", "whyNot": {"b": "This statement indicates correct understanding of infant feeding. Allowing a child to sleep with a bottle can result in dental caries, ear", "c": "This statement indicates correct understanding, since gradual weaning reduces breast engorgement that occurs when breastfeeding is", "d": "This statement indicates correct understanding of weaning, which should be gradual. In addition to avoiding maternal discomfort, gradual"}, "keyConcept": "Weaning from breastmilk in exclusively breastfed infants occurs around 6 months of age and should be gradual, to avoid breast engorgement. Solid foods are offered at this time, in addition to breast milk and formula. Breast milk and formula are important sources of calcium, protein, and fats. Cow's milk can be introduced at 12 months, but excess consumption of cow's milk will lead to decreased appetite for solid food."}, {"id": 11067, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "three-year-old hospitalized child is on bedrest. In order to help meet the child’s developmental needs, the nurse should:"}, {"id": "b", "t": "Athree-year-old is developing hand-eye coordination and this is a suitable activity."}, {"id": "c", "t": "The child in this situation is limited to activities in bed."}, {"id": "d", "t": "This is not a suitable activity for a child on bedrest."}], "correct": "b", "rationale": "Athree-year-old is developing hand-eye coordination and this is a suitable activity.", "whyNot": {"a": "This could meet the child’s security needs, but not the developmental needs of a three-year-old.", "c": "The child in this situation is limited to activities in bed.", "d": "This is not a suitable activity for a child on bedrest."}, "keyConcept": "During hospitalization, play has been proven to be of high therapeutic value for children. Play contributes to their physical and emotional well-being and to their recovery. Play also helps to identify and explore issues related to the child’s experiences in the hospital and reduces the intensity of negative feelings that accompany the child’s hospitalization."}, {"id": 11068, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc € OS @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Renal system"}, {"id": "b", "t": "Central nervous system"}, {"id": "c", "t": "Skeletal system"}, {"id": "d", "t": "Hematological system"}], "correct": "b", "rationale": "‘i Damaged nerves do not regenerate. Once a child has suffered the neurological effects of lead toxicity, the results are permanent. OB a", "whyNot": {"a": "Lead toxicity may cause kidney damage, but the most damage typically occurs in the central nervous system. D i", "c": "While lead toxicity may affect growth and development, the most significant irreversible damage typically occurs in the central nervous", "d": "Lead toxicity can cause damage to the hematological system, but the most significant irreversible problems occur in the central nervous"}, "keyConcept": "According to the Centers for Disease Control, all children should be screened for lead poisoning. The highest priority for screening should be children with a high probability of exposure to high-dose sources. Screening should be done using a blood lead test. Children at highest risk for high-dose lead exposure should be screened more frequently. High-dose sources of lead include deteriorated old buildings, including daycare centers. Because the highest concentrations of lead in paint were used in the early 1900s, children living in homes built before about 1960 are of greatest concern. Children whose homes are being renovated; children whose parents' work or hobbies involve lead; and children living near lead smelters or other industries where lead is processed may be at increased risk for lead poisoning."}, {"id": 11069, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "nurse? O A. Place the infant on the mother’s abdomen and help her get him to cry O B. Assist the mother with breastfeeding the infant to wake him up O C. Place the infant in a radiant warmer and dry him with a towel O D. Call a code blue and notify the neonatal resuscitation team", "choices": [{"id": "a", "t": "Place the infant on the mother’s abdomen and help her get him to cry"}, {"id": "b", "t": "Assist the mother with breastfeeding the infant to wake him up"}, {"id": "c", "t": "Place the infant in a radiant warmer and dry him with a towel"}, {"id": "d", "t": "Call a code blue and notify the neonatal resuscitation team"}], "correct": "c", "rationale": "All 12% — Hard Depending on facility policy, a newborn infant may be placed in a radiant warmer for observation or on the mother’s abdomen immediately B 1% after delivery. However, if the infant is pale and not crying, the nurse should place him in a warmer and dry him off to stimulate him to cry. In | many cases, gentle stimulation after birth is enough to make an infant cry; if he does not respond, then further measures, such as ec | 53% pressurized oxygen, are necessary. D || 33%", "whyNot": {"a": "The infant may eventually be placed on the mother’s abdomen; however, this infant is showing signs of distress and is not crying. The", "b": "The infant is not sleepy and does not need to breastfeed at this moment. The nurse should place him in a radiant warmer to stimulate him", "d": "While a code blue may be necessary if the nurse has attempted unsuccessfully to get the infant to breathe, the nurse should first make"}, "keyConcept": "Radiant warmer beds provide accessibility for resuscitation or procedures while providing thermal stability in the neonate. When the neonate's condition has stabilized, the infant can be moved to a preheated incubator, on skin temperature servocontrol, if necessary. The axillary temperature should be monitored closely. Temperature should be checked 30 minutes after moving the neonate to the incubator and every hour for four hours afterwards."}, {"id": 11070, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following is an expected finding in an assessment of an 18-month-old child?", "choices": [{"id": "a", "t": "Eats with a spoon"}, {"id": "b", "t": "Builds a 6-7 block tower"}, {"id": "c", "t": "Says sentences with 2-4 phrases"}, {"id": "d", "t": "Grips crayons with fingers"}], "correct": "a", "rationale": "An 18-month-old should be able to meet the following milestones (see table below). Walks up and down steps with help, jumps in one place, throws Gross motor skills han uackekal Builds 3-4 block towers, uses spoon and cup, scribbles, grips crayon with fist, turns 2-3 book pages Language skills 10+ words, can identify common objects Social and cognitive skills | Expresses ownership, has temper tantrums, imitates others Developmental Milestones for Toddlers Non-verbal Looks for hidden Crawls up steps, _| Hits 2 objects 12months | takes fist steps | together, 2finger | Sestures ike | objects; may ecco tes) | Pree ee 3.5 words separation anxiety Motor skills Jumps in place, macy anal then abl! | $P00n, turns 2-3 | Identifies common | Identifies objects as monthe Seg Pages in together in | objects, has aten- | as “mine,” Rolland) ak abook, stacks 3-4 | word vocabulary | imitates, temper or cose ears blocks ina tower, | or more tantrums ses scribbles (Gon eok psd | Lined one Book || Soc eee more words, down stairs alone, | page at atime, | OF 2A months | Licks a ball and runs | stacks 6-7 blocks in | *atesownname | independence vaithout falling. ‘a tower, draws line | 204 Us€s 2-3 word | from parents or x phrases, caregiver Jumps forward, Feeds self without | Sentences are 3-4 sémonths | Walks up steps with | help, rips crayon _| words and include | ToHet lear siternating feet, | with fingers instead | “why\" questions, | <- stive play, pedals tricycle of fist, draws circle _| can state own age", "whyNot": {"b": "A 2-year-old normally has the fine motor skills to build a 6-7 block tower. An 18-month-old can build a tower of 3-4 blocks.", "c": "An 18-month-old has at least a 10-word vocabulary but does not make phrases. A 2-year-old makes 2-3 word phrases.", "d": "By the age of 3, a child can grip a crayon with fingers. An 18-month-old child uses a fist."}, "keyConcept": null}, {"id": 11071, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "The amount of fat and water begin to decrease, resulting in loss of turgor"}, {"id": "b", "t": "The outer layer of skin sloughs off and is replaced with new cells every few days"}, {"id": "c", "t": "The vascularity of the skin decreases, resulting in lowered ability to regulate body temperature"}, {"id": "d", "t": "Collagen begins to lose its elasticity and strength"}], "correct": "b", "rationale": "all 7% Easy As a person ages, the skin begins to lose fat, water, and collagen, resulting in loss of turgor and elasticity. Blood supply to the skin decreases, OB TY ry making it harder for an aging adult's body to regulate the temperature. This is one of the reasons older adults feel cold at higher temperatures. Although the outer layer of skin is replaced every few days in younger people, this cell replacement does not occur as quickly c | 6% in older adults.", "whyNot": {"a": "The amount of fat and water decreases in an older adult, resulting in loss of skin turgor.", "c": "An older adult’s skin vascularity decreases, lowering the ability to regulate body temperature.", "d": "The collagen found under the skin of most older adults begins to lose its elasticity and strength."}, "keyConcept": "There are many anatomical and physiological changes experienced in the course of aging. This results in increased vulnerability and special skin care needs in the elderly. Elderly individuals have fragile skin and injury can result in scar tissue, slow healing, infections, and wounds that will not heal."}, {"id": 11072, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching the parent of a toddler who has an iron deficiency anemia. Which of the following food choices should the nurse include as the best source of iron?", "choices": [{"id": "a", "t": "1 cup of diced chicken breast"}, {"id": "b", "t": "1 cup of chopped raw broccoli"}, {"id": "c", "t": "1 slice of whole wheat bread"}, {"id": "d", "t": "1 cup of whole milk yogurt"}], "correct": "a", "rationale": "The nurse should teach the parent that iron comes from meat, fish, grains, and vegetables. One cup of diced chicken breast contains B a LER approximately 1.8 mg of iron and should be recommended as the best source of iron. ° cl 1%", "whyNot": {"b": "One cup of chopped raw broccoli contains approximately 0.7 mg of iron.", "c": "One slice of whole wheat bread contains approximately 0.7mg of iron.", "d": "One cup whole milk yogurt contains approximately 0.12 mg of iron."}, "keyConcept": "lron can be found in two forms: nonheme, which is found in plants, and heme, which is found in meats. Heme iron is absorbed more readily; however, the majority of daily iron intake will come from nonheme sources. It is the role of the nurse to provide nutritional education to the parents of children. The nutritional needs of a child should be based on the child's age. Because the child's appetite can vary from day to day, the parents should offer the child the recommended amount of food based on dietary needs and allow the child to decide how much to eat."}, {"id": 11073, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A client’s serum calcium level indicates hypocalcemia. Which of the following signs should a nurse assess in this client?", "choices": [{"id": "a", "t": "Chadwick’s sign"}, {"id": "b", "t": "Chvostek sign"}, {"id": "c", "t": "Homan’s sign"}, {"id": "d", "t": "Ladin’s sign"}], "correct": "b", "rationale": "al 5% Easy The Chvostek sign is caused by nerve hyperexcitability in response to hypocalcemia. When the facial nerve is tapped at the angle of the jaw, OB rsd G1 the facial muscles on the same side of the face will contract, causing a twitch of the nose or lips. I ° © 3%", "whyNot": {"a": "Chadwick’s sign is bluish discoloration of the cervix and vagina and an indication of pregnancy.", "c": "Homan’s sign indicates deep vein thrombosis; there is pain in the calf with forceful and abrupt dorsiflexion of the client's foot at the ankle", "d": "Ladin’s sign is a clinical sign of pregnancy that occurs around 6 weeks, softening in the midline of the uterus anteriorly at the junction of"}, "keyConcept": "Hypocalcemia refers to a corrected calcium level < 8.5. Signs and symptoms of hypocalcemia include numbness and tingling in fingers, toes, and around the mouth (perioral); muscle cramps or muscle spasms; hyperactive deep tendon reflexes; a positive Trousseau's sign and positive Chvostek's sign. Cardiac manifestations include long QT interval and arrhythmias, including bradycardia and asystole. Trousseau's sign is elicited by inflating a blood pressure cuff above systolic pressure. A positive sign occurs with wrist flexion and hand flexion at the MCP joints and extension at the DIP and PIP joints. (Figure shows Chovstek's sign and Trousseau's sign.)"}, {"id": 11074, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in an outpatient clinic is advising the parents of a 7-year-old child about healthy sleep habits in their child. Which of the following should the nurse recommend?", "choices": [{"id": "a", "t": "The child should sleep for 7-8 hours each night."}, {"id": "b", "t": "The parents should encourage the child to engage in physically tiring play before bedtime."}, {"id": "c", "t": "It is important to establish a regular bedtime."}, {"id": "d", "t": "The sleep needs of the child are the result of the high growth rate experienced in this age group."}], "correct": "c", "rationale": "Eas) This child is in the school-age population, which is defined as age 6-12 years. At this period of growth, the child’s needs for rest and sleep A I io y depend primarily on age, activity level, and health status. Although less sleep (9 hours) is necessary as the child approaches age 12, a child 6 needs approximately 11 hours of sleep. Children have not yet learned to recognize fatigue, so a routine bedtime should be ec FY 90% established to ensure adequate sleep. At this age, children may enjoy rituals before bedtime that include reading or listening to music, but .", "whyNot": {"a": "This is the correct amount of sleep for adults, but children require more sleep to prevent fatigue.", "b": "Excessive stimulation or activity should be avoided before bedtime, and parents should suggest quiet alternative activities to promote", "d": "Compared to preschool children or toddlers, school-age children have a slower rate of growth. The need for sleep depends on the child’s"}, "keyConcept": "Between ages 6 and 12 years, a child's need for sleep and rest depends on age, activity level, and health status. At age 6, children need approximately 11 hours of sleep, decreasing to 9 hours as they approach 12 years of age. Routine bedtimes should be recommended to encourage adequate sleep."}, {"id": 11075, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "When discussing a toddler, which of the following indicates a parent has understood the nurse’s explanation of parallel play? O A.\"My child’s choice of a game will determine the choices of the group.\" O B. \"The group will play without a common goal.\" O C. \"One child will take on the leadership role in the group.\" O D. \"My child may enjoy watching the others play.\"", "choices": [{"id": "b", "t": "! 65% Parallel play is typical of toddlers but may also occur at other ages."}, {"id": "c", "t": "There is little interaction with other members of the group and no common group goal. Leaders are important in cooperative play, but"}, {"id": "d", "t": "This does not describe parallel play. The child who is watching others is an onlooker but is not engaging in parallel play."}], "correct": "b", "rationale": "! 65% Parallel play is typical of toddlers but may also occur at other ages. This occurs when children are independently playing near one another Cc | 2% without forming a group with common goals. Children who play in parallel may share their toys, but the primary focus is their own activity. D | | 271% Interaction with others is not an important feature of parallel play.", "whyNot": {"c": "There is little interaction with other members of the group and no common group goal. Leaders are important in cooperative play, but", "d": "This does not describe parallel play. The child who is watching others is an onlooker but is not engaging in parallel play."}, "keyConcept": "Parallel play is a characteristic of play in toddlers, although it occurs at other ages in some circumstances. The child's primary focus is their own activity. Children engaging in parallel play are independently playing, although they may share toys or be playing in close proximity to one another."}, {"id": 11076, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Calcium"}, {"id": "b", "t": "Thiamine"}, {"id": "c", "t": "Folic acid"}, {"id": "d", "t": "Carbohydrates"}], "correct": "c", "rationale": "A | % Moderate Folic acid is a necessary coenzyme in the formation of heme, the iron-containing protein in hemoglobin. cy 17%", "whyNot": {"a": "Calcium is not involved in the production of red blood cells.", "b": "Thiamine is not necessary for the production of red blood cells.", "d": "The production of red blood cells does not involve carbohydrates."}, "keyConcept": "Vitamins are organic compounds required by the human body. These vital nutrients cannot be synthesized in sufficient amounts by the human body and must be obtained from the diet. Folic acid is necessary for cell growth and development through key cellular reactions and processes. Deficiency of folate (vitamin B9) results in megaloblastic anemia and neural tube defects."}, {"id": 11077, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "following should the nurse include when providing teaching to reassure the parents?", "choices": [{"id": "a", "t": "\"The baby is too young to sense your stress or anxiety.\""}, {"id": "b", "t": "\"The baby understands you will return.\""}, {"id": "c", "t": "\"The baby will not cry at this age because you are leaving.\""}, {"id": "d", "t": "\"The baby will probably feel abandoned, but infants are resilient.\""}], "correct": "c", "rationale": "‘i oy | Separation anxiety does not usually occur until about 6 months of age. It usually peaks between the ages of 10 and 18 months, and most ec | children have resolved their separation anxiety by the age of 3. This occurs when the primary caregivers leave the child in the care of D | unfamiliar people. Separation anxiety plays an important role and is the often greatest stressor experienced by children during this period of development, even when compared to injury or pain. Separation anxiety will not occur in a 2-month-old infant. An infant younger than 6 months can usually be calmed by anyone with a soothing manner and voice.", "whyNot": {"a": "Infants may sense anxiety, but they are unable to process the sensation.", "b": "An infant this age has no conception of time.", "d": "A 2-month-old infant does not have the cognitive ability to feel abandonment."}, "keyConcept": "Separation anxiety usually does not develop in infants until 6 months of age, so younger infants can be calmed by anyone with a soothing manner and voice. Separation anxiety peaks between 10-18 months and usually resolves by the age of 3."}, {"id": 11078, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is preparing to set up continuous internal fetal monitoring for a high-risk pregnant client who is in labor. Which of the following must be present before the nurse initiates internal fetal monitoring?", "choices": [{"id": "a", "t": "Membranes that have not ruptured yet"}, {"id": "b", "t": "Cervical dilation of at least 2cm"}, {"id": "c", "t": "Evidence of at least three periods of fetal heart rate decelerations"}, {"id": "d", "t": "Epidural anesthesia to control discomfort"}], "correct": "b", "rationale": "Continuous internal fetal monitoring is a useful tool for consistently assessing fetal heart rate during labor for high-risk clients. When setting up an internal fetal monitoring system, a probe that measures the heart rate is inserted into the baby’s presenting part, which is usually the scalp if it is a cephalic presentation. The mother must have a cervical dilation of at least 2 cm before the probe can be internally placed.", "whyNot": {"a": "The membranes should be ruptured before the nurse places the internal monitoring system. This type of fetal monitor is placed internally", "c": "Fetal heart decelerations are a dangerous sign for the fetus. The client does not need to show that she is having fetal decelerations before", "d": "While a client may have an epidural to provide comfort during labor, it is not necessary to have an epidural before an internal fetal"}, "keyConcept": "Fetal heart rate monitoring during labor demonstrates changes in fetal heart rate patterns in response to contractions. Auscultation, internal monitoring, or external fetal monitoring can be utilized. Auscultation can be performed using a Doppler transducer. External monitoring is performed by wrapping a pair of belts around the mother's abdomen. One belt uses Doppler to detect the fetal heart rate while the other belt measures the length and timing of contractions. Internal monitoring is performed using an electrode that is placed on the presenting part of the fetus, usually the scalp, to record the fetal heart rate. Uterine contractions may be monitored using an intrauterine pressure catheter inserted through the vagina. Internal monitoring can be used only after the membranes have ruptured."}, {"id": 11079, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a G1P0 female client who is at 37 weeks’ gestation. The healthcare provider should be called immediately for which of the following findings during the assessment?", "choices": [{"id": "a", "t": "Low back pain"}, {"id": "b", "t": "Blood pressure 130/80 mmHg"}, {"id": "c", "t": "Severe headache with blurred vision"}, {"id": "d", "t": "Weight gain of 2 lbs since the last visit 5 days earlier"}], "correct": "c", "rationale": "Preeclampsia is a leading cause of maternal morbidity and mortality. It is characterized by onset of hypertension (blood pressure >140 mm Hg systolic or >90 mm Hg diastolic) after the 20th week of gestation in a woman with previously normal blood pressure, accompanied by proteinuria or new onset of one of the following: low platelet count, renal insufficiency, liver dysfunction, pulmonary edema, or neurological symptoms. Urine protein is 0.3 g or more in a 24-hour urine specimen or a 1+ dipstick reading for protein. Preeclampsia can lead to stroke, acute renal failure, pulmonary edema, DIC, and fetal or maternal death. It may progress to eclampsia, which is characterized by seizures. Risk factors include a prior history of preeclampsia, pregestational diabetes mellitus,advanced maternal age, multifetal gestation, obesity, chronic kidney disease, and lupus. Platelets, urine and serum protein, serum creatinine, weight, and blood pressure should be monitored carefully in the last trimester of pregnancy in women at high risk of preeclampsia. The only option for reversal of preeclampsia is delivery, but in clients who are at 36 weeks' gestation or less, pharmacologic treatment may include antihypertensive medication and magnesium sulfate for seizure prophylaxis. Nursing interventions include accurate blood pressure measurement, dietary guidance to target a healthy body weight; providing client education about warning signs of preeclampsia; and monitoring weight gain that may indicate fluid imbalance and edema.", "whyNot": {"a": "Pain should be addressed, but it is not necessary to call the healthcare provider immediately. Many pregnant women experience back pain", "b": "Blood pressures of 140 mmHg systolic and 90 mmHg diastolic or greater are consistent with preeclampsia. However, this blood pressure is", "d": "Rapid weight gain should prompt concern, but normal weight gain in women in the third trimester is a pound per week. The client should"}, "keyConcept": "Preeclampsia refers to new onset of hypertension after 20 weeks' gestation, accompanied by proteinuria, thrombocytopenia, liver"}, {"id": 11080, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "following? O A. Increased height O B. Voice change O C. Changes in the scrotum O D. Growth of hair on the upper lip", "choices": [{"id": "a", "t": "Increased height"}, {"id": "b", "t": "Voice change"}, {"id": "c", "t": "Changes in the scrotum"}, {"id": "d", "t": "Growth of hair on the upper lip"}], "correct": "c", "rationale": "‘a ° Puberty begins between the ages of 9.5 and 14 years of age. Changes associated with sexual maturation begin with scrotal changes, @c YT including changes in texture, reddening of the skin, and increased testicular size. Pubic hair may appear around the same time, with facial D | and axillary hair appearing about 2 years later. Acne may appear at this time. During puberty, the penis also increases in size, usually a year after the testicular changes appear. This is accompanied by changes in the voice.", "whyNot": {"a": "Body growth follows the initial changes of puberty.", "b": "The voice usually changes about 2 years after the onset of initial changes.", "d": "Facial hair appears about 2 years after the onset of puberty."}, "keyConcept": "Puberty begins typically between 9.5 and 14 years of age. The initial changes in puberty in males are scrotal changes, which include reddening and textural changes in the skin and enlargement of the testicles."}, {"id": 11081, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse at a community health center is asked to provide education to high-risk adults about sexually transmitted infections. Which of the following is a sign of primary syphilis?", "choices": [{"id": "a", "t": "Burning urination and urethral irritation"}, {"id": "b", "t": "Painless genital ulcer"}, {"id": "c", "t": "Vesicular lesions in the genital area"}, {"id": "d", "t": "Anorexia and malaise"}], "correct": "b", "rationale": "Mm | 19% = Hard eo: 7 46% Primary syphilis is characterized by a chancre, which is a painless, round ulcer that is located at the point of entry of the bacteria Treponema Cc i 22% pallidum. Although usually a genital ulcer, chancres can occur on the anus, fingers, lips, or other areas exposed through sexual contact. The . If untreated, it progresses through a primary, secondary, and tertiary stage. The secondary stage is characterized by malaise, anorexia, weight loss, and symmetrical lesions. A low-grade fever may occur. Tertiary syphilis can affect the central nervous system or heart. All cases must be reported to the public health authorities, and the client should inform any sexual partners. HIV testing is recommended for individuals who contract syphilis.", "whyNot": {"a": "Chlamydia infections can cause urinary pain and burning with urethral irritation.", "c": "Herpes infections are characterized by vesicular lesions.", "d": "Secondary syphilis is characterized by anorexia and malaise."}, "keyConcept": "Syphilis is a sexually transmitted infection. The primary stage of syphilis is characterized by a painless ulcer, known as a chancre, at the site of inoculation. It is treated with an intramuscular injection of long-acting benzathine penicillin. Untreated, syphilis progresses through three clinical stages associated with significant morbidity. Individuals with syphilis infection are at increased risk of HIV infection."}, {"id": 11082, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is advising a young adult client on nutrition. Which of the following is a good source of complete protein?", "choices": [{"id": "a", "t": "Cruciferous vegetables"}, {"id": "b", "t": "Brown rice"}, {"id": "c", "t": "Eggs"}, {"id": "d", "t": "Whole grain cereal"}], "correct": "c", "rationale": "Dietary sources of complete protein include seafood, poultry, milk, yogurt, cheese, eggs, and soybeans.", "whyNot": {"a": "Cruciferous vegetables are a source of incomplete protein (e.g. broccoli).", "b": "Brown rice is a source of vitamin B3 and a variety of trace minerals.", "d": "Whole grain cereal is a source of incomplete protein."}, "keyConcept": "Complete proteins are proteins that provides all essential amino acids. Essential amino acids are amino acids that cannot be made by the body. As a result, they must come from dietary sources. There are nine essential amino acids. Complete proteins are usually animal sources of protein, such as meat, fish, poultry, dairy products, and eggs."}, {"id": 11083, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is asked to provide education about safety and reduction of risk for parents of 6th-grade children. Which of the following should the nurse include when planning the presentation about this age group?", "choices": [{"id": "a", "t": "Children who are cooking should only do so with parental assistance and should wear 2 oven mitts."}, {"id": "b", "t": "Children who skate or rollerblade in the street should wear head protection."}, {"id": "c", "t": "When children are outdoors, sunscreen should be applied every 3-4 hours."}, {"id": "d", "t": "Children should ride in the backseat of the car and use a restraint system."}], "correct": "a", "rationale": "on 24% ~~ Hard Parental assistance will prevent burns and injuries that can occur when children are not supervised while cooking. Safety rules in the kitchen Cc | | 8% should be emphasized. In addition to wearing two oven mitts to handle hot items, safe kitchen habits include cutting with a knife away from . Parents should allow children to place their hand at a distance above steam rising from a pot to see how hot it is. Other safety habits that children should learn from parents include washing fruits and vegetables before using, thawing food overnight in the refrigerator or in cold water, changing knives and cutting boards when switching between slicing meats or poultry and vegetables or fruits, and thorough hand-washing. Children should learn the importance of not eating unprepared doughs or foods with raw egg.", "whyNot": {"b": "Children should avoid the street when rollerblading. When children are inline skating, they should wear a helmet, knee pads, elbow pads,", "c": "Sunscreen should be applied every two hours, beginning 30 minutes before going outdoors.", "d": "The American Academy of Pediatrics recommends that children between the ages of 8 and 12 years should use a booster seat until they"}, "keyConcept": "Nurses should provide information about safety rules in the kitchen when advising parents of children who may be cooking. These rules include parental assistance and use of two oven mitts to prevent burns and scalding injuries; cutting or slicing in the direction away from the body; washing fruits and vegetables thoroughly before using; avoiding contamination by use of different knives for meats/poultry/seafoods and fruits or vegetables; and careful hand hygiene."}, {"id": 11084, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "indicates an understanding of this topic?", "choices": [{"id": "a", "t": "Pushing and pulling large toys alongside other children who have chosen other types of toys to enjoy"}, {"id": "b", "t": "Working in a group to construct a structure of blocks"}, {"id": "c", "t": "Placing the children on 2 teams to race"}, {"id": "d", "t": "Using a video to teach a group of children about numbers"}], "correct": "a", "rationale": "ce | 9% Toddlers typically engage in parallel play at their stage of development. This refers to playing alongside other children rather than playing Cc | 5% with them in cooperation. When toddlers are in a group, having a variety of toys will allow the children to be present with other children and , improvement of their motor skills, and the use of multiple senses.", "whyNot": {"b": "The group approach described is typical of children in the preschool period.", "c": "This describes team cooperation. The concept of team cooperation is advanced for a toddler. The concept of working for a team goal", "d": "This describes a classroom approach that is too challenging for most toddlers."}, "keyConcept": "Parallel play refers to children playing independently while present alongside others in a group. It is typical of play for toddlers who are ina group of other children. The toddler may cooperate with others by sharing toys, but maintains an independent goal."}, {"id": 11085, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Gonorrhea O >B. syphilis"}, {"id": "b", "t": "Late stages of syphilis include these symptoms and can be fatal."}, {"id": "c", "t": "Chlamydia O p.nPv"}], "correct": "b", "rationale": "Late stages of syphilis include these symptoms and can be fatal. A healthcare provider can diagnose tertiary syphilis with the help of multiple tests. It can affect the heart, brain, and other organs of the body.", "whyNot": {"a": "While untreated gonorrhea can spread to the blood and joints, it does not cause paralysis, blindness, and dementia.", "c": "Untreated chlamydia can cause pelvic inflammatory disease; however, it does not lead to paralysis, blindness, and dementia."}, "keyConcept": "Syphilis is an infection caused by the bacterium Treponema pallidum. It is usually spread by sexual contact, including direct contact with a syphilis sore (chancre), which is a firm, raised, painless genital ulcer. The most common syphilis tests detect antibodies in the blood that are produced in response to a T. pallidum infection. Two tests are required for the diagnosis if the screening test is positive. A treponemal test must be positive to make the diagnosis. Primary syphilis: a sore or sores at the original site of infection (on or around the genitals, around the anus or in the rectum, or in or around the mouth). Secondary syphilis: a skin rash, swollen lymph nodes, and fever. Latent stage: no signs or symptoms. Tertiary syphilis: 10-30 years after infection was first acquired. It can affect the heart, eyes, brain, and other organs of the body."}, {"id": 11086, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "of the following methods of contraception should the nurse suggest for this client?", "choices": [{"id": "a", "t": "Transdermal contraceptive"}, {"id": "b", "t": "Oral contraceptive pill"}, {"id": "c", "t": "Male condom"}, {"id": "d", "t": "Intrauterine device (IUD)"}], "correct": "c", "rationale": "| 3% None of the choices given provide the client with protection against sexually transmitted infections (STIs), which is an important ec fe 54% consideration for a client who has multiple sexual partners. Additionally, smoking over the age of 35 years is a contraindication to the use of Pp! Pi y: ig iB ¥ D na 38% a hormonal contraception. Contraindications include smoking in clients over 35 years of age; a history of coronary artery or cerebrovascular disease, thromboembolic disease, breast cancer, or gallbladder disease; estrogen-dependent tumor; cirrhosis; liver tumor; headaches with focal neurologic symptoms; hypertension; diabetes for more than 20 years; and lactation for <6 weeks’ postpartum.", "whyNot": {"a": "This client has a contraindication to use of a hormonal contraceptive, and a transdermal contraceptive would not offer protection against", "b": "The client has a contraindication (smoking over the age of 35) to an oral contraceptive pill, and it would not offer protection from STIs.", "d": "The IUD would not protect this client from STIs."}, "keyConcept": "When advising clients about contraception, it's important to consider lifestyle risk factors for harmful effects; the coexistent risk of sexually transmitted infections; and plans for conception. Although a male condom does not provide the most effective contraceptive protection, it reduces the risk of transmission of sexually transmitted diseases."}, {"id": 11087, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following interventions is most appropriate when working with a family member who has been given the nursing diagnosis of caregiver role strain?", "choices": [{"id": "a", "t": "Teach the family member appropriate caregiving techniques to make the most of her time"}, {"id": "b", "t": "Make a referral to a dietitian for nutrition care of the family member"}, {"id": "c", "t": "Encourage the caregiver to start a support group to meet other people"}, {"id": "d", "t": "Acknowledge the role the caregiver plays and her value in the client’s life"}], "correct": "d", "rationale": "A Hi 16% Moderate The nurse should provide support and encouragement to the family member with caregiver role strain by acknowledging the role she plays B | a0 in the client’s life. In this way, the nurse opens the opportunity for the family member to discuss her situation further, and the nurse may be able to determine if there are other areas where she can help. c |__| 25% Incorrect Answer: A. The family member most likely knows the techniques needed to care for the client; while she may benefit from more information, this is not the most appropriate intervention. B. A referral to a dietitian would not necessarily help this family member. C. The family member most likely has enough to do that she does not have time to start a support group. She may benefit from joining a group that is already established, but taking the time to start a new group would not be the best intervention for her.", "whyNot": null, "keyConcept": "Caregiver strain and burden refers to the difficulties inherent in assuming and functioning in the caregiver role and related alterations in the caregiver’s emotional and physical health that can occur when care demands are greater than available resources. Caregivers experience challenges when caring for a sick family member that can significantly impact the caregiver's functioning and quality of life."}, {"id": 11088, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client with a fractured wrist who is 36 weeks pregnant. Which of the following assessment items should the nurse prioritize?", "choices": [{"id": "a", "t": "The client reports 3 contractions in the past hour."}, {"id": "b", "t": "The client has a hemoglobin of 12 g/dL."}, {"id": "c", "t": "The fetal heart rate is 210/min."}, {"id": "d", "t": "The fetus kicked 6 times in the past hour."}], "correct": "c", "rationale": "Fetal tachycardia refers to a heart rate of more than 160 beats per minute for more than 10 minutes. This is the concerning item for the nurse. Fetal tachycardia is associated with fetal hypoxia and fetal distress. In fetal movement, fetal tachycardia is a primary indicator of fetal health.", "whyNot": {"a": "Braxton Hicks contractions are painless and occur beginning in mid-pregnancy. They are a physiological response to the stretched uterus", "b": "Hemoglobin can decrease during pregnancy, resulting in a relative increase in plasma volume compared to the increase in red blood cells.", "d": "Fetal movement of 10 in 2 hours or 4 per hour is considered reassuring as an indicator of fetal health."}, "keyConcept": "Assessment of fetal health status includes assessment of fetal movement, including extent, timing, and any changes in the pattern of movement. Fetal heart rate can be detected early in pregnancy, and should be routinely assessed with a fetoscope for rate and rhythm. Fetal tachycardia may indicate fetal hypoxia or distress."}, {"id": 11089, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "tired, which response from the nurse is most appropriate?", "choices": [{"id": "a", "t": "“I will help you find a way to send your children to school so that you can get some rest.”"}, {"id": "b", "t": "“Have you considered that maybe you are taking on too much? You are not taking care of yourself.”"}, {"id": "c", "t": "“Who do you have for support who can help you with your children each day so that you can get more rest?”"}, {"id": "d", "t": "“Why are you teaching your children at home? You are only hurting yourself and your baby by not getting enough rest.”"}], "correct": "c", "rationale": "al 2% Easy By stating this, the nurse is helping the client to better determine who is a source of support and is therefore helping her to problem-solve. B I a The nurse does not try to change the client’s mind about her choices; she only helps her with understanding her options.", "whyNot": {"a": "This response does not consider the mother’s desire to teach her children; instead, the nurse should validate the mother’s choice.", "b": "While it is true the mother may not be taking care of herself, the mother should look for solutions instead of having the nurse simply point", "d": "This response negates the parent’s choice about teaching her children and is too harsh."}, "keyConcept": "A nurse helps the client to know that her feelings are understood and accepted and encourages the client to continue expressing them. By recognizing that it must be difficult or frustrating to feel as the client does, the nurse does not pass judgment on the thought or feeling itself. The nurse accept the thoughts and feelings the client is expressing to open the opportunity for a therapeutic conversation. If the client senses that the nurse does not approve of or does not agree with what she is expressing, it is unlikely that a positive nurse-client relationship will ensue."}, {"id": 11090, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "o- =o Sx Recor: ™ Inbox student.atitesting.com/LT| Mi Inbox — E} Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~", "choices": [{"id": "a", "t": "Perform range of motion exercises several times a day"}, {"id": "b", "t": "Deep-breathing and coughing several times a day"}, {"id": "c", "t": "Wear antiembolism stockings daily as ordered"}, {"id": "d", "t": "Flex and extend her feet every two hours"}], "correct": "b", "rationale": "Deep breathing and coughing will help to expand the lungs and prevent atelectasis.", "whyNot": {"a": "Range of motion exercise is appropriate for the client on bed rest, but will not prevent atelectasis.", "c": "Antiembolism stockings may be ordered to help prevent thrombophlebitis, but they will not prevent atelectasis.", "d": "Flexing and extending the feet may help prevent thrombophlebitis, but it will not prevent atelectasis."}, "keyConcept": "Atelectasis refers to collapse of all or part of the lung usually due to obstruction, resulting in impaired gas exchange. To prevent atelectasis in clients on bedrest, the nurse should encourage the client to perform coughing and deep-breathing exercises every 1 to 2 hours; assist the client with use of an incentive spirometer to encourage deep breathing; reposition the client often and help him walk as soon as possible; administer adequate analgesics to control pain; encourage adequate fluid intake to mobilize secretions; and use postural drainage and chest percussion to remove secretions. Normal Bronchiole Atelectasis Area of Blocked Bronchiole collapsed lung"}, {"id": 11091, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing information to the mother of a toddler concerning toilet training. Which of the following does the nurse relate as an important factor in the process of toilet training?", "choices": [{"id": "a", "t": "Approach, attitude, and understanding of the parents"}, {"id": "b", "t": "Age of the child"}, {"id": "c", "t": "Parent’s commitment to the process © ability of the child to sit still"}], "correct": "a", "rationale": "The attitude and understanding of the parents related to the child’s readiness, both physically and psychologically, are essential to the B | Ase success of toilet training. cH 14%", "whyNot": {"b": "Children are ready to be toilet-trained at different ages. At about one year of age, the infant may recognize the sensation of a full bladder", "c": "This is a factor, but the parent’s overall attitude is more important."}, "keyConcept": "Toilet training is a developmental milestone that presents a challenge to parents and children. It is one of the first steps as children become self-sufficient. The nurse should help parents identify the readiness signs in their child. Physical ability and psychophysiologic readiness are necessary for successful toilet-training."}, {"id": 11092, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "this nurse conclude about this behavioral interaction?", "choices": [{"id": "a", "t": "It is a typical expression of toddler’s social development"}, {"id": "b", "t": "This is an example of antisocial behavior found in some children"}, {"id": "c", "t": "This is a lack of parental role models to demonstrate acceptable behavior"}, {"id": "d", "t": "This is an illustration of separation anxiety typical in hospitalized children"}], "correct": "a", "rationale": "As part of the socialization process, toddlers enjoy playing beside other children but are not developmentally ready for interactive play that B ] a begins in preschool. This is known as parallel play. c | 1%", "whyNot": {"b": "Toddlerhood is a time of developing independence and self-awareness. These children are experiencing a normal part of development", "c": "Toddlerhood is a time of developing independence and self-awareness. These children are displaying acceptable behavior that is normal", "d": "Toddlerhood is a time of developing independence and self-awareness. These children are experiencing a normal part of development."}, "keyConcept": "At two years of age, a toddler will copy others, especially adults and older children; become excited when with other children; show more independence and defiant behavior; and play mainly beside other children, but begins to include other children, such as in chase games. Playing alongside others is typical of toddlers. This is known as parallel play."}, {"id": 11093, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing teaching about treatment for a client who has alcohol use disorder. Which of the following statements should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"Addiction treatment is the same regardless of the substance or the client.\""}, {"id": "b", "t": "\"Treatment will focus only on the addiction issue.\""}, {"id": "c", "t": "\"Multiple rounds of treatment are frequently necessary.\""}, {"id": "d", "t": "\"Buprenorphine is used to assist you in abstaining from alcohol during the addiction treatment period\""}], "correct": "c", "rationale": ". Participation in an ongoing B I a support group and knowledge of triggers as well as ways to manage stress can promote the success of a treatment program.", "whyNot": {"a": "There are a wide variety of treatments available to clients who have substance use disorders. They include inpatient treatment centers,", "b": "In order to be effective, treatment for substance use needs to address multiple needs including medical, psychological, social, vocational,", "d": "Buprenorphine is used in medication-assisted therapy for clients who have opioid addiction. Medication-assisted therapy for alcohol"}, "keyConcept": "The treatment of substance use disorders focuses on assisting the client and significant others in the client's life to view the substance use disorder as a chronic illness. Treatment concentrates on assisting the client to make lifestyle changes, manage stress, and identify and avoid triggers. Family members are often a part of the therapy as well because codependence frequently occurs as a part of the client's disorder."}, {"id": 11094, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 1 year old who has been diagnosed with sickle cell anemia. Which of the following may delay diagnosis of infants with sickle cell anemia?", "choices": [{"id": "a", "t": "The absence of any respiratory disorders"}, {"id": "b", "t": "General good health and an excellent growth curve"}, {"id": "c", "t": "The presence of fetal hemoglobin during the first year of life"}, {"id": "d", "t": "Compensation of increased hematocrit and hemoglobin if they are well-nourished"}], "correct": "c", "rationale": "A l 3% Hard High levels of fetal hemoglobin prevent sickling of red blood cells in an infant. 8 8 Pp ig B || 23%", "whyNot": {"a": "Respiratory disorders are not associated with sickle cell anemia except in times of crisis as a consequence of hypoxia. D | | 25%", "b": "The diagnosis is made on the basis of hematologic tests.", "d": "These factors do not affect the diagnosis of sickle cell anemia."}, "keyConcept": "Fetal hemoglobin (HbF) usually disappears after about 6 months of age, but the exact time of disappearance of HbF varies. Healthy adults usually have <1% fetal hemoglobin, compared to 5-8% in adults with sickle cell anemia. Fetal hemoglobin modulates the clinical manifestations of the disease. Red blood cells with fetal hemoglobin are less likely to deform and polymerize in the manner of HbS. The presence of high concentrations of fetal hemoglobin in infants is a protective factor against sickle cell crisis."}, {"id": 11095, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is conducting a community workshop on bullying among school-age children. Which of the following comments indicates a need for further teaching?", "choices": [{"id": "a", "t": "Children with a physical disability have an increased risk of being bullied."}, {"id": "b", "t": "Verbal aggression is the most common form of bullying."}, {"id": "c", "t": "Bullying is part of the normal development of school-age children."}, {"id": "d", "t": "Victims of bullying are unlikely to confide in an adult."}], "correct": "c", "rationale": "All 10% Easy Some adults believe bullying is a normal manifestation of childhood, despite widespread efforts to educate the public about the sequelae of B I a bullying in school settings and in the media. Bullying is a form of abuse that has serious psychological and physical consequences for the victim, including school adjustment difficulties, sleep disturbance, anxiety, depression, and suicide. The belief that bullying will strengthen ec Pe 83% children is wrong. Bullying is not “fun” and can result in tragedy. D l 3%", "whyNot": {"a": "This is a true statement. Bullies tend to target the physically weak or disabled or those who are seen as “different.”", "b": "This is a true statement and indicates understanding. Verbal aggression can include intimidation or insults. Physical bullying tends to", "d": "This statement indicates understanding. Children who are bullied are often concerned that the bullying will escalate if they tell an adult."}, "keyConcept": "Bullying is a form of abuse with serious psychological and physical consequences for children. As children enter high school, verbal bullying becomes more common than physical bullying. Victims are unlikely to confide in an adult."}, {"id": 11096, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse in an assisted living facility is planning an exercise program for a group of older adult clients who are typically sedentary. Which of the following activities should the nurse plan to include in the program?", "choices": [{"id": "a", "t": "Tennis"}, {"id": "b", "t": "Swimming"}, {"id": "c", "t": "Running"}, {"id": "d", "t": "Jumping rope"}], "correct": "b", "rationale": "Clients who are primarily sedentary experience cardiac deconditioning. Swimming is an aerobic activity that uses large-muscle groups and can improve cardiovascular function as well as mood. The nurse should recommend low-impact exercises, such as swimming and yoga, as initial exercises for clients who are typically sedentary to avoid injury. Low-impact exercises can maintain and increase strength and flexibility.", "whyNot": {"a": "The nurse should recommend low-impact exercises, such as using a stationary bicycle, to maintain and increase strength and flexibility.", "c": "The nurse should not recommend running because it is a high-intensity exercise that places excessive stress on the joints, especially the", "d": "Jumping rope is a high-impact exercise that places excessive stress on the hips, knees, and ankles. High-impact exercises are"}, "keyConcept": "Older adults should engage in moderate-intensity aerobic exercise for 30 min each day or at least 2 hr and 30 min each week. Types of exercise suitable for older adults include the following: EXERCISES FOR OLDER ADULTS Type Examples Balance Yoga, tai chi ‘Stretching Yoga, range-of-motion exercises"}, {"id": 11097, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "following? O A. Metabolism of brown adipose tissue O B. Increased shunting of blood to the skin surface O C. Decreased utilization of glycogen stores O D. Decreased shivering to keep warm", "choices": [{"id": "a", "t": "Metabolism of brown adipose tissue"}, {"id": "b", "t": "Increased shunting of blood to the skin surface"}, {"id": "c", "t": "Decreased utilization of glycogen stores"}, {"id": "d", "t": "Decreased shivering to keep warm"}], "correct": "a", "rationale": "Infants burn brown fat as a response to cold stress and there is increased utilization of glycogen and calorie stores. Hypoglycemia may occur C ] ue from stress as a result of a cold environment. ° om 13%", "whyNot": {"b": "Increased shunting of blood to the skin surface", "c": "The infant would utilize more glycogen stores in response to cold stress from the environment.", "d": "Newborn infants do not have the capacity to shiver. This is not a response to cold stress in the neonate."}, "keyConcept": "It is important to maintain constant body temperature in neonates. Hypothermia and hyperthermia are associated with increased morbidity and mortality. Non-shivering thermogenesis is the main source of heat production in the neonate. It refers to the production of heat by the metabolism of brown fat, which is deposited after 28 weeks gestation around the scapulae, kidneys, adrenals, neck, and axilla. The neonate’s response to a cold environment is constriction of superficial blood vessels to maintain heat in the core and prevent transmission of heat to the periphery. Superficial vasoconstriction results in a mottled appearance of the skin. If the neonate is not warmed then cold stress can occur, resulting in increased metabolic rate, leading to increased oxygen consumption; increased caloric consumption and decreased glycogen stores which can lead to hypoglycemia; development of acidosis due to pulmonary vasoconstriction; and thermal shock and disseminated intravascular coagulation, progressing to death"}, {"id": 11098, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a pregnant client who is having an initial prenatal visit at 30 weeks’ gestation. Which of the following vaccines are considered safe for administration in this client?", "choices": [{"id": "a", "t": "Tetanus, diphtheria, and pertussis"}, {"id": "b", "t": "Varicella"}, {"id": "c", "t": "Measles, mumps, and rubella"}, {"id": "d", "t": "Influenza nasal spray"}], "correct": "a", "rationale": "8 | 4% Pregnant women should not receive vaccines that contain live attenuated viruses, which are weakened viruses that theoretically can still c I 6% pose a danger through vaccination. Some viruses are associated with the development of severe birth defects if the mother is infected D || 21% during pregnancy. Live attenuated viral vaccines are contraindicated in pregnancy, and women who receive the vaccines should also be counseled to avoid pregnancy within 4 weeks of receiving these vaccines. They include the MMR and varicella vaccines, as well as LAIV (live attenuated influenza vaccine), which is administered as a nasal spray. Pregnant women can receive killed influenza vaccine by injection throughout pregnancy, which is recommended for all pregnant women. The immune system is suppressed during pregnancy, placing pregnant women at increased risk of illness and complications. Of the options listed, only Tdap is considered safe in pregnancy. It is recommended for all pregnant women from 27 to 36 weeks’ gestation in order to provide passive immunity against pertussis to the newborn. Pertussis is a respiratory infection caused by Bordetella pertussis and is commonly known as whooping cough.", "whyNot": {"b": "Varicella contains live virus and is contraindicated in pregnancy. It causes chicken pox and shingles, but the risk of contracting the virus is", "c": "MMR contains a live attenuated virus and is contraindicated.", "d": "Influenza vaccine by nasal spray (LAIV) is contraindicated, although injectable influenza vaccine is considered safe and is recommended"}, "keyConcept": "Live attenuated virus vaccines are contraindicated during pregnancy and within four weeks of pregnancy. They include nasal influenza vaccines, MMR, and varicella vaccine"}, {"id": 11099, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "S Viralr = 8x Recor ™ Inbox = Inbox —E} Untitlc Untitl (4 Goog! @ TEAS Online @ Mark! @ Micro: (lernwermaieNme( ier @ atits G@ Newe € > @G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q } N x G GERO x» *o!1@0 + Finish update", "choices": [{"id": "a", "t": "Hypercalcemia and tells her to increase her intake of milk"}, {"id": "b", "t": "Hypocalcemia and tells her to increase her intake of milk"}, {"id": "c", "t": "Hyperkalemia and tells her to immediately go to the emergency room"}, {"id": "d", "t": "Hypokalemia and tells her to drink green tea"}], "correct": "b", "rationale": "Most calcium in the fetal skeleton crosses the placenta during the third trimester and is primarily derived from maternal dietary absorption of calcium during pregnancy. Intestinal calcium absorption doubles during pregnancy, driven by 1,25-dihydroxy vitamin D (calcitriol) and other factors. After delivery, the maternal calcium demand remains high as a result of breastfeeding. The average daily loss of calcium into breast milk is 210 mg. Daily calcium losses can be as high as 1000 mg when nursing twins. Instead of increased absorption, the demand for calcium is met by temporary demineralization of maternal bones. NORMAL PREGNANCY LACTATION cacum caccium CALCIUM INTAKE INTAKE INTAKE 1 + + oe se 6 | s 4 SERUM Ca” SERUM Ca” SERUM Ca” YX #7 wh “aw 2 a\\fe . ae 4 URINE JRINE", "whyNot": {"a": "Hypercalcemia does not necessarily cause leg pain and increasing milk intake will not resolve the condition. D |", "c": "Hyperkalemia does not cause leg cramps and would not be suspected in this situation.", "d": "Hypokalemia may cause muscle aches and leg cramps; however, drinking green tea will not resolve the condition."}, "keyConcept": "Most calcium in the fetal skeleton crosses the placenta during the third trimester and is primarily derived from maternal dietary absorption of calcium during pregnancy. Intestinal calcium absorption doubles during pregnancy, driven by 1,25-dihydroxy vitamin D (calcitriol) and other factors. After delivery, the maternal calcium demand remains high as a result of breastfeeding. The average daily loss of calcium into breast milk is 210 mg. Daily calcium losses can be as high as 1000 mg when nursing twins. Instead of increased absorption, the demand for calcium is met by temporary demineralization of maternal bones. NORMAL PREGNANCY LACTATION cacum caccium CALCIUM INTAKE INTAKE INTAKE 1 + + oe se 6 | s 4 SERUM Ca” SERUM Ca” SERUM Ca” YX #7 wh “aw 2 a\\fe . ae 4 URINE JRINE"}, {"id": 11100, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc € OS @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "The week before menstruation occurs"}, {"id": "b", "t": "The week of menstruation"}, {"id": "c", "t": "The week after menstruation"}, {"id": "d", "t": "It makes no difference; technique is more important than timing"}], "correct": "c", "rationale": "The best time in the menstrual cycle for a woman to perform breast self-examination is the week after menstruation when her hormones are at their lowest. Before and during menstruation are times when the woman's hormones may cause breast tissues to feel different.", "whyNot": {"a": "During the week before a menstrual period, a woman may have bloating and breast tenderness, which can cause the breast tissue to feel", "b": "During the week of menstruation, a woman may experience bloating and breast tenderness, which can cause the breast tissue to feel", "d": "The best time to perform a breast self-exam is a week after the menstrual period. The woman should perform the exam each month at"}, "keyConcept": "There are cyclical changes in the size and nodularity of breast tissue in response to cyclic ovarian changes. The hormones estrogen and progesterone stimulate breast tissue. Estrogen stimulates the growth of the breasts and increases vascularity. Progesterone causes maturation of the mammary glands. These alterations in breast size are at a minimal level 5 to 7 days after menstruation stops. Breast self- examination should be performed during this phase of the menstrual cycle"}, {"id": 11101, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching the parents of a school-age child who has diabetes mellitus about nutrition and medication usage. Which of the following instructions should the nurse include in the teaching? O A.\"You should eliminate all carbohydrates.\" O B. \"You should combine glargine and regular insulin in the same syringe.\" O C. \"You should aspirate for blood before injecting the insulin.\" O D.\"You should give four or five injections around one area before switching sites.\"", "choices": [{"id": "a", "t": "8%"}, {"id": "b", "t": "The nurse should instruct the client and parents to avoid mixing glargine with any other medication due to incompatibility."}, {"id": "c", "t": "The nurse should instruct the client and parents that it is not necessary to aspirate for blood prior to administering insulin."}, {"id": "d", "t": "A | | 8% Hard The nurse should instruct the client and parents to administer four or five injections about 2.5 cm (1 in) apart before switching to another it | 33% site."}], "correct": "d", "rationale": "A | | 8% Hard The nurse should instruct the client and parents to administer four or five injections about 2.5 cm (1 in) apart before switching to another it | 33% site. ci 11%", "whyNot": {"a": "Carbohydrates are necessary for a well-balanced diet. The type of carbohydrate is not as important as the content. Healthy carbohydrates", "b": "The nurse should instruct the client and parents to avoid mixing glargine with any other medication due to incompatibility.", "c": "The nurse should instruct the client and parents that it is not necessary to aspirate for blood prior to administering insulin."}, "keyConcept": "Children who have diabetes are more successful in maintaining good nutrition if their entire family adopts a diabetic-friendly diet. A child who has diabetes can become resentful or depressed if they are not able to be included in meals with their loved ones. Allowing children to be involved in meal planning and shopping helps to get them excited about their food options."}, {"id": 11102, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Na Recor: Viral n ™. Inbox student.atitesting.com/LT| Mi Inbox — E} Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions Anewly pregnant woman asks the nurse in the OB/GYN office if she should continue to wear her seat belt while driving. The nurse’s BEST response is:", "choices": [{"id": "a", "t": "“Wear your seat belt as long as it feels comfortable. When it gets too tight, stop wearing it.”"}, {"id": "b", "t": "“Always wear your seat belt in a car. Wear the lap belt higher than usual; above your pregnant abdomen so as not to cause discomfort or injury to the fetus if you happen to be involved in an accident.”"}, {"id": "c", "t": "“You should not be driving anywhere. Walking is better for you.”"}, {"id": "d", "t": "“You can continue to wear your seat belt. Wear the lap belt low across your hips, under your pregnant abdomen.”"}], "correct": "d", "rationale": "Seat belts should be worn throughout pregnancy to promote safety for the mother and her unborn child. The correct position is low across the hips to prevent pressure on the pregnant abdomen.", "whyNot": {"a": "Pregnant women should not stop wearing their seat belts. The risk of entrapment of the mother is far less than the risk of trauma caused", "b": "A seat belt in this position affords little protection and may cause injury.", "c": "The client has not asked for the nurse’s advice about exercise."}, "keyConcept": "During pregnancy, the safest type of seat belt is a lap and shoulder belt combination. The lap belt should be placed below the client's abdomen, touching the thighs, and low on the hip bones. The seat belt should never be worn above or across the belly. The nurse should advise the client to always use the shoulder belt, which should fit snugly across the center of the shoulder and chest. The shoulder belt should never be placed under the arm or behind the back. When driving, the pregnant woman should make sure the abdomen is a safe distance away from the airbag. The breast bone should be at least 10 inches away from the dashboard or steering wheel. Pregnancy seatbelt placement ®) @"}, {"id": 11103, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching a client who has schizophrenia about strategies to manage the anticholinergic effects of fluphenazine. Which of the following strategies should the nurse review with the client?", "choices": [{"id": "a", "t": "Take the medication in the morning to prevent insomnia."}, {"id": "b", "t": "Chew sugarless gum to moisten the mouth."}, {"id": "c", "t": "Control loose stools with dietary changes."}, {"id": "d", "t": "Take an antacid to relieve nausea."}], "correct": "b", "rationale": "Chewing sugarless gum can help the client cope with dry mouth, a potential anticholinergic effect of fluphenazine.", "whyNot": {"a": "Insomnia is not an anticholinergic effect. Anticholinergic effects include dry mouth, blurred vision, photophobia, urinary retention,", "c": "Loose stools or diarrhea are not anticholinergic effects. Constipation is an anticholinergic effect and can be controlled with dietary", "d": "Nausea is not an anticholinergic effect. Anticholinergic effects include dry mouth, blurred vision, and urinary retention."}, "keyConcept": "Fluphenazine is a first generation antipsychotic (FGA). Adverse effects of the FGAs include: + Extrapyramidal symptoms: tardive dyskinesia, acute dystonia, parkinsonism, and akathisia + Neuroleptic malignant syndrome: Signs include high fever, muscle rigidity, sweating, dysrhythmias, confusion, and coma, leading to death if not treated promptly. + Orthostatic hypotension: The nurse should measure the blood pressure of the client when lying down and then 1-2 minutes after the client sits or stands. + Sedation: The client should be instructed to give the dose at bedtime."}, {"id": 11104, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is admitting a pregnant client for observation and possible labor induction. Which of the following actions is part of the nurse’s physical assessment?", "choices": [{"id": "a", "t": "Check for a list of the client’s medications"}, {"id": "b", "t": "Measure fundal height"}, {"id": "c", "t": "Assess use of alcohol or nicotine during pregnancy"}, {"id": "d", "t": "Determine social support"}], "correct": "b", "rationale": "al 4% Easy The physical exam that is performed during admission of a pregnant client includes actions that make up the physical assessment, such as OB rsd eer measuring fundal height, checking vital signs, checking cervical dilation, and assessing for contractions. Finding information such as a list of medications, history of alcohol or nicotine use, and amount of social support is part of the client history. c | 5% p| 2%", "whyNot": {"a": "Checking for a list of the client’s medications would be part of taking the client’s history, not part of the physical assessment. iT}", "c": "Assessing for the use of alcohol or nicotine during pregnancy is included as part of the client’s history, not the physical assessment. g", "d": "Determining the amount of social support the client has is part of the client’s social history. It is not included as part of the physical 2"}, "keyConcept": "During the third trimester, the client is seen by the healthcare provider every 2 to 4 weeks, depending on the client's health and obstetrical history. Starting at 36 weeks the client will undergo weekly checkups until delivery. During the third trimester, prenatal care includes vaginal exams to check the baby's position. Screening for group B streptococcus (GBS) also occurs during the third trimester."}, {"id": 11105, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "she can continue her assessment and the woman refuses. Which response from the nurse is most appropriate?", "choices": [{"id": "a", "t": "“Would you like help with taking your head covering off or can you do it yourself?”"}, {"id": "b", "t": "“If you prefer, will leave the room and you can take off your head covering.”"}, {"id": "c", "t": "“Let’s figure out how we can complete this assessment and you can keep your head covering on.”"}, {"id": "d", "t": "“You need to take this off for my assessment. cannot finish my work until you listen to me.”"}], "correct": "c", "rationale": "When caring for a client with a Muslim background, the nurse may encounter practices that differ from the nurse's usual experience. Many Muslim women value and respect privacy and they demonstrate this by wearing clothes that cover much of their bodies, including their heads. Some women are very uncomfortable taking off their head coverings, even in front of a female nurse. The nurse should find a way to perform the assessment while continuing to respect the privacy and culture of the client.", "whyNot": {"a": "The client has already stated that she does not want to take off her head covering. The nurse should find another way to perform the", "b": "Leaving the room will not allow the nurse to finish her assessment. Instead, the nurse should find a way to continue the assessment while", "d": "This statement indicates disrespect of the client’s beliefs and privacy. The nurse should instead find a way to complete the assessment"}, "keyConcept": "In order to provide high-quality client-centered care to Muslim clients, the nurse must have an awareness of the Islamic faith and Islamic beliefs. Although there are many Muslims in Western-oriented countries who may not adhere strictly to Islamic practices, these practices may dominate every aspect of life for other lim clients. A culturally competent nurse is aware that religious or cultural practices may influence diet, modesty, family relationships, communication, and healthcare choices, but also realizes that it is important to ask the client about their individual practices, values, and beliefs in order to provide individualized care. % CLOSE N xX G GERO + v Qa * es * © tb Finish update : { Browse Questions > iit Search Questions QJ"}, {"id": 11106, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "When performing a physical examination of a toddler, which of the following is the appropriate nursing intervention?", "choices": [{"id": "a", "t": "Begin the examination at the head and proceed in an orderly manner to the toes."}, {"id": "b", "t": "Keep the medical equipment used in the exam out of the toddler’s sight until it’s needed."}, {"id": "c", "t": "Encourage the parent to step out of the exam room."}, {"id": "d", "t": "Begin the exam by removing the toddler’s clothing."}], "correct": "b", "rationale": "A Yt 38% Moderate eo i” 55% c | 1% og 6% The nurse should develop trust by talking to the toddler about things the toddler enjoys before beginning the exam. The toddler’s anxiety may also be reduced and cooperation enhanced if the nurse encourages the parents to remain involved by holding the child and assisting with the exam. The use of appropriate toys or games can be helpful when a child is uncooperative and anxious.", "whyNot": {"a": "The exam should begin with an assessment of the regions that do not require undressing or invasive maneuvers, such as the ears and", "c": "The parents should be encouraged to participate.", "d": "The exam should begin with areas that do not require undressing. The parents can help the nurse undress the child as the exam"}, "keyConcept": "When examining a toddler, the nurse should gain the child's trust by talking about things the toddler enjoys before beginning the exam. It is also helpful to encourage the parents to hold the child during the exam and to assist with the exam. Toys or games can sometimes be helpful in the case of uncooperative or anxious children."}, {"id": 11107, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is counseling a parent whose preschool child began wetting the bed again after a recent hospitalization. Which of the following is the most appropriate response by the nurse?", "choices": [{"id": "a", "t": "\"Involving the child in changing wet linens will end the behavior.\""}, {"id": "b", "t": "\"Your child is acting out because of the hospitalization.\""}, {"id": "c", "t": "\"We can restrict playroom privileges until the bedwetting stops.\""}, {"id": "d", "t": "\"This is a normal regression behavior due to stress as a result of the hospitalization.\""}], "correct": "d", "rationale": "| 2% Easy The stress of hospitalization in an unfamiliar environment with an unfamiliar routine and fear or pain due to invasive procedures results in B | a0 regression during hospitalization. Illness and hospitalization can be more traumatic for a child than an adult because the child is unable to communicate or monitor care. Additionally, children have different physiological needs, including nutritional and metabolic needs. This c | 2% response is normal and may cause toilet-trained children to wet their beds. Children who have given up a pacifier may ask for the pacifier @D PY 95% again. The nurse should explain to the parent that the child will regain previous milestones after discharge.", "whyNot": {"a": "Although some modifications in lifestyle (e.g. involving the child in planning and changing wet linens, limiting the child’s fluid intake at", "b": "Acting out refers to misbehavior. Many preschool children misbehave, so it is unlikely to be the cause of resumption of enuresis with", "c": "Disciplinary measures during a hospitalization could cause further stress to the child and would probably be counterproductive."}, "keyConcept": "Children may regress to an earlier stage of development during hospitalization or illness, due to the stress of an unfamiliar environment, pain, and fear. The nurse should reassure parents that the child will regain earlier developmental milestones with reduction of stress or resolution of the illness or hospitalization."}, {"id": 11108, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a 28-year-old client diagnosed with human immunodeficiency virus infection (HIV). Which of the following symptoms is associated with acute HIV infection?", "choices": [{"id": "a", "t": "Fatigue, weight loss, and night sweats"}, {"id": "b", "t": "Confusion, visual changes, and loss of coordination"}, {"id": "c", "t": "Purplish lesions on the neck and face"}, {"id": "d", "t": "Fever, shortness of breath, and tachycardia on exertion"}], "correct": "a", "rationale": "(HIV) infection is transmitted through blood and body fluids. The virus attacks the CD-4 T-cells of the body’s c I 6% immune system, reducing immune function. Clients acquire opportunistic infections, usually ten to fifteen years after infection, as immunity my | aon becomes severely impaired. After infection, the body's immune response can lead to early symptoms that include fatigue, fevers, weight loss, night sweats, and lymphadenopathy. Some individuals may remain asymptomatic. The risk of infection is high in the weeks after initial infection, due to the replication of the virus during this period. There is a \"window period\" of several weeks after infection before HIV can be detected. A nucleic acid test can detect HIV 10-33 days after infection.", "whyNot": {"b": "These symptoms are consistent with Wernicke encephalopathy, which is caused by vitamin B1 deficiency.", "c": "Kaposi’s sarcoma is an angioproliferative disorder related to human herpesvirus 8 that occurs in individuals who are", "d": "Respiratory problems occur in clients with Pneumocystis pneumonia, an opportunistic infection that occurs in the later stages of HIV"}, "keyConcept": "After initial infection with HIV, flu-like symptoms may occur as a result of the immune system response to the initial infection. Symptoms usually occur two to four weeks after infection, although some infected individuals remain asymptomatic. The risk of transmission of HIV is very high during this period, although tests cannot detect HIV until at least 10-33 days after infection."}, {"id": 11109, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a preschooler who has heart failure. Which of the following manifestations should the nurse expect?", "choices": [{"id": "a", "t": "Strong peripheral pulses"}, {"id": "b", "t": "Increased urine output"}, {"id": "c", "t": "Bradycardia"}, {"id": "d", "t": "Orthopnea"}], "correct": "d", "rationale": ", which leads to pulmonary congestion. The B | 3\" congestion causes orthopnea, or difficulty breathing while lying down. Having the toddler sit up decreases venous return and the pressure the abdominal organs have on the diaphragm. This decrease in pressure improves breathing and oxygenation. c |__| 20%", "whyNot": {"b": "A preschooler who has heart failure is expected to have decreased urine output due to impaired cardiac function and decreased cardiac", "c": "A preschooler who has heart failure is expected to have tachycardia because of sympathetic stimulation of the heart."}, "keyConcept": "The nurse should be able to identify the expected findings of heart failure when assessing a child. The child exhibits these findings because of decreased myocardial contraction, increased afterload, and increased preload. It is important for the nurse to understand the pathophysiology, diagnostic testing, and therapeutic management required for children who have heart failure."}, {"id": 11110, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is teaching an adolescent client who has a new prescription for fluoxetine to treat obsessive compulsive disorder (OCD). Which statement should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"Wear sunscreen when outdoors.\""}, {"id": "b", "t": "\"Check your weight daily.\""}, {"id": "c", "t": "\"Take this medication at bedtime.\" O D.\"The effects of this medication are immediate.”"}], "correct": "a", "rationale": "o; Wearing sunscreen and protective clothing when outdoors will decrease reactions caused by photosensitivity, an adverse effect of SSRI B | medications.", "whyNot": {"b": "The nurse should instruct the client to check his weight weekly to assess for weight loss.", "c": "The client should take the medication in the morning, rather than at bedtime, to prevent insomnia."}, "keyConcept": "Fluoxetine, an SSRI, is indicated for the treatment of obsessive compulsive disorder. The nurse should provide the following instructions for the client: + Take the medication after waking; if a second dose is required, take at lunch time. + Avoid driving and other activities that require alertness until the client's response to the medication is known; the medication might cause drowsiness, dizziness, and blurred vision. + Use sugarless gum and candy to minimize dry mouth. +» Change positions slowly to minimize dizziness. + Wear protective clothing and use sunscreen to decrease risk for photosensitivity reactions. «Monitor appetite and nutritional intake; check weight weekly. * Monitor nutritional intake; report weight changes to the provider."}, {"id": 11111, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a newborn infant after a simple vaginal delivery. Which of the following findings on assessment should the nurse prioritize for follow-up?", "choices": [{"id": "a", "t": "An area of localized soft tissue edema on the scalp that crosses the suture line"}, {"id": "b", "t": "White cheesy material in the genital region"}, {"id": "c", "t": "A pigmented nevus with tuft of hair at the base of the lumbar spine"}, {"id": "d", "t": "Acrocyanosis"}], "correct": "c", "rationale": "A pigmented nevus at the base of the spine with a tuft of hair is often a sign of spina bifida occulta. This is a neural tube defect that is associated with a low intake of folic acid during the first trimester of pregnancy. Pregnant women with no family history of neural tube defect should take a folate supplement of at least 400 micrograms of folate daily. Although 95% of infants with neural tube defects are born to parents with no family history, a supplement of 4 mg daily is recommended for women with a family or personal history of a neural tube defect. Since folate supplementation has become widespread, the incidence of neural tube defects has diminished. Spina bifida (open defect)", "whyNot": {"a": "This refers to caput succedaneum, which is a normal finding in a newborn. It results from trauma of delivery.", "b": "This vernix caseosa, an odorless discharge that may be found in folds or skin creases in the genitals or axilla. It is a normal finding.", "d": "Mottled skin is a normal finding in a newborn."}, "keyConcept": "Spina bifida occulta is a neural tube defect that is usually asymptomatic, but neurologic complications may occur and early recognition is important. Signs of spina bifida occulta may include a sacral dimple, a pigmented nevus at the base of the spine, and/or a tuft of hair at the base of the spine. Folic acid is recommended for women during pregnancy to reduce the risk of neural tube defects, including spina bifida and anencephaly."}, {"id": 11112, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which activity related to identity formation would a nurse most likely expect to see in a 12-year-old?", "choices": [{"id": "a", "t": "Preoccupation with body changes"}, {"id": "b", "t": "Secure gender-role definition"}, {"id": "c", "t": "Self-centeredness and narcissism"}, {"id": "d", "t": "Stability of self-esteem"}], "correct": "a", "rationale": "A 12-year-old is in the stage of beginning puberty or is in the middle of puberty; he or she would most likely be preoccupied with the changes B i at that are taking place in the body. cf 5%", "whyNot": {"b": "A 12-year-old does not have a secure gender-role definition and is still learning about his or her role as a boy or girl.", "c": "Self-centeredness and narcissism are more commonly seen in adolescents rather than in a 12-year-old.", "d": "A 12-year-old is still developing some of the concepts of self-esteem while he or she is entering adolescence. Self-esteem has not"}, "keyConcept": "Adolescence is a period of biological, cognitive, and social changes that stimulate the young to think about themselves, reflect on the type of person they want to become, and find their place in society. These changes are explained by Erikson's theory and Marcia's identity status model. Finding a stable identity is intertwined strongly with an individual's psychosocial functioning and well-being."}, {"id": 11113, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is reviewing laboratory results for a 16-month-old child with an elevated lead level. Which of the following is the most serious concern associated with an elevated blood lead level?", "choices": [{"id": "a", "t": "Cirrhosis of the liver"}, {"id": "b", "t": "Failure to thrive"}, {"id": "c", "t": "Gastrointestinal bleeding"}, {"id": "d", "t": "Neurocognitive impairment"}], "correct": "d", "rationale": "all 6% Easy cy 8% Lead poisoning occurs less often today than in previous generations but remains a problem due to lead-based paints that were used in older Cc I 6% homes prior to 1978. Screening for a blood lead level should be performed at ages 1 and 2. If a child has not been previously tested, eD | 80% screening is recommended up to the age of 6 years. The most serious adverse effect associated with elevated blood lead levels (25 mcg/dL) is neurocognitive impairment. Lead poisoning is associated with greater harm in young children, because the brain and nervous system are not yet fully developed. Log-level exposure over a prolonged length of time can lead to developmental delays, including difficulty with reading and impairment of visual-motor skills. Mild to moderate increases in the blood lead level is associated with impulsive behavior and hyperactivity. Extreme elevations are associated with permanent cognitive impairment. They can result in blindness, seizures, and, in severe cases, death.", "whyNot": {"a": "The renal and neurological system are the primary systems affected by lead poisoning. Hepatotoxicity occurs with acetaminophen", "b": "Chronic lead poisoning can cause growth delay, but the most consequential effect is damage to the neurological system. Growth", "c": "GI bleeding occurs with iron toxicity, not with lead toxicity."}, "keyConcept": "Lead-based paints and lead in the water supply in some areas can result in serious adverse effects on development of the brain and central nervous system when young children are exposed. Screening should occur between the ages of 1 and 2 years. All children should be screened at least once before the age of 6."}, {"id": 11114, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "prevention for mental health disorders?", "choices": [{"id": "a", "t": "Parenting class to teach about infant and toddler development"}, {"id": "b", "t": "Community health treatment program for clients following discharge from an acute care mental health facility"}, {"id": "c", "t": "Counseling service for couples who are planning to marry"}, {"id": "d", "t": "Screening program for alcohol use disorder in a group of clients admitted to a mental health facility"}], "correct": "d", "rationale": ", which has the goal of early detection of a dual diagnosis for clients already diagnosed with a B | mar mental illness, is an example of secondary prevention. The focus of secondary prevention is to assess clients who are experiencing an illness for a secondary problem or complication. Identifying complications early can aid in treatment that targets both disorders. c | 4%", "whyNot": {"b": "Acommunity health treatment program for clients following discharge from a mental health facility is an example of tertiary care", "c": "Acounseling service for couples who are planning to marry is an example of primary prevention. Teaching couples about ways to interact"}, "keyConcept": "All three levels of prevention, including primary, secondary, and tertiary, should work together to provide a comprehensive wellness strategy for preventing, identifying, and treating mental illness. The nurse should be aware of programs within the community that promote health and should be proactive in supporting wellness programs for the community as well as individual clients."}, {"id": 11115, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who is at 30 weeks' gestation and scheduled for a biophysical profile. Which best describes the process of a biophysical profile?", "choices": [{"id": "a", "t": "An ultrasound is used to visualize characteristics of the fetus and observe for fetal responses to stimuli"}, {"id": "b", "t": "The clinician monitors the fetal heart rate and uterine contractions while the client pushes a button whenever she feels a fetal movement"}, {"id": "c", "t": "Uterine contractions are stimulated while the fetus is monitored and the client presses a button whenever she feels a fetal movement"}, {"id": "d", "t": "Aneedle is inserted into the amniotic sac under ultrasound and a small amount of fluid is withdrawn for testing"}], "correct": "a", "rationale": "@ , particularly in a high-risk pregnancy. A biophysical profile combines an B | Ase ultrasound with a non-stress test. The clinician performs an ultrasound to check the status of the baby while the mother pushes a button on a monitor when she feels the baby move. c | T™% of 11%", "whyNot": {"b": "This describes a non-stress test, not a biophysical profile.", "c": "This describes a contraction stress test, not a biophysical profile.", "d": "This describes an amniocentesis, not a biophysical profile."}, "keyConcept": "The biophysical profile combines ultrasound evaluation with a non-stress test (NST). It is performed during the third trimester to determine fetal health. The test is performed if there are questions about fetal health and well being resulting from either an examination, maternal/fetal symptoms, or if the pregnancy is considered high risk. The NST is performed by attaching one belt to the mother’s abdomen to measure fetal heart rate, and another belt to measure contractions. Movement, heart rate and “reactivity” of heart rate to movement are measured for 20-30 minutes. The ultrasound may take as long as an hour. Attributes measured in a biophysical profile include breathing, movement, muscle tone, heart rate, and amniotic fluid volume."}, {"id": 11116, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Drops suddenly and stays low until the onset of menstruation"}, {"id": "b", "t": "Drops slightly, then rises"}, {"id": "c", "t": "Should be taken at morning and at bedtime"}, {"id": "d", "t": "Rises suddenly and then falls"}], "correct": "b", "rationale": "A | | 8% Hard When ovulation occurs, the BBT drops slightly due to increased estrogen, then rises due to increased progesterone. Peston : pes o: a", "whyNot": {"a": "When ovulation occurs, the BBT drops slightly due to increased estrogen, then rises due to increased progesterone. D i 31%", "c": "Basal body temperature is taken in the morning before a woman gets out of bed.", "d": "When ovulation occurs, BBT drops slightly and then rises."}, "keyConcept": "Fertility awareness-based methods to prevent pregnancy, including the basal body temperature method, will result in pregnancy in up to 24% of women over the course of a year. Combined use of the basal body temperature along with another fertility awareness-based method for birth control can produce better contraceptive results but requires diligence. The BBT method is based on small changes in the basal body temperature during the month-long cycle. The BBT is lower in the first part of the menstrual cycle and then rises 1-2 degrees F with ovulation. The BBT should be measured daily and entered on a chart."}, {"id": 11117, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "spotting on January 22. According to Naegele’s rule, which of the following is the estimated date of delivery?", "choices": [{"id": "a", "t": "October 8"}, {"id": "b", "t": "October 12"}, {"id": "c", "t": "October 22"}, {"id": "d", "t": "October 30"}], "correct": "a", "rationale": "To arrive at the estimated date of delivery, Naegele’s rule uses the first day of the date of the last normal menstrual period minus 3 months Cc i plus 7 days. Therefore, this client’s estimated date of delivery is (January 1) - 3 months plus 7, or October 8. Other methods to determine the D I estimated date of delivery include measurement of the uterine height (McDonald’s measurement); auscultation of fetal heart rate by Doppler; and ultrasound, specifically around the 16-18th week of pregnancy. Naegele’s rule assumes the client will have a 28-day cycle. The rule is not as accurate when the client has a longer or shorter menstrual cycle. B. The rule is not based on the last day of the cycle. Length of menstrual bleeding varies among individuals. C. This date is consistent with the conception date of the embryo, which is based on the period of fertility 24-72 hours from with time of ovulation, which is approximately 14 days from the beginning of the last menstrual period. The trophoblast implants 7-10 days after fertilization. Using the date of conception results in a later date than the true gestational age. D. This date may have been calculated from the period of spotting. It should not be used to calculate the gestational age. Spotting may occur when the trophoblast implants into the endometrial lining of the uterus, but use of this date will result in a delay of the estimated date of birth.", "whyNot": null, "keyConcept": "Naegele's rule is used to calculate an estimated date of delivery based upon the date of the last normal menstrual period. The client's estimated date of delivery is calculated by using the first day of the last normal menstrual period and substracting three months, then adding 7 days."}, {"id": 11118, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is counseling a 20-year-old client with multiple sexual partners about the hepatitis B vaccination. Which of the following is indicated for adequate immunization?", "choices": [{"id": "a", "t": "Acomplete series of 3 HBV vaccines"}, {"id": "b", "t": "Avaccine with a booster every 10 years"}, {"id": "c", "t": "Hepatitis B immune globulin followed by the vaccine"}, {"id": "d", "t": "1-time HBV vaccination"}], "correct": "a", "rationale": "The hepatitis B vaccine is now given at birth, at 1 month, and at 6 months of age, as recommended by the Centers for Disease Control and Prevention. For clients who have not received the vaccine as infants, the vaccine can be administered at any age. A series of three injections is necessary to be immunized against the hepatitis B virus. Hepatitis B is a bloodborne virus that is usually transmitted through parenteral, sexual, or perinatal transmission. High-risk groups include men who have sex with men (MSM), IV drug users (IVDU), infants of infected mothers, healthcare workers, and individuals who are on hemodialysis.", "whyNot": {"b": "A 3-injection series is given within a 6-month period, if possible.", "c": "The Hepatitis B immune globulin provides passive immunity for individuals who have not been immunized but who have an exposure to", "d": "A series of 3 vaccines is required for immunity."}, "keyConcept": "Hepatitis B virus is transmitted through exchange of blood and body fluids, causing acute viral hepatitis that can progress to cirrhosis of the liver and end stage liver disease. A series of three vaccines is required for immunity. It is given at birth, one month, and six months of age, but clients who were not immunized as infants can receive the vaccine series at any age. Healthcare facilities are required to provide the vaccine to staff who are at risk."}, {"id": 11119, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for an older adult client who has injuries resulting from intimate partner violence. Which of the following actions is the nurse's highest priority?", "choices": [{"id": "a", "t": "Inform the client about the location of shelters or safe houses."}, {"id": "b", "t": "Encourage the client to participate in a support group."}, {"id": "c", "t": "Coordinate with case management to provide community and social services."}, {"id": "d", "t": "Allow the client to discuss feelings related to the abuse."}], "correct": "a", "rationale": "The greatest risk to this client is injury from intimate partner violence; therefore, the priority action the nurse should take is to assist the client with the development of a safety plan that includes the identification of safe places to live.", "whyNot": {"b": "The nurse should encourage participation in a support group. However, this does not address the greatest risk to the client and is,", "c": "The nurse should coordinate with case management to provide community and social services. However, this does not address the", "d": "The nurse should allow the client to discuss feelings and emotions regarding the abuse. However, this does not address the greatest risk"}, "keyConcept": "The role of the nurse is to educate clients who experience intimate partner violence about safety and provide information regarding community resources. The nurse should implement therapeutic communication techniques to establish rapport and support the client by listening, giving support, and discussing options."}, {"id": 11120, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "The nurse is assessing the nutritional status of a female client who is 5 feet, 7 inches tall who is about to undergo surgery. Which observation would indicate poor nutritional status in the client?", "choices": [{"id": "a", "t": "Poor posture"}, {"id": "b", "t": "Brittle nails"}, {"id": "c", "t": "Dull expression © D. Weight of 128 Ibs. (57.6 kg)"}], "correct": "b", "rationale": "| 2% Easy Brittle nails indicate poor nutrition.", "whyNot": {"a": "Poor posture is not necessarily an indication of poor nutrition. D | | 13%", "c": "A dull expression from the client could be caused by a number of things, including apathy or disinterest in medical care."}, "keyConcept": "The most visually obvious areas to assess nutrient and hydration status are skin, hair, and nails. These changes occur because the body shunts nutrients to the most important organs, including brain and heart. Malnutrition can make the skin dry, thin, and pale. The hair becomes dry and brittle. The nails may become thin and brittle or curve like a spoon, especially on the index finger or third finger., indicating iron deficiency. Nails also may be ridged or start to come apart from the nail bed. In addition to issues with iron, nail problems can be caused by low levels of protein, calcium, or vitamins A, B6, C, and D."}, {"id": 11121, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Na Recor [ Inbox ™ Inbox 2) untitle Untitl (4 Googl! @ TEAS Online @ Mark! @ Micro: (leeUeesitte mei: @ atits @ Newc € OS @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Surgical procedures to correct noise-induced hearing loss are very expensive"}, {"id": "b", "t": "Hearing loss caused by exposure to loud noise is preventable"}, {"id": "c", "t": "Noise-induced hearing loss can result from a one-time exposure to a very loud noise"}, {"id": "d", "t": "Noise-induced hearing loss can have negative effects on speech"}], "correct": "a", "rationale": "Noise-induced hearing loss cannot be surgically corrected. All of the other statements are true.", "whyNot": {"b": "Hearing loss caused by exposure to loud noise is preventable and should be taught to this group of clients.", "c": "Noise-induced hearing loss can result from a one-time exposure to a very loud noise; this information is important for this group to", "d": "Noise-induced hearing loss can have negative effects on speech."}, "keyConcept": "Noise-induced hearing loss (NIHL) can be immediate or may develop over time. It can be temporary or permanent, and it can affect one ear or both ears. Children, teens, young adults, and older individuals can develop NIHL due to exposure of harmful levels of noise at any age. At least 10 million adults (6 percent) in the U.S. under age 70 have features demonstrated on hearing tests that suggest hearing loss in one or both ears from exposure to loud noise. As many as 24% of adults in the US may be affected. NIHL can be caused by a one-time exposure to intense “impulse” sounds or by continuous exposure to loud sounds over an extended period of time."}, {"id": 11122, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a client's lungs and notes dullness on percussion. Which situation would this most likely indicate?", "choices": [{"id": "a", "t": "Pneumothorax"}, {"id": "b", "t": "Atelectasis"}, {"id": "c", "t": "Pleurisy"}, {"id": "d", "t": "Cardiac tamponade"}], "correct": "b", "rationale": "i 28% Hard Atelectasis is the collapse of the alveoli in the lungs, which can cause consolidation and decreased air movement. Atelectasis makes a dull OB a AT sound when percussing the lung fields. ° ci 18%", "whyNot": {"a": "Pneumothorax would be indicated by hyper-resonance on percussion, not dullness. This result most likely indicates atelectasis.", "c": "Pleurisy is classified as pain in the lung tissue because of inflammation; this would not be manifested as dullness with percussion during", "d": "Cardiac tamponade is caused by a buildup of fluid in the sac around the heart. This would not be manifested as dullness on percussion of"}, "keyConcept": "Apulmonary examination is broken down into 4 basic parts: Inspection, palpation, percussion, and auscultation. Percussion is performed by placing the middle fingertip of the nondominant hand on the chest wall and striking the distal interphalangeal joint of that finger with the top of the dominant middle finger. Conditions that result in dullness to percussion include consolidation, mucous plugging with airway collapse, and pleural effusion. Hyperresonance to percussion is seen in pneumothorax and emphysema."}, {"id": 11123, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "€ > @G 23 student.atitesting.com/LT| © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ Sx Recor Mi Inbox M Inbox [J Untitlc Untitl € Goog! @ TEAS Online @ Mark! @ Micro: (lererrrpaie Nae rer @ atits @ Newc % CLOSE { Browse Questions > iit Search Questions QJ N x G GERO x» * 3 '|1@0 + Finish update", "choices": [{"id": "a", "t": "Heart rate"}, {"id": "b", "t": "Muscle tone"}, {"id": "c", "t": "Respiratory effort"}, {"id": "d", "t": "Presence of vernix caseosa"}], "correct": "d", "rationale": "Assessing for the presence of vernix caseosa is not included in calculating Apgar scores.", "whyNot": {"a": "Heart rate is assessed for obtaining Apgar scores, along with muscle tone, respiratory effort, reflex irritability and color.", "b": "An infant’s muscle tone is one of the assessments performed as part of obtaining the Apgar score.", "c": "The infant’s respiratory effort is one of the assessments performed as part of obtaining the Apgar score."}, "keyConcept": "The diagram pictured below illustrates the factors scored when using Apgar scores to describe neonatal well-being at one and five minutes after birth. (Taken on tat min and Sth min of Iie and lator # necessary fowbom baby on fe sienplo criteria on a scale from zero to two, |} ——_ then summing up the fve values | ‘determined by evaluating the thus obtained = Wow Ready )__ vt J [bs This Chas"}, {"id": 11124, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is checking for cyanosis in a client who has COPD and has dark skin. Which of the following sites should the nurse assess to identify cyanosis in this client?", "choices": [{"id": "a", "t": "Pinnae of the ears"}, {"id": "b", "t": "Dorsal surface of the hand"}, {"id": "c", "t": "Palpebral conjunctivae"}, {"id": "d", "t": "Facial skin"}], "correct": "c", "rationale": "A To assess skin-color changes in clients who have dark skin, the nurse should examine the sclerae, the soles of the feet, the palms of the B = hands, the palpebral conjunctivae (inside the eyelids), and the mucous membranes. oc i", "whyNot": {"a": "The external ear structures can reflect cyanosis in clients who have light skin.", "b": "The nurse should assess the palms of the client's hands and the soles of the feet for a bluish discoloration as an indication of cyanosis in", "d": "Facial skin is more likely to reflect pallor than cyanosis. In clients who have dark skin, pallor will cause an ashen gray discoloration."}, "keyConcept": "Cyanosis is a late manifestation of hypoxia, appearing when clients have 5 g/dL or more of hemoglobin that carries no oxygen. This reflects a reduction in circulating oxygen to two-thirds of the usual level. It is usually most evident inside the mouth, on the lips, and in the nail beds. For clients who have dark skin, body areas that have less pigmentation should be used to assess for cyanosis."}, {"id": 11125, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing education to a client who has just had her first prenatal visit. Which of the following should be included as part of routine education about self-care measures for a pregnant client?", "choices": [{"id": "a", "t": "Strive to increase calorie intake by at least 500 calories each day to provide nourishment and control weight gain"}, {"id": "b", "t": "Avoid foods that are high in iron to reduce the risk of constipation"}, {"id": "c", "t": "Get a flu shot during the autumn or winter to protect against influenza infection"}, {"id": "d", "t": "Avoid physical activities such as yoga or swimming, as these exercises increase the risk of premature labor"}], "correct": "c", "rationale": "Throughout a client’s pregnancy, a nurse provides education about a number of topics that will support the client’s comfort and help her to better care for herself. The nurse should provide instructions for weight management depending on the client’s pre-pregnancy weight and health status; she should also encourage safe physical activities to improve feelings of health and well-being. Getting a flu shot during high- risk months is safe for most pregnant women, and will protect against influenza infection that could lead to severe illness during pregnancy.", "whyNot": {"a": "Most women need approximately 300 extra calories a day while pregnant, but this amount varies depending on a woman's weight and", "b": "Because iron supports hemoglobin synthesis, a woman needs to eat more foods with iron while pregnant to make sure that both she and", "d": "Physical activity is beneficial during pregnancy. Activities such as yoga and swimming are low-impact options that can increase strength"}, "keyConcept": "Routine vaccinations such as a flu shot are recommended during pregnancy to protect the mother and the fetus."}, {"id": 11126, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is providing nutritional teaching to a client who is at 8 weeks of gestation. Which food should the nurse recommend as a good source of calcium?", "choices": [{"id": "a", "t": "Dark green, leafy vegetables"}, {"id": "b", "t": "Deep red or orange vegetables"}, {"id": "c", "t": "Red fruits"}, {"id": "d", "t": "Meat, poultry, and fish Check Answer"}], "correct": "a", "rationale": "o; During pregnancy, the client should consume 1,000 to 1,300 mg of calcium each day to promote fetal skeletal and teeth formation. The nurse B ] should recommend that the client consume dark green, leafy vegetables, such as kale, artichokes, and turnip greens.", "whyNot": {"b": "Deep red or orange vegetables are good sources of vitamins A and C but do not contain high levels of calcium.", "c": "Red fruits, such as apples, strawberries, and tomatoes, are high in vitamins A and C but do not contain high levels of calcium.", "d": "Meat, poultry, and fish are sources of protein but do not contain high levels of calcium."}, "keyConcept": "Calcium is an essential mineral in the body that aids in fetal skeletal and teeth formation. It also is essential for maintaining maternal bone strength and tooth mineralization. Good sources of calcium include dairy or milk products and dark green, leafy vegetables, such as kale and turnip greens. It can also be fortified in products such as orange juice. It is recommended that a client consume 1,000 to 1,300 mg of calcium each day during pregnancy."}, {"id": 11127, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a new client during an initial prenatal visit at 10 weeks’ gestation. The nurse understands that which of the following factors on assessment places the client at risk for preterm birth? O a.age30 O B. Hypoglycemia O C. Non-Hispanic white ethnicity O D. Tobacco use", "choices": [{"id": "a", "t": "Maternal age <17 or >35 is associated with increased risk of preterm birth."}, {"id": "b", "t": "Type 1 diabetes is associated with increased risk of preterm birth."}, {"id": "c", "t": "The highest rate of preterm labor and birth is among non-Hispanic black women."}, {"id": "d", "t": "Infection is associated with increased risk of preterm birth."}], "correct": "d", "rationale": "Infection is associated with increased risk of preterm birth. It results in a release of prostaglandins, which promote contractions and increase cervical softening. Other risk factors include use of illicit drugs, history of a prior cervical procedure like a cone biopsy or loop excision, or a history of a spontaneous preterm birth (which is the most significant risk factor). Poor maternal nutritional status may increase risk. Short interpregnancy intervals, cervical insufficiency, and vaginal bleeding in early pregnancy are also associated with increased risk. Aterm pregnancy lasts 38-42 weeks, and 85% of women deliver within 7 days of their due date. Birth before 37 weeks’ gestation is defined as preterm birth. Preterm labor refers to cervical changes and uterine contractions that occur at 20-37 weeks of gestation and may occur without preterm birth. A short length of gestation is a more serious risk to the newborn than low birth weight, as the intrauterine time correlates with the maturation of body systems. Preterm births account for 85% of complications in newborns at the time of delivery. Approximately 75% of preterm births are spontaneous, and the remainder are medically indicated to resolve risk to the mother or fetus associated with continuing pregnancy. Tobacco smoking has a dose-dependent relationship with increased risk.", "whyNot": {"a": "Maternal age <17 or >35 is associated with increased risk of preterm birth.", "b": "Type 1 diabetes is associated with increased risk of preterm birth.", "c": "The highest rate of preterm labor and birth is among non-Hispanic black women."}, "keyConcept": "Delivery before 37 weeks' gestation defines preterm birth. Risk factors for preterm birth include previous history of spontaneous preterm birth, infection, maternal use of tobacco or illicit drugs, maternal diabetes, and a history of cervical procedure, such as a cone biopsy. Length of gestation is closely correlated with maturation of body systems. Respiratory complications, including respiratory distress syndrome, bronchopulmonary dysplasia, apnea, and chronic lung disease, result from failure of the lungs to fully mature. Respiratory complications are a significant cause of morbidity and mortality of in the preterm infant. Other complications include patent ductus arteriosis, retinopathy of prematurity, necrotizing enterocolitis, and intraventricular hemorrhage."}, {"id": 11128, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "6 Viralr =x Recor = Inbox Inbox Until: Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Tell the child that thumb-sucking will cause buck teeth"}, {"id": "b", "t": "Provide distraction every time the child displays the behavior"}, {"id": "c", "t": "Accept the thumb-sucking"}, {"id": "d", "t": "Report the behavior to the physician"}], "correct": "c", "rationale": "Regression results from the stress of hospitalization. When caring for a hospitalized child, the nurse should advise the parents to accept regression if it occurs. Parents are often overly concerned about regression. The nurse should advise the parents that their child may", "whyNot": {"a": "Cause and effect will not be meaningful to a five-year-old. D || 12%", "b": "Distraction will provide only short-term relief and places unrealistic expectations on the mother. It also may reinforce the behavior.", "d": "Thumb-sucking is unrelated to the client’s medical condition."}, "keyConcept": "Regression results from the stress of hospitalization. When caring for a hospitalized child, the nurse should advise the parents to accept regression if it occurs. Parents are often overly concerned about regression. The nurse should advise the parents that their child may"}, {"id": 11129, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@0@ X Viraln 8x Recor M Inbox ™ Inbox ] Untitl Untitl (4 Googl @ TEAS Online €& Mark! @ Micro: (INANETEMEME @ ATITE G Newc N x | G GERO + v € > G 23 student.atitesting.com/LT| Qa * ws * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Garlic"}, {"id": "b", "t": "St. John’s wort © c.Gingko biloba"}, {"id": "d", "t": "Gotu kola"}], "correct": "b", "rationale": "St. John’s wort is the herbal supplement that has been shown to cause the most adverse reactions as a result of its interaction with medications. St. John’s wort tends to make many medications less effective. However, it may also increase the adverse effects of some medications. It is a popular supplement. Clients who take this remedy should be educated about its potential adverse effects.", "whyNot": {"a": "Garlic may need to be limited with some medications, but it is not the supplement that causes the most interactions.", "d": "Gotu kola may need to be limited with some medications, but it is not the supplement that causes the most interactions."}, "keyConcept": "St. John’s wort is an herbal supplement commonly used for depression, anxiety, sleep disorders, and nerve pain. It may work by preventing the breakdown of the neurotransmitter serotonin. St. John’s wort proved superior to placebos for treatment of mild to moderate depression in several short-term studies. St. John's wort is not effective for the treatment of severe depression. This supplement interacts with antiretrovirals that are used to treat HIV, reducing the efficacy of the drugs. It decreases levels of the anti-rejection medication cyclosporine in clients who have undergone an organ transplant. St. John's wort also interacts with SSRI and SNRI antidepressants, with the potential to cause serotonin syndrome, an adverse side effect."}, {"id": 11130, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client who has been unsuccessful at breastfeeding her newborn. Which of the following interventions are appropriate for the nurse?", "choices": [{"id": "a", "t": "Explain that the use of an electrical breast pump is discouraged."}, {"id": "b", "t": "Provide supplemental formula for feedings until breastfeeding improves."}, {"id": "c", "t": "Refer the client to a lactation consultant immediately."}, {"id": "d", "t": "Assess the baby’s sucking reflex and position during feeding."}], "correct": "d", "rationale": "A 0% Easy ce | 5% Newborns should be put to the mother’s breast within the initial hour of life and should remain in skin-to-skin contact with the mother until Cc i 10% they are able to breastfeed for the initial time. Factors that can result in ineffective breastfeeding include prematurity, poor latching by the eD | 84% infant, poor sucking reflex, use of formula feeding, and breast anomaly or previous breast surgery. Nursing interventions that are appropriate in this situation include assessment of the infant’s physical condition and sucking reflex; assessment of the mother’s technique when breastfeeding, including positioning and behavior or anxiety during the feeding; and teaching the client how to express milk by hand and how to use an electric pump to increase milk production.", "whyNot": {"a": "A nurse can teach a client how to hand express breast milk and how to use an electric pump to increase production of milk. Before a", "b": "Use of supplemental formula for feedings interferes with the mother’s ability to breastfeed exclusively and should be used only for", "c": "A lactation consultant is not the most appropriate intervention, but the referral should be made if ineffective breastfeeding continues for"}, "keyConcept": "Newborns should be put to the mother’s breast within the initial hour of life and should remain in skin-to-skin contact with the mother until they are able to breastfeed for the initial time. After assessment of the mother and infant and providing assistance, consultation with a lactation expert may be necessary after 24 hours without success."}, {"id": 11131, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "During routine prenatal testing, it is determined that a pregnant client is not immune to rubella. Which of the following considerations must the nurse consider when preparing to administer the rubella vaccine?", "choices": [{"id": "a", "t": "Educate the client that she will need at least two doses of the vaccine to provide rubella immunity"}, {"id": "b", "t": "Do not provide the vaccine to a pregnant client. The client cannot receive the vaccine until after childbirth"}, {"id": "c", "t": "Many clients develop fever, swelling at the site of injection, and bleeding into the joints after rubella vaccine administration"}, {"id": "d", "t": "The client must wait at least six months after receiving the vaccine before becoming pregnant again"}], "correct": "b", "rationale": "all 7% Easy Routine testing for rubella immunity during pregnancy may determine that a pregnant client is not immune to rubella and that the vaccine is OB TY epi necessary to avoid potential birth defects in future pregnancies. Although the client needs the vaccine for protection, it should not be given during pregnancy. The rubella vaccine is often administered the first postpartum day while the client is still in the hospital. c | 3% off 8%", "whyNot": {"a": "Only one dose of the rubella vaccine is necessary to provide immunity. The client will not need at least two doses.", "c": "Some clients may develop pain or redness at the injection site with a rubella vaccine. Bleeding into the joints after the injection is nota", "d": "A client who receives the rubella vaccine after giving birth can safely become pregnant again and does not need to wait six months."}, "keyConcept": "Rubella can be prevented with the MMR vaccine, which protects against three diseases: measles, mumps, and rubella. Children should receive two doses of the MMR vaccine, starting with the first dose at 12 through 15 months of age, and the second dose at 4 through 6 years of age. MMR vaccine is very safe and effective. One dose of the MMR vaccine is about 97% effective at preventing rubella. The Advisory Committee on Immunization Practices (ACIP) recommends that healthy adults who do not have evidence of immunity to measles, mumps, and rubella should get vaccinated against these diseases. Women of childbearing age, especially those who grew in areas where routine rubella vaccination might not occur, should be vaccinated with 1 dose of MMR vaccine or have serologic evidence of rubella immunity, but the vaccine is a live attenuated virus vaccine and is contraindicated in pregnant women."}, {"id": 11132, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "@ @ & Viraln x Recor M Inbox ™ Inbox [J Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc € > @G 23 student.atitesting.com/LT| N xX G GERO + v Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "Nasal congestion and a low-grade fever followed by a rash"}, {"id": "b", "t": "Ahigh fever and Koplik spots in the mouth"}, {"id": "c", "t": "Arash, mainly on the trunk of the body, and low-grade fever"}, {"id": "d", "t": "Nausea and vomiting"}], "correct": "b", "rationale": "Rubeola signs and symptoms include a high fever, photophobia, and Koplik’s spots (white patches on the mucous membranes in the mouth).", "whyNot": {"a": "Although rubeola may include nasal congestion and other cold symptoms, rubeola is characterized by a high fever, not a low-grade fever.", "c": "The rash associated with rubeola often starts on the face and moves downward over the body. Rubeola is also characterized by a high", "d": "Nausea and vomiting are typically not symptoms associated with rubeola."}, "keyConcept": "Rubeola, or measles, is a viral illness that results in a viral exanthem, which refers to a rash or skin eruption. Rubeola has a distinct rash that aids in diagnosis. Measles is very contagious. It is spread through direct contact with discharge from the nose and throat and can also be spread through airborne droplets from an infected individuals. Clinical manifestations include fever, and cough, followed by a generalized rash"}, {"id": 11133, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "perform prior to administration of the medication?", "choices": [{"id": "a", "t": "Assess the client's pain level."}, {"id": "b", "t": "Monitor the client's intake and output."}, {"id": "c", "t": "Educate the client on the effects of clonidine."}, {"id": "d", "t": "Obtain baseline vital signs."}], "correct": "d", "rationale": "Assessment is the initial step of the nursing process. Obtaining the client's baseline vital signs is the priority nursing action.", "whyNot": {"a": "Assessing the client's pain level is an important step, but it is not the priority prior to administering clonidine.", "b": "Monitoring the client's intake and output is an important nursing action, but it is not the priority nursing action prior to administering", "c": "Educating the client about the medication is an important nursing action. However, it is not a priority action."}, "keyConcept": "Clonidine is an antihypertensive medication that can cause hypotension, so the nurse should assess the client's vital signs prior to administering clonidine. The nurse should monitor a client who is experiencing opioid withdrawal for the following manifestations: + tachycardia + diarrhea +» sweating * nausea, vomiting, and stomach cramps + shivering + gooseflesh + difficulty sleeping"}, {"id": 11134, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is caring for a client with multiple comorbid disorders who has a prescription for massage therapy. What is an example of a proven benefit of massage therapy?", "choices": [{"id": "a", "t": "Decreased symptoms of asthma"}, {"id": "b", "t": "Relief of anxiety and depression"}, {"id": "c", "t": "Complete restoration of mobility with arthritis"}, {"id": "d", "t": "Resolution of nausea and diarrhea"}], "correct": "b", "rationale": "Massage therapy is beneficial for many conditions, including relief of anxiety and depression. Massage improves circulation and may promote the release of endorphins, which can result in elevation of mood.", "whyNot": {"a": "While massage therapy may help to improve breathing in some people, it has not been proven to decrease symptoms of asthma.", "c": "While massage has been shown to partially restore mobility for those with arthritis, it has not been proven to provide complete", "d": "Massage typically does not relieve or affect nausea or diarrhea."}, "keyConcept": "Massage affects both body and mind. Researchers have quantified the benefits of massage through changes in stress hormone levels, vital sign measurements, and pain scores, as well as other validated measures. Benefits of massage therapy include reduction of stress, improved pain management, promotion of relaxation and sleep, promotion of a general sense of well-being; reduction of inflammation; and reduction of discomfort in clients recovering from severe burns."}, {"id": 11135, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is assessing a 3-year-old child’s fine motor skills. Which of the following activities should be included in the assessment?", "choices": [{"id": "a", "t": "Monitoring the child’s ability to climb a ladder on some playground equipment"}, {"id": "b", "t": "Watching the child use a zipper"}, {"id": "c", "t": "Asking the child to throw a ball"}, {"id": "d", "t": "Assessing whether the child can walk backwards"}], "correct": "b", "rationale": ", hands, and arms, usually smaller movements that are made to manipulate objects and OB rd aan often may be used in everyday activities. Examples of fine motor skills include zipping a zipper, brushing teeth, eating, cutting with scissors, or coloring with crayons. c | 30% of 5%", "whyNot": {"a": "Climbing a ladder on playground equipment such as a slide is an example of large (\"gross\") motor skills.", "c": "Throwing a ball is an example of large motor skills.", "d": "The ability to walk backwards is an example of large motor skills."}, "keyConcept": "When assessing a child's development, the nurse should ask questions of the parents and listen to their concerns. Concerning findings in a three-year-old would include shaky or stiff movements, weakness in the hands or arms, holding a crayon only with a full fist; inability to draw circles or straight lines; inability to stack several blocks; or inability to hold scissors."}, {"id": 11136, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "We Recor Mi Inbox M Inbox — E}_ Untitl Untitl (4 Goog) @ TEAS Online & Mark! | @ Micro: (eeuNnes creme rel @ AtTits =G@ Newe N x) G GERO) + v € > G 23 student.atitesting.com/LTI Q * sw * © tb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Rooting reflex"}, {"id": "b", "t": "Sucking reflex"}, {"id": "c", "t": "Babinski reflex"}, {"id": "d", "t": "Swallowing reflex"}], "correct": "a", "rationale": "The infant is demonstrating the rooting reflex, which occurs when the area around the mouth is stimulated and the infant turns her head in B I a that direction. This is a normal reflex present at birth that helps the infant to look for the breast or bottle to start feeding. n © 4%", "whyNot": {"b": "The sucking reflex is described as the infant making sucking motions when the area around the mouth is stimulated; the description given", "c": "The Babinski reflex is associated with the plantar surface of the feet, not with the mouth.", "d": "The swallowing reflex refers to the act of swallowing when liquid or food enters the mouth."}, "keyConcept": "Newborn reflexes are tested as part of the assessment of brain and nerve activity. The root reflex begins when the corner of the baby's mouth is stroked or touched. The newborn will turn his or her head and open his or her mouth to \"root\" in the direction of stroking. Rooting helps the infant become ready to suck. When the roof of the baby's mouth is touched, the baby will begin to suck. The suck reflex s not fully developed until about 36 weeks. The Moro reflex is known as the startle reflex because it usually occurs when a baby is startled by a loud sound or movement and throws back his or her head, extends out the arms and legs, cries, then pulls the arms and legs back in. Other normal newborn reflexes include the tonic neck reflex, step reflex, grasp reflex. and Babinski reflex."}, {"id": 11137, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "A nurse is instructing a parent whose 4-year-old child has a prescription for morphine sulfate for pain. Which of the following statements by the parent indicates a need for further teaching?", "choices": [{"id": "a", "t": "“The FACES pain scale can help my child report his pain.”"}, {"id": "b", "t": "“If my child is sleeping, there is no need for pain medication.”"}, {"id": "c", "t": "“My child may begin to act aggressively as a result of the pain.”"}, {"id": "d", "t": "“My child may believe pain is a punishment.”"}], "correct": "b", "rationale": "A Pain may be present when a child is playing or sleeping but they are coping through distraction. The parent should continue to administer OB — pain medication as prescribed if the child describes pain. Pain can be reported by young children using a visual analog scale like the FACES i 7 © pain scale. on International Parenting “Pain” Face Scale on oo} a> @& Ate bd ~ ~~ ~ ~~ = SA NS = ~~ r~ TX o 2 4 6 8 10 open us — — terse Wontponbi bnoiog ——ncamfarle, aa Great tne ran teatime pon roma extn pon be =", "whyNot": {"a": "The FACES pain scale is a visual analog scale that can be useful in helping young children describe the severity of pain.", "c": "Children who are preschool age may become aggressive in a physical or verbal manner as a result of pain.", "d": "Magical thinking is common in young children and may lead them to believe the pain is a punishment for some fault or wrongdoing."}, "keyConcept": "Avisual analogue scale is a good way for children who cannot read to report pain. Pain can occur when the child is sleeping, so the parents should be encouraged to give the prescription as ordered, even if the child is going to sleep."}, {"id": 11138, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "o- =o Sx Recor: ™ Inbox student.atitesting.com/LT| Mi Inbox — E} Untitlc Untitl: €@ Goog! @ TEAS Online @ Mark! | @ Micro: (eettgasire mer irer @ atits @ Newc © Tutorial: BoardVitals NCLEX Prep RN ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~", "choices": [{"id": "a", "t": "Testicular self-examinations should be done on a monthly basis"}, {"id": "b", "t": "Testicular self-examinations can be done while taking a shower"}, {"id": "c", "t": "Testicular cancer is usually found in older men"}, {"id": "d", "t": "Lumps should be reported to a physician"}], "correct": "c", "rationale": "Testicular cancer is primarily found in younger men.", "whyNot": {"a": "Testicular self-examinations should be done at least monthly; the nurse should provide this information.", "b": "Testicular self-examinations can easily be done while taking a shower.", "d": "Any lumps found during a testicular self-examination should be reported to the physician. The nurse should provide this information for"}, "keyConcept": "Testicular cancer is the most common cancer in men 15-34 years of age. The two types of testicular tumors most commonly identified are seminoma and nonseminoma. Nonseminomas usually grow and spread more rapidly than seminomas. The most common sign of testicular cancer is a lump or swelling in the testicle. Most testicular cancers can be cured, even when diagnosed at an advanced stage. Epididymus Testicular gs Cc Self-Examination Cancer Sites"}, {"id": 11139, "cat": "NCLEX 19-HEALTH PROMOTION & MAINT", "stem": "Which of the following findings on a newborn assessment should be reported by the nurse to the healthcare provider?", "choices": [{"id": "a", "t": "Heart rate of 120/min"}, {"id": "b", "t": "Respiratory rate of 35/min"}, {"id": "c", "t": "Sacral dimple"}, {"id": "d", "t": "Areas of purplish hyperpigmentation on the buttocks"}], "correct": "c", "rationale": "8 14% Asacral dimple should be reported to the healthcare provider for further evaluation. It may be caused by spina bifida occulta, which is a ec | 68% common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. A sacral dimple may D | | 13% represent a dermal sinus tract, or tract between the skin and the spinal cord. Assessment is needed. Some individuals may have variants of spina bifida occulta in which the spinal cord is tethered or split in two, which causes stretching and neurological damage. Others may have thickening of the nerve fibers at the base of the spinal cord. Spina bifida occurs in 10-20% of births, but many individuals with spina bifida occulta have no other significant findings or impairment.", "whyNot": {"a": "The normal heart rate for a newborn is 110-160/minute.", "b": "The normal respiratory rate in a newborn is 30-60/minute.", "d": "This describes Mongolian spots, a normal finding of purplish/blue pigmentation on the buttocks, back, or neck."}, "keyConcept": "Asacral dimple on a newborn assessment may represent spina bifida occulta, a common neural tube defect in which the bones surrounding the meninges and spinal cord fail to close during gestation. Other signs of spina bifida occulta include a hairy patch, hemangioma, dark red spot, or hypopigmented spot near the sacrum."}], "nclex_21_immune_system": [{"id": 11140, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "Which of the following statements by a client should the nurse consider significant for a severe allergy?", "choices": [{"id": "a", "t": "\"When use my nitroglycerin tablets, get a headache.\""}, {"id": "b", "t": "\"My lips swell when eat avocados or tomatoes.\""}, {"id": "c", "t": "\"I can't drink grapefruit juice with simvastatin.\""}, {"id": "d", "t": "\" have increased blood pressure with selegiline when eat smoked or aged meats and processed lunch meats.\""}], "correct": "b", "rationale": "Asevere hypersensitivity reaction to proteins in foods like tomatoes, avocados, bananas, peaches, grapes, and kiwi, increases the likelihood of a type | hypersensitivity reaction to latex. The proteins in these foods are similar to proteins in rubber that cause . severe latex allergies. Since allergic reactions increase in severity with repeated exposure, a nurse should advise the client to limit exposure to latex, including latex gloves, balloons, pacifiers, nipples, condoms, or diaphragms. Anaphylactic reactions refer to severe and life-threatening type | hypersensitivity reactions to natural rubber latex proteins. When caring for a client with latex allergy, a designated cart of latex free products should be placed outside the client's room. Clients who have experienced an anaphylactic reaction to any allergen should carry an injectable epinephrine pen in the event of unintended exposure to a product or food that causes a reaction due to cross-sensitivity. A medical alert bracelet is also indicated, as cardiovascular collapse can occur rapidly, and bystander help can be lifesaving.", "whyNot": {"a": "This is a typical side effect of cerebral vasodilation that occurs with nitroglycerin and can be treated with acetaminophen.", "c": "Grapefruit juice reacts with many medications. With statin medications, it can increase absorption and should be avoided.", "d": "Selegiline is a monoamine oxidase inhibitor used to treat Parkinson's disease. Tyramine-containing foods (which include aged cheeses,"}, "keyConcept": "Severe hypersensitivity to latex can be associated with cross-allergy to proteins in certain foods (tomatoes, bananas, kiwi, peaches, grapes.) Ifa client has had a significant type | hypersensitivity reaction to one of these foods, exposure to latex should be avoided."}, {"id": 11141, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is providing teaching to a client who has HIV. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| will wear gloves while changing the cat litter box.\" O B. \"I will rinse raw fruits with water before eating them.\" O C. \"I will wear a mask when I'm around sick family or friends.\" O D. \"I will cook vegetables before eating them.\"", "choices": [{"id": "b", "t": "A client who has HIV should avoid consuming raw fruits due to the presence of bacteria that can cause opportunistic infections."}, {"id": "c", "t": "Due to a compromised immune response, a client who has HIV should avoid contact with family or friends who are ill."}, {"id": "d", "t": "A i 10% Moderate A client who has HIV should cook vegetables before eating them to kill bacteria that cause opportunistic infections."}], "correct": "d", "rationale": "A i 10% Moderate A client who has HIV should cook vegetables before eating them to kill bacteria that cause opportunistic infections. B I Ee", "whyNot": {"b": "A client who has HIV should avoid consuming raw fruits due to the presence of bacteria that can cause opportunistic infections.", "c": "Due to a compromised immune response, a client who has HIV should avoid contact with family or friends who are ill."}, "keyConcept": "Human immune deficiency virus (HIV) is an infection that invades and attacks the immune system. The nurse should know that there are four HIV stages. CD4 counts during stage 2 of HIV are typically 200 to 499 cells/mm3, which is enough to protect the immune system from an invasion of an opportunistic infection. Clients in stage 2 of HIV infection are not considered to have AIDS until the CD4 count has dropped below 200 cells/mm3."}, {"id": 11142, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is caring for an elderly client with rheumatoid arthritis. The most effective intervention for relieving stiffness in this client is which of the following?", "choices": [{"id": "a", "t": "Aspirin to decrease inflammation in the joints"}, {"id": "b", "t": "Recommending that the client lose 20 pounds"}, {"id": "c", "t": "Taking a warm shower or bath in the morning"}, {"id": "d", "t": "Applying cold to the affected joints"}], "correct": "c", "rationale": "Awarm bath or shower in the morning may help to relieve stiffness from sleeping.", "whyNot": {"a": "Aspirin can be used before exercise to decrease inflammation, but may not be helpful in relieving stiffness.", "b": "Losing weight may be helpful in decreasing the stress on joints, but this intervention will not help to relieve stiffness.", "d": "Cold is not effective for relieving stiffness, but may help with joint pain."}, "keyConcept": "Rheumatoid arthritis (RA) is a chronic autoimmune disease of unknown origin that causes diffuse inflammation and destruction of connective tissues. Treatment goals include Improvements in comfort level; daily incorporation of pain management techniques and strategies to modify fatigue; maintenance of optimal functional mobility; and the use of effective coping strategies to deal with actual or perceived limitations."}, {"id": 11143, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "diagnoses is the priority for this client with regards to the new prescription?", "choices": [{"id": "a", "t": "Depression"}, {"id": "b", "t": "Risk for infection is discouraged because of his inability to continue working as a carpenter without severe pain. He has received a new prescription for etanercept. Which of the following nursing"}, {"id": "c", "t": "Risk for cardiac arrhythmia"}, {"id": "d", "t": "Impaired physical mobility"}], "correct": "b", "rationale": "All 12% — Hard eo: ii” 41% Ankylosing spondylitis (AS) is a rheumatological disease that causes spinal stiffness and back pain. It is a systemic disorder that can result in Cc | | 22% pain in other joints and effects on the eyes, heart, lungs, and kidneys. In addition to treatment with NSAIDs (nonsteroidal anti-inflammatory D || 19% medications), sulfasalazine, and physical therapy, tumor necrosis factor inhibitors may be used to treat AS and other rheumatological disorders. Tumor necrosis factor (TNF) inhibitors, including infliximab (Remicade), adalimumab (Humira), and etanercept (Enbrel), reduce inflammation by suppressing the body’s normal immune response. Immune suppression can lead to new infections, including serious fungal infections, or reactivation of a latent or chronic infection, including TB or hepatitis B. These medications also increase the risk of certain", "whyNot": {"a": "Individuals with chronic and progressive debilitating illnesses often become depressed or have a sense of hopelessness. With respect to", "c": "Etanercept is not associated with cardiac arrhythmia.", "d": "Although impaired physical mobility is a concern for any client with AS or another rheumatological disorder, it is important to realize that"}, "keyConcept": "Tumor necrosis factor inhibitors are used to treat several rheumatological disorders, including rheumatoid arthritis, psoriatic arthritis, and AS. They are associated with impairment of the immune system, which increases the risk of opportunistic infections, reactivation of latent infections, including TB, and malignancy, including lymphoma. Increased risk for infection is the primary nursing concern."}, {"id": 11144, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is caring for a client who has had a liver transplant. Mycophenolate mofetil (CellCept) was prescribed. Which of the following will be included in the discharge instruction for this client?", "choices": [{"id": "a", "t": "Aspirin or ibuprofen may be used for pain"}, {"id": "b", "t": "Pregnancy is allowed"}, {"id": "c", "t": "Cholesterol level will rise"}, {"id": "d", "t": "client may shop and socialize with groups"}], "correct": "c", "rationale": "A || 24% Moderate Mycophenolate mofetil (Cellcept) is an immunosuppressive agent, and decreases the proliferation of cells in the immune system. It is used to B | 3\" prevent organ tissue rejection after transplantation. Cellcept is usually administered concurrently with corticosteroids to try to reduce side effects, which can include gastrointestinal bleeding, elevated levels of cholesterol, leukopenia, hypocalcemia, hyperkalemia, diarrhea, ec | 68% headache, fever, and abdominal pain.", "whyNot": {"a": "Aspirin and ibuprofen should be avoided due to effects such as gastrointestinal bleeding.", "b": "Taking CellCept during pregnancy is not allowed because of its teratogenic effect on the growing fetus.", "d": "Socializing, shopping, and other activities that expose the client to crowded places are not recommended due to the client's"}, "keyConcept": "Mycophenolate mofetil (CellCept) is used concurrently with cyclosporine and corticosteroids for prevention of rejection in allogenic renal, hepatic, and cardiac transplantation. The nurse should reinforce the need for lifelong therapy to prevent transplant rejection and should review the symptoms of rejection. The nurse should also emphasize the need to notify the healthcare professional immediately if signs of rejection or infection occur. Signs and symptoms of infection include temperature of 100.5F or higher; cold symptoms that include runny nose, sore throat; flu-like symptoms including upset stomach, stomach pain, vomiting, and diarrhea; earache or headache; pain during urination, frequent urination, white patches in mouth or throat, unexpected bruising or bleeding, cuts, scrapes, or incisions that are red, warm, or have pus draining. The client should avoid contact with individuals with contagious diseases and must avoid vaccinations with live attenuated virus during therapy."}, {"id": 11145, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "Astudent nurse develops hives and redness the first time she uses latex gloves on her initial clinical rotation. Which of the following precautions should be taken?", "choices": [{"id": "a", "t": "When using latex gloves, the student nurse should use oil-based lotion to protect the skin from irritation."}, {"id": "b", "t": "The student nurse should wash hands with an antiseptic such as chlorhexidine after using latex gloves."}, {"id": "c", "t": "Latex items used by the student nurse should be replaced with latex-free items."}, {"id": "d", "t": "Use of reduced-powder latex gloves will prevent a skin reaction when using latex gloves."}], "correct": "c", "rationale": "Hives and redness within minutes of exposure to latex are consistent with Type | allergic reaction to latex. A person who has been identified with a latex sensitivity or allergy should immediately stop using latex gloves and other latex-containing products. It is essential to provide non-latex replacement products and to take precautions to avoid exposure. Type | latex allergy can be more serious than Type 4 allergic reaction, which is a delayed reaction occurring 6-48 hours after exposure. A Type 4 allergic reaction causes a contact dermatitis with dryness, pruritus, fissuring, and cracking of the skin in response to exposure to chemicals used in latex manufacturing. Severe allergic reactions can produce symptoms that range from redness, urticaria, wheezing, and difficulty breathing to anaphylactic shock, sometimes leading to death if not promptly treated. Individuals with latex allergy must avoid all latex products, which are ubiquitous in the healthcare environment. The student nurse should use latex-free gloves. A cart of latex-free items should be designated for use when caring for a client with latex allergy.", "whyNot": {"a": "An individual with latex sensitivity or allergy must avoid all exposure to latex. To avoid development of a latex allergy, avoidance of oil-", "b": "An individual with latex sensitivity or allergy must avoid all exposure to latex. Healthcare workers can reduce the risk of development of", "d": "An individual with latex sensitivity or allergy must avoid all exposure to latex. Inhalation of powder in latex gloves can result in an allergic"}, "keyConcept": "Healthcare workers and individuals who have undergone multiple procedures are at higher risk of latex allergy than the general population. Type | latex allergies cause a range of symptoms, from redness, urticaria, and wheezing to anaphylactic shock. Symptoms of Type | latex allergies usually appear within minutes of exposure, although they can occur hours later. Individuals with symptoms of latex allergy should avoid all contact with latex products."}, {"id": 11146, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is caring for a client with myasthenia gravis. The nurse understands that the risk of respiratory infection is increased in this client due to which of the following?", "choices": [{"id": "a", "t": "Narrowed airways"}, {"id": "b", "t": "Impaired immunity"}, {"id": "c", "t": "Ineffective coughing"}, {"id": "d", "t": "Thickening of secretions"}], "correct": "c", "rationale": "A i 10% Moderate Weakened muscles result in ineffective coughing, which leads to the retaining of secretions, providing a medium for bacterial growth and B | Bn infection.", "whyNot": {"a": "Myasthenia gravis does not result in narrowed airways.", "b": "Myasthenia gravis does not directly lead to impaired immunity.", "d": "Viscosity of secretions is dependent on fluid intake and humidity."}, "keyConcept": "Myasthenia gravis is a chronic autoimmune neuromuscular disease characterized by weakness of the skeletal muscles of the body. In this"}, {"id": 11147, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A client experiencing anaphylaxis after exposure to an allergen is having which of the following types of reaction?", "choices": [{"id": "a", "t": "Typel O B.typell O ctype O p.typelv"}, {"id": "b", "t": "An example of a type I! reaction is ABO blood incompatibility. It is mediated by IgG and IgM and can lead to hemolytic anemia."}, {"id": "c", "t": "Atype Ill hypersensitivity reaction is caused by the formation of antigen-antibody complexes in serum and includes drug fever and"}, {"id": "d", "t": "A type IV hypersensitivity reaction is delayed, often by up to several days. It is mediated by T cells and can include transplant rejection."}], "correct": "a", "rationale": "Atype | allergic or hypersensitivity reaction is mediated by IgE. It occurs when an allergen binds with free IgE, which then binds to basophils and mast cells, causing the release of histamine. The initial reaction may be less severe, but over subsequent exposures, the response can increase. Clinical manifestations may include wheezing, urticaria, and hypotension. Severe anaphylaxis can lead to death. Treatment includes IM epinephrine, antishistamines, steroids, and IV fluid support.", "whyNot": {"b": "An example of a type I! reaction is ABO blood incompatibility. It is mediated by IgG and IgM and can lead to hemolytic anemia.", "c": "Atype Ill hypersensitivity reaction is caused by the formation of antigen-antibody complexes in serum and includes drug fever and", "d": "A type IV hypersensitivity reaction is delayed, often by up to several days. It is mediated by T cells and can include transplant rejection."}, "keyConcept": "Anaphylaxis is a type | allergic reaction that is rapid in onset and may cause death. Clinical manifestations include hives, throat or tongue edema, shortness of breath, vomiting, lightheadedness, and hypotension. Common triggers include venom from insect bites or stings, foods, and medication. Foods are the most common trigger in children, but medications and insect bites and stings are more common in older adults. Anaphylaxis Swelling of the conjuctiva — c— Central nervous system - lightheadedness loss of consciousness eas confusion ~headache ~anxiety Swelling of lips, tongue and/or throat —~ Respiratory Heart and vasculature shortness of breath - fast or slow heart rate heezes or stridor low blood pressure Af - hoarseness pain with swallowing"}, {"id": 11148, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A client with a diagnosis of polyarteritis nodosa asks the nurse for information about this disorder. What information should the nurse include in her response?", "choices": [{"id": "a", "t": "Clients with this disease have an excellent prognosis"}, {"id": "b", "t": "The disorder affects males and females in equal numbers"}, {"id": "c", "t": "The disorder is considered one of hypersensitivity and the exact cause is unknown"}, {"id": "d", "t": "Clients with this disease have problems with only the kidneys and retina of the eyes"}], "correct": "c", "rationale": "An autoimmune response plays a role in the development of polyarteritis,; although drugs and infections may precipitate its development.", "whyNot": {"a": "Most clients with polyarteritis nodosa have a poor prognosis, especially with little treatment.", "b": "The condition is more common in males than in females.", "d": "Clients with this condition can have multiple problems with a number of body systems, including heart attack, kidney failure, and stroke."}, "keyConcept": "Polyarteritis nodosa (PAN), also known as panarteritis nodosa, is a systemic disorder of necrotizing inflammation of blood vessels, known as a vasculitis. It affects small- or medium-sized muscular arteries, usually involving the arteries of the kidneys and other internal organs. Because PAN affects multiple organ systems, symptoms are variable and wide-ranging. It is often associated with chronic hepatitis B infection."}, {"id": 11149, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is providing discharge teaching with a client who has AIDS. Which of the following statements should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"Prevent the spread of infection by cleaning contaminated surfaces with one part bleach and 10 parts water.\""}, {"id": "b", "t": "\"Disinfect clothing using hot water and detergent to clean clothing soiled with vomit or feces.\""}, {"id": "c", "t": "\"Recommendations are to not use reusable household dishes and silverware at meal time.\""}, {"id": "d", "t": "\"Place any type of solid waste from the client in the trash.\""}], "correct": "a", "rationale": "A. The nurse should instruct the client to follow standard precautions, including the use of a 1 part bleach and 10 parts water solution to B a mu disinfect areas that come into contact with blood and other bodily fluids. ° ci 12%", "whyNot": {"b": "The nurse should instruct the client to wash and disinfect clothing soiled with vomit, feces, sputum, urine, or blood with 1 cup of bleach", "c": "The nurse should instruct the client that household dishes and silverware can be used and to wash them in hot water and dishwashing", "d": "The nurse should instruct the client to dispose of any type of bodily waste, such as vomit, stool, or excessive sputum, in the toilet. The"}, "keyConcept": "The nurse should teach clients who have AIDS about the mode of transmission of the disease, including how to implement measures to prevent infection of other individuals, and how to minimize the risk for developing an infection. Clients who have AIDS should not share razors, toothbrushes, or any other devices that have the risk for contamination with blood. Good self-care strategies can help prevent infection, such as using good hygiene, including good mouth and skin care, getting plenty of rest, and maintaining adequate nutrition."}, {"id": 11150, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is performing the admission assessment of a client who has systemic lupus erythematosus (SLE). Which of the following manifestations should the nurse expect?", "choices": [{"id": "a", "t": "Weight gain"}, {"id": "b", "t": "Truncal petechiae"}, {"id": "c", "t": "Systolic murmur"}, {"id": "d", "t": "Alopecia"}], "correct": "d", "rationale": "A Hi 18% Hard Alopecia, or hair loss, is an expected finding in a client who has SLE.", "whyNot": {"a": "Weight loss, not weight gain, is an expected finding in a client who has a new diagnosis of SLE. e@", "b": "A butterfly rash (malar rash) on the face, not truncal petechiae, is an expected finding in a client who has lupus. Petechiae on the lower", "c": "Acardiac friction rub is an expected finding of SLE."}, "keyConcept": "Systemic lupus erythematosus (SLE) is a chronic and progressive systemic inflammatory autoimmune disease of the connective tissue that can affect any body system. The nurse should monitor for skin disorders, including alopecia or hair loss, butterfly rash to the face, and other lesions that resemble scarring."}, {"id": 11151, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is teaching an adolescent about HIV. Which of the following statements by the adolescent indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"You can get HIV by kissing your partner.\""}, {"id": "b", "t": "\"HIV can be caught by inhaling illegal drugs.\""}, {"id": "c", "t": "\"There is a cure for HIV now.\" O D.\" A pregnant woman can pass HIV to her unborn baby.\""}, {"id": "d", "t": "al 4% Easy Transmission of HIV to a fetus is the most common cause of HIV infections in children under the age of 13."}], "correct": "d", "rationale": "al 4% Easy Transmission of HIV to a fetus is the most common cause of HIV infections in children under the age of 13. a | 10%", "whyNot": {"a": "HIVis transmitted via blood, semen, vaginal secretions, and breast milk. There is no evidence that casual contact, such as kissing, spreads e@", "b": "HIV is transmitted via blood, semen, vaginal secretions, and breast milk. People who use IV substances are at greatest risk for transmitting", "c": "There is no cure for HIV. Antiretroviral therapy slows the progression of HIV but does not cure the disease."}, "keyConcept": "HIV, also known as human immunodeficiency virus, is transmitted through contact with the blood or body fluids of an infected individual. The most common route of exposure to HIV in adolescents occurs during unprotected sexual encounters. An additional high-risk behavior that can transmit the virus is the use of recreational intravenous drugs. The average time frame from exposure to disease development is 10 years. During pregnancy, HIV can be transmitted to the fetus. There is no cure for HIV, only measures to lessen the severity of symptoms. Some of the common initial manifestations include fever, chills, muscle aches, swollen lymph nodes, weight loss, decreased appetite, oral candidiasis, failure to thrive, and diarrhea. Treatment for HIV includes the administration of antiretroviral therapy, childhood immunizations, nutritional supplements, avoiding individuals who are sick, promptly calling the provider for acute illness, and administering a non-aspirin analgesic for pain relief."}, {"id": 11152, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is preparing to administer immune globulin to a client who has been exposed to hepatitis B. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"This medication will provide a permanent immunity to hepatitis B.\""}, {"id": "b", "t": "\"This medication involves two injections that are administered over several months.\""}, {"id": "c", "t": "\"This medication provides an immune response more quickly than your body can produce it.\""}, {"id": "d", "t": "\"This medication contains an attenuated virus to help your body create antibodies.\""}], "correct": "c", "rationale": "-artificial immunity and contains antibodies to help protect against hepatitis B for several weeks or B | ue months. °", "whyNot": {"a": "This medication produces a passive-artificial immunity that lasts only several weeks or months.", "b": "This medication is given one time after exposure to hepatitis B.", "d": "This medication contains antibodies, not an attenuated virus."}, "keyConcept": "Hepatitis is the inflammation of the liver cells. Hepatitis B is transmitted through contact with infected blood (e.g., unprotected sexual intercourse, IV drug use, needle sticks, contaminated blood transfusions). The nurse should know that treatment includes hepatitis B vaccinations for prevention and hepatitis B immune globulin (HBIG) to provide passive immunity after exposure. The vaccination series consists of three injections over a 6-month period. The immune globulin is administered as a onetime dose."}, {"id": 11153, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse ina clinic is interviewing a client who is scheduled for a scan using contrast dye. During which of the following phases of the nursing process should the nurse ask about a client's potential allergies?", "choices": [{"id": "a", "t": "Planning"}, {"id": "b", "t": "Evaluation"}, {"id": "c", "t": "Assessment"}, {"id": "d", "t": "Implementation"}], "correct": "c", "rationale": "All 11% Easy Assessment is the systematic and deliberate collection of data about a client that will determine the client's current and past health and B | 3\" functional status, as well as past and present coping patterns. During the assessment phase, data is validated to ensure a complete database, which includes conducting a review of possible allergies. ec | 85% p | 1%", "whyNot": {"a": "The planning phase is when client care goals are set, desired outcomes are determined, and appropriate nursing actions are identified.", "b": "The evaluation phase is when the nurse determines if goals and expected outcomes were achieved.", "d": "The implementation phase includes performing nursing actions that were identified during the planning phase."}, "keyConcept": "Nurses are responsible for having the knowledge to navigate the nursing process. Nurses should be able to identify each step of the process and what each step entails. Nurses are responsible for implementing the process in daily activities, including data collection from a client."}, {"id": 11154, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is teaching a client who has a new prescription for oral dimenhydrinate for motion sickness. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| might experience some dizziness while taking this medication.\" O B. \"It is not unusual to have my blood pressure increase while taking this medication.\" O C. \"I will take this medication at least 24 hours before | plan to travel.\" O D.\"I can expect to have an increase in salivation while taking this medication.\"", "choices": [{"id": "a", "t": "The client can experience drowsiness and dizziness while taking this medication and should avoid activities that require alertness, such as B driving or operating machinery."}, {"id": "b", "t": "Dimenhydrinate can cause hypotension, not hypertension"}, {"id": "c", "t": "The client should take the medication at least 30 min and preferably 1 to 2 hr prior to traveling."}, {"id": "d", "t": "Dimenhydrinate can cause anticholinergic effects, such as dry mouth and blurred vision."}], "correct": "a", "rationale": "The client can experience drowsiness and dizziness while taking this medication and should avoid activities that require alertness, such as B driving or operating machinery. (see chart for potential adverse effects of dimenhydrinate) | ci Central nervous system Drowsiness D | (CNS) Dizziness Headache Eye, ear, nose, throat Blurred vision (EENT) Tinnitus Cardiovascular (CV) Hypotension Palpitations Gastrointestinal (GI) Anorexia Constipation Dry mouth Genitourinary (GU) Dysuria Frequency Dermatological (DERM) Photosensitivity", "whyNot": {"b": "Dimenhydrinate can cause hypotension, not hypertension", "c": "The client should take the medication at least 30 min and preferably 1 to 2 hr prior to traveling.", "d": "Dimenhydrinate can cause anticholinergic effects, such as dry mouth and blurred vision."}, "keyConcept": "It is the nurse's responsibility to educate clients regarding the medications they are prescribed. This includes ensuring the client is aware of potential adverse effects and what to expect while taking the medication."}, {"id": 11155, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A client has systemic lupus erythematosus (SLE). Which skin manifestation is associated specifically with this disorder?", "choices": [{"id": "a", "t": "Pruritus"}, {"id": "b", "t": "Jaundice"}, {"id": "c", "t": "Butterfly-shaped rash"}, {"id": "d", "t": "Hives"}], "correct": "c", "rationale": "Correct Answer: C. Butterfly-shaped rash SLE is associated with a malar rash in up to 50% of individuals with lupus. The malar rash characteristic of cutaneous lupus is a red rash that can be flat or raised, forming a butterfly shape across the nose and cheeks. It may be related to exposure to ultraviolet light in sunlight and is often worse during a flare of the disease. Recurrent aphthous oral ulcers are also a common manifestation of lupus, which is an autoimmune disorder characterized by the production of autoantibodies that attack the cells and tissues of the body during periods of exacerbation or flare. These periods are interspersed with periods of disease remission.", "whyNot": {"a": "Pruritus may occur with SLE, but it is not specific and may occur in many other conditions.", "b": "Jaundice occurs in advanced liver disease.", "d": "Urticaria may occur. Hives are primarily associated with allergic reactions."}, "keyConcept": "Systemic lupus erythematosus (SLE) is a chronic inflammatory characterized by immune system abnormalities. It affects multiple body systems, including skin, joints, serous membranes (pericardium, pleura), renal, neurologic, and hematologic systems. Clinical manifestations vary, but the disease is characterized by periods of alternating exacerbation and remission."}, {"id": 11156, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A client has systemic lupus erythematosus (SLE). Which skin manifestation is associated specifically with this disorder?", "choices": [{"id": "a", "t": "Pruritus"}, {"id": "b", "t": "Jaundice"}, {"id": "c", "t": "Butterfly-shaped rash"}, {"id": "d", "t": "Hives eck Answer"}], "correct": "c", "rationale": "Correct Answer: C. Butterfly-shaped rash A B SLE is associated with a malar rash in up to 50% of individuals with lupus. The malar rash characteristic of cutaneous lupus is a red rash that c FY can be flat or raised, forming a butterfly shape across the nose and cheeks. It may be related to exposure to ultraviolet light in sunlight and is my | often worse during a flare of the disease. Recurrent aphthous oral ulcers are also a common manifestation of lupus, which is an autoimmune disorder characterized by the production of autoantibodies that attack the cells and tissues of the body during periods of exacerbation or flare. These periods are interspersed with periods of disease remission.", "whyNot": {"a": "Pruritus may occur with SLE, but it is not specific and may occur in many other conditions.", "b": "Jaundice occurs in advanced liver disease.", "d": "Urticaria may occur. Hives are primarily associated with allergic reactions."}, "keyConcept": "Systemic lupus erythematosus (SLE) is a chronic inflammatory characterized by immune system abnormalities. It affects multiple body systems, including skin, joints, serous membranes (pericardium, pleura), renal, neurologic, and hematologic systems. Clinical manifestations vary, but the disease is characterized by periods of alternating exacerbation and remission."}, {"id": 11157, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is assessing a client with Crohn’s disease who is being considered for treatment with infliximab. Which of the following statements by the client indicates a need for further investigation?", "choices": [{"id": "a", "t": "“ had a negative TB skin test last month.”"}, {"id": "b", "t": "“I had a series of hepatitis B vaccines when was in nursing school.”"}, {"id": "c", "t": "“lam taking an antibiotic for sinusitis.”"}, {"id": "d", "t": "“I take vitamin B supplements.”"}], "correct": "c", "rationale": "Tumor necrosis factor inhibitors are used to treat inflammatory disorders, including inflammatory bowel disease and rheumatoid arthritis. TNF is important to the body's immune response, so clients who are treated with TNF inhibitors are at increased risk of serious infections, including reactivation of latent Tb and herpes zoster virus.", "whyNot": {"a": "Before beginning a TNF inhibitor, it is important to assess the client for latent tuberculosis. A positive skin test would require treatment", "b": "Reactivation of hepatitis B can occur in chronic carriers of the virus, but the vaccine should have conferred immunity, so it is not a", "d": "Malabsorption is associated with Crohn’s disease. Clients with Crohn's disease may have vitamin deficiencies requiring supplementation"}, "keyConcept": "Tumor necrosis factor inhibitors are used to treat inflammatory disorders, including inflammatory bowel disease and rheumatoid arthritis. TNF is important to the body's immune response, so clients who are treated with TNF inhibitors are at increased risk of serious infections, including reactivation of latent Tb and herpes zoster virus."}, {"id": 11158, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "and tinnitus (ringing in the ears.). What is the most appropriate intervention?", "choices": [{"id": "a", "t": "This is a normal reaction and the nurse should reassure the client and continue the infusion."}, {"id": "b", "t": "Stop the infusion and disconnect the IV tubing."}, {"id": "c", "t": "Check the doctor’s orders for an antiemetic"}, {"id": "d", "t": "Update the primary care provider"}], "correct": "b", "rationale": "al 3% Easy The symptoms the client is complaining of a serious reaction to the medication. Stopping the medication and detaching the tubing prevents further exposure to the potential allergen. The provider needs to be alerted that the client is not tolerating the prescribed medication and OB as ehh may be having an allergic reaction. © | 2% oi 5%", "whyNot": {"a": "The symptoms the client is experiencing could be signs of a serious medication reaction. A thick tongue can be a symptom of angioedema", "c": "The client is not complaining of nausea. An antiemetic is not required at this time nor would it be considered the most important nursing", "d": "The nurse should first stop the infusion and disconnect the IV tubing, then assess the client before notifying the healthcare provider."}, "keyConcept": "Allinfusion reactions involve the immune system. Anaphylactic reactions are allergic in nature, mediated by immunoglobulin E (IgE). Other hypersensitivity reactions may be anaphylactoid reactions, which are not true allergic reactions. Anaphylactoid reactions are not mediated by IgE. The clinical manifestations are the same and must be promptly and accurately assessed and managed to avoid serious adverse events, including death."}, {"id": 11159, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "should the nurse make? O A.\"Pressing on the duct will prevent the medication from burning or stinging.\" O B. \"Pressing on the duct will prevent the medication from being absorbed into the body.\" O C. \"Pressing on the duct will prevent infection.\" O D. \"Pressing on the duct will prevent dry eye.\"", "choices": [{"id": "a", "t": "Hi 14%"}, {"id": "b", "t": "A Hi 14% Moderate Pressing on the nasolacrimal duct blocks the lacrimal punctum and prevents systemic absorption of the medication, which can cause OB a Ta08 adverse cardiovascular effects, or bronchospasm."}, {"id": "c", "t": "Pressing on the nasolacrimal duct will not prevent infection. The client should be taught to wash hands, to avoid touching the tip of the"}, {"id": "d", "t": "Pressing on the duct will not prevent dry eye, as it is a common side effect of beta-adrenergic blockers."}], "correct": "b", "rationale": "A Hi 14% Moderate Pressing on the nasolacrimal duct blocks the lacrimal punctum and prevents systemic absorption of the medication, which can cause OB a Ta08 adverse cardiovascular effects, or bronchospasm. c] 3% Adverse effects of ophthalmic timolol include ® r 11% Local effects Transient stinging a Blurred vision Photophobia FH Ory eye 5 Conjunctivitis a ‘Systemic Bradycardia g AV heart block s Bronchospasm 5 <", "whyNot": {"a": "Burning or stinging is a common side effect of the beta-adrenergic eye drops.", "c": "Pressing on the nasolacrimal duct will not prevent infection. The client should be taught to wash hands, to avoid touching the tip of the", "d": "Pressing on the duct will not prevent dry eye, as it is a common side effect of beta-adrenergic blockers."}, "keyConcept": "Systemic absorption of a beta blocker can cause systemic effects, especially in the cardiac and respiratory systems. One drop of 5% timolol in each eye is the equivalent of 10 mg of timolol by mouth. Caution should be taken with clients who are taking a beta-blocker orally as well. The nurse should assess the client's pulse prior to the administration of timolol."}, {"id": 11160, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is planning an educational session about HIV for newly licensed nurses. Which of the following information should the nurse include about HIV transmission?", "choices": [{"id": "a", "t": "Primarily transmitted through casual contact."}, {"id": "b", "t": "Primarily transmitted through a wound caused by an accident."}, {"id": "c", "t": "Primarily transmitted through direct contact with infected bodily fluids."}, {"id": "d", "t": "Primarily transmitted through eating raw meat."}], "correct": "c", "rationale": "The nurse should inform the newly licensed nurses that HIV is transmitted through direct contact with infected blood, seminal fluid, vaginal secretions, amniotic fluid, breast milk, urine, saliva, tears, and other bodily fluids.", "whyNot": {"a": "HIVis primarily transmitted by infected bodily fluids coming into contact with mucous membranes or skin that is not intact, not by casual", "b": "HIV is primarily transmitted by infected fluids coming into contact with mucous membranes or skin that is not intact, not by a wound", "d": "HIVis primarily transmitted by infected bodily fluids coming into contact with mucous membranes or skin that is not intact, not by eating"}, "keyConcept": "Health care workers can take the following actions to help prevent the transmission of HIV: © Follow strict standard precautions. © Cover an open lesion or sore when providing direct client care. © Disinfect and sterilize reusable equipment. © Wear gloves when in contact with mucous membranes."}, {"id": 11161, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is preparing to administer a varicella immunization to a client. Which of the following questions should the nurse ask? O A.\"Do you have an allergy to eggs?\" O B. \"Are you allergic to baker's yeast?\" O C. \"Are you pregnant?\" O D.\"Do you have a history of Guillain-Barré syndrome?\"", "choices": [{"id": "a", "t": "An allergy to eggs should be reviewed if the client is to receive an influenza immunization."}, {"id": "b", "t": "An allergy to yeast should be reviewed if the client is to receive HPV immunization."}, {"id": "c", "t": "The nurse should ask whether the client is pregnant because the varicella immunization is contraindicated during pregnancy."}, {"id": "d", "t": "Guillain-Barré syndrome is a contraindication for receiving the influenza vaccine."}], "correct": "c", "rationale": "The nurse should ask whether the client is pregnant because the varicella immunization is contraindicated during pregnancy.", "whyNot": {"a": "An allergy to eggs should be reviewed if the client is to receive an influenza immunization.", "b": "An allergy to yeast should be reviewed if the client is to receive HPV immunization.", "d": "Guillain-Barré syndrome is a contraindication for receiving the influenza vaccine."}, "keyConcept": "Varicella vaccine is administered to prevent infection by the chicken pox (varicella) virus. The nurse should avoid administering this vaccination to anyone who is pregnant or who might be pregnant to prevent fetal harm."}, {"id": 11162, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is caring for a client who develops hives after a new antibiotic is administered. Which of the following is the mechanism by which diphenhydramine (Benadryl) reduces the client's allergic reaction?", "choices": [{"id": "a", "t": "Metabolizes histamine and inhibits the release of substances that cause intense itching"}, {"id": "b", "t": "Competes with histamine for receptors and interferes with vasodilation"}, {"id": "c", "t": "Dilates capillaries within the tissues"}, {"id": "d", "t": "Destroys histamine in the tissues to stop the allergic response."}], "correct": "b", "rationale": "A || 24% Moderate Histamines are released in an allergic response. Benadryl and other antihistamines compete with histamines at receptor sites. This reduces OB a ae: fo the effect of the histamines, and reducing vasodilation, pruritus, and inflammation associated with the allergic response. I © 3%", "whyNot": {"a": "Diphenhydramine does not metabolize histamine.", "c": "Histamines dilate the capillaries.", "d": "Diphenhydramine does not destroy histamines; it competes with histamines at receptor sites."}, "keyConcept": "Diphenhydramine is an antihistamine used to treat allergies. It is a histamine antagonist and reduces the vasodilation caused by histamines in allergic response. It is also used to treat insomnia, symptoms of the common cold, tremor in parkinsonism, and nausea. Diphenhydramine can be administered by oral, intravenous, and intramuscular routes. It is used in addition to epinephrine for treatment of anaphylaxis. The most common side effect is sedation."}, {"id": 11163, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "The nurse is assessing a client on antibiotic therapy. Examination reveals swollen lips and tongue. What may have caused the client's current condition?", "choices": [{"id": "a", "t": "Response to antigen"}, {"id": "b", "t": "Low dosage of antibiotic"}, {"id": "c", "t": "Noncompliance with the antibiotic schedule"}, {"id": "d", "t": "Polypharmacy"}], "correct": "a", "rationale": "Antibiotics such as penicillin, cephalosporins, amphotericin B, and nitrofurantoin may trigger hypersensitivity reactions. The chemical . The nurse must assess for allergies before drug administration. c | 5% of 9% Acommon sign of hypersensitivity reaction is angioedema. Angioedema is characterized by swelling of the lips and tongue. Angioedema may occur in isolation, accompanied by urticaria, or as a component of anaphylaxis, which is due to a hypersensitivity reaction. Symptoms suggestive of a hypersensitivity reaction or anaphylaxis include urticaria, dyspnea, chest pain, and shock. Polypharmacy, low dosage, and non-compliance to the antibiotic treatment do not cause angioedema.", "whyNot": {"b": "The client is experiencing angioedema from an allergic reaction to the antibiotic, not from a low dose of the antibiotic.", "c": "The client is experiencing angioedema from an allergic reaction to the antibiotic, not from non-compliance with the antibiotic schedule.", "d": "The client is experiencing angioedema from an allergic reaction to the antibiotic, not from polypharmacy."}, "keyConcept": "Angioedema, swelling of the lips and face, can occur as a result of an allergic reaction to a medication and presents a serious adverse event. Immediate action is needed to prevent further swelling and a compromised airway. The allergic reaction should be recorded as a medication allergy and this medication should not be given in the future."}, {"id": 11164, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is providing discharge teaching for a client who has rheumatoid arthritis. Which of the following statements should the nurse include in the teaching? O A.\"You might experience joint stiffness when you get out of bed.\" O B. \"You might experience abdominal pain.\" O C. \"You might experience weight gain.\" O D. \"You might experience low blood pressure.\"", "choices": [{"id": "a", "t": "The nurse should include in the teaching that a client who has rheumatoid arthritis might experience stiffness in the joints upon rising from bed."}, {"id": "b", "t": "A client who has rheumatoid arthritis might experience pleuritic pain upon inspiration, not abdominal pain."}, {"id": "c", "t": "A client who has rheumatoid arthritis might experience weight loss, not weight gain."}, {"id": "d", "t": "Rheumatoid arthritis does not cause low blood pressure."}], "correct": "a", "rationale": "The nurse should include in the teaching that a client who has rheumatoid arthritis might experience stiffness in the joints upon rising from bed.", "whyNot": {"b": "A client who has rheumatoid arthritis might experience pleuritic pain upon inspiration, not abdominal pain.", "c": "A client who has rheumatoid arthritis might experience weight loss, not weight gain.", "d": "Rheumatoid arthritis does not cause low blood pressure."}, "keyConcept": "Rheumatoid arthritis (RA) is a chronic and progressive systemic inflammatory autoimmune disease of the synovial joints. The nurse should recognize that the manifestations of RA can include decreased range of motion and stiffness of the joints, weight loss and anorexia, fatigue, weakness, fever, and chronic pain."}, {"id": 11165, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is teaching about oral care to a client who is immunocompromised. Which of the following instructions should the nurse provide?", "choices": [{"id": "a", "t": "\"Rinse with commercial mouthwash 4 times daily.\""}, {"id": "b", "t": "\"Use a medium-bristled toothbrush when brushing your teeth.\""}, {"id": "c", "t": "\"Use lemon-glycerin swabs to moisturize your mouth.\""}, {"id": "d", "t": "\"Use a sodium bicarbonate toothpaste when brushing your teeth.\""}], "correct": "d", "rationale": "im 17% Hard The nurse should instruct the client to use a sodium bicarbonate toothpaste, or sodium bicarbonate diluted with water, when brushing the B | oom fo teeth. This sodium bicarbonate will not irritate the mucosa and will dissolve thick oral debris. c i 25%", "whyNot": {"a": "The nurse should instruct the client to rinse with 30 mL of normal saline 4 times daily. If needed, rinsing can be increased to every 2 hr.", "b": "The nurse should instruct the client to use a soft-bristled toothbrush when brushing the teeth to avoid further irritation of the oral °", "c": "The nurse should instruct the client to avoid using lemon-glycerin swabs for moisturizing the mouth because they can cause further a"}, "keyConcept": "Clients who are immunocompromised, debilitated, or who are undergoing cancer treatments can develop stomatitis. Care should be taken to prevent further irritation of the oral mucosa. The nurse should instruct the client that if flossing is not contraindicated, it should be performed gently to prevent the gums from bleeding. If brushing causes too much irritation, the nurse should instruct the client to clean the teeth, tongue, and oral mucosa with an oral swab soaked in normal saline. If the client is experiencing excessive pain from the stomatitis, the provider might need to prescribe a topical or oral analgesic."}, {"id": 11166, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "Which phase of primary intention healing is accurately paired with its sign or symptom?", "choices": [{"id": "a", "t": "First stage: migration of fibroblasts and regeneration of epithelium."}, {"id": "b", "t": "Second stage: acute inflammation with redness, warmth, and edema."}, {"id": "c", "t": "Third stage: formation of scar tissue"}, {"id": "d", "t": "Fourth stage: serous drainage"}], "correct": "c", "rationale": "im 17% Hard The third stage of primary intention healing is characterized by the formation of mature scar tissue to replace the damaged tissue. The first B a Baon stage of primary intention healing is marked by acute inflammation with heat, redness, edema, pain, and tenderness. The second stage of the inflammatory process is characterized by regeneration of surface epithelium. ec | 44% p| 2%", "whyNot": {"a": "The first stage of primary intention healing is characterized by migration of white blood cells, alignment of incision edges, and filling in", "b": "The second stage of primary intention healing is characterized by regeneration of surface epithelium.", "d": "There are three stages of primary intention healing."}, "keyConcept": "Healing by primary intention has three phases: initial phase, granulation, and maturation. The initial phase is marked by alignment of incision edges; blood filling the incision to form a matrix for migration of white blood cells; and an acute inflammatory reaction. This phase lasts 3-5 days. The granulation phase includes migration of fibroblasts, which secrete collagen and regeneration of surface epithelium. During this phase, the wound is vascular and pink. The maturation phase is the third phase, characterized by the formation of a mature scar. This phase begins about 7 days after injury and can last for months to years."}, {"id": 11167, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A client has been prescribed fexofenadine for the treatment of severe allergies. Which condition should the nurse counsel the client to look for as a possible side effect?", "choices": [{"id": "a", "t": "Skin rash"}, {"id": "b", "t": "Joint pain"}, {"id": "c", "t": "Drowsiness"}, {"id": "d", "t": "Sleep difficulties"}], "correct": "c", "rationale": "A Hi 11% Moderate Fexofenadine is used to treat seasonal allergies. It is an antihistamine and one of the most common side effects is drowsiness. The client B ] a should be counseled about the effects of using this medication before performing certain activities, such as driving.", "whyNot": {"a": "Fexofenadine is used for allergies; it typically does not result in skin rash.", "b": "Joint pain is not a common side effect associated with fexofenadine.", "d": "Fexofenadine would more likely cause drowsiness, as opposed to sleep difficulties."}, "keyConcept": "Fexofenadine is an antihistamine used in remedies for allergies and in cough and cold remedies. This class of medication antagonizes the effects of histamine at peripheral histamine 1 (H1) receptors, including pruritus and urticaria. Antihistamines have a drying effect on the nasal mucosa. Therapeutic effects include a decrease in sneezing, rhinorrhea, itchy eyes, nose, and throat associated with seasonal allergies and decreased urticaria. Adverse effects include drowsiness, fatigue, dyspepsia, and dysmenorrhea"}, {"id": 11168, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is providing teaching to a client who has systemic lupus erythematosus (SLE). Which of the following statements by the client indicates an understanding of the teaching? O A.\"| should limit my time to 10 minutes in the tanning bed.\" O B. \"I will apply powder to any skin rash.\" O C. \"I should use a mild hair shampoo.\" O D. \"I will inspect my skin weekly for rashes or sores.\"", "choices": [{"id": "a", "t": "A client who has SLE should avoid the use of tanning beds as well as prolonged sun exposure."}, {"id": "b", "t": "A client who has SLE should apply steroid-based creams to skin rashes, not a powder."}, {"id": "c", "t": "A client who has SLE should use a mild hair shampoo that does not irritate the scalp."}, {"id": "d", "t": "A client who has SLE should inspect her skin daily for any open areas or rashes."}], "correct": "c", "rationale": "A client who has SLE should use a mild hair shampoo that does not irritate the scalp.", "whyNot": {"a": "A client who has SLE should avoid the use of tanning beds as well as prolonged sun exposure.", "b": "A client who has SLE should apply steroid-based creams to skin rashes, not a powder.", "d": "A client who has SLE should inspect her skin daily for any open areas or rashes."}, "keyConcept": "Systemic lupus erythematosus (SLE) is a chronic and progressive systemic inflammatory autoimmune disease of the connective tissue that can affect any body system. The nurse should provide teaching on maintaining skin integrity, including methods to avoid sun exposure, applying moisturizers, use of mild soaps and shampoos, and performing daily skin checks to identify sores or rashes."}, {"id": 11169, "cat": "NCLEX 21-IMMUNE SYSTEM", "stem": "A nurse is providing teaching for a client who has HIV and is having difficulty gaining weight. Which of the following statements by the client indicates an understanding of the teaching? O A.\" will choose a diet high in fat.\" O B. \"I will be sure to eat three large meals daily.\" O C. \"I will drink up to 1 liter of liquid each day.\" O D.\"I will add foods that are high in protein to my diet.\"", "choices": [{"id": "a", "t": "The client should be instructed to avoid high-fat foods to gain weight because fat intolerance, which causes flatus, bloating, and diarrhea,"}, {"id": "b", "t": "The client should be instructed that small frequent meals (e.g., six small meals daily) are better tolerated than three large meals."}, {"id": "c", "t": "The client should be instructed to drink 2 to 3 L of liquids daily to maintain hydration status."}, {"id": "d", "t": "all 9% Easy The client should be taught to eat high-protein, high-calorie foods daily since this is the best way for the client to gain weight and maintain B | 3\" health."}], "correct": "d", "rationale": "all 9% Easy The client should be taught to eat high-protein, high-calorie foods daily since this is the best way for the client to gain weight and maintain B | 3\" health. c | 1%", "whyNot": {"a": "The client should be instructed to avoid high-fat foods to gain weight because fat intolerance, which causes flatus, bloating, and diarrhea,", "b": "The client should be instructed that small frequent meals (e.g., six small meals daily) are better tolerated than three large meals.", "c": "The client should be instructed to drink 2 to 3 L of liquids daily to maintain hydration status."}, "keyConcept": "Human immunodeficiency virus (HIV) is an infection that invades and attacks the immune system. The nurse should know that clients who have HIV or AIDS experience inadequate nutrition due to fatigue, loss of appetite, or gastrointestinal disturbances. The nurse should inform the client to eat several small meals, choose foods that are high in calories and protein, and drink at least 2 to 3 liters of fluids each day."}], "nclex_24_leadership_mgt": [{"id": 11170, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "appropriate initial intervention? O A. Get the clients to a safe area immediately O B. Pull the fire alarm O C. Yell “Fire”! loudly so staff and clients can hear O D. Find the nearest fire extinguisher to extinguish the fire O E. Call the fire department to report the fire", "choices": [{"id": "a", "t": "Get the clients to a safe area immediately"}, {"id": "b", "t": "Pull the fire alarm"}, {"id": "c", "t": "Yell “Fire”! loudly so staff and clients can hear"}, {"id": "d", "t": "Find the nearest fire extinguisher to extinguish the fire"}, {"id": "e", "t": "Call the fire department to report the fire"}], "correct": "a", "rationale": "o; ox The nurse's first priority is to remove those in immediate danger. Remember RACE: rescue the people in danger, pull the fire alarm, contain B I a the fire, and extinguish the fire, if it is safe to do so. c | 1%", "whyNot": {"b": "The nurse should pull the fire alarm after first ensuring that the clients in danger were removed from the area. E 0%", "c": "It is inappropriate to yell “Fire!” as this could cause people to panic. Instead, the nurse should be calm and organized, providing clear and", "d": "The nurse should attempt to extinguish the fire only after people are removed from the danger area, the fire alarm has been released, and", "e": "The priority is to move anyone in immediate danger. In many cases, the fire department is called automatically when a fire breaks out."}, "keyConcept": "R.A.C.E: is an acronym that the nurse should use to remember priority interventions in case of fire. It stands for RESCUE, ALARM, CONFINE, EXTINGUISH/EVACUATE. Another acronym that used to remember the process of discharging a fire extinguisher is P.A.S.S., which refers to PULL, AIM, SQUEEZE, SWEEP."}, {"id": 11171, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who is newly diagnosed with metastatic lung cancer and declines treatment. Which of the following responses would indicate paternalism?", "choices": [{"id": "a", "t": "understand that this diagnosis might be difficult for you. Would you like to talk about it?"}, {"id": "b", "t": "You should undergo the treatment recommended by your healthcare provider."}, {"id": "c", "t": "Did you have any questions or concerns about the treatment?"}, {"id": "d", "t": "What does your family think of your decision?"}], "correct": "b", "rationale": "mw | 27% ~~ Hard A paternalistic statement suggests that the client needs someone else - the healthcare provider - to make his/her decisions, suggesting that OB a a a competent client doesn’t have the ability to understand the disease or treatment plan and should yield to the provider. Although the provider may have greater medical knowledge, the client has a greater knowledge of his/her values, needs, and fears. c i 8% om 13% Paternalistic attitudes promote the client’s dependence on the healthcare provider for medical decision making. It also reflects an underlying assumption that the client and healthcare provider share the same values. Paternalism often places a higher value on technology than client needs and values.", "whyNot": {"a": "This statement does not indicate paternalism. It is a therapeutic response that shows acceptance and provides an opportunity for the", "c": "This question does not reflect a paternalistic attitude. It offers the opportunity for the client to open a discussion of any unresolved issues.", "d": "This question does not reflect paternalism, but this is a close-ended question that may put the client on the defensive."}, "keyConcept": "A paternalistic attitude reflects a belief that the client is dependent and the healthcare provider’s authority should be the dominant factor in healthcare decision-making. Paternalism also reflects an assumption that the client shares the same values as the healthcare provider."}, {"id": 11172, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse assigned a task to an assistive personnel (AP) who did not perform the task within the predetermined timeframe. Which of the following statements should the nurse make to the AP? O A.\"You should have asked another AP to complete the task for you.\" O B.\"I have to let the director of nursing know about the situation.\" O C. \"I need you to tell me why you did not complete your assigned task.\" O D.\"I have completed the task | assigned you, but next time | will expect you to complete it yourself.\"", "choices": [{"id": "a", "t": "The AP cannot delegate an assigned task to another AP. The nurse who assigned the task maintains accountability for the task and should"}, {"id": "b", "t": "Delaying conflict resolution or involving superiors without first attempting to resolve the situation can create adversarial feelings. A"}, {"id": "c", "t": "| 2% Easy The nurse should determine why the AP did not complete the assigned task."}, {"id": "d", "t": "The nurse should not complete the task in an attempt to avoid confrontation. This does not promote independence or responsibility in the a"}], "correct": "c", "rationale": "| 2% Easy The nurse should determine why the AP did not complete the assigned task. It is then the responsibility of the nurse to work to remove the B I a barriers that caused the task to not be completed as assigned.", "whyNot": {"a": "The AP cannot delegate an assigned task to another AP. The nurse who assigned the task maintains accountability for the task and should", "b": "Delaying conflict resolution or involving superiors without first attempting to resolve the situation can create adversarial feelings. A", "d": "The nurse should not complete the task in an attempt to avoid confrontation. This does not promote independence or responsibility in the a"}, "keyConcept": "It is important for the nurse to understand why a delegated task is not completed. There are many reasons this can occur, and the nurse should attempt to see the task from the perspective of the delegatee. The nurse can then attempt to remove the barriers preventing the delegatee from completing the task."}, {"id": 11173, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "following is the most appropriate immediate response?", "choices": [{"id": "a", "t": "The nurse should notify the healthcare provider."}, {"id": "b", "t": "The nurse should complete an incident report."}, {"id": "c", "t": "The nurse should contact the nurse who administered the medication."}, {"id": "d", "t": "The nurse should dispose of the needle in the sharps container."}], "correct": "d", "rationale": "When failure to follow correct procedures to dispose of sharps and hazardous waste is discovered, the priority intervention is to correctly dispose of the item(s), to prevent injury to the client and others in the healthcare facility. An incident report is only necessary if the lapse resulted in harm or injury to the client or others.", "whyNot": {"a": "It is not necessary to notify the healthcare provider. @D FY 90%", "b": "It is only necessary to complete an incident report if an incident has resulted in harm to the client or others in the facility.", "c": "Although the nurse should notify the nurse who administered the medication, the primary concern is proper disposal of the sharp."}, "keyConcept": "When failure to follow correct procedures to dispose of sharps and hazardous waste is discovered, the priority intervention is to correctly dispose of the item(s), to prevent injury to the client and others in the healthcare facility. An incident report is only necessary if the lapse resulted in harm or injury to the client or others."}, {"id": 11174, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who continually makes sexually suggestive comments to the nurse and other staff. How should the nurse handle this situation?", "choices": [{"id": "a", "t": "Ignore the client, whose behavior will stop if it does not elicit a reaction from you"}, {"id": "b", "t": "Report the client's behavior to the client's healthcare provider."}, {"id": "c", "t": "Tell the client that the behavior is inappropriate and will not be tolerated"}, {"id": "d", "t": "Avoid going into the client’s room unless it is an emergency situation"}], "correct": "c", "rationale": "| 2% Easy Respectfully informing the client that the behavior will not be tolerated will let the client know that the nurse is not going to tolerate the B | a abuse. Most facilities have a zero tolerance for abuse, whether verbal, physical, or sexual in nature. The nurse should firmly inform the client that such behavior is not welcome and will not be permitted to continue. ec Fe 91% p | 1%", "whyNot": {"a": "Ignoring the situation will not be helpful. It may encourage the client to escalate the behavior rather than stop it.", "b": "The nurse should be able to manage this behavior independently by addressing the behavior with the client. If the behavior persists, the", "d": "Avoiding the client’s room may reinforce the behavior. The nurse has an obligation to care for the client, regardless of how distasteful the"}, "keyConcept": "The Employment Opportunity Commission (EEOC) defines sexual harassment as “unwelcome sexual advances, requests for sexual favors, and other verbal or physical conduct of a sexual nature...when submission to or rejection of this conduct explicitly or implicitly affects an individual's employment; unreasonably interferes with an individual's work performance; or creates an intimidating, hostile, or offensive work environment.” Incidents of sexual harassment in the workplace should not be tolerated. If the behavior does not stop, the nurse should report the behavior to the nursing supervisor."}, {"id": 11175, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse and an unlicensed assistive personnel (UAP) are working together to care for a group of clients on the pediatric unit. Which of the following actions should the nurse request the UAP perform first?", "choices": [{"id": "a", "t": "Collect a clean-catch urine specimen from a school-age child."}, {"id": "b", "t": "Engage a toddler in play."}, {"id": "c", "t": "Wash the hair of an adolescent who reports extreme fatigue and is scheduled for radiation therapy."}, {"id": "d", "t": "Ensure the elbow restraint is in place for an infant who is postoperative following surgical correction of a cleft palate."}, {"id": "e", "t": "Option E (text recovered from OCR is incomplete)."}], "correct": "e", "rationale": "D. palate. mM | 18% Moderate 8 11% An infant who is postoperative from a surgical correction of a cleft palate is at risk for damage to the suture line, and an elbow immobilizer decreases the risk for this complication. Therefore, this is the priority action the nurse should have the AP take first. c |_| 16%", "whyNot": {"a": "The nurse should have the AP collect a clean-catch urine specimen for laboratory analysis; however, there is another action the nurse", "b": "The nurse should ask the AP to engage a toddler in play because it provides diversion and promotes the toddler's sense of security;", "c": "The nurse should ask the AP to assist an adolescent who reports extreme fatigue with personal hygiene measures; however, there is"}, "keyConcept": "Prioritization of care is key to the delivery of safe and effective client care. One model for priority setting in nursing practice includes the following steps: ° Assess client. © Identify problems. © Prioritize problems. © Identify desired outcomes. Identify interventions for achieving outcomes. ¢ Prioritize interventions. * Deliver client care. ¢ Evaluate interventions."}, {"id": 11176, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Prior to surgery, a circulating nurse calls for a \"time out.\" What is the purpose of a \"time out?\" O A.To start the IV O B. To insert a catheter O C. To verify that the team is going to do the correct procedure on the right client O D. To verify that the surgeon has been approved by the hospital to do the surgery", "choices": [{"id": "a", "t": "The nurse does not need to call a time-out to start an IV."}, {"id": "b", "t": "The client should already have a catheter in place before the time-out occurs."}, {"id": "c", "t": "The surgical “time out” has been implemented in many hospitals and outpatient surgery centers to reduce the incidence of wrong-client or wrong-site surgery."}, {"id": "d", "t": "The time-out is not performed to verify that the surgeon has privileges; this should have been determined long before surgery."}], "correct": "c", "rationale": "The surgical “time out” has been implemented in many hospitals and outpatient surgery centers to reduce the incidence of wrong-client or wrong-site surgery. During this time out, the team verifies that they are working with the right client, doing the correct procedure, and doing the procedure at the correct site. The other answer options will have been completed prior to the client's transport to the surgical suite.", "whyNot": {"a": "The nurse does not need to call a time-out to start an IV.", "b": "The client should already have a catheter in place before the time-out occurs.", "d": "The time-out is not performed to verify that the surgeon has privileges; this should have been determined long before surgery."}, "keyConcept": "The time-out is part of the \"Universal Protocol.\" The Universal Protocol is a mandatory quality standard introduced by the Joint Commission to ensure correct client identity, correct scheduled procedure, and correct surgical site. It consists of the following three components a pre- procedure verification process; surgical site marking; and surgical \"time out\" immediately prior to starting the procedure. \"Time out\" is performed in the operating room immediately before the procedure, to review correct client, procedure, and site."}, {"id": 11177, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "assign to the RN? O A. A client who has an evolving myocardial infarction O B. A client who has acute pancreatitis O C. A client who is 1 day postoperative following a total abdominal hysterectomy O D. A client who is being admitted following a stroke", "choices": [{"id": "a", "t": "A client who has an evolving myocardial infarction"}, {"id": "b", "t": "A client who has acute pancreatitis"}, {"id": "c", "t": "A client who is 1 day postoperative following a total abdominal hysterectomy"}, {"id": "d", "t": "A client who is being admitted following a stroke"}], "correct": "c", "rationale": "al 3% Easy C. This client is stable. The RN who has a background in maternal-newborn care will have the knowledge and skills to manage the care for a . °", "whyNot": {"a": "Floating of professional staff can fill needed services on units and reduce staffing costs. However, the Joint Commission and nursing case", "b": "The nurse who floats to another unit must have the skills to provide safe care to clients. This client requires specialized care and skills that", "d": "When making client assignments, the charge nurse should consider the skills and knowledge of any staff who are floating. Client"}, "keyConcept": "Nurses who are assigned to float to another unit have a responsibility to report to the charge nurse and refuse tasks that they cannot perform safely and competently. It is not unreasonable for a floating nurse to request orientation to an unfamiliar unit and to have a resource nurse available to assist as needed."}, {"id": 11178, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which type of data is the most useful for identification of patterns and trends when planning performance improvement activities?", "choices": [{"id": "a", "t": "Aggregated data"}, {"id": "b", "t": "Critical incident data"}, {"id": "c", "t": "Formative data"}, {"id": "d", "t": "Summative data"}], "correct": "a", "rationale": "co. i 30% Hard Aggregated data over time is the most useful for performance improvement activities in terms of identifying patterns and trends. Data B ] 80% aggregation involves the gathering and collection of data rather than looking at single pieces of data. For example, you may want to aggregate client falls data so you can identify the time of day that most falls occur. Critical incident data relates to only one incident; c |_| 23% formative and summative data are collected during and after an educational activity to evaluate its effectiveness. D | | 27%", "whyNot": {"b": "Critical incident data is related to only one situation; it does not involve identifying patterns and trends.", "c": "Formative data is collected during an educational activity to evaluate its effectiveness.", "d": "Summative data is collected after an educational activity to evaluate its effectiveness."}, "keyConcept": "The four steps of data management for healthcare performance improvement initiatives include collecting, tracking, analysis/interpretation, and acting on the data. Healthcare data is obtained from multiple sources, including payers, providers, and government databases. An aggregated database is commonly used to store and analyze healthcare performance data. An aggregate database relies on coordination between the central storage site, the data sources, and the parties who analyze the data."}, {"id": 11179, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "threatening manner, “I'll be back!” Which of the following is the most appropriate initial response by the nurse?", "choices": [{"id": "a", "t": "“If you do not lower your voice and calm down, will have to call hospital security to escort you outside.”"}, {"id": "b", "t": "“I will call the police if you do not leave the Emergency Department.”"}, {"id": "c", "t": "“You are frustrated about not receiving the medication you requested. Would you like to talk about this calmly?”"}, {"id": "d", "t": "“This behavior is drug-seeking, and we don’t tolerate that at this facility.”"}], "correct": "c", "rationale": "all 7% Easy . Most experts ec PY 90% recommend verbal de-escalation, using empathic listening to defuse the situation. However, real threats of violence should not be ignored. -escalation will allow the nurse to assess the individual’s behavior and response while regaining some control over a potentially harmful situation. The keys to empathic listening are giving the person undivided attention and focusing on his or her feelings in a nonjudgmental way. A nurse should allow periods of silence and can use restatement to clarify messages. It is also important to recognize that this approach may not always be successful, and a nurse should understand the plan developed by the facility when situations that are potentially violent escalate or cannot be defused. Nurses should realize their personal limits and should not continue this approach if the situation seems to escalate.", "whyNot": {"a": "This may be a necessary response if empathic communication fails to resolve the client’s anger.", "b": "This is not an ideal approach but appears hostile and confrontational.", "d": "This is a confrontational and judgmental response, and the individual may not be exhibiting drug-seeking behavior. The nurse should use"}, "keyConcept": "Angry clients or their family members can pose a threat to healthcare workers and others in a healthcare facility. Although the nurse should attempt verbal de-escalation, it's important to recognize that this approach may not always be successful. The nurse should be prepared to follow agency procedures for workplace safety if the situation cannot be de-escalated or defused."}, {"id": 11180, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is presenting an in-service about delegation to a group of newly licensed nurses. Which of the following statements by a newly licensed nurse indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Delegation ensures the client receives appropriate resources.\""}, {"id": "b", "t": "\"Delegation permits a designated individual to meet a goal on your behalf.\""}, {"id": "c", "t": "\"Delegation promotes client discharge teaching by unlicensed personnel.\""}, {"id": "d", "t": "\"Delegation shifts accountability to the individual performing the task.\""}], "correct": "b", "rationale": "A || 24% Moderate Delegation is defined as directing the performance of others to accomplish goals of the nurse and the facility. Delegation is a time OB a Gar: management tool that promotes safe client care by helping to ensure client tasks are accomplished in a timely manner. | ° © 1%", "whyNot": {"a": "Delegation allows work to be done by others. It does not ensure that the client receives appropriate resources.", "c": "Delegation allows work to be done by others. Teaching activities should not be delegated by nurses because they require specialized", "d": "Delegation transfers the responsibility of completing client tasks from one person to another. However, the nurse retains accountability"}, "keyConcept": "Delegation is a complex process involving task assignment and supervision of members of the health care team to deliver client care. It requires the nurse to evaluate the task and provide guidance, feedback, and intervention, if necessary."}, {"id": 11181, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "which of the following torts? O A. Assault O B. Invasion of privacy O C. Negligence O D. Battery", "choices": [{"id": "a", "t": "Assault"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Negligence"}, {"id": "d", "t": "Battery"}], "correct": "d", "rationale": "A | | 25% Moderate Battery is physical contact with the client without the client's consent. Administering a medication against a client's wishes is an example of . A client can make a charge of battery against a nurse who failed to obtain permission to touch the client even if there was no harm or 9 injury to the client. c i 9%", "whyNot": {"a": "Assault is the act of causing a client to fear that they will be touched without their consent. This often involves the use of verbal threats,", "b": "Invasion of privacy is an intentional tort that occurs when a client's private information is shared with others without the client's consent.", "c": "Negligence is an unintentional tort that involves actions that do not meet the established standard of care and results in harm to the"}, "keyConcept": "Atort is a civil wrong committed against a client or their property. Nurses are at risk for committing intentional torts, which involve a direct violation of the client's legal rights. Examples of intentional torts include assault, battery, defamation of character, false imprisonment, invasion of privacy, and intention of causing emotional distress."}, {"id": 11182, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "following? O A. Moral distress O B. Power O C. Horizontal violence O D. Hazing", "choices": [{"id": "a", "t": "Moral distress"}, {"id": "b", "t": "Power"}, {"id": "c", "t": "Horizontal violence"}, {"id": "d", "t": "Hazing"}], "correct": "c", "rationale": "Horizontal violence may occur as part of the nurse-nurse relationship, in which nurses who are of the same professional standing mistreat one another using actions or words. Examples of horizontal violence include intimidation, criticism, harassment, and interpersonal conflict. Horizontal violence that occurs in the workplace often causes pain and suffering for those who must endure it.", "whyNot": {"a": "Moral distress occurs when a nurse feels a loss of satisfaction with her work environment; it may or may not be due to harassment from", "b": "This is not an example of power exhibited by the nurses.", "d": "Hazing refers to imposing humiliating tasks on a person as a form of initiation."}, "keyConcept": "\"Horizontal violence\" in nursing is often unrecognized or underreported. It is characterized by acts of unwanted abuse or hostility in the workplace, where bullying is described as repeated acts of aggression over a period of time. The Joint Commission mandates healthcare organizations to develop codes of workplace conduct that define acceptable and unacceptable behaviors and processes to manage behaviors that undermine the culture of safety."}, {"id": 11183, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is providing discharge teaching about medications to a client who has a low level of health literacy. Which statement indicates that the nurse is accounting for this client's level of health literacy?", "choices": [{"id": "a", "t": "“Take two of these tablets every morning with food to help manage your hypertension.”"}, {"id": "b", "t": "“This medication can make you feel dizzy because it will lower your blood pressure.”"}, {"id": "c", "t": "“The physician has prescribed this medicine for you. You should take it every day.”"}, {"id": "d", "t": "“Please read this pharmaceutical packet with information about your medication if you have any other questions.”"}], "correct": "b", "rationale": "A || 19% Moderate Health literacy is an ability to understand the sometimes-complex medical terminology and data needed to effectively manage health and OB a aan well-being. Many Americans have low levels of health literacy, despite being well educated and understanding many other complex topics. ° When providing information to a client with a low level of health literacy, the nurse should explain what the client needs to know about the c | 8% topic while using simple terms and avoiding complex medical jargon.", "whyNot": {"a": "This response may be too technical for the client to understand. 2", "c": "This does not best describe why or how the client should take the medication. 3", "d": "Pharmaceutical materials may be confusing and too difficult to read for someone with low health literacy; the nurse should provide the g"}, "keyConcept": "The nurse should allot extra time when necessary to effectively communicate with the client when the subject of the conversation is complex and particularly if the client has a low level of health literacy or if there is a language barrier. Additional time and consideration are necessary when the client is affected by confusion, decreased level of consciousness, hearing loss, or aphasia. For communication to be effective, all conveyed messages must be fully understood by the receiver and all feedback conveyed by the receiver of the message to the sender of the message is also completely understood."}, {"id": 11184, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is reviewing ethical principles with a newly licensed nurse. Which of the following actions by a nurse is an example of adhering to the ethical principle of fidelity?", "choices": [{"id": "a", "t": "Keeping an appointment with a client"}, {"id": "b", "t": "Allowing a new parent to hold his stillborn infant"}, {"id": "c", "t": "Assisting a client who wishes to complete an advance directive"}, {"id": "d", "t": "Refusing to disclose information about a client to the media"}], "correct": "a", "rationale": "Fidelity is the duty to keep one's promises or word. Keeping an appointment with a client is an example of fidelity. B | aI", "whyNot": {"b": "Beneficence is the duty to do good for others. Allowing a grieving parent an opportunity to spend time with his infant helps him to process D Hi 14%", "c": "The ethical principle of autonomy describes an individual's right to choose. In healthcare, autonomy is the principle underlying informed", "d": "Confidentiality is not disclosing a client's personal healthcare information to unauthorized individuals or other entities."}, "keyConcept": "100} 2 = o 4 zg a [R a < A nurse should be able to identify and practice within the ethical principles of nursing."}, {"id": 11185, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following tasks can be safely delegated to the UAP (unlicensed assistive personnel)?", "choices": [{"id": "a", "t": "Monitoring a client who is self-administering insulin"}, {"id": "b", "t": "Changing a dressing on a skin tear on a client’s forearm"}, {"id": "c", "t": "Changing the dressing and caps on a client’s central line"}, {"id": "d", "t": "Assisting a client recovering from abdominal surgery to ambulate to the bathroom"}, {"id": "e", "t": "Monitoring a client’s response to a new pain medication"}], "correct": "d", "rationale": "al 2% Easy Assisting clients to ambulate to the bathroom is within the UAP’s scope of practice. B I a", "whyNot": {"a": "Monitoring a client who is self-administering insulin requires knowledge of correct procedure and technique. This is not within the UAP’s e@D fF 91%", "b": "Changing a dressing requires evaluation of the wound for signs of healing or failure to heal/infection. Wound evaluation and wound", "c": "Changing the dressing and caps on an indwelling central catheter must be performed by a nurse. There is a high risk of complications if", "e": "Monitoring the effectiveness of pain medication requires evaluation by the nurse. Evaluation cannot be delegated to the UAP."}, "keyConcept": "A nurse cannot delegate any part of the nursing process. Tasks that can be delegated to the UAP include routine, stable vital signs; fingerstick blood glucose; assisting a client with meals; basic hygiene; assistance with activities of daily living (ADL) and helping a stable client to ambulate."}, {"id": 11186, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "explains the results of a study about a new nursing practice?", "choices": [{"id": "a", "t": "“ should consider the study design.”"}, {"id": "b", "t": "“The study should be designed to test a hypothesis.”"}, {"id": "c", "t": "“I should determine who funded the study.”"}, {"id": "d", "t": "“I should consider the method used to gather the data.”"}], "correct": "c", "rationale": "A i 8% Moderate Aresearch article is structured to present evidence in support of a hypothesis. The type of study design is one determinant of the weight of B Hl a the evidence or significance of study findings. A randomized controlled trial, for example, provides a higher level of evidence than case control studies or retrospective studies. The methods used to collect data are important to note, since they can bea source of bias in the ec | 12% study. A nurse should evaluate these factors when reading a journal article. The source of funding for a research article is not a consideration .", "whyNot": {"a": "This statement indicates understanding of how to evaluate a journal article. The study design is one factor that can be used to assess the", "b": "This statement indicates an understanding of the need to state a hypothesis to be tested before undertaking a research study.", "d": "This statement indicates understanding of the need to examine the method of collecting data in a research study as part of the evaluation."}, "keyConcept": "When evaluating a research article, the nurse should consider the conceptual model, research methodology, and the theory that was tested or generated by the research."}, {"id": 11187, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following statements is accurate in terms of delegation?", "choices": [{"id": "a", "t": "Delegating nurses must supervise and follow up on staff"}, {"id": "b", "t": "Delegation transfers accountability to another"}, {"id": "c", "t": "Delegation empowers autonomous staff members"}, {"id": "d", "t": "Nurses do not delegate to unlicensed assistive staff"}], "correct": "a", "rationale": "Delegating nurses must supervise staff after they have delegated tasks to others. The nurse retains accountability for the outcome of all B ] a delegated tasks, including those delegated to unlicensed assistive staff such as nursing assistants. Delegation transfers authority to do the job but not accountability. Empowerment is not achieved with delegation; empowerment is a different process. c | 6% p | 1%", "whyNot": {"b": "Delegation transfers authority to other staff, not accountability.", "c": "Empowerment refers to a different process than delegation.", "d": "Nurses can and do delegate to unlicensed assistive personnel."}, "keyConcept": "Delegation occurs when a nurse transfers a task to another staff member while retaining accountability for the outcome. When delegating a task, the nurse is transferring responsibility for a task that is within the nurse's scope of practice that is not within the individual's scope of practice. Although the individual to whom the task is delegated is responsible for performing the task, they are not accountable for the outcome. When delegating, the nurse must verify that the person is competent to perform the task. Assignment refers to giving someone a task that is within their scope of practice."}, {"id": 11188, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following tasks can a charge nurse assign to a licensed practical nurse?", "choices": [{"id": "a", "t": "Teaching a client newly diagnosed with diabetes about self-injections"}, {"id": "b", "t": "Performing triage in the Emergency Department"}, {"id": "c", "t": "Performing routine suctioning and tracheostomy care"}, {"id": "d", "t": "Planning care for a client who has been admitted for elective surgery the next day"}], "correct": "c", "rationale": "al 4% Easy Alicensed practical nurse’s (LPN's) scope of practice is defined by the nursing board of the state and facility policies. The RN should also take B | 3\" into account the LPN’s experience and ability to perform a task. In general, the most qualified person able to complete a task should perform the task. Sometimes, it is necessary to assign routine tasks to subordinates in order to allow other staff members with more knowledge and ec P| 90% education to complete more complex tasks. Registered nurses cannot delegate the nursing process, including tasks that require nursing D l 3% judgment. Although practice varies by locale, some tasks performed by LPNs include monitoring IV sites, giving some medications, performing vital signs, and conducting routine tracheostomy care, including suctioning.", "whyNot": {"a": "Teaching cannot be delegated to an LPN, although the LPN may reinforce teaching.", "b": "Triage requires evaluation and cannot be delegated by an RN to an LPN.", "d": "Planning care is part of the nursing process and cannot be delegated to the LPN."}, "keyConcept": "Assignment refers to giving someone else a task within his/her own practice. It is based on the LPN's job description, facility policies, scope of practice, and competence. LPNs are accountable for caring out the activities assigned to them. When a RN delegates an activity to an LPN, the LPN is accountable for safely performing the task according to established regulations and standards, and for completing the activity. The RN is accountable to follow up with the LPN to review the outcome of the intervention or task."}, {"id": 11189, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "healthcare? O A. Justice O B. Beneficence O C. Nonmaleficence O D. Autonomy OE Fidelity", "choices": [{"id": "a", "t": "Justice"}, {"id": "b", "t": "Beneficence"}, {"id": "c", "t": "Nonmaleficence"}, {"id": "d", "t": "Autonomy OE Fidelity"}], "correct": "d", "rationale": "| 2% Easy The principle of autonomy refers to the client's right to self-determination. In order for a client to make a fully informed decision, the client a | Bon must understand all risks and benefits of the procedure and the likelihood of success. The decision-making process must be free of coercion. Provided a client is of sound mind, any decisions they make regarding their care must be respected. The nurse should advocate for the client c | 2% to protect this right. @D PF 93%", "whyNot": {"a": "Justice refers to an equal and fair distribution of resources and implies that all citizens have an equal right to the goods distributed,", "b": "Beneficence relates to compassion and taking positive action to help others. It equates to a desire to do good and is one of the core ethical", "c": "Nonmaleficence is the avoidance of harm or hurt. It is the core of the physician’s oath."}, "keyConcept": "Healthcare providers must respect principles of autonomy, justice, beneficence, and non-maleficence when providing care. The nurse is an important advocate for the client by ensuring the client is aware of his/her rights and that the principles of ethical care are respected."}, {"id": 11190, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "healthcare? O A. Justice O B. Beneficence O C. Nonmaleficence O D. Autonomy OE Fidelity eck Answer", "choices": [{"id": "a", "t": "Justice"}, {"id": "b", "t": "Beneficence"}, {"id": "c", "t": "Nonmaleficence"}, {"id": "d", "t": "Autonomy OE Fidelity eck Answer"}], "correct": "d", "rationale": "| 2% Easy The principle of autonomy refers to the client's right to self-determination. In order for a client to make a fully informed decision, the client a | Bon must understand all risks and benefits of the procedure and the likelihood of success. The decision-making process must be free of coercion. Provided a client is of sound mind, any decisions they make regarding their care must be respected. The nurse should advocate for the client c | 2% to protect this right. D PF 93%", "whyNot": {"a": "Justice refers to an equal and fair distribution of resources and implies that all citizens have an equal right to the goods distributed,", "b": "Beneficence relates to compassion and taking positive action to help others. It equates to a desire to do good and is one of the core ethical", "c": "Nonmaleficence is the avoidance of harm or hurt. It is the core of the physician’s oath."}, "keyConcept": "Healthcare providers must respect principles of autonomy, justice, beneficence, and non-maleficence when providing care. The nurse is an important advocate for the client by ensuring the client is aware of his/her rights and that the principles of ethical care are respected."}, {"id": 11191, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "The unit secretary is transcribing a healthcare provider's written order and asks the nurse to interpret an illegible phrase. Which of the following is the most appropriate action by the nurse in response?", "choices": [{"id": "a", "t": "Interpret the order according to the client’s previous medication records"}, {"id": "b", "t": "Clarify the order with the pharmacist"}, {"id": "c", "t": "Clarify the order by calling the healthcare provider"}, {"id": "d", "t": "Clarify the order by speaking to the family"}], "correct": "c", "rationale": "| 2% Easy Illegible writing is one of the most common reasons for errors. The nurse should advise the unit secretary to clarify the order with the B | a0 healthcare prescriber.", "whyNot": {"a": "lf the nurse cannot interpret the order, she must call the healthcare provider to clarify.", "b": "The pharmacist did not write the order; the nurse must call the healthcare provider for clarification if an order is illegible.", "d": "Asking the family is not an appropriate solution when trying to interpret an illegible order."}, "keyConcept": "There are multiple steps the nurse must take to safely administer medication. The nurse should not interpret an illegible prescription. Illegible prescriptions should always be clarified with the healthcare provider. Other precautions include double-checking medication orders and administration processes when administering high-risk medications, including patient-controlled analgesia, heparin, and insulin; double-checking calculations; questioning unusual orders, including very large or very small doses; avoiding interruptions when giving medications; and documenting medications as soon as they are administered."}, {"id": 11192, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is teaching a newly licensed nurse about delegating tasks to assistive personnel (AP). Which of the following statements by the newly licensed nurse indicates an understanding of the teaching? O A.\"The nurse relinquishes accountability for client outcomes when care is delegated to an AP.\" O B. \"The AP can provide client education about how to perform basic self-care to the client.\" O C. \"The nurse should consider the AP's level of experience when making delegation decisions.\" O D. \"The nurse should delegate all tasks that don't require specialized skill or knowledge to an AP.\"", "choices": [{"id": "a", "t": "Delegation is the act of assigning tasks or client care to a licensed practical nurse (LPN) or an AP. The nurse should use the five rights of"}, {"id": "b", "t": "3%"}, {"id": "c", "t": "\"The nurse should consider the AP's level of experience when making delegation decisions.\" ec 82%"}, {"id": "d", "t": "The nurse should consider the workload of the AP when delegating and should avoid overburdening the AP with tasks and activities. The"}], "correct": "c", "rationale": "Eas) Correct Answer: A | ™% y . \"The nurse should consider the AP's level of experience when making delegation decisions.\" ec | 82% When delegating a task, the nurse should delegate the task to the right person. The nurse should consider the AP's job description, level of D | | 9% knowledge, and individual level of experience. Other considerations include the Nurse Practice Act and the facilities policies.", "whyNot": {"a": "Delegation is the act of assigning tasks or client care to a licensed practical nurse (LPN) or an AP. The nurse should use the five rights of", "b": "The nurse should recognize that certain tasks cannot be delegated. These include activities or tasks that require critical thinking and", "d": "The nurse should consider the workload of the AP when delegating and should avoid overburdening the AP with tasks and activities. The"}, "keyConcept": "Facility policies and job descriptions might limit the tasks that certain healthcare staff are allowed to complete according to the state's Nursing Practice Act. However, regardless of facility policies or job descriptions, staff members cannot perform tasks that are prohibited by the state's Nurse Practice Act."}, {"id": 11193, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "SM Viral 8. Reco. ™M Inbox ™ Inbox {J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "On discharge from the hospital"}, {"id": "b", "t": "On discharge from the cardiac care unit"}, {"id": "c", "t": "On admission to the hospital"}, {"id": "d", "t": "4 weeks after the onset of illness"}], "correct": "c", "rationale": "| 2% Easy Abasic principle of rehabilitation, including cardiac rehabilitation, is that rehabilitation begins on hospital admission. Early rehabilitation is B | Ee important to promote maximum functioning ability as the client recovers.", "whyNot": {"a": "The client will need discharge instructions when he leaves the hospital; however, discharge planning should begin upon admission.", "b": "The client may need to know some discharge instructions when he is moved from the cardiac care unit, but discharge planning should", "d": "The client should know discharge instructions before 4 weeks after the onset of illness. Discharge instructions should begin upon"}, "keyConcept": "Cardiac rehabilitation (cardiac rehab) refers to individualized outpatient programs of exercise and education that are designed to help clients improve their health and facilitate recovery from myocardial infarction, other forms of heart disease or cardiac surgery. Cardiac rehab includes exercise training, emotional support, and education about lifestyle changes to reduce the risk of recurrent cardiac events. Lifestyle changes may include the adoption of a heart-healthy diet, maintenance of a healthy weight, and smoking cessation. Cardiac rehab goals include prevention of progressive worsening of the condition; reduction of the risk of future cardiac events; and improvement of strength, health, and quality of life."}, {"id": 11194, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "tasks to the assistive personnel (AP). Which of the following statements should the nurse manager make to the staff nurse? O A.\"| need to talk to you about unit expectations regarding delegating and completing tasks.\" O B. \"Several staff members have commented that you don't do your fair share of the work.\" O C. \"If you don't do your share of the work, | will have to file a written admonishment.\" O D. \"You have been very inconsiderate of others by not completing your share of the work.\"", "choices": [{"id": "a", "t": "This statement opens the conversation in a nonthreatening way."}, {"id": "b", "t": "This statement is aggressive and nontherapeutic. Accusing the staff nurse of failing to do a fair share of the work can cause the staff nurse"}, {"id": "c", "t": "This statement is punitive. The nurse manager should converse with the nurse and obtain more information before threatening"}, {"id": "d", "t": "This statement is aggressive and nontherapeutic. The nurse manager should obtain more information before determining the need for"}], "correct": "a", "rationale": "This statement opens the conversation in a nonthreatening way. The focus is on the issue of the equity of the assignment rather than on any B | a0 personal characteristic of the individual. c | 1%", "whyNot": {"b": "This statement is aggressive and nontherapeutic. Accusing the staff nurse of failing to do a fair share of the work can cause the staff nurse", "c": "This statement is punitive. The nurse manager should converse with the nurse and obtain more information before threatening", "d": "This statement is aggressive and nontherapeutic. The nurse manager should obtain more information before determining the need for"}, "keyConcept": "The nurse should identify important steps in conflict resolution, which include focusing on the issues causing the conflict rather than verbally attacking the other individual. Other techniques include the use of active listening to gain an understanding of the other individual's perspective and to approach the conflict as a problem to be solved collaboratively."}, {"id": 11195, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "continued treatment against the client's wishes is a violation of which of the following ethical principles?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Autonomy O c.utility"}, {"id": "d", "t": "Justice"}], "correct": "b", "rationale": "al 5% Easy The nurse should identify that the client has the right to make his own decisions regarding health care. The ethical principle of autonomy OB rsd eer applies to an individual's right to choose and control their care. Respecting autonomy requires the nurse to recognize that the client's choice is based on his own personal values, and those values might not be shared by the nurse. c ! 2% D 4% Incorrect: ACD A. The ethical principle of veracity requires the nurse to tell the truth and not to intentionally deceive or mislead clients.", "whyNot": null, "keyConcept": "The nurse should identify that the client has the right to make his own decisions regarding health care. If a client chooses to discontinue treatment, the nurse should notify the provider and ensure that the client is aware of the consequences of this decision. By performing this action, the nurse is demonstrating the ethical principle of autonomy."}, {"id": 11196, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is planning to teach the nurses on the unit about a new infusion pump. Which of the following teaching strategies is the most effective way to ensure that the staff can use the device correctly?", "choices": [{"id": "a", "t": "Create a step-by-step instructional handout about using the device for the staff to review."}, {"id": "b", "t": "Demonstrate using the device and observe the staff returning the demonstration."}, {"id": "c", "t": "Remind the staff to review the procedure manual prior to using the new pump."}, {"id": "d", "t": "Show a video about the new infusion pump during an in-service."}], "correct": "b", "rationale": "al 3% Easy B. Evidence-based practice indicates that psychomotor skills are best taught by using demonstration and return demonstration methods of OB TS ORY learning, such as the \"see one, do one, teach one\" model. ° c | 2% Planning a Demonstration to Promote Psychomotor Learning 1. Assemble and organize the equipment, making sure it is in working order. 2. Ensure all learners have a clear view of each step of the demonstration. 3. Perform each step slowly and in sequence, offering rationales for each step. 4, Encourage participants to ask questions throughout the demonstration. a © o 2 ° s a = a < 5. Allow practice time for each participant to work with the equipment. 6. Complete the training with a return demonstration by each participant.", "whyNot": {"a": "The nurse manager should provide written information for the nurses during an in-service. Additional information cards can be placed on", "c": "The nurse manager should have a procedure manual available on the unit for the nurses to review prior to use and for troubleshooting, if", "d": "The nurse manager should present a visual demonstration of the use of the new infusion pump during an in-service to enhance learning in"}, "keyConcept": "In-service programs are presented to staff members in order to increase the skills, competencies, and knowledge required to promote the safe and effective care of the client. Often, the focus is on new technologies and how to use new equipment. When planning in-services for staff members, the developer should use strategies specifically for adult learners, such as focusing on solving problems or issues that affect the adult learner's immediate environment or work situation."}, {"id": 11197, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "| 8x Reco. Mi Inbox M Inbox J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Call the surgeon so he can talk to the client again"}, {"id": "b", "t": "Answer the client's questions about the risks"}, {"id": "c", "t": "Have the client sign the form and then call the surgeon"}, {"id": "d", "t": "Reassure the client that the surgeon is very experienced"}], "correct": "a", "rationale": "The physician is ultimately responsible for explaining the risks and benefits of the scheduled surgical procedure. Therefore, the nurse should B I a call the physician and let him know that the client continues to have questions about the procedure. | © 1%", "whyNot": {"b": "Although the nurse can help explain the procedure, the risks MUST be explained by the surgeon.", "c": "The consent form should NOT be signed until the client is comfortable with all explanations. Legally, the nurse can witness the client's", "d": "The nurse can reassure the client about the surgeon's skill, but that can NOT take the place of informed consent after the physician has"}, "keyConcept": "Informed consent is of both legal and ethical importance. Legally, informed consent requires that the client, or the client's surrogate, is informed of the risks, benefits, and alternatives to a treatment. Legal documentation of consent is provided by witnessed signature. Ethically, consent protects the client's autonomy, because it is necessary for the client to understand and freely agree to the treatment."}, {"id": 11198, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which procedure is most often consented to with an implied client consent?", "choices": [{"id": "a", "t": "An MRI with contrast"}, {"id": "b", "t": "A minor surgical procedure"}, {"id": "c", "t": "Tube thoracostomy"}, {"id": "d", "t": "Administration of an intramuscular injection"}], "correct": "d", "rationale": "A | | 8% Moderate Types of consent include implied consent, expressed verbal consent, and written consent. Implied consent is used for routine procedures B I a such as taking vital signs, checking blood glucose, or receiving an intramuscular injection. The client has consented to these routine procedures as the result of their admission. The nurse also tells the client what they are doing before providing care, such as taking vital c |__| 21% signs or giving injections. Major invasive procedures, such as surgical procedures, intubation, and diagnostic tests such as an MRI with @ , require a written expressed consent.", "whyNot": {"a": "This is not an example of implied consent; the client would need to provide written consent.", "b": "The client would need to provide written consent for a surgical procedure; consent is not implied except in an emergency.", "c": "Written consent is required for tube thoracostomy, even though it is a procedure often performed at the bedside."}, "keyConcept": "The requirements for valid consent are the same whether or not the consent is implied or expressly given. The client must be competent to give consent; the client must be informed about the nature of the procedure or intervention; and the consent must be given voluntarily, without coercion. In most interactions between the nurse and client, implied consent is given. It's important for the nurse to accurately answer the client's questions so informed consent is valid."}, {"id": 11199, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following points relating to personal hygiene and the activities of daily living should you emphasize during an educational session for a group of newly employed nursing assistants?", "choices": [{"id": "a", "t": "The wholly compensatory client, according to Orem, benefits greatly from independent function in terms of enhancing the client's dignity and self-esteem"}, {"id": "b", "t": "bathing and shower water should be about 190 degrees Fahrenheit to prevent chilling and shivering during the bathing process"}, {"id": "c", "t": "Culture and cultural practices greatly affect the client's personal hygiene and activities of daily living"}, {"id": "d", "t": "Nursing assistants are not permitted to do any foot care or hygiene for clients who have diabetes"}], "correct": "c", "rationale": "A || 19% Moderate Culture and cultural practices greatly affect the client’s practice of personal hygiene and activities of daily living. For example, some cultures , more than others, may need more privacy. The water used for bathing and showering should be no warmer than 110F to 115 F for prevention of burns, particularly among ec | 1% those with poor peripheral circulation and increased skin fragility. According to Dorothea Orem, the wholly compensatory client is D i 9% completely dependent on the health care provider for care because they cannot participate at all. For example, the client may be an infant, a very young child or an adult in a coma. Independence should be encouraged, however, among those who are able to participate in order to maintain and enhance their level of dignity and self-esteem. Nursing assistants can, and should, provide foot care for the diabetic client, with the exception of trimming and clipping the toenails.", "whyNot": {"a": "The wholly compensatory client is completely dependent on the caregiver and has little, if any, independence, although this should be", "b": "Bath and shower water should be 110-115 degrees, no higher, to reduce the incidence of burns and to avoid drying out the skin.", "d": "Nursing assistants should participate in foot care to help diabetic clients keep their feet clean and avoid infection."}, "keyConcept": "The nurse should ensure the client has opportunities for proper hygiene. Depending upon the rules of the healthcare facility, some client hygiene tasks can be assigned to unlicensed assistive personnel (UAP). When assisting the client with hygiene measures, the nurse can also assess the client's need for additional teaching about correct practices in personal hygiene. Factors that impact the client's personal hygiene include illness, disability, mobility, emotional factors, developmental stage, cultural and religious practices, and personal preferences."}, {"id": 11200, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse touches a staff nurse in a way that the staff nurse feels is inappropriate. Which of the following is the most appropriate initial action for the staff nurse to take?", "choices": [{"id": "a", "t": "Inform the charge nurse that the touch was inappropriate and must stop immediately."}, {"id": "b", "t": "Report the charge nurse to human resources."}, {"id": "c", "t": "Notify the nursing supervisor of sexual harassment."}, {"id": "d", "t": "Document the incident in writing."}], "correct": "a", "rationale": "The initial action taken by the staff nurse is to tell the charge nurse that the touch was inappropriate and the behavior must stop B I Ee immediately. The staff nurse should also document the incident and can inform others, but the priority action is to tell the charge nurse the behavior must stop. c | 10% of 4%", "whyNot": {"b": "The priority action is asking the charge nurse to stop the inappropriate behavior. The staff nurse can then document the behavior and", "c": "The priority action is asking the charge nurse to stop the inappropriate behavior. The nurse should document the behavior and can then", "d": "Before documenting the incident in writing, the staff nurse should confront the charge nurse with the inappropriate behavior and ask that"}, "keyConcept": "When experiencing inappropriate or harassing behavior in the workplace, the nurse should first inform the other person that the behavior is objectionable and must stop. The incident should be documented by the nurse after confronting the other party."}, {"id": 11201, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "continuity of care? O A. Collaboration with a social worker to determine the best client placement in the community O B. Discussing the nutritional needs of a client with a dietitian O C. Awell-planned and seamless movement of a client to a different level of care based on the client's status O D. The assignment of the same nurse to the client throughout the client's hospitalization", "choices": [{"id": "a", "t": "Collaboration with a social worker to determine the best client placement in the community"}, {"id": "b", "t": "Discussing the nutritional needs of a client with a dietitian"}, {"id": "c", "t": "Awell-planned and seamless movement of a client to a different level of care based on the client's status"}, {"id": "d", "t": "The assignment of the same nurse to the client throughout the client's hospitalization"}], "correct": "c", "rationale": "A | | 22% Moderate Simply stated, the continuity of care is the well-planned and seamless movement of a client to a different level of care based on their status. B | 3\" This movement, or transition, to another level of care is based on the identified needs of the client. In some cases a client may be moved toa less intense level of care; in other cases, a client may be moved to a more intense level of care based on the client's changing needs. OG a Ce om 14%", "whyNot": {"a": "Collaboration with a social worker plans for continuity of care, it does not carry it out.", "b": "This does not necessarily describe continuity of care, which involves moving the client to different levels of care as needed.", "d": "This may provide continuity of care but it is only one element of it."}, "keyConcept": "Joint Commission advises the use of Health Information Technology to maintain continuity of care. It should contain information from providers in the clinical record, and the information must be accessible to those internal and external providers of care as well. Planning for continuity of care should be a consideration in all healthcare encounters. The client's medical record should reflect the current health status and lifetime medical history of the client. Documentation must be accurate and comprehensive in order to maintain continuity of care and track client outcomes."}, {"id": 11202, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is leading a group discussion about the risk factors of family and community violence. This nurse should include that which of the following clients has a risk factor for experiencing violence? O A.A 7-year-old male who asserts his independence to his parents O B. A 29-year-old female who works for a demanding and authoritative boss O C. A 62-year old retired male who lives independently in a retirement community O D. A 25-year-old female who is pregnant with her first child", "choices": [{"id": "a", "t": "This patient is not considered to be at risk of experiencing violence. Female children and children younger than 3 years of age are more"}, {"id": "b", "t": "This patient is not considered to be at risk of experiencing violence."}, {"id": "c", "t": "This patient is not considered to be at risk of experiencing violence."}, {"id": "d", "t": "The nurse should include pregnancy as a risk factor for partner violence."}], "correct": "d", "rationale": "The nurse should include pregnancy as a risk factor for partner violence. The patient's partner might resent the added responsibility of having a baby or be jealous of the relationship the mother has with the child. Populations at Risk for Experiencing Violence: Women Children Older Adults", "whyNot": {"a": "This patient is not considered to be at risk of experiencing violence. Female children and children younger than 3 years of age are more", "b": "This patient is not considered to be at risk of experiencing violence.", "c": "This patient is not considered to be at risk of experiencing violence."}, "keyConcept": "The role of the nurse is to provide early intervention and health promotion to improve the health of the community. It is important for the nurse to recognize which populations are likely to be at an increased risk of experiencing violence. Populations at an increased risk for experiencing violence include women, children, and older adults."}, {"id": 11203, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Tell the client that an \"against medical advice\" form (AMA) must be completed before leaving the facility."}, {"id": "b", "t": "Contact the facility administrator and explain the situation."}, {"id": "c", "t": "Explain to the client the risks of leaving the facility prior to speaking with the provider."}, {"id": "d", "t": "Ask the facility security officer to stand by the door to the client's room to prevent the client from leaving."}], "correct": "c", "rationale": "A | | 25% Moderate B 1% an increased risk for bleeding. The nurse should document the information provided to the client and the client's understanding of the | information in the client's medical record. OG PS oo D 0% The nurse has an obligation to explain to the client that an INR of 4.5 is above the expected reference range of 2 to 3 and places the client at", "whyNot": {"a": "The nurse should attempt to have the client sign the AMA form because this measure can help to defend the facility if a lawsuit ensues.", "b": "The nurse should promptly contact the client's provider and relay pertinent information regarding the laboratory result and the client's", "d": "Guarding the client's door or preventing the client from leaving can lead to charges of false imprisonment."}, "keyConcept": "The nurse should discuss the risks of leaving a facility against medical advice (AMA) and document what the client has been told in the medical record. It is in the best interest of the facility for the client to sign an AMA; however, under no circumstance can a competent client be forced to remain ina facility if they choose to leave."}, {"id": 11204, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "for a nursing diagnosis of altered tissue perfusion related to decreased circulatory volume?", "choices": [{"id": "a", "t": "Assess the client’s abdomen for bowel sounds and tenderness."}, {"id": "b", "t": "Check the pulse oximeter reading."}, {"id": "c", "t": "Request a prescription for 2 units of O-negative blood."}, {"id": "d", "t": "Place a large-bore intravenous catheter and administer a bolus of normal saline or lactated Ringer’s."}], "correct": "d", "rationale": ", so no further assessment data should be obtained prior to implementation of an B r | Bay appropriate nursing intervention. The client has significant hypovolemia with likely ongoing blood loss, which is a life-threatening emergency. The appropriate intervention is support of circulation by infusing an isotonic crystalloid solution. Physiological needs, at the bottom of Maslow’s Hierarchy, are the top priority when making decisions about prioritization of nursing interventions. Life-threatening @ , breathing, or circulation are the highest physiological priorities. c] 3%", "whyNot": {"a": "Anursing diagnosis has been formulated after assessment of vital signs in a client with GI bleeding. Further assessment should be delayed", "b": "Pulse oximetry is unnecessary to provide circulatory support.", "c": "The initial action is infusing at least 2 liters of isotonic crystalloid solution. If typed and cross-matched blood is not available immediately,"}, "keyConcept": "Hemorrhage and subsequent hypovolemia can be life-threatening and should be prioritized by a nurse for intervention. Signs of hypovolemia include hypotension, tachycardia, signs of cardiac ischemia, and decreased level of consciousness."}, {"id": 11205, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is delegating tasks to an unlicensed assistive personnel (UAP). Which of the following tasks should the nurse ask the UAP to perform first?", "choices": [{"id": "a", "t": "Take an arterial blood gas (ABG) specimen to the laboratory."}, {"id": "b", "t": "Transport a client to the radiology department for an X-ray."}, {"id": "c", "t": "Perform a simple dressing change on a client."}, {"id": "d", "t": "Obtain a routine urine sample from a newly-admitted client."}], "correct": "a", "rationale": "@ . When using the urgent vs. nonurgent approach to client care, the nurse should determine the priority action is to take the aterial blood gas B a Ban (ABG) blood sample to the laboratory. An ABG sample is placed on ice, and the unlicensed assistive personnel. (UAP) should transport it to the laboratory immediately to ensure accurate lab results. An ABG sample that is not transported to the laboratory immediately can c | 2% deteriorate, causing inaccurate results. D || 14%", "whyNot": {"b": "Although the UAP should transport the client to the radiology department, there is another task that is the priority for the UAP to perform.", "c": "Although the UAP should perform a simple dressing change on the client, there is another task that is the priority for the UAP to perform.", "d": "Although the UAP should obtain a routine urine sample from the client, there is another task that is the priority for the UAP to perform."}, "keyConcept": "When delegating tasks, the nurse should communicate to the UAP which tasks to accomplish, when each task should be completed, the expected outcome for each task, which findings to report, and who will serve as a resource individual for the AP. The nurse should make certain the AP understands the directions regarding the tasks."}, {"id": 11206, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "client's chart? O A. Allow the client's father to read the chart since he is a physician with hospital staff privileges. O B. Ask the client's father to leave the nursing station immediately O C. Inform the client's father that written permission must be obtained from the client. O D. Tell the client's father that he cannot read the chart but staff can answer his questions about the client's condition. O E. Refer the father to the nursing supervisor", "choices": [{"id": "a", "t": "Allow the client's father to read the chart since he is a physician with hospital staff privileges."}, {"id": "b", "t": "Ask the client's father to leave the nursing station immediately"}, {"id": "c", "t": "Inform the client's father that written permission must be obtained from the client."}, {"id": "d", "t": "Tell the client's father that he cannot read the chart but staff can answer his questions about the client's condition."}, {"id": "e", "t": "Refer the father to the nursing supervisor"}], "correct": "c", "rationale": "Clients have a right to confidentiality. Family members should not be permitted to read the client’s chart unless written consent is provided by the client.", "whyNot": {"a": "Although the client’s father is a physician on the hospital staff, he is not the client's healthcare provider and should not be allowed to read", "b": "This could potentially escalate the situation and does not solve the problem.", "d": "Providing information that is contained in the chart is still a breach of confidentiality without the client's written permission.", "e": "The nurse should be capable of handling this situation independently."}, "keyConcept": "Ahealth care provider should only share the client's personal health information with the client's permission, unless the client cannot give permission when a health care provider believes, based on professional judgment, that sharing the information is in the client's best interest, such as in an emergency when the client is unconscious. Under HIPAA, the health care provider may also discuss client health information with family members if the client is present and does not object to sharing the information."}, {"id": 11207, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse and an assistive personnel (AP) are providing care to a group of clients. The nurse should delegate assisting which of the following clients with their meal to the AP?", "choices": [{"id": "a", "t": "A client who has a lumbosacral spinal tumor"}, {"id": "b", "t": "A client who has Guillain-Barré syndrome"}, {"id": "c", "t": "A client who has amyotrophic lateral sclerosis (ALS)"}, {"id": "d", "t": "A client who receives enteral feedings through a nasogastric tube"}], "correct": "a", "rationale": "@ . One of these rights is the right B ] Aen circumstance. The nurse should identify that the client who has a lumbosacral spinal tumor can have limited mobility and require assistance with setting up their meal tray and opening containers. The client is stable and not at risk for aspiration. Therefore, the nurse should c || 24% delegate meal assistance for this client to the AP.", "whyNot": {"b": "When delegating tasks to an AP, the nurse should consider the task to be delegated, the frequency with which the AP has completed the", "c": "The nurse should consider the right person to assist the client who has ALS with eating. A client who has ALS is at risk for aspiration during", "d": "The nurse should identify that administering an enteral feeding through a nasogastric tube requires assessment of the tube placement,"}, "keyConcept": "To delegate effectively, the nurse should know the client's needs and acuity level, the staff abilities and job description, and the complexity of the task to be delegated. If the task is appropriate for delegation, the nurse should provide clear communication regarding the task itself, the time frame within which the task should be completed, and the information to be reported back to the nurse. The nurse is also responsible for assessing the task's completion, the performance of the staff member, and providing feedback to the staff member based upon their job performance."}, {"id": 11208, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is planning to delegate tasks to an assistive personnel (AP). Which of the following tasks should the nurse assign to the AP?", "choices": [{"id": "a", "t": "Teaching a client how to use a walker to get to the bathroom"}, {"id": "b", "t": "Assisting a client who has difficulty seeing the foods on the tray while eating"}, {"id": "c", "t": "Obtaining a straight-catheter urine specimen."}, {"id": "d", "t": "Monitoring a postoperative client who is confused"}], "correct": "b", "rationale": ". Assisting a client who has a vision deficiency to eat is an appropriate task to delegate to an AP. OB a cei", "whyNot": {"a": "Teaching a client is not within the range of function of the AP.", "c": "Placing a catheter is invasive and requires sterile technique. This task is not within the range of function of an AP. iii]", "d": "A nurse who uses the five rights of delegation is responsible for delegating tasks to the right person. The client who is postoperative and 2"}, "keyConcept": "A nurse who delegates tasks to other staff members is responsible for abiding by the five rights of delegation. The five rights of delegation include: + Right task + Right circumstance + Right person + Right direction and communication + Right supervision and evaluation"}, {"id": 11209, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse on a pediatric unit is planning care for a group of clients. Which of the following clients should the nurse plan to assess first?", "choices": [{"id": "a", "t": "Aschool-age child who has diabetes mellitus and requires blood glucose monitoring"}, {"id": "b", "t": "An infant who has pertussis and is receiving oxygen via nasal cannula"}, {"id": "c", "t": "An adolescent who is one day status-post an appendectomy"}, {"id": "d", "t": "A toddler who is scheduled for an upper gastrointestinal x-ray series"}], "correct": "b", "rationale": ". Using the airway, breathing, circulation (ABC) approach to prioritizing client care, the nurse should assess this infant first because the OB a 73% infant has a compromised airway and requires oxygen. ° cil 9%", "whyNot": {"a": "The nurse should monitor the blood glucose level of a child who has diabetes mellitus because the child might need care to manage", "c": "The nurse should assess the adolescent who is postoperative to ensure there are no postoperative complications, such as infection.", "d": "The nurse should assess the toddler who is scheduled for x-rays to ensure the toddler has remained NPO prior to the procedure. However,"}, "keyConcept": "When planning care for multiple clients, it is important for the nurse to set priorities. The first step in prioritizing care is to identify each client's diagnoses and classify these as high, intermediate, or low priority. The highest priorities are assigned to those clients whose condition which, if untreated, can result in harm to the client. Examples of high priorities include those that address airway, breathing, and circulation, safety, and pain."}, {"id": 11210, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "bath. Which of the following is the most appropriate intervention by the nurse?", "choices": [{"id": "a", "t": "Encourage the client to go for her scheduled bath"}, {"id": "b", "t": "Ignore the situation as the aide clearly has the situation under control"}, {"id": "c", "t": "Report the aide’s rough handling of the client to your immediate supervisor"}, {"id": "d", "t": "Call the client’s physician"}, {"id": "e", "t": "Attempt to talk to the aide privately and tell her that you will report her should you observe her mistreating a client again"}], "correct": "c", "rationale": "’s immediate supervisor as soon as possible, thus prioritizing the client’s safety and B a autonomy.", "whyNot": {"a": "The client has the right to refuse her bath. Forcing a client to take a bath or to submit to other treatment without consent could be", "b": "Ignoring a situation in which a staff member mistreats a client is tantamount to acceptance of the behavior. There should be a zero", "d": "The charge nurse is capable of handling this situation independently, although the physician may eventually be notified. The client’s", "e": "Attempting to talk to the UAP privately is not be the first priority in this situation. In this case, making sure that the nurse’s immediate"}, "keyConcept": "Unlicensed assistive personnel are unlicensed health care personnel who provide direct client care under the delegation and supervision of a registered nurse. Licensed nurses have accountability for the management and provision of nursing care, including all delegation decisions. Nurses are accountable for the delivery of safe, competent care to clients entrusted to them; this obligation is founded on the ethical principles of fidelity and respect for persons. Nurses have a professional responsibility to the public and the profession at large to ensure that safe and competent care is provided to clients."}, {"id": 11211, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a stable client who was admitted for myocardial infarction 3 days ago. Which of the following tasks can the nurse safely delegate to an experienced unlicensed assistive personnel (UAP?)", "choices": [{"id": "a", "t": "Low-sodium diet teaching"}, {"id": "b", "t": "Teaching about risk factors for coronary disease"}, {"id": "c", "t": "Measuring intake and output"}, {"id": "d", "t": "Auscultating the abdomen and lungs"}], "correct": "c", "rationale": "| 2% Easy The nurse should never delegate teaching responsibilities or physical assessment to an aide. The RN cannot delegate any part of the nursing B | a0 process. Measuring intake and output is within the scope of practice for an experienced nurse’s aide.", "whyNot": {"a": "Itis not within the aide’s scope of practice to provide teaching to the client.", "b": "This is outside of the UAP’s scope of practice; it should be done by an RN.", "d": "This is part of the assessment. The nurse cannot delegate any part of the nursing process, including the assessment."}, "keyConcept": "A nurse cannot delegate the nursing process to the UAP. When the nurse delegates a task, the UAP can accept responsibility for the task based on his/her competence level and while the Nurse retains accountability for the delegated activity."}, {"id": 11212, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following is addressed by the Patient Self-Determination Act?", "choices": [{"id": "a", "t": "Whether the client has an advance directive"}, {"id": "b", "t": "The client's right to confidentiality of medical records"}, {"id": "c", "t": "Whether the client is able to pay for health care services"}, {"id": "d", "t": "The client's right to access areas of the facility"}], "correct": "a", "rationale": "@ -Determination Act (PSDA) supports the client’s decisions to care for himself and to decide who will make decisions for him if B . oR he is unable to do so. One aspect of the PSDA is to encourage the client to have an advance directive. According to the Act, health care facilities must ask clients upon admission whether they have an advance directive and provide information about client rights upon c | 3% admission.", "whyNot": {"b": "This is a right through HIPAA, not the Patient Self-Determination Act.", "c": "This does not describe the correct answer.", "d": "The client may not have access to all areas of the facility."}, "keyConcept": "The Patient Self Determination Act was passed into law in 1990 and requires hospitals, nursing homes, home health agencies, hospice providers, health maintenance organizations (HMOs), and other health care institutions to provide information about advance health care directives to individuals upon their admission to the healthcare facility. Client rights include the right to make their own health care decisions; the right to accept or refuse medical treatment; and the right to make an advance health care directive. Healthcare facilities must ask whether the client already has an advance health care directive, document the information in the medical record, and provide education to staff about advance health care directives."}, {"id": 11213, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "seem suspicious for intoxication at work. Which of the following is the most appropriate initial intervention by the agency nurse?", "choices": [{"id": "a", "t": "Remain silent unless the nurse appears unable to perform the job safely."}, {"id": "b", "t": "File an anonymous complaint with the department of human resources."}, {"id": "c", "t": "Confront the nurse and ask for an explanation."}, {"id": "d", "t": "Discuss these concerns with the nursing supervisor."}], "correct": "d", "rationale": "-worker, as B | 3\" this could result in client harm and may also be a criminal violation. The nurse should report the concerns confidentially to the nursing supervisor, who can then determine the next intervention. The nursing supervisor must take a reasonable report of suspicion of substance c | ™% abuse to the correct authorities, which include the nursing board and a designated institutional representative within the facility. The @ .", "whyNot": {"a": "A confidential report with the nursing supervisor is necessary so that any reasonable suspicion of impairment can be investigated", "b": "A nurse should report confidentially to the appropriate nursing supervisor, who can investigate and notify the appropriate agencies and", "c": "Speaking directly with the nurse involved can result in confrontation or may simply be ignored. This behavior will expose clients to a"}, "keyConcept": "Legal requirements to report suspected substance-abuse by a nurse vary among individual states, but nurses have an ethical and moral duty to protect clients, colleagues, the profession of nursing, and the community by reporting suspected impairment by a colleague."}, {"id": 11214, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which skill do nurses need to adequately advocate for their clients, particularly when conflicts arise?", "choices": [{"id": "a", "t": "Collaboration"}, {"id": "b", "t": "Compassion"}, {"id": "c", "t": "Caring"}, {"id": "d", "t": "Assertiveness"}], "correct": "d", "rationale": "A || 19% Moderate The skill that nurses need to adequately advocate for their clients, particularly when conflicts arise, is assertiveness. It is the duty of the B 1] 11% fo nurse to advocate for the client. Other skills that are needed in terms of advocacy are superior communication, the willingness to take risks, and self-confidence. Compassion and caring are values that are integrated into all aspects of nursing care; they are not skills. c I 4%", "whyNot": {"a": "Collaboration may be necessary when dealing with others or working on a team, but this does not best describe advocacy.", "b": "Compassion is not considered a skill.", "c": "Caring, although necessary for advocacy, is not considered a skill."}, "keyConcept": "The nurse acts as an advocate by speaking up for client care issues even when others may disagree. The nurse has a unique opportunity to assess the client's point of view and uses this unique knowledge when acting as an advocate. To be an effective advocate, the nurse should be sensitive to the client's needs and values and able to articulate them. Assertiveness allows the nurse to advocate for a client without sounding judgmental or argumentative in a situation where others may disagree.. Assertive communication includes the use of intermittent eye contact; nonverbal communication that reflects honesty, active listening, and interest in the other's point of view; confident response; and awareness of cultural differences in communication. Assertive communication improves the nurse's ability to attain the goal of communication."}, {"id": 11215, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is documenting in the medical record information of a client and suspects opioid use disorder. Which of the following manifestations should the nurse expect and document in the client’s record?", "choices": [{"id": "a", "t": "Euphoria"}, {"id": "b", "t": "Rhinorrhea"}, {"id": "c", "t": "Yawning"}, {"id": "d", "t": "Dilated pupils"}], "correct": "a", "rationale": "The client who has opioid use disorder can experience euphoria, which is a behavioral manifestation of opioid analgesics. The nurse should B 1] or distinguish between behavioral effects of opioid use and manifestations of withdrawal from opioids and accurately document these in the client's medical records. c | 11% > i”! 34%", "whyNot": {"b": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning.", "c": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning.", "d": "The client who is experiencing withdrawal from opioid use disorder can manifest rhinorrhea, pupillary dilation, and yawning."}, "keyConcept": "Documenting client information is a vital aspect of nursing communication that allows an oncoming nurse to develop a plan of care. It also allows other health care workers who are caring for the client to access the information. Accurate documentation allows the oncoming nurse to identify whether a client is experiencing a behavioral effect of an opioid analgesic or is experiencing withdrawal.\""}, {"id": 11216, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "take first? O A. Prevent cross-contamination of clients. O B. Complete a thorough client assessment. O C. Treat clients arriving at the facility who have yellow triage tags. O D. Maintain a client tracking system.", "choices": [{"id": "a", "t": "Prevent cross-contamination of clients."}, {"id": "b", "t": "Complete a thorough client assessment."}, {"id": "c", "t": "Treat clients arriving at the facility who have yellow triage tags."}, {"id": "d", "t": "Maintain a client tracking system."}], "correct": "a", "rationale": "Adisaster involving the release of a toxic substance indicates that the clients are at greatest risk for cross-contamination between B | at nonexposed clients and exposed clients. Therefore, the priority action is to promote the safety of the clients by separating them to prevent cross-contamination and limit the spread of the unknown toxin. c | 6% om 18%", "whyNot": {"b": "The nurse should complete a thorough client assessment to determine the extent of exposure and injury to the client. However, there is", "c": "The nurse should treat clients who have a yellow triage tag, which indicates a significant injury that requires medical care. However, these", "d": "The nurse should maintain a client tracking system in a disaster situation to track the client's medical record number and information,"}, "keyConcept": "A nurse should identify the priorities of client care during a disaster situation. The nurse should promote the safety of the clients and follow the facility's emergency operation plan (EOP). Some of the components of the EOP can include: + Activation response + Internal/external communication plan + Plan for coordinated client care + Security plans + Identification of external resources + Data management strategy + Education plan for each component"}, {"id": 11217, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a group of clients and is delegating an assistive personnel (AP) to obtain vital signs. Which of the following clients should the nurse assign to the AP?", "choices": [{"id": "a", "t": "A client who is 1 hr postoperative following a thyroidectomy"}, {"id": "b", "t": "A client who is experiencing a new onset of chest pain"}, {"id": "c", "t": "A client who is preoperative and scheduled for gastric bypass surgery"}, {"id": "d", "t": "A client who is newly admitted following a motor vehicle crash and has bruising to the abdomen"}], "correct": "c", "rationale": "all 7% Easy The client's physiologic status and stability are considerations when assigning an AP to collect vital signs. There is no indication that this B | a0 preoperative client is unstable; therefore, the nurse can assign an AP to take vital signs for this client.", "whyNot": {"a": "Clients who are postoperative following a thyroidectomy are at risk for complications, such as hypocalcemia, hemorrhage, respiratory", "b": "The client who is experiencing a new onset of chest pain should be fully assessed by an RN, including vital signs. This client is considered", "d": "The client who experienced abdominal trauma and has bruising to the abdomen might have damage to the internal organs or might be"}, "keyConcept": "Delegation is a complex task that requires the nurse to evaluate multiple factors, including client needs and the clinical situation. Clients who are not physically stable should be assessed by an RN. Even if there is a moderate to a high risk that the client can develop complications or experience a change in status, the nurse should not delegate care tasks for the client, such as vital signs."}, {"id": 11218, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is teaching a group of nurses about the civil judicial process. The nurse manager should include that witness depositions take place during which of the following steps?", "choices": [{"id": "a", "t": "Complaint step"}, {"id": "b", "t": "Discovery step"}, {"id": "c", "t": "Decision step"}, {"id": "d", "t": "Trial step"}], "correct": "b", "rationale": "A | % Hard The nurse manager should include in the teaching that the witnesses’ depositions occur during the discovery step. The discovery step is when attorneys for the plaintiff and the defendant obtain relevant information about the case. cf 5%", "whyNot": {"a": "During the complaint step, the plaintiff files a document alleging either the defendant failed to provide the expected level of safe care or", "c": "During the decision step, the judge provides a decision, or the jury issues a verdict.", "d": "During the trial step, both sides of the dispute are presented to the judge or jury."}, "keyConcept": "In a court of law, there are major steps followed to settle a dispute using the civil judicial process: © The first step includes the filing of a petition that outlines what the defendant failed to do or did to injure the plaintiff. When a client files a lawsuit against a nurse, the client is the plaintiff and the nurse is the defendant. © The second step includes the defendant writing a response in answer to the complaint, either admitting or denying the allegations in the petition. The plaintiff must then respond with supporting information for anything the defendant did not admit to. © The third step is the discovery phase, during which all the facts are gathered to support the plaintiff and defendant. These facts are obtained through the client's medical records, depositions, and interrogatories. Interrogatories are written questions asked and responded to under oath. Depositions are the questions asked to the opposing parties, other witnesses, and experts under oath to extract relevant and non-privileged information about the lawsuit. © The fourth step is the trial phase, which can last 1 to 3 years after the petition is filed. If the lawsuit is not settled out of court, a trial is scheduled and the relevant facts are presented to a judge or jury. © The final step is the decision phase when a judge provides a decision or a jury provides a verdict. If one party is not satisfied with the outcome, that party can file an appeal for another trial."}, {"id": 11219, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse is making assignments for the oncoming shift. Which of the following considerations should the charge nurse consider when making the assignments?", "choices": [{"id": "a", "t": "The National Patient Safety Goals"}, {"id": "b", "t": "Personal comfort level in making the assignments"}, {"id": "c", "t": "Social relationships between nurses working the oncoming shift"}, {"id": "d", "t": "The physiologic status of the clients on the unit"}], "correct": "d", "rationale": "Making assignments requires knowing the physiologic status of the clients on the unit, such as the stability of the clients' vital signs, the amount of health education they need, and the complexity of care involved. Clients who have an unstable physiologic status might require a higher level of skilled care.", "whyNot": {"a": "The National Patient Safety Goals are a set of objectives developed by The Joint Commission to improve client safety. While every member", "b": "The charge nurse's role requires adequate preparation and the ability to make appropriate assignments. The charge nurse should not take", "c": "The charge nurse should be aware of the right person doing the right task for the right person. Social relationships between the nurses"}, "keyConcept": "The nurse should consider five rights of delegation when delegating care or assigning tasks to members of the health care team. The five rights can be utilized whether the nurse is delegating tasks to an LPN or assistive personnel (AP) as well as when a charge nurse is making shift assignments involving all nursing personnel. Task Delegation Raghis o AN To Seal Wa ‘Charge Nurse Waking SRW Tigh Task etogata ony take Bal are win the] Coraider Be lanl care taaka needed Yor Svs ‘delegating nurse's own scope of practice. | clients when making assignments. An LPN or AP For assistive personne! (AP), do not ‘might not be legally permitted to complete some delegate a task that includes aspects of the | client care tasks or care for certain chents. process. Fgh Crear Deiegate only W the cients slabie “Rasta care OT Comtex rene a ore exper personnel, o provide adctonal supervision # ng 10 a newer staf! member Fight Person Cer ‘practical nurse (PNYor | Batance stat ‘Su Tevel and Competen With work load assignments, cal Provide Geer, concise ‘Use Gear. Cordes commaricaton Update sia ‘Communication ‘objectives, time frame for completion. and | regarding admissions, transfers, and discharges ‘expectations. impacting stat! assignment | Right supervison | Supervise or Talo op mo] Provide ro. Us treeded Provide feedback of task ‘evatuation and feedback to stat! members"}, {"id": 11220, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "purposes? O A. Ensuring the client is of age to sign the form O B. Confirming the client appears competent to provide consent O C. Asserting the nurse has explained the risks and benefits of the procedure O D. Recording that the client's partner agrees the procedure is necessary", "choices": [{"id": "a", "t": "Ensuring the client is of age to sign the form"}, {"id": "b", "t": "Confirming the client appears competent to provide consent"}, {"id": "c", "t": "Asserting the nurse has explained the risks and benefits of the procedure"}, {"id": "d", "t": "Recording that the client's partner agrees the procedure is necessary"}], "correct": "b", "rationale": "By signing as a witness on an informed consent form, the nurse is confirming that the client is signing the consent form voluntarily.", "whyNot": {"a": "The nurse's signature does not confirm that the client is of age to sign the consent form. A minor can sign the consent form if the minor is", "c": "It is the responsibility of the provider to explain the risks and benefits of the procedure to the client.", "d": "Although support from the client's partner can be a factor when the client considers surgery, the nurse should respect the ethical principle"}, "keyConcept": "Informed consent includes the provider explaining the risks, benefits, consequences, and alternatives of a procedure, diagnostic procedure, or invasive treatment to the client. This explanation is presented in terms the client can understand in order to facilitate an educated decision. If the client is unable to comprehend the information due to age, medications, injury, or illness, a relative, parent, or guardian can legally sign the informed consent form after the provider has explained the information to them. Minors can also sign a consent form if considered an emancipated. An emancipated minor is a client who is underage and is married, divorced, or widowed, active in the military, or has been designated by a court order. Unemancipated minors can provide consent in certain circumstances, such as a minor who is pregnant, has an STI, needs treatment for substance use disorder, or is in a mental health facility. The nurse who witnesses the signature of the client on the informed consent form is using her signature to indicate the client is signing voluntarily, the signature is authentic, and that the client appears competent."}, {"id": 11221, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who is actively dying. Which of the following actions by the nurse demonstrates the ethical principle of nonmaleficence?", "choices": [{"id": "a", "t": "Discussing advance directives with the client and the client's family"}, {"id": "b", "t": "Providing comfort care measures to the client"}, {"id": "c", "t": "Withholding a dose of pain medication when the client has respiratory depression"}, {"id": "d", "t": "Giving the client privacy during perineal care"}], "correct": "c", "rationale": "A l 3% Moderate The principle of nonmaleficence is the obligation to not cause harm. The nurse should ease the client's pain with the administration of B narcotics. However, if the nurse believes the dose is potentially lethal or could hasten the client's death, the nurse should not administer the medication based on the principle of nonmaleficence. ec | 54% p| 2%", "whyNot": {"a": "Discussing advance directives with the client and the client's family is an example of promoting client autonomy by respecting the client's", "b": "Providing comfort care measures to a client who is dying is an example of the principle of beneficence, which is a moral obligation to act", "d": "The nurse uses the principle of beneficence, which is a moral obligation to act to benefit others, when providing privacy during sensitive"}, "keyConcept": "The principle of nonmaleficence is the obligation to not cause harm. If a nurse believes an action could harm the client, such as administering an analgesic, the nurse should not perform the action. The nurse should provide the client with other pharmacological medications and nonpharmacological interventions to promote comfort and reduce the client's pain."}, {"id": 11222, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Aregistered nurse delegates a routine task to the UAP. Which of the following best describes the legal consequences for the nurse if there is negligence by the UAP?", "choices": [{"id": "a", "t": "The nurse is automatically held liable for negligence on the part of personnel they supervise."}, {"id": "b", "t": "The nurse is only liable for negligence if the task delegated was outside the scope of practice of the UAP."}, {"id": "c", "t": "The RN may be liable if negligent in supervising the UAP."}, {"id": "d", "t": "The RN is only liable if the task was not within the job description of the UAP."}], "correct": "c", "rationale": "i 28% Hard si 24% The scope of liability is increased when an RN acts as a delegator or supervisor to a UAP. This liability is not automatic in acts of negligence ec | 44% by those supervised by the RN, but the RN is responsible for determining whether the subordinate is able to perform a task safely without . The RN may be found liable for negligent acts by a subordinate if the RN is negligent in failing to monitor a subordinate who needs supervision or assigns client needs to a subordinate who is unqualified.", "whyNot": {"a": "The RN is not automatically held liable for all negligent acts by a subordinate, but the RN assumes additional liability when delegating", "b": "The scope of care of UAP varies among states, but many state boards of nursing have published task lists for UAP. Most states have", "d": "Many facilities do not have well-defined job descriptions, and some allow UAPs to perform skills historically reserved for an LPN."}, "keyConcept": "When a nurse delegates a routine task to the UAP, the nurse delegates the responsibility for completion of the task. The nurse remains responsible for the outcome. The nurse may be legally liable for bad outcomes that arise from a failure to appropriately assign a task or monitor a subordinate."}, {"id": 11223, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "| 8x Reco. Mi Inbox M Inbox J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "patient diagnosed with AIDS asks about the possibility of using hospice. In order to be eligible for hospice care, the patient must:"}, {"id": "b", "t": "There is no requirement that a client be willing to discuss his prognosis; in fact, hospice personnel are skilled in helping clients talk"}, {"id": "c", "t": ", the client must have two physicians who are willing to attest that the client has a life expectancy of B | 3\" less than six months, if the disease follows its normal course."}, {"id": "d", "t": "Finally, one of the general requirements of hospice is that the client does not pursue further curative treatment since it has been"}], "correct": "c", "rationale": ", the client must have two physicians who are willing to attest that the client has a life expectancy of B | 3\" less than six months, if the disease follows its normal course.", "whyNot": {"a": "Although cancer is one of the major diagnoses associated with hospice, it is not a requirement for hospice care.", "b": "There is no requirement that a client be willing to discuss his prognosis; in fact, hospice personnel are skilled in helping clients talk", "d": "Finally, one of the general requirements of hospice is that the client does not pursue further curative treatment since it has been"}, "keyConcept": "Hospice is an opportunity for clients facing a life-limiting illness or injury, hospice care to receive compassionate medical care, pain management, and emotional/spiritual support, through a team-oriented approach tailored to the client's needs and wishes. Hospice care also provides support to the client's family members."}, {"id": 11224, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "| 8x Reco. Mi Inbox M Inbox J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "mother and recent immigrant from Central America brought her 3-month-old daughter to the emergency department with a fever of 103 degrees F. The child's father is on his way and should arrive within the"}, {"id": "b", "t": "A i 9% Moderate In a traditional Hispanic culture, the man is recognized as the head of household."}, {"id": "c", "t": "In this scenario, there is no indication that abuse or neglect is occurring that might warrant a call to CPS. Even though health care workers"}, {"id": "d", "t": "The mother has not refused the procedure, so the nurse should not document that."}], "correct": "b", "rationale": "A i 9% Moderate In a traditional Hispanic culture, the man is recognized as the head of household. In a non-emergent situation, should the mother's wishes OB rt an should be respected and the healthcare team should wait for the father to arrive before proceeding. I ° © 3%", "whyNot": {"a": "There is no reason to call the social worker unless the situation is emergent and the mother is still hesitating.", "c": "In this scenario, there is no indication that abuse or neglect is occurring that might warrant a call to CPS. Even though health care workers", "d": "The mother has not refused the procedure, so the nurse should not document that."}, "keyConcept": "In this case, the situation is not life-threatening and the nurse understands the cultural implications of the mother's request. In an emergency, healthcare providers are not held liable for treating a minor without parental consent if immediate injury or death could result from the delay associated with attempting to obtain parental consent. If the minor's condition is life-threatening but does not require immediate medical attention, a court order must usually be obtained."}, {"id": 11225, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "the appropriate action by the nurse?", "choices": [{"id": "a", "t": "Reprimand the UAP for today’s tardiness"}, {"id": "b", "t": "The nurse should not report the UAP without proof of chemical impairment"}, {"id": "c", "t": "Report the UAP to the nursing supervisor for suspected chemical impairment."}, {"id": "d", "t": "Ask the other staff members what they think is going on with the UAP."}], "correct": "c", "rationale": "al 2% Easy The nurse must immediately report the UAP for suspected chemical impairment. It is unnecessary for the nurse to establish proof before B | 3\" reporting. All substance abuse and impairments severely jeopardize client care and safety, therefore, it must be immediately reported.", "whyNot": {"a": "Reprimanding the UAP will not solve the situation; the nurse must report it.", "b": "The nurse should not keep her suspicions to herself; she should report even if she has no proof.", "d": "It is not appropriate to involve other staff members in this situation; the nurse should report it to her supervisor."}, "keyConcept": "It is the nurse's duty to report an impaired UAP to the immediate supervisor to prevent harm to clients and to reduce the employer's risk of legal liability. The supervisor will follow agency policy to confront the UAP, establish proof, collect evidence, or notify law enforcement personnel if necessary."}, {"id": 11226, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is presenting an in-service to staff nurses about methods to reduce the costs of client care delivery. Which of the following statements indicates an understanding of the teaching? O A.\"I should wait to empty my client's drainable colostomy until it is three-fourths full.\" O B. \"I should delegate providing closed irrigation to an assistive personnel.\" O C.\"I should use the minimum amount of dressings when providing wound care.\" O D.\"| should use sterile gloves when providing site care to clients who have peripheral IV sites.\"", "choices": [{"id": "a", "t": "Hi 18%"}, {"id": "b", "t": "It is cost-effective to delegate basic tasks to the AP, but the nurse should not delegate a skill requiring the use of sterile technique to the AP."}, {"id": "c", "t": "A Hi 18% Moderate Cost containment is the delivery of effective and efficient care."}, {"id": "d", "t": "The nurse should use clean gloves when providing site care to clients who have peripheral IV sites. Evidence-based practice indicates that"}], "correct": "c", "rationale": "A Hi 18% Moderate Cost containment is the delivery of effective and efficient care. Cost should be maintained without loss of quality. The nurse should use the B I a minimum amount of dressings when providing wound care.", "whyNot": {"a": "The nurse should empty the client's drainable colostomy when it is one-third to half full. If the nurse waits until it is three-fourths full, the", "b": "It is cost-effective to delegate basic tasks to the AP, but the nurse should not delegate a skill requiring the use of sterile technique to the AP.", "d": "The nurse should use clean gloves when providing site care to clients who have peripheral IV sites. Evidence-based practice indicates that"}, "keyConcept": "Nurses do not often link the use of health supplies and equipment to organization finances, nor the amount the client eventually has to pay. However, it is possible for nurses to reduce the cost of client care delivery by managing time, staff resources, and products responsibly in order to limit unnecessary client costs."}, {"id": 11227, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which client right is MOST similar to autonomy?", "choices": [{"id": "a", "t": "Self-determination"}, {"id": "b", "t": "Confidentiality"}, {"id": "c", "t": "Cogency"}, {"id": "d", "t": "Family involvement"}], "correct": "a", "rationale": "Autonomy is most similar to the client right of self-determination. Autonomy is defined as freedom and independence. Self-determination is B I Et defined as the person’s right to make choices with free will and without any coercion. Clients have the right to freely and independently make decisions without any coercion by others in a supportive and nonjudgmental environment, even when the nurse or another healthcare c | 2% professional does not agree with these decisions.", "whyNot": {"b": "Confidentiality is the protection of private information; it does not describe autonomy.", "c": "Cogency refers to being logical or convincing; it is not the same as autonomy.", "d": "Family involvement does not describe autonomy, which is a client’s rights to make his own decisions."}, "keyConcept": "The Patient Self-Determination Act (PSDA) is a federal law requiring mandatory compliance by healthcare organizations with specific measures to ensure that a client's right to self-determination in health care decisions is protected and that the client's decisions are communicated through advance directives, including the living will and the durable power of attorney for healthcare."}, {"id": 11228, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who is scheduled for a total hip arthroplasty. Which of the following tasks is the nurse's responsibility?", "choices": [{"id": "a", "t": "Verify that the client understands the procedure they are having done."}, {"id": "b", "t": "Explain the procedure to the client."}, {"id": "c", "t": "Inform the client of the risks of the procedure."}, {"id": "d", "t": "Provide information about alternate treatments."}], "correct": "a", "rationale": "The nurse's role in witnessing informed consent is to ensure that the client has been given an explanation of the procedure by the provider B | a0 and fully understands the risks and benefits of the procedure. c | 2% Incorrect Answer: . It is the responsibility of the provider to explain the procedure to the client. C. It is the responsibility of the provider to inform the client of the risks of the procedure. D. It is the responsibility of the provider to provide information about alternate treatments.", "whyNot": null, "keyConcept": "When witnessing an informed consent, the nurse must ensure that the client understands the procedure that is to be performed. If the client"}, {"id": 11229, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is planning care for a client who has anorexia nervosa and has been admitted for cardiac arrhythmias. Which of the following client goals should the nurse identify as the priority?", "choices": [{"id": "a", "t": "Attain a weight that is greater than the 75th percentile for ideal body weight."}, {"id": "b", "t": "Acknowledge misperceptions about body image."}, {"id": "c", "t": "Verbalize having a sense of control over behaviors."}, {"id": "d", "t": "Identify changes within the client's family unit that promote the client's autonomy."}], "correct": "a", "rationale": "A client who is less than 75% of their ideal body weight is at increased risk for systemic complications, including arrhythmias, electrolyte B ri Darn imbalances, cerebral atrophy, and renal failure. When using Maslow's hierarchy of needs, the nurse should determine the priority goal is to meet the physiological need for adequate nutrition. This means working with the client to attain an increase in weight. c |_| 16% of ™%", "whyNot": {"b": "A client who has anorexia nervosa can have a severely distorted body image, such as viewing themselves as fat despite obvious", "c": "A client who has anorexia nervosa can experience obsessions, such as thinking constantly about food to the extent that food is concealed", "d": "Family members can experience a sense of powerlessness and guilt about the client's diagnosis. Family therapy works toward developing"}, "keyConcept": "Priority setting involves establishing a sequence for addressing client needs. One framework that is often used for establishing priorities is Maslow's hierarchy of needs. The nurse should also recognize that priorities can change over time, so reassessment of client's needs is important."}, {"id": 11230, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following actions should the nurse manager take first?", "choices": [{"id": "a", "t": "Gather data about the nurse's work performance and attendance history."}, {"id": "b", "t": "Approach the involved nurse to discuss the behavior."}, {"id": "c", "t": "Provide the staff with resources for learning about substance use disorder."}, {"id": "d", "t": "Refer the nurse to the board of nursing diversion program."}], "correct": "a", "rationale": "Gather data about the nurse's work performance and attendance history. (correct) B rid oan fo Rationale A. Evidence-based practice indicates that the first action the nurse manager should take is to conduct an investigation and c | 1% determine if the allegations are true. The nurse manager should collect data to determine if the nurse is chemically impaired. The nurse , and another nurse if possible, should both objectively note in writing the following information: + Behavior + Work performance", "whyNot": {"b": "The nurse manager should approach the involved nurse to discuss the behavior; however, evidence-based practice indicates there is", "c": "The nurse manager should provide the staff with resources for learning about substance use disorder; however, evidence-based practice", "d": "The nurse manager should report the incident to the board of nursing if the suspicion of drug diversion is founded; however, evidence-"}, "keyConcept": "The nurse manager has an obligation to address employee reports of possible co-worker impairment. After gathering evidence, the nurse manager can decide whether or not the reports are true. The nurse manager has to maintain client safety first and foremost and then assist the impaired worker with meeting the expectations of the organization prior to returning to work."}, {"id": 11231, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "about how the heart works?” Which of the following negotiating tactics does this represent?", "choices": [{"id": "a", "t": "Ambiguous questioning"}, {"id": "b", "t": "Compromising"}, {"id": "c", "t": "Helplessness"}, {"id": "d", "t": "Competing"}], "correct": "a", "rationale": "The CEO is using an ambiguous (inappropriate) question that is irrelevant to the negotiation. A nurse who is skilled at managing conflict will B | at learn to recognize destructive and dishonest negotiation tactics and remain focused on the negotiation instead of the diversion. This can be difficult if a person of authority is using a dishonest negotiation tactic. © | 20) oe | 4% When managing a conflict, the optimal goal is to create a win-win situation. Since this is not always feasible, the manager should try to reduce the perception of the differences that may exist between the negotiating parties through the use of conflict resolution approaches like compromising, collaborating, cooperating, and accommodating. The strategy that can most successfully be used will depend on the situation. Factors that influence the type of negotiation include power and status of players, importance and urgency of the issues, and maturity of the individuals involved in the conflict. Managers should be able to recognize destructive negotiation tactics and develop the skill to overcome these tactics with a straightforward, honest approach to negotiation.", "whyNot": {"b": "Compromising refers to conflict resolution in which each party gives up something to reach a resolution.", "c": "Helplessness is a diversionary negotiation tactic that nurses may be more susceptible to because the profession of nursing generally", "d": "Competing is an approach to resolving conflict in which a party seeks to win without compromise and with no regard for the interests of"}, "keyConcept": "A nurse who is skilled at managing conflict will learn to recognize destructive and dishonest negotiation tactics. The nurse should remain focused on the negotiation and should ignore inappropriate negotiating tactics."}, {"id": 11232, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse hears a provider yelling at a staff nurse about the lack of supplies available to perform a procedure. Which of the following statements by the charge nurse is appropriate? O A.\"You should think about how you make others feel when you lose your temper.\" O B. \"I will help you with this procedure instead of the staff nurse.\" O C. \"It must be very frustrating when you don't have what you need to perform the procedure.\" O D.\"No one knew you were planning to perform a procedure. We cannot be blamed for not having the supplies needed.\"", "choices": [{"id": "a", "t": "The communication techniques used during conflict can either enable resolution or provoke further confrontation. This statement by the"}, {"id": "b", "t": "By using this approach, the charge nurse is avoiding the conflict. It is not effective, because it results in a lack of trust between the"}, {"id": "c", "t": "This statement by the charge nurse is an example of empathy, a therapeutic communication technique. The charge nurse is B at"}, {"id": "d", "t": "This statement by the charge nurse is an example of a defensive response. It is nontherapeutic and ignores the concerns of the provider"}], "correct": "c", "rationale": "all 6% Easy C. This statement by the charge nurse is an example of empathy, a therapeutic communication technique. The charge nurse is B | at acknowledging the provider's frustration, which can lead to resolution of the conflict.", "whyNot": {"a": "The communication techniques used during conflict can either enable resolution or provoke further confrontation. This statement by the", "b": "By using this approach, the charge nurse is avoiding the conflict. It is not effective, because it results in a lack of trust between the", "d": "This statement by the charge nurse is an example of a defensive response. It is nontherapeutic and ignores the concerns of the provider"}, "keyConcept": "The nurse should recognize that incivility is a component of workplace violence. Incivility includes a spectrum of behaviors from physical violence to eye-rolling, yelling, or disparaging comments. The nurse should implement facility policies that address workplace violence and identify tools that can be used to address disruptive behaviors when they occur."}, {"id": 11233, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse is delegating tasks to a licensed practical nurse (LPN). Which of the following criteria is the priority for the charge nurse to consider when delegating?", "choices": [{"id": "a", "t": "Facility policies"}, {"id": "b", "t": "The acuity of the clients"}, {"id": "c", "t": "The documented skill level of the LPN"}, {"id": "d", "t": "State Nurse Practice Act"}], "correct": "d", "rationale": "A | % Hard According to evidence-based practice, the nurse should first consider the state Nurse Practice Act, which provides the legal authority for B | ma fo nursing practice. A state's Nurse Practice Act specifies the qualifications and responsibilities of nurses and outlines the specific tasks that nurses can legally perform based upon their educational preparation. c |_| 20%", "whyNot": {"a": "When planning delegation, the charge nurse should take into account a number of factors, including the policies and procedures of the", "b": "The charge nurse should consider the established standards of care when planning delegation. The professional judgement of the charge", "c": "Delegation involves nursing judgment and evaluation of the skills and educational level of the nurse being assigned to client care. The LPN"}, "keyConcept": null}, {"id": 11234, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who has alcoholic liver disease with cirrhosis. Which of the following tasks can the nurse assign to the unlicensed assistive personnel (UAP)?", "choices": [{"id": "a", "t": "Assess skin for breakdown"}, {"id": "b", "t": "Administer lactulose prescribed by the healthcare provider"}, {"id": "c", "t": "Evaluate for asterixis"}, {"id": "d", "t": "Assist with personal hygiene"}], "correct": "d", "rationale": "| 2% Easy ’s job description, knowledge base, and demonstrated competence at the c | 2% task. The RN should recognize that training standards have not been established at the community level or federal level for unlicensed e@D PY 94% assistive personnel, and the responsibility for appropriate completion of client care tasks rests with the delegator. The nursing process cannot be delegated. The UAP can assist with bathing and hygiene, client transportation, assisting with procedures, and cleaning up after {) procedures. 2 ® 2. 3 a =", "whyNot": {"a": "Assessment cannot be delegated by an RN to the UAP. <", "b": "Medication administration cannot be delegated to the UAP.", "c": "Nurses cannot delegate evaluation to a subordinate."}, "keyConcept": "Tasks that can be delegated to unlicensed assistive personnel include ADLs, bathing, grooming, dressing, toileting, ambulating, feeding (without swallowing precautions), positioning, bed making, specimen collection, 1&0, and vital signs for stable clients."}, {"id": 11235, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "charge nurse assign this client? O A. The nursing assistant O B. The licensed practical nurse O C. The registered nurse O D. Either the registered nurse or the licensed practical nurse", "choices": [{"id": "a", "t": "The nursing assistant"}, {"id": "b", "t": "The licensed practical nurse"}, {"id": "c", "t": "The registered nurse"}, {"id": "d", "t": "Either the registered nurse or the licensed practical nurse"}], "correct": "c", "rationale": ", complex physical B 1% needs. The licensed practical nurse can be assigned client care when the client needs are relatively predictable, chronic and without | complexity. When the client is stable, the licensed practical nurse can then be assigned to care for this client. Lastly, nursing assistants are ec Ft 92% not delegated complete client care; nursing assistants and other unlicensed assistive staff can only be delegated some aspects of care .", "whyNot": {"a": "Anursing assistant cannot be delegated the admission of this client.", "b": "This client has acute and complex care needs and should be cared for by a registered nurse.", "d": "The registered nurse should care for this client because the client requires complex care and may be unstable."}, "keyConcept": "The charge nurse should consider staff competence, level of training, education, and scope of practice when delegating or assigning client care tasks. The clients with the greatest complexity should be assigned to the most experienced RN. When delegating tasks, the nurse retains accountability for the outcome. When assigning client care, the nurse who accepts the assignment has responsibility for the outcome."}, {"id": 11236, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse who is employed at a community mental health center participates in a program to screen adolescents for substance use disorder. This type of intervention represents which of the following?", "choices": [{"id": "a", "t": "Primary prevention"}, {"id": "b", "t": "Secondary prevention"}, {"id": "c", "t": "Tertiary prevention"}, {"id": "d", "t": "Assertive community treatment"}], "correct": "b", "rationale": "A || 19% Moderate Prevention activities reduce health risks in a population. Secondary prevention focuses on early detection of a disease or condition, which Cc l 3% provides an opportunity to intervene before a condition is advanced and to halt or slow progression and return individuals to health.", "whyNot": {"a": "Primary prevention refers to preventing a disease or condition before it occurs by reducing or preventing exposure to factors associated", "c": "Tertiary prevention refers to reducing the impact of a condition or disease by managing long-term care and facilitating improvement in", "d": "Assertive community treatment refers to a nontraditional model of case management, usually by an interprofessional team and targeted"}, "keyConcept": "Prevention activities reduce health risks within a population. Although primary prevention is targeted at preventing onset of a disease or condition by reducing risk factors, secondary prevention activities detect behaviors or conditions that have already occurred at an early stage, with the intention of reducing the harm before the condition advances."}, {"id": 11237, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "An unlicensed assistive personnel (UAP) reports to the nurse that a client was found on the floor. Which of the following should the nurse do after ensuring the client's safety?", "choices": [{"id": "a", "t": "Document the event in the client’s chart and file an incident report"}, {"id": "b", "t": "File the incident report only"}, {"id": "c", "t": "Document the event in the client’s medical record and have the UAP file an incident report"}, {"id": "d", "t": "Document the event in the client’s record only"}], "correct": "c", "rationale": "It is the responsibility of the RN to document the event in the medical record. It is the responsibility of the UAP to file the incident report B a Bay because the UAP found the client. The incident report does not become part of the medical record. ° oc i 30%", "whyNot": {"a": "The incident report should be filed by the person who found the client; in this case, it is the nursing assistant.", "b": "An incident report is important but the event must also be documented in the medical record.", "d": "The UAP must file an incident report."}, "keyConcept": "An incident report provides a formal record of facts related to an incident or injury. The incident report should be completed as soon as possible following the injury, by individuals who witnessed the incident. The report is used by the healthcare facility to improve safety, although it may be provided to insurers, overseeing regulatory bodies or law enforcement. The incident report should not be mentioned or entered into the client's medical record, but the event should be documented in the medical record by the nurse."}, {"id": 11238, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "@ @ X Viral x Reco. ™M™ Inbox ™ Inbox {J untit! Untit! (4 Gooo @ TEAS Onlin @ Mark @ Micre (eeinmenurmelicr @ atit = G@ New ‘oma kK x) 2S ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : Oo Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Call for a Vietnamese translator"}, {"id": "b", "t": "Have the client sign the consent form"}, {"id": "c", "t": "Have the son translate the pre-operative information for the client"}, {"id": "d", "t": "Inform surgery that the surgery will have to be rescheduled"}], "correct": "a", "rationale": "Informed consent implies that the client has received the appropriate information and has had an opportunity to talk about risks with the . In a situation in which this exchange cannot occur directly because of language differences, the nurse must call a professional translator who can accurately translate between the client and the surgeon. Asking a family member to translate can violate client © | i) confidentiality rights.", "whyNot": {"b": "Having the client sign the consent form without adequate explanation is not informed consent and the nurse must act as the client’s", "c": "In most cases, having any family member translate may not be appropriate since the the client's confidentiality may be violated and the", "d": "In appendicitis, rupture usually occurs within 24 hours of onset of pain and can lead to peritonitis and death. The surgery cannot be"}, "keyConcept": "Communication is essential when providing care or obtaining consent. If there is a language barrier, the nurse should contact a professional translator or use a telephone translation service, which will ensure the client receives accurate medical information and has an opportunity to ask questions and voice understanding. Use of a family member as a translator can violate client confidentiality and the nurse cannot be certain that the client has received the correct information."}, {"id": 11239, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following nursing diagnoses suggests that the client may not be able to provide informed consent?", "choices": [{"id": "a", "t": "Impaired nutritional status related to malabsorption"}, {"id": "b", "t": "Illegible handwriting related to left-sided weakness"}, {"id": "c", "t": "At risk for falls related to delirium"}, {"id": "d", "t": "Impaired speech related to expressive aphasia"}], "correct": "c", "rationale": "/she is not mentally competent to do so. All clients with delirium are not B I Ee incompetent, however, and competence should be formally assessed in these clients. Illegible handwriting, aphasia, left-sided weakness, and malabsorption do not indicate that the client is unable to sign a consent. ec a 82% of 12%", "whyNot": {"a": "The impaired nutritional status would not necessarily reflect a client’s ability to sign a consent.", "b": "Left-sided weakness may affect the client’s ability to physically write his signature, but he may still understand the consent.", "d": "Expressive aphasia does not necessarily mean a client does not understand the consent."}, "keyConcept": "A client with delirium has acute and fluctuating impairment of cognition and memory. Clients with delirium should be assessed on an individual basis to determine whether or not they have the capacity to understand the risks, benefits, adverse effects, and alternatives to treatment when informed consent is necessary. If the client is incompetent, a surrogate or family member should be consulted. In an emergency, the doctrine of implied consent allows necessary treatment to preserve life and limb."}, {"id": 11240, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "\"My partner isn't getting any better and it's the fault of the staff here.\" Which of the following actions should the nurse take to decrease conflict?", "choices": [{"id": "a", "t": "Offer to sit with the client and his partner in the dining room to talk about the conflict."}, {"id": "b", "t": "Avoid making direct eye contact with the client or his partner."}, {"id": "c", "t": "Stand with her hands at her side when talking to the client and his partner."}, {"id": "d", "t": "Contradict the partner's statement by telling the client and partner about the competence of the nursing staff."}], "correct": "c", "rationale": "The nurse should avoid standing in a defensive posture, such as with arms crossed, or using hostile body language, such as pointing at the B 0% individuals who are angry, especially if the gestures are combined with a frowning facial expression. The nurse should stand with her arms at her side or raised openly toward the client and his partner. The nurse should move toward the client and his partner rather than backing ec | 33% away, but should avoid standing within their personal space. Standing closer than 0.46 m (1.5 feet) to angry individuals can invade their , which could escalate the conflict. The nurse's tone of voice should remain neutral, sending a message of calmness and ww confidence. 2 ® 2.", "whyNot": {"b": "The nurse should make eye contact with the client and his partner. It is important to keep cultural differences in mind when deciding how", "d": "The nurse should avoid defensive communication techniques, such as contradicting the partner's statements. The nurse should attempt"}, "keyConcept": "When faced with a conflict situation, the nurse should utilize the principles of therapeutic verbal and nonverbal communication. The nurse's body position and tone of voice should demonstrate confidence and the willingness to converse about the topic of conflict. Use of nonjudgmental language and techniques such as active listening, clarifying, and focusing can help de-escalate a conflict situation and allow all participants to discuss the situation openly."}, {"id": 11241, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "and follows through with this act. Which of the following ethical principles is the nurse demonstrating?", "choices": [{"id": "a", "t": "Justice O B.Fidelity"}, {"id": "b", "t": "al 3% Easy Fidelity is the ethical principal of keeping a promise."}, {"id": "c", "t": "Autonomy"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "b", "rationale": "al 3% Easy Fidelity is the ethical principal of keeping a promise. The nurse is demonstrating the ethical principle of fidelity by promising the client to OB rsd ers return soon with prescribed pain medication to treat the client's pain. c] 4%", "whyNot": {"a": "Justice is the ethical principle of fairness. The nurse is demonstrating the ethical principal of justice by ensuring fair distribution of", "c": "Autonomy is the ethical principle of freedom of choice. The health care team respects autonomy for clients by including them in decision-", "d": "Nonmaleficence is the ethical principle to do no harm."}, "keyConcept": "Ethical principles reflects the guiding beliefs and values that the nurse should incorporate when practicing the profession. These moral principles are described in the formal code of professional ethics and all stem from the basic principal of respect for people. Ethical Principles Autonomy Client's right to make their own decision Beneficence Taking positive actions to help others Nonmaleficence ‘Avoiding the occurrence of causing harm Justice Treating all clients fairly Fidelity ‘Agreeing to keep a promise"}, {"id": 11242, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is preparing to contact a provider regarding a client. When using the SBAR communication tool, which of the following statements should the nurse include in the B step? O A.\"The client should be seen by a neurologist.\" O B. \"The client was found unconscious on the floor in her home.\" O C. \"The client is a 32-year-old female who was admitted this morning following a syncopal episode and is now experiencing seizures.’ O D. \"The client is disoriented. Pupils are slow to respond to light.\"", "choices": [{"id": "a", "t": "1%"}, {"id": "b", "t": ", which is the B step in the SBAR tool."}, {"id": "c", "t": "This statement is the situation as it relates to the client, which is the S step in the SBAR tool. This step provides brief information about the"}, {"id": "d", "t": "This statement is the assessment as it relates to the identified problem, which is the A step in the SBAR tool. This step can include the"}], "correct": "b", "rationale": ", which is the B step in the SBAR tool. The background portion should provide OR rs BavE information that is pertinent to the current situation. The SBAR Process 1. Organize relevant information in sequence using the SBAR format (Situation, Background, Assessment, Recommendation). 2. Present the information. 3. Work with the provider to clarify or enhance the information and obtain prescriptions for required actions.", "whyNot": {"a": "This statement is the recommendation for action, which is the R step in the SBAR tool. The recommendation provides opinions or new", "c": "This statement is the situation as it relates to the client, which is the S step in the SBAR tool. This step provides brief information about the", "d": "This statement is the assessment as it relates to the identified problem, which is the A step in the SBAR tool. This step can include the"}, "keyConcept": "The SBAR is a communication model that provides a standardized framework for communicating important information between members of the health care team. In addition to organizing the information prior to presenting it, the nurse should also have additional documentation available, such as the client's EMR, recent laboratory or radiology findings, current vital signs, and other assessment data."}, {"id": 11243, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "equipment by personnel. Which of the following recommendations should the nurse make to correct the lack of policy and procedures concerning use of equipment?", "choices": [{"id": "a", "t": "Have a subcommittee or work group write procedures relating to the proper use of pieces of equipment used by nursing staff"}, {"id": "b", "t": "Use a current nursing procedures textbook relating to the proper use of pieces of equipment used by nursing staff"}, {"id": "c", "t": "Use a database like the Cochrane Library for evidence-based practices for nurses"}, {"id": "d", "t": "Collect and publish the manufacturers’ instructions for pieces of equipment used by nursing staff"}], "correct": "d", "rationale": "A | | 22% Hard Collecting and publishing the manufacturers’ instructions for all pieces of equipment that are used by nursing staff is the best B ] aor recommendation for the committee members for several reasons. Using the manufacturers’ instructions for procedures saves time and money, and it also ensures that the procedures are accurate and complete. A textbook includes many procedures, but these procedures will c |__| 27% not be specific to the brand and model numbers of the equipment used by the nursing staff. Databases like the Cochrane Library are used for @ -based practices and not procedures.", "whyNot": {"a": "Using a subcommittee could be helpful, but the group needs data to use when developing policies and procedures.", "b": "A textbook may have current information but it is not specific to the brands and models used by each health care facility.", "c": "A database is useful for finding evidence-based practices, not for writing policy and procedures."}, "keyConcept": "The Joint Commission requires that healthcare agencies have policies and procedures regarding the use of equipment. Equipment-related accidents in healthcare facilities are caused by misuse and malfunction of equipment. If a nurse is unfamiliar with a piece of equipment or lacks the competence to use it safely, it is the nurse's responsibility to inform the supervisor, who should provide opportunities for ongoing training in the use of equipment by healthcare workers."}, {"id": 11244, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "evacuating first to the safe designated area?", "choices": [{"id": "a", "t": "Ambulatory clients"}, {"id": "b", "t": "Bedridden clients O C.ICU clients"}, {"id": "d", "t": "Infant clients"}], "correct": "a", "rationale": "Ambulatory clients have the potential to wander and end up in an unsafe place if not directed correctly. All the other options describe clients B ] a who cannot leave without assistance. ch 5%", "whyNot": {"b": "Bedridden clients need more assistance for moving instead of ambulatory clients who can walk to a safe area.", "d": "Infants need more assistance for moving; ambulatory clients should be evacuated first."}, "keyConcept": "All healthcare facilities should have emergency evacuation plans in place. The priorities in evacuation planning focus on prevention or reduction of injuries and loss of life; ensuring the safety of clients, visitors, and personnel and maintaining client care and life support during evacuation."}, {"id": 11245, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Anewly licensed nurse asks the nurse manager whether they need to purchase their own professional liability insurance. Which of the following statements should the nurse manager make? O A.\"The facility has insurance that will cover malpractice litigation.\" O B. \"Professional liability coverage is not mandatory, but you should consider purchasing your own coverage.” O C. \"The chances of a malpractice suit are minimal as long as you follow our policies and procedures.\" O D. \"Those who supervise you will take the responsibility when something goes wrong.\"", "choices": [{"id": "a", "t": "Healthcare organizations have insurance to cover the facility if a suit is brought against them alleging malpractice by an employee."}, {"id": "b", "t": "All 12% Easy In general, legal experts recommend that all nurses have their own liability insurance coverage because of the ever-expanding roles of nurses OB SY ry and their ongoing responsibility for supervising less experienced staff and delegating to them."}, {"id": "c", "t": "Although this is true to some extent, lawsuits do happen and not always because the nurse failed to adhere to policies and procedures."}, {"id": "d", "t": "Individual nurses are always responsible for the outcomes of their nursing actions. Another health care professional cannot relieve them"}], "correct": "b", "rationale": "All 12% Easy In general, legal experts recommend that all nurses have their own liability insurance coverage because of the ever-expanding roles of nurses OB SY ry and their ongoing responsibility for supervising less experienced staff and delegating to them. Floating and cross-training are other issues that increase nurses' risk for liability. Nurses who work in government facilities also have an increased risk because some states have c i 6% \"sovereign immunity,\" and government facilities in those states have protection from lawsuits, making individual nurses vulnerable in a . Employment in smaller facilities, such as walk-in-clinics, is another risk because they might not have liability insurance that covers their nurses.", "whyNot": {"a": "Healthcare organizations have insurance to cover the facility if a suit is brought against them alleging malpractice by an employee.", "c": "Although this is true to some extent, lawsuits do happen and not always because the nurse failed to adhere to policies and procedures.", "d": "Individual nurses are always responsible for the outcomes of their nursing actions. Another health care professional cannot relieve them"}, "keyConcept": "Acommon myth is that, by having their own professional liability insurance, nurses increase their risk for a malpractice suit. This is incorrect; the lack of coverage will not discourage clients or their families from suing when they believe that a nurse has caused them harm. Another compelling reason to purchase professional liability insurance is that some health care facilities fail to conduct an adequate defense for nurses or have insurance coverage limitations that are much lower than the monetary amounts the clients or families seek to obtain."}, {"id": 11246, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "€ 9 G 23 student.atitesting.com/LT| Finish update ? Tutorial: BoardVitals NCLEX Prep RN ati Module: Results Dashboard Quiz ~ Performance ~ & Highlight ~ & Calculator Read the following order from a physician. After reading the order, note which of the following nursing actions is most appropriate? \"Administer 500 mg ceftriaxone p.o. now and q 6 hrs x 24 hours for infection prevention.\"", "choices": [{"id": "a", "t": "Administer ceftriaxone by mouth as the physician ordered"}, {"id": "b", "t": "Wait until the client is served lunch and then administer the first dose with food"}, {"id": "c", "t": "Contact the pharmacy to clarify the order"}, {"id": "d", "t": "Contact the physician to clarify the order"}], "correct": "d", "rationale": "In this situation, the nurse must contact the physician to clarify the order. Ceftriaxone (Rocephin) is only administered in the IV or IM routes, % CLOSE x» *o!1@0 { Browse Questions > iit Search Questions QJ", "whyNot": {"a": "Ceftriaxone is given IM or IV. Therefore it is not possible to give it in the prescribed manner.", "b": "The route needed to be clarified, it is not possible to give this medication by mouth.", "c": "Itis the physician, not the pharmacy who should clarify the order."}, "keyConcept": "When accepting physician orders and following through, the nurse must be familiar with the facility’s policies, principles of medication administration, and client care standards to be able to correctly follow orders or know when to question them."}, {"id": 11247, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which client population is at greatest need for nurse advocacy?", "choices": [{"id": "a", "t": "Vulnerable populations"}, {"id": "b", "t": "The aging population"}, {"id": "c", "t": "The pediatric population"}, {"id": "d", "t": "Impoverished populations"}], "correct": "a", "rationale": "Vulnerable populations are in the greatest need of nurse advocacy. Examples of vulnerable populations include those who cannot speak, B | Ase confused clients, those affected with developmental disorders, and those at the end of life. Simply defined, advocacy describes the nurse’s role in ensuring that client rights are upheld, that clients are informed, and ensuring that the proper level and quality of care is rendered. c | 4% of 5%", "whyNot": {"b": "The aging population often needs nurse advocacy, but this group is not considered to be in the highest need.", "c": "The pediatric population is not the group in greatest need of nursing advocacy.", "d": "Impoverished populations are considered vulnerable populations, which would be the highest need."}, "keyConcept": "The primary goal of advocacy is to support client well-being. A nurse can speak up to promote the common good and call attention to the concerns of disadvantaged people. Nurse advocacy includes collaboration with individuals or groups who need support to express their preferences or exert their rights."}, {"id": 11248, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which law protects the client’s right to confidentiality and information security?", "choices": [{"id": "a", "t": "The Patient Self-Determination Act"}, {"id": "b", "t": "The Health Insurance Portability and Accountability Act"}, {"id": "c", "t": "The Disclosure and Confidentiality Act"}, {"id": "d", "t": "The American Hospital Association’s Bill of Rights"}], "correct": "b", "rationale": "| 2% Easy The Health Insurance Portability and Accountability Act (HIPAA) is the federal law that protects a client’s right to confidentiality and OB TS amas information security. This protects clients from any oral or written communication without their express consent. This right is violated in many ways including casual conversation, speaking about clients in an area when others can hear you, and with technology breaches such c | 9% as leaving a computer screen on and unattended when you have failed to log off.", "whyNot": {"a": "The Patient Self-Determination Act provides the client with the right to autonomy about decisions.", "c": "This act does not exist.", "d": "This is a Bill of Rights that does not best protect the client’s right to confidentiality when compared to HIPAA."}, "keyConcept": "The Health Insurance Portability and Accountability Act of 1996 (HIPAA) mandated the U.S. Department of Health and Human Services (HHS) to develop regulations to protect the privacy and security of confidential health information, resulting in the establishment of the HIPAA Privacy Rule and the HIPAA Security Rule. The Privacy Rule established national standards for the protection of individual health information. The Security Rule refers to the Security Standards for the Protection of Electronic Protected Health Information, which establishes a national set of security standards to protect health information that is stored or transferred in electronic form. The Security Rule provides the safeguards and procedures required of \"covered entities\" to ensure the protections contained in the Privacy Rule. by addressing the technical and non-technical safeguards that these entities must put in place to secure protected health information stored or transmitted electronically."}, {"id": 11249, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager receives a report that one of the staff nurses might be chemically impaired. Which of the following actions should the nurse manager take first?", "choices": [{"id": "a", "t": "Review the nurse's work performance history."}, {"id": "b", "t": "Complete a count of controlled substances on the unit."}, {"id": "c", "t": "Talk with the staff members who reported the nurse."}, {"id": "d", "t": "Remove the nurse from client care."}], "correct": "d", "rationale": "A | | 9% Moderate The greatest risk in this situation is injury to clients; therefore, the first action the nurse manager should take is to remove the nurse from B I a client care. A nurse who is chemically impaired can have impaired judgment and could make decisions that are unsafe for clients. The nurse should reassign care of these clients to other staff. c |_| 14%", "whyNot": {"a": "The nurse manager should review the staff nurse's work performance, including evaluations as well as time and attendance records, to", "b": "The nurse manager should conduct a count of all the controlled substances on the unit and review the staff nurse's history of obtaining", "c": "The nurse manager should investigate the allegations of chemical impairment to determine if disciplinary action of the staff nurse is"}, "keyConcept": "The nurse is responsible for reporting other members of the health care team whom they suspect might be working while impaired. This is an important tenet of the Nursing Code of Ethics, that the nurse's primary commitment is to the client and the nurse promotes the health and safety of self and others. It is important for the nurse to realize that reporting suspected impairment of another member of the health care team is not a form of betrayal but demonstrates commitment to the well-being of the team member and the safety of the clients. Additionally, there are legal ramifications for failure to report suspected impairment. If a state Board of Nursing investigation finds that other licensees, such as nurses, knew about the impairment and did nothing, the Board can also act against those individuals for failure to comply with the Nurse Practice Act."}, {"id": 11250, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who has an indwelling Foley catheter following bladder repair surgery. Which of the following tasks can be delegated to unlicensed assistive personnel (UAP)?", "choices": [{"id": "a", "t": "Observe the type and amount of urinary drainage"}, {"id": "b", "t": "Monitor for complications such as bleeding"}, {"id": "c", "t": "Irrigate the catheter with the ordered irrigation solution to ensure the catheter does not become blocked"}, {"id": "d", "t": "Perform perineal care"}, {"id": "e", "t": "Removal of the catheter"}], "correct": "d", "rationale": "All 12% ~— Easy Perineal care is within the UAP’s scope of practice, therefore this task can be assigned to the UAP.", "whyNot": {"a": "Observation of type and amount of drainage requires evaluation and is not appropriate to assign to a UAP. eD fs 85%", "b": "Monitoring for complications such as bleeding requires evaluation and is not appropriate to assign to a UAP.", "c": "Irrigation requires a skill that is not within the UAP’s scope of practice.", "e": "Removal of the catheter is not within the UAP’s scope of practice and should not be assigned to the UAP."}, "keyConcept": "The nurse cannot delegate any part of the nursing process to a UAP.Tasks that can be delegated to the UAP include taking routine vital signs on stable clients; assisting clients with ambulation;personal hygiene care; and assisting with activities of daily living. Inflated balloon |"}, {"id": 11251, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse in the intensive care unit is assigning clients. Which of the following clients should be assigned to the most experienced nurse?", "choices": [{"id": "a", "t": "A client with a potassium level of 6.0 mEq/L who has peaked T waves"}, {"id": "b", "t": "A client with type diabetes with a blood glucose level of 280 mg/dL"}, {"id": "c", "t": "A client with congestive heart failure who is scheduled for an echocardiogram O D.A client with COPD who has ABG values of: pH 7.38, PaO2 78, PaCO2 42, HCO3 24"}], "correct": "a", "rationale": "The normal serum potassium level is 3.5-5.0 mEq/L. The client with a potassium level of 6.0 mEq/L and peaked T waves has hyperkalemia, B | a0 which can produce life-threatening arrhythmias, including ventricular fibrillation, leading to death. The most experienced nurse should be assigned to this client, who is the least stable client. Early changes on ECG at potassium levels 5.5-6.5 mEq/L include tall, peaked T waves, c | 2% shortening of the QT interval, and ST-segment depression. In clients with hyperkalemia and ECG changes, treatment includes: © IVcalcium to stabilize myocardial cell membrane © Identify and remove source of potassium intake IV glucose and insulin infusion to increase potassium uptake by cells © Sodium bicarbonate to treat severe metabolic acidosis, when present © Diuretics or gastrointestinal cation-exchange medications to increase elimination of potassium", "whyNot": {"b": "Although this glucose level is high, it is not life-threatening.", "c": "An echocardiogram is a routine procedure, so a less experienced nurse can be assigned. There is no indication that this client is unstable."}, "keyConcept": "When assigning client care, the most experienced nurse should care for unstable clients. Hyperkalemia results in ECG changes and can cause fatal arrhythmias and death. Treatment is multifaceted and may include IV calcium, infusion of IV glucose and insulin, diuretics, cation exchange resins, and sodium bicarbonate."}, {"id": 11252, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "| 8x Reco. Mi Inbox M Inbox J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Call the pharmacy O B.startaniv"}, {"id": "c", "t": "Call the prescribing healthcare provider"}, {"id": "d", "t": "Prepare and give the medication"}], "correct": "c", "rationale": "al 4% Easy This order does not contain all of the necessary components for a nurse to give the medication safely. Therefore, the first action the nurse B | a0 should take is to call the prescribing physician for clarification of the order. Every medication order should have the name of the medication written out with a dosage and route of administration. In addition, the order should include the frequency at which the medication is to be ec | 91% administered.", "whyNot": {"a": "The pharmacy dispenses the medication but the nurse must talk to the healthcare provider who wrote the prescription.", "d": "The nurse should not prepare or give the medication until the prescription is clarified by the healthcare provider."}, "keyConcept": "Orders for medication should be reviewed by both nurse and pharmacy. Nurses should clarify incomplete orders and any errors in dosing, drug interaction, or allergy. The nurse should document the conversation, including the prescriber response. The pharmacy should clarify any dosing, formulary, or drug interaction issues they note when dispensing a medication. This provides two safety checks."}, {"id": 11253, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "What is the correct name for a document that identifies a legal proxy for making healthcare decisions in case the client is unable to make those decisions? O ativing will O B. Do-not-resuscitate order O C. Durable power of attorney O D. Client choice record", "choices": [{"id": "a", "t": "durable power of attorney for health care allows the individual to designate an agent to make decisions about their health care if the"}, {"id": "b", "t": "A do-not-resuscitate order means the client does not want extensive measures to prolong his life; it does not provide a proxy."}, {"id": "c", "t": "mM | 16% Easy Adurable power of attorney is a type of advance directive that designates a person, known as a proxy, to make health care decisions on ."}, {"id": "d", "t": "1%"}], "correct": "c", "rationale": "mM | 16% Easy Adurable power of attorney is a type of advance directive that designates a person, known as a proxy, to make health care decisions on . The durable healthcare power of attorney (POA) is a legal document that is signed and designated before the client undergoes treatment. ec ——— 82% D 1%", "whyNot": {"b": "A do-not-resuscitate order means the client does not want extensive measures to prolong his life; it does not provide a proxy.", "d": "There is no standard documentations called client choice record."}, "keyConcept": "A durable power of attorney for health care allows the individual to designate an agent to make all decisions about their health care if the client is unable to make these decisions. This applies to all health care decisions and for all types of medical conditions. A durable power of attorney is broader than a living will, which only expresses the client's desires in cases when the client is terminally ill, permanently unconscious, and unable to express his/her wishes regarding the use of life-prolonging procedures. The health care power of attorney is not limited to situations in which you are terminally ill, in a persistent vegetative state, or in some other condition narrowly defined by state law. It is not limited to lifeprolonging procedures, either. Issues may arise if you don’t have both a living will and health care power of attorney in place."}, {"id": 11254, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client with an asthma exacerbation who is complaining of shortness of breath and wheezing. Which of the following is the appropriate first nursing action?", "choices": [{"id": "a", "t": "Auscultate the lungs for wheezing and air movement."}, {"id": "b", "t": "Administer oral prednisone."}, {"id": "c", "t": "Call the respiratory therapist to deliver a prn breathing treatment as prescribed."}, {"id": "d", "t": "Notify the healthcare provider."}], "correct": "a", "rationale": "8 | 4% Asthma is a chronic inflammatory disorder caused by airway reactivity that results in intermittent reversible airway obstruction of the Cc | 11% bronchioles. The initial appropriate nursing action is an assessment of the client. By auscultating the lungs, the nurse can determine the , strength of air movement, and severity of the client’s condition. The assessments must match the problem; in this case, the assessment of the lung sounds and movement of air provide critical clinical material about the asthma exacerbation.", "whyNot": {"b": "Oral prednisone is used in severe asthma exacerbations and does not have an immediate effect. The client with an asthma exacerbation", "c": "The nurse should first assess the client and then determine the appropriate intervention.", "d": "The nurse should first assess the client and advise the healthcare provider after providing any prn medications that are appropriate."}, "keyConcept": "Assessment provides critical clinical information to guide a nurse. In a client with asthma exacerbation, assessment will guide administration of prn medications and notification of the healthcare provider. The nurse should evaluate the client's response to prn medication, when appropriate, before notifying the healthcare provider."}, {"id": 11255, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "mechanical lift. What is the appropriate response by the nurse manager?", "choices": [{"id": "a", "t": "Reprimand the nursing assistant"}, {"id": "b", "t": "Teach the UAP how to use the mechanical lift"}, {"id": "c", "t": "Assign the mechanical lift to another staff member"}, {"id": "d", "t": "Call and report this incompetence to the supervisor"}], "correct": "b", "rationale": "a| 1% Easy The nurse manager should teach the UAP how to use the mechanical lift. A reprimand is not appropriate; the UAP appropriately reported his OR sid omer lack of ability and this reporting is highly encouraged. Assigning the task to another team member does not solve this competency issue; education and training would solve this competency concern. It is, furthermore, not necessary to report this to the nursing supervisor c | ™ because the charge nurse should be able to address the issue without the support of the supervisor.", "whyNot": {"a": "Reprimanding the assistant is not appropriate and does not help her to learn.", "c": "While this may solve the initial issue, it does not teach the assistant how to use the lift.", "d": "This information does not need to be reported; the nurse manager should review the principles of using the lift with the assistant."}, "keyConcept": "It is essential for those who use assistive devices in client care to understand correct operation and utilization of the device in order to prevent client injury or harm. The nurse practice act of every state holds the registered nurse accountable for all client care, including those tasks delegated to assistive personnel. A nurse who delegates a task to another person must verify the individual's competence; supervise and inspect their work, and evaluate the outcome of the task. In addition to ongoing monitoring of tasks by a UAP, the nurse should provide corrective education when necessary."}, {"id": 11256, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client who has right-sided paralysis following a stroke. Which of the following information should the nurse provide the occupational therapist who will be involved in the care of the client?", "choices": [{"id": "a", "t": "The client will need a ramp built at his home."}, {"id": "b", "t": "The client is experiencing difficulty swallowing liquids."}, {"id": "c", "t": "The client is right-hand dominant."}, {"id": "d", "t": "The client wishes to complete an advance directive."}], "correct": "c", "rationale": "A | % Moderate The nurse should inform the occupational therapist (OT) that the client is right-hand dominant. The OT assists the client to become B | see independent with activities of daily living, such as bathing, dressing, and grooming. A client who is right-hand dominant and is experiencing right-sided paralysis will require assistance and teaching about how to perform routine activities without the use of the dominant hand and ec | 14% arm.", "whyNot": {"a": "The nurse should inform the social worker of the client's need for a ramp built at his home. The social worker can assist the client with", "b": "The nurse should inform the speech-language pathologist (SLP) that the client is experiencing difficulty swallowing liquids. The SLP can", "d": "The nurse should inform the social worker that the client wishes to complete an advance directive. The social worker can assist the client"}, "keyConcept": "The nurse should serve as a resource person for the interdisciplinary team members by providing the necessary information for care to be consistent across the continuum. The nurse should relay the needs of the client, as well as pertinent client information, to the team to ensure quality client outcomes."}, {"id": 11257, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "nurse take? O A. Clearly tell the nurse manager that the proposal causes discomfort. O B. Obtain more details about the nurse manager’s expectations. O C. File a report with the risk manager. O D. Ask the nurse manager to place the guarantee of the position in writing.", "choices": [{"id": "a", "t": "Clearly tell the nurse manager that the proposal causes discomfort."}, {"id": "b", "t": "Obtain more details about the nurse manager’s expectations."}, {"id": "c", "t": "File a report with the risk manager."}, {"id": "d", "t": "Ask the nurse manager to place the guarantee of the position in writing."}], "correct": "a", "rationale": "@A ; 56% Moderate The nurse manager's statement is a form of sexual harassment that is identified as quid pro quo. This form of harassment includes unwanted B | a0 advances or other verbal or physical conduct that indicates a job promotion, job benefits, or continued employment are dependent upon compliance with a request for sexual favors. The nurse should identify that this is a form of sexual harassment and should clearly indicate to c | 41% the nurse manager that the proposal is unwanted and causes discomfort.", "whyNot": {"b": "The nurse should identify that the nurse manager is taking advantage of the imbalance of power by offering a position in return for", "c": "Facilities have policies in place that prohibit harassment of any type. The nurse should file a report with the human resources department", "d": "The imbalance of power between the nurse manager and the nurse makes the statement by the nurse manager a form of harassment,"}, "keyConcept": "A nurse has the right to expect an employer to be committed to providing a harassment-free workplace. Policies should be in place prohibiting sexual harassment and outlining the processes for how employees will be protected. The facility is responsible for educating employees about these policies, both verbally and in writing."}, {"id": 11258, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "client understands hospice care? O A.\"| will have to be admitted to a long-term care facility in order to receive hospice care.\" O B.\"I should expect the hospice team to help me manage my difficulty breathing.\" O C. \"Hospice care services are available to anyone who is terminally ill, regardless of life expectancy.\" O D. \"My oncologist will continue to look for a cure for my cancer while | am receiving hospice care.\"", "choices": [{"id": "b", "t": ", such as dyspnea, that can occur with terminal eB Ys 64% lung cancer."}, {"id": "c", "t": "The focus of hospice care is to provide comfort care to clients who have a prognosis of 6 months or less to live."}, {"id": "d", "t": "The focus of hospice care is to provide the client with palliative care when there is no cure for the client's end-stage disease process."}], "correct": "b", "rationale": ", such as dyspnea, that can occur with terminal eB Ys 64% lung cancer.", "whyNot": {"c": "The focus of hospice care is to provide comfort care to clients who have a prognosis of 6 months or less to live.", "d": "The focus of hospice care is to provide the client with palliative care when there is no cure for the client's end-stage disease process."}, "keyConcept": "The nurse should inform the client about hospice care and evaluate the client's understanding. Hospice care is specialized palliative care that is initiated when the client is estimated to have 6 months or less to live. Hospice care focuses on maintaining the client's comfort, independence, and dignity while easing pain and manifestations of terminal illnesses, such as COPD, kidney failure, cardiac disorders, neurological diseases, and dementia. This specialized care is initiated when the client has 6 months or less to live. Hospice care includes palliative nursing care to maintain the client's comfort, independence, and dignity while easing pain and the manifestations of the client's disease process. Hospice care involves the client and the client's family."}, {"id": 11259, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is assigned to care for 4 clients on the medical-surgical unit. Which of the following interventions should take priority?", "choices": [{"id": "a", "t": "Call a nursing home with a transfer report for a client who is being discharged."}, {"id": "b", "t": "Perform a wet-to-dry dressing change for a client with a pressure ulcer."}, {"id": "c", "t": "Assess a client who has called the nursing station complaining of new-onset severe dizziness."}, {"id": "d", "t": "Discuss the choice of assistive device with the UAP who was delegated to assist a client who is partially weight-bearing with a bed-chair transfer."}], "correct": "c", "rationale": "| 2% This client is experiencing a physiological change and must be assessed by the nurse to determine which intervention is indicated. Severe ec fF 95% dizziness could represent a benign condition like positional vertigo or a serious one, including arrhythmia or stroke. This ongoing .", "whyNot": {"a": "Physiological needs are at the bottom of the pyramid of Maslow’s hierarchy of needs but represent the top nursing priority. Although", "b": "Changing the dressing meets a physiological need, but the acute problem is the client with a significant symptom of physiological", "d": "When delegating a task to UAP, the RN is responsible for ensuring the UAP is capable of safely performing the task. The RN should find a"}, "keyConcept": "A nurse should prioritize physiological needs of a client. Airway, breathing, circulation, and neurological disability are priority physiological needs. Dizziness can represent circulation problems (hypotension, arrhythmia) or neurological disability (stroke) and should be prioritized for assessment."}, {"id": 11260, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse in a provider's office is reviewing the laboratory findings for a client who is receiving chemotherapy. The client has a platelet count of 60,000/mm3. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Provide the client with information about the treatment."}, {"id": "b", "t": "Discuss these findings with the provider."}, {"id": "c", "t": "Ask the client to return to the clinic for further laboratory tests."}, {"id": "d", "t": "Obtain a referral to a specialized provider."}], "correct": "b", "rationale": "al 5% Easy The greatest risk to this client is injury from bleeding due to a low platelet count. Therefore, first action the nurse should take is to notify the OR rsd omar client’s provider about this finding. cf 4%", "whyNot": {"a": "The nurse should provide the client information about the treatment for a low platelet count. However, the nurse should take another", "c": "The nurse should contact the client ask them to return to the clinic for further blood specimen drawing and ongoing treatment. However,", "d": "The nurse should obtain a referral for a hematologist once the provider has a plan of action and initiates prescriptions for care. However,"}, "keyConcept": "A follow-up plan is important for the nurse to perform when the priority is to report new client information to the provider. The provider can then implement the necessary prescriptions for treatment. A follow-up plan includes the client's need for ongoing treatment, screenings, and tests. Other follow-up plans include providing the client with information about the treatment, including the late or long-term effects of the treatment, referral to a specialized provider, and informative websites."}, {"id": 11261, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is working to maintain fiscal and ethical accountability for the staffing. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Increase staffing when acuity levels are low."}, {"id": "b", "t": "Ask the staff to regularly work extra shifts and overtime."}, {"id": "c", "t": "Create a sense of trust to resolve staffing issues."}, {"id": "d", "t": "Focus on the number of personnel for client care."}], "correct": "c", "rationale": "The nurse manager should create a sense of trust to resolve staffing issues when client acuity is high and staffing is low. If the nurse manager works diligently to maintain client safety and meet client needs, then trust is developed and ethical accountability is maintained.", "whyNot": {"a": "The nurse manager should increase staffing when acuity levels are high and decrease staffing when acuity levels are low to maintain fiscal", "b": "The nurse manager who asks staff to regularly work extra shifts and overtime is not being fiscally or ethically accountable. Instead, the", "d": "The nurse manager who is fiscally and ethically accountable focuses on all components, not just the number of personnel for client care."}, "keyConcept": "Fiscal and ethical accountability for staffing requires the nurse manager to maintain adequate staffing for low and high acuity client care. The nurse manager should stay within the staffing budget and meet the needs of the clients and staff. Therefore, increasing staffing when acuity levels are high and decreasing staffing when acuity levels are low helps to maintain fiscal accountability. The nurse manager should consider many factors to maintain fiscal and ethical accountability, including the staffing mix and competencies, job descriptions, nursing activities, and the client care organization. A client acuity system is a fairer way to meet staffing needs. During times of high client acuity, the nurse manager should create a sense of trust to resolve staffing issues. If the nurse manager works as hard as the staff to maintain client safety and meets client needs, then trust is developed and ethical accountability is maintained."}, {"id": 11262, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is planning to announce a major change on the unit. Which of the following communication techniques should the nurse manager use to enhance the importance of the announcement?", "choices": [{"id": "a", "t": "Present the announcement to unit staff in a conference room."}, {"id": "b", "t": "Stand with arms crossed when giving the announcement."}, {"id": "c", "t": "Stare at the people the announcement will affect the most."}, {"id": "d", "t": "Pause frequently when making the announcement."}], "correct": "a", "rationale": "The environment in which the announcement is made can have a major impact on the manner in which the announcement is received. An announcement made during a meeting in a conference room will be taken more seriously than an announcement to staff members at the nurses' station during shift change. c |", "whyNot": {"b": "Crossing the arms over the chest suggests defensiveness or aggressiveness and will detract from the importance of the message the nurse", "c": "Eye contact promotes emotional connection and enhances communication if done appropriately. Staring impedes connecting with others", "d": "The delivery of the message is impacted by timing and vocal expression. For example, hesitation or frequent pauses during the"}, "keyConcept": "Nonverbal communication techniques can either confirm or discount the actual words being spoken. The nurse should identify that when there is a discrepancy between the verbal and nonverbal message, the receiver is more likely to believe the nonverbal message. This is an important factor for the nurse to consider when providing client care and when talking with other members of the health care team."}, {"id": 11263, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following best describes an example of intrapersonal conflict?", "choices": [{"id": "a", "t": "A nurse disagrees with a physician’s orders for a patient’s pain medication"}, {"id": "b", "t": "A nurse feels helpless when other nurses do not step in to assist her with a heavy workload"}, {"id": "c", "t": "A nurse opposes a charge nurse’s instructions to set up equipment for a procedure"}, {"id": "d", "t": "A nurse wants to apply for a management position but feels as if she already spends too much time at work"}], "correct": "d", "rationale": "A | % Moderate Intrapersonal conflict arises out of a struggle within oneself to make decisions that may contradict personal values or desires. A nurse who . c i ™%", "whyNot": {"a": "This is an example of interpersonal conflict, not conflict within the nurse.", "b": "This is an example of interpersonal conflict -- the nurse is engaging in conflict with others.", "c": "This opposition describes interpersonal conflict, not intrapersonal conflict."}, "keyConcept": "Conflict occurs as a result of experienced or perceived variations in goals, values, ideas, attitudes, beliefs, feelings, or actions. Conflict may be interpersonal, intrapersonal, intergroup, or intragroup. Intrapersonal conflict occurs within one individual; interpersonal conflict occurs between two or more individuals; intragroup conflict occurs within one group; and intergroup conflict occurs between two or more groups. Conflict can be dysfunction or healthy."}, {"id": 11264, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "for this client? O A. The room closest to the nursing station, where the patient will be able to hear all of the staff talking O B. The room at the farthest end of the hall, where the client won’t be disturbed by any noise O C. In a 4-bed ward where other clients will be able to alert nursing staff of any unusual behaviors O D. Asemi-private room with another confused client O E. Aroom close by the nursing station where nursing staff can check on the client frequently but keep noise to a minimum", "choices": [{"id": "a", "t": "The room closest to the nursing station, where the patient will be able to hear of the staff talking"}, {"id": "b", "t": "The room at the farthest end of the hall, where the client won’t be disturbed by any noise"}, {"id": "c", "t": "In a 4-bed ward where other clients will be able to alert nursing staff of any unusual behaviors"}, {"id": "d", "t": "Asemi-private room with another confused client"}, {"id": "e", "t": "Aroom close by the nursing station where nursing staff can check on the client frequently but keep noise to a minimum"}], "correct": "a", "rationale": "E. minimum , where excessive noise and conversation may increase unwanted behaviors. c | 1% D 1% A. Placing the client in a room close to the nursing station may increase the client's agitation due to excessive noise. B. Placing the client in a room at the end of the hall is not in the client’s best interest in terms of safety. The client may become more anxious and confused and injury may occur if the client is not supervised closely.", "whyNot": null, "keyConcept": "A client experiencing agitation or delirium should be closely observed and the nurse should provide a calming environment. A nurse who is caring for a client experiencing delirium or agitation should talk to the client frequently for short periods for reassurance, assisting the client to become oriented, and observing the client to ensure safety. The nurse should be prepared for possible hostile responses from the client when assessing vital signs or providing physical care."}, {"id": 11265, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "the best initial response by the nurse?", "choices": [{"id": "a", "t": "Instruct the UAP to set personal feelings aside and continue caring for the client."}, {"id": "b", "t": "Ask the UAP for more information and ask the UAP to discuss possible solutions to the problem."}, {"id": "c", "t": "Inform the nursing supervisor"}, {"id": "d", "t": "Tell the client that the behavior is inappropriate and will result in discharge if the behavior continues."}, {"id": "e", "t": "Assign another UAP to care for the client"}], "correct": "b", "rationale": "Asking the UAP to discuss the problem and work cooperatively to find a solution shows respect for the UAP's feelings and provides empowerment to the UAP.", "whyNot": {"a": "Forcing the UAP to continue to work with an abusive client without addressing the issue will lead to conflict and resentment. It does", "c": "The nurse should assess the situation and possible solutions. If the nurse determines the client's behavior is abusive, it may be necessary", "d": "It may be necessary to tell the client that the behavior is inappropriate, but threatening the client with discharge is inappropriate.", "e": "Assigning another UAP to care for the client does nothing to address the client's behavior or the UAP's feelings."}, "keyConcept": "The nurse should address the UAP's concerns and ask the UAP to describe the concerning incidents in order to assess the situation. The nurse should also ask the UAP to collaborate to find a possible solution when possible. Clients who demonstrate abusive behavior can potentially escalate the behavior and pose a risk to healthcare personnel. The nurse should follow facility policy if a client is verbally or physically abusive."}, {"id": 11266, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse overhears two assistive personnel (AP) discuss a client's personal health information in the facility cafeteria. Which of the following is the priority action for the nurse to take?", "choices": [{"id": "a", "t": "Inform the APs that this is a breach in client confidentiality."}, {"id": "b", "t": "Ask the nurse manager to provide an educational session about confidentiality to the staff on the unit."}, {"id": "c", "t": "Complete an incident report."}, {"id": "d", "t": "Report the occurrence to the nurse manager."}], "correct": "a", "rationale": "When using the urgent vs. nonurgent approach to client care, the nurse should determine that the priority action is to stop the APs before B | a0 there is additional breaching of client confidentiality. The nurse has a professional duty to protect the client's confidential information. | © 1%", "whyNot": {"b": "Although the nurse should ask the manager to review the importance of maintaining confidentiality with the staff on the unit, there is", "c": "Although the nurse should complete an incident report to document an unethical practice, error, or unusual occurrence, there is another", "d": "Although the nurse should report the occurrence to the nurse manager to prevent a future breach of confidentiality, there is another"}, "keyConcept": "A nurse has a professional duty to protect clients' confidential information. If a nurse witnesses a breach in confidentiality, the nurse should intervene to prevent any additional violation of privacy. The nurse should only share private client information in a nonpublic location with members of the health team that are involved in a client's care."}, {"id": 11267, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "demonstrating which of the following ethical principles?", "choices": [{"id": "a", "t": "Veracity"}, {"id": "b", "t": "Autonomy"}, {"id": "c", "t": "Justice"}, {"id": "d", "t": "Nonmaleficence"}], "correct": "d", "rationale": ". When the nurse completes an advanced B ] ne education program to provide safe care in the ICU, the nurse is demonstrating the ethical principle nonmaleficence. I © 4%", "whyNot": {"a": "The ethical principle of veracity is the duty to tell the truth.", "b": "The ethical principle of autonomy is respecting the client's right to make decisions about health care.", "c": "The ethical principle of justice is the duty to treat everyone equally, regardless of sex, gender identity, sexual orientation, race, culture, or"}, "keyConcept": "Nurses have an obligation to help others and promote the general good while doing no harm. When the nurse completes an advanced education program to provide safe care, the nurse is demonstrating the ethical principle nonmaleficence."}, {"id": 11268, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "the most significance? O A. The nurse has not used good professional judgment O B. The nurse has violated civil law. O C. The nurse can be prosecuted as a criminal O D. The nurse has violated hospital policy", "choices": [{"id": "a", "t": "The nurse has not used good professional judgment"}, {"id": "b", "t": "The nurse has violated civil law."}, {"id": "c", "t": "The nurse can be prosecuted as a criminal"}, {"id": "d", "t": "The nurse has violated hospital policy"}], "correct": "c", "rationale": "all 10% Hard Sharing a password or user name with another individual is a violation of the HIPAA Security Rule. The consequences of violation of this law B | ma include criminal prosecution and civil liability. The nurse has not demonstrated good professional judgment and has violated hospital ° policy, but criminal prosecution is the most significant consequence. ec || 35%", "whyNot": {"a": "While the nurse has not demonstrated good judgment by sharing his user name and password, this is not the most serious charge that can", "b": "A civil case could be brought against the nurse, but criminal prosecution is the most serious consequence.", "d": "The hospital’s policy has been violated, but this is not the most serious consequence."}, "keyConcept": "The HIPAA Security Rule requires that there must be a record of anyone who accesses protected health information and when they accessed it. The healthcare organization must be able to produce an audit of any access, view, edit, or change to an entry in the medical record. Although it may be convenient to share user names and passwords with coworkers or part-time personnel, it is a serious violation of the law and can potentially result in criminal penalties."}, {"id": 11269, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse is admitting four clients. Which of the following clients should the nurse assign to the room closest to the nurses' station?", "choices": [{"id": "a", "t": "A client who has delirium because of a febrile illness"}, {"id": "b", "t": "A client who reports a severe migraine headache"}, {"id": "c", "t": "A client who has clinical manifestations of tuberculosis (TB)"}, {"id": "d", "t": "A client who has a history of atrial fibrillation and requires continuous ECG monitoring."}], "correct": "a", "rationale": "A client who has delirium has impaired orientation, distorted perception, and possibly delusions and hallucinations. Because of the risk to 's safety due to unpredictable behavior, the nurse should place this client close to the nurses' station or ensure a constant nursing | © 1% presence in the client's room. om 14% Incorrect Answer: B. A client who reports a severe migraine headache needs a quiet and dark room, in a location with minimal sensory stimuli. C. A client who might have TB requires airborne precautions. The client should be placed in a private room with negative-pressure airflow, but the room does not need to be close to the nurses' station.", "whyNot": null, "keyConcept": "When making room assignments, nurses should consider the amount of observation the client requires, as well any insolation precautions and any special needs for reducing environmental stimuli. Nurses do not always have a choice, as they must work with the rooms that are available. However, it might be necessary to transfer other clients to accommodate priority needs."}, {"id": 11270, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Acharge nurse observes that an assistive personnel (AP) is providing optimal care to clients. Which of the following actions should the nurse take first to recognize the AP's great work?", "choices": [{"id": "a", "t": "Give positive feedback directly to the AP."}, {"id": "b", "t": "Recommend an increase in salary for the AP."}, {"id": "c", "t": "Nominate the AP for the Employee of the Month award."}, {"id": "d", "t": "Detail the AP's contributions to the nurse manager."}], "correct": "a", "rationale": "A. Evidence-based practice indicates that the charge nurse should first provide positive feedback to the AP to recognize the AP's ability.", "whyNot": {"b": "The nurse should recommend a salary increase for the AP to recognize the AP's ability and to provide motivation. However, evidence-", "c": "The nurse should nominate the AP for an award to recognize the AP's ability and to provide motivation. However, evidence-based practice", "d": "The nurse should share information about the excellent care the AP provides to recognize the AP's ability. However, evidence-based"}, "keyConcept": "The charge nurse should provide immediate positive reinforcement to encourage and motivate staff to provide safe and quality client care and to promote a positive interprofessional relationship for staff who are providing optimal care to clients. Other interventions to recognize and motivate staff can include an increase in salary and recognition, which can be provided using awards. Providing a motivating climate encourages productivity and growth, which results in an increase in quality of client care."}, {"id": 11271, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is delegating tasks to an unlicensed assistive personnel (UAP). Which of the following tasks should the nurse instruct the UAP to complete first?", "choices": [{"id": "a", "t": "Obtain a capillary blood glucose for a client who is prescribed premeal insulin"}, {"id": "b", "t": "Apply a condom catheter to a client who has urge urinary incontinence."}, {"id": "c", "t": "Feed a client who has bilateral casts due to upper arm fractures."}, {"id": "d", "t": "Ambulate a client who requires the use of a walker."}], "correct": "a", "rationale": "When using the urgent vs. nonurgent approach to client care, the nurse should determine the priority task to delegate is the blood glucose B ] a monitoring for the client who has an insulin prescription. This task is time sensitive and should be completed first. ci 11%", "whyNot": {"b": "Applying a condom catheter to an incontinent client is a nonurgent task. The client will need to have this task completed to improve the", "c": "Feeding a client who has bilateral casts is a nonurgent task. The client will need to have this task completed to meet the client's nutritional", "d": "Ambulating a client is a nonurgent task. This task will need to be completed to meet the client's mobility needs. However, there is another"}, "keyConcept": "When planning care, it is important for the nurse to prioritize tasks. Prioritization is a learned skill that must be practiced before proficiency can be achieved. It requires the ability to recognize what is the urgent, such as time-sensitive medications, and what is nonurgent, such as providing discharge teaching. The nurse should also prioritize when assigning tasks to UAPs and communicate which tasks should be done before the others."}, {"id": 11272, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "The \"planning\" step of the nursing process includes which of the following activities?", "choices": [{"id": "a", "t": "Performing an assessment"}, {"id": "b", "t": "Setting short- and long-term goals"}, {"id": "c", "t": "Coming to a diagnosis"}, {"id": "d", "t": "Reviewing the history"}], "correct": "b", "rationale": "al 3% Easy ADPIE is the acronym for the nursing process. It stands for: Assessment | 3% Planning Implementation Evaluation During the PLANNING stage of the nursing process, the nurse uses information that was gathered during their assessment, combined with their nursing diagnosis, to establish short-term and long-term goals for this patient's care plan. This should then be made into a written plan that all members of the healthcare team can access.", "whyNot": {"a": "Performing an assessment. This is the first stage of the nursing process, not a part of the planning stage.", "c": "Coming to a diagnosis. This is the second stage of the nursing process, not a part of the planning stage.", "d": "Reviewing the history. Gathering subjective data, like patient's history, is part of the first stage of the nursing process assessment."}, "keyConcept": null}, {"id": 11273, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is discussing when to complete an incident report with a newly licensed nurse. For which of the following situations should the nurse complete an incident report?", "choices": [{"id": "a", "t": "A nurse identified a broken piece of equipment."}, {"id": "b", "t": "An assistive personnel did not show up to work the assigned shift."}, {"id": "c", "t": "A client discovered that his dentures are missing."}, {"id": "d", "t": "Two nurses had a disagreement regarding an assignment."}], "correct": "c", "rationale": "A Hi 18% Moderate This situation requires the completion of an incident report because it is a variation from the normal standard of care. A change in the B I a client's plan of care might be necessary if the client has difficulty eating or speaking without the dentures. In addition, the facility might be liable for replacing the missing dentures. ec fe 15% my | 3%", "whyNot": {"a": "This situation should be resolved by removing the equipment from the client care area and placing a work order for its repair.", "b": "This situation requires the nurse manager to adjust the assignments and provide a solution for adequate staffing for safe client care.", "d": "This situation calls for the nurse manager to speak with the nurses and assist in resolving the conflict."}, "keyConcept": "A nurse should identify situations that require the completion of an incident report. Any event that is not consistent with the routine care of the client or deviates from the expected care and outcomes requires the completion of an incident report. An incident can be a deviation from the standard procedures in place for a particular unit within the facility. Some examples of incidents that require the completion of an incident report include the following: * Client or visitor fall or injury, or a visitor losing consciousness + Failure to follow provider orders, accidental omission of ordered therapies +A significant complaint by a client, family, health care provider, or other facility department + Error in technique or procedure + Malfunction of a device or product +» Needlestick injury + Medication administration error + Any situation that can lead to injury or pose a risk for injury"}, {"id": 11274, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse on an oncology unit accidently administered doxorubicin to the wrong client, resulting in harm to the client. This action is an example of which of the following torts?", "choices": [{"id": "a", "t": "Battery"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Malpractice"}, {"id": "d", "t": "Assault"}], "correct": "c", "rationale": "all 8% Easy Malpractice is an unintentional tort. To be classified as malpractice, the nurse must owe a duty to the client, the nurse must breach the duty, , and the nurse's breach of duty must have caused the injury.", "whyNot": {"a": "Battery is an intentional tort. To be classified as battery, the nurse must have touched the client without their consent. Battery can occur", "b": "Invasion of privacy is a quasi-intentional tort. Release of a client's confidential information to an unauthorized person is an example of", "d": "Assault is an intentional tort. To be classified as assault, the nurse must threaten the client with harm, resulting in the client being fearful"}, "keyConcept": "Nurses are legally and ethically responsible for providing accountable, safe care to their clients. The failure to provide safe care can result in legal charges against the nurse. Torts fall into three categories: intentional, quasi-intentional and unintentional. During an intentional tort, the nurse initiates an act knowing it was wrong or with the intent to harm a client. In the case of both quasi-intentional and unintentional torts, the nurse does not intend to harm the client. Intentional torts Assault Battery False imprisonment Quasi-intentional torts Invasion of privacy Defamation of character Unintentional torts Negligence Malpractice"}, {"id": 11275, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a group of clients. Which of the following clients should the nurse assess first?", "choices": [{"id": "a", "t": "A toddler who has asthma and a pulse oximetry reading of 95% while receiving oxygen at 2 L/min"}, {"id": "b", "t": "Atoddler who has otitis media, a temperature of 39.2° C (102.6° F), and purulent ear discharge"}, {"id": "c", "t": "Aschool-age child who has acute epiglottitis, is drooling, and has an absence of spontaneous cough"}, {"id": "d", "t": "An adolescent who is postoperative following a tonsillectomy, reports pain as 7 on a scale of 0 to 10, and requests pain medication"}], "correct": "c", "rationale": "| 2% Easy A client who has acute epiglottitis and an absence of spontaneous cough is unstable and at risk for respiratory failure. The child requires B I a immediate medical attention. Therefore, the nurse should assess this child first.", "whyNot": {"a": "The nurse should assess a toddler who has asthma because the toddler is at risk for respiratory compromise. However, a toddler who has", "b": "The nurse should assess and treat the temperature of a toddler who otitis media with purulent discharge from the ear because the toddler", "d": "The nurse should assess and treat the pain of an adolescent who is postoperative to provide comfort. However, a client who is"}, "keyConcept": "Prioritization is the act of determining which client the nurse should provide care for first and the tasks that should be completed first. Factors that the nurse should consider include the urgency of the situation, the needs of other clients, the familiarity with the task, and the resources needed and available."}, {"id": 11276, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "| 8x Reco. Mi Inbox M Inbox J untit! Untit| (4 Gooo @ TEAS Onlin = & Mark @ Mic (CONAN Me @ ATIT G New kx) © ATIT G GERC + v € > G 23 student.atitesting.com/LTI Qa * sw * © Cb Finish update : © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions od iit Search Questions Q }", "choices": [{"id": "a", "t": "Advance O sal"}, {"id": "c", "t": "Aggressive O D.aim"}, {"id": "d", "t": ". The P stands for pull, which directs the ."}], "correct": "d", "rationale": ". The P stands for pull, which directs the . The A stands for aim and directs the user to point the extinguisher toward the base of the fire. The | © 1% first S stands for squeeze and means to squeeze the handle, while the second S stands for sweep and directs the user to sweep the extinguisher from side to side. @", "whyNot": {"a": "The Ain PASS stands for aim, not advance.", "c": "The Ain PASS stands for aim, not aggressive."}, "keyConcept": "Acronyms are used to help healthcare workers implement safety and emergency procedures. RACE is the acronym used when a fire is discovered. It stands for \"RESCUE, ALARM, CONFINE, and EXTINGUISH/EVACUATE.\" PASS is the acronym used to recall the procedure for using a fire extinguisher. It stands for \"PULL, AIM, SQUEEZE, and SWEEP.\""}, {"id": 11277, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse manager is teaching a group of nurses about the Good Samaritan laws. Which of the following information should the nurse manager include?", "choices": [{"id": "a", "t": "Once aid is rendered, the nurse should not leave the scene until another qualified person can take over."}, {"id": "b", "t": "Good Samaritan laws protect the nurse from a claim of malpractice."}, {"id": "c", "t": "Federal laws require a licensed nurse to render aid in an emergency."}, {"id": "d", "t": "A nurse who volunteers at a summer camp for children is covered by Good Samaritan laws."}], "correct": "a", "rationale": "vant relationshi ; ; ; ; o;, 51% Hard Once the nurse renders aid, she has entered a nurse-client relationship and must continue to provide care until competent help arrives. B a sen", "whyNot": {"b": "Good Samaritan laws require the nurse to render the level of care expected by a competent, prudent nurse in a similar situation. To win a", "c": "Good Samaritan laws are state laws and can vary from state to state. Nurses are not required by law in most states to stop and assist with", "d": "Good Samaritan laws protect the nurse in an emergency. Volunteering at a summer camp would not be consistent with a nurse rendering"}, "keyConcept": "Guidelines for nurses who choose to render emergency care include: + If possible, limit actions to those that are generally included in first aid procedures. + Do not perform actions that you do not know how to do. + Offer assistance, but do not insist. + Have another person call or go for additional help. + Do not leave the scene until another qualified person takes over or the injured person leaves. + Do not accept any form of compensation for services rendered."}, {"id": 11278, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "best next step with regard to obtaining informed consent for the surgeries?", "choices": [{"id": "a", "t": "Call the first responders to identify and locate the client’s family"}, {"id": "b", "t": "Have the surgeon sign the informed consent for the client"}, {"id": "c", "t": "Call authorities to obtain a court order for surgery"}, {"id": "d", "t": "Take the client to surgery without informed consent"}], "correct": "d", "rationale": ", therapeutic or surgical procedures that are complex, invasive or involve any risk of B | aoe serious injury or death. There are two situations in which informed consent is not required. In a case like this one, where delaying surgery for the purpose of obtaining informed consent can lead to a worse outcome for the client (such as injury or death), informed consent is not c | 4% required. A second situation in which informed consent would not be required would be if the client signs a waiver stating that they waive @ . Informed consent means that the client has received information about their health condition as well as treatment options, that they understand those health conditions and treatment options, and that they are also able to decide what health care treatment they want to receive and give their consent to receive it. If they are unable to decide, a surrogate decision maker can be appointed to give informed consent.", "whyNot": {"a": "The nurse should not spend time locating the first responders to get the client’s information when he needs surgery right away.", "b": "The surgeon does not need to sign the consent; this is considered an emergency and consent is implied.", "c": "Acourt order is not necessary; the client may die without surgery so consent is implied."}, "keyConcept": "Informed consent is not necessary in a situation in which the client cannot provide informed consent and is at risk of life or limb, without an available surrogate. Consent is implied in these situations and the healthcare provider acts in the client's best interest by taking steps a reasonable person would consider prudent to protect the client."}, {"id": 11279, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following is correct concerning the nursing peer review process?", "choices": [{"id": "a", "t": "One person should be chosen to complete the review for several colleagues"}, {"id": "b", "t": "The review focuses on the employee’s work abilities as well as personal characteristics"}, {"id": "c", "t": "The performance appraisal should include other evaluation components in addition to the review"}, {"id": "d", "t": "The results of the review are typically shared with team members"}], "correct": "c", "rationale": ", as an employee’s peers can provide valuable information about one's B | Darn work performance. The peer review should be based on the employee’s work performance, and the results should only be shared with the employee and the manager. A performance appraisal should contain several components of evaluation; the peer review is only one part of ec | 59% the appraisal. D i 10%", "whyNot": {"a": "During a peer review, one colleague may evaluate the performance of another; one colleague is typically not selected to evaluate several", "b": "The peer review only focuses on work performance, not personal characteristics.", "d": "The results of the peer review are only shared with the staff member who is the subject of the review, not the entire team."}, "keyConcept": "Nurse managers have a responsibility to address performance issues in a fair and professional manner, since performance evaluations can affect continued employment, raises, promotions, and career changes. Performance evaluations should incorporate specific information to accurately depict any nonprofessional behavior. The nurse manager should also counsel the employee privately, verbally and in writing, concerning substandard practice or nonprofessional behavior, immediately after the observed behavior. Suspect or unsubstantiated peer input should never be included in a performance evaluation. A performance evaluation should include the employee's self-evaluation."}, {"id": 11280, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "oncoming nurse take? O A. Inform another staff member of his suspicions that the off-going nurse is impaired O B. Write a formal complaint about the nurse. O C. Confront the nurse and ask if she has been drinking. O D. Notify the charge nurse of the situation.", "choices": [{"id": "a", "t": "Inform another staff member of his suspicions that the off-going nurse is impaired"}, {"id": "b", "t": "Write a formal complaint about the nurse."}, {"id": "c", "t": "Confront the nurse and ask if she has been drinking."}, {"id": "d", "t": "Notify the charge nurse of the situation."}], "correct": "d", "rationale": "In the event a nurse suspects another nurse of being under the influence of alcohol, the nurse should report the matter, beginning at the lowest level of hierarchy, so that further evidence can be collected. Each facility has its own policies and procedures in place to identify and intervene in situations involving an impaired nurse.", "whyNot": {"a": "The oncoming nurse does not know for sure if the off-going nurse has been drinking alcohol; therefore, the oncoming nurse should not", "b": "The oncoming nurse does not know for sure if the off-going nurse has been drinking alcohol; therefore, the oncoming nurse should not", "c": "It is not the role of the oncoming nurse to confront the off-going nurse about his suspicion that she has been drinking."}, "keyConcept": "In the event a nurse suspects another nurse of being under the influence of alcohol, the nurse should report the matter, beginning at the lowest level of hierarchy, so that further evidence can be collected. Each facility has its own policies and procedures in place to identify and intervene in situations involving an impaired nurse."}, {"id": 11281, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "look to find information related to his scope of practice in this situation?", "choices": [{"id": "a", "t": "Physician orders"}, {"id": "b", "t": "Hospital formulary"}, {"id": "c", "t": "Handbook on IV medication administration"}, {"id": "d", "t": "Hospital policy and procedure manual"}, {"id": "e", "t": "Medication administration record"}], "correct": "d", "rationale": "The hospital policy and procedure manual contains information regarding the nurse’s scope of practice. In addition, the Nurse Practice Act can delineate the laws in individual states regarding which practices nurses may engage in.", "whyNot": {"a": "The physician’s orders will only tell the nurse what the physician has ordered for a particular client, not whether fulfilling the physician’s", "b": "The hospital formulary will detail which medications are available for use but will not provide the nurse with information regarding the", "c": "Ahandbook on IV medication administration will tell the nurse how and when to administer an IV medication, but will not provide", "e": "The medication administration record is simply a place to record the medications administered to the client and has nothing to do with"}, "keyConcept": "Healthcare organizations usually require competency validation for nurses and other professionals with I.V. administration responsibilities. When administering an I.V. push medication, the nurse should carefully review the vial or syringe label; confirm accuracy of the client, drug, dose/strength, route, and time the medication is due by comparing the drug label against the prescription or MAR; confirm that the container is intact; check for any visible contamination; verify the medication expiration date; and ensure that any special storage conditions required have been met."}, {"id": 11282, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Aregistered nurse is assigning care to an unlicensed assistive personnel (UAP) and a licensed practical nurse (LPN). Which of the following is the most appropriate task to assign to the LPN?", "choices": [{"id": "a", "t": "Administer a prescribed pain medication via intravenous push."}, {"id": "b", "t": "Plan discharge teaching for a client with a new prescription for metoprolol."}, {"id": "c", "t": "Measure and record fluid intake and output."}, {"id": "d", "t": "Monitor the client’s overall condition"}], "correct": "d", "rationale": "When delegating a task to less knowledgeable personnel, the needs of the client, skill of the staff, scope of practice, facility policies, and job Cc || description of the staff member should be taken into consideration. When assigning care to others, the “Five Rights of Delegation” must be e@D | considered: + Right person + Right task + Right circumstances + Right communication/directions + Right supervision and evaluation An LPN can monitor the client's vital signs or overall condition in a stable client. The LPN's task can include monitoring the client's response to medication, redness or swelling that may indicate infection, and may perform auscultation of lungs or heart when caring for a client. However, initial evaluation or evaluation of any significant change observed by the LPN is the function of the RN. An RN cannot delegate assessment, evaluation, medications, teaching, or an unstable client to unlicensed assistive personnel. The LPN should notify the RN of any change in assessment.", "whyNot": {"a": "Although licensed practical nurses can administer some intravenous medications if lV-certified, they cannot administer intravenous pain", "b": "The LPN can reinforce teaching, but the RN cannot delegate the act of teaching or planning to a less knowledgeable staff member.", "c": "The UAP or LPN can measure and record fluid intake and output for a stable client. Since the UAP is available, the more appropriate task"}, "keyConcept": null}, {"id": 11283, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "Which of the following responses should the nurse make?", "choices": [{"id": "a", "t": "\"There is a shortage of organs in this country, so think you should go ahead and donate your partner's organs.\""}, {"id": "b", "t": "\"What do you think your partner would have wanted?\""}, {"id": "c", "t": "\"This will not affect how your partner will appear in an open casket.\" O D.\"Don't you think you will feel a little better about the situation if you donate your partner's organs?\""}], "correct": "b", "rationale": "A 0% Moderate Federal law requires facilities to have policies and procedures in place about making a request for organ and tissue donation at the time of OB a aan death. The request is made by an employee, often a social worker, who has advanced training and can request the donations in a caring, sensitive manner. The role of the nurse is to provide emotional support to the family and encourage the family members to consider the c || 24% deceased person's wishes when making the decision.", "whyNot": {"a": "The nurse should avoid nontherapeutic communication techniques such as giving a personal opinions, which can take the decision-", "c": "The nurse should avoid nontherapeutic communication techniques such as changing the subject, which indicates a lack of empathy."}, "keyConcept": "A nurse who is caring for a client who has died should be aware of the policies and procedures regarding organ donation. The nurse involved in discussions with the client's family should be able to assist with decision-making and comforting the family during this time."}, {"id": 11284, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is assessing a client who experienced a traumatic brain injury. Which of the following findings is the nurse's priority?", "choices": [{"id": "a", "t": "Glasgow coma scale score of 10"}, {"id": "b", "t": "BP dropped from 150/74 to 143/80 mm Hg in 1 hr"}, {"id": "c", "t": "Pupils are round and 6 mm in diameter O D.3.cm (1 in) clear drainage from client's ear on gauze dressing"}, {"id": "d", "t": "All 10% Easy This finding is a priority because clear drainage from the client's ears or nose can indicate that a tear in the dura has occurred, which causes B | aI cerebral spinal fluid to drain."}], "correct": "d", "rationale": "All 10% Easy This finding is a priority because clear drainage from the client's ears or nose can indicate that a tear in the dura has occurred, which causes B | aI cerebral spinal fluid to drain. This is a serious condition because a tear in the dura enables organisms can gain access to the cranial contents and cause meningitis. c | 11%", "whyNot": {"a": "The Glasgow coma scale is used to determine a client's level of consciousness. The highest possible score is 15. A score of 8 or less is an", "b": "The nurse should continue to monitor the client's BP for the presence of a widening pulse pressure, which is a late indication of increased", "c": "Changes in pupillary response are an indication of increased intracranial pressure. Pupils that are round and 6 mm in diameter are within"}, "keyConcept": "A client who has experienced a traumatic brain injury is at risk for numerous complications, including increased intracranial pressure, ineffective respiratory status, infection, cerebral edema, coma, and brain herniation. The nurse should carefully monitor the client's neurological status because sudden changes in the client's status might indicate a need for immediate intervention. TABLE 38-2 Glasgow Coma Scale | pewnwon Response SORE Eye opening Spontaneously response To speech To pain No response Best verbal Oriented to time, place, and person response Confused Inappropriate words Incomprehensible sounds No response =Nwe =Nwan Obeys commands"}, {"id": 11285, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse knows that order \"read back\" must be done for which of the following?", "choices": [{"id": "a", "t": "When a written order is received"}, {"id": "b", "t": "When a printed lab result is transmitted"}, {"id": "c", "t": "When a verbal order is taken"}, {"id": "d", "t": "When a computerized order is received in the electronic health record"}], "correct": "c", "rationale": "al 3% Easy A “read back” should always be done when a verbal order is received, whether the verbal order is given in person or over the phone. B | a0 Although verbal orders are discouraged, the formal read back is a way to ensure that the healthcare provider gave the intended order and to ensure that the nurse heard the order correctly. An order written by a healthcare provider, a printed lab result, or computerized orders do not ec | 93% require \"read back.\"", "whyNot": {"a": "Awritten order does not require a read back because the order has been recorded in writing on the medical record.", "b": "A printed lab result is not an example of an order.", "d": "A computerized order does not require read back; only verbal orders require a read back."}, "keyConcept": "The Joint Commission has established a National Patient Safety Goal to address procedures used with verbal orders. The goal states that the receiver of the verbal or telephone order should write down the complete order or enter it into a computer, then read it back to the healthcare provider who gave the order and receive confirmation from that individual."}, {"id": 11286, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "suggest to the client? O A. Hospice Association O B. Visiting Nurses’ Association O C. Meals on Wheels O D. American Association of Retired Persons (AARP)", "choices": [{"id": "a", "t": "Hospice Association"}, {"id": "b", "t": "Visiting Nurses’ Association"}, {"id": "c", "t": "Meals on Wheels"}, {"id": "d", "t": "American Association of Retired Persons (AARP)"}], "correct": "c", "rationale": "al 2% Easy The Meals on Wheels program deliver meals to clients once a day. This is also a chance to check on elderly clients who live alone. B | a0", "whyNot": {"a": "The client is not necessarily on hospice; he needs resources for continued daily meals.", "b": "The VNA may provide more than meals; this client has not otherwise indicated a lack of self-care.", "d": "The AARP provides other resources for older adults, but not resources for obtaining meals."}, "keyConcept": "Meals on Wheels is a community-based program that provides one balanced meal daily to vulnerable members of the community. This daily visit also provides a respite from the social isolation that affects many older adults in the community. Other options for a meal and companionship include senior centers and suppers held by local church congregations. Food pantries are an option for seniors and others for whom a key obstacle to good nutrition is the lack of adequate financial resources. Soup kitchens are another option for the poor elderly."}, {"id": 11287, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "a violation of the client's rights and is an example of which of the following torts?", "choices": [{"id": "a", "t": "Slander"}, {"id": "b", "t": "Invasion of privacy"}, {"id": "c", "t": "Malpractice"}, {"id": "d", "t": "False imprisonment"}], "correct": "d", "rationale": ". The nurse should instruct the AP that the use of restraints can increase .", "whyNot": {"a": "Making false statements that damage a client's reputation is slander, which is a form of defamation of character. Libel is written", "b": "The invasion of privacy is a quasi-intentional tort in which the client's right to privacy is violated. The HIPAA and Health Information", "c": "Malpractice is a form of professional negligence in which the actions of the nurse do not meet the established standard of care, resulting in"}, "keyConcept": "Restraining a client involves restricting the movement or activity of a client using mechanical or chemical means. The use of restraints is limited to ensuring the safety of the client or those around the client. Regulations established by The Joint Commission and the Centers for Medicare and Medicaid Services, as well as facility policies, describe the use and limitations of restraints in addition to the requirements for ongoing assessment and documentation."}, {"id": 11288, "cat": "NCLEX 24-LEADERSHIP MGT", "stem": "A nurse is caring for a client with chronic hepatitis C who has returned to the unit after a liver biopsy. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Educate the client about cirrhosis and its progression"}, {"id": "b", "t": "Review pre-procedure coagulation studies"}, {"id": "c", "t": "Turn the client on the right side to provide pressure at the site"}, {"id": "d", "t": "Perform a detailed assessment"}], "correct": "c", "rationale": "A l 3% Moderate The correct priority is to provide pressure at the site to prevent bleeding, as this is a circulation issue and individuals with liver disease are at B I a higher risk of significant bleeding as a result of decreased production of clotting factors.", "whyNot": {"a": "The results of the biopsy have not returned, so teaching about cirrhosis is premature and teaching is not a priority at this time.", "b": "This is important to do prior to a liver biopsy in a client with liver disease who may be at increased risk of bleeding.", "d": "Performing a detailed assessment is important, but it is not the immediate priority."}, "keyConcept": "When determining priority of various nursing tasks, those tasks that are a threat to the client's immediate survival or safety should take precedence. These include airway, breathing, and circulation. The liver is highly vascular and clients with liver disease may be at greater risk of bleeding abnormally due to reduced production of clotting factors."}], "nclex_3": [{"id": 11289, "cat": "NCLEX 3", "stem": "‘A nurse asks the Licensed Practical Nurse (LPN) to assist the client to the Sim's position. Which of the following positions will indicate understanding by the LPN? . . C. — | 7 2 3 -", "choices": [{"id": "a", "t": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario."}, {"id": "b", "t": "0%"}, {"id": "d", "t": "0%"}, {"id": "e", "t": "0%"}], "correct": "a", "rationale": "Use clinical judgment to prioritize safety and select the best answer based on the client scenario.", "whyNot": null, "keyConcept": null}, {"id": 11290, "cat": "NCLEX 3", "stem": "A nurse finds the mother of a dying child in the child's room, visibly upset, who wants to take her child home. Which of the following responses by the nurse is most appropriate? O A.\"I know how you feel, but the medication will make your child feel better.\" O B. \"You can't let your child see that you are upset.\" O C. \"Is there a particular concern that we can discuss?\" O D. “I can imagine how hard this is for you, but it’s not what’s best for the child.”", "choices": [{"id": "a", "t": "The nurse does not necessarily know how the mother feels; she should instead allow the mother to talk about her feelings."}, {"id": "b", "t": "The nurse should work with the mother to find solutions that are agreeable to both parties instead of telling her what she can’t do."}, {"id": "c", "t": ", it is best to try to determine the cause."}, {"id": "d", "t": "Although the nurse may be able to imagine the mother’s pain, she should encourage the mother to express her feelings. The nurse should"}], "correct": "c", "rationale": ", it is best to try to determine the cause. Asking the mother an open-ended question about why she wants to B | Bt take the child home can provide insight into the problem and provides an opportunity for the mother to express her fears and concerns with the support of the nurse, who should listen actively and encourage the client to talk through her feelings.", "whyNot": {"a": "The nurse does not necessarily know how the mother feels; she should instead allow the mother to talk about her feelings.", "b": "The nurse should work with the mother to find solutions that are agreeable to both parties instead of telling her what she can’t do.", "d": "Although the nurse may be able to imagine the mother’s pain, she should encourage the mother to express her feelings. The nurse should"}, "keyConcept": "The nurse helps the client to know that her feelings are understood and accepted and encourage the mother to continue expressing emotions, thoughts, and concerns. If the mother says, “I hate it here. | wish | could go home with my child”, the nurse can respond by stating, “It must be difficult to stay here when you want to go home.” When a client talks about something that is upsetting to her or expresses a complaint or criticism, the nurse conveys acceptance by acknowledging the feelings she is expressing without agreeing or disagreeing. By sympathetically recognizing that it must be difficult or embarrassing or frightening or frustrating, etc. to feel as the client does, the nurse does not pass judgment on the thought or feeling itself. Successful communication must reflect to the client that the nurse accepts the thoughts and feelings the client is expressing, irrespective of whether or not the nurse thinks and feels the same way. If the client senses or is told that the nurse does not approve of or does not agree with what she is expressing, it is unlikely that the client will continue to be forthcoming or build a relationship of trust with the nurse."}, {"id": 11291, "cat": "NCLEX 3", "stem": "@0@ *X Viraln x Mi Inbox Mi Inbox ) untitl x €<€ 2 G student.atitesting.com/LT| Untitl x (4 Goog) x @ TEAS x NCLE x & Revie: @ Micro x NCLE x Convert study guide © Socia x ws * O Finish update Tutorial: BoardVitals NCLEX Prep RN x close SZ as ati Module: Quizzes & Assignments Dashboard — Quiz~- Performance ~ (Browse Questions ~ }{ Search Questions rowse Mode | 77 of 81 que:", "choices": [{"id": "a", "t": "client who is quadriplegic will not be able to use hands or arms to activate a call device, particularly one that has a small button. A variety"}, {"id": "b", "t": "This device requires pressing a small button, which is difficult for anyone with limited functional mobility."}, {"id": "c", "t": "This device"}, {"id": "d", "t": "This device requires the client to have the ability to press a small button on a small device, which a client with quadriplegia will not be"}], "correct": "a", "rationale": "8| 2% c| 1% o| 1% A client who is quadriplegic will not be able to use hands or arms to activate a call device, particularly one that has a small button. A variety ividuals with quadriplegia, including pneumatic devices that are activated by blowing through a tube or devices that can activate by eye movement. The type of device shown has a large pad, and the client with quadriplegia can activate a call for important to promote safety in the acute care setting by providing a means for clients to contact staff at any time for assistance. When a client is admitted, the nurse should be certain the client has a device available to call for assistance placed nearby so the client of devices are available for i assistance by placing a small amount of pressure on a large area to activate a call for help. able to activate the device.", "whyNot": {"b": "This device requires pressing a small button, which is difficult for anyone with limited functional mobility.", "c": "This device", "d": "This device requires the client to have the ability to press a small button on a small device, which a client with quadriplegia will not be"}, "keyConcept": null}, {"id": 11292, "cat": "NCLEX 3", "stem": "@ @ & Viralr x 8x Recor x M Inbox x M Inbox x [} Untitl x Untitl x (@ Goog) x @ TEAS Xx NCLE x & Revie X @ Micro x Convert study guide © Socia x [=| NCLE x | + v €< > G_— & student.atitesting.com/LT! Q * ew *¥* © nA Cb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE sg Poa ati Module: Quizzes & Assignments Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ {Search Questions [2 )", "choices": [{"id": "a", "t": "Peyronie’s contracture"}, {"id": "b", "t": "Muscular dystrophy deformity"}, {"id": "c", "t": "Dupuytren’s contracture"}, {"id": "d", "t": "Ehlers-Danlos syndrome deformity 2 = © 4 z = a fant g <"}], "correct": "c", "rationale": "A || 25% Moderate The client with a hand similar to that in the photo is most likely suffering from Dupuytren’s contracture. In this condition, the fingers are bent in the direction of the palm and cannot be extended; the condition develops from fibromatosis in the palm. Dupuytren's contracture is fairly a | ae common and it is characterized by progressive fibrosis of the palmar fascia, beginning with a nodule in the palm. Eventually, usually over the ec | 55% course of several decades, a loss of full extension accompanied by joint stiffness occurs. D | | 8%", "whyNot": {"a": "Peyronie's disease refers to an acquired, localized fibrotic disorder of the tunica albuginea of the penis.", "b": "There are a variety of types of muscular dystrophy, but none are characterized by palmar contractures.", "d": "Ehlers-Danhos syndrome is characterized by skin hyperextensibility, joint hypermobility, and tissue fragility."}, "keyConcept": "The nurse can advise the client with Dupuytren contracture to apply heat. Ultrasound may also be helpful in the early stages. A physical therapist may recommend a custom splint or brace to stretch the fingers. Range of motion (ROM) exercises should be performed several times daily."}], "nclex_4": [{"id": 11293, "cat": "NCLEX 4", "stem": "Convert study guide (J ATI? X @ New x {— NCL x + v Qa * Finish update : x» * 3 '|1@0 Tutorial: BoardVitals NCLEX Prep RN Module: Quizzes & Assignments ati Dashboard Quiz ~ Performance ~ % CLOSE { Browse Questions > iit Search Questions QJ", "choices": [{"id": "a", "t": "The nurse would only be administering 150 mg if she gave 15 mL; the correct amount is 35 mL."}, {"id": "b", "t": "The nurse would only be administering 250 mg if she gave 25 mL; the correct amount is 35 mL."}, {"id": "c", "t": "The nurse can determine the appropriate dose by the equation shown in the image below."}, {"id": "d", "t": "The nurse would administer 500 mg if she gave 50 mL; the correct amount is 35 mL."}], "correct": "c", "rationale": "The nurse can determine the appropriate dose by the equation shown in the image below. If 500 mg is in 50 mL, then 350 mg is in 35 mL. 500mg x 350mg 50 mL ?", "whyNot": {"a": "The nurse would only be administering 150 mg if she gave 15 mL; the correct amount is 35 mL.", "b": "The nurse would only be administering 250 mg if she gave 25 mL; the correct amount is 35 mL.", "d": "The nurse would administer 500 mg if she gave 50 mL; the correct amount is 35 mL."}, "keyConcept": "The equation to determine the desired volume of a dose can be calculated by setting up a ratio proportion equation: dose available/volume available = dose desired/volume desired. The nurse should solve the equation for the volume desired."}, {"id": 11294, "cat": "NCLEX 4", "stem": "the nurse question, based on the information provided under \"Exhibit\"? (Click the \"Figure/Media\" hyperlink above the question to review the exhibit)", "choices": [{"id": "a", "t": "Continue the home dose of lisinopril"}, {"id": "b", "t": "Obtain blood and urine cultures before initiating antibiotics"}, {"id": "c", "t": "Obtain a CT of the abdomen without contrast"}, {"id": "d", "t": "Administer IV antibiotics"}], "correct": "a", "rationale": "Chronic kidney disease is a significant and irreversible decline in kidney function occurring over a long period of time. It results in water, and B 21% electrolyte imbalances in the body and buildup of waste products. The client has hyperkalemia due to chronic renal disease, since potassium = excretion is normally modulated by the kidney. Hyperkalemia can be exacerbated by lisinopril, an ACE inhibitor, which suppresses c | 5% angiotensin II and leads to a decrease in aldosterone levels. Since aldosterone increases the excretion of potassium, use of ACE inhibitors can D i 10% result in retention of potassium. Antihypertensive medications that work by inhibiting the angiotensin-renin system include ACE inhibitors and angiotensin II receptor blockers. These medications can be used to treat hypertension that results from renal disorders, but they can result in hyperkalemia, particularly in advanced renal disease. ACE inhibitors include enalapril, lisinopril, and ramipril. Candesartan, losartan, valsartan, and irbesartan are angiotensin receptor blockers. Hyperkalemia can cause life-threatening arrhythmias, including ventricular fibrillation. po] e o 2 ° s a = a <", "whyNot": {"b": "Cultures are appropriate. Acute cholangitis refers to a condition characterized by fever, jaundice, and abdominal pain, caused by stasis", "c": "ACT of the abdomen without contrast is appropriate for a client who has renal failure. A contrasted CT would be contraindicated in a client", "d": "Empiric broad-spectrum antibiotics are appropriate for treatment of cholangitis pending results of cultures. This order would not cause"}, "keyConcept": "Chronic kidney disease results in hypervolemia and electrolyte Imbalances, including hyperkalemia, hypocalcemia, hyperphosphatemia, and hypermagnesemia. Hyperkalemia is a potentially life-threatening electrolyte imbalance that causes cardiac and neuromuscular dysfunction. ACE inhibitors, used to treat hypertension, have a protective effect in early renal insufficiency, but can exacerbate hyperkalemia in clients with impaired renal function."}, {"id": 11295, "cat": "NCLEX 4", "stem": "Based on the photograph, which portion of the syringe is the arrow pointing to? a", "choices": [{"id": "a", "t": "The shaft ring"}, {"id": "b", "t": "The barrel"}, {"id": "c", "t": "The locking tip"}, {"id": "d", "t": "The plunger 00}"}], "correct": "c", "rationale": "al 5% Easy q The arrow in the picture is pointing to the tip of the syringe; in this case, the syringe has a Luer lock, which allows it to connect to a port for B | 3\" injection of medication and “lock” into place. The grooves in the tip match those on the patient’s IV, which establishes a firm connection. There are several kinds of syringes with different tips, based on size and brand of the syringe. ec Fe 90% pI 2%", "whyNot": {"a": "Shaft ring is not common terminology associated with a syringe.", "b": "The barrel of the syringe is the round, elongated portion that is marked in units to measure content delivery.", "d": "The plunger is the inner portion of the syringe that is pushed forward causing syringe content to be discharged."}, "keyConcept": "Syringes consist of a barrel, a plunger, and a tip. On the outside of the barrel, markers calibrate in milliliters, minims, insulin units, and heparin units. A Luer lock injection ap can be attached to the end of an extension set in hospitalized clients to provide access for intermittent infusion. A Luer lock cap reduces discomfort and prolongs the life of a port by decreasing the number of needle punctures."}, {"id": 11296, "cat": "NCLEX 4", "stem": "deciliter (mg/dL). Further information can be obtained by clicking on the exhibit link to the right. Which of the following is the most appropriate action by the nurse?", "choices": [{"id": "a", "t": "Administer 15 units of NPH now and 9 units of regular insulin after breakfast"}, {"id": "b", "t": "Administer NPH and regular insulin in the same syringe, drawing NPH first"}, {"id": "c", "t": "Administer NPH and regular insulin in same syringe, drawing regular first"}, {"id": "d", "t": "Administer the two insulin doses in separate injections"}], "correct": "c", "rationale": "A | | 9% Moderate Regular insulin and rapid-acting insulin, including lispro and aspart, can be mixed safely in the same syringe with NPH insulin, which is an -acting insulin. Since regular insulin is drawn from a multi-use vial, it should be drawn first to avoid contamination of the vial. NPH insulin is then drawn into the same syringe. ec | 73% of 5% Although two syringes can be used, that would require two injections and additional client discomfort, so it is preferable to mix the two in the same syringe. The MAR indicates that 15 units of NPH insulin should be given at 0700, and the sliding scale indicates that this client, who has a blood glucose level of 280 mg/dL, should receive 9 units of regular insulin before breakfast.", "whyNot": {"a": "“AC” refers to the Latin abbreviation used to indicate a medication given “before meals.”", "b": "Regular insulin in a multidose syringe may be contaminated if the NPH insulin is drawn up initially.", "d": "This is not the best option, as two separate injections will cause additional client discomfort."}, "keyConcept": "Regular (R) insulin is short-acting insulin, with an onset of action of 30 min -1 hour, and peak action at 2-5 hours after administration. Regular insulin provides coverage for meals consumed within 30-60 minutes after administration and has a duration of action of 5-8 hours. Intermediate-acting insulin (NPH (N) and lente (L) insulin) has an onset of action of 1-2 hours, with peak levels 3-12 hours after administration and duration of action of 18-24 hours. it provides coverage for up to half a day or overnight. Mixed insulins combinations should be reviewed prior to administration."}], "nclex_6": [{"id": 11297, "cat": "NCLEX 6", "stem": "X-ray films reveal that a client has closed fractures of the right femur and tibia. Multiple soft-tissue contusions are also present. What is the most important next step in intervention?", "choices": [{"id": "a", "t": "Perform a neurovascular assessment of the extremity"}, {"id": "b", "t": "Reassure the client that these injuries are not that serious"}, {"id": "c", "t": "Gather equipment for a surgical reduction of the injured extremity"}, {"id": "d", "t": "Prepare the client for a surgical reduction of the injured extremity"}], "correct": "a", "rationale": "Identifying the extent of the damage is the priority. Before a treatment protocol can be determined, the nerve and vascular damage must be B 1% identified as part of the assessment. | c| 2%", "whyNot": {"b": "The client has suffered significant injuries; he should be reassured that he is being helped by the staff, not that his injuries are minor.", "c": "Gathering equipment will be necessary but it is not the first priority.", "d": "The client will need to be prepared for treatment, but the first priority is assessment and stabilization."}, "keyConcept": "A client with a fracture of an extremity should be assessed to determine if the trauma has resulted in neurovascular compromise. Assessment is always the initial priority in the nursing process. Assessment of the client's vascular perfusion includes assessment of skin color, capillary refill (normal = <2 seconds); and pulses. Pedal pulses include the posterior tibialis and dorsalis pedis. The pulse should be graded on a scale of zero to five: 2 = ® 4 z = a iat g < 0=no pulse 1=weak, easily obliterated with pressure 2= difficult to palpate, but easy to feel when located 3 = easily palpated, normal 4= strong 5 = bounding Neurological exam of the foot includes motor exam and sensory examination, including fine touch, proprioception, and pinprick."}, {"id": 11298, "cat": "NCLEX 6", "stem": "Convert study guid¢ ® ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja)", "choices": [{"id": "a", "t": "The Achilles reflex is a deep tendon reflex that demonstrates the integrity of the $1 and S2 reflex arc."}, {"id": "b", "t": "The pyramidal tracts are tracts of upper motor neurons that originate in the cerebral cortex and synapse in the brainstem or spinal cord."}, {"id": "c", "t": "The triceps reflex is a deep tendon reflex that tests the integrity of C7 and C8."}, {"id": "d", "t": "The patellar reflex is a deep tendon reflex that demonstrates integrity of L3 sensory and motor neurons."}], "correct": "b", "rationale": "The pyramidal tracts are tracts of upper motor neurons that originate in the cerebral cortex and synapse in the brainstem or spinal cord. The plantar or Babinski reflex is tested by using a tongue blade to slowly stroke the lateral side of the underside of the foot from the heel, moving toward the great toe. The normal response in an adult is plantar flexion of the toes. A positive Babinski reflex is characterized by dorsiflexion of the ankle and great toe with fanning of other toes. In an adult, it indicates disruption of the pyramidal tract. In a CVA, the abnormal reflex is seen on the side of paralysis. In spinal cord injury, the reflex is present bilaterally. The Babinski reflex is positive in neonates but disappears by six to twelve months of age.", "whyNot": {"a": "The Achilles reflex is a deep tendon reflex that demonstrates the integrity of the $1 and S2 reflex arc.", "c": "The triceps reflex is a deep tendon reflex that tests the integrity of C7 and C8.", "d": "The patellar reflex is a deep tendon reflex that demonstrates integrity of L3 sensory and motor neurons."}, "keyConcept": "The nurse should be well versed in performing a neurological assessment especially when a client has had a CVA. The pyramidal tract is the great inverted pyramid of motor nerve fibers descending from the motor cortex and down the brainstem where the fiber bundles on each Mi Inbo x {Eq Untit x Untii x (4 Goor x @ TEAS x Onlir x & Revi x @ Micr x Convert study guid¢ ® ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja)"}, {"id": 11299, "cat": "NCLEX 6", "stem": "edema does this size of indentation most likely characterize? Refer to the accompanying chart to answer the question. Stage Characteristics 1+ Trace Barely detectable, returns rapidly 2+ Mild 1/4 inch depth, returns in 10-15 seconds 3+ Moderate 1/2 inch depth, returns in 1-2 minutes 4+ Severe 1-inch depth, returns in 5 minutes", "choices": [{"id": "a", "t": "Trace O B.mild"}, {"id": "d", "t": "Severe"}], "correct": "a", "rationale": "Pitting edema in the extremities occurs when there is enough swelling that the caregiver can depress the skin. Pitting edema often occurs as a 7 OT3 g a result of a condition that causes excess fluid to build up in the extravascular spaces. This can occur with ascites or heart failure. i c © 7% 4 The nurse can assess the edema and stage it according to the amount of area affected when the skin is depressed and how long it takes for < the tissue to return to normal after pressing on it. A depression of 2 mm in pitting edema is considered to be a trace amount.", "whyNot": {"d": "This question does not describe severe edema, which is 1\" of edema or more"}, "keyConcept": "Generally, edema of the foot is called pedal edema. When fluid collects in the lungs it is called pulmonary edema and can be heard as rales with the stethoscope. Ascites refers to fluid retention in the abdominal cavity. Excess fluid in the brain is cerebral edema. Anasarca refers to extreme generalized edema: the severe, widespread accumulation of fluid in the all of the tissues and cavities of the body at the same time. Dependent edema refers to edema that occurs when the limbs are hanging down and gravity pulls the fluid downward."}, {"id": 11300, "cat": "NCLEX 6", "stem": "@O@ * Viral «<> ¢G o- =o x Sa Recc xX ™_ Inbo student.atitesting.com/LT| x Mi Inbo x {Eq Untit x Untii x (4 Goor x @ TEAS x Onlir x Tutorial: BoardVitals NCLEX Prep RN a Pas ati Module: Quizzes & Assignments Dashboard Quiz ~ Performance ~", "choices": [{"id": "a", "t": "The neurological assessment includes five deep tendon reflexes, including the biceps reflex (innervation of the dorsal roots of C5, C6), the brachioradialis (C5, C6), and the triceps reflex (C7, C8) in the upper extremity."}, {"id": "b", "t": "This depicts the Babinski reflex. It tests integrity of the upper motor neurons in the pyramidal tract."}, {"id": "c", "t": "This depicts the brachioradialis reflex."}, {"id": "d", "t": "This image depicts the patellar reflex."}], "correct": "a", "rationale": "The neurological assessment includes five deep tendon reflexes, including the biceps reflex (innervation of the dorsal roots of C5, C6), the brachioradialis (C5, C6), and the triceps reflex (C7, C8) in the upper extremity. The patellar (L3) and Achilles reflex (S1, $2) are tested in the lower extremity. Deep tendon reflexes demonstrate the homeostasis between the cerebral cortex and the spinal cord. When these reflexes are disrupted, hyperreflexia or hyporeflexia/areflexia occurs. When the nurse taps the tendon stretches the muscle group, which initiates the reflex arc, sending a sensory impulse up to the spinal cord using the sensory (afferent) nerve pathway. At the spinal cord, the signal is transmitted to the other neuron through the synapse, which sends a message back down via the motor (efferent) nerve pathway, causing the muscle to contract.", "whyNot": {"b": "This depicts the Babinski reflex. It tests integrity of the upper motor neurons in the pyramidal tract.", "c": "This depicts the brachioradialis reflex.", "d": "This image depicts the patellar reflex."}, "keyConcept": null}, {"id": 11301, "cat": "NCLEX 6", "stem": "A client is admitted after severe burn injury and is undergoing fluid resuscitation. Which of the following is the most accurate assessment of successful fluid resuscitation?", "choices": [{"id": "a", "t": "Urine output of >30 mL/hr"}, {"id": "b", "t": "Weight gain of 1 kg in 8 hours with good capillary refill"}, {"id": "c", "t": "Heart rate of 94/min with blood pressure of 95/55 mmHg"}, {"id": "d", "t": "Serum potassium level decrease from 5.8 mEq/L to 5.2 mEq/L"}], "correct": "a", "rationale": "Urine output of at least 30 mL/hour or 0.5 mL/kg/hr suggests that the kidneys are perfused and is the best indicator of resuscitation in a burn © I client. D | | Burn clients experience an inflammatory response to cellular injury. Mast cells release histamine and other chemical mediators, which cause an increase in capillary permeability. As a result, fluids leak into the interstitial space (\"third-spacing\"), and the client may experience hypovolemic shock. An indwelling urinary catheter should be used to monitor fluid resuscitation. An isotonic crystalloid, such as lactated Ringer’s solution, is used for fluid resuscitation in burn victims.", "whyNot": {"b": "A rapid weight change can indicate failure of the kidneys to eliminate fluid, with a continuing shift of fluid to the third space. Excessive", "c": "A mean arterial pressure of 65 mmHg or more or a systolic pressure of 90 or more with a heart rate less than 120/minute suggest an", "d": "Resolution of hyperkalemia is one indicator of improving hemodynamic status, but urine output is the key indicator of improved tissue"}, "keyConcept": "The Parkland Formula is commonly used to estimate fluid resuscitation needs in the first 24 hours after a severe burn. The fluid requirement is estimated for adults by using the \"Rule of 9's\" to calculate percentage of body area burned: 9% for each arm, 18% for each leg, 9% for head,18% for front torso, 18% for back torso. The amount of fluid needed is 4 ml x %TBSA x weight (kgs.)50% of fluid is given in the first 8 hours and the remainder is given over 16 hours. Children and older adults may require smaller volumes."}, {"id": 11302, "cat": "NCLEX 6", "stem": "would the nurse expect to see in this stage?", "choices": [{"id": "a", "t": "Acute respiratory failure"}, {"id": "b", "t": "Diminished bowel sounds"}, {"id": "c", "t": "Metabolic acidosis"}, {"id": "d", "t": "No clinical signs"}], "correct": "b", "rationale": "A client who is in the compensatory stage of shock would most likely demonstrate decreased bowel sounds. Although the client’s body is trying to compensate for changes, organs besides the heart and the brain begin to shut down. The gastrointestinal tract may not be functioning properly as the body attempts to compensate by shunting blood to the brain and heart. As shock progresses, other signs of deterioration, such as acidosis and respiratory failure, will occur.", "whyNot": {"a": "Acute respiratory failure would not present during the compensatory stage.", "c": "Metabolic acidosis is more likely to develop in the progressive stage of shock.", "d": "A patient in the compensatory stage of septic would still be expected to show signs/symptoms such as tachycardia, tachypnea, decreased"}, "keyConcept": "Septic shock is a distributive type of shock. Septic shock is associated with sepsis. Sepsis is a systemic antiinflammatory response to an infection. Septic shock is characterized by symptoms of sepsis plus hypotension and hypoperfusion despite adequate fluid volume replacement."}, {"id": 11303, "cat": "NCLEX 6", "stem": "with the greatest specificity and sensitivity in this client? Oj a.cKMB O B. Troponin O C. Myoglobin O p.ast", "choices": [{"id": "a", "t": "Serial measurements of CK-MB isoenzyme levels were previously the standard criterion for the diagnosis of myocardial infarction. CK-MB"}, {"id": "b", "t": "all 7% Easy Positive troponin levels are considered virtually diagnostic of myocardial infarction, according to a revised version of the ACC/AHA consensus es r...s~sSdY 90% statement, as they are without equal in combined specificity and sensitivity in this diagnosis."}, {"id": "c", "t": "Myoglobin, a low-molecular-weight heme protein found in cardiac and skeletal muscle, is released more rapidly from infarcted"}, {"id": "d", "t": "1%"}], "correct": "b", "rationale": "all 7% Easy Positive troponin levels are considered virtually diagnostic of myocardial infarction, according to a revised version of the ACC/AHA consensus es r...s~sSdY 90% statement, as they are without equal in combined specificity and sensitivity in this diagnosis. | D 1%", "whyNot": {"a": "Serial measurements of CK-MB isoenzyme levels were previously the standard criterion for the diagnosis of myocardial infarction. CK-MB", "c": "Myoglobin, a low-molecular-weight heme protein found in cardiac and skeletal muscle, is released more rapidly from infarcted", "d": "AST is used to diagnose liver injury not cardiac injury; AST is not specific for myocardial infarction."}, "keyConcept": "Troponin is the most sensitive and specific test for myocardial injury. Troponin is a protein that is released during myocardial infarction from damaged myocytes. Isoforms of troponin T and | are specific to myocardium. Causes of troponin elevation include acute myocardial infarction, severe pulmonary embolism causing acute right heart overload, heart failure, and myocarditis. Troponins can be used to calculate infarct by measurement of the peak in the 3rd day. After myocyte injury, troponin is released in 2-4 hours and persists for up to 7 days. The image below shows a comparison of troponin and CK MB, before and after reperfusion. i 5 = 100 H + 3 0 : — Troponin (keine Reperfusion) j F — Troponin (Reperfusion) 20 — CK-MB (keine Reperfusion) CK-MB (Reperfusion) 5 2 bere Grenze des : Referenzbereichs Ui T 7 TF 5 7 T Tage nach nfarktbegon _"}], "nclex_7": [{"id": 11304, "cat": "NCLEX 7", "stem": "@ @ % Viral x x Reco X M Inbo x ™ Inbo: x [] Untit x Untii x (4 Goo x @ TEAS X Onlr x && Revi xX @ Micr x Convert study guid: @ alli x @New x | NCL xX + v <€< > G 23 student.atitesting.com/LT| at Dashboard Quiz ~ Performance ~ Qa * es * © tb Finish update : Tutorial: BoardVitals NCLEX Prep RN % CLOSE Module: Quizzes & Assignments { Browse Questions ~ it Search Questions | Q }", "choices": [{"id": "a", "t": "Public distance"}, {"id": "b", "t": "Personal distance"}, {"id": "c", "t": "Social distance"}, {"id": "d", "t": "Intimate distance"}], "correct": "c", "rationale": "Proxemics refers to the different distances that people use when around others. The distance kept between people varies according to their A Public distance B. Personal distance C. Social distance D. Intimate distance", "whyNot": null, "keyConcept": "Proxemics describes the distance between people during communication. The intimate zone, from 0-18 inches, is appropriate for people who are whispering, those with small children or those who desire intimate contact. Invasion of the intimate zone and the personal zone (19- 36 inches) produces anxiety in other communication episodes, including communication used in work or business settings. Communication in the healthcare setting is usually within the social zone (4-12 feet). 2 = ® 4 z = a iat g <"}, {"id": 11305, "cat": "NCLEX 7", "stem": "According to the mechanisms of how a crisis develops and then proceeds, which of the following best describes what should be in the first box? ——", "choices": [{"id": "a", "t": "The client’s support system"}, {"id": "b", "t": "The level of functioning"}, {"id": "c", "t": "The triggering event"}, {"id": "d", "t": "The safety of the environment"}], "correct": "c", "rationale": "Gerald Caplan developed a timeline for the process of a crisis developing and how a person responds to the situation. The timeline begins with a triggering event, which is some sort of threat that causes a person to use coping mechanisms and may produce anxiety. Following the event, the situation escalates until it is considered a crisis. If the problem is not resolved, the person may end up in a disorganized state, unable to control his or her behavior or to utilize coping skills.", "whyNot": {"a": "The client's support system should work to help prevent a crisis. It is not one of the four phases of a crisis event.", "b": "Level of functioning is not one of the four phases of a crisis event.", "d": "Safety of the environment is important in a crisis, but it is not one of the four phases of a crisis."}, "keyConcept": "Gerald Caplan identified four phases of a crisis event, describing how individuals use problem-solving techniques in the face of a threat to their self-concept, which they experience as anxiety. If the client's usual methods of coping fail, the client is at risk of disorganization as mechanisms for problem solving are overwhelmed. This can lead to confusion, depression, suicide, and violence towards others. Convert study guide ) ATI? X % CLOSE { Browse Questions ~ it Search Questions Ja)"}], "nclex_8": [{"id": 11306, "cat": "NCLEX 8", "stem": "Read the following order from a physician. After reading the order, note which of the following nursing actions is most appropriate? \"Administer 500 mg ceftriaxone p.o. now and q 6 hrs x 24 hours for infection prevention.\"", "choices": [{"id": "a", "t": "Administer ceftriaxone by mouth as the physician ordered"}, {"id": "b", "t": "Wait until the client is served lunch and then administer the first dose with food"}, {"id": "c", "t": "Contact the pharmacy to clarify the order"}, {"id": "d", "t": "Contact the physician to clarify the order"}], "correct": "d", "rationale": "A i | 31% Moderate In this situation, the nurse must contact the physician to clarify the order. Ceftriaxone (Rocephin) is only administered in the IV or IM routes, . c] 3%", "whyNot": {"a": "Ceftriaxone is given IM or IV. Therefore it is not possible to give it in the prescribed manner.", "b": "The route needed to be clarified, it is not possible to give this medication by mouth.", "c": "It is the physician, not the pharmacy who should clarify the order."}, "keyConcept": "When accepting physician orders and following through, the nurse must be familiar with the facility’s policies, principles of medication administration, and client care standards to be able to correctly follow orders or know when to question them. 2 = ® 4 z = a iat g <"}, {"id": 11307, "cat": "NCLEX 8", "stem": "After receiving morning laboratory results, the nurse will need to intervene for which of the following clients? O A.A client with end-stage liver disease and elevated ammonia level O B. A client receiving warfarin with an INR of 2.0 O C. A client with heart failure who has a digoxin level of 2.4 ng/mL O D. A client with myocardial infarction and elevated CK-MB", "choices": [{"id": "a", "t": "Elevated ammonia levels are an expected finding in end-stage liver disease; although it is important to address this finding, it is not"}, {"id": "b", "t": "Warfarin is a vitamin K-dependent anticoagulant. Efficacy is monitored by the PT and INR. This is an expected finding. Depending on the"}, {"id": "c", "t": "A Digoxin is a cardiac glycoside used for the treatment of congestive heart failure and atrial fibrillation."}, {"id": "d", "t": "CK-MB is a cardiac isoenzyme released from a damaged myocardium. Elevation of cardiac isoenzymes is expected in myocardial"}], "correct": "c", "rationale": "A Digoxin is a cardiac glycoside used for the treatment of congestive heart failure and atrial fibrillation. Therapeutic levels are 0.8-2 ng/L. Toxic B : levels are >2 ng/L. Toxic effects of digoxin are most likely to occur in clients with hypokalemia, hypomagnesemia, hypoxia, hypercalcemia, and heart disease. Toxicity results in exaggeration of the pharmacological effect, including tachyarrhythmia and bradyarrhythmia. Clinical O€ et signs include nausea, vomiting, headache, disorientation, seizures, and hallucinations. A typical visual change associated with digoxin D Hi toxicity is seeing yellow or yellow-green halos around objects. There has been speculation that Vincent Van Gogh experienced digoxin toxicity.", "whyNot": {"a": "Elevated ammonia levels are an expected finding in end-stage liver disease; although it is important to address this finding, it is not", "b": "Warfarin is a vitamin K-dependent anticoagulant. Efficacy is monitored by the PT and INR. This is an expected finding. Depending on the", "d": "CK-MB is a cardiac isoenzyme released from a damaged myocardium. Elevation of cardiac isoenzymes is expected in myocardial"}, "keyConcept": "Digoxin is used for treatment of congestive heart failure and atrial fibrillation. Digoxin levels must be monitored carefully, as toxic effects occur with levels of more than 2 ng/L and may occur at lower levels in clients with coexisting hypokalemia, hypercalcemia, hypomagnesemia, hypoxia, and heart disease."}], "nclex_9": [{"id": 11308, "cat": "NCLEX 9", "stem": "A nurse is being fitted to use the mask in the picture. Which type of infection is this mask most likely designed to protect against?", "choices": [{"id": "a", "t": "Hepatitis B virus"}, {"id": "b", "t": "Human immunodeficiency virus (HIV)"}, {"id": "c", "t": "Malaria"}, {"id": "d", "t": "Tuberculosis 2 (S g o 5 [a <"}], "correct": "d", "rationale": "a| 1% Easy 95 respirator is a specialized type of mask used for protection against some types of infectious diseases that are transmitted through the © | 1% airborne route. This type of respirator mask filters out smaller particles when compared with standard surgical masks, which are inefficient @ . The other diseases listed are not transmitted via the airborne route.", "whyNot": {"a": "Hepatitis B virus is a blood borne pathogen and a mask is usually not required.", "b": "Human immunodeficiency virus (HIV) is a blood borne pathogen and a mask is usually not required.", "c": "Malaria is prevented by avoiding bites from infected mosquitoes. In addition, if you are traveling to an area that places you at risk, you"}, "keyConcept": "Airborne isolation precautions include airborne infection isolation rooms, use of personal protective equipment that includes a fit-tested N-"}], "neurological": [{"id": 11309, "cat": "NEUROLOGICAL", "stem": "A nurse is assessing a male client who recently began taking haloperidol to treat schizophrenia. Which of the following adverse effects is the highest priority for the nurse to report to the provider?", "choices": [{"id": "a", "t": "Shuffling gait"}, {"id": "b", "t": "Neck spasms"}, {"id": "c", "t": "Drowsiness"}, {"id": "d", "t": "Orthostatic hypotension"}], "correct": "b", "rationale": "‘7 Neck spasms are an indication of acute dystonia, which requires rapid treatment with anticholinergic medication. Acute dystonia can cause o; joint dislocation and impair respiration. This is the greatest risk to the client and is therefore the priority to report to the provider. cil Adverse Effects of Haloperidol include D ri Extrapyramidal symptoms: Manifestations Parkinsonism Pill-rolling tremor Masilike facial expression Shutting gait Stooped posture ‘Arathisia Restlessness Desire to keep moving. pacing Tardive dyskinesia Involuntary movements of the tongue and face ‘Acute dystonia ‘Severe involuntary spasms of the muscies of tongue, face, neck and back Neuroleptic malignant syndrome High fever, above 40° C (104° F) Respiratory distress Severe muscle rigidity Tachycardia Seizures (Other adverse effects: Orthostatic hypotension. Low blood pressure when changing positions ‘Anticholinergic effects Dry mouth Constipation Blurred vision Sedation Drowsiness Somnolence", "whyNot": {"a": "Shuffling gait is an indication of antipsychotic-induced parkinsonism and should be reported to the provider. Antipsychotic-induced", "c": "Drowsiness is an adverse effect of haloperidol and should be reported to the provider. The nurse should instruct the client to avoid driving", "d": "Orthostatic hypotension is an adverse effect of haloperidol and should be reported to the provider. The nurse should instruct the client to"}, "keyConcept": "Haloperidol is a first generation antipsychotic (FGA) used to treat schizophrenia by blocking receptors for dopamine, acetylcholine, histamine, and norepinephrine. The blockage of these receptors accounts for the major adverse effects of the antipsychotics. The nurse should be aware of these adverse effects and report them promptly to the provider."}, {"id": 11310, "cat": "NEUROLOGICAL", "stem": "A nurse is assessing a newly admitted client who reports numbness in the distal extremities and ataxia for the past 3 weeks. Which nutritional deficiency could be the cause of the client's symptoms? O A.Vitamin D O B. Potassium O c.vitamin B12 O D. Magnesium", "choices": [{"id": "a", "t": "1%"}, {"id": "b", "t": "Irritability, decreased respirations, muscle weakness, and gastrointestinal distress are associated with hypokalemia."}, {"id": "c", "t": "A | | 1% Hard Numbness and tingling of the hands and feet are neurologic manifestations associated with vitamin B12 deficiency."}, {"id": "d", "t": "Twitching of muscles and muscle weakness are manifestations of magnesium deficiency."}], "correct": "c", "rationale": "A | | 1% Hard Numbness and tingling of the hands and feet are neurologic manifestations associated with vitamin B12 deficiency. B i 16% oc 46% y", "whyNot": {"a": "Vitamin D deficiency is associated with bone pain, muscle weakness, and rickets.", "b": "Irritability, decreased respirations, muscle weakness, and gastrointestinal distress are associated with hypokalemia.", "d": "Twitching of muscles and muscle weakness are manifestations of magnesium deficiency."}, "keyConcept": "Vitamin B12 is also referred to as cobalamin. Absorption of this vitamin requires intrinsic factor, which is produced by the parietal cells of the gastric mucosa. Lack of intrinsic factor with subsequent B12 deficiency is associated with pernicious anemia. Pernicious anemia results from 2 = ® 4 z = a iat g < autoimmune destruction of the parietal cells. Other causes of B12 deficiency include atrophic gastritis and gastric bypass surgery. Vitamin B12 deficiency may occur in strict vegans or vegetarians who do not take supplemental vitamin B12. Manifestations include macrocytic anemia; glossitis, characterized by pain, swelling, tenderness, and loss of papillae of the tongue; neurologic, cognitive, or psychiatric changes, particularly symmetrical paresthesias or numbness; and gait problems, depression, cognitive change, confusion, and ataxia."}, {"id": 11311, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client who had a spinal cord injury 24 hr ago. Which of the following prescribed medications should the nurse clarify with the provider?", "choices": [{"id": "a", "t": "Calcium supplements"}, {"id": "b", "t": "Plasma expanders"}, {"id": "c", "t": "H2 antagonists"}, {"id": "d", "t": "Muscle relaxants"}], "correct": "d", "rationale": "A i 9% Hard The nurse should clarify the need for the client to receive muscle relaxants with the provider. The client will not experience muscle spasms B Ts 30% until after the spinal shock has resolved, making muscle relaxants unnecessary at this time. If muscle relaxants are used later in the client's treatment, the nurse must monitor for the adverse effects of severe drowsiness and sedation. C |__| io", "whyNot": {"a": "The nurse should administer calcium supplements to this client to help prevent osteoporosis that can result from lack of weight-bearing.", "b": "The nurse should administer plasma expanders to this client to increase capillary blood flow in the spinal cord and to prevent or treat", "c": "The nurse should administer H2 antagonists to decrease the likelihood of the client developing a gastric ulcer from stress."}, "keyConcept": "Spinal cord injuries (SCI) are treated with surgical intervention and immobilizing equipment and devices. Pharmacological measures are often a necessary part of treatment as well. It is the nurse's responsibility to be familiar with the therapeutic intent of prescribed 2 = ® 4 z = a iat g < medications. It is also the nurse's responsibility to review the dosage and administration requirements as well as the expected actions and adverse reactions of the prescribed medications."}, {"id": 11312, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for an older adult with impaired mobility. Which of the following should the nurse consider when planning the client's daily activities?", "choices": [{"id": "a", "t": "The skin of older adults is thicker and may slough more easily"}, {"id": "b", "t": "Hyperreflexia in the older adult affects transfer techniques and modifications may be necessary"}, {"id": "c", "t": "Provide analgesia and skin care for the older adult every day after activities"}, {"id": "d", "t": "Older adults who have been sedentary for long periods may be more likely to develop orthostatic hypotension"}], "correct": "d", "rationale": "Older adults who have been sedentary may be more likely to have blood pool in the lower extremities. When they stand up, they may suffer from orthostatic hypotension, which refers to a drop in blood pressure when the circulation changes lag behind the change in position. Orthostatic hypotension may cause light-headedness, dizziness, or syncope. It is a risk factor for falls in the elderly.", "whyNot": {"a": "Older adults tend to have thinner skin that is more prone to damage.", "b": "Older adults are at higher risk of muscle and joint stiffness, as well as contractures, rather than hyperreflexia.", "c": "Analgesia and skin care may be necessary in some situations, but they are not always needed after daily activities."}, "keyConcept": "Many factors can contribute to impaired mobility in the elderly, including poor vision, decreased hearing, impaired proprioception and balance, loss of muscle mass, and orthostatic hypotension. It's important to consider these limitations when planning care. Older adults are at risk of fracture from falling and a hip fracture may result in loss of independence. It's important to be aware of risks and implement measures to reduce the risk of fall."}, {"id": 11313, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client who has undergone craniotomy. Which of the following nursing interventions is appropriate for this client?", "choices": [{"id": "a", "t": "Keep the client in the supine position"}, {"id": "b", "t": "Encourage the client to cough and take deep breaths every hour"}, {"id": "c", "t": "Encourage the client to perform active range of motion exercises"}, {"id": "d", "t": "Use the Glasgow Coma Scale to monitor the client's mental status"}], "correct": "d", "rationale": "All The Glasgow Coma Scale is a reliable tool for clinical evaluation of changes in neurological signs that might indicate increasing intracranial B I pressure in a client with head trauma, stroke, or another intracranial disorder. The client should avoid coughing, since coughing and sneezing increase intracranial pressure. If the client is intubated, it is important to minimize suctioning that can lead to coughing. Passive € | range of motion will help the client maintain muscle tone but active range of motion should be avoided in the initial post-operative period. @bD Fs", "whyNot": {"a": "The head of the bed should be elevated 30-45 degrees to reduce ICP.", "b": "Coughing and deep breathing prevent atelectasis, not increased intracranial pressure.", "c": "Active range of motion may prevent contractures and muscle stiffness, not increased intracranial pressure."}, "keyConcept": "Normal intracranial pressure (ICP) in adults ranges from 0-15 mmHg (5-15 mm Hg in supine adults.) Increased intracranial pressure refers to ICP above 20 mm Hg. The intracranial compartment has three components: blood, cerebrospinal fluid, and brain tissue, all within a fixed space in the cranial vault. When there is an increase in volume of one of these components, the other components must decrease in size or the ICP will increase. When the physiological mechanisms for compensation are no longer adequate to control ICP, brain herniation may occur."}, {"id": 11314, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client with chronic hepatitis C and cirrhosis who was admitted for hepatic encephalopathy. Which of the following does the nurse expect when assessing the client?", "choices": [{"id": "a", "t": "Hyperactive reflexes"}, {"id": "b", "t": "Agitation and restlessness"}, {"id": "c", "t": "Asterixis"}, {"id": "d", "t": "Enlarged liver"}], "correct": "c", "rationale": ". The liver converts ammonia to urea, so replacement of ec | 39% hepatocytes with scar tissue in cirrhosis results in the buildup of ammonia in the blood stream. Asterixis is characterized by a flapping . Other clinical manifestations of hepatic encephalopathy include lethargy, confusion, difficulty awakening, changes in motor function, and cognitive changes. A late sign associated with cirrhosis that may be noted in clients with hepatic encephalopathy is fetor hepaticus, which refers to breath with a fruity, musty, or sweet fecal smell. Lactulose is prescribed to maximize excretion of ammonia.", "whyNot": {"a": "Reflexes are diminished.", "b": "The client is likely to be lethargic and difficult to awaken.", "d": "In late-stage liver disease, scar tissue replaces hepatocytes, and the liver becomes small and firm."}, "keyConcept": "Liver cirrhosis (hepatic cirrhosis) is a chronic disease characterized by diffuse destruction and fibrotic regeneration of hepatocytes. As necrotic tissues become fibrotic, the diseases alters the liver structure and normal vasculature, impairing flow of blood and lymph, resulting in hepatic insufficiency. The liver's functions include breakdown and elimination of ammonia. Serum levels of ammonia rise in end stage liver disease and result in a neurologic syndrome, hepatic encephalopathy."}, {"id": 11315, "cat": "NEUROLOGICAL", "stem": "the injury. How is this injury classified according to the American Spinal Injury Association’s ASIA scale?", "choices": [{"id": "a", "t": "Grade A spinal cord injury"}, {"id": "b", "t": "Grade B spinal cord injury"}, {"id": "c", "t": "Grade C spinal cord injury"}, {"id": "d", "t": "Grade D spinal cord injury"}], "correct": "b", "rationale": ", from Grade A to Grade E. Grade B is es rd 65% characterized by a lack of motor function, but some preserved sensory function at and below the level of the injury. Grade A spinal cord injuries are complete injuries with the lack of all sensory and motor function; Grade C reflects the some motor function but impaired sensory € || ah function below the level of the injury; and Grade E reflects normal sensory and motor function.", "whyNot": {"a": "This is classified as a Grade B spinal injury, not Grade A.", "c": "This is classified as a Grade B spinal injury, not Grade C.", "d": "This is classified as a Grade B spinal injury, not Grade D."}, "keyConcept": "Spinal cord injury (SCI) usually results from direct trauma to the vertebral column, which affects the spinal cord’s ability to send and receive messages to and from the brain, resulting in impairment of sensory, motor, and autonomic functions below the injury level. A complete SCI causes total loss of all motor and sensory function below the injury level, including sacral segments. In incomplete SCI, the client will retain some level of sensory function, motor function, or both below the injury level. 2 = ® 4 z = a iat g < Avalidated assessment tool, such as the International Standards for Neurological Classification of Spinal Cord Injury from the American Spinal Injury Association (ASIA) is used during assessment of the client to facilitate the appropriate evaluation of motor and sensory function. The scale classifies the degree of impairment as complete (type A) or incomplete (types B through E). ASIA Impairment Scale — ASIA A: Complete: no motor or sensory function is preserved in the sacral segments S4-S5 — ASIA B: Incomplete: sensory but NOT motor function is preserved below the neurological level and includes the sacral segments — ASIA C: Incomplete: motor function is preserved below the neurological level and more than half of key muscles below the neurological level have a muscle grade <3 — ASIA D: Incomplete: motor function is preserved w/ muscle grade > 3 — ASIA E: Normal"}, {"id": 11316, "cat": "NEUROLOGICAL", "stem": "A nurse is planning care for a 6-year-old child who has bacterial meningitis. Which of the following nursing interventions should the nurse include in the plan of care?", "choices": [{"id": "a", "t": "Assist the client in supine position."}, {"id": "b", "t": "Keep the client's room well lit."}, {"id": "c", "t": "Measure head circumference every shift."}, {"id": "d", "t": "Implement seizure precautions."}], "correct": "d", "rationale": "The nurse should include implementing seizure precautions in the plan of care because the child has an increased risk for seizure activity. The meningitis and corresponding brain edema and meningeal irritation can result in seizure activity. Meningitis typically causes a very high fever, which increases the risk of febrile seizures.", "whyNot": {"a": "Placing the client in a semi-Fowler's position, with the head of the bed elevated to between 30° and 45°, will help to reduce edema in the", "b": "The nurse should limit environmental stimuli, such as light and sound because children who have bacterial meningitis are especially", "c": "The head circumference of a 6-year-old child cannot increase since the fontanels and sutures have been closed since the child was 18"}, "keyConcept": "The nurse should be aware of the therapeutic management for a client who has bacterial meningitis. Isolation for the first 24 hr is indicated for a client who has bacterial meningitis due to the highly contagious nature of some types of bacterial meningitis. Decreasing environmental stimuli is also an important action in the care of a client who has meningitis. Additionally, the nurse should implement seizure and isolation precautions, initiate antimicrobial therapy, reduce increased intracranial pressure control temperature, and maintain hydration and ventilation."}, {"id": 11317, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a child who is postoperative following ventriculoperitoneal (VP) shunt placement. Which of the following positions should the nurse place the child?", "choices": [{"id": "a", "t": "Knee-chest"}, {"id": "b", "t": "Semi-Fowler's"}, {"id": "c", "t": "Prone"}, {"id": "d", "t": "Supine"}], "correct": "b", "rationale": "The nurse should monitor the infant postoperatively following a ventriculoperitoneal shunt placement for findings of increased intracranial pressure, such as tense or bulging fontanels, increasing head circumference, lethargy, decreased level of consciousness, poor sucking ability, vomiting, increased temperature, and a decrease in pulse and respiratory rate. These findings can indicate the shunt has an obstruction. The 2 = ® 4 z = a iat g < nurse should also conduct a neurologic assessment including assessment of the pupils, assess for the presence of any abdominal distention, and assess for manifestations of infection.", "whyNot": {"a": "Positioning the child in the knee-chest position can result in inadequate functioning of the VP shunt due to the child's head being lower D || 30%", "d": "Supine positioning does not allow for enough elevation", "c": "Positioning the child in prone position can result in inadequate functioning of the VP shunt due to the need to position the child's head to"}, "keyConcept": "The nurse should monitor the infant postoperatively following a ventriculoperitoneal shunt placement for findings of increased intracranial pressure, such as tense or bulging fontanels, increasing head circumference, lethargy, decreased level of consciousness, poor sucking ability, vomiting, increased temperature, and a decrease in pulse and respiratory rate. These findings can indicate the shunt has an obstruction. The 2 = ® 4 z = a iat g < nurse should also conduct a neurologic assessment including assessment of the pupils, assess for the presence of any abdominal distention, and assess for manifestations of infection."}, {"id": 11318, "cat": "NEUROLOGICAL", "stem": "A nurse is completing a neurological examination on a client who is recovering from a traumatic brain injury. The nurse should perform which of the following actions to assess cranial nerve III?", "choices": [{"id": "a", "t": "Test visual acuity."}, {"id": "b", "t": "Observe for facial symmetry."}, {"id": "c", "t": "Monitor the client's ability to hear the spoken word."}, {"id": "d", "t": "Check the client's pupillary response to light."}], "correct": "d", "rationale": "Cranial nerve III is the oculomotor nerve and is responsible, along with cranial nerves IV (trochlear) and VI (abducens), for eye movement and pupillary response to light. If the cranial nerve III is functioning properly, the expected reaction is pupil constriction in response to light.", "whyNot": {"a": "The nurse tests visual acuity when assessing the function of the optic nerve, which is cranial nerve II.", "b": "The nurse observes for facial symmetry when assessing the function of the facial nerve, which is cranial nerve VII.", "c": "The nurse monitors the ability to hear the spoken word when assessing the function of the auditory nerve, which is cranial nerve VIII."}, "keyConcept": "Nurses should be able to identify the function of each of the 12 cranial nerves. Nurses should also demonstrate the ability to assess each of the nerves by implementing the correct examination technique. Cranial nerves Olfactory sensory: nose Oculomotor motor:all eye muscles except those supplied by @ana © Trochlear ‘motor: superior oblique muscle sensory: face, sinuses ete. Trigeminal Abducent (6) G) motor: muscles of mastication rectus muscle Facial motor: muscles of the face Intermediate motor: submaxillary and sublingual gland sensory:anterior part of tongue and soft palate Vestibulocochlear"}, {"id": 11319, "cat": "NEUROLOGICAL", "stem": "A nurse is teaching a client who has a new prescription for pramipexole to treat Parkinson's disease. The nurse should instruct the client to monitor for which of the following adverse effects?", "choices": [{"id": "a", "t": "Hallucinations"}, {"id": "b", "t": "Increased salivation"}, {"id": "c", "t": "Diarrhea"}, {"id": "d", "t": "Urinary retention"}], "correct": "a", "rationale": "Pramipexole, an antiparkinson agent, stimulates the dopamine receptors in the brain to decrease the tremors and rigidity associated with Parkinson's disease. The nurse should monitor the client for adverse effects and report them promptly to the provider. Adverse effects include + Hallucinations + Dizziness + Orthostatic hypotension + Constipation + Dry mouth + Urinary frequency + Drowsiness and sleep attacks (falling asleep without warning)", "whyNot": {"b": "Dry mouth is an adverse effect of pramipexole. D i", "c": "Constipation is an adverse effect of pramipexole.", "d": "Urinary frequency is an adverse effective of pramipexole."}, "keyConcept": "Pramipexole, an antiparkinson agent, stimulates the dopamine receptors in the brain to decrease the tremors and rigidity associated with Parkinson's disease. The nurse should monitor the client for adverse effects and report them promptly to the provider. Adverse effects include + Hallucinations + Dizziness + Orthostatic hypotension + Constipation + Dry mouth + Urinary frequency + Drowsiness and sleep attacks (falling asleep without warning)"}, {"id": 11320, "cat": "NEUROLOGICAL", "stem": "Which of the following clients is a priority for assessment by a nurse on the pediatric unit?", "choices": [{"id": "a", "t": "A male infant with intussusception who is scheduled for surgery and has stool that looks like “currant jelly” O B.A child postoperative appendectomy who complains of pain"}, {"id": "c", "t": "A child admitted with pyelonephritis who has cloudy urine"}, {"id": "d", "t": "A child with a sickle cell crisis who has a sudden onset of right leg weakness."}], "correct": "d", "rationale": "Ischemic strokes can be a complication of sickle cell anemia. During a sickle cell crisis, sickled red blood cells can occlude blood supply. © | Other causes of stroke in children include carotid artery dissection and aneurysms. The client is at risk of significant permanent disability as ep FY a result of an acute change in condition, making this the most urgent priority for the nurse. A child with sickle cell anemia who has an ischemic stroke requires emergent treatment, just like an adult. In some cases, an exchange transfusion may be necessary.", "whyNot": {"a": "Intussusception is a condition where part of the intestine invaginates into the adjacent portion of intestine, usually around a mass or other", "c": "Pyelonephritis is an infection of the upper urinary tract, and cloudy urine is an expected finding."}, "keyConcept": "Priority assessments are those conditions that pose an immediate threat to survival or safety of the client, usually involving airway, breathing, or circulation. Ischemic stroke in sickle cell disease is caused by occlusion of the blood vessels that supply the brain. Time is critical to treatment to improve outcomes."}, {"id": 11321, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client with Lewy body dementia. The nurse understands that effective communication with a client with dementia can be facilitated by which of the following?", "choices": [{"id": "a", "t": "Speaking in a loud voice"}, {"id": "b", "t": "Touching the client gently before beginning a conversation"}, {"id": "c", "t": "Using simple sentences"}, {"id": "d", "t": "Using open-ended questions"}], "correct": "c", "rationale": "a| 1% Easy Clear and simple sentences and explanations are the most effective way to communicate with an individual with dementia. Lewy body . When communicating with an individual with dementia, the nurse should provide a calming environment and use simple phrases. O€ —— 89%) D 4%", "whyNot": {"a": "Dementia is not associated with hearing impairment. There is no reason to speak in a loud voice to an individual with dementia who does", "b": "Use of touch can be helpful when communicating with someone with hearing loss. It is not known to be useful for individuals with", "d": "Although the use of open-ended questions can help a nurse gain information from many clients, it may be confusing to an individual with"}, "keyConcept": "Dementia is characterized by cognitive impairment. The use of simple, clear phrases and sentences facilitates communication with 2 = ® 4 z = a iat g < individuals who are affected by dementia. The nurse should also provide a calming environment for the client with dementia, particularly when attempting to communicate."}, {"id": 11322, "cat": "NEUROLOGICAL", "stem": "The nurse is caring for a client with an injury to the thalamus. Which of the following nursing interventions is appropriate when caring for this client?", "choices": [{"id": "a", "t": "Give higher doses of pain medication"}, {"id": "b", "t": "Keep patches on the eyes to prevent corneal abrasion"}, {"id": "c", "t": "Monitor the temperature of the bathwater"}, {"id": "d", "t": "Avoid turning the client"}], "correct": "c", "rationale": "A The spinal cord connects the brain to the periphery. The thalamus is located in the midbrain and integrates all sensory impulses except B L olfactory. The afferent impulses are received and then transmitted from the thalamus. Destruction or interruption of the neurosensory pathway results in loss of communication between the two systems. O€ | om", "whyNot": {"a": "The client would not necessarily have pain or need higher doses of pain medicine.", "b": "This intervention is unnecessary in this client.", "d": "The client should be turned frequently to avoid skin breakdown."}, "keyConcept": "The thalamus is an oval-shaped walnut-sized structure in the forebrain, under the corpus callosum. The main function of the thalamus is relaying information from sensory receptors to areas of the brain where it will be processed. Damage to the thalamus can lead to failed processing of sensory information. Thalamic damage can also result in in confusion or coma. Minor damage can cause mild tingling or burning sensation in one side of the body, usually the face, hand, and/or leg. Minor damage can also cause concentration problems, sleeping problems, and insomnia. Thalamic pain syndrome results in hypersensitivity to pain. ‘Thalamus Motor Association Cortex Sensory [— Association Cortex Striatum Globus. Pallidus externus Subthalamic Substantia Nucleus Nigra Globus Pallidus internus"}, {"id": 11323, "cat": "NEUROLOGICAL", "stem": "of further episodes of pneumonia? O A. Well-ventilated room O B. Advanced directives O C. Improved mobility O D. Hydration", "choices": [{"id": "a", "t": "Well-ventilated room"}, {"id": "b", "t": "Advanced directives"}, {"id": "c", "t": "Improved mobility"}, {"id": "d", "t": "Hydration"}], "correct": "c", "rationale": ". A nurse caring for a paralyzed client understands that aspiration and , resulting in pneumonia. The nurse should advise the client of resources that assist the client with mobility in order to avoid the development and recurrence of this type of infection. O€ | 63% om! 24% C-8 clients have all arm movements, with some hand weakness. They can propel a manual wheelchair reasonable distances, in and out of a car, over curbs, and they may even become independent with the use of a wheelchair, allowing them to perform all personal care and daily activities, except heavy housework.", "whyNot": {"a": "Awell-ventilated environment is healthy but not specific to pneumonia and less important than mobility in the prevention of respiratory", "b": "Advance directives are not directly associated with the client’s condition.", "d": "Hydration is important in the maintenance of health, but dehydration is less of a factor in an increased risk of pneumonia than mobility"}, "keyConcept": "Pneumonia is the most common infection in individuals with limited mobility, so assistance with mobility is the most important intervention to assist with recovery and avoidance of future infections. Ineffective coughing causes aspiration and pooling of secretions, so the nurse should encourage the client to keep the lung alveoli open by using incentive spirometry."}, {"id": 11324, "cat": "NEUROLOGICAL", "stem": "Which of the following clients should receive priority for a nurse’s assessment at the beginning of the shift?", "choices": [{"id": "a", "t": "A client with pancreatitis who has nausea and vomiting"}, {"id": "b", "t": "A client who had a hip replacement the previous day and is complaining of 8/10 pain"}, {"id": "c", "t": "An elderly client who fell out of bed last night and has new-onset lethargy and confusion"}, {"id": "d", "t": "An elderly client who has lung cancer and COPD with an oxygen saturation of 89% by pulse oximetry"}], "correct": "c", "rationale": "A client with a closed head injury and a changed level of consciousness is an emergent priority, as mental status changes or neurological deficits may indicate increased intracranial pressure (ICP) from intracranial hemorrhage and/or increased intracerebral edema. Irreversible progression of cerebral edema can result in death, as the brain may herniate and compress the respiratory center. Each shift should begin with a basic neurological assessment that includes the level of consciousness, speech, mentation, pupillary size and response, and the strength of a hand grasp. After a baseline is established, subsequent assessments can be compared to determine if any changes indicative of increased ICP are present.", "whyNot": {"a": "Although nausea and vomiting must be addressed, the priority is a potential increase in ICP in the patient who fell.", "b": "Pain should be addressed in a timely fashion, but it is not life-threatening.", "d": "An oxygen saturation of 88-92% is a target goal for clients with COPD. Higher oxygen saturation may suppress the client’s respiratory drive"}, "keyConcept": "Signs of increased intracranial pressure (ICP) include altered level of consciousness, unequal pupil size or reactivity, headache, decreased respiratory rate and heart rate, and increased systolic pressure with a widened pulse pressure. These symptoms should be reported immediately so treatment can be initiated. The nurse should also calibrate and maintain equipment to monitor ICP; administer prescribed diuretics and corticosteroids to reduce cerebral edema; position the client with HOB elevated 30 degrees to facilitate venous drainage from head; and intervene when temperature is elevated to reduce the risk of increased cerebral metabolism, which increases ICP. Agitation can also increase ICP, so the nurse should intervene with measures to decrease agitation when indicated."}, {"id": 11325, "cat": "NEUROLOGICAL", "stem": "A nurse is providing information to a client with bipolar disorder who has a new prescription for valproic acid (Depakene). Which of the following side effects of valproic acid will the nurse discuss with the client?", "choices": [{"id": "a", "t": "Increased urination"}, {"id": "b", "t": "Hair growth"}, {"id": "c", "t": "Sedation"}, {"id": "d", "t": "Weight loss"}], "correct": "c", "rationale": "| Valproic acid can result in sedation as well as headache, nausea, vomiting, and indigestion. It also causes tremor and thrombocytopenia, B I which can result in bruising. o", "whyNot": {"a": "Increased urination is not a side effect of valproic acid.", "b": "Alopecia, not hair growth, is an adverse effect associated with valproic acid.", "d": "Weight loss is not a common side effect of valproic acid"}, "keyConcept": "Valproic acid is used for the treatment of epilepsy, mania, and migraine headache. The nurse should warn the client that abdominal pain, nausea, vomiting, and/or anorexia can be symptoms of pancreatitis that require prompt medical evaluation. If pancreatitis is diagnosed, valproate should be discontinued. Other significant toxicities include hepatotoxicity. Valproate can cause fetal malformation, so it should only be prescribed to women of childbearing age as a last resort after other medications have failed to control seizures."}, {"id": 11326, "cat": "NEUROLOGICAL", "stem": "A nurse is performing a neurological assessment every 30 minutes for a client admitted with a head injury. Which of the following findings indicate that the client’s condition is satisfactory?", "choices": [{"id": "a", "t": "Ascore of 13 on the Glasgow coma scale"}, {"id": "b", "t": "Absence of deep tendon reflexes."}, {"id": "c", "t": "Decorticate posturing"}, {"id": "d", "t": "Decerebrate posturing"}], "correct": "a", "rationale": "The Glasgow Coma Scale scores range from 0-15. A score of 13 is considered satisfactory. Deep tendon reflexes being absent, and decorticate and decerebrate posturing are abnormal findings. ‘Seortanees Obey commas Netespone fexemson Incorrect Answer: B. Absence of deep tendon reflexes indicates a neurological injury and is not considered normal. C. Decorticate posturing is a sign of a brain injury, not a satisfactory condition. D. Decerebrate posturing indicates a neurological injury and is not considered normal.", "whyNot": null, "keyConcept": "The Glasgow Coma Scale (GCS) is a common scoring system used to describe the level of consciousness in clients who have experienced a traumatic brain injury. It is used to help gauge the severity of an acute brain injury. The GCS correlates well with outcome following severe brain injury and it is a reliable and objective way of recording the initial and subsequent level of consciousness in a client after a brain injury. It measures eye, verbal, and motor responses to stimuli and it is scored on a scale of 3 to 15. (See table below.)"}, {"id": 11327, "cat": "NEUROLOGICAL", "stem": "Aconfused older client is in soft wrist restraints to prevent injury. Which of the following tasks should not be delegated by the Registered Nurse (RN)?", "choices": [{"id": "a", "t": "Reapplying the restraints after assisting the client with toileting"}, {"id": "b", "t": "Assessing neurovascular status and psychological response to restraints"}, {"id": "c", "t": "Performing range-of-motion exercises"}, {"id": "d", "t": "Repositioning and turning the client in bed"}], "correct": "b", "rationale": "Al o: State and federal regulations require all healthcare staff members directly caring for clients in restraints to complete training in caring for the © I client. As a result, all staff has the knowledge and ability to reapply restraints, perform range-of-motion exercises, and reposition the client. D I All staff members are also able to monitor and report any changes in skin integrity to the RN, but only the RN can make the primary assessment of neurovascular status and skin (color, temperature, and integrity), need for continuing restraints, psychological response to restraints, and appropriateness of restraints. A. Unlicensed and licensed healthcare team members directly participating in the care of clients in restraints are trained to reapply restraints. C. Unlicensed and licensed healthcare team members directly participating in the care of clients in restraints have the training and ability to perform range-of-motion exercises. D. All members of the healthcare team who participate directly in care of clients in restraints are trained to reposition and turn the client in bed.", "whyNot": null, "keyConcept": "Federal and state regulations require general training in use of restraints for all healthcare personnel who are participating directly in the care of the client in restraint. This general training teaches involved staff to reapply restraints, perform range of motion exercises, reposition the client in restraints, and monitor for changes in skin integrity. However, the task of primary assessment of neurovascular status, continuing need for restraints, appropriateness of restraints, and the client's psychological response to restraints can only be performed by the RN."}, {"id": 11328, "cat": "NEUROLOGICAL", "stem": "who is in the moderate stage of AD, which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Offer memory training activities."}, {"id": "b", "t": "Limit instructions to two to three steps at a time."}, {"id": "c", "t": "Provide protective undergarments."}, {"id": "d", "t": "Perform ADLs for the client."}], "correct": "c", "rationale": "Mm | 21% Hard A client in the moderate stage of AD begins to experience episodes of urinary and fecal incontinence, which become even more prominent as B Ti 51% the disease progresses. The nurse should assist with bowel and bladder continence by scheduling toileting. The nurse can also initiate the use of protective undergarments to limit the amount of skin breakdown that occurs with incontinence. O€ i 24% o| 4%", "whyNot": {"a": "Cognitive stimulation and memory training can provide some benefit to clients who have AD, but this intervention is appropriate for", "b": "Clients who have AD can become increasingly frustrated and anxious when instructions are given which include more than one step at a", "d": "A client in the moderate stage of AD requires assistance with ADLs as increasing cognitive deficits emerge, but it is not until AD becomes"}, "keyConcept": "Alzheimer's disease progresses over several years with manifestations of cognitive impairment that generally fall into early, middle, and late stages also called mild, moderate, and severe. Although each client is different in the development of manifestations associated with AD, certain characteristics are common to particular stages and involve alterations in language abilities, personality, behavior, cognitive processes, physical abilities, and neurologic status. The nurse should assist the client to maintain mobility and self-care abilities for as long as possible. Client safety and comfort should be high priorities in care planning. Implementing interventions to avoid complications include thickening liquids and cutting food into small pieces to help avoid choking; taking steps to avoid wandering and maintaining a consistent and structured environment to avoid injury and falls; and using a calm voice and avoiding confrontation with the client to reduce the client's agitation and anxiety."}, {"id": 11329, "cat": "NEUROLOGICAL", "stem": "A nurse is providing discharge teaching for a client who has hearing impairment and uses hearing aids. Which action is most appropriate when communicating with this client?", "choices": [{"id": "a", "t": "Stand at the front of the room and use a visual aid for teaching"}, {"id": "b", "t": "Speak slowly and clearly and avoid shouting"}, {"id": "c", "t": "Use hand gestures and miming when information is not understood"}, {"id": "d", "t": "Try using a tone of voice with a higher pitch"}], "correct": "b", "rationale": "all 8% Easy The nurse should speak slowly so that the instructions are clear, and avoid shouting that might make it more difficult for the client to eB Tr tsisSY 88% understand. c| 2%", "whyNot": {"a": "A client with hearing loss may not be able to understand the nurse if the nurse stands at the front of the room, even when using visual", "c": "If the client understands sign language, this might be appropriate, but the client may not understand the nurse’s gestures, and miming is", "d": "A tone of voice with a higher pitch is often more difficult to understand than a low tone of voice."}, "keyConcept": "Hearing-impaired clients have decreased hearing ability that still allows some degree of understanding speech. Hearing-impaired clients typically utilize a combination of subjective and objective signals to interpret speech, based on what they can hear and on lip-reading, body 2 = ® 4 z = a iat g < language, and the context of the conversation. Some clients may require some form of visual communication (sign language) for a significant portion of communication in combination with the previously named methods.Hearing-impaired clients may use a hearing aid or cochlear implant to improve their ability to detect and understand auditory stimuli. A hearing aid is an external battery-operated device that amplifies and changes sound, delivering auditory stimuli through a speaker. Hearing aids process and amplify sound to compensate for a hearing loss, but they cannot replicate natural hearing. Sounds may be distorted and all sounds are equally magnified."}, {"id": 11330, "cat": "NEUROLOGICAL", "stem": "response by the nurse? O A. \"Ibuprofen does not interact with lithium, so you can take it.\" O B. \"Aspirin is better to use than ibuprofen.\" O C. \"Lithium and ibuprofen taken together could upset your stomach.\" O D. \"The ibuprofen will make your lithium level fall too low.\"", "choices": [{"id": "a", "t": "\"Ibuprofen does not interact with lithium, so you can take it.\""}, {"id": "b", "t": "\"Aspirin is better to use than ibuprofen.\""}, {"id": "c", "t": "\"Lithium and ibuprofen taken together could upset your stomach.\""}, {"id": "d", "t": "\"The ibuprofen will make your lithium level fall too low.\""}], "correct": "b", "rationale": "Nm | 16% Hard Aspirin is recommended as a mild analgesic for clients who are taking lithium. Use of ibuprofen will increase the client's risk for lithium en ri 33% toxicity.", "whyNot": {"a": "Ibuprofen is not recommended for clients who are taking lithium because NSAIDS other than aspirin can increase the effect of lithium.", "c": "Lithium may cause gastrointestinal upset, but this is unrelated to the use of ibuprofen. GI upset may occur at peak levels and when the", "d": "Ibuprofen raises the lithium level, increasing the risk for lithium toxicity."}, "keyConcept": "When teaching a client, it is important for the nurse to provide alternative methods to solve a problem instead of simply telling the client what he should and should not do. If the client has an alternative, it is more likely he will adhere to the medication regime. 2 = ® 4 z = a iat g <"}, {"id": 11331, "cat": "NEUROLOGICAL", "stem": "A client with increased intraocular pressure has a new prescription for timolol eye drops. Which of the following describes this class of medication by mechanism of action?", "choices": [{"id": "a", "t": "Prostaglandin analog"}, {"id": "b", "t": "Carbonic anhydrase inhibitor"}, {"id": "c", "t": "Beta adrenergic blocker"}, {"id": "d", "t": "Alpha adrenergic agonist"}], "correct": "c", "rationale": "Timolol (Timoptic) is a beta-adrenergic blocker. It decreases intraocular pressure by reducing aqueous humor formation or increasing outflow. 1OP (intraocular pressure) is the pressure exerted by the fluid inside the eye. Intraocular pressure is measured by using tonometry. Measuring the IOP is a diagnostic test for determining if the client is at risk for developing glaucoma. An elevated or increased IOP is called ocular hypertension. The normally accepted range for |OP is between 10 and 21 mmHg. An obstruction that occurs in the flow of the fluid causes this condition. Normally the fluid that enters through the ciliary body exits through the trabecular mesh work such as in aqueous humor. Any obstruction limits or alters the circulation of the fluid.", "whyNot": {"a": "Prostaglandin analogs relax the ciliary body to improve the outflow of aqueous humor. Bimatoprost (Lumigan), travoprost (Travatan), and", "b": "Acetazolamide (Diamox) is a carbonic anhydrase inhibitor.", "d": "Alphagan is an alpha-adrenergic agonist."}, "keyConcept": null}, {"id": 11332, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client with a spinal cord injury. The nurse understands that which of the following spinal cord injury complications is accurately paired with its description?", "choices": [{"id": "a", "t": "Poikilothermia: A type of neurogenic shock that occurs in clients with a spinal cord injury above T 6"}, {"id": "b", "t": "Autonomic dysreflexia: A life-threatening complication that occurs in clients with a spinal cord injury above T 6"}, {"id": "c", "t": "Autonomic dysreflexia: Poikilothermia is the body’s loss of ability to control and regulate body temperature"}, {"id": "d", "t": "Neutropenia: An abnormally low neutrophil count"}], "correct": "b", "rationale": "-threatening complication of spinal cord injury clients who have a spinal cord injury above T 6. This es rd 56% complication most often occurs with bladder and bowel distension, but it can also occur with fractures and burns. cl 10%", "whyNot": {"a": "Poikilothermia is the loss of the ability to control and regulate body temperature, which may occur in some clients with spinal cord injury.", "c": "Autonomic dysreflexia does not develop as a result of poikilothermia.", "d": "Although neutropenia is an abnormally low neutrophil count, it is not associated with spinal cord injuries, but instead, it can result from"}, "keyConcept": "Autonomic dysreflexia is a complication of spinal cord injury that develops in individuals with injury at or above the sixth thoracic vertebral level (T6). Autonomic dysreflexia causes an imbalance of reflex sympathetic and parasympathetic discharge, which can result in potentially life-threatening hypertension. Signs and symptoms include anxiety and apprehension; irregular or racing heartbeat; nasal congestion; high 2 = ® 4 z = a iat g < blood pressure with systolic readings often over 200 mm Hg; pounding headache; flushing and profuse sweating; lightheadedness, dizziness, confusion, and dilated pupils."}, {"id": 11333, "cat": "NEUROLOGICAL", "stem": "charge nurse assign this client? O A. The nursing assistant O B. The licensed practical nurse O C. The registered nurse O D. Either the registered nurse or the licensed practical nurse", "choices": [{"id": "a", "t": "The nursing assistant"}, {"id": "b", "t": "The licensed practical nurse"}, {"id": "c", "t": "The registered nurse"}, {"id": "d", "t": "Either the registered nurse or the licensed practical nurse"}], "correct": "c", "rationale": "a| 1% Easy The charge nurse should assign the admission to the registered nurse because this client is acutely ill with unpredictable, complex physical . The licensed practical nurse can be assigned client care when the client needs are relatively predictable, chronic and without complexity. When the client is stable, the licensed practical nurse can then be assigned to care for this client. Lastly, nursing assistants are O€ PF 52% not delegated complete client care; nursing assistants and other unlicensed assistive staff can only be delegated some aspects of care .", "whyNot": {"a": "Anursing assistant cannot be delegated the admission of this client.", "b": "This client has acute and complex care needs and should be cared for by a registered nurse.", "d": "The registered nurse should care for this client because the client requires complex care and may be unstable."}, "keyConcept": "The charge nurse should consider staff competence, level of training, education, and scope of practice when delegating or assigning client care tasks. The clients with the greatest complexity should be assigned to the most experienced RN. When delegating tasks, the nurse retains accountability for the outcome. When assigning client care, the nurse who accepts the assignment has responsibility for the outcome. 2 = ® 4 z = a iat g <"}, {"id": 11334, "cat": "NEUROLOGICAL", "stem": "Which of the following clients should the nurse assign to a room closest to the nursing station? O A.A patient with pyelonephritis and agitated delirium receiving intravenous antibiotics O B. A patient with measles on airborne isolation O C.A patient with MRSA with contact precautions O D. A post-stroke patient with right-sided weakness who needs assistance with ambulation", "choices": [{"id": "a", "t": "o; Client safety should be considered a priority when making room assignments."}, {"id": "b", "t": "Proximity to the nursing station is not necessary to maintain airborne precautions."}, {"id": "c", "t": "Proximity to the nursing station is not a priority when maintaining contact precautions."}, {"id": "d", "t": "The call bell should be placed within reach of the client, but proximity to the nursing station should not affect the appropriate frequency"}], "correct": "a", "rationale": "o; Client safety should be considered a priority when making room assignments. Delirium refers to an acute and usually reversible confusional B | state that results from conditions that include fever, infection, and medication toxicity. Older clients are at greater risk of delirium during an | © acute infection. Clients with delirium are disoriented and sometimes agitated, presenting a significant safety risk. Client safety measures include supervision, use of side rails, provision of a quiet environment, and promoting a normal sleep-wake cycle. The call bell should be placed within reach, and traffic paths should be cleared. Assistance with ambulation may be necessary, including the use of assistive devices. Use of restraints should be avoided since they often increase the client’s agitation. The underlying cause of delirium should be addressed with treatment, including maintenance of normal fluid and electrolyte balance and supplemental oxygen if indicated. Blood glucose levels should be monitored, and blood pressure support may be necessary in some cases.", "whyNot": {"b": "Proximity to the nursing station is not necessary to maintain airborne precautions.", "c": "Proximity to the nursing station is not a priority when maintaining contact precautions.", "d": "The call bell should be placed within reach of the client, but proximity to the nursing station should not affect the appropriate frequency"}, "keyConcept": "Delirium is an acute confusional state that may result in agitation. Clients with delirium are at risk of falls and other injuries. A nurse should implement close supervision and environmental measures to reduce risk of harm. Delirium is treated by addressing the underlying illness or condition. Nursing interventions to protect the client include placement by the nurse's station, maintenance of a quiet environment, use of side rails, and promotion of normal sleep-wake cycle."}, {"id": 11335, "cat": "NEUROLOGICAL", "stem": "A nurse is teaching a client who has seizures about going home with her new vagal nerve stimulator. Which of the following statements should the nurse include in the teaching? O A.\"You should use hypoallergenic lotion on your skin in the area of the device.\" O B. \"Notify your provider if you experience hiccups.\" O C. \"You should place the special magnet over the device when you feel an aura occurring.\" O D. \"Itis recommended that you use ultrasound diathermy for pain management.\"", "choices": [{"id": "b", "t": "The nurse should instruct the client to monitor for complications that can develop following the placement of a vagal nerve stimulator"}, {"id": "c", "t": ". This practice B rd 44% has been shown to lessen the severity and duration of the seizure that follows."}, {"id": "d", "t": "The nurse should instruct the client to notify health providers of the presence of the vagal nerve stimulator because exposure to MRI"}], "correct": "c", "rationale": ". This practice B rd 44% has been shown to lessen the severity and duration of the seizure that follows. (See image below) o| 2%", "whyNot": {"b": "The nurse should instruct the client to monitor for complications that can develop following the placement of a vagal nerve stimulator", "d": "The nurse should instruct the client to notify all health providers of the presence of the vagal nerve stimulator because exposure to MRI"}, "keyConcept": "Nurses can provide both educational and emotional support to clients whose lives are impacted daily by seizure disorders. Because clients need to self-manage their conditions, the more information and coping strategies that nurses can provide, the better clients will be able to function and the less likely they will be to experience complications."}, {"id": 11336, "cat": "NEUROLOGICAL", "stem": "A nurse is assessing a client with complaint of hand and wrist pain. Which best describes using Tinel’s sign as part of the health assessment?", "choices": [{"id": "a", "t": "The nurse taps the median nerve with a reflex hammer to check for pain"}, {"id": "b", "t": "The client presses the backs of his hands together and holds for 60 seconds"}, {"id": "c", "t": "The client grasps the nurse’s hands and alternately squeezes each hand"}, {"id": "d", "t": "The nurse occludes the radial artery and then the ulnar artery to check for capillary refill"}], "correct": "a", "rationale": "o; Tinel’s sign is a test for carpal tunnel syndrome in which the nurse uses a reflex hammer to tap the median nerve in the wrist. If the client B i] complains of pain with this test, further assessment and testing of carpal tunnel syndrome is warranted.", "whyNot": {"b": "This describes Phalen’s maneuver, which also tests for carpal tunnel syndrome.", "c": "This test checks for bilateral strength and grip in the client’s hands.", "d": "This is the Allen test and checks for signs of occlusion in the major arteries of the wrist."}, "keyConcept": "Carpal tunnel syndrome is a progressive condition caused by compression of the median nerve in the wrist. Symptoms usually start gradually, with pain, weakness, or numbness in the hand and wrist, radiating up the arm. Paresthesias and decreased grip strength may make it difficult to form a fist, grasp small objects, or perform other manual tasks. In some cases no direct cause of the syndrome can be identified, but it is often seen in individuals who perform repetitive tasks involving wrist flexion."}, {"id": 11337, "cat": "NEUROLOGICAL", "stem": "A nurse is assessing a client with complaint of hand and wrist pain. Which best describes using Tinel’s sign as part of the health assessment?", "choices": [{"id": "a", "t": "The nurse taps the median nerve with a reflex hammer to check for pain"}, {"id": "b", "t": "The client presses the backs of his hands together and holds for 60 seconds"}, {"id": "c", "t": "The client grasps the nurse’s hands and alternately squeezes each hand"}, {"id": "d", "t": "The nurse occludes the radial artery and then the ulnar artery to check for capillary refill"}], "correct": "a", "rationale": "o; Tinel’s sign is a test for carpal tunnel syndrome in which the nurse uses a reflex hammer to tap the median nerve in the wrist. If the client B i complains of pain with this test, further assessment and testing of carpal tunnel syndrome is warranted.", "whyNot": {"b": "This describes Phalen’s maneuver, which also tests for carpal tunnel syndrome.", "c": "This test checks for bilateral strength and grip in the client’s hands.", "d": "This is the Allen test and checks for signs of occlusion in the major arteries of the wrist."}, "keyConcept": "Carpal tunnel syndrome is a progressive condition caused by compression of the median nerve in the wrist. Symptoms usually start gradually, with pain, weakness, or numbness in the hand and wrist, radiating up the arm. Paresthesias and decreased grip strength may make it difficult to form a fist, grasp small objects, or perform other manual tasks. In some cases no direct cause of the syndrome can be identified, but it is often seen in individuals who perform repetitive tasks involving wrist flexion."}, {"id": 11338, "cat": "NEUROLOGICAL", "stem": "with good capillary refill bilaterally. Which of the following is the correct initial action for the nurse? ©", "choices": [{"id": "a", "t": "60-year-old client who was diagnosed with type 2 diabetes at age 30 has undergone left hip arthroplasty. She is now complaining of tingling and numbness in her feet bilaterally. Distal pulses are strong and equal"}, {"id": "b", "t": "Traditional analgesics used after surgical procedures such as opioids are not usually as effective for pain related to diabetic neuropathy as"}, {"id": "c", "t": "A Hi 18% Moderate The client has had diabetes for 30 years."}, {"id": "d", "t": "The client's paresthesia is probably the result of diabetic neuropathy. Before any intervention, the nurse should establish whether or not"}], "correct": "c", "rationale": "A Hi 18% Moderate The client has had diabetes for 30 years. Diabetic neuropathy commonly occurs in a stocking-glove pattern, although diabetes can also affect . By asking the client if the symptoms were present before surgery, a baseline can be established. Other common causes of bilateral peripheral neuropathy include toxic neuropathy and vitamin deficiency neuropathy (in clients with , deficiency of vitamin B12 and thiamine cause several characteristic findings, including peripheral neuropathy). Guillain-Barre syndrome represents an autoimmune neuropathy triggered by a cross-reaction to viral antigens. Adetermination that the signs were present before surgery indicates that they are not the result of a surgical complication and are more likely to represent diabetic neuropathy. Additionally, the symptoms are bilateral, suggesting they are not the result of surgery, which only involved one limb. 2 = a & = a a", "whyNot": {"a": "There is no urgency to notify the healthcare provider since the client is stable. Strong pulses indicate good perfusion in the distal <", "b": "Traditional analgesics used after surgical procedures such as opioids are not usually as effective for pain related to diabetic neuropathy as", "d": "The client's paresthesia is probably the result of diabetic neuropathy. Before any intervention, the nurse should establish whether or not"}, "keyConcept": "When assessing a client's symptoms, it is important to determine the onset and duration, any precipitating or palliative factors, quality, and severity. These factors can provide clues about the cause of the symptoms, allowing the nurse to appropriately plan a course of action."}, {"id": 11339, "cat": "NEUROLOGICAL", "stem": "aspiration? O A. Displays continual tongue rolling while eating O B. Attempts to rapidly swallow with each bite O C. Displays no coughing when food enters the airway O D. Attempts to regurgitate food after swallowing", "choices": [{"id": "a", "t": "Displays continual tongue rolling while eating"}, {"id": "b", "t": "Attempts to rapidly swallow with each bite"}, {"id": "c", "t": "Displays no coughing when food enters the airway"}, {"id": "d", "t": "Attempts to regurgitate food after swallowing"}], "correct": "c", "rationale": "A The nurse should identify that a client who has silent aspiration might not display coughing when food enters the airway. However, the B - client will have manifestations of silent aspiration within 24 hr, such as aspiration pneumonia. o: >", "whyNot": {"a": "The nurse should identify that a client who has dysphagia will have abnormal movement of the mouth, tongue, or lips but will not have", "b": "The nurse should identify that a client who has dysphagia will have delayed swallowing and often incomplete oral clearance that includes", "d": "The nurse should identify that the client who has dysphagia might attempt to regurgitate food after swallowing. However, this is not an"}, "keyConcept": "Dysphagia is when a client has difficulty swallowing and is often caused by neurogenic, myogenic, obstructive, or connective tissue disorders. Numerous complications can occur, including silent aspiration that can lead to pneumonia, dehydration, malnutrition, and weight loss. Coughing during or after eating, a change in voice tone or quality after swallowing, or drooling or leakage of food from the mouth when eating can indicate that the client has dysphagia."}, {"id": 11340, "cat": "NEUROLOGICAL", "stem": "which of the following outcomes should be the nurse's highest priority?", "choices": [{"id": "a", "t": "Prevention of further damage to the spinal cord"}, {"id": "b", "t": "Prevention of urinary tract infections (UTIs)"}, {"id": "c", "t": "Prevention of skin breakdown of areas that lack sensation"}, {"id": "d", "t": "Prevention of contractures to the lower extremities"}], "correct": "a", "rationale": "o; The greatest risk to the client during the acute phase of an SCI is further damage to the spinal cord. When planning care, the nurse should B ] prevent further damage to the spinal cord by minimizing movement of the client until spinal stabilization is accomplished through either traction or surgery and ensuring adequate oxygenation of the client to decrease ischemia of the spinal cord. € |_|", "whyNot": {"b": "A client who has a SCl is at increased risk for the development of UTIs due to the use of urinary catheters which can introduce bacteria into", "c": "The nurse should implement a turning schedule to prevent skin breakdown. The client should be placed on a pressure-reducing mattress", "d": "Clients who have an SCI are at increased risk for the development of joint contractures due to disuse and atrophy of the muscles which"}, "keyConcept": "Clients who have an SCI have impaired physical mobility and a flaccid bladder and bowel. These clients are also at risk for respiratory distress, cardiovascular instability, as well as other complications related to immobility. The highest priority when caring for a client who has an SCl is to stabilize the spine and prevent any further damage to the spinal cord. Nurses also play an important role in preventing the potential complications of skin breakdown, infection, pressure ulcer development, VTE contractures, fractures as a result of osteoporosis, and orthostatic hypotension. Nurses should collaborate with other health care professionals to help clients who have SCls with psychosocial adaptation."}, {"id": 11341, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client who was admitted early in the shift with pancreatitis. When evaluating the client’s laboratory results, what is the immediate priority for intervention?", "choices": [{"id": "a", "t": "White blood cell count 11,000 cells/mm‘3 © B. Sodium 118 mEq/L"}, {"id": "b", "t": "Option B (text recovered from OCR is incomplete)."}, {"id": "c", "t": "Potassium 3.5 mEq/L"}, {"id": "d", "t": "Serum amylase 120 units/dL"}], "correct": "b", "rationale": "Correct Answer: B. Sodium 118 mEq/L | 1% The priority for intervention is the sodium level, which is very low. The normal range of sodium is 135-145 mg/dL. When the sodium level 120 mEq/mL, hyponatremia can result in seizures and other neurologic findings.", "whyNot": {"a": "This is slightly above the limit of normal but is not the priority for intervention. An elevated white blood cell count is consistent with the", "c": "This is a normal potassium level. Potassium should be monitored, particularly if the client is vomiting. Abnormal potassium is associated", "d": "Serum amylase reflects the release of the digestive enzyme from damaged pancreatic cells. It is expected to be elevated in pancreatitis."}, "keyConcept": "Sodium (Na) is a major extracellular fluid cation. The balance of sodium is important for many physiologic functions, including facilitation of impulse transmission in nerve and muscle fibers mediated through the sodium-potassium pump; and maintaining acid-base balance by combining with bicarbonate and chloride. The normal serum sodium concentration ranges from 135 to 145 mEq/L. Hyponatremia can result in neurologic symptoms and cerebral edema. Sodium cannot be replaced too rapidly or it may cause central pontine myelinolysis, which refers to severe damage to myelin sheaths in the area of the pons."}, {"id": 11342, "cat": "NEUROLOGICAL", "stem": "Why is a tilt table with an increased angle at the head of the table used each day to treat a client with quadriplegia?", "choices": [{"id": "a", "t": "It increases tolerance to exercise."}, {"id": "b", "t": "It promotes hyperextension of the spine."}, {"id": "c", "t": "It helps the nurse with transfers from bed."}, {"id": "d", "t": "It reduces the loss of muscle and bone mass."}], "correct": "a", "rationale": "on 7 25% Hard paralysis. Reflex vasoconstriction to change in position is delayed. A physical therapist may use a tilt table to increase tolerance gradually, € i i) increasing the angle at the head of the table each day. When transferring or changing the position of a client with quadriplegia, the nurse D ; | 36% should be cautious and make changes slowly, watching for signs of orthostatic hypotension. Orthostatic hypotension refers to a drop of more than 20 mmHg in systolic blood pressure or 10 mmHg in diastolic blood pressure between positions. Clients with spinal cord injuries may have difficulty maintaining blood pressure when out of bed due to the damage to the autonomic nervous system and spinal nerves. Clients with quadriplegia have delayed blood flow to the brain and upper body in addition to lower body Another reason for use of a tilt table is to keep the client in an erect posture for part of the day to reduce the risk of decubitus ulcers. The tissues on the bottom of the foot can withstand pressure better than other body tissues.", "whyNot": {"b": "Range of motion exercises and stretching are used to prevent contractures.", "c": "A mechanical lift is used to lift clients from bed. Transfers can be performed with a sliding board.", "d": "Weight-bearing exercises reduce the loss of muscle and bone mass."}, "keyConcept": "Clients with spinal cord injuries often experience orthostatic changes in blood pressure as a result of damage to the spinal nerves and autonomic nervous system. Use of a tilt table can increase tolerance to positional changes. A tilt table can also be used to transfer pressure to the tissues at the bottom of the foot, which are less likely to develop pressure ulcers."}, {"id": 11343, "cat": "NEUROLOGICAL", "stem": "addresses her concerns? O A. “Everything is going to be fine with your baby.” O B. “Babies born early can have a higher risk of some issues.” O C. “Stop worrying about things you cannot control.” O D. “Your baby will likely not survive if born now.”", "choices": [{"id": "a", "t": "“Everything is going to be fine with your baby.”"}, {"id": "b", "t": "“Babies born early can have a higher risk of some issues.”"}, {"id": "c", "t": "“Stop worrying about things you cannot control.”"}, {"id": "d", "t": "“Your baby will likely not survive if born now.”"}], "correct": "b", "rationale": "Be truthful with clients and give them accurate information. Morbidities and mortality decrease with increasing gestational age. Some early A | m5 aaa preterm babies born between 22 and 25 weeks of gestation have issues. Neurodevelopment is a major concern for patients with brain and eB Fe 85%) neurosensory impairments. © | 2%", "whyNot": {"a": "Avoid dismissing the client’s real concerns with false promises.", "c": "Do not scold the client for her concern.", "d": "Babies born at 22 weeks of gestation are surviving more often than in previous years but still grapple with risks of death and permanent"}, "keyConcept": "Ethical considerations in the management of periviable births (currently under 26 weeks of gestation) include the type and amount of information that should be given to parents. The measures available for these vulnerable infants have broadened, and outcomes are 2 = ® 4 z = a iat g < improving. Parental decisions for children born before the age of viability is an ongoing ethical question. Justice requires the equal treatment of all people."}, {"id": 11344, "cat": "NEUROLOGICAL", "stem": "A nurse is providing teaching to a client who has a new prescription for levodopa/carbidopa to treat Parkinson's disease. Which of the following statements should the nurse include in the teaching? O A.\"This medication will cause you to urinate more frequently.\" O B. \"Expect muscle twitching to occur.\" O C. \"Take this medication with food.\" O D. \"Relief of symptoms should occur within 24 hours.\"", "choices": [{"id": "a", "t": "Levodopa/carbidopa causes urinary retention; the client should be instructed to notify the provider if this occurs."}, {"id": "b", "t": "The client should monitor and report muscle twitching to the provider, which can indicate toxicity; a dose reduction might be required."}, {"id": "c", "t": "A The client should take this medication with food to reduce adverse gastrointestinal effects, such as nausea and vomiting."}, {"id": "d", "t": "The client should anticipate relief of manifestations to take several weeks to months."}], "correct": "c", "rationale": "A The client should take this medication with food to reduce adverse gastrointestinal effects, such as nausea and vomiting. However, the client B 7 should avoid high-protein meals. o: of", "whyNot": {"a": "Levodopa/carbidopa causes urinary retention; the client should be instructed to notify the provider if this occurs.", "b": "The client should monitor and report muscle twitching to the provider, which can indicate toxicity; a dose reduction might be required.", "d": "The client should anticipate relief of manifestations to take several weeks to months."}, "keyConcept": "Levodopa/carbidopa, a dopamine replacement, is used to treat Parkinson's disease. By replacing dopamine, levodopa/carbidopa decreases the motor symptoms of Parkinson's disease, including bradykinesia, akinesia, tremors, and rigidity. The nurse should include the following in the teaching plan: + Take levodopa/carbidopa with food to reduce nausea and vomiting. Notify the provider if nausea and vomiting becomes severe. + Levodopa/carbidopa should not be taken with high-protein meals as it will reduce the therapeutic response of the medication. + Levodopa/carbidopa might cause involuntary movements such as twitching, dystonic movements, or tremors. The client should notify the prescriber if these symptoms occur. + The therapeutic response to levodopa/carbidopa is not immediate, it can take weeks or months for a reduction in symptoms to occur. + Orthostatic hypotension, characterized by lightheadedness and dizziness, can occur. Instruct the client to move slowly when changing positions. + Levodopa/carbidopa might produce cardiac symptoms, such as tachycardia, irregular heartbeat, or palpitations; the client should notify the provider if these occur. + Levodopa/carbidopa can cause a medication-induced psychosis manifested by visual hallucinations, paranoid thoughts, and vivid dreams. The client should notify the provider if these occur. + Do not take levodopa/carbidopa with the following classes of medications: MAOIs, first-generation antipsychotics, and anticholinergics."}, {"id": 11345, "cat": "NEUROLOGICAL", "stem": "posture? O A. Legs and feet extended, arms pulled up and tucked into chest O B. Legs and feet flaccid, arms rigid and flexed at the elbows O C. Legs, feet, and arms stiffly extended, hands turned outward and flexed O D. Legs, feet, and arms flaccid with no motor response", "choices": [{"id": "a", "t": "Legs and feet extended, arms pulled up and tucked into chest"}, {"id": "b", "t": "Legs and feet flaccid, arms rigid and flexed at the elbows"}, {"id": "c", "t": "Legs, feet, and arms stiffly extended, hands turned outward and flexed"}, {"id": "d", "t": "Legs, feet, and arms flaccid with no motor response"}], "correct": "c", "rationale": "Decerebrate posturing is a rigid form of posturing that is often exhibited after damage to parts of the brain, including the pons and the midbrain. It is displayed by rigid legs and feet, with the feet extended in plantar flexion; the arms rigidly extended down at the sides and the hands clenched and turned outward.", "whyNot": {"a": "This position best describes decorticate posturing; it is not an example of decerebrate posturing.", "b": "A client with decerebrate posturing will have rigid legs and the arms will be extended, not flexed.", "d": "A client with decerebrate posturing will have rigid extremities; the legs, feet, and arms would not be flaccid in this case."}, "keyConcept": "Abnormal posturing is an involuntary flexion or extension of the arms and/or legs, indicating severe brain injury. Decorticate Posturing , Flexed Plantar flexed Internally rotated Flexed Adducted Decerebrate Posturing Plantar flexed Flexed Pronated Extended Adducted"}, {"id": 11346, "cat": "NEUROLOGICAL", "stem": "Which of the following best describes an appropriate desired outcome for a client with a traumatic head injury who has a nursing diagnosis of decreased adaptive capacity?", "choices": [{"id": "a", "t": "Glasgow Coma Scale will be 13 or higher"}, {"id": "b", "t": "Intracranial pressure will be 50 mmHg or greater"}, {"id": "c", "t": "Cerebral perfusion pressure will be less than 20 mmHg"}, {"id": "d", "t": "Mean systolic arterial pressure will be 40 mmHg or less"}], "correct": "a", "rationale": "vsarat scalfunct ; | Nerd The Glasgow Coma Scale (GCS) is a rating scale used to assess neurological function by assessment of eye opening, motor response, and ° ‘ Hi on verbal response to noxious stimuli. A higher GCS score indicates more neurological function; in this case, a score of 13 or higher would be an ideal goal for a client with a head injury. Scores from 3 to 15 are possible. € |_| 18%) of 6% GLASGOW COMA SCORE Eye(s) Opening Spontaneous To speech To pain No response Verbal Response Oriented to time, place, person Confused/disorientated Inappropriate words Incomprehensible sounds No response Best Motor Response Obeys commands Moves to localised pain Flexion withdraws from pain Abnormal flexion Abnormal extension No response BHNwe 2 (S g o 5 [a < PNwaN RPNwWEUD Best response 15 Comatose patient 8 or less Totally unresponsive 3", "whyNot": {"b": "The goal of intracranial pressure would be to have a lower pressure, such as < 10 mmHg, not greater than 50 mmHg.", "c": "Cerebral perfusion pressure should ideally be 60 mmHg to 90 mmHg, not less than 20 mmHg.", "d": "Mean arterial pressure would normally be between 70 mmHg and 105 mmHg, not less than 40 mmHg."}, "keyConcept": "The diagnosis of decreased intracranial adaptive capacity occurs in clients with intracranial hypertension, but is not synonymous with increased intracranial pressure. The diagnosis is related to failure of normal intracranial compensatory mechanisms manifested by repeated disproportional increases in ICP in response to noxious and nonnoxious stimuli. Appropriate outcomes include maintenance of a regular and effective breathing pattern, normal arterial blood gas levels, and regular body functions; normothermia; maintenance of skin integrity; remaining free of infection and signs of neurological dysfunction; maintenance of fluid, electrolyte, and acid-base balance; consciousness; and good wound healing."}, {"id": 11347, "cat": "NEUROLOGICAL", "stem": "oriented to place or time. Which of the following does the nurse suspect in this client?", "choices": [{"id": "a", "t": "Dementia"}, {"id": "b", "t": "Amnesia © c delirium"}, {"id": "c", "t": "Al | Delirium is an acute form of reversible cognitive dysfunction that can occur in hospitalized clients."}, {"id": "d", "t": "Depressive psychosis"}], "correct": "c", "rationale": "Al | Delirium is an acute form of reversible cognitive dysfunction that can occur in hospitalized clients. It may be the initial sign of infection in ec Fs some elderly clients at home or in a nursing home setting. It can be difficult to distinguish the symptoms of delirium from the effects of D I anxiety, medication, or pain. These manifestations can include hyperactive signs, such as agitation, restlessness, paranoia, or hallucinations. Hypoactive signs include disorientation, changes in the level of consciousness, withdrawal, and memory loss. Memory loss or impairment is global, in contrast to chronic and progressive forms of cognitive dysfunction like dementia or memory loss seen in depression. Delirium is associated with increased mortality, particularly if the client is critically ill. In the ICU, clients on mechanical ventilation are at high risk. Nurses should utilize a standardized screening tool for delirium. The Intensive Care Delirium Screening checklist and the Confusion Assessment Method are standardized tools frequently used in the ICU. A comparison of the clinical features of common forms of cognitive dysfunction is shown in the table below. Figure 1. Clinical features of common types of cognitive dysfunction in hospitalized clients", "whyNot": {"a": "Dementia has a gradual onset over a period of months to years, and memory loss is progressive.", "b": "Although amnesia can occur as an effect of a medication or an underlying psychological or psychiatric disorder, delirium is the most likely", "d": "Psychosis can occur as a result of several serious psychiatric conditions, including schizophrenia, bipolar mania, and major depressive"}, "keyConcept": "Delirium refers to an acute change in mental status that occurs as a result of an underlying disease or condition. Elderly clients are at greater risk of delirium than the general population. Clients with delirium experience global memory impairment, disorientation, and confusion. They may experience hallucinations or appear agitated. The priority nursing task is to ensure the client's safety."}, {"id": 11348, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client status post craniotomy who has clear wound drainage of 60 mL during one shift from a drain placed during the procedure. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Log-roll the client with the operative side up."}, {"id": "b", "t": "Cleanse the wound site using sterile saline and apply a new dressing."}, {"id": "c", "t": "Mark the drainage saturation of the dressing and monitor q 12 hours."}, {"id": "d", "t": "Notify the healthcare provider of the amount and color of drainage."}], "correct": "d", "rationale": "Drainage of 50 mL or more per shift or drainage that saturates dressings during the shift suggest the possibility of a leak of cerebral spinal B fluid as a result of an injury to the dura during surgery. A breach in the dura provides a breach in the body’s defense system against central | nervous system infection, including encephalitis, abscess, or meningitis. A dural leak can be exacerbated by increased intracranial pressure € | that results from injury and inflammation. Treatment targets reduction of pressure on the wound, including elevation of the head of the bed, @bD fF placement of a lumbar drain, bedrest, or surgical intervention.", "whyNot": {"a": "The correct position usually prescribed by the neurosurgeon after craniotomy places the head of the bed at 30 degrees of elevation. This", "b": "The healthcare provider should be notified when excessive drainage is noted. The healthcare provider will evaluate the fluid to identify a", "c": "Although the drainage edge should be marked on the dressing at least once a shift, this is not the priority action when the volume of"}, "keyConcept": "Signs of a CSF leak include presence of glucose in wound drainage when tested with a reagent strip; a clear, pink, or yellowish halo around bloody or serosanguinous drainage on the client's dressing, sheet, or pillowcase; and/or reports of headache. If signs and symptoms of cerebrospinal fluid leak occur, the nurse should notify the healthcare provider. Interventions include maintenance of activity restrictions to reduce stress on the dural tear; frequent dressing changes; use of stringent sterile technique for dressing changes; monitoring for signs and symptoms of meningitis; and administration of any prescribed antimicrobials. Dural tears usually resolve without surgical intervention."}, {"id": 11349, "cat": "NEUROLOGICAL", "stem": "@ @ MK ihave x Reco M Inbox M Inbox [J untit! Untit’ (4 Goog @ TEAS <€< > G 23 student.atitesting.com/LT| Tutorial: BoardVitals NCLEX Prep RN Onlin Sati Module: Results Dashboard Quiz ~ Performance ~ & Mark @ Micre Gea ymetier @ atit =@ NCL % CLOSE oma Qarxe we ¥ | O { Browse Questions ~ it Search Questions Ja) Fx ATIT G GERC + Finish update", "choices": [{"id": "a", "t": "Assess muscle strength"}, {"id": "b", "t": "Assess the performance of activities of daily living"}, {"id": "c", "t": "Assess the pain level"}, {"id": "d", "t": "Assess the level of consciousness"}], "correct": "d", "rationale": "a| 1% Easy The Glasgow Coma Scale is used to assess the level of consciousness.", "whyNot": {"a": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not muscle strength. ep fF 97%", "b": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not activities of daily living.", "c": "The Glasgow Coma Scale assesses neurological status and level of consciousness, not level of pain."}, "keyConcept": "The Glasgow Coma Scale (GCS) is a commonly used scoring system used to describe a client's level of consciousness after a traumatic brain injury. It is used to gauge the severity of an acute brain injury and provides an objective way to record initial and subsequent level of consciousness. GCS correlates well with outcome following severe brain injury. (See table below for scoring.) Glasgow Coma Scale Eyeopening Spontaneously 4 response To speech 3 To pain 73 No response 1 Best verbal Oriented to time, place, and person 5 response Confused 4 Inappropriate words 3 Incomprehensible sounds 2 No response 1 Best motor | Obeys commands 6 response Moves to localized pain 5 Flexion withdrawal from pain 4 Abnormal flexion (decorticate) 3 Abnormal extension (decerebrate) 2 No response 1 Totalscore: pect response 15 Comatose client 8orless Totally unresponsive 3"}, {"id": 11350, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for an elderly client who has bilateral hearing loss. The nurse expects to find which of the following on assessment?", "choices": [{"id": "a", "t": "Better hearing with low-pitched than high-pitched tones"}, {"id": "b", "t": "Large amounts of moist cer'umen"}, {"id": "c", "t": "Increased amounts of thickened epithelial tissue in the ear canal"}, {"id": "d", "t": "Tear in the tympanic membrane"}], "correct": "a", "rationale": "Age-related hearing impairment, known as “presbycusis,” is typically related to greater difficulty with high-pitched sounds. It is bilateral, has © Hi a gradual onset, and is caused by the natural process of aging in the auditory system. As presbycusis progresses, individuals will often have D | difficulty with hearing sounds at a lower frequency. Sounds may be unclear, even when they are perceived as loud. Up to 40% of individuals over the age of 65 have some degree of hearing impairment.", "whyNot": {"b": "Presbycusis is a cause of sensorineural hearing loss that is related to normal aging. Cerumen impaction or excess cerumen is a cause of", "c": "This describes a potential cause of conductive hearing loss. Presbycusis, or hearing loss related to aging, is a type of sensorineural hearing", "d": "The tympanic membrane does not appear to be more susceptible to tears as a result of aging."}, "keyConcept": "Hearing loss can be conductive or sensorineural. Presbycusis, which refers to age-related hearing loss, is characterized by gradual, bilateral difficulty with high-pitched sounds. It is a sensorineural process."}, {"id": 11351, "cat": "NEUROLOGICAL", "stem": "@ 0 @ SKihave %& Reco M™ Inbox ™ Inbox {J untit! Untit! (4 Gooo @ TEAS Onlin @& Mark @ Micre (eeiaenurmelicr @ atit =@ NCL € OS @G 23 student.atitesting.com/LT| Tutorial: BoardVitals NCLEX Prep RN % CLOSE O Sati Module: Results Dashboard Quiz~ —_ Performance ~” { Browse Questions ~ |{ Search Questions Ja) oma Qa * F x ATIT G GERC x» * 3 '|1@0 + Finish update", "choices": [{"id": "a", "t": "Contact lenses cannot be worn with the eye medication disk"}, {"id": "b", "t": "The disk is typically administered before the client goes to bed at night"}, {"id": "c", "t": "Swimming is contraindicated when wearing the disk"}, {"id": "d", "t": "The disk is typically replaced every day"}], "correct": "b", "rationale": "Eye medication disks are typically administered into the eye and remain in place for approximately one week, periodically releasing es rd 32% medication into the eye and reducing the need for the client to remember to take eye drops. The disks may cause blurred vision just after they are administered, so the client should place the disk in the eye just before going to bed. € |__| 20% o| 4%", "whyNot": {"a": "Eye medication disks can be administered if the client is wearing contact lenses. Contact lenses do not affect the release of medication", "c": "A client may swim or perform athletic activities while wearing a medication disk in the eye; the activities do not affect release of", "d": "The eye medication disk is typically changed once a week, not once a day."}, "keyConcept": "An oval eye medication disk is a small and flexible disk that consists of three layers: two soft outer layers and a middle layer that contains the medication. The disk floats between the eyelids and the sclera. It should remain in the eye while the client sleeps and during swimming and athletic activities. If the disk falls out, the caregiver or client should wash hands then rinse the disk before replacing it in the eye. A new disk is indicated if the disk is bent."}, {"id": 11352, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a pediatric client with increased intracranial pressure (ICP) who begins to have a seizure. Which of the following is the nurse's priority action?", "choices": [{"id": "a", "t": "Ensuring the client's safety"}, {"id": "b", "t": "Calling the healthcare provider"}, {"id": "c", "t": "Administering anticonvulsants."}, {"id": "d", "t": "Perform a neurological assessment."}], "correct": "a", "rationale": "O; MEM 90% 55 The immediate priority need for this pediatric client is safety. The nurse must protect the child and ensure the child's safety to prevent , and even life-threatening, complications of the seizure, including anoxic brain injury. After the child is no longer at risk for injury, the doctors should be notified and a complete neurological assessment can be performed. € 2%) D 2%", "whyNot": {"b": "The nurse will need to contact the doctor but she must first ensure the client’s safety.", "c": "Anticonvulsants may be prescribed, but the nurse's priority is to protect the client’s safety.", "d": "The nurse should perform a neurological assessment after the seizure; she must first ensure safety."}, "keyConcept": "The pressure in the skull results from the volume of three components: cerebrospinal fluid (CSF), intracranial blood volume and brain tissue. Since the skull cannot expand after the fontanelles and sutures close, the three components of the cranial vault must maintain a state of equilibrium. An increase in one component must be balanced or compensated by constriction either or both of the other two components. 2 = ® 4 z = a iat g < This can occur by decreasing the volume of cerebral blood flow or shifting CSF flow into the subarachnoid space and spinal canal. When these compartments can no longer adapt, ICP increases. Seizures put the client in a hypermetabolic state, increasing oxygen demand, which can cause further increases in ICP."}, {"id": 11353, "cat": "NEUROLOGICAL", "stem": "A nurse is assessing a client who was transported to the ER with neurological deficits after falling off a ladder. What client assessment is included in the Glasgow Coma Scale?", "choices": [{"id": "a", "t": "Breathing patterns"}, {"id": "b", "t": "Deep tendon reflexes"}, {"id": "c", "t": "Eye accommodation to light"}, {"id": "d", "t": "Motor response to a stimulus"}], "correct": "d", "rationale": "The three areas of assessment to determine the level of unconsciousness using the Glasgow Coma Scale are motor, verbal, and eye response B I to stimuli.", "whyNot": {"a": "Breathing patterns are not measured as part of the Glasgow Coma Scale.", "b": "Deep tendon reflexes are not assessed as part of the Glasgow Coma Scale.", "c": "Change in pupil size is not measured as part of the Glasgow Coma Scale."}, "keyConcept": "The Glasgow Coma Scale provides a standardized way to document a client's neurological status. The score should be documented ona coma scale chart. The Glasgow Coma Scale provides a way for healthcare providers to identify trends rapidly so that any improvement or deterioration in the client's condition can be communicated urgently to the healthcare provider. Deterioration in a client's condition should prompt immediate review of any factors that could be responsible for the change that can be corrected. Glasgow Coma Scale Eyeopening Spontaneously response To speech To pain No response -NwWwe Best verbal Oriented to time, place, and person response Confused Inappropriate words Incomprehensible sounds No response Best motor | Obeys commands response Moves to localized pain Flexion withdrawal from pain Abnormal flexion (decorticate) Abnormal extension (decerebrate) No response -Nwaun SHNwWEUnD Total score: gest response 15 Comatose client 8orless Totally unresponsive 3"}, {"id": 11354, "cat": "NEUROLOGICAL", "stem": "A nurse is reviewing the medical record of a client who has a new prescription for bupropion to treat major depressive disorder. Which of the following findings is the priority for the nurse to report to the provider?", "choices": [{"id": "a", "t": "The client reports he has been experiencing insomnia."}, {"id": "b", "t": "The client has hypertension that is treated with enalapril."}, {"id": "c", "t": "The client had a motor vehicle crash last year and sustained a head injury."}, {"id": "d", "t": "The client has a BMI of 25 and has gained 4.5 kg (10 lb) over the past year."}], "correct": "c", "rationale": "The greatest risk to the client is development of seizures. Bupropion can lower the seizure threshold and should be avoided by clients who B Ti 25% have a history of a head injury. This finding is the highest priority to report to the provider.", "whyNot": {"a": "Insomnia can be an adverse effect during initial therapy and should be reported to the provider. The nurse should recommend the client", "b": "The nurse should monitor the client's blood pressure and notify the provider of the client's prescription for enalapril because bupropion", "d": "The nurse should report the client's BMI and change in weight because bupropion can cause weight loss because it suppresses the"}, "keyConcept": "Bupropion is a norepinephrine dopamine reuptake inhibitor (NDRI) that is used to treat depression and seasonal affective disorder. It is also used as a smoking cessation aid. Antidepressant effects take between 7 and 21 days to occur. The nurse should monitor the client's mental status because this medication can cause suicidal ideations. 2 = ® 4 z = a iat g <"}, {"id": 11355, "cat": "NEUROLOGICAL", "stem": "on the information provided, which of the following nursing interventions is most important?", "choices": [{"id": "a", "t": "Increase the client’s activity level as quickly as possible"}, {"id": "b", "t": "Teach the client to promote circulation through ankle rotation and foot pumping"}, {"id": "c", "t": "Administer vasodilator medications as ordered"}, {"id": "d", "t": "Place an abdominal binder on the client and remove it every 24 hours"}], "correct": "a", "rationale": "eo, ia 28% Hard The client described is at high risk of immobility. Although the client may not be able to walk or move the legs below the waist, the nurse can B Hi 21% help the client to increase activity levels by assisting with getting out of bed. This movement, as well as regular turning and position changes, can reduce the complications associated with immobility. € 7 38% om 14%", "whyNot": {"b": "The client will not be able to complete these exercises due to their level of injury.", "c": "This will not help alleviate the client's condition, will not help prevent spinal shock and there is no indication that vasodilators are", "d": "An abdominal binder will not help the client and could have a negative impact on circulation."}, "keyConcept": "Spinal cord injuries that affect the spinal cord at levels T-2 to L-1 result in paraplegia with intact arm function and varying function of 2 = ® 4 z = a iat g < intercostal and abdominal muscles. The nurse should assist the client to perform full range of motion exercises on all extremities and joints and should hyperextend the hips periodically to prevent contractures. Foot drop and external rotation of the hips can be prevented by maintaining the ankles in position at 90 degrees with use of a footboard. It is also helpful to elevate the lower extremities occasionally when the client is in the chair or to raise the foot of the bed in order to prevent pooling of blood and venous stasis."}, {"id": 11356, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client who is post-op lumbar laminectomy. Which of the following is appropriate when caring for this client?", "choices": [{"id": "a", "t": "Encourage the client to cough frequently and deep-breathe"}, {"id": "b", "t": "Assist with repositioning by using the draw sheet and logrolling the client"}, {"id": "c", "t": "Assess the client for symptoms of peritonitis"}, {"id": "d", "t": "Instruct the client to bend the knees while turning"}], "correct": "b", "rationale": "When caring for a client who has undergone lumbar laminectomy, the nurse should consider body mechanics to maintain proper spinal alignment in a neutral spine position. The client usually must remain flat in bed for a period of time after surgery.The nurse should keep the bed flat or elevate the head of the bed slightly, placing a small pillow under the head. If the client lies on the side, the nurse should place a small pillow under the knees, or use a pillow to support the upper leg. This will minimize stress on the surgical incision. The client should be turned every 2 hours, using the logrolling technique. The nurse should advise the client not to use the side rails to change position and to maintain proper body alignment in all positions.", "whyNot": {"a": "The client should be instructed to deep-breathe and use the incentive spirometer. However coughing should be avoided because it would D I", "c": "The abdominal cavity has not been opened, so peritonitis is not a typical complication.", "d": "Flexion of the knees should be avoided in this client post-operatively as it could irritate inflamed spinal nerve roots. Bending, stooping,"}, "keyConcept": "When caring for a client who has undergone lumbar laminectomy, the nurse should consider body mechanics to maintain proper spinal alignment in a neutral spine position. The client usually must remain flat in bed for a period of time after surgery.The nurse should keep the bed flat or elevate the head of the bed slightly, placing a small pillow under the head. If the client lies on the side, the nurse should place a small pillow under the knees, or use a pillow to support the upper leg. This will minimize stress on the surgical incision. The client should be turned every 2 hours, using the logrolling technique. The nurse should advise the client not to use the side rails to change position and to maintain proper body alignment in all positions."}, {"id": 11357, "cat": "NEUROLOGICAL", "stem": "prompt intervention by the nurse? O A. The UAP assists the client to a prone position. O B. The UAP uses the lift sheet to move the client. O C. The UAP encourages the client when he attempts to brush his teeth. O D. The UAP performs passive range of motion exercises.", "choices": [{"id": "a", "t": "The UAP assists the client to a prone position."}, {"id": "b", "t": "The UAP uses the lift sheet to move the client."}, {"id": "c", "t": "The UAP encourages the client when he attempts to brush his teeth."}, {"id": "d", "t": "The UAP performs passive range of motion exercises."}], "correct": "a", "rationale": "A client who is experiencing increased intracranial pressure should not be placed in a prone position. Clients with increased intracranial , to reduce intracranial swelling. cH 9%", "whyNot": {"b": "This is an appropriate action and doesn’t require action by the nurse.", "c": "The client should be encouraged to attempt activities of daily living.", "d": "Passive range of motion exercises are useful to prevent contractures. They can be performed by UAP, so there is no reason for the nurse to"}, "keyConcept": "Delegation is the process of transferring a task or intervention to unlicensed personnel for whom the task or intervention is normally outside of the scope of practice. Although the nurse may delegate performance of a task, accountability for the outcome cannot be delegated. 2 = ® 4 z = a iat g <"}, {"id": 11358, "cat": "NEUROLOGICAL", "stem": "A nurse is caring for a client admitted for treatment of alcohol withdrawal. Which of the following does the nurse anticipate?", "choices": [{"id": "a", "t": "Bradycardia"}, {"id": "b", "t": "Hypotension"}, {"id": "c", "t": "Hypersomnolence © b.trritability"}, {"id": "d", "t": "al 2% Easy ce | 4% Alcohol is a central nervous system depressant and withdrawal can result in CNS excitation with dysfunction of the cardiovascular, © I 5% neurologic, and gastrointestinal system."}], "correct": "d", "rationale": "al 2% Easy ce | 4% Alcohol is a central nervous system depressant and withdrawal can result in CNS excitation with dysfunction of the cardiovascular, © I 5% neurologic, and gastrointestinal system. After prolonged use of alcohol, clients can manifest symptoms of withdrawal within 4 to 12 hours of @pD | 89% taking their last drink. The symptoms of alcohol withdrawal include tachycardia, increased blood pressure, disturbances in sleep, anxiety, irritability, tremor, headache, diaphoresis, nausea, and vomiting. Severe manifestations of alcohol withdrawal include seizures and delirium tremens, which is a life-threatening condition. The risk of progression of alcohol withdrawal can be reduced with treatment with long-acting benzodiazepines. It is not always possible to predict progression to serious manifestations of alcohol withdrawal.", "whyNot": {"a": "Tachycardia is characteristic of alcohol withdrawal.", "b": "Elevated blood pressure is characteristic of alcohol withdrawal syndrome.", "c": "Sleep disturbances are characteristic of alcohol withdrawal syndrome."}, "keyConcept": "Alcohol withdrawal can occur within 4-12 hours of the last drink in individuals who have a history of significant consumption. Physiological instability is manifested by hemodynamic changes, neurologic dysfunction, and gastrointestinal disturbances. If untreated, some individuals may progress to seizures and life-threatening delirium tremens. Nurses should be aware of the potential for physiologic manifestations of alcohol withdrawal in clients who are hospitalized for other conditions and may have underestimated their alcohol consumption when providing a personal history."}], "nutrition": [{"id": 11359, "cat": "Nutrition", "stem": "A nurse is caring for a client with anorexia nervosa. Which of the following is part of an appropriate nursing plan?", "choices": [{"id": "a", "t": "Assess for electrolyte imbalances"}, {"id": "b", "t": "Alert the healthcare provider of the need for a diuretic if edema or bloating occur"}, {"id": "c", "t": "Serve large portions with each meal"}, {"id": "d", "t": "Encourage daily exercise as much as the client desires"}], "correct": "a", "rationale": "3% prevent weight gain or to lose additional weight. As a result, the client may have a weight that is far lower than normal for age and height. A , correction of fluid and electrolyte imbalance; improving self-esteem and helping the client develop a realistic body image. A client's body weight is around 15% lower than expected in clients with anorexia. These clients may have excessive hair loss or increased growth of hair, amenorrhea, hypothermia, bradycardia, and other cardiac arrhythmias. A goal of therapy is to establish a dietary pattern with adequate nutritional intake to regain and maintain a healthy and appropriate weight. An initial assessment of the client’s electrolytes is crucial when planning an appropriate diet. A weight gain of 1 lb (approximately 0.5 kg) a week is the goal of treatment. a = o B f= 4 ° = a = g <", "whyNot": {"b": "Due to the loss of protein associated with malnutrition, edema or bloating may occur with refeeding. The nurse should reassure the client", "c": "Small portions should be offered, as they are less likely to cause gastric dilation and discomfort.", "d": "The client’s exercise should be monitored, as some clients will attempt to use excessive exercise to lose weight."}, "keyConcept": "Disturbance in body image and irrational fear of obesity in clients with anorexia results in food restriction and excessive exercise to lose weight and prevent weight gain. On average, the client with anorexia will have a body weight that is 15% lower than expected. With starvation, life threatening cardiac arrhythmias, electrolyte disturbances, and endocrine dysfunction occur."}, {"id": 11360, "cat": "Nutrition", "stem": "A nurse is providing discharge teaching for a client who has schizophrenia and a new prescription for olanzapine. Which of the following client statements indicates understanding of the teaching? O A.\"Ican skip doses as | begin to feel better on the medication.\" O B. \"If | feel drowsy during the day, | will stop taking this medication and call my provider.\" O C. \"I will watch my diet, so | do not gain too much weight while on the medication.\" O D. \"This medication is addictive and must be withdrawn slowly.\"", "choices": [{"id": "a", "t": "1%"}, {"id": "b", "t": "An adverse effect of olanzapine is somnolence or drowsiness. The nurse should instruct the client to notify the provider if drowsiness"}, {"id": "c", "t": ", such as olanzapine, have a high risk for metabolic effects, including elevated lipid levels, diabetes, and B | at significant weight gain."}, {"id": "d", "t": "Antipsychotic medications are not considered addictive. Therefore, it is not necessary to titrate olanzapine when discontinuing treatment."}], "correct": "c", "rationale": ", such as olanzapine, have a high risk for metabolic effects, including elevated lipid levels, diabetes, and B | at significant weight gain. The nurse should encourage the client to increase physical activity and should provide nutrition education to assist the client in avoiding weight gain. OG | 63%", "whyNot": {"a": "Olanzapine is a second-generation antipsychotic medication that is used in the treatment of schizophrenia. It requires consistent dosing,", "b": "An adverse effect of olanzapine is somnolence or drowsiness. The nurse should instruct the client to notify the provider if drowsiness", "d": "Antipsychotic medications are not considered addictive. Therefore, it is not necessary to titrate olanzapine when discontinuing treatment."}, "keyConcept": "When teaching a client about a new medication, the nurse should instruct the client exactly how to take the medication, what to do if he misses a dose and any expected and unexpected adverse effects. The client should also know what to do if he experiences adverse effects and when to contact the provider."}, {"id": 11361, "cat": "Nutrition", "stem": "the PPN. What is the most likely rationale for this action?", "choices": [{"id": "a", "t": "To prevent backup of blood that can cause clotting in the catheter"}, {"id": "b", "t": "To reduce the risk of phlebitis and infiltration at the site"}, {"id": "c", "t": "To reduce the risk of deep vein thrombosis"}, {"id": "d", "t": "To teach the client the importance of aseptic technique"}], "correct": "b", "rationale": "all 7% Easy Keeping an IV in the same place for a long period of time increases the risk of developing phlebitis or infiltration at the site. The nurse most OB rsd Bay likely changed the IV site to reduce this risk. ° c] 3%", "whyNot": {"a": "The IV site is not changed to reduce the risk of back flow or clotting.", "c": "Achange in IV site does not reduce the risk of DVT.", "d": "The change in IV site for PPN is intended to reduce the risk of thrombophlebitis."}, "keyConcept": "Peripheral parenteral nutrition (PPN) is artificial nutrition used when digestive absorption is insufficient for the client's nutritional needs. PPN provides supplemental nutrition for the client and permits administration through a peripheral catheter. Complications include extravasation and thrombophlebitis. The nurse should flush the line with saline to ensure patency before administration of PPN and should monitor the site for redness, edema, or formation of hard cords under the skin. The IV site should be changed every 72 hours to reduce the risk of thrombophlebitis."}, {"id": 11362, "cat": "Nutrition", "stem": "A nurse is teaching a client who has tobacco use disorder about the use of nicotine gum. Which of the following statements by the client indicates an understanding of the teaching? O A.\"I will chew the gum for no more than 10 minutes.\" O B.\"I will keep the gum in the refrigerator when | am at home.\" O C.\"I will avoid eating for 15 minutes prior to chewing the gum.\" O D.\"I must stop using the gum after 90 days.\"", "choices": [{"id": "a", "t": "The client should chew the gum slowly and intermittently over 30 min."}, {"id": "b", "t": "The client should keep the gum with him, so it can be used when there is a craving. It does not need refrigeration."}, {"id": "c", "t": "The client should avoid eating or drinking for 15 min prior to and while chewing the gum."}, {"id": "d", "t": "Use of nicotine gum is not recommended for longer than 6 months. However, it can be used longer than 90 days."}], "correct": "c", "rationale": "The client should avoid eating or drinking for 15 min prior to and while chewing the gum.", "whyNot": {"a": "The client should chew the gum slowly and intermittently over 30 min.", "b": "The client should keep the gum with him, so it can be used when there is a craving. It does not need refrigeration.", "d": "Use of nicotine gum is not recommended for longer than 6 months. However, it can be used longer than 90 days."}, "keyConcept": "The nurse should provide detailed verbal and written instructions about using nicotine gum to assist with smoking cessation. The nurse should also provide emotional support for the client during the smoking cessation. Other therapies are also often used to stop smoking in conjunction with nicotine gum. The client can use distraction or engage in other activities that use the hands, like cleaning or playing with a coin or rubber band, when the urge to smoke arises."}, {"id": 11363, "cat": "Nutrition", "stem": "A nurse is reviewing positioning for a client who is to receive enteral feedings at home with a family member. Which of the following statements by the family member indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"Iwill allow him to choose the position where he is most comfortable during the feeding.”"}, {"id": "b", "t": "\"I will place his head on a pillow during the feeding.\""}, {"id": "c", "t": "\"I will turn him on his left side during the feeding.\""}, {"id": "d", "t": "\"I will have him sit in his chair during the feeding.\""}], "correct": "d", "rationale": "all 6% Easy The client should be placed in a Fowler's position or in a sitting position in a chair, which is the usual position for eating. This position will B | or prevent aspiration of fluid into the lungs and promote a gravitational flow. | © 2%", "whyNot": {"a": "The head of the bed should be elevated to avoid aspiration, so positioning the client for comfort during enteral feedings might not be", "b": "The head of the bed should be elevated at least 30° to avoid aspiration. Therefore, this statement indicates the need for further teaching.", "c": "If the client cannot tolerate a sitting position, then a slightly elevated right side-lying position can be used. Therefore, this statement"}, "keyConcept": "A nurse who is teaching a family about home enteral feedings should teach about the purpose of the feedings, the correct procedure, including positioning of the client, how to prepare and store the formula, and who to contact for questions. The nurse should also teach the family about monitoring for manifestations of complications that would need to be reported to the provider, including: + Fever «Increased respiratory rate +» Decreased urinary output + Increased stool frequency or diarrhea + Altered level of consciousness"}, {"id": 11364, "cat": "Nutrition", "stem": "A nurse is advising a young adult client on nutrition. Which of the following is a good source of complete protein?", "choices": [{"id": "a", "t": "Cruciferous vegetables"}, {"id": "b", "t": "Brown rice"}, {"id": "c", "t": "Eggs"}, {"id": "d", "t": "Whole grain cereal"}], "correct": "c", "rationale": "| 2% Easy Dietary sources of complete protein include seafood, poultry, milk, yogurt, cheese, eggs, and soybeans. B | 3\"", "whyNot": {"a": "Cruciferous vegetables are a source of incomplete protein (e.g. broccoli).", "b": "Brown rice is a source of vitamin B3 and a variety of trace minerals.", "d": "Whole grain cereal is a source of incomplete protein."}, "keyConcept": "Complete proteins are proteins that provides all essential amino acids. Essential amino acids are amino acids that cannot be made by the body. As a result, they must come from dietary sources. There are nine essential amino acids. Complete proteins are usually animal sources of protein, such as meat, fish, poultry, dairy products, and eggs."}, {"id": 11365, "cat": "Nutrition", "stem": "the TPN is positively affecting the client's nutritional status?", "choices": [{"id": "a", "t": "WBC count 8,000 per cubic millimeter (mm?)"}, {"id": "b", "t": "Serum prealbumin 30 milligrams per deciliter (mg/dL)"}, {"id": "c", "t": "Hematocrit 32%"}, {"id": "d", "t": "Prothrombin time 11.5 seconds"}], "correct": "b", "rationale": "all 6% Easy The nurse should identify that the prealbumin level is directly related to a client's nutritional status. A serum prealbumin level of 30 mg/dL is OB rsd BO within the expected reference range of 15 to 36 mg/dL. Therefore, this level is an indication of a positive change in the client's nutritional ° status. A serum prealbumin level below 15 mg/dL indicates malnutrition. c | 10% oe | 4%", "whyNot": {"a": "The nurse should identify that a client's WBC count of 8,000/mm‘ is within the expected reference range of 5,000/mm? and 10,000/mm*.", "c": "The nurse should identify that a hematocrit level of 32% is below the expected reference range. This is an indication of ineffective RBC", "d": "The nurse should identify that a prothrombin time of 11.5 seconds is within the expected reference range of 11.0 to 12.5 seconds. This is"}, "keyConcept": "Prealbumin is one of the main plasma proteins. The serum albumin level is monitored frequently in clients who are receiving TPN to monitor its effectiveness. The test is used to verify a client's nutritional status, as well as to monitor liver function status. There are certain medications that cause an increase in the serum prealbumin level which include anabolic steroids and prednisolone. Medications that can cause a decrease in the serum prealbumin level include oral contraceptives, estrogen, and amiodarone."}, {"id": 11366, "cat": "Nutrition", "stem": "to improve the client's enjoyment of food?", "choices": [{"id": "a", "t": "\"Avoid citrus juices.\""}, {"id": "b", "t": "\"Use plastic utensils to eat.\""}, {"id": "c", "t": "\"Eat foods that are warm.\""}, {"id": "d", "t": "\"Eat meat with something sour.\""}], "correct": "b", "rationale": "Ail The use of plastic utensils when eating can enhance taste sensations for a client who is receiving chemotherapy and can reduce the OB a occurrence of a metallic taste caused by chemotherapy. c", "whyNot": {"a": "A client who is receiving chemotherapy and has altered taste should try adding tart foods to his diet to increase the flavor of foods and", "c": "A client who is receiving chemotherapy and has altered taste might find that eating cold or room-temperature foods improves taste", "d": "Eating meat with something sweet, such as turkey with cranberry sauce, can make it more flavorful."}, "keyConcept": "Chemotherapy can cause adverse effects to the gastrointestinal tract including anorexia, nausea and vomiting, and stomatitis. Nutritional recommendations to manage stomatitis include eating cold foods, consuming soft or non-irritating foods, and adding gravies or sauces to increase fluid content."}, {"id": 11367, "cat": "Nutrition", "stem": "Which nutritional assessment data should be collected during the health history and physical assessment portions of the nursing assessment?", "choices": [{"id": "a", "t": "Dentition"}, {"id": "b", "t": "Parathyroid functioning"}, {"id": "c", "t": "Adrenal gland functioning"}, {"id": "d", "t": "The Babinski reflex for swallowing"}], "correct": "a", "rationale": "There is a large amount of data that should be collected during a nutritional assessment. Poor dentition, including poorly fitting dentures, B I a places the client at risk for impaired nutrition. Other important data related to nutrition includes food preferences, cultural and religious practices, weight changes, appetite, changes in bowel patterns, food allergies, current medications, daily food and fluid intake, and the c | 3% client’s BMI. om 13%", "whyNot": {"b": "Parathyroid function is typically not part of the nutritional assessment.", "c": "Adrenal gland function is typically not part of the nutritional assessment.", "d": "The Babinski reflex assesses neurological function. It does not assess the swallowing reflex."}, "keyConcept": "When conducting a nutritional assessment, the nurse should combine multiple objective assessment measures in addition to subjective assessment items. The Mini Nutritional Assessment can be used to screen clients, but there is not one single effective measure available to adequately assess the client for risk of nutritional problems. Clients with chronic illness or increased metabolic needs due to surgery, burns, trauma, or acute illness have increased metabolic requirements."}, {"id": 11368, "cat": "Nutrition", "stem": "A nurse is providing teaching to an adult client who has a BMI of 28. Which of the following statements by the client indicates an understanding of the instructions?", "choices": [{"id": "a", "t": "\"Iwill eliminate foods containing to high amounts of Vitamin D.\""}, {"id": "b", "t": "\"I willincrease my daily water intake to 1 liter.\""}, {"id": "c", "t": "\"Iwill lose 2 pounds per week if eat a diet of 1,800 calories per day.”"}, {"id": "d", "t": "\"I will increase my amount of daily physical activity.\""}], "correct": "d", "rationale": "The nurse should identify that a BMI of 28 places the client into the upper range of the \"overweight\" category (25 to 29.9). Therefore, the nurse should recommend that the client increase her daily physical activity level because inactivity contributes to weight gain. Increasing daily physical activity helps to increase the amount of lean body mass, which positively affects the metabolic rate. Increasing activity and € | i) decreasing caloric intake will assist the client in losing weight. @D fF 88%", "whyNot": {"a": "The nurse should recommend that the client maintain sufficient intake of vitamin D to reduce her chances of developing osteoporosis.", "b": "The nurse should recommend a daily water intake of at least 2 to 3 liters. Drinking water helps to boost metabolism, cleanse the body of", "c": "The nurse should recommend a 1,000 to 1,200 calorie/day diet for middle adult female clients who are overweight. Decreasing caloric"}, "keyConcept": "A lifestyle approach which includes nutrition therapy, physical activity, and behavior modification is the foundation of comprehensive weight management. Assessing a client's motivation level is extremely important for successful weight loss. Weight loss is not likely to occur in client's who are not motivated or ready to change their lifestyle. A \"healthy weight\" is a weight in which a client can physically move comfortably, maintain without undue restriction of food intake or without excessive exercise, and can live without experiencing weight- related disorders. Increased physical activity = Greater health benefits for the client including: + Increased odds of living longer + Increased self-confidence + Decreased manifestations of depression + Decreased insomnia + Increased ease of movement «Increased muscle and bone strength"}, {"id": 11369, "cat": "Nutrition", "stem": "the subclavian vein. The current bag of solution was hung 24 hr ago, and 400 mL remain to infuse. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Remove the current bag and hang a new bag."}, {"id": "b", "t": "Infuse the remaining solution at the current rate and then hang a new bag."}, {"id": "c", "t": "Increase the infusion rate so the remaining solution is administered within 1 hr and hang a new bag."}, {"id": "d", "t": "Remove the current bag and hang a bag of dextrose 5% in water (D5W)."}], "correct": "a", "rationale": "TPN solutions contain high levels of dextrose and proteins which provide an excellent environment for bacterial growth. For this reason, TPN B ] 14% solution should be discarded after hanging for 24 hr. c| 1%", "whyNot": {"b": "The current bag of TPN should not hang for longer than 24 hr due to the risk of infection.", "c": "The rate of TPN infusion should never be increased abruptly, due to the risk of hyperglycemia. The infusion rate is prescribed by the", "d": "Administration of TPN should never be discontinued abruptly, due to the sudden change in blood glucose that can occur. If a new bag of"}, "keyConcept": "While the client is receiving TPN, the nurse is responsible to protect the catheter insertion site, ensure proper function of the infusion pump, 2 = ® 4 z = a iat g < and monitor the client's electrolyte and glucose levels as well as the client's fluid balance. Intensive nutrition therapy is beneficial to the client but does present risks. Careful monitoring by the nurse can help to avoid complications."}, {"id": 11370, "cat": "Nutrition", "stem": "A nurse is providing discharge instructions about a high-fiber diet to a client who has chronic constipation. Which food choice by the client indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "Peanut butter"}, {"id": "b", "t": "Roast chicken"}, {"id": "c", "t": "Fruit juice without pulp"}, {"id": "d", "t": "Dried beans"}], "correct": "d", "rationale": "all 6% Easy Dried beans are a good source of fiber and are low in fat. 8 | 3% cil 8% 9", "whyNot": {"a": "Peanut butter is a good protein source and has a high fat content; however, it is not a high-fiber food source.", "b": "Roast chicken is not a good source of fiber.", "c": "Fruit juice without pulp is not a good source of fiber."}, "keyConcept": "Constipation is treated by increasing the amount of dietary fiber and fluid the client consumes. The amount of fiber recommended is determined by the individual client's needs and is increased gradually to avoid manifestations of intolerance, such as gas and diarrhea. The client should also increase daily physical activity to promote bowel regularity."}, {"id": 11371, "cat": "Nutrition", "stem": "A nurse is teaching the parents of a school-age child who has diabetes mellitus about nutrition and medication usage. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"You should eliminate carbohydrates.\""}, {"id": "b", "t": "\"You should combine glargine and regular insulin in the same syringe.\""}, {"id": "c", "t": "\"You should aspirate for blood before injecting the insulin.\""}, {"id": "d", "t": "\"You should give four or five injections around one area before switching sites.\""}], "correct": "d", "rationale": "A The nurse should instruct the client and parents to administer four or five injections about 2.5 cm (1 in) apart before switching to another B LU site. iz cH", "whyNot": {"a": "Carbohydrates are necessary for a well-balanced diet. The type of carbohydrate is not as important as the content. Healthy carbohydrates", "b": "The nurse should instruct the client and parents to avoid mixing glargine with any other medication due to incompatibility.", "c": "The nurse should instruct the client and parents that it is not necessary to aspirate for blood prior to administering insulin."}, "keyConcept": "Children who have diabetes are more successful in maintaining good nutrition if their entire family adopts a diabetic-friendly diet. A child who has diabetes can become resentful or depressed if they are not able to be included in meals with their loved ones. Allowing children to be involved in meal planning and shopping helps to get them excited about their food options."}, {"id": 11372, "cat": "Nutrition", "stem": "A nurse is teaching the parents of a school-age child who has diabetes mellitus about nutrition and medication usage. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "\"You should eliminate carbohydrates.\""}, {"id": "b", "t": "\"You should combine glargine and regular insulin in the same syringe.\""}, {"id": "c", "t": "\"You should aspirate for blood before injecting the insulin.\""}, {"id": "d", "t": "\"You should give four or five injections around one area before switching sites.\""}], "correct": "d", "rationale": "A The nurse should instruct the client and parents to administer four or five injections about 2.5 cm (1 in) apart before switching to another B LU site. iz cH", "whyNot": {"a": "Carbohydrates are necessary for a well-balanced diet. The type of carbohydrate is not as important as the content. Healthy carbohydrates", "b": "The nurse should instruct the client and parents to avoid mixing glargine with any other medication due to incompatibility.", "c": "The nurse should instruct the client and parents that it is not necessary to aspirate for blood prior to administering insulin."}, "keyConcept": "Children who have diabetes are more successful in maintaining good nutrition if their entire family adopts a diabetic-friendly diet. A child who has diabetes can become resentful or depressed if they are not able to be included in meals with their loved ones. Allowing children to be involved in meal planning and shopping helps to get them excited about their food options."}, {"id": 11373, "cat": "Nutrition", "stem": "A nurse is providing medication teaching to a client who has major depressive disorder and a new prescription for amitriptyline. Which of the following information should the nurse include? O A.\"You might experience constipation while taking this medication.\" O B. \"Your blood pressure might increase while taking this medication.\" O C. \"Weight loss is a common adverse effect of this medication.” O D. \"Increased salivation is an expected adverse effect of this medication.\"", "choices": [{"id": "a", "t": "o; Constipation is a common adverse effect of amitriptyline."}, {"id": "b", "t": "Hypotension is a common adverse effect of amitriptyline. The nurse should instruct the client to change positions slowly to prevent"}, {"id": "c", "t": "Increased appetite and weight gain are expected adverse effects of amitriptyline. The nurse should instruct the client to monitor daily"}, {"id": "d", "t": "Dry mouth is an expected adverse effect of amitriptyline. The nurse should instruct the client to increase daily fluid intake and use"}], "correct": "a", "rationale": "o; Constipation is a common adverse effect of amitriptyline. The nurse should instruct the client to increase the daily intake of fluids and foods B i high in fiber.", "whyNot": {"b": "Hypotension is a common adverse effect of amitriptyline. The nurse should instruct the client to change positions slowly to prevent", "c": "Increased appetite and weight gain are expected adverse effects of amitriptyline. The nurse should instruct the client to monitor daily", "d": "Dry mouth is an expected adverse effect of amitriptyline. The nurse should instruct the client to increase daily fluid intake and use"}, "keyConcept": "The nurse should provide both verbal and written instructions to a client who has a new prescription. Amitriptyline is a tricyclic antidepressant used to treat depressive disorders, anxiety disorders, and chronic pain syndromes. The nurse should instruct the client to notify the provider of worsening manifestations of depression or suicidal ideation."}, {"id": 11374, "cat": "Nutrition", "stem": "discontinuation of NPO status? O A. Chicken broth, cranberry juice, and sherbet O B. Chicken broth, cranberry juice, and Italian ice or pudding O C. Beef broth, ginger ale, and pudding O D. Beef broth, gelatin, and a citrus soda", "choices": [{"id": "a", "t": "Chicken broth, cranberry juice, and sherbet"}, {"id": "b", "t": "Chicken broth, cranberry juice, and Italian ice or pudding"}, {"id": "c", "t": "Beef broth, ginger ale, and pudding"}, {"id": "d", "t": "Beef broth, gelatin, and a citrus soda"}], "correct": "d", "rationale": "A ; | The client should start with clear liquids after the physician has discontinued the NPO order. Clear liquids include such items as chicken or B i beef broth, gelatin, and soda. cil", "whyNot": {"a": "The client should start on a clear liquid diet, which may include chicken broth and juice, but sherbet is not included in this diet.", "b": "The client should start on a clear liquid diet, which may include chicken broth and juice, but pudding is not included in this diet.", "c": "The client should start on a clear liquid diet, which may include beef broth and ginger ale, but pudding is not included in this diet."}, "keyConcept": "When advancing a client from NPO, the nurse understands that dietary intake should progress gradually to manage the client's transition from the NPO state, promote appetite. Clear liquids are provided initially. Thicker liquids provide more control to the client. The nurse should assist the client with oral feedings as needed."}, {"id": 11375, "cat": "Nutrition", "stem": "A nurse is reinforcing teaching for a client who has stage 2 HIV infection and is having difficulty maintaining a normal weight. Which of the following client statements indicates understanding?", "choices": [{"id": "a", "t": "“Iwill choose a diet high in fat to gain weight.”"}, {"id": "b", "t": "“I will be sure to eat 3 large meals daily.”"}, {"id": "c", "t": "“I will drink up to 1 liter of liquid each day.”"}, {"id": "d", "t": "“I will add high-protein foods to my diet.”"}], "correct": "d", "rationale": "A ™% Easy Weight loss can occur in clients with HIV as a result of the virus or the medications used to treat the infection. Some clients may have i symptoms such as alterations in taste or nausea that reduce appetite. In advanced HIV infection, weight loss may be an indication of an opportunistic infection. The client should add high-protein, high-calorie foods to the diet daily to gain weight and maintain health. c| 2%)", "whyNot": {"a": "The client should avoid high-fat foods to gain weight because fat intolerance causing flatus, bloating, and diarrhea is common in clients", "b": "The client should eat small, frequent meals (e.g. 6 meals per day) to promote weight gain.", "c": "The client should drink 2-3 L of liquids daily to maintain hydration, not gain weight."}, "keyConcept": "Weight loss can occur as a result of the HIV virus, antiretroviral drug therapy, or symptoms that reduce appetite. Clients should eat frequent small meals with high-protein, high-calorie food choices. 2 = ® 4 z = a iat g <"}, {"id": 11376, "cat": "Nutrition", "stem": "and I’m tired of people asking me about it!” How should the nurse respond?", "choices": [{"id": "a", "t": "“It’s important for you to realize that carbohydrates can increase your blood glucose, which will cause additional health problems over time.”"}, {"id": "b", "t": "“You seem very angry. Can you tell me why you are feeling so upset?”"}, {"id": "c", "t": "“Your healthcare provider must have this information to advise you on how to control your diabetes.”"}, {"id": "d", "t": "“Don’t be angry. You don’t have to tell me what you eat.”"}], "correct": "b", "rationale": "Nm | 16% Easy The client may be angry about the condition and having to make accommodations for the condition, or the client may be upset about the © | 2% effects the condition has had on health, particularly if they are progressive or irreversible. The nurse’s priority is to allow the client to express D angry feelings and underlying concerns and to provide empathy and support. An open-ended question will allow the client to express anger, which will provide an opportunity to de-escalate and help the client cope with the frustrations. The nurse also acknowledges the client’s anger by a reflective statement. 0%", "whyNot": {"a": "This is not a therapeutic response and seems dismissive. The nurse is giving advice but fails to acknowledge or explore the client’s", "c": "This response does not address the client’s anger or concerns and does not show acceptance or empathy.", "d": "This response may deescalate the client’s anger but does not acknowledge or explore the client’s anger or help to address the client’s"}, "keyConcept": "Clients who are faced with life changes or behavior modifications as a result of a health condition may be upset about the condition or reluctant to make significant changes. The nurse should understand that angry responses may reflect fear and concern and should provide acceptance and encouragement for the client, which establishes trust and provides a therapeutic environment in which the client can express fears and feelings, including anger."}, {"id": 11377, "cat": "Nutrition", "stem": "A nurse is providing teaching to a new mother who has given birth to twins, both of whom are lactose intolerant. What should be part of the teaching plan for this client?", "choices": [{"id": "a", "t": "The benefits of low-iron milk for lactose intolerant infants"}, {"id": "b", "t": "The use of soy infant formulas for lactose intolerant infants."}, {"id": "c", "t": "The benefits of rice milk to decrease the infant’s intolerance"}, {"id": "d", "t": "The use of almond milk for infants who are lactose intolerant"}], "correct": "b", "rationale": "New mothers should be instructed about the use of soy infant formulas for lactose intolerant infants and those with milk protein allergy. Low-iron formulas are not indicated for infants with or without lactose intolerance, because infants need iron as part of their daily nutrition. Lastly, almond milk and rice milk, although used as milk substitutes by lactose intolerant adults, do not contain the nutrients that infants require.", "whyNot": {"a": "Infants need iron in their diets; low-iron milk would not benefit lactose intolerant infants.", "c": "Rice milk may be used in lactose intolerant adults but it is not nutritionally adequate for infants.", "d": "Almond milk may be used in lactose intolerant adults but it is not nutritionally adequate for infants."}, "keyConcept": "The best source of nutrition for infants is breast milk. The American Academy of Pediatrics (AAP) recommends exclusive breastfeeding of human milk for the first 6 months and continued breastfeeding for at least 12 months. If breastfeeding is contraindicated or otherwise impossible, there are a variety of commercial infant formulas, including cow’s milk-based formulas, soy-based formulas, which are commonly used for children who are lactose or cow’s milk-protein intolerant, and casein- or whey- hydrolysate formulas. Casein- or whey-hydrolysate formulas are used primarily for children who cannot tolerate or digest cow’s milk- or soy- based formulas. Amino acid formulas are also available for infants with multiple food protein intolerances. Worldwide prevalence of lactose intolerance in recent populations (schematic)"}, {"id": 11378, "cat": "Nutrition", "stem": "A nurse is providing teaching for a client who has HIV and is having difficulty gaining weight. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| will choose a diet high in fat.\" O B. \"Iwill be sure to eat three large meals daily.\" O C. \"Iwill drink up to 1 liter of liquid each day.\" O D. \"I will add foods that are high in protein to my diet.\"", "choices": [{"id": "a", "t": "The client should be instructed to avoid high-fat foods to gain weight because fat intolerance, which causes flatus, bloating, and diarrhea,"}, {"id": "b", "t": "The client should be instructed that small frequent meals (e.g., six small meals daily) are better tolerated than three large meals."}, {"id": "c", "t": "The client should be instructed to drink 2 to 3 L of liquids daily to maintain hydration status."}, {"id": "d", "t": "all 9% Easy The client should be taught to eat high-protein, high-calorie foods daily since this is the best way for the client to gain weight and maintain ."}], "correct": "d", "rationale": "all 9% Easy The client should be taught to eat high-protein, high-calorie foods daily since this is the best way for the client to gain weight and maintain . c| 1%", "whyNot": {"a": "The client should be instructed to avoid high-fat foods to gain weight because fat intolerance, which causes flatus, bloating, and diarrhea,", "b": "The client should be instructed that small frequent meals (e.g., six small meals daily) are better tolerated than three large meals.", "c": "The client should be instructed to drink 2 to 3 L of liquids daily to maintain hydration status."}, "keyConcept": "Human immunodeficiency virus (HIV) is an infection that invades and attacks the immune system. The nurse should know that clients who have HIV or AIDS experience inadequate nutrition due to fatigue, loss of appetite, or gastrointestinal disturbances. The nurse should inform the client to eat several small meals, choose foods that are high in calories and protein, and drink at least 2 to 3 liters of fluids each day."}, {"id": 11379, "cat": "Nutrition", "stem": "A nurse is providing discharge instructions about dietary modifications for a client with GERD. Which of the following foods should the nurse tell the client to avoid?", "choices": [{"id": "a", "t": "Pears"}, {"id": "b", "t": "Oranges"}, {"id": "c", "t": "Bananas"}, {"id": "d", "t": "Avocados"}], "correct": "b", "rationale": "Easy Correct Answer: B. Oranges (GERD) refers to excessive backflow of gastric and/or duodenal contents into the esophagus, through the c I 3% lower esophageal sphincter (LES). Foods that reduce the pressure of the LES or that irritate the esophagus should be avoided. D | 3 Dietary modifications to reduce GERD include avoidance of citrus fruits, tomatoes, and other acidic vegetables and fruits, as well as avoidance of fatty foods, chocolate, peppermint, caffeinated beverages, and alcohol. These foods lower the pressure in the lower esophageal sphincter (LES). Other dietary recommendations include eating 4-6 small meals daily, remaining upright for 1-2 hours after a meal, and scheduling meals 2-3 hours before going to bed. Esophagus ‘Stomach Lower esophageal sphincter (closed) 2 (S g o 5 [a < Lower esophageal sphincter (open) Backflow of acid and stomach contents into the esophagus causes heartburn Gastroesophageal Reflux Disease (GERD)", "whyNot": {"a": "Although all foods should be avoided for 3 hours before bedtime, pears are a bland fruit and are permissible in GERD.", "c": "Bananas are permitted. They do not increase symptoms of GERD.", "d": "Avocados are not an acidic fruit and are permissible in GERD."}, "keyConcept": "Dietary modifications in clients with GERD include avoidance of acidic foods, fatty foods, peppermint, caffeinated beverages, and alcohol, = which lower the pressure in the lower esophageal sphincter, increasing the risk of reflux of stomach/duodenal contents into the esophagus."}, {"id": 11380, "cat": "Nutrition", "stem": "of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Administer 10% dextrose in water IV until the next bag is available."}, {"id": "b", "t": "Slow the infusion rate of the current bag until the solution is available."}, {"id": "c", "t": "Monitor the client for hyperglycemia."}, {"id": "d", "t": "Monitor the client for fluid overload."}], "correct": "a", "rationale": "Administering 10% dextrose in water IV until the TPN solution is available helps to prevent hypoglycemia.", "whyNot": {"b": "The nurse should not decrease the rate of the TPN infusion, because a decreased rate can cause hypoglycemia.", "c": "The nurse should monitor the client for hypoglycemia when the TPN solution is not infusing because the client is not receiving adequate", "d": "The client is not at risk for fluid overload unless the nurse has increased the rate of the TPN infusion."}, "keyConcept": "A client who has been receiving TPN can experience several adverse effects, including hypoglycemia if the infusion is suddenly discontinued. Clients who have diabetes are at increased risk. The nurse should monitor the client's blood glucose levels every 6 hr and infuse 10% dextrose when discontinuing the TPN infusion suddenly."}, {"id": 11381, "cat": "Nutrition", "stem": "A nurse is providing care for a client who has dysphagia and requires liquids with honey-like thickness. Which of the following foods can the client consume without adding a thickening agent?", "choices": [{"id": "a", "t": "Ice cream"}, {"id": "b", "t": "Yogurt"}, {"id": "c", "t": "Buttermilk"}, {"id": "d", "t": "Cream of chicken soup"}], "correct": "b", "rationale": "The nurse should identify yogurt as a honey-like liquid, because it can be eaten with a spoon but not sipped with a straw. The consistency of the prescribed diet usually follows the recommendations of a speech pathologist who has performed a swallowing evaluation. Changes can be made if the client's ability to swallow improves or lessens. National Dysphagia Diet Liquid Consistency Description Foods Allowed Plain gelati ffee, tea, broth, soda, i Unthickened beverages and supplements ain gelatin, colee, tea, broth, soda, ice Thin cream, milk, water, frozen yogurt, \" of any kind eam, mil, water, Trozen yogurt, watermelon Nectar-lik Liquids thicker than water that can be Juices, chocolate milk, buttermilk, cream lectar-like sipped through a straw soups, thin milkshakes Liquids that cannot be sipped through a Honey-like straw and have to be eaten with a spoon Honey, yogurt, tomato sauce but do not hold their shape Pudding- ist liquids that must b Spoon-thick u Ing Consistency liquids atmus e Custard, hot cereal, puddings eaten with a spoon and hold their shape", "whyNot": {"a": "Ice cream has a thinner consistency than honey. It liquefies quickly in the mouth. Consumption of ice cream can place this client at risk for", "c": "The nurse should identify buttermilk as a nectar-like liquid that can place the client at risk for aspiration.", "d": "The nurse should identify cream of chicken soup as a nectar-like liquid that can place the client at risk for aspiration. The level of the liquid"}, "keyConcept": "The National Dysphagia Diet was developed on a national level by a group of health care professionals. The diet consists of four liquid consistencies and three levels of solid textures. Thin liquids are substances the liquify quickly in the mouth. Liquids that have been thickened to honey consistency flow off a spoon in a ribbon, just like actual honey. Other liquids may have been thickened to a consistency that coats. and drips off a spoon, similar to unset gelatin; or thickened to a consistency like pudding, that remains on the spoon in a soft mass."}, {"id": 11382, "cat": "Nutrition", "stem": "A nurse is providing dietary teaching to the guardian of a school-age child who has celiac disease. Which of the following food items should the nurse suggest for the child's afternoon snack?", "choices": [{"id": "a", "t": "Raisins"}, {"id": "b", "t": "Unsalted nuts"}, {"id": "c", "t": "Potato chips"}, {"id": "d", "t": "Ham sandwich"}], "correct": "c", "rationale": "The nurse should suggest potato chips to the guardian as an acceptable food choice for the child's afternoon snack. Potato chips are gluten- free and low in fiber. Therefore, they are an acceptable food choice for a child who has celiac disease.", "whyNot": {"a": "Clients who have celiac disease are placed on a gluten-free diet indefinitely. In addition to gluten, the child must avoid foods high in fiber", "b": "Clients who have celiac disease are placed on a gluten-free diet indefinitely. In addition to gluten, the child must avoid foods high in fiber", "d": "Clients who have celiac disease are placed on a gluten-free diet indefinitely. Therefore, because the bread on most sandwiches contain"}, "keyConcept": "Potato chips are gluten-free and low in fiber. Therefore, they are an acceptable food choice for a child who has celiac disease. Foods that are high in fiber must be avoided for children who have celiac disease because decreased absorption leads to bowel inflammation."}, {"id": 11383, "cat": "Nutrition", "stem": "his morning fasting blood glucose results. Which of the following responses should the nurse make? O A.\"HbA1c measures how well insulin is regulating your blood glucose between meals.\" O B. \"HbA1c indicates how well you have regulated your blood glucose over the past 90 days.” O C.\"HbA1c identifies other health problems associated with diabetes you might have.\" O D. \"HbA1c determines if your doctor should adjust your insulin dosage at this time.\"", "choices": [{"id": "a", "t": "Capillary glucose monitoring evaluates how well insulin is regulating blood glucose between meals."}, {"id": "b", "t": "al 5% Easy HbA1c measures blood glucose control over the past 90 days and helps the provider to assess the client's long-term glycemic control."}, {"id": "c", "t": "An HbA1c test, along with a fasting plasma glucose level, is used to screen for diabetes. Thereafter, the HbAlc measures blood glucose"}, {"id": "d", "t": "Capillary glucose monitoring identifies the client's current blood glucose level and helps to determine if an additional dose of insulin is"}], "correct": "b", "rationale": "al 5% Easy HbA1c measures blood glucose control over the past 90 days and helps the provider to assess the client's long-term glycemic control. es TCS 91%", "whyNot": {"a": "Capillary glucose monitoring evaluates how well insulin is regulating blood glucose between meals.", "c": "An HbA1c test, along with a fasting plasma glucose level, is used to screen for diabetes. Thereafter, the HbAlc measures blood glucose", "d": "Capillary glucose monitoring identifies the client's current blood glucose level and helps to determine if an additional dose of insulin is"}, "keyConcept": "The HbAIc is a test that is used to screen a client for diabetes, along with a fasting plasma glucose level. The expected reference range for an HbA\\Ic value is 4 to 6%. A level of 5.7 to 6.4% indicates an increased risk for diabetes, and levels above 8% indicate poor glycemic control. The 2 = ® 4 z = a iat g < HbA\\c test is unique in that it is an average blood glucose reading over the last 90 days, which is the life span of a red blood cell. The reading is not affected by eating habits that occurred the day before the test, as a capillary blood glucose reading is. An HBA1c test assesses the client’s long-term glycemic control and determines the need for an adjustment of the client's medication regimen and can indicate that a client is not adhering to the prescribed therapy."}, {"id": 11384, "cat": "Nutrition", "stem": "A nurse is assessing a newly admitted client who reports numbness in the distal extremities and ataxia for the past 3 weeks. Which nutritional deficiency could be the cause of the client's symptoms? O A.Vitamin D O B. Potassium O c.vitamin B12 O D. Magnesium", "choices": [{"id": "a", "t": "Vitamin D deficiency is associated with bone pain, muscle weakness, and rickets."}, {"id": "b", "t": "Irritability, decreased respirations, muscle weakness, and gastrointestinal distress are associated with hypokalemia."}, {"id": "c", "t": "All Numbness and tingling of the hands and feet are neurologic manifestations associated with vitamin B12 deficiency."}, {"id": "d", "t": "Twitching of muscles and muscle weakness are manifestations of magnesium deficiency."}], "correct": "c", "rationale": "All Numbness and tingling of the hands and feet are neurologic manifestations associated with vitamin B12 deficiency. B i oc", "whyNot": {"a": "Vitamin D deficiency is associated with bone pain, muscle weakness, and rickets.", "b": "Irritability, decreased respirations, muscle weakness, and gastrointestinal distress are associated with hypokalemia.", "d": "Twitching of muscles and muscle weakness are manifestations of magnesium deficiency."}, "keyConcept": "Vitamin B12 is also referred to as cobalamin. Absorption of this vitamin requires intrinsic factor, which is produced by the parietal cells of the gastric mucosa. Lack of intrinsic factor with subsequent B12 deficiency is associated with pernicious anemia. Pernicious anemia results from autoimmune destruction of the parietal cells. Other causes of B12 deficiency include atrophic gastritis and gastric bypass surgery. Vitamin B12 deficiency may occur in strict vegans or vegetarians who do not take supplemental vitamin B12. Manifestations include macrocytic anemia; glossitis, characterized by pain, swelling, tenderness, and loss of papillae of the tongue; neurologic, cognitive, or psychiatric changes, particularly symmetrical paresthesias or numbness; and gait problems, depression, cognitive change, confusion, and ataxia."}, {"id": 11385, "cat": "Nutrition", "stem": "A nurse is assessing a client who is receiving total parenteral nutrition (TPN) and finds the infusion pump is not infusing. The nurse should monitor the client for which of the following manifestations?", "choices": [{"id": "a", "t": "Excessive thirst and urination"}, {"id": "b", "t": "Shakiness and diaphoresis"}, {"id": "c", "t": "Headache and lethargy"}, {"id": "d", "t": "Hypertension and crackles"}], "correct": "b", "rationale": "When a sudden interruption in the infusion of TPN occurs, the client is at risk for hypoglycemia. Manifestations of hypoglycemia can include shakiness, diaphoresis, confusion, and loss of consciousness. If the nurse suspects the client is experiencing hypoglycemia, they should: «Test the client's blood glucose. + Administer IV bolus of 50% dextrose or glucagon per protocol. To minimize the risk for hypoglycemia when discontinuing TPN, the nurse should: + Taper the rate down to within 10% of infusion rate for 1 to 2 hr prior to stopping the TPN infusion.", "whyNot": {"a": "Excessive thirst and urination are manifestations of hyperglycemia, which can be a complication of TPN related to the high proportion of", "c": "Headache and lethargy can be manifestations of hyperglycemia, which can be a complication of TPN related to the high proportion of", "d": "Hypertension and crackles are manifestations of fluid overload, which can be a complication of TPN related to the fluid infusion rate."}, "keyConcept": "A nurse who is caring for a client who is receiving TPN should be able to identify the manifestations of potential complications of the therapy. The nurse should also be able to implement interventions to treat any complications that occur."}, {"id": 11386, "cat": "Nutrition", "stem": "A nurse is teaching a group of nurses about medication compatibility with total parenteral nutrition (TPN). Which of the following statements should the nurse make? O A.\"Use the Y-port on the TPN IV tubing to administer antibiotics.\" O B. \"Regular insulin can be 'piggybacked' to the TPN solution.” O C. \"Administer heparin through a port on the TPN tubing.” O D. \"Administer vitamin K IV bolus via a Y-port on the TPN tubing.\"", "choices": [{"id": "a", "t": "Administering any IV medication through a Y-port on the TPN line is contraindicated because of the risk for incompatibilities between the D Hi"}, {"id": "b", "t": "Regular insulin can be \"piggybacked\" to the TPN solution to improve glucose tolerance and to treat hyperglycemia."}, {"id": "c", "t": "Heparin can be added to the TPN solution to decrease clot formation in the cannula, but it is not injected directly into a port on the TPN"}, {"id": "d", "t": "Vitamin K can be added to the TPN solution, but it should not be administered IV bolus through the TPN IV line."}], "correct": "b", "rationale": "Regular insulin can be \"piggybacked\" to the TPN solution to improve glucose tolerance and to treat hyperglycemia.", "whyNot": {"a": "Administering any IV medication through a Y-port on the TPN line is contraindicated because of the risk for incompatibilities between the D Hi", "c": "Heparin can be added to the TPN solution to decrease clot formation in the cannula, but it is not injected directly into a port on the TPN", "d": "Vitamin K can be added to the TPN solution, but it should not be administered IV bolus through the TPN IV line."}, "keyConcept": "Clients who are receiving parenteral nutrition might sometimes have medications added either by the pharmacist or infused through a separate port. The general rule is that medications should not be added to parenteral nutrition solutions, because of the potential for incompatibilities."}, {"id": 11387, "cat": "Nutrition", "stem": "A nurse is caring for a client with acute renal failure who is undergoing hemodialysis. What should the nurse consider when educating the client on healthy food choices?", "choices": [{"id": "a", "t": "Increase dairy products to maintain phosphorus balance."}, {"id": "b", "t": "Decrease total fat intake to 45% of daily calories."}, {"id": "c", "t": "Decrease potassium intake to 40 mg/kg per day."}, {"id": "d", "t": "Limit sodium intake to 4.5 g/day."}], "correct": "c", "rationale": "A A client who is receiving hemodialysis should limit potassium intake to 2 to 4 g/day or 40 mg/kg per day. Clients on hemodialysis should limit B a intake of potassium, phosphorus, fluids, and sodium. o: > =", "whyNot": {"a": "intake of milk, yogurt, and cheese should be limited to /-cup milk or ¥2-cup yogurt or 1-ounce cheese per day. Most dairy foods are very", "b": "Total fat intake should be limited to 35% of daily calories.", "d": "Sodium intake should be limited to 2 to 4 g/day to prevent weight gain and maintain fluid homeostasis."}, "keyConcept": "One of the nutritional goals of a client who is receiving dialysis is to match dietary intake needs with renal replacement therapy while decreasing deficiencies of nutrients. Clients who are receiving dialysis are at an increased risk for complications related to malnutrition and metabolic issues."}, {"id": 11388, "cat": "Nutrition", "stem": "A nurse is providing teaching to a group of middle aged adult clients about preventing obesity. Which of the following statements should the nurse make? O A.\"To prevent weight gain, you should exercise for 15 minutes 3 to 4 days each week.\" O B. \"Keep a food diary of specific factors that trigger your desire to eat.\" O C. \"Using distractions to reduce the pleasure associated with eating prevents weight gain.\" O D. \"Consuming the majority of your daily calories in the evening increases metabolism.\"", "choices": [{"id": "a", "t": "The nurse should inform the clients that current physical activity guidelines recommend 30 min of to vigorous exercise 5 to 7"}, {"id": "b", "t": "‘i The nurse should recommend that the clients keep a record of cues or factors that trigger the desire to eat."}, {"id": "c", "t": "The nurse should recommend that the clients demonstrate awareness during meals to be more conscious of the eating experience."}, {"id": "d", "t": "The nurse should recommend that the clients spread meals throughout the day and reduce calorie intake in the evening when activity is"}], "correct": "b", "rationale": "‘i The nurse should recommend that the clients keep a record of cues or factors that trigger the desire to eat. By assisting the clients to identify es a specific triggers that lead to eating, the nurse can promote behavior modification that leads to greater client control over these triggers. cH", "whyNot": {"a": "The nurse should inform the clients that current physical activity guidelines recommend 30 min of moderate to vigorous exercise 5 to 7", "c": "The nurse should recommend that the clients demonstrate awareness during meals to be more conscious of the eating experience.", "d": "The nurse should recommend that the clients spread meals throughout the day and reduce calorie intake in the evening when activity is"}, "keyConcept": "Teaching about obesity can be tricky with overweight clients. It is best to assess the readiness for information and then individualize the information taking into account the lifestyle and food preferences of the client. Food diaries can provide individuals with concrete information about food intake and the time of day or events surrounding when food desires are at their peak."}, {"id": 11389, "cat": "Nutrition", "stem": "A nurse is providing instructions to a client about breastfeeding her infant. Which of the following will be included in the instruction?", "choices": [{"id": "a", "t": "Position the client according to protocol"}, {"id": "b", "t": "Place the thumb finger below the areola and the other four fingers above the areola"}, {"id": "c", "t": "Place the index finger above the areola and the other three fingers below the areola"}, {"id": "d", "t": "Put one finger to the nipple to ensure that the infant will suck"}], "correct": "c", "rationale": "Breastfeeding is an important task for a new mother in order to provide adequate nutrition to the infant, and facilitate maternal-infant attachment. The technique for this breastfeeding should be explained or demonstrated in order to promote effective breastfeeding and prevent breast trauma. This type of hold involves placing the index finger above the areola and the other three fingers below the areola. The infant needs to take the entire nipple into the mouth allowing the jaws to compress the milk ducts beneath the areola.", "whyNot": {"a": "The breastfeeding client is instructed to position herself according to her comfort because not all protocols will be effective; clients have", "b": "The hand using the C-hold supports the breast. This type of hold involves placing the index finger above the areola and the other three", "d": "The mother’s hand should be away from the nipple so that the infant can latch on the breast."}, "keyConcept": "Breast milk provides nutrition with an ideal mix of vitamins, protein, and fat. It is more easily digested than infant formula and contains antibodies that offer protection against viruses and bacteria. It is associated with a reduced risk of asthma or allergies. Exclusive breastfeeding for 6 months or longer is associated with fewer ear infections, respiratory illnesses, diarrheal illnesses, hospitalizations and doctor visits."}, {"id": 11390, "cat": "Nutrition", "stem": "A nurse is providing education about dietary recommendations for a client with irritable bowel syndrome. Which of the following menu choices reflects client understanding?", "choices": [{"id": "a", "t": "Bananas, cabbage, and milk"}, {"id": "b", "t": "Fish, pita bread, and beef broth"}, {"id": "c", "t": "Pork chops, honey, and tea"}, {"id": "d", "t": "Beans"}], "correct": "b", "rationale": "All Dietary management is an important part of the management of irritable bowel syndrome, a functional bowel disorder that is characterized es a by alterations in colonic motility. Patients with irritable bowel syndrome experience abdominal pain with chronic constipation, diarrhea, or mixed constipation and diarrhea. Dietary measures include restriction of caffeine; alcohol; and avoidance of gas-producing foods, including € | cruciferous vegetables (cauliflower, broccoli, cabbage, onions) and bananas. Foods that are spicy or fatty should be avoided since they can D I irritate the gastrointestinal tract. Dairy products and hot and cold foods and beverages are also gastrointestinal irritants that should be avoided.fermentable oligosaccharides, Disaccharides, monosaccharides, and polyols, known as FODMAPs, include honey, wheat, and high- fructose corn syrup. They should also be avoided. Increased fiber intake is encouraged, including consumptions of nuts, fruits, vegetables, grains, legumes, and fruits. Protein, bread, and bland foods are usually well-tolerated by individuals with IBS.", "whyNot": {"a": "Dairy products should be avoided, as they can irritate the GI tract. Bananas and cabbages tend to increase production of gas and should", "c": "Honey is a FODMAP and should be avoided by clients with IBS.", "d": "Beans increase gas production and should be avoided. Cheese is a dairy product that is a gastrointestinal irritant and should be avoided."}, "keyConcept": "Irritable bowel syndrome is a chronic disorder that affects up to 20% of the US population. It is characterized by intermittent abdominal pain with alterations in bowel function. Clients will experience constipation, diarrhea, or mixed constipation and diarrhea. Other symptoms include flatulence, bloating, an urge to defecate; with urgency, and a sensation of incomplete evacuation. Dietary measures are an important part of management. Clients should avoid gas-producing foods, dairy products, caffeine, alcohol, and foods in the FODMAP group. Treatments include anticholinergic medications, stress management, and relaxation techniques, and acupuncture."}, {"id": 11391, "cat": "Nutrition", "stem": "status in this client in the short term?", "choices": [{"id": "a", "t": "Weight gain of 1.5 pounds ( b) (0.68 kilograms in 7 days."}, {"id": "b", "t": "Serum glucose of 110 milligrams per deciliter (mg/dL)"}, {"id": "c", "t": "Hemoglobin of 14 milligrams per deciliter (mg/dL)"}, {"id": "d", "t": "Serum albumin of 3.5 grams per deciliter (g/dL)"}], "correct": "a", "rationale": "Weight gain indicates caloric intake is greater than energy expenditure in calories, so it is the best indicator that a client with malnutrition is responding to therapy. Inadequate dietary intake of major nutrients and micronutrients leads to malnutrition. The major nutrients proteins, carbohydrates, and fat. Micronutrients include vitamins and essential minerals. Clinical signs are related to severity of malnutrition. Muscle weakness occurs as a result of inadequate protein intake.", "whyNot": {"b": "Glycogen can maintain or elevate serum glucose in the absence of adequate intake.", "c": "Hemoglobin may be increased as a result of dehydration and concentration of red blood cells. Although vitamin B12 and iron deficiency", "d": "This serum albumin is within the normal range (3.5=5.0 g/dL), but it is not a good indicator of nutritional status in chronic or acute illness."}, "keyConcept": "Malnutrition places clients at risk of complications, including infections. Weight gain is a good indicator of adequate food and fluid intake in the short term, since indicators of nutrition such albumin may take longer to reflect changes in nutritional status."}, {"id": 11392, "cat": "Nutrition", "stem": "A client who was hospitalized with bipolar mania has a nursing diagnosis of “imbalanced nutrition: less than body requirements.” Which of the following dietary choices is most appropriate for this client?", "choices": [{"id": "a", "t": "Lean beef stir-fry with rice, apple, and iced tea"}, {"id": "b", "t": "Ham sandwich, celery and carrot sticks, and fruit punch"}, {"id": "c", "t": "Roast chicken and dressing, broccoli, mashed potatoes with gravy, and milk"}, {"id": "d", "t": "Cheeseburger, french fries, banana, and milkshake"}], "correct": "d", "rationale": "Correct Answer: D. Cheeseburger, french fries, banana, and milkshake A I oa A client who is admitted during a manic episode may be dehydrated and undernourished when admitted. The excess energy, sleeplessness, c i and psychomotor agitation associated with mania increase the metabolic demand for additional caloric intake, but those who have mania are usually too restless to sit through consumption of an adequate meal, and impaired judgment may result in poor choices. When Ob || hospitalized, these clients should be encouraged frequently to eat. The nurse should monitor the client’s intake. Appropriate dietary choices include high-calorie food with high nutritional density that is easy to eat without requiring the client to sit still to consume the meal. This option provides the best options for a high-calorie meal that can be eaten by a client who is too agitated or restless to remain seated.", "whyNot": {"a": "This is not a high-calorie diet.", "b": "This choice does not offer high-calorie choices.", "c": "Although this meal includes some high-calorie items, it would require the client to remain seated. It is unlikely the client would consume"}, "keyConcept": "A client who is agitated or manic may be dehydrated or malnourished, with a caloric deficit resulting from increased metabolic demand. Meal planning should include high-calorie food with high nutritional density that allows the client to eat without remaining seated."}, {"id": 11393, "cat": "Nutrition", "stem": "The nurse is preparing to teach a client with peptic ulcer disease about a diet that should be followed after discharge. The nurse should encourage the client to eat which of the following? O A.Bland foods O B. High-protein foods O C. Any foods that are tolerated O D. A glass of milk with each meal", "choices": [{"id": "a", "t": "There is no need for the client to eat bland foods"}, {"id": "b", "t": "There is no need for the client to eat high-protein foods"}, {"id": "c", "t": "Diet therapy for ulcer disease is controversial."}, {"id": "d", "t": "Milk may be included in the diet, but limiting the intake of milk is recommended."}], "correct": "c", "rationale": "Diet therapy for ulcer disease is controversial. There is no scientific evidence that diet therapy promotes healing. Most clients are instructed B Hi 17% to follow a diet they can tolerate.", "whyNot": {"a": "There is no need for the client to eat bland foods", "b": "There is no need for the client to eat all high-protein foods", "d": "Milk may be included in the diet, but limiting the intake of milk is recommended."}, "keyConcept": "A peptic ulcer is a defect in the gastric or duodenal wall that extends through the muscularis mucosa into the deeper layers. The most common cause is infection with Helicobacter pylori. NSAIDs (nonsteroidal anti-inflammatory drugs) are another cause, as they erode the gastric mucosa.Management includes testing for H. pylori infection and eradicating the bacteria. NSAIDs are discontinued and antisecretory medications may be prescribe to promote healing. Although dietary factors are not proven to cause PUD, clients should avoid foods that result in symptoms. 2 = ® 4 z = a iat g <"}, {"id": 11394, "cat": "Nutrition", "stem": "A nurse is providing a meal tray to a client who has just returned from hemodialysis treatment. Which best describes the dietary choices most likely to be included in the client's meal?", "choices": [{"id": "a", "t": "High-calorie, high-protein foods"}, {"id": "b", "t": "Low-calorie, high-sodium foods"}, {"id": "c", "t": "High-calorie saturated fats"}, {"id": "d", "t": "Low-calorie, low-protein foods"}], "correct": "a", "rationale": "o; A client who receives hemodialysis has many toxicities and nutrients removed from his body; she needs an increase in calories and protein in B | her diet. |", "whyNot": {"b": "A client with kidney disease who receives hemodialysis may need to increase caloric consumption, but does not need more sodium.", "c": "A client who receives hemodialysis would need higher caloric intake in her diet. Saturated fats and trans fats are associated with", "d": "A client who receives hemodialysis would be more likely to need additional calories as a result of poor appetite, not fewer calories. High"}, "keyConcept": "Clients who are on hemodialysis are unable to eliminate waste or maintain fluid and electrolyte balance between dialysis sessions. Renal dietitians recommend reduced consumption of fluids, sodium, potassium, and phosphorus. Caloric consumption is often low, due to poor appetite. High quality high calorie foods, including vegetable oils and proteins, can supply daily metabolic needs. High quality proteins include fish, eggs, meats, and poultry."}, {"id": 11395, "cat": "Nutrition", "stem": "A nurse is about to administer an enteral feeding through a client's NG tube. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Aspirate the client's stomach contents."}, {"id": "b", "t": "Hang the feeding bag 30 cm (12 in) above the client."}, {"id": "c", "t": "Flush the tube with 30 mL of water."}, {"id": "d", "t": "Warm the formula to room temperature."}], "correct": "a", "rationale": "The first action the nurse should take when using the nursing process is to assess the residual stomach contents. The nurse should measure the stomach contents to determine whether the client's gastrointestinal system is absorbing the formula at an acceptable rate. The nurse might delay the tube feeding if there is a high volume of residual to reduce the risk for aspiration.", "whyNot": {"b": "The nurse should hang the feeding bag 30 cm (12 in) above the client to allow for an average rate of infusion and reduce the risk for", "c": "The nurse should flush the tube with 30 mL of water to make sure that it is clear and patent before starting the formula instillation;", "d": "The nurse should warm the formula to room temperature to reduce the risk for abdominal cramping; however, there is another action the"}, "keyConcept": "Gastric residual is the amount of fluid, secretions, and formula that remains in the client's stomach since the last intermittent enteral feeding or that remains every 4 to 6 hr for clients who are receiving continuous feeding. . If it is difficult to aspirate the fluid, the nurse should try repositioning the client from side to side."}, {"id": 11396, "cat": "Nutrition", "stem": "provide for the infant? O A. Electrolyte solution O B. Formula O C. Orange juice O D. Water", "choices": [{"id": "a", "t": "Electrolyte solution"}, {"id": "b", "t": "Formula"}, {"id": "c", "t": "Orange juice"}, {"id": "d", "t": "Water"}], "correct": "a", "rationale": "o; The nurse should identify that infants should receive clear liquids that contain glucose and electrolytes, such as an oral electrolyte or B 1] rehydration solution, following gastrointestinal surgery. | ©", "whyNot": {"b": "Infant formula is a full-liquid, not a clear liquid.", "c": "Orange juice is a full-liquid, not a clear liquid.", "d": "Water does not contain the nutrients that the infant requires postoperatively. Therefore, it is not appropriate to provide for the infant."}, "keyConcept": "The nurse should identify that infants should receive clear liquids that contain glucose and electrolytes, such as an oral electrolyte or rehydration solution, following gastrointestinal surgery. Water, although a clear liquid, does not contain the adequate electrolytes and nutrients that an infant would require postoperatively. As infants demonstrate tolerance, the nurse should begin to give the infants their usual formula or breast milk after verifying with the physician."}, {"id": 11397, "cat": "Nutrition", "stem": "A nurse is caring for a client who follows a vegan diet. Which of the following foods should the nurse offer the client?", "choices": [{"id": "a", "t": "Bagel with cream cheese"}, {"id": "b", "t": "Boiled egg"}, {"id": "c", "t": "Fruit with yogurt"}, {"id": "d", "t": "Wheat toast with peanut butter"}], "correct": "d", "rationale": "A client who follows a vegan diet does not eat animal products. Peanut butter and wheat bread are plant-based foods and are an appropriate choice for a client who follows a vegan diet.", "whyNot": {"a": "A client who follows a vegan diet does not eat animal products, such as cream cheese.", "b": "A client who follows a vegan diet does not eat animal products, such as a boiled egg.", "c": "A client who follows a vegan diet does not eat animal products, such as yogurt."}, "keyConcept": "A nurse should clarify dietary restrictions with a client who identifies as vegan or vegetarian. A brief summary of vegetarian-style eating patterns is as follows: Category of Vegetarian Eating Pattern Plant-based with the occasional intake of fish, meat, poultry, or Semi-vegetarian . dairy products. Lacto-ovo Includes dairy and eggs, but no meats. Lacto includes dairy, but no meats or eggs. Vegan No meat, dairy, fish, or eggs permitted."}, {"id": 11398, "cat": "Nutrition", "stem": "of the following is the correct nursing action?", "choices": [{"id": "a", "t": "Recommend a feeding tube"}, {"id": "b", "t": "Educate the family about the risk of aspiration if the client is forced to eat"}, {"id": "c", "t": "Allow the family members to identify their fears and concerns"}, {"id": "d", "t": "Explain the physiological changes and responses associated with dying"}], "correct": "c", "rationale": "3 14% Active dying is often difficult for family members, who experience a variety of frustrations and concerns during the process. When a person ec YY 4T% who is actively dying refuses food, family members may feel that they are giving up, causing the family to confront the fact that the family D Yt 38% member is dying. Sometimes, family members feel that eating will give the dying person strength to “keep fighting” in the face of terminal illness and active dying. The priority nursing response in this situation is to allow the family members to explore and identify their concerns by listening carefully. Caregivers often feel the need to continue their efforts on behalf of the loved one. The nurse can help them identify ways to continue to express their care and provide information about the effects of food and water and the natural physiological changes that occur during terminal illness and active dying. a © o 2 ° s a = a <", "whyNot": {"a": "Although some individuals may have a feeding tube in place when they are admitted to hospice services, it is not a common practice to", "b": "This is not the correct nursing action. Although it is true that aspiration may occur, the primary nursing intervention necessary is to", "d": "Although the nurse should provide teaching on the physiological changes and response to food and water in an individual with a terminal"}, "keyConcept": "The goal of end of life care is relief of symptoms. Most EOL clients have little appetite and can’t maintain adequate oral intake to support caloric needs, but nutritional needs decrease as death nears and the body begins to shut down. Nurses can help families make difficult decisions on such issues as whether to use a feeding tube by listening to their concerns and by explaining the physiological changes associated with natural death."}, {"id": 11399, "cat": "Nutrition", "stem": "A nurse is teaching a client who is pregnant about a new prescription for iron supplements. With which of the following beverages should the nurse instruct the client to take the iron supplement?", "choices": [{"id": "a", "t": "Coffee © >B. Whole milk"}, {"id": "c", "t": "Green tea"}, {"id": "d", "t": "Orange juice"}], "correct": "d", "rationale": "A 0% Easy Orange juice contains vitamin C, which aids in the absorption of iron through the gastrointestinal tract. B | or", "whyNot": {"a": "Caffeine, which is found in tea and coffee, can interfere with iron absorption. Clients who are pregnant should consume no more than 200 e@", "c": "Caffeine, which is found in green and black tea, can interfere with iron absorption. Therefore, clients should avoid taking iron supplements"}, "keyConcept": "It is recommended when taking iron supplements that the client ingest a diet that is high in vitamin C. The absorption of iron is increased when taken in conjunction with drinks that contain vitamin C, such as orange juice. The client should also be instructed to take iron supplements on an empty stomach and to avoid taking the supplements with tea, coffee, and milk because these drinks and the presence of food can interfere with the absorption of iron. Clients who are taking iron supplements should be instructed that their stool might change color to dark green or black. Constipation is also an adverse effect of iron supplements."}, {"id": 11400, "cat": "Nutrition", "stem": "A client with hypertension is on a low-sodium diet and complains to the nurse that the food “has no taste.” How should the nurse respond?", "choices": [{"id": "a", "t": "“ prefer salty foods too.”"}, {"id": "b", "t": "“You will probably be ok if you sneak in an occasional pinch of salt.”"}, {"id": "c", "t": "“Dietary changes can be to make. What difficulties have you experienced?”"}, {"id": "d", "t": "“Additional salt in your diet will only make controlling your blood pressure more difficult.”"}], "correct": "c", "rationale": "A nurse should be aware that compliance with a new diet may be difficult for many individuals, even though their health condition necessitates a change in diet. The nurse should be empathetic and allow the client to voice frustration about health-related changes in lifestyle. This will allow the nurse to offer support and may improve compliance. It also offers the client the opportunity to identify frustration.", "whyNot": {"a": "This conversation is about the client, not the nurse. This response by the nurse would not allow the client to express real frustrations", "b": "This wrongly suggests that the client does not have to adhere to his therapeutic regimen.", "d": "This response is a poor response because it does not take into account the client’s level of knowledge and fails to address the client’s"}, "keyConcept": "Lifestyle modifications may be prescribed to prevent or reduce the impact of disease. These modifications disrupt the client's normal routine and sometimes cause frustration. The nurse should recognize the difficulty of making lifestyle changes and should offer support and provide opportunities for clients to voice frustration."}, {"id": 11401, "cat": "Nutrition", "stem": "A nurse is providing discharge education for a client with a newly placed gastrostomy tube. When should the client flush the tube to prevent clogging?", "choices": [{"id": "a", "t": "At least every 24 hours"}, {"id": "b", "t": "Three times a day"}, {"id": "c", "t": "Before and after administering medications"}, {"id": "d", "t": "Before going to bed at night"}], "correct": "c", "rationale": "al 3% Easy The nurse should instruct the client to flush the tube after administering medications. Flushing the tube after medication administration B I a prevents the medication from obstructing clogging the tube and ensures the correct medication dose is received by the client.", "whyNot": {"a": "The client should flush the tube more frequently than every 24 hours; waiting 24 hours may increase the risk of occlusion.", "b": "The client should flush the tube both before and after administration of feedings and medication. °", "d": "It is not necessary to routinely flush the tube before going to bed at night unless the client has just taken a medication or receive a ="}, "keyConcept": "A client with a gastrostomy tube should flush the tube with 30 cc of water before and after the administration of medication. To prevent a clogged feeding tube, the tube should be flushed your tube with water after feeding or medication. If the tube becomes obstructed, the client should aspirate with the 30 cc syringe or flush the tube with warm tap water."}, {"id": 11402, "cat": "Nutrition", "stem": "A nurse is caring for a client who has iron-deficiency anemia. The nurse should recommend which of the following foods as containing the greatest amount of dietary iron per serving?", "choices": [{"id": "a", "t": "Boiled eggs"}, {"id": "b", "t": "Greek yogurt"}, {"id": "c", "t": "1% low-fat milk"}, {"id": "d", "t": "Black beans"}], "correct": "d", "rationale": "The nurse should determine that black beans are the best food source to recommend to a client who has iron-deficiency anemia because they contain 3.61 mg of iron per 1 cup serving.", "whyNot": {"a": "The nurse should recommend a different food because there is another choice that contains more iron. One large boiled egg contains 0.59", "b": "The nurse should recommend a different food because there is another choice that contains more iron. Greek yogurt contains 0.12 mg of", "c": "The nurse should recommend a different food because there is another choice that contains more iron. One percent low-fat milk contains"}, "keyConcept": "Clients who have iron-deficiency anemia should increase consumption of dietary iron, which is found in both plant- and animal-based foods. Animal sources of dietary iron contain heme iron, which is more easily absorbed than nonheme iron. Plant sources such vegetable, legumes, dried fruits, and whole-grain cereals contain nonheme iron. The nurse should also instruct the client to consume foods that contain vitamin C when consuming iron-rich foods because it increases the absorption of iron. Another method of increasing iron in the diet is to cook foods in cast-iron skillets."}, {"id": 11403, "cat": "Nutrition", "stem": "A nurse is providing nutritional teaching to a client who is at 8 weeks of gestation. Which food should the nurse recommend as a good source of calcium?", "choices": [{"id": "a", "t": "Dark green, leafy vegetables"}, {"id": "b", "t": "Deep red or orange vegetables"}, {"id": "c", "t": "Red fruits"}, {"id": "d", "t": "Meat, poultry, and fish"}], "correct": "a", "rationale": "During pregnancy, the client should consume 1,000 to 1,300 mg of calcium each day to promote fetal skeletal and teeth formation. The nurse B ] 11% should recommend that the client consume dark green, leafy vegetables, such as kale, artichokes, and turnip greens. | ° © 2%", "whyNot": {"b": "Deep red or orange vegetables are good sources of vitamins A and C but do not contain high levels of calcium.", "c": "Red fruits, such as apples, strawberries, and tomatoes, are high in vitamins A and C but do not contain high levels of calcium.", "d": "Meat, poultry, and fish are sources of protein but do not contain high levels of calcium."}, "keyConcept": "Calcium is an essential mineral in the body that aids in fetal skeletal and teeth formation. It also is essential for maintaining maternal bone strength and tooth mineralization. Good sources of calcium include dairy or milk products and dark green, leafy vegetables, such as kale and turnip greens. It can also be fortified in products such as orange juice. It is recommended that a client consume 1,000 to 1,300 mg of calcium each day during pregnancy."}, {"id": 11404, "cat": "Nutrition", "stem": "nurse suggest? O A. Begin clear liquids for 24 hours O B. Feed the child bananas, rice, applesauce, and toast O C. Offer foods that are low in fat O D. Continue the child’s regular diet", "choices": [{"id": "a", "t": "Begin clear liquids for 24 hours"}, {"id": "b", "t": "Feed the child bananas, rice, applesauce, and toast"}, {"id": "c", "t": "Offer foods that are low in fat"}, {"id": "d", "t": "Continue the child’s regular diet"}], "correct": "d", "rationale": "A The current recommendations for children experiencing mild to moderate diarrhea are to continue the child’s regular diet. With this diet B = plan, children seem to get well faster. I ©", "whyNot": {"a": "Although the child needs liquid to avoid dehydration, this would not provide enough nutrients.", "b": "The BRAT (banana, rice, applesauce, and toast) diet has long been recommended, but no evidence shows it is useful and it has a poor", "c": "The child should continue his regular diet as long as the diarrhea is mild and the diet is tolerable."}, "keyConcept": "Lost fluids should be replaced if a child has diarrhea. It is usually adequate for the child to continue drinking fluids they normally drink. Too much water alone can be harmful. Pedialyte may help keep the child well-hydrated during an episode of diarrhea. Popsicles and Jell-O can be good sources of fluids, especially if the child is vomiting. Watered-down fruit juice or broth can provide fluid during active diarrhea. The child can advance to a normal diet as tolerated."}, {"id": 11405, "cat": "Nutrition", "stem": "The nurse sees a 37-year-old man with a Body Mass Index (BMI) of 27. Which of the following statements made by the nurse is most appropriate?", "choices": [{"id": "a", "t": "“Your BMI shows that you are obese. You need to eat healthier.”"}, {"id": "b", "t": "“Your BMI is in the normal range, keep doing what you are doing.”"}, {"id": "c", "t": "“Your BMI is in the overweight range. Let’s talk about what we can do to get you as healthy as possible.”"}, {"id": "d", "t": "“Your BMI is in the obese range. How much do you exercise?”"}, {"id": "e", "t": "“Your BMI is in the overweight range. There are things you can do to lose weight.”"}], "correct": "c", "rationale": "Overweight BMI= 25-29.9. This statement takes a collaborative approach with the client.", "whyNot": {"a": "Obesity is defined as a BMI of 30 or greater", "b": "A BMI of 18.5-24.9 is considered normal", "d": "Obesity is defined as a BMI of 30 or greater", "e": "The client is overweight but this statement is not helpful to the client."}, "keyConcept": "Obesity is a risk factor for diabetes, cardiovascular disease, and some cancers. Nurses can intervene with overweight clients by discussing weight and offering advice on nutrition and weight management. Weight loss interventions can be effective even when small changes are made, but the success of the intervention is dependent in part on the client's motivation and readiness to make changes."}, {"id": 11406, "cat": "Nutrition", "stem": "A nurse is caring for a client who will receive long-term total parenteral nutrition (TPN). Which condition is associated with long-term therapy?", "choices": [{"id": "a", "t": "Fatty liver"}, {"id": "b", "t": "Respiratory infection"}, {"id": "c", "t": "Hypotension"}, {"id": "d", "t": "Urinary retention"}], "correct": "a", "rationale": "Fatty liver is associated with long-term administration of TPN, due to excess buildup of fat tissue in the liver, leading to inflammation or liver B ] Aer damage. The exact reason that long-term TPN can cause fatty liver is unknown. chi 6%", "whyNot": {"b": "Respiratory infection is not a common complication associated with long-term administration of TPN.", "c": "A client who receives long-term TPN administration is not at high risk of developing hypotension.", "d": "Urinary retention is not a complication associated with long-term administration of TPN."}, "keyConcept": "Complications of long term total parenteral nutrition include thrombosis of the central access vein; frequent infections in the central-vein access lines; cholecystitis; osteoporosis; fatty liver and liver failure. Fatty liver is associated with elevation of plasma aminotransferases (ALT, AST) and liver enlargement. TPN-induced liver damage occurs more often in children than adults."}, {"id": 11407, "cat": "Nutrition", "stem": "should identify that these findings are manifestations of which condition?", "choices": [{"id": "a", "t": "Anemia"}, {"id": "b", "t": "Metabolic syndrome"}, {"id": "c", "t": "Heart failure"}, {"id": "d", "t": "Hypotension"}], "correct": "b", "rationale": "Weight gain in the abdomen, elevated blood glucose, and elevated triglycerides are manifestations associated with metabolic syndrome. Metabolic syndrome is diagnosed when a client has three or more of the following measurements: + Abdominal obesity, or a waist circumference of greater than 101.6 cm (40 in) in male clients, and greater than 88.9 cm (35 in) in female clients + Triglyceride level of 150 mg/dL or greater + HDL cholesterol of less than 40 mg/dL in male clients or less than 50 mg/dL in female clients + Systolic blood pressure of 130 mm Hg or greater or a diastolic blood pressure of 85 mm Hg or greater + Fasting blood glucose level of 100 mg/dL or greater Incorrect: A. Fatigue, lethargy, pallor of nail beds, and intolerance to cold are manifestations associated with anemia. C. Shortness of breath, fluid retention, and fatigue are manifestations associated with heart failure. D. Hypertension is one of the diagnostic criteria for metabolic syndrome.", "whyNot": null, "keyConcept": "Metabolic syndrome is a risk factor for heart disease and type 2 diabetes mellitus. Lifestyle changes, such as increased physical activity and weight loss, decrease the risk for heart attack and stroke. A Mediterranean-style diet might help with some of the risk factors, including abdominal obesity and blood glucose levels."}, {"id": 11408, "cat": "Nutrition", "stem": "A nurse is administering a lipid emulsion parenteral nutrition solution to a client and notes a layer of fat floating in the IV solution bag. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Shake the bag to mix the fat."}, {"id": "b", "t": "Turn the bag upside down one time."}, {"id": "c", "t": "Return the bag to the pharmacy."}, {"id": "d", "t": "Administer the bag of solution at a slower rate."}], "correct": "c", "rationale": "A Hi 18% Moderate The nurse should return the solution to the pharmacy. A layer of fat floating in the IV solution bag indicates that \"cracking\" of the solution B ] ue has occurred, and it should not be administered. °", "whyNot": {"a": "Shaking the bag is not an appropriate action. A layer of fat floating in the IV solution bag indicates that \"cracking\" of the solution has", "b": "Turning the solution upside down does not resolve the problem. A layer of fat floating in the IV solution bag indicates that \"cracking\" of", "d": "The nurse should not administer the solution. A layer of fat floating in the IV solution bag indicates that \"cracking\" of the solution has"}, "keyConcept": "\"Cracking\" occurs when there is a layer of fat or globule substances on top of a parenteral nutrition solution. It can be caused by a high calcium or phosphorus content or if salt-poor albumin has been added."}, {"id": 11409, "cat": "Nutrition", "stem": "A nurse is caring for a client who is postoperative and has a prescription for a clear liquid diet. Which of the following items should the nurse offer the client?", "choices": [{"id": "a", "t": "Grape juice"}, {"id": "b", "t": "Lemon sherbet"}, {"id": "c", "t": "Chocolate milk"}, {"id": "d", "t": "Vanilla ice cream"}], "correct": "a", "rationale": "Aclear liquid diet includes foods that are clear fluids, though not necessarily colorless, that are at body and room temperatures. This includes apple, cranberry, and grape juices, broth, black coffee, and plain gelatin.", "whyNot": {"b": "Lemon sherbet is an acceptable choice for a full liquid diet, but not a clear liquid diet.", "c": "Milk and milk-based drinks are acceptable choices for a full liquid diet, but not a clear liquid diet.", "d": "Vanilla ice cream is an acceptable choice for a full liquid diet, but not a clear liquid diet."}, "keyConcept": null}, {"id": 11410, "cat": "Nutrition", "stem": "A nurse is reviewing the DASH diet for hypertension with a client during discharge teaching. Which of the following statements by the client indicates an understanding of the teaching? O A.\"My daily sodium consumption should be 3,000 milligrams.\" O B.\"I should consume foods that are low in potassium.\" O C. \"I need to lose at least 25 pounds to see a decrease in my blood pressure.\" O D.\"I should consume low-fat dairy products.\"", "choices": [{"id": "a", "t": "The client's daily sodium consumption should be 1500 mg or less. This assists with lowering systolic and diastolic blood pressures, as well"}, {"id": "b", "t": "The nurse should encourage the client to consume high-potassium foods. This assists with lowering systolic and diastolic blood pressures,"}, {"id": "c", "t": "Blood pressure will typically decrease when a client has a weight loss of 4.5 to 6.8 kg (10 to 15 lb)."}, {"id": "d", "t": "The DASH (Dietary Approaches to Stop Hypertension) eating plan includes is a low sodium diet rich in fruits and vegetables, and low-fat or non-fat dairy, with whole grains."}], "correct": "d", "rationale": "The DASH (Dietary Approaches to Stop Hypertension) eating plan includes is a low sodium diet rich in fruits and vegetables, and low-fat or non-fat dairy, with whole grains. It is a high fiber, low to moderate fat diet, rich in potassium, calcium, and magnesium. Lifestyle modifications are the initial step in reduction of blood pressure in individuals with prehypertension or hypertension. Individuals with severe hypertension may not be able to eliminate medication, but the DASH diet can improve the response to medication and lower blood pressure. The DASH diet is associated with lower cholesterol, reduced insulin resistance, and reduced risk of developing diabetes when combined with exercise and weight loss. Blood Pressure Classification for Adults Category Systolic Diastolic Normal < 120 and <80 Prehypertensive 120 to 139 or 80 to 89 | Stage 1 hypertension 140 to 159 or 90 to 99 | Stage 2 hypertension > 160 or >110", "whyNot": {"a": "The client's daily sodium consumption should be 1500 mg or less. This assists with lowering systolic and diastolic blood pressures, as well", "b": "The nurse should encourage the client to consume high-potassium foods. This assists with lowering systolic and diastolic blood pressures,", "c": "Blood pressure will typically decrease when a client has a weight loss of 4.5 to 6.8 kg (10 to 15 lb)."}, "keyConcept": "The DASH diet was initially devised to lower blood pressure, but it has other beneficial effects on cardiovascular health, weight loss, and diabetes. Lifestyle modifications are an essential part of the treatment of hypertension. Weight loss is the most effective method, as well as increasing exercise, smoking cessation, and increasing intake of potassium, calcium, and magnesium."}, {"id": 11411, "cat": "Nutrition", "stem": "A nurse is caring for a client who has experienced a left-sided CVA. The nurse knows to intervene when the unlicensed nursing person assigned to help with feeding does which of the following?", "choices": [{"id": "a", "t": "Assists the client to sit upright at 90 degrees"}, {"id": "b", "t": "Tilts the client’s neck downward slightly during feeding"}, {"id": "c", "t": "Thins pureed food with some milk to ease swallowing"}, {"id": "d", "t": "Places food on the stronger side of the client's mouth"}], "correct": "c", "rationale": "A Clients can have difficulty swallowing (dysphagia) after a cerebral vascular accident (CVA), placing them at risk of aspiration pneumonia. a s Measures used to modify diet and rehabilitate swallowing to reduce the risk of aspiration include: o: Thickening liquids D | Positioning the client upright during feeding at a 90-degree angle Modifying food consistency to meet the client’s needs (options include soft or pureed diet) Tilting the client’s chin downward to elevate the larynx and promote closure of the epiglottis Placing food on the side of the mouth that is stronger in order to allow the client to form a bolus for swallowing", "whyNot": {"a": "The nurse does not have to intervene, as placing the client in an upright position is an appropriate action to reduce the risk of aspiration.", "b": "Tilting the client’s chin downward promotes closure of the epiglottis while raising the larynx, which reduces the risk of aspiration.", "d": "Food should be placed on the stronger side of the mouth if there is any facial weakness. This will help the client form a bolus and reduces"}, "keyConcept": "When delegating feeding, the nurse should be certain the UAP is aware that a client with neurological impairment from stroke may be at risk of aspiration. Aspiration precautions include upright positioning during feeding, modification of food consistency, and placement of food on the unaffected side of the mouth when assisting with feeding."}, {"id": 11412, "cat": "Nutrition", "stem": "A nurse is caring for a client who was admitted for treatment of bulimia nervosa. Which of the following is appropriate for the nursing care plan?", "choices": [{"id": "a", "t": "Perform frequent room checks."}, {"id": "b", "t": "Supervise the client during mealtime and for an hour afterward."}, {"id": "c", "t": "Provide a set menu and avoid asking the client to make choices."}, {"id": "d", "t": "Provide laxatives if the client complains of constipation."}], "correct": "b", "rationale": "Bulimia nervosa is an eating disorder that is characterized by binge eating followed by self-induced vomiting, allowing the client to avoid weight gain by getting rid of extra calories. Individuals with bulimia may also abuse diuretics and laxatives to maintain or lose weight. The disorder is, like anorexia nervosa, the result of a disturbance of body image and a fear of obesity. The nurse should supervise the client's meals for at least an hour afterward. If the client is unsupervised, the client may induce vomiting. The nurse should help the client establish a pattern of appropriate nutritional intake. An appropriate minimum weight gain should be determined, and regular weighing can be used to determine the client’s progress towards the goal. Other nursing tasks include assisting the client with the establishment of a realistic self-image, assessing suicide risk, and improving self-esteem. Clients with bulimia may have comorbid psychiatric symptoms, and some report a history of sexual abuse, which is a negative prognostic indicator. Poor nutrition alters mood and cognition, so improvements in psychological functioning can occur as the client improves nutritional status.", "whyNot": {"a": "Frequent room checks may exacerbate the client’s sense of powerlessness and should be avoided.", "c": "Providing healthy choices to allow the client to select from a menu will help with self-esteem and self-confidence and will give the client", "d": "Many individuals with eating disorders may use laxatives and diuretics to maintain or lose weight, so a laxative is not a good choice for"}, "keyConcept": "Clients with the eating disorders anorexia nervosa and bulemia nervosa experience disturbances in body image and a pathological fear of obesity. This continues during treatment until the client establishes a realistic self-image, so the nurse should supervise the client's nutritional intake while helping the client to establish an appropriate goal for minimum weight gain. Psychological functioning may improve as nutritional status is normalized."}, {"id": 11413, "cat": "Nutrition", "stem": "A nurse is instructing a client about preparations for a colonoscopy. She explains that a clear liquid diet includes which of the following?", "choices": [{"id": "a", "t": "Gelatin, tea, milk"}, {"id": "b", "t": "Tea, cola, milk"}, {"id": "c", "t": "Apple juice, tea, water"}, {"id": "d", "t": "Ice cream, gelatin, tea"}], "correct": "c", "rationale": "Aclear liquid diet includes foods and liquids that have thin consistency and are mostly transparent. Apple juice, tea, and water are included in a clear liquid diet, as are gelatin and broth.", "whyNot": {"a": "Gelatin and tea are included in a clear liquid diet, but milk is not a clear liquid.", "b": "Tea and cola may be included as part of a clear liquid diet, but milk is not a clear liquid.", "d": "While gelatin and tea may be included in a clear liquid diet, ice cream is not a clear liquid."}, "keyConcept": null}, {"id": 11414, "cat": "Nutrition", "stem": "A nurse is providing teaching to a client who has a new prescription for phenelzine. Which food should the nurse instruct the client to omit from the diet to avoid a hypertensive crisis?", "choices": [{"id": "a", "t": "Grapefruit juice"}, {"id": "b", "t": "Dark green vegetables"}, {"id": "c", "t": "Cottage cheese"}, {"id": "d", "t": "Smoked fish"}], "correct": "d", "rationale": "Smoked fish is high in tyramine, which has hypertensive effects similar to other amines. Because tyramine is metabolized by monoamine oxidase, clients who are taking MAOIs, such as phenelzine, and consume tyramine can experience a hypertensive crisis.", "whyNot": {"a": "Grapefruit juice interferes with the metabolism of many medications, but it will not cause a hypertensive crisis in a client who is taking", "b": "Dark green vegetables can decrease the anticoagulant effects of warfarin, but they will not cause a hypertensive crisis in a client who is", "c": "Cottage cheese is a high-protein source; 1 cup, or 226 g, contains 27 g of protein. High-protein foods, such as cottage cheese, can increase"}, "keyConcept": "Clients who are taking an MAO! should avoid the consumption of foods containing tyramine. Examples include any aged cheeses, bananas, beer, ale, red wine, caffeinated beverages, chocolate, peanuts, and yogurt. Clients should be provided a comprehensive list of all foods and beverages that contain tyramine."}, {"id": 11415, "cat": "Nutrition", "stem": "amount of dietary protein?\" O A. Medium baked potato O B. Homemade vegetable soup O C. Black eyed peas and rice O D. Canned fruit salad", "choices": [{"id": "a", "t": "Medium baked potato"}, {"id": "b", "t": "Homemade vegetable soup"}, {"id": "c", "t": "Black eyed peas and rice"}, {"id": "d", "t": "Canned fruit salad"}], "correct": "c", "rationale": "The nurse should determine that black eyed peas and rice are the best food source to recommend because this food combination contains 9 g of protein per 1 cup serving. This food combination provides the client with a complete protein that contains all nine of the essential amino acids.", "whyNot": {"a": "The nurse should recommend a different food because there is another choice that contains more protein. A medium baked potato", "b": "The nurse should recommend a different food because there is another choice that contains more protein. Homemade vegetable soup", "d": "The nurse should recommend a different food because there is another choice that contains more protein. Canned fruit salad contains"}, "keyConcept": "Vegetarian diets focus on consumption of plant-based foods. To maximize protein intake, a client who follows a vegetarian diet should be instructed to consume complete proteins. Complete proteins are those that contain all nine of the essential amino acids in quantities required to support proper health. While some foods alone do not provide a complete protein, combining them with another can produce a complete protein. For example, a combination of grains and legumes can provide a complete protein."}, {"id": 11416, "cat": "Nutrition", "stem": "A nurse is providing preconception teaching to a client who has phenylketonuria (PKU). Which of the following statements by the client indicates an understanding of the teaching? O A.\"I should avoid getting pregnant because of this disorder.\" O B. \"I will need my PKU levels checked once a year when I'm pregnant.\" O C.\"I should avoid foods high in protein for at least 3 months prior to pregnancy.\" O D. \"| will need to deliver my baby by cesarean section because of this disorder.\"", "choices": [{"id": "a", "t": "8%"}, {"id": "b", "t": "A client who has PKU will need to have her phenylalanine levels monitored one to two times per week throughout pregnancy."}, {"id": "c", "t": "A | | 8% Moderate A client who has PKU should decrease her dietary intake of protein for at least 3 months prior to conception."}, {"id": "d", "t": "A client who has PKU is not at increased risk for fetal macrosomia and will not require a cesarean birth."}], "correct": "c", "rationale": "A | | 8% Moderate A client who has PKU should decrease her dietary intake of protein for at least 3 months prior to conception. The client should be instructed B | nove to avoid meat and beans and to eat more fruits and vegetables. This will decrease the likelihood that the fetus will be exposed to high levels of PKU and will help to prevent neurocognitive impairments. ec | 68% om 14%", "whyNot": {"a": "There is no restriction on pregnancy for a client who has PKU. However, a client who has PKU will need counseling prior to conception and", "b": "A client who has PKU will need to have her phenylalanine levels monitored one to two times per week throughout pregnancy.", "d": "A client who has PKU is not at increased risk for fetal macrosomia and will not require a cesarean birth."}, "keyConcept": "Phenylalanine is an amino acid that is converted into tyrosine once ingested. With phenylketonuria (PKU), the body is unable to form this conversion; thus, phenylalanine accumulates in the bloodstream and can attack the brain cells. PKU is an inherited disorder that can cause cognitive and neurological impairments. Treatment includes placing the client on a low-phenylalanine diet, which includes eating fruits and vegetables and avoiding high-protein foods like meat and beans. A client who has PKU and desires pregnancy should consult with her provider. The client should be instructed to consume a low-phenylalanine diet for 3 months prior to conception and during pregnancy to prevent exposing the fetus to high phenylalanine levels, which can cause cognitive and neurological impairments."}, {"id": 11417, "cat": "Nutrition", "stem": "A nurse is teaching a client who has heart failure about increasing dietary potassium. The nurse should instruct the client that which of the following food selections contains the highest amount of potassium?", "choices": [{"id": "a", "t": "1 medium apple"}, {"id": "b", "t": "1 medium baked potato"}, {"id": "c", "t": "1 cup of raw green grapes"}, {"id": "d", "t": "1 large scrambled egg"}], "correct": "b", "rationale": "A i 10% Moderate Amedium baked potato is the best food source of potassium because it contains 941 mg potassium per serving. OB TY Tay fo", "whyNot": {"a": "One medium apple contains 195 mg potassium. The nurse should recommend a different food because another choice contains more", "c": "One cup of raw green grapes contains 288 mg potassium per serving. The nurse should recommend a different food because another", "d": "One large egg scrambled contains 81 mg potassium per serving. The nurse should recommend a different food because another choice"}, "keyConcept": "Clients who have heart failure and take loop or thiazide diuretics can develop hypokalemia due to potassium excretion. The nurse should instruct the client to increase dietary potassium. Foods high in potassium can include dried fruits, bananas, lentils, sweet potatoes, baked potatoes, squash, and yogurt. The nurse should instruct the client to monitor for manifestations of hypokalemia, such as muscle weakness, orthostatic hypotension, and irregular heartrate, and to have potassium levels checked periodically."}, {"id": 11418, "cat": "Nutrition", "stem": "A nurse is teaching a Laotian client who has hypertension about selecting low-sodium food choices. Which of the following actions by the nurse demonstrates cultural competency?", "choices": [{"id": "a", "t": "Asks the client what she likes to eat"}, {"id": "b", "t": "Instructs the client to use a salt-substitute"}, {"id": "c", "t": "Incorporates Buddhist concepts of diet into the teaching"}, {"id": "d", "t": "Recommends selecting cured meats instead of fresh"}], "correct": "a", "rationale": "@ (soy sauce or fish sauce) can B I a result in high sodium intake. However, race or ethnicity is not synonymous with cultural practices. The nurse should ask the client about her dietary practices, including the consumption of traditional foods that can be high in sodium. Asking the client what she likes to eat c |_| 23% demonstrates cultural competency by showing respect for the client's food preferences.", "whyNot": {"b": "Although the use of salt substitutes, such as herbs or potassium chloride, can be used in the place of regular table salt, this does not", "c": "Although religion can play a significant role in dietary practices, the assumption that a client practices Buddhism because she is Laotian is", "d": "The nurse should instruct a client who has hypertension to limit sodium intake. Cured and processed meats are high in sodium and should"}, "keyConcept": "The nurse should practice cultural awareness by being aware of personal cultural beliefs as well as one's own perceptions and assumptions about the client's culture. For example, a client's culture can have an effect on choices of food. Within a subculture, there might exist preferences for the role of food, how it is prepared, and the symbolism the food might have. Therefore, the nurse should ask the client about cultural practices and preferences in order to better support the client."}, {"id": 11419, "cat": "Nutrition", "stem": "consider the priority for this client?", "choices": [{"id": "a", "t": "Identify the client's nutritional status."}, {"id": "b", "t": "Request a mental health consult."}, {"id": "c", "t": "Assist the client in developing a healthy body image."}, {"id": "d", "t": "Provide a structured environment for the client."}], "correct": "a", "rationale": "Anorexia nervosa is characterized by a client having a BMI of less than 17. According to the nursing process, the nurse should perform an B assessment first to gather enough data to plan, implement, and evaluate care. The nurse should also assess the client's laboratory results, |_| such as electrolyte and glucose levels, along with the client's statement of their eating pattern and fluid intake. Physical assessment findings € | for a client who has anorexia nervosa include pale conjunctiva and mucous membranes, bradycardia, lanugo, amenorrhea, poor muscle D I tone and skin turgor, hypothermia, hypotension, cardiac dysrhythmias, and edema. The assessment identifies client nutrition needs as well as complications the client might be experiencing related to the eating disorder.", "whyNot": {"b": "The nurse should request a mental health consult to provide a comprehensive and multifaceted approach to maladaptive eating", "c": "Clients who have anorexia nervosa have a distorted perception of being overweight, regardless of their current weight status. Initially, the", "d": "It is important to provide a structured environment for the client regarding meals, such as setting times for weighing, and monitoring of"}, "keyConcept": "Anorexia nervosa is a chronic mental illness that has periods of exacerbation and remission and causes clients to experience an intense fear of gaining weight. To manage the anxiety associated with weight and diet, clients might engage in activities such as starvation, purging, using laxatives or enemas, or exercising for prolonged periods of time. The initial focus is on evaluation and treatment of a client's nutritional status with a treatment goal of obtaining 90% of the client's ideal weight based upon the client's height."}, {"id": 11420, "cat": "Nutrition", "stem": "feeding bag? ©) a.7:00 AM on Friday O B. 7:00 PM on Wednesday O C. 7:00 AM on Thursday O D. 7:00 PM on Thursday", "choices": [{"id": "a", "t": "This is too late since the bag must be replaced every 24 hours."}, {"id": "b", "t": "This is too early. The bag should not be replaced until Thursday at 7:00 AM."}, {"id": "c", "t": "An enteral nutritional system is a method of delivering complete nutrition of calories, protein, fats, vitamins, and minerals directly into the stomach or intestines."}, {"id": "d", "t": "The bag should be replaced Thursday morning. This is too late."}], "correct": "c", "rationale": "An enteral nutritional system is a method of delivering complete nutrition of calories, protein, fats, vitamins, and minerals directly into the stomach or intestines. It is indicated for clients who are critically ill or postoperative for whom enteral nutrition cannot be used, including clients who require bowel rest. A nurse caring for a client with continuous enteral feeding is responsible for maintaining the system and keeping bacterial count as low as possible. The feeding bag must be replaced every 24 hours. Hence, a nurse should change the feeding bag at the same hour on the next day.", "whyNot": {"a": "This is too late since the bag must be replaced every 24 hours.", "b": "This is too early. The bag should not be replaced until Thursday at 7:00 AM.", "d": "The bag should be replaced Thursday morning. This is too late."}, "keyConcept": "The nutrients contained in enteral feeds and administration at room temperature promote rapid growth of microorganisms. The feeding bag should be replaced at minimum every 24 hours and strict hand hygiene should be carried out before assembling the feed. The feed should be stored in a clean refrigerated space and prepared in a clean work area, to avoid introduction of environmental pathogens."}], "paediatrics": [{"id": 11421, "cat": "paediatrics", "stem": "@ @ “Clade %* “%& Extracto) x % ClaudeC xX & Login- Po x ™ [GitHub] x ™ Inbox-b xX @ TEASPra x OnlineN. x @ Microsofi x @ NCLEXE xX | NCLEXA xX ) bobyond) x + v € > GCG _— &% student.atitesting.com/LT| Q *& x * © OD Cb ) oO Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Surgical procedures to correct noise-induced hearing loss are very expensive"}, {"id": "b", "t": "Hearing loss caused by exposure to loud noise is preventable"}, {"id": "c", "t": "Noise-induced hearing loss can result from a one-time exposure to a very loud noise"}, {"id": "d", "t": "Noise-induced hearing loss can have negative effects on speech"}], "correct": "a", "rationale": "Noise-induced hearing loss cannot be surgically corrected. All of the other statements are true. B i at", "whyNot": {"b": "Hearing loss caused by exposure to loud noise is preventable and should be taught to this group of clients. D i 9%", "c": "Noise-induced hearing loss can result from a one-time exposure to a very loud noise; this information is important for this group to", "d": "Noise-induced hearing loss can have negative effects on speech."}, "keyConcept": "Noise-induced hearing loss (NIHL) can be immediate or may develop over time. It can be temporary or permanent, and it can affect one ear or both ears. Children, teens, young adults, and older individuals can develop NIHL due to exposure of harmful levels of noise at any age. At least 10 million adults (6 percent) in the U.S. under age 70 have features demonstrated on hearing tests that suggest hearing loss in one or both ears from exposure to loud noise. As many as 24% of adults in the US may be affected. NIHL can be caused by a one-time exposure to intense “impulse” sounds or by continuous exposure to loud sounds over an extended period of time."}, {"id": 11422, "cat": "paediatrics", "stem": "A nurse in an outpatient clinic is advising the parents of a 7-year-old child about healthy sleep habits in their child. Which of the following should the nurse recommend?", "choices": [{"id": "a", "t": "The child should sleep for 7-8 hours each night."}, {"id": "b", "t": "The parents should encourage the child to engage in physically tiring play before bedtime."}, {"id": "c", "t": "It is important to establish a regular bedtime."}, {"id": "d", "t": "The sleep needs of the child are the result of the high growth rate experienced in this age group."}], "correct": "c", "rationale": "This child is in the school-age population, which is defined as age 6-12 years. At this period of growth, the child’s needs for rest and sleep depend primarily on age, activity level, and health status. Although less sleep (9 hours) is necessary as the child approaches age 12, a child who is 6 needs approximately 11 hours of sleep. Children have not yet learned to recognize fatigue, so a routine bedtime should be established to ensure adequate sleep. At this age, children may enjoy rituals before bedtime that include reading or listening to music, but conflict over bedtime is rare.", "whyNot": {"a": "This is the correct amount of sleep for adults, but children require more sleep to prevent fatigue.", "b": "Excessive stimulation or activity should be avoided before bedtime, and parents should suggest quiet alternative activities to promote", "d": "Compared to preschool children or toddlers, school-age children have a slower rate of growth. The need for sleep depends on the child’s"}, "keyConcept": "Between ages 6 and 12 years, a child's need for sleep and rest depends on age, activity level, and health status. At age 6, children need approximately 11 hours of sleep, decreasing to 9 hours as they approach 12 years of age. Routine bedtimes should be recommended to encourage adequate sleep."}, {"id": 11423, "cat": "paediatrics", "stem": "A nurse is caring for a 9-year-old hospitalized client on bedrest who has attention deficit activity disorder, inattentive type. Which of the following should the nurse prioritize when caring for this child?", "choices": [{"id": "a", "t": "Limit visitors"}, {"id": "b", "t": "Explain verbally what the child should expect each day"}, {"id": "c", "t": "Provide the child with a daily schedule that is typed or written"}, {"id": "d", "t": "Suggest the child work on missed school assignments"}], "correct": "c", "rationale": "Astructured, calm environment should be provided to help a child with attention deficit hyperactivity disorder (ADHD) make the adjustment to bed rest or hospitalization. A written schedule of daily activities can help the child organize thoughts and expectations around anticipated activities associated with illness. Children with ADHD, inattentive type, cannot easily keep their attention on activities or tasks. They have difficulty giving attention to detail and organizing their activities. They dislike or avoid tasks requiring sustained concentration over a long period of time. The nurse’s priority is to assist the child by providing an organized environment that will allow the child to adjust to the change in routine.", "whyNot": {"a": "Children with ADHD may feel socially isolated during hospitalization. They often have impaired social skills, so the presence of visitors is", "b": "Verbal instructions may be forgotten, and sometimes children with ADHD may be distracted and fail to listen.", "d": "Although it is important for the child to keep up with schoolwork, the priority nursing action is creating a calm and organized environment"}, "keyConcept": "Attention deficit hyperactivity disorder (ADHD) is a brain disorder characterized by degrees of inattention, impulsive behavior, and hyperactivity. It occurs as a result of both environmental and genetic factors and results in developmental and functional impairment. When caring for a pediatric client with ADHD, the nurse should provide a structured environment to help the child organize thoughts and activities, resulting in reduction of stress and better adjustment to changes in routine related to illness."}, {"id": 11424, "cat": "paediatrics", "stem": "A nurse is caring for a school-age child who has a severe burn. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Initiate a high-protein, low-calorie diet."}, {"id": "b", "t": "Expose affected area to the air."}, {"id": "c", "t": "Establish an airway."}, {"id": "d", "t": "Implement contact isolation."}], "correct": "c", "rationale": "The nurse should establish and maintain an airway in a child who has a major burn. Children who have been exposed to smoke inhalation might have an adequate airway immediately after the injury, but inflammation, swelling and airway damage can cause respiratory distress and failure. Therefore, the nurse should frequently monitor the child's airway.", "whyNot": {"a": "The nurse should initiate a high-protein, high-calorie diet for clients who have severe burns.", "b": "The nurse should apply a dressing to the burned area to prevent infection.", "d": "Reverse isolation precautions are recommended to prevent wound infections."}, "keyConcept": "In clients who have severe burns, pulmonary hygiene is important to maintain adequate oxygenation and promote tissue healing. To promote good pulmonary hygiene, the nurse should take the following actions: Maintain the client in a semi-Fowler's position. Administer bronchodilators as needed. Use incentive spirometry, repositioning, and postural drainage. Administer high-flow humidified oxygen."}], "physiological_adaptation": [{"id": 11425, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "Which stage of HIV infection is considered the beginning stage of AIDS?", "choices": [{"id": "a", "t": "Stage 3"}, {"id": "b", "t": "Stage 1"}, {"id": "c", "t": "Stage 2"}, {"id": "d", "t": "Stage 4"}], "correct": "a", "rationale": "Correct Answer: A. Stage 3 @A | Without treatment, infection with human immunodeficiency virus (HIV) advances in stages. The three stages of HIV are: (1) acute HIV c | | infection, (2) chronic HIV infection, and (3) acquired immunodeficiency syndrome (AIDS). During stage 3, HIV has severely damaged the D | immune system, and the body is unable to fight off opportunistic infections. The diagnosis can be made in individuals with less than 200 CD4+ T cells per cubic millimeter of blood, compared with about 1,000 CD4+T cells for healthy people; CD4 T cells < less than 14% lymphocytes; or presence of an opportunistic infection, including Cryptococcus neoformans, Cryptosporidium, CMV retinitis, Pheumocystis jiroveci pneumonia, and Kaposi sarcoma.", "whyNot": {"b": "Stage 1 is acute HIV infection. It is characterized by a high viral load and flu-like symptoms days to weeks after infection occurs.", "c": "Stage 2 is chronic HIV infection. During the chronic stage of the disease, HIV continues to multiply in the body at very low levels.", "d": "Stage 4 is not a stage of HIV infection."}, "keyConcept": "HIV infection has three stages. The acute infection is followed by a chronic stage of infection, which may last for years. If untreated, HIV infection progresses to the third stage, AIDS (Acquired Immunodeficiency Syndrome). AIDS is characterized by low CD4 T cell count and opportunistic infections."}, {"id": 11426, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "Which of the following devices is most appropriate for delivering a predicted oxygen concentration in a client with unstable chronic obstructive pulmonary disease (COPD)?", "choices": [{"id": "a", "t": "Non-rebreather mask"}, {"id": "b", "t": "Venturi mask"}, {"id": "c", "t": "Face mask"}, {"id": "d", "t": "Nasal cannula"}], "correct": "b", "rationale": "‘a AVenturi mask uses a variety of adaptor sizes, allowing delivery of a fixed Fi02 that depends on the flow rate and size of the entrainment OB a port. It can deliver oxygen concentrations ranging from 24-60% and flow rates between 4-12 L/minute. It is used to titrate the oxygen concentration in clients who have unstable COPD. Ventilation is suppressed by high oxygen concentrations in these clients, who may retain c | carbon dioxide as a result. It is important in these cases to regulate the delivered oxygen concentration carefully. Humidification is usually D || unnecessary with a Venturi mask at low concentrations. Venturi mask Adjustable nose clip Exhalation ports. —— Flexible tube \\ ae Inhaled mixture of 100% oxygen and room air Removable adapter {", "whyNot": {"a": "Non-rebreather masks have a reservoir bag with a valve that prevents the entry of exhaled air. Valves on the side ports of the mask allow", "c": "An FiO2 is difficult to estimate with a simple face mask.", "d": "The exact concentration of oxygen delivered with a nasal cannula depends on the client’s breathing rate and pattern, depth of respiration,"}, "keyConcept": null}, {"id": 11427, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is reinforcing teaching with a client who has stage 3 HIV. Which of the following statements by the client indicates understanding?", "choices": [{"id": "a", "t": "“ will wear gloves while changing the litter box.”"}, {"id": "b", "t": "“I will rinse raw fruits with water before eating them.”"}, {"id": "c", "t": "“I will wear a mask around family members who are ill.”"}, {"id": "d", "t": "“I will cook vegetables before eating them.”"}], "correct": "d", "rationale": "A client who has AIDS should cook vegetables before eating to kill bacteria that cause opportunistic infections. It's important to avoid anything that can increase the risk of opportunistic infections, including cuts or tears in the skin, and foodborne or waterborne sources of opportunistic pathogens. Clients with HIV should be advised on maintenance of adequate weight and nutrition. Nursing care of a client with AIDS includes advocacy, health monitoring, management of symptoms, education about the effects of antiretroviral medications and the need for adherence to treatment, and health promotion teaching to reduce the incidence of HIV related conditions and to avoid transmission of HIV to others.", "whyNot": {"a": "A client who has AIDS should avoid changing a litter box to prevent acquiring toxoplasmosis.", "b": "A client who has AIDS should avoid consuming raw fruits due to the presence of bacteria that can cause opportunistic infections.", "c": "Due to compromised immune response, a client who has AIDS should avoid contact with family members who are ill."}, "keyConcept": "Clients with HIV infection have impaired immunity with decreased levels of CD4 T cells. When HIV infection progresses to AIDS (Stage 3 HIV infection), the CD4 T cell count is extremely low and the client is at high risk of acquiring opportunistic infections. Microscopic organisms transferred in food or water include Salmonella, Shigella, Cryptosporidium, and Giardia. Careful food safety practices include avoidance of raw foods."}, {"id": 11428, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "Which of the following findings should the nurse report to the healthcare provider after assessing a client with acromegaly in an outpatient setting?", "choices": [{"id": "a", "t": "Fasting blood glucose 130 mg/dL"}, {"id": "b", "t": "Hot flashes"}, {"id": "c", "t": "Headache and visual field loss"}, {"id": "d", "t": "Erectile dysfunction"}], "correct": "c", "rationale": "Correct Answer: C. Headache and visual field loss A - B Acromegaly is an endocrine disorder that results from overproduction of growth hormone, usually as the result of a benign pituitary ec fF adenoma. Clients with acromegaly may experience headaches and visual field defects from the growth of the tumor mass in the pituitary my I gland. When acromegaly occurs in an adult, it causes stimulation of growth of a variety of tissues, including skin, viscera (organs), and bone. Growth hormone excess results in lipolysis and insulin antagonism. Other hormone synthesis in the pituitary gland may be suppressed by growth of a large adenoma, causing reduction of other hormones. This can result in hot flashes, vaginal atrophy, galactorrhea, menstrual dysfunction, erectile dysfunction, decreased facial hair growth in men, and decreased testicular volume. The effects of growth hormone on the thyroid gland, liver, heart, lungs, and kidneys result in other abnormalities. Hypertension, angina, and heart failure are cardiovascular manifestations of acromegaly. Sleep apnea can occur as a result of changes in the soft tissues of the pharynx.", "whyNot": {"a": "Hyperglycemia is a common finding in individuals with acromegaly due to the effects of increased growth hormone on insulin and glucose", "b": "Hot flashes and menstrual irregularities result from reduced synthesis of reproductive hormones in many patients with acromegaly due to", "d": "Erectile dysfunction is a common finding in men with acromegaly due to suppression of male hormones by the growth of a pituitary"}, "keyConcept": "Growth hormone (GH) is an anabolic hormone produced by the anterior pituitary gland. It promotes synthesis of protein and mobilization of glucose and free fatty acid. It also stimulates the liver to produce insulin-like growth factor-1 (somatomedin C.), which stimulates growth of bones and soft tissues and, in a feedback loop, signals the anterior pituitary to reduce synthesis of GH. Benign pituitary adenomas are the most common cause of overproduction of GH. This results in insulin antagonism and increased blood glucose levels. In adults, acromegaly occurs as a result of excess GH."}, {"id": 11429, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "to minimize the risk of ventilator-associated pneumonia in this client?", "choices": [{"id": "a", "t": "Give antibiotics as prophylaxis"}, {"id": "b", "t": "Change the ventilator circuits every day"}, {"id": "c", "t": "Place the client in a semi-Fowler's position"}, {"id": "d", "t": "Turn the client from side to side every 4 hours"}], "correct": "c", "rationale": "‘i of Ventilator-associated pneumonia (VAP) is defined as pneumonia that develops at least 2 days after the initiation of mechanical ventilation in ec | a client with a tracheostomy or endotracheal tube. It is associated with increased pathogenic growth in the lower portion of the respiratory D || tract. The processes that cause development of VAP are bacterial colonization of the oral cavity and aspiration of contaminated secretions into the lower respiratory tract. A nurse caring for the client on a ventilator must minimize the risk of the VAP by placing the client in a semi- Fowler’s position and elevating the head of the bed to 30-45 degrees to minimize the risk of aspiration. This position reduces aspiration of oral secretions into the lower airways, minimizing the risk of infection from oral pathogens.", "whyNot": {"a": "Prophylactic antibiotics are rarely prescribed for clients on a mechanical ventilator, as it increases the risk of emergence of multidrug-", "b": "It is not necessary to change the ventilator circuits daily. Specific practices depend upon institutional guidelines and the healthcare", "d": "Clients who are immobile should be repositioned every 2 hours to prevent the development of pressure sores."}, "keyConcept": "Ventilator-associated pneumonia refers to a hospital-acquired lung infection in clientss who have been on a mechanical ventilator for at least 48 hours. It occurs when microorganisms are transferred to the lungs through the ventilator airway or the endotracheal tube. VAP is an adverse outcome and a national client-safety concern, causing increases in ventilator days, client morbidity and mortality, and healthcare costs."}, {"id": 11430, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "client to infection? O A. Weight gain O B. Fluid imbalances O C. Pooling of respiratory secretions O D. Small anteroposterior chest diameter", "choices": [{"id": "a", "t": "Weight gain"}, {"id": "b", "t": "Fluid imbalances"}, {"id": "c", "t": "Pooling of respiratory secretions"}, {"id": "d", "t": "Small anteroposterior chest diameter"}], "correct": "c", "rationale": ", 0 q : C. Pooling of respiratory secretions Bf 5% Emphysema is a type of chronic obstructive pulmonary disease. It is characterized by destruction of the walls of the alveoli (functional units ec FY 90% of the respiratory system), leading to decreased surface area of the lungs. Clients diagnosed with emphysema are at risk of infection related D I Bon to inadequate host defenses, including difficulty clearing lung secretions, which promote seeding by pathogenic organisms. Acute COPD i] exacerbation caused by respiratory infection results in increased respiratory rate, mucosal irritation, and increased mucus production, with Fo} bronchospasm and changes in sputum production. It results in overall increased work of breathing, leading to respiratory failure if A untreated. o a =", "whyNot": {"a": "Clients with emphysema are expected to lose weight due to decreased appetite and increased metabolism.", "b": "Fluid imbalance is not a factor in increasing the risk of infection in emphysema.", "d": "Clients with emphysema have wide anteroposterior chest diameters."}, "keyConcept": "The most common complication of COPD, and the most common cause of hospital readmissions in clients with COPD, is respiratory infection resulting in acute exacerbation. If untreated, this can lead to increased work of breathing and respiratory failure."}, {"id": 11431, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is assessing an unresponsive client who was found outside in freezing weather. Which of the following findings does the nurse expect in a client with injuries due to severe hypothermia?", "choices": [{"id": "a", "t": "Tachypnea"}, {"id": "b", "t": "Hypertension"}, {"id": "c", "t": "Increased metabolism"}, {"id": "d", "t": "Slow rate of respiration"}], "correct": "d", "rationale": "Eas) Correct Answer: D. Slow rate of respiration a | 12% y 35°C. The body temperature is controlled by the hypothalamus, which c I 5% acts reflexively in response to signals from peripheral neuroreceptors. The body loses heat through radiation, convection, conduction, and Op rd BO fo evaporation. When the body’s regulatory mechanisms are overwhelmed, the body is unable to preserve a normothermic state. The manifestations of severe hypothermia include bradycardia, hypotension, slow and shallow breathing, dyscoordination, and loss of consciousness. Initially, hypothermia may result in shivering, which increases the body’s metabolic rate and produces heat. Mild hypothermia may also result in tachycardia and hypertension, but the body’s metabolic processes slow considerably with severe hypothermia.", "whyNot": {"a": "Severe hypothermia results in a decreased heart rate, respiratory rate, and blood pressure.", "b": "Severe hypothermia results in hypotension.", "c": "All cellular metabolic processes begin to shut down with severe hypothermia."}, "keyConcept": "Initially, hypothermia may result in shivering, which increases the body’s metabolic rate and produces heat. Although hypothermia may initially result in tachycardia and hypertension, it can progress as the body’s metabolic processes slow, resulting in bradycardia, hypotension, slow and shallow breathing, dyscoordination, and loss of consciousness in clients who are affected by severe hypothermia."}, {"id": 11432, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "prioritize? O A. Prepare for potassium infusion. O B. Obtain a urine sample for urinalysis. O C. Administer regular insulin by sliding scale. O D. Begin infusion of normal saline.", "choices": [{"id": "a", "t": "Prepare for potassium infusion."}, {"id": "b", "t": "Obtain a urine sample for urinalysis."}, {"id": "c", "t": "Administer regular insulin by sliding scale."}, {"id": "d", "t": "Begin infusion of normal saline."}], "correct": "d", "rationale": "A The client’s pH and history suggest diabetic ketoacidosis (DKA). This is caused by hyperglycemia and leads to dehydration from the osmotic B - diuresis due to high urine glucose levels. The client should receive 0.9% normal saline to restore tissue perfusion and reduce synthesis and release of stress hormones. c || o;", "whyNot": {"a": "Although clients with DKA may have a total body potassium deficit, the initial serum potassium may be normal or high. A potassium", "b": "Although urinalysis is an important part of the evaluation, it is not a priority action.", "c": "Serum glucose levels will fall rapidly with rehydration, so insulin should be initiated after initial volume infusion."}, "keyConcept": "Diabetic ketoacidosis is characterized by hyperglycemia, ketosis, metabolic acidosis, and dehydration. Total body potassium stores are usually depleted as a result of osmotic diuresis from glucosuria. Clinical signs include polyuria, polyphagia, and polydipsia. Signs of dehydration include tenting of skin, dry mucous membranes, and tachycardia. Abdominal pain and vomiting lead to additional potassium loss. Kussmaul respirations refer to rapid deep breathing as the body attempts to achieve acid-base homeostasis by exhalation of carbon dioxide. Fruity breath is characteristic, caused by acetone."}, {"id": 11433, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "prioritize? O A. Prepare for potassium infusion. O B. Obtain a urine sample for urinalysis. O C. Administer regular insulin by sliding scale. O D. Begin infusion of normal saline.", "choices": [{"id": "a", "t": "Prepare for potassium infusion."}, {"id": "b", "t": "Obtain a urine sample for urinalysis."}, {"id": "c", "t": "Administer regular insulin by sliding scale."}, {"id": "d", "t": "Begin infusion of normal saline."}], "correct": "d", "rationale": "A | | 8% Moderate The client’s pH and history suggest diabetic ketoacidosis (DKA). This is caused by hyperglycemia and leads to dehydration from the osmotic B 5% diuresis due to high urine glucose levels. The client should receive 0.9% normal saline to restore tissue perfusion and reduce synthesis and I release of stress hormones. c || 32%", "whyNot": {"a": "Although clients with DKA may have a total body potassium deficit, the initial serum potassium may be normal or high. A potassium", "b": "Although urinalysis is an important part of the evaluation, it is not a priority action.", "c": "Serum glucose levels will fall rapidly with rehydration, so insulin should be initiated after initial volume infusion."}, "keyConcept": "Diabetic ketoacidosis is characterized by hyperglycemia, ketosis, metabolic acidosis, and dehydration. Total body potassium stores are usually depleted as a result of osmotic diuresis from glucosuria. Clinical signs include polyuria, polyphagia, and polydipsia. Signs of dehydration include tenting of skin, dry mucous membranes, and tachycardia. Abdominal pain and vomiting lead to additional potassium loss. Kussmaul respirations refer to rapid deep breathing as the body attempts to achieve acid-base homeostasis by exhalation of carbon dioxide. Fruity breath is characteristic, caused by acetone."}, {"id": 11434, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "nurse expect? O A. Serum sodium 150 mEq/L O B. Serum sodium 118 mEq/L O C. Serum calcium 9 mg/dL O D. Serum potassium 2.0 mEq/L O E. Serum potassium 3.6 mEq/L", "choices": [{"id": "a", "t": "Serum sodium 150 mEq/L"}, {"id": "b", "t": "Serum sodium 118 mEq/L"}, {"id": "c", "t": "Serum calcium 9 mg/dL"}, {"id": "d", "t": "Serum potassium 2.0 mEq/L"}, {"id": "e", "t": "Serum potassium 3.6 mEq/L"}], "correct": "b", "rationale": "All 13% Hard Cortisol is a glucocorticoid stress hormone that is secreted by the adrenal cortex in response to the release of ACTH by the pituitary gland. OB a ca The production of corticosteroids is controlled by a \"feedback mechanism,\" involving the adrenal glands, the pituitary gland, and the brain, known as the \"hypothalamic-pituitary-adrenal axis\" (HPAA). The use of exogenous glucocorticoids suppresses the production of ACTH by the c | ™% iii] pituitary gland, disrupting the normal feedback loop. Corticosteroids should be gradually tapered to allow the return of function. Abrupt D i 31% oO discontinuation of long-term exogenous corticosteroid used may result in adrenal crisis, which is characterized by weakness, abdominal , hypotension, syncope, shock, hyponatremia, hyperkalemia, and hypoglycemia. Treatment is cortisol replacement with glucocorticoids = and mineralocorticoids. Cortisol is usually replaced by intravenous hydrocortisone, with the replacement of electrolytes and glucose c through IV fluids. Fludrocortisone is administered to replace aldosterone, a mineralocorticoid that is produced and released by the adrenal : glands.", "whyNot": {"a": "Hypornatremia occurs in an Addisonian or adrenal crisis.", "c": "Calcium is not typically affected by an adrenal crisis.", "d": "Hyperkalemia may occur.", "e": "This is a normal serum potassium level. Hyperkalemia is expected in adrenal crisis."}, "keyConcept": "The production of corticosteroids is controlled by a \"feedback mechanism,\" involving the adrenal glands, the pituitary gland, and the brain. This feedback loop is known as the \"hypothalamic-pituitary-adrenal axis\" (HPAA). Using large doses of corticosteroids for a few days, or smaller doses for more than two weeks leads to disruption of the function of the normal regulatory mechanism. Steroid use cannot be stopped abruptly; tapering steroid medications allows the adrenal glands to return to their normal patterns of secretion over time."}, {"id": 11435, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "insufficiency? O A. Difficulty speaking between breaths O B. Retractions O C. Dependent edema O D. Clubbing of the fingers", "choices": [{"id": "a", "t": "Difficulty speaking between breaths"}, {"id": "b", "t": "Retractions"}, {"id": "c", "t": "Dependent edema"}, {"id": "d", "t": "Clubbing of the fingers"}], "correct": "d", "rationale": "all 10% Easy The nurse should expect a client who has chronic hypoxia or respiratory insufficiency to display clubbing of the fingers and toes, which is B | at caused by long-term inadequate oxygenation. The bases of the nailbeds become swollen, and the ends of the fingers and toes can increase | nc © 2% in size.", "whyNot": {"a": "This is not an expected manifestation of long-term inadequate oxygenation. A client who has difficulty speaking between breaths is", "b": "This is not an expected manifestation of long-term inadequate oxygenation. Retractions of the chest wall is a manifestation of increased", "c": "This is not an expected manifestation of long-term inadequate oxygenation. Dependent edema is a manifestation of right-sided heart"}, "keyConcept": "A client who has chronic dyspnea from COPD, cystic fibrosis, other chronic respiratory insufficiencies can develop clubbing of the fingers or toes. This condition is caused by a thickening of the skin under the nailbed from chronic hemoglobin desaturations, which causes the fingers to become rounded and bulbous. The nailbed feels spongy and becomes convex to 180° or more."}, {"id": 11436, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is completing a pain assessment of a client who has acute pancreatitis. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Pain in the right upper quadrant radiating to the right shoulder"}, {"id": "b", "t": "Report of pain being worse when sitting upright"}, {"id": "c", "t": "Pain is intermittent"}, {"id": "d", "t": "Epigastric pain radiating to the left shoulder"}], "correct": "d", "rationale": "A client who has pancreatitis will report severe, boring epigastric or left upper quadrant pain that radiates to the back, left flank, or left : — shoulder. The discomfort is related to the irritation and inflammation of the pancreas as well as obstruction of the pancreatic duct. cll", "whyNot": {"b": "A client who has acute pancreatitis will report pain as intense, boring pain that is continuous. The pain is relieved somewhat if the client", "c": "A client who has acute pancreatitis will report that pain is constant in nature. The client might be unable to pinpoint the exact location of"}, "keyConcept": "A distinguishing characteristic of acute pancreatitis is pain in the mid-epigastric or left upper quadrant regions. Pain often radiates to the back, left flank, or left shoulder and is described as a constant, boring pain. The client can assume a fetal position with the knees drawn up to the chest to relieve discomfort. This position increases the retroperitoneal space, which relieves some of the pressure on the inflamed pancreas. A supine position increases the pain, which can be especially problematic when diagnostic studies such as an abdominal ultrasound, MRI, or CT scan are prescribed. The client might require parenteral opioid analgesia prior to diagnostic studies. Nursing interventions for the client who has acute pancreatitis include assessing pain using an appropriate pain scale prior to and following the administration of an analgesic, monitoring the client's respiratory status before, during, and following the administration of opioid analgesics, and teaching the client to use nonpharmacological methods for alleviating pain, such as focused breathing, progressive relaxation, and distraction. The nurse should also report any pain that is unrelieved or if pain increases in intensity because this can be an indication of pancreatic hemorrhage."}, {"id": 11437, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is planning care for a client who has pneumonia and a prescription for oxygen therapy at 5 L/min via nasal cannula. Which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Attach a humidifier bottle to the base of the flow meter."}, {"id": "b", "t": "Prevent skin breakdown around the ears by removing the nasal cannula for 30 min twice a day."}, {"id": "c", "t": "Secure the oxygen tubing to the bed sheet near the client's head."}, {"id": "d", "t": "Apply petroleum jelly to the nares as needed to soothe mucous membranes."}], "correct": "a", "rationale": "Oxygen therapy can dry the mucous membranes. The nurse should attach a humidifier bottle for a client receiving oxygen greater than 4 L/min via nasal cannula. For adequate oxygen delivery, the humidifier bottle needs to be more than one-third full of sterile water, and the oxygen flow rate should be higher than 4 L/min.", "whyNot": {"b": "The nurse should check for skin breakdown, repositioning the straps around the client's ears and face and adjusting the prongs in the", "c": "The nurse should check that the tubing does not pull on the client's face, ears, or nose and secure the oxygen tubing to the client's", "d": "The nurse should apply water-soluble lubricant, not petroleum jelly, as needed to soothe the mucous membranes and relieve dryness."}, "keyConcept": "Best practice for administering oxygen is to check the provider prescription for type of device and flow rate. The nurse should examine the client's mouth and nose every 8 hr for mucous membrane dryness and cracks. Padding can be applied to areas around the ears to prevent skin breakdown. The nurse should cleanse the cannula or mask with warm water and the client's skin under the tubing and straps every 4 to 8 hr. No smoking is allowed around a client who is using oxygen therapy."}, {"id": 11438, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "Which of the following terms refers to the conversion of a painful stimulus into an electrical impulse which then travels through peripheral neurons (nervous fibers)?", "choices": [{"id": "a", "t": "Transmission"}, {"id": "b", "t": "Transduction"}, {"id": "c", "t": "Modulation"}, {"id": "d", "t": "Perception"}], "correct": "b", "rationale": "Transduction in the context of pain refers to the conversion of a painful external stimulus into an electrical impulse at receptors in the peripheral nervous system (nociceptors), which then travel through the peripheral nervous system to the spinal cord and brain. Transduction of Cortex ; tical Reflex modulation Ctl Spinal reflex loop Mechanical Interaction == >", "whyNot": {"a": "Transmission refers to the travel of an electrical impulse along nerve fibers, which is regulated by chemicals known as neurotransmitters.", "c": "Modulation of a painful stimulus occurs when the electrical impulse created through transduction reaches the spinal cord and causes", "d": "Perception of pain occurs when electrical impulses formed through transduction of painful stimuli at the nociceptors in the peripheral"}, "keyConcept": null}, {"id": 11439, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is assigned to care for a newly admitted client in a hyperosmotic hyperglycemic state (HHS). Which of the following laboratory findings does the nurse expect? Oa. Serum BUN 12 mg/dL O B. Positive urine ketones O C. Serum osmolarity 345 mOsm/L O D. Serum pH 7.1", "choices": [{"id": "a", "t": "hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent @c"}, {"id": "b", "t": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS."}, {"id": "c", "t": "al °- A hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent @c | hyperglycemia but adequate insulin to prevent the development of ketoacidosis."}, {"id": "d", "t": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}], "correct": "c", "rationale": "al °- A hyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent @c | hyperglycemia but adequate insulin to prevent the development of ketoacidosis. Risk factors include older age, preexisting underlying D i conditions such as stroke or sepsis, and dehydration. HHS is usually characterized by glucose >600 mg/dL and hyperosmolarity resulting in dehydration. The onset of HHS is usually gradual. Findings include polyuria, polydipsia, polyphagia, nausea, vomiting, abdominal pain, altered mental status, reversible paralysis, and coma. Coma typically occurs with serum osmolarity >350 mOsm/L. Normal serum osmolarity is 275-295 mOsm/L.", "whyNot": {"a": "This is a normal BUN. In HHS, BUN >30 mg/dL is expected as a result of dehydration. Creatinine would be expected to be >1.5 mg/dL.", "b": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS.", "d": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}, "keyConcept": "Hyperglycemic hyperosmolar nonketotic syndrome is characterized by hyperglycemia, hyperosmolarity, and dehydration. The condition occurs when individuals produce enough insulin to reduce ketosis but inadequate insulin to control hyperglycemia. Hyperglycemia results in osmotic diuresis, causing fluid and electrolyte imbalances."}, {"id": 11440, "cat": "PHYSIOLOGICAL ADAPTATION", "stem": "A nurse is assigned to care for a newly admitted client in a hyperosmotic hyperglycemic state (HHS). Which of the following laboratory findings does the nurse expect? Oa. Serum BUN 12 mg/dL O B. Positive urine ketones O C. Serum osmolarity 345 mOsm/L O D. Serum pH 7.1", "choices": [{"id": "a", "t": "This is a normal BUN. In HHS, BUN >30 mg/dL is expected as a result of dehydration. Creatinine would be expected to be >1.5 mg/dL."}, {"id": "b", "t": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS."}, {"id": "c", "t": "al °- Ahyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent ec | hyperglycemia but adequate insulin to prevent the development of ketoacidosis."}, {"id": "d", "t": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}], "correct": "c", "rationale": "al °- Ahyperosmolar hyperglycemic state occurs in individuals with diabetes mellitus who have insufficient amounts of insulin to prevent ec | hyperglycemia but adequate insulin to prevent the development of ketoacidosis. Risk factors include older age, preexisting underlying D i conditions such as stroke or sepsis, and dehydration. HHS is usually characterized by glucose >600 mg/dL and hyperosmolarity resulting in dehydration. The onset of HHS is usually gradual. Findings include polyuria, polydipsia, polyphagia, nausea, vomiting, abdominal pain, altered mental status, reversible paralysis, and coma. Coma typically occurs with serum osmolarity >350 mOsm/L. Normal serum osmolarity is 275-295 mOsm/L.", "whyNot": {"a": "This is a normal BUN. In HHS, BUN >30 mg/dL is expected as a result of dehydration. Creatinine would be expected to be >1.5 mg/dL.", "b": "Urine ketones are present in diabetic ketoacidosis but are absent in HHS.", "d": "The pH is 7.4 or greater in HHS. Acidosis is present in diabetic ketoacidosis, not in HHS."}, "keyConcept": "Hyperglycemic hyperosmolar nonketotic syndrome is characterized by hyperglycemia, hyperosmolarity, and dehydration. The condition occurs when individuals produce enough insulin to reduce ketosis but inadequate insulin to control hyperglycemia. Hyperglycemia results in osmotic diuresis, causing fluid and electrolyte imbalances."}], "physiology_integrity_pharmacological": [{"id": 11441, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "adverse effect of the medication? O A. Constipation O B. Insomnia O C. Blackening of the tongue O D. Red-orange colored body secretions", "choices": [{"id": "a", "t": "Constipation"}, {"id": "b", "t": "Insomnia"}, {"id": "c", "t": "Blackening of the tongue"}, {"id": "d", "t": "Red-orange colored body secretions"}], "correct": "d", "rationale": "A i 8% Moderate Rifampin can cause the urine, stool, saliva, sputum, sweat, and tears to turn reddish-orange to reddish-brown. If the client wears contact B | at lenses, the nurse should instruct the client to remove them because they can become permanently stained. The nurse should monitor the client for these manifestations and inform the client this can be an expected finding. The nurse should also monitor the client for © | Me manifestations of hepatitis, including yellow skin and eyes, nausea, vomiting, anorexia, weakness, or increased tiredness. These are @ . Thrombocytopenia can occur in the client who is taking rifampin. The nurse should monitor the client for any unusual bleeding or bruising and report these findings to the provider.", "whyNot": {"a": "The nurse should monitor the client who is taking rifampin for diarrhea, not constipation. Some clients can experience Clostridium", "b": "The nurse should monitor the client who is taking rifampin for drowsiness and fatigue, not insomnia.", "c": "The nurse should monitor the client who is taking a bismuth preparation or liquid iron preparations for darkening of the tongue. This not"}, "keyConcept": "The nurse who is preparing to administer rifampin to a client should have a plan of what to monitor the client for and how to address the findings with the client. The nurse should be able to discern those findings that are expected and those findings that should be reported to the provider."}, {"id": 11442, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "chest and neck. Which of the following is the priority action by the nurse?", "choices": [{"id": "a", "t": "Contact the healthcare provider"}, {"id": "b", "t": "Administer diphenhydramine (Benadryl)"}, {"id": "c", "t": "Discontinue vancomycin infusion"}, {"id": "d", "t": "Assess vital signs"}], "correct": "c", "rationale": "A| af Vancomycin is used to treat infection due to methicillin-resistant Staphylococcus and resistant Streptococcus pneumoniae. It is also used to ec fF treat serious infections like endocarditis when the client is allergic to penicillin and cephalosporins. Vancomycin is associated with two D | different hypersensitivity reactions, anaphylaxis, and red man syndrome. Red man syndrome is characterized by a pruritic erythematous rash over the face, neck, and upper chest. It occurs 4-10 minutes after beginning an infusion. Discontinuation of the infusion and administration of diphenhydramine will usually stop the reaction. Administration of diphenhydramine before the first infusion may prevent the occurrence of red man syndrome. Pretreatment with hydroxyzine can reduce redness and pruritus if the reaction occurs. The reaction can occur with the first dose of vancomycin or after several doses. Slower infusion times may reduce the risk of the reaction.", "whyNot": {"a": "The client should be stabilized first by stopping the infusion and administering diphenhydramine. Vital signs should be assessed before", "b": "The infusion should be stopped before any other intervention.", "d": "After discontinuing the infusion and administering prescribed diphenhydramine, the nurse should assess vital signs before notifying the"}, "keyConcept": "Red man syndrome refers to a reaction to vancomycin infusion, usually occurring 4-10 minutes after initiation of infusion. It is characterized by erythema, rash, and pruritus over face, neck, and upper chest. The infusion should be stopped immediately and diphenhydramine should be administered. Premedication with diphenhydramine may prevent a reaction."}, {"id": 11443, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse at a long-term care facility is preparing to administer a medication to a client. Which of the following client identifiers should the nurse use to identify the client?", "choices": [{"id": "a", "t": "The client's date of birth"}, {"id": "b", "t": "The client's room number"}, {"id": "c", "t": "The printed name on the medication administration record (MAR)"}, {"id": "d", "t": "Phone number of the client's room"}], "correct": "a", "rationale": "o; The nurse should use two identifiers before administering medications. Acceptable client identifiers include: B | +Name c i >| + Date of birth + Medical record number + Personal telephone number + Photo identification", "whyNot": {"b": "This is not an acceptable identifier because clients can have a room change, and ambulatory clients can visit other rooms.", "c": "This is not an acceptable identifier because the nurse could have inadvertently accessed another client's MAR.", "d": "This is not an acceptable identifier because this is not a client-specific identifier."}, "keyConcept": "Nurses are responsible for following the \"rights\" of medication administration. To ensure the medication is administered to the right client, the nurse should correctly identify the client using two different identifiers."}, {"id": 11444, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is caring for a client who asks the nurse about the herbal supplement valerian. Which of the following information should the nurse provide the client?", "choices": [{"id": "a", "t": "\"Valerian can promote sleep.\""}, {"id": "b", "t": "\"Valerian can help with vertigo and motion sickness.\""}, {"id": "c", "t": "\"Valerian contains an antioxidant that is extracted from grape skins.\""}, {"id": "d", "t": "\"Valerian can be beneficial in treating depression.\""}], "correct": "a", "rationale": "o; The nurse should inform the client that the herbal supplement valerian can provide sedation and prevent insomnia for clients who have B a sleep disorders.", "whyNot": {"b": "Ginger root can help treat vertigo and calm the nausea and vomiting associated with motion sickness.", "c": "Resveratrol is an antioxidant extracted from grape skins promoted as a supplement to increase longevity, although no human studies can", "d": "St. John's wort can be beneficial in the treatment for mild to moderate depression."}, "keyConcept": "Nurses should have working knowledge of herbal supplements, including their uses and potential adverse effects. Nurses should also be aware of contraindications. Nurses should recommend that clients consult with their health care providers before taking any herbal supplements."}, {"id": 11445, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is teaching a client who has a new prescription for daily aspirin. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"Aspirin reduces the formation of blood clots that could cause a heart attack.\""}, {"id": "b", "t": "\"Aspirin relieves pain during a myocardial infarction.\""}, {"id": "c", "t": "\"Aspirin dissolves clots that are forming in your coronary arteries.\""}, {"id": "d", "t": "\"Aspirin can lower total cholesterol.\""}], "correct": "a", "rationale": "Aspirin decreases platelet aggregation and inhibits vasoconstriction that can cause a myocardial infarction. The nurse should instruct the B I Ee client to take 81 to 325 mg of aspirin each day with food to reduce the risk for a formation of a thrombus as well as to monitor for and report tinnitus and any indication of bleeding, such as tarry stools, bruising, or bleeding gums. c i 6% p | 1%", "whyNot": {"b": "Pain associated with a myocardial infarction requires an opioid analgesic for relief. Aspirin will not alleviate ischemic pain.", "c": "Aspirin can relieve mild to moderate pain and reduce inflammation and fever. However, it does not dissolve clots. Thrombolytic therapy", "d": "Aspirin can relieve mild to moderate pain, reduce inflammation, and fever. However, it does not lower total cholesterol. Statin"}, "keyConcept": "Low-dose daily aspirin is prescribed for clients who have angina or suspected coronary artery disease to decrease platelet aggregation and inhibit vasoconstriction that can cause a myocardial infarction. The nurse should instruct the client to take 81 to 325 mg of aspirin each day with food to reduce the risk for a formation of a thrombus as well as to monitor for and report tinnitus and any indication of bleeding, such as tarry stools, bruising, or bleeding gums. Clients who have new-onset angina should call emergency services and then chew 4 chewable aspirin, which are 81 mg each, to initiate the antiplatelet effects."}, {"id": 11446, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "When instructing a client with type 2 diabetes mellitus who is being discharged with a prescription for glipizide, which statement should the nurse recognize as a sign of the need for further education? O A.\"I should call my healthcare provider if my morning blood glucose is below 60 mg/dL.\" O B. \"I can expect weight gain with this medication.\" O C.\"I should avoid alcohol after starting this medication.\" O D.\"I do not have to read the labels of foods that are 'sugar-free.\"\"", "choices": [{"id": "a", "t": "8%"}, {"id": "b", "t": "This statement by a client indicates understanding. Weight gain is a major adverse effect associated with sulfonylurea medications,"}, {"id": "c", "t": "This statement by a client indicates understanding. Hypoglycemia can occur with alcohol intake and should be avoided with sulfonylurea"}, {"id": "d", "t": "A | | 8% Moderate 8 9% Foods that are labeled “sugar-free,” “diabetic,” and “sugarless” may still contain carbohydrates that can raise the serum blood glucose."}], "correct": "d", "rationale": "A | | 8% Moderate 8 9% Foods that are labeled “sugar-free,” “diabetic,” and “sugarless” may still contain carbohydrates that can raise the serum blood glucose. c | 1% These carbohydrates, often used as sweeteners, include brown sugar, corn syrup, and honey. e@D FY 11%", "whyNot": {"a": "This statement by a client indicates understanding. Hypoglycemia is a major adverse effect associated with sulfonylurea medications,", "b": "This statement by a client indicates understanding. Weight gain is a major adverse effect associated with sulfonylurea medications,", "c": "This statement by a client indicates understanding. Hypoglycemia can occur with alcohol intake and should be avoided with sulfonylurea"}, "keyConcept": "Glipizide (Glucotrol) is a sulfonylurea hypoglycemic medication. It reduces the level of blood glucose by stimulating the pancreas to release more insulin and by increasing the sensitivity of insulin receptors. It is not used in type 1 diabetes mellitus, because the mechanism of action requires a functioning pancreas. The nurse should review signs of hypoglycemia and hyperglycemia with client and advise the client to drink a glass of orange juice or ingest 2- 3 tsp of sugar, if symptoms of hypoglycemia occur. Concurrent use of a beta-blocker medication may mask the signs/symptoms of hypoglycemia."}, {"id": 11447, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is reviewing the medication administration record (MAR) of a client. Which of the following entries correctly documents a prescribed dose of two-tenths of a milligram? O A..2mg © B.0.2mg © c.0.20mg © p..20mg", "choices": [{"id": "a", "t": "The nurse should place a leading zero before the decimal point to correctly document two-tenths of a milligram. Without the leading zero,"}, {"id": "b", "t": "| 2% Easy The use and placement of a decimal point can cause a medication error."}, {"id": "c", "t": "The nurse should not place a trailing zero after the \"2\" when documenting two-tenths of a milligram. With the presence of a zero behind"}, {"id": "d", "t": "The nurse should use a leading zero before the decimal point instead of a trailing zero after the \"2\" when documenting two-tenths of a"}], "correct": "b", "rationale": "| 2% Easy The use and placement of a decimal point can cause a medication error. A zero should precede a decimal point when documenting a OB rsd ower number smaller than one, but should not follow a decimal point unless another digit follows the zero, as in \"1.05 mg.\" cf 5% p | 1%", "whyNot": {"a": "The nurse should place a leading zero before the decimal point to correctly document two-tenths of a milligram. Without the leading zero,", "c": "The nurse should not place a trailing zero after the \"2\" when documenting two-tenths of a milligram. With the presence of a zero behind", "d": "The nurse should use a leading zero before the decimal point instead of a trailing zero after the \"2\" when documenting two-tenths of a"}, "keyConcept": "Nurses responsible for reviewing the MARs and transcribing medication orders should be able to identify the correct placements of decimals and leading versus trailing zeros when documenting numbers that include decimal points."}, {"id": 11448, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is assessing a client with arthritis who takes 1-2 325 mg aspirin tablets every 4-6 hours for analgesia, as needed. Which of the following will the nurse monitor for toxicity?", "choices": [{"id": "a", "t": "Hypothermia"}, {"id": "b", "t": "Bradycardia"}, {"id": "c", "t": "Tinnitus"}, {"id": "d", "t": "Bradypnea"}], "correct": "c", "rationale": "al of Salicylates are a class of nonsteroidal anti-inflammatory drug with anti-inflammatory, antipyretic, and analgesic effects. Aspirin is a ec | salicylate that inhibits platelet aggregation and the synthesis and action of prostaglandins. Aspirin toxicity is characterized by tinnitus, D I hearing loss, and vertigo; nausea, vomiting, and diarrhea; altered mental status, which can range from agitation to lethargy to coma; non- cardiac pulmonary edema; hyperpyrexia, hyperpnea, and acid-base abnormalities. Ten to 30 grams by adults and as little as 3 grams by children can result in fatal toxicity.", "whyNot": {"a": "Hyperpyrexia is associated with aspirin toxicity.", "b": "Clients may develop tachycardia as a result of hyperpyrexia or agitation.", "d": "Hyperpnea is commonly seen with aspirin toxicity."}, "keyConcept": "Salicylate toxicity can occur with as little as ten grams of aspirin in adults and 3 grams in children. Toxicity is characterized by tinnitus, hearing loss, nausea, vomiting, diarrhea, vertigo, altered mental status, hyperpyrexia, hypernea, and acid-base abnormalities. Stimulation of the respiratory center causes hyperventilation and respiratory alkalosis. The elderly are more susceptible to toxicity than younger adults."}, {"id": 11449, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer the hepatitis B vaccine to an adolescent. Which of the following questions should the nurse ask the adolescent prior to administering the vaccine? O A.\"Do you have an allergy to eggs?\" O B. \"Have you ever had encephalopathy following immunizations?\" O C. \"Are you currently taking a corticosteroid medication?\" O D. \"Have you ever had an anaphylactic reaction to yeast?\"", "choices": [{"id": "a", "t": "An allergy to eggs is not a contraindication to receiving the hepatitis B vaccine. The nurse should ask the adolescent about their allergy to e@D"}, {"id": "b", "t": "The DTaP vaccine is contraindicated for clients who have a history of encephalopathy within 7 days following prior doses of the vaccine."}, {"id": "c", "t": "The varicella vaccine is contraindicated for clients who have been taking corticosteroids or other medications that affect the immune"}, {"id": "d", "t": "‘i The hepatitis B vaccine is contraindicated for clients who have had an anaphylactic reaction to yeast."}], "correct": "d", "rationale": "‘i The hepatitis B vaccine is contraindicated for clients who have had an anaphylactic reaction to yeast. B i", "whyNot": {"a": "An allergy to eggs is not a contraindication to receiving the hepatitis B vaccine. The nurse should ask the adolescent about their allergy to e@D |", "b": "The DTaP vaccine is contraindicated for clients who have a history of encephalopathy within 7 days following prior doses of the vaccine.", "c": "The varicella vaccine is contraindicated for clients who have been taking corticosteroids or other medications that affect the immune"}, "keyConcept": "Allergy Contraindicated immunization Gelatin Measies, mumps, rubella (MMR) Measies, mumps, rubella, varicella (MMAV) Varicella Yeast Hepatitis 8 Human papilloma virus (HPV)"}, {"id": 11450, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is assessing a patient with major depressive disorder who recently began treatment with phenelzine (Nardil). Which of the following is a common adverse effect of this treatment?", "choices": [{"id": "a", "t": "Agitation"}, {"id": "b", "t": "Urinary frequency"}, {"id": "c", "t": "Diarrhea"}, {"id": "d", "t": "Weight gain"}], "correct": "d", "rationale": ". . 7 sts a ons Mm 21% Moderate MAOIs are used to treat major depression, although they are not a first-line medication due to the incidence of adverse effects, which include orthostatic hypotension, sedation, fatigue, insomnia, urinary hesitancy, constipation, muscle cramps, arrhythmias, and weight gain. Weight B | ™% gain is a frequent reason for discontinuation of antidepressant medication and is more common in MAOIs than in SSRIs. Phenelzine (Nardil) Cc | 11% is particularly associated with weight gain. Toxic effects can include hypertensive crisis, severe headache, hypertension, tachycardia, and @ /vomiting. Hypertensive crisis is the most serious reaction to an MAOI, so patients should monitor their blood pressure, particularly in the period immediately after beginning treatment. A variety of foods, beverages, and medications can interact with MAOIs to increase blood pressure. It is important to stress avoiding these foods.", "whyNot": {"a": "Sedation or fatigue is common. Agitation can occur in overdose.", "b": "The anticholinergic effects of MAOIs include urinary hesitancy and retention.", "c": "The anticholinergic effects of MAOIs include constipation."}, "keyConcept": "MAOIs are an early class of antidepressant medication associated with adverse effects due to interaction with tyramine-containing foods. These foods include smoked or cured meats and fish, including sausages, aged cheeses, red wine, soy products, and several varieties of beans (fava beans, broad beans). The most significant adverse effect associated with this interaction is hypertensive crisis. Hypotension, urinary hesitancy, weight gain, and sedation are common side effects from this class of medications."}, {"id": 11451, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer beclomethasone intranasally to a client who has a frontal sinus infection. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Ask the client to blow their nose gently before the instillation."}, {"id": "b", "t": "Assist the client to a side-lying position."}, {"id": "c", "t": "Have the client breathe slowly through the nose during installation."}, {"id": "d", "t": "Instruct the client to tilt the head upright immediately after the instillation."}], "correct": "a", "rationale": "o; Prior to instilling the medication, the nurse should instruct the client to blow their nose gently. This action will help remove any secretions or B | crusts that could interfere with the distribution and absorption of the medication.", "whyNot": {"b": "The nurse should assist the client to lie supine for a nasal instillation with their head turned toward the affected side.", "c": "The nurse should instruct the client to breathe through the mouth during instillation to prevent aspiration of the medication into the", "d": "The nurse should instruct the client to remain in the supine position for at least 1 min to prevent the solution from coming into contact"}, "keyConcept": "Nurses are responsible for the administration of medications to clients. This includes medication administered intranasally. The nurse should be able to identify the proper technique based on the location of the sinus infection."}, {"id": 11452, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "and medication? O A. Aseptic technique should be used to avoid contamination of sterile equipment. O B. Multi-dose vials of parenteral medications are preferable to reduce the cost of care. O C. When a client will receive successive doses of a medication from a multi-dose vial, the vial should be kept in the immediate client treatment area. O D. Large-volume bottles or bags of intravenous solution can be used to supply multiple clients who require only small quantities for flush or dilution of medication.", "choices": [{"id": "a", "t": "Aseptic technique should be used to avoid contamination of sterile equipment."}, {"id": "b", "t": "Multi-dose vials of parenteral medications are preferable to reduce the cost of care."}, {"id": "c", "t": "When a client will receive successive doses of a medication from a multi-dose vial, the vial should be kept in the immediate client treatment area."}, {"id": "d", "t": "Large-volume bottles or bags of intravenous solution can be used to supply multiple clients who require only small quantities for flush or dilution of medication."}], "correct": "a", "rationale": "5 i 17% Parenteral injections break the skin and are considered invasive. When using needles, cannulas, or intravenous delivery systems, aseptic Cc Hi 17% technique is required to avoid contamination. Most syringes are disposable, made of plastic and individually packaged for sterility. , needles, and cannulas are sterile single-use items. There are three types of aseptic technique: sterile, standard (medical), and surgical. Hand hygiene is the basis of all aseptic practices. Medical asepsis refers to absence of pathogenic (disease-causing) micro-organisms. Surgical asepsis (sterile technique) refers to elimination of all microorganisms and prevention of contamination. Sterile technique is used when administering parenteral fluids or medications. The nurse must ensure that the hub, inside of the barrel, shaft, and rubber plunger tip are kept sterile. When administering a medication using a syringe, the nurse should touch only the outside of the barrel and the handle of the plunger.", "whyNot": {"b": "Single-use vials are preferable to multi-dose vials of parenteral medications when possible.", "c": "When a client is receiving several doses of medication from a multidose vial, the vial should not be kept in the immediate client treatment", "d": "Large-volume bottles or bags of intravenous solution cannot be used to supply multiple clients."}, "keyConcept": "Sterile technique, also known as surgical asepsis, is used by the nurse during many nursing procedures, including sterile dressing changes; when administering parenteral medications or fluids; and when inserting a urinary catheter."}, {"id": 11453, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "When preparing to administer medications on the medical-surgical floor, which of the following actions should a nurse take to comply with client safety practices to prevent medication administration errors?", "choices": [{"id": "a", "t": "Ask the pharmacist to identify any unlabeled medications."}, {"id": "b", "t": "Wear gloves when preparing an unopened unit dose package."}, {"id": "c", "t": "Verify the client’s primary healthcare provider."}, {"id": "d", "t": "Medications must be given within a 1 hour time frame on the medication log."}, {"id": "e", "t": "Open unit doses and place in a dispensing cup before taking to the bedside."}], "correct": "d", "rationale": "Bf 5% The 6 rights of medication administration are: + Right individual c| 2% @D 44% + Right medication | ° i) ° , = + Right dose g 3 «Right time a [R a + Right route 4 + Right documentation The “right time\" is a 30-minute period either before or after the medication is due. It does not apply to PRN orders, which can’t be given until the correct time has passed.", "whyNot": {"a": "All unlabeled medications should be discarded. Each time a nurse administers any medication, the procedure must be checked to ensure", "b": "Hand hygiene should be performed before preparing a unit dose medication and before and after administering the medication. Gloves", "c": "The client’s healthcare provider is not a unique identifier and does not require verification.", "e": "Medications should only be opened at the client’s bedside. They can be placed in a medication administration cup just before"}, "keyConcept": null}, {"id": 11454, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "minutes now.\" Which of the following is the first priority?", "choices": [{"id": "a", "t": "Set the lV pump to 20 mL/hour."}, {"id": "b", "t": "Check the client’s most recent potassium level."}, {"id": "c", "t": "Assess the patency of the vein."}, {"id": "d", "t": "Verify the prescription with the healthcare provider."}], "correct": "d", "rationale": "Correct Answer: A | D. Verify the prescription with the healthcare provider. c | Potassium is the major cellular cation, necessary for nerve conduction and for contraction of both smooth and skeletal muscles, including @D | cardiac muscle. Abnormal levels of serum potassium can result in muscle weakness and cardiac arrhythmias. Potassium chloride is the most commonly used replacement solution used for intravenous potassium supplementation. It is a tissue irritant and should never be given IM or sQ. The maximum recommended rate for infusion of potassium through a peripheral vein is no more than 5-10 mEq (5-10 mmol) per hour. When using a central line, the rate of infusion should be no greater than 20 mEq (20 mmol)/hr. The order given is 4 times the recommended rate for a peripheral intravenous infusion of potassium, which can result in irritation, pain, and post-infusion phlebitis. Rapid administration of KCl can also cause cardiac arrhythmias. The nurse should contact the healthcare provider as a priority.", "whyNot": {"a": "This rate is much higher than the recommended rate. If the nurse infused the potassium at the rate prescribed, the pump would be set at", "b": "Although the nurse will check the client’s most recent potassium level before initiating the infusion, the priority is clarifying the order.", "c": "After determining the correct prescription, the nurse will assess the IV site for redness, tenderness, and swelling before beginning the"}, "keyConcept": "Potassium chloride is a tissue irritant and should not be given IM or SQ. Rapid infusion of a large volume of KCl can result in damage to tissues at the infusion site and may result in cardiac arrhythmias. Vials of concentrated KCl are no longer kept in client care areas. The dilution of potassium should be no more than 1 mEq KClin 10 mL solution. The nurse should check the dilution twice before administration. The maximum rate for infusion through a peripheral vein is 5-10 mEq/L (5-10 mmol/L.)"}, {"id": 11455, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer a topical ophthalmic anesthetic solution to a client. The prescription calls for 2 minims per eye. Which of the following does the nurse realize about this order? O A.A minim is a measurement in the metric system that is equal to a milliliter. O B. Aminim is a measurement in the apothecaries’ system roughly equivalent to 1 drop (ggt). O C. The minim is an abbreviation for a metric unit, milliliter. O D. The minim is a measurement of weight, not volume.", "choices": [{"id": "a", "t": "One milliliter is a metric unit that is equivalent to 15 minims, a measurement used in the apothecaries’ system."}, {"id": "b", "t": "al 5% Easy A nurse will sometimes be required to convert weights or volumes in a prescription when preparing to administer a medication to a client."}, {"id": "c", "t": "Aminim is a unit of the apothecaries’ system. The abbreviation for milliliter is mL."}, {"id": "d", "t": "The minim is the basic unit of measurement of volume in the apothecaries’ system, and the grain is the basic unit of weight."}], "correct": "b", "rationale": "al 5% Easy A nurse will sometimes be required to convert weights or volumes in a prescription when preparing to administer a medication to a client. OB TS amas Although these conversions are approximate, there are commonly used equivalents that can help a nurse make conversions when necessary. A minim is a unit in the apothecaries’ system and when converted to drops, is 1 minim is approximately equivalent to 1 drop. One c | 4% milliliter contains approximately 15 minims or 15 drops.", "whyNot": {"a": "One milliliter is a metric unit that is equivalent to 15 minims, a measurement used in the apothecaries’ system.", "c": "Aminim is a unit of the apothecaries’ system. The abbreviation for milliliter is mL.", "d": "The minim is the basic unit of measurement of volume in the apothecaries’ system, and the grain is the basic unit of weight."}, "keyConcept": "There are three commonly used measurement systems for weight and volume in prescribing. A minim is a unit in the apothecaries' system that is approximately equal to one drop."}, {"id": 11456, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "Which of the following abbreviations used in a prescription for indomethacin 50 mg po may be confusing and should not be written? O wprn O s.Bip Ocep Opb.ap", "choices": [{"id": "a", "t": "5%"}, {"id": "b", "t": "BID is a common and acceptable abbreviation in prescribing that means “twice a day.”"}, {"id": "c", "t": "’s list of improper abbreviations in prescribing, as it may easily be mistaken for QOD."}, {"id": "d", "t": "QID is an acceptable abbreviation for “four times a day.”"}], "correct": "c", "rationale": "’s list of improper abbreviations in prescribing, as it may easily be mistaken for QOD. B | a0 QD is a Latin abbreviation that refers to daily dosing, once a day, and should be written out as “daily.” QOD means every other day and should be written out fully without abbreviation. Other improper terms used in prescribing that are included on the list include \"u\" and \"U\" ec | 15% for unit; MS, MSO4, and MgSO4 for morphine sulfate or magnesium sulfate; \"IU\" for international unit; lack of a leading zero and trailing D Hi 18% zeros.", "whyNot": {"a": "PRN is an acceptable medical abbreviation that means “as needed” or “according to necessity.”", "b": "BID is a common and acceptable abbreviation in prescribing that means “twice a day.”", "d": "QID is an acceptable abbreviation for “four times a day.”"}, "keyConcept": "The Joint Commission (TJC) has established a National Patient Safety Goal that specifies certain abbreviations an accredited organization's must list on a \"do-not-use list.\" These abbreviations have been frequently misinterpreted and involved in harmful medication errors. They should NEVER be used when communicating medical information. Q.D., QD, q.d., qd (daily), Q.0.D., QOD, q.o.d, and qod (every other day) should never be used."}, {"id": 11457, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer an oral medication to a client. The client states, \"The pill | normally take is round. | don't think that is my medication.\" Which of the following responses should the nurse make? O A.\"Sometimes the same pill comes in different shapes.\" O B. \"I will see if this medication comes in a liquid form.\" O C. \"| will recheck the medication prescription in your medical record.\" O D. \"This is the medication that your doctor wants you to take.\"", "choices": [{"id": "a", "t": "Clients are often able to identify the medication they take; therefore, the nurse should check the provider's original medication"}, {"id": "b", "t": "This response is nontherapeutic because it changes the subject and indicates the nurse is not paying attention to the client's comments."}, {"id": "c", "t": "all 9% Easy The nurse should check the provider's original medication prescription prior to administering the medication to avoid a medication error."}, {"id": "d", "t": "This response is nontherapeutic because it is an automatic response that indicates the nurse is not taking the client's remarks seriously."}], "correct": "c", "rationale": "all 9% Easy The nurse should check the provider's original medication prescription prior to administering the medication to avoid a medication error. | 1%", "whyNot": {"a": "Clients are often able to identify the medication they take; therefore, the nurse should check the provider's original medication", "b": "This response is nontherapeutic because it changes the subject and indicates the nurse is not paying attention to the client's comments.", "d": "This response is nontherapeutic because it is an automatic response that indicates the nurse is not taking the client's remarks seriously."}, "keyConcept": "Nurses are responsible for administering the right medication. If there is any reason to doubt the accuracy of the medication, such as the client questioning the shape of the medication, the nurse should not administer the medication until the accuracy is verified."}, {"id": 11458, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "administration? O A. Blood pressure 104/70 mmHg O B. Respiratory rate of 10/min O C. Burning during injection O D. Nausea", "choices": [{"id": "a", "t": "Blood pressure 104/70 mmHg"}, {"id": "b", "t": "Respiratory rate of 10/min"}, {"id": "c", "t": "Burning during injection"}, {"id": "d", "t": "Nausea"}], "correct": "b", "rationale": "Opioid analgesics, such as morphine, can cause respiratory depression. The nurse should hold morphine administration in a client with a respiratory rate <12/min. An assessment should be performed to determine the severity and possible cause of the client’s pain. It may be necessary to decrease the client’s dose or to increase the time between administration.", "whyNot": {"a": "Opioid analgesics given intravenously, such as morphine, can lower blood pressure. Although this client has a low blood pressure, it is not", "c": "Burning may occur at the infusion site but can be relieved by slow administration over 3-5 minutes and dilution of morphine with normal", "d": "Nausea is a common side effect of opioid analgesics."}, "keyConcept": "When administering opioid analgesics, the nurse should monitor the client's respiratory rate. Opioid analgesics, particularly when given intravenously, depress respiratory drive. The nurse should hold further administration of morphine when the client's respiratory rate is less than 12/minute. After assessing the cause and severity of the client's pain, a determination can be made about reducing the dose or increasing the dosing interval."}, {"id": 11459, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is providing teaching for a client who has a new prescription for atorvastatin. The nurse should tell the client to notify the healthcare provider for which of the following symptoms?", "choices": [{"id": "a", "t": "Headache"}, {"id": "b", "t": "Muscle pain"}, {"id": "c", "t": "Cough"}, {"id": "d", "t": "Frequent urination"}], "correct": "b", "rationale": "Moderate Correct Answer: B. Muscle pain a | 14% Atorvastatin and other “statins” are HMG CoA reductase inhibitors that are used to lower LDL cholesterol, total cholesterol, and triglycerides c Hi 14% and to increase HDL cholesterol. Clients should notify the healthcare provider if muscle pain or tenderness develops. The creatine kinase my | 3\" level should be monitored as it may reflect an increase due to muscle breakdown. Liver function must be monitored regularly with statins, as they interact with the liver to reduce production of cholesterol. Incorect Answers: A. Headaches are not a common side effect of statin medications.", "whyNot": null, "keyConcept": "\"Statin\" medications are used to lower LDL cholesterol and increase HDL cholesterol for primary and secondary prevention of coronary artery disease. Important side effects include muscle breakdown (\"statin myopathy\") and liver dysfunction. Clients should report any new or increased muscle pain or tenderness to the healthcare provider."}, {"id": 11460, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "The school nurse is preparing to administer a prescribed medication to her client. She knows that the order for a teaspoon of hydrocodone reflects which of the following?", "choices": [{"id": "a", "t": "Metric system"}, {"id": "b", "t": "Apothecaries’ system"}, {"id": "c", "t": "Household system"}, {"id": "d", "t": "Standard system"}], "correct": "c", "rationale": "A Hi 19% Moderate There are 3 types of measurement systems used in the United States for medications. They include the household system, metric system, B I a and apothecaries’ system. The household system is used when a more accurate unit of measurement is unnecessary and includes units of measure such as teaspoons, drops, cups, and tablespoons. A teaspoon is equivalent to approximately 5 mL There are 15 mL in a tablespoon, ec | 61% which is equal to approximately 4 fluid drams in the apothecaries’ system. D Hi 14%", "whyNot": {"a": "The metric system is used in most European countries and in Canada. It is organized into units of 10, so basic units can be divided or", "b": "The apothecaries’ system has been used in the United States since the colonial era after it was adopted from England. The basic unit of", "d": "The standard system of measurement in the US refers to weights and measures derived from the English and used primarily in trade and"}, "keyConcept": "Ateaspoon is a measurement in the \"household\" system. The metric system uses milliliters as a volume of measurement. One teaspoon = approximately 5 mL."}, {"id": 11461, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer an intramuscular (IM) injection of morphine to a client. Which of the following assessments is the nurse's priority?", "choices": [{"id": "a", "t": "Last time the client voided"}, {"id": "b", "t": "Blood pressure"}, {"id": "c", "t": "Level of consciousness"}, {"id": "d", "t": "Respiratory rate"}], "correct": "d", "rationale": ", breathing, and circulation approach to client care, the nurse should prioritize assessing the respiratory rate. B | 3 Morphine can cause severe respiratory depression. The nurse should contact the provider and withhold the morphine for a client who has a respiratory rate less than 12/min. Other adverse effects of morphine include the following: c | 6% + Respiratory depression + Constipation + Orthostatic hypotension + Urinary retention Sedation + Emesis + Biliary colic + Elevation of intracranial pressure", "whyNot": {"a": "The nurse should assess the last time the client voided due to the potential adverse effect of urinary retention. However, there is another", "b": "The nurse should assess the client's blood pressure due to the potential adverse effect of orthostatic hypotension. However, there is", "c": "The nurse should assess the client's level of consciousness due to the potential adverse effect of sedation. However, there is another"}, "keyConcept": "Nurses who are responsible for the administration of opioid agonists should be able to identify and prioritize assessments that are necessary prior to medication administration. Nurses should also be able to identify potential adverse effects of the medication and monitor the client a © o 2 ° s a = a <"}, {"id": 11462, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer doses of both regular and glargine insulin 20 min before breakfast to a client who has a blood glucose of 278 mg/dL. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Draw up the regular insulin first and then the glargine insulin in the same syringe."}, {"id": "b", "t": "Draw up the glargine insulin first and then the regular insulin in the same syringe."}, {"id": "c", "t": "Draw up the regular and glargine insulin in separate syringes and administer them one after the other."}, {"id": "d", "t": "Administer the regular insulin 1 hr before administering the glargine insulin."}], "correct": "c", "rationale": "Nurses can teach clients that long-acting insulins are absorbed slowly over 24 hr; therefore, it is important for them to be administered at the same time each day to prevent any overlap of action. Taking glargine insulin along with regular insulin in the morning, instead of at bedtime, helps to ensure that the doses will not be forgotten or given inconsistently. Clients should be reminded that glargine insulin cannot be mixed in the same syringe with regular insulin or other insulins, even though the different kinds of insulin may be given at the same time.", "whyNot": {"a": "These insulins are not compatible and should not be drawn up in the same syringe.", "b": "These insulins are not compatible and should not be drawn up in the same syringe", "d": "These insulins should be administered at the same time. Regular insulin is short-acting and should lower the client's blood glucose level"}, "keyConcept": "Nurses can teach clients that long-acting insulins are absorbed slowly over 24 hr; therefore, it is important for them to be administered at the same time each day to prevent any overlap of action. Taking glargine insulin along with regular insulin in the morning, instead of at bedtime, helps to ensure that the doses will not be forgotten or given inconsistently. Clients should be reminded that glargine insulin cannot be mixed in the same syringe with regular insulin or other insulins, even though the different kinds of insulin may be given at the same time."}, {"id": 11463, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse in the emergency department is preparing to assist with the care of a client who has benzodiazepine toxicity. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Administer activated charcoal."}, {"id": "b", "t": "Collect data regarding the client's level of orientation."}, {"id": "c", "t": "Insert a nasogastric tube."}, {"id": "d", "t": "Perform gastric lavage."}], "correct": "b", "rationale": "A || 13% Moderate Rationale: The first action the nurse should take when using the nursing process is to collect data. Identifying the client's level of orientation c | 4% is the priority action because lethargy, drowsiness, and confusion are symptoms of benzodiazepine toxicity. my | a", "whyNot": {"a": "The nurse should administer activated charcoal and a saline cathartic after performing gastric lavage to promote the elimination of", "c": "The nurse should insert a large bore nasogastric tube so gastric lavage can be completed. Gastric lavage will remove the medication that", "d": "Gastric lavage is performed by instilling 200 to 300 mL of solution into a nasogastric tube and then connecting the tubing to suction. This"}, "keyConcept": "The use of benzodiazepines is common for clients who have anxiety disorders, sleep disorders, and various other conditions. While benzodiazepine toxicity is rare with oral administration of these medications, it can occur when the benzodiazepine is combined with another agent, such as alcohol. Significant respiratory and cardiovascular complications are not common, however. The nurse should ensure the client has an IV access so that fluids or norepinephrine can be administered to support the blood pressure. The nurse should also monitor oxygen saturation and ensure the client's airway is patent."}, {"id": 11464, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "solutions should the nurse infuse until the next container of TPN solution becomes available?", "choices": [{"id": "a", "t": "Lactated Ringer's"}, {"id": "b", "t": "Dextrose 5% in 0.45% sodium chloride"}, {"id": "c", "t": "Dextrose 10% in water"}, {"id": "d", "t": "0.9% sodium chloride"}], "correct": "c", "rationale": "Sudden withdrawal from TPN, which is a hypertonic solution that contains dextrose, vitamins, electrolytes, and sometimes lipids, can result in a sudden drop in the client's blood glucose levels. Administering an infusion of 10% dextrose will prevent hypoglycemia.", "whyNot": {"a": "Infusing this solution would increase the client's risk for hypoglycemia.", "b": "Infusing this solution would increase the client's risk for hypoglycemia.", "d": "Infusing this solution would increase the client's risk for hypoglycemia."}, "keyConcept": "A nurse who is caring for a client who is receiving total parenteral nutrition is responsible for identifying the interventions to take when the next bag of solution is not available. The nurse should identify which solutions would not be acceptable due to the risk for a sudden decrease in client glucose levels."}, {"id": 11465, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A nurse is preparing to administer an IM injection to a client. The nurse should complete the third and final medication check at which of the following times?", "choices": [{"id": "a", "t": "At the client's bedside before administration"}, {"id": "b", "t": "At the time the medication is drawn up into the syringe"}, {"id": "c", "t": "At the time the nurse documents administration of the medication"}, {"id": "d", "t": "At the nurses' station while reviewing the provider's prescription"}], "correct": "a", "rationale": "The nurse should perform the final medication check at the client's bedside while reviewing the medication label prior to administering the medication.", "whyNot": {"b": "The nurse should perform the second medication check when preparing the medication for administration.", "c": "The nurse should not document giving the medication until after the medication is administered to the client. At that time, it would be too", "d": "At this time, the nurse has not yet obtained the medication and, therefore, cannot complete a medication check."}, "keyConcept": "Nurses should perform three medication checks to ensure safe medication administration. The nurse should also check the expiration date of the medication at this time."}, {"id": 11466, "cat": "PHYSIOLOGY INTEGRITY- PHARMACOLOGICAL", "stem": "A client with cystitis receives a prescription for trimethoprim-sulfamethoxazole (Bactrim). Which of the following instructions should the nurse provide? O A.\"Stop the medication when you no longer have symptoms.\" O B. \"Avoid the sun during treatment with this medication.\" O C. \"Limit your fluid intake with this medication.\" O D. \"Take the medication with milk to increase absorption.\"", "choices": [{"id": "a", "t": "Cystitis is an infection of the bladder and is usually caused by bacteria that ascend from the perineal area, including bacteria from the Gl"}, {"id": "b", "t": "Medications that contain sulfa increase photosensitivity."}, {"id": "c", "t": "Clients should be encouraged to drink plenty of fluids in order to flush bacteria and eliminate metabolites (breakdown products) of the"}, {"id": "d", "t": "Milk can sometimes hinder the absorption of the medication."}], "correct": "b", "rationale": "Medications that contain sulfa increase photosensitivity. When taking a sulfa-containing medication, individuals should avoid prolonged exposure to the sun and should wear sunscreen while out of doors.", "whyNot": {"a": "Cystitis is an infection of the bladder and is usually caused by bacteria that ascend from the perineal area, including bacteria from the Gl", "c": "Clients should be encouraged to drink plenty of fluids in order to flush bacteria and eliminate metabolites (breakdown products) of the", "d": "Milk can sometimes hinder the absorption of the medication."}, "keyConcept": "Trimethoprim-sulfamethoxazole is an antibiotic associated with several severe adverse effects, including pseudomembranous colitis, hepatic necrosis, cholestatic jaundice, pancreatitis. erythema multiforme, Stevens-Johnson syndrome, toxic epidermal necrolysis, agranulocytosis, and aplastic anemia. Clients should be advised to monitor bowel function and immediately report diarrhea, abdominal cramping, fever, and bloody stools, which may be a sign of pseudomembranous colitis. The client should a rash to the healthcare provider, since trimethoprim-sulfamethoxazole has been associated with Stevens-Johnson syndrome. Therapy should be discontinued if these symptoms are severe or if they are accompanied by fever, general malaise, myalgia or arthralgia, blisters, oral lesions, conjunctivitis, hepatitis and/or eosinophilia."}], "psychosocial_integrity": [{"id": 11467, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "intervention? O A. Speak slowly O B. Use diagrams O C. Speak to the client with family present O D. Use an interpreter for translation", "choices": [{"id": "a", "t": "Speak slowly"}, {"id": "b", "t": "Use diagrams"}, {"id": "c", "t": "Speak to the client with family present"}, {"id": "d", "t": "Use an interpreter for translation"}], "correct": "d", "rationale": "al 2% Easy An interpreter should be requested to facilitate understanding by a client who does not understand English. Therapeutic communication is B | a0 important in caring for clients who have a mental illness. Healthcare organizations should be able to provide an interpreter to clients who have limited proficiency in English. Interpreters should be available in a timely manner and should be matched to the client in terms of c | 2% gender, social status, age, and religion, when possible. The interpreter should be able to translate both verbal and nonverbal communication @D PY 94% in a way that is specific to the client’s cultural norms.", "whyNot": {"a": "Speaking slowly will not be helpful to a client who has limited or no proficiency in English.", "b": "Diagrams will not assist the client in communicating concerns or to ask questions.", "c": "The stigma associated with mental illness may prevent the client from being open if friends or family are present. Additionally, in some"}, "keyConcept": "Therapeutic communication is particularly important when caring for a client with a mental illness. When the client does not speak English, an interpreter should be provided who is matched to the client as much as possible with respect to gender, age, social status, and religion, with the ability to translate both verbal and non-verbal communication."}, {"id": 11468, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for an adult client who has injuries resulting from intimate partner abuse. Which of the following actions is the nurse’s priority?", "choices": [{"id": "a", "t": "Advise the client about the location of safe houses."}, {"id": "b", "t": "Encourage the client to participate in a support group for survivors of abuse."}, {"id": "c", "t": "Implement case management to coordinate community and social services."}, {"id": "d", "t": "Educate the client about the use of stress management techniques."}], "correct": "a", "rationale": "o; B The priority action for the nurse is to assist the client with the development of a safety plan that includes the identification of safe places to c | live. The greatest risk to this client is harm from intimate partner violence (IPV.) IPV includes three types of abuse that usually overlap in a D | relationship: physical, sexual, or psychological abuse. Thirty percent of homicides in females are the result of IPV, so safety is the primary concern. An important intervention by nurses to address IPV is to ask all women about violence. The nurse can ask during any client encounter, but it must be done privately. If the client appears to be in danger, the nurse should assist in accessing community resources, including shelters. The nurse should inform the client that it is likely that abuse will occur again, increasing in severity.", "whyNot": {"b": "The nurse should encourage participation in a support group. However, this does not address the greatest risk to the client and is", "c": "The nurse should implement case management to help the client locate available community resources. However, this does not address", "d": "The nurse should educate the client about the use of stress management techniques. However, this does not address the greatest risk to"}, "keyConcept": "Intimate partner violence is responsible for 30% of female homicides in the United States. Interventions to address IPV include identification and screening, and development of a safety plan. If the client is in imminent danger, the nurse should assist the client with access to community resources, including shelters and safe houses."}, {"id": 11469, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "appropriate for the nurse to take? O", "choices": [{"id": "a", "t": "Reassure the client that the statement was a compliment."}, {"id": "b", "t": "Postpone the examination until the client feels less upset."}, {"id": "c", "t": "Ask the client for permission to touch the daughter’s hand."}, {"id": "d", "t": "Ask the client why the daughter accompanied her to the clinic."}], "correct": "c", "rationale": "It is important for a nurse to be aware of cultural beliefs common among members of the community. In some Latin American cultures, the ec | | “evil eye” or “mal de ojo” is thought to occur when a child is complimented by someone perceived with more power or by a stranger, but the D | curse is thought to be broken if the person touches the child when speaking or just afterward. The “curse” is characterized by crying, vomiting, and a fever. If someone believes a child is afflicted with this curse, they may consult a traditional healer known as curandero to perform rituals to rid the child of the curse. The charms and beaded bracelets worn by some children in these cultures is meant to protect them from the “mal de ojo.”", "whyNot": {"a": "This response shows a lack of cultural awareness and will not be helpful for relief of the client’s distress.", "b": "A postponement of the exam will not address the client’s concerns.", "d": "This response will not relieve the client’s distress and does not address concerns appropriately."}, "keyConcept": "A nurse should be aware that variations from the prevailing norm in communication or behavior may be the result of different cultural beliefs and values. To provide culturally competent care, nurses should be aware of their own cultural heritage and any biases or values that may affect care. Nurses should be aware of specifics in cultural groups they are likely to encounter and should accommodate the client's values and beliefs when providing care."}, {"id": 11470, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "personality? O A. Intellect, race, and socioeconomic status O B. Genetic makeup, placement in the family, and autoimmunity O C. Biological constitution, psychological development, and cultural setting O D. Childhood experiences, intellect, and socioeconomic status", "choices": [{"id": "a", "t": "Intellect, race, and socioeconomic status"}, {"id": "b", "t": "Genetic makeup, placement in the family, and autoimmunity"}, {"id": "c", "t": "Biological constitution, psychological development, and cultural setting"}, {"id": "d", "t": "Childhood experiences, intellect, and socioeconomic status"}], "correct": "c", "rationale": "A l 3% Moderate These factors make each individual unique. It's all about nature and nurture. This is the only correct combination. B | 3\"", "whyNot": {"a": "Race plays no part in personality development. ec | 63%", "b": "Autoimmunity plays no part in personality development.", "d": "These are limited to only some aspects of personality development. This answer is not comprehensive, as biological constitution has a"}, "keyConcept": "Personality development refers to how the organized patterns of behavior that constitute personality emerge over time. Factors that influence personality include genetics, environment, parenting, and societal variables. The interaction of all of these influences results in early personality development and continues to shape personality over the individual's lifetime. Different theories of personality development focus on different influences. Erickson's model focuses on social influences on personality development. Piaget's theories are based on stages in development of cognition."}, {"id": 11471, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is developing an informational brochure for clients who have borderline personality disorder. Which of the following treatments should the charge nurse include in the brochure?", "choices": [{"id": "a", "t": "Dialectical behavior therapy"}, {"id": "b", "t": "Behavioral contract"}, {"id": "c", "t": "Bibliotherapy"}, {"id": "d", "t": "Safety plan"}], "correct": "a", "rationale": "o; Dialectical behavior therapy is an effective intervention used in the treatment of clients who have borderline personality disorder. | c | D", "whyNot": {"b": "A behavioral contract is appropriate for a client who has aggressive or disruptive behavior, not borderline personality disorder.", "c": "Bibliotherapy is appropriate for clients who need to gain skills for dealing with stressful situations, not for a client who has borderline", "d": "A safety plan is appropriate for a competent adult client who is in an abusive relationship, not for a client who has borderline personality"}, "keyConcept": "Dialectical therapy is an evidence-based therapy that uses both cognitive and behavioral techniques to treat borderline personality disorder or clients who have chronic suicidal behavior. This therapy teaches clients to be aware of their behavior and how to modify it."}, {"id": 11472, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is developing an informational brochure for clients who have borderline personality disorder. Which of the following treatments should the charge nurse include in the brochure?", "choices": [{"id": "a", "t": "Dialectical behavior therapy"}, {"id": "b", "t": "Behavioral contract"}, {"id": "c", "t": "Bibliotherapy"}, {"id": "d", "t": "Safety plan eck Answer"}], "correct": "a", "rationale": "Dialectical behavior therapy is an effective intervention used in the treatment of clients who have borderline personality disorder.", "whyNot": {"b": "A behavioral contract is appropriate for a client who has aggressive or disruptive behavior, not borderline personality disorder.", "c": "Bibliotherapy is appropriate for clients who need to gain skills for dealing with stressful situations, not for a client who has borderline", "d": "A safety plan is appropriate for a competent adult client who is in an abusive relationship, not for a client who has borderline personality"}, "keyConcept": "Dialectical therapy is an evidence-based therapy that uses both cognitive and behavioral techniques to treat borderline personality disorder or clients who have chronic suicidal behavior. This therapy teaches clients to be aware of their behavior and how to modify it."}, {"id": 11473, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is preparing a community education seminar about abuse and violence in families. Which of the following should the nurse include as an example of physical violence?", "choices": [{"id": "a", "t": "Refusing to pay bills for a dependent, even when funds are available"}, {"id": "b", "t": "Intentionally causing an older adult to fall"}, {"id": "c", "t": "Calling an intimate partner derogatory names"}, {"id": "d", "t": "Failing to provide a stimulating environment for normal development"}], "correct": "b", "rationale": "| 2% Easy Abuse in the family setting can include intimate partner violence, child abuse or neglect, and elder abuse. It refers to intentional acts or Cc l 3% failures to act that cause harm or creates a risk of harm to one individual by another person who is a caregiver or with whom there is a family . Abuse can be physical, emotional, financial, or the result of neglect. Physical violence is the intentional use of physical force that results in acute or chronic illness, bodily injury, physical pain, functional impairment, distress, or death. It includes striking with an object or weapon, hitting, beating, scratching, biting, choking, suffocation, pushing, shoving, shaking, slapping, kicking, stomping, pinching, and burning.", "whyNot": {"a": "Refusing to pay bills for a dependent is economic maltreatment.", "c": "Calling an intimate partner derogatory names is emotional abuse.", "d": "Failure to provide a stimulating environment for normal development of a child is neglect."}, "keyConcept": "Abuse occurs when a caretaker or someone in a relationship of trust causes harm or increases the risk of harm to an individual through their actions or failure to act and include physical, emotional, or financial abuse or neglect."}, {"id": 11474, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who has illness anxiety disorder. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Frequent visits to multiple mental health professionals"}, {"id": "b", "t": "Obsession with a fictitious defect in physical appearance"}, {"id": "c", "t": "Sudden unexplained paresthesia"}, {"id": "d", "t": "Preoccupation about the perceived severity of physical symptoms."}], "correct": "d", "rationale": "A Hi 16% Moderate Clients who have illness anxiety disorder constantly worry about the presence of a serious illness, even if the results of the client's medical B I Ee tests do not support this concern. cl 1%", "whyNot": {"a": "Clients who have illness anxiety disorder might be referred to a mental health professional from their primary care provider due to the", "b": "Obsession over a fictitious defect in physical appearance is associated with body dysmorphic disorder.", "c": "Sudden sensory losses that do not have a medical explanation are associated with conversion disorder."}, "keyConcept": "Illness anxiety disorder is a mental disorder that is characterized by a preoccupation with bodily sensations and the development of a serious illness. Manifestations can be absent or innocuous. However, a client who has illness anxiety disorder will remain convinced that a serious illness is present and often go from provider to provider in search of validation."}, {"id": 11475, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "following? O A. The client accepts the need for dietary control. O B. The client agrees to count carbohydrates. O C. The client’s response may reflect a cultural norm. O D. The client is expressing an understanding of the treatment.", "choices": [{"id": "a", "t": "The client accepts the need for dietary control."}, {"id": "b", "t": "The client agrees to count carbohydrates."}, {"id": "c", "t": "The client’s response may reflect a cultural norm."}, {"id": "d", "t": "The client is expressing an understanding of the treatment."}], "correct": "c", "rationale": "Communication and behavior vary within and between cultures. A nurse should be aware that an individual's cultural context influences both verbal and nonverbal miscommunication. A nurse should clarify any misunderstanding by asking the client about specific cultural practices, offering acceptance and respect. Eye contact and personal space are two factors that differ among cultures and may cause confusion. Nurses usually maintain eye contact when speaking with clients, but this may be interpreted as a sign of disrespect or aggression by Asian, American Indian, Indo-Chinese, Arab, and Appalachian clients. Similarly, people from Western cultures generally feel more comfortable with a greater amount of personal space than those in non-Western cultures. Although nodding and smiling may indicate agreement or understanding of a treatment plan by the client, it may also be a simple reflection of an important cultural value of interpersonal harmony. The nurse should not assume that nonverbal behaviors by a client with different cultural background are an indication of understanding, agreement, or acceptance of a particular treatment.", "whyNot": {"a": "Although it is possible that the client accepts the need for dietary control, nonverbal behaviors may simply reflect important cultural", "b": "Nodding and smiling should not be taken as a sign of acquiescence.", "d": "Nodding and smiling are nonverbal behaviors that may only reflect the cultural value placed on interpersonal harmony."}, "keyConcept": "Poor communication in healthcare can result in poor outcomes and decreased satisfaction in both client and caregiver. Communication problems may result from misunderstanding of culturally influenced styles of communication. Use of a respectful tone, low voice, unhurried and caring manner, and attentiveness to the client's attempts to communicate can be helpful in this situation. When caring for a client with an unfamiliar cultural background, the nurse should ask the client about specific cultural behaviors and beliefs."}, {"id": 11476, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "reality? O A.\"Jan’s stuffed dog looks somewhat like my dog, Trixie.\" O B. \"Jan’s dog and my dog could be twins.\" O C.\"I wish Jan hadn’t had my dog stuffed.\" O D.\"I guess Jan needs a dog as much as | do.\"", "choices": [{"id": "a", "t": "Recognition by the client that there is a difference between the stuffed animal and a household pet indicates that the client perceives the B | 3\" reality of the situation."}, {"id": "b", "t": "This statement reflects the client’s continued misperception of reality."}, {"id": "c", "t": "This statement reflects a continued misperception of reality."}, {"id": "d", "t": "This statement is unrelated to the client’s perception or misperception of reality."}], "correct": "a", "rationale": "Recognition by the client that there is a difference between the stuffed animal and a household pet indicates that the client perceives the B | 3\" reality of the situation. c] 3%", "whyNot": {"b": "This statement reflects the client’s continued misperception of reality.", "c": "This statement reflects a continued misperception of reality.", "d": "This statement is unrelated to the client’s perception or misperception of reality."}, "keyConcept": "Delusions are false fixed beliefs detached from reality, culture, and religion. Presentation of facts or appeals to logic and reason do not alter the delusion. Delusions can occur in association with acute illness (delirium), psychosis, dementia, substance use, and mood disorders."}, {"id": 11477, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "An 82-year-old client is admitted with pyelonephritis and agitation. The client appears confused and is disoriented to place and time. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Providing a quiet environment with low lighting"}, {"id": "b", "t": "Providing close one-on-one supervision"}, {"id": "c", "t": "Encouraging the client to maintain adequate fluid intake"}, {"id": "d", "t": "Raising the side rails of the bed"}], "correct": "b", "rationale": "‘i o: Elderly clients who have an acute infectious illness may often become confused or agitated as a result of delirium. Delirium is associated Cc i with acute onset, fluctuating course, and global memory impairment. Level of consciousness is often reduced, and the client may be D | | disoriented. Safety concerns are the nursing priority. The client should be placed in proximity to the nurses’ station. The nurse should provide one-on-one supervision and should reorient the client frequently to the current place, time, and circumstances. Delirium is reversible, but it is important to continue to observe the client and to prevent physical injury.", "whyNot": {"a": "Dim lighting can disorient an older client, particularly one with visual impairment or delirium. The room should be well-lit during daytime", "c": "Ifa client is experiencing delirium, intravenous fluids can be used to replace volume and electrolytes.", "d": "A client with delirium or agitation may climb over bed rails, increasing the risk of fall or injury."}, "keyConcept": "Delirium refers to acute onset of confusion, agitation, and cognitive impairment. It can occur as a result of an infectious disease or onset of another systemic disorder. Elderly clients are more likely to experience delirium, which places them at risk of falls and other injuries. Safety is the nursing priority. In addition to administering prescribed treatment for the underlying illness, the nurse should reorient the client frequently and provide close supervision."}, {"id": 11478, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client with a new diagnosis of panic disorder. Which of the following symptoms should the client expect between attacks?", "choices": [{"id": "a", "t": "Belief that the client’s thoughts will influence outcomes"}, {"id": "b", "t": "Fear of another attack"}, {"id": "c", "t": "Severe anxiety"}, {"id": "d", "t": "Fear of leaving the house"}], "correct": "b", "rationale": "al o: Individuals with panic disorder have discrete episodes of incapacitating anxiety (panic attacks) that usually last for 15-30 minutes. Panic Cc | attacks have a rapid onset and escalation, causing significant emotional and physical discomfort. The disorder can be diagnosed when the D | client has recurrent panic attacks separated by at least 1 month of persistent worry about a future attack or a significant related behavioral change. During a panic attack, the individual will not be able to think rationally and will benefit from reassurance that the distressing physical and emotional symptoms will resolve and will not result in death or collapse. Panic attacks can be treated with SSRI antidepressants and cognitive behavioral therapy.", "whyNot": {"a": "Belief by a client that his or her thoughts will influence or control outcomes is a characteristic associated with obsessive-compulsive", "c": "Individuals with panic disorder are more likely to fear another attack than experience generalized anxiety. The fear of another attack", "d": "Fear of leaving the home is a characteristic of agoraphobia (“fear of the marketplace”)."}, "keyConcept": "Panic disorder is one variant of the spectrum of anxiety disorders. The attacks are discrete, but incapacitating, with rapid onset and escalation. Between attacks, clients with panic disorder will experience persistent worry about a future attack or may change behavior significantly to avoid onset of another attack."}, {"id": 11479, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who has been hospitalized for 8 days. The client is crying and expresses feelings of guilt for being in the hospital. Which of the following is the most appropriate intervention by the nurse?", "choices": [{"id": "a", "t": "Call the healthcare provider for medication to relieve her anxiety"}, {"id": "b", "t": "Call for a consult from the chaplain"}, {"id": "c", "t": "Reassure the client that she has no reason to feel guilty"}, {"id": "d", "t": "Ask the client to talk about her feelings of guilt"}], "correct": "d", "rationale": ". This should not be deferred to a . The most therapeutic intervention is to ask the client open-ended questions about her feelings of guilt. At this point, the client does not need to be medicated; she simply needs someone to actively listen to her feelings and c | 4% concerns. The nurse should not attempt to reassure the client that she has no reason to feel guilty; the nurse should demonstrate acceptance @ 's feelings.", "whyNot": {"a": "Medication is not necessary in this situation; the nurse should help the client to talk about her feelings of guilt.", "b": "A chaplain may be helpful, but it is also the nurse’s responsibility to address the client's thoughts and emotions.", "c": "This response is not necessarily helpful and does invite the client to talk about her feelings."}, "keyConcept": "A nurse should avoid asking “why” questions except when asking simple questions that relate directly to client care. The nurse can offer more assistance if she assists the client to describe his/her feelings. There are two types of questions the nurse can ask to obtain information: closed and open questions. A closed question is phrased so that a yes or no answer is the response or so that a specific choice of answers is given within the questions, e.g. “Do you want your lunch now or in an hour?” Although this type of question does not encourage the client to explore feelings or concerns, it can be useful to elicit specific information needed to assist the client. Open questions let the client provide his/her own answers. Words such as “who”, “what”, “when”, and “where” elicit factual information and help the client describe emotions, concerns, and experiences."}, {"id": 11480, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is providing information about planned treatment to a client who is of Japanese descent. The client nods and smiles throughout the discussion. The nurse should interpret this as which of the following?", "choices": [{"id": "a", "t": "Client understanding of the procedure"}, {"id": "b", "t": "Reflection of the client’s culture"}, {"id": "c", "t": "Agreement to the planned procedure"}, {"id": "d", "t": "Acceptance of the healthcare provider's advice"}], "correct": "b", "rationale": "Moderate Correct Answer: B. Reflection of the client’s culture eo |__| tik Nurses should be culturally aware of norms and beliefs that affect clients’ communication. Nonverbal communication norms unfamiliar in c | 3% our society may have important significance in non-Western cultures. In this case, failure to recognize the client’s cultural context may result my I a in misunderstanding. In Japanese culture, the behavior described in considered polite and respectful, and the nurse should not mistake the behavior as affirmation or understanding.", "whyNot": {"a": "Japanese culture emphasizes tact and politeness. Nodding may signify validation of the speaker, not understanding of the procedure.", "c": "Nodding and smiling is a sign of validation and respect for the nurse, not a sign of agreement.", "d": "Nodding and smiling do not indicate a decision by the client but is intended to provide respectful acknowledgment of the speaker."}, "keyConcept": "Non-verbal communication may be misinterpreted by a nurse who is not familiar with cultural differences that affect client behaviors and responses. In some Asian cultures, nodding and smiling while listening to a nurse or healthcare provider may be meant only to convey respect, not to indicate understanding or assent."}, {"id": 11481, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A client reports a 6-week history of depression with somnolence, fatigue, and weight gain. Which of the following medical illnesses is a cause of depression?", "choices": [{"id": "a", "t": "Inflammatory bowel disease"}, {"id": "b", "t": "Pernicious anemia"}, {"id": "c", "t": "Hypothyroidism"}, {"id": "d", "t": "Diabetes type 2"}], "correct": "c", "rationale": "all 6% Easy Hypothyroidism can result in symptoms associated with depression or can coexist with major depressive disorder. Hypothyroidism is B I Ee characterized by weight gain, cold intolerance, fatigue, bradycardia, depressions, memory loss, constipation, dry skin and thin brittle hair, arthralgia (joint pain) and myalgia (muscle pain), and menstrual irregularity. A goiter may be present. ec St 78% off 10%", "whyNot": {"a": "Inflammatory bowel disease is not characterized by depression.", "b": "Individuals with pernicious anemia may have peripheral neuropathy, but the disorder is not associated with depression.", "d": "Type 2 diabetes mellitus is not a cause of depression."}, "keyConcept": "Depression is a common complication of chronic illness. Up to one-third of individuals with a serious medical condition experience symptoms of depression. Some medical conditions, however, result in physiological changes consistent with depression, including hypothyroidism."}, {"id": 11482, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "to work. This is an example of which of the following?", "choices": [{"id": "a", "t": "Relapse"}, {"id": "b", "t": "Healthy coping"}, {"id": "c", "t": "Codependent behavior"}, {"id": "d", "t": "Denial"}], "correct": "c", "rationale": "A Co-dependence is a type of behavior commonly identified in family members or significant others of a person with a substance use disorder. i B The person who acts in a codependent manner feels overly responsible, and subsequent actions help (enable) the dependent person hide | the disorder, delaying the likelihood that the individual will seek help. ec | om", "whyNot": {"a": "Relapse refers to a return to using a mind- or mood-altering substance by an individual who has been treated for substance use disorder.", "b": "Although codependent behavior is a mechanism used by the codependent person to cope with the external problems that arise as a result", "d": "Denial is the failure to acknowledge that a problem exists. In this instance, the codependent person is aware of the client's problem but"}, "keyConcept": "Co-dependence is a pattern of behavior by a family member or significant other in a relationship with an individual with substance use disorder that enables the person with SUD to continue their substance use and avoid seeking help. Codependence is characterized by covering up or making excuses to employers and others to prevent discovery of the individual's substance use disorder."}, {"id": 11483, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "nurse prioritize when caring for this client?", "choices": [{"id": "a", "t": "Turn the client frequently to reduce the risk of pressure ulcer formation"}, {"id": "b", "t": "Help the client explore emotions about the condition"}, {"id": "c", "t": "Ask the client to participate in healthcare decisions"}, {"id": "d", "t": "Distract the client with conversation to avoid self-pity"}], "correct": "b", "rationale": "A Any degree of paralysis will have a profound effect on the client’s self-image. The priority nursing task should be to offer this client an OB —— opportunity to explore his feelings and concerns. A wide variety of feelings can occur when a client is undergoing a dramatic change in self- image and concerns about an ongoing role in family, work, and other spheres of life. © | >|", "whyNot": {"a": "Although it is important to prevent the formation of pressure ulcers and contractures in a client with paralysis of any degree, this does not", "c": "Itis important to ask the client to participate in healthcare decisions, but this does not address the client’s current concern.", "d": "An attempt to distract the client invalidates the client’s feelings and does not allow the nurse to address the current concern by"}, "keyConcept": "Impairment in movement or mobility can be transient, recurring or permanent. Immobility may occur in conditions such as stroke, leg fracture, multiple sclerosis, trauma, and morbid obesity. A sense of helplessness and impaired self image often result. Acceptance of limitations varies among individuals. The nurse should offer the client an opportunity explore feelings and concerns related to impaired mobility."}, {"id": 11484, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "health risk of heroin use? O A. Dental problems O B. Slowed breathing O C. Nasal septum perforation O D. Permanent short-term memory loss", "choices": [{"id": "a", "t": "Dental problems"}, {"id": "b", "t": "Slowed breathing"}, {"id": "c", "t": "Nasal septum perforation"}, {"id": "d", "t": "Permanent short-term memory loss"}], "correct": "b", "rationale": "Slowed or arrested breathing is one of the physical complications related to heroin use. Others include drowsiness, impaired coordination, nausea, and sedation.", "whyNot": {"a": "Dental problems is a physical complication related to methamphetamine use.", "c": "Perforation of the nasal septum is a physical complication related to intranasal cocaine use.", "d": "Permanent short-term memory loss is a physical complication related to marijuana use."}, "keyConcept": "Physical complications related to heroin use can include slowed respirations and breathing, euphoria, drowsiness, feeling of body heaviness, dizziness, impaired coordination, sedation, and nausea."}, {"id": 11485, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "following characterizes the client’s statement?", "choices": [{"id": "a", "t": "Rationalization"}, {"id": "b", "t": "Denial"}, {"id": "c", "t": "Projection"}, {"id": "d", "t": "Identification"}], "correct": "b", "rationale": "Denial is a defense mechanism characterized by refusal to admit a reality that causes extreme anxiety or stress. Individuals who use denial as a mechanism for coping will completely ignore the existence of painful situations or realities.", "whyNot": {"a": "Rationalization is a defense mechanism characterized by justifying an unreasonable situation or action by developing an alternative", "c": "Projection is a defense mechanism characterized by transferring internal feelings and thoughts that are unacceptable to someone else.", "d": "Identification refers to an individual who is unconsciously trying to change to resemble someone the individual admires."}, "keyConcept": "Denial is a defense mechanism characterized by ignoring or refusing to accept unpleasant realities in order to cope. This allows the client to delay acknowledgment of unpleasant realities and reduces anxiety. Defense mechanisms are automatic coping styles that can be healthy or maladaptive. Healthy defense mechanisms allow individuals to reduce anxiety in order to achieve goals. Determination of whether a defense mechanism is adaptive or maladaptive includes consideration of the frequency, intensity, and duration of its use. Unhealthy defense mechanisms are overused and may reflect an immature coping style."}, {"id": 11486, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "following should she also expect while assessing this client?", "choices": [{"id": "a", "t": "Disorientation"}, {"id": "b", "t": "Low self-esteem"}, {"id": "c", "t": "Delayed physical development."}, {"id": "d", "t": "Delayed intellectual development"}], "correct": "b", "rationale": "‘i oo Attention deficit hyperactivity disorder is characterized by impulsiveness, inattention, and hyperactivity. This manifests in the client as Cc l restlessness, excessive talking, difficulty remaining seated, and interruptions while others are talking. ADHD causes a reduced ability to D | maintain concentration and focus. Children with ADHD are easily distracted and often fail to follow through on homework or chores. As a result of these characteristics, the client may have significant difficulty interacting with others in school or other venues. This can result in academic failure or job difficulties later. They frequently receive criticism from teachers, other adults, and peers, sometimes resulting in rejection and low self-esteem. Other negative consequences include an increased risk of mental illness (such as anxiety or depression) and increased risk of substance abuse.", "whyNot": {"a": "Disorientation is not associated with ADHD. It can be associated with disorders that include delirium or intoxication.", "c": "Delayed physical development is not a feature of ADHD.", "d": "Children with ADHD have developmental variations across the normal range for their age of development, as well as giftedness and"}, "keyConcept": "Attention deficit hyperactivity disorder is characterized by impulsiveness, inattention, and hyperactivity. This manifests in the client as restlessness, excessive talking, difficulty remaining seated, and interruptions while others are talking. To make the diagnosis in a child, the symptoms must be present before the age of 12, in at least two settings (home, school, etc.) Stimulant medications are the first line of treatment for ADHD."}, {"id": 11487, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a hospitalized client with schizophrenia who appears upset and states, “The voices are telling me | am in trouble.” Which of the following is the most appropriate response by the nurse?", "choices": [{"id": "a", "t": "“Don’t listen to those voices; they are not real.”"}, {"id": "b", "t": "“What are the voices saying to you?”"}, {"id": "c", "t": "“I. can ask your healthcare provider for medication to help you calm down.”"}, {"id": "d", "t": "“Tell the voices they are not real and watch some television in the dayroom.”"}], "correct": "b", "rationale": "all 7% Easy This client is experiencing auditory hallucinations, which are common in psychosis. Hallucinations are false perceptions that are Cc l 3% experienced without external stimuli. They may involve auditory, visual, tactile, gustatory (taste), or olfactory (smell) sensation. The D l 3% hallucinations cause distress and may lead the client to harm himself/herself or others. The nurse should ask the client to describe the hallucinations. After exploring the content of the hallucinations, the nurse may identify a need for intervention to prevent harm to the client or others. Determining the potential for violence is the priority action by the nurse. The nurse should validate the reality of the hallucinations to the client while explaining that others do not experience the same voices (or other types of hallucination). The nurse should not challenge the reality of the hallucinations perceived by the client, but can remind the client that they occur as a result of the illness. It is helpful to guide the client to an activity or conversation based in reality.", "whyNot": {"a": "The nurse should not challenge the hallucinations, as the client’s experience feels real, and arguing or dismissal could escalate the client’s", "c": "After assessing the client’s level of distress, the nurse can better determine if a sedative medication is needed.", "d": "Ignoring the voices, stating that they are not real, or telling them to go away may be helpful for some clients, but this is not the priority"}, "keyConcept": "When a client experiencing hallucinations appears upset, the nurse should first assess the potential for violence or self-harm. The nurse should encourage the client to describe the content of the hallucination to determine if there is a need for intervention."}, {"id": 11488, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "the nurse's teaching? O A.\"Family members should not acknowledge their negative feelings about the client’s disease.\" O B. \"The client should limit alcohol intake to no more than 4 drinks per week.\" O C. \"Family members should accept responsibility for their role in the client’s addiction.\" O D. \"The family of the client is not responsible for the client's disease but are responsible for their recovery.\"", "choices": [{"id": "a", "t": "Family members should express and explore their feelings and problems. Mutual aid groups like Al-Anon, individual therapy, or family"}, {"id": "b", "t": "Abstinence from mood-altering substances is recommended for clients in recovery."}, {"id": "c", "t": "Family members cannot be blamed for the client’s disease, but they should explore their feelings and problems."}, {"id": "d", "t": "‘i | When providing teaching to a family about what to expect when a family member returns home after discharge from a drug or alcohol c | treatment facility, the nurse should encourage the family to attend family therapy or a mutual support group such as Al-Anon."}], "correct": "d", "rationale": "‘i | When providing teaching to a family about what to expect when a family member returns home after discharge from a drug or alcohol c | treatment facility, the nurse should encourage the family to attend family therapy or a mutual support group such as Al-Anon. Family e@D | members should acknowledge that they are not responsible for the client’s disease, but they should confront their own issues, including feelings and problems associated with the client and the disease.", "whyNot": {"a": "Family members should express and explore their feelings and problems. Mutual aid groups like Al-Anon, individual therapy, or family", "b": "Abstinence from all mood-altering substances is recommended for clients in recovery.", "c": "Family members cannot be blamed for the client’s disease, but they should explore their feelings and problems."}, "keyConcept": "Family members of individuals treated for substance use disorder frequently benefit from attendance at family therapy or mutual support groups such as Al-Anon. The nurse should provide information about resources for family members, who often have unresolved feelings or problems associated with the client's substance use."}, {"id": 11489, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is providing discharge education to a client who is not fluent in English. What should the nurse do to ensure the client understands the teaching ?", "choices": [{"id": "a", "t": "Stand closely, facing the client, and speak loudly"}, {"id": "b", "t": "Speak very slowly and loudly with good enunciation"}, {"id": "c", "t": "Ensure a family member is present when providing teaching"}, {"id": "d", "t": "Call for an interpreter to ensure the client can understand important instructions"}], "correct": "d", "rationale": "| 2% The ideal solution when a client does not speak or understand the local language is to arrange for an interpreter. c | 2%", "whyNot": {"a": "&B. Increased volume, facing the client, or using slow speech are all ineffective if the client does not understand the language spoken.", "c": "Gathering family members can potentially violate the client’s privacy. Even if the client agrees to have family present, it is not an adequate"}, "keyConcept": "The basic tenants of client rights are the same in any healthcare setting, regardless of the client's age or needs. Each client has the right to the be informed about all aspects of care and participate actively in the decision-making process. When caring for a client who is not fluent in the prevailing language, the nurse should arrange for an interpreter when possible. Use of a family member as interpreter is not ideal, since the client's privacy rights may not be protected. Use of a professional translator can provide greater assurance that the client understands important healthcare information."}, {"id": 11490, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "at a table with the client, who had been sitting alone and staring at the wall. Which action is the most appropriate for the nurse?", "choices": [{"id": "a", "t": "Allow the client to leave without commenting."}, {"id": "b", "t": "Tell the client it is important for recovery to talk to others."}, {"id": "c", "t": "Tell the client clearly and loudly that he must return to the room."}, {"id": "d", "t": "Follow the client until he returns to his room."}], "correct": "a", "rationale": "o; Schizophrenia is a major psychiatric disorder that is characterized by at least 1 psychotic (positive) symptom (hallucination, delusions, B ri disorganized speech), an inability function in daily life and neglect of basic needs. The diagnosis cannot be made unless the symptoms persists for over 6 months. During a six-month period, individuals may have times when they are not experiencing psychotic symptoms, but c | in those times they tend to be apathetic or depressed, which are negative symptoms of schizophrenia. D || The client in this presentation is demonstrating negative symptoms of schizophrenia, which include social withdrawal, impaired interpersonal function, anhedonia (inability to experience pleasure), poor personal hygiene, lack of motivation, and inability to make decisions. Bizarre posturing, pacing, rocking, and regression are other negative symptoms of schizophrenia. The negative symptoms of schizophrenia are more resistant to successful treatment compared to positive symptoms such as delusional thinking and hallucinations. The negative symptoms associated with social withdrawal result from attempts by the client to relieve the anxiety experienced when around others. When caring for a client with schizophrenia, a nurse can intervene to improve social interaction skills by minimizing demands or expectations. This demonstrates unconditional acceptance of the client by the nurse and creates a therapeutic environment. Other interventions include remaining with the client or nearby during periods of group activities and offering positive reinforcement when the client interacts with others. The nurse should make frequent, brief contacts with the client and assess the client’s readiness for longer periods of contact with others.", "whyNot": {"b": "The nurse should minimize expectations and demands to demonstrate unconditional acceptance.", "c": "This is not a therapeutic approach.", "d": "This may increase the client’s anxiety."}, "keyConcept": "When caring for a client with schizophrenia, a nurse should perform an assessment that includes medical history, mental health assessment, with assessment of positive and negative symptoms; and social history, including spiritual, cultural, biological, physiological, social, and environmental factors. The nurse should use therapeutic communication to establish trust; maximize the client's level of functioning with activities that decrease withdrawal, increase motivation, change unacceptable behaviors, facilitate support and feedback, and increase social competence and self esteem. The nurse should also attempt to evaluate the client's support system."}, {"id": 11491, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "following is the most appropriate course of action?", "choices": [{"id": "a", "t": "The nurse should not respond but signal to other staff members for backup."}, {"id": "b", "t": "The nurse should ask the client how he is feeling."}, {"id": "c", "t": "The nurse should ask the client what he means by “something bad.”"}, {"id": "d", "t": "The nurse should call the healthcare provider to request a sedative."}], "correct": "c", "rationale": "The priority for the nurse in this situation is to assess the client’s risk for violence, so she should ask the client what he means by “something bad is going to happen.” This statement could have multiple meanings that would not necessarily suggest a potential for violence. Asking the client to explain the remark presents an opportunity for therapeutic communication and will also help the nurse determine the next best action to provide care in this situation.", "whyNot": {"a": "The nurse should first assess the client’s risk for violence. If the nurse determines there is a high risk of violence, the nurse can alert other", "b": "Although the client’s feelings should be addressed, it is more important to clarify the meaning of the client’s statement.", "d": "Use of a sedative as a chemical restraint is not appropriate for an initial action. The nurse must assess the client’s risk of violence."}, "keyConcept": "Individuals with schizophrenia, severe depression, or an acute manic episode of bipolar disorder may experience delusions or hallucinations. The priority action when a client appears to be upset by their thoughts or hallucinations is to assess the individual's potential for violence or self-harm. The nurse should try to determine the meaning of unclear remarks by asking the client to explain the remark further. Through use of therapeutic communication techniques, the nurse can gain the client's trust while assessing the need for intervention."}, {"id": 11492, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is monitoring a client who was recently admitted for treatment of heroin abuse. The nurse expects which of the following assessment findings in heroin withdrawal?", "choices": [{"id": "a", "t": "Bradycardia"}, {"id": "b", "t": "Pinpoint pupils"}, {"id": "c", "t": "Respiratory depression"}, {"id": "d", "t": "Diarrhea"}], "correct": "d", "rationale": "A | | 8% Hard si 27% Opioid withdrawal will occur when clients who have used opioids for a long period of time suddenly reduce the dosage or stop the Cc Hi 16% medication. Clients who receive naloxone and are dependent on opioids will also experience withdrawal. Withdrawal is uncomfortable but eD ft 49% not life-threatening. If the client has significant symptoms, medications can ease withdrawal and may be used for maintenance treatment. Symptoms of withdrawal include: + Cardiovascular: hypertension, tachycardia + Gastrointestinal: nausea, vomiting, diarrhea, abdominal cramping, hyperactive bowel sounds a © o 2 ° s a = a < +» Musculoskeletal: myalgia, arthralgia + Autonomic nervous system: rhinorrhea, piloerection, lacrimation, diaphoresis Treatment of opioid dependence or withdrawal can include buprenorphine, a partial opioid agonist that can be prescribed in an office setting, or methadone, which must be prescribed by a physician certified by the Substance Abuse and Mental Health Services Administration (SAMHSA) to dispense opioid dependency treatment. It is an opioid agonist and generally more effective than buprenorphine for heroin addiction. It is generally given once a day in a specialized outpatient clinic.", "whyNot": {"a": "Tachycardia, not bradycardia, is typical of opioid withdrawal.", "b": "Mydriasis, or dilated pupils, is associated with withdrawal. Pinpoint pupils are associated with opioid intoxication or use.", "c": "Respiratory depression is an adverse effect of opioid use."}, "keyConcept": "Signs of withdrawal from opioids include hypertension, tachycardia; nausea, vomiting, and diarrhea; abdominal cramping; bone and joint pain; and rhinorrhea, piloerection, diaphoresis, and lacrimation. Naloxone can induce sudden withdrawal in opioid dependent clients, but"}, {"id": 11493, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is assessing a client who has psychosis and is experiencing a hallucination. The client states, \"| hear a special voice in my head.\" Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Act as if the hallucination is real when interacting with the client."}, {"id": "b", "t": "Instruct the client to argue with the voice. Ask the client direct questions about the hallucination."}, {"id": "c", "t": "Ask the client direct questions about the hallucination."}, {"id": "d", "t": "Avoid making direct eye contact with the client."}], "correct": "c", "rationale": "Asking the client direct questions about the hallucination provides important data to identify the client's risk level and current mental status.", "whyNot": {"a": "Acting as if the hallucination is real will increase the client's difficulty in identifying reality and is, therefore, not an action the nurse should", "b": "Arguing will increase the client's anxiety level and is, therefore, not an action the nurse should take. The nurse should not participate in", "d": "The nurse should make direct eye contact with the client while redirecting the focus onto the conversation. The nurse should call the"}, "keyConcept": "When a client is experiencing a hallucination, the nurse should ask direct questions about the hallucination to determine if the client is hearing, seeing, smelling, or feeling the experience. This also provides the nurse further data about the client's mental status during the hallucination."}, {"id": 11494, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is establishing a therapeutic relationship with a client. Which of the following actions should the nurse take during the orientation phase?", "choices": [{"id": "a", "t": "Prioritize the client's problems."}, {"id": "b", "t": "Encourage the client to use self-exploration."}, {"id": "c", "t": "Review the client's achievement of personal objectives."}, {"id": "d", "t": "Talk with others who have information about the client."}], "correct": "a", "rationale": "During the orientation phase of the therapeutic nurse-client relationship, the nurse should observe the client closely, make inferences about the client's behavior, prioritize problems, and identify the client's goals.", "whyNot": {"b": "Encouraging the client to use self-exploration is a component of the working phase of the therapeutic nurse-client relationship.", "c": "Reviewing the client's achievement of personal objectives is a component of the termination phase of the therapeutic nurse-client", "d": "Talking with others about the client is a component of the preinteraction phase of the therapeutic nurse-client relationship."}, "keyConcept": "The therapeutic nurse-client relationship provides a therapeutic climate in which nurses help clients attain personal health-related goals. Its four distinct phases - preinteraction, orientation, working, and termination - provide a structure for nurses to plan key actions and interactions, with the intention of moving forward in a systemic way."}, {"id": 11495, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "providing further teaching? O A. Provide the client with written instructions that have clear illustrations. O B. Continue to teach and verify the client’s understanding by asking the client to demonstrate the skills conveyed. O C. Remind the client that correct self-administration of insulin is necessary for the client’s health. O D. Try to maintain eye contact while providing teaching by moving with the client’s eye movement.", "choices": [{"id": "a", "t": "Provide the client with written instructions that have clear illustrations."}, {"id": "b", "t": "Continue to teach and verify the client’s understanding by asking the client to demonstrate the skills conveyed."}, {"id": "c", "t": "Remind the client that correct self-administration of insulin is necessary for the client’s health."}, {"id": "d", "t": "Try to maintain eye contact while providing teaching by moving with the client’s eye movement."}], "correct": "b", "rationale": "all 8% Easy Some cultures believe it is disrespectful or rude to make direct eye contact, including some Asian cultures and American Indian cultures. Cc l 3% European cultures and much of American culture view eye contact as a sign of openness and attention. A nurse should be respectful and , which include both verbal and nonverbal communication. The nurse should continue the instruction and verify the client’s understanding by asking the client to demonstrate the teaching in return.", "whyNot": {"a": "This is not a culturally sensitive response and does not allow the nurse to gauge the client’s understanding of the teaching or allow the", "c": "This response assumes that the client doesn’t know that self-administration of insulin is important and may seem disrespectful or", "d": "This action is likely to make the client uncomfortable if the client’s culture believes direct eye contact is rude or disrespectful."}, "keyConcept": "There are different norms among cultures with respect to eye contact, touch, decision-making, compliments, health-beliefs, health-care practices, personal space, modesty, and non-verbal communication. These can vary dramatically between cultures, sub-cultures, and religions. In various Asian, African and Latin American cultures, extended eye contact may be interpreted as rude or as a challenge of authority."}, {"id": 11496, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "appropriate to reduce recurrent hospitalizations and limit the need for crisis interventions for a client with a severe mental illness who has a history of noncompliance with traditional treatment?", "choices": [{"id": "a", "t": "Psychosocial rehabilitation"}, {"id": "b", "t": "Assertive community treatment"}, {"id": "c", "t": "Support group"}, {"id": "d", "t": "Home care"}], "correct": "b", "rationale": "‘i oo Assertive community treatment (ACT) is an evidence-based nontraditional method of case management and treatment by a Cc Hi multidisciplinary team that targets high-risk clients with mental illness, including those who have been noncompliant with traditional D Hi methods treatment for severe mental illness. Resources are available 24 hours a day, 7 days a week; the team helps the individual address issues of employment, housing, medication, and social support in addition to providing therapy for the mental illness. This level of care allows an individual who is able to transfer from an inpatient setting to enjoy a similar level of care while living in a less-restrictive setting. ACT has been shown to reduce hospitalization and crisis intervention by up to 20% more than traditional treatments.", "whyNot": {"a": "Psychosocial rehabilitation programs offer a structured day program with a range of services, including day programs and residential", "c": "This is inadequate. Support groups are comprised of individuals who have similar concerns or conditions and who meet together to", "d": "Home care is generally used to provide mental health assessment and intervention coupled with support in the home of clients who may"}, "keyConcept": "A nurse working on a psychiatric unit or mental health facility should be familiar with the various community-based mental health programs for clients who anticipate discharge into the community. Severe mental illnesses, including schizophrenia and bipolar disorder, type |, make compliance with treatment difficult at times. Assertive community treatment (ACT) is a method of multidisciplinary case management and treatment for clients at high risk of relapse, providing around the clock resources to help clients address multiple medical, social, and economic issues that would otherwise derail treatment."}, {"id": 11497, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "response to his stroke? O A. Location of the lesion O B. Intellectual ability to understand complex health information O C. Quality of nursing care O D. Premorbid coping skills of the client", "choices": [{"id": "a", "t": "Location of the lesion"}, {"id": "b", "t": "Intellectual ability to understand complex health information"}, {"id": "c", "t": "Quality of nursing care"}, {"id": "d", "t": "Premorbid coping skills of the client"}], "correct": "d", "rationale": "5 i 16% The most important factors in an individual’s response to a significant medical condition that may be life-changing are past experiences and Cc | 12% the set of coping mechanisms developed by the client. After any major or life-changing health event or diagnosis, clients may be emotionally eD | 55% labile. Although emotional lability is not unusual, the eventual emotional response to a life-changing illness or injury will depend in a large part on the coping mechanisms possessed by the client.", "whyNot": {"a": "Although the location of a lesion will determine the extent of morbidity, premorbid coping skills are a more important factor. Some", "b": "Emotional response is not a function of intellect. Emotional response to a lesion depends on coping skills and premorbid personality.", "c": "Good nursing care is helpful in improving an individual’s response to illness or injury, but a baseline personality and coping skills are"}, "keyConcept": "Past experiences and coping mechanisms developed as a result are the most important factors influencing an individual's response to significant life changes that result from health conditions. Although good nursing care is important in helping clients adapt to significant life changes, their ability to adapt is influenced primarily by coping mechanisms already in place."}, {"id": 11498, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is participating in a discussion group for clients hospitalized in the psychiatric unit. What is the most appropriate response by the nurse to a client who interrupts the group to accuse them of avoiding her?", "choices": [{"id": "a", "t": "Ask a group member to repeat the group rules."}, {"id": "b", "t": "Explain the client’s circumstances to the rest of the group."}, {"id": "c", "t": "After the group is over, spend some time with the client while allowing her to share her feelings."}, {"id": "d", "t": "Ask group members to offer an apology to the client."}], "correct": "c", "rationale": "Al 15% Easy . Therapeutic communication can ec | 80% be an opportunity for the nurse to encourage and support the client and will help build trust between the client and the nurse.", "whyNot": {"a": "This response would not take the client’s feelings into account and offers no opportunity for the client to share her fears and concerns. A", "b": "The nurse cannot discuss a client’s circumstances or illness with anyone not designated by the client. To do so would be a violation of the", "d": "There is no indication that the group has anything for which to apologize, so this is not an appropriate response."}, "keyConcept": "Clients who are in distress may express their anxieties or fears through their interactions with staff and other clients. The nurse should provide a therapeutic environment in which the client can openly express feelings while accepted and supported by the nurse."}, {"id": 11499, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "following is the next step in managing this patient?", "choices": [{"id": "a", "t": "File a report with CPS."}, {"id": "b", "t": "Assess caregiver interactions with the child. © c.admitthe child to the hospital."}, {"id": "d", "t": "Contact another family member."}], "correct": "b", "rationale": "f is chi i q . ra . Healthcare providers must be aware of the physical and behavioral indicators of child abuse and neglect. Neglect is the failure of a parent or other individual responsible for the child's welfare to meet the child's basic eB | 57% needs and provide an adequate care level. Neglect can be physical, emotional, educational, or medical. Common factors in child neglect © | 7% include lack of knowledge of the child's needs, lack of resources, and caregiver substance abuse. D 0% The priority when neglect is suspected is an assessment of the caregiver's interactions with the child. The healthcare provider should initiate a discussion with the caregivers that encompasses all concerns, which should then be prioritized and addressed. The formation of a multidisciplinary team can be helpful.", "whyNot": {"a": "All 50 states have laws for mandatory reporting of suspected child abuse and neglect, but the priority is to address the specific concerns", "d": "If corroboration is needed, the parents will have to consent to release medical information, or the case would be referred to Child"}, "keyConcept": "Child neglect is the most common form of child maltreatment. Common factors contributing to child neglect include lack of knowledge of the child's needs, lack of resources, and caregiver substance abuse. Providers should assess the interaction between the caregiver and the child and assess the child's weight, height, nutritional status, and hygiene."}, {"id": 11500, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "the nurse? O A. “The ultrasound technician should not have commented on your study. Your doctor will review the study.” O B. “There are many treatments available. Your healthcare provider can help you decide on the best option.” O C. “You are upset about what happened in ultrasound. Let’s talk about it.” O D. “You should report the technician to the hospital administration.”", "choices": [{"id": "a", "t": "“The ultrasound technician should not have commented on your study. Your doctor will review the study.”"}, {"id": "b", "t": "“There are many treatments available. Your healthcare provider can help you decide on the best option.”"}, {"id": "c", "t": "“You are upset about what happened in ultrasound. Let’s talk about it.”"}, {"id": "d", "t": "“You should report the technician to the hospital administration.”"}], "correct": "c", "rationale": "im | 20% Easy , and the nurse can take the opportunity to show empathy and concern by a therapeutic response. This will allow the ec FY 77% client to discuss fears and emotions while the nurse offers support and empathy. The interpersonal relationship between the nurse and , which is important particularly when clients are coping with difficult diagnoses or conditions.", "whyNot": {"a": "Although this statement is true, it does not give the client an opportunity to address feelings and concerns that can be overwhelming", "b": "This statement may be true, but it does not establish a therapeutic level of communication to allow the client to express feelings or", "d": "The nurse should act as the patient’s advocate while considering the chain of command. Although the nurse may report this to her"}, "keyConcept": "An open-ended question by the nurse can provide an opening for an upset client to discuss fears and emotions. The nurse can offer support and encouragement, which further builds a relationship of trust between the client and nurse."}, {"id": 11501, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "Which of the following is the most appropriate way to avert a developmental crisis?", "choices": [{"id": "a", "t": "Milieu therapy"}, {"id": "b", "t": "Electroconvulsive therapy (ECT)"}, {"id": "c", "t": "Anticipatory guidance"}, {"id": "d", "t": "Group therapy"}], "correct": "c", "rationale": "A || 24% Moderate Developmental crises arise in the course of life as changes occur that can become stressful and overwhelming. An example of a B | a0 developmental crisis is a new mother adjusting to caring for the demands of her baby and the change in her identity. Anticipatory guidance, which involves education about normal life stages, can prevent or prepare clients for developmental crises. ec | 66% off 8%", "whyNot": {"a": "The client would most benefit from anticipatory guidance, not milieu therapy.", "b": "Electroconvulsive therapy is not an appropriate option in this case.", "d": "Group therapy may help with some teaching, but anticipatory guidance is more effective in averting a developmental crisis."}, "keyConcept": "Erikson viewed personality development as a succession of phases that are each qualitatively different from previous phases. A crisis is a period of cognitive and affective upset that occurs between one phase and the next. A crisis is a period of disequilibrium and decreased functioning that occurs as a result of an event or situation for which the individual's familiar coping strategies are inadequate. Anticipatory guidance is an effective intervention to avoid or to reduce the severity of a developmental crisis. Anticipatory guidance is helpful in advance of major transitions, developmental crises, and other predictable periods of difficulty."}, {"id": 11502, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "identify as the cause of Wernicke-Korsakoff syndrome?", "choices": [{"id": "a", "t": "Alcohol"}, {"id": "b", "t": "Caffeine"}, {"id": "c", "t": "Cocaine"}, {"id": "d", "t": "Hallucinogens"}], "correct": "a", "rationale": "Chronic alcohol use disorder has many systemic effects. In the central nervous system, it can cause Wernicke-Korsakoff syndrome, a form of B | encephalopathy and psychosis. This is actually two disorders that often occur in tandem with different manifestations. D Wernicke’ Korsakoff | cephalopat syndrome diplopia, visual confusion, disturbances memory loss confabulation", "whyNot": {"b": "Chronic ingestion of caffeine can result in gastrointestinal upset and cardiac arrhythmias if excessive amounts are consumed. Withdrawal", "c": "Cocaine use can result in many physical and psychological complications. Physical manifestations include cardiac arrhythmias,", "d": "The use of hallucinogens has been associated with cognitive alterations including flashbacks, psychosis, and delirium. They can also"}, "keyConcept": null}, {"id": 11503, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "understanding of the teaching? O A. \"| will administer prophylactic treatment for sexually transmitted infections like chlamydia.\" O B. \"I should witness the client's informed consent after the nurse examiner collects forensic evidence.\" O C.\"I will seal each item of the client's clothing in plastic biohazard bags.\" O D.\"I should ask the client to shower before the forensic examination is done.\"", "choices": [{"id": "a", "t": "\" will administer prophylactic treatment for sexually transmitted infections like chlamydia.\""}, {"id": "b", "t": "\"I should witness the client's informed consent after the nurse examiner collects forensic evidence.\" O C.\"I will seal each item of the client's clothing in plastic biohazard bags.\" O D.\"I should ask the client to shower before the forensic examination is done.\""}], "correct": "a", "rationale": "o In many facilities, a specifically trained Sexual Assault Nurse Examiner (SANE) is available to perform the specific assessments and treatment B needed by the client who has experienced sexual assault. If a specifically trained professional is not available, the nurse must be prepared to a perform or assist with the physical and forensic examination. The client should not be left alone. The forensic examination includes a c mz complete physical and emotional examination, including a genital exam. Evidence, such as preserving hair, nail scrapings, and swabs of the D genital and other body areas, must be collected according to specific guidelines. The nurse will complete written and photographic documentation of the findings. The client should be given information about risk for manifestations of sexually transmitted diseases. The nurse should administer prescribed prophylactic treatment for infections such as chlamydia, according to the Centers for Disease Control and Prevention. Antibiotics are likely to be prescribed to prevent syphilis, chlamydia, and gonorrhea. For clients who could become pregnant, an emergency contraceptive medication might be prescribed.", "whyNot": {"b": "The nurse must witness the client's informed consent before collecting data that can be used as legal evidence. The client should be given"}, "keyConcept": "If a specifically trained sexual assault nurse is not available to care for a client who experienced sexual assault, the nurse should carefully follow facility forensic protocols and other procedures to assess the client. The nurse should actively listen to the client and should provide privacy and support during the assessment. The nurse should ensure that the client is offered counseling services and other follow-up care before discharge."}, {"id": 11504, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is assigned care of a client with bipolar mania who has been disrupting the floor. Which of the following should the nurse do first before administering care to this client?", "choices": [{"id": "a", "t": "Talk with the client’s family members"}, {"id": "b", "t": "Identify the client’s emotional needs and conflicts"}, {"id": "c", "t": "Recognize personal feelings about caring for the client"}, {"id": "d", "t": "Discuss the problematic behavior with the client’s healthcare provider"}], "correct": "c", "rationale": "A o When caring for a client, it is always important for a nurse to identify personal feelings or prejudices that could impact the nurse’s ec | assessment and care. This should be the initial priority for the nurse, particularly in a situation where care may be rendered more difficult by D | aclient’s pathology.", "whyNot": {"a": "Itis important to gain insight from family members and significant others. But, before doing so, the nurse should identify any personal", "b": "Identification of the client’s needs is important, but it is initially most important for the nurse to identify personal beliefs and emotions", "d": "Although problematic behaviors should be brought to the attention of the healthcare provider, the nurse should initially examine his or"}, "keyConcept": "When caring for difficult clients, the nurse should identify personal feelings or prejudices that may impact care. This should be a priority since lack of objectivity can interfere with the nurse's assessment and care."}, {"id": 11505, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "business trip, my spouse might have died. I'm in a state of shock.”?", "choices": [{"id": "a", "t": "“It is a good thing that you shortened your trip. Now, you can help your spouse recover.”"}, {"id": "b", "t": "“This is a very overwhelming situation for you. Can you tell me what you are feeling now?”"}, {"id": "c", "t": "“Can you calla friend or relative for support during this crisis?”"}, {"id": "d", "t": "“Did you realize your spouse was depressed?”"}], "correct": "b", "rationale": "Correct Answer: B. “This is a very overwhelming situation for you. Can you tell me what you are feeling now?” Finding a spouse or family member who has attempted suicide is overwhelming for most individuals, and they may respond with denial, anger, numbness, shock, confusion, helplessness, or disbelief. Some individuals exhibit physical manifestations as a result of the traumatic event, including dizziness, palpitations, and hyperventilation. It is most important for the nurse to respond in a way that addresses and acknowledges the spouse’s feelings and their appropriateness in light of the impact of the event. By allowing the spouse to identify and express these feelings, the nurse can facilitate relief of some of the immediate emotional distress caused by the incident.", "whyNot": {"a": "This statement could be interpreted by the spouse as judgmental, implying that the spouse should bear responsibility for the suicide", "c": "Although it will be important to address the support system available to the spouse and the client, it is not the immediate nursing priority.", "d": "Although the nurse should assess the client’s recent history at a later point, this is not the appropriate time. This response does not"}, "keyConcept": "Family members of a client who has attempted suicide often experience overwhelming emotions, including denial, shock, confusion, anger, and helplessness. Physical manifestations include palpitations, dizziness, and hyperventilation. The nurse should encourage them to explore these feelings and provide acceptance and support."}, {"id": 11506, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "you have to do this.” Which of the following is the best response by the nurse?", "choices": [{"id": "a", "t": "“This is just a part of nursing, and have seen much worse.”"}, {"id": "b", "t": "“It doesn’t bother me at .”"}, {"id": "c", "t": "“You are upset. Can you tell me about that?”"}, {"id": "d", "t": "“This is my job.”"}], "correct": "c", "rationale": "al 2% Easy 38 8% This nursing response is therapeutic and allows the client to verbalize any negative emotions about the current procedure. It does not ec | 89% negate the client’s feelings and provides an opportunity for the nurse to understand those feelings and offer support.", "whyNot": {"a": "This response is wrong because it identifies the client’s condition as “bad” compared to “worse.” It also doesn’t provide an opportunity for", "b": "This response is centered around the nurse and doesn’t address the client’s anxiety.", "d": "This response is also centered around the nurse. It fails to allow the client to address negative thoughts and feelings."}, "keyConcept": "Clients experience a variety of emotions when dealing with medical conditions and impairment. The nurse should provide acceptance and support, while allowing the client to express and explore these emotions."}, {"id": 11507, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse caring for a client with opioid dependence is speaking with the client’s spouse. Which of the following statements suggests codependent behavior?", "choices": [{"id": "a", "t": "“A group like Al-Anon can be a helpful forum to discuss what I’m going through.”"}, {"id": "b", "t": "“I am not responsible for my spouse’s dependence on opioids.”"}, {"id": "c", "t": "“I should have made my spouse happier so this wouldn’t have happened. will do better.”"}, {"id": "d", "t": "“lam going to focus on my job, as have missed work due to this crisis.”"}], "correct": "c", "rationale": "all 6% Easy ce | 5% Codependency occurs when the codependent person puts the needs of the addict before their own needs, allowing the person with the ec fs 85% addiction to avoid the consequences of their behavior. This includes making excuses for the client when the client misses work, gets into , or neglects family responsibilities. This statement suggests the spouse has taken responsibility for the client’s addiction and will focus on the client’s needs while ignoring his/her own. Other codependent behaviors include calling the addicted person’s place of employment to make excuses when he/she misses work, keeping the behavior secret from other friends and family, and allowing continued psychological or physical abuse.", "whyNot": {"a": "Al-Anon is a mutual help group formed by family members of those who have substance use disorders. It can be helpful to many to talk", "b": "This is a healthy statement. While family counseling is helpful in many cases, substance dependence is an illness, and the spouse should", "d": "This is a healthy statement that shows the spouse is focusing on personal needs and not on the needs of the client."}, "keyConcept": "Codependent behavior in a relationship is characterized by one person putting the needs of the other before their own needs in order to protect the other individual from consequences of their behavior. The codependent person may lie, make excuses, or cover up behaviors, which only serves to prolong the negative behavior of the other person. Codependent behavior often enables clients who have a substance or alcohol use disorder to avoid acknowledging their disorder."}, {"id": 11508, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "Which of the following pediatric clients would require prompt reporting to the authorities by the nurse?", "choices": [{"id": "a", "t": "A4-year-old who fell from a swing set with 1 fracture of the ulna and 2 healed fractures of the humerus on X-ray"}, {"id": "b", "t": "A3-year-old with second-degree burns on the upper chest and face after pulling a pot of hot water from the stove"}, {"id": "c", "t": "A3-year-old who has a large hematoma on the forehead after falling from a slide"}, {"id": "d", "t": "A 2-year-old with swelling of the tongue and drooling after eating a plant in the yard"}], "correct": "a", "rationale": "Moderate Correct Answer: A. A 4-year-old who fell from a swing set with 1 fracture of the ulna and 2 healed fractures of the humerus on X-ray OA Le ust 8 13% A nurse must be aware of signs associated with abuse and nonaccidental trauma. The following signs are consistent with abuse: c | 2% + Linear burns (immersion burns) D i 9% + Burns in the shape of common household items + Cigarette burns + Tears of the frenulum or gingiva + Retinal hemorrhage on funduscopic exam a © o 2 ° s a = a < + Multiple fractures, bruises, or burns in various stages of healing + Long bone fractures of the humerus or femur + Subdural or epidural hematoma resulting from coup-contrecoup injury + Inconsistencies between the pattern of injury and the explanation given by caregiver + Delay between the time of the injury and time care is sought This client has multiple fractures in various stages of healing, with a long bone fracture of the humerus.", "whyNot": {"b": "Immersion burns are typical of child abuse. Children are often injured accidentally when pulling items from the stove or counter. In this", "c": "The nurse should provide safety information to the caregivers at discharge to reduce the risk of future injury. This injury matches the", "d": "Young children often consume foreign objects, including plants and household items that may be toxic. The nurse should provide safety"}, "keyConcept": null}, {"id": 11509, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "the client, smiling widely, states, “Oh, my mother-in-law is so reassuring. She can always calm me down.” What type of defense mechanism is the client most likely demonstrating?", "choices": [{"id": "a", "t": "Regression"}, {"id": "b", "t": "Reaction formation"}, {"id": "c", "t": "Displacement"}, {"id": "d", "t": "Altruism"}], "correct": "b", "rationale": "All o: Reaction formation is a defense mechanism used to manage the individual’s response to anxiety and stress by demonstrating a behavior Cc Hl opposite to the the client's feelings. This defense mechanism may be preventing the client from confronting reality or improving the D Hi relationship. When a defense mechanism interferes with healthy behaviors, it becomes maladaptive.", "whyNot": {"a": "Regression refers to a return to an earlier, childlike behavior in response to stress or conflict.", "c": "Displacement occurs when an individual transfers strong feelings about a person, situation, or object to a less-threatening person, object,", "d": "Altruism is an adaptive defense mechanism. It is characterized by channeling strong or unpleasant feelings into good works for others."}, "keyConcept": "Individuals often deal with stressors by using coping mechanisms. These coping mechanisms can become maladaptive when they prevent the client from acknowledging and constructively confronting a stressful situation or relationship. Reaction formation is characterized by demonstration of behaviors or remarks that express the opposite of what the client appears to be feeling."}, {"id": 11510, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is conducting discharge teaching about a relapse plan with a client who has psychosis. Which of the following statements should the nurse make? O A.\"You should be aware that excessive sleeping is an early sign of relapse.\" O B. \"Relapse is an indication that you are not taking your medications properly.\" O C. \"You should keep your provider's and therapist's telephone numbers with you.\" O D. \"Discontinue your medication as soon as signs of relapse appear.”", "choices": [{"id": "a", "t": "Difficulty sleeping, not excessive sleeping, is an early sign of relapse."}, {"id": "b", "t": "Relapse can occur for several reasons and does not indicate failure on the client's part."}, {"id": "c", "t": "The client should have a written plan, which includes important telephone numbers, available in case relapse occurs."}, {"id": "d", "t": "The client should not change the dosage of medication without a prescription from the provider."}], "correct": "c", "rationale": "The client should have a written plan, which includes important telephone numbers, available in case relapse occurs.", "whyNot": {"a": "Difficulty sleeping, not excessive sleeping, is an early sign of relapse.", "b": "Relapse can occur for several reasons and does not indicate failure on the client's part.", "d": "The client should not change the dosage of medication without a prescription from the provider."}, "keyConcept": null}, {"id": 11511, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who has been diagnosed with generalized anxiety disorder. Which of the following is an example of interpersonal communication by the nurse?", "choices": [{"id": "a", "t": "The nurse informs the healthcare team of the client’s response to a medication for anxiety."}, {"id": "b", "t": "The nurse asks the client when the anxiety attacks began and how frequently they occur."}, {"id": "c", "t": "The nurse presents an educational program at a community health fair to explain different types of anxiety disorders and local resources."}, {"id": "d", "t": "The nurse considers their own feelings about individuals who suffer from anxiety disorders."}], "correct": "b", "rationale": "mw | 27% ~~ Hard Interpersonal communication occurs between two individuals on a one-on-one basis. Examples of interpersonal communication between a Cc l 3% nurse and client include obtaining a personal history and asking open-ended questions to allow the client to explore feelings. D Hl 20%", "whyNot": {"a": "Discussing the client’s condition in a meeting with the healthcare team is an example of small-group communication.", "c": "Presenting a community educational program is an example of public communication.", "d": "Reflecting on personal feelings is an example of intrapersonal communication used for self-assessment."}, "keyConcept": "Interpersonal communication refers to one-on-one communication between two individuals. It occurs between a nurse and client at many points in the nursing process, including assessment, evaluation, and implementation of care."}, {"id": 11512, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "of the crash because my boss was drinking, and that's expected if we want to advance at my company.” Which of the following defense mechanisms is this client displaying?", "choices": [{"id": "a", "t": "Displacement"}, {"id": "b", "t": "Rationalization"}, {"id": "c", "t": "Splitting"}, {"id": "d", "t": "Compensation"}], "correct": "b", "rationale": "sl 15% Easy Rationalization refers to the creation of an acceptable explanation for unacceptable behavior. The client is making an excuse to justify or OB sd 78% explain driving while intoxicated. The client thinks the excuse is logical, making his behavior tolerable to him. | ° © 2%", "whyNot": {"a": "Displacement refers to the transfer of strong or uncomfortable feeling from one person or situation to another, less-threatening situation,", "c": "Splitting refers to an inability to accept or resolve both negative and positive attributes in one individual, whether the self or another", "d": "Compensation is a defense mechanism characterized by emphasizing strengths to compensate for weaknesses. It can be adaptive if it"}, "keyConcept": "Individuals whose actions may have contributed to self-harm or harm to others will often provide explanations that provide a pretext to avoid acknowledging their role and make their behavior tolerable to them. Creation of an acceptable explanation to avoid accepting responsibility for unacceptable behavior is known as rationalization."}, {"id": 11513, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is assessing a client with anorexia nervosa. Which of the following should the nurse expect to find when talking to the client?", "choices": [{"id": "a", "t": "An intense fear of gaining weight, with an unrealistic body image and a weight decrease of 25% or more"}, {"id": "b", "t": "Ahistory of eating substances without nutritional value, including starch and chalk, for 1 month or more"}, {"id": "c", "t": "Ahistory of binge eating and an intense fear of being unable to stop eating"}, {"id": "d", "t": "Tremors and diaphoresis when exposed to the sight or smell of food"}], "correct": "a", "rationale": "Anorexia nervosa is an eating disorder that is characterized by an intense fear of weight gain, a distorted perception of body image, an unwillingness to maintain adequate body weight, and undue influence of weight/shape on self-esteem. Clients with anorexia nervosa may use restriction of food, purging, laxatives, diet pills, and intensive or extreme exercise in an attempt to lose weight. Anorexia may be treated on an outpatient basis, but clients who weigh less than 75% of their ideal body weight, or who have medical conditions resulting from malnutrition or suicidal ideation or behavior should be hospitalized. During hospitalization, controlled refeeding and replacement of critical nutrients are combined with treatment for any medical conditions that have developed as a result of starvation. Aweight goal of 90% of ideal body weight is usually adequate for restoration of the menstrual cycle. Psychosocial therapies address the client's feelings of anxiety, dysphoria, low self-esteem, and lack of control in a setting in which the client feels safe and accepted.", "whyNot": {"b": "This refers to pica, a disorder that causes an appetite for nonnutritive substances.", "c": "This refers to bulimia.", "d": "Although individuals with anorexia nervosa may avoid food due to distortion of body image, this is not a response associated with"}, "keyConcept": "A nurse assessing a client with anorexia nervosa would expect overly controlled eating behaviors, extreme weight loss, amenorrhea, preoccupation with food, and body image disturbance. The client may wear several layers of loose clothing to appear larger. The client will have physical findings that include growth of fine, downy hair on the face and back (lanugo); low blood pressure, slow heart rate, and hypothermia; and cool, mottled skin on the extremities."}, {"id": 11514, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "response by the nurse? O A. “Do you have a family member who | can call?” O B. “I can ask the hospital chaplain to visit.” O C. “I can stay for a short time, but then | will have to care for other clients.” O D. “I can stay with you for a while.”", "choices": [{"id": "a", "t": "“Do you have a family member who can call?”"}, {"id": "b", "t": "“I can ask the hospital chaplain to visit.”"}, {"id": "c", "t": "“I can stay for a short time, but then will have to care for other clients.”"}, {"id": "d", "t": "“I can stay with you for a while.”"}], "correct": "d", "rationale": "‘i of When caring for a client at the end of life, the nurse's responsibilities include assisting the client and family through the death and dying c || process, which includes providing information and support. Family members facing the death of a loved one are often sad, fearful, e@D | concerned about the dying individual, or confused. A family member or a client may want the nurse to sit with them at this time. This can reassure the family member that the nurse and the healthcare team continue to treat the client with respect, allowing time and giving attention to the client’s and family’s needs. Even if the nurse must leave after a short time, this response is the most reassuring and therapeutic.", "whyNot": {"a": "This may be helpful if a client or family member seems to need support, but it is not the most appropriate response at this time.", "b": "It may be appropriate to request a visit from clergy or hospital chaplain, but this will not address the client’s spouse’s immediate need.", "c": "This response suggests the nurse is busy and may prevent the client’s spouse from asking for time or attention when needed in the future."}, "keyConcept": "When caring for a seriously ill or dying client, the nurse can reinforce her concern for the client and the client's family by making time to address family needs, even if only momentarily. It's important for the nurse to avoid the appearance of impatience or haste when family members ask for support. Pausing to sit with family members conveys respect and encouragement in a time of significant life-change for the client's family members."}, {"id": 11515, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "mechanism? O A. Act out in reverse order something that has already taken place O B. Return to a less mature stage of development O C. Remove from consciousness thoughts which are psychologically distressing O D. Channel unacceptable desires into socially acceptable behaviors", "choices": [{"id": "a", "t": "Act out in reverse order something that has already taken place"}, {"id": "b", "t": "Return to a less mature stage of development"}, {"id": "c", "t": "Remove from consciousness thoughts which are psychologically distressing"}, {"id": "d", "t": "Channel unacceptable desires into socially acceptable behaviors"}], "correct": "d", "rationale": "al 5% Easy Sublimation is the unconscious attempt to fulfill desires that are socially unacceptable by selecting acceptable behaviors to pursue instead.", "whyNot": {"a": "This is an example of reaction formation, not sublimation. @", "b": "This is regression, not sublimation.", "c": "This is repression, not sublimation."}, "keyConcept": "Defense mechanisms are subconscious coping techniques that individuals use to deal with negative, unpleasant, and threatening situations and emotions that cause anxiety. Sublimation is a defense mechanism in which socially unacceptable impulses are transformed into socially acceptable actions or behavior. This defense mechanism is considered a mature response to unacceptable impulses and may result in a long-term change in the way the individual copes with the initial impulse or situation."}, {"id": 11516, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "driving the car.\" Which of the following responses should the nurse make? O A.\"Car crashes happen all the time. Your partner will be fine.\" O B.\"I think you should calm down before you see your partner again.\" O C. \"Why do you think the crash is your fault?\" O D. \"Tell me more about your feelings concerning what happened to your partner.\"", "choices": [{"id": "a", "t": "This response illustrates the nontherapeutic communication technique of giving false reassurance. This belittles the partner's feelings and"}, {"id": "b", "t": "1%"}, {"id": "c", "t": "This response illustrates the nontherapeutic communication technique of requesting an explanation. This can make the partner feel"}, {"id": "d", "t": "| 1% This response illustrates the therapeutic communication technique of exploring and encourages the partner to express his feelings about his partner's accident."}], "correct": "d", "rationale": "| 1% This response illustrates the therapeutic communication technique of exploring and encourages the partner to express his feelings about his partner's accident.", "whyNot": {"a": "This response illustrates the nontherapeutic communication technique of giving false reassurance. This belittles the partner's feelings and", "b": "This response illustrates the nontherapeutic communication technique of giving advice. This interferes with how the partner is feeling and", "c": "This response illustrates the nontherapeutic communication technique of requesting an explanation. This can make the partner feel"}, "keyConcept": "By using a therapeutic response known as exploring with the client's partner, the nurse examines the partner's feelings about the incident and the client. This focuses on the client's partner's feelings about the accident and provides the nurse a better understanding of the client's partner's thoughts and wishes."}, {"id": 11517, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse at an outpatient mental health clinic is assessing a client who is receiving treatment for depression and suicidal ideation. Which of the following statements indicates a low risk of suicide?", "choices": [{"id": "a", "t": "“Iwill sign my 'no-suicide' contract today.”"}, {"id": "b", "t": "“lam feeling more energetic since began my new medication.”"}, {"id": "c", "t": "“I lost my prescription for Elavil and would like to get a refill.”"}, {"id": "d", "t": "“Next month, hope to be feeling better since will be celebrating my wedding anniversary.”"}], "correct": "d", "rationale": "Articulation of long-term goals and plans to celebrate important milestones indicate the client has hope for the future, an indication that the Cc | client is less likely to commit suicide. Protective factors to be considered when assessing suicidal intent in a client who is receiving treatment e@D | for depression and suicidal ideation include future goals and plans, social support, family support, parenthood, religion, participation in religious activities, and pregnancy. Risk factors that the nurse should assess in a client at risk for suicide include problems in the home or work environment, overall affect, level of energy, support during a crisis, access to psychiatric medications, and access to weapons.", "whyNot": {"a": "Although a “no-harm\" (\"no-suicide\") contract is often used by clinicians to provide structure and support for a client with depression who", "b": "After beginning medication or therapy for depression, many individuals experience increased energy, but this can sometimes be turned to", "c": "Tricyclic antidepressants have a narrow therapeutic margin and can be deadly in overdose. A nurse should be cautious and ensure the"}, "keyConcept": "Hopelessness is an important factor that predisposes an individual to suicide. Statements of despair or helplessness indicate potential risk. A nurse should assess a depressed client for other risk factors for suicide, including a history of previous suicide attempt; alcohol or substance use or abuse; a history of childhood abuse; comorbid psychiatric conditions; family history of suicide; legal problems or loss of an important relationship, including bereavement."}, {"id": 11518, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who has been admitted to the psychiatric unit. Which of the following interventions should be included in the care plan as a cognitive behavioral intervention?", "choices": [{"id": "a", "t": "Orienting the client to the physical setting"}, {"id": "b", "t": "Assisting the client with problem-solving"}, {"id": "c", "t": "Modeling"}, {"id": "d", "t": "Providing teaching about medications for the client and his or her family"}], "correct": "c", "rationale": "im 17% Hard Cognitive behavioral and behavioral modification are often used therapeutically in mental health settings. Techniques include modeling, @c | 30% systematic desensitization, and operant conditioning. Modeling is a technique that employs only imitation by the client, without any verbal D l 3% instruction, to change behavior. Other therapeutic modalities used in the mental health setting include milieu therapy, counseling, psychobiologic therapy, promotion of self-care, health teaching, health promotion, and health maintenance and case management.", "whyNot": {"a": "Milieu therapy includes orientation of the client to the physical setting and the creation of a safe environment while identifying the rules", "b": "Counseling is used to assist the client with problem-solving, crisis intervention, and stress management.", "d": "Providing teaching about medications is a psychobiological intervention. Other psychobiological interventions include administering"}, "keyConcept": "The effectiveness of cognitive behavioral therapy (CBT) is supported by extensive evidence. It is widely recommended as a key component of treatment for many mental health problems. Techniques used in CBT include modeling, operant conditioning, and desensitization."}, {"id": 11519, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A client with a paranoid personality disorder sees some clients laughing during a group activity and asks the nurse, “Why are they laughing at me? | bet they are making fun of me.” Which of the following responses by the nurse is most appropriate?", "choices": [{"id": "a", "t": "“You should not let yourself get so upset.”"}, {"id": "b", "t": "“Don’t worry about them, they do not mean any harm.”"}, {"id": "c", "t": "“Look, they seem to be having fun.”"}, {"id": "d", "t": "“They are laughing at a joke John told. They are not laughing at you.”"}], "correct": "d", "rationale": "al 4% Easy The client with paranoid personality disorder interprets the actions of others as personal threats, feels vulnerable, and is overly sensitive to B I a other’s motives. ch 5%", "whyNot": {"a": "This response does not tell the client the truth; the nurse should let the client know they are not laughing at him.", "b": "This response plays into the client’s paranoia and is inappropriate.", "c": "This response does not educate the client about his paranoid thoughts, nor does it help him to cope with his own ideas."}, "keyConcept": "Paranoia can be due to schizophrenia, paranoid personality disorder, or drug/alcohol abuse. The client with paranoia mistakenly interprets others’ actions and motives as threatening. Some symptoms may be relieved by antipsychotic medication. The client may be suspicious about being poisoned and may not take their medication. Compliance needs to be monitored. When caring for a client with paranoia, the nurse should provide support and encouragement and accept that the client’s experience of the delusion is real to the client, but the nurse should not concur with the delusion and should orient the client to reality."}, {"id": 11520, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "Which of the following is a sign of progress towards therapeutic goals in a client diagnosed with dependent personality disorder?", "choices": [{"id": "a", "t": "“ think did something today that was really a mistake.”"}, {"id": "b", "t": "“My spouse was not able to drive me to work, so took a bus.”"}, {"id": "c", "t": "“My mother has remarried, so I’ve moved in with a friend.”"}, {"id": "d", "t": "“It's so kind of you to take the time to help me.”"}], "correct": "b", "rationale": "Correct Answer: B. “My spouse was not able to drive me to work, so | took a bus.” Apersonality trait refers to an individual’s way of dealing with the external environment. When an individual has a personality disorder, the personality trait becomes maladaptive and inflexible. This can result in a dysfunctional pattern of relationships, work, and interactions with the community. Dependent personality disorder is characterized by an abnormal need to be taken care of, resulting in needy and submissive behavior and fear of abandonment or separation. Characteristics also include: + Fear of confrontation + Avoidance of disagreement + Helplessness or anxiety when alone + Difficulty with decision-making + Needing an excessive amount of reassurance or advice from others + Lack of self-confidence This client is adapting to the absence of help from others by deciding to take action alone to resolve the situation. This represents progress towards a therapeutic goal.", "whyNot": {"a": "Individuals with dependent personality disorder often express feelings of anxiety or helplessness.", "c": "This represents the client’s need to exchange one dependent relationship for another. It does not represent therapeutic progress.", "d": "Clients with dependent personality disorder may be flattering to gain approval of others."}, "keyConcept": "Personality traits refer to an individual's way of dealing with the environment. Personality disorders are maladaptive responses to the environment and can impair functioning in all spheres of life. Dependent personality disorder results from abnormal fear of abandonment or separation. It can result in needy or submissive behaviors through which the client attempts to avoid confrontation or disagreement; a need Nx Logins Pc x [GitHub]’ x ™ Inbox-b xX @ TEASPra xX OnlineN. xX @ Microsofi xX @ NCLEXE xX | Results - % CLOSE x ©) bobyondi x @Q NewTab x + v Qe sw * oo! @ { Browse Questions > iit Search Questions QJ"}, {"id": 11521, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "of treatment with an anti-psychotic medication. The client refuses admission. Under which of the following circumstances can this client be involuntarily committed?", "choices": [{"id": "a", "t": "A diagnosis of schizophrenia has been made"}, {"id": "b", "t": "If the client poses a danger to self or others"}, {"id": "c", "t": "If the client does not voluntarily cooperate"}, {"id": "d", "t": "If the police request admission to an inpatient psychiatric unit"}], "correct": "b", "rationale": "al 3% Easy The United States Constitution protects Americans from loss of liberty under the Fourteenth Amendment. This includes refusal of OB SY oni involuntary hospitalization, but states have passed laws that allow involuntary commitment for a psychiatric disorder if the individual appears to be an imminent danger to self or others. Other criteria for involuntary commitment under the law include grave disability that c | 2% renders the individual unable to adequately provide for his or her basic needs (food, shelter, clothing, personal safety, and medical care). . Individuals also have the right to be treated in the least restrictive environment in which treatment can safely be provided. Involuntary commitment is usually reserved for clients with illness that markedly impairs judgment and insight, causing them to refuse treatment when illness is severe and safety is at risk.", "whyNot": {"a": "A diagnosis of schizophrenia or another mental illness does not meet the standard for involuntary commitment. Not all individuals with a", "c": "Clients with mental illness, like clients with any illness, have a right to refuse treatment, unless a significant impairment in judgment puts", "d": "This is inadequate. The police cannot give consent or demand involuntary commitment. If the attending healthcare provider determines"}, "keyConcept": "Although clients usually have legal rights to determine medical treatment, involuntary commitment to a psychiatric facility may become necessary to protect the client from self-harm or to protect others who might be in imminent danger as a result of the client's release. If the client's psychiatric illness is the cause of impaired judgment that renders the client unable to give informed consent, the client can be involuntarily committed pending treatment and resolution of the acute delusional state."}, {"id": 11522, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who is scheduled for electroconvulsive therapy (ECT). Which of the following should the nurse include when informing the client about the procedure?", "choices": [{"id": "a", "t": "One treatment usually results in resolution of depression."}, {"id": "b", "t": "Anti-seizure medications are given before the procedure."}, {"id": "c", "t": "The client may experience retrograde amnesia."}, {"id": "d", "t": "The client will remain awake during the procedure."}], "correct": "c", "rationale": "8 11% ECT is an effective treatment for depression and can be used successfully for treatment of psychotic illnesses. It is a first-line therapy in ec FY 74% individuals with treatment-resistant depression or psychosis, depression with delusions, catatonic schizophrenia; in severely malnourished D | | 13% or dehydrated clients who have experienced lengthy depression; and in clients with medical conditions that may make antidepressant medication less safe. The procedure is performed under general anesthesia, with paralytic agents to prevent fractures or muscle injuries resulting from seizure and muscle contraction. The client is placed on a cardiac monitor, and an electroencephalogram (EEG) monitors brain waves during the procedure. Seizures are induced for 30-60 seconds by transmission of an electrical current through electrodes attached to the head. The client usually awakens about 15 minutes post procedure and has a period of confusion or disorientation that lasts several hours. Retrograde amnesia, or loss of memory up to and including the event, is common.", "whyNot": {"a": "Two to three treatments are usually given each week for a total of 6 to 12 treatments.", "b": "Seizures are induced throughout the entire brain for 30-60 seconds during treatment.", "d": "The client is under general anesthesia, and a paralytic agent is used to prevent fractures and muscle injury or discomfort."}, "keyConcept": "Electroconvulsive therapy is an effective treatment for depression. Electrodes are attached to the head and electrical current is passed through, causing seizures that last 30-60 seconds. The procedure is performed under general anesthesia, with administration of paralytics to prevent musculoskeletal injury. Retrograde amnesia is a common adverse effect."}, {"id": 11523, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "week. | feel much better, so | think my kidneys are working well again.\" The nurse should identify that this client is demonstrating which of the following Kiibler-Ross stages of grieving?", "choices": [{"id": "a", "t": "Bargaining"}, {"id": "b", "t": "Denial"}, {"id": "c", "t": "Acceptance"}, {"id": "d", "t": "Anger"}], "correct": "b", "rationale": "all 8% Easy During the stage of denial, clients act as though nothing has happened and might refuse to believe or understand that a loss has occurred. OB rT tsisSY Bon They are unable to accept the reality of the loss. This client has not yet realized that kidney function is not going to improve. I ° © 3% p | 1%", "whyNot": {"a": "During the stage of bargaining, clients attempt to offer behavior or attributes to \"trade\" for a better outcome. They stall their awareness of", "c": "During the stage of acceptance, clients incorporate the reality of the loss into their life. This client has not accepted that his kidney", "d": "During the stage of anger, clients show resistance or blame other people, a higher power, or the situation itself. This client is showing no"}, "keyConcept": "Although there are many theories about adjusting to a loss, the most common is from Kiibler-Ross, who lists five stages: denial, anger, bargaining, depression, and acceptance. It is important for nurses who are caring for clients who are experiencing grief and loss to identify these stages and offer interventions that meet clients' needs during each stage. Nurses should also realize that there is no specific time frame for moving to the next stage and that clients are often in more than one stage at a time."}, {"id": 11524, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "responds by asking, “You are feeling hopeless about the future?” Which of the following therapeutic communication techniques is the nurse using?", "choices": [{"id": "a", "t": "Paraphrasing"}, {"id": "b", "t": "Focusing"}, {"id": "c", "t": "Presenting reality"}, {"id": "d", "t": "Showing acceptance and recognition"}], "correct": "a", "rationale": "ce | 9% Paraphrasing is a clarifying technique that is used by the nurse to restate the client’s message, allowing the client to confirm that his or her c l 3% communication was understood by the nurse.", "whyNot": {"b": "Focusing refers to providing assistance to the client to help him or her concentrate on the important topics or message in a", "c": "Presenting reality is a technique used to focus the client’s attention on reality when the client expresses faulty beliefs or delusions.", "d": "Showing acceptance and recognition is a therapeutic communication technique through which the nurse can express interest and respect"}, "keyConcept": "Therapeutic communication provides the client with an opportunity to explore and identify emotions and concerns. Techniques that affirm and encourage the client and build trust include paraphrasing. By restating the message the client has conveyed, the nurse confirms understanding."}, {"id": 11525, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is assisting a client with anxiety disorder in a meditation exercise. This is an example of which of the following types of communication?", "choices": [{"id": "a", "t": "Interpersonal"}, {"id": "b", "t": "Transpersonal"}, {"id": "c", "t": "Intrapersonal"}, {"id": "d", "t": "Nonverbal"}], "correct": "b", "rationale": "Transpersonal communication addresses the client’s spiritual needs or facilitates the client’s ability to meet those needs. Assisting the client Cc | | with meditation to reduce stress or anxiety and provide relaxation is an example of transpersonal communication in nursing. D Hi", "whyNot": {"a": "Interpersonal communication refers to a conversation between two individuals. There is a conversational exchange in interpersonal", "c": "Intrapersonal communication occurs within an individual as an internal discussion. The individual may be thinking about a situation but", "d": "Nonverbal communication refers to the impression conveyed outside of a verbal message by factors such as silence, eye contact, posture,"}, "keyConcept": "Communication between the nurse and client is foundational to nursing practice. Transpersonal communication occurs when the nurse uses communication to address the client's spiritual needs or to facilitate the client's ability to meet his/her spiritual needs."}, {"id": 11526, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is caring for a client who was admitted for treatment of major depression. Which of the following techniques is a barrier to therapeutic communication?", "choices": [{"id": "a", "t": "Reflecting"}, {"id": "b", "t": "Focusing"}, {"id": "c", "t": "Providing false reassurance"}, {"id": "d", "t": "Touch"}], "correct": "c", "rationale": "all 7% Easy Providing false reassurance or offering personal opinions can be barriers to effective communication. Other barriers include minimizing the B | a client’s feelings, changing the topic, offering value judgments, approving or disapproving responses, changing topics, giving advice, and asking irrelevant personal questions or “why” questions. ec | 82% of 4%", "whyNot": {"a": "Reflecting refers to a therapeutic technique that is used to direct the focus of communication to the client, allowing the client to examine", "b": "Focusing is a therapeutic communication technique used to help the client attend to an important topic or message.", "d": "Appropriate touch can be used in therapeutic communication to provide comfort and express caring."}, "keyConcept": "Therapeutic communication is a critical component of nursing care. Techniques to show acceptance, build trust, and encourage the client to explore feelings and concerns include reflecting, focusing, use of open-ended questions, and appropriate touch. Barriers include changing the topic, giving advice, making value judgments, and minimizing the client's concerns or feelings."}, {"id": 11527, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "that the client is experiencing which of the following types of delusions?", "choices": [{"id": "a", "t": "Persecution"}, {"id": "b", "t": "Control"}, {"id": "c", "t": "Erotomanic"}, {"id": "d", "t": "nihilistic"}], "correct": "b", "rationale": "All oo c om Clients who are experiencing control delusions believe that others are trying to control them. Often, they believe that others are forcing thoughts into their brains.", "whyNot": {"a": "Clients who are experiencing persecution delusions believe that others are trying to harm them.", "c": "Clients who are experiencing erotomanic delusions believe that someone desires a romantic relationship with them.", "d": "Clients who are experiencing nihilistic delusions believe that a major catastrophe or event is going to happen."}, "keyConcept": "The nurse should identify that a client who thinks he can read peoples' thoughts through the radio and speaks to aliens on another planet is experiencing a control delusion. This type of delusion causes a client to believe that someone or something can control a person's thoughts, feelings, or emotions through external forces."}, {"id": 11528, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "A nurse is speaking with the parents of a child who has been the victim of bullying. Which of the following statements is true?", "choices": [{"id": "a", "t": "Children who are victims of bullying are eager to confide in an adult."}, {"id": "b", "t": "Physical bullying is more common than verbal bullying."}, {"id": "c", "t": "Bullying is a normal part of childhood growth and development."}, {"id": "d", "t": "A physical disability is associated with a higher risk of bullying."}], "correct": "d", "rationale": "Bullying refers to repetitive, intentional infliction of physical, psychological, or emotional abuse by one or more individuals upon another A l io Easy individual deemed less physically or psychologically powerful than the bully. Bullying is not a normal part of childhood growth and . Children generally want to conform to their peer group, beginning in middle childhood, and some may be unable to do so, Cc I 4% preventing peer identification. This increases the risk of being bullied, particularly in children with disabilities or unusual physical e@D fs 88% characteristics. 00} Long-term consequences of bullying include sleep disturbances, adjustment disorders, anxiety, and depression. Bullied children may also 2 develop anxiety, feelings of insecurity, psychosomatic complaints, and poor academic performance. g :", "whyNot": {"a": "Children who are bullied are frequently ashamed of being perceived as weak or afraid to confide in an adult because of concerns about ‘", "b": "The most common type of bullying is verbal aggression, including intimidating remarks, obscenities, yelling, and derogatory remarks.", "c": "Bullying can cause lasting harm and should never be considered normal in childhood."}, "keyConcept": "Bullying refers to the infliction of repetitive abuse, including physical, emotional, or psychological abuse, by one or more individuals on an individual perceived as less physically or psychologically powerful. It is not a normal part of childhood and can result in long-lasting psychological harm, including sleep disturbance, adjustment disorders, anxiety, depression, and death, often due to suicide."}, {"id": 11529, "cat": "PSYCHOSOCIAL INTEGRITY", "stem": "anticipate if the client develops alcohol withdrawal syndrome?", "choices": [{"id": "a", "t": "Bradycardia"}, {"id": "b", "t": "Bradypnea"}, {"id": "c", "t": "Diaphoresis"}, {"id": "d", "t": "Ascites"}, {"id": "e", "t": "Megaloblastic anemia"}], "correct": "c", "rationale": "Alcohol withdrawal syndrome can cause significant problems when not recognized in hospitalized individuals who are heavy alcohol users. phoresis", "whyNot": {"a": "Tachycardia is consistent with alcohol withdrawal syndrome.", "b": "Bradypnea refers to decreased respiratory rate. It characterizes opiate overdose and extreme alcohol intoxication.", "d": "Ascites occurs in individuals with alcoholic cirrhosis, but it is not a sign of acute withdrawal.", "e": "Individuals who abuse alcohol may develop B12 deficiency, which results in megaloblastic anemia. It is not a sign of withdrawal, however."}, "keyConcept": null}], "physiological_integrity_basic_care_integrity": [{"id": 11530, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is teaching an assistive personnel (AP) how to perform postmortem care for a client who just died. Which of the following actions by the UAP indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "The UAP wraps the client's dentures in a napkin to give to the family."}, {"id": "b", "t": "The UAP places dirty linen in the corner of the client's room."}, {"id": "c", "t": "The UAP closes the client's eyes by holding them shut."}, {"id": "d", "t": "The UAP lays the client supine with bent arms across the chest."}], "correct": "c", "rationale": "A To ensure the client's eyes remain closed, gentle pressure should be applied for a few seconds. B '", "whyNot": {"a": "The UAP should place the dentures back in the client's mouth to give the face a natural appearance. If dentures are not placed back in the D |", "b": "The UAP should remove all dirty linens from the client's room to provide a clean environment for the family to visit the body.", "d": "The UAP should place a pillow under the client's head or elevate the head of the bed to prevent blood from settling in the face and"}, "keyConcept": "Postmortem care should be performed as soon as possible following death to prevent discoloration of the skin, tissue damage, or deformities. The client should be prepared to look comfortable and the environment should be cleaned so that family members feel comfortable when viewing the body. If possible, the nurse should adhere to any cultural or religious request made by the family when preparing the body."}, {"id": 11531, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "@ @ “Clade %* “%& Extracto) x %% ClaudeC: xX «& Login- Po x ™ [GitHub] x ™ Inbox-b xX @ TEASPra x OnlineN. x @ Microsofi x @ NCLEXE xX |. NCLEXA xX ©) bobyond) x + v € > G _ 8% student.atitesting.com/LT! Qa * s * ©o8 OD Cb ) © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Adjust the medication dosage"}, {"id": "b", "t": "Provide reassurance to the client"}, {"id": "c", "t": "Assess the client within 30 minutes after the pain medication"}, {"id": "d", "t": "Reposition the client"}], "correct": "c", "rationale": "| 2% Easy Before any other intervention, the nurse should reassess the client's pain 30 minutes after medication administration. This will ensure that B | a0 the nurse knows if the client received relief or if he needs an adjustment to the medication.", "whyNot": {"a": "The medication dosage should not be adjusted without assessing relief from the initial dose.", "b": "Reassuring the client may help to decrease some psychological discomfort, but the nurse will not be able to know the effects without °", "d": "Repositioning the client may help to decrease some discomfort, but the nurse will not be able to know the effects without monitoring the a"}, "keyConcept": "There are a variety of ways to measure pain, including numeric pain scales, behavioral assessments, and other objective observations. Self- report from the client provides the most reliable indicator of client pain. Evaluation of the effects of pain medication is essential when managing a client's pain."}, {"id": 11532, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has late stage cirrhosis. When assessing the client's hydration status, which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Bradycardia"}, {"id": "b", "t": "Increased BUN level"}, {"id": "c", "t": "Dependent edema"}, {"id": "d", "t": "Orthostatic hypotension"}], "correct": "c", "rationale": "A A client in the late stages of cirrhosis is expected to have fluid volume excess as the disease alters regular fluid volume balance. As liver B — failure progresses and plasma protein levels decrease, fluid cannot be retained in the vascular space and leaks into the interstitial spaces, causing edema. Gravity pulls the excess fluid to dependent areas such as the feet, ankles, and sacrum. ec | on Other Expected Findings of Overhydration Include: + Weight gain +» Bounding pulses + Distended neck veins + Moist crackles in the lungs +» Dyspnea and shortness of breath + Confusion", "whyNot": {"a": "The nurse should expect the client who has late stage cirrhosis to have tachycardia, rather than bradycardia. As cirrhosis progresses, the", "b": "The nurse should expect the client who has late stage cirrhosis to have a decreased BUN level. The liver is responsible for the synthesis of", "d": "The nurse should expect the client who has late stage cirrhosis to have hypertension, rather than orthostatic hypotension. As cirrhosis"}, "keyConcept": null}, {"id": 11533, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is teaching a group of clients about interventions to promote sleep. Which of the following interventions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Exercise moderately in the late afternoon."}, {"id": "b", "t": "Limit naps to 20min twice per day."}, {"id": "c", "t": "Avoid eating cheese or drinking milk at bedtime."}, {"id": "d", "t": "Relax by watching television before bedtime."}], "correct": "b", "rationale": "The nurse should include in the teaching that the clients should limit naps to twice per day for 20 min. Napping more frequently and for OB . FEY longer periods can hinder falling and staying asleep. ° c ii” 28% of 4%", "whyNot": {"a": "The nurse should include in the teaching that clients should exercise moderately in the morning or early afternoon, because exercising", "c": "The nurse should include in the teaching that clients should eat cheese or drink milk at bedtime because dietary L-tryptophan found in", "d": "The nurse should include in the teaching that clients should avoid watching television at bedtime because television is a stimulating"}, "keyConcept": "The function of sleep is to restore normal activity levels, balance the client's nervous system, and promote protein synthesis for repairs of the client's body. Psychological well-being is also restored during sleep. Factors that affect sleep include illness, an environment that is too warm or cold, lifestyle, stress, diet, being overweight, smoking, medications, stimulants, and alcohol use."}, {"id": 11534, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "nurse provide? O A. Elevate the head of the bed when the client is awake. O B. Ensure the client has liquid intake every 2 hr. O C. Instruct the family members to whisper when caring for the client. O D. Limit position changes for the client.", "choices": [{"id": "a", "t": "Elevate the head of the bed when the client is awake."}, {"id": "b", "t": "Ensure the client has liquid intake every 2 hr."}, {"id": "c", "t": "Instruct the family members to whisper when caring for the client."}, {"id": "d", "t": "Limit position changes for the client."}], "correct": "a", "rationale": "o; When awake, the client should be placed in a Fowler's position to promote better oxygenation and ease the client's effort when breathing. If B | unconscious, the caretakers should place the client in a lateral position to prevent aspiration.", "whyNot": {"b": "The family members should not force the client to drink liquids. The client should never be forced to eat or drink, but should be offered", "c": "Hearing is not necessarily diminished in the dying client. When providing palliative care, the family members should speak clearly to the", "d": "When providing palliative care, position changes for the client should be performed regularly to decrease the risk of skin breakdown. The"}, "keyConcept": "Family members should be encouraged to participate in the palliative care of their loved one. Activities that family members can provide include assisting with bathing and hygiene, providing skin care, reading to the client, offering nourishment, and keeping the client comfortable through repositioning."}, {"id": 11535, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is assessing a client after applying an ice bag for treatment of a sprain. The nurse should identify that which of the following findings is complication of this therapy?", "choices": [{"id": "a", "t": "Hypotension"}, {"id": "b", "t": "Edema"}, {"id": "c", "t": "Shivering"}, {"id": "d", "t": "Bleeding"}], "correct": "c", "rationale": "The nurse should identify that shivering is a complication of cold therapy because the body attempts to increase heat production in response to the cold. The nurse should discontinue the cold therapy if this occurs because shivering can increase the client's body temperature and cause an increase in energy consumption.", "whyNot": {"a": "The nurse should identify that hypertension, not hypotension, is a complication of cold therapy due to vasoconstriction.", "b": "The nurse should identify that edema and inflammation are complications of heat therapy, not cold therapy, due to vasodilation.", "d": "Heat therapy, not cold therapy, can cause bleeding in clients who have an open wound or surgical incision due to vasodilation."}, "keyConcept": "see table below. Therape | Usedto | Precautions Adverse utic treat effects effects Heat | Increase | Arthritis Contraindicated in clients who Bleeding from Ther | s blood have neurosensory impairment, | open wounds apy | flow Contract | impaired mental status, or surgical ures impaired circulation, incision Relaxes recent injury or surgery, open muscles | Low back | wounds, or localized infection. Burn injury pain Increase Protect skin under application. Peripheral healing | Rectal vasodilation of soft surgery Check skin every 20 min during tissue application. Hypotension Hemorrh Reduces | oids Instruct client to report joint increased pain or discomfort. stiffness Instruct client to not adjust temperature setting. Use a timer to time application. Cold | Decreas | Sprains | Contraindicated in clients who | Hypertension Ther | es blood have neurosensory impairment, apy flow Strains impaired mental status, Shivering impaired circulation, edema, or"}, {"id": 11536, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "include in the plan? O A. After applying electrodes, turn the knob until the client feels slight buzzing or tingling. O B. Apply the TENS unit for no longer than 30 min. O C. Instruct the patient on how to adjust the voltage on the TENS unit. O D. Avoid administering analgesics when using the TENS unit.", "choices": [{"id": "a", "t": "After applying electrodes, turn the knob until the client feels slight buzzing or tingling."}, {"id": "b", "t": "Apply the TENS unit for no longer than 30 min."}, {"id": "c", "t": "Instruct the patient on how to adjust the voltage on the TENS unit."}, {"id": "d", "t": "Avoid administering analgesics when using the TENS unit."}], "correct": "a", "rationale": "After applying electrodes, the nurse should turn the output knob until the client feels a tingling or buzzing. The intensity should be adjusted for client comfort. When using an older TENS unit, the nurse should apply a conductive gel before applying the electrodes from the TENS unit to the skin to provide good conduction between the electrode and the skin. Conductive gel may not be necessary for all TENS units, so the nurse should check the manufacturer's specifications.", "whyNot": {"b": "TENS units can be applied for as long as is required and prescribed by the provider.", "c": "The provider, nurse, or someone specially trained in TENS unit equipment should adjust the dial for voltage to be delivered to the client.", "d": "The nurse can administer pain medication while the client is using the TENS unit."}, "keyConcept": "Many clients who have cancer experience chronic pain. The use of non-pharmacologic methods of pain relief in combination with prescribed medications can improve client comfort. Transcutaneous electrical nerve stimulation (TENS) unit electrodes can be applied directly to the skin. The unit will send small electrical currents to the areas of pain to provide relief of symptoms. The therapy decreases pain levels by electrically stimulating local sensory fibers, which overrides the brain’s ability to process pain messages from the affected area."}, {"id": 11537, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is planning to provide postmortem care for a client. Which of the following actions should the nurse plan to take first?", "choices": [{"id": "a", "t": "Close the client's eyes."}, {"id": "b", "t": "Cleanse the client's body."}, {"id": "c", "t": "Elevate the head of the client's bed."}, {"id": "d", "t": "Give the client's personal items to the family."}], "correct": "c", "rationale": "‘i When using evidence-based practice, the first action the nurse should take is to elevate the head of the client's bed. Elevating the head of the B i client's bed as soon as possible following death prevents discoloration of the face. The nurse should also place a pillow under the client's head on the stretcher when transporting the client to another area. ec ||", "whyNot": {"a": "The nurse should close the client's eyes to provide a natural appearance for viewing the body of the deceased, which can serve to provide", "b": "The nurse should cleanse the client's body, maintaining standards of safety for bodily fluids, because a clean environment can serve to", "d": "The nurse should ask the family members if any personal items should remain with the body and then give any remaining items to a"}, "keyConcept": "The care of a client's body following death is referred to as postmortem care. The nurse can either provide this care or delegate the care to assistive personnel. The deceased client's body deserves the same dignity and respect as a living client would receive. Sensitivity to the client's personal, cultural, and religious beliefs should also be maintained during postmortem care because this gives family members a sense of fulfillment of the deceased client's obligations, which can promote acceptance of the death. Postmortem care can vary across health care settings; therefore, the nurse should be familiar with procedural guidelines and applicable policies when performing this level of care."}, {"id": 11538, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "states his pain is 8 on a scale of 0-10 and requests pain medication. Which of the following is the priority action by the RN?", "choices": [{"id": "a", "t": "Reposition the client"}, {"id": "b", "t": "Assess the client and notify the healthcare provider"}, {"id": "c", "t": "Give a second dose of hydromorphone"}, {"id": "d", "t": "Ask the LPN to take vital signs and administer the medication if vitals are within normal limits"}], "correct": "b", "rationale": "All o: ASTAT order prescribes immediate one-time administration of a prescribed medication, so the healthcare provider must be contacted Cc I before the medication can be repeated. D | There are four types of medication orders: -Stat medication orders are administered immediately and only once -Single orders are given only once but may not necessarily be given immediately -Standing order is repeated at specific times until the order is discontinued by a doctor's order or by default in accordance with the facility's policy -PRN order is only given when a specified condition is present (pain, nausea).", "whyNot": {"a": "Although repositioning the client may provide some relief, the priority is to assess the client and contact the healthcare provider. A STAT", "c": "ASTAT order is a one-time order, so the nurse cannot repeat this order before receiving a new prescription from the provider.", "d": "Although an LPN can give some medications, depending on local rules, intravenous opioid medications are usually the responsibility of"}, "keyConcept": "STAT orders are orders for immediate one-time administration of a prescribed medication The healthcare provider must be contacted for a new prescription in order to repeat administration of the medication."}, {"id": 11539, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is assisting a client with personal hygiene. Which of the following actions should the nurse take when performing nail care for the client?", "choices": [{"id": "a", "t": "Clean under the nails with an orange stick."}, {"id": "b", "t": "File the nails in a rounded shape."}, {"id": "c", "t": "Apply an alcohol rub to the cuticles after pushing them back."}, {"id": "d", "t": "Trim the nails at the lateral corners."}], "correct": "a", "rationale": "o; a The nurse should use an orange stick to push back the cuticles and clean under the nails. o cl", "whyNot": {"b": "The nurse should cut or file the nails straight across beyond the end of the finger.", "c": "The nurse should apply lotion or mineral oil to any areas around the nails that have dry tissue.", "d": "Trimming the nails at the lateral nail corners can result in ingrown nails. The nurse should file the nails straight across after cutting the"}, "keyConcept": "When providing nail care for most clients, nurses should soak their hands first to soften the nails and cuticles, especially if the nails are especially thick or hard. After drying the client's hands, cutting or filling the nails straight across beyond the lateral edges of the fingers is essential. Nurses should avoid trimming or digging into the corners of the nails; instead, nurses should file the edges straight across."}, {"id": 11540, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is providing teaching to a client who is to use a standard walker when ambulating. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Check the height of the walker by having the hand bar aligned with the finger joints."}, {"id": "b", "t": "Lift the walker up to move it forward."}, {"id": "c", "t": "Adjust the height of the walker to allow for stooping when ambulating."}, {"id": "d", "t": "Stand up straight and flex the elbows 40° when holding the walker grab bar."}], "correct": "b", "rationale": "All 13% Hard The nurse should tell the client to lift the standard walker up to move it forward. The client should have at least partial weight bearing of the OB a LER lower extremities and should be able to lift the walker with both hands in order to safely ambulate. I ° 4% c > i” 41%", "whyNot": {"a": "The nurse should tell the client to periodically check the height of the walker by having the hand bar aligned at the crease of the inside of", "c": "The nurse should tell the client to adjust the height of the walker to avoid stooping when ambulating with the walker. Stooping indicates", "d": "The nurse should tell the client to stand up straight and that the elbows should be flexed 15° to 30° when standing inside, the walker with"}, "keyConcept": "Awalker is a lightweight device that is either made to lift and walk or has wheels and can be pushed while walking. The walker's wide base provides the client with stability and allows the client to safely walk, resulting in a decreased risk of falling. A client who is weak or has difficulty with balance can benefit from using a walker."}, {"id": 11541, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is providing teaching to a client who is to use a standard walker when ambulating. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Check the height of the walker by having the hand bar aligned with the finger joints."}, {"id": "b", "t": "Lift the walker up to move it forward."}, {"id": "c", "t": "Adjust the height of the walker to allow for stooping when ambulating."}, {"id": "d", "t": "Stand up straight and flex the elbows 40° when holding the walker grab bar."}], "correct": "b", "rationale": "A Hi 13% Hard The nurse should tell the client to lift the standard walker up to move it forward. The client should have at least partial weight bearing of the OR a ree lower extremities and should be able to lift the walker with both hands in order to safely ambulate. n 4% ©", "whyNot": {"a": "The nurse should tell the client to periodically check the height of the walker by having the hand bar aligned at the crease of the inside of", "c": "The nurse should tell the client to adjust the height of the walker to avoid stooping when ambulating with the walker. Stooping indicates", "d": "The nurse should tell the client to stand up straight and that the elbows should be flexed 15° to 30° when standing inside, the walker with"}, "keyConcept": "Awalker is a lightweight device that is either made to lift and walk or has wheels and can be pushed while walking. The walker's wide base provides the client with stability and allows the client to safely walk, resulting in a decreased risk of falling. A client who is weak or has difficulty with balance can benefit from using a walker."}, {"id": 11542, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for an older adult client who requires maximum support to ambulate using a standard walker. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Check that the client lifts the walker and then places it down in front of them."}, {"id": "b", "t": "Ensure that the client's elbows are straight when gripping the walker."}, {"id": "c", "t": "Have the client move one leg forward with the walker."}, {"id": "d", "t": "Make sure that the upper bar of the walker is level with the client's waist."}], "correct": "a", "rationale": "eo, 41% Hard The client should lift the walker and advance it about 15 cm (6 in) before setting it down to provide a wide base of support. The client should B | 3\" have some strength in both hands and wrists and be able to bear some weight on both legs to use a standard walker. A client who has limited strength in their hands and wrists should use a rolling walker because the client can push the rolling walker forward when ambulating c |__| 17% instead of than lifting it. D | | 39%", "whyNot": {"b": "The nurse should ensure that the client's elbows are flexed at 15° to 30° when gripping the walker to allow the client to ambulate without", "c": "A client who requires maximum support should move the walker first before moving one foot up to the walker while bearing weight on", "d": "The nurse should make sure the top of the walker is just below the level of the client's waist to allow the client to ambulate without"}, "keyConcept": "Awalker is used for clients who require support to maintain balance and stability for ambulating. Standard walkers do not have wheels and must be lifted during use. Rolling walkers have two or four wheels, and the client can push them forward during use."}, {"id": 11543, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is updating the plan of care for a client who has cancer and is near death. Which of the following interventions should the nurse plan to include?", "choices": [{"id": "a", "t": "Ask the client about personal preference for a light or dark room."}, {"id": "b", "t": "Speak to the client in a soft, whispering voice."}, {"id": "c", "t": "Place the client supine in bed with one pillow under the head."}, {"id": "d", "t": "Avoid frequent movement and position changes."}], "correct": "a", "rationale": "If the client is able to communicate, the nurse should ask the client about preferences concerning light or darkness in the room and should B ™% accommodate the client's choice. The nurse should continue to include the client in making care decisions to the extent that the client i desires to participate. c i 10% > 7 34%", "whyNot": {"b": "The sensory perception of hearing is not generally altered in a client who is dying. The nurse should speak clearly and in a normal tone of", "c": "For a client who is conscious, the nurse should position the client in a Fowler's position. For a client who is unconscious, the nurse should", "d": "To assist with physical mobility, the nurse should frequently change the client's position. When the client is in bed, the nurse should"}, "keyConcept": "The nurse is responsible for caring for the client who is near death. When updating the plan of care, the nurse should address the following physiological needs of the client who is actively dying: + Airway clearance «Air hunger + Bathing/hygiene + Physical mobility + Nutrition + Constipation + Urinary elimination"}, {"id": 11544, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "@ @ “Clade %* “%& Extracto) x % ClaudeC xX & Login- Po x ™ [GitHub] x ™ Inbox-b xX @ TEASPra x OnlineN. x @ Microsofi x @ NCLEXE xX | NCLEXA xX ) bobyond) x + v € > GCG _— &% student.atitesting.com/LT| Q *& x * © OD Cb ) © Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Quizzes & Assignments. Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "At admission"}, {"id": "b", "t": "At discharge"}, {"id": "c", "t": "The day following admission"}, {"id": "d", "t": "At the first appointment following discharge"}], "correct": "a", "rationale": "All discharge teaching should begin at the time of admission. Hospital stays are extremely short and it is critical that the nurse use every B ] a opportunity to teach the client and family. c | 3%", "whyNot": {"b": "Waiting until discharge or after will potentially not allow the client to get all the information necessary.", "c": "If the nurse waits until the day following admission to begin teaching, the client may very well be close to discharge and an entire day of", "d": "Waiting until discharge or after will not allow the client to get all the information needed."}, "keyConcept": "It can be challenging for clients to understand and remember all discharge instructions. The client or family members may be anxious to leave, with physical or emotional discomfort at the time of discharge, making it less likely that they will be interested in discharge instructions. Some clients have low literacy or health literacy skills that increase the difficulty of understanding instructions at the time of discharge. Presenting discharge instructions early and reinforcing the teaching during the hospital stay and at discharge can provide an opportunity for better learning."}, {"id": 11545, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has a prescription for a cleansing enema. Which of the following actions should the nurse take when administering the enema?", "choices": [{"id": "a", "t": "Keep the container of solution at a level comfortable for the client."}, {"id": "b", "t": "Hold the container of solution 30 cm (12 in) above the anus."}, {"id": "c", "t": "Raise the container of solution if the client reports abdominal pain."}, {"id": "d", "t": "Clamp the tubing after instilling half of the enema solution and resume instillation in 5 min."}], "correct": "b", "rationale": "For most enemas, the nurse should hold the container of solution about 30 cm (12 in) above the anus to allow for a continuous, slow instillation of solution that promotes evacuation of feces in the bowel. If the provider has prescribed a high enema, the nurse should hold the container 30 to 45 cm (12 to 18 in) to help instill the solution farther into the bowel. Enema administration", "whyNot": {"a": "The type of enema the provider prescribes determines the height of the container of solution. The client's comfort level does not", "c": "If the client reports pain, the nurse should lower the container and possibly clamp the tubing briefly to prevent spasms that might result in", "d": "The nurse should clamp the tubing after instilling all of the enema solution unless the client cannot tolerate it."}, "keyConcept": "Administering an enema involves instilling a solution into the rectum and the sigmoid colon to stimulate peristalsis and promote defecation."}, {"id": 11546, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A client has been following a vegan diet for 3 years. Which of the following statements represents a possible complication associated with this diet?", "choices": [{"id": "a", "t": "“My feet are numb and tingling.”"}, {"id": "b", "t": "“I have a dry mouth and bad breath.”"}, {"id": "c", "t": "“ have a flaky scalp.”"}, {"id": "d", "t": "“I have had trouble sleeping for the past month.”"}], "correct": "a", "rationale": "Avegan diet consists of only plant-based foods. Animal proteins, including protein from milk products and eggs, are eliminated in a vegan diet. Since vitamin B12 is only available from animal proteins, individuals on this type of diet can develop significant B12 deficiency without nutritional supplementation. Vitamin B12 deficiency results in neurologic abnormalities and megaloblastic anemia. Neurologic deficiencies associated with B12 deficiency include muscle weakness, sore tongue, and paresthesias, particularly in the hands and feet. Patients may complain of numbness, tightness, burning pain, or a sensation of cold in the tips of the toes and fingertips. Ataxia may occur in severe deficiency.", "whyNot": {"b": "Dry mouth and bad breath occur with ketosis, which is sometimes a result of a high-protein, low-carbohydrate diet.", "c": "Vitamin A deficiency may cause rough, dry skin. It is not associated with a vegan diet in most individuals.", "d": "Vegan diets are not associated with insomnia."}, "keyConcept": "Vitamin B12 is a water soluble vitamin, so overdose cannot occur. Deficiency results in megaloblastic anemia, glossitis, anorexia, pallor, and inadequate myelin synthesis, resulting in neurologic dysfunction. Clients with B12 deficiency may have nonspecific symptoms of depression, weight loss, dizziness, nausea, and constipation."}, {"id": 11547, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is planning a teaching session concerning foot care for a client with type 2 diabetes mellitus. Which of the following should the nurse include in the client’s teaching?", "choices": [{"id": "a", "t": "Go barefoot when possible to allow the skin to “breathe.”"}, {"id": "b", "t": "Apply lotion or ointment between toes before putting on socks and shoes."}, {"id": "c", "t": "File calluses using a commercial exfoliant and nail file."}, {"id": "d", "t": "Trim toenails straight across."}], "correct": "d", "rationale": "| 10% Clients with diabetes are at greater risk for diabetic foot infections due to inadvertent or unnoticed injury as a result of neuropathy and due Cc | 5% to a greater risk of infection. Diabetic teaching should include foot care recommendations. Clients should inspect feet daily and wash with eD | 84% mild soap and warm water. The feet should be kept dry. Clients should avoid lotions or ointment between the toes, which facilitate the development of infection. A podiatrist should be consulted for foot care, particularly for removal of calluses that may form. Toenails should be clipped or filed with straight edges to prevent soft tissue injury.", "whyNot": {"a": "Clients with diabetes should be instructed to wear protective foot covering. Shoes should be leather instead of plastic. Open-toe or open-", "b": "Feet should be dried thoroughly before putting on shoes. The use of a mild foot powder with cornstarch may be helpful for sweaty feet,", "c": "A podiatrist should be consulted to file calluses. Commercial exfoliant use should be avoided due to the risk of tissue injury."}, "keyConcept": "Foot problems are common in clients with diabetes mellitus. High blood sugar over a long period of time can damage blood vessels, decreasing blood flow to the foot. Poor circulation weakens the skin, contributing to the formation of ulcers and impaired wound healing. The other factor in diabetic foot problems is neuropathy. Elevated blood glucose levels over time damage the nerves of the foot, decreasing a person's ability to notice pain and pressure. This lack of sensation leads to accidental or unnoticed injury to the skin, soft tissue, bones, and joints."}, {"id": 11548, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who asks for medication to relieve pain. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Reposition the client."}, {"id": "b", "t": "Administer the medication."}, {"id": "c", "t": "Determine the location of the pain."}, {"id": "d", "t": "Offer the client a massage."}], "correct": "c", "rationale": "The first action the nurse should take when using the nursing process is to assess the client. By determining the location of the pain, the nurse can take the necessary steps to alleviate the client's pain, such as administering pain medication, repositioning the client, and offering the client nonpharmacological approaches to pain management.", "whyNot": {"a": "The nurse should reposition the client to help reduce the pain. However, there is another action the nurse should take first.", "b": "The nurse should administer an analgesic to help reduce the client's pain. However, there is another action the nurse should take first.", "d": "The nurse should offer the client a therapeutic massage to promote comfort and relaxation and possibly reduce pain by improving"}, "keyConcept": "In addition to determining location, the nurse should assess a client who has pain to determine the severity of the pain using a pain scale, the pain's duration, the pain's quality, and any precipitating or alleviating factors. It is also essential to determine whether the client has any other manifestations accompanying the pain, such as dizziness, nausea, or vomiting. @ Microsoft x @ NCLEXE x |- NCLEXA xX @) bobyond) x + v % CLOSE Qe, sr *¥ Oo Oo! O { Browse Questions > iit Search Questions QJ"}, {"id": 11549, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is planning care for a client who is in traction for a fractured femur. Which of the following interventions should the nurse include in the plan?", "choices": [{"id": "a", "t": "Check the ropes and knots of the traction every 24 hr."}, {"id": "b", "t": "Remove the weights when transferring the client to another unit in the bed."}, {"id": "c", "t": "Inspect the skin of the affected extremity every 12 hr."}, {"id": "d", "t": "Ensure that the weights are freely hanging at times."}], "correct": "d", "rationale": "The nurse should check that the weights are freely hanging at all times and that they are not resting on the floor or hooked under the edge of the bed, because the client can develop increased muscle spasms and misalignment of the fracture if this occurs.", "whyNot": {"a": "The nurse should check the ropes and knots of the traction at least every 8 hr to monitor for loosened, frayed, or out-of-position ropes or", "b": "The nurse should transfer the client to another unit in the bed with the weights attached because the client can develop increased muscle", "c": "The nurse should inspect the client's skin on the affected extremity at least every 8 hr for circulatory compromise and tissue damage."}, "keyConcept": "The purpose of traction is to create a pulling force to reduce, align, and rest the fracture. Traction is used to decrease muscle spasm and relieve pain, to prevent or correct a deformity, and prevent further tissue damage. There are 2 types of traction, running and balanced suspension traction. Running traction uses the rope and weights to pull only in one direction, counter to the client's body. Balanced suspension traction provides countertraction so the pulling force of the ropes and weights are not altered when the client or bed is moved."}, {"id": 11550, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who is receiving heat therapy using an aquathermia pad. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Fill the reservoir to the top with water."}, {"id": "b", "t": "Stop the treatment if the client's skin becomes red."}, {"id": "c", "t": "Leave the pad in place for at least 40 min."}, {"id": "d", "t": "Use safety pins to keep the pad in place."}], "correct": "b", "rationale": "A The nurse should check the client's skin every 15 to 20 min and discontinue treatment if the client's skin becomes red or the client reports OB —_ increased pain. cl of}", "whyNot": {"a": "The nurse should fill the reservoir 2/3 full of water to reduce the risk for water leaking from the reservoir.", "c": "The nurse should apply the heat application for no longer than 30 min to reduce the risk for tissue injury.", "d": "The nurse should use gauze or tape to keep the pad in place. Safety pins can puncture the pad and cause leakage."}, "keyConcept": "An aquathermia pad is a heating pad that can provide moist or dry heat. It is made of water filled tubes that are heated electrically. The reservoir should be 2/3 full of water to reduce the risk for water leaking from the reservoir. Gauze or tape is used to keep the pad in place. Safety pins should not be used because they can puncture the pad and cause leakage. Heat therapy is used to treat arthritis, contractures, low back pain, rectal surgery, and hemorrhoids. It causes an increase in blood flow to the injured area, relaxes muscles, increases healing of soft tissue, and reduces joint stiffness. Heat therapy is contraindicated in clients who have a neurosensory impairment, impaired mental status, impaired circulation, recent injury or surgery, open wounds, or localized infection. The nurse should check the client's skin every 15 to 20 min and discontinue treatment if the client's skin becomes red or the client reports increased pain. The nurse should apply the heat application for no longer than 30 min to reduce the risk for tissue injury. The nurse should instruct the client to not adjust the temperature setting and should use a timer to time the application. Adverse effects of heat therapy can include bleeding from open wounds or a surgical incision, burns, peripheral vasodilation, and hypotension."}, {"id": 11551, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is teaching a client who has hearing loss about hearing aid care. Which of the following instructions should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Change the batteries if there is a constant whistling sound."}, {"id": "b", "t": "Remove detachable earmolds from the receiver and clean with soap and water."}, {"id": "c", "t": "Store extra hearing aid batteries in the refrigerator."}, {"id": "d", "t": "Clean the ear canal daily with a cotton applicator before inserting hearing aids."}], "correct": "b", "rationale": "c | 3% of 12% The nurse should instruct the client to remove detachable earmolds from the receiver and clean them with soap and water, not alcohol, because alcohol can damage the earmolds.", "whyNot": {"a": "The nurse should instruct the client that a constant whistling sound indicates that the batteries are functioning. If whistling or squealing", "c": "The nurse should instruct the client to store extra hearing aid batteries in a secure dry place and replace the batteries when needed. When", "d": "The nurse should instruct the client to never insert a cotton applicator, toothpick, or bobby pins into the ear canal to remove cerumen."}, "keyConcept": "The client who has a new hearing aid can take weeks to months to adjust to the hearing aid. The client might feel that sounds are too shrill and can hear high-frequency sounds that they had not heard for a long time. Hearing aids are measures to assist the client to hear sound better and are not a cure for hearing loss. The client should lengthen the wearing time each day until the client has adjusted to wearing the hearing aid for a full day."}, {"id": 11552, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is assessing a client who had a cast applied following a compound fracture of the femur. Which of the following findings is a manifestation of a fat embolism?", "choices": [{"id": "a", "t": "Dyspnea"}, {"id": "b", "t": "Reduced bowel sounds"}, {"id": "c", "t": "Swelling of the toes distal to the injury"}, {"id": "d", "t": "Pain with passive movement of the foot distal to the injury"}], "correct": "a", "rationale": "The earliest manifestation of fat embolism is dyspnea, which can lead to hypoxemia and tachypnea.", "whyNot": {"b": "Reduced bowel sounds is an adverse effect of opioid narcotics, which can indicate constipation. D i 10%", "c": "Swelling of the toes distal to the injury is a manifestation of reduced circulation and can be the result of a tight cast. The nurse should", "d": "Pain with passive movement of the foot distal to the injury is an expected finding. Severe pain or pain unrelieved by narcotics is a"}, "keyConcept": "Fat embolism syndrome is a complication that occurs when a fat globule enters the bloodstream usually within 12 to 48 hr after a bone fracture. The globules obstruct the small blood vessels that supply oxygen to a vital organ. Pancreatitis, osteomyelitis, blunt trauma, or sickle cell disease can also cause the complication of fat embolism syndrome. Early manifestations are dyspnea, hypoxemia, and tachypnea, followed by headache, lethargy, agitation, confusion, loss of consciousness, and seizures. The client might develop petechiae over the neck, upper chest, and arms. Fat embolism syndrome can result in respiratory failure and death and is often misdiagnosed as a pulmonary embolism for a blood clot."}, {"id": 11553, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has had an indwelling urinary catheter in place for 3 days. After removal, the nurse should assess the client for which of the following expected outcomes?", "choices": [{"id": "a", "t": "Temporary urinary retention"}, {"id": "b", "t": "Burning with urination"}, {"id": "c", "t": "Blood-tinged urine"}, {"id": "d", "t": "Highly concentrated urine"}], "correct": "a", "rationale": "Until the bladder regains its full tone, it is common for clients who have had an indwelling urinary catheter in place to develop urinary B retention. If a client does not urinate for 6 to 8 hr after catheter removal, or if the client urinates less than 100 mL with each urination, the |_| nurse should use a bladder scanner to check post void residual. If the client is retaining more than 200 mL of urine and does not respond to c | strategies to promote voiding, the nurse should notify the provider. Insertion of a straight catheter might become necessary. D |", "whyNot": {"b": "Burning or pain with urination is a manifestation of a urinary tract infection (UTI), which is not an expected outcome following catheter", "c": "Blood in the urine indicates trauma, which is not an expected outcome following the removal of an indwelling urinary catheter.", "d": "Highly concentrated urine indicates that the client is not receiving enough fluid. Catheter removal does not affect urine concentration."}, "keyConcept": "When clients are having difficulty voiding after urinary catheter removal, the nurse can try several techniques for encouraging urination: + Have clients assume their usual position for urinating. + Pour warm water over the perineal area. + Apply a hot water bottle to the lower abdomen. + Have clients gently press over their pubic area or lean forward to exert pressure over the bladder. (For some clients, this will require the provider's approval.) + Turn on a nearby faucet so clients can hear running water. + Place one of the client's hands in a basin of warm water. + Encourage double voiding: after urination stops, have clients attempt to urinate again."}, {"id": 11554, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "drink. The client complains that his medication is not strong enough to treat his pain. Which of the following should the nurse consider when assessing this client?", "choices": [{"id": "a", "t": "Clients with a history of substance abuse overreact to pain."}, {"id": "b", "t": "Frequent use of an opioid analgesic will result in addiction."}, {"id": "c", "t": "Clients who have a history of substance abuse, including alcohol, exaggerate their pain to obtain additional narcotic analgesics."}, {"id": "d", "t": "Clients with minor injuries do not always have less pain than those with major alterations."}], "correct": "d", "rationale": "A l 3% Moderate When assessing a client with pain, nurses should remember that biases and preconceived ideas about pain may be incorrect and should not B | see influence the nurse’s assessment of pain. In this example, the nurse should remember that clients who have minor injuries, surgeries, or illnesses do not always have less pain than others who have major injuries or changes. The most reliable assessment of a client’s pain is the © | Me patient’s self-report. @D i 65%", "whyNot": {"b": "Frequent use of an opioid analgesic may lead to tolerance over a period of time, but it does not necessarily result in addiction. Tolerance", "c": "This bias can prevent healthcare providers from providing adequate relief of pain experienced by individuals with current or former"}, "keyConcept": "The most reliable indicator of the severity of pain is the client's self report. A nurse should be aware of personal biases and preconceived ideas when assessing a client with pain. Clients with a history of substance use disorder sometimes do not receive adequate analgesia as a result of bias and mistaken beliefs."}, {"id": 11555, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is preparing to complete postmortem care for a client's body. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Remove the client's dentures."}, {"id": "b", "t": "Place the client's arms and hands under the clean linens."}, {"id": "c", "t": "Place a pillow under the client's head and shoulders."}, {"id": "d", "t": "Perform a complete bed bath."}], "correct": "c", "rationale": "A The nurse should place a pillow under the client's head to prevent blood from discoloring the client face. B - oc", "whyNot": {"a": "The nurse should keep the client's dentures in place to help maintain a more natural appearance of the face for the family when viewing", "b": "The nurse should place the client's arms and hands on top of the clean linens, either at the client's sides or across the chest to promote a", "d": "The nurse does not need to perform a complete bed bath for the client because the mortician will bathe the body at the mortuary."}, "keyConcept": "Postmortem care of the client's body after death is completed because it is common for the client's family to want to view the body. The deceased client's body deserves respect and dignity and needs to be prepared in accordance with the client's cultural and religious beliefs. The family might need some time to mourn the loss of their loved one, and the nurse should maintain an unrushed atmosphere when they visit."}, {"id": 11556, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is applying antiembolic stockings for a client who is postoperative. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Apply the stockings while the client is sitting in a chair."}, {"id": "b", "t": "Apply the foot portion while the client flexes their foot."}, {"id": "c", "t": "Check the stockings for wrinkles."}, {"id": "d", "t": "Measure the size of the client's foot."}], "correct": "c", "rationale": "A The nurse should check the stockings for wrinkles or constriction that can increase the risk for skin breakdown and circulation impairment. B : The nurse should smooth the fabric to eliminate creases and wrinkles. o:", "whyNot": {"a": "The nurse should apply the stockings before the client gets out of bed to reduce the risk for dependent edema.", "b": "The nurse should apply the foot portion while the client points their toes.", "d": "The nurse should measure the circumference of the client's calf and thigh at the widest point before obtaining the antiembolic stockings"}, "keyConcept": "Elastic antiembolic stockings exert external pressure on the muscles of the lower extremities to promote blood return to the heart. They are a preventive measure for thromboembolic events, such as deep-vein thrombosis. They also help prevent edema in the lower extremities. Whenever clients are at risk for venous stasis, such as postoperatively, nurses should apply antiembolic stockings in the morning before the client is out of bed or after elevating the client's legs for 15 to 30 min."}, {"id": 11557, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who is undergoing peritoneal dialysis. The nurse understands that which of the following is the most reliable indication of the efficacy of peritoneal dialysis?", "choices": [{"id": "a", "t": "Decreased blood pressure"}, {"id": "b", "t": "Hematemesis"}, {"id": "c", "t": "Weight loss"}, {"id": "d", "t": "Decreased urine output"}], "correct": "c", "rationale": "The purpose of peritoneal dialysis is to remove excess fluid and waste that cannot be excreted by the kidneys. The best indicator that the dialysis treatment has been successful is weight loss. Therefore, it is important for the client to be weighed before and after the treatment. Decreased urine output and hematemesis are NOT expected results of dialysis. Although blood pressure MIGHT be decreased, that indicator is not a reliable measure of the success of peritoneal dialysis.", "whyNot": {"a": "Blood pressure may decrease during dialysis, but decreased blood pressure is not a reliable indicator of the success of peritoneal dialysis.", "b": "Hematemesis is not an expected outcome of peritoneal dialysis and does not indicate success.", "d": "Decreased urine output is not an expected outcome of peritoneal dialysis and does not indicate success."}, "keyConcept": "Peritoneal dialysis uses the peritoneal membrane, as a filter membrane across which fluids, electrolytes, urea, glucose, albumin and other small molecules are exchanged from the blood. Like hemodialysis, peritoneal dialysis depends upon the passive movement of water and dissolve solutes across a semipermeable membrane by diffusion. Movement of solutes occurs down a concentration gradient from fluid with higher concentration to fluid with lower concentration. With dialysis, the client is at risk of deficient fluid volume. The desired outcome is to achieve the target alteration in fluid volume and weight, with blood pressure and electrolyte levels remaining in an acceptable range without symptoms of dehydration in the client. Dialysate fluid ‘Waste fluid Continuous Ambulatory Peritoneal Dialysis"}, {"id": 11558, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has a new prescription for continuous enteral feeding through an open system. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Reconstitute the formula with tap water."}, {"id": "b", "t": "Replace the bag and tubing every 24 hr."}, {"id": "c", "t": "Administer 100 mL of formula per hour."}, {"id": "d", "t": "Give the initial feeding over 15 min."}], "correct": "b", "rationale": "all 7% Easy The nurse should replace the bag and tubing of an open system every 24 hr to reduce the risk for bacterial growth. It is safe to hang closed OB TCS BO systems for 24 to 48 hr. ° cl 1% og 6%", "whyNot": {"a": "The nurse should reconstitute the formula with sterile water to reduce the risk for bacterial growth.", "c": "The nurse should begin continuous enteral feedings at a rate of no faster than 60 mL/hr. A common initial rate is 10 to 20 mL/hr, especially", "d": "Continuous feedings are ongoing, generally over 24 hr each day, though some clients receive feedings over 8 to 12 hr each day. The nurse"}, "keyConcept": "Continuous enteral feedings require an infusion pump. The formula can be in an open system, for which the nurse prepares the formula and pours it into a bag, or a closed, prefilled, ready-to-hang system that requires no special preparation. Open systems have a greater risk for bacterial contamination, and nurses should adhere to principles of medical asepsis when handling them."}, {"id": 11559, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who wears dentures. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Wrap the dentures in moist gauze when not in the client's mouth."}, {"id": "b", "t": "Use a firm-bristle toothbrush to cleanse the dentures."}, {"id": "c", "t": "Discourage the client from removing the dentures for more than 4 hr at one time."}, {"id": "d", "t": "Rinse the dentures after the client eats."}], "correct": "d", "rationale": "A The nurse should rinse the client's mouth and dentures after meals to prevent denture-induced stomatitis. B s o>", "whyNot": {"a": "The nurse should cover the dentures in water when the client is not wearing them to prevent warping.", "b": "The nurse should use a soft-bristle toothbrush or a denture toothbrush to clean the dentures to prevent scratching of the surface.", "c": "The nurse should encourage the client to remove dentures at night to prevent bacterial buildup, rest the gums, and prevent denture-"}, "keyConcept": "The nurse caring for a client who wears dentures should know how to properly care for the dentures. This includes the use of correct handling, storage, and cleaning process. The nurse should assess the client for ill-fitting dentures, cracks of the surfaces of the dentures, oral lesions, or oral discomfort."}, {"id": 11560, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is providing nutritional teaching to the guardian of an infant who has heart failure. Which of the following guardian statements indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\" will feed my baby every 4 hours.\""}, {"id": "b", "t": "\"I will add corn oil to my baby's bottles.\""}, {"id": "c", "t": "\"I will give my baby a minimum of 1 hour to finish a bottle.\""}, {"id": "d", "t": "\"1 will place my baby on her stomach for a few minutes each day.\""}], "correct": "b", "rationale": "A || The guardian should add corn oil produced just for consumption by infants to fortify the formula by increasing the number of calories per On | ounce. This addition allows the infant to consume more calories in a smaller amount of formula. ci om", "whyNot": {"a": "The guardian should feed the infant every 3 hr because of the increased metabolic rate and fatigue that limits adequate calorie intake.", "c": "The nurse should instruct the guardian to limit bottle time to 30 min. The guardian should avoid allowing the infant to take as much time", "d": "The nurse should instruct the guardian to hold the infant at a 45° angle during feedings. The guardian should avoid placing the infant"}, "keyConcept": "Manifestations of Heart Failure +» Tachycardia + Restlessness » Dyspnea + Nasal flaring +» Wheezing + Grunting + Weight gain + Distended neck veins 28% 31% 26% 14%"}, {"id": 11561, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "lithium toxicity? O A.\"I should notify my provider if | develop constipation.\" O B. \"I should avoid exercising outdoors on hot days.\" O C. \"I should consume a low-sodium diet.\" O D. \"I should expect to have my blood drawn once per year.\"", "choices": [{"id": "a", "t": "11%"}, {"id": "b", "t": ". A low sodium level, or OB TY ea factors that cause a low sodium level, such as dehydration, diarrhea, sweating, exercising outside in hot weather, diuretic use, and a low ° sodium diet, cause the body to conserve lithium and results in elevated lithium levels."}, {"id": "c", "t": "The nurse should instruct the client to eat a diet that consists of regular amounts of sodium because lithium excretion is decreased when"}, {"id": "d", "t": "The nurse should instruct the client to have their blood drawn frequently throughout the year to check for lithium toxicity. When lithium"}], "correct": "b", "rationale": ". A low sodium level, or OB TY ea factors that cause a low sodium level, such as dehydration, diarrhea, sweating, exercising outside in hot weather, diuretic use, and a low ° sodium diet, cause the body to conserve lithium and results in elevated lithium levels. c || 22% oe | 4%", "whyNot": {"a": "The nurse should instruct the client to notify the provider if vomiting or diarrhea occurs because these conditions can lower sodium levels,", "c": "The nurse should instruct the client to eat a diet that consists of regular amounts of sodium because lithium excretion is decreased when", "d": "The nurse should instruct the client to have their blood drawn frequently throughout the year to check for lithium toxicity. When lithium"}, "keyConcept": "It is important for a client who takes lithium to understand what factors can increase their lithium level and what factors can lead to toxic levels. The client should maintain adequate fluid intake up to 3,000 mL daily and should understand factors that cause dehydration, such as exercising in hot weather, vomiting, and diarrhea. Maintaining a diet that contains a consistent and moderate amount of sodium can also help to prevent lithium toxicity."}, {"id": 11562, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "the following of the client's current medications?", "choices": [{"id": "a", "t": "Loratadine"}, {"id": "b", "t": "Prednisone"}, {"id": "c", "t": "Furosemide"}, {"id": "d", "t": "Ibuprofen"}], "correct": "d", "rationale": "‘i The nurse should inform the client that ibuprofen is an NSAID which can cause a potential interaction with gingko biloba. Taking ibuprofen B | and gingko biloba concurrently can increase the client's risk of bleeding.", "whyNot": {"a": "Loratadine is an antihistamine and does not cause a potential interaction with gingko biloba. However, loratadine can interact with the", "b": "Prednisone is a corticosteroid and does not cause a potential interaction with gingko biloba. However, prednisone can interact with the", "c": "Furosemide is a loop diuretic and does not cause a potential interaction with gingko biloba. However, furosemide can interact with the"}, "keyConcept": "It is the nurse's responsibility to inform a client of potential interactions between medications they are currently taking or plan to take. This should include the use of herbal supplements and their potential interactions with other medications."}, {"id": 11563, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who reports that they think they are grinding their teeth at night. The nurse should document this finding as which of the following disorders?", "choices": [{"id": "a", "t": "Xerostomia"}, {"id": "b", "t": "Cheilosis"}, {"id": "c", "t": "Bruxism"}, {"id": "d", "t": "Sordes"}], "correct": "c", "rationale": "sll Bruxism, a clenching or grinding of the teeth during sleep, usually takes place during stage two of non-rapid eye movement (REM) sleep. It B | can eventually damage the teeth, make them loose, and erode dental crowns. A dentist can provide a custom-fitted, comfortable dental appliance to protect the teeth during sleep. ec | of}", "whyNot": {"a": "Xerostomia is dryness of the mouth.", "b": "Cheilosis is cracking of the lips, which requires lubrication and possibly antibiotic ointment to treat or prevent infection.", "d": "Sordes is an accumulation of foul brown crusts of food, microorganisms, and epithelial elements on the teeth and lips, usually due to a"}, "keyConcept": "Some clients who have bruxism are unaware that they are grinding their teeth, especially those who sleep alone. Because bruxism can also cause temporomandibular (TMJ) syndrome, they are more likely to report to nurses that they have jaw pain. In addition to oral appliance therapy, treatment of TMJ syndrome often includes analgesics and muscle relaxants."}, {"id": 11564, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "the appropriate response by the nurse?", "choices": [{"id": "a", "t": "Have another witness confirm that the client consumed his meal."}, {"id": "b", "t": "Withhold a portion of meals in the future to offer if the client asks for his meal soon after eating."}, {"id": "c", "t": "Tell the client that he has already eaten but another meal will be served soon."}, {"id": "d", "t": "Remind the client calmly during the course of the day that he has eaten."}], "correct": "b", "rationale": "A l 3% Hard Dementia, including Alzheimer’s dementia and Lewy body dementia, can result in a variety of problems with eating and nutrition that can OB | Ban advance with advanced stages of the disease. Early in the course of dementia, clients may forget that they have eaten a recent meal. In these cases, they should be offered something to eat when they say they are hungry. Options include serving multiple small meals throughout the c |__| 27% day while providing low-calorie snacks when the client asks for food after forgetting consumption of a recent meal. Other problems seen D Ye 47% with early stages of dementia with respect to eating and nutrition include anorexia and weight loss due to depression, sometimes caused by recognition of the onset of the disorder. During the middle stages, individuals with progressive dementia may forget to eat and become unable to recognize hunger or thirst sensations. They may refuse to eat or become too restless to sit still for consumption of their meals. Some forget how to use utensils, and others may consume non-food items. Late stages of dementia are characterized by dysphagia and inability to feed oneself.", "whyNot": {"a": "This confrontational approach may cause anxiety and agitation. The therapeutic response is validation and acceptance of the client’s", "c": "This approach may further increase the client’s frustration and agitation. The delay will not meet the client’s stated need or resolve the", "d": "Although this type of reality check has been considered useful in clients with confusion due to delirium or dementia in past practice, the"}, "keyConcept": "Anumber of factors contribute to the risk for inadequate nutritional intake by clients with dementia. These factors initially include forgetfulness and anorexia due to depression. As dementia progresses, factors that affect adequate nutrition and consumption include inability to recognize sensations of hunger or thirst, forgetting to eat; agitation or restlessness; inability to use utensils; dysphagia; and inability to self-feed."}, {"id": 11565, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse in an urgent care clinic is providing teaching about using crutches to a client who has injured her left foot. Which of the following statements by the client indicates an understanding of the teaching? O A.\"| will keep spare crutch tips handy.\" O B. \"I will bear the weight of my body on my underarms.\" O C. \"| have a set of my father's crutches in my basement | can also use.\" O D. \"When | go down stairs, | will put my crutches and my right foot on the next step first.\"", "choices": [{"id": "a", "t": "Clients who use crutches should keep spare parts handy."}, {"id": "b", "t": "It is important that the client bears the weight of her body on her hands and not her axillae."}, {"id": "c", "t": "The client should not use crutches that belong to someone else. The client's crutches must fit her body dimensions."}, {"id": "d", "t": "The client should first shift her weight to her right foot and move the crutches and her left foot down to the next step. Then, she should"}], "correct": "a", "rationale": "Clients who use crutches should keep spare parts handy. Crutch tips prevent slippage and further injury. B I a", "whyNot": {"b": "It is important that the client bears the weight of her body on her hands and not her axillae.", "c": "The client should not use crutches that belong to someone else. The client's crutches must fit her body dimensions.", "d": "The client should first shift her weight to her right foot and move the crutches and her left foot down to the next step. Then, she should"}, "keyConcept": "Crutches helps clients walk while minimizing or eliminating weight-bearing on an injured lower extremity. Clients require crutches that a health care professional has measured specifically for them. They should allow 2.5 to 5 cm (1 to 2 in) between the axilla and the crutch pad and allow an elbow flexion angle of about 30 degrees. The nurse must teach the client how to stand, walk, get in and out of a chair, and go up and down stairs."}, {"id": 11566, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is planning to assist a client with taking a shower. Which of the following information should the nurse provide regarding the use of a shower chair?", "choices": [{"id": "a", "t": "\"Iwill turn the water on once you feel comfortable in the shower chair.\""}, {"id": "b", "t": "\"Using a shower chair will minimize fatigue while taking a shower.\""}, {"id": "c", "t": "\"The shower chair can assist you with getting in and out of the shower.\""}, {"id": "d", "t": "\"Having a shower chair can allow you to spend up to 20 minutes or more in the shower.\""}], "correct": "b", "rationale": "All 10% Easy The use of a shower chair will assist the client with independence in performing personal hygiene tasks and will increase the safety of the OB TY 79% client in the shower. It will also facilitate the client with the process of bathing and minimize physical exertion during the bathing process. ° ci 10% p | 1%", "whyNot": {"a": "The nurse should have the water running prior to the client entering the shower. This allows the nurse to adjust the water temperature to", "c": "The nurse should teach the client how to use safety rails and bars to assist with getting in and out of the shower. The nurse should", "d": "The nurse should not instruct the client to spend more than 15 min in the shower. A client who has prolonged exposure to warm water can"}, "keyConcept": "The nurse assisting a client with personal hygiene care should provide information about any assistive devices used for the process. The nurse should explain the purpose of any assistive devices and should teach the client how to use the device safely."}, {"id": 11567, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who is unconscious. When positioning the client, the nurse understands that compression of which of the following structures will result in wrist drop?", "choices": [{"id": "a", "t": "Lateral cord of brachial plexus"}, {"id": "b", "t": "Radial nerve"}, {"id": "c", "t": "Median nerve"}, {"id": "d", "t": "Ulnar nerve"}], "correct": "b", "rationale": "a Wrist drop is the result of injury to the radial nerve. It can result from external compression or a fracture of the humerus anywhere along the OB a course of the nerve. The radial nerve originates from the posterior cord of the brachial plexus and travels from the axilla along the humerus into the anterior compartment of the arm above the lateral epicondyle, dividing into two branches in the forearm. The radial nerve motor c |_| fibers innervate the triceps, anconeus, and forearm extensor muscles. These muscles extend the elbow and wrist, supinate the forearm, and D | extend and abduct the thumb. When positioning an unconscious client, the wrist should be supported with padding or cockup wrist splint to prevent radial nerve compression in the dorsum of the wrist.", "whyNot": {"a": "The posterior cord of the brachial plexus gives off the radial nerve at the axilla.", "c": "Median nerve palsy causes loss of wrist and finger flexion and usually results from trauma or penetrating injury.", "d": "Ulnar nerve dysfunction can result in loss of hand grip strength and finger coordination with pain or paresthesia in the little finger and"}, "keyConcept": "Splints, padding, and other assistive devices are used to maintain joints in a neutral position in a client who is unconscious or immobile. When caring for a client who is immobile, the nurse should perform complete range of motion exercises for each joint at least twice a day and massage the extremities to promote circulation and prevent thrombosis."}, {"id": 11568, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is planning care for a client who requires cold therapy with an ice bag to reduce the swelling and pain of an ankle injury. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Apply the bag for 10-20 min at a time."}, {"id": "b", "t": "Check the client's skin two times each hour."}, {"id": "c", "t": "Allow room for some air inside the bag."}, {"id": "d", "t": "Place the bag directly on the client's skin."}], "correct": "a", "rationale": "The nurse should leave the bag in place for 10-20 min, then remove the ice bag for 1 hr, to reduce the risk for tissue injury. B i 10% fo", "whyNot": {"b": "The nurse should check the client's skin under the ice bag every 15 to 20 min to assess for tissue damage.", "c": "The nurse should remove excess air from the ice bag because air can block the conduction of cold to the injury. iii]", "d": "The nurse should place a towel, the bag's cover material, or a pillowcase between the ice bag and the client's skin to reduce the risk for 2"}, "keyConcept": "< Cold therapy is used to treat sprains, strains, fractures, minor burns, and injured joints. It reduces pain and decreases blood flow, inflammation, and edema to the area of injury. Cold therapy is contraindicated in clients who have neurosensory impairment, impaired mental status, impaired circulation, edema, or open wounds due to the risk for tissue injury. The nurse should place a towel, the bag's cover material, or a pillowcase between the ice bag and the client's skin to reduce the risk for tissue injury. The nurse should use a timer to time the cold application, check the client's skin every 15 to 20 min during application, and remove the ice bag every 30 min for 1 hr. Adverse effects of cold therapy can include hypertension, shivering, impaired circulation, and tissue damage. The nurse should instruct the client to report increased pain or discomfort that can indicate injury to tissue."}, {"id": 11569, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client with metastatic cancer. Although his pain is uncontrolled, he refuses opioid medications. Which of the following is a common factor that may result in undertreatment of the client's pain?", "choices": [{"id": "a", "t": "Middle age"}, {"id": "b", "t": "Genetic sensitivity"}, {"id": "c", "t": "Fear of addiction"}, {"id": "d", "t": "Presence of a support system"}], "correct": "c", "rationale": "Common factors that increase the risk of undertreatment of pain include fear of addiction, lack of knowledge, cultural and societal attitudes, and exaggerated fear of respiratory depression. Populations who are at risk for the undertreatment of pain include infants, children, individuals with substance use disorder, and older adults. Pain should be understood as described by the person experiencing it, and healthcare professionals should understand that the self-report of the client is the most reliable diagnostic measure of pain.", "whyNot": {"a": "Infants are at risk because they are unable to verbalize pain or understand it, and older adults may have multiple comorbidities that limit", "b": "Genetic sensitivity has an effect on tolerance of pain but is not a risk factor for undertreatment.", "d": "Asupport system or lack of one can affect the client’s experience of pain."}, "keyConcept": "Undertreatment of pain may result from a client's fear of addiction or respiratory depression, lack of knowledge, or from the influence of cultural and societal attitudes. Populations who are at risk of undertreatment of pain include infants, children, older adults, and individuals with substance use disorders."}, {"id": 11570, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has limitations in mobility. Which of the following actions should the nurse take to help maintain the integrity of the client's skin?", "choices": [{"id": "a", "t": "Reposition the client every 3 hr."}, {"id": "b", "t": "Massage bony prominences to promote circulation."}, {"id": "c", "t": "Provide the client with a diet that is high in protein."}, {"id": "d", "t": "Have the client shift their weight every 30-45 min when sitting."}], "correct": "c", "rationale": "A An inadequate intake of protein, vitamins (especially vitamins A and C), minerals (especially zinc), fluids, and calories increases the client's B ' risk for skin breakdown. o: >=", "whyNot": {"a": "Frequent position changes are important for preventing skin breakdown. The nurse should reposition the client at least every 2 hr.", "b": "Massaging the skin over bony prominences can traumatize deep tissues.", "d": "The nurse should have the client shift their weight every 15-30 min when sitting in a chair or wheelchair."}, "keyConcept": "Preventing skin breakdown is a priority for clients who have limited mobility. In addition to adequate nutrition and hydration, frequent repositioning and the use of pressure-relieving devices can help prevent pressure ulcers on bony prominences. For clients who have urinary incontinence, fecal incontinence, or both, meticulous hygiene and application of a moisture barrier are necessary to prevent skin breakdown."}, {"id": 11571, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is teaching a client who has a new diagnosis of acne vulgaris. Which of the following instructions should the nurse include?", "choices": [{"id": "a", "t": "Use friction when washing the affected area."}, {"id": "b", "t": "Use a mild soap to wash affected areas daily."}, {"id": "c", "t": "Express the larger pustules periodically."}, {"id": "d", "t": "Cover pustules with an oil-based cosmetic."}], "correct": "b", "rationale": "The nurse should instruct the client to use warm water and a mild, noncomedogenic, or nonoil-based soap daily to wash the affected areas.", "whyNot": {"a": "The nurse should instruct the client to avoid using friction because this can cause an increase in inflammation.", "c": "The nurse should instruct the client to avoid expressing the pustules because this can increase the risk for scarring and result in an", "d": "The nurse should instruct the client to avoid cosmetics, creams, and shaving cream that can cause an increase in acne."}, "keyConcept": "Acne vulgaris is a chronic skin condition that is characterized by comedones, or whiteheads and blackheads, papules, pustules, nodules, and cysts. It occurs when sebum plugs pilosebaceous ducts or pores. The nurse should instruct the client to wash their hair and the affected area each day with warm water and mild soap; use nonoil-based cosmetics sparingly; avoid oil-based cosmetics, creams, or lotions; avoid foods containing refined sugars; avoid friction, rubbing, and touching the face; and avoid expressing or picking pustules."}, {"id": 11572, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has dysphagia and is receiving continuous enteral feedings via a gastrostomy tube. Which of the following actions is the nurse's priority?", "choices": [{"id": "a", "t": "Observe the tube's insertion site for irritation or leakage."}, {"id": "b", "t": "Elevate the head of the client's bed 30° to 45°."}, {"id": "c", "t": "Monitor intake and output every 8 hr."}, {"id": "d", "t": "Check residual volume every 4 to 6 hr."}], "correct": "b", "rationale": "A Hi 15% Moderate The greatest risk to this client is injury from aspiration of enteral formula if regurgitation or vomiting occurs; therefore, the priority action the OB a 78% fo nurse should take is to keep the head of the bed elevated, preferably to 45°, to promote gastric emptying and to help keep formula or secretions from entering the trachea. c | 1% off 8%", "whyNot": {"a": "The nurse should check the gastrostomy tube's insertion site to identify irritation, skin breakdown, leakage, or a poor fit. This allows the", "c": "The nurse should monitor the client's intake and output to help assess fluid balance and hydration status. However, another action is the", "d": "The nurse should check the residual volume every 4 to 6 hr to help assess gastric emptying and to prevent overfeeding if gastric emptying"}, "keyConcept": "The risk for aspiration increases for clients who have difficulty swallowing, impairment of the gag reflex, diminished consciousness, and gastric reflux. For these clients, aspiration precautions are essential and include upright positioning to the extent the client's status allows as well as having suction equipment functional and available at all times."}, {"id": 11573, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is providing teaching to a client who has a new diagnosis of obstructive sleep apnea. Which of the following statements should the nurse make?", "choices": [{"id": "a", "t": "\"Sleep apnea increases your risk for developing type 1 diabetes mellitus.\""}, {"id": "b", "t": "\"Sleep apnea occurs when you stop breathing for at least 10 seconds.\""}, {"id": "c", "t": "\"Sleep apnea is caused by a malfunction in the right lobe of the brain.\""}, {"id": "d", "t": "\"Sleep apnea causes excessive episodes of REM sleep.\""}], "correct": "b", "rationale": "Sleep apnea is a disorder that causes the client to have cessation of airflow through the mouth and nose for at least 10 seconds. The structures in the mouth or nose relax during sleep, causing the obstruction.", "whyNot": {"a": "Sleep apnea increases the client's risk for hypertension, stroke, cardiac dysrhythmias, and pulmonary hypertension. It does not increase", "c": "Central sleep apnea is caused by a dysfunction in the respiratory center of the client's brain. Obstructive sleep apnea is caused by", "d": "Sleep apnea causes awakening during sleep, interfering with the client's ability to maintain a deep, rapid eye movement (REM) sleep"}, "keyConcept": "Obstructive sleep apnea is a potentially serious sleep disorder. It causes breathing to repeatedly stop and start during sleep. There are several types of sleep apnea, but the most common is obstructive sleep apnea. This type of apnea occurs when the throat muscles intermittently relax and block the airway during sleep. A noticeable sign of obstructive sleep apnea is snoring. These disruptions in sleep can occur up to 30 times or more each hour, all night long. Therefore, it will impair the client's ability to reach the desired deep, restful phases of REM sleep, and cause the client to feel sleepy during waking hours."}, {"id": 11574, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is preparing to perform postmortem care. Which of the following actions should the nurse plan to take?", "choices": [{"id": "a", "t": "Ask the family to leave the room while postmortem care is being provided."}, {"id": "b", "t": "Identify the client using two identifiers prior to initiating postmortem care."}, {"id": "c", "t": "Remove the client's dentures and return them to the family."}, {"id": "d", "t": "Place the bed in a supine position to perform postmortem care."}], "correct": "b", "rationale": ", date of birth, or medical record number prior to initiating eB | 61% fo postmortem care. I 4% c mC 31%", "whyNot": {"a": "The nurse should ask the family if anyone desires to assist with preparing the body. If so, the nurse should make arrangements for their", "c": "The nurse should leave the dentures in place to preserve the shape of the client's face.", "d": "The nurse should raise the head of the bed as quickly as possible after death to prevent discoloration of the face."}, "keyConcept": "A nurse has the responsibility for performing or delegating postmortem care. The nurse should document end-of-life care in the client's medical record. Documentation should include the following information: + Time and date of death and all actions taken to respond to the impending death + Name of health care provider certifying the death + People notified of the death + Names of any individuals making requests for organ or tissue donations + Special preparations of the body + Medical tubes, devices, or lines left in or on the body + Personal items left on or secured to the body + Personal items given to the family with description, date, time, and the recipient's name + Location of body identification tags"}, {"id": 11575, "cat": "Physiological Integrity-Basic Care & Integrity", "stem": "A nurse is caring for a client who has balance issues. When assisting the client to ambulate, which of the following devices should the nurse use? O a Gait belt O B. Jacket harness O C. Four-wheel walker O D. Crutches", "choices": [{"id": "a", "t": "o; The nurse should use a gait belt to help support a client during ambulation."}, {"id": "b", "t": "The nurse should use a jacket harness to keep a client from falling out of a chair."}, {"id": "c", "t": "Awalker can help clients who have balance issues; however, a walker with wheels can increase the client's risk for falling if they lean"}, {"id": "d", "t": "Crutches are used for clients who have weight-bearing limitations on one or both feet. They will not help clients who have balance injuries"}], "correct": "a", "rationale": "o; The nurse should use a gait belt to help support a client during ambulation. A gait belt helps keep the client's center of gravity stable and B | helps maintain balance and prevent falls. ci >|", "whyNot": {"b": "The nurse should use a jacket harness to keep a client from falling out of a chair.", "c": "Awalker can help clients who have balance issues; however, a walker with wheels can increase the client's risk for falling if they lean", "d": "Crutches are used for clients who have weight-bearing limitations on one or both feet. They will not help clients who have balance injuries"}, "keyConcept": "Atransfer, or gait, belt is a wide piece of canvas that fits around the client's waist and has a buckle to keep it in place. To allow for a better grip, some transfer belts have add-on handles on each side. Using this device during ambulation can also help with moving the client from a sitting to a standing position. If the client becomes weak or dizzy while walking and begins to fall, the nurse shouldn't try to hold them up or catch them, but the nurse should instead use the gait belt to help ease them gently to the floor."}], "physiological_integrity_reduction_of_risk_potential": [{"id": 11576, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is planning care for a client scheduled to have vertebroplasty of the thoracic spine. Which of the following interventions should the nurse include in the plan of care?", "choices": [{"id": "a", "t": "Apply heat to the puncture site."}, {"id": "b", "t": "Place the client in a supine position."}, {"id": "c", "t": "Remove the dressings after the third day."}, {"id": "d", "t": "Ambulate the client within the first hour after the procedure."}], "correct": "b", "rationale": "1 to 2 hr following the procedure to allow for hardening of the eB rd 59% fo cement. ci 16%", "whyNot": {"a": "The nurse should apply cold therapy to the puncture site to decrease bleeding and swelling, and to relieve pain following the procedure.", "c": "The nurse should remove the dressings the day following the procedure. The nurse should provide discharge instructions that include", "d": "The nurse should have the client remain in a supine position with the bed flat for 1 to 2 hr following the procedure. The client can resume"}, "keyConcept": "Avertebroplasty is a diagnostic procedure that is performed in the surgical or radiology department under moderate sedation. During the procedure, bone cement is injected percutaneously into the fractured vertebrae to stabilize the injured site and relieve pain. The procedure is not recommended for clients who have an infection, are taking anticoagulants, or have multiple old fractures. The client should remain supine for 1 to 2 hr after the procedure with an ice pack applied to the puncture site to decrease swelling, bleeding, and discomfort. Mild analgesics should be administered if the client has pain. The nurse should monitor the site for bleeding, check for shortness of breath, and report any changes to the provider. After discharge, the client should have a family member or friend remove the dressing the next day and check the site for signs of infection. The client can resume the usual activities of daily living, especially walking, the next day."}, {"id": 11577, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is teaching a client who has seizures about going home with her new vagal nerve stimulator. Which of the following statements should the nurse include in the teaching? O A.\"You should use hypoallergenic lotion on your skin in the area of the device.\" O B. \"Notify your provider if you experience hiccups.\" O C. \"You should place the special magnet over the device when you feel an aura occurring.\" O D. \"It is recommended that you use ultrasound diathermy for pain management.\"", "choices": [{"id": "b", "t": "The nurse should instruct the client to monitor for complications that can develop following the placement of a vagal nerve stimulator"}, {"id": "c", "t": ". This practice B rd aay has been shown to lessen the severity and duration of the seizure that follows."}, {"id": "d", "t": "The nurse should instruct the client to notify health providers of the presence of the vagal nerve stimulator because exposure to MRI"}], "correct": "c", "rationale": ". This practice B rd aay has been shown to lessen the severity and duration of the seizure that follows. (See image below) ° p| 2% po] e o 2 ° s a = a <", "whyNot": {"b": "The nurse should instruct the client to monitor for complications that can develop following the placement of a vagal nerve stimulator", "d": "The nurse should instruct the client to notify all health providers of the presence of the vagal nerve stimulator because exposure to MRI"}, "keyConcept": "Nurses can provide both educational and emotional support to clients whose lives are impacted daily by seizure disorders. Because clients"}, {"id": 11578, "cat": "physiological integrity- Reduction of risk potential", "stem": "has this disorder? O A. Serum triiodothyronine O B. Plasma-free metanephrine O C. Urine chloride O D. Urine osmolality", "choices": [{"id": "a", "t": "Serum triiodothyronine"}, {"id": "b", "t": "Plasma-free metanephrine"}, {"id": "c", "t": "Urine chloride"}, {"id": "d", "t": "Urine osmolality"}], "correct": "a", "rationale": "Increased serum triiodothyronine (T3) indicates hyperthyroidism. B | 3\" c] 3% 9", "whyNot": {"b": "An increase in plasma-free metanephrine indicates the presence of a pheochromocytoma, which is a tumor of the cells of the adrenal", "c": "A high urine chloride level indicates Addison's disease.", "d": "Increased urine osmolality indicates syndrome of inappropriate antidiuretic hormone secretion (SIADH)."}, "keyConcept": "Testing for thyroid function includes measuring blood levels of the following: © Triiodothyronine (T3) © Thyroxine (T4) © Thyroid-stimulating hormone (TSH) T3 and T4 levels will be increased with hyperthyroidism. Thyroid-stimulating hormone (TSH) levels will be decreased with Graves’ disease, the most common type of hyperthyroidism, and increased with secondary or tertiary hyperthyroidism. Other diagnostic testing for hyperthyroidism includes thyroid scanning with radioactive iodine and an ultrasound to determine the size of the thyroid and if any masses are present. An ECG may also be performed to determine if dysrhythmias are present."}, {"id": 11579, "cat": "physiological integrity- Reduction of risk potential", "stem": "oximeter probe to which of the following locations?", "choices": [{"id": "a", "t": "Finger"}, {"id": "b", "t": "Earlobe"}, {"id": "c", "t": "Toe"}, {"id": "d", "t": "Forehead"}], "correct": "b", "rationale": "All The earlobe is rarely edematous, is the least affected by decreased blood flow, and has greater accuracy when measuring oxygen saturation. OB rT CiS@Y cl", "whyNot": {"a": "Edema of the hands and fingers interferes with blood circulation in the capillary bed. Therefore, the oximeter probe might not be able to", "c": "Thickening of nails interferes with blood circulation in the capillary bed. Therefore, the oximeter probe might not be able to adequately", "d": "Forehead sensors are preferred for the client who is critically ill and requires vasopressor medications."}, "keyConcept": "Nurses are responsible for measuring the oxygen saturation level of clients. Nurses should be aware of the various types of probes and when each one should be used. Factors Affecting Determination of Oxygen Saturation with Light Trans with Arterial Outside aght sources Atheroscieross Carton mono trom smoke innalaton ypomersa Dark skin pigment \\Vasoconstrictor medications ‘Black oF brown nal polish / metal studs in naits Low cardiac output Thickened naits, dardce stypetension Client moton such as tremors Penphera! edera Intravascular dyes used for treatment and diagnostics ‘Tight probe:"}, {"id": 11580, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is reviewing the laboratory results of a client who has fluid volume overload. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Urine specific gravity 1.022"}, {"id": "b", "t": "Hematocrit 34% © c. BUN 19 mg/d © D. Sodium 150 mEq/L"}], "correct": "b", "rationale": "a Ahematocrit of 34% is below the expected reference range of 37% to 47% for female clients and 42% to 53% for male clients. A client On a experiencing fluid volume overload would manifest a decreased hematocrit. cil >=", "whyNot": {"a": "Aurine specific gravity of 1.022 is within the expected reference range of 1.005 to 1.030. A client experiencing fluid volume overload would"}, "keyConcept": "A nurse caring for the client who has fluid volume overload should be able to identify the expected laboratory findings for this imbalance. The nurse should also be able to identify other manifestations, including: + Weight gain of 1 kg (2 lb) or more in 24 hr + Edema, especially in dependent areas + Full neck veins when upright or semi-upright + Crackles in lungs"}, {"id": 11581, "cat": "physiological integrity- Reduction of risk potential", "stem": "A client in the cardiac care unit is asymptomatic with sinus rhythm on the monitor. Which of the following laboratory values is most likely the result of laboratory error?", "choices": [{"id": "a", "t": "Potassium 8.0 mEq/L © B. Sodium 150 mEq/L"}, {"id": "c", "t": "Creatinine 3.8 mg/dL"}, {"id": "d", "t": "BUN (blood urea nitrogen) 50 mg/dL"}], "correct": "a", "rationale": "8 | 4% Aserum potassium value of >7.0 mEq/L represents factitious hyperkalemia in a client who is asymptomatic. Normally, this level of serum Cc l 3% potassium is an electrolyte imbalance that would result in significant weakness, paralysis, and arrhythmia, leading to cardiac arrest. Since , the serum potassium is likely to be elevated as a result of hemolysis or a clotted blood sample. This client should be assessed for any cardiac symptoms or muscular weakness. The critical value must be reported to the healthcare provider, who will most likely request another blood draw. Heparin-impregnated vials can be used to prevent clotting. To prevent hemolysis, fist clenching should be avoided, and the use of tourniquets should be minimized. A larger gauge needle can also limit hemolysis during a blood draw.", "whyNot": {"c": "The creatinine value is elevated. Normal creatinine range is 0.6-1.3 mg/dL. Further assessment of the client’s renal function and volume", "d": "The normal BUN range is 6-20 mg/dL. This elevated BUN could be the result of dehydration or renal damage. It is not likely to be"}, "keyConcept": "When evaluating abnormal results from diagnostic laboratory tests, the nurse should be aware of the expected signs and symptoms associated with abnormal values. Discrepancies between expected clinical signs and the client's actual assessment findings should alert the nurse to the possibility of a laboratory error."}, {"id": 11582, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse in a pediatric clinic is assessing a child who is suspected of having cystic fibrosis (CF). Which of the following diagnostic tests will confirm the diagnosis?", "choices": [{"id": "a", "t": "Sweat chloride test"}, {"id": "b", "t": "Asputum culture"}, {"id": "c", "t": "A stool fat content analysis"}, {"id": "d", "t": "Chest radiography"}], "correct": "a", "rationale": "Clients who have cystic fibrosis have an increase of sodium and chloride in both saliva and sweat. Therefore, a sweat chloride test can B I a confirm a diagnosis of cystic fibrosis. cf 4%", "whyNot": {"b": "A sputum culture is used to determine what specific organism is infecting the lungs. However, it is not a diagnostic test that determines a", "c": "Astool fat content analysis is used to determine the amount of fat within a stool. However, it is not a diagnostic test that determines a", "d": "Chest radiography can determine the characteristics of patchy atelectasis and obstructive emphysema. However, it is not a diagnostic test"}, "keyConcept": "Cystic fibrosis is the most common lethal genetic condition among non-Hispanic white children, adolescents, and young adults. It is inherited as an autosomal recessive trait. It affects the respiratory system, gastrointestinal tract, and reproductive and integumentary systems. Traditionally, cystic fibrosis was diagnosed with a positive sweat test, which is still used to diagnose children who were not diagnosed by the newborn screening. It is important for nurses to understand the pathophysiology, clinical manifestations, diagnostic testing, and treatment for cystic fibrosis."}, {"id": 11583, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is providing care to a client who is scheduled for a hemicolectomy. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Encourage the client to void after sedative medication is administered."}, {"id": "b", "t": "Administer antibiotics 2 hr prior to surgical procedure."}, {"id": "c", "t": "Perform hair removal using a disposable razor."}, {"id": "d", "t": "Remove nail polish on the client's fingers and toes."}], "correct": "d", "rationale": "A l 3% Hard The nurse should ensure the client's nail beds are visible to allow for monitoring of color and circulation.", "whyNot": {"a": "The client should void before the administration of medication for relaxation or sedation to prevent the risk for falls. e@", "b": "The nurse should administer antibiotics within 1 hr prior to the surgical procedure as a prophylactic measure to prevent infection.", "c": "The nurse should remove hair at the surgical site with electric clippers or use a chemical depilatory to prevent traumatizing the skin and"}, "keyConcept": "Client safety is highly important when a client is scheduled for a surgical procedure. To help ensure safety, the nurse should complete a"}, {"id": 11584, "cat": "physiological integrity- Reduction of risk potential", "stem": "The nurse assesses a 6-month-old for vaccination readiness. Which finding would most likely indicate the need to delay administering the diphtheria, tetanus, and acellular pertussis (DTaP)? O A.A family history of sudden infant death syndrome (SIDS) O B.A fever of 38.5 degrees C following the 4-month vaccination O C. An acute bilateral ear infection O D. Living with a family member who is immunosuppressed", "choices": [{"id": "a", "t": "There is currently no evidence to suggest vaccines raise the risk of SIDS. A mild fever may be expected with the DTaP."}, {"id": "b", "t": "A fever of greater than 40.5C within 48 hours of vaccination would warrant caution. The DTaP is not a live vaccine."}, {"id": "c", "t": "A Vaccination in the presence of a moderate to severe infection, with or without fever, increases the risk of injury and decreases the chance of B = mounting a strong immune response to the vaccine."}, {"id": "d", "t": "No special precautions are needed regarding immunosuppressed family members."}], "correct": "c", "rationale": "A Vaccination in the presence of a moderate to severe infection, with or without fever, increases the risk of injury and decreases the chance of B = mounting a strong immune response to the vaccine. o;", "whyNot": {"a": "There is currently no evidence to suggest vaccines raise the risk of SIDS. A mild fever may be expected with the DTaP.", "b": "A fever of greater than 40.5C within 48 hours of vaccination would warrant caution. The DTaP is not a live vaccine.", "d": "No special precautions are needed regarding immunosuppressed family members."}, "keyConcept": "Children with minor illnesses may be vaccinated, but children who are moderately or severely ill should wait until they recover before getting DTaP vaccine. DTaP vaccine should not be given to a child who has had a life-threatening allergic reaction after a dose of DTaP or who experienced a brain or nervous system disease within 7 days after a dose of DTaP."}, {"id": 11585, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is caring for a 4-year-old child who has epiglottitis. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Initiate contact precautions."}, {"id": "b", "t": "Obtain a throat culture."}, {"id": "c", "t": "Use a tongue depressor to observe the epiglottis."}, {"id": "d", "t": "Monitor oxygen saturation."}], "correct": "d", "rationale": "all 6% Easy The nurse should monitor the child's oxygen saturation levels to check for indications of respiratory distress or a decline in the child's B | at condition. cf 4%", "whyNot": {"a": "The nurse should implement and maintain droplet precautions for 24 hr after a child begins antibiotic therapy.", "b": "Attempting to obtain a throat culture can cause an airway obstruction.", "c": "Using a tongue depressor to observe the epiglottis can cause an airway obstruction."}, "keyConcept": "Acute epiglottitis is a medical emergency. The causative agent is usually Haemophilus influenzae. The onset is abrupt and often follows a"}, {"id": 11586, "cat": "physiological integrity- Reduction of risk potential", "stem": "flexion contractures? O A. Limit any type of exercise to the residual limb for the first 48 hr after surgery. O B. Place the client in prone position several times each day. O C. Wrap the residual limb in a figure-eight pattern. O D. Encourage the client to sit in a chair during the day.", "choices": [{"id": "a", "t": "Limit any type of exercise to the residual limb for the first 48 hr after surgery."}, {"id": "b", "t": "Place the client in prone position several times each day."}, {"id": "c", "t": "Wrap the residual limb in a figure-eight pattern."}, {"id": "d", "t": "Encourage the client to sit in a chair during the day."}], "correct": "b", "rationale": "20 to 30 min to prevent flexion contractures. OB rd 54% fo", "whyNot": {"a": "To prevent flexion contractures, the nurse should encourage the client to perform range-of-motion exercise to the residual limb and to D Hl 21%", "c": "The nurse should wrap the residual limb in a figure-eight pattern to prepare the limb for the prosthesis; however, this action does not", "d": "The client can develop flexion contractures by allowing the residual limb to flex in a bent position when sitting for an extended period"}, "keyConcept": "Aplan of care for a client who had an amputation should include the following goals: Pain relief © Promotion of wound healing ¢ Enhancing body image © Helping the client with grief resolution © Promotion of independent self-care © Helping the client achieve physical mobility © Monitoring and managing potential complications ¢ Promoting home, community-based, and transitional care"}, {"id": 11587, "cat": "physiological integrity- Reduction of risk potential", "stem": "A nurse is teaching a client who had a wound debridement for osteomyelitis. Which of the following information should the nurse include in the teaching?", "choices": [{"id": "a", "t": "Plan to continue antibiotic therapy for 3 months."}, {"id": "b", "t": "Relief of pain indicates the infection is eradicated."}, {"id": "c", "t": "Airborne precautions are implemented during wound care."}, {"id": "d", "t": "Expect paresthesia distal to the wound."}], "correct": "a", "rationale": "o; A client who has osteomyelitis can plan to have prolonged antibiotic therapy for up to 3 months in order to eliminate the micro-organism B I that is causing the bone infection.", "whyNot": {"b": "Relief of pain does not indicate that osteomyelitis is resolved, and the client should continue antibiotic therapy as prescribed. If the client", "c": "When performing wound care, universal precautions and contact precautions are implemented to prevent spread of the micro-organism.", "d": "The client should not expect paresthesia distal to the wound; however, the nurse should monitor and report manifestations of"}, "keyConcept": "Osteomyelitis is an infection of the bone caused by one or more micro-organisms, such as bacteria, viruses, or fungi. When a micro-organism invades the bone tissue, inflammation occurs, causing edema in the surrounding tissue. Edema causes the vessels in the affected area to become thrombosed, resulting in bone necrosis and bone abscess where pus is released into the bone tissue. Manifestations of osteomyelitis include fever, swelling, erythema, tenderness, and continuous localized throbbing pain, especially with movement. The client should be placed in contact isolation to prevent the spread of the microorganism and should be started on antibiotic therapy, which can last up to 3 months after discharge. The nurse should instruct the client that the full course of the prescribed IV or oral antibiotics must be completed to ensure the infection is eradicated. If the debridement involves the client's extremity, the nurse should monitor for and teach the client about the manifestations of compartment syndrome, which include the six \"P's\": pain, pressure, paralysis, paresthesia, pallor, and pulselessness"}], "pre_post_operative": [{"id": 11588, "cat": "pre & post operative", "stem": "A nurse on a medical-surgical unit is planning care for a client who has just returned to the unit after abdominal surgery. Which of the following tasks should the nurse assign to an assistive personnel (AP)?", "choices": [{"id": "a", "t": "Listen to the client's breath sounds."}, {"id": "b", "t": "Determine whether the client needs pain medication."}, {"id": "c", "t": "Document the amount of urine in the client's catheter-drainage bag."}, {"id": "d", "t": "Show the client how to use the incentive spirometer."}], "correct": "c", "rationale": "The nurse should consider the Five Rights of Delegation when considering tasks to delegate to an AP. One of these rights, the right task, requires that the task be routine and the steps for completion do not deviate. Measuring and documenting intake and output are tasks that are within the range of function of the AP.", "whyNot": {"a": "Auscultating breath sounds involves assessment to interpret the findings. The nurse may not delegate tasks to APs that involve nursing", "b": "The nurse should not delegate aspects of the nursing process or skills, such as teaching, to an AP. Assessing a client's pain level requires", "d": "The nurse should not delegate aspects of the nursing process to an AP. The delivery of education to a client requires assessment,"}, "keyConcept": "Delegation is the act of assigning tasks to other members of the healthcare team who are competent to perform those tasks and whose scope of practice or range of function includes those tasks. The nurse who delegates the task has accountability for the outcome. When delegating tasks to assistive personnel, the nurse must follow the five rights of delegation carefully: the right task, under the right circumstances, to the right person, with the right direction and communication, and the right supervision and evaluation. DELEGATION TO ASSISTIVE PERSONNEL Tasks to delegate * Measuring and documenting intake and output Performing uncomplicated dressing changes Measuring and documenting vital signs Performing CPR Ambulating and transferring clients instilling formula via established gastrostomies Suctioning chronic tracheostomies Weighing clients Feeding clients Bathing clients"}, {"id": 11589, "cat": "pre & post operative", "stem": "A nurse is completing the admission assessment of a client who is scheduled for peripheral bypass graft surgery on the left leg. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Rubor on the client's affected leg when elevated"}, {"id": "b", "t": "3+ dorsal pedal pulse on the client's left foot"}, {"id": "c", "t": "Increased hair on the client's left calf"}, {"id": "d", "t": "Report of intermittent claudication in the client's affected leg"}], "correct": "d", "rationale": "A || 13% Moderate Peripheral bypass graft surgery is performed to increase arterial blood flow to the extremity of a client who has severe peripheral arterial B | Aen disease. The nurse should expect a client who has peripheral arterial disease to experience intermittent claudication, numbness, or burning pain in the extremity that ceases with rest. c | 3%", "whyNot": {"a": "The nurse should expect a client who has peripheral arterial disease to experience reddening, or rubor, when the affected leg is placed in a iT}", "b": "The nurse should expect a client who has peripheral arterial disease to have decreased or absent pulses in the affected foot. 3", "c": "The nurse should expect a client who has peripheral arterial disease to have hair loss on the affected calf. g"}, "keyConcept": "Peripheral bypass graft surgery is performed to increase arterial blood flow to the extremity of a client who has severe peripheral arterial disease. Manifestations of peripheral arterial disease can include intermittent claudication, or burning, cramping muscle pain that discontinues with rest, loss of hair on the lower calf and ankle, thickened toenails, dependent rubor, or reddening, when the extremity is in a dependent position and decreased or absent pulses. The nurse should instruct the client to participate in gradual progressive exercise to increase peripheral circulation, avoid exposure to cold temperatures, wear warm socks and shoes to increase vasodilation, and increase fluid intake to reduce the risk for thrombophlebitis. The nurse should also advise the client to avoid nicotine and caffeine as well as reduce stress to decrease the risk for vasoconstriction."}, {"id": 11590, "cat": "pre & post operative", "stem": "Which of the following is an expected outcome for a client who is recovering from an abdominal perineal resection with a colostomy? The client will:", "choices": [{"id": "a", "t": "Resume walking on the hospital floor soon after surgery"}, {"id": "b", "t": "Eliminate fiber from the diet"}, {"id": "c", "t": "Permanently limit physical activity to light exercise"}, {"id": "d", "t": "Anticipate urinary self-catheterization"}], "correct": "a", "rationale": "o; In order to prevent deep venous thrombosis (DVTs) from forming, the client is encouraged to walk around in addition to the anticoagulation B i medications they are taking. There is a risk of pulmonary embolism if the client remains immobile for a long period of time, and dislodges a clot from the lower extremities with movement. c i", "whyNot": {"b": "There is no need to eliminate fiber from the diet; the client can eat whatever he wants.", "c": "Physical activity does not need to be limited. The client can resume normal activities as tolerated, usually within 6 to 8 weeks.", "d": "Urinary retention may occur in the immediate post-operative period, but typically resolves."}, "keyConcept": "Abdominoperineal resection is characterized by complete removal of the distal colon, rectum, and anal sphincter. Both anterior abdominal and perineal incisions are used, and the procedure results in a permanent colostomy. It is sometimes performed in clients with advanced rectal cancer."}, {"id": 11591, "cat": "pre & post operative", "stem": "5 hours of receiving the pain medication. What does this reaction represent?", "choices": [{"id": "a", "t": "Chronic pain"}, {"id": "b", "t": "Neuropathic pain"}, {"id": "c", "t": "Breakthrough pain"}, {"id": "d", "t": "Tolerance"}], "correct": "c", "rationale": "Breakthrough pain refers to flares of moderate to severe pain that occur despite administration of therapeutic doses of analgesic medication. The analgesic prescribed has a therapeutic effect, but the patient continues to experience flares of pain.", "whyNot": {"a": "Chronic pain describes a persistent feeling of discomfort or pain over a long period of time. The cause of chronic pain may not be easily", "b": "Neuropathic pain results from direct stimulation of central or peripheral pain receptors in the nervous system. It is often described as a", "d": "Tolerance refers to the need to increase a dose of medication to achieve the same therapeutic effect. This usually takes weeks to months"}, "keyConcept": "Breakthrough pain refers to intense spikes of pain that occur while the client is already medicated with a long-acting opioid analgesic."}, {"id": 11592, "cat": "pre & post operative", "stem": "the nurse make? O A. \"It is normal to be nervous before surgery.\" O B. \"I will notify the provider about your decision.\" O C. \"You will feel better after the surgery.\" O D.\"If you don't have the surgery, you could die.\"", "choices": [{"id": "a", "t": "\"It is normal to be nervous before surgery.\""}, {"id": "b", "t": "\"I will notify the provider about your decision.\""}, {"id": "c", "t": "\"You will feel better after the surgery.\" O D.\"If you don't have the surgery, you could die.\""}], "correct": "b", "rationale": "Correct Answer: B. \"I will notify the provider about your decision.\" When a client is unsure about a surgery or treatment, it is the responsibility of the nurse to notify the provider about the client's feelings. The nurse should be aware that the client can refuse or change their mind at any time about the surgery.", "whyNot": {"a": "By making this statement, the nurse is assuming the client is nervous and does not explore the client's feelings about the surgery.", "c": "By making this statement, the nurse is providing false reassurance and does not address the client's feelings about the surgery."}, "keyConcept": "The nurse should respect that a client has the right to change their mind at any time about a treatment or procedure, regardless of the reason. It is the nurse's responsibility to contact the provider about the client's wishes. The provider will then request the client sign a refusal form regarding the surgery."}, {"id": 11593, "cat": "pre & post operative", "stem": "pain. Which of the following should the nurse do first?", "choices": [{"id": "a", "t": "Assessment of the client’s pain."}, {"id": "b", "t": "Contact the healthcare provider to hold a family meeting to obtain consent."}, {"id": "c", "t": "Administer a bolus dose of morphine."}, {"id": "d", "t": "Continue to complete the pre-operative checklist for this client."}], "correct": "a", "rationale": "Assessment of the client’s pain is the priority task in this case. An assessment of a new client should be completed before the nurse proceeds B |] Aen with any other action. c] 3%", "whyNot": {"b": "Although it will be important to identify someone who can give informed consent for this client, the priority task for the nurse is to", "c": "The nurse should complete an assessment of the client and if necessary should consult with the healthcare provider to determine whether", "d": "The pre-operative checklist should be completed after the client assessment is complete."}, "keyConcept": "Assessment is the foundation of nursing care. The nurse must make an initial assessment before providing care."}, {"id": 11594, "cat": "pre & post operative", "stem": "responses should the nurse make? O A. \"Give it some time. Everything will be okay.\" O B. \"I will come back later, and perhaps we can talk then.\" O C. \"Why are you crying?\" O D. \"Most people who had this kind of surgery react this way.\"", "choices": [{"id": "a", "t": "\"Give it some time. Everything will be okay.\""}, {"id": "b", "t": "\"I will come back later, and perhaps we can talk then.\""}, {"id": "c", "t": "\"Why are you crying?\""}, {"id": "d", "t": "\"Most people who had this kind of surgery react this way.\""}], "correct": "b", "rationale": ". With this response, the nurse is using the technique of offering self to the client, which encourages open communication. It makes no demands on the client and attaches no conditions; it is simply an offer of presence.", "whyNot": {"a": "This response creates a communication barrier by giving the client false reassurance, which can block further communication.", "c": "With this response, the nurse creates a communication barrier by probing, which can make the client react defensively.", "d": "With this response, the nurse creates a communication barrier by making a stereotypical comment, which can block further"}, "keyConcept": "Therapeutic communication techniques, such as offering self, help nurses build trusting nurse-client relationships. They demonstrate respect for clients' feelings and promote further communication. Nontherapeutic communication techniques, such as giving false reassurance, probing, and stereotyping, minimize clients' feelings and block further communication. Therapeutic Communication Techniques Technique Explanation Example Offering self Conveying presence and interest without | “I can sit here with you for a while, if imposing expectations on the client you'd like that.” Providing general | Using responses that encourage the client to | “Tell me more about how the leads talk more about a problem or issue changes in your face make you feel.” ‘Summarizing Reviewing the major points of an “Today we talked about some interaction, often at the end of a techniques to help reduce stress.” ‘communication session Seeking Using a comment or question to help “i'm not sure | understand what you clarification understand a client's vague statement are saying.” Using touch Using a hand to offer comfort (the client's | Placing a hand over a client's hand preference on touch should be considered | or on their shoulder before using touch) Giving Offering information that will help a client | “Eating yogurt and toast can help"}, {"id": 11595, "cat": "pre & post operative", "stem": "A nurse is beginning a morning shift. Which of the following clients should the nurse assess initially?", "choices": [{"id": "a", "t": "A client on bed rest who complains of swelling in the lower leg"}, {"id": "b", "t": "A client complaining that the breakfast tray is late every day"}, {"id": "c", "t": "A client diagnosed with pneumonia who has bilateral crackles on an exam"}, {"id": "d", "t": "A client admitted with a urinary tract infection who complains of urinary urgency eck Answer"}], "correct": "a", "rationale": "A client on bed rest is at risk of venous thromboembolic disease, including deep vein thrombosis and pulmonary embolism, which can be fatal. Swelling in the legs is not an expected finding in clients on bedrest. This client should be the priority initial assessment, as the situation could be life-threatening or life-altering.", "whyNot": {"b": "This is a psychosocial problem that should be addressed, but it is not a priority.", "c": "This is an expected finding in pneumonia but requires assessment. The client should be seen after the client with possible PE.", "d": "This finding is a normal symptom in a urinary tract infection. It is not potentially life-threatening and does not take priority."}, "keyConcept": "Immobility is a significant risk factor for venous thromboembolism in hospitalized clients. Deep vein thrombosis is characterized by swelling, calf tenderness, and a positive Homan's sign. Embolization of a deep vein thrombosis to the lungs can result in cardiopulmonary arrest, making assessment and intervention a priority."}, {"id": 11596, "cat": "pre & post operative", "stem": "Postoperative nursing care for a client after an appendectomy should include which of the following?", "choices": [{"id": "a", "t": "Administering sitz baths 4 times a day"}, {"id": "b", "t": "Noting the first bowel movement after surgery"}, {"id": "c", "t": "Limiting the client’s activity to bathroom privileges"}, {"id": "d", "t": "Measuring abdominal girth every 2 hours"}], "correct": "b", "rationale": "A The client’s first bowel movement after surgery is important because it indicates that normal peristalsis has returned. OB —", "whyNot": {"a": "Sitz baths are used after rectal surgery, not an appendectomy. D ||", "c": "Ambulation is started the day of surgery and is not confined to bathroom privileges.", "d": "The abdomen should be auscultated for bowel sounds and palpated for softness, but there is no need to measure the client's girth every 2"}, "keyConcept": "An appendectomy is the surgical removal of the vermiform appendix. Appendectomy is usually performed emergently after the client presents with symptoms. Post-operative concerns include acute pain related to the surgical wound; risk for infection; nausea and anorexia. The nurse will assess pain and administer analgesics as indicated. The client should be kept NPO initially to decrease discomfort, gastric irritation, and vomiting. The semi-Fowler's position will decrease tension on the abdomen and promote comfort. The client should ambulate early to stimulate peristalsis and passing of flatus, which will reduce abdominal discomfort."}, {"id": 11597, "cat": "pre & post operative", "stem": "A nurse on a medical-surgical unit is about to move a client from the bed to a chair for the first time since surgery. Which of the following actions should the nurse take first?", "choices": [{"id": "a", "t": "Determine whether the client can bear weight."}, {"id": "b", "t": "Place a transfer belt on the client."}, {"id": "c", "t": "Lock the wheels on the bed."}, {"id": "d", "t": "Assist the client to a sitting position."}], "correct": "a", "rationale": "eo. 52% Hard The first action the nurse should take when using the nursing process is to assess the client. This includes determining whether the client B a0 can bear weight, evaluating activity tolerance and muscle strength, identifying any risk factors for orthostatic hypotension, determining the need for another staff member to assist with moving the client, and assessing the client's overall stability and level of comfort. c — 37% D 9%", "whyNot": {"b": "The nurse should place a transfer belt snugly around the client's waist to help keep the client stable and keep them from falling; however,", "c": "The nurse should lock the wheels on the bed to prevent it from roiling away from the client and causing a fall; however, there is another", "d": "The nurse should assist the client to a sitting position in bed before the transfer to shift their center of gravity and weight toward the"}, "keyConcept": "Before beginning the process of transferring a client from the bed to a chair, the nurse should assess the client thoroughly and determine what assistive devices or additional staff the procedure will require. It is also important to explain the transfer process to the client to make it less stressful. If the nurse is transferring the client to a wheelchair, the nurse should lock the wheels on it and on the bed. If the client has a high BMI or is unable to assist in the transfer or bear weight, it is best to use a mechanical lift to prevent injury to the client and to the staff."}, {"id": 11598, "cat": "pre & post operative", "stem": "A nurse is caring for a postoperative client who is having difficulty sleeping at night. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Avoid administration of analgesics within two hours of bedtime."}, {"id": "b", "t": "Adjust the client's room temperature to provide a cold environment."}, {"id": "c", "t": "Keep a clear pathway around the client's bed to avoid accidental movement of client's bed"}, {"id": "d", "t": "Turn out of the lights, including pathway lights, in the client's room."}], "correct": "c", "rationale": "A | % Hard Keeping a clear pathway around the client's bed will ensure that no one who enters the client's room will bump into the bed and awaken the client during the night. 5 i 25%", "whyNot": {"a": "The nurse should administer required analgesics to the client 30 min prior to bedtime to ensure the client's comfort during the early phase", "b": "The nurse should adjust the room temperature to provide an environment that is comfortable for the client. Most clients cannot sleep if", "d": "While overhead and bright lights should be turned out, the nurse should ensure that there is a night-light or bathroom light left on. This"}, "keyConcept": "Other interventions that can help clients to rest better at night include the following: closing windows to block outside lighting, using a flashlight during night-time assessments rather than turning on overhead lights, closing the door to the client's room, wearing rubber-soled shoes, and ensuring staff conversations are kept at a low level."}, {"id": 11599, "cat": "pre & post operative", "stem": "skin is warm and pink. Which of the following is the next most appropriate action by the nurse?", "choices": [{"id": "a", "t": "Check the client’s pupillary reflexes"}, {"id": "b", "t": "Assess hemodynamic status by connecting the client to a monitor"}, {"id": "c", "t": "Provide 100 percent oxygen via face mask"}, {"id": "d", "t": "Assess the client's pain level"}], "correct": "b", "rationale": "sl 15% Hard When receiving a newly admitted client in the recovery room, the receiving nurse should assess the essential components of airway, OB rT ay fo breathing, and circulation. After making a visual inspection to verify the client's status, the nurse should place the client on a hemodynamic monitor to confirm heart rate, respiratory rate, and oxygen saturation levels. c | 6% >i! 26%", "whyNot": {"a": "The nurse should check hemodynamic status by connecting the client to a monitor, which will display the client’s heart rate and pulse", "c": "The client has pink skin and does not appear to be in distress; supplemental oxygen does not appear to be necessary.", "d": "Asking about the client’s pain is important, but the nurse must prioritize assessment of the client's hemodynamic status."}, "keyConcept": "When assessing a client admitted to PACU after a surgical procedure, the client's hemodynamic status and oxygenation should be assessed by monitor after a visual inspection of the client's status for airway, breathing, circulation, and disability. Continuous pulse oximetry is indicated for all clients in the PACU. Other assessments include temperature, respiratory effort, level of sedation score (using a clinical scale such as the Glasgow Coma Scale); and assessment of pain and nausea."}, {"id": 11600, "cat": "pre & post operative", "stem": "A nurse is caring for a client undergoing preoperative assessment for tonsillectomy the next day. Which of the following laboratory tests does the nurse expect the surgeon to assess in this client?", "choices": [{"id": "a", "t": "Prothrombin time"}, {"id": "b", "t": "Serum bilirubin"}, {"id": "c", "t": "Blood urea nitrogen"}, {"id": "d", "t": "Erythrocyte sedimentation rate"}], "correct": "a", "rationale": "The tonsillar area is very vascular, which can increase the chances of bleeding. If the prothrombin time is not therapeutic, the client could B | 3\" bleed excessively. cf 4%", "whyNot": {"b": "Bilirubin is not associated with a tonsillectomy; this would be unnecessary.", "c": "Blood urea nitrogen is not associated with a tonsillectomy; this would be unnecessary.", "d": "The erythrocyte sedimentation rate measures inflammation, which is unnecessary before a tonsillectomy."}, "keyConcept": "The tonsils are well-vascularized. The arterial supply includes the external carotid arteries and their branches. All clients undergoing tonsillectomy should undergo a basic coagulation workup to check for abnormal bleeding. To reduce the risk of bleeding, the client should avoid aspirin, aspirin containing compounds, Advil, or Ibuprofen for two weeks prior to surgery. Acetaminophen (Tylenol) can be used instead."}, {"id": 11601, "cat": "pre & post operative", "stem": "assessment? O A. Blood pressure and pulse rate O B. Respiratory rate and quality/pattern of breathing O C. Reflexes and pupillary reaction O D. Signs of infection at the surgical site", "choices": [{"id": "a", "t": "Blood pressure and pulse rate"}, {"id": "b", "t": "Respiratory rate and quality/pattern of breathing"}, {"id": "c", "t": "Reflexes and pupillary reaction"}, {"id": "d", "t": "Signs of infection at the surgical site"}], "correct": "b", "rationale": "al 4% Easy In a client that has undergone a procedure under general anesthesia, moderate sedation, or who received opioid medications, respiratory Cc | 2% assessment is the most critical assessment after surgery. Assessment should include quality and pattern of breathing, respiratory rate and , use of accessory muscles for breathing, supplemental oxygen settings, and pulse oximetry readings. Respiratory complications after a surgical procedure can include atelectasis, pulmonary embolism, ventilator dependence, pneumonia, and laryngeal or pulmonary edema.", "whyNot": {"a": "Circulation should be prioritized after respirations in the initial assessment of routine post-operative clients who have undergone", "c": "The nurse should assess mental status and level of consciousness as part of the initial assessment of a client on arrival to a medical-", "d": "The surgical incision site should be assessed for drainage, bleeding, drains present, and whether the drains are properly set and"}, "keyConcept": "The most significant adverse effect of opioid analgesics is respiratory depression, so the priority assessment in a client who is receiving intravenous opioid analgesics is respiratory status. The risk of respiratory depression is increased in the immediate post-surgical period after general anesthesia."}, {"id": 11602, "cat": "pre & post operative", "stem": "After surgery to create a urinary diversion, the client is at risk for a urinary tract infection. The nurse should plan to incorporate which of the following interventions into the client’s care?", "choices": [{"id": "a", "t": "Clamp the appliance at night"}, {"id": "b", "t": "Empty the urinary appliance when one-third full"}, {"id": "c", "t": "Administer prophylactic antibiotics"}, {"id": "d", "t": "Change the urinary appliance daily"}], "correct": "b", "rationale": "A The urinary application should be emptied before the pouch is a third full, to prevent urinary reflux. The application should be attached to OB — the leg bag at night to allow for adequate drainage. a", "whyNot": {"a": "The appliance should not be clamped at night to allow for continued drainage while the client sleeps.", "c": "Prophylactic antibiotics are not necessary unless there are other indications associated with the client’s condition.", "d": "The appliance does not need to be changed daily; the system should remain closed as much as possible."}, "keyConcept": "When caring for a client who has undergone urinary diversion surgery, the nurse should assess the color and consistency of urine. The nurse expects pink or bright red urine fading to pink and then clearing by the third postoperative day. Urine may be cloudy due to the production of mucus by the bowel mucosa. Bright red blood in the urine from a urinary diversion may indicate hemorrhage and may require further surgery. Excessive cloudiness or malodorous urine is concerning for infection. The nurse should also assess the size, color, and condition of the stoma and surrounding skin every 2 hours for the first 24 hours, then every 4 hours for 48 to 72 hours. The stoma will initially appear bright red and slightly edematous. Slight bleeding during cleansing is normal. Compromised circulation causes the stoma to appear pale, gray, or cyanotic. Other complications include infection or impaired healing and may be evidenced by a change in the appearance of the stoma or incision. The nurse should Irrigate the ileal diversion catheter with 30 to 60 mL of normal saline every 4 hours or as prescribed."}, {"id": 11603, "cat": "pre & post operative", "stem": "A nurse is demonstrating diaphragmatic breathing to a group of clients who are scheduled for surgery. Which of the following actions should the nurse include in the demonstration?", "choices": [{"id": "a", "t": "Place hands on the sides of the rib cage."}, {"id": "b", "t": "Inhale slowly and evenly through the nose."}, {"id": "c", "t": "Hold the breath in for as long as possible."}, {"id": "d", "t": "Exhale forcefully through the nose."}], "correct": "b", "rationale": "‘i The nurse should inhale slowly and evenly through the nose until chest expansion is maximized. OB a", "whyNot": {"a": "The nurse should place both hands palms down on the border of the rib cage. D l", "c": "The nurse should hold the breath in for 2 to 3 seconds.", "d": "The nurse should exhale slowly through the mouth until maximum chest contraction is achieved."}, "keyConcept": "Nurses should be able to demonstrate diaphragmatic breathing using correct technique. This type of breathing will assist the postoperative client with maximizing lung expansion to prevent postoperative complications."}, {"id": 11604, "cat": "pre & post operative", "stem": "What intervention can the perioperative nurse employ to prevent hypothermia in the surgical client?", "choices": [{"id": "a", "t": "Wrap the extremities in pressure dressings to maintain heat"}, {"id": "b", "t": "Enforce regular incentive spirometry immediately after the procedure"}, {"id": "c", "t": "Use forced air warming blankets"}, {"id": "d", "t": "Place hot packs under the axilla and the lower back"}], "correct": "c", "rationale": "al 5% Easy Hypothermia is a risk for clients undergoing surgery, due to the cooler temperatures in the operating suite and recovery areas, increased B I a exposure of the client’s body during the procedure, and administration of unwarmed fluids. The nurse can prevent heat loss by utilizing forced air warming blankets during the recovery period to circulate heat around the client’s body to minimize heat loss, provide active ec | 81% external warming, and prevent hypothermia. D i 10%", "whyNot": {"a": "While covering the client may reduce heat loss, pressure dressings are not appropriate.", "b": "This is a measure that may reduce atelectasis following surgery but would not impact heat loss.", "d": "This action may risk burning the client’s skin and should be avoided."}, "keyConcept": "Core temperature heat loss after anesthesia induction averages an estimated 1.0° C to 3.0° C (1.8° F to 5.4° . nadvertent hypothermia is defined as a core body temperature lower than 36° C (96.8° F). Risk factors for perioperative hypothermia include extremes in age, low body weight, chronic or systemic health conditions, and poor nutritional status. Inadvertent perioperative hypothermia increases the risk of complications and results in prolonged stays in the postoperative anesthesia care unit (PACU), intensive care unit, and overall hospital lengths of stay. Inadvertent hypothermia is also associated with increased costs and decreased client satisfaction."}, {"id": 11605, "cat": "pre & post operative", "stem": "@O@ * Claude x % Extracto) X x Login- Pc x ™ [GitHub] xX = Inbox-b x @ TEASPra xX OnlineN. x @ Microsofi x @ NCLEXE x |. Results- x ©) bobyond) x @ NewTab x + v € > GCG _— &% student.atitesting.com/LT| Q *& x * © OD Cb ) oO Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "lron supplementation for 3 weeks prior to surgery to increase hemoglobin concentration"}, {"id": "b", "t": "Storing blood donated by family members prior to surgery"}, {"id": "c", "t": "Autologous blood donation prior to surgery"}, {"id": "d", "t": "Purchasing blood from a bank that screens multiple times"}], "correct": "c", "rationale": "A l 3% Moderate ’s own blood before reuse during a scheduled procedure. Autologous @c | 70% transfusion reduces the risk of transfusion reactions and disease transmission, but it is contraindicated in clients with bacteremia or D ; | 25% leukemia. Donations can be made every 3 days if the client's hemoglobin level remains within the target range. Blood can be frozen and {) stored for as long as ten years. Autotransfusion refers to aseptic collection, filtering, and return of the client's own blood during surgical 2 procedures. a & =) a = ay", "whyNot": {"a": "Although iron supplementation can improve hemoglobin levels in clients with iron deficiency anemia, they are not effective for", "b": "Donated blood by family members may make the client feel more comfortable, but the risk of disease transmission or transfusion reaction", "d": "Additional screening is not provided by blood banks."}, "keyConcept": "Autologous blood transfusion refers to collection of an individual's blood, usually before a surgical procedure, for reinfusion when necessary. Autologous blood transfusion reduces the risk of allergic reaction, blood type incompatibility, and transmission of infectious disease."}, {"id": 11606, "cat": "pre & post operative", "stem": "A nurse is assessing a client who is postoperative following gynecological surgery. The nurse should rely on which of the following methods for determining the intensity of the client's pain?", "choices": [{"id": "a", "t": "Vital-sign measurement"}, {"id": "b", "t": "The client's self-report of pain severity"}, {"id": "c", "t": "Visual observation for nonverbal signs of pain"}, {"id": "d", "t": "The relief the client reports from analgesic medications"}], "correct": "b", "rationale": "al 3% Easy Because nurses cannot measure pain objectively, it is standard practice to accept that the severity of pain is what the client says it is and to OB rsd omar intervene accordingly. chi 6% p| 2%", "whyNot": {"a": "Pain can affect vital signs, such as causing tachycardia, but this is not always a reliable indicator of pain.", "c": "Nonverbal signs, such as grimacing, can indicate pain, but this is not always a reliable indicator of pain.", "d": "The relief the client reports is subjective information that the nurse can use to help determine the effectiveness of pain management, but"}, "keyConcept": "Nurses must acknowledge a client's expression of pain and accept that the pain level is whatever clients say it is and that it exists whenever they say it does. Nurses should use standardized pain scales for clients who are older than 7 years old. Specialized pain scales are available for use with younger children or with clients who have difficulty communicating verbally."}, {"id": 11607, "cat": "pre & post operative", "stem": "with good capillary refill bilaterally. Which of the following is the correct initial action for the nurse?", "choices": [{"id": "a", "t": "Notify the HCP immediately."}, {"id": "b", "t": "Offer the client prescribed PRN pain medication."}, {"id": "c", "t": "Ask the client if these symptoms were present prior to surgery."}, {"id": "d", "t": "Change the surgical dressing to reduce the pressure"}], "correct": "c", "rationale": "The client has had diabetes for 30 years. Diabetic neuropathy commonly occurs in a stocking-glove pattern, although diabetes can also affect the autonomic nervous system. By asking the client if the symptoms were present before surgery, a baseline can be established. Other common causes of bilateral peripheral neuropathy include toxic neuropathy and vitamin deficiency neuropathy (in clients with chronic alcohol use disorder, deficiency of vitamin B12 and thiamine cause several characteristic findings, including peripheral neuropathy). Guillain-Barre syndrome represents an autoimmune neuropathy triggered by a cross-reaction to viral antigens. A determination that the signs were present before surgery indicates that they are not the result of a surgical complication and are more likely to represent diabetic neuropathy. Additionally, the symptoms are bilateral, suggesting they are not the result of surgery, which only involved one limb.", "whyNot": {"a": "There is no urgency to notify the healthcare provider since the client is stable. Strong pulses indicate good perfusion in the distal", "b": "Traditional analgesics used after surgical procedures such as opioids are not usually as effective for pain related to diabetic neuropathy as", "d": "The client's paresthesia is probably the result of diabetic neuropathy. Before any intervention, the nurse should establish whether or not"}, "keyConcept": "When assessing a client's symptoms, it is important to determine the onset and duration, any precipitating or palliative factors, quality, and severity. These factors can provide clues about the cause of the symptoms, allowing the nurse to appropriately plan a course of action."}, {"id": 11608, "cat": "pre & post operative", "stem": "Which of the following tasks should a nurse prioritize when caring for a client in the PACU who is one hour post-op total hip replacement?", "choices": [{"id": "a", "t": "Assessment of urine cloudiness or pus in the catheter bag"}, {"id": "b", "t": "Placement of the abduction pillow"}, {"id": "c", "t": "Assessment of bloody drainage in a suction drainage device"}, {"id": "d", "t": "Last dose of pain medication and assessment of client pain level"}], "correct": "c", "rationale": "‘i a Complications of total hip replacement include dislocation of the prosthesis, bleeding, infection, and deep vein thrombosis. During the ec | immediate postoperative period, the priority assessment is monitoring blood loss since this is a potentially life-threatening complication of D || surgery, particularly in the first few hours.", "whyNot": {"a": "Cloudiness and pus in urine can be a sign of urinary tract infection in a client who has an indwelling urinary catheter, but it does not", "b": "An abduction pillow is placed between the legs of the client after total joint replacement of the hip to prevent adduction of the hip and", "d": "Pain control is always important, but hemorrhage is a priority. Many surgeons prescribe a patient-controlled analgesia device with"}, "keyConcept": "In the immediate post-operative period, the client will be in the post-anesthesia care unit (PACU.) There are three phases of recovery in the PACU. Phase 1 is the immediate recovery phase. During phase 2, the nurse prepares the client for self/hospital care, Phase 3 is preparation for discharge. The PACU stay can be 4-6 hours, during which the client is closely monitored for hemorrhage and other potential complications of surgery. The client is discharged after regaining motor and sensory function and stable vital signs. Before discharge from the PACU, the client should be oriented and without evidence of complications."}, {"id": 11609, "cat": "pre & post operative", "stem": "A nurse is caring for a client who indicated a religious preference on admission. The client is now scheduled for surgery. Which of the following is the most appropriate nursing action at this time?", "choices": [{"id": "a", "t": "Call the hospital chaplain to request a visit for the client prior to surgery."}, {"id": "b", "t": "Ask the client if he or she has contacted a pastor or spiritual leader."}, {"id": "c", "t": "Document the client’s preference and notify the healthcare provider."}, {"id": "d", "t": "Ask the client about any spiritual needs."}], "correct": "d", "rationale": "There is some evidence that clients who engage in regular religious or spiritual practice have better healthcare outcomes. The nurse should try to accommodate the client’s beliefs and practices when planning care. The initial step is an assessment of spiritual needs or religious preference. After determining the client’s beliefs, the nurse should further determine how to meet the client’s spiritual needs or religious preference.", "whyNot": {"a": "This option assumes the client has identified a religious or spiritual leader and may also cause concern by the client that a poor outcome", "b": "This answer presumes the client has a church, pastor, or spiritual leader.", "c": "The nurse should first assess the client’s religious or spiritual beliefs and needs."}, "keyConcept": "Aspiritual needs assessment will help the nurse to better accommodate the client's beliefs and spiritual needs. Clients who engage in regular religious or spiritual practice have better healthcare outcomes, suggesting the importance of consideration of these needs in healthcare."}, {"id": 11610, "cat": "pre & post operative", "stem": "A client has just returned from the post-anesthesia care unit after having a laryngectomy. Which of the following interventions should the nurse include in the plan of care?", "choices": [{"id": "a", "t": "Maintain the head of the bed at 30 to 40 degrees"}, {"id": "b", "t": "Teach the client how to use esophageal speech"}, {"id": "c", "t": "Initiate small feedings of soft food"}, {"id": "d", "t": "Irrigate drainage tubes as needed"}], "correct": "a", "rationale": "Immediately after surgery, the client should be maintained in a position with the head of the bed elevated 30 to 40 degrees. B I a", "whyNot": {"b": "Immediately postoperatively, the client should be provided alternative means of communication, such as a communication board. As", "c": "Food is not initiated in the immediate post-op phase. Enteral feedings are usually used to meet nutritional needs. °", "d": "Irrigation of the drainage tubes is an inappropriate action. ="}, "keyConcept": "PURPOSE 4 Removing the larynx is sometimes necessary for treatment of clients who have cancer of the larynx, those who have sustained severe injury to the neck ,or who develop radiation necrosis from radiation treatment. The throat muscles and the skin are closed with surgical stitches. Drainage tubes are often place in the neck to drain the surgical site of bloods and fluids. Most clients who undergo complete or partial laryngectomy spend the first couple of days after surgery in the intensive care unit (ICU). Blood pressure, heart rate, breathing, and other vital signs are closely monitored. Oxygen is provided through the stoma right after surgery. A nasogastric tube or PEG tube is placed to provide nutrition while the surgical site heals. The nurse will encourage the client to move around to prevent blood clots, decrease the risk of pneumonia, and help the client get accustomed to the stoma and new ways of breathing. Getting up and out of bed is important for recovery. The client may receive physical therapy, as well as speech and language therapy."}, {"id": 11611, "cat": "pre & post operative", "stem": "A nurse is caring for an adolescent following a below-the-knee amputation. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Avoid discussing the amputation."}, {"id": "b", "t": "Administer acetaminophen for phantom pain."}, {"id": "c", "t": "Prepare them for a prosthesis fitting."}, {"id": "d", "t": "Maintain the affected limb in the dependent position."}], "correct": "c", "rationale": ". Preparing the adolescent for a prosthesis is an appropriate action for the nurse to take. B = Bay fo", "whyNot": {"a": "Clients experience the grieving process after losing limb. Avoiding discussion of the amputation is not an appropriate action for the nurse", "b": "Amitriptyline should be given for phantom pain. Acetaminophen is ineffective for treating phantom limb pain.", "d": "The affected limb should be elevated after surgery to decrease swelling."}, "keyConcept": "Preparation of the child and family for a limb amputation is crucial because they might have great difficulty with adjustment. Honesty is essential in gaining the adolescent’s trust and cooperation. In order to accept the idea for such radical surgery, the adolescent and family must be made aware that there is no other alternative for treatment. The nurse should also be prepared for the adolescent to be angry and grieve postoperatively over the radical body alteration. Loss of a limb entails a grieving process. Therefore, the family and anyone caring for the adolescent should be aware that reactions of anger and depression are expected and necessary."}, {"id": 11612, "cat": "pre & post operative", "stem": "A nurse is caring for an adolescent who is 2 hr postoperative following a tonsillectomy. Which of the following fluids should the nurse offer to the adolescent?", "choices": [{"id": "a", "t": "Crushed ice"}, {"id": "b", "t": "Orange juice"}, {"id": "c", "t": "Ice cream"}, {"id": "d", "t": "Cranberry juice"}], "correct": "a", "rationale": "Cold, clear liquids are well-tolerated following a tonsillectomy. Liquids that are brown or red should be avoided in order to tell the difference B | 3\" between liquid and fresh or old blood.", "whyNot": {"b": "Citrus juices should be avoided as they can be irritating to the throat and typically are not tolerated well.", "c": "Dairy products can cause nausea and increased oral mucus in some individuals. This is not the best initial option. °", "d": "Acidic fluids should be avoided as they can be irritating to the throat. Liquids that are red should be avoided because any emesis the child ="}, "keyConcept": "The nurse should offer the adolescent crushed ice, cool water, diluted fruit juice, and flavored ice pops following a tonsillectomy. However, the nurse should avoid giving the adolescent orange juice, cranberry juice, ice cream, milk, or pudding. Also, the client should avoid straws because they can damage the surgical site and cause bleeding."}, {"id": 11613, "cat": "pre & post operative", "stem": "A nurse is teaching a group of student nurses on a surgical unit about postoperative complications. Which of the following statements by a student nurse indicates understanding of this teaching?", "choices": [{"id": "a", "t": "Dehiscence is the protrusion of an internal bodily organ through the surgical wound incision"}, {"id": "b", "t": "Evisceration is the complete or partial separation of the surgical wound incision"}, {"id": "c", "t": "Healing by primary intention is the least common type of surgical wound healing"}, {"id": "d", "t": "Abdominal compartment syndrome occurs as the result of gas and fluid accumulation"}], "correct": "d", "rationale": "Abdominal compartment syndrome, a risk associated with surgery, occurs as the result of gas and fluids in the intraabdominal cavity. The normal intraabdominal pressure is 5 mm Hg or less but may increase to more than 15 mm Hg after a surgical procedure. Increased intraabdominal pressure results in reduced cardiac output, hypotension, and .oliguria. At very high pressures (> 40 mm Hg) anuria may occur. (absence of urine) Dehiscence is the complete or partial separation of the surgical wound incision; evisceration is the protrusion of an internal bodily organ through the surgical wound incision; and healing by primary intention is the most, not the least, common type of surgical wound healing. Primary intention wound healing is done when the incision is closed because the site is without infection.", "whyNot": {"a": "Dehiscence describes the separation of the wound edges following surgery.", "b": "Evisceration occurs when internal organs protrude from an opening in the skin, such as through a surgical wound.", "c": "Healing by primary intention, such as with the surgical closure of a wound, is the most common type of surgical wound healing, not the"}, "keyConcept": "It is important to recognize the complications that can occur post-operatively. Particularly in clients with risk factors for poor wound healing, complications such as dehiscence (wound reopening), evisceration (internal structures protruding from a wound), and wound infection are some of the complications to be aware of. Post-operative clients should also be carefully monitored for signs of complications like abdominal compartment syndrome which would present with increased abdominal girth, nausea, vomiting, decreased urine output, abdominal pain, and difficulty breathing. Dehiscence Evisceration"}, {"id": 11614, "cat": "pre & post operative", "stem": "A nurse is caring for a client who is scheduled for a surgical procedure the next day. Which of the following does the nurse consider when preparing the client for the procedure?", "choices": [{"id": "a", "t": "The client should take a bath in a tub of warm water the day of surgery, using a mild soap to cleanse the skin."}, {"id": "b", "t": "Excess hair should be shaved from the planned surgical site on the night before surgery."}, {"id": "c", "t": "An indwelling urinary catheter is often only necessary for surgeries that occur below the waistline."}, {"id": "d", "t": "Hair in the area of the surgical site should be removed with electrical clippers and depilatories."}], "correct": "d", "rationale": "A | % Moderate A break in the skin, which is the body’s first line of defense against infection, increases the risk of infection for client’s undergoing a surgical c I 4% procedure. The risk is increased in clients with reduced immune function, including older clients. The primary step in reduction of risk of eD | 58% infection before any surgical procedure is careful preparation of the skin to reduce possible contamination of the surgical field and burden of microorganisms at the surgical site. In addition to cleansing the skin, hair removal may be necessary. The Joint Commission’s National Patient SafetyGuideline requires hair clipping with electrical clippers and depilatories, since shaving can cause nicks in the skin and increase the potential for infection. If shaving is necessary, the area should be shaved with disposable sterile supplies immediately before the start of the procedure.", "whyNot": {"a": "The client should shower (not bathe) the night before surgery or the morning of the procedure. The surgeon may ask the client to use an", "b": "If shaving is necessary, it should occur immediately before the surgical procedure, in the surgical suite treatment room, holding area, or", "c": "The client should be informed that various types of drains, tubes, and vascular access devices may be placed. Urinary catheters are placed"}, "keyConcept": "Hair removal may be necessary before surgery, to reduce contamination of the surgical field and the burden of microorganisms at the surgical site. Shaving should be avoided when possible, since it may result in nicks in the skin, which increase the risk of infection. Depilatories and electrical clippers are recommended. If shaving is necessary, disposable sterile supplies should be used."}, {"id": 11615, "cat": "pre & post operative", "stem": "A nurse is teaching a client who is scheduled for a cardiac catheterization. Which of the following statements should the nurse include in the teaching? O A.\"You should restrict fluids following the procedure.\" O B. \"You will be given general anesthesia during the procedure.\" O C. \"You should not have this procedure if you are allergic to eggs.\" O D. \"You will need to keep your affected leg straight following the procedure.”", "choices": [{"id": "a", "t": "The nurse should instruct the client to increase fluids following a cardiac catheterization to promote excretion of the contrast dye and"}, {"id": "b", "t": "The nurse should instruct the client that he will be awake and sedated during the procedure and that a local anesthetic is used at the"}, {"id": "c", "t": "The nurse should ask the client about an allergy to iodine or shellfish due to the use of contrast dye. An allergy to eggs is not a"}, {"id": "d", "t": "The nurse should instruct the client to remain on bed rest in the supine position with the affected leg straight for a prescribed amount of B | time following the procedure."}], "correct": "d", "rationale": "The nurse should instruct the client to remain on bed rest in the supine position with the affected leg straight for a prescribed amount of B | time following the procedure. This positioning decreases the client's risk for bleeding and hematoma formation at the catheter insertion site.", "whyNot": {"a": "The nurse should instruct the client to increase fluids following a cardiac catheterization to promote excretion of the contrast dye and", "b": "The nurse should instruct the client that he will be awake and sedated during the procedure and that a local anesthetic is used at the", "c": "The nurse should ask the client about an allergy to iodine or shellfish due to the use of contrast dye. An allergy to eggs is not a"}, "keyConcept": "Acardiac catheterization is an invasive procedure that is used to diagnose cardiovascular disease and to evaluate the function of the left or right side of the heart and coronary arteries. Before the procedure, clients should receive testing, such as ECGs, CBCs, coagulation studies, renal function studies, or chest X-rays. The nurse should ask the client about an allergy to iodine or shellfish because a contrast agent is used during a left heart catheterization. Preprocedure nursing care includes taking a complete set of vital signs, listening to the client's lungs, and checking the client's peripheral pulses. The nurse should confirm that the client has been NPO for 8 hr prior to the procedure. The nurse should make sure an informed consent for the procedure was obtained. The nurse might administer a sedative to the client to reduce the client's anxiety prior to the procedure. During the cardiac catheterization, the client will have one or two IVs lines to administer fluids and medications. The client's ECG, pulse oximetry, and blood pressure are continuously monitored, and the client is instructed to report any chest pain, pressure, or shortness of breath. Resuscitation equipment should be available in case the client develops a myocardial infarction, dysrhythmias, or any hemodynamic instability. After the procedure, the client is to remain on bedrest for 2 to 6 hr and should keep the affected extremity straight to decrease the risk for bleeding and hematoma formation. The nurse should check the client's vital signs every 15 min for 1 hr, then every 30 min for 2 hr as per facility protocol until the client is stable. The nurse should check the client's pulses, temperature and color on the affected extremity, and the insertion site for bleeding or a hematoma. The nurse should report any changes."}, {"id": 11616, "cat": "pre & post operative", "stem": "the following medications should the nurse administer? Medications 0701-1500 1501-2300 Acetaminophen 325 mg, 1/2 po q 4-6 hrs prn Temazepam 7.5 mg po qhs prn Hydrycodone/acetaminophen 5 mg/325 mg. 1-2 2000 po q 4-6 hrs prn Morphine 2 mg IV push, q 4 hrs prn 1400 Promethazine 25 mg IV q 4-6 hrs prn 1530", "choices": [{"id": "a", "t": "Acetaminophen"}, {"id": "b", "t": "Temazepam"}, {"id": "c", "t": "Hydrocodone/acetaminophen"}, {"id": "d", "t": "Morphine"}], "correct": "c", "rationale": "The client is reporting a moderate level of pain, so the oral hydrocodone/acetaminophen combination is a reasonable medication, which the client received 5 hours ago. The client did not require further analgesia after the last dose of hydrocodone/acetaminophen, so it is likely to provide adequate pain relief.", "whyNot": {"a": "The client describes a moderate level of pain, which is unlikely to be relieved with acetaminophen alone.", "b": "Temazepam is prescribed for this client every hours of sleep as needed (qhs prn). It is a benzodiazepine that is sometimes used to assist", "d": "The oral pain medication combination relieved the client’s earlier pain without the need for intravenous morphine. Morphine should be"}, "keyConcept": "When determining the need for an as needed (prn) medication for relief of pain, the nurse should consider the severity of pain and the client's previous response to analgesics."}], "psychiatric": [{"id": 11617, "cat": "psychiatric", "stem": "Acharge nurse in a mental health facility is providing an in-service about the use of guided imagery. For which of the following conditions should the nurse suggest the use of guided imagery?", "choices": [{"id": "a", "t": "Posttraumatic stress disorder"}, {"id": "b", "t": "Schizophrenia © c.Pedophilia"}, {"id": "d", "t": "Antisocial personality disorder"}], "correct": "a", "rationale": "Guided imagery is a recommended treatment to relieve the anxiety associated with posttraumatic stress disorder. It is a complementary B I a alternative therapy that is also used to treat sleep disorders, anxiety, and pain. c | 2% my 6%", "whyNot": {"b": "Guided imagery is not indicated for the treatment of schizophrenia.", "d": "Guided imagery is not indicated for the treatment of antisocial personality disorder."}, "keyConcept": "During guided imagery, clients are instructed to focus on pleasant images or thoughts to replace a negative feeling. Clients are instructed to take slow, deep breaths to help relax the mind and body. Sometimes, clients are encouraged to close their eyes to imagine the image or scene."}, {"id": 11618, "cat": "psychiatric", "stem": "A nurse is assessing a child who has autism spectrum disorder. Which of the following findings should the nurse expect?", "choices": [{"id": "a", "t": "Preoccupation of thoughts"}, {"id": "b", "t": "Associative looseness"}, {"id": "c", "t": "Echolalia"}, {"id": "d", "t": "Magical thinking"}], "correct": "c", "rationale": "‘i Echolalia is a fundamental sign of autism spectrum disorder and is manifested as repeating speech sounds, usually in a meaningless way. B Bl oc D", "whyNot": {"a": "Preoccupation of thoughts is an indication of schizophrenia, not autism spectrum disorder, and is manifested as inappropriate emotional", "b": "Associative looseness is an indication of schizophrenia, not autism spectrum disorder, and is manifested as disorganized thoughts and", "d": "Magical thinking is an indication of schizophrenia, not autism spectrum disorder. A client who is exhibiting magical thinking believes their"}, "keyConcept": "When assessing a client who has autism spectrum disorder, the nurse should expect the client to exhibit repetitive motor movements or speech. Examples include flipping toys consistently or echolalia. A client who has autism spectrum disorder can be inflexible to change in routine and might experience extreme distress when this occurs."}, {"id": 11619, "cat": "psychiatric", "stem": "actions should the nurse take? O A. Encourage the client to go back to bed. O B. Administer zolpidem to the client. O C. Remain with the client. O D. Explore alternatives to pacing the floor with the client.", "choices": [{"id": "a", "t": "Encourage the client to go back to bed."}, {"id": "b", "t": "Administer zolpidem to the client."}, {"id": "c", "t": "Remain with the client."}, {"id": "d", "t": "Explore alternatives to pacing the floor with the client."}], "correct": "c", "rationale": "A client who is experiencing a severe level of anxiety has a very restricted sense of the surrounding environment. They can be confused and are at risk for injury. Remaining near the client will help to alleviate feelings of abandonment and reassure the client of their safety.", "whyNot": {"a": "The nurse should recognize that the client is experiencing a severe level of anxiety. At this level, the client's behaviors are automatic and", "b": "The use of medications to treat severe or panic levels of anxiety include the administration of a benzodiazepine, such as diazepam or", "d": "A client who is experiencing severe anxiety engages in automatic behaviors, such as pacing or wringing of the hands. While in this state,"}, "keyConcept": "Clients who experience severe to panic levels of anxiety have a decreased ability to self-regulate behaviors and a diminished sense of the surrounding environment. While experiencing the anxiety, the client can become confused and have a diminished ability to communicate with others. The nurse should ensure the client remains safe and relay information to the client using short and simple statements. The nurse should be aware that repetition of information is often necessary as a client who is experiencing a severe or panic level of anxiety is unable to learn or retain information. The nurse should listen for themes in the client's communication and reinforce reality if needed. Finally, the nurse should ensure the client's physical safety and attend to physical needs, such as nutrition and fluid intake."}, {"id": 11620, "cat": "psychiatric", "stem": "actions should the nurse take? O A. Encourage the client to go back to bed. O B. Administer zolpidem to the client. O C. Remain with the client. O D. Explore alternatives to pacing the floor with the client.", "choices": [{"id": "a", "t": "Encourage the client to go back to bed."}, {"id": "b", "t": "Administer zolpidem to the client."}, {"id": "c", "t": "Remain with the client."}, {"id": "d", "t": "Explore alternatives to pacing the floor with the client."}], "correct": "c", "rationale": "A A client who is experiencing a severe level of anxiety has a very restricted sense of the surrounding environment. They can be confused and B : are at risk for injury. Remaining near the client will help to alleviate feelings of abandonment and reassure the client of their safety.", "whyNot": {"a": "The nurse should recognize that the client is experiencing a severe level of anxiety. At this level, the client's behaviors are automatic and", "b": "The use of medications to treat severe or panic levels of anxiety include the administration of a benzodiazepine, such as diazepam or", "d": "A client who is experiencing severe anxiety engages in automatic behaviors, such as pacing or wringing of the hands. While in this state,"}, "keyConcept": "Clients who experience severe to panic levels of anxiety have a decreased ability to self-regulate behaviors and a diminished sense of the surrounding environment. While experiencing the anxiety, the client can become confused and have a diminished ability to communicate with others. The nurse should ensure the client remains safe and relay information to the client using short and simple statements. The nurse should be aware that repetition of information is often necessary as a client who is experiencing a severe or panic level of anxiety is unable to learn or retain information. The nurse should listen for themes in the client's communication and reinforce reality if needed. Finally, the nurse should ensure the client's physical safety and attend to physical needs, such as nutrition and fluid intake."}, {"id": 11621, "cat": "psychiatric", "stem": "consider about pseudoneurologic symptoms such as blindness or paralysis?", "choices": [{"id": "a", "t": "It is an unconscious method for getting attention"}, {"id": "b", "t": "It is necessary for the client to cope with the present situation"}, {"id": "c", "t": "It is usually solved when the client learns to deal with ongoing family conflicts"}, {"id": "d", "t": "It is reversible and will subside if the client is helped to focus on other things"}], "correct": "b", "rationale": "vondi ‘ety: ; All 7% Hard Conversion disorders develop when anxiety is converted to physical symptoms that are not under voluntary control. OB a 44%", "whyNot": {"a": "Conversion disorder does not exist for the purpose of getting attention.", "c": "It is more important for a client to learn how to deal with personal feelings before focusing on family conflicts.", "d": "It is important for the client to work on the issue that is causing the disorder rather than focusing on other things."}, "keyConcept": "Conversion disorder is one of a group of disorders known as somatoform disorders. It is characterized by neurological signs or symptoms. that are inconsistent with neurologic disease, including weakness, abnormal movements, or nonepileptic seizures. These are inconsistent with a neurologic disease, but still cause distress, and/or impairment. Somatization refers to mechanisms by which anxiety manifests as a physical illness or bodily complaint. The expression of physical symptoms suggests the presence of a physiological disorder, but the symptoms are not fully explained by any physical disorder. The symptoms appear to be linked to psychological factors or conflicts."}, {"id": 11622, "cat": "psychiatric", "stem": "A nurse is caring for a client with major depression and suicidal ideation who is suddenly calmer and more energetic. Which of the following should the nurse consider?", "choices": [{"id": "a", "t": "The client is improving"}, {"id": "b", "t": "The client’s medication dosage is too high"}, {"id": "c", "t": "The client is over stimulated"}, {"id": "d", "t": "The client is suicidal"}], "correct": "d", "rationale": "When a client with major depression and suicidal ideation displays a sudden elevation in mood, seems calmer, has more energy, or appears to be more peaceful, the nurse should judge these behaviors as an indication that a suicide attempt may be imminent.", "whyNot": {"a": "Improvement is often slow for clients who are depressed and suicidal; this change in behavior may instead signify that the client has a", "b": "Too much medication would not cause these effects in the client; instead, he is most likely suicidal.", "c": "The client is probably not overstimulated; his behavior indicates that he is suicidal and is at peace with his decision."}, "keyConcept": "Clients who are at risk for self-harm need close, supervised, and supportive care. Any clients who verbalize thoughts of hurting themselves should be taken seriously. People who commit suicide often tell at least one person they are thinking about killing themselves before they actually commit the act. Clients with a history of self-harm or unsuccessful suicide attempts are at risk for subsequent self-harm. Clients who are severely depressed and suicidal are often hospitalized and medicated, but it takes several weeks before the medication has a therapeutic effect on the depression. However, the client may appear more energetic and focused after a few days to a week of treatment. This can be harmful, as the mood disorder is not yet adequately resolved and the client may use the energy to complete suicide."}, {"id": 11623, "cat": "psychiatric", "stem": "A nurse is conducting group therapy with clients. Which of the following responses should the nurse make to a client's aggressive statement?", "choices": [{"id": "a", "t": "\"You seem very upset.\""}, {"id": "b", "t": "\"I will call security if you don't settle down immediately.\""}, {"id": "c", "t": "\"I don't think anyone in the group appreciates the way you're talking.\""}, {"id": "d", "t": "\"What's wrong with you?\""}], "correct": "a", "rationale": "This statement allows for exploration of feelings, and it might lead to de-escalation. The nurse should use a calm, clear tone of voice when B | a0 talking with the client, and show empathy for the client's feelings. cf 5%", "whyNot": {"b": "This statement is a show of force and might be seen as confrontational. To help calm a client showing aggressive behavior, the nurse", "c": "This statement invokes judgment about the client's behavior and makes assumptions about group members. Talking to the client in this", "d": "This statement implies a threat and a lack of respect for the client. This represents nontherapeutic communication because it shows"}, "keyConcept": "It can be uncomfortable for a nurse to manage a situation during which a client displays aggression. However, for the safety of staff and clients, the nurse should implement de-escalation techniques with the client showing aggression. Primarily, the nurse should remain calm in action and tone of voice. The nurse should not ignore the behavior, but directly confront the client, discussing rules about appropriate behavior while not making threats toward the individual. Offering the client options in the situation can help ease the client's stress. For example, the nurse could suggest the client take a walk with another staff member or journal about the feelings behind the behavior."}, {"id": 11624, "cat": "psychiatric", "stem": "oO @ %€ Claude x SE Extractq. x Na Logins Pc x ™ [GitHub]: x ™ Inbox-b: x @ TEASPra x OnlineNi xX @ Microsofi x ®@ NCLEXE x {— Results- x Q bobyond| x © NewTab x + v € > GCG _— &% student.atitesting.com/LT| Q *& x * © OD Cb ) oO Tutorial: BoardVitals NCLEX Prep RN % CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Practicing effective socialization skills"}, {"id": "b", "t": "Perceiving her body shape as acceptable"}, {"id": "c", "t": "Decreasing preoccupation with delusional thoughts"}, {"id": "d", "t": "Verbalizing the desire to increase control over stressful situations"}], "correct": "d", "rationale": ", rather than resort to binge-purge behaviors. The first step toward B | ma fo achieving control is expressing a desire to do so. ci 8%", "whyNot": {"a": "This client is not demonstrating ineffective socialization skills; this would not be a useful goal.", "b": "While it is important for the client to eventually learn to accept her body, she first needs to have the desire to change her habits.", "c": "The client is not exhibiting delusional thoughts by having bulimia."}, "keyConcept": "Bulimia nervosa is an eating disorder sometimes known as binge-purge syndrome. The disorder is characterized by extreme binge overeating followed by self-induced vomiting, as the affected individual to get rid of the extra calories. Abuse of laxatives and diuretics is associated with this disorder. These behaviors result from an unhealthy preoccupation with body shape and weight. Women are three times as likely to be affected as men. The disorder is associated with non-suicidal self-injury and comorbid psychological disorders, including anxiety disorders, body dysmorphic disorder, depressive disorders, posttraumatic stress disorder, and substance use disorders."}, {"id": 11625, "cat": "psychiatric", "stem": "A nurse is teaching a group of clients about alcohol intoxication. Which of the following statements by a client indicates an understanding of the teaching?", "choices": [{"id": "a", "t": "\"The level of intoxication is higher if drink the alcohol slowly.\""}, {"id": "b", "t": "\"Alcohol intoxication can lead to death.\""}, {"id": "c", "t": "\"Alcohol tolerance is the same thing as alcohol intoxication.\""}, {"id": "d", "t": "\"Alcohol intoxication can cause delirium tremens.\""}], "correct": "b", "rationale": "0.02 g/dL. At this level, mood alterations are OB a aa present along with a decreased ability to multi-task. As blood alcohol levels increase, incoordination, decreased cognitive abilities, and difficulty detecting danger occur. When blood alcohol levels reach 0.40 g/dL, death can occur. c | 1% om 20%", "whyNot": {"a": "Rapid consumption of alcoholic beverages will increase the speed at which a client will become intoxicated.", "c": "A client can develop alcohol tolerance due to repeated exposure to the substance, which results in a decreased physical response to the", "d": "Delirium tremens (DTs) are caused by alcohol withdrawal in a client who has a history of prolonged, heavy alcohol use. The presence of"}, "keyConcept": "While the legal definition of alcohol intoxication in many states is a blood alcohol level of 0.08 g/dL, intoxication occurs with the blood alcohol level as low as 0.02 g/dL. Factors related to intoxication include the client's sex and body size, whether or not food is in the stomach at the time of alcohol consumption, the client's level of hydration, and the type of alcohol consumed."}, {"id": 11626, "cat": "psychiatric", "stem": "A nurse is assessing factors that indicate maltreatment of an infant during a home visit. Which of the following actions by the guardian requires intervention by the nurse?", "choices": [{"id": "a", "t": "Responds to the infant's needs within 5 min."}, {"id": "b", "t": "Makes positive facial expression in response to the infant's actions"}, {"id": "c", "t": "Expresses unrealistic expectations of the infant"}, {"id": "d", "t": "Makes physical contact with the infant during feedings"}], "correct": "c", "rationale": "A 4% Easy Expressing unrealistic expectations of the infant is an indication of child maltreatment that requires intervention by the nurse. An example of a mn, an unrealistic expectation would be for an infant who is 4 months old to avoid dropping a pacifier. Fine motor skills are not developed by this stage and the infant is likely to drop a pacifier being held in their hand. ec Ft 90% of 4% Attitudes That Indicate Potential Child Maltreatment Feelings of inadequacy Unrealistic expectations of the infant Misdirected anger Adult conflict Fear of \"Always doing something wrong\" Attribution of negative qualities to the infant Evidence of isolation, frustration, anger, and/or apathy", "whyNot": {"a": "A guardian who is responsive and attentive to the needs of the infant does not require intervention by the nurse. A guardian who allows", "b": "A guardian who exhibits positive facial expressions, such as a smile, in response to the infant's actions does not require intervention by", "d": "A guardian who makes physical contact with the infant during feedings does not require intervention by the nurse. Holding the infant"}, "keyConcept": "It is important for the nurse to assess the guardian's attitude toward the infant during a home visit. These attitudes can be an indicator of a © o 2 ° s a = a <"}, {"id": 11627, "cat": "psychiatric", "stem": "things again.\" What is the best initial response from the nurse?", "choices": [{"id": "a", "t": "\"You should be able to go out soon.\""}, {"id": "b", "t": "\"What activities did you enjoy in the past?\""}, {"id": "c", "t": "\"That will be up to your doctor.\""}, {"id": "d", "t": "\"How much money can you spend?\""}], "correct": "b", "rationale": "al 2% Easy This is an open ended question that will provide an opportunity for therapeutic communication. Identifying the client’s interests will guide the nurse in planning activities that the client will enjoy while acquiring practice in social skills in a safe setting where positive reinforcement OE as cata) can be provided by the nurse and other staff. c | 2% p | 1%", "whyNot": {"a": "This statement may not be true. It is also a closed-ended statement that does not encourage the client to discuss feelings or emotions", "c": "This is a paternalistic statement and does not encourage communication.", "d": "This is not a therapeutic statement."}, "keyConcept": "Schizophrenia has both positive and negative symptoms. Positive symptoms include delusions and hallucinations. Negative symptoms include anhedonia (lack of pleasure), apathy, and blunted affect. Positive symptoms are more responsive to medication than negative symptoms. Negative symptoms are often persistent in the absence of delusions and hallucinations and are associated with impaired social functioning. The nurse should establish a relationship of trust with the client and assist the client to maximize functioning by reinforcing positive behaviors, promoting social skills, involving family members in the client's treatment, and identifying available community resources."}, {"id": 11628, "cat": "psychiatric", "stem": "A nurse is teaching a newly licensed nurse about electroconvulsive therapy (ECT). Which of the following statements should the nurse include in the teaching? O A.\"The most common adverse effect is short-term memory loss.\" O B. \"Many clients experience muscle cramping from the induced seizure.\" O C. \"The client will remain unconscious for several hours following the treatment.\" O D. \"The presence of a metal implant in the head is a contraindication to the procedure.\"", "choices": [{"id": "a", "t": "ECT is used in the management of medication-resistant depression or psychosis."}, {"id": "b", "t": "A client will receive a general anesthetic and a paralytic agent before the procedure to prevent injury during the procedure. Muscle"}, {"id": "c", "t": "ECT is performed under general anesthesia, which results in temporary unconsciousness. The client should awaken about 15 min"}, {"id": "d", "t": "There are several medical conditions that increase the risk for complications associated with ECT. Clients who have cardiac disease, brain"}], "correct": "a", "rationale": "ECT is used in the management of medication-resistant depression or psychosis. The procedure involves the application of an electric | current to the brain, which results in a grand mal seizure. The most common adverse effects include mild disorientation and confusion immediately after the treatment, a slight headache, and short-term memory problems. c | om Mecicatons Admnstered During 6 Therapy Class Medication Effect Anticholinergic Atropine, glycopyrrolate Decrease secretions, counteract bradycardia (vagal response to the induced seizure) ‘Anesthetic Propofol, etomidate Cause short-term unconsciousness: Paralytic agent Succinylcholine Prevent severe muscle contractions during induced seizure activity", "whyNot": {"b": "A client will receive a general anesthetic and a paralytic agent before the procedure to prevent injury during the procedure. Muscle", "c": "ECT is performed under general anesthesia, which results in temporary unconsciousness. The client should awaken about 15 min", "d": "There are several medical conditions that increase the risk for complications associated with ECT. Clients who have cardiac disease, brain"}, "keyConcept": "Electroconvulsive therapy (ECT) is used in the management of medication-resistant depression and psychotic disorders. Nurses who are caring for clients who are scheduled to receive ECT should ensure the client has signed an informed consent. Preliminary workups should also be completed, which include ECG, chest X-ray, urinalysis, complete blood count, blood urea nitrogen, and electrolytes. The nurse should review the findings of the preliminary workups and notify the provider about any findings that are outside of the expected reference ranges. Following the procedure, the nurse should monitor the client's vital signs, oxygen saturation, level of consciousness, and orientation."}, {"id": 11629, "cat": "psychiatric", "stem": "should the nurse make? O A.\"Using homeopathic treatments is not a good Idea. You should find another alternative.\" O B. \"A lot of people think homeopathic treatments will work, and they find out too late that they made the wrong choice.\" O C. \"Your provider is very knowledgeable. If she prescribes chemotherapy, that means it's the best treatment for you.\" O D. \"Tell me more about your concerns about taking chemotherapy.\"", "choices": [{"id": "a", "t": "This response is an example of the nontherapeutic communication technique of disapproving. This can make the client feel defensive. A"}, {"id": "b", "t": "This response is an example of the nontherapeutic communication technique of minimizing the client's feelings. This can make the feel a"}, {"id": "c", "t": "This response is an example of the nontherapeutic communication technique of defending. This can make the client feel defensive and"}, {"id": "d", "t": ". This encourages communication and is an B | a0 example of the therapeutic communication technique of exploring."}], "correct": "d", "rationale": ". This encourages communication and is an B | a0 example of the therapeutic communication technique of exploring. c| 2% 00}", "whyNot": {"a": "This response is an example of the nontherapeutic communication technique of disapproving. This can make the client feel defensive. A", "b": "This response is an example of the nontherapeutic communication technique of minimizing the client's feelings. This can make the feel a", "c": "This response is an example of the nontherapeutic communication technique of defending. This can make the client feel defensive and"}, "keyConcept": "The nurse should identify that a client who has cancer and is scheduled to receive chemotherapy might be fearful about what to expect. By using the therapeutic technique of exploring, the nurse allows the client to discuss concerns and feelings about the chemotherapy. From the provided information, the nurse can examine the client's feelings and ideas about the treatment itself."}, {"id": 11630, "cat": "psychiatric", "stem": "e@ @ %€ Claude x SE Extract aq. x Na Logins Pc x ™ [GitHub] x ™ Inbox-b: x @ TEASPra x OnlineNi xX @ Microsofi x @® NCLEXE x {. Results- x Q bobyond| x © NewTab x + v € > G _ 8% student.atitesting.com/LT! Qa * s * ©o8 OD Cb ) 2 Tutorial: BoardVitals NCLEX Prep RN x CLOSE ati Module: Results Dashboard Quiz ~ Performance ~ { Browse Questions > iit Search Questions Q }", "choices": [{"id": "a", "t": "Binge eating disorder: The client maintains a relatively stable body weight"}, {"id": "b", "t": "Bulimia nervosa: clients with bulimia nervosa purge"}, {"id": "c", "t": "Nonpurging bulimia nervosa: The client has ritualistic eating patterns"}, {"id": "d", "t": "Anorexia nervosa: The client has an unrealistic fear of obesity"}], "correct": "d", "rationale": "all 6% Easy Clients with anorexia nervosa have unrealistic fears about obesity. Other signs and symptoms of anorexia include ritualistic eating patterns, B | or over-exercise, restricting food intake, and a preoccupation with food. I © 6%", "whyNot": {"a": "People with binge eating disorder often experience significant weight gain and obesity.", "b": "Clients with bulimia may or may not purge as part of the disease.", "c": "Ritualistic eating patterns are associated with anorexia nervosa."}, "keyConcept": "Eating disorders described in the Diagnostic and Statistical Manual of Psychiatry V include anorexia nervosa, bulimia nervosa, a = o B f= 4 ° = a = g < avoidant/restrictive food intake disorder, binge eating disorder, pica, and rumination disorder. These disorders are described by symptoms and each is distinguished by symptoms associated exclusively with the specific disorder. Anorexia nervosa is characterized by severe calorie restriction, an abnormal fear of becoming fat, and disturbed body image. Weight loss and caloric restriction in anorexia nervosa result in multiple medical problems, including electrolyte imbalance, amenorrhea, and cardiac arrhythmia."}, {"id": 11631, "cat": "psychiatric", "stem": "A nurse is assessing a client who has posttraumatic stress disorder (PTSD) following a natural disaster. Which of the following finding should the nurse expect?", "choices": [{"id": "a", "t": "Increasingly cautious behavior"}, {"id": "b", "t": "Increasing sense of attachment to others"}, {"id": "c", "t": "Constant need to talk about the event"}, {"id": "d", "t": "Increasing feelings of anger"}], "correct": "d", "rationale": "‘i sem Hard Several manifestations are often present in clients who have PTSD. Clients can experience hypervigilance, an exaggerated startle response, B | a0 and problems with concentration and sleep. Clients might also engage in reckless or self-destructive behavior. Clients can experience irritability and strike out in anger at others with little to no provocation, which can damage or hinder relationships with others. c | 8% oo i” 34%", "whyNot": {"a": "PTSD is characterized by persistent thoughts about a traumatic event the client has experienced. These events can be related to military", "b": "Manifestations of PTSD include the development of problems with relationships with others. Clients who have PTSD often avoid", "c": "PTSD is associated with intense psychological and physiologic distress when thinking or talking about the traumatic event. Even similar"}, "keyConcept": "Nursing interventions for clients who have PTSD include teaching the client about adaptive coping skills and encouraging the client to utilize adaptive coping strategies to replace those that are maladaptive. Consistency in care delivery is an important aspect in caring for a client who has PTSD and serves to establish trusting relationships between the client and members of the healthcare team."}, {"id": 11632, "cat": "psychiatric", "stem": "an understanding of the teaching? O A. \"Ritualistic behaviors provide sexual satisfaction.\" O B. \"Clients perform ritualistic behaviors to boost self-confidence.\" O C. \"Ritualistic behaviors temporarily relieve anxiety.\" O D. \"Clients perform ritualistic behaviors that are directly related to the stressor.\"", "choices": [{"id": "a", "t": "\"Ritualistic behaviors provide sexual satisfaction.\""}, {"id": "b", "t": "\"Clients perform ritualistic behaviors to boost self-confidence.\""}, {"id": "c", "t": "\"Ritualistic behaviors temporarily relieve anxiety.\""}, {"id": "d", "t": "\"Clients perform ritualistic behaviors that are directly related to the stressor.\""}], "correct": "c", "rationale": "Clients who have OCD perform ritualistic behaviors to provide a temporary relief from the anxiety that is related to obsessions. ; o;", "whyNot": {"a": "While certain ritualistic behaviors might provide sexual satisfaction, the primary purpose of the behavior is to relieve anxiety.", "b": "Ritualistic behaviors typically cause clients to feel humiliation and do not raise their self-esteem.", "d": "A client who has OCD experiences persistent thoughts or urges that increase the client's anxiety level. In an attempt to relieve the anxiety,"}, "keyConcept": "The nurse should recognize that a client who has OCD performs ritualistic behavior to reduce anxiety or stress related to a dreaded situation or incident. The client feels obligated to perform the ritual in a specific order, which can be time consuming. This behavior can impair a client's personal, professional, and social interactions."}, {"id": 11633, "cat": "psychiatric", "stem": "A nurse is caring for a client who states \"| have been under a lot of stress lately as a result of financial problems.\" Which of the following is a true statement regarding stress?", "choices": [{"id": "a", "t": "Stress describes a situation, rather than a person’s reaction to it"}, {"id": "b", "t": "Stress is largely a psychological phenomenon, mostly affecting cognitive responses"}, {"id": "c", "t": "Stress is a response to a situation that is seen as threatening to a person’s well-being"}, {"id": "d", "t": "Stress produces a deviation from normal behavior due to its inherently negative impact"}], "correct": "c", "rationale": "A l 3% Moderate Stress is defined as the response to a situation that is seen as threatening to a person’s well-being. Stress, such as distress in the case of a B | oom fo difficult and demanding situation, can be challenging. Alternatively, eustress is a type of stress that can be energizing. Some amount of stress is helpful for survival. ec | 12% om 13%", "whyNot": {"a": "Stress refers to a person’s response to a situation, whether it is positive or negative.", "b": "Stress can affect the physical and cognitive functioning.", "d": "Stress is not always negative; even positive stress can impact a person’s abilities and may be energizing."}, "keyConcept": "Stress is primarily a physical response by the body to a perceived threat. The body's response is also known as the ‘fight or flight' reaction, primarily mediated by the sympathetic nervous system. A mix of hormones and chemicals such as adrenaline, cortisol and norepinephrine prepare the body for physical action. Physical responses to stress include increased blood pressure and pulse rate; rapid breathing; pupil dilation; reduced gastrointestinal activity; muscle contraction; and heightened alertness. Stress can be acute, chronic, or acute episodic, which refers to recurrent episodes of acute stress."}, {"id": 11634, "cat": "psychiatric", "stem": "should the nurse take next? O A. Suggest that the client rest in bed. O B. Stay with the client for a while. O C. Administer a sedative to the client. O D. Encourage the client to join an activity with others.", "choices": [{"id": "a", "t": "Suggest that the client rest in bed."}, {"id": "b", "t": "Stay with the client for a while."}, {"id": "c", "t": "Administer a sedative to the client."}, {"id": "d", "t": "Encourage the client to join an activity with others."}], "correct": "b", "rationale": "| 15% Easy Stay with the client for a while. Rationale B. When providing client care, the nurse should first use the least restrictive intervention. Therefore, the nurse should remain with Cc I 5% a client who has anxiety. The nurse should stay with the client to encourage him to express his feelings, which might help to lower his anxiety .", "whyNot": {"a": "The nurse can suggest that the client rest in bed to help with his anxiety level. However, this is not the least restrictive intervention.", "c": "The nurse might have to medicate the client with a sedative to help with the client's anxiety level. However, this is not the least restrictive", "d": "When the client's anxiety peaks, interaction with other clients might cause his anxiety to increase. This is an appropriate intervention later"}, "keyConcept": "Clients who have generalized anxiety disorder might experience distress. When this occurs, the priority intervention for the nurse is to remain with the client. This action can indicate to the client that the nurse willing to help, which can decrease the client's level of anxiety. This action can also calm and help provide a sense of security for the client."}, {"id": 11635, "cat": "psychiatric", "stem": "A nurse in the emergency department is assigned to care for a client complaining of anxiety. Which of the following are physiological signs of anxiety?", "choices": [{"id": "a", "t": "Dilated pupils, dilated bronchioles, increased pulse rate, hyperglycemia, and peripheral vasoconstriction"}, {"id": "b", "t": "Constricted pupils, dilated bronchioles, increased pulse rate, hypoglycemia, and peripheral vasodilation"}, {"id": "c", "t": "Constricted pupils, constricted bronchioles, increased pulse rate, hypoglycemia, and peripheral vasodilation"}, {"id": "d", "t": "Dilated pupils, constricted bronchioles, decreased pulse rate, hypoglycemia, and peripheral vasoconstriction"}], "correct": "a", "rationale": "The “fight or flight” response of the sympathetic nervous system is activated in individuals with anxiety. This response is a primitive reflex to B 9% fear or a perceived threat. | o| 4% Physiological signs of anxiety re Dilated pups Disted bronchioles Increased pulse rate Nypertycemia 2 (S g o 5 [a < Peripheral vasoconstriction", "whyNot": {"b": "Pupils dilate and blood glucose rises in response to anxiety. Vasodilation is not a symptom of anxiety.", "c": "The pupils and bronchioles dilate, and the blood glucose rises in response to anxiety. Vasodilation is not a symptom.", "d": "The bronchioles dilate, the pulse rate increases, and the blood sugar increases in the “fight or flight\" response."}, "keyConcept": "The fight or flight response is mediated by the sympathetic nervous system in response to a perceived threat or to fear. In this response, the peripheral blood vessels constrict and coronary arteries dilate to increase blood supply to brain, muscles, and the heart. Cardiac output increases by increase in heart rate and contractility. The lungs take in more O2 and release more CO2 and the liver releases glucose produced from glycogen stores for energy. Muscles tense and sweating increases to speed heat loss. The adrenal glands release adrenalin to fuel these responses. Symptoms of anxiety range from mild symptoms to panic and may include heart palpitations, pounding heart, excessive sweating, uncontrollable trembling, shortness of breath.choking sensation, difficulty swallowing, nausea / vomiting, and dizziness or lightheadedness."}, {"id": 11636, "cat": "psychiatric", "stem": "Aprovider is caring for a patient admitted for treatment of depression. Which of the following behaviors exhibited by the patient indicate a readiness for discharge?", "choices": [{"id": "a", "t": "Interactions with staff and peers"}, {"id": "b", "t": "Sleeping for 4 hours in the afternoon and 4 hours at night"}, {"id": "c", "t": "Verbalization of feeling in control of self and situations"}, {"id": "d", "t": "Statements of dissatisfaction over not being able to perform at work"}], "correct": "c", "rationale": "‘i The patient who verbalizes feelings of being in control of self and situations no longer feels powerless, and realizes that their actions can B | have an impact on self and situations. It is common for clients with depression to feel powerless to influence outcomes and lack of control over events and situations.Expression of a feeling of having more control is a sign of readiness for discharge. O€ — D", "whyNot": {"a": "Interacting with staff and peers is a positive action; however, the patient could be conversing in a negative or nontherapeutic manner, so", "b": "Sleeping 4 hour hours in the afternoon and 4 hours at night may be symptomatic of depression. It is not an indication of improvement or", "d": "Verbalizing dissatisfaction over not being able to perform at work indicates that the client is most likely focusing on shortcomings and"}, "keyConcept": "A patient with depression may be admitted to an inpatient unit to ensure safety if the patient is suicidal or because the client cannot provide self-care. Desired treatment outcomes are individualized based on the patient's disease severity, symptoms, and needs and may include outcomes related to thought processes, social interaction, and self-esteem."}, {"id": 11637, "cat": "psychiatric", "stem": "Acharge nurse is admitting a client who has bipolar disorder and is experiencing a manic episode. Which of the following client room assignments should the nurse make?", "choices": [{"id": "a", "t": "Asemi-private room across from the dayroom"}, {"id": "b", "t": "A private room across from the linen room"}, {"id": "c", "t": "A private room across from the exercise room"}, {"id": "d", "t": "Asemi-private room across from the nurses' station"}], "correct": "b", "rationale": ". Assigning OB | aa the client to a private room in a quiet area of the unit decreases stimuli for the client, thus reducing client anxiety. The area around the linen room should be a low-traffic area, which will help decrease the client's anxiety and manic activities. c |_| 16%", "whyNot": {"a": "Bipolar disorder is a chronic recurrent illness that is characterized by alterations in mood, energy, and the ability to function. Clients who", "c": "During manic episodes, the client is at increased risk for self-injury due to hyperactive psychomotor activity. A client who is experiencing", "d": "A manifestation of mania is an increase in motor activity and social interactions with others. A client who is experiencing a manic episode"}, "keyConcept": "Care of a client who is experiencing a manic episode includes providing a safe environment. The nurse should implement interventions to maintain the safety of the client and others, such as limiting environmental stimulation and providing consistent boundaries and limits for the client. The nurse should interact with the client in a neutral but nonthreatening and firm manner while using short and concise instructions and should redirect the client's behavior and energies into constructive activities. This provides structure and a sense of security for the client, which can decrease the client's anxiety."}, {"id": 11638, "cat": "psychiatric", "stem": "teaching? O A. \"ECT is an effective treatment for anxiety disorders.\" O B.\"I should monitor the client closely for hypotension following ECT.\" O C. \"Informed consent should be obtained prior to ECT.\" O D. \"It is a myth that clients experience seizures during ECT.\"", "choices": [{"id": "a", "t": "\"ECT is an effective treatment for anxiety disorders.\" O B.\"I should monitor the client closely for hypotension following ECT.\""}, {"id": "c", "t": "\"Informed consent should be obtained prior to ECT.\""}, {"id": "d", "t": "\"It is a myth that clients experience seizures during ECT.\""}], "correct": "c", "rationale": "A ECT is a treatment that requires informed consent from the client or an authorized person on the client's behalf. B L o: o|", "whyNot": {"a": "ECT is effective in the treatment of depression, not anxiety disorders. It can also be effective for clients who are acutely suicidal and clients", "d": "Clients will experience a seizure during ECT because the procedure induces a grand mal seizure through the application of an electrical"}, "keyConcept": "Electroconvulsive therapy (ECT) is effective in the treatment of clients who have depression, clients who are acutely suicidal, and clients who have bipolar disorder. ECT induces a grand mal seizure through the application of an electrical current to the brain. Clients typically receive this treatment three to five times per week for 4 to 6 weeks. Nurses play an important role prior to the procedure, during the procedure, and after the procedure. The client might experience confusion and temporary memory loss following the procedure. This treatment is used only after therapy with antidepressant medication has been proven to be ineffective. The provider should explain the procedure, risk and benefits, and alternatives to the client or authorized person when obtaining informed consent prior to performing ECT."}, {"id": 11639, "cat": "psychiatric", "stem": "A nurse is caring for a client with antisocial personality disorder who is demonstrating manipulative behavior. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Allow the manipulative behavior to continue to avoid angering the client."}, {"id": "b", "t": "Confront the behavior later in the day when there are fewer people around."}, {"id": "c", "t": "Institute consequences for manipulative behavior."}, {"id": "d", "t": "Bargain with the client to discourage manipulative behavior."}], "correct": "c", "rationale": "A Individuals with personality disorders exhibit inflexible and distorted thinking; impaired emotional responses; poor impulse control; and B 4 interpersonal problems. Antisocial personality disorder is characterized by lack of empathy and disregard for the rights of others. The characteristics are evident in childhood or adolescence and continue into adulthood. These individuals are focused on personal gain. ec as Characteristic behaviors include manipulation, deceit, and lying. Disregard for the law frequently results in legal problems. Individuals with D | anti-social personality disorder are often in the prison system. The nurse should work with the client to develop a behavior plan that includes specific consequences for manipulative behavior. In response to manipulative behavior, the nurse should: + Be aware of the use of flattery, seductiveness, or guilt as a method of manipulation. + Set clear and realistic limits and boundaries. + Set and enforce consequences. + Ensure consistency in adhering to limits. + Document signs and the use of manipulation.", "whyNot": {"a": "The nurse should intervene to discourage the client's attempts at manipulation by setting limits and boundaries and enforcing", "b": "The nurse should confront the client about the behavior when it occurs. The nurse should be consistent and enforce consequences when", "d": "The nurse should not bargain with the client, because this promotes continued manipulative behavior. The nurse should set limits and"}, "keyConcept": "Personality disorders are characterized by persistent patterns of perception, relation, and thinking about oneself and the environment that are unyielding and maladaptive, resulting in distress or impairment in function. Clients who have personality disorders have difficulty"}], "safe_and_effective_care_environment": [{"id": 11640, "cat": "safe and effective care environment", "stem": "provider of this incident. Which of the following should be included when writing an incident report? O A.\"The client was disoriented and tried to get out of bed.\" O B. \"The client fell.\" O C. \"The client was confused and climbed over the side rail.\" O D.\"The client was found lying on the floor.\"", "choices": [{"id": "a", "t": "The nurse was not present and cannot report something that was not witnessed."}, {"id": "b", "t": "2%"}, {"id": "c", "t": "The nurse should only document observations that are factual and accurate."}, {"id": "d", "t": "7 , A l 3% Easy Correct Answer: D."}], "correct": "d", "rationale": "7 , A l 3% Easy Correct Answer: D. \"The client was found lying on the floor.\" . These reports help with identification of risk in the healthcare facility, ultimately c | 2% guiding improvement in client care. The report must be filled out completely and accurately, with documentation only of observed facts. The Op TiS OR fo incident must be documented in a separate report in the client’s record, but the incident report is not copied or placed in the client’s record and should not be referenced in the record. If an error or injury has occurred, the nurse should assess the client frequently.", "whyNot": {"a": "The nurse was not present and cannot report something that was not witnessed.", "b": "Although this is probably a true statement, the nurse does not have a way to verify something that occurred before entering the client’s", "c": "The nurse should only document observations that are factual and accurate."}, "keyConcept": "Incident reports are used to identify risk and guide improvements in client care. They should only include observed facts and should be kept separate from the client's medical record. Although the incident report is not part of the client's medical record, the incident must be documented separately in the medical record."}, {"id": 11641, "cat": "safe and effective care environment", "stem": "better organization for the new graduate?", "choices": [{"id": "a", "t": "The experienced nurse should prepare a list of priority tasks for the new nurse at the beginning of each shift."}, {"id": "b", "t": "The preceptor can assist the inexperienced nurse with client care."}, {"id": "c", "t": "The preceptor should suggest beginning the workday with an organization sheet for the assigned clients."}, {"id": "d", "t": "The preceptor should suggest the new nurse take frequent breaks to relieve stress."}], "correct": "c", "rationale": "‘i | Apreceptor is an experienced nurse who is available to share knowledge, act as a role model, and offer support for the new nurse. The ec | preceptor should help the graduate nurse gain understanding of the expectations associated with the new position. The experienced D | preceptor should recommend an organizational tool to help the new graduate organize the workload and ensure that priority tasks are not overlooked. Organizing the workload will help the nurse manage time effectively and clarify priorities in client care.", "whyNot": {"a": "Itis important for the graduate nurse to gain skill in organizing the workload.", "b": "Although there may be times when it is appropriate for the preceptor to assist the inexperienced nurse, this is not a realistic solution and", "d": "Although breaks should be scheduled, this is not a solution to managing care."}, "keyConcept": "It is important for nurses to develop time management and organizational skills. It can be helpful to arrive early for a shift. Nurses should be certain to allow time to complete charting several times during the day. Meals and breaks are also important and should be scheduled. When organizing the workload, items to consider include time specific events, clients who may require additional care, and tasks that can be delegated to an LPN or UAP."}, {"id": 11642, "cat": "safe and effective care environment", "stem": "The nurse is caring for a client with a kidney stone who is writhing in pain. Which of the following is the priority nursing intervention?", "choices": [{"id": "a", "t": "Decreasing fluids"}, {"id": "b", "t": "Medicating for pain"}, {"id": "c", "t": "Increasing fluids"}, {"id": "d", "t": "Straining urine"}], "correct": "b", "rationale": "The immediate priority for a client with severe pain is to manage his pain so definitive treatment can be implemented. After pain is under control, the nurse should increase the client's fluids in an attempt to wash the stone out of the urinary tract. In order to evaluate the effectiveness of that intervention, the nurse should instruct the client to save all urine so it can be strained to identify any stones that are passed. Kidney stones Kidney Mocca sealchen Marcy plot n oate", "whyNot": {"a": "The nurse should increase, not decrease, fluids.", "c": "While this is important, the nurse must first provide for pain management.", "d": "The nurse should strain the client’s urine but pain management is the priority action."}, "keyConcept": "Urolithiasis refers to stones (calculi) in the urinary tract that precipitate when the urinary concentration of substances such as calcium oxalate, calcium phosphate, and uric acid increases. Slow urine flow allows accumulation of crystals. Stones can be found anywhere in the urinary tract but pain usually occurs when the ureter or flow of urine is obstructed, which results in the most severe pain and can potentially result in kidney damage. Treatment includes opioid analgesics or nonsteroidal antiinflammatory drugs (NSAIDs) and increased fluid intake"}, {"id": 11643, "cat": "safe and effective care environment", "stem": "encounters. Which of the following options lists the personal protective equipment necessary to implement standard precautions?", "choices": [{"id": "a", "t": "Gloves, mask, plastic bags, and gown"}, {"id": "b", "t": "Gloves, gown, mask, and goggles"}, {"id": "c", "t": "Gloves, goggles, mask, and surgical cap"}, {"id": "d", "t": "Gloves, gown, goggles, and N95 respirator"}], "correct": "b", "rationale": "All 11% Easy A nurse is expected to understand and apply different types of transmission precautions while caring for clients. Standard precautions are OB rT CSY eas used in client care for all clients, and isolation precautions for clients with an infectious disease are based on the type of infectious organism and mode of transmission. Personal protective equipment used in standard precautions includes gloves, gowns, masks, and goggles. The © | 29) selection of equipment for an encounter with a client depends on the risk of splash or splatter of blood or body fluids.", "whyNot": {"a": "Plastic bags are not part of standard precautions, but appropriate disposal of medical waste is always important in the prevention of", "c": "Asurgical cap is used to protect the client from contamination through the hair of healthcare personnel. It is not considered a part of", "d": "An N95 respirator is used by healthcare workers in contact with clients on airborne isolation. This is not a standard precaution."}, "keyConcept": "Standard Precautions refer to infection prevention practices that apply to all clients, regardless of suspected or confirmed infection status, in any setting in which healthcare is delivered. They include hand hygiene; use of gloves, gown, mask, eye protection, or face shield, depending on the anticipated exposure; safe injection practices; and safe handling of equipment or items in the environment likely to have been contaminated with infectious body fluids in order to prevent transmission of infectious agents."}, {"id": 11644, "cat": "safe and effective care environment", "stem": "When the nurse calls the healthcare provider to recommend a higher dose of pain medication, the nurse is acting in which of the following roles?", "choices": [{"id": "a", "t": "Manager"}, {"id": "b", "t": "Advocate"}, {"id": "c", "t": "Educator"}, {"id": "d", "t": "Caregiver"}], "correct": "b", "rationale": "9) Easy Correct Answer: B. Advocate bs | 2% When a nurse is acting in the role of an advocate, the nurse provides support for the client by ensuring the client’s rights are respected, the c | 2% client has received all relevant information, and the client is receiving an appropriate level of care. Client rights when hospitalized include: my | or + Right to respectful care + Right to be informed + Right to know the names and roles of members of the healthcare team who are providing care + Right to an advance directive + Right to privacy and confidentiality of medical records + Right to review the record and to have information in the record explained + Right to consent or refuse to participate in research + Right to know of alternative treatments + Right to know about hospital rules affecting treatment + Right to know all charges and acceptable methods of payment", "whyNot": {"a": "A nurse acting in the role of manager helps coordinate interdisciplinary care for the client.", "c": "The role of a nurse educator is to help the client and the client’s caregivers or family to learn about issues relevant to the client’s health.", "d": "When the nurse acts in the role of caregiver, the nurse promotes the client’s wellbeing and recovery and helps the client set goals to"}, "keyConcept": "In the role of advocate for the client, the nurse protects the client's rights, ensures the client remains informed about the medical condition and any associated procedures or treatments, and ensures the client receives an appropriate level of care. a © o 2 ° s a = a <"}, {"id": 11645, "cat": "safe and effective care environment", "stem": "Which of the following best describes a nurse who collaborates with a client directly to create and implement the plan of care?", "choices": [{"id": "a", "t": "Clinical specialist"}, {"id": "b", "t": "Nurse manager"}, {"id": "c", "t": "Primary nurse"}, {"id": "d", "t": "Advanced practice nurse"}], "correct": "c", "rationale": "all of Aprimary nurse oversees the client’s care, including client assessment, implementation of the care plan, and evaluation of the client’s ec FY progress in light of the care given. The primary nurse role is based upon responsibility, accountability and authority. The primary nurse is D i responsible for development of a therapeutic relationship, with accountability to the client, family and members of the health-care team and the authority to develop and implement an individualized plan of care for the client. This relationship-based model of care includes elements of leadership, responsibility, work allocation, and communication with other members of the healthcare team.", "whyNot": {"a": "A clinical specialist has a specific area of clinical expertise or practices in a given clinical area.", "b": "A nurse manager oversees the care of a number of clients on a unit.", "d": "An advanced practice nurse, such as a nurse practitioner, may provide primary care or may serve as a specialist in an area of healthcare,"}, "keyConcept": "Nurses fill a variety of roles in healthcare. A primary nurse is the nurse who oversees the client's care, from assessment to planning, implementation, and evaluation of nursing care. The role of primary nurse is based upon the responsibility to develop a therapeutic relationship; accountability to the client, family and other members of the health-care team; and the authority to develop and implement an individualized plan of care for the client."}, {"id": 11646, "cat": "safe and effective care environment", "stem": "daughter is visiting. The client’s daughter asks you to resuscitate the client, stating “I’ve changed my mind, please help him!” What is the correct immediate nursing intervention?", "choices": [{"id": "a", "t": "Review the client’s DNR status and family’s wishes with the healthcare provider"}, {"id": "b", "t": "Call “code blue” and begin cardiopulmonary resuscitation"}, {"id": "c", "t": "Call the hospital chaplain to comfort the daughter"}, {"id": "d", "t": "Explain the client’s wishes to the daughter"}], "correct": "d", "rationale": "all 9% Easy The purpose of advance directives is to allow individuals to make decisions concerning medical care ahead of a time when they may not be B I Ee able to express their wishes. The client’s wishes should guide the healthcare team and the client’s family at the end of life, if the client has expressed choices about cardiopulmonary resuscitation and other life-sustaining treatments. If a client has signed an advanced directive, it c | 2% must be followed, even when family members object. A medical power of attorney empowers a designated person to make healthcare @D FY 84% decisions for the client, but advanced directives allow the client to make decisions that are observed in case the client becomes incapacitated.", "whyNot": {"a": "An advance directive describes the client’s wishes concerning end-of-life care and does not require consultation with the healthcare", "b": "If a client has signed an advanced directive and does not wish to have CPR initiated (DNR status), the nurse should advocate for the client", "c": "This is not the immediate priority, although the nurse should offer to contact the hospital chaplain after discussing the client’s status with"}, "keyConcept": "Do-not-resuscitate (DNR) orders were initiated to give competent individuals the chance to determine under what circumstances they choose life or natural death. Every client is a “full code” unless a DNR order is documented clearly in the medical record. The nurse should act as an advocate for the client, who exercised autonomy when signing a living will. Although clients should be encouraged to discuss their wishes with family members, this does not always occur."}, {"id": 11647, "cat": "safe and effective care environment", "stem": "A nurse beginning a shift at 7 PM receives a report from the nurse on the day shift. Which of the following clients is the priority assessment for the evening nurse?", "choices": [{"id": "a", "t": "A client who continues to press the call button claiming their service has been poor"}, {"id": "b", "t": "A client who received oral pain medication 15 minutes ago for pain described as “6” on a scale of 1-10"}, {"id": "c", "t": "A client just admitted from the ED without a current complaint"}, {"id": "d", "t": "A client who underwent a balloon angioplasty 10 hours ago and has been granted bathroom privileges"}], "correct": "c", "rationale": ". Although the client denies a current complaint, the client was admitted from B | Aer the ED and the nurse should determine what complaint resulted in the admission and what plan should be instituted to monitor for recurrent problems. A new admit is always a priority. The alternatives include: someone calling to complain about their \"service\" (not a ec | 35% priority for the bedside nurse, but maybe something to delegate to the nurse manager), a patient who received oral pain medication 15 (they should be reassessed, but not urgently), and a patient who has been granted bathroom privileges after an angio performed that morning (if the patient has privileges, they can walk without assistance, or delegate to a UAP). The only patient on the list that requires the nurse's assessment skills urgently is the new admit.", "whyNot": {"a": "Although all clients should be attended to, a claim that care has been neglected may be a psychosocial problem, which has lower priority", "b": "Although it is important to assess a client’s response to pain medication, the client just received medication and can be assessed shortly.", "d": "This client can have bathroom privileges since the angioplasty was performed 10 hours ago. This is not a priority."}, "keyConcept": "Anursing plan of care is based on an assessment of the client. A plan of care cannot be established for a client who has not been assessed. The assessment may reveal urgent priorities and should be performed first."}, {"id": 11648, "cat": "safe and effective care environment", "stem": "The nurse working on a medical surgical unit has a newly licensed nurse assigned to the floor. Which of the following clients is most appropriate to assign to the new nurse?", "choices": [{"id": "a", "t": "A client admitted with an exacerbation of heart failure whose oxygen saturation is 87%"}, {"id": "b", "t": "A client admitted with cirrhosis of the liver who is scheduled paracentesis tomorrow and has extreme dyspnea on exertion"}, {"id": "c", "t": "A client admitted with diabetes who blood sugar is 678 and they are having some confusion and blurred vision."}, {"id": "d", "t": "A client admitted with hyperthyroidism who is scheduled to have a partial thyroidectomy tomorrow and their vital signs are stable."}], "correct": "a", "rationale": "D. signs are stable. A l 3% Easy . Their vital signs are stable so it would be appropriate to assign them to a new nurse. They will need to be prepped for surgery overnight, but if this responsibility falls to the new nurse someone should provide c | instructions on how to prep the pacing. @D PY 90%", "whyNot": {"a": "This client Appears unstable and will require a great deal of nursing expertise and judgment. This would not be the most appropriate", "b": "This client appears to be either unstable or potentially unstable and requires a great deal of nursing expertise and judgment. This would", "c": "This client is likely experiencing or near the onset of DKA. This client or require a great deal of nursing expertise and judgment. This would"}, "keyConcept": "As a nurse, you should be aware of which assignments are and are not appropriate to assign to particular personnel. Assigning clients with a high level of acuity and complexity to a new nurse is inappropriate in most cases."}, {"id": 11649, "cat": "safe and effective care environment", "stem": "A nurse is reviewing the facility's policies and procedures for organ donation to ensure they adhere to state and federal statutes. Which of the following information should the nurse expect to find?", "choices": [{"id": "a", "t": "The nurse caring for the client at the time of death requests the family consider organ donation."}, {"id": "b", "t": "Organs are no longer useful after brain death."}, {"id": "c", "t": "Nurses may serve as witnesses to informed consent for organ donation"}, {"id": "d", "t": "If the facility does not have advance directives from the client, organ donation cannot proceed."}], "correct": "c", "rationale": "Nurses may witness the consent for organ donation after a specially trained professional request the consent.", "whyNot": {"a": "Specially trained professionals in the facility request organ donation from those who can legally give consent.", "b": "Depending on the client's status, some organs and tissues are healthy and eligible for donation after brain death. The organ procurement", "d": "Although it is helpful to have a statement of the client's wishes about organ donation, the next of kin or legally designated person may"}, "keyConcept": "Federal and state legislation regulates the process of organ donation to help meet the demand for available organs and tissues, which greatly exceeds the supply. During the consent process, nurses are responsible for answering questions about the donation process and for providing emotional support to family members."}, {"id": 11650, "cat": "safe and effective care environment", "stem": "unlicensed assistive personnel (UAP)?", "choices": [{"id": "a", "t": "Inspecting the client's feet to ensure they appear in overall good health"}, {"id": "b", "t": "Instructing the client in wound care for a new ulceration on their foot"}, {"id": "c", "t": "Performing a bedside blood glucose test"}, {"id": "d", "t": "Providing education on the types of insulin the client may be prescribed"}], "correct": "c", "rationale": "all 8% Easy This is an appropriate task for unlicensed assistive personnel. And lessons assistive personnel are able to perform bedside glucose testing, as B | a0 long as they are validated in this procedure by their hospital.", "whyNot": {"a": "This task is an assessment and should not be delegated to unlicensed assistive personnel.", "b": "This task is an assessment and also requires nursing judgment. This task should not be assigned to unlicensed assistive personnel. This", "d": "Client education should not be delegated. Client education should be completed by the registered nurse."}, "keyConcept": "The RN should master how to effectively and appropriately delegate. In doing so, the RN will learn more effectively be able to manage their time and resources. This will allow the RN to provide the highest quality of care possible to clients."}, {"id": 11651, "cat": "safe and effective care environment", "stem": "bleeding from a wound on the arm? O A. Apply a pressure bandage to the wound. O B. Remove the victim from the area. O C. Provide rescue breathing. O D. Begin intravenous fluids for shock.", "choices": [{"id": "a", "t": "Apply a pressure bandage to the wound."}, {"id": "b", "t": "Remove the victim from the area."}, {"id": "c", "t": "Provide rescue breathing."}, {"id": "d", "t": "Begin intravenous fluids for shock."}], "correct": "b", "rationale": ", which will help prevent potential harm to rescuers. An open gas line can be a OB a aan source of further injury to the victim and a source of injury to the nurse. The nurse should remove the victim from the area before any other intervention. © | Gr p | 1%", "whyNot": {"a": "Although it is important to control hemorrhage, the initial priority is to avoid additional injury to the victim or injury to the rescuer. The", "c": "Although the victim’s respiratory status must be addressed, it is immediately important to remove the victim from a potential area of", "d": "The client should first be removed from the area of potential additional danger."}, "keyConcept": "When providing care at the scene of a disaster, the initial priority is to ensure the safety of the scene, to prevent potential injury to caregivers and other first responders."}, {"id": 11652, "cat": "safe and effective care environment", "stem": "The nurse is preparing a lecture about advance care directives. The nurse correctly cites which of the following acts as a landmark in patient rights in relation to advance directives?", "choices": [{"id": "a", "t": "The Patient Self Determination Act of 1990"}, {"id": "b", "t": "The Consolidated Omnibus Budget Reconciliation Act of 1985 © c.The No Child Left Behind Act of 2002"}, {"id": "d", "t": "The Economic Stabilization Act of 1970"}], "correct": "a", "rationale": "The Patient Self Determination Act of 1990 served to protect and ensure client rights in determining end of life care.", "whyNot": {"b": "The Consolidated Omnibus Budget Reconciliation Act did not ensure end of life decision rights for clients. It provided for continued health", "d": "The Economic Stabilization Act of 1970 gave the President the ability to make certain economic decisions without congressional consent"}, "keyConcept": "It is important for the nurse working with clients who may want an advanced directive to understand the history of advanced directives. This will help the nurse to understand the client’s rights, and how these rights have been bolstered (and reaffirmed) over the course of time. This enable the nurse to be a strong client advocate when they are making end of life decision"}, {"id": 11653, "cat": "safe and effective care environment", "stem": "A nurse is admitting a client who has delirium resulting from a systemic bacterial infection. At which of the following times during the client's stay at the facility should the nurse initiate discharge planning?", "choices": [{"id": "a", "t": "The day before the client's discharge"}, {"id": "b", "t": "When the provider approves the client for discharge"}, {"id": "c", "t": "During the client's admission process"}, {"id": "d", "t": "When the client's delirium resolves"}], "correct": "c", "rationale": "' needs after discharge. To be effective, discharge planning must begin B | a during admission. The nurses caring for the client should begin to determine the client's needs at the time of admission and devise a plan for meeting those needs during and after hospitalization. ec a 85% off 7%", "whyNot": {"a": "Many clients' facility stays are brief, and nurses must focus on the completion of necessary nursing tasks. Waiting until the day before", "b": "Waiting until a few hours before discharge, typically when the provider writes the prescription for discharge, is likely to result in ineffective", "d": "Nurses should wait until a client has the readiness to learn before providing education because cognitive impairments, such as delirium,"}, "keyConcept": "Discharge planning is a process that nurses begin at admission. At that time, they must determine the client's ability to participate in the admission and in discharge planning. Clients who are in physiologic distress or have cognitive alterations cannot participate fully, and nurses might have to rely on family members at that time. Discharge planning is an interprofessional process. Therefore, nurses must also work with other members of the team to ensure that clients will have the support, referrals, and resources they need following their discharge."}, {"id": 11654, "cat": "safe and effective care environment", "stem": "following members of the interdisciplinary team?", "choices": [{"id": "a", "t": "Occupational therapist"}, {"id": "b", "t": "Physical therapist"}, {"id": "c", "t": "Respiratory therapist"}, {"id": "d", "t": "Paramedical technologist"}], "correct": "c", "rationale": "Respiratory therapists help clients learn to use oxygenation and airway management devices, such as BiPAP equipment.", "whyNot": {"a": "Occupational therapists help clients develop skills for managing activities of daily living.", "b": "Physical therapists help clients strengthen muscles and compensate for musculoskeletal problems.", "d": "Paramedical technologists provide laboratory, radiology, nuclear medicine, and other services."}, "keyConcept": "Interprofessional teams are groups of healthcare professionals from various disciplines who work together to meet clients' needs. They develop plans of care, coordinate services in inpatient and outpatient settings, and improve the quality of clients' care and their satisfaction with the care they receive. Nurses must initiate the necessary referrals to team members who could help improve clients' outcomes. The following table highlights the functions of some other members of these teams: Interprofessional Team Members Physical therapist Evaluates and promotes the strength and mobility of clients who have musculoskeletal problems ‘Occupational therapist Helps clients develop skilis for managing activities of daily living or returning to work Social worker Coordinates community services to assist clients with financial issues and accessing various resources ‘Speech-language Evaluates swallowing and communication pathologist problems and teaches strategies to prevent aspiration Spiritual representative Attends to spiritual needs and provides religious services Pharmacist Prepares and dispenses medications Registered dietitian Teaches clients about meeting nutritional needs Case manager ‘Assumes responsibility for coordinating care, referrals, and services to ensure optimal outcomes Paramedical technologist Provides laboratory, radiology, nuclear medicine, and other services"}, {"id": 11655, "cat": "safe and effective care environment", "stem": "A nurse smells smoke when entering a client's room and finds a fire is burning in the bathroom. What is the most appropriate response?", "choices": [{"id": "a", "t": "Find other staff members to assist."}, {"id": "b", "t": "Take the client out of the room"}, {"id": "c", "t": "Check the bathroom to find out if anything is broken"}, {"id": "d", "t": "Find the closet fire extinguisher"}], "correct": "b", "rationale": "Here are the actions to take in the event of a fire, using the mnemonics \"RACE\" and \"PASS:\" RACE 1, Rescue clients who are in immediate danger. 2. Activate the fire alarm. 3. Confine the fire. 4. Extinguish the fire and obtain the fire extinguisher. PASS 5. Pull the pin on the fire extinguisher. 6. Aim at the base of the fire. 7. Squeeze the extinguisher handle. 8. Sweep the extinguisher from side to side to coat the area of the fire evenly. A. The priority is the safety of individuals in the area of the fire, who should be rescued or removed. The nurse should not take time to find assistance prior to moving the clients in danger C. Assessment of damage is not a priority for the nurse. D. After safety of individuals is assured and the nurse has taken any measures to confine the fire (closing doors and windows,)_ the nurse can use the extinguisher if conditions are safe to do so.", "whyNot": null, "keyConcept": null}, {"id": 11656, "cat": "safe and effective care environment", "stem": "Which of the following clients should the nurse on the day shift prioritize for assessment after receiving a change of shift report?", "choices": [{"id": "a", "t": "A client who had a subdural hemorrhage 2 days ago and is now requesting something to eat"}, {"id": "b", "t": "A client who is receiving total parenteral nutrition post-op gastrojejunostomy who has a urine output of 4500 mL over the last shift"}, {"id": "c", "t": "A client who was admitted after a transient ischemic attack and is scheduled to receive aspirin and clopidogrel at 0700"}, {"id": "d", "t": "A client who was admitted for fibrinolytic therapy for ischemic stroke who has a change in Glasgow Coma Score from 10 to 13"}], "correct": "a", "rationale": "B. over the last shift @B AT% B. Total parenteral nutrition provides nutrition for clients with dysfunction of the GI tract. Components of total parenteral nutrition include | ° glucose, salts, amino acids, lipids, and supplemental vitamins and minerals. Glucose or liver function abnormalities occur in over 90% of c | 34% clients who are receiving TPN. These abnormalities include hypoglycemia and hyperglycemia. Polyuria occurs with hyperglycemia, which D Hi 17% also causes polydipsia, blurred vision, and headaches. Hyperglycemia can lead to excessive diuresis and electrolyte abnormalities. It can be avoided by monitoring plasma glucose often, adjusting the insulin dose in the TPN solution, and giving subcutaneous insulin on a sliding scale. This client is a priority since hyperglycemia can lead to a hyperosmolar hyperglycemic emergency, coma, and even death.", "whyNot": {"a": "Averbal request for food for this client is not an immediate priority. Clients with subdural hemorrhage should be assessed for signs of", "c": "Antiplatelet therapy is prescribed for individuals who experience transient ischemic attacks, which manifest as a period of stroke-like", "d": "Fibrinolytic therapy is administered in acute ischemic stroke to dissolve the culprit clot and restore perfusion to the brain. An increase in"}, "keyConcept": "Maslow's Hierarchy of Needs can be used to help prioritize client care. When prioritizing care, physiologic needs are the first level priority. Actual physiological needs take priority over potential needs."}, {"id": 11657, "cat": "safe and effective care environment", "stem": "After receiving a report from the day nurse, which client should the oncoming night-shift nurse assess first?", "choices": [{"id": "a", "t": "A client who is 2 days postop open cholecystectomy who reports a fever, shortness of breath, and a productive cough"}, {"id": "b", "t": "A client who is 1 day post prostatectomy with an indwelling catheter, a fever, and cloudy urine."}, {"id": "c", "t": "A client who is 2 days post open reduction and internal fixation of a femur fracture with new onset of shortness of breath and chest pain"}, {"id": "d", "t": "A client who has gallstone pancreatitis and requests pain medication for severe epigastric pain"}], "correct": "a", "rationale": "Cc. breath and chest pain : C. A client who is 2 days post open reduction and internal fixation of a femur fracture with new onset of shortness of 91% p| 2% Orthopedic surgery clients are at risk for formation of deep vein thrombosis and subsequent pulmonary embolism (PE). This client should be assessed first, as PE is a life-threatening condition and an urgent priority. When assessing prioritization of client needs, decision-making tools that can be used effectively include airway, breathing, and circulation; degree of threat to survival; threat of complications; and Maslow’s hierarchy of needs.", "whyNot": {"a": "clients will often fail to breathe deeply and may develop atelectasis and subsequent pneumonia after abdominal surgery. This client", "b": "clients with an indwelling catheter are at increased risk for urinary tract infections. Although this client should be assessed and treated", "d": "Pancreatitis is painful, so it is important to address this client's ongoing pain needs, but this is not the urgent priority for assessment."}, "keyConcept": "Conditions that present an immediate risk to the client's safety or survival should take priority. Pulmonary embolism is a clot that breaks from a venous thrombosis in the pelvic veins or deep veins of the lower extremities and travels to the pulmonary circulation. It can cause hemodynamic collapse."}, {"id": 11658, "cat": "safe and effective care environment", "stem": "A nurse is planning care for a group of clients. Which of the following tasks should the nurse assign to an assistive personnel (AP)?", "choices": [{"id": "a", "t": "Applying antibiotic ointment to the arm of a client who has dermatitis"}, {"id": "b", "t": "Obtaining medical history information from a stable client who is being admitted"}, {"id": "c", "t": "Monitoring vital signs of a client who had an appendectomy 12 hr ago"}, {"id": "d", "t": "Removing the NG tube of a client who has been receiving enteral feedings"}], "correct": "c", "rationale": "A i 22% Moderate When planning delegation, the nurse should ensure the task can be legally delegated to the AP. This involves knowledge of the state's Nurse B | 3\" Practice Act and the facility's policies and procedures. Delegating the monitoring of vital signs of a stable client 12 hr after surgery is within the range of function of an AP. ec P| 12% my | 3%", "whyNot": {"a": "A task that requires medication administration, such as application of antibiotic ointment to an infected area, requires clinical judgment", "b": "A task that requires assessment, such as obtaining information about a client's medical history, involves the nursing process, which", "d": "A task that requires assessment and specialized skills or training, such as removing an NG tube, is outside the range of function of an AP."}, "keyConcept": "The nurse should take the time to identify client needs and plan the tasks to be delegated to health care team members. The nurse should fully understand the range of function and the skill level of the AP at the start of each shift. Periodic reassessments of delegated tasks should also be completed to provide supervision to the AP and identify cases of overdelegation."}, {"id": 11659, "cat": "safe and effective care environment", "stem": "The nurse is providing client teaching for a client newly diagnosed with diabetes. Which statement by the client indicates teaching has been effective?", "choices": [{"id": "a", "t": "will need to avoid flu vaccines in the future."}, {"id": "b", "t": "will have an inactivated flu vaccine each year."}], "correct": "b", "rationale": "The nurse should be capable of providing education about the flu shot. They need to understand and be able to convey correct information about flu vaccines the diabetic client.", "whyNot": {"a": "The diabetic client needs to have a flu shot each year."}, "keyConcept": "The nurse should be capable of providing education about the flu shot. They need to understand and be able to convey correct information about flu vaccines the diabetic client."}, {"id": 11660, "cat": "safe and effective care environment", "stem": "Before using a floor-based full-body sling for manual client lifting (a Hoyer lift), the nurse should instruct the client on the operation of the lift. What is the best position for the client while in the lift?", "choices": [{"id": "a", "t": "Keeping their hands away from the overhead strap"}, {"id": "b", "t": "Keeping their arms under their hips"}, {"id": "c", "t": "Separating their legs in an upright position"}, {"id": "d", "t": "Shifting the shoulders backward"}], "correct": "a", "rationale": "Pulling on the straps could cause the strap to detach from the lift or the patient to lose their balance in the lift. B I a", "whyNot": {"b": "The client’s arms should be folded over their chest or in their lap. If they keep their hands under the hips, they may experience pitching or", "c": "The client’s legs should be relaxed and crossed at the ankles if possible.", "d": "The client’s shoulders should be relaxed and positioned slightly forward in the sling."}, "keyConcept": "Ifa client holds or supports their weight on a lift sling, straps or hooks may detach from the lift. The straps should hang freely."}, {"id": 11661, "cat": "safe and effective care environment", "stem": "A client is exposed to radiation following a bombing. Which action should the nurse perform immediately?", "choices": [{"id": "a", "t": "Rinse the client with water"}, {"id": "b", "t": "Wrap the client in a blanket"}, {"id": "c", "t": "Remove the client’s clothing"}, {"id": "d", "t": "Blow off the client with an air hose"}], "correct": "c", "rationale": "The nurse should first remove the clothing from the client. To control the radiation, the clothing should then be placed in a plastic bag. The client should shower or be rinsed after the removal of clothing. Then, the nurse should wrap the client in a blanket.", "whyNot": {"a": "Clothing should be removed prior to rinsing.", "b": "This action would worsen the effects of radiation exposure.", "d": "This would put the nurse and others in the area at risk for exposure to radiation."}, "keyConcept": "Radiation particles can burn the skin and should be removed as quickly as possible."}, {"id": 11662, "cat": "safe and effective care environment", "stem": "appropriate method of transfer from a bed to a chair?", "choices": [{"id": "a", "t": "2-person assist with a body sling"}, {"id": "b", "t": "1-person standby assistance"}, {"id": "c", "t": "1-person assist stand-and-pivot transfer with gait belt"}, {"id": "d", "t": "Motorized assist device"}], "correct": "b", "rationale": ", a nurse should determine if the client is cooperative and Cc | 57% able to bear weight. The client’s strength should be used when possible to assist in transfer. If the client is cooperative and can understand , the client does not require an assisted transfer, but a caregiver should be standing by during the initial transfer to provide fii) assistance and ensure safety. 2 & 3 =) a =", "whyNot": {"c": "A 1-person assist stand-and-pivot transfer with a motorized assist device or gait belt is appropriate for a cooperative client with partial", "d": "A motorized assist device is appropriate for a cooperative client who is non-weight-bearing."}, "keyConcept": "Ifa client is able to bear weight, the client's strength should be used in transfer, when possible. A caregiver should be standing by to provide assistance and ensure safety during an initial transfer."}, {"id": 11663, "cat": "safe and effective care environment", "stem": "initial priority action by the nurse?", "choices": [{"id": "a", "t": "Alert the nursing supervisor and fill out an incident report."}, {"id": "b", "t": "Assess the client after stopping the infusion."}, {"id": "c", "t": "Notify the healthcare provider to obtain further orders for the client."}, {"id": "d", "t": "Turn down the infusion pump to the correct rate and assess the client’s vital signs."}], "correct": "b", "rationale": "’s priority is client safety. When a medication error is discovered, the nurse should assess the client and intervene as necessary to OB sid ers prevent injury. In this case, the insulin infusion should be discontinued immediately before the nurse assesses the client to determine if further intervention is necessary for stabilization . “U” is an unacceptable abbreviation in medical documentation, since it can easily be c | 2% mistaken for a zero. D i 10%", "whyNot": {"a": "After the client is stabilized, the nurse should report the error to the nursing supervisor or nurse manager, following institutional policy. An", "c": "The healthcare provider should be informed before administering the correct dosage, but client safety and prevention of injury through", "d": "The infusion should be stopped, and the client should be stabilized. Before restarting the infusion at the correct rate, the healthcare"}, "keyConcept": "When medication error is discovered, the first priority is client safety. A nurse who discovers the medication error should discontinue any erroneous medication, then assess the client and intervene to prevent further injury before reporting the error to the nursing supervisor and healthcare provider and before filing an incident report."}, {"id": 11664, "cat": "safe and effective care environment", "stem": "A nurse is giving routine daily medications to a client in the hospital. The client is oriented but does not have an armband. What action should the nurse take?", "choices": [{"id": "a", "t": "Give the medication after the client states her name."}, {"id": "b", "t": "Leave the medication with the client and go get an armband."}, {"id": "c", "t": "Obtain an armband for the client and return with the medication."}, {"id": "d", "t": "Ask the client if this is her usual medication."}], "correct": "c", "rationale": "The nurse should get an armband and give the patient her medication. Some facilities require scanning the armband as part of the medication administration procedure.", "whyNot": {"a": "The medication should not be given until the client has an armband.", "b": "Medication should not be left unattended, even with the client.", "d": "The client should not receive medications without identification."}, "keyConcept": "The nurse should review proper identification prior to giving medications in the hospital. Each client must have a name band for proper identification."}, {"id": 11665, "cat": "safe and effective care environment", "stem": "A nurse is caring for a 33-year-old client who is suspected to have human immunodeficiency viral (HIV) infection. Which of the following precautions should the nurse institute when caring for this client?", "choices": [{"id": "a", "t": "Standard precautions"}, {"id": "b", "t": "Contact precautions"}, {"id": "c", "t": "Airborne precautions"}, {"id": "d", "t": "Medical handwashing"}], "correct": "a", "rationale": "Human immunodeficiency virus (HIV) infection is a bloodborne pathogen spread through blood and body fluids. The virus attacks the T-cells of the body’s immune system and impairs immunity. This leads to opportunistic infections. Standard precautions are indicated for all clients, including those infected with HIV.", "whyNot": {"b": "HIV is not spread through casual contact. Standard precautions are adequate.", "c": "HIVis transmitted through the exchange of blood and body fluids, so airborne precautions are not indicated.", "d": "HIV infection can be transmitted through sexual contact or accidental puncture. Medical handwashing is an important nursing practice"}, "keyConcept": "Health-care workers should consider ALL clients to be potentially infected with HIV or other blood-borne pathogens. The risk of exposure to infectious blood and body fluids is minimized through use of standard precautions, including handwashing, barrier precautions, and safe use/disposal of sharps."}, {"id": 11666, "cat": "safe and effective care environment", "stem": "Which of the following measures should be used to prevent the transmission of respiratory infections?", "choices": [{"id": "a", "t": "Individuals should not be admitted as visitors or staff without proof of immunization for seasonal influenza and pneumonia."}, {"id": "b", "t": "Individuals with signs of respiratory infection should wear a surgical mask."}, {"id": "c", "t": "Adistance of separation of at least 10 feet should be maintained from an individual with signs of respiratory infection."}, {"id": "d", "t": "Infected individuals should be encouraged to sneeze or cough into their hand."}], "correct": "b", "rationale": "al 3% Easy Respiratory hygiene/cough etiquette is intended to prevent transmission of respiratory infections and is directed at visitors and clients who OB rT SY amas have signs of a respiratory illness, including a cough, congestion, or rhinorrhea. The recommended elements of respiratory hygiene and cough etiquette include education, posted signs, hand hygiene, and use of a tissue or surgical mask to cover the nose and mouth, with c | 6% prompt disposal of any tissue used.", "whyNot": {"a": "This is not a recommended as a standard measure for respiratory hygiene, although it is important to ensure clients receive adequate", "c": "The recommended distance from an individual who appears to have a respiratory illness is 3 feet at the minimum.", "d": "The shirt sleeve should be used for sneezing or coughing when a tissue or surgical mask is not available. Hand hygiene should be"}, "keyConcept": "Respiratory precautions have been added as an element of Standard Precautions, to prevent the spread of respiratory pathogens. In addition to providing signs and education, measures include covering the mouth/nose with a tissue when coughing and prompt disposal of used tissues; using surgical masks on the coughing person when tolerated and appropriate; hand hygiene after contact with respiratory secretions; and separation of persons with respiratory infections in common waiting areas by at least three feet, when possible."}, {"id": 11667, "cat": "safe and effective care environment", "stem": "A nurse on an orthopedic unit is caring for several clients who are stable. The nurse leaves the shift 1 hr early without notifying the charge nurse. The nurse is liable for which of the following torts?", "choices": [{"id": "a", "t": "Negligence O B.Libel"}, {"id": "c", "t": "Battery"}, {"id": "d", "t": "Assault"}], "correct": "a", "rationale": "Client abandonment displays negligence, which is providing client care below the standard of care and placing clients at risk for harm. B | 3\" c | 2%", "whyNot": {"c": "A nurse who engages in battery intentionally touches a client without permission with the intention of causing physical injury or", "d": "Assault is a threat of offensive or harmful physical contact."}, "keyConcept": "Torts are wrongful acts of a civil nature that have caused or have the potential to cause harm. Other torts that apply to nursing, besides negligence, are as follows: Tort Definition False imprisonment __| Restraint of a person without lawful justification Invasion of privacy Unwanted intrusion into a client's personal or private circumstances Slander Untrue spoken words about another person"}, {"id": 11668, "cat": "safe and effective care environment", "stem": "Which of the following pieces of equipment is essential for facility communication in a disaster situation?", "choices": [{"id": "a", "t": "Cell phone"}, {"id": "b", "t": "Intercom O c. walkie-talkie"}, {"id": "c", "t": "Disaster situations usually involve power and cell phone loss."}, {"id": "d", "t": "Speakerphone"}], "correct": "c", "rationale": "Disaster situations usually involve power and cell phone loss. Walkie-talkies can provide a means of communication.", "whyNot": {"a": "Cell phones may not work in a disaster situation.", "b": "Intercom systems do not work when the facility loses power.", "d": "Phone systems may not work when the facility loses power."}, "keyConcept": "Simple devices may allow essential communication during a loss of power and cell service in a facility."}, {"id": 11669, "cat": "safe and effective care environment", "stem": "A nurse notes that a graduate nurse has initiated a ceftriaxone infusion instead of clindamycin for a client with a penicillin allergy. Which of the following is the nurse’s priority for initial action?", "choices": [{"id": "a", "t": "Inform the nurse manager that the nurse has administered the wrong medication."}, {"id": "b", "t": "File an incident report and give the correct medication."}, {"id": "c", "t": "Discontinue the infusion and assess the client."}, {"id": "d", "t": "Call the healthcare provider to report the error."}], "correct": "c", "rationale": "A Client safety should always be the priority. The nurse should stop the erroneous medication infusion and assess the client before calling the B ' healthcare provider. The nursing supervisor should then be notified, and an incident report should be filed. o:", "whyNot": {"a": "Client safety is the priority. After assessing and stabilizing the client, the nurse should notify the nurse manager or nursing supervisor in", "b": "After assessing and stabilizing the client, the nurse should first contact the healthcare provider to determine if the correct medication", "d": "The initial priority is to stop the infusion, followed by assessment and stabilization of the client. After client safety is ensured, the nurse"}, "keyConcept": "When an incorrect medication has been administered, the nurse who discovered the medication error should write an incident report after assessing the client and intervening to prevent injury. If an injury has occurred, the nurse should follow agency policy. The incident report should only include observed facts and the nurse should not make assumptions that negligence was the cause of the error."}, {"id": 11670, "cat": "safe and effective care environment", "stem": "which of the following people? O A. The client's partner O B. Clergy at the facility O C. The facility's administrators O D. Nursing staff who are caring for the client", "choices": [{"id": "a", "t": "The client's partner"}, {"id": "b", "t": "Clergy at the facility"}, {"id": "c", "t": "The facility's administrators"}, {"id": "d", "t": "Nursing staff who are caring for the client"}], "correct": "d", "rationale": "To coordinate safe and effective care delivery, the nurse may share details of a client's health status and treatment plan with others who are responsible for delivering care to that client.", "whyNot": {"a": "The client, not the nursing staff, decides whether a client's partner may have access to the client's protected health information.", "b": "The nurse must have the client's permission to share protected health information with any spiritual adviser.", "c": "Although healthcare facility administrators have access to information about the census, provider status, staffing, and other issues, they"}, "keyConcept": "To adhere to HIPAA standards for client privacy and confidentiality, nurses may not disclose information to unauthorized individuals, including clients' family members, friends, and acquaintances, as well as staff from other units. Nurses who disclose protected health information to an unauthorized person can be liable for invasion of privacy, a breach of confidentiality, and even defamation of character or slander."}, {"id": 11671, "cat": "safe and effective care environment", "stem": "the following is the next appropriate action?", "choices": [{"id": "a", "t": "Obtain a court order for the surgical procedure."}, {"id": "b", "t": "Ask the police to identify and contact the client's family members."}, {"id": "c", "t": "Transport the client to surgery under implied consent."}, {"id": "d", "t": "Search a national database to determine the client’s identity using fingerprints."}], "correct": "c", "rationale": "When emergent treatment is required for any client who is unable consent in order to protect life or limb, the principle of implied consent allows life- or limb-saving treatment under the assumption that the client would want that treatment. The healthcare provider should intervene with life-saving treatment when consent is impractical to obtain in a timely manner.", "whyNot": {"a": "Seeking a court order would cause unnecessary delay and place the client’s life at further risk.", "b": "Although the help of the police should be enlisted to identify family members or guardians, this cannot delay emergency treatment.", "d": "It is unlikely that any national database would contain the fingerprints of an adolescent. Even if the child was registered with a"}, "keyConcept": "When a client is at risk of losing life or limb without a treatment or procedure, formal consent is not required. When the client is a minor and parents or guardians cannot be located for consent, implied consent allows healthcare providers to administer treatments or procedures necessary to prevent substantial client harm or death."}, {"id": 11672, "cat": "safe and effective care environment", "stem": "The nurse working in the intensive care unit should immediately report which of the following to security as the most unsafe equipment in an occupied room? O A.A lamp without a bulb O B. A hospital bed plug with the third prong missing O C. A blinking overhead fluorescent light fixture O D. An uncovered electric outlet", "choices": [{"id": "a", "t": "5%"}, {"id": "b", "t": "3-prong plug missing a prong is not safe and should be reported."}, {"id": "c", "t": "Fluorescent bulbs may blink in response to cold temperature or a bulb going bad but pose no safety problem."}, {"id": "d", "t": "An uncovered outlet needs a plug cover, but this is not the most unsafe issue. An ICU patient is usually not well enough to be utilizing the"}], "correct": "b", "rationale": "3-prong plug missing a prong is not safe and should be reported. The damaged plug could cause a fire or electrocution, and the bed is OB rs oan currently in use. ci 10%", "whyNot": {"a": "The lamp needs a bulb but it not unsafe if not plugged in.", "c": "Fluorescent bulbs may blink in response to cold temperature or a bulb going bad but pose no safety problem.", "d": "An uncovered outlet needs a plug cover, but this is not the most unsafe issue. An ICU patient is usually not well enough to be utilizing the"}, "keyConcept": "Three-pronged plugs carry 120 volts of electricity and have a prong that provides grounding for the electricity. This prevents the current from traveling and causing injury from electrocution. When damaged, it poses a safety issue."}, {"id": 11673, "cat": "safe and effective care environment", "stem": "immediately? O A. Notify the client’s primary care provider. O B. Measure the blood pressure using a manual cuff. O C. Give the client a prescribed dose of prn clonidine. O D. Direct the UAP to ask the client if any symptoms are occurring such as chest pain or headache and recheck the blood pressure.", "choices": [{"id": "a", "t": "Notify the client’s primary care provider."}, {"id": "b", "t": "Measure the blood pressure using a manual cuff."}, {"id": "c", "t": "Give the client a prescribed dose of prn clonidine."}, {"id": "d", "t": "Direct the UAP to ask the client if any symptoms are occurring such as chest pain or headache and recheck the blood pressure."}], "correct": "b", "rationale": "al 4% Easy The RN should make a primary assessment of the client and should recheck the blood pressure using a manual cuff before taking further OB ris SO action. If the client’s blood pressure reading is not as high using the manual cuff, the RN should ask the UAP to use a different automated ° machine when taking subsequent measurements. © I S20 pi 3%", "whyNot": {"a": "The nurse should first make an assessment of the client and should verify the reading using a manual cuff. If the reading is accurate, the", "c": "It is important for the RN to verify the reading and assess the client before taking any further action.", "d": "In the case of a change in the client’s condition, a severely high blood pressure reading is associated with a risk of significant risk of harm"}, "keyConcept": "If assistive personnel report an abnormal blood pressure reading, the RN should make a primary assessment of the client and should recheck the blood pressure using a manual cuff before taking any action. If there is a discrepancy between an automatic machine anda manual cuff, the automatic machine should be recalibrated and checked again before putting it back in use."}, {"id": 11674, "cat": "safe and effective care environment", "stem": "standards of care for nursing practice?", "choices": [{"id": "a", "t": "They are established by the United States Department of Health and Human Services."}, {"id": "b", "t": "They are established by the Joint Commission."}, {"id": "c", "t": "They can be found in the nurse practice act of each state."}, {"id": "d", "t": "They are the same for nurses in every healthcare facility across the country."}], "correct": "c", "rationale": "A l 3% Moderate The practice of nursing is based on legal guidelines and established standards of care and are found in the nurse practice act of each state. B r | Bn Enforcement of legal practice guidelines is under the jurisdiction of the state board of nursing or another government agency. A nurse is responsible for being informed about the legal parameters of practice in his or her state. Standards of nursing practice developed by ec | 68% professional groups like the American Nurses Association are published in journals that are widely available. At the institutional level, each D | | 8% organization develops a set of policies and procedures that must be observed by employees in that practice setting. When a nurse has a a concern to express about a violation of the standard of practice, the formal chain of command should be followed, beginning with the 2 nursing supervisor. = a", "whyNot": {"a": "The standard of nursing practice varies by state and is determined by an agency appointed by the state to oversee nursing licensure and ‘", "b": "The Joint Commission is an organization that accredits healthcare facilities.", "d": "Each healthcare institution formalizes policies and procedures for nursing standards of practice within the guidelines established by the"}, "keyConcept": "The Nurse Practice Act of each state establishes legal guidelines and standards of care. Widely published standards of nursing practice are published in nursing journals and other practice policies and procedures are developed within healthcare organizations. The nurse has a responsibility to be aware of all practice guidelines mandated professionally in the nurse's area of care and at the state and institutional level."}, {"id": 11675, "cat": "safe and effective care environment", "stem": "The public health nurse is responsible for gathering and reporting the incidence of infectious diseases. Which of the following diseases must be reported immediately?", "choices": [{"id": "a", "t": "Scabies"}, {"id": "b", "t": "Lyme disease"}, {"id": "c", "t": "Influenza"}, {"id": "d", "t": "Tuberculosis"}], "correct": "d", "rationale": "al 3% Easy One of the major responsibilities of a public health nurse (PHN) is to conduct epidemiological reports of the diseases in the community. B | Ase Typically, PHNs submit these reports according to the schedule set by the local or national health centers. However, highly contagious diseases such as tuberculosis must be reported at once in order to contain the infection and prevent it from spreading. c | 3% Tuberculosis is an infectious lung disease caused by the bacteria Mycobacterium tuberculosis. It is considered an airborne disease and airborne isolation is indicated. It can be passed to another person by inhaling the infectious agents in the air dispersed through coughing, sneezing, or spitting. It is associated with high mortality in the community, and multidrug-resistant strains exist. The centers and health departments have to take necessary actions by ensuring management of the client’s condition and conducting preventive measures.", "whyNot": {"a": "Scabies is not a reportable disease. It is transmitted through sexual contact and through contact with infested clothing and linens.", "b": "Lyme disease is transmitted through ticks and is reportable to the CDC, but immediate local reporting is not required.", "c": "Invasive haemophilus influenza is reportable to the CDC."}, "keyConcept": "The National Notifiable Diseases Surveillance System (NNDSS) is a nationwide collaborative system that enables all levels of public health to share health information about notifiable diseases. The reported information is used to monitor, control, and prevent the spread of notifiable infectious and noninfectious diseases and outbreaks."}, {"id": 11676, "cat": "safe and effective care environment", "stem": "decides not to complete an incident report. Which of the following ethical principles is the nurse violating?", "choices": [{"id": "a", "t": "Autonomy"}, {"id": "b", "t": "Advocacy"}, {"id": "c", "t": "Veracity"}, {"id": "d", "t": "Confidentiality"}], "correct": "c", "rationale": "All Veracity is the duty, to tell the truth. The nurse violated the ethical principle of veracity when choosing not to report the error instead of B r] being truthful. It is the nurse's responsibility to report medication errors immediately upon discovery and to complete an incident report. The nurse also failed to tell the truth to the client. The client has the right to refuse additional dosing if that is what the provider suggests O€ | after learning of the medication error. D |", "whyNot": {"a": "Autonomy is an ethical principle indicating respect for a client's right to make their own health decisions. However, the ethical principle of", "b": "Advocacy is an ethical principle in which the nurse protects and defends the health, safety, and rights of the client. However, the ethical", "d": "Confidentiality means disclosing information about a client only to those who are caring for the client or those individuals designated by"}, "keyConcept": "The ethical practice involves acting in a professional manner that adheres to the standards in the American Nurses' Association's Code of Ethics for Nurses with Interpretive Statements. Nurses must accept accountability for their actions, including following the facility's protocol for addressing and reporting medication errors."}, {"id": 11677, "cat": "safe and effective care environment", "stem": "When delegating assignments for the shift, which of the following does the registered nurse realize is the most appropriate assignment for an unlicensed assistive personnel (UAP)?", "choices": [{"id": "a", "t": "A client receiving continuous feeding through a PEG tube"}, {"id": "b", "t": "A client who needs feeding and has difficulty swallowing both liquids and solids"}, {"id": "c", "t": "A client who requires irrigation of a colostomy"}, {"id": "d", "t": "A client who requires a urine specimen collection"}], "correct": "d", "rationale": "When a nurse is assigning tasks, the needs of the client should be matched with the skills of the staff member. In this case, the nurse Cc l assistant should be assigned to the client who requires urine specimen collection, as this is within the scope of nursing assistant practice. e@D | Nursing assistants are unlicensed personnel and should generally be assigned noninvasive interventions, including hygiene and ambulation.", "whyNot": {"a": "PEG tube feedings must be performed by licensed personnel.", "b": "Since this client is at risk of aspiration, this is a physiological needs that is outside of the scope of practice of unlicensed personnel.", "c": "Irrigation of a colostomy can only be performed by licensed personnel in accordance with their job description."}, "keyConcept": "The nurse can transfer authority and responsibility for performance of a task to a competent individual, but remains responsible for the outcome. Although the scope of practice of UAP is not uniformly defined across states and healthcare facilities. the nurse practice act of each state specifies the activities that must be performed only by a nurse and those which may be delegated to others. The UAP may not delegate tasks to other personnel."}, {"id": 11678, "cat": "safe and effective care environment", "stem": "A nurse is caring for a client who is 1-day postoperative an abdominal surgery. Which of the following tasks should the nurse complete, rather than delegating to an unlicensed assistive personnel (UAP)?", "choices": [{"id": "a", "t": "Measuring the client's vital signs"}, {"id": "b", "t": "Removing the dressing over the client's incision"}, {"id": "c", "t": "Transferring the client from the bed to a chair"}, {"id": "d", "t": "Assisting the client with ambulation"}], "correct": "b", "rationale": "The nurse may not delegate assessment, diagnosis, planning, or evaluation because these are steps of the nursing process that require nursing judgment. When removing an abdominal dressing just 1 day after surgery, the nurse should assess the surgical wound and determine if the client requires any further intervention. This could include notifying the provider and using surgical asepsis to apply anew dressing. For simple, routine dressing changes later, if necessary, the nurse may delegate this task to the UAP.", "whyNot": {"a": "The nurse may delegate measuring the client's vital signs to the UAP because this task does not require nursing assessment, teaching, or", "c": "The nurse may delegate transfers to the UAP because this task does not require nursing assessment, teaching, or special skills that are", "d": "The nurse may delegate ambulation of the client to the UAP because this task does not require nursing assessment, teaching, or special"}, "keyConcept": "Delegation is the act of assigning tasks to other members of the healthcare team who are competent to perform those tasks and whose scope of practice or range of function includes those tasks. The nurse who delegates the task has accountability for the outcome. When delegating tasks to assistive personnel, the nurse must follow the five rights of delegation carefully: the right task, under the right circumstances, to the right person, with the right direction and communication, and the right supervision and evaluation. DELEGATION TO ASSISTIVE PERSONNEL Tasks to delegate ‘Measuring and documenting intake and output Performing uncomplicated dressing changes Measuring and documenting vital signs Performing CPR Ambulating and transferring clients Instilling formula via established gastrostomies Suctioning chronic tracheostomies Weighing clients Feeding clients Bathing clients Performing postmortem care Caring for invasive lines Assessing or evaluating Teaching Planning nursing care Tasks NOT to delegate eee eleeene"}, {"id": 11679, "cat": "safe and effective care environment", "stem": "Which of the following problems should a nurse prioritize when planning care for a client with acute viral gastroenteritis?", "choices": [{"id": "a", "t": "Self-care deficit"}, {"id": "b", "t": "Impaired body image"}, {"id": "c", "t": "Fluid and electrolyte imbalance"}, {"id": "d", "t": "Altered nutrition"}], "correct": "c", "rationale": ", which can occur with diarrhea, hemorrhage, drainage of , dehydration from inadequate intake, and fluid shifts from the plasma to the interstitial space. Signs associated with abnormal loss of volume include tachycardia, hypotension, cool and clammy skin, concentrated urine, and thready pulse. Weight loss can also occur and ec | 81% can result in abnormal electrolyte levels when there is an uneven loss of water compared to electrolyte loss. Hyponatremia, or low serum , may occur with vomiting and diarrhea. Potassium loss can also occur with diarrhea and vomiting. Hypokalemia refers to low potassium levels in the body. Potassium is critical for the conduction of cardiac impulses and muscle contraction. Weakness, fatigue, cardiac arrhythmias, and paresthesias may occur with hypokalemia. The ECG will demonstrate a flattened T wave and ST-segment depression. Fluid volume deficit can also cause elevated potassium, which leads to peaked T waves and widening of the QRS complex on an ECG. This can eventually culminate in cardiac arrest if untreated.", "whyNot": {"a": "Psychosocial problems are less of a priority than physiological problems.", "b": "Impaired body image may occur, but this is a psychosocial problem and has lower priority than a physiological problem.", "d": "Acute gastroenteritis will probably resolve before the effects of altered nutritional intake occur. This is not an immediate priority. Acute"}, "keyConcept": "Physiological needs should be prioritized over psychosocial needs. The priority physiological needs are airway, breathing, circulation, and neurologic disability. Immediate needs are prioritized over future needs. Actual or imminent client injury or harm is prioritized over potential risks that may occur later."}, {"id": 11680, "cat": "safe and effective care environment", "stem": "Nurses are working with the victims of disaster after a bombing at a school lunchroom. Which persons have the greatest risk for factors of post-traumatic stress disorder?", "choices": [{"id": "a", "t": "First responders arriving just after the bombing"}, {"id": "b", "t": "Cafeteria workers at the site closest to the bomb"}, {"id": "c", "t": "Children who were being dropped off for school at the entrance"}, {"id": "d", "t": "Disaster-trained health care school nurses"}], "correct": "b", "rationale": "all 8% Easy The closer the individual is to the actual site and the longer they are exposed to it, the greater the psychological distress the individual will OB TY 79% experience, possibly leading to post-traumatic stress disorder. ° ci 12%", "whyNot": {"a": "First responders undergo training for disaster situations. While trained professionals do experience post-traumatic stress, this is not the", "c": "Children with their parents in the car did not witness the bombing occurring in the lunchroom. They may find reassurance by being with", "d": "Disaster-trained school nurses are not the most likely to experience post-traumatic stress."}, "keyConcept": "Nurses should assess clients for psychiatric trauma and physical trauma following a disaster. Post-traumatic stress disorder symptoms include emotional numbness, sleep disturbances, depression, anxiety, irritability, and emotional outbursts of anger or feelings of intense guilt. PTSD is typically diagnosed by a mental health professional when symptoms last for more than a month."}, {"id": 11681, "cat": "safe and effective care environment", "stem": "Aregistered nurse is delegating care to two nursing assistants and a licensed practical nurse. Which of the following tasks should the nurse assign to the LPN?", "choices": [{"id": "a", "t": "24-hour urine collection"}, {"id": "b", "t": "Twice-daily irrigation of an infected wound with dressing changes"}, {"id": "c", "t": "Assisting a post-surgical client with ambulation"}, {"id": "d", "t": "Bed-bathing"}], "correct": "b", "rationale": "All 11% Easy A nurse is responsible for selecting an appropriately skilled staff caregiver and for evaluation of delegated tasks. Unlicensed personnel can OB rsd ears perform non-invasive tasks, such as hygiene and assisting with ambulation. Collection of urine specimens is also within the scope of acceptable tasks. A licensed practical nurse can perform all of the tasks performed by unlicensed personnel in addition to certain invasive c | 5% tasks, such as urinary catheterization, dressing changes, and medication administration, depending on the job description.", "whyNot": {"a": "This task can be assigned to non-licensed personnel and will allow assignment of the LPN to a higher level of care.", "c": "Assisting with ambulation can be performed by a nursing assistant.", "d": "Hygiene and grooming can be assigned to unlicensed personnel."}, "keyConcept": "Licensed practical nurses practice under supervision of an RN and provide basic care to clients. The RN retains responsibility for assessment of the client's condition, planning care, and evaluation of the outcome of care measures. When delegating or assigning care to team members, assignment of client care tasks to UAP that do not require the knowledge or skills of licensed personnel allows the LPN or RN to attend to higher level client care tasks."}, {"id": 11682, "cat": "safe and effective care environment", "stem": "A nurse who is transcribing a client's medication prescriptions finds that one handwritten prescription is partially illegible. Which of the following actions should the nurse take?", "choices": [{"id": "a", "t": "Clarify the prescription with the client's family."}, {"id": "b", "t": "Check the client's medication reconciliation document."}, {"id": "c", "t": "Ask the pharmacist to verify the prescription."}, {"id": "d", "t": "Contact the provider to clarify the prescription."}], "correct": "d", "rationale": "| 2% Easy The nurse should contact the provider for clarification of the prescription and document the verbal transaction and prescription. The nurse B I a should repeat the prescription back to the provider without any abbreviations to make sure there are no miscommunications and to confirm accuracy. Then, the provider must acknowledge verbally that the nurse's read-back is complete and correct. c | 4%", "whyNot": {"a": "The nurse should not clarify the medication prescription with the client's family because this action could be a breach of confidentiality.", "b": "When a client enters a facility, the nurse performs medication reconciliation, which involves compiling a list of the medications the clients", "c": "The nurse should not ask the pharmacist for clarification of the prescription because incorrect medication administration might result if"}, "keyConcept": "Whenever nurses receive a prescription that is in any way unusual, such as when it is difficult to read, the dosage seems outside the usual safe range, the medication seems inappropriate for the client, the medication interacts unfavorably with medications the client is already receiving, or there is any ambiguity in one or more elements of the prescription, the nurse must clarify it with the prescriber. Nurses are accountable for every medication they administer, even when the error was on the part of the prescriber."}, {"id": 11683, "cat": "safe and effective care environment", "stem": "An RN is working with a UAP and an LPN. Which of the following tasks should not be delegated by the RN?", "choices": [{"id": "a", "t": "Bed baths and routine hygiene"}, {"id": "b", "t": "Transporting the client to nuclear medicine"}, {"id": "c", "t": "Administration of routine oral medications"}, {"id": "d", "t": "Evaluating a change in the client’s heart rate"}], "correct": "d", "rationale": "all 7% Easy A nurse cannot delegate any part of the nursing process, which includes evaluation, assessment, and education. Nursing judgment and B I a knowledge are necessary to evaluate the client. Although it is appropriate to assign others to monitor routine vital signs, only the RN can evaluate any changes. c i ™%", "whyNot": {"a": "UAPs can provider routine hygiene for a stable client.", "b": "This is a task that can be carried out by the UAP.", "c": "An LPN can administer routine oral medication."}, "keyConcept": "Delegation and assignment refer to the transfer of the nurse's responsibility for performance of a task to another staff member while retaining accountability for the outcome. The staff member who accepts the delegation or assignment has the responsibility for appropriate completion of the task. Registered nurses have authority to make assessments, plan nursing care, evaluate nursing care, and exercise nursing judgment, which includes delegation. Delegation and assignment are based on the nurse's judgment of the client's condition, the competence of personnel, and the degree of supervision required."}, {"id": 11684, "cat": "safe and effective care environment", "stem": "following torts? O A. Defamation of character O B. Assault O C. Battery O D. False imprisonment", "choices": [{"id": "a", "t": "Defamation of character"}, {"id": "b", "t": "Assault"}, {"id": "c", "t": "Battery"}, {"id": "d", "t": "False imprisonment"}], "correct": "d", "rationale": ". The client has the right to refuse treatment B | at against medical advice and leave the facility and cannot be legally restrained from doing so. ci 11%", "whyNot": {"a": "Defamation of character is an attack on a person's reputation either in writing, known as libel, or while speaking, known as slander. This", "b": "Assault is threatening to inflict injury on or otherwise harm another person. This situation does not constitute assault.", "c": "Battery is intentionally touching a person harmfully or without their consent. This situation does not constitute battery."}, "keyConcept": "When nurses deviate from the standards of client care, it is most often unintentional. When a nurse deliberately violates a client's rights, however, it is an intentional tort. In addition to defamation of character, assault, battery, and false imprisonment, intentional torts nurses must avoid include: + Invasion of privacy: Nurses must maintain confidentiality of the client's information. An invasion of privacy is the act of disclosing personal information, including health information, to anyone who is not participating in the client's care or whom the client has not authorized to receive this information. «Intentional infliction of emotional distress: Nurses follow a strict code of ethics which includes beneficence and nonmaleficence, or that of doing good and avoiding harm to others. Behavior that is unconventional and unprofessional according to nursing standards and causes a client undue emotional trauma or distress is an example of intentional infliction of emotional distress."}, {"id": 11685, "cat": "safe and effective care environment", "stem": "committed what legal tort? O A. Negligence O B. Battery O C. Slander © D.Libel", "choices": [{"id": "a", "t": "Negligence"}, {"id": "b", "t": "Battery"}, {"id": "c", "t": "Slander © D.Libel"}], "correct": "c", "rationale": ", which refers to causing damage to someone’s reputation by making a false statement. The remark B | a0 may be made deliberately or carelessly. oi 12%", "whyNot": {"a": "Negligence refers to omission or commission of acts by a professional that fall below the reasonable standard expected for the specific", "b": "Battery refers to touching another person without consent."}, "keyConcept": "Repeating harmful rumors that cause damage to the reputation of coworkers or clients can open the nurse to a legal claim of defamation. Slander refers to spoken defamation and libel refers to written defamation."}, {"id": 11686, "cat": "safe and effective care environment", "stem": "A nurse realizes that he made an error when documenting an item found in a client assessment. What is the appropriate way to correct the record?", "choices": [{"id": "a", "t": "Use white-out to delete the error and then complete with correct data"}, {"id": "b", "t": "Draw a line through the error, then initial and date before adding the correct information"}, {"id": "c", "t": "Add a late entry into the record"}, {"id": "d", "t": "Erase the error to make space for the correct entry"}], "correct": "b", "rationale": ". Any information entered into the medical record must be complete, accurate, and factual. Guidelines Cc I 4% for entry of information in the medical record are determined by state medical practice acts for nurses and physicians, state licensure laws, . Use of white-out or erasure of an error is unacceptable. The correct agency policy should be followed. The entry should be made in black ink and must be dated and timed. No blank spaces can be left unfilled. All entries must be signed with the nurse’s name and title. If an error is made in the documentation, the nurse should draw a line through the erroneous data and provide initials, date, and time.", "whyNot": {"a": "White-out is not used on the medical record.", "c": "Alate entry documents information that the nurse recalls at a point after completing documentation of a client encounter. Agency policies", "d": "Erasure is prohibited."}, "keyConcept": "The medical record must be accurate and complete. It is intended to be contemporaneous documentation of care. If an error is discovered, the record can be corrected by drawing a line through the entry. The person who corrects the entry must sign the record, with date and time. Erasures and white-out are not permitted."}, {"id": 11687, "cat": "safe and effective care environment", "stem": "appropriate nursing diagnosis for this client?", "choices": [{"id": "a", "t": "Ineffective airway clearance"}, {"id": "b", "t": "Impaired gas exchange"}, {"id": "c", "t": "Activity intolerance"}, {"id": "d", "t": "Risk for infection"}], "correct": "a", "rationale": "Ineffective airway clearance is the most appropriate for this client. They are producing this sputum and there is nothing the question to B I a indicate they are having a gas exchange issue. c| 2%", "whyNot": {"b": "There is no data in the question that indicates the client is having a gas exchange issue.", "c": "Activity intolerance is not the priority diagnosis.", "d": "The client likely has an infection, so this diagnosis is not the most appropriate."}, "keyConcept": "Care planning is a critical component of nursing. It is vital the nurse learn how to plan care, revise care as needed and to evaluate care to inure quality client outcomes."}, {"id": 11688, "cat": "safe and effective care environment", "stem": "Which of the following approaches should the nurse manager use in this situation?", "choices": [{"id": "a", "t": "Coercion of the reluctant nursing assistant"}, {"id": "b", "t": "Positive incentives for the nursing assistant"}, {"id": "c", "t": "Confrontation with the nursing assistant with active challenging to verbalize feelings about the change"}, {"id": "d", "t": "Ignoring the nursing assistant’s reluctance since the assistant will gain enthusiasm once the change benefits clients"}], "correct": "c", "rationale": "It is important to confront resistance directly in order to give personnel the opportunity to identify issues or problems, verbalize feelings, and work to find solutions. This option will provide a potential long-term solution that works for all involved. Factors that drive groups and individuals to change include belief that the change offers a solution to a problem; perception of challenge; economic gain; potential for personal achievement or improved relationships; and visualization of a future positive impact as a result of the change.", "whyNot": {"a": "Coercion is never appropriate.", "b": "Although positive incentives can work in the short-term, over the long-term this will leave concerns unaddressed.", "d": "It is never wise to ignore negative behaviors that can impact client care and personnel."}, "keyConcept": "Forces that may prevent individuals from accepting change include fear, misunderstanding, lack of time or energy; perception that the change will not lead to the desired goal; perception of loss of freedom; and low tolerance for change resulting from emotional or intellectual insecurity. Identification of the issue causing resistance may lead to solutions that benefit all parties."}, {"id": 11689, "cat": "safe and effective care environment", "stem": "medication error prevention? O A. Taking all medications out of the unit-dose wrappers before entering the client’s room O B. Checking with the provider when a single dose requires administration of multiple tablets O C. Administering a medication then looking up the usual dosage range O D. Relying on another nurse to clarify a medication prescription", "choices": [{"id": "a", "t": "Taking medications out of the unit-dose wrappers before entering the client’s room"}, {"id": "b", "t": "Checking with the provider when a single dose requires administration of multiple tablets"}, {"id": "c", "t": "Administering a medication then looking up the usual dosage range"}, {"id": "d", "t": "Relying on another nurse to clarify a medication prescription"}], "correct": "b", "rationale": "Ifa single dose requires multiple tablets, it is possible that an error has occurred in the prescription or transcription of the medication. The nurse should use critical thinking skills when administering a medication and should question any orders that are unclear or cause concern. The nurse is responsible for checking the medication order and the status and condition of the client, with consideration of contraindications, pertinent lab results, pertinent data (vital signs, client allergies), and potential drug interactions.The order must include the client's full name, date and time of the order, the medication name, ordered dosage, and the form, route, and time or frequency of administration. The order must be signed by the healthcare provider ordering the medication.", "whyNot": {"a": "To prevent errors, the nurse should not take unit-dose medications out of wrappers until at the bedside when performing the third check", "c": "Reviewing the usual dosage range prior to administration can help the nurse identify an inaccurate dosage.", "d": "If the prescription is unclear, the nurse should contact the provider, not another nurse, for clarification."}, "keyConcept": "The nurse uses knowledge, experience, and critical thinking skills when administering medications. Medication errors can result in client harm, increased length of stay, and increased costs. The nurse should review the usual dosage range for a medication before administration. Ifa single dose requires multiple tablets, a prescribing or transcription error may have occurred."}, {"id": 11690, "cat": "safe and effective care environment", "stem": "A client is hospitalized for the insertion of a low-dose radioactive implant. Which of the following nursing interventions should be used to promote safety for everyone?", "choices": [{"id": "a", "t": "Do not assign pregnant staff members to the client"}, {"id": "b", "t": "Limit visitors to 1 hour daily"}, {"id": "c", "t": "Keep visitors 3 feet from the client"}, {"id": "d", "t": "Allow the client’s grandchildren to visit for only 30 minutes per day"}], "correct": "a", "rationale": "A client undergoing brachytherapy with an implanted radioactive device requires certain radioactive precautions. The client should stay ina private room with appropriate notices posted about radiation safety precautions. Staff members caring for the client should wear dosimeter badges. Pregnant staff members should not be assigned to care for the client.", "whyNot": {"b": "Visitors should be limited to 30 minutes daily.", "c": "Visitors should be kept 6 feet away from the client.", "d": "Children should not be allowed to visit a client with a radioactive implant."}, "keyConcept": "Anewly implanted low-dose radioactive device causes a client to be radioactive for 1-7 days after insertion. The client must stay in the hospital for a few days after insertion and prior to the removal of the device. Pregnant nurses should not care for these clients."}, {"id": 11691, "cat": "safe and effective care environment", "stem": "should the nurse manager do first? O", "choices": [{"id": "a", "t": "Notify the nursing supervisor and file an incident report"}, {"id": "b", "t": "Administer the correct dosage and notify the nurse of the mistake"}, {"id": "c", "t": "Assess the client and notify the healthcare provider"}, {"id": "d", "t": "Notify the client and file an incident report"}], "correct": "c", "rationale": "All om The first priority is client safety, so the nurse should assess the client and notify the healthcare provider before taking any further action. ec FP >|", "whyNot": {"a": "The client assessment is first, then the healthcare provider should be notified to determine the course of care. The healthcare provider", "b": "The first action is a client assessment since the safety of the client is paramount. Furosemide is often the first line of treatment in a client", "d": "The client should be assessed, and the healthcare provider must be notified."}, "keyConcept": "Medication administration is an important nursing duty. Medication errors result in preventable risk to clients. Reporting medication errors is fundamental to client safety, as it reduces the adverse effects of errors and prevents future errors. Although reporting an error is important, the client's immediate safety is the priority when a medication error is discovered."}, {"id": 11692, "cat": "safe and effective care environment", "stem": "following? O A. Moral distress O B. Power O C. Horizontal violence O D. Hazing", "choices": [{"id": "a", "t": "Moral distress"}, {"id": "b", "t": "Power"}, {"id": "c", "t": "Horizontal violence"}, {"id": "d", "t": "Hazing"}], "correct": "c", "rationale": "Horizontal violence may occur as part of the nurse-nurse relationship, in which nurses who are of the same professional standing mistreat", "whyNot": {"a": "Moral distress occurs when a nurse feels a loss of satisfaction with her work environment; it may or may not be due to harassment from", "b": "This is not an example of power exhibited by the nurses.", "d": "Hazing refers to imposing humiliating tasks on a person as a form of initiation."}, "keyConcept": "\"Horizontal violence\" in nursing is often unrecognized or underreported. It is characterized by acts of unwanted abuse or hostility in the workplace, where bullying is described as repeated acts of aggression over a period of time. The Joint Commission mandates healthcare organizations to develop codes of workplace conduct that define acceptable and unacceptable behaviors and processes to manage behaviors that undermine the culture of safety."}, {"id": 11693, "cat": "safe and effective care environment", "stem": "Ahospitalized client falls and sustains a laceration above the left eye that is actively bleeding. Which of the following is the priority nursing action?", "choices": [{"id": "a", "t": "Check the pulse"}, {"id": "b", "t": "Assess respiratory rate"}, {"id": "c", "t": "Apply pressure to the wound"}, {"id": "d", "t": "Assess level of consciousness"}], "correct": "c", "rationale": "8% An actively bleeding laceration should be prioritized. Direct pressure should be applied to control the hemorrhage. After performing this ec | 60% intervention, the nurse should assess the client using the primary survey. Assessment in the primary survey includes airway, breathing, D i 31% circulation, and neurologic disability.", "whyNot": {"a": "The pulse check is used to assess circulation, which is an element of the primary survey. Control of hemorrhage should be prioritized in a", "b": "Assessment of respiratory rate is an element in the primary survey. First aid measures to stop active bleeding should be prioritized in this", "d": "Assessment of disability or neurologic status is not the priority in a client with a bleeding laceration."}, "keyConcept": "A full assessment should be completed when a client falls, but an actively bleeding wound is the immediate priority. The nurse should apply pressure, using sterile gauze, in order to control the hemorrhage. Airway, breathing, and circulation problems that are immediately evident should take priority over other interventions."}, {"id": 11694, "cat": "safe and effective care environment", "stem": "A nurse is leading a nursing team in providing care for a group of clients on a medical-surgical unit. Which of the following actions by the nurse is an indirect nursing-care activity?", "choices": [{"id": "a", "t": "Providing discharge teaching about self-care"}, {"id": "b", "t": "Assigning tasks to an assistive personnel"}, {"id": "c", "t": "Providing anticipatory guidance to a client in crisis"}, {"id": "d", "t": "Monitoring for adverse reactions to therapy"}], "correct": "b", "rationale": "(AP) is an indirect care activity. To meet a client's needs, APs assist them with activities OB rd aan of daily living, such as ambulation and bathing, and also measure vital signs, intake, and output. Ultimately the nurse is responsible for verifying that the APs have completed these tasks according to standards of care. c | 12% of 11%", "whyNot": {"a": "Client education is an essential direct care activity nurses engage in to provide for continuity of care after an illness, injury, or procedure.", "c": "Counseling is a direct care activity that nurses perform that involves helping clients manage overwhelming stress and solve problems.", "d": "Monitoring for adverse effects of medications, diagnostic procedures, and other therapies and evaluating clients for therapeutic outcomes"}, "keyConcept": "Indirect nursing-care activities center on managing the environment and collaborating with the interprofessional health care team. Examples are delegation, infection control measures, such as hand hygiene, and communicating and documenting nursing care plans and activities."}]};

